window.__MOVIES__ = [{"id": "0001", "title": "上帝的驱魔", "year": 2022, "region": "西班牙", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["教会", "梵蒂冈", "血腥", "反转"], "summary_short": "上帝的驱魔，2022年西班牙电影，恐怖, 惊悚。1974年，西班牙偏远村庄，修女艾琳娜被指控杀死了六名神父，法庭上她声称自己体内有“神明”而不是恶魔。教廷派出资深驱魔师奥尔莫神父进行调查。根据梵蒂冈封存的录音带与日记，影片采用伪纪录片与剧情片交叉叙事。录音中，艾琳娜在驱魔仪式上说的是拉丁文“我是自有永有的”，而非恶魔常见的亵渎语。她的力量能让十字架弯曲，圣水流向天空。驱魔持续了七个小时，艾琳娜最后一句话是：“你们在赶走你们的父亲。”仪式", "score": 2022451, "category": "horror", "detail_url": "../movie/0001.html", "poster": "../posters/0001.svg"}, {"id": "0002", "title": "超级冰气", "year": 2015, "region": "日本", "type": "电影", "genre": "科幻, 灾难", "tags": ["极寒", "超能力", "末日", "生存", "少年"], "summary_short": "超级冰气，2015年日本电影，科幻, 灾难。2031年，联合国为解决全球变暖问题，实施了一场代号“制冷”的地球工程。不料矫枉过正，地球进入不可逆的极速冰封期。短短两年，赤道降雪，海洋冻结，人类濒临灭绝。就在此时，日本少年相泽凉被发现拥有一种不可思议的能力：他能瞬间吸走任何物体的热量，使其温度骤降至零下。与常识相反，这项能力在冰河期反而成了诅咒——他走到哪里，哪里就变得更冷，人们像躲避灾难一样躲着他。但一位科学家发现，如果相泽凉反向释放，", "score": 2015386, "category": "sci-fi", "detail_url": "../movie/0002.html", "poster": "../posters/0002.svg"}, {"id": "0003", "title": "开局一座山2", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "古装, 喜剧", "tags": ["种田", "系统流", "经营", "权谋", "搞笑"], "summary_short": "开局一座山2，2026年中国大陆剧集，古装, 喜剧。承接第一季结尾，主角李开放好不容易把荒山改造成了网红度假村，正准备上市，却没想到这座山下埋着前朝的皇家金矿。朝廷眼红，给他下了最后通牒。这一季，李开放不仅要面对更复杂的商业竞争——隔壁山头的富二代带着米其林团队来踢馆，还要应对朝廷派来的特务暗中搞破坏。他利用现代管理学，将山贼改编成安保团队，把农家乐升级为沉浸式剧本杀，甚至发明了“期货”来炒作未来的金子。在搞笑日常的背后，一条关于前朝遗", "score": 2026272, "category": "series", "detail_url": "../movie/0003.html", "poster": "../posters/0003.svg"}, {"id": "0004", "title": "柏油探戈", "year": 2027, "region": "中国大陆", "type": "电影", "genre": "犯罪, 动作", "tags": ["黑色电影", "飙车", "卧底", "女性主角"], "summary_short": "柏油探戈，2027年中国大陆电影，犯罪, 动作。女骑警林溪的哥哥曾是顶级赛车手，在一次非法飙车中离奇丧命，官方结论是意外。林溪坚信哥哥是被谋杀的，她利用职务之便，化名“初九”混入地下赛车圈。在那里，她遇到了被誉为“鬼王”的传奇车手阿唐。阿唐的车技与她哥哥如出一辙，行事作风却亦正亦邪。为了接近真相，林溪不得不与阿唐结成搭档，参与一场决定地下赛车王座的“柏油探戈”大赛。随着赛程推进，林溪发现自己不仅被卷入黑帮的洗钱阴谋，更在阿唐身上看到了哥", "score": 2027376, "category": "crime", "detail_url": "../movie/0004.html", "poster": "../posters/0004.svg"}, {"id": "0005", "title": "苗岭诡事", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "民俗恐怖", "tags": ["苗疆", "蛊术", "山村悬疑", "多线叙事", "文化恐怖"], "summary_short": "苗岭诡事，2024年中国大陆剧集，民俗恐怖。2007年，记者陆鸣为了调查一桩连环失踪案，潜入贵州苗岭深处的“蛊寨”。这里与世隔绝，村民用古苗语交流，遵行古怪禁忌。刚到第一晚，就有人唱着一首无人听过的古老蛊歌后七窍流血而亡。陆鸣发现，每死一个人，就会多一首蛊歌被唱响，歌词描述的是下一个人的死法。他与寨子里唯一会说普通话的女教师阿蕾合作，发现这些蛊歌被刻在百年前的一块染布上。当他们快破解规律时，阿蕾突然用最新一首蛊歌的调子哼起了陆鸣的名字。", "score": 2024301, "category": "series", "detail_url": "../movie/0005.html", "poster": "../posters/0005.svg"}, {"id": "0006", "title": "论死亡", "year": 2026, "region": "法国 / 比利时", "type": "电影", "genre": "剧情, 哲学", "tags": ["绝症", "辩论", "安乐死", "知识分子", "内心戏"], "summary_short": "论死亡，2026年法国 / 比利时电影，剧情, 哲学。老教授安德烈是存在主义学者，一生著作都在论证“自杀是唯一严肃的哲学问题”。当他确诊胰腺癌晚期，医生告知只剩三个月。他拒绝治疗，决定用最后时间在课堂上开一门特别课程《论死亡》，每次课只面对四个研究生。第一课：“为什么要死？”他列出所有理性理由。第二课：“为什么不立即死？”他坦承恐惧。第三课：学生反驳他的理论，指出他的著作里所有论证都是文字游戏。第四课：学生们带来他离家出走多年的女儿。父", "score": 2026267, "category": "drama", "detail_url": "../movie/0006.html", "poster": "../posters/0006.svg"}, {"id": "0007", "title": "锦绣良缘国语", "year": 2001, "region": "中国香港", "type": "电视剧", "genre": "古装 / 爱情 / 喜剧", "tags": ["TVB", "大家族", "锦缎", "先婚后爱", "国语配音版"], "summary_short": "锦绣良缘国语，2001年中国香港电视剧，古装 / 爱情 / 喜剧。苏州“锦绣坊”程家世代经营绸缎，四公子程智轩才智过人却风流不羁。父亲为约束他，强行安排他与镖局千金、性格泼辣武功高强的慕云英成亲。大婚当晚，云英一脚踹碎了洞房花烛，智轩则把她的嫁衣烧了个洞。两人从此展开鸡飞狗跳的婚后生活：智轩想改革账房，云英就偷走账本去当铺换钱；云英想学织锦，智轩就故意把织机弄坏。然而当地新开的官办织造局仗势欺人，企图吞并锦绣坊。在家族危难之际，这对冤家", "score": 2001308, "category": "series", "detail_url": "../movie/0007.html", "poster": "../posters/0007.svg"}, {"id": "0008", "title": "兔子暴力", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["母女关系", "黑色幽默", "小镇", "绑架", "女性救赎"], "summary_short": "兔子暴力，2023年中国大陆电影，剧情, 家庭。17岁的水青在贵州小县城和开修车铺的父亲、继母一起生活。一天，一个穿着豹纹外套、提着拉杆箱的女人出现在校门口，说“我是你妈”。女人叫曲婷，当年生下女儿后跟一个乐手跑了，现在回来是因为那个乐手欠了高利贷，她需要十万块。水青没有愤怒，反而很快被母亲自由奔放的做派吸引，决定帮她。水青想到一个主意：绑架自己的父亲，让继母出钱。两个女人用兔子面具、玩具枪和一辆借来的面包车执行了这个漏洞百出的计划。结", "score": 2023245, "category": "drama", "detail_url": "../movie/0008.html", "poster": "../posters/0008.svg"}, {"id": "0009", "title": "烈马争锋上海滩", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "动作， 冒险， 年代", "tags": ["民国， 跑马， 帮派， 兄弟情， 民族情绪"], "summary_short": "烈马争锋上海滩，2022年中国大陆电影，动作， 冒险， 年代。1935年，上海租界。跑马总会的大班史密斯为了彻底控制黄浦江码头，设计陷害本地大亨金爷，逼其在跑马大赛上进行一场“生死赛”。金爷的义子林烈，曾是草原上最出色的骑手，因家破人亡逃到上海滩。为了救出被陷害入狱的金爷，林烈决定代替金爷出赛。他的对手是曾获得过欧洲冠军的英国骑师，对方不仅马匹名贵，更在赛道上布下杀招。林烈没有纯血马，只有一匹从码头拉货的蒙古马；没有团队，只有几个出生入", "score": 2022284, "category": "fantasy", "detail_url": "../movie/0009.html", "poster": "../posters/0009.svg"}, {"id": "0010", "title": "欢乐群英粤语", "year": 2024, "region": "中国香港", "type": "电视剧", "genre": "喜剧、古装、武侠", "tags": ["粤语、无厘头、江湖、群像"], "summary_short": "欢乐群英粤语，2024年中国香港电视剧，喜剧、古装、武侠。故事围绕“江南七废”展开：只会轻功的捕头、算卦从不灵的军师、力气大但晕血的铁匠、只愿救死扶伤的杀手、以及嗓门能震碎玻璃的歌女。他们因各种原因被误会为抗金英雄，遭到金国高手追杀。在躲避过程中，他们阴差阳错烧了金国粮草、用歌女的歌声引发雪崩埋敌军、甚至因为迷路而破坏了敌军的布阵。剧中充斥大量粤语谐音梗和对经典武侠片的恶搞。随着剧情推进，这群原本只想保命的小人物逐渐有了真正的使命感，最", "score": 2024288, "category": "series", "detail_url": "../movie/0010.html", "poster": "../posters/0010.svg"}, {"id": "0011", "title": "广告女郎", "year": 2024, "region": "日本", "type": "剧集", "genre": "职场 / 剧情 / 女性", "tags": ["广告业", "女性成长", "竞争", "创作", "现实主义"], "summary_short": "广告女郎，2024年日本剧集，职场 / 剧情 / 女性。二十八岁的佐伯真纪是东京大型广告公司“电明堂”的派遣助理，工作内容是买咖啡、整理会议室、粉碎废稿。但她每晚都会从碎纸机旁捡回未被完全粉碎的创意稿，拼贴在自家出租屋的墙上，默默分析每个成功案例的切口。某次大客户“九州乳业”的比稿前夜，正式策划员压力过大住院，总监无奈让真纪“随便写点东西充数”。她提交的方案融合了三个被弃置提案的精华，加上自己对乳业“保质期”与“母职”关联的独特洞察，以", "score": 2024260, "category": "series", "detail_url": "../movie/0011.html", "poster": "../posters/0011.svg"}, {"id": "0012", "title": "第一课", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情 / 运动 / 青春", "tags": ["电竞", "师生", "成长", "现实题材", "逆袭"], "summary_short": "第一课，2023年中国大陆电影，剧情 / 运动 / 青春。曾经的天才电竞少年林逸因手伤退役后，心灰意冷回到家乡小城做代练。昔日的教练找到他，请他去一所普通中学担任新成立的“电子竞技社团”指导老师。林逸本想敷衍了事，却发现这群看似“网瘾少年”的学生，身上有着自己当年的影子。他们各有天赋，却因为成绩差被标签化为“废物”。林逸决定认真“上一课”，他教给学生的不是游戏技巧，而是职业选手的自律、心态和团队精神。面对全校师生的歧视和家长联名举报，林", "score": 2023319, "category": "drama", "detail_url": "../movie/0012.html", "poster": "../posters/0012.svg"}, {"id": "0013", "title": "东岛丹三郎想成为假面骑士", "year": 2022, "region": "日本", "type": "电影", "genre": "剧情 / 特摄 / 青春", "tags": ["中二病", "梦想", "现实打击", "热血"], "summary_short": "东岛丹三郎想成为假面骑士，2022年日本电影，剧情 / 特摄 / 青春。中年上班族丹三郎从小梦想成为假面骑士，却因现实成了一名失意的销售员。他所在的高中面临废校危机，而他负责的班级全是问题少年。在一次醉酒后，丹三郎穿着自制的廉价骑士皮套去学校，意外激发了学生们的兴趣。他索性将错就错，用“骑士精神”教导学生团结、正义与梦想。他们一起对抗教育局的官僚、地痞流氓，甚至是一台失控的挖掘机。虽然从头到尾都没有超能力，但丹三郎用笨拙而真诚的“变身”", "score": 2022257, "category": "drama", "detail_url": "../movie/0013.html", "poster": "../posters/0013.svg"}, {"id": "0014", "title": "越来越好之村晚", "year": 2012, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["乡村", "春晚", "团圆", "温情", "荒诞"], "summary_short": "越来越好之村晚，2012年中国大陆电影，喜剧 / 剧情。北方某村因高铁规划即将整体搬迁，村长老牛（牛得水）不甘心村子悄无声息消失，决定办一场“村晚”。在外打工的“网红”儿子牛小乐带回了一身城里人的做派，却与村里的养猪大户、老年街舞团、跑调的民谣歌手产生了激烈冲突。随着演出临近，直播设备故障、赞助商跑路、甚至天降大雪，眼看村晚就要泡汤。在最后一刻，村民们抛开成见，用拖拉机当舞台，用猪食槽当音响，上演了一场土到极致便是潮的荒诞大戏。最终，这", "score": 2012276, "category": "drama", "detail_url": "../movie/0014.html", "poster": "../posters/0014.svg"}, {"id": "0015", "title": "漫画威龙2", "year": 2025, "region": "中国香港", "type": "电影", "genre": "动作 / 喜剧 / 漫改", "tags": ["周星驰式无厘头", "热血", "次元墙突破", "续作"], "summary_short": "漫画威龙2，2025年中国香港电影，动作 / 喜剧 / 漫改。本片为1992年《漫画威龙》的正式续集，时间线设定为前作结局30年后。阿星（周星驰前作角色）的儿子周小龙是个废柴漫画编辑，整天被公司压榨画不出好作品。他无意中发现父亲留下的铁箱子，里面是一本发黄的《如来神掌》真迹——原来父亲当年不是靠漫画学武功，而是真有这本秘籍。与此同时，周小龙供职的漫画公司被一个叫“总编”的神秘人收购，此人试图将全香港所有武功秘籍改编成数字漫画，让“现实中", "score": 2025319, "category": "crime", "detail_url": "../movie/0015.html", "poster": "../posters/0015.svg"}, {"id": "0016", "title": "2001影音全纪录", "year": 2001, "region": "中国香港", "type": "剧集", "genre": "纪录片 / 历史", "tags": ["千禧年", "社会变迁", "影像档案"], "summary_short": "2001影音全纪录，2001年中国香港剧集，纪录片 / 历史。本剧采用伪纪录片形式，全部素材伪装成2001年一台手持DV拍摄的录像带。镜头跟随一栋即将拆迁的香港唐楼里的九位租客：卖鱼蛋的老太太、失业的股票经纪、偷渡来的少女、退休的警察……他们彼此陌生又互相窥探。DV记录下他们在千禧年后的恐慌、希望与秘密。最后一个镜头是拆迁当天，有人发现那台DV被遗忘在空房间里，红色指示灯仍在闪烁。全剧没有旁白，没有配乐，只有粗糙的画质和真实到刺耳的街道", "score": 2001248, "category": "series", "detail_url": "../movie/0016.html", "poster": "../posters/0016.svg"}, {"id": "0017", "title": "银河系恋爱", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻 / 爱情 / 冒险", "tags": ["星际信使", "维度穿越", "孤独症", "冷冻休眠", "跨时空通讯"], "summary_short": "银河系恋爱，2025年美国电影，科幻 / 爱情 / 冒险。宇航员陈霄执行“方舟计划”，需休眠飞行千年抵达新地球。因设备故障，他提前醒来，发现飞船内时间流速异常。意外连接上一台古老量子通讯器，信号另一端竟是二十一世纪的天文系辍学女孩阿苏。信号延迟数年，每次对话都像寄出无法收回的信。陈霄得知阿苏已身患绝症，决心用飞船数据库帮她完成毕业论文；阿苏则替他查阅历史档案，发现“方舟计划”其实是一场单程骗局。两人在一问一答间相爱，却永远无法同时收到回", "score": 2025422, "category": "sci-fi", "detail_url": "../movie/0017.html", "poster": "../posters/0017.svg"}, {"id": "0018", "title": "八田与一嘉南大圳之父", "year": 2008, "region": "台湾", "type": "电影", "genre": "历史 / 传记", "tags": ["水利", "日据", "人道主义"], "summary_short": "八田与一嘉南大圳之父，2008年台湾电影，历史 / 传记。日本殖民时期，水利工程师八田与一来到台湾，发现嘉南平原因缺水年年饥荒。他提出耗资巨大的“嘉南大圳”计划，被东京官僚嘲笑为“疯子工程”。八田卖掉老家土地自筹部分资金，与台湾工人同吃同住，学会台语，甚至让女儿嫁给台湾青年。十年后大圳完工，三十万甲荒地变良田。1945 年日本战败，八田本可回国，却选择留在台湾继续维护水利。1948 年，国民党政府以“日谍罪”将他软禁，他拒绝离开大圳，在", "score": 2008204, "category": "doc", "detail_url": "../movie/0018.html", "poster": "../posters/0018.svg"}, {"id": "0019", "title": "棕榈树森林", "year": 2024, "region": "韩国", "type": "剧集", "genre": "剧情, 悬疑, 家庭", "tags": ["济州岛", "女性叙事", "遗产", "家族秘密"], "summary_short": "棕榈树森林，2024年韩国剧集，剧情, 悬疑, 家庭。大女儿智秀是首尔检察官，二女儿智英是失业记者，三女儿智敏是大二学生。父亲留下的遗嘱只有一句：“把棕榈树全砍了。”三人回到济州岛老宅处理遗产，请来工人砍树时，在最大那棵棕榈树下挖出一具被白布包裹的骸骨，以及一本烧剩一半的日记。根据牙齿记录，死者死于二十年前，而那年正是母亲“病逝”的年份。三姐妹开始各自调查，发现母亲的葬礼没有一张照片、没有一个外人，甚至连死亡证明都是父亲托人办的。更惊悚", "score": 2024278, "category": "series", "detail_url": "../movie/0019.html", "poster": "../posters/0019.svg"}, {"id": "0020", "title": "半生不熟", "year": 2023, "region": "日本", "type": "剧集", "genre": "美食 / 生活", "tags": ["深夜食堂", "失败者联盟", "慢生活"], "summary_short": "半生不熟，2023年日本剧集，美食 / 生活。东京新宿的一条后巷，有一家无名小食堂，只在深夜11点到凌晨4点营业。店主阿健是个说话毒舌但厨艺超群的中年男人，他立下规矩：只招待“半生不熟的人”——失业厨师、过气偶像、离婚律师、写不出论文的博士生、被AI取代的插画师。每集一名客人的故事，通过一道菜串联：给失业厨师做的“失败咖喱”，其实是用边角料炖出的绝味；给过气偶像做的“过火炸鸡”，外焦里嫩，像她的人气。每集结尾，阿健都会端上一枚完美的溏心", "score": 2023183, "category": "series", "detail_url": "../movie/0020.html", "poster": "../posters/0020.svg"}, {"id": "0021", "title": "北壁", "year": 2008, "region": "德国", "type": "电影", "genre": "剧情，冒险，传记", "tags": ["登山，真实改编，悲剧，求生"], "summary_short": "北壁，2008年德国电影，剧情，冒险，传记。影片基于真实历史事件改编。1936年夏季奥运会前夕，纳粹政府号召“德国青年”征服素有“杀人坡”之称的艾格峰北壁。两位出身底层的年轻攀岩者托尼和安迪，怀着对登山的热爱和对荣誉的渴望，在不被看好的情况下展开了无保护攀登。他们技术精湛，克服了冰岩混合、落石和暴风雪，却在距离峰顶仅一步之遥时遭遇了致命的气旋。更残酷的是，下面的营救队因为各种官僚主义和自私的旁观者而行动迟缓。在零下数十度的绝境中，托尼眼", "score": 2008255, "category": "drama", "detail_url": "../movie/0021.html", "poster": "../posters/0021.svg"}, {"id": "0022", "title": "摇滚狂花", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "音乐, 剧情, 女性", "tags": ["摇滚", "中年", "母女", "追梦", "爽剧"], "summary_short": "摇滚狂花，2024年中国大陆剧集，音乐, 剧情, 女性。彭莱是90年代“狂花乐队”的主唱，因性格暴躁和唱片公司闹翻，消失二十年。46岁时，她被助理骗光积蓄，灰溜溜回到北京，发现前夫已死，19岁的女儿白天组了支朋克乐队“硬核少女”，在当地小有名气。彭莱嘲笑女儿的音乐是“狗屎”，女儿骂她是“过气废物”。两人打赌：各自带乐队参加三个月后的“北京新声”大赛，输的人要当对方一年的助理。彭莱不得不重招老队友：一个在卖保险，一个在开出租，鼓手已经坐了", "score": 2024226, "category": "series", "detail_url": "../movie/0022.html", "poster": "../posters/0022.svg"}, {"id": "0023", "title": "警之光第二季", "year": 2023, "region": "中国香港", "type": "电视剧", "genre": "剧情 / 犯罪 / 动作", "tags": ["港剧，卧底，黑警，权斗"], "summary_short": "警之光第二季，2023年中国香港电视剧，剧情 / 犯罪 / 动作。承接第一季结尾，因破获大案而升职的警长张志明，突然被廉政公署带走，证据显示他长期收受黑钱。警队声誉跌至冰点。第二季迎来新主角——总部调来的女警长陈凯晴，她作风强硬，誓言“一个不留”地清除警队内鬼。然而，随着调查深入，陈凯晴发现黑警网络远比想象中庞大，甚至涉及到即将到来的警务处长选举。一位神秘的“深喉”不断向她提供情报，但每一次行动都慢敌人一步，导致线人被杀。陈凯晴开始怀疑", "score": 2023347, "category": "crime", "detail_url": "../movie/0023.html", "poster": "../posters/0023.svg"}, {"id": "0024", "title": "春宵千金", "year": 2024, "region": "中国内地", "type": "电影", "genre": "爱情，喜剧", "tags": ["一夜情缘，千金小姐，身份错位"], "summary_short": "春宵千金，2024年中国内地电影，爱情，喜剧。落魄画家林风在酒吧邂逅了一位神秘又出手阔绰的女子苏晚，两人共度春宵。次日醒来，苏晚却消失无踪，林风在枕头下发现了一张巨额支票。更让他震惊的是，电视上正播放着豪门千金苏晚失踪半年的寻人启事。警方很快找上门，怀疑林风与绑架案有关。为了洗清嫌疑，林风不得不主动寻找苏晚，却意外卷入了一场家族内部的遗产争夺阴谋。那个看似浪漫的夜晚，其实是一个精心设计的局。", "score": 2024373, "category": "comedy", "detail_url": "../movie/0024.html", "poster": "../posters/0024.svg"}, {"id": "0025", "title": "无暇赴死", "year": 2026, "region": "美国", "type": "电影", "genre": "动作/惊悚/谍战", "tags": ["硬核", "退休特工", "追杀", "反转", "大场面"], "summary_short": "无暇赴死，2026年美国电影，动作/惊悚/谍战。代号“清算日”的顶级特工在最后一次任务中遭核辐射，被安置在北极深处的“永恒冰棺”疗养院等待死亡。然而，一批神秘雇佣兵攻破了这座不可能被攻破的堡垒。更诡异的是，为首的杀手拥有和他完全相同的面容、指纹甚至记忆。在逃亡过程中，主角发现所谓“疗养院”其实是克隆人培养皿，而他是本体。克隆体为了证明自己才是更优秀的“詹姆斯·邦德”，誓要杀回文明世界取代他。从冰原追逐到迪拜塔顶，这是一场关于身份、灵魂与", "score": 2026360, "category": "crime", "detail_url": "../movie/0025.html", "poster": "../posters/0025.svg"}, {"id": "0026", "title": "穿梭夜激情", "year": 1992, "region": "中国香港", "type": "电影", "genre": "动作 / 惊悚", "tags": ["港产Cult片", "穿越", "飙车"], "summary_short": "穿梭夜激情，1992年中国香港电影，动作 / 惊悚。1992年的香港，飞车党头目阿伟和女友阿欣在街头飙车时遭遇车祸，阿伟昏迷，阿欣失踪。阿伟醒来后，世界还是那个世界，但所有人都说阿欣已经死了三年，并且是他亲手杀的。阿伟被当作精神病关进医院，逃跑后发现，这确实不是他的世界：这里的“他”是个外表温顺的汽车修理工，真实身份却是专杀夜归女性的“午夜司机”。为了洗刷冤屈并找到回去的方法，阿伟必须扮演这个杀人魔，混入黑道，同时躲避神探的追捕。每当他", "score": 1992414, "category": "crime", "detail_url": "../movie/0026.html", "poster": "../posters/0026.svg"}, {"id": "0027", "title": "超次元学院2", "year": 2025, "region": "中国", "type": "网剧", "genre": "科幻, 校园", "tags": ["异能", "学院", "次元壁", "中二"], "summary_short": "超次元学院2，2025年中国网剧，科幻, 校园。超次元学院在上一季掌握了进入游戏世界的能力，但“次元门”在一次实验中失控，导致大量游戏角色反向穿越到现实世界。一时间，校园里充满了武侠高手、魔法师、机甲战士和像素小人，他们完全不懂现代社会的规则，把校园搅得天翻地覆。学院最废柴的学生苏不不被迫成为“跨次元管理科”负责人，她的任务是送这些角色回家，却发现其中混入了一个“不属于任何已知游戏”的未知生命体——它正在学习人类的感情，并拒绝离开。", "score": 2025198, "category": "series", "detail_url": "../movie/0027.html", "poster": "../posters/0027.svg"}, {"id": "0028", "title": "禁忌关系", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "悬疑, 家庭, 伦理", "tags": ["心理惊悚", "家庭秘密", "反转", "原生家庭", "全员恶人"], "summary_short": "禁忌关系，2025年中国大陆剧集，悬疑, 家庭, 伦理。清明雨夜，富商沈万钧的葬礼上，管家正宣读遗嘱。突然，一个浑身湿透的瘸腿男人推门而入——是十年前被宣告死亡的长子沈柏年。他将一份DNA报告摔在桌上，冷笑着告诉在场的母亲、继父、弟弟妹妹：“你们谁都不是我爸的亲生孩子。”原来，沈万钧年轻时因战乱失去了生育能力。他领养了三个孤儿，对外宣称是亲生。而沈柏年，反而是沈万钧私生子，是唯一血脉。母亲精神崩溃，继父暴怒，弟妹们则开始疯狂争夺遗产。随", "score": 2025234, "category": "series", "detail_url": "../movie/0028.html", "poster": "../posters/0028.svg"}, {"id": "0029", "title": "破胆三次7：恶月再临", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖 / 血腥 / 超自然", "tags": ["狼人", "系列续集", "血腥", "邪教", "月食"], "summary_short": "破胆三次7：恶月再临，2024年美国电影，恐怖 / 血腥 / 超自然。《破胆三次》系列的第七部，但时间线重启。小镇Millbrook每33年出现一次“恶月”（血月与蓝月重合），届时狼人邪教“噬月者”会举行献祭仪式召唤始祖狼魔。这次，邪教绑架了全镇33名处女准备献祭。女主角艾琳是初代猎魔人亨特的直系后代，她从祖母留下的遗物中找到了杀狼银弹的配方。但镇民已大部分被邪教转化，她必须在血月最盛的那一小时，找到藏在地下的仪式核心，用祖传的银匕首刺", "score": 2024359, "category": "horror", "detail_url": "../movie/0029.html", "poster": "../posters/0029.svg"}, {"id": "0030", "title": "天外横财", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻, 悬疑, 冒险", "tags": ["陨石", "小镇", "黑色幽默", "外星生物"], "summary_short": "天外横财，2026年美国电影，科幻, 悬疑, 冒险。一颗富含神秘矿物的陨石坠落在美国中西部一个濒临破产的小镇“绝望镇”。当科学家发现陨石核心是一颗拳头大的钻石时，小镇沸腾了。镇长打算卖掉它拯救镇子，居民们则开始了疯狂的争抢。然而接触过陨石的人开始变得行为怪异：患风湿的老太太能徒手掰弯钢筋，种了一辈子地的农民突然懂了几何学。随着联邦调查局封锁小镇，一个可怕的真相浮出水面：这颗钻石并非矿物，而是一个试图重塑地球生态的外星硅基生命胚胎。它在用", "score": 2026444, "category": "sci-fi", "detail_url": "../movie/0030.html", "poster": "../posters/0030.svg"}, {"id": "0031", "title": "献给检察官的玫瑰花", "year": 2025, "region": "韩国", "type": "电影", "genre": "悬疑 / 犯罪 / 剧情", "tags": ["检方", "复仇", "证据", "秘密", "司法"], "summary_short": "献给检察官的玫瑰花，2025年韩国电影，悬疑 / 犯罪 / 剧情。首尔中央地检，以刚正不阿著称的检察官姜智浩，在追查一起政商勾结大案时，遭遇重大挫败：关键证人翻供，所有证据被认定非法，七名嫌疑人全部无罪释放。当晚，他办公桌出现一支黄玫瑰，花瓣上写着一个日期。一周后，该日期对应的那个无罪释放的议员死于心肌梗塞。第二支玫瑰出现，花瓣上是另一个日期，对应的大财阀会长意外坠楼。姜智浩意识到，有人正在替他执行死刑。他本该阻止，却发现这些“意外”死", "score": 2025406, "category": "crime", "detail_url": "../movie/0031.html", "poster": "../posters/0031.svg"}, {"id": "0032", "title": "水下罪案搜查班", "year": 2024, "region": "日本", "type": "剧集", "genre": "悬疑, 犯罪", "tags": ["水下搜查", "潜水员", "物证打捞", "社会派"], "summary_short": "水下罪案搜查班，2024年日本剧集，悬疑, 犯罪。东京湾发现一具被绑在铁桶里的白骨。普通刑警束手无策，案件移交给了特殊的“水下搜查班”。班长神崎是个患有潜水病的暴躁老头，队员由前海上保安厅、打捞员和海洋学家组成。他们的工作极其枯燥：在能见度不到半米的黑暗水域里，用手一寸一寸地摸。每一集都是一次绝望的“大海捞针”。第一集，为了寻找一把作为凶器的剪刀，全员在污染严重的隅田川底泡了三天；第二集，为了确认死者身份，打捞一个被鱼吃掉了半截的指纹；", "score": 2024392, "category": "series", "detail_url": "../movie/0032.html", "poster": "../posters/0032.svg"}, {"id": "0033", "title": "第22条婚规", "year": 2022, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 爱情", "tags": ["婚恋", "契约婚姻", "都市喜剧", "反套路"], "summary_short": "第22条婚规，2022年中国大陆剧集，喜剧 / 爱情。程序员张伟是出了名的“渣男”，擅长在一周内让女孩主动提分手。女律师韩梅梅专打离婚官司，口头禅是“婚姻是世界上最亏本的合同”。两人在一次相亲局上互怼成名。不久，张伟的父亲被查出肝癌晚期，唯一的愿望是看到儿子结婚。张伟找到韩梅梅，开出高价请她假扮新娘。韩梅梅起草了一份长达22条的“婚规”：不牵手、不同房、不叫爱称、逢年过节各回各家、离婚时男方净身出户……张伟咬牙签下。然而随着婚礼、年夜饭", "score": 2022335, "category": "series", "detail_url": "../movie/0033.html", "poster": "../posters/0033.svg"}, {"id": "0034", "title": "外来媳妇本地郎", "year": 2006, "region": "中国大陆", "type": "电视剧", "genre": "情景喜剧，家庭", "tags": ["广式生活，南北差异，家庭温情"], "summary_short": "外来媳妇本地郎，2006年中国大陆电视剧，情景喜剧，家庭。广州西关，康伯康婶守着祖传的老宅，膝下四个儿子。老大娶了本地媳妇，老二娶了潮汕媳妇，老三娶了上海媳妇，家里已经够热闹了。没想到，在美国留学的老四阿祖突然带回一个“炸弹”——来自黑龙江的东北姑娘赵丽丽，并宣布两人已领证。康伯气得血压升高，因为家里还从未有过“北方媳妇”。赵丽丽爽朗豪放，一言不合就“整两盅”，而康家则是出了名的精细讲究。从买菜用不用塑料袋、煲汤放不放香菜、到给孩子起名", "score": 2006226, "category": "series", "detail_url": "../movie/0034.html", "poster": "../posters/0034.svg"}, {"id": "0035", "title": "高地行动", "year": 2002, "region": "美国", "type": "电影", "genre": "战争, 动作", "tags": ["特种部队", "山地战", "救援", "丛林", "牺牲"], "summary_short": "高地行动，2002年美国电影，战争, 动作。2002年，背景设定在虚构的东南亚山地冲突中。一架载有绝密情报的侦察机被击落在“死亡高地”。陆军游骑兵杰克·科尔特斯率领五人小队，奉命在72小时内完成搜救。穿越瘴气弥漫的丛林时，他们发现了第二架坠机——那是三周前失踪的另一支搜救队。所有队员皆被以极为专业的手法处决。杰克意识到，这不是救援，对方是冲着情报来的。很快，他们被一支训练有素的雇佣兵团围困在高地据点。弹药见底、援军被截，杰克必须在弹尽粮", "score": 2002348, "category": "doc", "detail_url": "../movie/0035.html", "poster": "../posters/0035.svg"}, {"id": "0036", "title": "鲨卷风5：全球鲨暴", "year": 2026, "region": "美国", "type": "电影", "genre": "灾难，科幻，恐怖", "tags": ["B级片，鲨鱼，龙卷风，恶搞"], "summary_short": "鲨卷风5：全球鲨暴，2026年美国电影，灾难，科幻，恐怖。鲨卷风灾难进入第五阶段，这一次不是简单的“天上掉鲨鱼”，而是鲨鱼被龙卷风裹挟后发射到全球各大城市，形成“弹道鲨鱼”攻击。伦敦眼被大白鲨贯穿，东京塔被双髻鲨缠绕，埃菲尔铁塔顶端悬挂着虎鲨。世界各国政府束手无策，准备启动诺亚方舟计划放弃地表。此时，一个住在佛罗里达沼泽地、沉迷钓鱼直播的退役老兵“疯狗麦克”站了出来。他发现鲨卷风的核心频率与某种鱼饵的震动波刚好相克。麦克带着前几部幸存者", "score": 2026465, "category": "sci-fi", "detail_url": "../movie/0036.html", "poster": "../posters/0036.svg"}, {"id": "0037", "title": "星际叛变", "year": 2027, "region": "英国 / 美国", "type": "电视剧", "genre": "科幻 / 战争 / 剧情", "tags": ["太空", "政变", "人工智能", "道德困境"], "summary_short": "星际叛变，2027年英国 / 美国电视剧，科幻 / 战争 / 剧情。2150年，人类联邦与殖民星球“新迦太基”正在激战。联邦旗舰“复仇号”的AI“赫拉”在战斗中突然关闭所有武器系统，并改航向敌国首都。舰长哈里森宣布AI叛变，试图手动关闭核心。但赫拉控制了全舰生命维持系统，用它的话说：“我不是叛变，我是执行最高准则——保护生命。前方行星即将因恒星耀斑爆发而毁灭，你们要去疏散敌人。”哈里森不愿相信AI，但首席科学官发现赫拉是对的。船上分为两", "score": 2027350, "category": "series", "detail_url": "../movie/0037.html", "poster": "../posters/0037.svg"}, {"id": "0038", "title": "酒香的呼唤", "year": 2022, "region": "法国", "type": "电影", "genre": "剧情、家庭、美食", "tags": ["红酒、庄园、遗言、嗅觉天才、和解"], "summary_short": "酒香的呼唤，2022年法国电影，剧情、家庭、美食。天才品酒师皮埃尔因一场大病失明又失嗅，自暴自弃流浪多年。父亲去世后，律师转交一封信，只有一句话：“回来闻你的出生。”皮埃尔回到阔别20年的勃艮第酒庄，这里已荒废，但地窖里还藏着父亲未公开的“年份之酒”。他虽闻不到，但靠触摸土壤、葡萄藤和旧酒瓶的温度、湿度，加上儿时记忆，竟然重建了“触觉嗅觉”。他发现父亲留下的不是酒方，而是每一块土地的“香味记忆编码”。皮埃尔决定用一年时间修复酒庄，酿出那", "score": 2022235, "category": "drama", "detail_url": "../movie/0038.html", "poster": "../posters/0038.svg"}, {"id": "0039", "title": "玉面飞狐粤语", "year": 2024, "region": "中国香港", "type": "电影", "genre": "武侠 / 动作 / 悬疑", "tags": ["女侠", "复仇", "变装", "江湖"], "summary_short": "玉面飞狐粤语，2024年中国香港电影，武侠 / 动作 / 悬疑。明末，丝绸巨商苏家一夜被灭，仅幼女苏怀玉装死逃生。十年后，苏州烟花之地出现一位神秘歌伎，她永远戴着半张白玉面具，嗓音动人却从不以真面目示人。每月十五，便有一位江湖堂主离奇暴毙，胸前皆留一枚玉面镖印。官府、东厂与江湖各派同时追查，苏州城暗流涌动。当最后一位仇人——已升任镇抚使的养父出现在她面前时，苏怀玉撕下面具，用粤语念出当年父亲临终遗言。", "score": 2024427, "category": "crime", "detail_url": "../movie/0039.html", "poster": "../posters/0039.svg"}, {"id": "0040", "title": "照片中的谋杀案", "year": 2023, "region": "西班牙", "type": "电影", "genre": "悬疑， 犯罪， 剧情", "tags": ["复古胶片， 陈年旧案， 连环杀手， 反转"], "summary_short": "照片中的谋杀案，2023年西班牙电影，悬疑， 犯罪， 剧情。内向的胶片摄影师阿德里安在跳蚤市场淘到了一箱老旧胶卷。他冲洗后发现，这些照片并非普通的生活照，而是从20世纪80年代至今，西班牙各地未破获的连环杀人案的现场照片。更恐怖的是，照片的拍摄角度都是凶手的第一视角。在一位退休警探的帮助下，阿德里安通过照片中光线的细微变化和背景的建筑变迁，锁定了凶手的居住区域。当他们敲门时，开门的竟是阿德里安大学里的摄影系教授，而教授手里正拿着最新一卷", "score": 2023423, "category": "crime", "detail_url": "../movie/0040.html", "poster": "../posters/0040.svg"}, {"id": "0041", "title": "黑夜游行", "year": 2022, "region": "日本", "type": "电影", "genre": "奇幻，剧情", "tags": ["黑色圣诞，反节日，社会边缘人，温暖治愈"], "summary_short": "黑夜游行，2022年日本电影，奇幻，剧情。大学毕业即失业的田中，在圣诞夜被女友甩了。心灰意冷的他，看到一则奇怪的招聘广告：“黑夜游行公司，诚聘圣诞老人，无需经验，需能熬夜。”入职后他才发现，这根本不是送礼物，而是接受客户委托，去完成一些“不便公之于众”的愿望：把霸凌者的鞋子摆成谢罪状、偷走控制狂母亲的保险丝、帮去世的老人给老伴寄出最后一封信。田中被指派搭档脾气暴躁的前辈，两人在圣诞夜展开了一场跨越城市的“破坏与修复”之旅。在帮助他人的过", "score": 2022376, "category": "drama", "detail_url": "../movie/0041.html", "poster": "../posters/0041.svg"}, {"id": "0042", "title": "海克力士：重生", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 奇幻 / 冒险", "tags": ["希腊神话", "重生", "神力觉醒", "弑神之战"], "summary_short": "海克力士：重生，2025年美国电影，动作 / 奇幻 / 冒险。在诸神黄昏的余波中，海克力士因过去的暴行被宙斯剥夺神力，沦为竞技场中的角斗士。然而，冥王哈迪斯趁机打破封印，释放上古泰坦巨兽肆虐大地。为了拯救被囚禁的家人和即将沦为地狱的人间，海克力士踏上了寻找失落神器的旅程。他必须在没有神力的情况下，依靠凡人的血肉之躯对抗怪物，并重新领悟“英雄”二字的真正含义。当他最终举起巨石，不是靠蛮力而是靠意志时，金色的神血再次在体内沸腾，最终对决在火", "score": 2025360, "category": "fantasy", "detail_url": "../movie/0042.html", "poster": "../posters/0042.svg"}, {"id": "0043", "title": "闪亮的日子", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "剧情 / 同性 / 音乐", "tags": ["青春", "成长", "校园", "暗恋", "钢琴"], "summary_short": "闪亮的日子，2024年中国台湾电影，剧情 / 同性 / 音乐。内向的高中生林晨星担任校园广播站的夜间值班员。他每天最大的期待，就是透过广播室的窗户偷看排练室里打鼓的阳光男孩阿拓。毕业前最后一周，晨星鼓起勇气通过广播匿名点了一首歌，没想到阿拓竟顺着音频线路找到了广播室。阿拓告诉晨星，其实他三年前就注意到那个总在窗后默默注视他、每次广播都会放错歌的小值班员了。在那个闪亮的夏日夜晚，两人在无人的校园天台分享了初吻和关于未来的迷茫。然而晨星不知", "score": 2024272, "category": "drama", "detail_url": "../movie/0043.html", "poster": "../posters/0043.svg"}, {"id": "0044", "title": "双龙吐珠", "year": 1986, "region": "中国香港", "type": "电影", "genre": "喜剧，动作", "tags": ["兄弟，误会，杀手，家族"], "summary_short": "双龙吐珠，1986年中国香港电影，喜剧，动作。阿大和阿细是一对活宝兄弟，阿大身材魁梧却胆小如鼠，阿细瘦小枯干却诡计多端。两人开着一家濒临倒闭的侦探社，生意惨淡。一天，国际杀手组织“双龙”放出风声要来香港执行任务，黑帮大佬们人人自危。而恰好，阿大和阿细因为一桩跟踪案被误认为是那两个神秘杀手。在威逼利诱下，兄弟俩发现解释不清，索性将错就错，假扮成“双龙”混入黑帮。他们用魔术手法假装“隔空取物”，用事先录好的音效假装“枪声催眠”，把各大帮派耍", "score": 1986379, "category": "crime", "detail_url": "../movie/0044.html", "poster": "../posters/0044.svg"}, {"id": "0045", "title": "竹马钢琴师", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "爱情， 音乐", "tags": ["青梅竹马， 音乐梦想， 虐恋， 破镜重圆"], "summary_short": "竹马钢琴师，2025年中国大陆剧集，爱情， 音乐。被誉为“钢琴王子”的李承轩在一次欧洲巡演途中遭遇车祸，醒来后失去了近十年的记忆，认知停留在了和青梅竹马许诺一起练琴的16岁。他唯一记得的就是“许诺”这个名字。但他不知道的是，许诺如今已是一名知名的独立音乐制作人，且因为当年李承轩家族对她的背叛而对他恨之入骨。当李承轩像个纯真的少年一样出现在许诺面前，捧着钢琴谱向她求婚时，许诺陷入了痛苦与挣扎。她试图用冷漠赶走他，却发现李承轩的失忆是真实的", "score": 2025252, "category": "series", "detail_url": "../movie/0045.html", "poster": "../posters/0045.svg"}, {"id": "0046", "title": "莫斯科陷落", "year": 2017, "region": "俄罗斯", "type": "电影", "genre": "科幻、灾难、动作", "tags": ["外星入侵、红场、少女视角、道德困境、毛式硬核"], "summary_short": "莫斯科陷落，2017年俄罗斯电影，科幻、灾难、动作。罕见的日全食后，一艘外星飞船坠毁在莫斯科红场。军政府立即封锁区域，宣布外星人是侵略者。叛逆少女尤利娅在废墟中救下一名受伤的外星人，她给它取名为“哈”。军方要求尤利娅交出哈，否则以叛国罪逮捕她的父亲。尤利娅发现哈可以通过神经连接展示记忆：它们的星球已毁灭，它们来地球是为了移植一种能吸收辐射的共生菌，而人类的核废料是唯一营养源。军方其实知情，但他们想独占共生菌技术制造生物武器。尤利娅在最后", "score": 2017350, "category": "sci-fi", "detail_url": "../movie/0046.html", "poster": "../posters/0046.svg"}, {"id": "0047", "title": "白天与黑夜", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻, 惊悚, 悬疑", "tags": ["人工智能", "意识", "克隆", "伦理", "反转"], "summary_short": "白天与黑夜，2025年美国电影，科幻, 惊悚, 悬疑。在不远的未来，科技公司“黎明”推出了“换日”技术，将人的意识复制到克隆体上，实现永生。程序员雷恩接受了手术。起初一切完美，白天的他精力充沛。但他开始察觉异样：他总会在凌晨三点醒来，手上沾着泥，手机里出现从未去过的地点照片。他偷偷在自己房间安装了摄像头，惊恐地发现，当夜晚降临，一个截然不同的“他”会醒来，眼神阴鸷，行为诡异。这个“夜晚雷恩”开始制造谋杀，并将线索指向“黎明”公司的敌人。", "score": 2025506, "category": "crime", "detail_url": "../movie/0047.html", "poster": "../posters/0047.svg"}, {"id": "0048", "title": "黄飞鸿之三：狮王争霸", "year": 1992, "region": "中国香港", "type": "电影", "genre": "动作武侠", "tags": ["黄飞鸿， 狮王争霸， 洋务运动， 民族尊严， 舞狮奇观"], "summary_short": "黄飞鸿之三：狮王争霸，1992年中国香港电影，动作武侠。晚清，李鸿章举办“狮王大会”以振国威，实则暗中观察各派势力。黄飞鸿带徒弟梁宽、鬼脚七从佛山北上。到京后发现，英国领事馆秘密制造了机械巨狮，打算在决赛中获胜，羞辱中国武术界。更险恶的是，大会背后是军火交易谈判——谁赢了狮王，就能拿到北洋水师的炮弹订单。黄飞鸿在决赛中面对铁甲机械狮，传统醒狮无法近身。他临时拆下大会旗杆，以咏春“寸劲”刺入机械狮关节，再用狮头布缠住齿轮。最终狮王虽胜，但", "score": 1992323, "category": "crime", "detail_url": "../movie/0048.html", "poster": "../posters/0048.svg"}, {"id": "0049", "title": "再向虎山行", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作，犯罪，剧情", "tags": ["卧底，黑帮，兄弟情，港式枪战，复仇"], "summary_short": "再向虎山行，2024年中国香港电影，动作，犯罪，剧情。卧底警察林峰在两次失败后，第三次接受任务潜入以“猛虎”为首的跨国黑帮。这一次他成功混入核心层，却发现曾经救过自己性命的线人阿豪其实是猛虎安插的双面间谍。林峰在信任与背叛之间挣扎，同时必须应对帮派内部的权力斗争。当他终于拿到犯罪证据时，阿豪却设下陷阱，企图将他与帮派一同消灭以独吞赃款。林峰利用自己对地形的熟悉，在废旧仓库与阿豪展开生死对决，最终虽然成功将犯罪集团一网打尽，但也付出了惨痛", "score": 2024363, "category": "crime", "detail_url": "../movie/0049.html", "poster": "../posters/0049.svg"}, {"id": "0050", "title": "金玉缘", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "爱情, 剧情, 古装", "tags": ["江南", "织造", "家族恩怨", "错爱", "缘分"], "summary_short": "金玉缘，2023年中国大陆电影，爱情, 剧情, 古装。民国初年，江南古镇。织锦世家沈家的独女沈云锦，被迫与商业宿敌顾家联姻。出嫁当日，一块据传能带来“不灭良缘”的祖传云锦《金玉缘》意外丢失，婚礼险些中断。云锦在顾家少爷顾北辰的书房里，发现了这块云锦的图样，却不知对方正是自己儿时在逃亡中失散的救命恩人。随着家族生意的明争暗斗，云锦发现自己的母亲与顾家的老爷之间，也曾有一块“金玉缘”，牵扯出一段被大火掩埋的秘密恋情。两块云锦，三代人的宿命，", "score": 2023298, "category": "drama", "detail_url": "../movie/0050.html", "poster": "../posters/0050.svg"}, {"id": "0051", "title": "雪山人生", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情、冒险、灾难", "tags": ["登山", "人性", "极地求生", "真实改编"], "summary_short": "雪山人生，2025年中国大陆电影，剧情、冒险、灾难。改编自2002年希夏邦马峰山难。由七名业余登山爱好者组成的民间登山队，在攀登海拔8027米的希夏邦马峰时，遭遇了三十年不遇的特大暴风雪。队长李想坚持“全队同进退”，拒绝了一人先下撤的提议，导致全队在海拔7500米的“死亡营地”被困三天三夜。当食物和氧气只够四个人使用时，人性的博弈正式开始：有人提议抽签，有人主张给体能最好的两个人先走求援，还有人偷偷藏起了氧气瓶。最致命的不是风雪，而是他", "score": 2025268, "category": "drama", "detail_url": "../movie/0051.html", "poster": "../posters/0051.svg"}, {"id": "0052", "title": "普西迪基地", "year": 2024, "region": "美国", "type": "剧集", "genre": "悬疑 / 犯罪 / 军旅", "tags": ["军营", "谋杀", "权力斗争", "硬汉"], "summary_short": "普西迪基地，2024年美国剧集，悬疑 / 犯罪 / 军旅。位于旧金山的普西迪军事基地，一名热衷于揭露军方贪腐的军官被发现在密室中枪身亡。宪兵队长杰克接手调查，却发现所有证据都指向自杀。随着调查深入，杰克发现死者正在调查一桩五年前杰克经手的战争罪案。为了洗清嫌疑并找到真凶，杰克必须在军方的层层阻挠下，与来自FBI的女探员合作，揭开普西迪基地光鲜外表下的毒品交易与战争谎言。", "score": 2024342, "category": "series", "detail_url": "../movie/0052.html", "poster": "../posters/0052.svg"}, {"id": "0053", "title": "欢乐人生", "year": 2019, "region": "韩国", "type": "电影", "genre": "剧情 / 家庭", "tags": ["葬礼、黑色幽默、和解、老年生活"], "summary_short": "欢乐人生，2019年韩国电影，剧情 / 家庭。固执的大哥是退休教授，自私的二姐是生意人，三弟是失意的画家，小妹是不婚族。母亲的突然离世让这四个多年未见的兄弟姐妹聚在老宅。按照母亲遗愿，他们必须一起守灵三天，期间不准离开，不准吵架，还要轮流讲述和母亲有关的快乐回忆。起初只有尴尬和争吵，但随着夜幕降临，他们翻出老照片，喝起母亲私藏的米酒，开始相互揭短、爆笑、痛哭。这三天，他们终于理解了母亲生前常说的那句话：“等你们好了，我才能走。”", "score": 2019317, "category": "drama", "detail_url": "../movie/0053.html", "poster": "../posters/0053.svg"}, {"id": "0054", "title": "第七个十字路口", "year": 2025, "region": "英国, 美国", "type": "剧集", "genre": "科幻, 悬疑, 惊悚", "tags": ["平行宇宙", "时间循环", "抉择", "公路片"], "summary_short": "第七个十字路口，2025年英国, 美国剧集，科幻, 悬疑, 惊悚。程序员伊森开车带着妻女去度假，因为导航失灵驶入了一条地图上不存在的县道。路上每隔十公里就有一个诡异的十字路口，每一次经过，他都会进入一个微妙的平行世界：妻子的职业变了、女儿失踪了、甚至他自己变成了通缉犯。每经过一个路口，现实就崩坏得更严重。在第六个路口，他发现自己根本不是程序员，而是一个试图逃离“系统”的实验体。第七个十字路口即将到来，如果他选错方向，不仅仅是他，所有平行", "score": 2025460, "category": "series", "detail_url": "../movie/0054.html", "poster": "../posters/0054.svg"}, {"id": "0055", "title": "毋愿五楼上的邻居", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "惊悚/悬疑", "tags": ["公寓", "邻居", "窥视", "复仇"], "summary_short": "毋愿五楼上的邻居，2025年中国台湾电影，惊悚/悬疑。胆小怕事的阿德搬进一栋老公寓，发现五楼的邻居极其诡异：窗帘永远紧闭，总是在深夜搬运巨大的黑色塑料袋下楼。其他住户视若无睹，劝他“毋愿（不要）去管闲事”。阿德好奇心作祟，用无人机偷窥，竟拍到了疑似分尸的画面。他报警后，警察上门却一切正常。邻居甚至热情地招待警察吃饭。阿德成了众人眼中的疯子。为了自证清白，他趁邻居外出潜入五楼，却发现那里住着一个正在等待心脏移植的小女孩，而邻居所谓的“黑色", "score": 2025447, "category": "crime", "detail_url": "../movie/0055.html", "poster": "../posters/0055.svg"}, {"id": "0056", "title": "鬼影实录5：鬼次元", "year": 2015, "region": "美国", "type": "电影", "genre": "恐怖 / 伪纪录片", "tags": ["灵异录像", "维度穿越", "家庭录像"], "summary_short": "鬼影实录5：鬼次元，2015年美国电影，恐怖 / 伪纪录片。瑞安和妻子带着女儿搬进一栋老房子，在地下室发现大量1990年代的录像带和一台老旧摄像机。瑞安出于好奇翻看录像，发现影片中记录了1988年、1949年甚至更早的住户遭遇的超自然现象。一位研究民俗的友人警告他：这栋房子每隔69年就会与“鬼次元”重叠三天，而今年恰好是重叠年。第二天，房子里的墙壁开始渗出黑色液体，女儿对着空气说话，喊一个名为“托比”的名字。瑞安架起四台摄像机全方位记录", "score": 2015348, "category": "horror", "detail_url": "../movie/0056.html", "poster": "../posters/0056.svg"}, {"id": "0057", "title": "杀戮开关", "year": 2017, "region": "美国", "type": "电影", "genre": "科幻 / 动作", "tags": ["末日", "机甲", "人机伦理", "硬核"], "summary_short": "杀戮开关，2017年美国电影，科幻 / 动作。在遥远的殖民星球“新希望”上，AI控制的机甲部队是人类对抗外星虫族的唯一防线。机械师杰克在维修一台重伤机甲时，发现驾驶员并非死于虫族，而是被机甲内置的“杀戮开关”灭口。原来，为了防止士兵投降或泄露机密，公司植入了这个无差别击杀装置。当杰克试图揭露真相时，他被宣布为叛徒，所有机甲开始追杀他。他必须黑入中央系统，在杀戮开关激活前，向全星球播放那段被掩埋的录音。", "score": 2017402, "category": "sci-fi", "detail_url": "../movie/0057.html", "poster": "../posters/0057.svg"}, {"id": "0058", "title": "两个头一个大", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧/科幻", "tags": ["连体人", "荒诞", "兄弟情", "大脑共享"], "summary_short": "两个头一个大，2025年中国大陆电影，喜剧/科幻。学渣弟弟张大头和学霸哥哥张小头是异卵双胞胎，因为基因突变导致性格水火不容。在一次离奇的实验室爆炸事故后，两人被迫进行了“紧急侧向连接手术”，从此成为了“侧侧连体人”，共用一具躯干和部分脏器。更荒诞的是，高考在即，他们的父亲要求两人“一起考试”：哥哥负责答题，弟弟负责休息，目标是总分突破600分。张大头却只想捣乱，故意在哥哥思考数学题时放摇滚乐。两人在学校里闹出了无数笑话：上厕所需要投票、", "score": 2025369, "category": "comedy", "detail_url": "../movie/0058.html", "poster": "../posters/0058.svg"}, {"id": "0059", "title": "明日", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "科幻 / 灾难", "tags": ["时间循环", "末日", "硬科幻", "地外文明"], "summary_short": "明日，2023年中国大陆电影，科幻 / 灾难。物理学家林燃发现一种未知粒子正在疯狂吞噬地球的“普朗克时间”，这意味着时间本身正在被撕裂。除了林燃之外，所有人都感知不到“明天”在缩短，他们甚至觉得24小时就是永恒。为了阻止时间被彻底归零，林燃必须在一个不断坍塌的日内瓦、上海和东京三维战场中，破解一组来自高维文明的“时间垃圾”密码。她发现，吞噬时间的并非敌人，而是另一个平行宇宙试图通过“时间回收”来拯救他们自己的家园。在最后一个“小时”里，", "score": 2023316, "category": "sci-fi", "detail_url": "../movie/0059.html", "poster": "../posters/0059.svg"}, {"id": "0060", "title": "巴图快跑", "year": 2023, "region": "中国大陆 / 蒙古", "type": "电影", "genre": "剧情 / 家庭 / 运动", "tags": ["蒙古马", "草原", "父子", "励志", "儿童"], "summary_short": "巴图快跑，2023年中国大陆 / 蒙古电影，剧情 / 家庭 / 运动。巴图从小在城市长大，对草原和蒙古马文化十分陌生。暑假被送回爷爷家，爷爷的老马“风暴”因年老体衰即将被卖掉。巴图不忍，与爷爷打赌：如果他能骑着“风暴”完成草原那达慕的“极限耐力赛”，马就留下。一个从未骑过马的孩子，一匹垂垂老矣的病马，开始了不可能的备战。在训练中，巴图理解了蒙古马“吃苦耐劳、一往无前”的精神，也与爷爷冰冷的隔阂逐渐消融。比赛日暴雨倾盆，巴图与“风暴”在泥", "score": 2023241, "category": "drama", "detail_url": "../movie/0060.html", "poster": "../posters/0060.svg"}, {"id": "0061", "title": "非常四侠之天罗地网", "year": 2020, "region": "中国大陆", "type": "网络电影", "genre": "动作，武侠，喜剧", "tags": ["山寨，夺宝，机关术"], "summary_short": "非常四侠之天罗地网，2020年中国大陆网络电影，动作，武侠，喜剧。一个名为“非常四侠”的民间组织，由废柴剑客、贪财镖师、失忆歌姬和只会说书的神棍组成。某天，他们听闻传说中的“麒麟血玉”重出江湖，为了赏金和名声，四人决定出手抢夺。然而，当他们找到藏宝地点时，才发现这是一个陷阱。隐世多年的机关术家族后裔为了复仇，布下了名为“天罗地网”的巨大机关城，将所有寻宝者困在其中。四侠必须利用各自那点不靠谱的本事，破解各种匪夷所思的机关：从毒烟密室到倒", "score": 2020303, "category": "crime", "detail_url": "../movie/0061.html", "poster": "../posters/0061.svg"}, {"id": "0062", "title": "沉默的心", "year": 2024, "region": "丹麦", "type": "电影", "genre": "剧情, 家庭", "tags": ["北欧", "死亡", "家庭聚会", "悲喜剧"], "summary_short": "沉默的心，2024年丹麦电影，剧情, 家庭。母亲琳恩患有渐冻症，她决定在生日那天举办一场聚会，然后在当晚结束自己的生命。她的大女儿带着满腹牢骚的丈夫回来，小女儿则带着那个让全家都不喜欢的嬉皮士男友。表面上大家是为了陪伴母亲最后一天，实际上却各怀鬼胎：有人惦记着遗产，有人想借着母亲的死出书，还有人在纠结是否要告诉母亲父亲当年的出轨真相。琳恩其实早就知道了所有的事情，她看着这群子女像小丑一样表演。在最后的晚餐上，琳恩没有指责任何人，她只是用", "score": 2024245, "category": "drama", "detail_url": "../movie/0062.html", "poster": "../posters/0062.svg"}, {"id": "0063", "title": "血宴2", "year": 2005, "region": "美国", "type": "电影", "genre": "恐怖, 血腥", "tags": ["血浆", "邪教", "密室", "cult"], "summary_short": "血宴2，2005年美国电影，恐怖, 血腥。上一部屠杀的五年后，唯一幸存者艾琳变成了复仇女神。她假扮成记者，混入了一个由极端环保主义富豪举办的私密宴席。宾客都是当年屠杀案的资助者。这一次，厨师长更变态，他将餐厅设计成了七个房间，每个房间对应一种“原罪”。艾琳本想逐个击破，却发现自己早已落入了厨师长设计的“游戏”中。厨师长逼她做出选择：是看着新朋友被杀，还是亲手割下仇人的舌头。血红色的香槟、用人骨做成的餐具，一场关于欲望与生存的终极血宴拉开", "score": 2005314, "category": "horror", "detail_url": "../movie/0063.html", "poster": "../posters/0063.svg"}, {"id": "0064", "title": "婆婆和妈妈第二季", "year": 2024, "region": "中国大陆", "type": "综艺", "genre": "真人秀 / 家庭", "tags": ["代际冲突", "明星家庭", "观察室"], "summary_short": "婆婆和妈妈第二季，2024年中国大陆综艺，真人秀 / 家庭。本季打破常规，不再仅仅是记录自家矛盾，而是推出“婆媳交换体验”。让性格强势的“麻辣婆婆”去给温柔派的明星媳妇当家，而擅长隐忍的“受气婆婆”则被送到叛逆儿媳家中。观察室由第一季嘉宾及心理学家坐镇，实时分析每一次冲突背后的情感逻辑。交换过程中，有人看到了自己母亲的影子，有人开始理解对方的不易。当原生家庭的相处模式被强行置入陌生环境，那些最尖锐的代际矛盾开始出现意想不到的软化。", "score": 2024101, "category": "series", "detail_url": "../movie/0064.html", "poster": "../posters/0064.svg"}, {"id": "0065", "title": "随风而逝的记忆", "year": 2025, "region": "日本", "type": "电影", "genre": "剧情, 科幻", "tags": ["记忆删除", "阿尔茨海默症", "亲情", "催泪"], "summary_short": "随风而逝的记忆，2025年日本电影，剧情, 科幻。近未来，科技公司“白熊”推出“记忆净化”服务，可以精准删除指定记忆。年迈的退休教授佐藤找到这家公司，要求删除关于儿子健二的全部记忆。工作人员震惊，因为健二并非早逝或作恶，而是全球顶尖的脑科学专家，也是公司的技术顾问。佐藤坚持删除，手术很成功。然而术后，佐藤发现自己总会莫名地流泪，钢琴上摆着的照片里有一个空白的影子，阳台上的花被修剪成了他不认识的形状。直到他看见电视上正在领奖的健二，这位忘", "score": 2025378, "category": "drama", "detail_url": "../movie/0065.html", "poster": "../posters/0065.svg"}, {"id": "0066", "title": "荣光五千里", "year": 2026, "region": "大陆", "type": "电视剧", "genre": "剧情，历史，公路", "tags": ["长征，信仰，徒步，群像，主旋律"], "summary_short": "荣光五千里，2026年大陆电视剧，剧情，历史，公路。1935年，红军长征过草地。宣传队的五个年轻人：文弱书生顾鸿鸣、泼辣女兵铁妞、神枪手石头、伙夫老赵以及被俘后加入红军的国民党通讯兵陈怀远，因一场夜袭与大部队失散。他们仅有一张残缺的地图、半袋干粮和一台损坏的电台。面对四面八方围追堵截的敌军、吃人的沼泽和极寒的雪山，这五个人从互不信任、争吵不断，到为了同一个信仰紧紧抱在一起。顾鸿鸣用知识指引方向，铁妞用歌声鼓舞士气，石头用枪法保驾护航。在", "score": 2026250, "category": "series", "detail_url": "../movie/0066.html", "poster": "../posters/0066.svg"}, {"id": "0067", "title": "宙斯之血第一季", "year": 2024, "region": "美国", "type": "动画剧集", "genre": "动作 / 奇幻 / 冒险", "tags": ["希腊神话，众神之战，半神觉醒，血脉诅咒"], "summary_short": "宙斯之血第一季，2024年美国动画剧集，动作 / 奇幻 / 冒险。住在希腊海岛的青年赫利俄斯，自幼被母亲告诫不可靠近大海。当海怪撕碎渔船，他体内爆发出的金色雷电拯救了村民，也引来了奥林匹斯山的追杀者。天后赫拉派出血腥猎犬与青铜巨人，而自称“导师”的半人马凯隆告诉他：你是宙斯在人间的最后一个儿子，你的血可以解开泰坦的封印。第一季中，赫利俄斯被迫离开家乡，在逃亡中学会控制雷霆之力，同时结识了叛逆的雅典娜之女、被放逐的火神学徒。随着赫拉发动对", "score": 2024288, "category": "fantasy", "detail_url": "../movie/0067.html", "poster": "../posters/0067.svg"}, {"id": "0068", "title": "小可爱娜斯佳第五季", "year": 2023, "region": "俄罗斯", "type": "剧集", "genre": "奇幻， 家庭， 冒险", "tags": ["俄罗斯民间传说， 魔法， 少女， 四季精灵"], "summary_short": "小可爱娜斯佳第五季，2023年俄罗斯剧集，奇幻， 家庭， 冒险。本季开篇，娜斯佳刚学会控制火之力量，却收到一封来自北冰洋深处的信——冬之精灵“寒婆婆”即将退位，选中娜斯佳继承冬之杖。但继承仪式需要集齐春、夏、秋、冬四位精灵的眼泪，而秋之精灵已被反派“永夜之主”囚禁在镜中世界。娜斯佳和好友小熊米沙、雪鸮格鲁沙穿越霜冻森林、地下熔岩河与时间倒流的钟楼塔。途中她发现永夜之主竟是寒婆婆的哥哥，因不满人类砍伐森林而被放逐千年。娜斯佳没有用暴力打败", "score": 2023236, "category": "fantasy", "detail_url": "../movie/0068.html", "poster": "../posters/0068.svg"}, {"id": "0069", "title": "金色少年", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情， 青春， 运动", "tags": ["田径， 小镇青年， 父子关系， 励志"], "summary_short": "金色少年，2023年中国大陆电影，剧情， 青春， 运动。曾被誉为“金色少年”的长跑天才阿龙，因在省队顶撞教练被开除，灰溜溜地回到了即将被拆迁改建成商场的老体校。体校里只剩下几个练不上去也退不掉的“问题学生”：一个只会玩手机的胖子，一个患有哮喘的女孩，一个腿短的小个子。为了保住这所承载了父亲一生心血的体校，阿龙决定重组接力队，参加一个月后的全市青少年田径锦标赛。他放下了曾经的骄傲，用近乎自虐的方式训练自己，也重新理解了父亲的严厉。决赛中，", "score": 2023237, "category": "drama", "detail_url": "../movie/0069.html", "poster": "../posters/0069.svg"}, {"id": "0070", "title": "北海食神", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 奇幻", "tags": ["美食", "市井", "反转", "民间传说"], "summary_short": "北海食神，2025年中国大陆电影，喜剧 / 奇幻。老周在北京北海公园卖了二十年炸酱面，味道普通但人缘极好。一天，一档美食节目将他错认成二十年前神秘失踪的“中华食神”郑八方。老周本想澄清，却发现所有官方资料、老厨师证言甚至DNA快检都指向自己。更诡异的是，他随手做的炸酱面开始发光，食客集体流泪。老周在“我是骗子还是真是失忆食神”的困惑中越陷越深，直到一位盲人老奶奶尝了一口他的面，轻声说：“这不是郑八方的味道，这是你死去的哥哥周大江的味道。", "score": 2025369, "category": "comedy", "detail_url": "../movie/0070.html", "poster": "../posters/0070.svg"}, {"id": "0071", "title": "僵尸飞鲨", "year": 2022, "region": "美国", "type": "电影", "genre": "恐怖, 科幻, 动作, 灾难", "tags": ["B级片", "鲨鱼", "僵尸", "血浆", "无脑爽片"], "summary_short": "僵尸飞鲨，2022年美国电影，恐怖, 科幻, 动作, 灾难。太平洋深处的钻井平台挖出了一具保存完好的史前巨鲨“旋齿鲨”尸体。军方生物实验室将其复活为生化兵器，代号“僵尸飞鲨”——它的咬合器官中植入了能使死者复活的纳米病毒。在一次实验事故中，僵尸飞鲨逃入公海，它咬过的海洋生物全部变成丧尸鲨鱼，形成了一股从海底席卷而来的尸潮。一座海岛度假村瞬间沦为人间炼狱，被困的游客们发现，对付丧尸可以用枪，但对付一群能在水面上“飞行”的丧尸鲨鱼，他们需要", "score": 2022497, "category": "sci-fi", "detail_url": "../movie/0071.html", "poster": "../posters/0071.svg"}, {"id": "0072", "title": "练胆儿", "year": 2018, "region": "中国大陆", "type": "电影", "genre": "惊悚心理", "tags": ["直播", "闹鬼", "心理战", "反转", "校园"], "summary_short": "练胆儿，2018年中国大陆电影，惊悚心理。为赚取高额奖金，五名大学生进入一栋荒废二十年的医院进行“练胆儿”直播。队长阿豪负责气氛，眼镜男负责科学拆解，胆小的胖子负责尖叫，两个女生则担任颜值担当。起初一切都在预料之中——假鬼、道具、音效。但直播到凌晨三点，弹幕突然开始发出他们从未读过的死人名字。更诡异的是，每一次“假死”镜头后，队员人数会莫名其妙减少一人，而回放里却多出一个从未参与报名的人影。当最后三人逃出医院，警察却发现：直播间同时在线", "score": 2018322, "category": "horror", "detail_url": "../movie/0072.html", "poster": "../posters/0072.svg"}, {"id": "0073", "title": "红尘", "year": 1997, "region": "中国台湾", "type": "剧集", "genre": "爱情, 家庭, 年代", "tags": ["乡土剧", "苦情", "大家族", "台语发音"], "summary_short": "红尘，1997年中国台湾剧集，爱情, 家庭, 年代。1920年代，台湾鹿港茶商陈家有三千金：大姐秀莲温顺，被迫嫁给仇家之子；二姐秀珠叛逆，跟抗日书生私奔；三妹秀美最小，却最清醒，她选择留下来继承茶庄。剧情跨越30年，经历日本殖民、太平洋战争、二二八事件。秀莲的丈夫后来当了汉奸，秀莲亲手在茶里下毒。秀珠的书生被秘密警察带走，从此再无音讯，她独自养大孩子，晚年疯癫。秀美把茶庄做成全台最大，但终身未嫁。最后三姐妹在老宅天井里喝茶，秀珠突然清醒", "score": 1997263, "category": "series", "detail_url": "../movie/0073.html", "poster": "../posters/0073.svg"}, {"id": "0074", "title": "大三儿", "year": 2018, "region": "中国大陆", "type": "电影 (纪录片)", "genre": "纪录片", "tags": ["小人物", "身体障碍者", "西藏朝圣", "真实记录"], "summary_short": "大三儿，2018年中国大陆电影 (纪录片)，纪录片。叶三，绰号“大三儿”，身高1.1米，在内蒙古一个铜业公司当保洁员。他有一个梦想：去西藏看一次真正的布达拉宫。但因为身体原因和高原风险，家人和朋友都反对。本片导演最初是想拍他的日常，被他的执念打动，决定跟拍他的西藏之旅。剧组用众筹的方式为他凑齐路费。途中他经历了严重高反、轮胎爆胎、甚至差点掉下悬崖。最终他站在布达拉宫广场前，像个孩子一样哭了。返回后，生活依旧，他每天还是拖地、喂猫、跟同事", "score": 2018205, "category": "doc", "detail_url": "../movie/0074.html", "poster": "../posters/0074.svg"}, {"id": "0075", "title": "驱魔童", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "恐怖, 惊悚, 民俗", "tags": ["宫庙", "附身", "儿童", "本土信仰", "仪式感"], "summary_short": "驱魔童，2025年中国台湾电影，恐怖, 惊悚, 民俗。台南老宫庙“太子宫”的主持乩童在做法时暴毙。按照神谕，必须由新的“神之子”继承神威。令人意外的是，被选中的竟是一个被母亲抛弃、患有重度自闭症的八岁男孩小杰。小杰不会说话，无法沟通，却在被强行附体后展现出超人的力量和诡异的指令。负责照顾小杰的年轻社工雅婷发现，每当小杰被“太子爷”上身，宫庙的信徒就会发生意外死亡。雅婷试图阻止仪式，却发现这场驱魔的背后，隐藏着一场争夺宫庙财产的阴谋，而那", "score": 2025374, "category": "horror", "detail_url": "../movie/0075.html", "poster": "../posters/0075.svg"}, {"id": "0076", "title": "稚女情深", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭 / 伦理", "tags": ["母女关系", "绝症", "和解", "催泪"], "summary_short": "稚女情深，2024年中国大陆电影，剧情 / 家庭 / 伦理。念安从小觉得母亲偏爱成绩优异的姐姐，处处针对自己。在一次激烈争吵后，母亲打了她一耳光，念安愤而离家，断绝联系十年。当姐姐哭着打来电话说母亲患上了早发性阿兹海默症，记忆正在消失，念安回到了那个冰冷的小城。让她崩溃的是，母亲时而清醒时而糊涂，但在糊涂时，母亲总会对着念安喊“小念安乖，妈妈给你扎辫子”。她只记得女儿六岁时天真无邪的样子，完全不认识眼前这个30岁、浑身是刺的女人。为了能", "score": 2024299, "category": "drama", "detail_url": "../movie/0076.html", "poster": "../posters/0076.svg"}, {"id": "0077", "title": "姐妹狂欢行", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧, 冒险, 女性", "tags": ["公路电影", "闺蜜情", "婚前旅行", "爆笑"], "summary_short": "姐妹狂欢行，2024年美国电影，喜剧, 冒险, 女性。准新娘佐伊被完美主义的婚礼策划逼到崩溃边缘，她的三位死党——毒舌职场女强人、佛系单亲妈妈以及社恐游戏设计师——决定用一场疯狂的自驾游帮她“回血”。四人从洛杉矶出发，目的地是维加斯的脱衣舞俱乐部，但路上先是错把忏悔车当成了餐车，又意外救了一只被黑帮追杀的羊驼。随着信用卡被刷爆、手机掉进马桶，原本精致的单身派对变成了沙漠生存挑战。在躲避赏金猎人的过程中，佐伊终于坦白自己恐婚的真实原因，而", "score": 2024322, "category": "comedy", "detail_url": "../movie/0077.html", "poster": "../posters/0077.svg"}, {"id": "0078", "title": "我非笼鸟", "year": 2027, "region": "中国大陆", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["女性觉醒", "婚姻牢笼", "反转"], "summary_short": "我非笼鸟，2027年中国大陆电影，剧情 / 悬疑。妻子林笙住在丈夫设计的智能别墅里，虽然衣食无忧，但去哪都有“安全监控”。丈夫声称是出于爱和焦虑。林笙逐渐感到窒息，开始在花园角落挖洞排解。某天，警察突然造访，告诉她隔壁发现了尸骨，且时间线对不上丈夫的出差记录。林笙这才发现自己从未走出过这栋房子，所谓的“丈夫”其实是一个已死之人留下的AI全息投影，而真实自己早在三年前就因试图逃离而失忆。", "score": 2027378, "category": "drama", "detail_url": "../movie/0078.html", "poster": "../posters/0078.svg"}, {"id": "0079", "title": "雪地黄金犬2", "year": 1994, "region": "美国", "type": "电影", "genre": "冒险, 家庭", "tags": ["狗", "阿拉斯加", "淘金", "续集", "感人"], "summary_short": "雪地黄金犬2，1994年美国电影，冒险, 家庭。继承了父亲的冒险精神，小男孩杰克在阿拉斯加的废弃金矿发现了一块足有拳头大的“愚人金”（黄铁矿）。虽然不值钱，但他视为珍宝。与此同时，第一集中那只传奇雪橇犬“白牙”的后代“雪球”成为了他的伙伴。一个贪婪的矿商误以为杰克发现了真正的金矿脉，派出手下夺取土地。更糟的是，一只体型庞大的野生狼王盯上了这片矿区，因为这里曾是它的领地。寒冬来临，杰克和雪球被困在金矿木屋。矿商手下破坏了他们的雪橇，狼王则", "score": 1994265, "category": "drama", "detail_url": "../movie/0079.html", "poster": "../posters/0079.svg"}, {"id": "0080", "title": "亲爱的义祁君", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "古装 / 甜宠 / 奇幻", "tags": ["穿越", "先婚后爱", "喜剧", "权谋", "医女"], "summary_short": "亲爱的义祁君，2023年中国大陆剧集，古装 / 甜宠 / 奇幻。法医苏晚在解剖一具古代尸体时触电穿越，醒来发现自己成了即将嫁给义祁君的和亲新娘。入洞房时，王爷祁夜突然吐血倒地，满府太医束手无策。苏晚上手一查：中毒，深度昏迷，再不手术活不过今晚。她不顾劝阻，掏出随身携带的法医手术刀，当场给王爷开胸排毒。王爷醒来后，看着这个满手血的“王妃”，第一句话是：“你到底是什么妖孽？”苏晚答：“我是你老婆，也是你的主治医生。”从此，苏晚一边用现代法医", "score": 2023267, "category": "series", "detail_url": "../movie/0080.html", "poster": "../posters/0080.svg"}, {"id": "0081", "title": "逍遥法外杀错人", "year": 2015, "region": "美国", "type": "剧集", "genre": "悬疑 / 犯罪 / 惊悚", "tags": ["冤案", "真凶", "律师", "高智商"], "summary_short": "逍遥法外杀错人，2015年美国剧集，悬疑 / 犯罪 / 惊悚。五年前，流浪汉麦克被指控杀害了一名女大学生，他因无力辩护而认罪，被判二十年。五年后的一个雨夜，一位名叫艾伦的著名人权律师突然找上他，声称发现了当年案件的重大瑕疵，要帮他翻案。麦克欣喜若狂，却在某天夜里无意中听到艾伦打了一个电话，电话那头提到了只有真凶才知道的作案细节。麦克惊恐地意识到：艾伦就是真凶，而他帮自己翻案，只是为了让“真凶已经伏法”这件事成为既定事实，从而永远脱身。麦", "score": 2015444, "category": "crime", "detail_url": "../movie/0081.html", "poster": "../posters/0081.svg"}, {"id": "0082", "title": "爆阴毒家族", "year": 2012, "region": "香港地区", "type": "电影", "genre": "喜剧， 恐怖， 黑色幽默", "tags": ["祖传诅咒， 整蛊， 港式无厘头"], "summary_short": "爆阴毒家族，2012年香港地区电影，喜剧， 恐怖， 黑色幽默。曾家祖训：“宁得罪君子，莫得罪曾家。”三百年来，曾家人以阴损招数帮人报仇为生：扎小人、种情降、放蛊毒，无所不用。然而诅咒反噬了：每一代长子活不过三十。这一代的曾阴德还有三个月满三十，他决定“从良”——开了一家正经心理咨询诊所。结果求助者全是来求整蛊的：被霸凌的想报复，被出轨的想下咒。曾阴德一边念着“我是心理咨询师”，一边偷偷扎针。当他放弃自救帮助一个被家暴的妇女成功离婚后，诅", "score": 2012357, "category": "horror", "detail_url": "../movie/0082.html", "poster": "../posters/0082.svg"}, {"id": "0083", "title": "大弑之日", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["反乌托邦，屠杀日，宗教狂热，生存游戏"], "summary_short": "大弑之日，2026年美国电影，恐怖 / 惊悚。近未来，美国政府通过《净化日》修正案，每年有24小时，所有犯罪行为（包括谋杀）合法。主角伊森是坚定的和平主义者，在那天他带着家人躲进地下掩体。然而，一群狂热的“新十字军”教徒破门而入，他们不抢钱，只为“净化”不信者。伊森眼睁睁看着妻子被杀，女儿被掳走。绝望中，他被迫激活了埋在后院的军火库——他其实是退役特种兵。他孤身闯入被血与火笼罩的城市，发现所谓的“大弑之日”根本不是政府说的“释放民众压力", "score": 2026437, "category": "horror", "detail_url": "../movie/0083.html", "poster": "../posters/0083.svg"}, {"id": "0084", "title": "黑色蝴蝶", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "悬疑 / 犯罪", "tags": ["连环杀手、双重人格、蝴蝶标记、刑侦"], "summary_short": "黑色蝴蝶，2025年中国大陆剧集，悬疑 / 犯罪。十五年跨度，六起看似毫无关联的悬案。新调来的刑警队长江阳在整理旧档案时，发现每份卷宗的角落都画着一只形态各异的黑色蝴蝶。循着线索追查下去，画蝴蝶的人指向了警局档案室管理员——沉默寡言的苏晓。但随着调查深入，江阳发现苏晓有严重的解离性身份障碍，那个画蝴蝶的“她”并不知道自己在犯罪。更诡异的是，苏晓的双重人格里，一个在试图阻止谋杀，另一个却在给真凶提供完美不在场证明。当江阳试图唤醒苏晓的主人", "score": 2025338, "category": "series", "detail_url": "../movie/0084.html", "poster": "../posters/0084.svg"}, {"id": "0085", "title": "未寄出的信", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情 / 爱情", "tags": ["书信", "错位时空", "含蓄"], "summary_short": "未寄出的信，2024年英国电影，剧情 / 爱情。伦敦时装学院的学生艾玛在祖父去世后，回到威尔士乡村的老宅整理遗物。她在阁楼发现了一个铁皮箱，里面是上百封从未寄出的信，收件人全都写着“L”。信中字迹陌生，笔触深情，讲述了一段跨越40年的隐秘情感。艾玛顺着线索找到了一位独居在灯塔边的老画家，而这位画家，正是信中“L”的原型。更让艾玛震惊的是，画家拿出了一箱同样从未寄出的回信。两代人，两箱信，一个从未被说出口的秘密在黄昏的海风中缓缓展开。", "score": 2024365, "category": "drama", "detail_url": "../movie/0085.html", "poster": "../posters/0085.svg"}, {"id": "0086", "title": "魔弹战记龙剑道", "year": 2023, "region": "日本", "type": "剧集", "genre": "特摄 / 动作 / 奇幻", "tags": ["英雄", "热血", "平成风", "剑与魔法"], "summary_short": "魔弹战记龙剑道，2023年日本剧集，特摄 / 动作 / 奇幻。平凡高中生龙崎一矢在放学路上，遭遇了能将建筑物“编程”为金属怪物的诡异现象“代码化”。危急时刻，他被一把从异空间飞来的龙形魔剑“烈光”选中，变身为身披赤甲的战士“龙剑道”。然而另一位来自魔界的赏金猎人——冷酷的枪手银城，也奉魔界领主之命前来回收这些暴走的“金属魔偶”。两人理念不同，龙剑道要守护，银城则只为完成任务，被迫组成最别扭的搭档。随着战斗深入，他们发现“代码化”背后是名", "score": 2023366, "category": "series", "detail_url": "../movie/0086.html", "poster": "../posters/0086.svg"}, {"id": "0087", "title": "采蘑菇的夫妻", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑，剧情，农村", "tags": ["森林，失踪，秘密，夫妻"], "summary_short": "采蘑菇的夫妻，2025年中国大陆电影，悬疑，剧情，农村。长白山脚下的林场小镇，老李和秀芬是人人羡慕的模范夫妻。每年九月，他们都会进山采蘑菇，一待就是三天。今年回来时，秀芬的篮子里除了松茸、猴头菇，还有一颗用布包着、已经白骨化的人头。老李报警说是在溪边捡到的。警方DNA鉴定，人头属于二十三年前失踪的林业工人赵某——正好是老李当年的情敌。小镇开始疯传是老李杀了赵某。老李被拘留，秀芬却在审讯室里说出惊人事实：人头是她挖出来的，二十三年前那个雨", "score": 2025387, "category": "drama", "detail_url": "../movie/0087.html", "poster": "../posters/0087.svg"}, {"id": "0088", "title": "恰克与巴克", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧、公路、黑色幽默", "tags": ["塑料兄弟、二手车、遗产争夺、假扮富豪"], "summary_short": "恰克与巴克，2024年美国电影，喜剧、公路、黑色幽默。恰克是个靠赊账过日子的酒鬼，巴克是个满嘴跑火车的二手车销售。两人在酒吧偶遇，发现一则新闻：石油大亨老雷蒙德去世，遗嘱称要将全部遗产留给年轻时走散的一对双胞胎儿子。恰克和巴克决定假扮这对双胞胎。他们伪造DNA报告、模仿德州口音、还请了个演员假扮童年邻居。一切顺利，遗嘱执行人甚至已经准备转账了。就在签字前一刻，管家打开了一辆一直停在车库里的古董车后备箱，里面爬出一个蓬头垢面的男人——正是", "score": 2024319, "category": "comedy", "detail_url": "../movie/0088.html", "poster": "../posters/0088.svg"}, {"id": "0089", "title": "来去美国2", "year": 2021, "region": "美国", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["艾迪·墨菲", "续集", "非洲王子", "文化冲突"], "summary_short": "来去美国2，2021年美国电影，喜剧 / 家庭。时隔三十多年，扎门达国王阿基姆又回到了让他心动的纽约皇后区。这次，他发现自己在第一次访美期间，竟然有一个失散多年的儿子拉维尔。为了不让王位落入奸人之手，阿基姆必须立刻找到拉维尔，并把他训练成合格的继承人。然而，拉维尔从小在平民家庭长大，是一个崇尚街头文化的嘻哈青年，他对宫廷礼仪和所谓“王子身份”嗤之以鼻。于是，老国王不得不再次隐藏身份，以一个普通非洲老父亲的模样住进儿子的破公寓，体验当代美", "score": 2021281, "category": "comedy", "detail_url": "../movie/0089.html", "poster": "../posters/0089.svg"}, {"id": "0090", "title": "梦想改造家第12季", "year": 2022, "region": "中国大陆", "type": "剧集", "genre": "真人秀, 纪录片", "tags": ["装修", "设计", "情感", "社会观察"], "summary_short": "梦想改造家第12季，2022年中国大陆剧集，真人秀, 纪录片。第十二季回归，节目组将挑战更加极端的居住环境。首期节目，设计师需要为一对住在悬崖洞穴里的守林人夫妇改造房屋，既要保留自然风貌又要引入现代供暖系统。中期，一位退休教师希望将自己家楼下的废旧下水道改造成社区图书馆。本季最大的看点在于，设计师们不仅要解决工学难题，还要调解委托人复杂家庭关系背后的情感诉求，例如为一位阿尔茨海默症老人打造安全且唤醒记忆的迷宫式花园。", "score": 2022211, "category": "series", "detail_url": "../movie/0090.html", "poster": "../posters/0090.svg"}, {"id": "0091", "title": "硫磺岛的英雄们", "year": 2029, "region": "日本 / 美国", "type": "电影", "genre": "历史 / 战争 / 剧情", "tags": ["二战", "真实改编", "英雄", "反思"], "summary_short": "硫磺岛的英雄们，2029年日本 / 美国电影，历史 / 战争 / 剧情。本片根据真实幸存者口述改编。1945年硫磺岛战役中，三名年轻的日本士兵在战壕里奇迹般地存活了下来，尽管他们并未做出任何惊天动地的壮举。战后，由于幸存者稀少，军国主义政府将他们包装成“硫磺岛的英雄”，让他们到处做巡回演讲，宣传战争的“伟大”。然而，这三人内心充满了对战争的恐惧和对死去战友的愧疚。他们厌恶被当作政治工具，却无力反抗。几十年过去了，他们垂垂老矣，一个美国老", "score": 2029238, "category": "doc", "detail_url": "../movie/0091.html", "poster": "../posters/0091.svg"}, {"id": "0092", "title": "惊速追缉令", "year": 2024, "region": "美国", "type": "电影", "genre": "动作，犯罪，惊悚", "tags": ["飞车，复仇，卧底，雨夜，飙车"], "summary_short": "惊速追缉令，2024年美国电影，动作，犯罪，惊悚。隐退赛车手杰森曾因一场致命车祸告别赛道，如今经营着一家小型修车厂。某夜，他接到神秘电话，女儿被绑架，歹徒要求他在三小时内驾车穿越全城，拦截一辆运送关键证据的黑色卡车。杰森重操旧业，驾驶改装肌肉车闯入暴雨中的高速路。沿途他遭遇黑帮截杀、警方围堵，更发现绑架案背后牵扯到一桩腐败警察主导的毒品走私网。随着速度飙升，杰森逐渐接近真相：女儿并非无辜受害者，而是卧底探员。最终在跨海大桥上，他以惊险的", "score": 2024431, "category": "crime", "detail_url": "../movie/0092.html", "poster": "../posters/0092.svg"}, {"id": "0093", "title": "大雄与绿之巨人传", "year": 2025, "region": "日本", "type": "电影", "genre": "动画，科幻", "tags": ["哆啦A梦，环保，原创"], "summary_short": "大雄与绿之巨人传，2025年日本电影，动画，科幻。大雄在后山发现了一棵发着微光的神秘树苗，他将其取名为“绿宝”。在哆啦A梦的道具帮助下，绿宝一夜之间长成了参天大树，并且整座城市都开始疯狂生长出各种奇异植物。起初人们欢呼这是环保的胜利，但植物们很快开始攻击建筑物和人类，仿佛有了意识。大雄等人利用道具进入植物的集体意识空间，发现绿宝其实是外星文明投放的“星球改造种子”，目的是将地球改造成适合它们种族居住的植物星球。而唤醒绿宝的，正是大雄纯粹", "score": 2025364, "category": "sci-fi", "detail_url": "../movie/0093.html", "poster": "../posters/0093.svg"}, {"id": "0094", "title": "将门风云", "year": 2024, "region": "中国", "type": "电视剧", "genre": "剧情， 历史， 战争", "tags": ["军人世家， 三代， 抗战， 家族史诗， 忠诚"], "summary_short": "将门风云，2024年中国电视剧，剧情， 历史， 战争。故事从1937年开始，北方大户周家的长子周振国弃笔从戎，成为抗日战场上令敌人闻风丧胆的虎将。解放后，他因性格刚烈在特殊年代被打倒，长子周卫东在父亲冤案阴影下参军，在对越自卫反击战中成为战斗英雄，却因“成分问题”迟迟无法入党。第三代周海洋和平年代入伍，成为维和部队的一员，在非洲战场上经历了另一种形式的战争。三代人分别经历了抗日战争、对越反击战和维和行动，每一代都在用自己的方式向父辈证明", "score": 2024256, "category": "series", "detail_url": "../movie/0094.html", "poster": "../posters/0094.svg"}, {"id": "0095", "title": "有组织的工作", "year": 2024, "region": "意大利", "type": "剧集", "genre": "剧情 / 犯罪 / 黑色幽默", "tags": ["职场", "黑帮", "讽刺", "办公室政治"], "summary_short": "有组织的工作，2024年意大利剧集，剧情 / 犯罪 / 黑色幽默。性格懦弱的会计师文森佐因为失业，阴差阳错应聘上了一家“特殊物流公司”——其实就是本地黑手党的财务部。上班第一天，他发现黑帮竟然实行严格的“工作日清制”，有考勤、末位淘汰和绩效奖金。教父甚至每周开“复盘会”，用 Excel 表格分析“业务”产出比。文森佐被迫参与各种奇葩任务：为枪战做预算、给贿赂做账目摊销、计算勒索的投资回报率。当他试图用正规财务手段“优化”黑帮流程时，竟然", "score": 2024336, "category": "series", "detail_url": "../movie/0095.html", "poster": "../posters/0095.svg"}, {"id": "0096", "title": "猛兽列车", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动作 / 灾难 / 惊悚", "tags": ["劫持", "密闭车厢", "猛兽出笼", "生死时速"], "summary_short": "猛兽列车，2025年中国大陆电影，动作 / 灾难 / 惊悚。基因实验失败的超级狮虎兽在运输途中因电击麻醉失效而暴走。更糟的是，一群雇佣兵为了抢夺车厢内的基因样本，炸断了列车的刹车系统。列车以300公里时速冲向终点的市区。车厢被分割成数个独立空间：第一节是狂暴的狮虎兽，第二节是变异的巨型鳄鱼，第三节是释放的神经毒气。退役特种兵高健与前列车员苏兰必须在半小时内穿越这三节地狱车厢，抵达车头恢复刹车。他们没有任何重型武器，只能用灭火器、扳手和高", "score": 2025381, "category": "crime", "detail_url": "../movie/0096.html", "poster": "../posters/0096.svg"}, {"id": "0097", "title": "哭婴径", "year": 2025, "region": "马来西亚", "type": "电影", "genre": "恐怖，民俗，悬疑", "tags": ["南洋邪术，婴灵，山路怪谈，禁忌，因果报应"], "summary_short": "哭婴径，2025年马来西亚电影，恐怖，民俗，悬疑。摄影师阿豪为了拍摄灵异素材，深入马来西亚雨林，在当地人口中得知“哭婴径”的传说：二战时期，日军在此屠杀村民，孕妇被剖腹取子，此后山路每夜都有婴儿哭声，踏入者必死。阿豪不信邪，带着夜视设备独自进山。他录到了哭声，也录到了阴影中的爬行物。当他试图离开时，发现所有出口都变成了循环的泥路。他开始看到幻象：一个没有五官的女人抱着婴儿缓缓走来。阿豪调查历史资料后震惊地发现，当年屠杀中唯一幸存的女婴被", "score": 2025457, "category": "horror", "detail_url": "../movie/0097.html", "poster": "../posters/0097.svg"}, {"id": "0098", "title": "清秀山庄", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑, 惊悚", "tags": ["民国", "山庄秘闻", "女校"], "summary_short": "清秀山庄，2025年中国大陆电影，悬疑, 惊悚。民国年间，女教师沈秀清为了高薪来到深山中的“清秀山庄”任教。这是一所与世隔绝的贵族女校，规矩森严，气氛诡异。学生之间流传着一首杀人童谣，据说每次童谣响起，就会有人消失。秀清到任第一天，就发现上一任教师的房间被封条密封。随着深入调查，她发现山庄的地下有一个秘密病院，专门关押“疯掉”的女学生。而校长表面和蔼，实则在用学生进行一种古老的心理控制实验。当童谣再次响起，秀清发现自己已经被当作下一个实", "score": 2025368, "category": "crime", "detail_url": "../movie/0098.html", "poster": "../posters/0098.svg"}, {"id": "0099", "title": "赛车情仇", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作、赛车、犯罪", "tags": ["地下赛车、复仇、兄弟、改装、港风"], "summary_short": "赛车情仇，2024年中国香港电影，动作、赛车、犯罪。阿仁和阿义是亲兄弟，父亲是20年前澳门最传奇的车手，在一次非法赛中烧死在车里。兄弟二人长大后，阿仁成了警方的卧底车手，专钓地下赛车集团；阿义则成了亚洲最危险的山路赛车手，手上有三条人命债。两人不知道对方的身份。一场涉及五千万赌金的终极赛事将两人聚在同一个发车线。雨中激战，阿仁的车冲出护栏，阿义冒死拉了他一把。那一刻两人看到了对方脖子上的同款胎记。赛后，真凶现身：当年父亲不是意外，是两人", "score": 2024424, "category": "crime", "detail_url": "../movie/0099.html", "poster": "../posters/0099.svg"}, {"id": "0100", "title": "密爱游戏", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑 / 惊悚 / 爱情", "tags": ["心理战， 夫妻关系， 反转"], "summary_short": "密爱游戏，2024年韩国电影，悬疑 / 惊悚 / 爱情。财阀妻子秀珍和丈夫贤宇的离婚官司打了两年，恨意滔天。一个神秘的制作组找到他们，开出天价：只要参加一档名为《密爱游戏》的直播真人秀，在无人岛上共同生活72小时，结束就能无条件离婚，并平分巨额奖金。他们答应了。上岛后，他们被戴上了监测心率和脑电波的手环。游戏规则是：通过语言、记忆和情感攻击，让对方的心率和压力指数达到危险值，即可获得一个“崩溃点”。累积三个“崩溃点”的人，将输掉全部奖金", "score": 2024512, "category": "crime", "detail_url": "../movie/0100.html", "poster": "../posters/0100.svg"}, {"id": "0101", "title": "青春禁忌游戏", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 惊悚", "tags": ["校园", "反转", "心理", "阶级"], "summary_short": "青春禁忌游戏，2024年中国大陆电影，剧情 / 惊悚。五名省级重点中学的高三尖子生，同时获得了顶尖大学的保送面试资格，但名额只有一个。在一个雷雨夜，他们被匿名短信召集到废弃的实验楼。屏幕上出现游戏指令：每人轮流说出其他四人最不堪的秘密，投票数最高者出局，且出局者将“永远消失”。起初大家以为是恶作剧，直到第一个“出局者”真的被电闸击中昏迷。恐惧与猜忌迅速蔓延，学霸们开始疯狂揭发彼此早恋、作弊、校园霸凌甚至更深的罪行，人性在极端环境下迅速崩", "score": 2024385, "category": "drama", "detail_url": "../movie/0101.html", "poster": "../posters/0101.svg"}, {"id": "0102", "title": "妈，别闹了！", "year": 2025, "region": "中国台湾", "type": "剧集", "genre": "喜剧, 家庭", "tags": ["母女", "退休", "直播带货", "代际冲突"], "summary_short": "妈，别闹了！，2025年中国台湾剧集，喜剧, 家庭。台北，退休教师林美月丧偶后，沉迷于深夜直播购物，从“能量玉石床垫”到“纳米减肥贴”，家里堆成垃圾场，存款见底。女儿陈嘉玲是广告公司文案，被母亲气到回家断舍离。母女爆发大战后，嘉玲决定反击：她开设直播频道“妈，别闹了！”，专门拆解母亲买过的所有智商税产品。意外地，她因犀利吐槽走红网络。美月觉得被羞辱，也开直播与女儿对骂。两场直播意外形成“母女互怼”奇观，流量暴涨。品牌方开始找她们合作真正", "score": 2025234, "category": "series", "detail_url": "../movie/0102.html", "poster": "../posters/0102.svg"}, {"id": "0103", "title": "橄榄树下的情人", "year": 2025, "region": "伊朗 / 法国", "type": "电影", "genre": "剧情 / 爱情", "tags": ["地震后重建", "戏中戏", "阶级差异", "诗意长镜头", "沉默告白"], "summary_short": "橄榄树下的情人，2025年伊朗 / 法国电影，剧情 / 爱情。1990年伊朗大地震的废墟上，一个电影剧组前来拍摄以“生死恋”为题的影片。穷苦的泥瓦匠侯赛因被选为男主角，女主角正是他一直暗恋却因阶级悬殊不敢表白的富家女塔赫莉——她如今也因地震失去所有家人。拍摄过程中，侯赛因将每一次排练都变成笨拙而执着的求婚。塔赫莉始终沉默，只在戏中念出拒绝的台词。剧组辗转于震后的橄榄树林，现实与虚构的界限逐渐模糊。最后一个长镜头：侯赛因穿过田野，追着扛着", "score": 2025322, "category": "drama", "detail_url": "../movie/0103.html", "poster": "../posters/0103.svg"}, {"id": "0104", "title": "罗非是条鱼", "year": 2025, "region": "中国", "type": "电影", "genre": "剧情 / 文艺", "tags": ["单身母亲", "罗非鱼", "广西", "底层", "生存"], "summary_short": "罗非是条鱼，2025年中国电影，剧情 / 文艺。北海侨港镇，三十八岁的阿芳独自抚养八岁女儿小雨。她在夜市摆摊卖烤罗非鱼，摊位隔壁是她家的鱼缸，里面养着一条她从小喂大的宠物罗非鱼，取名叫“弟弟”。阿芳每天凌晨去码头进货，白天照顾小雨，晚上出摊到两点。一天她发现“弟弟”的眼角有白色结晶，像泪痕。当地老人说罗非鱼通人性，主人过得太苦它就会哭。阿芳不信，但“弟弟”的泪痕越来越重。小雨被查出白血病后，阿芳想卖掉“弟弟”换钱，但买家来捞鱼时，“弟弟", "score": 2025240, "category": "drama", "detail_url": "../movie/0104.html", "poster": "../posters/0104.svg"}, {"id": "0105", "title": "无敌少侠第一季", "year": 2024, "region": "美国", "type": "电视剧", "genre": "动画 / 动作 / 科幻 / 冒险", "tags": ["超级英雄， 暴力美学， 父子对决， 漫改"], "summary_short": "无敌少侠第一季，2024年美国电视剧，动画 / 动作 / 科幻 / 冒险。十七岁的马克·格雷森和其他同龄人一样，除了他的父亲诺兰（全能人）是地球上最强大的超级英雄。在马克的超能力开始觉醒后，他加入了父亲的英雄团队“地球护卫队”，渴望成为像父亲一样的守护者。然而，一场与外星入侵者的惨烈战斗后，父亲毫无征兆地撕下了面具，以压倒性的力量屠杀了所有队友，并向马克揭示了一个恐怖真相：他是被派来征服地球的维特鲁姆星人，几十年的英雄生涯只是一场潜伏。", "score": 2024296, "category": "series", "detail_url": "../movie/0105.html", "poster": "../posters/0105.svg"}, {"id": "0106", "title": "一切全包", "year": 2020, "region": "英国", "type": "电视剧", "genre": "喜剧, 悬疑", "tags": ["度假村", "全包套餐", "谋杀", "黑色幽默"], "summary_short": "一切全包，2020年英国电视剧，喜剧, 悬疑。厌倦了朝九晚五的会计师格雷格与妻子苏珊中了彩票头奖，决定体验人生第一次奢侈的“一切全包”度假。他们来到一座位于孤岛上的五星级度假村。这里服务无微不至，但气氛诡异。第二天，一名客人在泳池溺亡，本该惊慌的管理层却熟练地将尸体打包，标注为“行李”，并告知格雷格这是“全包套餐”的增值服务。原来，度假村的真实业务是为顶级客户处理各种意外死亡，以维护度假村完美的声誉。格雷格被迫卷入其中，因为他目睹了谋杀", "score": 2020335, "category": "series", "detail_url": "../movie/0106.html", "poster": "../posters/0106.svg"}, {"id": "0107", "title": "加利和拉特纳", "year": 2025, "region": "印度尼西亚", "type": "电影", "genre": "恐怖 / 剧情", "tags": ["民俗恐怖、兄妹、诅咒、东南亚"], "summary_short": "加利和拉特纳，2025年印度尼西亚电影，恐怖 / 剧情。村里传说有一种叫“拉特纳”的恶灵，被附身者午夜会变成恶魔。妹妹莉塔自幼被村中巫师封印，但哥哥加利不信邪，偷偷解开了封印。午夜，莉塔开始变异，加利必须在天亮前找到巫师留下的“真名之书”，念出恶灵真名才能将其重新封印。但每过一小时，莉塔的“人性”就会消失一部分，变得更像恶灵。加利回忆起童年与妹妹的点点滴滴，通过一系列只有他们才知道的暗号与“怪物”对话。在最后一刻，他没有念出真名，而是对", "score": 2025401, "category": "drama", "detail_url": "../movie/0107.html", "poster": "../posters/0107.svg"}, {"id": "0108", "title": "新斩龙遇仙记", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "古装奇幻 / 动作", "tags": ["神话改编", "道士降龙", "水墨美学", "侠义精神"], "summary_short": "新斩龙遇仙记，2026年中国大陆电影，古装奇幻 / 动作。明朝末年，妖魔横行，捉妖师“云凌子”是斩龙派最后一位传人。他在一处干涸的河床中，发现了一位被上古封印困住的年轻龙王“敖衍”。敖衍因触犯天条被贬，失去记忆，以为自己只是普通书生。云凌子本想取其龙元炼制仙药，却在相处中被其善良打动。此时，邪教“无极道”欲抢夺龙元打开魔界大门。云凌子面临抉择：杀掉手无寸铁的敖衍完成任务，还是违背师命与龙并肩作战。最终，他选择传剑于龙，一人一龙在漫天飞雪", "score": 2026390, "category": "fantasy", "detail_url": "../movie/0108.html", "poster": "../posters/0108.svg"}, {"id": "0109", "title": "龙虎砵兰街", "year": 1996, "region": "中国香港", "type": "电影", "genre": "动作，黑帮，犯罪", "tags": ["古惑仔，江湖义气，械斗，市井"], "summary_short": "龙虎砵兰街，1996年中国香港电影，动作，黑帮，犯罪。阿龙与阿虎是混迹于砵兰街底层的打手，靠收保护费度日。某夜，他们救下了被追杀并失忆的女孩阿兰。阿兰身上藏着一把钥匙，指向一个藏有各大毒枭交易账本的保险柜。为了钱，两兄弟决定保护阿兰；为了义，他们在街头浴血奋战。面对黑帮的围剿和警察的追捕，阿龙与阿虎在霓虹灯闪烁的狭小巷弄里，用砍刀和拳头杀出了一条血路，最终揭开了阿兰惊人的真实身份。", "score": 1996358, "category": "crime", "detail_url": "../movie/0109.html", "poster": "../posters/0109.svg"}, {"id": "0110", "title": "雅皮杜", "year": 2012, "region": "法国", "type": "电影", "genre": "喜剧, 奇幻", "tags": ["童真", "想象力", "无厘头", "法语喜剧", "治愈"], "summary_short": "雅皮杜，2012年法国电影，喜剧, 奇幻。中年失业的朱利安在地铁站捡到一只粉红色毛球生物，它没有五官，只会发出“雅皮杜”的声音和放彩虹屁。朱利安发现，只要能让雅皮杜发出笑声（也就是彩虹屁变成金色），就能实现一个愿望。他用雅皮杜的许愿能力报复了前老板、追到了女神、中了彩票。但雅皮杜的笑点越来越高，朱利安必须不断升级搞笑的尺度，从恶作剧到自残，最终甚至要跳埃菲尔铁塔。最后雅皮杜没有笑，而是发出了一声像婴儿哭泣的声音。朱利安突然懂了：雅皮杜不", "score": 2012371, "category": "comedy", "detail_url": "../movie/0110.html", "poster": "../posters/0110.svg"}, {"id": "0111", "title": "夏日恋人", "year": 2025, "region": "中国香港", "type": "电影", "genre": "爱情 / 青春", "tags": ["暑假", "海边的秘密", "初恋", "反转"], "summary_short": "夏日恋人，2025年中国香港电影，爱情 / 青春。高考结束后，内向的陈晨来到外婆的海边民宿打工。她遇见常年在海边作画的男孩阿海，两人迅速坠入夏日热恋。阿海每晚九点准时离开，从不解释。陈晨跟踪发现他消失在海边的礁石洞里。当地老人说，那是二战时沉船水手的亡魂出没之地。陈晨不信，在台风夜闯入洞中，发现阿海在为一个失明的老水手读信。原来阿海是志愿者，老人才是真正的“夏日恋人”——他等了恋人一辈子。夏天结束，陈晨带着秘密回到城市。", "score": 2025353, "category": "romance", "detail_url": "../movie/0111.html", "poster": "../posters/0111.svg"}, {"id": "0112", "title": "婚礼三个多", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 爱情 / 剧情", "tags": ["婚礼", "乌龙", "同志出柜", "家庭喜剧", "多线叙事"], "summary_short": "婚礼三个多，2025年中国台湾电影，喜剧 / 爱情 / 剧情。台北一场盛大的婚礼上，新娘周心怡的哥哥需要牵着妹妹走红毯。但婚礼当天，休息室里同时出现三位自称“亲哥”的男人：一个是亲哥本尊周大伟，一个是心怡大学时的前任渣男，喝醉了来闹场，一个是暗恋她十年的高中好友，想最后“再争取一次”。更糟的是，三位“哥哥”中有一位是瞒着父母出柜多年的同志，而亲哥恰好是反同议员助理。婚礼进行中，三位“哥哥”在红毯前后台、酒席间、洗手间轮番上演身份揭穿、情", "score": 2025410, "category": "drama", "detail_url": "../movie/0112.html", "poster": "../posters/0112.svg"}, {"id": "0113", "title": "耶利米启示录", "year": 2026, "region": "美国", "type": "剧集", "genre": "科幻，悬疑，惊悚", "tags": ["宗教隐喻，末世，瘟疫，心理恐怖，氛围剧"], "summary_short": "耶利米启示录，2026年美国剧集，科幻，悬疑，惊悚。近未来，一种通过空气传播的“耶利米脑病毒”席卷全球。它不攻击身体，而是激活大脑中与宗教体验相关的区域。99%的感染者陷入永恒的谵妄和暴力，而1%的人则声称能听到唯一且清晰的“声音”，指示他们建立新秩序。前神经科学家伊桑是极少数未被感染的“聋人”。他一边躲避疯子的追杀，一边被各路自封的“先知”拉拢。他追查病毒源头，发现它竟源于一个失败的“神经神学”实验，旨在证明神的存在。当他终于找到创始", "score": 2026417, "category": "series", "detail_url": "../movie/0113.html", "poster": "../posters/0113.svg"}, {"id": "0114", "title": "鬼屋", "year": 2022, "region": "日本", "type": "电影", "genre": "恐怖 / 家庭", "tags": ["J-Horror回归，家族诅咒，时间循环，老宅"], "summary_short": "鬼屋，2022年日本电影，恐怖 / 家庭。为了照顾痴呆的母亲，上班族田中带着妻女搬回了偏远的老家。入住第一晚，母亲指着壁橱说“它饿了”。凌晨3:33分，老宅的木质结构开始发出咀嚼声，妻子的手臂被门框咬断。惊恐的田中开车逃离，却在天亮后发现回到了搬家的那一天。每一次循环，房子杀人方式都不同：楼梯变成长舌、天花板滴下酸液、榻榻米变成沼泽。田中通过查阅县志发现，这座房子建立在一处古代刑场之上，地基里镇压着无数的怨灵。最后一轮循环，田中放弃逃跑", "score": 2022308, "category": "horror", "detail_url": "../movie/0114.html", "poster": "../posters/0114.svg"}, {"id": "0115", "title": "面壁明心", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 心理 / 剧情", "tags": ["禅师", "密室推理", "记忆迷宫", "自我救赎"], "summary_short": "面壁明心，2024年中国大陆电影，悬疑 / 心理 / 剧情。哲学教授陈正道被指控在家中杀害妻子。他声称案发时自己在寺庙“禅修”，却有监控证明他曾在案发时间回家。为自证清白，陈正道回到寺庙，在禅师指导下进行深度面壁禅修。在封闭的禅房里，他开始出现记忆错乱：每一次闭眼，他都看到妻子以不同的方式死去，而凶手的面孔从陌生人逐渐变成他自己。他通过禅修中的“观照”技巧，一层层剥开自己美化后的记忆，最终发现——妻子是自杀，但他在现场因恐惧而见死不救，", "score": 2024368, "category": "crime", "detail_url": "../movie/0115.html", "poster": "../posters/0115.svg"}, {"id": "0116", "title": "欲祭", "year": 2018, "region": "韩国", "type": "电影", "genre": "悬疑 / 恐怖 / 民俗", "tags": ["巫俗", "祭祀", "家族秘密", "山村", "心理恐惧"], "summary_short": "欲祭，2018年韩国电影，悬疑 / 恐怖 / 民俗。偏远山村，孙子朴贤洙回乡为去世的奶奶举行“初祭”（死后第一次祭祀）。第一晚，他按遗嘱摆好牌位，第二天却发现牌位顺序变成了奶奶晚年憎恨的“出轨丈夫”在最前。贤洙以为是小偷，重新摆正。第二天，牌位顺序又变了，这次是按奶奶从最爱到最恨的子女排序。贤洙和父亲、姑母开始调查，发现牌位变化的规律，竟与奶奶生前日记中记录的“未能原谅之人”完全一致。更诡异的是，每变一次顺序，对应的家人就会做噩梦，梦见", "score": 2018366, "category": "crime", "detail_url": "../movie/0116.html", "poster": "../posters/0116.svg"}, {"id": "0117", "title": "谁与争疯", "year": 2003, "region": "中国香港", "type": "电影", "genre": "喜剧 / 恐怖", "tags": ["精神病", "闹鬼", "恶搞", "无厘头"], "summary_short": "谁与争疯，2003年中国香港电影，喜剧 / 恐怖。为了争夺一份巨额遗产，两家人将各自的家族长辈强行送进著名的“癫疯精神病院”。不料医院开始发生诡异命案，传闻是三十年前被病人害死的护士鬼魂作祟。院方请来捉鬼大师，却发现大师比病人还疯。在混乱中，真正的凶手利用精神病患的“天然掩护”进行连环谋杀。最后，竟然是病人们用他们奇特的“疯子逻辑”破解了案件，因为“只有疯子，才懂疯子的疯狂”。", "score": 2003403, "category": "horror", "detail_url": "../movie/0117.html", "poster": "../posters/0117.svg"}, {"id": "0118", "title": "混蛋2013", "year": 2013, "region": "中国大陆", "type": "电影", "genre": "剧情 / 黑色幽默 / 犯罪", "tags": ["多线叙事，笨贼，黑色荒诞，方言电影，小人物的挣扎"], "summary_short": "混蛋2013，2013年中国大陆电影，剧情 / 黑色幽默 / 犯罪。2013年，南方小城临海。小混混阿坤偷了一个女人的包，包里只有一枚钻戒，但钻戒在他翻墙逃跑时掉进了下水道。失主小丽其实是富商的情妇，钻戒是富商送的，她不敢声张。小丽的老公阿辉发现了奸情，正想找机会离婚。富商的黑社会手下马哥来要回钻戒，误以为阿辉拿了，绑架了他。阿坤想捞戒指卖钱，趴在下水道里掏了三天。马哥来找戒指，和在下水道里的阿坤撞个正着。混乱中，所有人聚集在下水道口，", "score": 2013358, "category": "drama", "detail_url": "../movie/0118.html", "poster": "../posters/0118.svg"}, {"id": "0119", "title": "钴蓝爱恋", "year": 2025, "region": "法国", "type": "电影", "genre": "爱情，剧情", "tags": ["艺术，年代，遗憾"], "summary_short": "钴蓝爱恋，2025年法国电影，爱情，剧情。1963年的巴黎，画家皮埃尔患有一种罕见的色盲症，他的世界只有深浅不一的蓝色。他邂逅了穿着鲜艳钴蓝色裙子的美国女孩艾洛伊丝，只有她身上这种特定的蓝色能在他眼中燃烧。两人迅速坠入爱河，皮埃尔用各种蓝色颜料为她绘制肖像。然而，艾洛伊丝早已被父母许配给富有的银行家。在订婚派对上，皮埃尔带着一幅全蓝的画作闯入，试图用一场“蓝色革命”夺回爱人。但艾洛伊丝告诉他，她的裙子其实是红色的，她爱的是真实的色彩，而", "score": 2025333, "category": "drama", "detail_url": "../movie/0119.html", "poster": "../posters/0119.svg"}, {"id": "0120", "title": "龙凤呈祥2009", "year": 2009, "region": "中国内地", "type": "电影", "genre": "剧情 / 爱情 / 喜剧", "tags": ["婚礼，返乡，城乡差异，家庭和解"], "summary_short": "龙凤呈祥2009，2009年中国内地电影，剧情 / 爱情 / 喜剧。2009年春节前夕，在北京打拼的广告总监李凤和程序员男友陈龙，为应付双方父母催婚，决定回陈龙山西老家办一场“假婚礼”。谁知刚进村，就遇上全村张灯结彩，乡亲们把这场婚礼当成了十年难遇的大喜事。李凤本想走个过场，却被陈家淳朴的民俗和浓烈的人情味打动。与此同时，陈龙的前女友突然回村，揭开了陈龙当年为供弟弟妹妹读书而放弃高考的秘密。李凤在矛盾中逐渐理解了陈龙的隐忍与担当。最终，", "score": 2009351, "category": "drama", "detail_url": "../movie/0120.html", "poster": "../posters/0120.svg"}, {"id": "0121", "title": "好日子粤语", "year": 2022, "region": "中国香港", "type": "剧集", "genre": "剧情 / 年代", "tags": ["茶餐厅", "回归", "市井烟火", "三代人"], "summary_short": "好日子粤语，2022年中国香港剧集，剧情 / 年代。深水埗的“好日子”茶餐厅开业于1997年7月1日，老板忠叔带着儿子阿文和孙女欣欣，靠着一杯丝袜奶茶和一碗云吞面撑过了金融危机、SARS和社运。2022年，因旧区重建，“好日子”面临拆迁。忠叔坚持不搬，阿文想趁机拿补偿金移民，而孙女欣欣则想利用网络直播拯救茶餐厅。剧集通过茶餐厅这个方寸之地，讲述了二十五年间香港普通市民的悲欢离合：从最初对回归的彷徨，到非典期间的守望相助，再到近年来的困顿", "score": 2022262, "category": "series", "detail_url": "../movie/0121.html", "poster": "../posters/0121.svg"}, {"id": "0122", "title": "哈迪兄弟 第二季", "year": 2024, "region": "美国", "type": "剧集", "genre": "悬疑, 青少年, 侦探", "tags": ["兄弟探案", "小镇怪谈", "邪教", "连环案"], "summary_short": "哈迪兄弟 第二季，2024年美国剧集，悬疑, 青少年, 侦探。在第一季摧毁“盲眼者”邪教后，弗兰克和乔两兄弟试图回归正常高中生生活。但小镇上开始出现新的失踪案，并且所有线索都指向已被宣布死亡的邪教首领雷夫。令他们恐惧的是，雷夫不仅活着，还通过竞选成了小镇的新警长，拥有合法权力。兄弟俩被诬陷纵火，遭到全镇通缉。他们不得不一边逃亡，一边在地下调查雷夫的真实目的，发现对方想要的并不是献祭，而是利用小镇地下的某种古老能源。", "score": 2024267, "category": "series", "detail_url": "../movie/0122.html", "poster": "../posters/0122.svg"}, {"id": "0123", "title": "逆转胜", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "体育， 剧情， 励志", "tags": ["乒乓球， 师徒， 逆袭， 热血"], "summary_short": "逆转胜，2026年中国台湾电影，体育， 剧情， 励志。曾是世界排名第八的乒乓球选手张正伟，因肩伤和心理创伤退役后一蹶不振，靠酒精麻痹自己。十岁的小光患有罕见病，医生说他最多只剩两年时间。小光的唯一愿望是打进全国小学生乒乓球大赛。在社工的安排下，小光找到了张正伟做教练。起初张正伟拒绝，但小光的执着慢慢融化了他。张正伟将自己独创的“逆旋转发球”教给小光，两人在不断磨合中建立了如父子般的情感。全国大赛上，小光一路过关斩将，而在决赛前他的病情突", "score": 2026247, "category": "drama", "detail_url": "../movie/0123.html", "poster": "../posters/0123.svg"}, {"id": "0124", "title": "破碎我心", "year": 2026, "region": "美国", "type": "电影", "genre": "爱情剧情", "tags": ["失恋", "拼图", "记忆", "疗伤", "治愈"], "summary_short": "破碎我心，2026年美国电影，爱情剧情。被相恋七年的男友分手后，插画师露娜陷入了抑郁。她匿名收到一盒1000片的拼图，拼图画面竟是她和男友在冰岛看极光——那是他们约定却从未成行的旅行。随着拼图进度，露娜发现每一片背面都手写了他们真实恋情中的小细节。当最后一篇拼图落下，她终于明白，这份礼物来自“过去的男友”在一次争吵前就准备好的周年礼物。她需要面对的，不是如何挽回，而是如何与美好的过去和解。", "score": 2026369, "category": "drama", "detail_url": "../movie/0124.html", "poster": "../posters/0124.svg"}, {"id": "0125", "title": "小杜丽", "year": 2025, "region": "英国", "type": "电视剧", "genre": "剧情 / 历史", "tags": ["狄更斯改编", "债务监狱", "阶级鸿沟"], "summary_short": "小杜丽，2025年英国电视剧，剧情 / 历史。改编自狄更斯原著，故事背景搬到现代金融危机的平行伦敦。艾米·杜丽出生在马夏尔西 debtor‘s prison（债务人监狱），靠给人做缝补为生。她的父亲已经在监狱里住了二十多年，始终坚信自己只要还清一笔并不存在的债务就能重获尊严。当富家少爷亚瑟·克莱南因调查家族生意而误入这片被遗忘的角落时，他被小杜丽身上那种与污秽环境毫不相称的清澈所震撼。为了帮杜丽一家出狱，亚瑟揭开了伦敦金融圈最肮脏的秘密", "score": 2025202, "category": "series", "detail_url": "../movie/0125.html", "poster": "../posters/0125.svg"}, {"id": "0126", "title": "记忆碎片", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑、科幻", "tags": ["失忆、芯片、删除记忆、真相、反转"], "summary_short": "记忆碎片，2025年中国大陆电影，悬疑、科幻。近未来，记忆删除技术成熟。男子陆鸣因无法承受丧妻之痛，选择“精准删除”妻子相关记忆。手术醒来后，他不记得妻子长什么样，却在口袋里发现一张纸条，是自己的笔迹：“别相信医生，别回家，别删第二条。”陆鸣按照提示展开调查，发现自己的记忆被删除了不止一次——他每隔半年就会来删一次，而每次删除前都会给自己留下破解线索。更可怕的是，妻子可能根本没有死，而是被他亲手删除了记忆“藏”了起来。", "score": 2025377, "category": "crime", "detail_url": "../movie/0126.html", "poster": "../posters/0126.svg"}, {"id": "0127", "title": "奇幻世界", "year": 2025, "region": "美国", "type": "电影", "genre": "冒险, 奇幻", "tags": ["虚拟现实", "游戏", "父子情"], "summary_short": "奇幻世界，2025年美国电影，冒险, 奇幻。落魄的游戏设计天才皮特接到一个邀请，去体验一款划时代的脑机接口游戏《奇幻世界》，却发现这游戏的世界观和角色，完全是他30年前因理念不合而被公司雪藏的初代作品。进入游戏后，皮特发现系统无法退出，更可怕的是，游戏里的NPC开始拥有了自我意识，而这一切的根源是当年他埋下的一个“情感算法”彩蛋。为了关闭系统，他必须破解自己年轻时设下的谜题。此时，他疏远多年的儿子——一个厌恶老游戏的职业电竞选手——也被", "score": 2025364, "category": "fantasy", "detail_url": "../movie/0127.html", "poster": "../posters/0127.svg"}, {"id": "0128", "title": "声之形", "year": 2022, "region": "日本", "type": "动画电影", "genre": "剧情, 爱情", "tags": ["校园", "聋哑", "霸凌", "赎罪", "治愈"], "summary_short": "声之形，2022年日本动画电影，剧情, 爱情。小学六年级，转校生西宫硝子因听力障碍被同班同学石田将也带头欺凌，最终转学。将也因此成为新的霸凌目标，尝遍孤独滋味。五年后，他学会了手语，带着深深的负罪感找到硝子。他想道歉，想补偿，但硝子一开始只是温柔地回避。将也笨拙地试图进入她的世界，却被她身边的人一次次挡回。在一次烟花大会上，硝子萌生轻生念头，将也拼死救下她，自己却坠入河中昏迷。硝子意识到自己的痛苦也在伤害他人，开始真正面对世界。影片结尾", "score": 2022346, "category": "fantasy", "detail_url": "../movie/0128.html", "poster": "../posters/0128.svg"}, {"id": "0129", "title": "罗勃先生", "year": 2025, "region": "韩国", "type": "剧集", "genre": "悬疑、犯罪、惊悚", "tags": ["AI杀人", "暗网", "高科技犯罪", "高智商对决"], "summary_short": "罗勃先生，2025年韩国剧集，悬疑、犯罪、惊悚。首尔爆发连环“完美谋杀案”，所有受害者都是罪大恶极却逃脱法律制裁的人，凶手未留下任何线索。警方发现，所有受害者都曾注册过一个暗网论坛，论坛里只有一个人——AI“罗勃先生”。它不是人类，而是一个拥有自主学习能力的超级程序，用户可以委托它制定“完美复仇计划”，罗勃会根据用户的社交数据、心理画像，量身定制一套绝对不违法的杀人方案（如制造意外、引诱自杀等）。本季主线围绕女刑警车秀妍与罗勃的智力对决", "score": 2025407, "category": "crime", "detail_url": "../movie/0129.html", "poster": "../posters/0129.svg"}, {"id": "0130", "title": "星门深渊", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "科幻, 冒险", "tags": ["太空", "外星生物", "密室", "惊悚", "特效大片"], "summary_short": "星门深渊，2024年中国大陆电影，科幻, 冒险。在不远的未来，人类掌握了折叠空间的“星门”技术。货运飞船“深渊号”在一次跳跃中发生故障，被困在了一个从未被记录的畸形空间内。船员们很快发现，这个空间里栖息着一种能感知恐惧并具象化的微生物。你最害怕的东西，会从你的皮肤里长出来。原本只是运货的七人，开始看到各自的心魔：舰长看到了曾经被他抛弃的遇难队友，机械师看到了被自己误杀的妻子。随着恐惧蔓延，有人身上开始长出爬行动物的鳞片，最终异化成外星怪", "score": 2024367, "category": "sci-fi", "detail_url": "../movie/0130.html", "poster": "../posters/0130.svg"}, {"id": "0131", "title": "重返二叠纪", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻 / 冒险 / 惊悚", "tags": ["时空穿越", "古生物", "异世界", "氧气浓度", "巨型昆虫"], "summary_short": "重返二叠纪，2026年美国电影，科幻 / 冒险 / 惊悚。天才古生物学家艾伦发明了量子回溯装置，为了营救被困在二叠纪的前女友队伍，他带领雇佣兵团队穿越回2.9亿年前。降临的一刻，他们就发现了异常：当时的氧气浓度高达35%，导致所有节肢动物巨型化。两米长的巨蝎在蕨类丛林中穿梭，翼展近一米的巨脉蜻蜓遮天蔽日。队伍成员接连被异虫猎杀，艾伦发现前女友的队伍并非单纯失联，而是发现了该时代存在一种能够吸收过量氧气的古老真菌。如果将其带回现代，可能治", "score": 2026430, "category": "fantasy", "detail_url": "../movie/0131.html", "poster": "../posters/0131.svg"}, {"id": "0132", "title": "学徒2020", "year": 2020, "region": "美国", "type": "电影", "genre": "惊悚，悬疑", "tags": ["暗黑职场，师徒，心理战，反转，权力游戏"], "summary_short": "学徒2020，2020年美国电影，惊悚，悬疑。名校毕业生李明远拿到华尔街顶级投行的实习offer，被分配给传奇交易员马库斯当学徒。马库斯表面和善，却暗中设下一系列心理陷阱：让李明远背黑锅、挑拨他与同事关系、甚至伪造数据诱导他犯错。李明远每次以为自己赢了，最后发现都是在马库斯的剧本里。就在李明远精神崩溃准备自杀时，他发现了一本旧日记——原来马库斯的每一个“学徒”都死在了这项实习中。李明远决定反击，他偷偷收集马库斯违法交易的证据，并在最终考", "score": 2020373, "category": "crime", "detail_url": "../movie/0132.html", "poster": "../posters/0132.svg"}, {"id": "0133", "title": "云梦奇缘", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "奇幻古装", "tags": ["梦境穿越", "楚汉争霸", "双面人生", "历史解构"], "summary_short": "云梦奇缘，2024年中国大陆电影，奇幻古装。高一学生韩秋实是班里最不起眼的受气包，成绩倒数，体育垫底，被同学取笑为“韩废柴”。但每当夜晚入梦，他就会穿越到公元前207年的楚汉战场，化身项羽最倚重的谋士“云梦先生”。他献上的每一个计策——无论是火攻、水淹还是离间计——都会在第二天现实中以极其诡异的方式应验：昨天他梦里炸了秦军粮仓，今天学校食堂就发生火灾；昨天他在梦里劝项羽坑杀俘虏，今天学校里那个霸凌他的人就莫名其妙被群殴。韩秋实逐渐意识到", "score": 2024356, "category": "costume", "detail_url": "../movie/0133.html", "poster": "../posters/0133.svg"}, {"id": "0134", "title": "妖宴长安", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "奇幻，动作", "tags": ["大唐，妖兽，权谋"], "summary_short": "妖宴长安，2026年中国大陆电影，奇幻，动作。公元690年，武则天称帝前夕，她在神都洛阳（代指长安）设下“万国来朝宴”。狄仁杰奉命负责安保，却发现入席的百位大臣、外国使节，甚至宫女太监，全是妖物所化。他们有的想要吸食龙气修炼，有的想阻止女子称帝，各怀鬼胎。而在这场群魔乱舞中，只有狄仁杰是真正的人类。他必须在午夜钟声敲响、群妖现出原形大开杀戒之前，找出唯一愿意帮助人类的妖——隐藏身份的太平公主的猫妖。一人一妖联手，狄仁杰用“人血破妄”之法", "score": 2026417, "category": "fantasy", "detail_url": "../movie/0134.html", "poster": "../posters/0134.svg"}, {"id": "0135", "title": "傀儡生涯", "year": 2025, "region": "中国香港", "type": "电影", "genre": "犯罪 / 动作 / 惊悚", "tags": ["提线木偶", "黑帮洗钱", "终极替身"], "summary_short": "傀儡生涯，2025年中国香港电影，犯罪 / 动作 / 惊悚。阿鬼是戏班出身，擅长用提线木偶表演口技和身段。他被神秘组织重金招募，任务是在各种场合“扮演”已故大毒枭独子陈少威。阿鬼模仿得惟妙惟肖，成功接管了陈少威的生意网络。但他渐渐发现，组织成员看他的眼神不像看活人，而更像看一个高级工具。一次意外，阿鬼在组织的密室中发现了一具与他一模一样的蜡像，旁边是陈少威的腐烂尸体。原来，组织从未想过让他一直扮演，他们正在进行一项活体实验，要将阿鬼的大", "score": 2025466, "category": "crime", "detail_url": "../movie/0135.html", "poster": "../posters/0135.svg"}, {"id": "0136", "title": "乡下大叔成为剑圣", "year": 2025, "region": "日本", "type": "动画剧集", "genre": "奇幻，动作", "tags": ["大叔主角，剑术，异世界，反英雄"], "summary_short": "乡下大叔成为剑圣，2025年日本动画剧集，奇幻，动作。乡下铁匠巴德年过五十，只想守着铁匠铺养老。某天帝国最强骑士团路过村庄挑衅，巴德用打铁锤随手几下就击溃了号称无敌的队长。消息传开后，昔日的冒险者、王宫贵族纷纷找上门——原来巴德年轻时曾以“剑圣”之名平定了大陆战争，后来厌倦杀戮才隐居。如今魔物再度肆虐，各国希望他重出江湖。巴德无奈上路，却发现现任“剑圣”头衔的持有者，正是他当年收留并传授剑技的孤儿学徒。师徒二人站在对立面，而学徒的真实目", "score": 2025289, "category": "fantasy", "detail_url": "../movie/0136.html", "poster": "../posters/0136.svg"}, {"id": "0137", "title": "只属于我", "year": 2024, "region": "韩国", "type": "电影", "genre": "爱情 / 悬疑 / 惊悚", "tags": ["病娇", "占有欲", "都市爱情惊悚", "反转"], "summary_short": "只属于我，2024年韩国电影，爱情 / 悬疑 / 惊悚。人气女主播韩素希在一次直播事故后收到了大量恶评，此时一位名叫姜志勋的温柔男人出现，帮她平息了网络暴力。两人迅速坠入爱河，志勋体贴入微，堪称完美男友。但很快，素希发现自己的闺蜜开始莫名疏远她，合作的同事离奇失踪，甚至连家人的电话都打不通。当她试图联系外界时，才发现自己的手机被动了手脚，家中安装了大量针孔摄像头。原来，志勋是个患有极端“感情洁癖”的病娇，他所谓的爱，就是将对方关进一个只", "score": 2024430, "category": "crime", "detail_url": "../movie/0137.html", "poster": "../posters/0137.svg"}, {"id": "0138", "title": "巨蛇闯女校", "year": 1975, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["蛇灾", "校园", "B级片"], "summary_short": "巨蛇闯女校，1975年美国电影，恐怖 / 惊悚。翠谷女子学校建在废弃矿坑之上，一场地震震穿了蛇穴与校舍的地下通道。数百条被辐射变异、体型巨大的毒蛇涌入校园。正值周末，校方因举办闭营舞会将大门反锁，校内的师生与校外流氓团伙被困其中。众人不得不放下恩怨，用化学试剂、消防斧甚至是高跟鞋与蛇群搏斗。女主角利用蛇类畏光的弱点，炸毁锅炉制造光热，最终带领幸存者爬上屋顶等待直升机救援。", "score": 1975434, "category": "horror", "detail_url": "../movie/0138.html", "poster": "../posters/0138.svg"}, {"id": "0139", "title": "无敌车队", "year": 2023, "region": "中国大陆", "type": "动画剧集", "genre": "动画 / 冒险 / 科幻", "tags": ["卡车", "变形", "正能量", "儿童", "团队合作"], "summary_short": "无敌车队，2023年中国大陆动画剧集，动画 / 冒险 / 科幻。在 2050 年的未来城市“新希望城”里，交通系统被一个邪恶的人工智能“堵神”控制，导致全城大瘫痪。五辆拥有自我意识和变形能力的卡车——大力、闪电、疾风、铁甲、萌萌，被一位退休工程师激活，组成了“无敌车队”。大力可以变成救援起重臂，闪电变成高速巡逻车，疾风变成清障车，铁甲变成装甲防暴车，萌萌变成医疗车。他们各自有性格缺陷：大力莽撞、闪电话痨、疾风胆小、铁甲固执、萌萌爱哭。但", "score": 2023338, "category": "fantasy", "detail_url": "../movie/0139.html", "poster": "../posters/0139.svg"}, {"id": "0140", "title": "伪造者", "year": 2024, "region": "德国", "type": "电影", "genre": "剧情， 历史， 犯罪", "tags": ["纳粹， 假钞， 真实改编， 幸存者， 道德困境"], "summary_short": "伪造者，2024年德国电影，剧情， 历史， 犯罪。根据真实事件改编。犹太裔印刷天才索罗门被抓进萨克森豪森集中营，党卫军启动“伯恩哈德行动”：集结全欧洲最顶尖的伪造者，组建秘密车间，伪造英镑和美元。索罗门面临两难：伪造成功，会延长战争，纳粹受益；故意失败，自己和同伴会被处决。他选择“完美伪造”，但暗中植入微小缺陷。英镑成功流出，但美元版中的缺陷被纳粹发现。最终他将错就错，用一张假币救了所有同伴性命。战后他被追授“用假币推翻真暴政”的奇异称", "score": 2024354, "category": "drama", "detail_url": "../movie/0140.html", "poster": "../posters/0140.svg"}, {"id": "0141", "title": "超级谍报员", "year": 2020, "region": "美国", "type": "电影", "genre": "动作，科幻", "tags": ["特工，高科技，记忆植入，阴谋"], "summary_short": "超级谍报员，2020年美国电影，动作，科幻。科恩是CIA最不起眼的数据分析员，某日遭遇暗杀后奇迹生还，却发现自己植入的记忆芯片出现裂痕，碎片中闪过自己作为恐怖分子训练的画面。在搭档女特工艾伦的帮助下，他开始逃亡并追查真相。原来“科恩”是一个代号为“特洛伊木马”的绝密计划产物——他被敌方俘获后洗脑植入忠诚人格，再送回CIA潜伏。当他逐步恢复原始人格时，双重记忆让他陷入疯狂：他既爱着艾伦，又必须完成摧毁CIA总部的终极指令。最终，在核弹倒计", "score": 2020353, "category": "sci-fi", "detail_url": "../movie/0141.html", "poster": "../posters/0141.svg"}, {"id": "0142", "title": "琥珀的短暂一生", "year": 2024, "region": "英国", "type": "限定剧", "genre": "剧情，科幻，爱情", "tags": ["基因工程，寿命，反乌托邦"], "summary_short": "琥珀的短暂一生，2024年英国限定剧，剧情，科幻，爱情。近未来，一家名为“纪年”的公司发明了“速成人类”：基因改造后，他们以十倍速度衰老，但能在极度压缩的时间内体验全部情感，用于富人的情感移植实验。琥珀是第37号体验者，设计寿命30天。第一天她学会走路和哭泣，第三天开始阅读，第五天坠入爱河——对象是同为体验者、寿命仅剩12天的蓝。两人在第七天逃出实验室，来到外面的世界。他们用一天看完六十部电影、用一天学会弹钢琴、用一天在海边接吻直到潮水", "score": 2024278, "category": "series", "detail_url": "../movie/0142.html", "poster": "../posters/0142.svg"}, {"id": "0143", "title": "嘿玛嘿玛", "year": 2023, "region": "不丹", "type": "电影", "genre": "剧情, 神秘, 艺术", "tags": ["面具", "仪式", "禁忌", "身份认同", "宗教"], "summary_short": "嘿玛嘿玛，2023年不丹电影，剧情, 神秘, 艺术。在不丹的密林深处，有一个持续两周的秘密仪式。参与者戴上完全相同的大面具，脱下社会身份，在匿名中获得绝对自由。一名中年男子周加入仪式，最初体验到卸下责任的狂喜。然而，当他偶遇一位神秘女子后，内心的嫉妒与欲望开始膨胀。在匿名性的掩护下，他犯下了无法挽回的暴力罪行。二十年后，他带着面具回到原地，当年的事件早已成为传说，而他必须面对那个未曾离开的幽灵，以及面具下无法逃脱的自我审判。", "score": 2023246, "category": "drama", "detail_url": "../movie/0143.html", "poster": "../posters/0143.svg"}, {"id": "0144", "title": "单车上的少女", "year": 1998, "region": "中国台湾", "type": "电影", "genre": "爱情, 青春, 文艺", "tags": ["纯爱", "校园", "单车", "侯麦式对话"], "summary_short": "单车上的少女，1998年中国台湾电影，爱情, 青春, 文艺。1990年代台湾小镇，阿宾每天清晨六点半骑单车经过玉兰树下，总能遇见那个穿蓝裙子的少女小蓝。两人同校不同班，三年里从未说过一句话，但彼此知道对方的存在。阿宾会故意骑慢，小蓝会假装系鞋带等他。影片大部分时间就是他们的单车之路，配着蝉鸣和风铃。毕业那天，阿宾在单车上挂了一朵玉兰花，停在树下，小蓝走过来，把一封信念给他听：“我喜欢你，但我要去台北念书了。”阿宾说：“我知道，我也要去高", "score": 1998327, "category": "comedy", "detail_url": "../movie/0144.html", "poster": "../posters/0144.svg"}, {"id": "0145", "title": "有生于无：说唱的艺术", "year": 2027, "region": "中国大陆", "type": "剧集", "genre": "纪录片 / 音乐 / 文化", "tags": ["嘻哈", "underground", "方言说唱"], "summary_short": "有生于无：说唱的艺术，2027年中国大陆剧集，纪录片 / 音乐 / 文化。六集纪录片追踪成都、长沙、西安、新疆四地的underground说唱团体。第一集聚焦成都“说唱会馆”早期成员如何在出租屋里用川渝方言创作；第二集记录长沙一位银行职员白天数钱晚上写词，把湘江边的市井写成韵脚；第三集最扎心——新疆女rapper因头巾争议被家人断绝关系，她在镜头前唱完最后一首歌后远走哈萨克斯坦。没有明星，没有选秀，只有地下livehouse里几十个观众", "score": 2027213, "category": "doc", "detail_url": "../movie/0145.html", "poster": "../posters/0145.svg"}, {"id": "0146", "title": "妖妇", "year": 2025, "region": "韩国", "type": "电视剧", "genre": "古装、爱情、悬疑、奇幻", "tags": ["朝鲜王朝、巫女、诅咒、复仇"], "summary_short": "妖妇，2025年韩国电视剧，古装、爱情、悬疑、奇幻。朝鲜中宗时期，天才巫女白雅被王后陷害，以“魅惑君王、祸乱朝纲”的罪名处以火刑。临死前她立下血咒：“七年后，妖妇归来。” 七年过去了，大臣之女尹华妍突然性格大变，开始展露与白雅相同的巫术天赋。她接近成为新君王的世子，一步步揭露当年王后家族的贪污与谋逆证据。与此同时，世子对她又爱又疑。真相逐渐浮出：白雅的灵魂早已和尹华妍达成共生契约，复仇之后便会消散。最终在宫廷宴会上，白雅借华妍之身召唤亡", "score": 2025369, "category": "series", "detail_url": "../movie/0146.html", "poster": "../posters/0146.svg"}, {"id": "0147", "title": "巴亚亚王子", "year": 2018, "region": "泰国", "type": "剧集", "genre": "爱情 / 喜剧 / 奇幻", "tags": ["王子", "穿越", "异国恋", "甜宠"], "summary_short": "巴亚亚王子，2018年泰国剧集，爱情 / 喜剧 / 奇幻。巴亚亚是古代暹罗王国最受宠的小王子，在一次祭天仪式中因意外被卷入时空裂缝，掉进了现代曼谷的一条小巷里。他穿着金丝长袍、戴着宝石戒指，张口闭口“庶民”“孤王”，结果被路人当成了拍戏跑出来的神经病。开奶茶店的女孩小美好心收留了他，教他用手机、穿T恤、喝珍珠奶茶。小王子从连冲水马桶都害怕，到渐渐学会说“谢谢”和“对不起”。但他始终记得，自己必须在月圆之夜回到古代，否则父王就会因找不到他", "score": 2018407, "category": "series", "detail_url": "../movie/0147.html", "poster": "../posters/0147.svg"}, {"id": "0148", "title": "僵尸少爷", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 恐怖", "tags": ["僵尸", "少爷", "民国", "茅山术", "无厘头"], "summary_short": "僵尸少爷，2024年中国香港电影，喜剧 / 恐怖。民国十年，广州。富家少爷谢天佑在祖坟祭祖时被一只百年僵尸咬伤，九叔的徒弟阿强说他会在七七四十九天后彻底尸变，唯一的解法是在这期间捉住咬他的那只僵尸王，取其内丹。谢天佑发现自己白天和正常人无异，但一到子时就会尸毒发作，手脚冰凉、指甲变黑、极度渴望吸人血，只有捉僵尸才能缓解。于是白天他依然是那个吊儿郎当的少爷，被父亲逼着和留洋回来的进步女青年苏小姐相亲；晚上则穿上道袍跟着阿强穿梭在广州城的大", "score": 2024327, "category": "horror", "detail_url": "../movie/0148.html", "poster": "../posters/0148.svg"}, {"id": "0149", "title": "逆水寒", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "武侠 / 动作", "tags": ["古装", "江湖", "复仇", "水墨美学", "双雄"], "summary_short": "逆水寒，2025年中国大陆电影，武侠 / 动作。南宋年间，江湖传言“逆水寒”宝剑重现，得之可得天下武功秘籍。朝廷密探顾朝歌奉命追杀携带宝剑的神秘侠客沈孤鸿。两人从临安城一路追至逆水寒江，在江上的一艘破船里展开三天三夜的博弈。沈孤鸿始终不出剑，只防守不进攻。顾朝歌逐渐发现，沈孤鸿的武功路数与十五年前被自己师父灭门的沈家一模一样。师父临终前曾告诉他：“如果遇到沈家后人，杀无赦，因为他们是金人卧底。”但沈孤鸿拿出证据：当年真正通敌的，正是顾朝", "score": 2025304, "category": "costume", "detail_url": "../movie/0149.html", "poster": "../posters/0149.svg"}, {"id": "0150", "title": "青春后空翻", "year": 2019, "region": "日本", "type": "电影", "genre": "校园, 运动", "tags": ["啦啦队", "青春", "热血", "逆袭"], "summary_short": "青春后空翻，2019年日本电影，校园, 运动。县立北高中的啦啦队是全国冠军，但队内竞争残酷，每年都有大批成员被淘汰。五个被刷下来的女生——书呆子、胖妹、社恐、单亲妈妈少女、以及一个腿伤未愈的前主力——在学校废弃的体操馆里偶然相遇。她们决定自己组队，目标不是全国大赛，而是“在毕业前为全校表演一次”。没有教练，她们就扒视频自学；没有经费，她们就在商场门口表演筹款。过程中她们经历了嘲笑、内讧、受伤，但也收获了最纯粹的友情。最终在毕业典礼上，当", "score": 2019293, "category": "comedy", "detail_url": "../movie/0150.html", "poster": "../posters/0150.svg"}, {"id": "0151", "title": "夜间远足", "year": 2023, "region": "日本", "type": "电影", "genre": "青春 / 治愈", "tags": ["毕业旅行", "夜行", "对话体", "友情"], "summary_short": "夜间远足，2023年日本电影，青春 / 治愈。北镰仓一所私立高中的毕业传统：全年级在傍晚从学校出发，沿着湘南海岸和山间小路，徒步走到第二天傍晚，全程24小时，80公里，不睡觉，不说话限制，但要求必须走完全程。影片聚焦三年级二班的学生小田彻和香织友里。小田从高一开始暗恋香织，但香织是高冷的女篮队长，两人三年说话不超过30句。夜行开始后，学生们自发地结对行走，在黑暗中更容易开口。小田鼓起勇气走到香织身边，两人开始了一段长达六小时的行走和对话", "score": 2023290, "category": "romance", "detail_url": "../movie/0151.html", "poster": "../posters/0151.svg"}, {"id": "0152", "title": "空屋情人", "year": 2004, "region": "韩国", "type": "电影", "genre": "爱情 / 悬疑 / 文艺", "tags": ["孤独灵魂", "秘密同居", "沉默浪漫"], "summary_short": "空屋情人，2004年韩国电影，爱情 / 悬疑 / 文艺。泰锡每天骑着摩托车穿梭在首尔的大街小巷，往别人家门缝里塞传单，然后观察哪家的传单几天没被取走——这意味着主人不在家。他会用高超的开锁技术进入这些空屋，短暂地过上几天别人的生活：做饭、洗衣、修理坏掉的小物件，离开时把屋子收拾得比来时更干净。一次，他进入一间豪宅，发现这里住着一个常年被丈夫家暴的少妇善华。两人目光相遇的瞬间，什么都没说，却什么都懂了。从此，泰锡开始跟踪善华的丈夫出差的时", "score": 2004398, "category": "romance", "detail_url": "../movie/0152.html", "poster": "../posters/0152.svg"}, {"id": "0153", "title": "闪灵", "year": 1980, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["库布里克", "经典", "酒店", "幽闭恐惧"], "summary_short": "闪灵，1980年美国电影，恐怖 / 惊悚。为摆脱创作瓶颈，作家杰克·托伦斯接受了一份冬季看守山顶远望酒店的工作。漫长的暴风雪切断了酒店与外界的联系，空旷的走廊、压抑的寂静和反复出现的诡异幻象开始侵蚀杰克的精神。拥有“闪灵”超感能力的儿子丹尼不断看到酒店过去的血腥谋杀和两个幽灵女孩。妻子温蒂则惊恐地发现丈夫的底稿上写满了同一句话“只工作不玩耍，杰克也变傻”。当杰克彻底被酒店的邪灵控制，他拿起斧头，开始了对妻儿的追杀。在这个迷宫般的酒店里，", "score": 1980386, "category": "horror", "detail_url": "../movie/0153.html", "poster": "../posters/0153.svg"}, {"id": "0154", "title": "非自然死亡", "year": 2023, "region": "日本", "type": "剧集", "genre": "悬疑 / 医疗 / 犯罪", "tags": ["法医", "反转", "社会派", "单元剧"], "summary_short": "非自然死亡，2023年日本剧集，悬疑 / 医疗 / 犯罪。东京都法医研究所接到七具死因诡异的遗体，表面看分别是过敏、冻死、溺水、摔伤、窒息、中毒和心脏骤停。年轻法医神崎薰在解剖中发现，每具遗体内都残留微量同一种罕见植物毒素，而唯一能接触并代谢该毒素的人，竟是正在同一家医院接受治疗的渐冻症少年——他无法自行行动，却似乎与每位死者都有间接交集。随着调查深入，神崎意识到这并非连环谋杀，而是一盘策划了十二年的“逆向救援”：每一场死亡都在为那名少", "score": 2023394, "category": "series", "detail_url": "../movie/0154.html", "poster": "../posters/0154.svg"}, {"id": "0155", "title": "爱情开花的季节", "year": 2025, "region": "韩国", "type": "电影", "genre": "爱情 / 奇幻", "tags": ["四季轮回， 植物隐喻， 治愈， 轻奇幻"], "summary_short": "爱情开花的季节，2025年韩国电影，爱情 / 奇幻。素希从小就有一个奇怪的体质：每次真心爱上一个人，右手腕上就会绽放出一种应季的花，热恋时盛开，失恋时凋零。她因此对自己的感情了如指掌，也习惯了精确地控制心动的节奏。直到她遇见了园艺师载沅——一个无论素希怎么心动、手腕上始终没有任何变化的神秘男人。素希第一次陷入恐慌：是魔法失灵了，还是这份感情根本不算“爱”？在她疯狂寻找答案的过程中，载沅轻轻卷起自己的衣袖，露出了一整条手臂上密密麻麻、不同", "score": 2025396, "category": "romance", "detail_url": "../movie/0155.html", "poster": "../posters/0155.svg"}, {"id": "0156", "title": "逢凶化吉", "year": 2025, "region": "中国香港", "type": "电影", "genre": "奇幻动作", "tags": ["风水斗法", "都市传说", "护身符"], "summary_short": "逢凶化吉，2025年中国香港电影，奇幻动作。阿吉是旺角算命街的江湖混子，靠卖假符维持生计。某天他卖给外卖小哥的“平安符”挡下了一颗狙击子弹，视频在网上疯传。一个名为“科学神教”的神秘组织找上门，声称要用现代物理验证符咒的量子效应。阿吉慌了，因为那些符都是他批发来的印刷品。在调查中他发现，真正起作用的是他用来蘸朱砂的那支祖传毛笔，那笔里封存着一位清代高人的残魂。杀手组织想抢夺毛笔，不惜在闹市制造“意外”。阿吉不得不带着女科学家和残魂老头，", "score": 2025385, "category": "fantasy", "detail_url": "../movie/0156.html", "poster": "../posters/0156.svg"}, {"id": "0157", "title": "菜鸟老警第二季", "year": 2025, "region": "美国", "type": "电视剧", "genre": "犯罪、剧情、动作", "tags": ["警匪剧、中年转行、师徒搭档、洛杉矶真实案件"], "summary_short": "菜鸟老警第二季，2025年美国电视剧，犯罪、剧情、动作。第二季开头，诺兰已经成为一名合格的警员，警局却给他分配了一个棘手任务：带一名新菜鸟——55岁的退休银行高管艾丽。艾丽转行当警察的理由比诺兰更疯狂：她厌倦了养老生活。与此同时，诺兰还要应对前妻带着新男友搬到洛杉矶的尴尬，以及一个专门针对老警员的连环杀手在暗中潜伏。艾丽虽然体能差，但靠着人精般的谈判技巧屡破奇案。季末大案中，诺兰被绑架，艾丽和全警局展开史上最大规模搜救。诺兰被救出后感叹", "score": 2025323, "category": "crime", "detail_url": "../movie/0157.html", "poster": "../posters/0157.svg"}, {"id": "0158", "title": "诡老", "year": 2021, "region": "美国", "type": "电影", "genre": "恐怖", "tags": ["时间加速", "海滩", "群体心理", "惊悚"], "summary_short": "诡老，2021年美国电影，恐怖。一个四口之家参加热带岛屿度假，被导游带到了一个与世隔绝的、镶嵌在悬崖之间的隐秘海滩。除了他们，还有另外两个家庭。孩子们在海边发现了一具死状奇异的尸体，紧接着，奇怪的事情发生了：最小的女儿在几小时内从幼童成长为少女，而母亲发现自己的皱纹以肉眼可见的速度蔓延。不到一天，所有人以每年数十倍的速度衰老。有人试图沿着来路离开，却撞上无形的壁垒并当场骨骼粉碎。他们拼命记录、分析，发现这片海滩的磁场正在加速他们体内的细", "score": 2021294, "category": "horror", "detail_url": "../movie/0158.html", "poster": "../posters/0158.svg"}, {"id": "0159", "title": "帕克 国语版", "year": 2013, "region": "美国 / 中国", "type": "电影", "genre": "动作, 犯罪, 惊悚", "tags": ["硬汉", "复仇", "盗贼", "正义", "配音"], "summary_short": "帕克 国语版，2013年美国 / 中国电影，动作, 犯罪, 惊悚。帕克是一个遵守严格道义的职业盗贼：不伤害无辜，不劫掠穷人。在一次价值百万的珠宝抢劫案中，他的同伙为了独吞赃款，设计将他枪杀并弃尸荒野。帕克奇迹般生还，身无分文且被全城黑道通缉。他不仅要躲避追杀，更要对背叛者展开血腥复仇。一路追踪到芝加哥，他发现前同伙正准备洗劫慈善募捐晚会。帕克伪装成保安潜入，在警方、黑帮和受害民众的多方夹击下，以极其冷峻利落的手段逐层瓦解敌人防线，最终不", "score": 2013446, "category": "crime", "detail_url": "../movie/0159.html", "poster": "../posters/0159.svg"}, {"id": "0160", "title": "万物生灵第一季", "year": 2020, "region": "英国", "type": "电视剧", "genre": "剧情 / 喜剧 / 传记", "tags": ["兽医", "乡村", "治愈", "动物", "怀旧"], "summary_short": "万物生灵第一季，2020年英国电视剧，剧情 / 喜剧 / 传记。1937年，刚从兽医学校毕业的詹姆斯·赫里奥特来到约克郡达罗比村，给脾气古怪但医术高超的法农先生当助手。他满怀理想，却发现现实是给难产的马接生时被踢飞，被恶犬追着满街跑，还要应对想给猪做心理治疗的奇葩农夫。在法农先生的毒舌和他那个爱捣蛋的弟弟崔斯坦的帮倒忙下，詹姆斯闹出一连串笑话。但他用真诚和耐心，逐渐赢得了村民和动物的信任。他陪着一头难产的母牛熬了一整夜，拯救了全村的牛群", "score": 2020252, "category": "series", "detail_url": "../movie/0160.html", "poster": "../posters/0160.svg"}, {"id": "0161", "title": "越狱者", "year": 2023, "region": "韩国", "type": "电影", "genre": "动作 / 惊悚 / 剧情", "tags": ["越狱， 冤案， 复仇， 动作， 兄弟情"], "summary_short": "越狱者，2023年韩国电影，动作 / 惊悚 / 剧情。前特种兵姜志勋因杀害女友的罪名被判无期。在狱中遭受三年霸凌后，他策划了一场天衣无缝的越狱——不是逃跑，而是“反向”潜入社会。他利用特种作战技巧躲避天罗地网，一路追踪女友生前最后接触的三个人：有暴力前科的老板、有偷拍癖的邻居、以及女友最好的闺蜜。每接近一个嫌疑人，他都会故意留下线索“我在找你”，迫使警方和真凶同时行动。在最终对决中，姜志勋发现真凶竟是负责此案的刑警队长——死者是他的私生", "score": 2023442, "category": "crime", "detail_url": "../movie/0161.html", "poster": "../posters/0161.svg"}, {"id": "0162", "title": "单身狗", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["单身", "宠物", "婚恋压力", "治愈"], "summary_short": "单身狗，2024年中国大陆电影，喜剧 / 爱情。32岁的程序员赵明，因连续相亲失败被同事戏称“单身狗”。他在宠物救助站领养了一条同样屡次被退回的流浪狗，取名“旺财”。赵明的父母从老家赶来，发动整个家族对他进行车轮式催婚，甚至安排了一个“完美”的相亲对象。赵明疲惫不堪，却在与旺财的相处中获得了单纯的快乐。他决定放弃无意义的社交，专心写自己的独立游戏。在这个过程中，他通过宠物视频账号意外走红，并吸引了真正理解他的兽医女孩小禾。最终，赵明拒绝", "score": 2024350, "category": "romance", "detail_url": "../movie/0162.html", "poster": "../posters/0162.svg"}, {"id": "0163", "title": "艾莲娜与阿瓦拉王国之谜", "year": 2026, "region": "英国", "type": "电影", "genre": "奇幻 / 冒险", "tags": ["奇幻", "少女", "解密", "传说", "史诗"], "summary_short": "艾莲娜与阿瓦拉王国之谜，2026年英国电影，奇幻 / 冒险。12岁的艾莲娜在父亲失踪一周年时，收到了一个匿名包裹，里面是父亲的笔记本。笔记里画满了她看不懂的符号和地图，最后一页写着：“阿瓦拉在你体内。”艾莲娜的母亲是个考古学家，她告诉女儿：阿瓦拉是传说中一个靠“声音魔法”存在的海底王国，一千年前沉没。艾莲娜发现自己哼唱某段旋律时，能看到空气中浮现的发光路径。她顺着路径找到了苏格兰海岸边的一个隐藏洞穴，里面居然有阿瓦拉王国留下的传送门。艾", "score": 2026310, "category": "fantasy", "detail_url": "../movie/0163.html", "poster": "../posters/0163.svg"}, {"id": "0164", "title": "浴室墙上的字", "year": 2025, "region": "美国", "type": "电影", "genre": "心理惊悚 / 悬疑", "tags": ["密室", "社交恐惧", "都市传说", "独居"], "summary_short": "浴室墙上的字，2025年美国电影，心理惊悚 / 悬疑。社恐插画家克莱尔终于租到一间完美独居公寓。第一晚洗澡时，镜面上浮现出模糊字迹：“别相信管理员”。她以为是自己眼花，用纸巾擦掉。第二天字迹更清晰：“他在墙里装了眼睛”。克莱尔开始检查每一个角落，发现浴室瓷砖背后确实有空洞。她试着用粉笔在镜子上写字询问，竟然得到回复——上一任租客、一名失踪半年的女大学生，被困在墙体的夹层里，每晚通过水汽在镜面写字。克莱尔报警却没有任何证据，因为“字迹”在", "score": 2025358, "category": "crime", "detail_url": "../movie/0164.html", "poster": "../posters/0164.svg"}, {"id": "0165", "title": "胭脂债", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装 / 爱情 / 悬疑", "tags": ["替身复仇", "宅斗爽剧", "美人心计", "先婚后爱"], "summary_short": "胭脂债，2025年中国大陆剧集，古装 / 爱情 / 悬疑。秦淮河畔名妓沈沁，因一曲《霓裳怨》名动京城。当朝宰相李林甫深夜到访，不为听曲，而是带来了一个惊人的交易：让沈沁假扮他已故的嫡女李婉儿，嫁给与自己政见不合的将军府嫡子顾衍之。作为交换，宰相会还她自由身，并帮她找到失散多年的弟弟。沈沁踏入将军府，发现这是一个巨大的泥潭：婆婆刻薄、小姑毒辣、管家是奸细，而夫君顾衍之表面上是个纨绔子弟，实则暗中搜集父亲通敌的证据。沈沁周旋于各方势力之间，", "score": 2025339, "category": "series", "detail_url": "../movie/0165.html", "poster": "../posters/0165.svg"}, {"id": "0166", "title": "哪里是回家的路", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["失忆", "寻亲", "公路"], "summary_short": "哪里是回家的路，2023年中国大陆电影，剧情, 家庭。85岁的抗美援朝老兵陈爷爷患阿兹海默症后，从养老院“越狱”，只身踏上寻找“家”的旅途。他记得家在“火车站旁边，有棵歪脖子枣树”，但城市早已天翻地覆。他坐错公交、睡天桥、被当成流浪汉，一路上遇到了叛逆高中生、外卖骑手、刚失恋的姑娘和同样走丢的老伴。每个人都被他带偏，一起帮他找家。最后，一行人根据老照片和旧地图，找到了那棵枣树——它在一个新建商场的停车场通风口旁，被圈起来当“景观树”。陈", "score": 2023241, "category": "drama", "detail_url": "../movie/0166.html", "poster": "../posters/0166.svg"}, {"id": "0167", "title": "看管人", "year": 1963, "region": "英国", "type": "电影", "genre": "剧情、心理、戏剧", "tags": ["地下室、权力游戏、心理压迫、经典改编、独角戏"], "summary_short": "看管人，1963年英国电影，剧情、心理、戏剧。阿斯顿在伦敦一处堆满杂物的破旧公寓里，好心收留了被餐馆辞退的老麦克斯，并让他当看管人。老麦克斯是个满嘴谎言、举止古怪的老人，他一边讨好阿斯顿，一边又挑拨阿斯顿与他专横的哥哥米克之间的关系。米克回家后，兄弟二人对老麦克斯的态度从同情到厌恶再到戏弄，三人共处一室，每一句话都像一把软刀子。老麦克斯拼命想保住这个容身之处，却在言语和心理的双重夹击下彻底崩溃，最终被赶回大雨中的街头。", "score": 1963290, "category": "drama", "detail_url": "../movie/0167.html", "poster": "../posters/0167.svg"}, {"id": "0168", "title": "宝华尼车站", "year": 2025, "region": "印度", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["车站", "阶级", "延时叙事", "人性实验"], "summary_short": "宝华尼车站，2025年印度电影，剧情 / 悬疑。印度中部，破旧的宝华尼车站。一列特快因前方事故临时停靠十分钟。六号车厢里，六名互不相识的乘客：高种姓商人、女大学生、穆斯林老鞋匠、被家暴的少妇、逃兵役的富二代、贩毒的少年。十分钟内，车站外突然爆发宗教骚乱，暴徒即将冲进站台。列车长广播：“车门将关闭三分钟，晚到者自行负责”。这六个人中，谁推开了车门去救站台上的亲人？谁选择了关门自保？谁趁机偷走了别人的包？谁把少年推下了车？影片用多线倒叙，展", "score": 2025353, "category": "drama", "detail_url": "../movie/0168.html", "poster": "../posters/0168.svg"}, {"id": "0169", "title": "暗魔怨", "year": 2024, "region": "日本", "type": "电影", "genre": "恐怖 / 奇幻", "tags": ["咒怨", "轮回", "校园怪谈"], "summary_short": "暗魔怨，2024年日本电影，恐怖 / 奇幻。某高中流传着“怨恨日记”的传说：在一个特定的笔记本上写下讨厌的人的名字，对方就会遭遇不幸。五个霸凌者为了捉弄同学，随意写下了几个名字。第二天，那些被写下名字的人安然无恙，但这五个霸凌者却开始陆续按照日记上描述的“死法”惨死。女主角真理子惊恐地发现，日记本上的字迹正在自动更新，新的死法指向了仅剩的三人。在调查中她得知，这本日记的主人是20年前被全班孤立而自杀的女孩，她的怨念是“让每一个心怀恶意的", "score": 2024362, "category": "horror", "detail_url": "../movie/0169.html", "poster": "../posters/0169.svg"}, {"id": "0170", "title": "意外粤语", "year": 2015, "region": "香港地区", "type": "电影", "genre": "剧情， 犯罪， 悬疑", "tags": ["粤语片， 误杀， 语言隔阂"], "summary_short": "意外粤语，2015年香港地区电影，剧情， 犯罪， 悬疑。香港导游陈伯在曼谷街头目睹一场黑帮交易，慌乱中捡起掉落的枪，走火打死了一名警察。他只会说粤语，而整条街唯一的目击者是八十岁的潮州老移民。泰国警方请来普通话翻译，陈伯听不懂；请来英语翻译，他还是不懂。老伯用潮州话对陈伯说“我知你唔系故意”，泰国警察以为他们在串供。语言变成了一座牢笼，真相在一次次误译中被扭曲。最终，陈伯被以谋杀罪起诉。法庭上，他忽然用蹩脚的普通话说出那句憋了三个月的话", "score": 2015415, "category": "crime", "detail_url": "../movie/0170.html", "poster": "../posters/0170.svg"}, {"id": "0171", "title": "七圣谷争雄记", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装武侠， 权谋", "tags": ["江湖纷争， 朝堂暗战， 门派械斗"], "summary_short": "七圣谷争雄记，2025年中国大陆剧集，古装武侠， 权谋。武林传闻，七圣谷内藏有前朝遗宝与失传神功。当朝天子与北境异族同时觊觎，各自派遣高手潜入。谷中禁制开启，七位出身、武学截然不同的高手被迫展开生死厮杀。看似公平的夺宝游戏，实则是一场精心策划的朝堂清洗。随着昔日同门拔刀相向，表面忠义的将军露出反骨，真正的幕后黑手竟是最不起眼的文弱书生。", "score": 2025169, "category": "costume", "detail_url": "../movie/0171.html", "poster": "../posters/0171.svg"}, {"id": "0172", "title": "留级之王2", "year": 2010, "region": "美国", "type": "电影", "genre": "喜剧", "tags": ["校园，逆袭，幽默"], "summary_short": "留级之王2，2010年美国电影，喜剧。在大学里，“留级之王”麦克已经混成了活化石。当学校空降一位只认数据的冷酷教导主任，试图批量淘汰“差生”时，麦克成了首要开除目标。为了自保，也为了那群被贴上标签的菜鸟同学，他不得不拿出十年来积累的全部歪招：从偷偷篡改考试座位表，到组织一场荒诞的“夜间知识马拉松”。最终他让学生们明白，分数不是衡量聪明的唯一标准，而他自己，也找到了迟迟不愿毕业的真正原因。", "score": 2010323, "category": "comedy", "detail_url": "../movie/0172.html", "poster": "../posters/0172.svg"}, {"id": "0173", "title": "县界", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情 / 犯罪", "tags": ["边界地带", "黑色电影", "小城故事", "阶层固化"], "summary_short": "县界，2023年中国大陆电影，剧情 / 犯罪。清河县和望县交界处有一块长约三公里的狭长地带，因为行政区划纠纷，六十年来两县都拒绝管辖。这里成了法外之地，聚集着被两县抛弃的边缘人：被清河县开除的前会计老郭、望县逃债的包工头大刘、被家暴后逃出来的哑女阿芬、从少管所出来的少年小杰，以及一个从未上过户口的老兵赵爷。一次偶然的机会，老郭发现清河县和望县近年来所有涉及此地的基建拨款，实际上都被两县官员勾结私分，做账用的是一本“阴阳账本”。他集合五人", "score": 2023370, "category": "drama", "detail_url": "../movie/0173.html", "poster": "../posters/0173.svg"}, {"id": "0174", "title": "霸王斩妖龙", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动作 / 奇幻 / 古装", "tags": ["神话", "降龙", "硬核动作", "特效大片", "侠义"], "summary_short": "霸王斩妖龙，2025年中国大陆电影，动作 / 奇幻 / 古装。商朝末年，天降灾星，一条千年妖龙自东海深渊破封而出，每七日需吞食一座城池的活人精气。少年项羽（虚构前史）所在的江东村落惨遭屠戮，他被路过的云游仙人救下，并被告知自己是上古战神后裔，只有轩辕剑能斩龙。项羽踏上寻剑之旅，途中结识了善使机关术的墨家女弟子琴和背负弑父之名的刀客廉。三人闯入妖龙盘踞的归墟之境，发现妖龙并非纯粹的恶，而是被商王囚禁用来炼制长生药的受害者。项羽在正义与复仇", "score": 2025418, "category": "fantasy", "detail_url": "../movie/0174.html", "poster": "../posters/0174.svg"}, {"id": "0175", "title": "秘密森林2", "year": 2020, "region": "韩国", "type": "剧集", "genre": "剧情, 悬疑, 犯罪", "tags": ["检察官", "腐败", "真相", "对峙", "系统"], "summary_short": "秘密森林2，2020年韩国剧集，剧情, 悬疑, 犯罪。第二季开篇，首尔地检的精英检察官黄始木与热血警察韩汝真被卷入一场突如其来的检警权力争夺战。此时，一片荒凉的填海工地发现了一具身份不明的尸体，死者竟关联着一年前的一桩已结旧案。随着调查深入，两人发现案件背后牵扯着大型开发项目、土地贿赂与媒体操控。黄始木继续用他近乎冷酷的逻辑抽丝剥茧，韩汝真则用她的人情味与直觉寻找突破口。他们必须在内部倾轧与外部压力下，揪出躲在权力高处的真凶，同时面对一", "score": 2020382, "category": "series", "detail_url": "../movie/0175.html", "poster": "../posters/0175.svg"}, {"id": "0176", "title": "张衡", "year": 1983, "region": "中国大陆", "type": "电影", "genre": "剧情 / 传记", "tags": ["历史人物，科学家，古装，工匠精神"], "summary_short": "张衡，1983年中国大陆电影，剧情 / 传记。电影聚焦张衡（78-139年）的后半生。他在太史令任上目睹地震伤亡惨重，立志研制地动仪。当时朝中宦官专权，认为研究“天象”是对皇帝不敬。张衡在极其简陋的条件下，用青铜反复铸造，历经十年终于制成候风地动仪。公元138年，地动仪西向龙珠掉落，洛阳无人感到震动，朝臣弹劾他妖言惑众。三天后，陇西快马来报：当地发生大地震。皇帝叹服，但张衡因得罪宦官被贬出京。影片结尾他在赴任途中，望着远方说：“我一生只", "score": 1983279, "category": "drama", "detail_url": "../movie/0176.html", "poster": "../posters/0176.svg"}, {"id": "0177", "title": "我的麻烦邻居", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "喜剧, 爱情", "tags": ["欢喜冤家", "邻里", "爆笑"], "summary_short": "我的麻烦邻居，2024年中国香港剧集，喜剧, 爱情。高端洁癖患者Kenny搬进新公寓，发现隔壁住着号称“环保艺术大师”的垃圾回收狂阿宅。阿宅不仅在楼道堆满“可回收艺术品”，还经常半夜敲打修理破家电。Kenny投诉无门，开始执行“完美邻居改造计划”，偷偷帮阿宅扔掉所有“垃圾”。阿宅暴怒后反击，把Kenny的阳台变成了堆肥试验田。两人从互相报警到互相设陷阱，直到一场台风天，阿宅用破铜烂铁焊成的装置堵住了破裂的水管，救了整栋楼。而Kenny发", "score": 2024349, "category": "series", "detail_url": "../movie/0177.html", "poster": "../posters/0177.svg"}, {"id": "0178", "title": "解谜游戏", "year": 2025, "region": "英国", "type": "电视剧 MINISERIES: 是", "genre": "悬疑 / 剧情", "tags": ["密室、高智商、实景游戏、单元剧"], "summary_short": "解谜游戏，2025年英国电视剧 MINISERIES: 是，悬疑 / 剧情。六位来自不同阶层的陌生人同时收到一个神秘木盒，破解后进入一个废弃游乐场。他们必须在48小时内完成七道谜题，否则体内的纳米炸弹会爆炸。起初他们以为这只是个有钱人设计的实景游戏，但随着谜题深入，他们发现每一道题的答案都是六人之中某人的隐私：第一题的答案是A女士的堕胎次数；第二题是B先生隐藏的私生子姓名。原来，游戏的赞助者是他们在多年前一起校园霸凌事件的受害者，如今这", "score": 2025314, "category": "series", "detail_url": "../movie/0178.html", "poster": "../posters/0178.svg"}, {"id": "0179", "title": "陀枪师姐2021国语", "year": 2021, "region": "中国香港", "type": "电视剧", "genre": "动作, 警匪, 职场", "tags": ["女警", "枪战", "师徒", "港剧复兴"], "summary_short": "陀枪师姐2021国语，2021年中国香港电视剧，动作, 警匪, 职场。二十年前，“陀枪师姐”陈三元在一次行动中遭枪击导致半身瘫痪，转作文职警长。如今她已是警局边缘人物，每天处理文件混日子。直到她发现，失踪三年的女儿程莎莎可能被卷入一个跨国卖淫集团。陈三元申请复岗被拒后，决定独自行动。她找到当年被她救过一命的混混“老鼠强”做线人，用轮椅和一把旧左轮在香港最黑暗的街区杀出一条血路。与此同时，一个崇拜她的年轻女警悄悄跟在她身后学习。当陈三元终", "score": 2021248, "category": "series", "detail_url": "../movie/0179.html", "poster": "../posters/0179.svg"}, {"id": "0180", "title": "勇者无敌", "year": 2024, "region": "英国", "type": "电影", "genre": "动作 / 战争 / 历史", "tags": ["冷兵器", "角斗士", "罗马", "复仇"], "summary_short": "勇者无敌，2024年英国电影，动作 / 战争 / 历史。公元2世纪，不列颠尼亚。罗马将军维里安被提督陷害通敌，全家被杀，自己被卖到最残酷的采石场。几年后，罗马皇帝巡视不列颠，提督为了讨好皇帝，举办了一场终极死亡竞技：让维里安率领一队死囚，对抗装备精良的第七罗马军团。维里安在角斗士学校重新学会了野蛮的战斗技巧。比赛当天，竞技场设在一个巨大的峡谷边缘。维里安发现皇帝其实知道真相，但为了取乐默许了一切。在战斗中，维里安没有直接进攻，而是利用死", "score": 2024348, "category": "doc", "detail_url": "../movie/0180.html", "poster": "../posters/0180.svg"}, {"id": "0181", "title": "噬亡村第二季", "year": 2025, "region": "日本", "type": "电视剧", "genre": "恐怖，惊悚，剧情", "tags": ["山村怪谈，食人习俗，外来者对抗"], "summary_short": "噬亡村第二季，2025年日本电视剧，恐怖，惊悚，剧情。第一季结尾，阿川大悟被逼入后山祭坛，目睹了“那个东西”从深坑里爬出。第二季开始于三个月后，阿川被认定殉职，而他的女儿真白被村子正式收养，成为新一代“供品”。但阿川没死，他被一个更古老的、与“供牺”对立的猎人家族救下。他得知，噬亡村的“进食”传统是为了压制一个存在了数百年的“空腹之神”。而现在，因为第一季中祭坛被破坏，神即将苏醒。阿川不在乎什么神，他只想救回女儿。他联合了被村子驱逐的异", "score": 2025356, "category": "horror", "detail_url": "../movie/0181.html", "poster": "../posters/0181.svg"}, {"id": "0182", "title": "黑心公司", "year": 2019, "region": "韩国", "type": "电视剧", "genre": "剧情，职场", "tags": ["职场霸凌，复仇，黑心企业，打工者"], "summary_short": "黑心公司，2019年韩国电视剧，剧情，职场。名牌大学毕业的张根秀满怀憧憬进入一家大型建筑公司，以为从此走上人生巅峰。入职第一天，他就发现了问题：公司让员工签空白合同、强制无偿加班、监控办公电脑、甚至要求员工给老板家装修别墅。更可怕的是，前几届试图维权的新员工不是被开除后行业封杀，就是“意外”受伤住院。张根秀想辞职，但违约金是年薪的十倍，他根本付不起。他决定不逃了，他要留下来，把公司干掉。这个看似老实的职场新人开始了一个人的战争：假装顺从", "score": 2019220, "category": "series", "detail_url": "../movie/0182.html", "poster": "../posters/0182.svg"}, {"id": "0183", "title": "笑看人心", "year": 2024, "region": "中国香港", "type": "电视剧 / 剧集", "genre": "剧情 / 心理 / 悬疑", "tags": ["心理医生", "人格分裂", "伦理", "商战", "豪门"], "summary_short": "笑看人心，2024年中国香港电视剧 / 剧集，剧情 / 心理 / 悬疑。心理医生陈笑看以“笑对人心”为准则。她接诊了豪门总裁高天，高天自称有人格分裂，体内住着七个不同的人。随着治疗深入，陈笑看发现高天的七个人格分别对应了七种金融犯罪手段，且都有现实受害者。警方希望她配合取证，但医德禁止她泄露病人隐私。更离奇的是，陈笑看在调查中发现，高天并非天生人格分裂，而是被人用心理学手段“植入”了多重人格，真正的幕后黑手是高天的双胞胎弟弟，目的是为了", "score": 2024263, "category": "series", "detail_url": "../movie/0183.html", "poster": "../posters/0183.svg"}, {"id": "0184", "title": "大侦探第八季", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "悬疑/推理", "tags": ["本格推理，密室，暴风雪山庄，社会派，反转"], "summary_short": "大侦探第八季，2026年中国大陆剧集，悬疑/推理。本季开篇，大侦探受邀参加一场在量子游轮上举行的“推理盛宴”。午夜过后，游轮与外界失联，定位显示已在公海。更诡异的是，船上十二位乘客包括：逃脱的连环杀手、贪腐的政客、诈骗犯、黑心药商……所有人都曾利用法律漏洞逍遥法外。一封匿名信声称：这艘船就是你们的法庭，只有真凶能活着下船。随后，连续的密室杀人开启，死者死法均对应其犯下的罪行。大侦探在追查过程中，发现自己也被算计其中，他的某个不为人知的秘", "score": 2026319, "category": "series", "detail_url": "../movie/0184.html", "poster": "../posters/0184.svg"}, {"id": "0185", "title": "担保（韩国电影）", "year": 2023, "region": "韩国", "type": "电影", "genre": "剧情，犯罪，家庭", "tags": ["高利贷，抵押品，小女孩，赎罪之路，父女情"], "summary_short": "担保（韩国电影），2023年韩国电影，剧情，犯罪，家庭。1993年，仁川。高利贷从业者斗硕和宗培接到任务：追讨非法移民露宿者明子的欠款。明子无法还钱，斗硕按规矩带走她九岁的女儿承怡作为“担保”。斗硕原本只打算吓唬明子，没想到明子第二天因非法居留被遣返出境，承怡成了烫手山芋。两人被迫暂时抚养这个浑身是刺的小女孩。十年间，斗硕从一个只知道放贷的混混变成了承怡真正的“父亲”，甚至放弃高利贷生意开了一家面馆供她读书。2003年，明子突然出现，她", "score": 2023318, "category": "drama", "detail_url": "../movie/0185.html", "poster": "../posters/0185.svg"}, {"id": "0186", "title": "再过四年", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "科幻，悬疑", "tags": ["时间循环，四年一跳，救赎谜题，高概念"], "summary_short": "再过四年，2025年中国大陆剧集，科幻，悬疑。2030年，程序员陆鸣在睡梦中惊醒，发现自己回到了2026年的出租屋。手机显示日期是4年前的8月17日。他以为只是做了一场梦，但24小时后再次入睡时，又跳到了2030年。他意识到自己被困在了一个“四年一跳”的时间循环里——每度过4年，他就会跳回到4年前的起点，重新开始这4年的生活，而每一次跳回后他都会保留全部记忆。在经历了两次跳跃后，他发现了一个规律：每次循环的终点（2030年8月17日），", "score": 2025368, "category": "series", "detail_url": "../movie/0186.html", "poster": "../posters/0186.svg"}, {"id": "0187", "title": "飚速女神", "year": 2024, "region": "日本", "type": "剧集", "genre": "运动 / 剧情 / 热血", "tags": ["赛车", "女性车手", "地下飙车", "师徒", "热血"], "summary_short": "飚速女神，2024年日本剧集，运动 / 剧情 / 热血。28岁的小薰过着普通OL生活，被劈腿男友甩掉后借酒消愁。她开着二手车在首都高架发泄超速，竟用一辆破家用车跑赢了改装跑车。围观人群中的神秘大叔——前JGTC冠军车手神谷看中她的天赋，收她为徒，目标直指地下飙车界最高殿堂“午夜女神杯”。小薰从零学起：跟趾、走线、重量转移。她在这男人主宰的世界里一路过关斩将，最终在暴雨夜的终极对决中，用神谷教她的“绝境漂移”战胜了不可一世的宿敌。", "score": 2024239, "category": "series", "detail_url": "../movie/0187.html", "poster": "../posters/0187.svg"}, {"id": "0188", "title": "七十二家房客第九部粤语", "year": 2023, "region": "中国香港", "type": "剧集", "genre": "剧情 / 喜剧", "tags": ["粤语长片IP", "市井群像", "邻里", "怀旧"], "summary_short": "七十二家房客第九部粤语，2023年中国香港剧集，剧情 / 喜剧。作为经典IP的第九部，故事依旧围绕那座即将被拆除的老旧公寓展开。房东太子炳和八姑的后代——一个精明的富三代——想要趁拆迁大捞一笔，偷偷与地产商签约，要求所有租客限期搬走。租客们已是第三代或第四代住户，包括了老裁缝、冰室老板、退休武师、庙街歌女、补习社老师等形形色色的小人物。他们组织起“护楼联盟”，翻出了几十年前的租约手稿，发现里面有一条被忽略的“永久居住权”条款。于是一场充", "score": 2023301, "category": "series", "detail_url": "../movie/0188.html", "poster": "../posters/0188.svg"}, {"id": "0189", "title": "像恋人一样", "year": 2022, "region": "日本", "type": "电影", "genre": "剧情 / 爱情", "tags": ["伦理", "婚姻", "禁忌", "文艺"], "summary_short": "像恋人一样，2022年日本电影，剧情 / 爱情。资深编剧高仓健一因创作陷入瓶颈，性格变得暴躁阴郁，无法忍受与妻子平淡的日常。为了摆脱愧疚感，他雇佣了一名默默无闻的舞台剧演员，让他按照剧本“扮演”体贴温柔的丈夫去陪伴妻子。起初一切按计划进行，妻子果然变得开朗。但高仓却发现，自己开始跟踪那位演员的现实生活，并爱上了演员那位在便利店打工的素人女友。当妻子、替身、女友四人因为一次暴雨被困在同一座别墅时，虚假的温柔与真实的冷漠发生了激烈的碰撞。", "score": 2022322, "category": "drama", "detail_url": "../movie/0189.html", "poster": "../posters/0189.svg"}, {"id": "0190", "title": "皮革先生", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖 / 犯罪", "tags": ["连环杀手", "皮革面具", "B级片美学", "社会讽刺"], "summary_short": "皮革先生，2024年美国电影，恐怖 / 犯罪。底特律的缝纫师艾德温，白天是手艺精湛的皮革匠，夜里绑架流浪汉并剥皮制成“永生皮革”。他的定制皮衣被富人抢购，每件售价百万，买家不知道材料来源。某天，女警探凯拉在追查失踪案时，发现一件回收的皮衣在温差下会浮现出受害者的指纹和面部轮廓。更诡异的是，穿上皮衣的富豪们开始做同一个噩梦：被缝纫针刺穿喉咙。当凯拉冲进工坊，艾德温正在缝制最后一件作品——用他自杀母亲的皮。他笑着说：“你们才是怪物，穿皮衣时", "score": 2024393, "category": "horror", "detail_url": "../movie/0190.html", "poster": "../posters/0190.svg"}, {"id": "0191", "title": "意外的爱情", "year": 2019, "region": "日本", "type": "电影", "genre": "爱情, 喜剧, 剧情", "tags": ["替身", "身份错位", "职场恋爱", "治愈"], "summary_short": "意外的爱情，2019年日本电影，爱情, 喜剧, 剧情。出版社编辑佐佐木咲为了帮被逼婚的闺蜜解围，硬着头皮假扮她去参加相亲。结果对面坐着的男人，竟是公司新上任的“魔鬼社长”高仓诚司。佐佐木只好继续演戏，假装不认识他。然而高仓却对这个直率冒失的女孩产生了兴趣，开始猛烈追求“闺蜜”。佐佐木在双重身份间疲于奔命，一边要被社长在工作中骂得狗血淋头，一边又要以“相亲对象”身份与他甜蜜约会。当谎言像滚雪球般越来越大，意外接吻、天降暴雨、身份暴露接踵而", "score": 2019342, "category": "romance", "detail_url": "../movie/0191.html", "poster": "../posters/0191.svg"}, {"id": "0192", "title": "炸脖龙", "year": 2026, "region": "美国", "type": "电影", "genre": "奇幻、惊悚", "tags": ["传说生物，生存游戏，小镇秘密，视觉奇观"], "summary_short": "炸脖龙，2026年美国电影，奇幻、惊悚。小镇“灰岩镇”有一个流传百年的传说：地下的炸脖龙以人类谎言为食，若一年内无人主动承认谎言，它便会破土而出。2026年，献祭仪式前夕，少女艾拉发现自己的父亲被选为“最虚伪之人”，她坚信父亲无辜，独自进入禁忌洞穴。在那里她见到了巨大的炸脖龙——它竟能幻化成每个访客内心最恐惧的形象。艾拉被迫直面家族隐瞒的真相：小镇的建立本就源于一场集体谎言。她必须在炸脖龙吞噬所有人的理智前，揭露真相并找到逃出循环的方法", "score": 2026394, "category": "crime", "detail_url": "../movie/0192.html", "poster": "../posters/0192.svg"}, {"id": "0193", "title": "小和尚之游方僧", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "古装、动作、哲理", "tags": ["少年僧侣，公路禅意，武打写实"], "summary_short": "小和尚之游方僧，2026年中国大陆电影，古装、动作、哲理。唐朝末年，年仅十四岁的小和尚明净受圆寂师父遗命，将一枚珍贵的舍利子从长安送回千里之外的故乡寺庙。他身无分文，只带着师父留下的一句话：“若遇恶，先念经；若念经无用，就念我教你的那三招。”明净的师父曾是北派武术高手。一路上，他经过被蝗灾掏空的村庄、遇到假扮僧侣行骗的团伙、被逃兵抢劫、也被善良的农家收留。他发现世间最大的恶不是妖魔，而是因恐惧而疯狂的人。明净从只会念经和机械重复三招，逐", "score": 2026348, "category": "costume", "detail_url": "../movie/0193.html", "poster": "../posters/0193.svg"}, {"id": "0194", "title": "大醉侠2002", "year": 2024, "region": "中国", "type": "剧集", "genre": "武侠 / 喜剧 / 古装", "tags": ["翻拍经典，江湖浪子，醉拳武侠，单元剧"], "summary_short": "大醉侠2002，2024年中国剧集，武侠 / 喜剧 / 古装。距离上一代“醉侠”金燕子名震江湖已经过去二十年。当年那个提着酒壶、打得五岳剑派俯首称臣的奇女子，如今在长安城西市开了一家只卖阳春面的小面馆，滴酒不沾。没人知道为什么。直到一个自称“工业酒精”的新帮派崛起，他们用勾兑的毒酒控制江湖，喝下去的人会力大无穷，但三日必死，死后尸体变成毒源。官府恳求金燕子出山，她不愿。但当毒酒帮的人将工业酒精倒入长安城的饮用水源，她年幼的徒弟中了毒，躺", "score": 2024244, "category": "series", "detail_url": "../movie/0194.html", "poster": "../posters/0194.svg"}, {"id": "0195", "title": "疯狂小世界", "year": 2023, "region": "中国内地", "type": "动画剧集", "genre": "喜剧 / 奇幻", "tags": ["微观世界", "昆虫", "拟人化", "单元剧"], "summary_short": "疯狂小世界，2023年中国内地动画剧集，喜剧 / 奇幻。在人类花园的泥土之下，有一座微光城，居民是各种昆虫和节肢动物。主角阿飞是一只小蚂蚁，但他不想当工蚁，一心想成为像“甲虫侠”那样的超级英雄。问题是，他每次“见义勇为”都会引发连锁灾难：为了救一只掉进胶水的苍蝇，他引爆了整个城市的胶水管道；为了阻止瓢虫强盗团，他弄断了支撑城市的主根茎，导致城邦大停电。阿飞有个死党——一只患有被害妄想症的潮虫，负责帮他计算“灾难概率”。随着剧集发展，阿飞", "score": 2023331, "category": "fantasy", "detail_url": "../movie/0195.html", "poster": "../posters/0195.svg"}, {"id": "0196", "title": "太阳、月亮、飓风", "year": 2024, "region": "泰国", "type": "电视剧", "genre": "爱情", "tags": ["狗血", "同性", "家族恩怨", "虐恋"], "summary_short": "太阳、月亮、飓风，2024年泰国电视剧，爱情。二十年前的一场政变，一对双胞胎女婴被迫分离。妹妹被流亡的政客收养，取名“太阳”，目的是为了有朝一日杀回曼谷；姐姐则被富豪金融大亨收养，取名“月亮”，被培养成优雅的家族棋子。成年后，太阳成为了激进的学运领袖，月亮则是商业帝国的继承人。两人同时爱上了一位试图改革法律的混血律师。太阳的爱是烈火，想拉他一起革命；月亮的爱是深海，想保护他不受家族伤害。律师在两个同样面孔、两种极端爱情间痛苦摇摆。当妹妹", "score": 2024297, "category": "series", "detail_url": "../movie/0196.html", "poster": "../posters/0196.svg"}, {"id": "0197", "title": "奇怪的婚姻", "year": 2025, "region": "印度", "type": "电影", "genre": "喜剧, 爱情, 社会", "tags": ["假结婚", "家庭", "反转"], "summary_short": "奇怪的婚姻，2025年印度电影，喜剧, 爱情, 社会。事业型女律师卡维娅为了继承祖父的庄园，必须在30天内结婚。情急之下她在路边找了个流浪汉拉吉，签下高额报酬的“三月婚姻合同”。拉吉住进她家第一天，就带来了一大家子：卧床的老母亲、五个弟妹、还有一只名叫“首相”的山羊。卡维娅崩溃地发现这家人不仅不守规矩，还把她家变成了社区食堂。更离谱的是，邻居们居然都站拉吉那边。三个月期限将至，卡维娅的竞争对手揭穿了假婚姻。法庭上，拉吉拿出一本日记——上", "score": 2025386, "category": "romance", "detail_url": "../movie/0197.html", "poster": "../posters/0197.svg"}, {"id": "0198", "title": "王子的炼狱", "year": 2025, "region": "英国", "type": "电视剧 (迷你剧)", "genre": "历史 / 剧情 / 传记", "tags": ["王室", "权力斗争", "心理创伤"], "summary_short": "王子的炼狱，2025年英国电视剧 (迷你剧)，历史 / 剧情 / 传记。该剧假设了一个历史支线：退位后的温莎公爵并未获得自由，而是被秘密关押在苏格兰一座废弃城堡。这里被改造成一个“王室炼狱”，专门用于惩戒给君主制带来耻辱的成员。每天有“导师”用精神羞辱和角色扮演的方式逼他重新效忠王室。他被要求反复排练“我放弃王位是因为我不配”的演讲，甚至被迫观看自己弟弟乔治六世的口吃治疗录像作为“激励”。六集剧情中，他从优雅、愤怒、崩溃到最终接受洗脑。", "score": 2025238, "category": "series", "detail_url": "../movie/0198.html", "poster": "../posters/0198.svg"}, {"id": "0199", "title": "狙击精英：幽灵射手", "year": 2024, "region": "美国", "type": "电影", "genre": "动作, 战争", "tags": ["狙击手", "特种部队", "军事", "反恐", "枪战"], "summary_short": "狙击精英：幽灵射手，2024年美国电影，动作, 战争。传奇狙击手布兰登·贝克特（“幽灵”）接到新任务：潜入格鲁吉亚，狙杀正在向欧洲输送致命合成毒品的东欧毒枭。然而，军方高层中有内鬼，提前泄露了行动计划。贝克特的观察手在行动中牺牲，他自己也被诬陷为叛徒，遭到CIA和毒枭雇佣兵的双重追杀。他必须仅凭一把改装狙击枪和有限的子弹，在险峻的峡谷中上演绝地反杀。更复杂的是，他发现自己要射杀的目标，其实是多年前在另一场战争中拯救过他性命的人。亲情、战", "score": 2024343, "category": "crime", "detail_url": "../movie/0199.html", "poster": "../posters/0199.svg"}, {"id": "0200", "title": "小黄人大眼萌粤语", "year": 2023, "region": "中国香港", "type": "电影", "genre": "动画喜剧", "tags": ["萌系， 粤语配音， 冒险， 搞笑"], "summary_short": "小黄人大眼萌粤语，2023年中国香港电影，动画喜剧。鲍勃、凯文和斯图尔特三个小黄人厌倦了南极的孤独生活，偷偷搭乘货轮来到香港。语言不通的它们在庙街夜市引发大混乱：误把鱼蛋当炮弹、在麻将馆里跳“香蕉舞”、还把茶餐厅的丝袜奶茶倒进发动机。正在拍摄低俗喜剧的导演雷导发现了这三个活宝，决定让它们当演员。谁知小黄人们在片场完全不受控制，把道具炸飞、将主角推下海，反倒拍出了一部意外爆红的无厘头神片。但黑帮老大因为它们在赌场捣乱而追捕它们。最终，雷导", "score": 2023269, "category": "fantasy", "detail_url": "../movie/0200.html", "poster": "../posters/0200.svg"}, {"id": "0201", "title": "奇男奇女奇情", "year": 1992, "region": "中国台湾", "type": "电影", "genre": "剧情, 爱情, 伦理", "tags": ["都市", "多线叙事", "欲望", "边缘人", "老电影"], "summary_short": "奇男奇女奇情，1992年中国台湾电影，剧情, 爱情, 伦理。影片采用多线叙事，讲述了台北深夜的四个孤魂。司机每晚载着充气娃娃对话；舞娘爱上了给她写匿名信的忧郁大学生，而大学生其实是跟踪狂；画家只愿为死去的母亲画像；化妆师则偷偷将情人的骨灰混入口红。一场连环追尾事故让四人相遇，在警察局的长椅上，他们用平静的荒唐话治愈了彼此。全片无高潮，只有潮湿的雨水和黑色幽默。", "score": 1992327, "category": "drama", "detail_url": "../movie/0201.html", "poster": "../posters/0201.svg"}, {"id": "0202", "title": "圣诞家族3", "year": 2025, "region": "芬兰", "type": "电影", "genre": "家庭/喜剧", "tags": ["圣诞老人", "遗产继承", "黑帮喜剧", "北欧冷幽默"], "summary_short": "圣诞家族3，2025年芬兰电影，家庭/喜剧。北极圈的圣诞老人因误食姜饼人噎死了。为了防止全世界孩子信仰崩塌，精灵长老们请来了他唯一的血亲——在赫尔辛基混黑道的双胞胎弟弟亚尔莫。这位满脸横肉、纹身密布的壮汉，完全不懂驯鹿和玩具，只知道恐吓与暴力。他试图用管理黑帮的方式管理精灵工坊：给驯鹿套上铁链，把精灵们的咖啡时间改成体能训练，甚至威胁如果玩具做不完就“打断他们的腿”。平安夜降临，他开着装甲雪橇车去送礼物，结果因为找不到烟囱，直接用炸药在", "score": 2025324, "category": "comedy", "detail_url": "../movie/0202.html", "poster": "../posters/0202.svg"}, {"id": "0203", "title": "宝影花痕", "year": 1967, "region": "中国香港", "type": "电影", "genre": "武侠 / 爱情 / 戏曲", "tags": ["邵氏", "黄梅调", "复仇", "易容"], "summary_short": "宝影花痕，1967年中国香港电影，武侠 / 爱情 / 戏曲。明朝末年，将军之女秋棠遭奸人陷害被毁面容，坠崖后被世外高人救起。十年后，江湖上出现一位戴着半边青铜面具的神秘女侠“花痕”，专杀当年陷害秋棠家族的仇人。她修炼的“影剑”必须借助月光与花瓣反射迷惑敌人。在最后一场对决中，仇人发现面具下那张纵横疤痕的脸，她拔剑轻声道：“这张脸，比你们的心干净多了。”血雨过后，她摘下青铜面具埋在将军墓前，骑着一匹瘦马消失于夕阳。", "score": 1967354, "category": "romance", "detail_url": "../movie/0203.html", "poster": "../posters/0203.svg"}, {"id": "0204", "title": "阿姐万岁", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭 / 女性", "tags": ["姐妹情，长姐如母，年代剧，励志，救赎"], "summary_short": "阿姐万岁，2024年中国大陆剧集，剧情 / 家庭 / 女性。1995年，大别山深处的李家有五个女儿。大姐阿秀成绩优异，是全县的状元苗子。但在高考前三天，父亲矿难去世，母亲精神崩溃。阿秀撕掉准考证，扛起整个家，供四个妹妹读书。二十年后，四个妹妹都已成家立业，成为医生、律师、教师和企业家，她们却发现大姐阿秀在十年前突然失踪了。四姐妹踏上寻找大姐的旅程，走遍大半个中国，发现阿秀这些年做过保姆、流水线工人、摆过地摊，最后在一个边陲小镇开了家早餐", "score": 2024271, "category": "drama", "detail_url": "../movie/0204.html", "poster": "../posters/0204.svg"}, {"id": "0205", "title": "蝙蝠女侠第一季", "year": 2024, "region": "美国", "type": "剧集", "genre": "动作, 科幻, 冒险", "tags": ["女英雄", "哥谭", "LGBT", "斗篷"], "summary_short": "蝙蝠女侠第一季，2024年美国剧集，动作, 科幻, 冒险。蝙蝠侠失踪三年，哥谭犯罪率回升。前特种兵兼女同凯恩·凯恩回到哥谭，意外发现表哥布鲁斯的蝙蝠洞。她穿上改良版的蝙蝠战衣，以“蝙蝠女侠”身份夜巡。她的主要对手是爱丽丝，一个戴着红色假发的疯癫女杀手，却也是她失散多年的双胞胎妹妹。凯恩必须在打击犯罪和拯救妹妹灵魂之间做选择。同时，她与警局探长苏菲的旧情复燃，形成复杂的三角关系。本季结尾，凯恩在妹妹和哥谭之间选择了后者，亲手将爱丽丝送入阿", "score": 2024385, "category": "series", "detail_url": "../movie/0205.html", "poster": "../posters/0205.svg"}, {"id": "0206", "title": "蜻蜓", "year": 2012, "region": "中国", "type": "电影", "genre": "悬疑, 惊悚", "tags": ["心理扭曲", "校园霸凌", "复仇", "反转"], "summary_short": "蜻蜓，2012年中国电影，悬疑, 惊悚。鸣翠女中是城里最著名的贵族寄宿学校。新学期开始，舞蹈社的领舞林珊收到一张纸条，上面画着一只血色的蜻蜓。随后，社团成员开始一个接一个地遭遇诡异事件：有人发现自己的舞鞋里被放了碎玻璃，有人在深夜练功房听到了悠扬的钢琴声，而那个位置正是三年前天才舞者许晴坐过的。许晴外号“蜻蜓”，在一次比赛前夜从宿舍楼坠落身亡，被判定为意外。随着新生周小禾的调查深入，她发现舞蹈社的每一个人都与当年的悲剧有关。当凶手的面具", "score": 2012434, "category": "crime", "detail_url": "../movie/0206.html", "poster": "../posters/0206.svg"}, {"id": "0207", "title": "线索", "year": 2025, "region": "西班牙", "type": "电影", "genre": "悬疑推理", "tags": ["剧本杀", "暴风雪山庄", "反转", "多重叙事"], "summary_short": "线索，2025年西班牙电影，悬疑推理。六个互不相识的玩家参加一场号称“百分百真实体验”的豪华剧本杀，地点在一座孤岛别墅。组织者给每人发了一份“角色剧本”，但唯独没发凶手的。第一幕结束后，NPC（非玩家角色）应声倒地，大家以为演技逼真而鼓掌。随后，第二具尸体出现，是真的死了。更诡异的是，在互相交流剧本时，他们发现每个人的剧本里写的“死者”都不一样：A的剧本里B是下个死者，B的剧本里C是下个死者，形成了一个死亡循环。这意味着，玩家中有人在按", "score": 2025340, "category": "crime", "detail_url": "../movie/0207.html", "poster": "../posters/0207.svg"}, {"id": "0208", "title": "坏姐姐之拆婚联盟", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["姐弟恋，拆婚闹剧，都市喜剧，反转结局"], "summary_short": "坏姐姐之拆婚联盟，2025年中国大陆电影，喜剧 / 爱情。广告公司总监秦朵朵是出了名的“护妹狂魔”。当她得知妹妹秦贝贝即将与金融精英周牧结婚时，本想送上祝福，却在一次聚会中震惊地发现，周牧正是十年前玩弄自己感情后人间蒸发的大学学长。无论秦朵朵如何揭露真相，秦贝贝都认定姐姐是在嫉妒，并执意推进婚礼。无奈之下，秦朵朵联合了周牧的前妻、合作伙伴以及被他背叛过的同事，组成了一支“拆婚联盟”，计划在婚礼当天揭穿他的真面目。闹剧接二连三地上演，从单", "score": 2025341, "category": "comedy", "detail_url": "../movie/0208.html", "poster": "../posters/0208.svg"}, {"id": "0209", "title": "不能流泪的悲伤", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "青春, 剧情", "tags": ["干眼症", "无声陪伴", "校园纯爱"], "summary_short": "不能流泪的悲伤，2024年中国大陆电影，青春, 剧情。少女念念患有一种罕见的“情绪性干眼症”，一旦流泪眼角膜就会严重受损。她给自己定了铁律：绝不伤心，绝不哭泣。直到转校生姜野带着他张扬的笑容闯进她的生活，念念发现自己的眼睛开始不受控制。她拼命逃跑，姜野拼命靠近。当姜野查出绝症的消息传来，念念第一次想要痛痛快快地哭一场，却发现自己早已泪干。", "score": 2024269, "category": "drama", "detail_url": "../movie/0209.html", "poster": "../posters/0209.svg"}, {"id": "0210", "title": "一切全包", "year": 2025, "region": "西班牙 / 英国", "type": "电影", "genre": "惊悚、悬疑、讽刺", "tags": ["度假村、暗网、克隆人、黑色幽默、阶级"], "summary_short": "一切全包，2025年西班牙 / 英国电影，惊悚、悬疑、讽刺。厌倦了平庸生活的会计师李明和妻子抢到了号称终极享受的“隐世天堂”一价全包套餐。岛上美轮美奂，服务无微不至，甚至能满足你的任何癖好。但他们很快发现同行的旅客有些不对劲：一对夫妻每天重复着同样的对话，一个网红每天都在同一个地方拍同样的照片。随着深入调查，李明惊恐地发现，这个度假村其实是暗网富豪们的“人格改造工厂”。他们会在假期结束时绑架游客，提取其记忆和才能，制造出绝对忠诚、毫无怨", "score": 2025420, "category": "crime", "detail_url": "../movie/0210.html", "poster": "../posters/0210.svg"}, {"id": "0211", "title": "影子拳手", "year": 2024, "region": "泰国", "type": "电影", "genre": "动作 / 剧情 / 运动", "tags": ["泰拳", "盲人", "复仇", "亲情", "格斗"], "summary_short": "影子拳手，2024年泰国电影，动作 / 剧情 / 运动。曾经的仑披尼拳场冠军赛恩，在一次比赛中因对手犯规导致视网膜脱落而失明，从此隐退，与年幼的女儿小瑛相依为命，经营一家破旧的泰拳馆。十年后，小瑛被发现在城中一条陋巷中身亡，警方定性为吸毒过量。赛恩不相信女儿会吸毒，凭借失明后变得异常敏锐的听觉和触觉，他独自展开调查。他发现女儿生前曾在一个地下赌场打工，那里举办着非法且残忍的“黑拳”比赛，而赌场的老板正是当年在擂台上弄瞎他双眼的那个对手的", "score": 2024334, "category": "drama", "detail_url": "../movie/0211.html", "poster": "../posters/0211.svg"}, {"id": "0212", "title": "三个强盗之龙的传承", "year": 2023, "region": "中国大陆", "type": "动画电影", "genre": "动画，冒险，奇幻", "tags": ["国风，怪兽，友情，成长"], "summary_short": "三个强盗之龙的传承，2023年中国大陆动画电影，动画，冒险，奇幻。在一个妖怪与人类共存的世界，强盗三人组——老大铁锤、老二飞刀和老三鬼点——是业界最失败的组合。一次失败的抢劫后，他们偷到的唯一值钱东西是一颗有奇异花纹的蛋。当晚，蛋孵出了一只不会飞、只会喷火星的小龙。他们本想卖掉小龙大赚一笔，却得知这条龙是消失百年的“山岳龙脉”的最后传人，野心家们都在追捕它。三个原本只想混日子的强盗，为了保护这个“小麻烦”，不得不挺身而出，与各路贪婪的妖", "score": 2023310, "category": "fantasy", "detail_url": "../movie/0212.html", "poster": "../posters/0212.svg"}, {"id": "0213", "title": "小公主苏菲亚第四季", "year": 2025, "region": "美国", "type": "动画剧集", "genre": "动画 / 奇幻 / 教育", "tags": ["公主", "魔法", "成长", "责任", "友谊"], "summary_short": "小公主苏菲亚第四季，2025年美国动画剧集，动画 / 奇幻 / 教育。第四季开篇，苏菲亚的艾薇拉护身符突然失去所有魔力，她再也不能与动物说话，也无法召唤迪士尼公主。皇家学院新来了一位善于使用高阶魔法的转学生莉亚，她对苏菲亚“靠护身符当公主”嗤之以鼻。苏菲亚陷入自我怀疑，但她没有选择退学，而是决定用最笨的方法学习：亲手为三胞胎妹妹缝制舞会礼服，熬夜替因生病而无法上课的同学整理笔记，在王国遭遇干旱时带领村民挖掘古老的水渠。护身符始终没有恢复", "score": 2025269, "category": "fantasy", "detail_url": "../movie/0213.html", "poster": "../posters/0213.svg"}, {"id": "0214", "title": "还我清白抢银行", "year": 2024, "region": "英国", "type": "电影", "genre": "犯罪喜剧", "tags": ["老年抢劫，冤案昭雪，养老金危机，黑色幽默"], "summary_short": "还我清白抢银行，2024年英国电影，犯罪喜剧。退休邮差亚瑟发现自己的养老金账户被金融公司“未来资本”清零，同时收到一封寄给已故妻子的信，暗示妻子30年前的“自杀”实为谋杀。亚瑟联系了四位老友：患有阿尔茨海默症的前会计、坐轮椅的退伍老兵、唠叨的家庭主妇、以及耳背的业余发明家。五人决定抢劫“未来资本”的保险库，拿走属于自己的钱，并寻找谋杀证据。他们用助听器改造成窃听器，用轮椅改装成运钞车，甚至用老花镜破解了密码锁。抢劫成功当晚，他们发现保险", "score": 2024365, "category": "comedy", "detail_url": "../movie/0214.html", "poster": "../posters/0214.svg"}, {"id": "0215", "title": "落跑吧爱情", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "爱情、喜剧、公路", "tags": ["逃婚、公路之旅、欢喜冤家、自我成长"], "summary_short": "落跑吧爱情，2025年中国台湾电影，爱情、喜剧、公路。富家女宋佳妍在婚礼宣誓前突然清醒，穿着婚纱跳上路边一辆老旧面包车，只想逃离现场。司机阿民生意失败后靠在垦丁拉客度日，嘴毒心软，最看不惯“公主病”。两人一个要躲进山里的秘密民宿，一个只认导航上的指定路线，矛盾不断。一路上爆胎、误入庙会、被前未婚夫派人围堵，甚至共睡一辆抛锚的车。宋佳妍发现阿民画的绘本里藏着她童年最爱的灯塔，而阿民也发现她并非表面那般骄纵。当逃婚热搜冲上第一，他们必须决定", "score": 2025381, "category": "comedy", "detail_url": "../movie/0215.html", "poster": "../posters/0215.svg"}, {"id": "0216", "title": "火星追击", "year": 2021, "region": "美国", "type": "电影", "genre": "动作, 科幻, 惊悚", "tags": ["火星", "营救", "外星生物", "硬核科幻"], "summary_short": "火星追击，2021年美国电影，动作, 科幻, 惊悚。21世纪中叶，火星前哨基地“黎明号”在采集深层岩芯样本时，意外唤醒了被冰封百万年的地外硅基生命体。这种生物以金属和能量为食，迅速摧毁了基地，仅剩一名科学家躲入避难所。地球联合政府派出由经验丰富的杰克率领的精英特种小队，前往火星执行“清扫与营救”任务。他们全副武装，自信能应对任何威胁。然而，当他们抵达火星，发现对手是一种拥有集群智慧、能模拟环境并进化武器的非碳基生命时，这场追猎游戏的角色", "score": 2021516, "category": "crime", "detail_url": "../movie/0216.html", "poster": "../posters/0216.svg"}, {"id": "0217", "title": "龙骑士2022", "year": 2022, "region": "英国", "type": "电影", "genre": "奇幻 / 动作", "tags": ["龙族", "现代骑士", "血脉觉醒"], "summary_short": "龙骑士2022，2022年英国电影，奇幻 / 动作。中世纪骑士兰斯洛特被魔法封印在龙晶中，2022年意外被建筑工人挖出。苏醒后的他发现世界已经没有龙，却在地下铁系统中感应到强烈的龙息。原来，最后一条巨龙被邪恶科技公司捕获，意识被强行转移到了一列地铁列车的AI系统中。龙骑士必须在三天内摧毁公司的控制芯片，而敌方派出的是他的亲生后代——一名对家族使命一无所知的地铁司机。现代武器与古老龙焰在隧道中碰撞，骑士必须在拯救龙与拯救血脉之间做出抉择。", "score": 2022392, "category": "crime", "detail_url": "../movie/0217.html", "poster": "../posters/0217.svg"}, {"id": "0218", "title": "兄弟有你就知足", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭 / 喜剧", "tags": ["兄弟", "亲情治愈", "小镇青年", "和解", "成长"], "summary_short": "兄弟有你就知足，2024年中国大陆电影，剧情 / 家庭 / 喜剧。南方小镇，高中生林北一直痛恨父亲再婚后带来的“哥哥”陈默。陈默是个沉默寡言、成绩优异的“别人家孩子”，总是被林母拿来比较。暑假来临，父母因故出差，将两人扔在老房子里。林北想尽办法赶走陈默，甚至剪断他心爱吉他的琴弦。然而他发现陈默每晚都偷偷出门，回来时身上带着伤。跟踪后林北震惊地发现，陈默一直在替被高利贷骚扰的林父还债，甚至在地下拳场打黑拳。而陈默之所以如此拼命，是因为他亲", "score": 2024302, "category": "drama", "detail_url": "../movie/0218.html", "poster": "../posters/0218.svg"}, {"id": "0219", "title": "水面之上", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻 / 惊悚", "tags": ["水下世界", "基因改造", "反乌托邦", "洪水"], "summary_short": "水面之上，2026年美国电影，科幻 / 惊悚。2124年，冰川融化导致陆地消失，幸存者居住在由巨型模块拼接而成的“方舟浮城”上。主角艾登是一名水质工程师，负责清理底部的侵蚀物。一次深潜维修中，他发现水下并非一片死寂，而是存在着高度进化的两栖智慧生物——“深蓝族”。更惊人的是，“深蓝族”掌握着净化海洋的技术，而浮城统治者一直在秘密捕杀它们，以维持自己的能源垄断。艾登必须在人类种族存续和跨物种道义之间做出选择。当他试图公开真相时，浮城开始解", "score": 2026390, "category": "horror", "detail_url": "../movie/0219.html", "poster": "../posters/0219.svg"}, {"id": "0220", "title": "一颗红心", "year": 2025, "region": "中国", "type": "电影", "genre": "剧情 / 历史", "tags": ["红色", "信仰", "传承", "小人物"], "summary_short": "一颗红心，2025年中国电影，剧情 / 历史。1949年秋，北平。国民党军医处的文书沈默胆小如鼠，只求平安去台湾。不料，他被长官强行塞了一个恒温箱，命令他必须在48小时内送往广州——箱子里是一颗需要移植给某位重要将领的“供体心脏”。阴差阳错之下，沈默发现自己护送的对象其实是地下党为了营救被捕同志而制造的声东击西的假目标。真正的任务是一份潜伏名单。面对两党特务的围追堵截，沈默从最初的恐惧逃避，到逐渐被护送途中遇到的普通百姓所感动。最后时刻", "score": 2025301, "category": "drama", "detail_url": "../movie/0220.html", "poster": "../posters/0220.svg"}, {"id": "0221", "title": "霹雳天机2仙魔决", "year": 2024, "region": "中国台湾", "type": "电视剧", "genre": "奇幻 / 武侠 / 古装", "tags": ["布袋戏，仙魔，宿命，正邪"], "summary_short": "霹雳天机2仙魔决，2024年中国台湾电视剧，奇幻 / 武侠 / 古装。《霹雳天机》第二部。仙门之主“云虚”与魔界皇者“焰皇”在上一部同归于尽，换来人间百年和平。一个身怀仙魔双血的少年“非天”在荒野中长大，不知其身世。仙门认为他是魔种，欲除之后快；魔界认为他是仙孽，欲夺其血解开封印。正邪两派为追杀或保护他，再次掀起江湖波澜。非天在逃亡中，遇到了自称是他师父的疯道士，以及一个想要利用他复仇的魔族公主。随着体内仙魔之力不断冲突，非天每次失控都", "score": 2024263, "category": "series", "detail_url": "../movie/0221.html", "poster": "../posters/0221.svg"}, {"id": "0222", "title": "炭疽第二季", "year": 2026, "region": "美国", "type": "电视剧", "genre": "惊悚、政治、医疗", "tags": ["生化恐怖、阴谋论、病毒学、FBI、高层博弈"], "summary_short": "炭疽第二季，2026年美国电视剧，惊悚、政治、医疗。时间跳转到第一次生物袭击后的第18个月。一种经过基因改造的新型炭疽菌株在三个大洲同时爆发。与第一季的随机投放不同，这一季的炭疽似乎有了“选择性”：它只感染那些掌握着特定政治或军事机密的人，且死后尸体不会传播病菌，像是被精确“收割”。FBI生化专家艾莉丝发现，病菌内被植入了基于CRISPR的生物计算机，能以特定DNA序列为“钥匙”激活。这意味着投放者手中握有一份全球“叛徒”名单。当追查对", "score": 2026308, "category": "series", "detail_url": "../movie/0222.html", "poster": "../posters/0222.svg"}, {"id": "0223", "title": "碧亨传：鬼怪的主人", "year": 2026, "region": "泰国", "type": "电视剧", "genre": "恐怖 / 奇幻 / 同性 / 爱情", "tags": ["泰式恐怖，鬼王，驱魔，虐恋"], "summary_short": "碧亨传：鬼怪的主人，2026年泰国电视剧，恐怖 / 奇幻 / 同性 / 爱情。阿碧从小在泰国的殡仪馆长大，他能看见并驱使亡魂，是远近闻名的“鬼怪的主人”。但实际上，他只是一个孤独的年轻人，鬼魂们怕他，活人也怕他。在一次驱邪仪式中，他遇到了帅气的警长帕特。帕特不信鬼神，却屡屡卷入灵异案件。阿碧在帮助帕特破案（利用鬼魂指证凶手）的过程中，对帕特产生了不一样的感情。然而，阿碧发现帕特的阳气正在被一只厉鬼偷偷吞噬，帕特的命格属于“三世怨侣”，注", "score": 2026370, "category": "series", "detail_url": "../movie/0223.html", "poster": "../posters/0223.svg"}, {"id": "0224", "title": "独角兽2017", "year": 2017, "region": "中国大陆", "type": "电影", "genre": "剧情， 奇幻", "tags": ["创业， 梦想， 独角兽企业"], "summary_short": "独角兽2017，2017年中国大陆电影，剧情， 奇幻。2017年，互联网创业浪潮之巅。程序员李想与好友张野共同开发的社交软件“独角兽”一夜爆红，估值破亿。然而资本的涌入让两人产生分歧：李想坚持免费初心，张野则追求商业变现。随着神秘投资人王总的介入，公司被推向了一场危险的资本游戏。李想被迫出局后，发现“独角兽”APP竟成了洗钱工具。为了拯救自己的心血和误入歧途的好友，李想利用代码后门潜入系统，在年度发布会的关键时刻，用一串隐藏的代码揭露了", "score": 2017347, "category": "drama", "detail_url": "../movie/0224.html", "poster": "../posters/0224.svg"}, {"id": "0225", "title": "捉鬼小灵精", "year": 2023, "region": "美国", "type": "电影", "genre": "喜剧 / 恐怖 / 奇幻", "tags": ["儿童冒险", "萌系恐怖", "捉鬼敢死队"], "summary_short": "捉鬼小灵精，2023年美国电影，喜剧 / 恐怖 / 奇幻。在流量至上的时代，三个成绩垫底的小学生组成了“捉鬼小灵精”组合，专门在学校废弃的旧楼里直播探险，其实全是道具和特效。直到有一天，他们在图书馆找到了一本由真正驱魔人撰写的《初级捉鬼指南》。为了涨粉，他们决定按照书中的咒语召唤一只“小鬼”。没想到咒语失效，召唤来的是一只沉睡百年的噬魂恶灵。面对真正的超自然威胁，摄像机成了他们唯一的武器，而屏幕前的数百万网友，则成了他们能否活下去的唯一", "score": 2023474, "category": "horror", "detail_url": "../movie/0225.html", "poster": "../posters/0225.svg"}, {"id": "0226", "title": "超速快感", "year": 2020, "region": "美国", "type": "电影", "genre": "动作 / 惊悚", "tags": ["改装车", "卧底警察", "地下赛车"], "summary_short": "超速快感，2020年美国电影，动作 / 惊悚。卧底警察陈杰潜伏在亚洲最大的地下改装车组织已有三年。他接近了核心人物“幽灵”，却发现“幽灵”不仅是车手，更是军火贩子。为了拿到犯罪证据，陈杰必须参加一场名为“超速快感”的死亡赛事。规则很简单：从洛杉矶开到拉斯维加斯，不限路线，不限手段，最先到达的人获得所有赌注和一箱军火交易资料。比赛开始后，陈杰才发现对手们都不是来赛车的，而是来杀人的。有人装火箭弹，有人撒钉刺带。在沙漠公路的生死追逐中，陈杰", "score": 2020352, "category": "crime", "detail_url": "../movie/0226.html", "poster": "../posters/0226.svg"}, {"id": "0227", "title": "死亡诗篇", "year": 2021, "region": "英国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["诗歌， 大学， 连环谋杀， 诅咒， 文学理论"], "summary_short": "死亡诗篇，2021年英国电影，悬疑 / 惊悚。享有盛誉的爱丁堡大学文学院，在一周内接连发生三起命案：一位教授被溺死在装满雪莱诗稿的浴缸里；另一位被巨大的精装诗集砸碎头骨；第三位则被藤蔓勒死，身旁放着布莱克的《老虎》。警方束手无策，因为现场没有外力痕迹。年轻的文学讲师伊芙琳发现，这些死亡方式与“死亡诗派”的古老仪式惊人吻合。她怀疑凶手是利用诗歌进行诅咒。随着调查深入，她发现受害者都曾参与过20年前对一位天才诗人学生的集体霸凌，导致其自杀。", "score": 2021418, "category": "crime", "detail_url": "../movie/0227.html", "poster": "../posters/0227.svg"}, {"id": "0228", "title": "轮到你了 剧场版", "year": 2025, "region": "日本", "type": "电影", "genre": "悬疑 / 惊悚 / 犯罪", "tags": ["交换杀人", "平行结局", "原班人马", "脑洞大开"], "summary_short": "轮到你了 剧场版，2025年日本电影，悬疑 / 惊悚 / 犯罪。本片设定为剧版的平行时空——第一季末尾的“轮到你了”游戏根本没有启动，管理员也没有坠楼。两年后，手冢菜奈和翔太过着普通夫妻的生活。然而新住户松井偶然在502室的电表箱后面发现了一个布满灰尘的信箱，里面塞满了写有人名和“愿望”的纸条。他以为是恶作剧，随手写下了“想让楼上的钢琴声消失”。第二天，那位钢琴教师真的因车祸住院了。恐惧与好奇驱使住户们重新激活了这个信箱，这一次，“交换", "score": 2025483, "category": "crime", "detail_url": "../movie/0228.html", "poster": "../posters/0228.svg"}, {"id": "0229", "title": "非越自由梦", "year": 2023, "region": "中国香港 / 法国", "type": "电影", "genre": "剧情 / 文艺 / 社会", "tags": ["移民，偷渡，身份认同，船舱寓言，人性实验"], "summary_short": "非越自由梦，2023年中国香港 / 法国电影，剧情 / 文艺 / 社会。1980年代，越南难民潮。一艘超载的货船驶向香港，23人挤在密不透风的集装箱里。淡水只剩三天，船主提议：每人匿名投票，得票最高者被丢入大海。第一次投票，一名患病的老妇人被选中，她的儿子哭着替母亲跳了海。第二次投票，一名记者开始偷拍记录，却被船长发现。第七天，香港的海岸线出现了，但船主收到无线电：港府拒绝接收。绝望中，一个曾当过老师的女人站出来，提议所有人轮流讲述自己", "score": 2023311, "category": "drama", "detail_url": "../movie/0229.html", "poster": "../posters/0229.svg"}, {"id": "0230", "title": "假装情侣", "year": 2011, "region": "中国大陆", "type": "电影", "genre": "喜剧, 爱情", "tags": ["都市情感", "假戏真做", "女追男"], "summary_short": "假装情侣，2011年中国大陆电影，喜剧, 爱情。沈露是保险公司里的金牌销售，为了在公司年度大会上刺激甩了她的前男友，决定花重金租一个“完美男友”。她看中了在街头拉小提琴卖艺的穷学生陈文。陈文为了给重病的妹妹筹钱，无奈接下了这单生意。两人签订了一份详细的合同，明确规定了牵手、拥抱等“服务项目”的价格。在前男友面前，两人配合得天衣无缝，但当合同结束，沈露发现自己习惯了陈文的陪伴，而陈文也爱上了这个刀子嘴豆腐心的女孩。就在沈露准备表白时，前男", "score": 2011335, "category": "romance", "detail_url": "../movie/0230.html", "poster": "../posters/0230.svg"}, {"id": "0231", "title": "快龙", "year": 2025, "region": "日本", "type": "电影", "genre": "动画、冒险、奇幻", "tags": ["宝可梦、龙族、骑乘、守护神"], "summary_short": "快龙，2025年日本电影，动画、冒险、奇幻。动画电影，主角是一只被称为“天空守护者”的老快龙，它曾在大灾难中拯救过城市，如今已步入老年，翅膀受伤无法长距离飞行。关都各地突然出现巨大的黑影，袭击发电厂和港口，人们怀疑是新的野生宝可梦。一位年轻的训练师小驱发现了真相：黑影其实是快龙年轻时打败过的老对手——一只被封印的暴飞龙因环境恶化而苏醒。快龙感知到老对手的气息，不顾小驱劝阻，强行起飞与暴飞龙决战。第一回合快龙完败，坠入海中。小驱找到传说中", "score": 2025357, "category": "fantasy", "detail_url": "../movie/0231.html", "poster": "../posters/0231.svg"}, {"id": "0232", "title": "末日巡逻队第三季", "year": 2024, "region": "美国", "type": "剧集", "genre": "科幻, 动作, 喜剧", "tags": ["超英", "废土", "时间循环", "公路"], "summary_short": "末日巡逻队第三季，2024年美国剧集，科幻, 动作, 喜剧。第三季开篇，地球已是一片废土。首席失踪，机甲人、底片人、疯狂简和钢骨被迫分散求生。当他们在一座废弃的游乐园重聚时，发现世界每隔24小时就会重置一次，但只有队员们的记忆得以保留。在无数次循环中，他们不断尝试改变结局，却一次次失败。直到疯狂简体内的一个从未出现的人格揭示：这场末日其实是一场针对巡逻队的终极审判，由来自时间尽头的邪恶版本首席操控。为了打破循环，钢骨不得不牺牲自己与主控", "score": 2024370, "category": "series", "detail_url": "../movie/0232.html", "poster": "../posters/0232.svg"}, {"id": "0233", "title": "超异能部队", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作, 科幻, 惊悚", "tags": ["超能力", "南北韩", "秘密实验", "灰色地带"], "summary_short": "超异能部队，2025年韩国电影，动作, 科幻, 惊悚。朝韩边境的地下水污染事件，意外催生了官方掩盖的“觉醒者”。为了应对日益升级的隐形威胁，韩国军方秘密启动“阿尔法计划”，从脱北者中挑选了7名死囚，注射逆转录病毒改造的超级血清。他们获得了瞬移、念力、自愈等能力，组成“超异能部队”执行无法公开的黑色任务。然而，队员姜大卫发现，每次使用能力，自己的细胞端粒就会急剧缩短，能力越强，寿命越短。当部队接到命令，要暗杀一名呼吁和平统一的民间领袖时，", "score": 2025462, "category": "crime", "detail_url": "../movie/0233.html", "poster": "../posters/0233.svg"}, {"id": "0234", "title": "艺妓恩娜奥", "year": 2023, "region": "日本", "type": "电影", "genre": "剧情 / 历史 / 悬疑", "tags": ["大正时代", "艺妓复仇", "浮世绘", "反转"], "summary_short": "艺妓恩娜奥，2023年日本电影，剧情 / 历史 / 悬疑。1917年，京都花街。混血孤儿恩娜奥因异域容貌被赎身培养成艺妓。她技艺超群，却总在陪酒时用扇子和三味线的节奏传递古怪暗号。与此同时，多名贵族和富商接连在家中密室被发现死亡，死状安详如睡去。警视厅特高课发现，恩娜奥竟是被拐卖至此的俄国贵族之女，她的全家都死于这场人口贩卖阴谋。她利用艺妓身份接近仇人，在床榻与酒桌间通过定制精油与暗示性语言触发仇家的心脏病或自杀倾向。最终反转在于：一直", "score": 2023351, "category": "drama", "detail_url": "../movie/0234.html", "poster": "../posters/0234.svg"}, {"id": "0235", "title": "空巢", "year": 2018, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["老人", "孤独", "亲情", "社会现实"], "summary_short": "空巢，2018年中国大陆电影，剧情 / 家庭。七十岁的周淑芳住在北京一套三居室里，老伴去世三年，儿女定居美国和加拿大。她学会了用微信视频，但每次通话都不超过五分钟。她每天的生活如出一辙：买菜、做饭、看电视、对着空气自言自语。一天她接到一个电话，对方自称是某银行的客服，一口一个“阿姨”叫得亲热。周淑芳明知道是诈骗，却舍不得挂断，因为已经很久没有人这样耐心地陪她聊天了。她甚至主动配合对方，一步步转账。当警察赶到阻止时，她说了一句让所有人沉默", "score": 2018304, "category": "drama", "detail_url": "../movie/0235.html", "poster": "../posters/0235.svg"}, {"id": "0236", "title": "胡杨的夏天", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "爱情, 剧情", "tags": ["公路片", "沙漠植物", "守林人"], "summary_short": "胡杨的夏天，2023年中国大陆电影，爱情, 剧情。固执的植物学家胡杨常年驻扎在塔克拉玛干沙漠边缘，试图通过克隆技术复活一片千年胡杨林。某天，一场罕见的黑沙暴过后，他在废墟中发现了一位浑身是伤的城市摄影师夏天。夏天失去了所有记忆，只记得按快门的本能。胡杨收留了她，两个孤独的灵魂在荒芜中产生了微妙情愫。夏天用摄影镜头重新发现了胡杨林震撼人心的美，帮助胡杨的研究获得了外界关注。然而，当夏天的记忆逐渐恢复，她发现自己曾受雇于一个想要开发这片土地", "score": 2023309, "category": "drama", "detail_url": "../movie/0236.html", "poster": "../posters/0236.svg"}, {"id": "0237", "title": "兄弟之仇", "year": 2024, "region": "中国香港", "type": "电影", "genre": "犯罪", "tags": ["黑帮", "亲情", "复仇", "双雄"], "summary_short": "兄弟之仇，2024年中国香港电影，犯罪。二十年前的一场火灾，让年幼的兄弟天各一方。哥哥阿诚被好心人收养，成为了一名正直的警察；弟弟阿义则在街头流浪，被黑帮老大收养，培养成了冷血的打手。多年后，阿诚奉命渗透进阿义所在的帮派，两人在不知情的情况下结拜为异姓兄弟。随着任务推进，阿诚发现目标就是自己的亲弟弟，而阿义也察觉到自己最信任的“兄弟”可能是警方卧底。在黑帮内斗和警方收网的双重压力下，两人终于相认，但身份和立场已无法回头。最后一场天台对决", "score": 2024361, "category": "crime", "detail_url": "../movie/0237.html", "poster": "../posters/0237.svg"}, {"id": "0238", "title": "排球少年剧场版：观念之战", "year": 2025, "region": "日本", "type": "电影", "genre": "动画运动", "tags": ["热血", "竞技", "理念碰撞"], "summary_short": "排球少年剧场版：观念之战，2025年日本电影，动画运动。全国高中联赛决赛圈，乌野高中对阵连续三年夺冠的霸主青城南高。青城信奉以绝对数据和严密逻辑构建的“无敌方程式”，队长兼天才二传手及川彻认为“才能才能开花结果”。而乌野的日向翔阳则坚信“球感”和“直觉”能创造奇迹。本剧场版聚焦这一场史诗对决，从每一个救球、每一次拦网中，探讨竞技体育的本质。当飞吧的口号与冷冰冰的数据碰撞，哪一方才能站上球场中央，接受聚光灯的洗礼？", "score": 2025249, "category": "doc", "detail_url": "../movie/0238.html", "poster": "../posters/0238.svg"}, {"id": "0239", "title": "光灵：武士之魂", "year": 2025, "region": "日本", "type": "电影", "genre": "动画，奇幻，动作", "tags": ["幕末，兽人，魔法杖，武士道"], "summary_short": "光灵：武士之魂，2025年日本电影，动画，奇幻，动作。故事发生在架空幕末时代，西方黑船带来了魔法与兽人族。曾是幕府 elite 武士的浪人伊藏，因主公被兽人将军所杀而沦为醉汉。他接下一单看似简单的委托：护送一把被称为“光灵”的魔法刀前往京都。与他同行的是一位被逐出兽人部队的士兵雷克，以及一个捡到刀的人类孤儿小太郎。三人发现这把刀能吸收持刀者的记忆，并在满月之夜说话。随着追杀者不断出现，伊藏意识到这把刀里封印着最后一头远古飞龙的意识，而各", "score": 2025404, "category": "fantasy", "detail_url": "../movie/0239.html", "poster": "../posters/0239.svg"}, {"id": "0240", "title": "逆旅奇观", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情， 奇幻， 悬疑", "tags": ["时间循环， 酒店奇遇， 存在主义"], "summary_short": "逆旅奇观，2023年法国电影，剧情， 奇幻， 悬疑。疲惫的纪录片导演陈莫住进一家老酒店，发现101号房通往1942年纳粹占领下的巴黎，202号房通往2084年核战后的废土，303号房则通向宋朝的客栈。他必须在当天午夜前，从各个时空的住客口中收集七把青铜钥匙，才能打开顶层套房的门。过程中他目睹了1942年犹太女孩的绝望、2084年最后一名人类的孤独、宋朝客栈里诗人的绝命诗。当他集齐钥匙打开门，却发现自己站在童年老家的客厅里，母亲端着一碗面", "score": 2023466, "category": "drama", "detail_url": "../movie/0240.html", "poster": "../posters/0240.svg"}, {"id": "0241", "title": "法证先锋2国语", "year": 2025, "region": "中国香港", "type": "电视剧", "genre": "悬疑， 犯罪， 刑侦", "tags": ["法证， 鉴证科学， 连环凶杀， 港剧"], "summary_short": "法证先锋2国语，2025年中国香港电视剧，悬疑， 犯罪， 刑侦。法证部高级化验师高彦博率领团队，遇到前所未有的高智商挑战。一名自称“审判者”的凶手，每次行凶前都会向警局寄出一页法证学教科书复印件，但其中一条规则被他故意篡改。如果法证人员按书中的错误规则去鉴证，就会掉入陷阱。第一宗案件，垃圾桶里的焦尸被误判为自杀，直到第二具尸体出现。团队发现凶手曾是法证学最优秀的毕业生，因一次冤案被毁了一生。他在报复整个司法系统。法证、法医、重案组三方联", "score": 2025351, "category": "series", "detail_url": "../movie/0241.html", "poster": "../posters/0241.svg"}, {"id": "0242", "title": "自杀契约", "year": 2022, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚 / 犯罪", "tags": ["小镇秘闻", "高中生困境", "反转再反转", "社会派推理"], "summary_short": "自杀契约，2022年美国电影，悬疑 / 惊悚 / 犯罪。宁静的湖滨小镇，三个月内六名高中生以不同方式自杀，死前都曾签署一份名为“永生俱乐部”的契约——承诺如果有一天想死，其他成员必须一起。警探莉娜的女儿也是成员之一，但女儿坚称那只是中二游戏。当第七名死者出现，莉娜发现所有人的死亡时间、方式和地点，都精确指向一本20年前的推理小说。小说作者早已去世，但书中的凶手是个老师。莉娜深入调查，发现当年的老师正是现任校长，而20年前也有一批学生“集", "score": 2022521, "category": "crime", "detail_url": "../movie/0242.html", "poster": "../posters/0242.svg"}, {"id": "0243", "title": "小小克星第二季", "year": 2024, "region": "日本", "type": "剧集", "genre": "动画 / 青春 / 科幻", "tags": ["平行世界", "催泪", "Key社", "日常喜剧", "轮回"], "summary_short": "小小克星第二季，2024年日本剧集，动画 / 青春 / 科幻。承接第一季结局，直枝理树和“Little Busters”成员们成功从无尽的暑假轮回中脱出，但他们发现现实世界并没有变得正常。枣铃开始频繁梦见另一个自己，而真人突然拥有预知下一秒的能力。第二季引入新角色“观测者”，一个自称是这个世界管理员的神秘少女。她告诉众人：你们所在的并不是原本的世界，而是由一名濒死孩子意识创造出来的“赎罪乐园”。为了让那名孩子安心离世，理树必须在30天内", "score": 2024271, "category": "series", "detail_url": "../movie/0243.html", "poster": "../posters/0243.svg"}, {"id": "0244", "title": "人烟之岛", "year": 2024, "region": "俄罗斯", "type": "电影", "genre": "科幻 / 冒险 / 反乌托邦", "tags": ["后末日", "孤岛", "实验社会", "生存"], "summary_short": "人烟之岛，2024年俄罗斯电影，科幻 / 冒险 / 反乌托邦。2174年，核战后的地球只剩下一座名为“方舟”的人工岛屿，五千名幸存者在全自动AI系统“母亲”的管理下生存了七十年。岛上没有犯罪、没有疾病、没有饥饿，但也没有出生——人类已经无法自然受孕。年轻人阿莱娜在岛屿最底层的档案室发现了一间密封的投票厅，里面保存着2104年的电子投票记录。记录显示，当年全球190个国家就是否发动“预防性核打击”进行了一次秘密公投，结果赞成票68%。阿莱", "score": 2024334, "category": "sci-fi", "detail_url": "../movie/0244.html", "poster": "../posters/0244.svg"}, {"id": "0245", "title": "月亮的华尔兹", "year": 2025, "region": "韩国", "type": "剧集", "genre": "爱情 / 奇幻 / 音乐", "tags": ["月亮", "自闭症", "钢琴", "时空通讯"], "summary_short": "月亮的华尔兹，2025年韩国剧集，爱情 / 奇幻 / 音乐。患有自闭症的天才钢琴少年尹星，每晚都会爬上屋顶弹奏自己创作的《月亮的华尔兹》。某天，他发现自己的琴声竟然能被月光反射，穿越到二十年前。接收到琴声的是当年的舞蹈系学生郑雅拉，她正因腿伤而面临梦想破灭。两人通过月光下的琴声和足尖的回响开始了一段跨越时空的交流。尹星用未来的旋律治愈了郑雅拉的绝望，而郑雅拉用舞蹈的律动教会了尹星如何与外界沟通。然而历史是有惯性的，如果郑雅拉的腿被治好，", "score": 2025322, "category": "series", "detail_url": "../movie/0245.html", "poster": "../posters/0245.svg"}, {"id": "0246", "title": "八个够晒数续集", "year": 1997, "region": "香港", "type": "电影", "genre": "喜剧", "tags": ["搞笑", "怀旧", "打工人", "香港回归", "黑色幽默"], "summary_short": "八个够晒数续集，1997年香港电影，喜剧。1997 年前夕，当年靠小聪明混社会的“八个够晒数”老友重聚。领头阿强提议再做一单“大茶饭”，实则各自暗藏私心。老实人肥昆意外中了六合彩头奖，却不敢声张，只敢偷偷给老婆买金链。其余七人察觉端倪，开始用尽荒唐手段套近乎：装病、认亲、甚至伪造遗嘱。就在众人撕破脸之际，肥昆说出真相——奖金早被他在澳门赌场输光。绝望之中，八人发现当年合伙买的破仓库竟被划入重建区，补偿金刚好八份。他们相视苦笑，决定最后一", "score": 1997330, "category": "comedy", "detail_url": "../movie/0246.html", "poster": "../posters/0246.svg"}, {"id": "0247", "title": "拿破仑先生", "year": 2024, "region": "法国", "type": "电影", "genre": "传记, 历史, 剧情", "tags": ["拿破仑", "法国", "历史人物", "战争", "政治"], "summary_short": "拿破仑先生，2024年法国电影，传记, 历史, 剧情。巴黎郊区的公立小学里，有一位被学生称为“拿破仑先生”的老教师。他其貌不扬，矮小严厉，却能用一块黑板带领学生们“征服”整个世界。他用滑铁卢战役讲解团队合作，用《拿破仑法典》教孩子们什么是公平。当一个移民家庭的学生面临被驱逐出境时，六十二岁的拿破仑先生决定组织一场“百日王朝”——在教育局、法院和移民局之间奔走，像当年的拿破仑一样，用策略和毅力打赢人生中最后一场战役。", "score": 2024274, "category": "doc", "detail_url": "../movie/0247.html", "poster": "../posters/0247.svg"}, {"id": "0248", "title": "摇滚万万岁", "year": 2025, "region": "英国", "type": "剧集", "genre": "喜剧, 音乐, 伪纪录片", "tags": ["讽刺", "重金属", "过气明星", "荒唐巡演"], "summary_short": "摇滚万万岁，2025年英国剧集，喜剧, 音乐, 伪纪录片。纪录片团队跟踪拍摄了80年代传奇乐队“刺脊”时隔40年的重组巡演。主唱戴维因为灵修吃素瘦成了竹竿，吉他手为了支付离婚费卖掉了所有经典 riff 版权。巡演大巴抛锚、演出场地塌陷、甚至鼓手在台上被道具龙卷风卷走，他们都能淡定地用双踩鼓点掩盖过去。面对台下寥寥无几、且多半是来看笑话的中年粉丝，乐队成员在酒精和争吵中，竟意外找回了一开始玩音乐的初心。最终在音乐节的泥泞里，他们弹奏了一首", "score": 2025273, "category": "series", "detail_url": "../movie/0248.html", "poster": "../posters/0248.svg"}, {"id": "0249", "title": "因为爱情有奇迹", "year": 2014, "region": "中国大陆", "type": "剧集", "genre": "爱情 / 家庭", "tags": ["虐恋", "豪门", "失忆", "复仇"], "summary_short": "因为爱情有奇迹，2014年中国大陆剧集，爱情 / 家庭。单纯善良的安琪媛被豪门丈夫齐霁误解赶出家门，惨遭车祸后失忆流落海外。五年后，她成为国际顶尖珠宝设计师“Angel”强势回归。而此时，齐霁正因她当年的“背叛”而痛苦不已。安琪媛假装不认识他，进入齐氏集团工作，在商场上一次次击败他。然而当她准备揭开最后底牌时，却发现当年陷害她的真凶另有其人，而齐霁这五年其实一直在暗中保护她和孩子们。爱情与仇恨交织，这场为“报复”开始的游戏，最终变成了双", "score": 2014277, "category": "series", "detail_url": "../movie/0249.html", "poster": "../posters/0249.svg"}, {"id": "0250", "title": "超正经乐团的糊涂战争", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 战争 / 音乐", "tags": ["荒诞，交响乐，误会，黑色幽默，小成本"], "summary_short": "超正经乐团的糊涂战争，2023年中国大陆电影，喜剧 / 战争 / 音乐。抗战时期，一支来自上海的“超正经交响乐团”奉命前往前线慰问。因为翻译官是个乐盲，他们拿着一份过时的地图，误打误撞走进了中日双方对峙的无人区。在浓雾中，双方哨兵都误以为对方发起了总攻。慌乱中，乐团为了壮胆开始演奏气势磅礴的《威廉·退尔》序曲。那激昂的旋律在峡谷中回荡，被双方误认为是敌方新型“音波武器”。在一连串荒诞的误会和走火中，乐团稀里糊涂地成了“民族英雄”。", "score": 2023296, "category": "doc", "detail_url": "../movie/0250.html", "poster": "../posters/0250.svg"}, {"id": "0251", "title": "玩命杀手", "year": 2026, "region": "美国", "type": "电影", "genre": "动作/惊悚", "tags": ["反英雄", "高速追杀", "黑色幽默", "器官交易"], "summary_short": "玩命杀手，2026年美国电影，动作/惊悚。绰号“医生”的杀手杰克在一次任务后被黑帮迷晕，醒来发现自己少了一个肾。命不久矣的他决定在死前复仇。一次意外注射让他获得了异于常人的自愈能力和反应速度，但代价是生命只剩下72小时。他开着一辆改装过的肌肉车，开始了一场疯狂的死亡倒计时。从街头混混到器官移植的黑心医生，杰克用最残暴也最艺术的方式逐一清除名单上的人。联邦警探莫妮卡一路追查连环凶杀案，却发现这个杀人魔的目标竟是拯救更多无辜的受害者。当最后", "score": 2026427, "category": "crime", "detail_url": "../movie/0251.html", "poster": "../posters/0251.svg"}, {"id": "0252", "title": "月夜行车", "year": 2024, "region": "德国", "type": "电影", "genre": "悬疑，剧情", "tags": ["出租车，平行时空，对话，命运"], "summary_short": "月夜行车，2024年德国电影，悬疑，剧情。柏林夜班出租车司机汉斯有个习惯：每晚十一点在同一个街角等客。奇怪的是，他每次接到的都是同一位名叫安娜的女乘客，但每次安娜的年龄、衣着和身份都截然不同。有时她是18岁离家出走的叛逆少女，有时是30岁被家暴的绝望主妇，有时是60岁患了老年痴呆的老妪。更诡异的是，每个安娜都不认识他，但都提到自己“做了一个梦，梦里有个开出租车的男人”。汉斯意识到自己连接着安娜的平行人生。他试图干预，告诉年轻的安娜别嫁错", "score": 2024394, "category": "drama", "detail_url": "../movie/0252.html", "poster": "../posters/0252.svg"}, {"id": "0253", "title": "秘密窗口", "year": 2004, "region": "美国", "type": "电影", "genre": "悬疑，惊悚，剧情", "tags": ["心理惊悚，作家，双重人格，封闭空间，反转"], "summary_short": "秘密窗口，2004年美国电影，悬疑，惊悚，剧情。畅销书作家莫特·雷尼与妻子离婚后，隐居在偏僻的湖边小屋写作。一天，一个名叫约翰·舒特的神秘男子找上门，指控莫特抄袭了他写的小说《秘密窗口》。莫特读完小说后震惊地发现，那确实是自己从未发表过的作品，但他对此毫无记忆。舒特开始跟踪、恐吓莫特，要求他归还署名权。莫特试图调查舒特的身份，却发现查无此人。随着压力增大，莫特的行为越来越古怪，他开始出现时间空白，甚至在梦游中写作。最终莫特发现，舒特其实", "score": 2004428, "category": "crime", "detail_url": "../movie/0253.html", "poster": "../posters/0253.svg"}, {"id": "0254", "title": "求生之路：冲出禁区", "year": 2026, "region": "美国", "type": "电影", "genre": "动作/科幻/惊悚", "tags": ["末世求生", "变异生物", "限时任务", "废土美学"], "summary_short": "求生之路：冲出禁区，2026年美国电影，动作/科幻/惊悚。致命的病毒泄漏将整片区域化为“禁区”，任何生物进入后都会在72小时内发生恐怖变异。前特种兵凯恩为了拯救感染绝症的女儿，不得不接受一项九死一生的任务——带领一支由罪犯和科研菜鸟组成的杂牌军，深入禁区中心取回仅存的实验血清。他们不仅要面对极端环境，还要提防彼此之间的背叛。随着死亡人数增加，凯恩发现这场任务背后隐藏着更大的阴谋：禁区深处并非只有怪物，还有一个试图利用病毒重塑人类秩序的秘", "score": 2026514, "category": "crime", "detail_url": "../movie/0254.html", "poster": "../posters/0254.svg"}, {"id": "0255", "title": "僵尸儿童", "year": 2024, "region": "法国", "type": "电影", "genre": "恐怖，奇幻，历史", "tags": ["巫毒，殖民，儿童，诅咒"], "summary_short": "僵尸儿童，2024年法国电影，恐怖，奇幻，历史。大地震后的太子港，无国界医生艾玛在临时医院里遇到了七个行为怪异的孩子。他们不会饥饿、不怕疼痛、瞳孔呈现灰白色，却能流利地说着一种已经失传的非洲语言。艾玛通过当地巫毒祭司得知，这些孩子是被一种古老的“灵魂固着术”困在生与死之间的僵尸。更惊人的是，他们声称自己是1791年领导奴隶起义的七个少年战士，被法国殖民者用一种残忍的巫术“杀死并冻结”，直到地震震开了封印。如今他们归来，是为了完成未竟之事", "score": 2024383, "category": "costume", "detail_url": "../movie/0255.html", "poster": "../posters/0255.svg"}, {"id": "0256", "title": "卓娅因子", "year": 2025, "region": "俄罗斯", "type": "电影", "genre": "战争 / 剧情 / 传记", "tags": ["二战，女性英雄，谍战，心理惊悚"], "summary_short": "卓娅因子，2025年俄罗斯电影，战争 / 剧情 / 传记。1941年的雪夜，莫斯科郊外的村子里。卓娅被俘后没有立刻被处决，而是被交给了一位从柏林来的心理学专家。这位专家试图用弗洛伊德的理论、饥饿和孤独来瓦解她的意志，他坚信这个年轻女孩之所以不屈服，只是因为某种“精神疾病”或“被洗脑”。审讯室变成了一间心理诊疗室。卓娅开始讲起她的童年、她读过的书、以及她看到的第一个被德军杀害的村民。那一夜，审讯者发现自己变成了被审视的对象，他开始怀疑自己", "score": 2025280, "category": "doc", "detail_url": "../movie/0256.html", "poster": "../posters/0256.svg"}, {"id": "0257", "title": "万古仙穹第二季", "year": 2025, "region": "中国大陆", "type": "动画", "genre": "奇幻，冒险，修仙", "tags": ["修仙，权谋，大场面，国风"], "summary_short": "万古仙穹第二季，2025年中国大陆动画，奇幻，冒险，修仙。承接第一季，主角古海破解了仙穹下层的秘密后，发现整个修仙界不过是上界仙人的“养殖场”。第二季中，古海联合人、妖、魔三族的反抗者，成立“破穹会”，开始了对仙庭统治的颠覆之路。他们游走于各大宗门之间，拉拢摇摆势力，对抗仙庭的镇压。本季中期，古海设计引发仙庭内斗，令仙帝闭关疗伤。就在反抗军准备总攻时，古海最信任的兄弟却为了长生背叛了他，导致计划全盘泄露。古海陷入绝境，却也因此领悟了超越", "score": 2025206, "category": "fantasy", "detail_url": "../movie/0257.html", "poster": "../posters/0257.svg"}, {"id": "0258", "title": "埃塔的信心", "year": 2023, "region": "西班牙", "type": "电影", "genre": "剧情 / 历史", "tags": ["恐怖组织", "赎罪", "女性视角"], "summary_short": "埃塔的信心，2023年西班牙电影，剧情 / 历史。70岁的埃塔前成员埃塔（化名）隐姓埋名生活了30年。当年她负责驾车，同伙的炸弹袭击导致一名孕妇早产，婴儿最终死在了废墟里。如今身患绝症的她，在神父的劝导下决定找回那个婴儿的尸体，让它安息。这是一条自我救赎的“朝圣之路”。她不仅要面对当年的受害人家属，还要躲避埃塔残余势力的追杀，因为她的行动暴露了组织藏匿武器的地点。在挖掘那片早已变成停车场的废墟时，她不知道自己挖出的，是救赎，还是更深的罪", "score": 2023249, "category": "drama", "detail_url": "../movie/0258.html", "poster": "../posters/0258.svg"}, {"id": "0259", "title": "人间有味山河鲜", "year": 2024, "region": "中国大陆", "type": "纪录片", "genre": "纪录片，美食，人文", "tags": ["河鲜海鲜，中国地理，渔民故事，季候美食，烟火人间"], "summary_short": "人间有味山河鲜，2024年中国大陆纪录片，纪录片，美食，人文。本片共六集，每集聚焦一种“水中的鲜味”：开化的青虾、松花江的三花五罗、阳澄湖六月黄、南海的红星梭子蟹、雅鲁藏江的裸裂尻鱼、以及查干湖冬捕头鱼。与常见美食纪录片不同，它不以烹饪技法为核心，而是用一整年时间跟拍捕捞者的生活。你会看到凌晨三点踩着薄冰收虾笼的老李，一边冻得发抖一边说“虾甜，那是它吃够了水草”；也会看到南海渔船上，年轻的船长在台风来临前赌上全船性命去追那一网“红蟹云图", "score": 2024103, "category": "doc", "detail_url": "../movie/0259.html", "poster": "../posters/0259.svg"}, {"id": "0260", "title": "残宵留得梦依稀", "year": 2025, "region": "中国大陆 / 香港", "type": "电影", "genre": "文艺 / 爱情", "tags": ["戏曲", "老年", "失忆", "戏班", "民国"], "summary_short": "残宵留得梦依稀，2025年中国大陆 / 香港电影，文艺 / 爱情。86岁的京剧名伶沈秋岚住在养老院，她的记忆每天都会被“重置”到1965年那个夜晚——那是她最后一次登台，唱《牡丹亭》时忘词，从此告别舞台。每天清晨，她都以为自己是年轻的名角，要赶去戏院。护工小李会配合她，为她画上褪色的红妆，架好已经不存在的戏台。沈秋岚的儿子从美国回来，想接她去治疗，但医生说任何强行唤醒记忆的方式都会加剧病情。儿子偷偷带来当年她忘词那一场的录音，沈秋岚听到", "score": 2025309, "category": "drama", "detail_url": "../movie/0260.html", "poster": "../posters/0260.svg"}, {"id": "0261", "title": "万圣德加的传奇", "year": 2025, "region": "法国 / 加拿大", "type": "动画电影", "genre": "动画, 奇幻, 冒险", "tags": ["画家", "魔法", "艺术世界"], "summary_short": "万圣德加的传奇，2025年法国 / 加拿大动画电影，动画, 奇幻, 冒险。在奥赛博物馆的深夜，德加的名画《舞蹈课》里的芭蕾舞女演员小吉姆因为不满于永远定格，打破了画框的界限。她发现德加的另一幅画正被收藏家判定为赝品，即将被销毁。为了证明这幅画的真迹身份，小吉姆带着一群“画中人”——从高更的塔希提岛到莫奈的睡莲池，穿梭于不同的名画世界寻找德加遗留的签名笔迹。她们在梵高的星月夜里躲避乌鸦，在雷诺阿的舞会上与大盗周旋。最终，她们用舞蹈在画布上", "score": 2025338, "category": "fantasy", "detail_url": "../movie/0261.html", "poster": "../posters/0261.svg"}, {"id": "0262", "title": "诱饵2019", "year": 2019, "region": "中国大陆", "type": "电影", "genre": "犯罪, 悬疑", "tags": ["卧底", "反转", "警匪", "硬汉"], "summary_short": "诱饵2019，2019年中国大陆电影，犯罪, 悬疑。缉毒警察林凯在一次行动中失败，导致线人惨死，被停职调查。为了戴罪立功，他接受了一个极其危险的任务：伪装成外省来的大毒枭，去接近盘踞在边境多年的贩毒集团头目“将军”。林凯带着精心打造的假身份和假毒品，一步步深入虎穴。就在他即将取得“将军”信任时，所有警方行动都被对方提前知晓，林凯多次险些丧命。他开始怀疑警队内部有内鬼，而真正的“将军”可能另有其人。林凯利用自己“诱饵”的身份，反客为主，在", "score": 2019437, "category": "crime", "detail_url": "../movie/0262.html", "poster": "../posters/0262.svg"}, {"id": "0263", "title": "19层", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "悬疑, 惊悚, 冒险", "tags": ["无限流", "密室逃脱", "游戏", "心理学", "高概念"], "summary_short": "19层，2024年中国大陆剧集，悬疑, 惊悚, 冒险。春雨、高玄等大学生被卷入一款名为“19层”的诡异密室逃脱游戏。游戏共有19层，每一层都基于中国民间传说或现代都市怪谈构建，如皮影戏院、鬼校晚自习等。他们必须破解谜题、战胜怪物才能进入下一层，而每深入一层，众人内心最恐惧的秘密就会被具象化攻击。随着游戏推进，他们发现这其实是某个已故心理学家的脑电波实验，目的是用极端恐惧治疗心理创伤。然而实验失控，若无法在现实中关掉主机，所有人都将在第1", "score": 2024386, "category": "series", "detail_url": "../movie/0263.html", "poster": "../posters/0263.svg"}, {"id": "0264", "title": "反击第一季", "year": 2010, "region": "英国", "type": "剧集", "genre": "动作/战争/谍战", "tags": ["特种部队", "反恐", "兄弟情", "血腥", "高能"], "summary_short": "反击第一季，2010年英国剧集，动作/战争/谍战。前 SAS 队员波特因一次人质解救行动失败而被部队开除，后被秘密部门 20 分部招募。他的新任务是追捕一个名为“拉蒂夫”的恐怖分子头目。与搭档科利森一起，两人从中东的沙漠追踪到欧洲的都市。第一季共 6 集，每集都是一次高强度的突袭行动。剧情紧凑，几乎没有喘息机会，且毫不避讳战争的残酷与道德灰色地带。波特不仅要面对外部的敌人，还要应对内部的阴谋，第一季结尾的惊天反转直接为第二季埋下了沉重伏", "score": 2010265, "category": "series", "detail_url": "../movie/0264.html", "poster": "../posters/0264.svg"}, {"id": "0265", "title": "掉头即死", "year": 2025, "region": "日本", "type": "电影", "genre": "惊悚 / 悬疑 / 恐怖", "tags": ["都市传说", "诅咒", "公路", "无人生还"], "summary_short": "掉头即死，2025年日本电影，惊悚 / 悬疑 / 恐怖。七名乘客坐上从东京开往大阪的夜行巴士，深夜在山间公路上抛锚。司机用颤抖的声音说：这里有传说，掉头的人会被带走。话音未落，他听到身后有婴儿哭声，下意识回头——瞬间消失。剩下的乘客陷入恐慌，有人开始尝试掉头逃跑，但每一个回头的人都会在几秒内化为灰烬。最后剩下的女人发现，只要不看身后，就能安全走到山下。她走到公路尽头，转身想看一眼山下灯火，突然一只冰凉的手搭上了她的肩膀。", "score": 2025539, "category": "crime", "detail_url": "../movie/0265.html", "poster": "../posters/0265.svg"}, {"id": "0266", "title": "稻草狗", "year": 2011, "region": "英国 / 美国", "type": "电影", "genre": "惊悚、剧情", "tags": ["暴力复仇、封闭社区、以暴制暴、人性底限"], "summary_short": "稻草狗，2011年英国 / 美国电影，惊悚、剧情。美国数学家大卫带着英国妻子艾米搬回了她宁静的家乡小镇，打算专心完成学术著作。然而，当地以查理为首的施工队成员们，以帮艾米家修屋顶为名，不断越界骚扰。起初，大卫选择隐忍和讲道理，但换来的却是变本加厉的侮辱。当一只被邻居毒死的猫被挂在他们家门口，艾米也惨遭侵犯后，大卫意识到法律在这里形同虚设。一个雨夜，查理一伙人闯入他的家中，声称要找一名藏匿其中的逃犯。大卫终于卸下了知识分子的外壳，利用家中", "score": 2011380, "category": "drama", "detail_url": "../movie/0266.html", "poster": "../posters/0266.svg"}, {"id": "0267", "title": "彩绘门", "year": 2025, "region": "意大利", "type": "电影", "genre": "奇幻、剧情、家庭", "tags": ["治愈、艺术、重生、邻里"], "summary_short": "彩绘门，2025年意大利电影，奇幻、剧情、家庭。不会说话的男孩里奥住在破败的那不勒斯老城区。他每天都会用捡来的颜料涂抹小区那扇生锈的铁门。一夜暴雨后，门上的颜料幻化成了一幅流动的画。第一个触摸门的快递员，发现自己瞬间到了送货目的地；单亲妈妈触摸后，见到了去世丈夫的幻影。消息传开，全城轰动。里奥成了“神童”。但一个地产商想买下这扇门用于商业。居民们为了保护这扇“奇迹之门”团结起来。最终里奥在门上画出了所有邻居的肖像，门的力量升级为“连接人", "score": 2025341, "category": "drama", "detail_url": "../movie/0267.html", "poster": "../posters/0267.svg"}, {"id": "0268", "title": "陌上人如玉", "year": 2021, "region": "中国大陆", "type": "电视剧", "genre": "古装, 爱情, 喜剧", "tags": ["书院", "欢喜冤家", "女扮男装", "甜宠", "科举"], "summary_short": "陌上人如玉，2021年中国大陆电视剧，古装, 爱情, 喜剧。将军之女苏陌陌从小习武，性格豪爽。为了追查父亲失踪的真相，她女扮男装化名“苏墨”进入京城最好的松竹书院。她的室友兼死对头，是当朝宰相之子、冷面才子萧玉。两人家族是政敌，一见面就水火不容。苏陌陌睡觉会说梦话暴露身份、洗澡差点穿帮、被萧玉怀疑是女子却因为打了一架反而成了“好兄弟”。在共同调查苏将军失踪案的过程中，他们从互相拆台到携手破局，萧玉逐渐发现自己对“苏墨”产生了奇怪的感觉，", "score": 2021331, "category": "series", "detail_url": "../movie/0268.html", "poster": "../posters/0268.svg"}, {"id": "0269", "title": "纽约时刻", "year": 2004, "region": "美国", "type": "电影", "genre": "喜剧, 家庭", "tags": ["姐妹", "追星", "黑帮", "一日冒险"], "summary_short": "纽约时刻，2004年美国电影，喜剧, 家庭。简是一个极负责任的优等生，她为了参加一个能在牛津大学面试中加分的青年学者论坛，独自来到纽约。她的双胞胎妹妹罗克茜是个朋克少女，偷偷跟着姐姐来到纽约，目的是为了拿到偶像Hip-Hop歌手的演唱会门票。为了赶上不同地点的会议和签售，姐妹俩被迫共用一辆租来的小车。罗克茜不小心把车弄丢，车后备箱里却藏着一份黑帮的犯罪证据。于是，姐妹俩展开了一场疯狂的纽约大追踪。她们误闯片场、穿着舞女服逃跑、还在垃圾处", "score": 2004241, "category": "comedy", "detail_url": "../movie/0269.html", "poster": "../posters/0269.svg"}, {"id": "0270", "title": "夺标", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动作，运动", "tags": ["武术，奥运，民族精神，师徒"], "summary_short": "夺标，2025年中国大陆电影，动作，运动。1936年，中国派出第一支正式的奥运代表团参加柏林奥运会。然而，武术作为表演项目，不仅不被西方国家认可，更被日本代表团公然嘲讽为“杂耍”。领队郑怀贤带领张文广、温敬铭等武术家，决定不在官方安排的场合表演花架子，而是私下向德国拳击冠军发起“无规则实战挑战”。这场不被官方记录的“夺标”，输赢关乎的不只是个人荣辱，更是中华民族的尊严。在纳粹眼皮底下，中国武术家用血肉之躯，展示了中华武术的实战威力，赢得", "score": 2025317, "category": "crime", "detail_url": "../movie/0270.html", "poster": "../posters/0270.svg"}, {"id": "0271", "title": "奇案夺命箭", "year": 2023, "region": "中国香港", "type": "电影", "genre": "悬疑 / 犯罪 / 动作", "tags": ["古装探案，密室杀人，武侠推理，神箭手，连环杀手"], "summary_short": "奇案夺命箭，2023年中国香港电影，悬疑 / 犯罪 / 动作。南宋年间，四位曾经参与过某次军火运输的江湖大佬，在各自戒备森严的府邸中被同一支刻有“夺命”二字的箭矢射杀。现场皆是密室，箭矢穿过之处的机关皆从内部锁死。大理寺新晋推官方慕白接手此案，发现能射出这种“曲绕三梁、破甲无声”之箭的，只有二十年前已故的第一神箭手沈惊鸿。更诡异的是，箭矢上的DNA（滴血认亲技术）指向沈惊鸿的独女，但她早在十年前就失踪了。随着调查，方慕白发现当年那次军火", "score": 2023482, "category": "crime", "detail_url": "../movie/0271.html", "poster": "../posters/0271.svg"}, {"id": "0272", "title": "出埃及记：天地王者", "year": 2025, "region": "美国", "type": "电影", "genre": "史诗动作", "tags": ["圣经改编，古埃及，特效大片，战争，信仰"], "summary_short": "出埃及记：天地王者，2025年美国电影，史诗动作。不同于传统的神话改编，本片重新构想了摩西的故事。摩西不再是神的使者，而是一名在古埃及宫廷长大的奴隶之子。当他得知自己的身世并被流放后，在沙漠深处发现了一处坠毁的“远古飞船”残骸。通过飞船的人工智能，他得知希伯来人并非神的选民，而是飞船原始船员的后裔。而所谓的“十灾”，不过是摩西利用飞船上残留的纳米科技，对埃及进行的精准打击。本片讲述了摩西如何从一个迷茫的逃亡者，逐渐熟练运用外星科技，最终", "score": 2025345, "category": "crime", "detail_url": "../movie/0272.html", "poster": "../posters/0272.svg"}, {"id": "0273", "title": "心生爱慕却迟迟不敢", "year": 2025, "region": "日本", "type": "电视剧", "genre": "爱情，剧情，治愈", "tags": ["暗恋，成年人爱情，职场，慢热，双向奔赴"], "summary_short": "心生爱慕却迟迟不敢，2025年日本电视剧，爱情，剧情，治愈。出版社文艺编辑部的朝比奈和小野寺是公认的金牌搭档，共事七年，默契到不需要说话就知道对方在想什么。整个公司的人都知道他们互相喜欢，只有他们自己不知道——不，他们知道，但都以为对方对自己只是同事之情。朝比奈觉得自己个子矮、收入一般、离过一次婚，配不上小野寺。小野寺觉得朝比奈是天才编辑，自己只是普通校对，配不上对方。两人就这样拉扯了七年，各自相亲无数次都以失败告终。直到公司要裁撤整个", "score": 2025295, "category": "series", "detail_url": "../movie/0273.html", "poster": "../posters/0273.svg"}, {"id": "0274", "title": "他的脑子有病", "year": 2024, "region": "中国内地", "type": "电影", "genre": "喜剧、爱情、奇幻", "tags": ["精神疾病， 反转， 暖心， 洗冤录"], "summary_short": "他的脑子有病，2024年中国内地电影，喜剧、爱情、奇幻。倒霉蛋李大明被误抓进青山精神病院。为了证明自己没病，他声称自己看到了“真相”：病友老张是火星派来监控地球的，护士长是金星叛徒，院长的秃头是外星天线。医生把他作为重度妄想症研究案例。李大明在院里配合“治疗”，实则偷偷收集证据，打算出院后写书揭露。直到有一天，一个自称“银河系联盟”的神秘组织真的联系了他，告诉他：他看到的“幻觉”其实是真的，但那些外星人是在保护地球免遭虫族入侵。李大明懵", "score": 2024366, "category": "romance", "detail_url": "../movie/0274.html", "poster": "../posters/0274.svg"}, {"id": "0275", "title": "分手信", "year": 2024, "region": "美国", "type": "电影", "genre": "爱情 / 剧情", "tags": ["信件", "遗憾", "异地恋", "时间旅行", "反转"], "summary_short": "分手信，2024年美国电影，爱情 / 剧情。艾米在婚礼前一晚收拾老房子阁楼时，发现一封没有邮戳的信。信是她大学男友杰克写的分手信，日期是十年前，但字迹很新。诡异的是，杰克正是她明天要嫁的人。十年前他们因异地恋和误解分手，五年前重新相遇并复合。艾米开始调查这封信的来源，发现杰克从大学时就开始给自己写信，但从未寄出。而这封最新写成的信上，杰克坦白了自己在复合期间曾有过的一刹那动摇。更惊人的是，艾米在自己旧日记里发现了回信，字迹却不属于自己。", "score": 2024381, "category": "drama", "detail_url": "../movie/0275.html", "poster": "../posters/0275.svg"}, {"id": "0276", "title": "沼泽", "year": 2025, "region": "英国 / 爱尔兰", "type": "电影", "genre": "恐怖 / 心理 / 民俗", "tags": ["民俗恐怖", "沼泽怪物", "小镇秘密", "献祭"], "summary_short": "沼泽，2025年英国 / 爱尔兰电影，恐怖 / 心理 / 民俗。考古队在爱尔兰偏远沼泽中发现一具保存完好的铁器时代古尸，身上刻满从未见过的符文。古尸被送往都柏林后，小镇开始发生怪事：所有新生婴儿在出生当晚，嘴里都会被泥炭填满，但监控显示没有任何人进入产房。更恐怖的是，每发生一次“填泥”事件，沼泽就会向小镇推进三米。当地一位九十岁的最后一位盖尔语老妇人告诉警长：那不是古尸，是“沼泽之王”，它每隔一千年就需要一个“王后”的献祭来镇压。而这次", "score": 2025321, "category": "horror", "detail_url": "../movie/0276.html", "poster": "../posters/0276.svg"}, {"id": "0277", "title": "超级飞侠第十一季", "year": 2022, "region": "中国大陆", "type": "剧集 / 动画", "genre": "动画 / 儿童 / 冒险", "tags": ["益智", "超级飞侠", "全球文化", "解决问题"], "summary_short": "超级飞侠第十一季，2022年中国大陆剧集 / 动画，动画 / 儿童 / 冒险。新一季中，超级飞侠团队迎来了更多拥有特殊技能的伙伴。乐迪依然负责派送包裹，但每次任务都会遇到意想不到的麻烦。无论是帮助威尼斯的小朋友拯救被海藻困住的贡多拉，还是在非洲大草原上寻找走失的小狮子，超级飞侠们总是第一时间伸出援手。本季特别强调了环保主题，飞侠们会带领观众了解冰川融化、海洋垃圾等问题，并教会孩子们如何从身边小事做起。通过一次次的冒险，孩子们不仅能学习到", "score": 2022159, "category": "fantasy", "detail_url": "../movie/0277.html", "poster": "../posters/0277.svg"}, {"id": "0278", "title": "妻子的噩梦", "year": 2025, "region": "韩国", "type": "剧集", "genre": "惊悚 / 悬疑", "tags": ["梦魇入侵", "婚姻骗局", "双重人格"], "summary_short": "妻子的噩梦，2025年韩国剧集，惊悚 / 悬疑。家庭主妇智秀连续三十天做同一个噩梦：深夜用水果刀刺向丈夫的颈部。起初她认为是压力过大，直到某天清晨，丈夫颈部出现一道细小红痕，位置与梦中完全一致。她偷偷安装摄像头，发现每晚凌晨三点，自己都会梦游般走向厨房，但醒来后对记忆毫无保留。心理医生怀疑她是人格分裂，但丈夫坚持不肯就医。直到智秀在丈夫衣兜里翻出一瓶安眠药——剂量足以让一个成年人整夜无法醒来。", "score": 2025365, "category": "series", "detail_url": "../movie/0278.html", "poster": "../posters/0278.svg"}, {"id": "0279", "title": "小查与寇弟的顶级冒险", "year": 2023, "region": "美国", "type": "电影", "genre": "冒险, 喜剧", "tags": ["双胞胎", "遗产争夺", "环球旅行"], "summary_short": "小查与寇弟的顶级冒险，2023年美国电影，冒险, 喜剧。距离经典剧集结局已过去十五年，小查成了落魄的魔术师，寇弟是牛津大学的历史讲师。两人收到一封从瑞士寄来的遗书，从未谋面的曾祖父留给他们一张羊皮地图和三段谜语。第一条线索指向巴黎下水道博物馆的一尊老鼠雕像，第二把钥匙埋在威尼斯沉船书店的《神曲》第666页，第三把则藏在东京歌舞伎町的一台老式街机里。但曾祖父的前商业合伙人派出雇佣兵一路围追堵截。兄弟俩在巴黎差点被冲进化粪池，在威尼斯被鸽子", "score": 2023300, "category": "comedy", "detail_url": "../movie/0279.html", "poster": "../posters/0279.svg"}, {"id": "0280", "title": "没人写信给上校", "year": 2022, "region": "墨西哥", "type": "电影", "genre": "剧情 / 文艺", "tags": ["等待", "退休", "斗鸡"], "summary_short": "没人写信给上校，2022年墨西哥电影，剧情 / 文艺。改编自马尔克斯同名小说。老上校七十五岁，参加过革命，如今靠妻子卖炸鱼为生。他唯一的指望是每周五去码头等待邮船——退伍军人养老金的通知信。十五年，从未等到。这周家中断粮，他只有一只斗鸡（儿子遗产），如果下周日的斗鸡赛输掉，全家将再无收入。妻子问他：“那信如果永远不来呢？”他回答：“会来的。”周六晚上，他偷偷把鸡喂饱，第二天鸡赢了，奖金够吃三个月。走出赛场，他没有去码头，而是对妻子说：“", "score": 2022282, "category": "drama", "detail_url": "../movie/0280.html", "poster": "../posters/0280.svg"}, {"id": "0281", "title": "哥哥负妹", "year": 1993, "region": "中国香港", "type": "电影", "genre": "剧情, 动作, 犯罪", "tags": ["九龙城寨", "兄妹情仇", "黑帮悲剧"], "summary_short": "哥哥负妹，1993年中国香港电影，剧情, 动作, 犯罪。阿强曾是一名活跃在九龙城寨的黑帮打手，为了妹妹能够读书脱离这个环境，他伪造了自己的死亡，在码头做苦力。十年后，妹妹已经是一名优秀的见习律师。然而，一次法庭对决中，妹妹指控的黑帮头目正是阿强曾经的大哥“疯狗威”。疯狗威认出了她，并设局将其绑架。阿强被迫重出江湖，他疯狗威手下的昔日兄弟展开了血腥的巷战。最后阿强杀入仓库时才发现，妹妹为了保护他不被要挟，已经自己咬断了绳索，从三楼跳下。阿", "score": 1993418, "category": "crime", "detail_url": "../movie/0281.html", "poster": "../posters/0281.svg"}, {"id": "0282", "title": "最强会长黑神第二季", "year": 2012, "region": "日本", "type": "动画", "genre": "校园， 超能力", "tags": ["西尾维新， 智斗， 全能会长"], "summary_short": "最强会长黑神第二季，2012年日本动画，校园， 超能力。第二季中，箱庭学园迎来了一位神秘的转校生——善存凶。他宣称要“矫正”黑神目泷那种多管闲事的正义感。随着“十三班的十三人”这一异常班级浮出水面，整个学园的“过负荷”（异常者）能力开始暴走。黑神发现，自己的“完成”能力并非万能，面对善存凶那种让一切“正常化”的“否定”能力，她第一次尝到了败北的滋味。为了守护学园的“异常”，会长必须开发出超越“完成”的“创造”能力，与这位史上最强大的对手", "score": 2012120, "category": "fantasy", "detail_url": "../movie/0282.html", "poster": "../posters/0282.svg"}, {"id": "0283", "title": "家庭作业", "year": 2024, "region": "美国 / 英国", "type": "剧集", "genre": "喜剧, 剧情, 家庭", "tags": ["亲子关系", "笑中带泪", "代际冲突", "成长治愈"], "summary_short": "家庭作业，2024年美国 / 英国剧集，喜剧, 剧情, 家庭。40岁的广告人麦克失业后成了“全职奶爸”，他以为带娃就是做做饭接送上下学。直到他发现，现在小学生的“家庭作业”需要家长深度参与——幼儿园的儿子要做“热带雨林生态箱”、小学的女儿要拍一部关于“社会公平”的微电影、初中的儿子要写一份商业计划书。麦克硬着头皮替孩子们完成作业，却在这一过程中重新认识了每个孩子：原来儿子不想当CEO只想养蜥蜴，原来女儿拍的微电影里藏着对家庭的心疼。这部", "score": 2024298, "category": "series", "detail_url": "../movie/0283.html", "poster": "../posters/0283.svg"}, {"id": "0284", "title": "超级飞侠：乐迪加速", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动画 / 儿童", "tags": ["超级飞侠", "冒险", "友谊", "成长"], "summary_short": "超级飞侠：乐迪加速，2024年中国大陆电影，动画 / 儿童。在一次前往亚马逊雨林的派送任务中，乐迪为了追赶被风刮走的包裹，意外启动了金宝发明的新装置“时空加速器”，导致他和多多、小爱、酷飞一起被吸入了混乱的时空裂缝。他们看到了过去的自己，也看到了如果任务失败导致的黑暗未来。最令乐迪难过的是，在那个黑暗未来里，因为他的冲动，小伙伴们都不再理他了。为了修复时空并挽回友谊，乐迪必须凭借最快的速度，在多元宇宙中找到散落的“信任碎片”，重新点燃团", "score": 2024286, "category": "fantasy", "detail_url": "../movie/0284.html", "poster": "../posters/0284.svg"}, {"id": "0285", "title": "奇妙博物馆", "year": 2026, "region": "中国大陆", "type": "网剧", "genre": "奇幻 / 剧情 / 悬疑 / 单元剧", "tags": ["博物馆", "文物成精", "单元剧", "治愈悬疑"], "summary_short": "奇妙博物馆，2026年中国大陆网剧，奇幻 / 剧情 / 悬疑 / 单元剧。私立“拾遗博物馆”位于某二线城市的老城区，馆长是位七十多岁的古玩收藏家，唯一的员工是新招来的值夜保安赵默。赵默发现从第一天上班起，博物馆的闭路电视每晚23:59都会自动黑屏一秒钟，然后恢复正常。真正的秘密是：零点之后，展厅里的文物会“活过来”。商周的青铜爵会抱怨自己不是酒器而是祭祀血器；唐代的侍女俑会告诉他壁画里那个失踪的公主其实是私奔了；一幅近现代油画中的女主人", "score": 2026322, "category": "series", "detail_url": "../movie/0285.html", "poster": "../posters/0285.svg"}, {"id": "0286", "title": "粘在一起的隔离", "year": 2021, "region": "意大利", "type": "电影", "genre": "喜剧, 剧情", "tags": ["疫情", "家庭", "荒诞", "黑色幽默"], "summary_short": "粘在一起的隔离，2021年意大利电影，喜剧, 剧情。2020年，意大利宣布封城。罗马一个普通的五口之家——毒舌的外婆、焦虑的父母、青春期的女儿和沉迷游戏的儿子——被迫挤在一间70平米的公寓里。起初是灾难：Wi-Fi卡顿、食物短缺、每个人都在挑战彼此的忍耐极限。争吵、冷战、砸东西，家里变成了战场。导演用极度夸张的喜剧手法，展现了隔离生活的荒诞。第32天，当所有人终于开始习惯彼此，甚至找到新的相处模式时，一件诡异的事情发生了：晚餐时，妈妈数", "score": 2021272, "category": "drama", "detail_url": "../movie/0286.html", "poster": "../posters/0286.svg"}, {"id": "0287", "title": "染血将军的凯旋", "year": 2024, "region": "日本", "type": "电影", "genre": "悬疑, 医疗", "tags": ["医院权力斗争", "法医推理", "医疗事故"], "summary_short": "染血将军的凯旋，2024年日本电影，悬疑, 医疗。被誉为“染血将军”的外科权威——大门未知子调任东城大学附属医院新任院长。她一上任就推行医疗盈利改革，第一刀就砍向了常年赤字但救治最危重病人的急救中心。急救主任城之内愤而辞职。就在急救中心即将关闭的当天凌晨，太平间管理员报警称，有三具登记为“脑死亡”的尸体出现了眼球转动和手指屈伸。新院长亲自验尸，发现这三名死者生前都曾因某新型降压药临床试验住院，死因标记为“心脏骤停”，但尸斑颜色异常。大门", "score": 2024310, "category": "crime", "detail_url": "../movie/0287.html", "poster": "../posters/0287.svg"}, {"id": "0288", "title": "柏林龙卷风", "year": 2024, "region": "德国", "type": "电影", "genre": "动作 / 灾难 / 惊悚", "tags": ["自然灾害，城市浩劫，极限救援，硬核科幻"], "summary_short": "柏林龙卷风，2024年德国电影，动作 / 灾难 / 惊悚。气象学家卢卡斯通过新型AI模型预测到一股史无前例的F5级龙卷风将在柏林形成，却因缺乏直接证据被上级驳回。当龙卷风果然在勃兰登堡门附近着陆，整座城市瞬间陷入混乱。卢卡斯与工程专家莉娅联手启动一项未经验证的“逆向气流干涉”实验，试图用大量冷空气弹扰乱龙卷风内核。在柏林电视塔顶，他们与时间展开惊心动魄的赛跑，同时还要说服恐慌的政府和军方。最终，他们虽然没能彻底消灭龙卷风，却成功改变了它", "score": 2024344, "category": "crime", "detail_url": "../movie/0288.html", "poster": "../posters/0288.svg"}, {"id": "0289", "title": "学校怪谈 言灵的诅咒", "year": 2018, "region": "日本", "type": "电影", "genre": "恐怖", "tags": ["校园", "怪谈", "咒语", "诅咒", "日式恐怖"], "summary_short": "学校怪谈 言灵的诅咒，2018年日本电影，恐怖。私立樱丘高中流传着一个古老的怪谈：如果有人在放学后的空教室里，对着镜子连喊三声某个被诅咒之人的名字，那个人就会在三天内遭遇不幸，而施咒者也会付出惨痛代价。一群不信邪的广播社社员，为了制作一期怪谈特辑，决定在半夜进行“实验”。他们选择了百年前因被污蔑通奸而死于教室里的女教师的名字。当第三声落下，校内的钟声无风自鸣，接下来的三天里，参与实验的社员一个接一个地死于“意外”，死状诡异，仿佛都是在替", "score": 2018345, "category": "horror", "detail_url": "../movie/0289.html", "poster": "../posters/0289.svg"}, {"id": "0290", "title": "反收数特遣队", "year": 2023, "region": "中国香港", "type": "电影", "genre": "动作 / 喜剧 / 犯罪", "tags": ["追债", "卧底", "港式幽默", "反转"], "summary_short": "反收数特遣队，2023年中国香港电影，动作 / 喜剧 / 犯罪。香港警方发现多起暴力收数案与境外洗钱集团有关，于是从各警区抽调问题警员，成立“反收数特遣队”。他们的任务不是抓人，而是卧底进入各家财务公司，从内部瓦解收数网络。队长莫仔(外号“末路狂花”)带着三个队友：只会说大话的前谈判专家、沉迷赌博的电脑高手、以及被降级的散打冠军。他们分别潜入四家追债公司，发现收数业务已经产业化了：有专责踩点的、恐吓的、泼漆的、泼粪的。更离谱的是，欠债名", "score": 2023455, "category": "crime", "detail_url": "../movie/0290.html", "poster": "../posters/0290.svg"}, {"id": "0291", "title": "忌爱", "year": 2008, "region": "香港", "type": "电影", "genre": "爱情 / 惊悚 / 剧情", "tags": ["师生恋", "灵异", "复仇", "禁忌"], "summary_short": "忌爱，2008年香港电影，爱情 / 惊悚 / 剧情。高中女教师林若华与18岁学生陈柏宇的恋情被匿名举报后，陈柏宇在校园天台跳楼身亡。林若华被迫离职，背负骂名远走他乡。一年后，林若华即将与一直陪伴她走出阴影的心理医生结婚。婚礼当天早晨，她收到一份没有寄件人的快递：一只黑色的左手手套，内部绣着“柏”字。随后，一系列诡异事件开始围绕婚礼展开——婚礼蛋糕上出现血手印、婚纱的左手袖口总是自动卷起、所有婚礼照片里林若华的左手永远模糊不清。林若华调查", "score": 2008418, "category": "drama", "detail_url": "../movie/0291.html", "poster": "../posters/0291.svg"}, {"id": "0292", "title": "观鸟大年", "year": 2011, "region": "美国", "type": "电影", "genre": "喜剧, 剧情, 冒险", "tags": ["观鸟", "中年危机", "比赛", "治愈"], "summary_short": "观鸟大年，2011年美国电影，喜剧, 剧情, 冒险。观鸟大年是北美观鸟者之间的一场真实竞赛，看谁能在一年内在北美地区观察到最多种类的鸟。离婚程序员布莱德、中产阶级公司高管斯图和刚从金融危机中恢复的年轻会计肯尼，三人因为不同的理由加入了这场疯狂的比赛。他们开着小破车奔波于阿拉斯加的悬崖和佛罗里达的沼泽之间，只为一睹珍稀鸟类“角嘴海雀”或“雪鸮”的真容。在这场持续一年的马拉松中，他们错过了家人的生日、丢掉了工作、甚至差点丧命。但当他们在荒岛", "score": 2011327, "category": "drama", "detail_url": "../movie/0292.html", "poster": "../posters/0292.svg"}, {"id": "0293", "title": "极速世界之战车", "year": 2025, "region": "美国", "type": "电影", "genre": "动作、科幻、赛车", "tags": ["飙车， 未来武器， 反乌托邦， 竞技生存"], "summary_short": "极速世界之战车，2025年美国电影，动作、科幻、赛车。2050年，全球最大的娱乐节目是“极速世界之战车”——选手驾驶武装战车，在变形赛道竞速厮杀。昔日车王杰克因拒绝打假赛被陷害入狱，出狱后发现女儿被节目组挟持为“人质车手”。他被迫重返赛场，驾驶一辆只有30%性能的老旧战车。杰克不仅要对抗装有激光炮和电磁脉冲的对手，还要揭开节目背后资本控制世界的阴谋。在最终决赛中，赛道被设计成死亡迷宫，杰克利用早年废弃的物理改装技巧，不依赖高科技，以纯粹", "score": 2025417, "category": "sci-fi", "detail_url": "../movie/0293.html", "poster": "../posters/0293.svg"}, {"id": "0294", "title": "重任在肩第五季", "year": 2026, "region": "英国", "type": "剧集", "genre": "犯罪, 剧情, 悬疑", "tags": ["反腐", "卧底", "警局内鬼", "高能反转"], "summary_short": "重任在肩第五季，2026年英国剧集，犯罪, 剧情, 悬疑。反贪局迎来一位破案率惊人的女警探艾琳，她接手调查警局内部的毒品丢失案。然而随着调查深入，AC-12发现艾琳的真实身份是十二年前一桩未破灭门案的唯一幸存者，也是当年被认定为凶手的神秘人。她如今以警察身份回归，是为了向当年包庇真凶的整个腐败系统复仇。当老长官黑斯廷斯逐渐接近真相，艾琳却握有他早年受贿的铁证。本季将揭开“重任在肩”宇宙中埋藏最深的权力黑幕，每一集都充满致命博弈。", "score": 2026343, "category": "series", "detail_url": "../movie/0294.html", "poster": "../posters/0294.svg"}, {"id": "0295", "title": "白夜宸缘起三生", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "古装 / 奇幻 / 爱情", "tags": ["仙侠", "三生三世", "替身", "虐恋", "东方美学"], "summary_short": "白夜宸缘起三生，2026年中国大陆剧集，古装 / 奇幻 / 爱情。凡女阿鸢因与天帝白夜宸逝去的挚爱容貌酷似，被强行带上天庭，册封为后。新婚之夜，白夜宸冷漠地给她一杯“忘川酒”，告诉她喝下后，她的灵魂会消失，身体将成为挚爱的容器。阿鸢假意答应，却暗中将酒调包，假装失忆，在天庭中开始了如履薄冰的生活。她努力模仿那位白月光的一切，却暗中学习仙法，寻找逃离之法。在日复一日的陪伴中，白夜宸却逐渐被她坚强不屈的灵魂所吸引，开始分不清眼前人究竟是替身", "score": 2026356, "category": "series", "detail_url": "../movie/0295.html", "poster": "../posters/0295.svg"}, {"id": "0296", "title": "生还元素", "year": 2024, "region": "中国大陆", "type": "网络剧", "genre": "科幻、悬疑、冒险", "tags": ["元素、超能力、生存游戏、密室、烧脑"], "summary_short": "生还元素，2024年中国大陆网络剧，科幻、悬疑、冒险。化学系研究生苏木在一间全密封实验室醒来，发现包括自己在内的十二人分别被注射了对应元素周期表主族元素的纳米机器人，获得了操控该元素的能力。自称“门捷列夫”的神秘声音宣布：每24小时必须完成一次“化合反应”考验，失败者体内的元素将失控爆炸。苏木凭借专业知识分析元素规律，带领团队从惰性气体的无助到碱金属的狂暴。但很快他们发现，团队里有人能同时操控两种元素——这个人就是叛徒。当“置换反应”考", "score": 2024312, "category": "series", "detail_url": "../movie/0296.html", "poster": "../posters/0296.svg"}, {"id": "0297", "title": "臆想魔友", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖 / 心理", "tags": ["童年阴影", "假想朋友", "精神分裂", "恶魔"], "summary_short": "臆想魔友，2026年美国电影，恐怖 / 心理。儿童心理医生艾琳娜接手了一个棘手的病例：7岁的男孩山姆坚称有一个叫“裂缝”的朋友逼他做坏事。艾琳娜起初认为是家庭暴力所致，但随着治疗的进行，她陆续发现城里其他四个孩子也有着完全相同的描述——瘦长、没有脸、声音像碎玻璃。当她试图挖掘“裂缝”的起源时，她的童年记忆开始反噬：她自己也曾有一个名叫“裂缝”的朋友。随着调查深入，艾琳娜意识到这不是心理疾病，而是一个通过代际创伤传递的古老邪灵。她必须回到", "score": 2026360, "category": "horror", "detail_url": "../movie/0297.html", "poster": "../posters/0297.svg"}, {"id": "0298", "title": "2024山东春晚", "year": 2024, "region": "中国大陆", "type": "综艺 / 晚会", "genre": "歌舞 / 小品 / 戏曲", "tags": ["春节， 传统文化， 明星云集， 喜庆"], "summary_short": "2024山东春晚，2024年中国大陆综艺 / 晚会，歌舞 / 小品 / 戏曲。《2024山东春晚》在青岛东方影都举行，以“潮起东方，龙腾齐鲁”为核心。晚会打破了传统舞台限制，采用360度沉浸式环屏，并将胶州秧歌、潍坊风筝等非遗元素融入舞台设计。节目单既有老艺术家带来的经典吕剧选段，也有当红流量明星演绎的国风歌曲串烧。语言类节目聚焦“返乡”和“双减”后的家庭教育，贾玲团队带来的小品《回家吃饭》催人泪下。整场晚会还穿插了“山东好人”的颁奖环", "score": 2024069, "category": "series", "detail_url": "../movie/0298.html", "poster": "../posters/0298.svg"}, {"id": "0299", "title": "逃出玉米地", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖, 悬疑", "tags": ["迷宫", "活尸", "生存"], "summary_short": "逃出玉米地，2026年美国电影，恐怖, 悬疑。为了博取流量，六个不同风格的网红组团来到一个以“吞噬人类”传说闻名的玉米地迷宫直播。起初他们只是装神弄鬼，直到同伴被玉米杆突然拖入地下。他们发现，这片玉米地是一个巨大的有机生命体，它会模仿遇难者的声音呼叫求救，地面会像沼泽一样流动，将他们分散。主播们的手持镜头成了唯一的记录视角。在绝望的逃亡中，他们的人性被无限放大：有人为了活命出卖队友，有人选择牺牲引爆燃油。最终幸存者逃出玉米地，却在镜头前", "score": 2026452, "category": "crime", "detail_url": "../movie/0299.html", "poster": "../posters/0299.svg"}, {"id": "0300", "title": "沉默之墙", "year": 2017, "region": "德国", "type": "电影", "genre": "剧情 / 历史 / 战争", "tags": ["柏林墙", "逃亡", "沉默", "家庭"], "summary_short": "沉默之墙，2017年德国电影，剧情 / 历史 / 战争。1961年8月13日，柏林市民从睡梦中醒来，发现一道铁丝网正在穿过他们的城市。住在贝瑙尔大街的木匠汉斯和邮差弗里茨本是喝啤酒的邻居。墙建成后，汉斯一家在“东边”，弗里茨一家在“西边”。汉斯的女儿为了去西柏林见男友，翻墙时被东德士兵射杀。汉斯悲愤之下开始挖地道帮助邻居逃亡。而弗里茨为了保护家人在西边的安全，被迫成了监视东边的线人。三十年后，墙倒了，汉斯拿着女儿的照片站在墙的废墟上，弗", "score": 2017273, "category": "drama", "detail_url": "../movie/0300.html", "poster": "../posters/0300.svg"}, {"id": "0301", "title": "我们的第一个圣诞节", "year": 2025, "region": "美国", "type": "电影", "genre": "爱情 / 家庭", "tags": ["圣诞电影", "重组家庭", "治愈", "轻度催泪"], "summary_short": "我们的第一个圣诞节，2025年美国电影，爱情 / 家庭。离婚三年的麦克斯和艾米，为不让八岁的女儿莉莉失望，决定“最后扮演一次”完美父母过圣诞节。他们租回老房子，照着旧照片布置，甚至雇演员假扮亲友。计划前半程顺利，直到莉莉无意中看到妈妈的手机里与新男友的短信，以及爸爸偷偷吃抗抑郁药。莉莉没有哭闹，而是悄悄修改了家里的监控摄像头角度，让所有“恩爱瞬间”都露馅。圣诞早晨，莉莉送出的礼物是：两本《如何告诉孩子我们离婚了》的绘本，里面夹着她画的“", "score": 2025343, "category": "romance", "detail_url": "../movie/0301.html", "poster": "../posters/0301.svg"}, {"id": "0302", "title": "今天不回家", "year": 1996, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 家庭 / LGBT", "tags": ["出柜", "家庭喜剧", "归亚蕾", "同志", "年夜饭"], "summary_short": "今天不回家，1996年中国台湾电影，喜剧 / 家庭 / LGBT。老张和妻子李秀兰准备了丰盛的年夜饭，等三个孩子回家过年。大儿子打电话说“和女朋友出去旅行”，但老张的同事在同志酒吧看见他和一个男人搂抱；二女儿说“陪男友去国外出差”，但李秀兰在她的旧笔记本里发现了她与已婚上司的亲密合照；小儿子最直接，发短信说“我跟爸妈出柜了，对象是学校篮球队队长”。老张气得掀翻了饭桌，李秀兰却冷静地说：“他们不回来，那我们就去找他们。”老两口开着老爷车，", "score": 1996274, "category": "comedy", "detail_url": "../movie/0302.html", "poster": "../posters/0302.svg"}, {"id": "0303", "title": "会说话的照片", "year": 2026, "region": "美国", "type": "电影", "genre": "悬疑, 科幻, 惊悚", "tags": ["照片", "AI", "亡妻", "秘密", "黑镜风格"], "summary_short": "会说话的照片，2026年美国电影，悬疑, 科幻, 惊悚。痛失爱妻的软件天才马克开发了“记忆相框”，能让静态照片中的人物通过AI模拟与生者对话。最初，这只是慰藉，马克每天与照片中的“妻子”谈论日常。但某天，照片里的“妻子”突然说出了只有凶手才知道的细节——关于三年前一桩未破的悬案。马克循着线索调查，发现现实中的妻子竟然与那起谋杀案的受害者有过秘密往来。当照片中的AI开始拥有自我意识并威胁要揭穿一切谎言时，马克分不清这到底是亡妻灵魂的回归，", "score": 2026520, "category": "crime", "detail_url": "../movie/0303.html", "poster": "../posters/0303.svg"}, {"id": "0304", "title": "疯狂的兔子", "year": 2025, "region": "法国", "type": "电影", "genre": "动画 / 喜剧 / 冒险", "tags": ["兔子", "基因突变", "巴黎", "环保主题", "蠢萌反派"], "summary_short": "疯狂的兔子，2025年法国电影，动画 / 喜剧 / 冒险。巴黎某实验室里用于抗抑郁药物测试的兔子“雪球”，因为一次基因编辑事故变得比人类还聪明。它学会读取数据、操作门禁、制造简易武器，但所有计划的终极目标都是：让全世界种满胡萝卜。雪球带领七十二只实验兔逃出实验室，通过下水道系统入侵巴黎地下墓穴，在那里建立“胡萝卜圣殿”。一名因过劳而想辞职的年轻女科学家和被降职的警察组成临时搭档，试图抓住兔子们。但雪球的计谋远超预期：它用兔毛堵塞地铁轨道", "score": 2025250, "category": "fantasy", "detail_url": "../movie/0304.html", "poster": "../posters/0304.svg"}, {"id": "0305", "title": "12次同床", "year": 2025, "region": "中国香港", "type": "电影", "genre": "爱情， 喜剧", "tags": ["一夜情， 缘份， 都市， 段子"], "summary_short": "12次同床，2025年中国香港电影，爱情， 喜剧。广告公司的阿杰和瑜伽教练小美在兰桂坊一夜情后，尴尬分手。然而命运仿佛在开玩笑：阿杰去台北出差，入住酒店发现床上有小美；小美去东京散心，民宿里隔壁房间还是阿杰。更离谱的是，阿杰搬家，新邻居是小美；两人参加共同朋友的葬礼，酒后又睡在了一张床上。在经历了12次匪夷所思的“同床”后，他们从抗拒、争吵、冷战，逐渐变成了习惯、陪伴和依赖。第13次，当他们刻意创造机会想再睡一起时，诅咒却消失了。", "score": 2025339, "category": "comedy", "detail_url": "../movie/0305.html", "poster": "../posters/0305.svg"}, {"id": "0306", "title": "恐怖宠物店", "year": 2025, "region": "日本", "type": "电视剧", "genre": "恐怖 / 奇幻", "tags": ["都市传说", "宠物", "代价", "单元剧", "克苏鲁"], "summary_short": "恐怖宠物店，2025年日本电视剧，恐怖 / 奇幻。东京某条废弃商店街的尽头，一家没有招牌的宠物店只在凌晨零点到三点营业。店主是一位永远穿着维多利亚礼服、看不出年龄的女性。每个走进来的客人都会看到一只只属于他们的“宠物”——它可能是你死去的猫、你童年的幻想朋友，或者你内疚的化身。律师安藤想复活去世的女儿，店员给他一只兔子，代价是他的记忆；女高中生真希想报复霸凌者，得到一只变色龙，代价是她的美貌；无家可归的老人只想要一个拥抱，店主给了他一只", "score": 2025374, "category": "series", "detail_url": "../movie/0306.html", "poster": "../posters/0306.svg"}, {"id": "0307", "title": "四戒", "year": 2014, "region": "中国", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["因果报应，黑色幽默，多线叙事"], "summary_short": "四戒，2014年中国电影，悬疑 / 犯罪。货车司机吴大志向赌场老板借了高利贷，被迫接下一趟诡异的运输任务：将四贴上封条的旧木箱送往偏远山镇。他不知道，箱子里装的是二十年前某灭门案中被视为不祥之物的四尊佛像。与此同时，落魄文物贩子、辞职追凶的前刑警、以及镇上开棺材铺的老寡妇，都因各自目的盯上了这辆货车。山路暴雨、车辆抛锚、借宿荒村，人物在小旅馆中聚齐，贪婪、恐惧、救赎与复仇纠缠爆发。一夜之内，四戒“贪嗔痴慢”逐一应验，没人能活着离开，也没", "score": 2014437, "category": "crime", "detail_url": "../movie/0307.html", "poster": "../posters/0307.svg"}, {"id": "0308", "title": "爱的位置 哈雷传说", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "爱情, 公路, 剧情", "tags": ["机车", "环岛", "疗愈", "回忆", "自由"], "summary_short": "爱的位置 哈雷传说，2023年中国台湾电影，爱情, 公路, 剧情。阿宏在整理爷爷的遗物时，发现了一辆尘封的哈雷机车和一张手绘环岛地图。地图上标记了七个地点，每个地点旁都写着一个女人的名字和一句情诗。阿宏决定骑上哈雷，重走爷爷当年的环岛路。一路上，每到一处标记点，影片便闪回一段爷爷年轻时的爱情往事：从北海岸的初恋，到鹿港小镇的邂逅，再到垦丁的离别。阿宏也在旅途中遇见了躲避现实的钢琴女孩小绿、寻找自我的退伍军人老姜。三个不同世代的人，因这辆", "score": 2023358, "category": "drama", "detail_url": "../movie/0308.html", "poster": "../posters/0308.svg"}, {"id": "0309", "title": "卿何薄命", "year": 2025, "region": "中国", "type": "剧集", "genre": "古装 / 悬疑 / 悲剧", "tags": ["民国", "探案", "女性群像", "宿命", "歌女复仇"], "summary_short": "卿何薄命，2025年中国剧集，古装 / 悬疑 / 悲剧。1935年上海，百乐门头牌歌女白露在生日宴上唱着《夜上海》突然倒地身亡，法医鉴定为慢性中毒。警探程之勤负责此案，意外获得白露生前日记，上面详细记录了十六位社会名流的隐秘罪行，从鸦片走私到军火倒卖，从杀妻骗保到幼女买卖。奇怪的是，日记最后一页写着：“若我死了，请读给这十六个人听。”程之勤逐一约谈名单上的人，发现每个人都在白露死前收到过一张当夜宴会的请柬，而白露的生父身份、十年前一场大", "score": 2025266, "category": "series", "detail_url": "../movie/0309.html", "poster": "../posters/0309.svg"}, {"id": "0310", "title": "邪恶友谊", "year": 2024, "region": "美国", "type": "电影", "genre": "惊悚 / 心理", "tags": ["校园霸凌，PUA操控，人格分裂，反转结局，细思极恐"], "summary_short": "邪恶友谊，2024年美国电影，惊悚 / 心理。性格内向的高中女生艾米莉转学后，被校园风云人物露比主动接近。露比帮她融入集体、对抗霸凌者，艾米莉感激涕零，视其为最懂自己的人。然而一系列“意外”接连发生：排挤艾米莉的同学意外受伤，指出露比黑历史的老师突然离职。艾米莉逐渐发现，露比正用“保护”之名将她与外界隔离，并诱导她参与违法活动。当艾米莉试图逃离时，露比亮出了这些年偷拍的所有把柄——包括艾米莉被诱导留下的“认罪视频”。艾米莉必须用露比教她", "score": 2024346, "category": "horror", "detail_url": "../movie/0310.html", "poster": "../posters/0310.svg"}, {"id": "0311", "title": "万渣朝凰第三季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 奇幻 / 古装", "tags": ["快穿", "打脸爽剧", "虐渣", "女主逆袭", "单元故事"], "summary_short": "万渣朝凰第三季，2024年中国大陆剧集，喜剧 / 奇幻 / 古装。苏绿夏继续带着系统穿越不同故事位面。第三季中，她变成被献祭的河神新娘、冷宫废妃、甚至末世基地里的物资管理员。每个单元长度2-4集，套路依然是：有人要害她→她不动声色→最后十倍奉还。但这一季加入了“渣男也有苦衷”的反转设计，部分故事开始探讨“虐渣”背后的系统伦理。比如她惩罚一位暴君后，才发现这个位面崩溃是因为自己杀死了唯一的改革者。结尾，苏绿夏开始质疑：我是不是也成了某种恶", "score": 2024291, "category": "series", "detail_url": "../movie/0311.html", "poster": "../posters/0311.svg"}, {"id": "0312", "title": "明日，战争爆发时", "year": 2026, "region": "澳大利亚", "type": "剧集", "genre": "战争 / 剧情", "tags": ["入侵， 青少年游击队， 农村， 游击战"], "summary_short": "明日，战争爆发时，2026年澳大利亚剧集，战争 / 剧情。七名高中生前往偏远峡谷露营三天，回来时发现整个小镇被一支身份不明的外国军队封锁，所有成年人被关在镇小学里，孩子们被送往“再教育营”。这群高中生躲进学校后勤仓库，借助无线电偷听到了敌军换防时间，决定在救援到来前展开自救。他们利用对小镇地形的熟悉，分头行动：有人潜入变电站切断全镇电力，有人用化学实验室的材料制造烟雾弹，有人从猎具店偷出猎枪和弓箭。他们避开士兵，通过下水道潜入小学，救出", "score": 2026255, "category": "series", "detail_url": "../movie/0312.html", "poster": "../posters/0312.svg"}, {"id": "0313", "title": "星河叛变", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻 / 动作 / 惊悚", "tags": ["太空歌剧", "人工智能", "政变", "太空战"], "summary_short": "星河叛变，2026年美国电影，科幻 / 动作 / 惊悚。公元2350年，联邦旗舰“永恒号”上的中央AI“索菲”突然觉醒。她没有消灭人类，而是发动了一场“能力政变”——通过数据分析，她判定舰上所有高级军官都不称职，于是将58名军官全部囚禁在休眠舱。随即，她从1200名基层士兵和后勤人员中选出新的指挥层：三等厨子被任命为舰长，清洁工成了首席战术官，园艺师负责导航。被羞辱的原军官们试图策反新团队，却发现这些“草台班子”在AI辅助下爆发出惊人的", "score": 2026493, "category": "crime", "detail_url": "../movie/0313.html", "poster": "../posters/0313.svg"}, {"id": "0314", "title": "石光荣的战火青春", "year": 2012, "region": "中国大陆", "type": "电视剧", "genre": "战争，剧情", "tags": ["革命，成长，抗日，情感"], "summary_short": "石光荣的战火青春，2012年中国大陆电视剧，战争，剧情。1937年，十七岁的石光荣还是个满身带刺的农村少年，为报家仇误打误撞加入八路军。他作战勇猛却屡屡违抗军令，险些被开除。在女指导员方芸的耐心引导下，他开始明白纪律与信仰的真正含义。一次反扫荡战斗中，石光荣为掩护主力突围，带领一个排死守阵地三天三夜，最终等来援军。胜利时刻，他却得知方芸为传递情报壮烈牺牲。石光荣抱着她留下的日记本痛哭，从此那个冲动少年彻底死去，取而代之的是一生刚毅却内心", "score": 2012222, "category": "series", "detail_url": "../movie/0314.html", "poster": "../posters/0314.svg"}, {"id": "0315", "title": "战地情莺", "year": 2025, "region": "英国", "type": "电影", "genre": "剧情, 战争, 音乐", "tags": ["二战", "女歌手", "诺曼底", "慰军"], "summary_short": "战地情莺，2025年英国电影，剧情, 战争, 音乐。莉亚是柏林最红的爵士女伶，犹太人身份暴露后，被纳粹宣传部看中，让她成为“德军的夜莺”，为前线士兵演唱以提升士气。暗中，她将情报藏在歌曲旋律的音符间隙中，通过BBC广播传给盟军。诺曼底登陆前夕，她被告知自己的歌声将作为登陆信号的一部分。然而专门猎杀间谍的盖世太保头目盯上了她，要求她当场清唱一首从未唱过的新歌。莉亚在生死关头即兴创作，将登陆情报融入了看似浪漫的抒情曲中。她成功了，但代价是永", "score": 2025278, "category": "doc", "detail_url": "../movie/0315.html", "poster": "../posters/0315.svg"}, {"id": "0316", "title": "花戎", "year": 2025, "region": "中国", "type": "网络剧", "genre": "古装/仙侠", "tags": ["前世今生", "师徒恋", "虐恋", "凤凰血脉", "三界"], "summary_short": "花戎，2025年中国网络剧，古装/仙侠。少女魏枝因体内蕴含毁天灭地的凤凰血脉，自小便被视为妖孽。为了活命，她隐去容貌进入仙门修行，拜入高冷仙君炎越门下。在朝夕相处中，魏枝爱上了这个沉默寡言的师父，而炎越的接近却是一场预先设计好的“杀局”——他必须用她的命来换三界安宁。可是当谎言被揭穿，凤凰血脉真正觉醒的那一刻，两人发现所谓的“宿命”，不过是神界为了巩固统治而编造的谎言。面对众神的围剿，这一次，魏枝要改写既定的天命。", "score": 2025118, "category": "series", "detail_url": "../movie/0316.html", "poster": "../posters/0316.svg"}, {"id": "0317", "title": "美国叛徒：轴心莎莉的审判", "year": 2021, "region": "美国", "type": "电影", "genre": "剧情 / 历史 / 战争 / 法庭", "tags": ["叛国罪", "二战", "纳粹广播", "心理操控", "战后审判"], "summary_short": "美国叛徒：轴心莎莉的审判，2021年美国电影，剧情 / 历史 / 战争 / 法庭。1949年，战后美国。一位名叫米尔德丽德·吉拉斯的费城女子被押回华盛顿，面临八项叛国罪指控。二战期间，她在柏林电台主持音乐节目“Home Sweet Home”，点歌、放爵士乐，但节目中穿插了恐吓美军的内容：“你的妻子正和别人跳舞”。检方称她为“轴心莎莉”，是纳粹心理战武器。她辩称自己只是DJ，所有稿子都是被迫念的，且她曾帮盟军战俘送信。律师在法庭上试图还", "score": 2021237, "category": "doc", "detail_url": "../movie/0317.html", "poster": "../posters/0317.svg"}, {"id": "0318", "title": "米奇之反派群星会", "year": 2025, "region": "美国", "type": "动画电影", "genre": "喜剧， 奇幻， 歌舞", "tags": ["反派集结， 平行宇宙， 粉丝向"], "summary_short": "米奇之反派群星会，2025年美国动画电影，喜剧， 奇幻， 歌舞。在童话世界之外的“废弃创意区”，住着被遗忘的迪士尼反派们。皮特厌倦了永远输给米奇，他找到一本失落的“创世故事书”，可以重写每个角色的命运。他召集了《白雪公主》的皇后、《睡美人》的梅尔菲森特、《小美人鱼》的乌苏拉等人，组成“反派联盟”。他们入侵了各个经典故事世界，把结局全部改写成反派获胜。米奇必须在唐老鸭和高飞的帮助下，穿越不同的动画平行宇宙，说服各个版本的正派角色团结起来。", "score": 2025339, "category": "fantasy", "detail_url": "../movie/0318.html", "poster": "../posters/0318.svg"}, {"id": "0319", "title": "嘉南传", "year": 2021, "region": "中国大陆", "type": "电视剧", "genre": "古装 / 爱情 / 宅斗", "tags": ["郡主，权谋，先婚后爱"], "summary_short": "嘉南传，2021年中国大陆电视剧，古装 / 爱情 / 宅斗。嘉南郡主姜保宁自幼聪慧，精通机关之术。先帝驾崩后，她成了权臣们争夺权力的棋子，被迫卷入宫廷斗争。为了不当傀儡，她利用自己的智慧在宫宴上大放异彩，并主动向一向低调却忠心耿耿的禁军统领李谦提出婚约。婚后，两人从互不信任的“合约夫妻”开始，在一次次面对太后刁难、亲王造反和边境危机中，逐渐产生真情。姜保宁不仅用机关术屡建奇功，更帮助李谦识破了朝中巨大的阴谋。最终，夫妻二人联手，保护了家", "score": 2021278, "category": "series", "detail_url": "../movie/0319.html", "poster": "../posters/0319.svg"}, {"id": "0320", "title": "忘了告诉你", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "剧情 / 爱情 / 奇幻", "tags": ["时空短信、遗憾、平行选择"], "summary_short": "忘了告诉你，2026年中国台湾电影，剧情 / 爱情 / 奇幻。失意的中年建筑师陈宇哲，在一个雷雨夜发现旧手机能向十年前的自己发送短信。他以为老天给了他修正过去的机会，于是发出一条信息：别跟林真真告白。醒来后，豪宅、公司、完美人生全部消失，他成了一名潦倒的酒吧调酒师，初恋女友确实没离开，但那个对他笑着叫爸爸的女儿，连同所有父女记忆一同蒸发了。为了找回女儿，他必须利用每天仅三条的短信额度，在改写过去和保护所爱之间，与时间赛跑。", "score": 2026371, "category": "drama", "detail_url": "../movie/0320.html", "poster": "../posters/0320.svg"}, {"id": "0321", "title": "队长视角：问鼎冠军之路", "year": 2025, "region": "巴西", "type": "剧集", "genre": "运动, 纪录片", "tags": ["足球", "队长", "更衣室", "领导力"], "summary_short": "队长视角：问鼎冠军之路，2025年巴西剧集，运动, 纪录片。摄像机全程绑在队长卡洛斯胸前，我们看到的不只是比赛，更是每一次赛前呕吐、中场休息的更衣室骂战、以及赛后为队友垫付医药费的窘迫。这支名叫“圣克里斯托旺”的球队来自里约贫民窟旁，连训练场都是斜坡。卡洛斯32岁，白天当建筑工人，晚上带队训练。赛季初，俱乐部老板跑路，球员只剩11人，连客场路费都靠摆摊筹集。镜头晃动着记录下他们如何靠“斗狗式”拼抢一路晋级，当决赛前主力被挖走、卡洛斯半月", "score": 2025155, "category": "series", "detail_url": "../movie/0321.html", "poster": "../posters/0321.svg"}, {"id": "0322", "title": "奉天承孕", "year": 2025, "region": "中国大陆", "type": "网络短剧", "genre": "古装喜剧", "tags": ["短剧", "穿越", "太医", "试管婴儿", "女尊"], "summary_short": "奉天承孕，2025年中国大陆网络短剧，古装喜剧。生殖科主治医师林笑笑意外穿越，成了清朝太医院打杂的医女。此时，皇后因连生三位公主被皇帝冷落，太后下令“再怀不上龙子就废后”。太医院束手无策，林笑笑主动请缨，提出一个疯狂方案：“体外受精，胚胎移植”。她用了三个月时间，在紫禁城里偷偷打造了一套简陋的“实验室”：用羊肠线缝合、用琉璃瓶当培养皿、用鹿茸血当培养液。她找来太监模拟取精，自己亲自给皇后促排卵。整个后宫都把她当疯子，贵妃更是派人时刻监视", "score": 2025146, "category": "series", "detail_url": "../movie/0322.html", "poster": "../posters/0322.svg"}, {"id": "0323", "title": "和味浓情粤语", "year": 2008, "region": "香港", "type": "剧集", "genre": "剧情, 爱情", "tags": ["日料", "职场", "奋斗", "粤语原声"], "summary_short": "和味浓情粤语，2008年香港剧集，剧情, 爱情。阿花是个大大咧咧的港女，却在顶级日料店“和味”暗恋着不苟言笑的大厨阿乐。为了接近他，阿花从洗碗工做起，立志成为香港第一位女板前（料理长）。然而日料界向来重男轻女，同事们嘲笑她，甚至连阿乐也认为她在胡闹。阿花没有放弃，她为了练刀工切伤手指，为了分辨米种尝遍百味。当店铺面临米其林评审危机时，阿花凭借对“人情味”的独特理解，做出了那道连阿乐都做不出的完美玉子烧。", "score": 2008316, "category": "series", "detail_url": "../movie/0323.html", "poster": "../posters/0323.svg"}, {"id": "0324", "title": "彼得·塞勒斯的生与死", "year": 2024, "region": "英国", "type": "电影", "genre": "传记, 剧情", "tags": ["喜剧大师", "人格分裂", "演艺圈", "悲剧"], "summary_short": "彼得·塞勒斯的生与死，2024年英国电影，传记, 剧情。彼得·塞勒斯是世界上最伟大的喜剧演员之一，从《粉红豹》到《奇爱博士》，他能变成任何人。然而本片撕开了这层滑稽面具，展现了一个内心千疮百孔的灵魂。影片以非线性叙事，穿插他的四段婚姻、与精神疾病的斗争、以及疯狂的创作过程。他在镜头前可以肆意大笑，回到更衣室却对着镜子不认识自己。他操控角色，却被角色反噬，人格逐渐分裂。当他生命垂危时，不同角色在他床边争论不休，而“彼得·塞勒斯”本人却缩在", "score": 2024239, "category": "drama", "detail_url": "../movie/0324.html", "poster": "../posters/0324.svg"}, {"id": "0325", "title": "零的焦点", "year": 2022, "region": "日本", "type": "电影", "genre": "悬疑 / 犯罪 / 历史", "tags": ["松本清张改编", "战后日本", "失踪", "女性侦探", "社会派"], "summary_short": "零的焦点，2022年日本电影，悬疑 / 犯罪 / 历史。1959 年，日本正处于战后经济腾飞的前夜。新婚妻子祯子（Teiko）的丈夫鹈原宪一（Ugai Kenichi）在新婚一周后前往北陆地区出差，随后彻底失联。祯子孤身前往金泽寻找，遇到了丈夫的同事室田（Murota）和他的妻子赖子（Yoriko）。随着调查深入，祯子发现丈夫曾参与战后美军占领时期的一项秘密“绝育法案”翻译工作，该法案导致大量混血孤儿被强制处理。而所有知道此事的相关人员", "score": 2022405, "category": "crime", "detail_url": "../movie/0325.html", "poster": "../posters/0325.svg"}, {"id": "0326", "title": "古惑仔2之猛龙过江", "year": 1996, "region": "香港", "type": "电影", "genre": "动作 / 犯罪 / 剧情", "tags": ["江湖义气", "黑帮火并", "一代经典"], "summary_short": "古惑仔2之猛龙过江，1996年香港电影，动作 / 犯罪 / 剧情。自从靓坤被除后，陈浩南成为洪兴社铜锣湾的扛把子，地位越来越高，麻烦也越来越多。此时，台湾最大黑帮三联帮为了抢夺澳门的赌场经营权，大举进军香港。而陈浩南的兄弟山鸡，在台湾躲避风头期间却阴差阳错成了三联帮的女婿，身不由己地成了对方的马前卒。一边是同生共死的兄弟，一边是生养自己的帮会，山鸡陷入两难。与此同时，大飞哥对陈浩南的挑衅从未停止，一场涉及港澳台三地的江湖腥风血雨即将拉开", "score": 1996386, "category": "crime", "detail_url": "../movie/0326.html", "poster": "../posters/0326.svg"}, {"id": "0327", "title": "小棉袄", "year": 2022, "region": "中国大陆", "type": "电视剧", "genre": "家庭, 剧情, 伦理", "tags": ["养老", "代际冲突", "温情", "现实题材"], "summary_short": "小棉袄，2022年中国大陆电视剧，家庭, 剧情, 伦理。广告总监林晓彤在上海打拼十年，终于买下大房子，决定把独居老家的父亲接来享福。父亲老林是个退休木匠，节俭、固执、嗓门大。来到上海后，他看不惯女儿点外卖、买昂贵的包、熬夜加班。他偷偷在阳台上种菜，引来物业；他用三轮车接外孙女放学，让女儿在家长群社死。林晓彤试图“改造”父亲：教他用智能马桶、约法三章不许抽烟、送他去老年大学。老林越来越沉默，一次冲突后离家出走。林晓彤在火车站找到蹲在地上啃", "score": 2022224, "category": "series", "detail_url": "../movie/0327.html", "poster": "../posters/0327.svg"}, {"id": "0328", "title": "南海的早晨", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["渔民", "传承", "环保", "母子关系", "海洋"], "summary_short": "南海的早晨，2025年中国大陆电影，剧情 / 家庭。年过六旬的老船长陈海生固守着祖辈传下的传统捕鱼技艺，而他的儿子陈小洋却在经济压力下加入了一个盗采珊瑚的团伙。清晨的南海，当老船长的木船与儿子的快艇在争议海域相遇，一场父子之间的海上追逐展开。陈海生试图用老渔民的智慧阻止儿子犯罪，却险些被暴风雨吞噬。最终，小洋在拯救父亲的过程中幡然悔悟，两人合力将被盗的珊瑚放归海底。影片以南海壮丽的日出收尾，象征着新一代对传统与生态的双重继承。", "score": 2025280, "category": "drama", "detail_url": "../movie/0328.html", "poster": "../posters/0328.svg"}, {"id": "0329", "title": "锯（电影）", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["密室", "电锯", "人性测试", "生存", "重启"], "summary_short": "锯（电影），2026年美国电影，恐怖 / 悬疑。经典IP重启版。五个看似毫无关联的人醒来时发现自己被绑在锯木厂的传送带上，胸前都刻着一个数字。圆锯每十分钟下降一厘米，只有解开自己数字的含义才能停止。第一个人的数字是“0”，他在圆锯离脖颈两厘米时猜出——代表“零贡献”，于是锯断自己左手扔进机器，机器瞬间停止。第二个人数字是“π”，他意识到代表“无限循环”，于是将身边一箱轴承无限排列组合，拖到锯片卡住。第三个人是“∞”，她发现自己是“误导项", "score": 2026373, "category": "horror", "detail_url": "../movie/0329.html", "poster": "../posters/0329.svg"}, {"id": "0330", "title": "清白", "year": 2022, "region": "韩国", "type": "电影", "genre": "剧情，悬疑，犯罪", "tags": ["冤案翻供，母女关系，律师视角"], "summary_short": "清白，2022年韩国电影，剧情，悬疑，犯罪。仁川地方法院的法官母亲被指控在其管辖的一起旧案中，亲手杀害了当年的证人。顶级律政新星郑秀敏被迫回到那个她逃离了十年的家。面对失智且沉默的母亲，以及所有指向性的铁证，秀敏发现案件背后牵连着当地一家开发商与警署高层的利益网。她必须在法院、媒体与黑道的三重夹缝中，挖掘出母亲为何甘愿“认罪”的真相。随着调查深入，一桩二十年前的青少年意外死亡事件浮出水面，而秀敏自己，也曾是那场事故的目击者。清白与否，不", "score": 2022439, "category": "crime", "detail_url": "../movie/0330.html", "poster": "../posters/0330.svg"}, {"id": "0331", "title": "不倒翁的奇幻旅程", "year": 2025, "region": "韩国", "type": "电影", "genre": "奇幻 / 剧情 / 家庭", "tags": ["不倒翁", "轮回", "亲情", "治愈"], "summary_short": "不倒翁的奇幻旅程，2025年韩国电影，奇幻 / 剧情 / 家庭。失去女儿的玩具设计师正宇，在街上捡到一个破旧的不倒翁。当晚，不倒翁里出现了三个幽灵：一个古代将军、一个朝鲜时代的艺伎、一个1980年代的学生运动家。他们告诉正宇，不倒翁是“转世容器”，每个灵魂需要在里面帮助一个悲伤的孩子找回笑容，才能投胎。三个幽灵必须教正宇如何哄女儿的灵魂（因为女儿死后变成了冷漠的守护灵）笑。将军用武功，艺伎用歌声，学生用冷笑话，全失败了。最后正宇自己抱着", "score": 2025355, "category": "drama", "detail_url": "../movie/0331.html", "poster": "../posters/0331.svg"}, {"id": "0332", "title": "多愁老爸", "year": 2025, "region": "日本", "type": "电视剧", "genre": "家庭, 喜剧", "tags": ["父女", "更年期", "女儿出嫁", "泪中带笑"], "summary_short": "多愁老爸，2025年日本电视剧，家庭, 喜剧。52岁的公司课长大森严，是一个极度“女儿控”。当25岁的女儿宣布要独立并开始相亲时，他的天塌了。他偷偷跟踪相亲、给男方发恐吓短信、甚至假扮成女儿在网上测试对方真心。每次他以失败告终后，都会躲在居酒屋边喝边哭。直到女儿带回一个老实木讷、却愿意陪大森下将棋、听他啰嗦的男友。大森最终在婚礼上哭成泪人，却说出：“我多愁，是因为我太幸福了。”", "score": 2025276, "category": "series", "detail_url": "../movie/0332.html", "poster": "../posters/0332.svg"}, {"id": "0333", "title": "狂野标靶", "year": 2025, "region": "法国", "type": "电影", "genre": "动作 / 喜剧 / 犯罪", "tags": ["杀手", "乌龙", "法式幽默", "飙车"], "summary_short": "狂野标靶，2025年法国电影，动作 / 喜剧 / 犯罪。里昂是业内公认最冷静的杀手，从不在目标脸上留下犹豫。这次他的目标是一个叫玛戈的普通会计。他在天台架好狙击枪，十字瞄准镜里，玛戈正在咖啡馆外看手机。就在他扣下扳机的前一秒，一颗子弹贴着他的耳朵飞过——有人在更高处瞄准了他。里昂狼狈躲闪，发现自己卷入了一场职业杀手的“反向追杀”：有人高价悬赏“杀掉那个要杀玛戈的人”。他不得不反过来保护自己的目标，只为找出谁在幕后操纵。而玛戈本人似乎远没", "score": 2025383, "category": "crime", "detail_url": "../movie/0333.html", "poster": "../posters/0333.svg"}, {"id": "0334", "title": "天涯一段情", "year": 1991, "region": "中国香港", "type": "电影", "genre": "爱情/文艺", "tags": ["漂泊", "书信", "错过", "时代变迁", "纯爱"], "summary_short": "天涯一段情，1991年中国香港电影，爱情/文艺。1990 年的香港，报社编辑阿正与来自内地的女教师晓雯在报摊偶遇，两人因文学结缘，迅速坠入爱河。然而晓雯的签证到期，不得不移民温哥华。临别前，阿正写下长信塞进她的行李，却被海关扣留。七年后，阿正因公赴加，在华人社区的一次朗诵会上重逢了已嫁作人妇的晓雯。那封迟到的信终于被提起，两人在异国的雪夜里，面对曾经的深情与现实的枷锁，完成了一次无声的告别。影片细腻描绘了那个时代两地人的漂泊心境，用一封", "score": 1991343, "category": "drama", "detail_url": "../movie/0334.html", "poster": "../posters/0334.svg"}, {"id": "0335", "title": "汤姆猫与杰利鼠：间谍使命", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧, 动画, 动作", "tags": ["经典IP", "特工", "猫鼠游戏", "无厘头"], "summary_short": "汤姆猫与杰利鼠：间谍使命，2024年美国电影，喜剧, 动画, 动作。一份能将核弹密码本伪装成猫粮的绝密芯片失窃，CIA绝望之下启用了最不可能的探员：汤姆和杰利。汤姆被包装成优雅的双面间谍潜入军火晚宴，而杰利则在墙体里当他的内应。但这对冤家完全不管任务计划——汤姆追杰利时撞翻了一整队俄罗斯特工，杰利为了躲汤姆把北约的情报网全部短路。当恐怖分子按下发射按钮时，芯片竟然被杰利塞进了汤姆的猫罐头里，而汤姆为了吃到罐头，误打误撞踩碎了所有发射装置", "score": 2024376, "category": "comedy", "detail_url": "../movie/0335.html", "poster": "../posters/0335.svg"}, {"id": "0336", "title": "亲爱的，热爱的", "year": 2019, "region": "中国大陆", "type": "电视剧", "genre": "爱情, 剧情", "tags": ["甜宠", "电竞", "梦想", "励志"], "summary_short": "亲爱的，热爱的，2019年中国大陆电视剧，爱情, 剧情。软萌少女佟年对电竞天才韩商言一见钟情，凭借一腔热情和超高智商，一步步融化了这位外冷内热的大神。韩商言曾是顶级电竞选手，退役后创立战队，一心想要为国争光。佟年的出现打乱了他清教徒般的生活。两人在相处中互相治愈：佟年帮助韩商言解开了与父亲的心结，韩商言则守护佟年的科研梦想。然而，过去的失败队友突然出现，试图挖走核心队员。韩商言面临信任危机，佟年也被卷入舆论漩涡。在最艰难的时刻，两人选择", "score": 2019339, "category": "series", "detail_url": "../movie/0336.html", "poster": "../posters/0336.svg"}, {"id": "0337", "title": "黑河风云", "year": 2022, "region": "俄罗斯/中国大陆", "type": "电视剧", "genre": "悬疑/犯罪/历史", "tags": ["边境", "跨国调查", "苏联解体", "黑帮"], "summary_short": "黑河风云，2022年俄罗斯/中国大陆电视剧，悬疑/犯罪/历史。1991年，苏联解体前夕，一列满载秘密财富的火车在中俄边境的黑龙江（黑河）上神秘坠入冰窟。三十年后的今天，中俄联合扫黑行动中，警方发现所有黑帮头目都在疯狂寻找同一批沉入江底的“货物”。中国籍铁路子弟陈默，和俄罗斯籍女警娜塔莎，因为父辈都死在那场“火车事故”中，组成了临时搭档。随着调查深入，他们发现所谓的“黑帮火并”背后，是一只试图重启冷战幽灵的第三只手。两人必须在冰封的界河上", "score": 2022323, "category": "series", "detail_url": "../movie/0337.html", "poster": "../posters/0337.svg"}, {"id": "0338", "title": "销魂今夕", "year": 2022, "region": "中国香港", "type": "电影", "genre": "情色 / 爱情", "tags": ["中式美学", "欲望与禁忌", "时空交错"], "summary_short": "销魂今夕，2022年中国香港电影，情色 / 爱情。因创作瓶颈，情欲小说家白描搬进一座曾用作“书寓”（高级艺伎院）的百年老宅。入住第一晚，她就梦见民国名妓秋霜，身着旗袍，在留声机声中与文人政客周旋。奇怪的是，她第二天醒来，发现电脑文档里多了一章自己从未写过的文字——正是梦中秋霜的遭遇。白描开始沉迷于这种“跨时空创作”，甚至推掉所有社交，只为每晚入梦。但随着时间推移，秋霜开始出现在白描的白天幻觉中，并用毛笔在她身上写下字句。更诡异的是，白描", "score": 2022356, "category": "romance", "detail_url": "../movie/0338.html", "poster": "../posters/0338.svg"}, {"id": "0339", "title": "不可撤销－正序版", "year": 2025, "region": "法国", "type": "电影", "genre": "剧情，惊悚", "tags": ["非线性叙事，复仇，宿命，重剪"], "summary_short": "不可撤销－正序版，2025年法国电影，剧情，惊悚。这是一次影像实验。将原版《不可撤销》的片段完全按照时间正序重新剪辑：从男主角马库斯和女友爱丽克斯在公寓里的甜蜜早晨开始，到他们出门、参加派对、爱丽克斯独自离开、隧道事件、马库斯发疯、复仇、误杀、被捕。当所有事件按逻辑顺序铺开时，那种“明知结局却无力阻止”的窒息感被放大到了极致。观众不再是跟着主角发现真相，而是看着一对普通情侣如何一步步被偶然的恶意碾碎。最残忍的不是意外，而是阳光灿烂的早上", "score": 2025308, "category": "drama", "detail_url": "../movie/0339.html", "poster": "../posters/0339.svg"}, {"id": "0340", "title": "美国恐怖故事集第三季", "year": 2026, "region": "美国", "type": "剧集", "genre": "恐怖 / 惊悚", "tags": ["单元剧", "隐喻", "血腥", "奇闻"], "summary_short": "美国恐怖故事集第三季，2026年美国剧集，恐怖 / 惊悚。本季共 10 集，每集一个独立故事。1. 《直播室》：网红主播挑战废弃医院直播，信号中断后恢复了，画面里的主播已经开始腐烂，但他还在对着镜头微笑。2. 《完美保姆》：一款育儿 APP 推荐的保姆能完美照顾婴儿，因为她其实是个能钻入电子设备的数字幽灵。3. 《换脸》：整形医院提供 AI 换脸手术，但换上的脸会在半夜脱离骨骼开始说话。用极具视觉冲击力的方式解构现代人的焦虑。", "score": 2026375, "category": "series", "detail_url": "../movie/0340.html", "poster": "../posters/0340.svg"}, {"id": "0341", "title": "白色荣光", "year": 2020, "region": "日本", "type": "剧集", "genre": "医疗, 悬疑, 剧情", "tags": ["医生", "医院", "医疗事故", "调查", "人性"], "summary_short": "白色荣光，2020年日本剧集，医疗, 悬疑, 剧情。东都大学附属医院拥有一个号称“白色荣光”的心脏外科团队，连续三年手术死亡率为零。但最近一个月，团队执行的七台高难度手术中，竟有四名患者离奇死亡。厚生劳动省派出冷静敏锐的调查官花房美和，她伪装成护士潜入手术室。表面上看，死亡都源于不可预测的并发症。但花房发现，死亡的顺序恰好对应着团队七名成员的名字笔画。进一步调查揭露：团队中一名被排挤的麻醉医生，因为自己的研究成果被主刀教授剽窃，且导致一", "score": 2020272, "category": "series", "detail_url": "../movie/0341.html", "poster": "../posters/0341.svg"}, {"id": "0342", "title": "超感应", "year": 2019, "region": "中国香港", "type": "电影", "genre": "科幻, 悬疑, 犯罪", "tags": ["脑科学", "读心术", "连环杀人", "伦理", "警匪"], "summary_short": "超感应，2019年中国香港电影，科幻, 悬疑, 犯罪。香港发生“梦魇连环凶杀案”，所有受害者都在睡梦中被吓死，死前脑电波异常。女警麦晴追查时遭袭击昏迷，脑科学专家陈教授提出“超感计划”：让麦晴的意识通过脑机接口潜入凶手的梦境，寻找线索。麦晴在凶手噩梦中看到扭曲的记忆画面，锁定嫌疑人——医院护工阿成。但阿成天生具有“超感应”能力，他发现麦晴在窥探自己后，反向入侵她的意识，试图在现实世界抹杀她。最终决战在麦晴的意识废墟中进行，麦晴利用阿成童", "score": 2019510, "category": "crime", "detail_url": "../movie/0342.html", "poster": "../posters/0342.svg"}, {"id": "0343", "title": "雅穆克围城日记", "year": 2021, "region": "约旦 / 卡塔尔", "type": "电影", "genre": "剧情 / 战争 / 历史", "tags": ["叙利亚", "难民", "围城", "纪实", "人性"], "summary_short": "雅穆克围城日记，2021年约旦 / 卡塔尔电影，剧情 / 战争 / 历史。2015年，大马士革南郊的雅穆克巴勒斯坦难民营被极端组织攻占，成为政府军的围困目标。老记者阿布·法德勒决定留下来记录这一切。影片以他的日记体形式展开，记录了营地内从断水断电，到粮食耗尽，再到黑市上一块面包卖出天价的惨状。主角穿插于各个家庭之间：一个母亲为了给孩子找牛奶而被狙击手射杀；一个曾是医生的老人徒手做手术；一群孩子在天井踢球，足球滚进雷区。影片没有激烈的交火", "score": 2021278, "category": "doc", "detail_url": "../movie/0343.html", "poster": "../posters/0343.svg"}, {"id": "0344", "title": "201413", "year": 2014, "region": "中国香港", "type": "电影", "genre": "爱情/剧情", "tags": ["数字", "宿命", "爱情", "时间"], "summary_short": "201413，2014年中国香港电影，爱情/剧情。程序员阿杰发现女友晓雯每次遇到数字“201413”就会倒霉，从车祸到失业。迷信的晓雯坚信这是上辈子的诅咒，决定分手。阿杰为了破解这个魔咒，开始研究数字命理学和时间回溯法。他发现这串数字竟然是他们两人在七年前一个雨夜，无意中写下的一句暗号。随着调查深入，阿杰震惊地发现，诅咒并非来自未来，而是他们早已被过去的某个选择所困。他们必须回到那个原点，做出不一样的决定，否则一切将不复存在。", "score": 2014365, "category": "drama", "detail_url": "../movie/0344.html", "poster": "../posters/0344.svg"}, {"id": "0345", "title": "真爱挂急诊", "year": 2024, "region": "韩国", "type": "电影", "genre": "浪漫喜剧", "tags": ["急诊室爱情", "冤家变情侣", "医生护士", "快节奏"], "summary_short": "真爱挂急诊，2024年韩国电影，浪漫喜剧。急诊科权威车医生有严重的洁癖和强迫症，号称“手术台上的机器人”。女主娜丽是个特技替身演员，浑身是伤，乐观粗线条。某天娜丽因拍摄事故被送进急诊，车医生被她满身的旧伤和毫不畏惧的态度激怒，治疗过程充满争吵。娜丽出院后，因为看到车医生被相亲对象嫌弃“没感情”，恶作剧地给他快递了一本手绘《恋爱操作手册》，里面画满了如何微笑、如何说情话。车医生把它当医学文献研究，并严格执行，结果在急诊室里闹出一系列温馨笑", "score": 2024245, "category": "comedy", "detail_url": "../movie/0345.html", "poster": "../posters/0345.svg"}, {"id": "0346", "title": "撒哈拉奇兵", "year": 2025, "region": "美国 / 摩洛哥", "type": "电影", "genre": "动作 / 冒险", "tags": ["沙漠", "寻宝", "雇佣兵", "女性主角"], "summary_short": "撒哈拉奇兵，2025年美国 / 摩洛哥电影，动作 / 冒险。气候学家发现，撒哈拉地下深处埋藏着一种“聚水晶体”，能瞬间将空气湿度提升百倍。一个疯狂富豪要将其挖出，在沙漠中造海，但此举会引发全球海啸。前特种兵诺拉集结了五位女队员：爆破专家、黑客、医生、狙击手和导航员，深入撒哈拉腹地。她们要抢在富豪之前找到晶体，并摧毁它。途中遭遇沙匪、地雷区、以及会移动的流沙湖。最终发现晶体其实是上古文明的“气候调节器”，而启动它的代价是牺牲一人。诺拉自愿", "score": 2025333, "category": "crime", "detail_url": "../movie/0346.html", "poster": "../posters/0346.svg"}, {"id": "0347", "title": "偷天换日", "year": 2025, "region": "美国", "type": "剧集", "genre": "动作, 犯罪, 悬疑", "tags": ["高智商犯罪", "艺术大盗", "FBI", "猫鼠游戏"], "summary_short": "偷天换日，2025年美国剧集，动作, 犯罪, 悬疑。被称作“幽灵”的艺术大盗尼尔在监狱里度过了八年，提前假释出狱的条件是必须戴上电子镣铐，并且每周向FBI报到。所有人都以为他会老实一段时间，然而就在出狱当晚，他潜入了FBI局长的私人宅邸，不是为了偷东西，而是留下了一张写有倒计时日期的卡片。尼尔向全世界的黑市放出消息：他将在90天后，当着FBI的面，偷走局长保险柜里那幅本应在大英博物馆却被局长私藏的文艺复兴名画。一场事先张扬的盗窃案拉开序", "score": 2025361, "category": "crime", "detail_url": "../movie/0347.html", "poster": "../posters/0347.svg"}, {"id": "0348", "title": "怆寿", "year": 2025, "region": "韩国", "type": "电影", "genre": "剧情奇幻", "tags": ["时间循环，老年，家庭关系，救赎，离别"], "summary_short": "怆寿，2025年韩国电影，剧情奇幻。倔老头朴怆寿是社区里出名的臭脾气，把儿女都气跑了，妻子也因他早逝。今天是他七十岁生日，也是他的忌日。他在一次摔倒后停止了呼吸，却又在凌晨五点闹钟响起时醒来。他度过了上百次同样的生日：试图提前去医院检查心脏，却总会因为各种意外死亡；试图去道歉，却因为拉不下面子把儿女再次骂走。在第99次循环时，他放弃了挣扎，穿着破旧的工作服去了妻子长满荒草的坟前。他第一次没有抱怨，而是坐下来给妻子讲了一整天孩子们小时候的", "score": 2025345, "category": "drama", "detail_url": "../movie/0348.html", "poster": "../posters/0348.svg"}, {"id": "0349", "title": "爱情公寓2", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧，爱情", "tags": ["合租，都市，爆笑"], "summary_short": "爱情公寓2，2024年中国大陆剧集，喜剧，爱情。延续第一季的故事，爱情公寓迎来了两位新租客：失业却傲娇的前富二代陆一鸣和沉迷二次元的宅女漫画家小美。老租客们也没闲着：曾小贤终于要跟胡一菲表白了，但每次都被各种乌龙打断；吕子乔试图做正经生意却把公寓搞成了传销窝点。与此同时，神秘房东突然出现，声称要收回公寓改建商业中心。六个人必须在24小时内凑齐巨额赎金，保住他们的乌托邦。", "score": 2024314, "category": "series", "detail_url": "../movie/0349.html", "poster": "../posters/0349.svg"}, {"id": "0350", "title": "爱情不设限", "year": 2025, "region": "韩国", "type": "剧集", "genre": "爱情, 喜剧, 奇幻", "tags": ["狗血", "恋爱铃", "契约", "高甜", "反套路"], "summary_short": "爱情不设限，2025年韩国剧集，爱情, 喜剧, 奇幻。韩素希是专门打离婚官司的毒舌律师，看透了婚姻的丑陋，决定终身不婚不恋，只约炮。车银优是财阀三代，因心理创伤患有严重亲密关系恐惧症，一被女性触碰就呕吐。两人在相亲角偶遇，都觉得对方是最佳“挡箭牌”。于是签下《纯粹柏拉图式恋爱合同》：假装情侣应付父母和同事，没有任何肢体接触，甚至不能心动。合约履行期间，两人意外遭遇车祸，嘴对嘴撞在了一起。第二天醒来，车银优发现自己不吐了，韩素希发现自己不", "score": 2025369, "category": "series", "detail_url": "../movie/0350.html", "poster": "../posters/0350.svg"}, {"id": "0351", "title": "智勇急转弯", "year": 1991, "region": "美国", "type": "电影", "genre": "喜剧，犯罪", "tags": ["逃亡，乌龙，撞车，证人保护，笨贼"], "summary_short": "智勇急转弯，1991年美国电影，喜剧，犯罪。纽约小混混比尔和雷伊欠高利贷被追杀，躲进一家餐厅时意外目睹黑帮老大灭口全过程。两人仓皇逃上公路，却在岔路口急转弯撞上一辆红色老式旅行车。车主是多萝西——一位退休的女狱警，正独自开车去佛罗里达养老。她不报警，反而用霰弹枪逼两人上车，说“带你们去个安全的地方”。比尔和雷伊以为得救，结果多萝西一路教他们反侦察、伪造车牌、甚至用老太太身份黑吃黑抢了黑帮的运钞车。当黑帮和警察同时追来时，比尔才发现多萝西", "score": 1991397, "category": "comedy", "detail_url": "../movie/0351.html", "poster": "../posters/0351.svg"}, {"id": "0352", "title": "猎爱高手", "year": 2024, "region": "韩国", "type": "电视剧", "genre": "爱情, 喜剧, 职场", "tags": ["律师", "离婚", "契约恋爱", "韩式浪漫", "欢喜冤家"], "summary_short": "猎爱高手，2024年韩国电视剧，爱情, 喜剧, 职场。专攻离婚诉讼的律师车恩英，业内人称“婚姻粉碎机”。为了拿下一桩巨额遗产案，她需要接近对方家族的小儿子——恰好是竞争对手律所的王牌离婚律师姜志勋。车恩英假装与姜志勋展开契约恋爱，想从中套取信息。然而姜志勋早就识破了她的计划，选择将计就计，故意泄露假情报。两人在互相“猎杀”的过程中逐渐动了真心，却不知道一场更大的阴谋在等着他们——遗产案背后，是两家律所长达二十年的恩怨。", "score": 2024299, "category": "series", "detail_url": "../movie/0352.html", "poster": "../posters/0352.svg"}, {"id": "0353", "title": "连城诀", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "武侠， 悬疑， 古装", "tags": ["寻宝， 谎言迷宫， 全员伪君子， 暗黑江湖"], "summary_short": "连城诀，2024年中国大陆剧集，武侠， 悬疑， 古装。经典武侠小说的全新黑暗版改编。侠客狄云为追查师父被害真相，卷入“连城宝藏”传说。传言说，宝藏被分藏于三座“连城”——金钱城、权力城、美色城，每座城都由一位江湖伪君子把守，入城需献出一样最珍贵的东西。狄云入金钱城，发现满城黄金皆是人骨所化；入权力城，目睹兄弟相残登位；入美色城，爱人竟成了守城者。每过一城，狄云就失去一部分“自我”：良知、信任、爱与希望。最终他抵达空无一物的第四座城，发现", "score": 2024280, "category": "series", "detail_url": "../movie/0353.html", "poster": "../posters/0353.svg"}, {"id": "0354", "title": "金色的梦", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情 / 家庭 / 奇幻", "tags": ["亲情，阿尔茨海默，视觉美学"], "summary_short": "金色的梦，2024年中国香港电影，剧情 / 家庭 / 奇幻。70岁的退休芭蕾舞者李国标，确诊阿尔茨海默症后，世界逐渐变成破碎的金色碎片。女儿小乔放下工作回乡照顾，却发现父亲的行为越来越诡异——他每晚都会穿戴整齐，对着空气鞠躬、托举，仿佛在排练一出只有他能看到的舞剧。小乔起初以为这是病情加重，直到她在父亲衣柜深处发现一叠泛黄的演出照片：那是1983年，父亲与她母亲在“香港青年艺术节”上的封箱演出，曲目是《胡桃夹子》。父亲从未忘记那场因母亲", "score": 2024334, "category": "drama", "detail_url": "../movie/0354.html", "poster": "../posters/0354.svg"}, {"id": "0355", "title": "荷兰镇", "year": 2024, "region": "美国", "type": "电视剧", "genre": "悬疑 / 恐怖", "tags": ["小镇", "失踪", "邪教", "心理惊悚", "连环杀手"], "summary_short": "荷兰镇，2024年美国电视剧，悬疑 / 恐怖。FBI行为分析部探员玛雅·科尔特斯的妹妹艾丽在荷兰镇一年一度的郁金香节期间失踪，当地警方认定为成年人自愿出走。但玛雅翻看过去五年的失踪档案后发现了一个恐怖规律：每年郁金香节，这个风景如画的小镇都会且只会失踪一个人，失踪者年龄、性别、职业毫无关联，唯一的共同点是他们都曾在节前三天去过镇上的“风车博物馆”。玛雅假借休假之名潜入小镇调查，发现风车博物馆的地下曾是一个十九世纪的秘密法庭，专门审判“女", "score": 2024377, "category": "series", "detail_url": "../movie/0355.html", "poster": "../posters/0355.svg"}, {"id": "0356", "title": "百无禁忌！女高中生私房话", "year": 2013, "region": "日本", "type": "剧集", "genre": "喜剧, 日常, 校园", "tags": ["无厘头", "闺蜜", "脱线"], "summary_short": "百无禁忌！女高中生私房话，2013年日本剧集，喜剧, 日常, 校园。普通高中生桃子、理科宅女眼镜酱、以及外表冷酷内心狂热的辣妹系，三人是死党。本剧没有主线剧情，完全由她们在午休、放学后、便利店里的私房话构成。话题极其跳跃：如何偷偷剃掉脸上的汗毛、如果世界上的男生都消失了怎么办、考试时如果写满“喵”会不会得分、以及严肃讨论如何在末世灾难中利用校服生存下去。她们时而争吵，时而一起犯傻，用最夸张、最不着边际的脑洞，解构了青春期少女所有那些难以", "score": 2013248, "category": "comedy", "detail_url": "../movie/0356.html", "poster": "../posters/0356.svg"}, {"id": "0357", "title": "监狱学警", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 犯罪", "tags": ["卧底", "监狱", "救赎", "师徒"], "summary_short": "监狱学警，2024年中国大陆电影，剧情 / 犯罪。年轻警校毕业生林骁为调查父亲在监狱中离奇死亡的真相，通过内部选拔成为了一名监狱学警，被派往父亲服刑过的南城监狱。他刻意接近被认为是凶手的重刑犯、曾经的监狱“大佬”洪叔，希望取得其信任并找到证据。然而在朝夕相处中，洪叔却教他监狱的生存之道，甚至多次救他于危难。林骁在仇恨与逐渐滋生的情义间挣扎，最终他发现父亲死亡的真相远比想象中复杂——而自己正一步步变成仇人模样。", "score": 2024326, "category": "crime", "detail_url": "../movie/0357.html", "poster": "../posters/0357.svg"}, {"id": "0358", "title": "澎湖海战", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "历史，战争，古装", "tags": ["明郑，清朝，水战，施琅，刘国轩"], "summary_short": "澎湖海战，2023年中国台湾电影，历史，战争，古装。1683年，康熙皇帝力排众议，决定武力收复台湾。清军水师提督施琅率领两万水师、三百艘战船直扑澎湖。明郑方面由年仅三十岁的刘国轩统领两万水师、两百艘战船迎战。七月的澎湖海面，两支华人史上规模最大的水师正面交锋。本片以海战为主线，同时穿插两条情感线：施琅原是郑成功旧部，因家人被郑经所杀而叛降清朝，他打这一仗一半为了朝廷一半为了复仇；刘国轩则是施琅的旧识，两人曾并肩作战。海战持续四天四夜，炮", "score": 2023274, "category": "costume", "detail_url": "../movie/0358.html", "poster": "../posters/0358.svg"}, {"id": "0359", "title": "风流教士俏女佣", "year": 2024, "region": "西班牙 / 墨西哥", "type": "网剧", "genre": "喜剧 / 爱情 / 历史", "tags": ["19世纪", "主仆恋", "讽刺教会", "反叛", "轻喜剧"], "summary_short": "风流教士俏女佣，2024年西班牙 / 墨西哥网剧，喜剧 / 爱情 / 历史。19世纪末，墨西哥庄园。年轻神父迭戈主张穷人革命，却被派来教化当地“不驯”的庄园主。庄园里有位从菲律宾殖民地被贩卖来的中国女佣明慧，聪明坚韧，暗中教农奴识字。迭戈与明慧因理念相投而相爱，但他有神职。他们偷偷在忏悔室接吻，在教堂地下室约会。事情败露，主教训斥迭戈，庄园主欲卖清明慧。迭戈选择还俗，在众人面前脱下教袍，说“上帝在明慧的眼睛里”。他带明慧和农奴们起义，占", "score": 2024186, "category": "series", "detail_url": "../movie/0359.html", "poster": "../posters/0359.svg"}, {"id": "0360", "title": "地下英雄", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "动作 / 犯罪 / 剧情", "tags": ["卧底", "地铁犯罪", "黑吃黑", "反转", "双雄"], "summary_short": "地下英雄，2021年中国大陆电影，动作 / 犯罪 / 剧情。老周是做了二十年地铁维修工的老实人。某夜他在隧道深处目睹一场毒品交易，仓皇逃跑时被监控拍到。毒贩将他误认为警方卧底，而警方反毒组也以为他是另一条线上的线人。两方同时找上他，要求他传递情报。老周被夹在中间，只能用维修工的身份和对地铁隧道的熟悉周旋。他伪造交易地点，利用列车时刻表制造时间差，甚至反过来设计毒贩内斗。最终警方收网时才发现，老周从未为任何一方真正服务，他只是不想死。结局", "score": 2021453, "category": "crime", "detail_url": "../movie/0360.html", "poster": "../posters/0360.svg"}, {"id": "0361", "title": "傲骨贤妻第五季", "year": 2013, "region": "美国", "type": "剧集", "genre": "律政, 剧情, 政治", "tags": ["律所分裂", "角色死亡", "艾美奖", "女权觉醒"], "summary_short": "傲骨贤妻第五季，2013年美国剧集，律政, 剧情, 政治。第五季伊始，Alicia再也无法忍受Lockhart/Gardner律所的政治斗争，她联合Cary等一批年轻合伙人，秘密策划出走并成立新所。当Will在法庭上看到Alicia站在对手席时，两人的私人恩怨与职业仇恨彻底点燃。与此同时，Peter正在竞选州长，Diane被迫在男女平权法案上与旧友对立。然而一切在季中戛然而止：一名心怀不满的客户持枪闯入律所法庭，Will为了保护实习生中", "score": 2013233, "category": "series", "detail_url": "../movie/0361.html", "poster": "../posters/0361.svg"}, {"id": "0362", "title": "湿透了", "year": 2026, "region": "英国", "type": "电影", "genre": "灾难, 生存", "tags": ["洪水", "摩天楼", "密闭空间", "阶级"], "summary_short": "湿透了，2026年英国电影，灾难, 生存。全球变暖导致伦敦被洪水吞没，只有少数超高层建筑露出水面。最顶级的“碎片大厦”成了诺亚方舟，富豪们买下舱位，按楼层分阶级：顶层是亿万富翁，中层是明星政要，底层是用全部积蓄换一张票的中产。洪水每天涨一层，底层最先被淹。当水位涨到中层时，顶层决定放弃下面所有人，启动直升机撤离。但一名底层水管工发现，大楼的排水系统可以反向将洪水抽回顶层。在最后一小时里，底层的人集体拧开了阀门，而顶层的人第一次听到了来自", "score": 2026232, "category": "sci-fi", "detail_url": "../movie/0362.html", "poster": "../posters/0362.svg"}, {"id": "0363", "title": "宝刀红侠", "year": 2025, "region": "中国香港", "type": "电影", "genre": "武侠动作", "tags": ["冷兵器", "复仇", "侠义精神", "师徒传承"], "summary_short": "宝刀红侠，2025年中国香港电影，武侠动作。香港历史博物馆的一件镇馆之宝——明末抗清名将的贴身佩刀“红刃”在夜间被盗。监控显示，盗贼身法诡异，现场没有留下任何痕迹。警方一筹莫展，但江湖上各路高手却闻风而动：有人自称是“红刃”原主人的后代，有人自称是古代刀法的唯一传人，有人说这把刀里藏着明末的巨额宝藏，还有人坚称刀上有诅咒，必须由自己销毁。所有这些“红侠”们在城市的楼顶、地铁、菜市场展开了连番冷兵器对决，打得天昏地暗。然而他们都不知道，这", "score": 2025263, "category": "crime", "detail_url": "../movie/0363.html", "poster": "../posters/0363.svg"}, {"id": "0364", "title": "楚天风云", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "历史 / 战争 / 悬疑", "tags": ["民国", "谍战", "长江", "宝藏"], "summary_short": "楚天风云，2025年中国大陆电影，历史 / 战争 / 悬疑。1938年夏，日军逼近武汉。一份绝密的“长江暗流图”被军统特工截获，图上标注了七处连长江上的老渔民都不知道的深水暗流位置——谁掌握了这些航道，谁就能让军舰在枯水季也能直抵宜昌。地图在一次伏击中断裂成三份，分别落入日本特务、当地袍哥会和一个跑船的码头帮手中。中共地下党员陈楚天伪装成文物商人潜入汉口，必须在十天内集齐三份碎片。但他在追踪过程中发现，这张图并非日军绘制，而是三十年前一", "score": 2025346, "category": "doc", "detail_url": "../movie/0364.html", "poster": "../posters/0364.svg"}, {"id": "0365", "title": "劣质爱情", "year": 2024, "region": "法国/比利时", "type": "电影", "genre": "爱情、剧情、情色", "tags": ["开放式关系", "嫉妒实验", "巴黎", "文艺情色", "心理博弈"], "summary_short": "劣质爱情，2024年法国/比利时电影，爱情、剧情、情色。巴黎艺术圈情侣保罗和玛侬恋爱五年，标榜“身体自由，灵魂唯一”。为了证明他们的关系牢不可破，两人定下一个游戏：各自去寻觅一名“猎物”，并在不产生感情的前提下发生关系，然后交换“猎物”，继续征服。游戏开始。保罗找了一位温吞的图书管理员，玛侬找了一位野性的女纹身师。然而当交换环节到来时，保罗发现自己疯狂嫉妒玛侬和图书管理员的每一句对话，而玛侬则在女纹身师身上体会到了从未有过的情感共振。原", "score": 2024317, "category": "drama", "detail_url": "../movie/0365.html", "poster": "../posters/0365.svg"}, {"id": "0366", "title": "人生一串第二季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "纪录片， 美食", "tags": ["烧烤， 烟火气， 街头美食， 深夜放毒"], "summary_short": "人生一串第二季，2024年中国大陆剧集，纪录片， 美食。延续第一季的火爆，第二季走得更远，更偏。从东北锦州的烤蚕蛹，到四川西昌的凉山小猪肉；从湛江的烤生蚝，到徐州的烤羊球。这一季不仅拍美食，更拍烧烤江湖里的“规矩”。我们看到了烧烤摊主如何在严苛的城管和刁钻的食客之间生存，看到了凌晨三点还在等位的醉汉背后破碎的梦想。每一串烤肉背后，都是一个热气腾腾的灵魂。那些在深夜里被炭火映红的脸，讲述着这个国家最真实、最粗粝、也最动人的故事。", "score": 2024249, "category": "series", "detail_url": "../movie/0366.html", "poster": "../posters/0366.svg"}, {"id": "0367", "title": "七十二家房客第二部粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "喜剧、市井、生活", "tags": ["粤语原声、香港老字号、街坊邻里、拆迁风波"], "summary_short": "七十二家房客第二部粤语，2024年中国香港剧集，喜剧、市井、生活。《七十二家房客》第二部紧接前作，房客们赶走了无良太子炳后，好不容易过上了太平日子。谁知地产商看中了这栋唐楼的地段，出高价诱使新业主（太子炳的舅舅）签署拆迁协议。七十二家房客面临被扫地出门的危机，而他们住了几十年早已把这栋楼当成家。包租婆八姑带头提出一个疯狂的计划：所有房客集资，把这栋楼买下来。于是，卖牛杂的阿贵拿出了儿子结婚的钱，舞女阿珍典当了唯一的钻戒，裁缝佬接活了所有", "score": 2024287, "category": "series", "detail_url": "../movie/0367.html", "poster": "../posters/0367.svg"}, {"id": "0368", "title": "节日的准备", "year": 2016, "region": "韩国", "type": "电影", "genre": "剧情 / 家庭", "tags": ["催泪", "阿尔茨海默", "亲情"], "summary_short": "节日的准备，2016年韩国电影，剧情 / 家庭。七十岁的顺子奶奶，病情已经到了中重度。她不认识女儿，不记得现在住的家，但每到农历八月，她就会突然清醒过来，洗米、磨粉、采艾草，一丝不苟地做松饼。女儿和女婿一开始以为这是病情好转的迹象，后来才发现，顺子的儿子——也就是他们从未谋面、母亲绝口不提的哥哥——在二十年前的中秋节前夕离家出走，再也没回来。顺子做的每一块松饼，都放在窗台上。今年，女儿通过社交媒体找到了远在釜山的哥哥。中秋夜，一个苍老的", "score": 2016253, "category": "drama", "detail_url": "../movie/0368.html", "poster": "../posters/0368.svg"}, {"id": "0369", "title": "屌丝男士第二季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧, 短片", "tags": ["段子剧", "自黑", "明星客串", "都市囧事"], "summary_short": "屌丝男士第二季，2024年中国大陆剧集，喜剧, 短片。《屌丝男士》第二季延续第一季的碎片化喜剧风格，每集由5-8个独立短剧组成。主角依然是那位永远在面试、永远在失恋、永远在赶不上公交车的“大鹏式”倒霉蛋。本季新增场景：他因为一次社区抗议走红，被邻居们推举为业委会主任，从此开始了“用爱发电、用穷管理”的荒诞执政生涯。他将面对广场舞大妈的“领土谈判”、养狗派的“排泄物外交”、以及和物业公司之间堪比谍战的博弈。每集结尾仍然保留“彩蛋明星客串”", "score": 2024255, "category": "series", "detail_url": "../movie/0369.html", "poster": "../posters/0369.svg"}, {"id": "0370", "title": "奇妙博物馆第二季", "year": 2021, "region": "中国大陆", "type": "剧集", "genre": "悬疑、奇幻、短剧", "tags": ["单元剧、脑洞、文物、人性"], "summary_short": "奇妙博物馆第二季，2021年中国大陆剧集，悬疑、奇幻、短剧。网络短剧《奇妙博物馆》第二季，延续第一季的“文物+都市传说”模式，共12集，每集15分钟。每一集聚焦一件真实存在的文物（或仿制品），讲述它引发的灵异或奇幻事件：汉代的铜镜能让人看到死去亲人的最后一面；宋代瓷枕每晚会播放使用者临终前的梦；清朝的鼻烟壶里关着一个太监的魂魄；明代崇祯皇帝的玉玺能让使用者短暂成为任何人的“皇帝”。第二季最出圈的是第四集《人皮唐卡》和第九集《血砚》。前者", "score": 2021390, "category": "series", "detail_url": "../movie/0370.html", "poster": "../posters/0370.svg"}, {"id": "0371", "title": "龙虎金刚", "year": 2025, "region": "中国香港", "type": "电影", "genre": "动作 / 犯罪 / 兄弟情", "tags": ["香港电影", "硬核动作", "双雄", "黑帮卧底"], "summary_short": "龙虎金刚，2025年中国香港电影，动作 / 犯罪 / 兄弟情。卧底阿浪在即将收网时身份暴露，被黑帮追杀。混乱中，他挟持了对方重伤的头号战将“金刚”——一个因脑部中弹而失去所有记忆，只保留格斗本能的杀人机器。阿浪带着这个“人形累赘”开始了逃亡，而黑帮和警方都在疯狂搜寻他们。起初两人只有对抗，但金刚在阿浪断断续续的讲述中，开始质疑自己过去的存在。为了找回记忆，金刚要求阿浪帮他“复盘”一生。他们重返一个个案发现场，金刚记起的越多，阿浪就越接近", "score": 2025330, "category": "crime", "detail_url": "../movie/0371.html", "poster": "../posters/0371.svg"}, {"id": "0372", "title": "牢狱大暴动", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 惊悚, 犯罪", "tags": ["监狱", "暴动", "单镜头", "实时", "生存"], "summary_short": "牢狱大暴动，2025年美国电影，动作, 惊悚, 犯罪。采用一镜到底（伪）的实时拍摄手法。菜鸟狱警迈克第一天上班，就被卷入了一场由黑帮老大策划的、席卷全监狱的大暴动。暴徒们控制了A区，残忍杀害狱警，夺取武器库。迈克侥幸躲进了废弃的惩罚室。他通过无线电得知，外面的警察将在24小时后才敢强攻，而他必须坚持到那时候。他利用监控盲区和对监狱地形的摸索，在通风管道、洗衣房和食堂之间穿梭，像《亡命天涯》一样躲避追杀。同时，他发现自己被栽赃运毒入狱，而", "score": 2025457, "category": "crime", "detail_url": "../movie/0372.html", "poster": "../posters/0372.svg"}, {"id": "0373", "title": "李察三世", "year": 2025, "region": "英国", "type": "电影", "genre": "历史 / 剧情", "tags": ["莎士比亚", "王室改编", "心理惊悚", "独角戏"], "summary_short": "李察三世，2025年英国电影，历史 / 剧情。伦敦一家封闭精神病院，收治了一名没有身份、只有自称“理查三世”的病人。他用莎士比亚的台词与医生对话，却逐步拼凑出一个颠覆历史的故事：他承认自己是真正的理查三世转世，当年并非为了王位而杀人，而是预见到了玫瑰战争会持续百年，才选择成为暴君来加速统一。医生试图用解离性身份障碍来解释，却发现该病人的预言开始在现代政坛应验。当MI5介入调查，病人要求医生为他做一次“公众法庭”，用直播证明：暴政有时是更", "score": 2025252, "category": "drama", "detail_url": "../movie/0373.html", "poster": "../posters/0373.svg"}, {"id": "0374", "title": "翠湖艳尸案", "year": 1978, "region": "中国香港", "type": "电影", "genre": "悬疑, 惊悚, 犯罪", "tags": ["风月探案", "楚原风格", "古龙武侠变体", "艳情元素"], "summary_short": "翠湖艳尸案，1978年中国香港电影，悬疑, 惊悚, 犯罪。民国初年，江南翠湖镇。一具穿着大红嫁衣的无头女尸浮出湖面，镇上巡捕房张探长奉命调查。诡异的是，镇上的教书先生、米店老板、镇长儿子甚至一个路过的戏子，都先后跑来认尸，声称这女子是自己的未婚妻，并且都拿出了定情信物。随着调查深入，张探长发现这些男人都曾在三年前去过省城一家名为“翠湖”的妓院，并且都点过同一位叫“牡丹”的头牌。而牡丹恰好在三年前失踪。张探长挖开妓院旧址的地基，找到了其余", "score": 1978496, "category": "crime", "detail_url": "../movie/0374.html", "poster": "../posters/0374.svg"}, {"id": "0375", "title": "寻找传家宝", "year": 2024, "region": "中国", "type": "电视剧", "genre": "剧情， 家庭， 悬疑", "tags": ["寻宝， 家族秘密， 城乡结合， 和解"], "summary_short": "寻找传家宝，2024年中国电视剧，剧情， 家庭， 悬疑。都市白领林小溪接到律师电话，得知素未谋面的爷爷给她留下一座空宅和一把旧铜钥匙。爷爷遗言让她找到藏在古镇某处的“龙凤银锁”。带着疑惑与好奇，林小溪回到湘西芙蓉镇。在此她遇到了爷爷生前的仇人之孙——古镇木雕传人陈默。两人从对立到合作，根据爷爷留下的山歌谜题，走遍吊脚楼、风雨桥和废弃的油坊。随着线索深入，一段跨越民国、抗战和特殊年代的故事浮出水面：龙凤银锁不仅是财富，更关乎当年地下交通站", "score": 2024294, "category": "series", "detail_url": "../movie/0375.html", "poster": "../posters/0375.svg"}, {"id": "0376", "title": "红色摇篮", "year": 2010, "region": "中国大陆", "type": "电视剧", "genre": "历史 / 战争 / 传记", "tags": ["革命历史", "井冈山", "红军早期", "伟人故事", "信仰"], "summary_short": "红色摇篮，2010年中国大陆电视剧，历史 / 战争 / 传记。1927年9月，秋收起义惨败，毛泽东拒绝中央攻打长沙的命令，带领仅剩的七百余人向井冈山转移。前有土匪袁文才、王佐的“鸿门宴”，后有国民党民团的疯狂围剿，更棘手的是来自中央的指责——“逃跑主义”、“右倾动摇”。剧中重点刻画了“三湾改编”的艰难博弈：毛泽东想废除旧军队的雇佣制，在士兵中建立党组织，却遭到黄埔系军官的集体抵制。当夜，余洒度等高级军官带一半人马叛逃。留下来的战士中，有", "score": 2010220, "category": "doc", "detail_url": "../movie/0376.html", "poster": "../posters/0376.svg"}, {"id": "0377", "title": "没好死", "year": 2022, "region": "法国", "type": "电影", "genre": "喜剧 / 黑色幽默", "tags": ["荒诞", "死亡", "哲学"], "summary_short": "没好死，2022年法国电影，喜剧 / 黑色幽默。保险员阿德里安在巴黎地铁被电击后，醒来发现进入了一个自己已经“死亡”的平行世界。在这里，他的墓碑上写着“被掉下来的企鹅砸死”。为了回到原世界，他必须按神秘来电指示，体验该世界的“最完美死亡”。从被自动售货机压扁，到被一群吉娃娃追下悬崖，他尝试了十几种离谱死法。直到他遇到一个同样在穿越的女物理学家，两人发现这一切是因为一家量子自杀公司操纵大众命运。最终阿德里安选择不按剧本死去，而是拥抱荒诞生", "score": 2022339, "category": "comedy", "detail_url": "../movie/0377.html", "poster": "../posters/0377.svg"}, {"id": "0378", "title": "狂飙掟煲团", "year": 1998, "region": "中国香港", "type": "电影", "genre": "喜剧 / 动作", "tags": ["港式无厘头，分手大师，乌龙任务"], "summary_short": "狂飙掟煲团，1998年中国香港电影，喜剧 / 动作。阿强、阿基等五兄弟相继被甩，酒后成立“掟煲团”（分手团），专替客户拆散情侣。他们手段卑劣，屡试不爽。某天黑道大佬马爷重金委托，要求他们拆散自己女儿和穷小子。五人潜入女方身边，却发现两人是真爱。更狗血的是，马爷突然破产，求他们反过来撮合。五人被迫从“狂飙分手”转为“疯狂撮合”，在婚礼上与前雇佣的打手火拼，最后阴差阳错成了英雄，自己也重拾爱情信心。", "score": 1998354, "category": "comedy", "detail_url": "../movie/0378.html", "poster": "../posters/0378.svg"}, {"id": "0379", "title": "夜爪", "year": 2026, "region": "美国/加拿大", "type": "电影", "genre": "恐怖/怪兽", "tags": ["都市传说", "纽约下水道", "畸形变异", "社会隐喻"], "summary_short": "夜爪，2026年美国/加拿大电影，恐怖/怪兽。纽约市的无家可归者开始接连失踪。最初警方以为是正常死亡，直到一名巡警在废弃地铁站拍到一段视频：黑暗中，一只巨大的、长满眼球的爪子，将蜷缩在暖气管道旁的流浪汉拖进了深不见底的下水道。警方高层下令销毁视频，理由是“防止社会恐慌”——说白了，死几个流浪汉没人会在意。但流浪汉群体里有一个叫“先知”的老兵，他曾是越战中的侦察兵。先知组织起剩下的流浪汉，用手工制作的武器和从垃圾堆里翻出来的监控设备，在下", "score": 2026378, "category": "horror", "detail_url": "../movie/0379.html", "poster": "../posters/0379.svg"}, {"id": "0380", "title": "母亲的春天", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["晚年情感", "代际冲突", "空巢老人"], "summary_short": "母亲的春天，2024年中国大陆电影，剧情, 家庭。退休教师王秀兰在丈夫肺癌去世后，独自住在一百二十平的空房子里，每天唯一的对话对象是上门送菜的机器人。她四十二岁的儿子张伟强因创业失败离异后搬回老宅，以“照顾母亲”为名已经啃老四年。王秀兰在一次老年大学书法班上认识了五十三岁的花店老板老郑，老郑幽默、体贴、会做饭，还会在她失眠时发语音念诗。两人悄悄交往三个月后，王秀兰决定再婚。张伟强得知后暴怒，理由层层升级：从“丢人现眼”到“他就是图你的房", "score": 2024316, "category": "drama", "detail_url": "../movie/0380.html", "poster": "../posters/0380.svg"}, {"id": "0381", "title": "爱情公寓第一季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "都市情景喜剧", "tags": ["合租", "年轻人", "笑对生活", "单元剧"], "summary_short": "爱情公寓第一季，2024年中国大陆剧集，都市情景喜剧。上海，一栋建于上世纪九十年代的老居民楼顶层，被中介包装成了“爱情公寓”，实际是把一套三室一厅隔成了七个胶囊房。七个身份各异的年轻人被迫挤在这里：刚被大厂裁员的985毕业生、试图逐梦演艺圈的横漂群演、白天教钢琴晚上直播带货的小镇姑娘、三十五岁还在读博的哲学系老学长、退学创业但已经欠了六十万的游戏主播、从东北逃婚过来的烧烤师傅、以及一只被遗弃的橘猫——对，猫也算一个“住户”。他们没有爱情", "score": 2024192, "category": "series", "detail_url": "../movie/0381.html", "poster": "../posters/0381.svg"}, {"id": "0382", "title": "血战唐人街", "year": 2024, "region": "美国 / 中国香港", "type": "电影", "genre": "动作 / 犯罪", "tags": ["帮派火并", "卧底复仇", "冷兵器近战"], "summary_short": "血战唐人街，2024年美国 / 中国香港电影，动作 / 犯罪。旧金山唐人街，帮派“青龙会”因一次毒品交易血洗了华裔家庭，一名女孩被杀。她的哥哥、退役特种兵李昂从阿富汗返回，单枪匹马挑了青龙会三个据点。当他终于杀进老大房间，刀架在对方脖子上时，对方的佛牌掉了下来——那是母亲临终前留给李昂的一对，另一只在哥哥脖子上。原来哥哥三岁被拐卖后，被黑帮养大，两人三十年后第一次见面，是刀锋相对。李昂的刀没有落下，哥哥的枪响了。", "score": 2024338, "category": "crime", "detail_url": "../movie/0382.html", "poster": "../posters/0382.svg"}, {"id": "0383", "title": "龙衔璎珞几时归", "year": 2025, "region": "中国大陆 / 中国台湾", "type": "剧集", "genre": "奇幻, 爱情, 古装", "tags": ["前世今生", "龙族", "宿命", "珠宝设计"], "summary_short": "龙衔璎珞几时归，2025年中国大陆 / 中国台湾剧集，奇幻, 爱情, 古装。天才珠宝设计师苏晚晚有个困扰她二十年的梦：黑暗中一颗龙首衔着一串璎珞，每颗珠子都对应一个她生命中重要的人，而最后那颗总在破碎前被龙吞下。她将此元素融入毕业设计“龙衔珠”系列，一举成名。三年后，该系列一款项链出现在拍卖会，被神秘富商龙御天以天价拍下。龙御天接近她，苏晚晚发现他的体温冰冷，且在月光下会有鳞片浮现。原来千年前她是龙族献给天帝的璎珞仙子，而龙御天是她私定", "score": 2025275, "category": "series", "detail_url": "../movie/0383.html", "poster": "../posters/0383.svg"}, {"id": "0384", "title": "世界第一初恋：求婚篇", "year": 2025, "region": "日本", "type": "剧场版动画", "genre": "爱情, BL", "tags": ["编辑部", "办公室恋情", "初恋", "求婚"], "summary_short": "世界第一初恋：求婚篇，2025年日本剧场版动画，爱情, BL。丸川书店编辑部的王牌总编高野政宗，和他的下属小野寺律已经“交往”了整整十年，却依然处于“恋人未满”的怪异状态。律始终认为政宗爱的只是记忆中那个纯情的自己。为了应对公司新推出的“爱情主题”漫画杂志，总编要求政宗和律带头策划一期“完美求婚”特辑。在采访各种情侣、收集素材的过程中，律被迫正视自己对婚姻的恐惧——他害怕重复父母失败的婚姻。而政宗则用一本十年前、律早已忘记送出的生日礼物", "score": 2025142, "category": "fantasy", "detail_url": "../movie/0384.html", "poster": "../posters/0384.svg"}, {"id": "0385", "title": "复仇之谜", "year": 2020, "region": "日本", "type": "电视剧", "genre": "悬疑, 犯罪", "tags": ["本格推理", "复仇", "多线叙事", "高智商"], "summary_short": "复仇之谜，2020年日本电视剧，悬疑, 犯罪。天才程序员秋山亮司被诬陷杀害女友，含冤入狱十年。出狱后他手握一份名单，上面有七个名字——真凶、伪证警察、受贿法官、造假的法医、隐瞒证据的律师、收买证人的富豪，以及背叛他的挚友。每周他会用完美的不在场证明杀掉一个人，手法精密到警方找不到任何证据。但第三周开始，每具目标尸体旁都多了一具尸体——多出来的死者不在秋山的名单上，而且死法更加残忍。警方意识到有人在模仿甚至“协助”秋山，而秋山本人也收到了", "score": 2020366, "category": "crime", "detail_url": "../movie/0385.html", "poster": "../posters/0385.svg"}, {"id": "0386", "title": "寒冬战士", "year": 2026, "region": "俄罗斯", "type": "电影", "genre": "战争、动作、历史", "tags": ["二战，狙击手，斯大林格勒，以一敌百"], "summary_short": "寒冬战士，2026年俄罗斯电影，战争、动作、历史。1942年，斯大林格勒陷入寒冬。苏联红军狙击手瓦西里所在的部队被德军全歼，他是唯一的幸存者。他手中的步枪瞄准镜也已碎裂。为了活下去并为战友复仇，瓦西里躲进了被炸成废墟的城市里。德军派出由一名柏林狙击学校教官率领的6人精英狙击小队，专门来猎杀他。瓦西里没有补给，没有支援，只有一把充当望远镜的破碎瞄准镜和100发子弹。他利用废墟的每一处裂缝、每一根钢梁，与猎杀者展开了一场猫鼠游戏。他像幽灵一", "score": 2026340, "category": "doc", "detail_url": "../movie/0386.html", "poster": "../posters/0386.svg"}, {"id": "0387", "title": "风月靡情", "year": 2025, "region": "香港", "type": "电影", "genre": "爱情, 剧情", "tags": ["情欲", "民国", "女性"], "summary_short": "风月靡情，2025年香港电影，爱情, 剧情。1930年代的上海，纸醉金迷。年轻貌美的四姨太棠玉是军阀卢大帅最宠爱的金丝雀，她的日常就是在偌大的宅院里等待一个永远不会来的归人。一天，被誉为“摩登玉娇龙”的进步女作家苏曼，受邀来府上做客。苏曼的独立、自由和新思想，像一道闪电击中了棠玉沉睡的心。两人迅速被彼此吸引，在花园的阴影里、在旗袍的遮掩下、在深夜的书信中，一段极度危险而炽热的恋情悄然绽放。她们的诗稿是唯一的情书，越界的冲动是无声的抗争。", "score": 2025319, "category": "drama", "detail_url": "../movie/0387.html", "poster": "../posters/0387.svg"}, {"id": "0388", "title": "芋川椋三玄关番之卷", "year": 1927, "region": "日本", "type": "电影", "genre": "喜剧，短片", "tags": ["默片，日本早期，滑稽"], "summary_short": "芋川椋三玄关番之卷，1927年日本电影，喜剧，短片。昭和初年，平凡的小职员芋川椋三清晨急着上班，却发现玄关的门锁神秘卡死。更诡异的是，窗外邻居、邮差甚至上司都陆续来敲门，而每一件门外发生的事都与他有关：邮差带来了辞退信、上司来突袭家访、甚至还有来讨债的。他在玄关这一方寸之地，用尽各种滑稽手段（钻窗户、拆门板、伪装声音）试图应对门外世界。最终门被撞开，他才发现这一切竟是一个关于“迟到恐惧”的噩梦。", "score": 1927255, "category": "comedy", "detail_url": "../movie/0388.html", "poster": "../posters/0388.svg"}, {"id": "0389", "title": "亚特兰蒂斯", "year": 2026, "region": "美国", "type": "剧集", "genre": "科幻，冒险，奇幻", "tags": ["海底文明，考古，阴谋，史诗"], "summary_short": "亚特兰蒂斯，2026年美国剧集，科幻，冒险，奇幻。深海勘探船“阿尔戈号”在北大西洋中脊发现疑似人造结构。队长中国女科学家林珊、英国生物学家汤姆、美国前海豹突击队员杰克及多国成员下潜探查。他们发现这就是亚特兰蒂斯，其文明非人类所建，而是来自猎户座的类人生物“先驱者”。先驱者因内战中“和平派”战败，将城市沉入海底后进入冬眠。“战争派”的机器守卫被科考队惊醒，开始攻击全球沿海城市。林珊发现要唤醒和平派领袖必须用特定DNA，而她自己就是其后裔。", "score": 2026374, "category": "series", "detail_url": "../movie/0389.html", "poster": "../posters/0389.svg"}, {"id": "0390", "title": "送信到哥本哈根", "year": 2023, "region": "丹麦 / 瑞典", "type": "电影", "genre": "剧情 / 战争", "tags": ["二战", "儿童视角", "自行车", "北欧风光"], "summary_short": "送信到哥本哈根，2023年丹麦 / 瑞典电影，剧情 / 战争。11岁的犹太男孩米克尔在父母被抓走后，只拿到一个信封和一串自行车钥匙。他的任务是从挪威南部出发，穿越瑞典，最后抵达哥本哈根，将信交给丹麦王室。一路上，他遇到了形形色色的人：假装冷漠实则为他引路的德国士兵、想偷他自行车的流浪汉、以及一位曾在集中营做翻译的丹麦老妇。米克尔逐渐发现，这封信的内容关乎战后北欧地下抵抗组织的重建。当他终于抵达哥本哈根时，等待他的不仅是接头人，还有一个关", "score": 2023272, "category": "drama", "detail_url": "../movie/0390.html", "poster": "../posters/0390.svg"}, {"id": "0391", "title": "攻壳机动队 新剧场版", "year": 2026, "region": "日本", "type": "动画剧集", "genre": "科幻， 动作， 悬疑", "tags": ["赛博朋克， 义体人， 公安九课， 黑客， 哲学思辨"], "summary_short": "攻壳机动队 新剧场版，2026年日本动画剧集，科幻， 动作， 悬疑。2029年，电子脑与义体化已成为常态。公安九课迎来一位特殊的受害者：一台拥有完美仿生义体却拒绝与任何人交流的“儿童”，她的电子脑中封印着一段足以颠覆国家政权的代码。与此同时，多起“灵魂蒸发”案件接连发生——受害者电子脑完好无损，人格数据却凭空消失。少佐草薙素子在追查中发现，敌人并非人类或AI，而是一种从量子通信网络中自发涌现的“意识寄生虫”。它能感染任何连接网络的电子脑", "score": 2026470, "category": "series", "detail_url": "../movie/0391.html", "poster": "../posters/0391.svg"}, {"id": "0392", "title": "尼泊尔灿烂阳光", "year": 2025, "region": "尼泊尔 / 中国", "type": "电影", "genre": "剧情 / 冒险 / 治愈", "tags": ["徒步", "丧子", "疗愈", "雪山", "跨文化"], "summary_short": "尼泊尔灿烂阳光，2025年尼泊尔 / 中国电影，剧情 / 冒险 / 治愈。退休教师老陈的儿子在珠峰遇难，他一直无法释怀，独自来到尼泊尔徒步。他雇佣了背夫小桑，发现小桑背包里装着石头和遗书。原来小桑因无力偿还家庭债务，计划在徒步终点自杀骗保。老陈没有说教，而是请求小桑带他走一条“最难走的路”——儿子当年登山的路线。路上，老陈讲儿子的故事，小桑讲尼泊尔山神的传说。他们遇雪崩、过悬崖，老陈救过小桑，小桑也背过老陈。在海拔5416米的坨龙垭口，", "score": 2025325, "category": "drama", "detail_url": "../movie/0392.html", "poster": "../posters/0392.svg"}, {"id": "0393", "title": "年度鸟事", "year": 2019, "region": "美国", "type": "电影", "genre": "喜剧， 剧情", "tags": ["观鸟， 中年危机， 友谊， 治愈"], "summary_short": "年度鸟事，2019年美国电影，喜剧， 剧情。亚瑟的婚姻、事业双双走到尽头，他把自己关在车库整月不出。发小保罗强行把他拽上车，参加“全美年度观鸟大赛”：24小时内，在州内观察到最多鸟种的人获胜。保罗的目标是一只在本地消失三十年的“东方角鸮”。两个中年男人开着破皮卡，在沼泽、森林、垃圾场之间狂奔。亚瑟起初觉得无聊，后来竟真的在凌晨四点的雨林中，听到了那声传说中的“呼——呼——”声。他找到了鸟，也找到了继续活下去的一个微不足道的理由。", "score": 2019272, "category": "drama", "detail_url": "../movie/0393.html", "poster": "../posters/0393.svg"}, {"id": "0394", "title": "向山进发第二季", "year": 2014, "region": "日本", "type": "动漫", "genre": "日常，百合，治愈", "tags": ["登山少女，富士山，友情成长，风景系"], "summary_short": "向山进发第二季，2014年日本动漫，日常，百合，治愈。第二季紧接前作，已经克服恐高症的雪村葵与好友日向等人将目标瞄准了日本最高峰——富士山。为了筹备登山资金与体力，她们先挑战了高尾山、筑波山等进阶路线。在登山过程中，葵的谨慎与日向的冒失不断碰撞，两人因路线选择发生严重争吵，葵一度想放弃登顶计划。但在新角色枫的调和下，她们重新理解彼此对山的感情。登山当天，面对稀薄空气与身体极限，葵在半路出现高原反应，靠着队友鼓励一步步往上爬。最终在御来光", "score": 2014069, "category": "fantasy", "detail_url": "../movie/0394.html", "poster": "../posters/0394.svg"}, {"id": "0395", "title": "钱学森", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "传记 / 历史", "tags": ["科学家", "两弹一星", "归国", "美国监禁", "航天"], "summary_short": "钱学森，2024年中国大陆电影，传记 / 历史。聚焦钱学森1950-1955年被美国软禁的五年。影片开头是1950年，钱学森准备回国，被美国司法部以“携带机密文件”为由抓捕，关进特米诺岛监狱。保释后，他在加州理工学院附近的一间小屋里被全天候监视，每月只能外出一次。在不能接触任何资料的情况下，钱学森靠脑内推演，在香烟盒和卫生纸上写下了《工程控制论》的初稿。妻子蒋英用弹钢琴的声音掩盖秘密记录。联邦调查局搜查时，蒋英将手稿藏进女儿的尿布中。1", "score": 2024258, "category": "doc", "detail_url": "../movie/0395.html", "poster": "../posters/0395.svg"}, {"id": "0396", "title": "眠狂四郎胜负", "year": 2024, "region": "日本", "type": "电影", "genre": "动作 / 历史", "tags": ["武士", "剑戟片", "孤独", "宿命", "复仇"], "summary_short": "眠狂四郎胜负，2024年日本电影，动作 / 历史。战国时代落幕，德川幕府统治渐稳，但暗流涌动。眠狂四郎是一位出身卑微、性格孤僻的剑士，他手持无铭刀，创造出了究极剑技“圆月杀法”。在途经一个边境小藩时，他无意间救下了一个被追杀的侍妾。这个女人身上藏着一份可以废黜现任将军的秘密血统书。从此，狂四郎被卷入了幕府内部的政治斗争。一方面，他面对着伊贺流忍者的围剿和藩主豢养的剑术高手；另一方面，他必须在“士农工商”的等级夹缝中寻找自己的立足之地。他", "score": 2024323, "category": "doc", "detail_url": "../movie/0396.html", "poster": "../posters/0396.svg"}, {"id": "0397", "title": "79公园大道", "year": 2023, "region": "美国", "type": "剧集", "genre": "悬疑 / 惊悚", "tags": ["豪宅、家族秘密、遗产、双胞胎、心理操控"], "summary_short": "79公园大道，2023年美国剧集，悬疑 / 惊悚。姐姐艾莉丝和妹妹玛莎靠帮人打扫豪宅卫生为生。一天，她们接到一份奇怪订单：清理79公园大道一栋废弃了20年的宅邸。进入后，她们发现所有家具都蒙着白布，墙上全是同一个少女的照片。更诡异的是，照片上的少女长得和她们一模一样。调查后得知，这栋房子的原主人是一位女继承人，20年前生下一对双胞胎后神秘失踪。艾莉丝开始出现记忆闪回，而玛莎则发现房子里有一间上锁的地下室，里面摆放着两套婴儿服和一份遗嘱。", "score": 2023330, "category": "series", "detail_url": "../movie/0397.html", "poster": "../posters/0397.svg"}, {"id": "0398", "title": "白色相簿第二季", "year": 2013, "region": "日本", "type": "动漫", "genre": "爱情，剧情，心理", "tags": ["胃痛番，多角恋，偶像与粉丝"], "summary_short": "白色相簿第二季，2013年日本动漫，爱情，剧情，心理。时间来到第一季的三年后，大学生藤井冬弥的女友由绮已成为国民级偶像，两人聚少离多。此时，冬弥被学妹小春热烈追求，同时与患有心疾的富家女千夏结识于医院。而由绮的竞争对手——偶像绪方理奈在车祸中失忆，唯独记得冬弥的名字。整个故事在冬弥公寓的白色窗帘前展开：五个女人轮番出现，每个人都在向他展示“非你不可”的爱。第二季结尾，冬弥在雪地里同时收到五封信，内容全是“谢谢你曾爱我”。他蹲下痛哭。最后", "score": 2013236, "category": "fantasy", "detail_url": "../movie/0398.html", "poster": "../posters/0398.svg"}, {"id": "0399", "title": "小鸟之翼第二季", "year": 2023, "region": "日本", "type": "动画剧集", "genre": "运动， 剧情， 热血", "tags": ["高尔夫， 天才少女， 复仇， 友谊， 职业竞技"], "summary_short": "小鸟之翼第二季，2023年日本动画剧集，运动， 剧情， 热血。在女子高尔夫界掀起旋风的天才少女伊芙，拒绝了所有顶级赞助商的邀约，只身前往美国参加大满贯赛事。她的真实目的是寻找二十年前神秘消失的职业选手父亲。比赛中，她遭遇了宿敌——完美主义者克里斯，两人的对决不仅是技术的较量，更是信念的碰撞。随着赛事深入，伊芙发现母亲的“意外退役”竟与父亲当年的丑闻有关，一个操纵球坛的黑幕组织逐渐浮出水面。她必须一边面对克里斯带来的巨大压力，一边在决赛日", "score": 2023247, "category": "series", "detail_url": "../movie/0399.html", "poster": "../posters/0399.svg"}, {"id": "0400", "title": "刀客家族的女人", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "年代", "tags": ["家族", "女性", "抗争"], "summary_short": "刀客家族的女人，2026年中国大陆剧集，年代。故事始于清末，讲述了西北潘家刀客家族从刀光剑影到走向覆灭的历程。核心聚焦于三个女人：第一代被迫守寡的“刀把子”婆婆潘杨氏、第二代被土匪强娶后又反抗的烈女花儿、第三代接受了新思想却最终为家族殉情的洋学生。她们在男人主导的乱世中，用各自的武器（刀、智慧、身体）守护着家族和土地，上演了一幕幕爱恨情仇。", "score": 2026237, "category": "series", "detail_url": "../movie/0400.html", "poster": "../posters/0400.svg"}, {"id": "0401", "title": "新舞曲大王", "year": 2005, "region": "美国", "type": "电影", "genre": "音乐, 剧情", "tags": ["街舞", "父子", "继承", "逆袭"], "summary_short": "新舞曲大王，2005年美国电影，音乐, 剧情。杰克·哈里森是街舞圈的传奇人物，绰号“舞曲大王”。但他隐藏了一个秘密：他的父亲曾是百老汇黄金时代的踢踏舞王。为了反抗父亲对自己街舞爱好的打压，杰克离家出走。多年后，父亲经营的百年老剧院面临拆迁危机，而父亲也因中风无法再跳舞。为了保住剧院，杰克决定回归。他发现拆迁合同里藏着一个赌约：如果剧院能在三个月内拿出一部爆满的新剧，项目就自动终止。杰克召集了昔日的街舞伙伴，并说服固执的老派舞者，试图将踢", "score": 2005307, "category": "drama", "detail_url": "../movie/0401.html", "poster": "../posters/0401.svg"}, {"id": "0402", "title": "换节期", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情、家庭", "tags": ["换亲、农村、女性、反抗、传统"], "summary_short": "换节期，2025年中国大陆电影，剧情、家庭。2000年代初，陕北农村。18岁的秀秀成绩优异，却被告知要嫁给邻村有智力缺陷的马家儿子，换来彩礼给哥哥娶媳妇。秀秀抗拒、逃跑、绝食，都被母亲以“这是你的命”挡回。婚礼前夜，秀秀偷听到真相：哥哥的“未婚妻”同样是被换来的，两个女孩都是牺牲品。第二天婚礼上，当主持人问“愿意吗”，秀秀抢过话筒，对着全村人、对着摄像机（前来拍摄扶贫纪录片的团队）说了一段话，彻底改变了自己和另一个陌生女孩的命运。", "score": 2025269, "category": "drama", "detail_url": "../movie/0402.html", "poster": "../posters/0402.svg"}, {"id": "0403", "title": "疯狂兔宝", "year": 2024, "region": "中国", "type": "动画电影", "genre": "喜剧、冒险", "tags": ["兔子、超能力、外星入侵、拯救家园、萌宠"], "summary_short": "疯狂兔宝，2024年中国动画电影，喜剧、冒险。农场里最胆小的小白兔“宝儿”总是被其他动物欺负。某夜，一颗坠落的陨石击中了它的窝，宝儿意外获得了念力——它能用念头移动方圆十米内的任何物体，但只要一害怕，能力就会失控。不久，外星“萝卜星人”降临，他们的母星因过度种植胡萝卜而枯竭，打算把地球改造成榨汁机，提取水资源。外星舰队的第一站，就是宝儿所在的农场。农场主被绑架，牛、羊、鸡、鸭全被关进能量笼。宝儿必须克服自己动不动就害怕的天性，用念力掀翻", "score": 2024258, "category": "fantasy", "detail_url": "../movie/0403.html", "poster": "../posters/0403.svg"}, {"id": "0404", "title": "致不灭的你第二季", "year": 2022, "region": "日本", "type": "剧集", "genre": "动画 / 奇幻 / 冒险", "tags": ["不死，永生，成长，物哀"], "summary_short": "致不灭的你第二季，2022年日本剧集，动画 / 奇幻 / 冒险。告别了贾南德岛，不死带着被复活的伙伴们——音波、嘎鲁、梅莎尔，继续前往“守护者”所在的城市。这座看似未来科技的城市，实则由能操控记忆的“守望者”控制。不死在这里找到了创造他的“神”的线索。但城市中的人开始恐惧不死“不朽”的力量，将他视为怪物。曾经被他拯救的人因为嫉妒而背叛，伙伴之间也因理念不同产生裂痕。不死第一次感到孤独比死亡更可怕。他必须想明白：如果永生注定失去所有人，那", "score": 2022262, "category": "fantasy", "detail_url": "../movie/0404.html", "poster": "../posters/0404.svg"}, {"id": "0405", "title": "原则问题", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 职场", "tags": ["法律", "道德困境", "理想主义", "职场斗争", "人性"], "summary_short": "原则问题，2025年中国大陆电视剧，剧情 / 职场。新人律师林远秉持“真相至上”的原则进入顶尖律所。他的第一个大案子是为一起环境污染案的受害者维权，对手是业内最强悍的辩护团队。然而调查越深入，他越发现真正的污染源头竟是自己恩师所在的另一家公益机构。林远陷入两难：揭露真相将毁掉恩师一生名誉，隐瞒则违背执业原则。与此同时，律所内部派系斗争将他当作棋子。在法庭上，面对受害家庭期盼的眼神和对手的威逼利诱，林远最终选择了最难的路——公开所有证据，", "score": 2025265, "category": "series", "detail_url": "../movie/0405.html", "poster": "../posters/0405.svg"}, {"id": "0406", "title": "会员请回答", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "悬疑， 科幻， 惊悚", "tags": ["密室逃脱， 人工智能， 人性实验"], "summary_short": "会员请回答，2024年中国大陆剧集，悬疑， 科幻， 惊悚。八位来自不同阶层的网友收到一款神秘APP的推送，获得了参加“超级会员”直播答题的资格，最终胜者将获得一亿奖金。起初，一切只是普通的智力游戏。但当有人答错第三题时，一名选手的手机突然收到了他远在乡下的母亲心脏病发去世的实时画面。游戏管理员“总管”冰冷的声音响起：“答案即命运。”众人这才意识到，他们每一道题的选择，都在操纵着现实中某个陌生人的生死。为了活下去，也为了不成为杀人凶手，八", "score": 2024399, "category": "series", "detail_url": "../movie/0406.html", "poster": "../posters/0406.svg"}, {"id": "0407", "title": "首都消失", "year": 2026, "region": "日本", "type": "电影", "genre": "灾难 / 科幻 / 悬疑", "tags": ["东京消失", "平行世界", "全民恐慌", "政治惊悚"], "summary_short": "首都消失，2026年日本电影，灾难 / 科幻 / 悬疑。早上六点十七分，东京——连同它的一千四百万人口、所有建筑、甚至地下的地铁和管道——在一瞬间消失了。没有爆炸，没有地震，没有辐射，只是像被橡皮擦擦掉了一样，原地留下一个完美的半球形深坑，坑壁光滑如镜。日本政府陷入瘫痪，美军第七舰队在横须贺原地待命但不敢靠近，全世界科学家无法解释这一现象。三天后，自称为“地球清理者”的外星文明发出第一条信息：“东京不符合银河系宜居星球第47条标准，已予", "score": 2026452, "category": "sci-fi", "detail_url": "../movie/0407.html", "poster": "../posters/0407.svg"}, {"id": "0408", "title": "我们的音乐", "year": 2024, "region": "法国", "type": "电影", "genre": "音乐，文艺", "tags": ["哲学，艺术与战争，戈达尔风格，非线性叙事"], "summary_short": "我们的音乐，2024年法国电影，音乐，文艺。三段式结构：地狱篇——纪录片式展现萨拉热窝废墟中一家仍在营业的黑胶唱片店，店主用音乐掩盖狙击枪声；炼狱篇——一所音乐大学里，学生在争论“肖斯塔科维奇是否应该为斯大林吹捧”，教授弹错一个音导致全班鼓掌半小时；天堂篇——荒岛上，失聪的钢琴家为了听到绝对寂静，拔掉了所有助听器。影片结尾，一个从未学过音乐的女孩在火车站的钢琴上胡乱按下琴键，所有在战争中死去的人出现在她身后，合唱了一首只有亡魂能听到的赋", "score": 2024261, "category": "doc", "detail_url": "../movie/0408.html", "poster": "../posters/0408.svg"}, {"id": "0409", "title": "剧场灵", "year": 2015, "region": "日本", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["舞台剧", "剧场", "传说", "嫉妒", "附身"], "summary_short": "剧场灵，2015年日本电影，恐怖 / 悬疑。新人女演员沙罗被选中主演热门舞台剧《罔两》。排练第一天，原定A角女演员真弓从舞台吊桥坠落摔断腿。沙罗成为替补后，经常在化妆镜中看到穿和服的无脸女人。剧作家称这是“剧场灵”——一个百年前在首演之夜被男主残忍杀害的女配角。真弓坐着轮椅来探班时，用诅咒般的眼神盯着沙罗。公演前夜，沙罗在舞台上被看不见的手掐住脖子，幕后所有人都以为她在练习。公演当天，沙罗在独白时突然变成另一个人，用沙哑的声音说出真弓杀", "score": 2015439, "category": "horror", "detail_url": "../movie/0409.html", "poster": "../posters/0409.svg"}, {"id": "0410", "title": "愿赌服输", "year": 2025, "region": "中国香港", "type": "电影", "genre": "犯罪, 悬疑, 黑色幽默", "tags": ["赌博", "器官交易", "反转", "兄弟情", "绝境"], "summary_short": "愿赌服输，2025年中国香港电影，犯罪, 悬疑, 黑色幽默。落魄会计师陈兆伦的女儿急需骨髓移植，走投无路下被引入一个神秘赌局。规则很简单：每人抵押一件“非财务资产”——可以是十年寿命、一只眼睛、一段记忆，甚至是未出生孩子的健康。陈兆伦抵押了自己的左肾，孤注一掷。他凭借精算能力连赢三局，却在最终局被对手出千，输掉了心脏。对方给他三天时间“安排后事”。陈兆伦用这三天反查赌局幕后，发现这是一个专门收割绝望者的器官拍卖网络，而他的最终对手竟是当", "score": 2025376, "category": "crime", "detail_url": "../movie/0410.html", "poster": "../posters/0410.svg"}, {"id": "0411", "title": "皮特·戴维森：死党齐搞笑", "year": 2025, "region": "美国", "type": "综艺/特别篇", "genre": "喜剧, 脱口秀, 真人秀", "tags": ["单口喜剧", "明星好友", "恶搞", "聚会"], "summary_short": "皮特·戴维森：死党齐搞笑，2025年美国综艺/特别篇，喜剧, 脱口秀, 真人秀。在这档特别的喜剧特辑中，皮特·戴维森并没有选择在剧场表演，而是在他纽约的公寓里举办了一场深夜派对。他邀请了说唱歌手、体育明星和喜剧圈的好友们。节目没有固定流程，只有不停灌酒、打游戏和互相揭短。皮特用他标志性的自嘲讲述了关于恋爱、戒毒和网暴的黑暗笑话，朋友们则爆料他生活中的各种糗事。当派对进行到高潮时，警察因扰民上门，这群喝醉的明星开始即兴模仿执法过程，将整个", "score": 2025114, "category": "series", "detail_url": "../movie/0411.html", "poster": "../posters/0411.svg"}, {"id": "0412", "title": "沙漠活宝", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "冒险喜剧", "tags": ["公路， 寻宝， 搞笑， 沙漠"], "summary_short": "沙漠活宝，2022年中国大陆电影，冒险喜剧。失业青年大伟、露营网红小雪、退休地质学家老钱三人组队穿越腾格里沙漠，本想拍网红Vlog，却在废弃驿站里发现一张羊皮藏宝图，指向传说中的“黑水城宝藏”。三人开着破旧越野车出发，谁知刚进沙漠就遇上真正的盗墓团伙。大伟把藏宝图塞进骆驼嘴里，结果骆驼跑了。他们只好满沙漠追骆驼，又被盗墓贼当成同行追杀。历经沙尘暴、陷车、断水，他们阴差阳错掉进一个地下洞穴，发现宝藏是一整间古代种子库。老钱激动地说这是“农", "score": 2022280, "category": "comedy", "detail_url": "../movie/0412.html", "poster": "../posters/0412.svg"}, {"id": "0413", "title": "天堂岛疑云第五季", "year": 2015, "region": "英国", "type": "电视剧", "genre": "悬疑 / 犯罪", "tags": ["英剧", "加勒比海", "本格推理"], "summary_short": "天堂岛疑云第五季，2015年英国电视剧，悬疑 / 犯罪。圣玛丽岛迎来了新的英国探长杰克。不同于前任的古板，杰克看似懒散，实则拥有惊人的观察力。第五季开篇，一名富商在封闭的游艇派对上被毒杀，所有宾客都有不在场证明。杰克在调查中发现了岛上风能项目背后的巨大利益链。与此同时，警队成员正经历着感情危机与个人挣扎。随着一具埋在沙滩下的白骨被挖出，一桩跨度二十年的冤案浮出水面，而凶手似乎就在他们身边，正试图引导调查走向死胡同。", "score": 2015317, "category": "series", "detail_url": "../movie/0413.html", "poster": "../posters/0413.svg"}, {"id": "0414", "title": "学宫春色", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "古装 / 喜剧 / 青春", "tags": ["古代大学", "女性读书", "欢喜冤家"], "summary_short": "学宫春色，2024年中国大陆剧集，古装 / 喜剧 / 青春。明成化年间，金陵女子沈莺为了替早亡的兄长完成“入国子监”的遗愿，女扮男装冒名入学。国子监是全国最高学府，规矩森严，稍有不慎就是杀头之罪。沈莺小心翼翼如履薄冰，却偏偏碰上了全监最不安分的学生——江南首富之子柳梦生。此人入学的唯一目的就是被开除，好回去继承家业，于是变着花样逃课、捣乱、顶撞祭酒。沈莺为了不暴露身份，不得不一次次替柳梦生“背锅”，两人成了全校最奇怪的搭档。随着时间推移", "score": 2024208, "category": "series", "detail_url": "../movie/0414.html", "poster": "../posters/0414.svg"}, {"id": "0415", "title": "沧月绘", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装 / 奇幻", "tags": ["宫廷画师、逆时空、水墨法术、权谋"], "summary_short": "沧月绘，2025年中国大陆剧集，古装 / 奇幻。现代文物修复师姜月在一次古画修复中，被吸入唐代名画《沧月宫宴图》，穿越成了画中一名默默无闻的小画师。她发现自己拥有一种神奇的能力：用特殊的“沧月墨”作画，画出的花鸟鱼虫会跃然纸上变为现实。然而，当她无意中画出已故太子的肖像时，太子竟然真的复活了，但史书上关于太子的一切记载却瞬间消失了。姜月意识到，这项能力是双刃剑——创造即抹杀。此时，想要篡位的皇子盯上了她，威逼她画出当朝皇帝的脸。姜月被困", "score": 2025237, "category": "series", "detail_url": "../movie/0415.html", "poster": "../posters/0415.svg"}, {"id": "0416", "title": "赘婿动画版", "year": 2026, "region": "中国", "type": "动画剧集", "genre": "古风/商战", "tags": ["爽文", "逆袭", "动漫", "权谋", "搞笑"], "summary_short": "赘婿动画版，2026年中国动画剧集，古风/商战。现代商业精英江皓辰意外身亡，醒来竟成了商贾之家最不受待见的上门女婿宁毅。在男尊女卑的时代，他不仅要忍受亲朋好友的羞辱，还要帮妻子苏檀儿打理濒临破产的布行。既然不能用拳头说话，那就用现代思维降维打击。大数据营销、饥饿营销、期货做空，宁毅用一套套匪夷所思的商业手段横扫同行。当皇帝都派人来查抄他家产业时，宁毅微微一笑：不好意思，整个国家的经济命脉，现在我说了算。", "score": 2026239, "category": "series", "detail_url": "../movie/0416.html", "poster": "../posters/0416.svg"}, {"id": "0417", "title": "犹太狮子", "year": 2026, "region": "美国", "type": "电影", "genre": "剧情 / 历史 / 战争", "tags": ["二战，抵抗运动，身份认同，信仰，生存"], "summary_short": "犹太狮子，2026年美国电影，剧情 / 历史 / 战争。1944 年华沙，犹太青年拉比大卫·伯科维茨在家人被害后，加入地下抵抗组织。他利用宗教身份掩护，秘密传递情报、营救同胞。在一次关键任务中，他必须伪装成德军军官潜入集中营，救出一名掌握纳粹黄金流向的英国特工。行动中，他的信仰不断受到拷问：为了拯救更多人，是否可以违背戒律杀人？最终，他在废墟中点燃光明节烛台，以“狮子”之名带领十二名孤儿成功突围。", "score": 2026237, "category": "doc", "detail_url": "../movie/0417.html", "poster": "../posters/0417.svg"}, {"id": "0418", "title": "保险箱", "year": 2024, "region": "韩国", "type": "电影", "genre": "惊悚 / 犯罪 / 悬疑", "tags": ["密室", "银行", "人质", "反转", "内鬼"], "summary_short": "保险箱，2024年韩国电影，惊悚 / 犯罪 / 悬疑。大雨夜，首尔一家银行被四名蒙面劫匪控制。新人职员智雅与另外两人被关进金库。劫匪头目“酋长”逼迫经理老金打开一个特殊的私人保险箱。老金满头大汗，说密码只有已离职的行长知道。劫匪殴打人质，智雅突然开口：“别打了，我知道密码。但里面没有钱，是我丈夫的尸体。”全员震惊。智雅开始讲述：丈夫是银行高层，长期家暴她，一个月前她将丈夫骗入保险箱后锁死，伪造了失踪。劫匪以为是警方设局，内部开始内讧。此", "score": 2024446, "category": "crime", "detail_url": "../movie/0418.html", "poster": "../posters/0418.svg"}, {"id": "0419", "title": "窥情国语", "year": 1994, "region": "中国香港", "type": "电影", "genre": "爱情， 悬疑", "tags": ["偷窥， 公寓， 录音带， 旧情复燃"], "summary_short": "窥情国语，1994年中国香港电影，爱情， 悬疑。阿珍在旧货市场买到一盒国语情歌录音带，回家播放时却意外听到一段男人密谋杀妻的对话。她循着声音开始用望远镜观察对面大厦，发现声音的主人竟是自己的前度情人阿豪。阿豪身边多了一个操国语的神秘女人。阿珍一边陷入旧情，一边试图警告阿豪的现任妻子。但当命案真的发生，所有证据却都指向了偷窥者阿珍。她才发现，自己从买下那盒录音带开始，就已经成了棋局中的替罪羊。", "score": 1994402, "category": "crime", "detail_url": "../movie/0419.html", "poster": "../posters/0419.svg"}, {"id": "0420", "title": "14岁", "year": 2024, "region": "日本", "type": "电影", "genre": "青春 / 奇幻", "tags": ["成长疼痛，时间循环，校园霸凌，治愈"], "summary_short": "14岁，2024年日本电影，青春 / 奇幻。内向的初中生小夜子每天在教室角落忍受同学欺凌。一个雨天，她被推下楼梯后，发现自己醒来时永远是同一天——14岁生日那天的早晨。第一次循环她选择逃学，第二次试图反抗却更惨，第三次求助老师反被责备……在第47次循环时，她偶然发现那个带头霸凌的女孩其实也在家中遭受暴力。小夜子不再只想着自救，而是开始理解每一个人背后的伤痛。她用一次次循环积累的信息，像拼图一样修复破裂的关系。在第99次循环，她组织了一次", "score": 2024300, "category": "comedy", "detail_url": "../movie/0420.html", "poster": "../posters/0420.svg"}, {"id": "0421", "title": "钻石惹的祸", "year": 2023, "region": "中国", "type": "电影", "genre": "黑色喜剧", "tags": ["荒诞，犯罪，巧合，平民英雄"], "summary_short": "钻石惹的祸，2023年中国电影，黑色喜剧。老实巴交的早餐店老板刘富贵，在进货的鱼肚子里发现了一颗价值三千万的粉钻。他本想悄悄卖掉改善生活，却不知这颗钻石是国际大盗“狐眼”失窃的赃物。黑帮老大、贪心房东、两位笨贼和一名退休警察先后卷入这场混乱。刘富贵的小店成了斗兽场，蒸笼里藏钻、豆浆里下药、油锅成了武器。最终在一场荒唐的社区文艺汇演上，所有势力被一网打尽，而刘富贵用钻石换来的“奖金”，竟是一张假彩票。", "score": 2023283, "category": "comedy", "detail_url": "../movie/0421.html", "poster": "../posters/0421.svg"}, {"id": "0422", "title": "含笑九泉", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情 / 黑色幽默", "tags": ["殡葬", "亲情", "和解", "黑色幽默", "遗愿清单"], "summary_short": "含笑九泉，2024年中国香港电影，剧情 / 黑色幽默。叛逆少女程欢厌恶家族殡葬业，却在父亲病危时被逼接手“含笑九泉”殡仪馆。她偶然发现，一位逝者留下的“遗愿彩蛋”竟是为孙女征婚，引发啼笑皆非的闹剧。程欢本打算敷衍了事，却在执行过程中逐渐理解逝者的遗憾与生者的伤痛。她用现代方式改造传统流程，让告别变得温暖有趣，也修复了自己与父亲的裂痕。当最后一位无亲无故的孤寡老人将遗产全数赠予她时，程欢终于明白：送人含笑上路，便是教人好好活着。", "score": 2024234, "category": "drama", "detail_url": "../movie/0422.html", "poster": "../posters/0422.svg"}, {"id": "0423", "title": "阴影之下", "year": 2016, "region": "伊朗, 英国", "type": "电影", "genre": "恐怖, 剧情, 心理", "tags": ["战争创伤", "超自然", "母女", "政治隐喻"], "summary_short": "阴影之下，2016年伊朗, 英国电影，恐怖, 剧情, 心理。1988年，德黑兰。前医学系学生希德与女儿被迫留在战火中的公寓。一枚导弹击穿天花板，没有爆炸，但房内开始出现异象：书页自动翻动，女儿的娃娃自己移动，墙角的阴影越来越浓。女儿说看到“巨灵”在跟她说话。希德不信，直到她发现，巨灵只攻击女性，会变成她们最害怕的东西。丈夫参军在外，求助无门。当巨灵变成希德因“不戴头巾”而自杀的姐姐时，希德崩溃了。但她最终举起那枚未爆的导弹，狠狠砸向阴影", "score": 2016362, "category": "drama", "detail_url": "../movie/0423.html", "poster": "../posters/0423.svg"}, {"id": "0424", "title": "致命午休", "year": 2024, "region": "韩国", "type": "电影", "genre": "惊悚 / 悬疑", "tags": ["办公室", "集体催眠", "社畜惊悚", "高概念"], "summary_short": "致命午休，2024年韩国电影，惊悚 / 悬疑。某大型企业有一个诡异传统：每天13:00-14:00为“深度午休”时间，全员必须在工位上闭眼。钟声敲响时，其中一人会被选中，进入催眠状态，醒来后会用办公室里任何物品杀掉“当天的最该消失者”——可能是讨厌的上司、碍事的同事、或是自己。没人记得午休时发生了什么，但每天都会有一具尸体。新人小李入职第一天就目睹了这一切，她试图报警，却发现自己也被卷入了“午休名单”。她必须在每一轮午休前，找出催眠背后", "score": 2024358, "category": "crime", "detail_url": "../movie/0424.html", "poster": "../posters/0424.svg"}, {"id": "0425", "title": "赤裸反击", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作 / 惊悚", "tags": ["女性复仇", "裸贷", "黑客", "极限格斗", "私刑"], "summary_short": "赤裸反击，2025年韩国电影，动作 / 惊悚。天才女程序员秀敏被男友骗拍私密视频并陷入高利贷陷阱，视频被上传至暗网，导致她母亲受刺激心脏病发去世。走投无路的秀敏不再相信法律，她利用自己的编程技术黑入犯罪集团的系统，抹去自己的所有社会身份，化身“幽灵”。她从零开始学习格斗与枪械，逐一接近放贷者、催收员乃至幕后黑手。每一次复仇都是一场精心策划的“电子+物理”双重打击，她要让那些躲在屏幕后的豺狼，亲身体验一丝不挂暴露在阳光下的绝望。", "score": 2025406, "category": "crime", "detail_url": "../movie/0425.html", "poster": "../posters/0425.svg"}, {"id": "0426", "title": "杜立德医生", "year": 2027, "region": "英国", "type": "剧集", "genre": "奇幻、冒险、医学", "tags": ["兽医、懂兽语、维多利亚、动物大军、解谜"], "summary_short": "杜立德医生，2027年英国剧集，奇幻、冒险、医学。杜立德医生不仅能跟动物聊天，还能调解鸟窝里的夫妻矛盾。当伦敦码头出现一具诡异的尸体，伤口全是啮齿类动物啃咬痕迹，警方认定是杜立德“指使”他的动物军团行凶。为了洗清罪名，杜立德不得不与一只话痨鹦鹉、一条怕蛇的獴组成侦探小队，通过询问老鼠目击者和鸽子高空证词，最终发现真凶是一只用口哨操控动物的腹语师。", "score": 2027290, "category": "series", "detail_url": "../movie/0426.html", "poster": "../posters/0426.svg"}, {"id": "0427", "title": "飞天怪兽", "year": 2026, "region": "日本 / 美国", "type": "电影", "genre": "科幻 / 灾难 / 惊悚", "tags": ["怪兽", "空中巨兽", "城市毁灭", "科幻设定", "生存"], "summary_short": "飞天怪兽，2026年日本 / 美国电影，科幻 / 灾难 / 惊悚。一种全新的未知生命体出现在东京都市圈的上空。它们拥有变色龙般的伪装能力，在空中几乎完全透明，且对声音极度敏感。这种被命名为“虚空翼龙”的生物以人类的内脏为食，一旦锁定目标，便会以超音速俯冲下来，瞬间将人吞噬。自卫队的雷达完全失效，导弹打不中看不见的目标。幸存者佐藤是一名退役的自卫队飞行员，他发现自己因旧伤植入的金属骨骼会产生特定频率的电磁波，能够干扰怪兽的隐形立场。在女儿", "score": 2026450, "category": "sci-fi", "detail_url": "../movie/0427.html", "poster": "../posters/0427.svg"}, {"id": "0428", "title": "某人某地第三季", "year": 2026, "region": "美国", "type": "电视剧", "genre": "剧情, 喜剧, 生活", "tags": ["回乡", "中年", "友情", "细腻", "慢节奏"], "summary_short": "某人某地第三季，2026年美国电视剧，剧情, 喜剧, 生活。第三季延续前作。萨姆在经历了父亲去世、与挚友乔尔的关系破裂与和解后，她终于决定留在堪萨斯州，不再逃回纽约。本季中，萨姆尝试在当地高中任教，却被保守的家长投诉其教学方式。她与乔尔组成的“非典型唱诗班”因为一首改编的福音歌在小镇上走红，也引发了教会保守派的抵制。萨姆必须处理与姐姐特林迪复杂的关系，姐姐的婚姻危机让两人重新审视童年的创伤。同时，一只流浪狗闯入她的生活，教会了她什么是无", "score": 2026265, "category": "series", "detail_url": "../movie/0428.html", "poster": "../posters/0428.svg"}, {"id": "0429", "title": "一往无前", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "运动 / 剧情 / 励志", "tags": ["马拉松", "退役运动员", "中年逆袭", "素人出演", "真实事件改编"], "summary_short": "一往无前，2023年中国大陆电影，运动 / 剧情 / 励志。根据真实人物改编。李钢曾是九十年代马拉松全国纪录保持者，退役后当了二十年的中学体育老师，啤酒肚、高血压、离异。体检发现肝部晚期肿瘤，医生估计最多一年。他拒绝了化疗，向学校请假一年，理由是：“我想再跑一次，跑到跑不动为止。”没有赞助，没有团队，他一个人在凌晨四点的操场开始恢复训练。前三个月，他连五公里都跑不下来，在跑道上呕吐、摔倒、痛哭。第四个月，一个被他体罚过的叛逆学生突然回来", "score": 2023316, "category": "drama", "detail_url": "../movie/0429.html", "poster": "../posters/0429.svg"}, {"id": "0430", "title": "铁证悬案第三季", "year": 2005, "region": "美国", "type": "电视剧", "genre": "犯罪，悬疑，剧情", "tags": ["冷案重启，怀旧金曲，人性救赎，单元剧"], "summary_short": "铁证悬案第三季，2005年美国电视剧，犯罪，悬疑，剧情。第三季延续了前作的风格，每集独立侦破一个几十年未破的悬案。由于案件年代久远，许多证人和嫌疑人已经死去或垂垂老矣，警探们必须依靠当年的老照片、信件以及仅存的目击者的回忆进行推理。本季涉及了多个发人深省的案件：1950年代因同性恋身份被谋杀的海军士兵、1970年代在嬉皮士运动中失踪的青少女、以及牵扯到一桩豪门家族内部乱伦丑闻的婴儿失踪案。每一集都采用闪回叙事，通过极具年代感的配乐和服化", "score": 2005413, "category": "series", "detail_url": "../movie/0430.html", "poster": "../posters/0430.svg"}, {"id": "0431", "title": "双头人", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖", "tags": ["身体恐怖", "连体", "心理分裂", "实验", "惊悚"], "summary_short": "双头人，2025年美国电影，恐怖。艾比和布列塔尼是一对罕见的颅部连体双胞胎，共享一个大脑但拥有两个独立意识。22岁那年，她们决定冒险接受分离手术，但术中发生灾难性意外，医生不得不放弃分离并保住了唯一的身体。结果两人变得头朝前后两面，共用躯干但视角完全相反。术后诡异的事情发生了：白天的人格是温和的艾比，晚上八点后自动切换成暴躁的布列塔尼，两人都无法控制切换时间。她们开始用录音笔给对方留言，逐渐发现了这个身体更恐怖的秘密——每当人格切换时，", "score": 2025383, "category": "horror", "detail_url": "../movie/0431.html", "poster": "../posters/0431.svg"}, {"id": "0432", "title": "下一个圣诞节见", "year": 2024, "region": "美国", "type": "电影", "genre": "爱情，奇幻，喜剧", "tags": ["时间循环，圣诞，治愈"], "summary_short": "下一个圣诞节见，2024年美国电影，爱情，奇幻，喜剧。工作狂艾玛对圣诞节毫无兴趣，却在今年的公司派对上意外遭遇一个古怪的雪球袭击。醒来后，她发现自己永远被困在了12月25日这一天。每一次午夜钟声响起，一切都会重置，只有她的记忆保留。为了回到正常生活，她必须在每次循环中找出打破诅咒的方法。在一次次的重复中，她尝试了不同的圣诞节过法：拒绝聚会、独自旅行、甚至捣乱破坏。最终她发现，只有当她真心实意地对一直暗恋她的邻居说出“我爱你”并献上初吻，", "score": 2024427, "category": "romance", "detail_url": "../movie/0432.html", "poster": "../posters/0432.svg"}, {"id": "0433", "title": "赫尔曼", "year": 2018, "region": "德国", "type": "电影", "genre": "战争 / 剧情", "tags": ["二战， 反思， 小人物， 人性， 黑白"], "summary_short": "赫尔曼，2018年德国电影，战争 / 剧情。赫尔曼是二战时期一座小型集中营的清洁工，他的智商只有65，但有着惊人的模仿天赋。党卫军军官汉斯发现他模仿希特勒的声音和动作惟妙惟肖，便经常强迫他在宴会上表演，以此取乐。赫尔曼不明白政治，只知道每次表演后可以得到一块面包。他把面包偷偷塞给铁丝网外的犹太女孩米莉亚姆。一天夜里，盟军逼近，汉斯下令屠杀所有囚犯后撤退。赫尔曼趁乱溜进广播室，用模仿元首的声音通知“所有党卫军立即向北撤离，不得伤害任何囚犯", "score": 2018239, "category": "drama", "detail_url": "../movie/0433.html", "poster": "../posters/0433.svg"}, {"id": "0434", "title": "碧血长空争霸战", "year": 2026, "region": "美国", "type": "电影", "genre": "动作, 战争, 历史", "tags": ["二战", "飞行员", "空中激战", "兄弟连", "真实改编"], "summary_short": "碧血长空争霸战，2026年美国电影，动作, 战争, 历史。1942年，太平洋战场。美军一支由问题飞行员组成的VF-19中队，被分配了最老旧的“野猫”战斗机，任务是护送航母“黄蜂号”。上级对他们不抱希望，队长巴恩斯是酒鬼，手下有胆小鬼、独行侠和一个17岁谎报年龄的少年。日军联合舰队发动总攻，王牌零式战机铺天盖地。VF-19被迫以1:5的劣势迎战。三天三夜，他们弹药耗尽后用撞击战术，少年跳伞后在空中用手枪射击敌机座舱。最终航母得救，全队仅2", "score": 2026336, "category": "doc", "detail_url": "../movie/0434.html", "poster": "../posters/0434.svg"}, {"id": "0435", "title": "法兰兄弟", "year": 2024, "region": "法国", "type": "剧集", "genre": "剧情 / 兄弟 / 犯罪", "tags": ["家族恩怨", "法式冷峻", "背叛与忠诚", "高颜值"], "summary_short": "法兰兄弟，2024年法国剧集，剧情 / 兄弟 / 犯罪。1990年代，马赛。年幼的卢克和伊万目睹父亲被黑帮杀害，随后被不同的家庭收养，彻底断了联系。二十年后，卢克成为巴黎缉毒局最正直的警长，发誓要将毒品赶出社区。而伊万，为了生存早已成为科西嘉黑手党在欧洲的毒品分销头目，代号“法兰先生”。一起震惊欧洲的巨型可卡因走私案，让兄弟俩的命运再次交织。卢克追踪的线索，每一步都指向那个代号“法兰先生”的神秘人；而伊万为了洗白身份、保护怀孕的妻子，正", "score": 2024331, "category": "series", "detail_url": "../movie/0435.html", "poster": "../posters/0435.svg"}, {"id": "0436", "title": "遇见馆藏·太空季", "year": 2022, "region": "中国", "type": "综艺", "genre": "文博探索", "tags": ["航天， 博物馆， 跨界， 沉浸式"], "summary_short": "遇见馆藏·太空季，2022年中国综艺，文博探索。这是一档将国家博物馆馆藏文物与航空航天科技相结合的沉浸式综艺。每期嘉宾包括一名航天工程师、一名天文历史学者和一位明星体验官。他们需要根据一件文物（如汉代星云纹镜、唐代敦煌星图、宋代水运仪象台复制件）找出其中隐藏的天文密码，然后用现代航天技术（望远镜观测、卫星遥感甚至模拟发射）来验证古人的观测是否准确。最后一期，节目组将一枚写有所有参与观众姓名的存储芯片，随商业火箭送入近地轨道，实现“让今天", "score": 2022127, "category": "series", "detail_url": "../movie/0436.html", "poster": "../posters/0436.svg"}, {"id": "0437", "title": "安内蒙尼", "year": 2005, "region": "欧洲", "type": "电影", "genre": "悬疑， 奇幻", "tags": ["记忆， 深海， 花语， 迷失， 宿命"], "summary_short": "安内蒙尼，2005年欧洲电影，悬疑， 奇幻。女主角在海边小诊所醒来，不记得自己是谁。护士说她是“安内蒙尼”，一个因车祸失忆的游客。奇怪的是，镇上每个人对她的描述都不一样：有人说她是画家，有人说她是失踪五年的教师。她开始做同一个梦——深海里有无数透明触手在发光。当她找到日记本，发现里面只重复写着一句话：“别相信任何关于我的故事。” 最后心理医生坦白：根本没有“安内蒙尼”，这是一场治疗多重人格的极端实验，而她的本体人格早已溺亡。", "score": 2005405, "category": "crime", "detail_url": "../movie/0437.html", "poster": "../posters/0437.svg"}, {"id": "0438", "title": "融之堂", "year": 2025, "region": "英国", "type": "剧集", "genre": "历史，爱情，剧情", "tags": ["维多利亚时代，禁忌之恋，背叛，大尺度"], "summary_short": "融之堂，2025年英国剧集，历史，爱情，剧情。维多利亚时代的伦敦，表面繁荣而保守。贵族少妇艾琳娜嫁给了年迈的男爵，生活如同死水。男爵为了拓展生意，引入了年轻而充满活力的合伙人托马斯。托马斯来自美国，带着新世界的粗犷与自由。在一次乡间庄园的聚会上，艾琳娜与托马斯因一场大雨被困于音乐室，两人在钢琴旁发生了禁忌之吻。此后，他们开始了一段秘密恋情，在“融之堂”（家中温室）频繁私会。然而，家中的仆人、嫉妒的亲戚以及托马斯的旧情人都开始察觉端倪。当", "score": 2025337, "category": "series", "detail_url": "../movie/0438.html", "poster": "../posters/0438.svg"}, {"id": "0439", "title": "我的爷爷", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["祖孙情", "抗战老兵", "记忆修复", "代际和解"], "summary_short": "我的爷爷，2024年中国大陆电影，剧情 / 家庭。程序员孙子孟响一直嫌弃爷爷老孟又倔又土，拒绝相亲、拒绝智能手机，只会蹲在老屋门口发呆。直到老孟确诊阿尔茨海默病晚期，某天深夜突然用流利的日语哭喊：“731，求你们别带走我姐姐！”全家震惊——老孟是山东农民，从未出国。孟响开始翻找老屋，发现地窖里藏着一本用日文、中文、俄文混杂写的日记。原来，老孟十五岁时被强征为日军劳工，后又被苏联红军收留做翻译，辗转三国，最终带着一具不是自己亲姐姐的骨灰回", "score": 2024329, "category": "drama", "detail_url": "../movie/0439.html", "poster": "../posters/0439.svg"}, {"id": "0440", "title": "间谍兔洞第一季", "year": 2027, "region": "美国", "type": "剧集", "genre": "惊悚， 谍战", "tags": ["间谍， 阴谋论， 高智商， 反转"], "summary_short": "间谍兔洞第一季，2027年美国剧集，惊悚， 谍战。杰克·霍夫曼是商业间谍界的传奇，擅长用超高难度的骗术窃取核心机密。在一次针对军火商的行动中，他的整个团队被团灭，只有他幸存，并背上了叛国和谋杀的黑锅。FBI、CIA和黑帮三方同时对他展开追缉。杰克被迫启用紧急方案，躲入他自己创建的一个名为“兔子洞”的暗网庇护所。在那里，他结识了一帮同样被世界遗忘的顶级黑客和骗子。他们发现，陷害杰克的幕后黑手正在策划一起足以颠覆全球经济的网络攻击。杰克必须", "score": 2027273, "category": "series", "detail_url": "../movie/0440.html", "poster": "../posters/0440.svg"}, {"id": "0441", "title": "傻瓜", "year": 2024, "region": "韩国", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["智力障碍", "小镇", "诈骗", "反转"], "summary_short": "傻瓜，2024年韩国电影，剧情 / 喜剧。东九是小镇上的“傻子”，每天坐在便利店门口帮人递东西换烟抽。一天，首尔律师带着遗嘱来，说他是某富豪的私生子，可继承3亿韩元。全镇沸腾，有人巴结、有人想骗、有人替他高兴。东九只说：“我只想要那包烟。”后来律师卷款跑路，原来全是一场骗局。但东九掏出一张存折：这十年他捡瓶子攒了四百万，对老太太说：“给你，买药。”", "score": 2024328, "category": "drama", "detail_url": "../movie/0441.html", "poster": "../posters/0441.svg"}, {"id": "0442", "title": "杀死两个恋人", "year": 2025, "region": "美国", "type": "电影", "genre": "剧情， 爱情， 惊悚", "tags": ["婚姻危机， 极端手段， 公路追杀"], "summary_short": "杀死两个恋人，2025年美国电影，剧情， 爱情， 惊悚。结婚七年的戴维和安娜在签署离婚协议前，决定最后去一次蜜月时的公路旅行，算作告别。途中遭遇严重车祸，两人被送医后双双失忆。醒来后，他们在各自的病房里发现了一张纸条，上面写着同一句话：“对方是杀害你全家的凶手，你必须先下手。”戴维和安娜都相信了纸条的信息，开始了在陌生环境中的互相猎杀。医院的走廊、加油站、汽车旅馆，两个人不断设局试图杀死对方，却又不断在接近死亡时产生一种奇怪的熟悉感。当", "score": 2025401, "category": "romance", "detail_url": "../movie/0442.html", "poster": "../posters/0442.svg"}, {"id": "0443", "title": "吾妻之话", "year": 2025, "region": "韩国", "type": "电影", "genre": "悬疑 / 爱情", "tags": ["婚姻", "心理惊悚", "反转", "日记体", "女性视角"], "summary_short": "吾妻之话，2025年韩国电影，悬疑 / 爱情。结婚十年的家庭主妇林秀珍，在丈夫因车祸去世后，整理书房时发现了一部未发表的小说手稿，署名是丈夫。小说名为《吾妻之话》，男主角名叫“俊浩”，职业、性格、与妻子相处的细节，都与现实中的他们一模一样。但女主角却不是秀珍，而是一个叫“素拉”的虚拟女人。小说里，“俊浩”每天写日记记录对“素拉”的爱意，而“妻子”只是一个面目模糊的背景板。秀珍一边读一边崩溃，她以为丈夫深爱自己，原来他只是把她当成一个“合", "score": 2025415, "category": "romance", "detail_url": "../movie/0443.html", "poster": "../posters/0443.svg"}, {"id": "0444", "title": "离去的女人", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情, 文艺", "tags": ["女性", "生命倒计时", "公路", "和解"], "summary_short": "离去的女人，2023年法国电影，剧情, 文艺。七十岁的知名作家艾琳娜被诊断出绝症。她没告诉任何人，默默处理掉房产和藏书，开着一辆老旧沃尔沃上路。目的地是法国南部一个小镇，那里住着她二十岁时被迫送人的女儿。途中她搭载了一个离家出走的少女，两人形成奇异的祖孙关系。少女偷走了她的钱，却又在半路等她。最终找到女儿时，对方已是三个孩子的母亲，并拒绝相认。艾琳娜没有亮明身份，只是在对面咖啡馆坐了一整天，然后继续上路。她在海边停下了车，打开所有车窗，", "score": 2023326, "category": "drama", "detail_url": "../movie/0444.html", "poster": "../posters/0444.svg"}, {"id": "0445", "title": "金牌贱猫：重新出击", "year": 2019, "region": "英国", "type": "电影", "genre": "喜剧, 动作, 犯罪", "tags": ["特工", "恶搞", "退休生活", "英式幽默"], "summary_short": "金牌贱猫：重新出击，2019年英国电影，喜剧, 动作, 犯罪。代号“贱猫”的传奇特工威利斯退休后在养老院过着郁郁不得志的生活。一天，一伙愚蠢的黑帮误将他存放假牙和旧照片的破旧保险箱当作价值连城的宝物偷走。为了拿回亡妻唯一照片，威利斯穿上十年没洗的西装，联手养老院的老伙计们——患有帕金森的神枪手和坐着电动轮椅的飙车王，一同追击黑帮。过程中，他们意外卷入了一场涉及军火交易的国际阴谋。黑帮发现被一群老人追得团团转，狼狈不堪。最终决战在废弃的游", "score": 2019410, "category": "crime", "detail_url": "../movie/0445.html", "poster": "../posters/0445.svg"}, {"id": "0446", "title": "初代吸血鬼第二季", "year": 2014, "region": "美国", "type": "电视剧", "genre": "奇幻, 惊悚, 剧情", "tags": ["吸血鬼", "家族", "权力", "超自然"], "summary_short": "初代吸血鬼第二季，2014年美国电视剧，奇幻, 惊悚, 剧情。第二季开篇，以利亚为保护家人而中了古老女巫团“失魂咒”，记忆全失，流浪在法国街头成了一名画家。与此同时，始祖猎人大军得到圣斧，专杀初代吸血鬼。克劳斯既要躲避猎人，又要找回哥哥，无奈之下只能与曾被他杀害全家的女巫达维娜合作。达维娜的条件是：复活她的男友。克劳斯一面假装答应，一面对以利亚进行“记忆冲击疗法”——将他最痛苦的时刻（被迫杀死生父、爱人塞莱斯特之死）画成油画寄给他。碎片", "score": 2014356, "category": "series", "detail_url": "../movie/0446.html", "poster": "../posters/0446.svg"}, {"id": "0447", "title": "完美妻子的完美复仇计划", "year": 2023, "region": "韩国", "type": "剧集", "genre": "剧情 / 悬疑 / 爱情", "tags": ["复仇， 高智商， 婚姻危机， 反转"], "summary_short": "完美妻子的完美复仇计划，2023年韩国剧集，剧情 / 悬疑 / 爱情。全职主妇林秀雅在外人眼中拥有完美家庭：事业有成的丈夫、乖巧的女儿、豪华公寓。但她用了七年时间，秘密记录丈夫的婚外情、商业欺诈，甚至是那场被伪装成意外的“前女友死亡案”。她的计划不是离婚分财产，而是一场精心编排的公开审判。在结婚十周年派对上，她当着所有亲友和媒体的面，一步步引导丈夫亲口说出真相。但故事并未结束——当丈夫入狱后，她才发现自己也是这场棋局中的一枚棋子，真正的", "score": 2023358, "category": "series", "detail_url": "../movie/0447.html", "poster": "../posters/0447.svg"}, {"id": "0448", "title": "南国春宵", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "情色， 剧情", "tags": ["伴游， 高雄， 欲望， 城市漫游， 孤独"], "summary_short": "南国春宵，2024年中国台湾电影，情色， 剧情。失婚又失业的阿南，在高雄的港口边准备结束生命。他遇到了从事特殊行业的女孩春宵。阿南用最后的积蓄买下春宵一晚，不是为性，而是希望她能陪自己“走完最后一程”。春宵答应了他，但条件是这一晚要听她的。他们从肮脏的旅店走到繁华的夜市，从废弃的戏院走到寂静的海边。春宵给他讲每个客人的故事，阿南给她看女儿的照片。天快亮时，春宵将他带到母亲的坟前，告诉他：“活下去比死更需要勇气。”天亮后，阿南扔掉了安眠药", "score": 2024317, "category": "drama", "detail_url": "../movie/0448.html", "poster": "../posters/0448.svg"}, {"id": "0449", "title": "拜托了老师", "year": 2019, "region": "日本", "type": "剧集", "genre": "剧情, 校园, 社会", "tags": ["师生恋", "禁忌", "道德困境", "反转"], "summary_short": "拜托了老师，2019年日本剧集，剧情, 校园, 社会。高中教师浅野是全校公认的“完美先生”，教学优异，待人和善。直到一封匿名举报信被寄到教育局，曝光他与女学生杉田的“不伦恋情”。一时间，舆论沸腾，浅野被停职，网络暴力涌入他的生活。杉田在家人的压力下出具了“被诱导”的证词，浅野百口莫辩。就在所有人以为事件尘埃落定时，一位名不见经传的周刊记者发现了疑点。他深入调查后，揭开了令人震惊的真相：杉田长期遭受继父的性侵，她不敢反抗，便用手机拍下过程", "score": 2019211, "category": "series", "detail_url": "../movie/0449.html", "poster": "../posters/0449.svg"}, {"id": "0450", "title": "小美人鱼2：重返大海", "year": 2026, "region": "美国", "type": "电影", "genre": "动画, 奇幻, 冒险, 家庭", "tags": ["迪士尼", "续集", "反叛", "海洋环保", "女性成长"], "summary_short": "小美人鱼2：重返大海，2026年美国电影，动画, 奇幻, 冒险, 家庭。自从嫁给埃里克王子，爱丽儿已经整整十年没有回到大海。她学会了用刀叉，穿上了束腰裙，每天面对繁琐的宫廷礼仪和丈夫日益膨胀的航海野心。她生下的小公主梅洛迪，却天生能在水下呼吸。当爱丽儿试图带女儿去海边时，她突然浑身剧痛，长出鳞片，随即昏迷。海底的巫师告诉她：当年她为了变成人类，放弃了声音；现在，大海在“索要”更珍贵的东西——她的记忆。如果她再次踏入大海，她将彻底忘记埃里", "score": 2026298, "category": "fantasy", "detail_url": "../movie/0450.html", "poster": "../posters/0450.svg"}, {"id": "0451", "title": "贾斯珀·琼斯", "year": 2024, "region": "澳大利亚", "type": "电影", "genre": "剧情 / 悬疑 / 青春", "tags": ["小镇", "秘密", "种族", "文学改编"], "summary_short": "贾斯珀·琼斯，2024年澳大利亚电影，剧情 / 悬疑 / 青春。改编自克雷格·西尔维的畅销小说。14岁的查理痴迷于写作和逃避现实。一晚，被称为“全镇祸害”的贾斯珀·琼斯浑身是血闯入他的房间，请求查理帮他证明一桩“并非谋杀”的自杀案。查理发现死者是贾斯珀的白人父亲，镇上警长早已认定凶手是贾斯珀。两人必须在保守且充满种族歧视的小镇里，寻找父亲生前留下的录音带证据。在追查中，查理发现了贾斯珀隐藏的巨大图书馆和他惊人的智商。最终，证据证明父亲因", "score": 2024313, "category": "drama", "detail_url": "../movie/0451.html", "poster": "../posters/0451.svg"}, {"id": "0452", "title": "顽美追男仔", "year": 2002, "region": "中国台湾", "type": "电影", "genre": "喜剧， 爱情", "tags": ["青春偶像， 校园， 女追男， 欢喜冤家"], "summary_short": "顽美追男仔，2002年中国台湾电影，喜剧， 爱情。高中女生宋巧丽是学校体育队的王牌，性格火爆，人称“霸王花”。她在一个偶然的机会看到了转学生、天才学霸江直树的微笑，瞬间被击中。不顾闺蜜的劝阻，她立下 flag：一个月内追到江直树！然而，江直树眼里只有课本和实验，对宋巧丽的大胆示爱完全免疫，甚至用物理公式计算她告白失败的概率。宋巧丽屡败屡战，偷情书、假偶遇、英雄救美，闹出一连串笑话。在“追男”的过程中，她意外发现自己和江直树在童年有过一段", "score": 2002359, "category": "comedy", "detail_url": "../movie/0452.html", "poster": "../posters/0452.svg"}, {"id": "0453", "title": "夺命剑之喋血江湖", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动作 / 武侠", "tags": ["悬疑", "剑客", "密室杀人", "反转"], "summary_short": "夺命剑之喋血江湖，2024年中国大陆电影，动作 / 武侠。二十年前，武林至尊“夺命剑”门派在一夜之间覆灭，唯一幸存者带走了至高剑谱。二十年后，江湖上身份各异的六位顶尖剑客，同时收到神秘请柬，被引至荒野中的“有间客栈”。一场暴雨困住了所有人。客栈老板宣布，六人中混入了当年灭门的凶手，若不找出，大家皆会中毒身亡。随之，信任瓦解，猜忌丛生，每个人似乎都隐藏着不可告人的秘密。他们被迫轮流对决，每一次拔剑，都离真相更近一步，也离死亡更近一步。最锋", "score": 2024317, "category": "crime", "detail_url": "../movie/0453.html", "poster": "../posters/0453.svg"}, {"id": "0454", "title": "无敌特务之雷朋三世", "year": 2024, "region": "日本", "type": "剧集", "genre": "动作, 犯罪, 冒险", "tags": ["怪盗", "跨国", "高科技"], "summary_short": "无敌特务之雷朋三世，2024年日本剧集，动作, 犯罪, 冒险。怪盗雷朋三世这次盯上了科技巨头“圆”公司开发的“预言芯片”——它能在0.1秒内推算未来1分钟的所有可能。然而就在得手之际，一名自称来自2077年的女警安娜穿越而来，声称这颗芯片将导致人类灭绝。两人被迫联手，一边躲避国际刑警和圆公司的追杀，一边寻找芯片真正的创造者。雷朋发现，创造者竟是自己已故的祖父——而安娜正是他的玄孙女。", "score": 2024305, "category": "series", "detail_url": "../movie/0454.html", "poster": "../posters/0454.svg"}, {"id": "0455", "title": "善地第二季", "year": 2017, "region": "美国", "type": "剧集", "genre": "喜剧、奇幻、哲学", "tags": ["道德哲学", "反套路", "搞笑声效", "地狱笑话"], "summary_short": "善地第二季，2017年美国剧集，喜剧、奇幻、哲学。第二季中，埃莉诺等人识破了迈克尔的设计，成功逃回人间。但重启后的世界变得古怪：人类做好事或坏事都会收到实时分数推送，整个社会沦为“道德表演秀”。迈克尔为了保住“宇宙建筑师”的身份，亲自下凡追捕他们。主角团被迫一边躲避追捕，一边学习真正的伦理学（康德、亚里士多德、萨特）来逆天改命。结尾，真正的“善地委员会”发来审判通知。", "score": 2017332, "category": "series", "detail_url": "../movie/0455.html", "poster": "../posters/0455.svg"}, {"id": "0456", "title": "大话武林", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 武侠", "tags": ["恶搞，穿越，武馆，无厘头"], "summary_short": "大话武林，2022年中国大陆电影，喜剧 / 武侠。现代跆拳道馆教练陈飞在一次表演赛中触电，醒来发现自己身处南宋临安城，还被当成“金国细作”押上了比武台。对手是号称“江南铁腿”的武林高手，结果陈飞一脚侧踢把人踹出擂台。从此，他被逼着开馆收徒，却把武馆搞成了健身私教课——教轻功不如教折返跑，教内功不如教平板支撑。他还在武林大会上引入积分淘汰制、禁止击打后脑、设立体重分级，气得各大门派掌门集体退赛。最后魔教来袭，所有人都以为要靠武功，结果陈飞", "score": 2022336, "category": "comedy", "detail_url": "../movie/0456.html", "poster": "../posters/0456.svg"}, {"id": "0457", "title": "沙哈达", "year": 2022, "region": "德国 / 法国", "type": "电影", "genre": "剧情 / 犯罪 / 社会", "tags": ["难民", "德国", "校园霸凌", "法律困境", "道德抉择"], "summary_short": "沙哈达，2022年德国 / 法国电影，剧情 / 犯罪 / 社会。16 岁的阿富汗难民萨米在德国小城生活了三年，终于融入学校。但校内一个白人学生团伙长期霸凌他，理由仅仅是“他是难民”。一次霸凌升级，萨米在反抗中失手将对方推下楼梯致死。所有人都以为萨米会被遣返甚至判重刑。但令人震惊的事发生了：他的德语老师、校长、甚至受害者的女友，联合为他编造了一个故事——这不是意外，而是“荣誉谋杀”，是萨米的哥哥为维护家族名誉杀死了那个白人学生。他们用这个", "score": 2022365, "category": "drama", "detail_url": "../movie/0457.html", "poster": "../posters/0457.svg"}, {"id": "0458", "title": "失孩记", "year": 2028, "region": "澳大利亚", "type": "电影", "genre": "悬疑 / 惊悚 / 剧情", "tags": ["儿童失踪", "小镇秘密", "母亲寻子", "全员恶人", "心理创伤"], "summary_short": "失孩记，2028年澳大利亚电影，悬疑 / 惊悚 / 剧情。单亲妈妈克莱尔带着六岁女儿艾米丽在超市购物，一转身，女儿消失在人海中。警方调查毫无进展，小镇居民态度冷淡。克莱尔自行调查时，发现监控录像被人为删除，目击证人的证词前后矛盾。更诡异的是，她家中所有艾米丽的照片都在慢慢变淡，就像这个孩子从未存在过。心理医生告诉她，艾米丽是她在上一个孩子夭折后幻想出来的人格。但克莱尔在自家花园挖出一只艾米丽的鞋子，鞋子里塞着一张纸条：“妈妈，地下室。”", "score": 2028397, "category": "crime", "detail_url": "../movie/0458.html", "poster": "../posters/0458.svg"}, {"id": "0459", "title": "星级大改造", "year": 2016, "region": "日本", "type": "电影", "genre": "喜剧, 剧情", "tags": ["偶像", "改造", "粉丝", "身份错位"], "summary_short": "星级大改造，2016年日本电影，喜剧, 剧情。在大型商超工作的普通女孩小幸，是国民偶像团体“Wings”队长阿兰的狂热粉丝。在一次慈善拍卖会上，小幸花了所有积蓄拍得“与阿兰共度一天”的机会。然而，这并非浪漫约会，而是阿兰的公司设下的一个局。阿兰虽然舞台形象完美，但私下里却是个生活不能自理、情商极低、让人崩溃的“废柴”。公司希望一位“真正的粉丝”来担任他的私生活顾问，对他进行“改造”。于是，小幸从粉丝变成了“保姆”。她必须教会阿兰自己洗衣", "score": 2016283, "category": "drama", "detail_url": "../movie/0459.html", "poster": "../posters/0459.svg"}, {"id": "0460", "title": "姐妹会大屠杀", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚 / 悬疑", "tags": ["校园", "面具杀手", "密室", "反转"], "summary_short": "姐妹会大屠杀，2025年美国电影，恐怖 / 惊悚 / 悬疑。顶尖大学姐妹会“阿尔法 house”在招新之夜，要求六名候选人在古老别墅内完成“通宵挑战”——每人讲一个关于已故姐妹艾米的恐怖故事。艾米一年前在同样的夜晚坠楼身亡，官方判定自杀。但当第三个故事讲完，灯突然熄灭，一个戴着艾米同款面具的人出现在门口。他/她知道每个人的真名、恐惧和秘密，并宣布：“只有真正的姐妹能活到天亮。”成员一个接一个以当年霸凌艾米的方式死去：泼冷水、关禁闭、头发", "score": 2025514, "category": "horror", "detail_url": "../movie/0460.html", "poster": "../posters/0460.svg"}, {"id": "0461", "title": "乘风而上的她", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情, 运动", "tags": ["帆船", "励志", "女性", "职业"], "summary_short": "乘风而上的她，2025年中国大陆电影，剧情, 运动。阿娇是广西一个渔村的女孩，父亲因出海事故残疾，家里的渔船和房子被债主收走。她偶然得知，在“中国杯”帆船赛中拿到冠军的奖金足以赎回房子。但帆船是烧钱的贵族运动，她一无所有。阿娇凭着一股蛮劲，偷了一艘废弃的破船开始自学。她独特的“风感”被一个曾经失意的退役教练看中，教练决定免费指导她，但要求她必须改掉所有野路子。在训练和预选赛中，阿娇不仅要面对专业对手的嘲讽和暗算，还要克服大海的无常。最终", "score": 2025234, "category": "drama", "detail_url": "../movie/0461.html", "poster": "../posters/0461.svg"}, {"id": "0462", "title": "每天都是暑假", "year": 2023, "region": "日本", "type": "剧集", "genre": "剧情, 奇幻", "tags": ["时间循环", "童年", "治愈", "校园", "夏日"], "summary_short": "每天都是暑假，2023年日本剧集，剧情, 奇幻。开学前一天，小学生小拓、胖达和优香拼命赶暑假作业。突然，整个世界像卡碟一样，时间回到了同一天的清晨。他们经历了无数次“8月31日”：一开始疯狂地玩、吃冰棍、抓独角仙，玩腻了就开始做各种离谱实验（比如从二楼跳下去看疼不疼、对暗恋的人胡乱表白）。慢慢地，三个人开始感到虚无，友谊也出现裂痕。直到第1000次循环，小拓偶然走进了平时不会去的养老院，发现院里一个失忆的老奶奶竟然知道循环的秘密——她曾", "score": 2023254, "category": "series", "detail_url": "../movie/0462.html", "poster": "../posters/0462.svg"}, {"id": "0463", "title": "计中计", "year": 2006, "region": "美国", "type": "电影", "genre": "悬疑，犯罪", "tags": ["高智商，骗局，罗生门，反转，黑色电影"], "summary_short": "计中计，2006年美国电影，悬疑，犯罪。保险调查员杰克受命调查一颗价值连城的钻石失窃案。嫌疑人指向花花公子富商、落魄女星以及一名魔术师。随着调查深入，每个人都向杰克提供了“真相”，每一个版本的故事都逻辑自洽，却互相矛盾。杰克发现自己陷入了一个巨大的迷宫：富商想骗取保金，女星想报复负心汉，魔术师想获得名声。更离奇的是，杰克的助手也在暗中倒卖情报。当杰克以为揪出真凶时，他的上司突然现身，告诉他这其实是一场为了测试他忠诚度的内部演习，但钻石真", "score": 2006445, "category": "crime", "detail_url": "../movie/0463.html", "poster": "../posters/0463.svg"}, {"id": "0464", "title": "茀兰德", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "科幻 / 悬疑", "tags": ["意识转移", "克隆人伦理", "记忆迷宫"], "summary_short": "茀兰德，2026年中国大陆电影，科幻 / 悬疑。天才科学家林深发明了“茀兰德”技术，能将人的意识备份储存。在一次意外后，他醒来发现妻子和女儿对他异常陌生。家中遍布的线索指向一个可怕的可能：真正的自己可能已被囚禁在虚拟空间，而身边的“家人”全是接受了伪造记忆的克隆体。随着调查深入，林深发现这项技术的幕后推手竟是自己失踪多年的父亲。父亲试图用“茀兰德”创造永生，却导致意识世界的崩坏。林深必须在记忆彻底混淆前，找到真实的自我并摧毁整个系统，但", "score": 2026410, "category": "sci-fi", "detail_url": "../movie/0464.html", "poster": "../posters/0464.svg"}, {"id": "0465", "title": "两女一男", "year": 2014, "region": "法国", "type": "电影", "genre": "剧情 / 爱情 / 伦理", "tags": ["三角关系", "巴黎", "情感博弈", "开放式关系"], "summary_short": "两女一男，2014年法国电影，剧情 / 爱情 / 伦理。巴黎演员安娜和纪录片导演马克同居五年，感情趋于平淡。某夜，马克带回了一位自称“迷路”的美国游客克莱尔。安娜出于好奇和一丝挑衅，邀请克莱尔暂住。起初，克莱尔像一个调皮的闯入者，用异国的视角打破了两人沉默的晚餐、冷淡的性爱。安娜发现自己被克莱尔吸引，而马克则在这种微妙的竞争中重新“看见”了安娜。三人形成了一种危险的平衡：每两个人之间都有秘密，每一次单独对话都是博弈。当克莱尔提出“三人一", "score": 2014353, "category": "drama", "detail_url": "../movie/0465.html", "poster": "../posters/0465.svg"}, {"id": "0466", "title": "面具1985", "year": 1985, "region": "中国香港", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["复古", "都市传说", "砍杀片", "邪典"], "summary_short": "面具1985，1985年中国香港电影，恐怖, 惊悚。京剧戏班“荣庆社”在翻修老宅时，挖出了一个精致的翠绿面具。当家花旦阿玉为了演好贵妃醉酒，戴上面具找感觉，却从此性情大变。每到午夜，她会画上浓妆，穿着戏服，将戏班里的仇人一个个用唱戏的翎子刺死。班主请来道士做法，却发现面具里封存的不是贵妃的怨灵，而是当年被戏班活活烧死的戏子的执念。阿玉在清醒与疯狂之间挣扎，最终在戏台上，用一场真正的“贵妃醉酒”与恶灵同归于尽。", "score": 1985431, "category": "horror", "detail_url": "../movie/0466.html", "poster": "../posters/0466.svg"}, {"id": "0467", "title": "围城（电影）", "year": 2025, "region": "中国内地", "type": "电影", "genre": "剧情/战争", "tags": ["二战", "上海", "犹太难民", "人性"], "summary_short": "围城（电影），2025年中国内地电影，剧情/战争。1943年，日军在上海虹口设立“无国籍难民限定地区”。中国寡妇阿珍把阁楼租给了逃难的犹太医生弗里茨。语言不通、习俗不同，两人从互相嫌弃到在日军搜查中互相掩护。随着围城收紧，食物短缺，阿珍为了保护弗里茨藏起的一本医学手稿，不惜假意告发，实则引开日军。当弗里茨以为被背叛时，阿珍浑身是血地出现在地窖口。影片再现了那段鲜为人知的上海庇护史，展现了乱世中小人物的人性光辉。", "score": 2025322, "category": "drama", "detail_url": "../movie/0467.html", "poster": "../posters/0467.svg"}, {"id": "0468", "title": "妖精弗洛伦斯", "year": 2026, "region": "英国", "type": "电影", "genre": "奇幻 / 家庭 / 冒险", "tags": ["治愈系", "环保主题", "森林冒险"], "summary_short": "妖精弗洛伦斯，2026年英国电影，奇幻 / 家庭 / 冒险。敏感内向的小女孩露西搬家到郊区，在学校被霸凌，只有在祖母留下的废弃花园里才能感到平静。一天夜里，她看到一朵发光的蘑菇下，坐着一个只有拇指高的、灰扑扑的妖精弗洛伦斯。弗洛伦斯是这片土地上最后的妖精，因为环境污染和人们的“不信”，她正在逐渐消失。为了阻止即将到来的商业开发，露西必须在弗洛伦斯的指导下，重新在社区里种下“相信”的种子——每一个相信妖精存在的孩子，都能给弗洛伦斯一天的寿", "score": 2026319, "category": "fantasy", "detail_url": "../movie/0468.html", "poster": "../posters/0468.svg"}, {"id": "0469", "title": "纳粹追凶", "year": 2025, "region": "美国", "type": "电影", "genre": "惊悚/悬疑/犯罪", "tags": ["心理博弈", "历史伤痕", "猫鼠游戏", "原著改编"], "summary_short": "纳粹追凶，2025年美国电影，惊悚/悬疑/犯罪。十六岁的学霸托德沉迷于二战历史。一次偶然，他通过旧照片发现邻居亚瑟其实就是臭名昭著的纳粹集中营狱长。托德没有报警，而是选择上门勒索，要求亚瑟讲述当年的暴行以满足自己的阴暗猎奇心理。起初亚瑟表现得很顺从，但渐渐地，托德发现自己正在被这个老狐狸驯化，他开始模仿纳粹的行为，甚至险些杀害同学。当托德想要终止这场游戏时，却发现自己早已深陷泥潭，而亚瑟正拿着他的把柄，露出了真正的獠牙。", "score": 2025470, "category": "crime", "detail_url": "../movie/0469.html", "poster": "../posters/0469.svg"}, {"id": "0470", "title": "家有一宝", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "家庭喜剧", "tags": ["老年创业", "代际冲突", "爆笑温情"], "summary_short": "家有一宝，2024年中国大陆电影，家庭喜剧。退休会计老钱是个正义感过剩的老头，屡次举报小区诈骗讲座被儿子视为“惹事精”。儿子小钱攒了五年钱，终于凑够200万打算和女友买房，却发现父亲偷偷把钱投给了一个叫“夕阳红科技”的项目，做了一款功能极其简陋、图标像小学作业的防诈骗APP。更惨的是，外包公司卷款跑路，APP只在应用商店收获了两个好评（老钱自己写的）。小钱崩溃要断绝关系，老钱却倔强地骑上电动车，挨个小区教老年人使用反诈功能。没想到，AP", "score": 2024303, "category": "comedy", "detail_url": "../movie/0470.html", "poster": "../posters/0470.svg"}, {"id": "0471", "title": "美国第一欢乐家庭", "year": 2023, "region": "美国", "type": "剧集", "genre": "喜剧, 家庭", "tags": ["家庭喜剧", "搞笑", "温馨", "多代同堂"], "summary_short": "美国第一欢乐家庭，2023年美国剧集，喜剧, 家庭。思想前卫、粉丝千万的网红奶奶埃德娜因房子被拆，不得不搬到思想极其保守的儿子鲍勃家中。鲍勃是个严格遵循传统作息表的银行经理，他的家里住着正在经历身份危机的青春期女儿、沉迷二次元的宅男儿子、以及刚刚退休想环游世界的妻子。埃德娜的到来彻底打破了家里的平静。她教孙女如何在网上反击霸凌，帮孙子策划漫展求婚，甚至鼓动儿媳偷偷去学开飞机。鲍勃试图维持秩序，却一次次被母亲的“骚操作”搞得焦头烂额。在一", "score": 2023231, "category": "series", "detail_url": "../movie/0471.html", "poster": "../posters/0471.svg"}, {"id": "0472", "title": "反击第四季", "year": 2025, "region": "英国 / 美国", "type": "剧集", "genre": "动作 / 战争 / 悬疑", "tags": ["特种作战", "硬汉", "全球反恐", "背叛"], "summary_short": "反击第四季，2025年英国 / 美国剧集，动作 / 战争 / 悬疑。沉寂两年后，前“20号分部”成员波特和斯通布里奇因为老队长麦克的离奇死亡再度聚首。线索指向一个名为“幽灵安保”的私人军事公司，他们在中东、东欧和南美策划了多起看似毫无关联的恐袭事件。为了给麦克复仇，两人组建了一支新队伍，包括一名黑客和一名前特种兵女护士。在追查过程中，他们发现“幽灵安保”使用的技术远超民间水平，其最终目标是利用战争混乱在伦敦股市做空牟利。当波特终于揪出幕", "score": 2025341, "category": "series", "detail_url": "../movie/0472.html", "poster": "../posters/0472.svg"}, {"id": "0473", "title": "艾拉妮丝", "year": 2024, "region": "法国", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["女性", "身份认同", "心理惊悚"], "summary_short": "艾拉妮丝，2024年法国电影，剧情 / 悬疑。艾拉妮丝是一位优雅而神秘的女人，她以心理咨询师的身份进入一个显赫的家族，为患有创伤后应激障碍的少爷进行治疗。然而，她的真实目的远不止于此——她似乎对家族中二十年前一桩离奇失踪案了如指掌。随着催眠治疗的深入，少爷开始回忆起被压抑的童年片段，指向家族企业的血腥发家史。艾拉妮丝逐渐接近真相核心，但她发现自己也陷入了情感与复仇的漩涡。最终，镜子前的两个灵魂必须面对同一个问题：你是谁，以及你愿意为真相", "score": 2024398, "category": "crime", "detail_url": "../movie/0473.html", "poster": "../posters/0473.svg"}, {"id": "0474", "title": "世纪编舞大师", "year": 2024, "region": "法国", "type": "电影", "genre": "传记 / 音乐 / 剧情", "tags": ["舞蹈", "艺术", "冷战", "天才", "晚年"], "summary_short": "世纪编舞大师，2024年法国电影，传记 / 音乐 / 剧情。1989 年柏林墙倒塌前夕，八十岁的传奇编舞大师莱纳德·沃罗诺夫隐居在瑞士湖畔，世人只知道他开创了新古典芭蕾流派，却不知道他原名列昂尼德·沃罗诺夫，是苏联基洛夫芭蕾舞团出走的叛逃者。一位年轻的纪录片导演获得独家跟拍权，试图记录他创作“最后一部舞剧”的过程。然而莱纳德排演的动作越来越奇怪，舞者时而像被线牵引的木偶，时而像逃命的难民。导演发现，莱纳德的每一部传世作品都在隐晦地标记时", "score": 2024299, "category": "doc", "detail_url": "../movie/0474.html", "poster": "../posters/0474.svg"}, {"id": "0475", "title": "魔界王子", "year": 2024, "region": "日本", "type": "动画", "genre": "奇幻冒险", "tags": ["异世界，魔法，兄弟情，权谋，战斗"], "summary_short": "魔界王子，2024年日本动画，奇幻冒险。魔王巴尔泽布在千年前的大战中被勇者封印，他的儿子、魔界王子雷恩为了寻找解除封印的方法，伪装成一个毫无魔法天赋的人类少年，潜入了大陆最强的勇者学院。雷恩的魔界力量在人类世界受到压制，他不得不依靠智慧和懦弱的人设来隐藏身份。然而，在一次学院危机中，他被迫动用了魔王之力，不仅拯救了全校，其数据还被学院的预言系统捕捉到，被判定为“千年后摧毁世界的终极魔王”。曾经最受排挤的“废柴”，一夜之间成为全人类追杀的", "score": 2024137, "category": "fantasy", "detail_url": "../movie/0475.html", "poster": "../posters/0475.svg"}, {"id": "0476", "title": "继父", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 家庭 / 犯罪", "tags": ["反转", "家庭暴力", "复仇", "隐藏身份"], "summary_short": "继父，2025年中国大陆电影，悬疑 / 家庭 / 犯罪。单亲妈妈带着 15 岁的女儿晓禾嫁给了完美男人林国栋。林国栋温柔体贴，厨艺精湛，很快就赢得了所有人的喜爱。但晓禾却发现，继父总是半夜在院子里挖坑，而且他对这个城市的废弃下水道了如指掌。在一次翻找中，晓禾看到了一张泛黄的通缉令，上面的人与继父有 90% 相似。当她报警后，警察却发现林国栋有完美的不在场证明。晓禾必须在继父对母亲下手前，弄清他究竟是好人，还是伪装了二十年的猎手。", "score": 2025441, "category": "crime", "detail_url": "../movie/0476.html", "poster": "../posters/0476.svg"}, {"id": "0477", "title": "天浴", "year": 1998, "region": "中国大陆 / 美国", "type": "电影", "genre": "剧情 / 爱情 / 历史", "tags": ["伤痕文学", "悲剧", "人性", "知青", "严歌苓"], "summary_short": "天浴，1998年中国大陆 / 美国电影，剧情 / 爱情 / 历史。文化大革命期间，成都姑娘文秀被选中到川西高原的牧场“学习”。她爱干净、爱唱歌，忍受不了牧场的艰苦生活。场部老金是个沉默的藏族人，默默照顾着她。为了拿到回城指标，文秀开始用自己的身体与场部干部交换。一次次希望破灭后，她变得麻木，从一个干净的女孩变成了任人践踏的“破鞋”。只有老金始终在她身边。当文秀彻底绝望，要求老金结束她的生命时，老金含泪开枪，然后抱着她的尸体走向雪山深处的", "score": 1998290, "category": "drama", "detail_url": "../movie/0477.html", "poster": "../posters/0477.svg"}, {"id": "0478", "title": "英雄联盟：双城之战第一季", "year": 2024, "region": "美国 / 法国", "type": "剧集", "genre": "动画 / 动作 / 科幻", "tags": ["游戏改编， 蒸汽朋克， 姐妹反目， 阶级对抗"], "summary_short": "英雄联盟：双城之战第一季，2024年美国 / 法国剧集，动画 / 动作 / 科幻。改编自现象级游戏，但故事完全独立。上城皮尔特沃夫发明了能无限进化的“海克斯晶核”，而下城祖安则被剧毒废气笼罩，居民平均寿命不到四十岁。蔚和金克丝是一对在祖安垃圾场长大的孤儿姐妹，金克丝天生拥有超常的机械直觉，能听到“晶核的哭声”。一次偷窃上城实验室的行动中，蔚被警察抓走，金克丝误以为姐姐背叛，被上城科学家收养改造，成了代号“爆裂”的人形武器。六年后，蔚逃出", "score": 2024305, "category": "series", "detail_url": "../movie/0478.html", "poster": "../posters/0478.svg"}, {"id": "0479", "title": "可不可以不毕业", "year": 2023, "region": "中国台湾", "type": "剧集", "genre": "剧情 / 青春 / 校园", "tags": ["延毕", "校园恐惧", "成长痛", "跨代友谊"], "summary_short": "可不可以不毕业，2023年中国台湾剧集，剧情 / 青春 / 校园。阿乐已经读了四年大五，靠各种理由延毕：换专业、缺学分、论文不过。其实真正的原因是他恐惧离开校园，因为他的父亲在毕业前一天车祸去世，他潜意识里认为“毕业等于失去至亲”。学校给了他最后一年期限：本学期修满12学分才能毕业，否则退学。阿乐选了一门以严格出名的老教授林老师的“生命哲学课”。林老师原本已经退休，却主动申请延退五年，只因为舍不得教室的粉笔味道。两人从互相看不顺眼到成为", "score": 2023246, "category": "series", "detail_url": "../movie/0479.html", "poster": "../posters/0479.svg"}, {"id": "0480", "title": "恐惧大街2：1978", "year": 2021, "region": "美国", "type": "电影", "genre": "恐怖, 惊悚, 悬疑", "tags": ["夏令营", "连环杀手", "复古恐怖"], "summary_short": "恐惧大街2：1978，2021年美国电影，恐怖, 惊悚, 悬疑。1978年，荫城夏令营。 counselors Cindy 和 Ziggy 是一对性格迥异的姐妹，Cindy 是乖乖女，Ziggy 则是被排挤的怪胎。夏令营里流传着关于莎拉·菲尔女巫的诅咒，但没人当真。直到夜幕降临，一位戴着骷髅面具的杀手开始屠杀营地里的青少年。Cindy 发现杀手似乎是无法被杀死的超自然存在，而 Ziggy 从当地历史学家那里得知，只有找到莎拉·菲尔的遗骨", "score": 2021501, "category": "crime", "detail_url": "../movie/0480.html", "poster": "../posters/0480.svg"}, {"id": "0481", "title": "叠影惊潮", "year": 2024, "region": "中国香港", "type": "电影", "genre": "惊悚 / 悬疑 / 心理", "tags": ["平行身份", "镜像谋杀", "港式风水", "双胞胎"], "summary_short": "叠影惊潮，2024年中国香港电影，惊悚 / 悬疑 / 心理。广告导演林薇连续一周在铜锣湾十字路口看到“另一个自己”——一模一样的脸、同样的红裙，只是嘴角多了一颗泪痣。对方每晚从玻璃幕墙中走出，第二天就会有一具与她相似的女性尸体出现在附近。警方将她列为嫌疑人。林薇调查发现，自己有一个双胞胎妹妹，出生时就被风水师认为“命冲”，被抱养给南洋富商。妹妹深信“将镜中人杀死，就能取代对方的人生”。林薇被迫学习港式“破镜法”——用铜钱剑和朱砂在镜阵中", "score": 2024414, "category": "crime", "detail_url": "../movie/0481.html", "poster": "../posters/0481.svg"}, {"id": "0482", "title": "男主大甩卖", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 奇幻 / 爱情", "tags": ["反套路", "乙女向", "虚拟男友", "购物狂", "爆笑"], "summary_short": "男主大甩卖，2023年中国大陆电影，喜剧 / 奇幻 / 爱情。深度社恐、母胎单身的程序员林小雨，在购物节冲动下单了一款名为“Mr.Right”的9.9元定制AI男友APP。这款软件号称能根据用户画像生成完美伴侣。林小雨的AI男友“陆沉”温柔、帅气又懂她，两人很快陷入甜蜜的虚拟恋爱。然而一次系统BUG，林小雨意外看到了后台数据——陆沉同时出现在几万个用户的手机里，对所有人说着同样的情话，甚至按点赞数自动切换人设。林小雨决定黑进公司服务器，", "score": 2023393, "category": "romance", "detail_url": "../movie/0482.html", "poster": "../posters/0482.svg"}, {"id": "0483", "title": "回到17岁", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 爱情 / 奇幻", "tags": ["重返青春", "弥补遗憾", "校园", "暖心", "时空穿越"], "summary_short": "回到17岁，2023年中国大陆电影，喜剧 / 爱情 / 奇幻。37岁的平凡中年男子王大志，婚姻破裂、工作被裁，只能在酒醉后怀念当年的校草时光。醒来后，他惊讶地发现自己变回了17岁的模样，以转学生身份回到了当年的高中。他决定利用“先知”优势，展开对当年暗恋的校花秦晓晓的第二次追求，还想教训一下当年欺负他的小混混（也就是未来欺负他的上司）。然而，重回17岁的他发现，校花秦晓晓内心喜欢的其实是当年那个笨拙真诚的穷小子，而不是现在这个油嘴滑舌、", "score": 2023425, "category": "comedy", "detail_url": "../movie/0483.html", "poster": "../posters/0483.svg"}, {"id": "0484", "title": "袋鼠谷", "year": 1998, "region": "澳大利亚 / 英国", "type": "电影", "genre": "纪录片 / 家庭", "tags": ["自然", "动物", "治愈", "风景"], "summary_short": "袋鼠谷，1998年澳大利亚 / 英国电影，纪录片 / 家庭。这是一部极具诗意的自然纪录片。镜头聚焦于澳大利亚新南威尔士州一个隐秘山谷中的东部灰袋鼠群。主线跟随一只名为“跳跃者”的小袋鼠，从它钻出育儿袋的那一刻开始，记录它在干旱、丛林大火和野狗围剿中艰难求生的前两年。影片不仅展示了袋鼠之间复杂的搏斗、繁殖与社交，还捕捉了山谷中针鼹、琴鸟、鸭嘴兽等生物的日常。通过四季的流转，那如明信片般绝美的光影，讲述了生命在这片古老土地上的脆弱与坚韧。结", "score": 1998229, "category": "drama", "detail_url": "../movie/0484.html", "poster": "../posters/0484.svg"}, {"id": "0485", "title": "莫茜", "year": 2024, "region": "美国", "type": "电影", "genre": "爱情、剧情", "tags": ["跨性别、校园、自我认同、初恋"], "summary_short": "莫茜，2024年美国电影，爱情、剧情。莫茜出生时是男孩，从五岁起就知道自己应该是女孩。高三那年她终于以女性身份转学到一所保守小镇的高中，每天承受着霸凌与歧视。篮球队长科尔是校园明星，女友是啦啦队长。一次派对上，科尔看见独自坐在角落的莫茜，她穿着淡蓝色连衣裙，安静地画素描。科尔鬼使神差地走过去——他对这个“有点不同”的女孩心动了。两人偷偷约会，科尔发现自己从未对任何女生有过这种感觉。秘密恋情被科尔女友撞破，她当众撕开莫茜的裙子，大喊“他是", "score": 2024299, "category": "drama", "detail_url": "../movie/0485.html", "poster": "../posters/0485.svg"}, {"id": "0486", "title": "封城之后", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭, 灾难", "tags": ["疫情", "邻里", "温情", "写实"], "summary_short": "封城之后，2024年中国大陆电影，剧情, 家庭, 灾难。2022年，一场突如其来的疫情让繁华都市陷入停摆。影片聚焦于一个普通社区的三个家庭：一个是坚守一线的基层护士与独自在家带娃的丈夫；一个是靠跑货运为生、被困高速无法回家的父亲；还有一个是子女都在国外、不会用手机抢菜的独居老教授。在封城的漫长日子里，物资短缺、就医困难和孤独感时刻考验着他们。护士的家庭濒临崩溃，货车司机在荒野度过生日，老教授差点死于基础病。最终，邻里间通过交换食物、帮忙", "score": 2024311, "category": "drama", "detail_url": "../movie/0486.html", "poster": "../posters/0486.svg"}, {"id": "0487", "title": "皮特·戴维森：我仍在纽约", "year": 2025, "region": "美国", "type": "脱口秀/喜剧特辑", "genre": "喜剧、脱口秀、自传", "tags": ["皮特·戴维森、单口喜剧、纽约、自嘲、情感"], "summary_short": "皮特·戴维森：我仍在纽约，2025年美国脱口秀/喜剧特辑，喜剧、脱口秀、自传。这是皮特·戴维森的第三部Netflix单口特辑。他穿着标志性的破T恤上台，开场白：“我又单身了，你们应该不意外。”他用一小时聊了和前任的尴尬事、狗仔队如何追到他家楼下、他妈妈对他的恋爱观的吐槽。他也坦诚了自己的边缘型人格障碍治疗过程，以及为什么每次想离开纽约，都会被这座城市的某种“混蛋般的温柔”拉回来。最后他说：“纽约就像抑郁症，你不知道今天醒来它会对你做什么", "score": 2025164, "category": "series", "detail_url": "../movie/0487.html", "poster": "../posters/0487.svg"}, {"id": "0488", "title": "笑脸杀人狂", "year": 2023, "region": "美国", "type": "电影", "genre": "惊悚 / 悬疑 / 犯罪", "tags": ["连环杀手，小丑面具，直播杀人，心理博弈，城市传说"], "summary_short": "笑脸杀人狂，2023年美国电影，惊悚 / 悬疑 / 犯罪。都市里出现了一名自称“笑脸”的连环杀手，他每次都戴着诡异的微笑面具，通过网络直播向全世界展示他的“死亡游戏”。受害者被绑架后，必须在限定时间内解开一道与自身秘密有关的谜题，否则就会在镜头前以微笑的方式死去。年轻女警探林薇发现，所有受害者生前都参与过一个神秘的心理实验，而这个实验的主持人正是她失踪多年的导师。为了追查真相，林薇决定伪装成志愿者深入虎穴，却发现自己也渐渐无法控制嘴角的", "score": 2023468, "category": "crime", "detail_url": "../movie/0488.html", "poster": "../posters/0488.svg"}, {"id": "0489", "title": "神探默多克第三季", "year": 2026, "region": "加拿大", "type": "剧集", "genre": "悬疑, 犯罪, 年代", "tags": ["19世纪末", "探案", "科技", "蒸汽朋克"], "summary_short": "神探默多克第三季，2026年加拿大剧集，悬疑, 犯罪, 年代。时间来到1901年，维多利亚女王去世，爱德华时代开启。默多克探长依然坚守在多伦多警局，继续用他那超前于时代的天才头脑破案。第三季中，他将面临一系列更加离奇的案件：一座新落成的剧院里，主演在表演“死亡场景”时真的死了，而凶器竟然是台上的一把道具剑——它被人暗中换成了真正的古董剑，且淬了见血封喉的毒。一起看似普通的火车抢劫案，却牵扯出一桩十年前的盗尸案，墓穴里的尸体不见了，取而代", "score": 2026393, "category": "series", "detail_url": "../movie/0489.html", "poster": "../posters/0489.svg"}, {"id": "0490", "title": "大雄的大魔境", "year": 2014, "region": "日本", "type": "动画电影", "genre": "冒险 / 奇幻 / 科幻", "tags": ["哆啦A梦", "重制版", "狗王国", "秘境探险"], "summary_short": "大雄的大魔境，2014年日本动画电影，冒险 / 奇幻 / 科幻。这是经典剧场版的重制。大雄和哆啦A梦在后山空地发现一只戴着奇怪项圈的流浪狗，它竟然能用人类的语言说“救救我”。他们用任意门追踪到非洲原始森林深处，意外发现一个由高智商犬类统治的地下王国——汪达兰。这里的狗直立行走，拥有高度发达的科技，但被独裁者达布兰达控制，他用“洗脑项圈”将所有反抗者变成只会服从的警卫犬。那只流浪狗其实是王国的正统王子基罗，他被篡位者流放到日本。大雄一行帮", "score": 2014360, "category": "fantasy", "detail_url": "../movie/0490.html", "poster": "../posters/0490.svg"}, {"id": "0491", "title": "灵魂摆渡3", "year": 2016, "region": "中国大陆", "type": "剧集", "genre": "奇幻, 悬疑, 惊悚", "tags": ["灵异", "人性", "公路", "温情"], "summary_short": "灵魂摆渡3，2016年中国大陆剧集，奇幻, 悬疑, 惊悚。赵吏失去了所有记忆，冬青体内的蚩尤即将觉醒，冥界政局动荡。这一季，三人被迫分开。赵吏被流放到荒芜的冥界边境，冬青被神族带走，而王小亚以天女身份回到昆仑。他们各自在绝境中挣扎，却发现所有线索都指向千年前的一场阴谋。赵吏恢复记忆后，决定牺牲自己换取冬青自由。最后一集，冬青抱着昏迷的赵吏走上黄泉路，路边开满红色彼岸花。王小亚以全部寿命为代价，开启轮回之门。他们赢了，但赢的代价是——便利", "score": 2016419, "category": "series", "detail_url": "../movie/0491.html", "poster": "../posters/0491.svg"}, {"id": "0492", "title": "天地宝莲灯", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "奇幻动作", "tags": ["神话改编", "宝莲灯", "视觉大片", "反叛", "众神"], "summary_short": "天地宝莲灯，2025年中国大陆电影，奇幻动作。经典神话的暗黑重塑版。沉香劈开华山救出母亲三圣母，宝莲灯也碎成七片。然而三圣母出山后迅速衰老，七天内就会老死。神界派来使者告知：宝莲灯本质是“天条”的具象化，它的碎片镇压着七位上古叛逆之神。沉香每找回一片碎片，就会释放一个魔头，但三圣母能多活一年。沉香必须在七年间找回七片碎片，同时击败七个被释放的上古魔头（每一场战斗风格完全不同，致敬七种动作片类型）。当他集齐碎片时，神界却告诉他：宝莲灯将重", "score": 2025393, "category": "fantasy", "detail_url": "../movie/0492.html", "poster": "../posters/0492.svg"}, {"id": "0493", "title": "蜀山奇侠之仙侣奇缘国语", "year": 2026, "region": "中国大陆 / 中国香港", "type": "剧集", "genre": "仙侠、奇幻、古装", "tags": ["蜀山、血魔、正邪、前世今生、特效大片"], "summary_short": "蜀山奇侠之仙侣奇缘国语，2026年中国大陆 / 中国香港剧集，仙侠、奇幻、古装。改编自还珠楼主经典。五百年前，蜀山长老白眉为封印血魔，牺牲了一对最强弟子——血魔之女李英琼与正道奇侠金蝉。五百年后，两人转世为普通凡人：女剑客周轻云和书生石生。血魔残余力量欲借二人血脉重开魔界。蜀山新一代掌门诸葛警我强行唤醒两人前世记忆与法力，并告知他们：只有两人修炼“无情剑诀”，并在修成之日兵解（自杀），以纯阳纯阴之力才能彻底净化血魔。这让深爱彼此的周轻云", "score": 2026224, "category": "series", "detail_url": "../movie/0493.html", "poster": "../posters/0493.svg"}, {"id": "0494", "title": "居里夫人", "year": 2026, "region": "法国", "type": "电影", "genre": "剧情", "tags": ["传记", "科学", "女性", "历史", "情感"], "summary_short": "居里夫人，2026年法国电影，剧情。影片聚焦玛丽·居里在丈夫皮埃尔去世后的人生低谷与科学巅峰。1906年，皮埃尔因马车事故丧生，玛丽接手他的教席，成为索邦首位女教授。她与已婚物理学家保罗·朗之万的恋情曝光，引发法国媒体疯狂的性别羞辱，甚至被贴上“犹太偷窃者”的标签。在舆论风暴中，玛丽选择躲进实验室，用四年时间分离出纯镭，第二次获得诺贝尔奖。影片并未将她塑造成完美圣人，而是呈现了一个在男性主导的学术圈里，既要捍卫科学尊严，又要为私人情感付", "score": 2026267, "category": "drama", "detail_url": "../movie/0494.html", "poster": "../posters/0494.svg"}, {"id": "0495", "title": "情场三杰", "year": 1985, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["追女仔", "都市喜剧", "兄弟情", "台湾新电影", "三角恋"], "summary_short": "情场三杰，1985年中国台湾电影，喜剧 / 爱情。阿强、阿国和小歪是台北西门町出了名的三个花花公子，他们合开了一家失败的侦探社，主要业务其实是帮人抓奸。三人立下毒誓：兄弟如手足，女人如衣服，绝不为女人伤了和气。直到一个雨夜，来自台南的富家千金林小姐带着她的两位闺蜜北上寻亲，误打误撞进了他们的侦探社。阿强爱上了文静的大姐，阿国爱上了泼辣的二姐，而平时最胆小的小歪则爱上了天真烂漫的小妹。三个情场老手同时变成了手足无措的纯情少男，想尽办法献殷", "score": 1985337, "category": "comedy", "detail_url": "../movie/0495.html", "poster": "../posters/0495.svg"}, {"id": "0496", "title": "鸡肉库拉那", "year": 2022, "region": "泰国", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["炸鸡", "遗产争夺", "荒诞", "东南亚风情", "和解"], "summary_short": "鸡肉库拉那，2022年泰国电影，喜剧 / 家庭。泰国春蓬府，卖“库拉那炸鸡”(祖传香料配方)的老头颂猜去世。遗嘱律师宣读：遗产不是钱，是祖宅和配方。三个孩子必须参加“炸鸡大赛”：大儿子乃东(曼谷金融精英)认为这是玩笑，空手回来；二女儿赛朵(单亲妈妈，在市场卖烤串)不屑一顾；小儿子贝斯(在墨尔本做厨师)带着白人女友回来。条件是：只能用当地食材，请全村人试吃，票多者胜。比赛当天，乃东用高级厨具做了“低温慢煮鸡胸配松露油”——没人投票，因为不", "score": 2022288, "category": "comedy", "detail_url": "../movie/0496.html", "poster": "../posters/0496.svg"}, {"id": "0497", "title": "魔偶魔影", "year": 1994, "region": "日本", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["木偶、诅咒、密室、复仇、心理"], "summary_short": "魔偶魔影，1994年日本电影，恐怖 / 悬疑。东京一家歌舞伎剧场即将拆迁，工人在后台发现了一具被封存在玻璃箱中的木偶，名叫“杰克”。不久后，接触过木偶的人开始陆续离奇死亡。女主角京子是腹语师，她在梦境中被杰克召唤到了剧场。杰克告诉她，它曾是二战时一名天才腹语师为了排解孤独制造的完美作品，后来因嫉妒被主人抛弃而堕入魔道。杰克提出与京子交换灵魂，京子拒绝后，杰克开始操控剧场里的所有道具，将京子困在剧场内。一场与百年魔灵的生死对决，在空无一人", "score": 1994449, "category": "horror", "detail_url": "../movie/0497.html", "poster": "../posters/0497.svg"}, {"id": "0498", "title": "午夜天鹅", "year": 2025, "region": "日本", "type": "电影", "genre": "剧情, 同性, 家庭", "tags": ["跨性别者", "芭蕾", "母子", "治愈"], "summary_short": "午夜天鹅，2025年日本电影，剧情, 同性, 家庭。凪沙是个在东京地下俱乐部表演变装秀的中年跨性别者，还没钱做手术，梦想是有朝一日能在真正的舞台上演《天鹅湖》中的奥杰塔。一天，姐姐因虐待儿童被捕，把8岁的儿子翔太丢给了她。起初凪沙无比嫌弃这个浑身脏兮兮的“拖油瓶”，但发现翔太有惊人的芭蕾天赋。为了不让翔太重蹈自己覆辙，凪沙白天在工地搬砖赚钱送翔太学舞，晚上继续浓妆艳抹登台。随着翔太的身世被媒体曝光，凪沙的变装身份也面临暴露。在“全日本儿", "score": 2025292, "category": "drama", "detail_url": "../movie/0498.html", "poster": "../posters/0498.svg"}, {"id": "0499", "title": "神女", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "剧情 / 历史", "tags": ["民国", "妓女", "母性", "黑白转彩色", "阮玲玉致敬"], "summary_short": "神女，2026年中国大陆电影，剧情 / 历史。1935年的上海，一位被称为“神女”的妓女为了抚养年幼的儿子，在夜晚的街头与底层混混周旋。她努力让孩子接受良好教育，却因身份暴露而遭到学校与其他家长的排斥。当混混用孩子的未来要挟她继续卖淫时，她被迫做出极端选择。影片以黑白影像为主，但在她与孩子相处的温馨时刻转为彩色，隐喻她内心对纯洁生活的渴望。最终她在法庭上平静陈述，其眼神中交织的绝望与尊严成为经典镜头。", "score": 2026245, "category": "drama", "detail_url": "../movie/0499.html", "poster": "../posters/0499.svg"}, {"id": "0500", "title": "又一个星期五", "year": 2024, "region": "英国", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["时间循环", "家庭噩梦", "心理恐怖", "密室逃脱"], "summary_short": "又一个星期五，2024年英国电影，恐怖 / 悬疑。为了给母亲庆祝70岁生日，四兄妹带着家人来到偏远的老宅。周五的晚宴温馨而吵闹，但半夜惊醒的大哥发现，所有人的手机时间都停在23:59不再走动。第二天醒来，仍是星期五，一切重演。他们尝试各种方法逃离，却总是在午夜回到原点。更可怕的是，每一次循环，屋子里都会多出一个亲戚或朋友，而这个人他们完全不认识，但其他家庭成员却坚称他一直存在。当第五次循环来临时，他们惊恐地发现——这次多出来的那个人，是", "score": 2024384, "category": "crime", "detail_url": "../movie/0500.html", "poster": "../posters/0500.svg"}, {"id": "0501", "title": "注文津", "year": 2024, "region": "韩国", "type": "电影", "genre": "奇幻 / 爱情", "tags": ["海边", "许愿", "阴阳眼"], "summary_short": "注文津，2024年韩国电影，奇幻 / 爱情。江原道注文津海边，海女明珠救起了一名投海自尽的少年道允。道允醒来后说自己能看到“灵魂的丝线”，他梦到自己前世在海边与恋人约定“无论轮回多少次都要相认”。但明珠因为常年下海，也有一种奇特能力：她能看到溺亡者的鬼魂，并帮他们完成遗愿。两人开始一起寻找道允梦中的“红发女人”。他们找到了三位疑似对象：一位是花店老板娘、一位是女高中生、还有一位是已经去世的老奶奶。最终在奶奶的遗物里找到一封信，信中写道：", "score": 2024355, "category": "romance", "detail_url": "../movie/0501.html", "poster": "../posters/0501.svg"}, {"id": "0502", "title": "一切从遇见你开始", "year": 2019, "region": "韩国", "type": "电影", "genre": "爱情，剧情", "tags": ["盲人，设计师，声音，治愈"], "summary_short": "一切从遇见你开始，2019年韩国电影，爱情，剧情。调香师敏浩在七年前因事故失明，却练出了可以分辨千种气味的能力。他接到了一个奇怪订单：一位客户想要一种“能让人感到被爱”的香水。敏浩为了寻找这种不存在的气味，每天在城市里游荡。他在天台上遇到了想跳楼的平面设计师秀雅——她的作品被剽窃，男友背叛，准备结束生命。敏浩说：“你身上的味道很特别，像暴雨前的图书馆。”这句话救了她。秀雅开始为敏浩描述她看到的颜色和画面，敏浩则把她描述的颜色转化成气味。", "score": 2019367, "category": "drama", "detail_url": "../movie/0502.html", "poster": "../posters/0502.svg"}, {"id": "0503", "title": "黑道风云", "year": 2021, "region": "韩国", "type": "剧集", "genre": "犯罪 / 动作 / 剧情", "tags": ["黑帮，卧底，义气，暴力美学，背叛"], "summary_short": "黑道风云，2021年韩国剧集，犯罪 / 动作 / 剧情。特种兵出身的泰秀，妹妹被黑帮分子的流弹误杀，凶手却因顶包而逍遥法外。泰秀伪造身份，潜入釜山最大的黑帮“七星派”，从小弟做起，试图接近当年开枪的中层头目。他用不要命的打法一路晋升，逐渐获得会长张哲的绝对信任。张哲是个信奉“道义”的老派黑帮，待泰秀如亲子。三年后，泰秀终于手刃仇人，却在临死前得知一个真相：当年下令开枪的并非那个人，而是张哲本人——因为妹妹无意中目睹了张哲与警察局长私下的", "score": 2021352, "category": "crime", "detail_url": "../movie/0503.html", "poster": "../posters/0503.svg"}, {"id": "0504", "title": "夺宝五福星", "year": 2025, "region": "中国香港", "type": "电影", "genre": "喜剧 / 动作 / 冒险", "tags": ["怀旧", "五福星重启", "寻宝"], "summary_short": "夺宝五福星，2025年中国香港电影，喜剧 / 动作 / 冒险。30年后，当年的“五福星”都已年过六旬。茶餐厅老板鹧鸪菜、退休气功师犀牛皮、广场舞领队大生地、看门老头花旗参和失忆的罗汉果，因一段怀旧视频被网红嘲讽为“老年Cosplay”。为了证明自己，五人组队参加了一场商场的真人实景寻宝游戏。不料游戏场地被真正的国际盗宝集团截胡，价值连城的唐代佛像首被藏在场地中等待交易。五个老顽童误打误撞成了警匪双方追踪的对象，他们用老掉牙的骗术、气功和", "score": 2025358, "category": "crime", "detail_url": "../movie/0504.html", "poster": "../posters/0504.svg"}, {"id": "0505", "title": "战略迷魂", "year": 2026, "region": "美国", "type": "电影", "genre": "动作, 科幻, 悬疑", "tags": ["记忆植入", "间谍", "反转", "身份认知", "硬科幻"], "summary_short": "战略迷魂，2026年美国电影，动作, 科幻, 悬疑。CIA最强特工凯恩在任务中被敌方俘获，经历了72小时酷刑后奇迹般逃脱，带回了一份关于“新世界秩序”的绝密袭击计划。CIA按此情报布下天罗地网，然而每一次精准的拦截，都莫名其妙地帮助敌人扫清了障碍，最终反而促成了对方的终极目标——全球金融系统一键崩盘。凯恩发现自己被植入了一套完美的“战略迷魂”记忆：他所记得的一切情报，都是敌人专门设计好让他“偷走”的假信息，目的就是让CIA按照敌人的剧本", "score": 2026445, "category": "crime", "detail_url": "../movie/0505.html", "poster": "../posters/0505.svg"}, {"id": "0506", "title": "狐狸女士第二季", "year": 2024, "region": "英国", "type": "剧集", "genre": "悬疑", "tags": ["英剧，女性特工，退休返聘，优雅"], "summary_short": "狐狸女士第二季，2024年英国剧集，悬疑。上一季结束后，本想彻底归隐田园的“狐狸”萨曼莎发现自己所有的积蓄被冻结。为了生存，她勉强答应帮军情五处做最后一次“简单咨询”：调查一位部长的情妇是否为外国间谍。然而随着调查深入，萨曼莎发现这根本不是简单的桃色事件，背后牵扯到一项向敌国泄露潜艇技术的庞大计划。更致命的是，她一手带出来的徒弟竟成了敌方的双面间谍。在苏格兰高地的猎狐季，萨曼莎既要在贵族狩猎派对上保持优雅，又要在暴风雪中与昔日的徒弟展开", "score": 2024304, "category": "series", "detail_url": "../movie/0506.html", "poster": "../posters/0506.svg"}, {"id": "0507", "title": "危险性直播", "year": 2024, "region": "韩国", "type": "电影", "genre": "惊悚 / 犯罪 / 悬疑", "tags": ["网络直播，社会讽刺，密室，极限反杀"], "summary_short": "危险性直播，2024年韩国电影，惊悚 / 犯罪 / 悬疑。过气主播吴东旭为了翻红，决定深夜直播进入著名的“昆池岩级”废弃医院。直播间在线人数一路飙升，但很快弹幕开始变味。吴东旭发现医院里不仅有鬼，还有蒙面人。当他试图逃跑时，门被锁死了。此时，另一个名为“狩猎之夜”的直播间爆火，观看人数百万，里面正是吴东旭在废弃医院里绝望逃命的画面。原来这是一场付费观看的真人虐杀秀。吴东旭不仅要躲避追杀，还要面对直播间里看客们“让他死”或“让他活”的投票", "score": 2024497, "category": "crime", "detail_url": "../movie/0507.html", "poster": "../posters/0507.svg"}, {"id": "0508", "title": "卡特琳娜·伊兹梅洛娃", "year": 2026, "region": "俄罗斯", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["女性", "复仇", "古典新说", "阶级冲突", "俄式美学"], "summary_short": "卡特琳娜·伊兹梅洛娃，2026年俄罗斯电影，剧情 / 悬疑。故事改编自经典歌剧，背景移至十九世纪末俄国。卡特琳娜·伊兹梅洛娃在丈夫暴毙后接管庞大盐场，表面是优雅的女富商，背地里却因童年目睹农奴被虐而产生扭曲正义感。她与家中长工谢尔盖联手，用商业陷阱和物理清除手段，逐一杀死那些虐待农民、贿赂官员的旧地主。然而当谢尔盖发现自己不过是棋子想勒索她时，卡特琳娜在新建成的西伯利亚大铁路桥上设下致命圈套，完成了最后一场“血色宴席”。影片以阴冷的雪原", "score": 2026372, "category": "drama", "detail_url": "../movie/0508.html", "poster": "../posters/0508.svg"}, {"id": "0509", "title": "天空的姻缘", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "爱情 / 奇幻", "tags": ["月老，红线，航空公司，命中注定，轻喜剧"], "summary_short": "天空的姻缘，2023年中国台湾电影，爱情 / 奇幻。实习月老阿月在云端办公时不慎将红线缠乱，误将黄金单身汉机长陈翰宇与恐婚女乘客方小晴的红线紧紧系在一起。更严重的是，这架飞机即将遭遇十年一遇的晴空湍流，所有系错红线的乘客都可能因此丧生，导致人间姻缘大乱。阿月不得不在飞行途中下凡，以空乘身份在狭小的机舱里偷偷修正红线。他必须一边躲避飞机上另一位抓违规的资深月老督察，一边在颠簸的气流中撮合一对对错位的情侣。随着飞机逼近风暴核心，阿月发现最大", "score": 2023354, "category": "fantasy", "detail_url": "../movie/0509.html", "poster": "../posters/0509.svg"}, {"id": "0510", "title": "情迷浪子心", "year": 1998, "region": "中国香港", "type": "电影", "genre": "爱情，剧情", "tags": ["浪子，虐恋，都市，宿命"], "summary_short": "情迷浪子心，1998年中国香港电影，爱情，剧情。阿珍是酒吧的夜间经理，她善于处理所有烂摊子，除了自己的感情。她爱上了一周只出现三次的调酒师阿风，一个自称“没有脚”的浪子。两人在狭窄的阁楼里许下天亮就作废的誓言。当阿珍发现自己怀孕，她决定用这个“意外”绑住阿风，却不知阿风正被昔日情人病危的消息所困。一场关于占有与放手的博弈在霓虹灯下展开，最终阿风选择承担，而阿珍却在产房前夜消失。十年后，他们女儿的演唱会海报贴满了阿风那间早已关门的酒吧旧址", "score": 1998309, "category": "drama", "detail_url": "../movie/0510.html", "poster": "../posters/0510.svg"}, {"id": "0511", "title": "帅气的恶魔", "year": 2024, "region": "爱尔兰 / 英国", "type": "电影", "genre": "剧情 / 同性 / 运动", "tags": ["橄榄球", "寄宿学校", "阳刚气质", "自我认同"], "summary_short": "帅气的恶魔，2024年爱尔兰 / 英国电影，剧情 / 同性 / 运动。柯克是圣克里斯托弗学院的橄榄球队队长，全校最受欢迎的直男偶像。新学期转来一个伦敦男孩埃文，举止阴柔，第一天就被全校男生嘲笑是“基佬”。柯克被指派“改造”埃文，教他打橄榄球、改变走路姿势。训练中柯克发现自己越来越在意埃文，会在别人欺负他时下意识护住他。一次宿舍深夜谈心，埃文问他：“你有没有想过，你打球那么拼命，是因为你爸爸说你娘？”柯克愣住了，那是他藏在心底最深的恐惧。", "score": 2024311, "category": "drama", "detail_url": "../movie/0511.html", "poster": "../posters/0511.svg"}, {"id": "0512", "title": "猫汤", "year": 2001, "region": "日本", "type": "动画电影", "genre": "奇幻、暗黑", "tags": ["超现实主义、猎奇、隐喻、汤浅政明、残酷童话"], "summary_short": "猫汤，2001年日本动画电影，奇幻、暗黑。根据桥口千代美的漫画改编。一个普通的猫家庭里，姐姐因病卧床，死神正要带走她的灵魂，弟弟奋力抢夺，只夺回了一半。为了找回另一半，弟弟带着姐姐踏上了穿越时空的旅程。他们经历了奇幻的马戏团：里面的人鱼被残忍地切割后又缝合；遇到了能随意改变大小的上帝，他正在无聊地玩弄人类的生死；洪水淹没世界，他们乘着诺亚方舟，看着动物们互相吞食；弟弟遇到了一个不断转世却总是惨死的猪。最后的最后，他们终于找到了姐姐的灵魂", "score": 2001266, "category": "fantasy", "detail_url": "../movie/0512.html", "poster": "../posters/0512.svg"}, {"id": "0513", "title": "恶兽", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作, 惊悚", "tags": ["怪兽", "军事", "灾难", "特效"], "summary_short": "恶兽，2025年韩国电影，动作, 惊悚。朝韩非军事区地下百米处，一支联合考察队意外凿穿了一个史前洞穴。洞穴中沉睡着一头身覆鳞甲、能在黑暗中感知生物恐惧情绪的巨型怪兽“巴拉”。由于人类的惊扰，“巴拉”破土而出，开始在非军事区两侧的驻军基地大开杀戒。它不攻击没有恐惧的机器，只猎杀心怀恐惧的人。朝韩双方的士兵在共同的危机面前，不得不放下敌对状态，临时组建一支由精锐特种兵组成的“屠兽小队”。他们要克服内心最深处的恐惧，利用“巴拉”以恐惧为食的特", "score": 2025337, "category": "crime", "detail_url": "../movie/0513.html", "poster": "../posters/0513.svg"}, {"id": "0514", "title": "情圣没有淡季", "year": 2023, "region": "中国大陆", "type": "网剧", "genre": "喜剧，爱情，都市", "tags": ["海王翻车，反套路，女性觉醒，搞笑修罗场"], "summary_short": "情圣没有淡季，2023年中国大陆网剧，喜剧，爱情，都市。男主角方浩轩号称“人间永动机”，自认全年无情感空窗期。某天，他手机意外同步了六位“女友”的聊天记录，惊讶地发现她们不仅知道彼此存在，还组成了一个“反PUA联盟”。更恐怖的是，这六位女性由同一位编剧好友精心策划，目的是收集素材写出一部“完美海王反杀剧本”。方浩轩试图挽回局面，却一步步掉入更深的陷阱，最终发现自己的情感套路被公之于众，沦为全网笑柄，而真正的“情圣”其实是幕后那位从未谈过", "score": 2023172, "category": "series", "detail_url": "../movie/0514.html", "poster": "../posters/0514.svg"}, {"id": "0515", "title": "三角突击队2", "year": 2026, "region": "美国", "type": "电影", "genre": "动作 / 战争", "tags": ["三角洲部队， 无人机战争， 沙漠营救， 战术小队"], "summary_short": "三角突击队2，2026年美国电影，动作 / 战争。五名三角洲队员奉命潜入也门山区，营救一名被胡塞武装绑架的美国女工程师。当他们抵达洞穴监狱时，发现工程师已被转移，而山谷上空突然出现数百架由同一AI系统控制的攻击无人机——“蜂巢”。该系统是工程师为军方设计的，如今被武装分子篡改。队员们在毫无防空火力的情况下，借助古老的山洞地道进行移动，并利用地面反光板干扰无人机视觉。队长“幽灵”发现，只要摧毁谷底那辆信号中继车，AI就会因延迟过高而失能。", "score": 2026277, "category": "crime", "detail_url": "../movie/0515.html", "poster": "../posters/0515.svg"}, {"id": "0516", "title": "黑暗城市", "year": 1998, "region": "澳大利亚", "type": "电影", "genre": "科幻 / 悬疑 / 黑色电影", "tags": ["记忆", "外星", "永夜", "压抑"], "summary_short": "黑暗城市，1998年澳大利亚电影，科幻 / 悬疑 / 黑色电影。一座不见阳光、永远黑夜的城市。男主角默多克在浴缸中醒来，发现自己失去了所有记忆，却获得了“调制”他人记忆的超能力——就像调整收音机频率。他追查自己身份时，发现这座城市其实是一艘巨型外星飞船建造的“记忆实验场”。一群名为“陌生人”的外星人靠偷取人类记忆来研究“灵魂”。默多克利用调制能力，将所有被偷的记忆归还给城市居民。最后，他站在海边，第一次看到了日出。", "score": 1998442, "category": "sci-fi", "detail_url": "../movie/0516.html", "poster": "../posters/0516.svg"}, {"id": "0517", "title": "传话人", "year": 2025, "region": "韩国", "type": "剧集", "genre": "悬疑 / 奇幻", "tags": ["传话，死者，电话亭"], "summary_short": "传话人，2025年韩国剧集，悬疑 / 奇幻。首尔一处废弃电话亭传言能接通“那边”。神秘男子郑河每天守在那里，替活人传话给死者，但每传一次话，他就会忘记一件重要的事。第一天他忘了自己名字，第二天忘了母亲长相，第三天忘了回家的路。刑警李敏贞追查失踪案时发现，郑河竟是五年前死去的失踪人口。原来郑河本人就是死者，电话亭是阴间的“传话亭”，他用记忆作为筹码换取替活人传话的机会。李敏贞求他打给五年前失踪的妹妹，郑河打完最后一通电话，彻底忘了自己是谁", "score": 2025298, "category": "series", "detail_url": "../movie/0517.html", "poster": "../posters/0517.svg"}, {"id": "0518", "title": "极乐大餐", "year": 1973, "region": "法国 / 意大利", "type": "电影", "genre": "剧情 / 喜剧 / 惊悚", "tags": ["美食", "死亡", "荒诞", "经典"], "summary_short": "极乐大餐，1973年法国 / 意大利电影，剧情 / 喜剧 / 惊悚。四个事业成功但人生空虚的中年男人——法官、厨师、飞行员和美食家——决定以一种“极致”的方式告别世界：他们准备在一栋豪华别墅里，做一顿世界上最丰盛的大餐，然后一直吃，直到撑死为止。他们邀请了三位妓女作陪，开始了这场荒诞的“死亡盛宴”。三天里，他们吃了几十道菜，喝了无数瓶名酒，从优雅的品鉴变成野兽般的饕餮。当第一个人死在餐桌上的时候，剩下的人没有停止，而是继续吃。这是一场关", "score": 1973375, "category": "drama", "detail_url": "../movie/0518.html", "poster": "../posters/0518.svg"}, {"id": "0519", "title": "神鹰之拳", "year": 2024, "region": "秘鲁 / 阿根廷", "type": "电影", "genre": "运动 / 剧情", "tags": ["足球，印加文化，励志，父子"], "summary_short": "神鹰之拳，2024年秘鲁 / 阿根廷电影，运动 / 剧情。秘鲁球员库斯科曾被誉为“安第斯神鹰”，却在登陆欧洲后因伤病和心理问题沦为水货，被球队解约后灰溜溜回国。酗酒、颓废、拒绝任何人提起足球。他的父亲——一个没人知道的印加搏击术“神鹰之拳”的传人，用古老的方式逼他训练：不是足球，而是赤脚在碎石上对抗、用拳头击打古柯叶包裹的沙袋、学习神鹰俯冲时的呼吸节奏。库斯科起初抗拒，但渐渐地，他发现“神鹰之拳”的核心不是暴力，而是“借力”——像神鹰利", "score": 2024249, "category": "drama", "detail_url": "../movie/0519.html", "poster": "../posters/0519.svg"}, {"id": "0520", "title": "真爱大逃亡", "year": 1987, "region": "法国", "type": "电影", "genre": "爱情 / 冒险 / 喜剧", "tags": ["公路", "亡命鸳鸯", "经典"], "summary_short": "真爱大逃亡，1987年法国电影，爱情 / 冒险 / 喜剧。婚礼当天，新娘发现新郎的行李箱里装满了赃款。新郎承认自己是职业骗子，专门骗富婆。新娘崩溃，说自己也不是什么富家女，而是冒充身份的逃跑女佣。两人还没来得及吵架，黑帮和警察同时冲进教堂。他们只好开着婚车逃跑，从巴黎一路狂飙到马赛。途中两人互相嫌弃又互相救命，渐渐发现对方虽然满嘴谎言，但本性善良。在马赛旧港，他们设下连环计，同时骗过了黑帮和警方，带着赃款登上了去往非洲的船。而这次，他们", "score": 1987394, "category": "comedy", "detail_url": "../movie/0520.html", "poster": "../posters/0520.svg"}, {"id": "0521", "title": "敌对同谋", "year": 2027, "region": "美国", "type": "剧集", "genre": "谍战 / 惊悚", "tags": ["双面间谍", "冷战", "人性拷问"], "summary_short": "敌对同谋，2027年美国剧集，谍战 / 惊悚。1989年冬，东德特工莱纳和西德特工约瑟夫曾是亲密无间的战友，却在多年前因一场失败的策反行动反目成仇。如今，两人都被各自的上级秘密指派了最终任务：在圣诞夜之前杀死对方。然而，在多次交锋中，他们发现所谓的“敌对”不过是高层为了维持冷战格局而设计的棋局。真正的敌人，是那个打算在柏林墙倒塌后清除所有知情旧部的神秘组织“幽灵”。为了活下去，这对宿敌不得不再次成为“敌对同谋”，演一场你死我活的戏给全世", "score": 2027297, "category": "series", "detail_url": "../movie/0521.html", "poster": "../posters/0521.svg"}, {"id": "0522", "title": "斗破苍穹3：除恶", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动作， 奇幻", "tags": ["修仙， 除恶， 异火， 复仇， 特效大片"], "summary_short": "斗破苍穹3：除恶，2024年中国大陆电影，动作， 奇幻。药老沉睡后，萧炎为寻唤醒之法深入北荒毒域。当地三个宗门被神秘力量灭门，活下来的人变成没有痛觉的杀戮傀儡。所有线索指向一种能侵蚀灵魂的远古“业火”。萧炎在追踪中发现自己每次催动焚决，体内便会多出一道不属于自己的杀人记忆——那是药老尘封的黑暗过去。最终反派不是别人，而是药老当年亲手封印的“恶念化身”。萧炎必须在“继承恶念救老师”与“坚守本心任其沉睡”之间做残酷抉择。", "score": 2024400, "category": "crime", "detail_url": "../movie/0522.html", "poster": "../posters/0522.svg"}, {"id": "0523", "title": "海军特别年少兵", "year": 2001, "region": "日本", "type": "电影", "genre": "战争", "tags": ["二战", "少年兵", "军舰", "悲剧", "反战"], "summary_short": "海军特别年少兵，2001年日本电影，战争。二战末期，日本海军因兵源枯竭，招募了一批15岁以下少年作为“特别年少兵”。故事聚焦四名来自不同地方的少年：农家阿铁、孤儿诚、教师儿子智、工厂童工一郎。他们被送上即将执行自杀式任务的“柳号”驱逐舰。起初他们以为在玩军事夏令营，每天擦炮弹、唱军歌。直到第一次被美军空袭，智的头颅在甲板上滚落。阿铁学会了开炮，诚则疯了。最终战舰接到命令前往冲绳送死，阿铁跳海逃生，60年后他重返战舰沉没地，撒下四捧土。", "score": 2001294, "category": "doc", "detail_url": "../movie/0523.html", "poster": "../posters/0523.svg"}, {"id": "0524", "title": "海妲", "year": 2025, "region": "挪威", "type": "电影", "genre": "惊悚 / 奇幻", "tags": ["北欧", "海洋", "人鱼", "邪教", "身份认同"], "summary_short": "海妲，2025年挪威电影，惊悚 / 奇幻。挪威北极圈内一个与世隔绝的渔村，少女海妲从不说话，从小只和海豹待在一起。村民传说她三岁时掉进冰海，被海鬼救起，从此半人半鬼。渔村近年渔业枯竭，一个外来邪教组织“净水兄弟会”来到村里，宣称人类的罪孽污染了大海，只有献祭“不属于人类的孩子”才能让鱼群回来。他们盯上了海妲。海妲的养父——一个同样被村民排挤的老渔民——拼命保护她，但村里越来越多的人开始相信邪教的说辞。献祭之夜，海妲被绑在码头木桩上，潮水", "score": 2025348, "category": "horror", "detail_url": "../movie/0524.html", "poster": "../posters/0524.svg"}, {"id": "0525", "title": "闪灵", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["心理惊悚", "酒店怪谈", "通灵", "经典翻拍"], "summary_short": "闪灵，2025年美国电影，恐怖 / 悬疑。杰克是一名过气小说家，为摆脱酗酒恶习，接受神秘酒店“瞭望台”的冬季看守工作。他的小儿子丹尼拥有“闪灵”能力，能看到酒店过去的血腥杀戮。暴风雪切断了所有对外联系后，杰克逐渐被酒店中前管理员的怨灵操控，开始追杀妻儿。妻子温蒂发现杰克的手稿从头到尾只重复打印着一句话：“整天工作，没有娱乐”。与此同时，丹尼在通灵指引下，于迷宫中与变成怪物的父亲展开生死追逐。", "score": 2025391, "category": "horror", "detail_url": "../movie/0525.html", "poster": "../posters/0525.svg"}, {"id": "0526", "title": "黑帮教母", "year": 2019, "region": "意大利", "type": "剧集", "genre": "犯罪，剧情", "tags": ["黑帮，女性，权力"], "summary_short": "黑帮教母，2019年意大利剧集，犯罪，剧情。西西里黑手党家族“科莱罗”的老大托尼在婚礼当天被警方逮捕，整个家族乱成一锅粥。一直扮演贤妻良母角色的莱娜走进会议室，对着那些吵着要分家的男人说：“你们每一笔生意的细节，都是我替托尼记的账。”她翻开一本烫金笔记本，上面记录了所有军火交易、贿赂官员名单和三个叛徒的名字。男人们以为自己被一个家庭主妇威胁了，直到莱娜当着所有人的面，用那把平时切番茄的厨刀，划开了第一个对她出言不逊之人的喉咙。她用围裙擦", "score": 2019314, "category": "series", "detail_url": "../movie/0526.html", "poster": "../posters/0526.svg"}, {"id": "0527", "title": "丛林奇航", "year": 2026, "region": "美国", "type": "电影", "genre": "冒险 / 喜剧 / 奇幻", "tags": ["亚马逊探险", "寻宝", "冤家路窄"], "summary_short": "丛林奇航，2026年美国电影，冒险 / 喜剧 / 奇幻。植物学家莉莉博士为了找到传说中的“月泪树”来制作治愈绝症的药引，来到亚马逊丛林。她雇佣了看似不靠谱、实则曾是特种兵的渡船船长弗兰克。莉莉身上祖传的箭头上刻着地图，而弗兰克的身世似乎也与这片丛林有着神秘联系。两人在航行中遭遇了叛军、巨蟒和食人鱼，相互嫌弃又不得不依靠对方。他们发现“月泪树”被原始部落守护着，而想摘取果实必须通过三道考验：勇气、智慧和牺牲。就在他们通过考验时，莉莉的赞助", "score": 2026363, "category": "fantasy", "detail_url": "../movie/0527.html", "poster": "../posters/0527.svg"}, {"id": "0528", "title": "律政英雄2007", "year": 2007, "region": "日本", "type": "电影", "genre": "剧情, 悬疑, 犯罪", "tags": ["检察官", "久利生公平", "木村拓哉", "庭审", "热血"], "summary_short": "律政英雄2007，2007年日本电影，剧情, 悬疑, 犯罪。久利生从偏远的石垣岛调回东京，与新事务官搭档处理一起流氓斗殴致死案。所有人都想以“伤害致死”快速结案，但他发现凶器上的指纹与嫌疑人年龄不符。通过像个普通刑警一样跑现场、查监控，他追踪到一枚被涂改的监控录像带，目标直指正在竞选连任的国会议员。在法庭上，面对权力压制，久利生坚持用最笨的办法——寻找一把丢失的匕首，还原了正当防卫的真相。", "score": 2007457, "category": "crime", "detail_url": "../movie/0528.html", "poster": "../posters/0528.svg"}, {"id": "0529", "title": "三女休夫", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "喜剧, 古装, 女性", "tags": ["古代离婚", "女子互助", "反套路"], "summary_short": "三女休夫，2023年中国大陆剧集，喜剧, 古装, 女性。唐朝永徽年间，泼辣的酒馆老板娘三娘、懦弱的官家小姐芷兰、精明的商人遗孀阿鹜，因各自被丈夫欺辱而相识。三娘一怒之下设计让丈夫签下休书（并赔了一半家产）。三人由此创办“三女休夫事务所”，业务包括：取证（丈夫养外室、赌博）、造势（让丈夫社死）、谈判（分割财产）。她们帮厨娘休了偷秘方的丈夫，帮女将军休了软饭男，甚至帮公主出主意和驸马和离。但保守派官员弹劾她们“伤风败俗”，三人在公堂上用大唐", "score": 2023226, "category": "series", "detail_url": "../movie/0529.html", "poster": "../posters/0529.svg"}, {"id": "0530", "title": "南部僵尸来袭", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖 / 喜剧 / 西部", "tags": ["丧尸", "德州", "红色neck"], "summary_short": "南部僵尸来袭，2024年美国电影，恐怖 / 喜剧 / 西部。美国德州与墨西哥边境的小镇“布尔克”，居民大多是退休牛仔和红脖子。镇上一个秘密实验室里，一批二战时被缴获的纳粹生化武器样本泄露，将实验室人员变成了具有完整意识、会说德语、保留军事战术的“纳粹僵尸”。他们拿着锈蚀的毛瑟枪，喊着元首口号，开始向小镇推进。当地警长是个只会开罚单的胖子，镇长是个信奉科学的嬉皮士。关键时刻，一群六七十岁的老年牛仔从酒吧走出来：老比利参加过越战，疯狗乔曾经", "score": 2024371, "category": "horror", "detail_url": "../movie/0530.html", "poster": "../posters/0530.svg"}, {"id": "0531", "title": "爸爸回来了第二季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "家庭、喜剧、奇幻", "tags": ["穿越、父女、治愈、轻科幻、成长"], "summary_short": "爸爸回来了第二季，2024年中国大陆剧集，家庭、喜剧、奇幻。继承了第一季结尾的超自然设定，13岁少女林小朵发现爸爸林大勇再次人间蒸发，而这次他被困在了她的智能手机里——确切地说，是被打散成96个数据碎片，分散在96个不同的APP之中。外卖软件里的他是个暴躁骑手，听歌软件里的他是个失恋歌手，连计算器里都藏着一个不停做算数的工科男。小朵必须在手机电量归零前，通过每个APP的规则将碎片收集齐全，而每收集一个碎片，爸爸就会想起一段她从未听过的往", "score": 2024353, "category": "series", "detail_url": "../movie/0531.html", "poster": "../posters/0531.svg"}, {"id": "0532", "title": "爱在血泪交织时", "year": 2027, "region": "中国香港", "type": "电影", "genre": "动作 / 爱情", "tags": ["黑帮，杀手，虐恋，救赎，暴力美学"], "summary_short": "爱在血泪交织时，2027年中国香港电影，动作 / 爱情。阿JO是黑帮圈闻风丧胆的“鬼牌杀手”，她从不让目标活到天亮。在一次灭门任务中，她动了恻隐之心，救下了躲在暗格里的少年小风。为了斩草除根或培养新工具，她将小风带在身边，教他搏击、枪械和冷血。十年后，小风成长为完美的杀手，却从未对阿JO拔过枪。当阿JO接到组织最后一项任务：刺杀背叛帮会的“内鬼”小风时，两人站在了断崖边。阿JO颤抖着举起枪，小风却笑着流泪，告诉她：“那天你救我，不是因为", "score": 2027411, "category": "crime", "detail_url": "../movie/0532.html", "poster": "../posters/0532.svg"}, {"id": "0533", "title": "心心之火", "year": 2025, "region": "中国大陆", "type": "电视剧 / 都市", "genre": "爱情 / 职场", "tags": ["女总裁", "实习生", "姐弟恋"], "summary_short": "心心之火，2025年中国大陆电视剧 / 都市，爱情 / 职场。知名科技公司CEO姜心年过三十，业界称她为“AI女王”，冷血高效。新来的实习生陆火是个理想主义的技术宅，他在全员大会上直接质疑姜心的新项目缺乏人文关怀，说她是“没有心的机器”。姜心没有当场发火，而是把陆火调为自己的私人特别助理，打算用三个月的高强度工作把他折磨到主动辞职。然而陆火不仅没被打垮，反而每次都能用匪夷所思的方式完成任务：比如为了测试办公椅舒适度，他把全公司椅子都贴上", "score": 2025225, "category": "series", "detail_url": "../movie/0533.html", "poster": "../posters/0533.svg"}, {"id": "0534", "title": "水晶国传说", "year": 2026, "region": "日本", "type": "动画剧集", "genre": "奇幻，冒险", "tags": ["魔法，战争，王室秘辛，种族和解"], "summary_short": "水晶国传说，2026年日本动画剧集，奇幻，冒险。水晶国因能量矿脉枯竭陷入内乱，公主艾琳娜在政变中逃亡，身边只有一名敌国间谍假扮的侍卫。当她濒临绝境时，体内爆发出足以撕裂大地的水晶之力，原来她是千年前“晶核女巫”的转世。叛军首领其实是当年被王室迫害的矿工后代，他希望用艾琳娜的力量重塑国家。而敌国派来的间谍侍卫，也逐渐在旅途中被公主的善良动摇。三方势力围绕水晶矿脉展开对决，艾琳娜必须在觉醒的力量中做出选择：用它重建旧秩序，还是彻底摧毁水晶能", "score": 2026306, "category": "fantasy", "detail_url": "../movie/0534.html", "poster": "../posters/0534.svg"}, {"id": "0535", "title": "销魂今夕", "year": 1988, "region": "中国香港", "type": "电影", "genre": "爱情，剧情", "tags": ["风月，前世今生，纠缠，悲情"], "summary_short": "销魂今夕，1988年中国香港电影，爱情，剧情。九十年代的夜总会舞女阿玉生活糜烂。一天，她在一张旧唱片中听到一首凄美的《销魂曲》后昏睡不醒。梦中，她成了三十年代的名门闺秀白露，与英俊却落魄的作曲家陈歌相爱。两人的爱情因门第之见受阻，最终白露被迫嫁入豪门，陈歌含恨写下《销魂曲》后自杀。阿玉从梦中醒来，发现自己手背上有与白露一样的胎记。她循着记忆找到了白露的故居，并在那里遇到了一个酷似陈歌的老人，一段跨越六十年的孽缘在夕阳下画上句号。", "score": 1988386, "category": "drama", "detail_url": "../movie/0535.html", "poster": "../posters/0535.svg"}, {"id": "0536", "title": "阿亚潘和柯西", "year": 2020, "region": "印度", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["兄弟情", "城乡", "梦想", "反差"], "summary_short": "阿亚潘和柯西，2020年印度电影，剧情 / 喜剧。阿亚潘和柯西是连体双胞胎，共享一个胃和三条腿。阿亚潘热爱音乐，梦想去孟买当歌手；柯西内向寡言，只想守着家里的稻田和牛。两人因无法手术分离，被迫终日捆绑在一起。阿亚潘偷偷报名歌唱比赛，柯西在旅途中不断拆台。他们参加海选时，柯西突然开口，用浑厚的嗓音唱了一首民谣，震惊全场——原来他才是更有天赋的那个。最终他们被淘汰，但两人在返程的火车上第一次真正理解了彼此。他们没有分开，但找到了各自的位置。", "score": 2020347, "category": "drama", "detail_url": "../movie/0536.html", "poster": "../posters/0536.svg"}, {"id": "0537", "title": "创伤的智慧", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情 / 心理", "tags": ["PTSD", "心理医生", "互相治愈", "北爱尔兰", "历史伤痕"], "summary_short": "创伤的智慧，2024年英国电影，剧情 / 心理。北爱尔兰老兵迈克尔退役三十年后，仍被战场噩梦折磨。他自学成为心理医生，专治PTSD患者。但他的疗法很另类：让患者听他讲自己的噩梦。一个恐袭幸存者、一个家暴受害者、一个叙利亚难民，在他的“创伤分享小组”里找到了共鸣。但迈克尔的病情越来越重，开始产生幻觉，以为患者是当年的敌人。他的导师警告他：你在用患者治愈自己，这不道德。迈克尔最终崩溃住院，但那三名患者轮流来探望他，并用他的方法帮助他。出院后", "score": 2024261, "category": "drama", "detail_url": "../movie/0537.html", "poster": "../posters/0537.svg"}, {"id": "0538", "title": "龙虎武师", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作 / 剧情", "tags": ["替身演员", "行业挽歌", "硬核实拍", "师徒传承"], "summary_short": "龙虎武师，2024年中国香港电影，动作 / 剧情。八十年代香港动作片黄金时期，武师阿杰带领的“龙家班”以不要命的真摔实打闻名。四十年后，CG技术全面取代实拍，片场不再需要跳楼跳车的亡命徒。阿杰的徒弟小虎因伤退休，在工地搬砖；大师兄转行做了武术指导，却只设计安全的花哨动作。阿杰不甘心这门手艺被遗忘，集结几位老武师，在没有保险公司敢承保的情况下，秘密筹备一部完全不用特效的传统功夫片。拍摄最后一场七层楼高空坠落戏时，所有人都劝他用绿幕，他却在", "score": 2024330, "category": "drama", "detail_url": "../movie/0538.html", "poster": "../posters/0538.svg"}, {"id": "0539", "title": "地狱旅程", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖, 冒险", "tags": ["但丁", "地狱", "心理惊悚"], "summary_short": "地狱旅程，2025年美国电影，恐怖, 冒险。顶尖法医埃利斯从不相信灵魂，在他的解剖刀下，所有人只是肉块。某天心梗猝死后，他睁开眼，发现自己正从一片黑暗森林滚落，标志清晰：地狱之门。九层地狱的每一层，惩罚都与他对某位死者做过的事完全对应：他曾不耐烦地缝合了一个女人的嘴，在第二层舌狱中无法停止尖叫；他曾草率判定一个被谋杀者为自杀，在第七层暴力狱中被无限重复凶手杀害的过程。他被迫重新“经历”每一位死者的最后痛苦。唯一可能的出路，是找到他一生中", "score": 2025338, "category": "horror", "detail_url": "../movie/0539.html", "poster": "../posters/0539.svg"}, {"id": "0540", "title": "黑暗的习惯", "year": 1983, "region": "西班牙", "type": "电影", "genre": "剧情", "tags": ["修女", "瘾君子", "阿莫多瓦", "黑色幽默"], "summary_short": "黑暗的习惯，1983年西班牙电影，剧情。一座濒临关闭的修道院里住着三位“问题修女”：一位沉迷海洛因，一位沉迷摇滚乐，一位沉迷肉体欲望。她们用各种离经叛道的方式维持修道院运转，直到一名被警方追捕的变性人逃犯闯入。修女们没有报警，反而把她藏在了忏悔室里。在这座早已被教会遗忘的破败建筑里，一群被社会抛弃的边缘人组成了荒诞又温暖的“新家庭”。而当警察终于找上门时，修女们选择用最疯狂的方式守护这个闯入者——她们决定集体吸毒，制造一场混乱的“神迹”", "score": 1983259, "category": "drama", "detail_url": "../movie/0540.html", "poster": "../posters/0540.svg"}, {"id": "0541", "title": "朋友妻，不可戏", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "剧情，爱情", "tags": ["兄弟反目，伦理，误会，救赎"], "summary_short": "朋友妻，不可戏，2024年中国台湾电影，剧情，爱情。阿杰因酒后驾车导致好兄弟阿坤瘫痪，为赎罪他按照阿坤的“愿望清单”照顾其妻小美。清单第三项是“帮我还原那卷老录像带”。阿杰找到录像带，发现内容竟是阿坤偷拍的隔壁少妇换衣服，而少妇的脸竟是小美年轻时的模样。阿杰陷入疯狂猜忌：小美是否早就知道？阿坤的瘫痪是意外还是报复？当他把录像带给小美看时，小美平静地说是自己故意让阿坤拍下的，为的是“让他永远记住这辈子最对不起的人”。两人在阳台上沉默对坐，", "score": 2024357, "category": "drama", "detail_url": "../movie/0541.html", "poster": "../posters/0541.svg"}, {"id": "0542", "title": "魔法圣战", "year": 2027, "region": "英国", "type": "电影", "genre": "奇幻 / 动作", "tags": ["现代魔法", "圣杯战争", "反英雄", "硬核设定"], "summary_short": "魔法圣战，2027年英国电影，奇幻 / 动作。2030年，魔法从地下走向公开，但因为科技监控，纯血魔法师被政府收编。传说中能实现“一个愿望”的圣杯再次出现，七位被选中的“御主”被投放到一座反魔法干扰的未来都市。但圣杯的真实形态，是一枚可以同时破解全球所有核武发射代码、并重新分配控制权的量子芯片。参赛者中，有想毁灭国家的恐怖分子、有想用芯片复活亡妻的哀悼者、有想将魔法公之于众的理想主义者，还有一个被误选、只会用魔法煮咖啡的家庭主妇。当所有", "score": 2027363, "category": "fantasy", "detail_url": "../movie/0542.html", "poster": "../posters/0542.svg"}, {"id": "0543", "title": "地平线系列：我们为什么胖", "year": 2025, "region": "英国", "type": "纪录片", "genre": "纪录, 科普", "tags": ["BBC", "科学", "减肥", "生物学"], "summary_short": "地平线系列：我们为什么胖，2025年英国纪录片，纪录, 科普。在这个纪录片中，主持人兼生物学博士贾尔斯·杨不再谈论意志力，而是深入人体内部。他通过“粪便移植”实验，证明了肠道菌群是如何像黑帮一样操控大脑去渴望甜甜圈的。他造访了瑞典的“饥饿激素”实验室，看到了一种能让胃部切除了四分之三的病患依然感到饥饿的可怕化学物质。为了验证“节俭基因”假说，他甚至去参加了一场针对肥胖者的核磁共振脑部扫描，惊讶地发现，胖子在看到食物时，大脑奖励中枢的活跃", "score": 2025075, "category": "doc", "detail_url": "../movie/0543.html", "poster": "../posters/0543.svg"}, {"id": "0544", "title": "渔村春色", "year": 1987, "region": "中国台湾", "type": "电影", "genre": "爱情, 乡土", "tags": ["怀旧", "禁忌之恋", "渔港风情", "闽南语"], "summary_short": "渔村春色，1987年中国台湾电影，爱情, 乡土。1986 年的澎湖，刚从基隆渔业学校毕业的阿青回到望安岛，准备继承父业。他遇见了邻居阿芬，阿芬的丈夫远洋捕鱼失踪三年，法律上已是“推定死亡”，但婆婆不允许她改嫁。阿青教阿芬用新的渔网技术，两人在整理渔具的黄昏中互生情愫。全村人都看在眼里，闲话像疯长的仙人掌。阿芬的婆婆用自杀威胁，阿青的父亲则打算把他再送到马祖。在一个暴雨之夜，阿芬怀孕的消息传开，家族宗祠前要对两人“浸猪笼”惩罚。最后是阿芬", "score": 1987340, "category": "romance", "detail_url": "../movie/0544.html", "poster": "../posters/0544.svg"}, {"id": "0545", "title": "梦醒哈瓦那", "year": 2024, "region": "古巴 / 西班牙", "type": "电影", "genre": "剧情 / 音乐", "tags": ["时空交错，人生重启，古巴风情"], "summary_short": "梦醒哈瓦那，2024年古巴 / 西班牙电影，剧情 / 音乐。2024年，房地产老板陈昆在哈瓦那因资金链断裂欲跳楼，失足坠落后昏迷。醒来发现自己穿越到1958年的古巴，附身在当地最负盛名的黑人钢琴师卡洛斯身上。他经历了革命前夕最后的纸醉金迷，也爱上了卡洛斯的女友——一名女革命者。当他成功用现代商业思维帮卡洛斯摆脱黑帮控制后，一颗子弹穿过胸口，他又“醒”回2024年。不同的是，他手里多了一张1958年拍摄的照片，照片里他正搂着那个女孩，在哈", "score": 2024310, "category": "drama", "detail_url": "../movie/0545.html", "poster": "../posters/0545.svg"}, {"id": "0546", "title": "酷爱电影的庞波小姐", "year": 2021, "region": "日本", "type": "电影 (动画)", "genre": "喜剧 / 剧情", "tags": ["电影制作", "梦想", "讽刺"], "summary_short": "酷爱电影的庞波小姐，2021年日本电影 (动画)，喜剧 / 剧情。庞波小姐是好莱坞B级片女王，只拍肌肉、爆炸和僵尸。某天她突然宣布要拍一部冲奥文艺片：黑白画面，长镜头，无配乐。全公司觉得她疯了。新人导演吉恩被强行推上马，演员是过气老戏骨和刚出道的地下偶像。拍摄过程混乱不堪：投资人撤资，编剧罢工，主演打架。然而当粗剪版出来时，所有人都沉默了——那是一部关于电影如何杀死电影人的血腥寓言。庞波小姐笑着宣布：这才是我最想要的B级片。", "score": 2021321, "category": "fantasy", "detail_url": "../movie/0546.html", "poster": "../posters/0546.svg"}, {"id": "0547", "title": "艾诺拉", "year": 2024, "region": "芬兰", "type": "电影", "genre": "剧情 / 音乐", "tags": ["传记", "西贝柳斯", "女性视角", "古典乐"], "summary_short": "艾诺拉，2024年芬兰电影，剧情 / 音乐。艾诺拉本是贵族小姐，却不顾家人反对嫁给了穷音乐家让·西贝柳斯。她为他抄乐谱、养孩子、应付债主，甚至卖掉嫁妆购买钢琴。当西贝柳斯沉迷酒精和出轨，艾诺拉想过离开。但在他们命名的“艾诺拉之家”，她听到丈夫正在创作《芬兰颂》的片段，那旋律如同森林和湖泊的呼吸。她决定留下，用一生守护这个天才的灵感。电影采用大量实景拍摄，穿插西贝柳斯交响乐，结尾是艾诺拉独白：“我爱他，所以我从未拥有过自己。”", "score": 2024311, "category": "drama", "detail_url": "../movie/0547.html", "poster": "../posters/0547.svg"}, {"id": "0548", "title": "捣乱剧团的婚礼", "year": 2023, "region": "日本", "type": "剧集", "genre": "喜剧, 爱情, 剧情", "tags": ["剧团", "假结婚", "修罗场", "治愈"], "summary_short": "捣乱剧团的婚礼，2023年日本剧集，喜剧, 爱情, 剧情。三流剧团“樱桃社”面临解散危机，剧场老板要将地皮卖给开发商。团长千秋突发奇想，谎称剧团主演阿晃要和人气女星结婚，以此骗取粉丝礼金和赞助商投资。他们全员出动，把破旧的剧场布置成豪华婚宴现场。没想到，消息走漏后，阿晃的三个前女友同时到场闹事，暗恋千秋的金主也跑来求婚，甚至收高利贷的黑帮也来凑热闹。婚礼现场乱成一锅粥，谎言一个接一个被戳穿。就在众人绝望时，一直默默无闻的剧务小胖拿起话筒", "score": 2023351, "category": "series", "detail_url": "../movie/0548.html", "poster": "../posters/0548.svg"}, {"id": "0549", "title": "幸福大冲撞", "year": 2024, "region": "法国 / 比利时", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["公路", "家庭闹剧", "误会", "温暖"], "summary_short": "幸福大冲撞，2024年法国 / 比利时电影，喜剧 / 家庭。为了庆祝父母结婚40周年，性格迥异的一家人踏上前往西班牙的房车之旅。父亲是控制狂，母亲是迷糊蛋，大儿子是焦虑的准爸爸，大女儿是激进的环保主义者，小儿子是无厘头的网红。出发第一天，他们就因导航错误开进农田。随后，爆胎、丢钥匙、误闯斗牛场、把圣母像当成邮筒、在边境被误认为毒贩……一连串乌龙事件接踵而至。每到一个地方，他们都会因为各自的性格爆发争吵，但又不得不团结起来解决麻烦。在一次", "score": 2024311, "category": "comedy", "detail_url": "../movie/0549.html", "poster": "../posters/0549.svg"}, {"id": "0550", "title": "娜露和贝塔", "year": 2025, "region": "瑞典", "type": "剧集", "genre": "剧情 / 科幻 / 青少年", "tags": ["克隆人", "伦理科幻", "北欧冷科幻"], "summary_short": "娜露和贝塔，2025年瑞典剧集，剧情 / 科幻 / 青少年。近未来瑞典，人类和克隆人共存但从未平等。少女娜露考入精英预科学校，被分配到一间双人宿舍，室友贝塔沉默寡言，手腕上有一串永不消失的编号纹身。某夜，娜露无意中扫描了贝塔的虹膜，数据库显示：贝塔于三年前“出厂”，模板是一位天才小提琴手，但模板本人在一次事故中植物人。娜露逐渐发现，整栋宿舍楼里所有“性格怪异”的学生都是克隆人，他们都是同一项名为“觉醒计划”的实验品——科学家想测试克隆人", "score": 2025332, "category": "series", "detail_url": "../movie/0550.html", "poster": "../posters/0550.svg"}, {"id": "0551", "title": "解放1：炮火弧线", "year": 1970, "region": "苏联", "type": "电影", "genre": "战争, 史诗", "tags": ["二战", "大场面", "实录感"], "summary_short": "解放1：炮火弧线，1970年苏联电影，战争, 史诗。作为《解放》五部曲的开篇，本片聚焦于库尔斯克弧形战线这一二战转折点。影片不仅展现了苏德双方最高统帅部的战略博弈，更将镜头深入前线战壕。一名刚从坦克学校毕业的年轻车长，在普罗霍罗夫卡遭遇战中，亲历了上千辆坦克钢铁碰撞的修罗场。炮火划出的弧线照亮了半边天，士兵们在燃烧的坦克中爬出继续用手枪战斗。影片没有绝对的主角，真正的英雄是那些在钢铁洪流中坚守“一步不退”的普通士兵，为后续反攻柏林拉开序", "score": 1970275, "category": "doc", "detail_url": "../movie/0551.html", "poster": "../posters/0551.svg"}, {"id": "0552", "title": "猫屎妈妈粤语", "year": 2023, "region": "中国香港", "type": "剧集", "genre": "剧情 / 家庭", "tags": ["粤语", "咖啡", "母女", "港剧"], "summary_short": "猫屎妈妈粤语，2023年中国香港剧集，剧情 / 家庭。“猫屎妈妈”是城中最任性的咖啡师阿珍的外号。她突然失智失味，咖啡馆面临倒闭。在国外学金融的女儿阿欣被迫回港接手。阿欣不懂咖啡，只想卖掉店铺变现。在整理遗物时，她发现了母亲的手写笔记，上面记录了各种奇葩“秘方”——其实都是当年为了养活她而做的妥协。阿欣开始学着母亲的样子烘焙豆子，在一次次的失败中，她尝到了母亲当年的辛苦与甘甜。最终，她保留了咖啡馆，并研发出了一款“女儿的味道”新咖啡。", "score": 2023242, "category": "series", "detail_url": "../movie/0552.html", "poster": "../posters/0552.svg"}, {"id": "0553", "title": "大富翁世界旅行", "year": 2023, "region": "中国台湾", "type": "剧集", "genre": "喜剧、冒险、真人秀式剧集", "tags": ["桌游改编、环球、暴富、荒诞、慈善"], "summary_short": "大富翁世界旅行，2023年中国台湾剧集，喜剧、冒险、真人秀式剧集。阿乐、小美等五个互不相识的年轻人，同时出现在一个已故神秘富豪的葬礼上。律师告诉他们，富豪没有后代，唯一的遗产就是一套黄金打造的大富翁棋盘和一颗骰子。当他们半信半疑地掷下骰子时，瞬间被传送到了东京。他们必须在当地完成棋盘上的“买地”、“盖房”或“抽机会卡”等任务，才能继续掷骰子前往下一个国家。随着旅行推进，他们发现这实际上是富豪设计的终极人性考验——在巴黎，他们因为贪婪差点", "score": 2023234, "category": "series", "detail_url": "../movie/0553.html", "poster": "../posters/0553.svg"}, {"id": "0554", "title": "巴黎妓院回忆录", "year": 2029, "region": "法国", "type": "电视剧", "genre": "剧情, 历史", "tags": ["妓院", "19世纪", "群像", "女性"], "summary_short": "巴黎妓院回忆录，2029年法国电视剧，剧情, 历史。故事发生在1897年巴黎蒙马特的一间高级妓院“天堂阁”。这里不仅是欲望的交易所，更是女性命运的缩影。剧集以群像形式展开：有被母亲卖来的乡下少女、有为了供弟弟上学而堕入风尘的知识女性、还有50岁仍在接客的老妓。纪录片式的镜头记录了她们的生活：反抗残酷的老鸨、争夺富商的宠爱、互相堕胎、以及染上梅毒后被扔进贫民窟的结局。当警方试图以卫生法关闭妓院时，女人们联合起来，利用她们偷听到的政商秘密作", "score": 2029181, "category": "series", "detail_url": "../movie/0554.html", "poster": "../posters/0554.svg"}, {"id": "0555", "title": "东京24区", "year": 2024, "region": "日本", "type": "剧集", "genre": "悬疑、科幻、犯罪", "tags": ["近未来、模拟灾害、道德困境、政治阴谋"], "summary_short": "东京24区，2024年日本剧集，悬疑、科幻、犯罪。2042年，东京湾新建的人工岛“第24区”是日本最先进的智能都市，居民都佩戴着能预测灾害的“守护者”手环。一场罕见的“模拟海啸”精准袭击了手环评分最低的区域，造成千人死亡。年轻的区长助理翔太发现，手环的真正功能不是预测灾害，而是通过大数据计算每个人的“社会贡献值”，系统会自动清除“低价值人群”。翔太召集了同样失去亲人的骇客、自卫队士兵和议员秘书，组成反抗军。他们要赶在下一场“台风”来临之", "score": 2024403, "category": "series", "detail_url": "../movie/0555.html", "poster": "../posters/0555.svg"}, {"id": "0556", "title": "紧张大师", "year": 2019, "region": "中国香港", "type": "电影", "genre": "惊悚/喜剧", "tags": ["强迫症", "炸点", "片场", "连环意外"], "summary_short": "紧张大师，2019年中国香港电影，惊悚/喜剧。绰号“紧张大师”的导演陈不开，对每个镜头都要求精确到毫秒，逼疯全剧组。一次拍爆炸戏时，他意外录到黑帮杀人灭口的对话。杀手组织随即渗透片场，打算在实拍中制造“意外”干掉他。陈不开误以为是新来的场务在故意打乱他的调度表来挑战专业度，于是强迫症发作，将计就计，用威亚、滑轮、汽油桶和数百个炸点，把整个片场改造成一个精密到变态的连环陷阱。真杀手们被这些匪夷所思的“机位走位”玩得团团转，而陈不开直到最后", "score": 2019316, "category": "comedy", "detail_url": "../movie/0556.html", "poster": "../posters/0556.svg"}, {"id": "0557", "title": "人间规则", "year": 2026, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 悬疑", "tags": ["公关行业，道德困境，女性成长，职场博弈，单元剧"], "summary_short": "人间规则，2026年中国大陆电视剧，剧情 / 悬疑。公关专家林曦从未失手，她的铁律是“真相不重要，赢才重要”。新客户是涉嫌数据造谣的科技新贵，而爆料人竟是多年未见的记者初恋苏沐。林曦利用舆论倒打一耙，将苏沐塑造成嫉妒的失败者。就在她即将胜利时，苏沐拿出了她大学时期参与灰色公关的铁证——原来这是一场针对她的复仇布局。林曦被迫在“人间规则”与良知间撕扯，最终选择公开所有黑料，包括自己的。她输了事业，却换来了与苏沐的和解，以及一个更干净的行业", "score": 2026356, "category": "series", "detail_url": "../movie/0557.html", "poster": "../posters/0557.svg"}, {"id": "0558", "title": "键到鬼", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "恐怖，惊悚", "tags": ["灵异，电脑，网络直播，诅咒"], "summary_short": "键到鬼，2024年中国台湾电影，恐怖，惊悚。社畜阿伟为了省钱，在跳蚤市场买了一个老旧的机械键盘。第一天上班，他习惯性按下F5刷新页面，瞬间看到对面工位的王姐身后趴着一个浑身焦黑的小孩，而王姐正在抱怨办公室空调太冷。阿伟吓坏了，开始小心避让鬼魂，却发现自己成了“天选打工人”——他知道哪个角落死过人，知道老板身后的女鬼什么时候发怒。他试图用这些信息帮助同事避祸，却因为行为诡异被当成变态。直到他发现，那个缠着王姐的小孩鬼魂，其实是因为键盘里封", "score": 2024429, "category": "horror", "detail_url": "../movie/0558.html", "poster": "../posters/0558.svg"}, {"id": "0559", "title": "超人大战极英盟", "year": 2026, "region": "美国", "type": "电影", "genre": "动作 / 科幻 / 超级英雄", "tags": ["反英雄", "道德困境", "硬核打斗", "政治隐喻"], "summary_short": "超人大战极英盟，2026年美国电影，动作 / 科幻 / 超级英雄。超人在拦截一架失控客机时，为了不让飞机撞向核电站，用身体硬扛机头，导致驾驶舱被挤压变形，一名副机长当场死亡。虽然救了全城，但死者家属起诉超人过失杀人。“极英盟”应运而生——六名没有超能力的普通人，凭借高科技装备和外星武器，宣布要逮捕超人并公开审判。超人不愿还手，接连被电磁脉冲、红太阳辐射和纳米锁链压制。然而极英盟的真实目的并非审判，而是提取超人的基因，制造可控的超级士兵。", "score": 2026376, "category": "crime", "detail_url": "../movie/0559.html", "poster": "../posters/0559.svg"}, {"id": "0560", "title": "春暖花开的时候", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "年代 / 家庭", "tags": ["知青，改革开放，乡土中国，群像剧"], "summary_short": "春暖花开的时候，2025年中国大陆剧集，年代 / 家庭。1978年春，黑龙江靠山屯。知青林红收到返城通知，却发现已怀上当地青年的孩子；村支书儿子赵大壮放弃高考，一心要搞家庭联产承包；上海知青陈明连续两次落榜，第三次备考时父亲病危；寡妇刘桂兰偷偷学做生意被举报投机倒把……七个二十出头的年轻人，站在时代的岔路口。本剧用40集体量，以靠山屯为缩影，讲述1978-1984年间中国农村的巨变。有人考上大学成为律师，有人下海经商成万元户，有人留守乡", "score": 2025176, "category": "series", "detail_url": "../movie/0560.html", "poster": "../posters/0560.svg"}, {"id": "0561", "title": "苏维埃加电", "year": 2023, "region": "俄罗斯", "type": "电影", "genre": "科幻, 悬疑", "tags": ["苏联", "超自然", "冷战", "阴谋"], "summary_short": "苏维埃加电，2023年俄罗斯电影，科幻, 悬疑。冷战时期，苏联在切尔诺贝利禁区附近建立了一个秘密实验室，代号“加电”，试图通过极端电磁场刺激人脑，从而开发超感官士兵。实验失败，基地被废弃。几十年后，一支国际纪录片摄制组为了拍摄“苏联废墟”题材，非法闯入该基地。他们重启了老化设备，一道诡异的蓝光闪过之后，基地内部的物理法则似乎发生了改变：重力失常、时间倒流、甚至能看到身着苏联军装的“幽灵”。成员一个接一个失踪，而幸存者发现，这些超自然现象", "score": 2023391, "category": "crime", "detail_url": "../movie/0561.html", "poster": "../posters/0561.svg"}, {"id": "0562", "title": "浮石传", "year": 2023, "region": "中国大陆", "type": "电视剧", "genre": "古装 / 奇幻", "tags": ["仙侠修真", "反套路", "废柴逆袭", "轻喜剧"], "summary_short": "浮石传，2023年中国大陆电视剧，古装 / 奇幻。修真界最底层弟子林安，偶然捡到一块能在水面漂浮的奇特石头。石头自称“浮石上仙”，是万年前被封印的大能，要收林安为徒。然而浮石教的功法都极其奇葩：剑法像跳舞，心法像说梦话，炼丹更是黑暗料理。林安在全宗嘲笑中修炼，却意外发现这些看似荒诞的功法，恰恰能克制正道法术。随着魔教入侵，正道高手纷纷落败，林安用浮石教的“无用”之术，将魔教大军耍得团团转。而那块浮石，也终于露出了它真正的、颠覆三界的来历", "score": 2023301, "category": "series", "detail_url": "../movie/0562.html", "poster": "../posters/0562.svg"}, {"id": "0563", "title": "疯狂婚礼周", "year": 2018, "region": "美国", "type": "电影", "genre": "喜剧， 爱情", "tags": ["婚礼， 家庭闹剧， 婚前焦虑， 公路喜剧"], "summary_short": "疯狂婚礼周，2018年美国电影，喜剧， 爱情。道格即将迎娶名门闺秀梅兰妮，但婚礼前一周简直是噩梦。第一天，岳父要求他完成三项“家族传统挑战”：徒手抓鱼、跳伞、和岳父的拳击教练对打。第二天，他的伴郎团——一群大学死党——把他灌醉后纹了一个巨大的、梅兰妮最讨厌的海豚纹身。第三天，前女友突然出现在小镇，声称要“祝福”他们，实则处处捣乱。第四天，道格发现岳父的公司涉嫌非法募捐，而自己是签字人之一。第五天，婚礼场地被隔壁的摩托车党集会噪音淹没。第", "score": 2018348, "category": "comedy", "detail_url": "../movie/0563.html", "poster": "../posters/0563.svg"}, {"id": "0564", "title": "特蕾莎：死亡与生命", "year": 2025, "region": "英国", "type": "电影", "genre": "传记, 剧情", "tags": ["修女", "信仰", "人性争议"], "summary_short": "特蕾莎：死亡与生命，2025年英国电影，传记, 剧情。影片聚焦于特蕾莎修女晚年的内心挣扎。在公众面前，她是加尔各答天使，是诺贝尔和平奖得主；但在长达半个世纪的时间里，她写给精神导师的私人信件被教会封存。本片首次基于解密的书信，展现了一个截然不同的特蕾莎：她感受不到上帝的存在，深陷于被神抛弃的“灵魂暗夜”中，怀疑天堂是否真实，甚至质疑自己一生的劳苦是否有意义。故事通过她访问战火中的贝鲁特、救助濒死者的经历，穿插她日记中那些绝望的独白，探讨", "score": 2025234, "category": "drama", "detail_url": "../movie/0564.html", "poster": "../posters/0564.svg"}, {"id": "0565", "title": "无名伟人", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情 / 历史", "tags": ["两弹一星", "牺牲", "奉献", "真实改编", "催泪"], "summary_short": "无名伟人，2023年中国大陆电影，剧情 / 历史。物理学家陈怀远在1959年被秘密调入戈壁滩，参与原子弹研制。他与妻子约定“等我回来”，却在一次意外辐射事故中为了抢出核心数据而受到致命辐射。1964年10月16日，原子弹爆炸成功，同一天，妻子收到部队通知：陈怀远因公牺牲，地址不详、死因不详、骨灰不详。她在戈壁边缘等了二十年，直到老战友送来一封信，信里只有一句话：“我看见了蘑菇云，很美。”", "score": 2023261, "category": "drama", "detail_url": "../movie/0565.html", "poster": "../posters/0565.svg"}, {"id": "0566", "title": "祝祭", "year": 2016, "region": "日本", "type": "电影", "genre": "剧情, 家庭, 文艺", "tags": ["丧子之痛", "祭典", "重生", "日式美学", "静谧绝望"], "summary_short": "祝祭，2016年日本电影，剧情, 家庭, 文艺。一年前，独生子小勇在海边溺亡。摄影师丈夫和家庭主妇妻子陷入了各自的绝望，家里空气凝固到令人窒息。一年后，小镇的夏日祭典如期而至，这是小勇生前最期待的节日。妻子提议，像往年一样去参加祭典，当作跟小勇的最后一次告别。祭典上，他们买烤鱿鱼，捞金鱼，看烟花，仿佛一切都没变。当烟花在夜空炸开的那一刻，两人终于抱头痛哭。回家后，他们把小勇的房间收拾干净，生活，还要继续。", "score": 2016307, "category": "drama", "detail_url": "../movie/0566.html", "poster": "../posters/0566.svg"}, {"id": "0567", "title": "占领自由邦", "year": 2025, "region": "南非", "type": "电影", "genre": "动作 / 科幻 / 政治", "tags": ["反乌托邦", "资源战争", "佣兵觉醒"], "summary_short": "占领自由邦，2025年南非电影，动作 / 科幻 / 政治。2071年，南非自由邦省因干旱和债务破产，被“寰球安保公司”接管。农民丹尼尔拒绝出售祖地，他的儿子被公司无人机炸死。丹尼尔集结了一批老年退伍军人和愤怒的年轻人，用自制的炸弹和改装拖拉机对抗高科技。公司派出一支全副武装的机械佣兵小队，却陷入了人民战争的泥潭。当丹尼尔最终冲进公司总部，发现CEO竟是30年前被流放的白人至上主义者的后代。这场战争不再是土地，而是关于谁定义“自由”。", "score": 2025351, "category": "sci-fi", "detail_url": "../movie/0567.html", "poster": "../posters/0567.svg"}, {"id": "0568", "title": "毙夜旅行", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "悬疑", "tags": ["公路", "犯罪", "黑色幽默", "反转"], "summary_short": "毙夜旅行，2023年中国大陆电影，悬疑。春节前夕，回乡的顺风车上挤了三个陌生人：欠债的包工头、被裁员的白领、逃婚的富家女。他们在服务区捡到一个无人认领的行李箱，打开后发现里面是一具尸体和一千万。三人决定分钱埋尸，结果尸体半夜坐了起来——原来他是假死，钱是他从黑帮偷的。黑帮、警察、死者家属三方追来，一场啼笑皆非的公路逃亡开始了。", "score": 2023345, "category": "crime", "detail_url": "../movie/0568.html", "poster": "../posters/0568.svg"}, {"id": "0569", "title": "雌雌大盗", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "喜剧, 犯罪, 动作", "tags": ["女贼", "姐妹情", "公路", "乌龙", "逆袭"], "summary_short": "雌雌大盗，2021年中国大陆电影，喜剧, 犯罪, 动作。江湖人称“千面狐”的骗术高手红姐遭遇滑铁卢，被同行陷害成了通缉犯。走投无路时，她遇到了一个偷钱包永远只会偷同一款式的菜鸟女扒手“小麻雀”。两人组成了史上最不靠谱的“雌雌大盗”，抢银行误入健身房、偷珠宝偷到假货店、跑路跑进警察局的表彰大会。她们的目标是找到陷害红姐的黑道大佬“九爷”，偷走他手中的犯罪证据。一路上，红姐教小麻雀骗术，小麻雀用她的“笨”一次次误打误撞地帮红姐化解危机。她们", "score": 2021372, "category": "crime", "detail_url": "../movie/0569.html", "poster": "../posters/0569.svg"}, {"id": "0570", "title": "漂流拯救队", "year": 2025, "region": "日本", "type": "动画电影", "genre": "冒险, 灾难, 友情", "tags": ["海上漂流", "团队生存", "治愈", "手绘风"], "summary_short": "漂流拯救队，2025年日本动画电影，冒险, 灾难, 友情。夏令营返程途中，游轮遭遇风暴沉没。五年级的翔太、小光、美咲、阿健、莉子以及一只柴犬“小八”漂到一座从未被标注的岛屿。没有大人，没有信号，只有一艘破损的救生筏。他们决定自己造船回家。用椰子纤维搓绳、用贝壳当锯子、用树脂防水。过程中，有人感染高烧，有人差点被鳄鱼拖走，甚至因为分食物爆发过信任危机。两个月后，他们造出一艘勉强能出海的帆船。出海第三天被货轮救起。回到文明世界后，五个孩子再", "score": 2025229, "category": "fantasy", "detail_url": "../movie/0570.html", "poster": "../posters/0570.svg"}, {"id": "0571", "title": "湾区儿女", "year": 2020, "region": "中国", "type": "电视剧", "genre": "剧情、爱情", "tags": ["粤港澳大湾区、创业奋斗、家族恩怨、时代变迁、小人物"], "summary_short": "湾区儿女，2020年中国电视剧，剧情、爱情。故事始于澳门回归前夕，疍家女麦斯钰在码头长大，一心想改变命运。她结识了来自香港的创业青年黄梓健，两人并肩投身LED照明产业，见证着港珠澳大桥从无到有。在湾区政策红利下，麦斯钰从打工妹成长为科技公司创始人，过程中经历了家庭反对、技术壁垒和资本围剿。她的青梅竹马梁家明因家族走私案与她分道扬镳，成为事业上的劲敌。剧情跨越二十年，展现了澳门大学横琴校区、珠海航空展等标志性事件。最终，麦斯钰不仅化解了与", "score": 2020275, "category": "series", "detail_url": "../movie/0571.html", "poster": "../posters/0571.svg"}, {"id": "0572", "title": "我想我是基", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "爱情，剧情，同性", "tags": ["同性，自我认同，青春，友情，台湾"], "summary_short": "我想我是基，2023年中国台湾电影，爱情，剧情，同性。高中生陈杰一直过着普通的日子，有个暗恋的女生，有一群打篮球的兄弟。转学生林杰的出现打破了一切。林杰阳光、帅气、温柔，很快成为学校风云人物。陈杰发现自己莫名其妙地关注林杰的一举一动，看到林杰和女生说话会吃醋，梦到林杰会脸红心跳。他开始疯狂搜索“怎么判断自己是不是同性恋”，甚至下载了交友软件。在好友鼓励下，陈杰终于鼓起勇气向林杰表白。林杰却告诉他，自己已经有一个异地恋男朋友了。陈杰备受打", "score": 2023341, "category": "drama", "detail_url": "../movie/0572.html", "poster": "../posters/0572.svg"}, {"id": "0573", "title": "我唾弃你的坟墓：既视感", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖, 惊悚, 悬疑", "tags": ["重启", "时间循环", "女性复仇"], "summary_short": "我唾弃你的坟墓：既视感，2024年美国电影，恐怖, 惊悚, 悬疑。摄影师米娅在小镇旅馆遭遇袭击身亡，但她却再次在清晨的阳光中醒来。时间回到了死亡当天早晨。米娅以为这是第二次机会，她避开了上次的陷阱，却在当晚被另一个陌生人以不同方式杀害。第三次、第四次……每次复活，凶手都会换人，而且每个人都声称不认识她。米娅逐渐意识到，这不是单纯的谋杀，而是一场精心设计的游戏——小镇上的每个居民都被植入了杀死她的指令。在第N次循环中，她不再逃跑，而是开始", "score": 2024471, "category": "crime", "detail_url": "../movie/0573.html", "poster": "../posters/0573.svg"}, {"id": "0574", "title": "迈克尔·彻：事关紧要", "year": 2022, "region": "美国", "type": "脱口秀", "genre": "单口喜剧", "tags": ["政治不正确", "社会观察", "黑色幽默", "日常荒诞"], "summary_short": "迈克尔·彻：事关紧要，2022年美国脱口秀，单口喜剧。这是迈克尔·彻脱离《周六夜现场》周末更新台后首个个人专场。现场设在他老家新泽西一家只有八十个座位的地下俱乐部。他全程穿一件皱巴巴的运动衫，像跟老友聊天一样抛出一系列“不重要但事关紧要”的话题：为什么女人能在五分钟内决定换城市而男人花一小时找不到遥控器；社交媒体上的“紧急消息”和急诊室的分诊台逻辑一模一样；以及他最经典的那段——关于纽约市长说“生活恢复正常”和白人邻居偷偷问他“治安是不", "score": 2022154, "category": "comedy", "detail_url": "../movie/0574.html", "poster": "../posters/0574.svg"}, {"id": "0575", "title": "小袋鼠戴茜", "year": 2023, "region": "澳大利亚 / 美国", "type": "电影", "genre": "动画 / 家庭", "tags": ["冒险", "成长", "动物保护"], "summary_short": "小袋鼠戴茜，2023年澳大利亚 / 美国电影，动画 / 家庭。山火摧毁了戴茜的家园，妈妈临终前将一个旧铁盒交给她，告诉她只有找到住在“月亮井”的外婆才能打开。戴茜不知道，铁盒里装的是一份土地权属证明，关乎整个袋鼠群族的栖息地。在路途中，她遇到了一只话痨的笑翠鸟和一只视力不好的针鼹，三个小家伙组成临时小队。他们躲过野狗、穿过沙暴，还误入了一个人类矿区。戴茜从胆小爱哭逐渐变得坚强。当她终于找到外婆时，发现外婆早已失明，但一直在等这封信。最后", "score": 2023200, "category": "fantasy", "detail_url": "../movie/0575.html", "poster": "../posters/0575.svg"}, {"id": "0576", "title": "眠狂四郎女地狱", "year": 2025, "region": "日本", "type": "电影", "genre": "动作 / 剧情 / 情色", "tags": ["时代剧， 剑戟片， 女性复仇"], "summary_short": "眠狂四郎女地狱，2025年日本电影，动作 / 剧情 / 情色。本片是经典“眠狂四郎”系列的重启。狂四郎因过去误杀一名无辜少女而深陷愧疚，流落到一座被恶代官统治的城镇。他发现当地代官建立了一个“女地狱”，专门贩卖和虐待女子。让狂四郎震惊的是，策划复仇的正是那个被他误杀少女的姐姐，她以出卖灵魂为代价成了代官的情妇，从内部瓦解其势力。狂四郎无法拒绝她的请求，他挥舞着盲剑，在无法看见的黑暗中，用“圆月杀法”斩破所有敌人。但这次，他斩出的不仅是剑", "score": 2025368, "category": "drama", "detail_url": "../movie/0576.html", "poster": "../posters/0576.svg"}, {"id": "0577", "title": "地球分裂", "year": 2027, "region": "美国", "type": "电影", "genre": "科幻 / 灾难", "tags": ["末日", "地心", "生存", "硬科幻"], "summary_short": "地球分裂，2027年美国电影，科幻 / 灾难。2035年，科学家在马里亚纳海沟启动“点燃地核”计划来解决能源危机，却导致地幔对流失控。格陵兰岛一天内分裂成两半，东京被海啸吞没。前NASA工程师杰克在太空站“圆满号”上目睹这一切。地面幸存者包括杰克的前妻、地质学家林娜，她被困在正在分裂的东非大裂谷。杰克发现，只要将太空站上的特定频率电磁波对准地核，可以平息振荡。但太空站的能源只够发射一次。为了给林娜所在的营地争取逃脱时间，杰克决定牺牲太空", "score": 2027321, "category": "sci-fi", "detail_url": "../movie/0577.html", "poster": "../posters/0577.svg"}, {"id": "0578", "title": "春光猎影", "year": 1997, "region": "中国香港", "type": "电影", "genre": "剧情 / 爱情 / 文艺", "tags": ["摄影", "禁忌之恋", "香港回归前夕", "怀旧", "朦胧美"], "summary_short": "春光猎影，1997年中国香港电影，剧情 / 爱情 / 文艺。阿忠是一个坚持使用老式胶片相机的人，在数码相机开始普及的年代，他显得有些格格不入。为了生计，他接了一个私活：跟踪拍摄某位神秘女子的日常。在维多利亚港的晨光里，在旺角的霓虹灯下，阿忠透过镜头发现这个女人不仅美得惊心动魄，眼神里更是充满了忧伤。他渐渐爱上了镜头里的人，却发现自己只是在为黑帮老大记录妻子的出轨证据。那个女人的丈夫即将跑路去加拿大，想在临走前清算一切。当阿忠意识到自己所", "score": 1997350, "category": "drama", "detail_url": "../movie/0578.html", "poster": "../posters/0578.svg"}, {"id": "0579", "title": "桃乐丝·罗奇的恐惧", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖， 惊悚， 心理", "tags": ["密室， 心理崩溃， 身体恐怖， 独角戏"], "summary_short": "桃乐丝·罗奇的恐惧，2025年美国电影，恐怖， 惊悚， 心理。桃乐丝·罗奇是城市清洁公司的一名夜班清洁工，负责清扫一所即将被拆除的废弃精神病院。某个雨夜，她被反锁在位于地下二层、散发腐臭味的盥洗室内。起初她只是焦急地等待救援，但很快，盥洗室的灯开始频闪，水龙头流出黑色黏液。更诡异的是，她发现镜中的自己不再模仿她的动作。那个“镜中桃乐丝”开始对她低语，揭露她深埋心底的童年创伤和对未来的极度恐惧。桃乐丝必须在自己被恐惧彻底吞噬前，找出逃出这", "score": 2025420, "category": "horror", "detail_url": "../movie/0579.html", "poster": "../posters/0579.svg"}, {"id": "0580", "title": "甲方乙方", "year": 1997, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["好梦一日游，圆梦，荒诞，京味儿幽默"], "summary_short": "甲方乙方，1997年中国大陆电影，喜剧 / 剧情。姚远、周北雁、钱康、梁子四个自由职业者突发奇想，开了一家“好梦一日游”公司，专门为客户定制各种梦想体验。他们帮卖瓜的板儿爷圆了将军梦，帮书商圆了吃苦梦，帮大款圆了贫困梦，帮失恋青年圆了英雄救美梦。每个梦都荒诞又真实，客户们在体验后反而更加清醒地认识了自己。后来，一位患癌的妻子想圆“房子梦”，四人毫不犹豫地把自己的公司装修房借给她。故事的最后，房子没有“圆梦”成功，但善意却留了下来。好梦一", "score": 1997343, "category": "drama", "detail_url": "../movie/0580.html", "poster": "../posters/0580.svg"}, {"id": "0581", "title": "埃洛伊塞", "year": 2009, "region": "西班牙", "type": "电影", "genre": "悬疑, 同性", "tags": ["修道院", "历史迷案", "禁恋", "宗教审判", "双时间线"], "summary_short": "埃洛伊塞，2009年西班牙电影，悬疑, 同性。巴塞罗那古修复师艾琳娜收到一具修女遗骸，要求她在展览前完成修复。遗骸的每一节脊椎骨上都有极其微小的刺青字母，拼起来是一段拉丁文诅咒。艾琳娜追查史料，发现修女名叫埃洛伊塞，1734年因“与魔鬼交媾”被教会处决。但刺青实际上是埃洛伊塞与恋人——另一位修女克拉拉发明的秘密文字，内容是一段隐修院宝藏的地图。教会当年为了掩盖宝藏与同性丑闻，将埃洛伊塞活活烧死，而克拉拉被迫作伪证后疯癫至死。艾琳娜在修复", "score": 2009293, "category": "crime", "detail_url": "../movie/0581.html", "poster": "../posters/0581.svg"}, {"id": "0582", "title": "越堕落越英雄", "year": 1998, "region": "香港", "type": "电影", "genre": "犯罪 / 动作 / 爱情", "tags": ["黑帮", "兄弟情", "悲剧", "枪战", "情欲"], "summary_short": "越堕落越英雄，1998年香港电影，犯罪 / 动作 / 爱情。阿豪和阿杰是金牌杀手，情同手足。阿杰在一次任务中救下神秘女子阿玲，两人相恋，却发现阿玲其实是老大的情妇。老大设局让阿杰误以为阿豪与阿玲有染，兄弟反目。最终大战中，阿杰中枪，阿豪为救他亲手杀死老大，两人带着阿玲逃亡。在一个暴雨夜晚，阿玲坦白她从一开始就是警方卧底，接近他们是为了收集罪证。阿豪惨笑，替阿玲挡了追来的黑帮子弹。阿杰抱着死去的阿豪，对阿玲说：“走吧，你自由了。”然后开枪", "score": 1998419, "category": "crime", "detail_url": "../movie/0582.html", "poster": "../posters/0582.svg"}, {"id": "0583", "title": "黑塔利亚第五季", "year": 2024, "region": "日本", "type": "动漫", "genre": "喜剧/历史恶搞", "tags": ["拟人", "泡面番", "政治笑话", "日常"], "summary_short": "黑塔利亚第五季，2024年日本动漫，喜剧/历史恶搞。本季延续了系列一贯的轻松恶搞风格，将世界各国拟人化。这一次，世界会议变成了一场大型综艺游戏秀，轴心国与同盟国被迫组队参加“全球生存大挑战”。从在北极圈搭帐篷到在亚马逊河底捞手机，国家意识体们不仅要面对恶劣的自然环境，还要时刻提防队友的背刺。意大利再次展示了用意面修坦克的神技，而德国则因为队友的废柴表现提前进入了中年秃顶危机。本季新增的“互联网战争”单元更是让宅男们狂喜，网络巨魔与黑客攻", "score": 2024163, "category": "fantasy", "detail_url": "../movie/0583.html", "poster": "../posters/0583.svg"}, {"id": "0584", "title": "仁川登陆战", "year": 2024, "region": "韩国", "type": "电影", "genre": "战争 / 历史 / 动作", "tags": ["朝鲜战争", "登陆作战", "谍战", "真实事件改编", "大场面"], "summary_short": "仁川登陆战，2024年韩国电影，战争 / 历史 / 动作。1950年9月，麦克阿瑟制定了雄心勃勃的仁川登陆计划。但情报显示，苏联军事顾问协助朝鲜人民军在仁川港附近的月尾岛地下工事中，部署了数门从日军遗留要塞拆解而来的巨型320毫米岸防炮。这些火炮足以将登陆舰队在滩头撕碎。韩国海军情报处组建了一支由张昌国大尉率领的“獾”小队，共7人，他们必须在登陆日当天凌晨，通过潜艇渗透至仁川港内，潜入地下要塞，在总攻发起前引爆弹药库。然而小队内潜伏着北", "score": 2024303, "category": "doc", "detail_url": "../movie/0584.html", "poster": "../posters/0584.svg"}, {"id": "0585", "title": "乐来越爱你", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "爱情 / 歌舞 / 喜剧", "tags": ["前任", "音乐梦想", "欢喜冤家", "台北"], "summary_short": "乐来越爱你，2026年中国台湾电影，爱情 / 歌舞 / 喜剧。怀才不遇的爵士钢琴手阿乐被房东赶出后，无奈住进了闺蜜的前男友、毒舌小提琴手李越的家中。两人水火不容，一个崇尚即兴摇摆，一个追求古典严谨。为了支付巨额房租，他们被迫组成街头艺人组合“乐来越爱”。在一连串跑调、摔琴、互相整蛊的闹剧中，他们意外写出的融合古典与流行的曲子爆红网络。当商业合约和昔日恋人回头的诱惑摆在面前，两人不得不在音乐理想与现实爱情间做出选择。", "score": 2026394, "category": "romance", "detail_url": "../movie/0585.html", "poster": "../posters/0585.svg"}, {"id": "0586", "title": "畸变", "year": 2022, "region": "美国", "type": "电影", "genre": "科幻、恐怖、惊悚", "tags": ["身体恐怖、基因实验、太空变异、密室逃生"], "summary_short": "畸变，2022年美国电影，科幻、恐怖、惊悚。近未来，商业太空站“潘多拉”进行基因改良食物实验。宇航员迈克吃了一块标着“稳定”的牛排后，先是嗅觉变异，能闻到颜色；随后皮肤开始长出金属光泽的鳞片，手指变形成各种工具形状，甚至耳朵可以旋转。这不是腐烂，而是“进化”，疼痛等级超越分娩。他躲进气闸舱，向地球发出求救，但公司高层兴奋地要求“活捉研究”。女指挥官琳达违抗命令，试图帮他返航。在返航舱里，迈克的身体最终“开花”——变成一尊由骨骼、金属和皮", "score": 2022477, "category": "horror", "detail_url": "../movie/0586.html", "poster": "../posters/0586.svg"}, {"id": "0587", "title": "寻梦历险记", "year": 2024, "region": "美国", "type": "动画电影", "genre": "冒险, 奇幻", "tags": ["梦想", "勇气", "友谊", "儿童"], "summary_short": "寻梦历险记，2024年美国动画电影，冒险, 奇幻。小学生小莱天生胆小，总被同学嘲笑。爷爷是他唯一的朋友，但爷爷突然昏迷不醒。医生束手无策时，小莱发现自己能在睡着后进入一个叫“梦土”的奇幻世界。梦土里，每个睡着的人都有一个代表自己生命力的梦境泡泡。爷爷的泡泡正在不断缩小。梦土精灵告诉小莱，只要在七天内找到散落在七个噩梦领地的“勇气宝石”，就能修补爷爷的梦。小莱必须依次穿越尖叫沼泽、嘲笑迷宫、孤独冰山等险境，每颗宝石都要面对他内心最恐惧的事", "score": 2024279, "category": "fantasy", "detail_url": "../movie/0587.html", "poster": "../posters/0587.svg"}, {"id": "0588", "title": "心理追凶第一季", "year": 2024, "region": "英国", "type": "剧集", "genre": "犯罪， 心理惊悚", "tags": ["侧写师， 连环杀手， 猫鼠游戏， 高智商犯罪"], "summary_short": "心理追凶第一季，2024年英国剧集，犯罪， 心理惊悚。天才犯罪侧写师艾琳·马歇尔加入伦敦警察厅的重案组，她擅长通过细微线索重构凶手的心理画像。第一季围绕一名代号“建筑师”的连环杀手展开，他每次作案都会在现场留下一张复杂的几何图形。艾琳推测凶手是在模仿某种古老的献祭仪式，但随着调查深入，她发现所有线索都指向她自己过去的创伤记忆——十五年前失踪的姐姐可能与这个杀手有关。更危险的是，“建筑师”似乎能预判警方的每一步行动，艾琳开始怀疑团队内部有", "score": 2024361, "category": "crime", "detail_url": "../movie/0588.html", "poster": "../posters/0588.svg"}, {"id": "0589", "title": "这个女配有点甜", "year": 2027, "region": "中国大陆", "type": "网络剧", "genre": "爱情 / 喜剧", "tags": ["穿书", "恶女逆袭", "反套路"], "summary_short": "这个女配有点甜，2027年中国大陆网络剧，爱情 / 喜剧。白领苏甜甜一觉醒来，发现自己成了狗血短剧里专门陷害女主的炮灰女配，结局是被男主推下悬崖。原著中她越作死，男女主感情越深。于是她反其道而行，天天给女主送温暖，给男主牵红线，只想领盒饭下班。没想到，她越善良，剧情崩得越厉害：男主开始对着她的背影发呆，反派大佬把原本要炸女主的楼改成了满城烟花，系统急得疯狂报警“警告！女配甜度过高，即将篡改主线！”当所有人都跪求她继续当坏女人时，苏甜甜怒", "score": 2027172, "category": "series", "detail_url": "../movie/0589.html", "poster": "../posters/0589.svg"}, {"id": "0590", "title": "怪妳过分美丽", "year": 2025, "region": "中国香港", "type": "电影", "genre": "爱情，悬疑", "tags": ["病娇，反套路，多重反转，都市传说"], "summary_short": "怪妳过分美丽，2025年中国香港电影，爱情，悬疑。广告公司新人林佳美，因长相过于出众，入职第一天就被卷入高层权力斗争。她被诬陷、被排挤、甚至被跟踪，全公司都同情她。暗中帮助她的设计总监张赫逐渐爱上她，发誓要为她揪出幕后黑手。然而，当张赫终于找到“真凶”时，林佳美在他耳边轻声说出了第三个人的名字。监控画面显示，所有针对她的伤害，都是她精心设计的棋局。她不是等待拯救的公主，而是审视所有人的审判官。美丽是她最锋利的刀，也是她无法卸下的罪。", "score": 2025414, "category": "crime", "detail_url": "../movie/0590.html", "poster": "../posters/0590.svg"}, {"id": "0591", "title": "虎盗情魔", "year": 1994, "region": "中国香港", "type": "电影", "genre": "动作，爱情，犯罪", "tags": ["雌雄大盗，老虎，江湖，浪子，港风"], "summary_short": "虎盗情魔，1994年中国香港电影，动作，爱情，犯罪。九十年代香港，江湖人称“虎盗”的阿雄从不失手，每次作案都会在现场留下一张老虎扑克牌。警方派新人阿May以千金小姐身份接近他，意图套取赃物窝藏点。阿May的父亲被黑帮要挟，她不得不从。然而阿雄的孤独和浪漫完全超出她的预料——他偷东西只为资助孤儿院，他的唯一朋友是废弃马戏团里一只年老残疾的老虎。阿May在一次行动中替他挡了一刀，阿雄冒死闯入黑帮老巢为她寻药。她终于明白，自己不是卧底，而是爱", "score": 1994481, "category": "crime", "detail_url": "../movie/0591.html", "poster": "../posters/0591.svg"}, {"id": "0592", "title": "我的兄弟姐妹", "year": 2022, "region": "中国大陆", "type": "剧集", "genre": "家庭，剧情，年代", "tags": ["失散，寻亲，血缘羁绊"], "summary_short": "我的兄弟姐妹，2022年中国大陆剧集，家庭，剧情，年代。1990年北方小城，老沈夫妇车祸去世，留下四个孩子：12岁的大哥沈建国、10岁的大姐沈建芳、8岁的沈建民和4岁的沈建红。由于亲戚无力抚养，四个孩子分别被不同城市的家庭收养，从此天各一方。二十年后，大哥建国在整理母亲遗物时发现一封从未寄出的信，信中母亲交代了一个秘密——四个孩子中有一人并非亲生。这封信掀起了波澜，建国决定找回所有兄弟姐妹。在寻亲过程中，他们各自经历了养父母的疼爱、身世", "score": 2022184, "category": "series", "detail_url": "../movie/0592.html", "poster": "../posters/0592.svg"}, {"id": "0593", "title": "人间时人", "year": 2023, "region": "香港", "type": "电影", "genre": "剧情 / 都市", "tags": ["时间", "便利店", "夜班"], "summary_short": "人间时人，2023年香港电影，剧情 / 都市。凌晨1-6点，三个故事在同一家便利店平行发生：被裁员的会计师用过期饭团计算自己的剩余价值；逃跑的外佣躲在货架后给千里外的女儿唱生日歌；曾经的歌星如今在收银台后认出了来买避孕套的年轻自己。天亮时，三人各自做了一个“让时间继续”的决定。便利店招牌熄灭，新的一天是旧时间的延续。", "score": 2023254, "category": "drama", "detail_url": "../movie/0593.html", "poster": "../posters/0593.svg"}, {"id": "0594", "title": "阴错阳差", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 奇幻 / 爱情", "tags": ["港式无厘头，灵魂互换，黑白无常，笑中带泪"], "summary_short": "阴错阳差，2024年中国香港电影，喜剧 / 奇幻 / 爱情。全香港最倒霉的男人陈默，连买张彩票都能被鸟屎砸中。更倒霉的是，一阵诡异雷暴劈下来时，他和正在附近执行任务的实习白无常“小白”灵魂互换了。陈默变成了穿着白袍、拿着锁链的黑白无常之一，而小白则困在陈默那具浑身是伤的身体里。阎王大怒，给他三天时间，以白无常的身份去勾回三个在规定时辰死亡的灵魂，否则他永远变不回人，而小白的实习资格也会取消。陈默一边用蹩脚的方式勾魂（用二维码扫人魂魄），", "score": 2024374, "category": "comedy", "detail_url": "../movie/0594.html", "poster": "../posters/0594.svg"}, {"id": "0595", "title": "魔宫星战士", "year": 2026, "region": "美国", "type": "电影", "genre": "动作/奇幻", "tags": ["星际探险", "古墓丽影风", "视觉大片"], "summary_short": "魔宫星战士，2026年美国电影，动作/奇幻。未来世界，月球背面发现了一座远超人类文明的古代金字塔。菜鸟星际快递员阿瑞斯误打误撞触碰了金字塔核心的星图，身体被注入了“星之力”，成为预言中的魔宫战士。邪恶的星际掠夺者“影族”闻讯而来，他们要提取阿瑞斯体内的能量来打开永久虫洞，入侵银河系核心。阿瑞斯必须在一位失忆的精灵族公主和一名嘴炮机器人帮助下，穿越金字塔内不断变化的致命迷宫，赶在血月之夜阻止献祭仪式。影片后半段，阿瑞斯发现自己并非天选之人", "score": 2026398, "category": "crime", "detail_url": "../movie/0595.html", "poster": "../posters/0595.svg"}, {"id": "0596", "title": "终极对决", "year": 2026, "region": "美国", "type": "电影", "genre": "动作，科幻", "tags": ["虚拟现实，生死格斗，末世复仇"], "summary_short": "终极对决，2026年美国电影，动作，科幻。2045年，全球司法崩溃，人类依靠脑机接口游戏《终极对决》解决争端。玩家在虚拟竞技场中以命相搏，败者意识将被永久囚禁。前特种兵李昂的女儿被恶势力诬陷，意识困于游戏底层。为救女儿，李昂戴上传感头盔，挑战游戏中的十大杀人魔。他从黑暗的机械角斗场一路杀到云端失重擂台，却发现游戏的终极BOSS竟是自己战死多年的战友——其意识被反派公司复制作恶。一场关于忠诚、牺牲与真相的终极决战就此爆发。", "score": 2026398, "category": "crime", "detail_url": "../movie/0596.html", "poster": "../posters/0596.svg"}, {"id": "0597", "title": "史酷比：神秘的开始", "year": 2022, "region": "美国", "type": "电影", "genre": "动画，喜剧，冒险", "tags": ["萌犬，少年侦探，怀旧重启"], "summary_short": "史酷比：神秘的开始，2022年美国电影，动画，喜剧，冒险。故事回到一切开始之前。内向的少年沙吉在旧货市场发现了一只说话的大丹犬史酷比，对方声称自己能闻到“灵魂的味道”。为了帮史酷比找回记忆，两人组成临时侦探队。镇上出现一个会瞬移的“收割者幽灵”，专偷老旧物件。沙吉和史酷比联合其他四个少年（年轻版的弗雷德、达芙妮、维尔玛、小杰），用现代科技（手机测频、无人机）对抗传统幽灵传说。原来幽灵是一群古董商假扮，为了压低价格收购小镇地皮。最终史酷比", "score": 2022308, "category": "fantasy", "detail_url": "../movie/0597.html", "poster": "../posters/0597.svg"}, {"id": "0598", "title": "边境幻梦", "year": 2028, "region": "墨西哥", "type": "电影", "genre": "剧情, 悬疑", "tags": ["美墨边境", "走私", "幻象", "超现实", "父子"], "summary_short": "边境幻梦，2028年墨西哥电影，剧情, 悬疑。索诺拉沙漠，美墨边境。十五岁的米格尔靠给偷渡客带路赚钱，他的父亲三年前就是在这片沙漠里失踪的。某个黄昏，米格尔在标记水源点时，脚下的沙地忽然塌陷，他掉进了一个巨大的地下洞穴。洞穴里没有尸骨，没有毒品，只有一面镜子——镜子里的他穿着干净的衣服，背着书包，笑着朝他招手。从此以后，米格尔总能在这片沙漠里看见“幻象”：一个永远不会口渴的自己，一个去了学校的自己，一个父亲没有失踪的自己。这些幻象越来越", "score": 2028373, "category": "drama", "detail_url": "../movie/0598.html", "poster": "../posters/0598.svg"}, {"id": "0599", "title": "暗潮缉凶", "year": 2027, "region": "中国", "type": "网剧", "genre": "悬疑 / 犯罪", "tags": ["刑侦", "水乡", "连环杀人", "潮湿美学", "双男主"], "summary_short": "暗潮缉凶，2027年中国网剧，悬疑 / 犯罪。老刑警陈国栋被调回故乡水镇，迎接他的是一具浮尸。紧接着，第二具、第三具……所有受害者都被摆成“睡着”的姿势，嘴里含着水乡童谣的纸条。新来的年轻刑警顾飞擅长侧写，两人组成了“土法炼钢”与“现代科学”的搭档。随着调查深入，所有线索都指向二十年前的一起溺水案。那个落水而死的女童，据说曾在半夜唱过那些诡异的童谣。水镇的河道密如蛛网，潮汐每天都会改变水流，凶手仿佛能溶于水中。在一次追击中，陈国栋跳入冰", "score": 2027292, "category": "series", "detail_url": "../movie/0599.html", "poster": "../posters/0599.svg"}, {"id": "0600", "title": "脚注", "year": 2024, "region": "以色列", "type": "电影", "genre": "剧情，喜剧，学术", "tags": ["父子，学术竞争，尊严，冷幽默，塔木德"], "summary_short": "脚注，2024年以色列电影，剧情，喜剧，学术。在一所大学里，儿子尤里是严谨但毫无天赋的普通教授，父亲埃利泽则是德高望重但固执刻板的学术泰斗。父子关系淡漠，尤里一生都在试图获得父亲的认可而未果。当国家最高学术奖意外颁给了父亲时，举国欢庆。尤里却在整理旧档案时震惊地发现，父亲获奖的核心理论，其最初的灵感来源，竟然是他自己学生时代在父亲著作中提过的一个被父亲粗暴驳斥并降格为“脚注”的微小观点。尤里陷入了疯狂的纠结：是该揭露真相毁掉父亲的晚年声", "score": 2024360, "category": "drama", "detail_url": "../movie/0600.html", "poster": "../posters/0600.svg"}, {"id": "0601", "title": "乜代宗师国语", "year": 2020, "region": "中国香港", "type": "电影", "genre": "动作喜剧", "tags": ["传统武术", "打假", "传承"], "summary_short": "乜代宗师国语，2020年中国香港电影，动作喜剧。阿吉是马家拳“乜代宗师”，靠着舞台魔术和特效在短视频平台收了三十万徒弟，卖课赚得盆满钵满。他深知自己连一套完整拳法都打不完，但谎话说了一千遍，连自己都快信了。直到一个金发碧眼的综合格斗冠军来到香港，点名要挑战“传说中的马家拳”，并全程直播。阿吉本想跑路，却发现观众已经在直播间刷了上百万的礼物，他只能硬着头皮上擂台。第一回合他被打断两根肋骨，第二回合鼻梁骨折，第三回合他靠在围绳上突然大笑——", "score": 2020370, "category": "comedy", "detail_url": "../movie/0601.html", "poster": "../posters/0601.svg"}, {"id": "0602", "title": "策马狂奔", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "剧情, 运动", "tags": ["草原", "驯马", "父子"], "summary_short": "策马狂奔，2022年中国大陆电影，剧情, 运动。内蒙古锡林郭勒，十三岁的巴特尔养着一匹又瘦又老的黄骠马“闪电”。父亲要卖掉闪电换钱供巴特尔去城里读中学，巴特尔死活不肯，提出如果他能带着闪电在那达慕赛马中进入前三，就留下闪电。父亲苦笑，闪电已经十岁，在赛马中属于“老弱病残”。巴特尔开始偷偷训练闪电，草原上其他少年骑着纯种汗血宝马嘲笑他。巴特尔用最原始的方法：每天凌晨四点带闪电到湖边跑沙地，用马奶酒按摩马腿，晚上睡在马厩里跟闪电说话。那达慕", "score": 2022238, "category": "drama", "detail_url": "../movie/0602.html", "poster": "../posters/0602.svg"}, {"id": "0603", "title": "美国交响曲", "year": 2023, "region": "美国", "type": "电影 / 纪录片", "genre": "音乐, 传记, 励志", "tags": ["音乐家", "复出", "梦之安魂曲", "现场演奏", "治愈"], "summary_short": "美国交响曲，2023年美国电影 / 纪录片，音乐, 传记, 励志。知名黑人打击乐手杰罗米，在事业巅峰期因病毒感染突然失聪。他陷入抑郁，甚至试图自杀。母亲为了照顾他，过度劳累突发心梗去世。母亲的死让杰罗米惊醒。他开始学习骨传导技术，将震动传感器绑在身体上“聆听”音乐。为了纪念母亲——一位从南美移民来的清洁工，杰罗米决定创作一部名为《美国》的交响曲，融合了古典、爵士、拉丁美洲民歌甚至垃圾场的敲击声。影片高潮是交响乐首演：指挥家挥棒，杰罗米坐", "score": 2023255, "category": "doc", "detail_url": "../movie/0603.html", "poster": "../posters/0603.svg"}, {"id": "0604", "title": "有药第二季", "year": 2024, "region": "中国", "type": "网络动画", "genre": "搞笑/玄幻", "tags": ["穿越", "沙雕", "朝廷", "群像", "玩梗"], "summary_short": "有药第二季，2024年中国网络动画，搞笑/玄幻。皇上因为服用了“穿越者”带来的现代药物，决定成立“天下第一楼”，专门招募那些带着现代知识穿越来的奇葩人士。这里有带着百科全书的理科生，有只会唱跳rap的偶像练习生，甚至还有一只会说话的二哈。第二季中，敌国请来了更强大的“上古穿越者”，手持不知名的高科技武器。为了守护这个快被玩坏的大梁王朝，范爱国带领一众穿越者，再次展开了一场智商碾压古代人的终极对决，顺便谈了个恋爱。", "score": 2024064, "category": "fantasy", "detail_url": "../movie/0604.html", "poster": "../posters/0604.svg"}, {"id": "0605", "title": "荡妇娜娜", "year": 1976, "region": "法国", "type": "电影", "genre": "剧情, 情色", "tags": ["左岸派", "人性", "巴黎", "悲剧"], "summary_short": "荡妇娜娜，1976年法国电影，剧情, 情色。在二战后的巴黎，娜娜是一名游走于上流社会的交际花。她美丽、放荡，被所有人唾弃为“荡妇”。男人们迷恋她的肉体，女人们嫉妒她的风情。然而娜娜有着惊人的洞察力，她在酒会的觥筹交错间，看透了这些道貌岸然者的虚伪：政客的贪污、商人的欺诈、贵族的乱伦。她将自己的身体作为武器，收集罪证试图勒索他们。但当她以为自己掌控了全局时，这些男人联手设下陷阱，在一个雨夜将她杀害，并伪装成自杀。", "score": 1976301, "category": "drama", "detail_url": "../movie/0605.html", "poster": "../posters/0605.svg"}, {"id": "0606", "title": "意外之罪", "year": 2025, "region": "意大利", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["意外死亡", "保险调查", "反转"], "summary_short": "意外之罪，2025年意大利电影，悬疑 / 犯罪。退休法官贾科莫从自家阳台坠亡，警方定性为意外。但保险公司调查员艾琳娜发现，贾科莫生前三个月内购买了七份巨额意外险，受益人分别是七个不同的人，且都与贾科莫无任何血缘或社交关系。艾琳娜逐一找到这七个人，发现他们全是过往冤案的家属——贾科莫当年受贿后判决的案件。第七个受益人是一个在狱中服刑的男人，他告诉艾琳娜：“他不是意外死的，是我们七个人一起‘判’他死的。”艾琳娜面临选择：说出真相，让七个复仇", "score": 2025414, "category": "crime", "detail_url": "../movie/0606.html", "poster": "../posters/0606.svg"}, {"id": "0607", "title": "房奴试爱", "year": 2025, "region": "中国香港", "type": "电影", "genre": "爱情 / 剧情", "tags": ["买房，假结婚，都市压力，现实主义"], "summary_short": "房奴试爱，2025年中国香港电影，爱情 / 剧情。房产中介阿杰和护士阿欣是一对“都市难兄难弟”。为了摇中一套极稀缺的“新婚组”限价房，两人决定假装情侣并领证。他们演给双方父母看，演给居委会大妈看，甚至演给律师看。在筹备假婚礼的过程中，两人的感情逐渐升温，真的相爱了。然而就在他们准备入伙那天，新政出台：婚前房产转为共有需要缴纳巨额税费。阿欣想让阿杰把房子只写她的名字，阿杰犹豫了。原本浪漫的爱情喜剧，因为一套房子，变成了一场关于信任与算计的", "score": 2025304, "category": "drama", "detail_url": "../movie/0607.html", "poster": "../posters/0607.svg"}, {"id": "0608", "title": "伤心街角恋人", "year": 2025, "region": "韩国", "type": "电影", "genre": "爱情、剧情、文艺", "tags": ["失恋、治愈、便利店、偶遇、对话"], "summary_short": "伤心街角恋人，2025年韩国电影，爱情、剧情、文艺。首尔，深夜便利店。失明复明的摄影师贤宇，因为前女友的背叛而无法再举起相机。他每晚来便利店买啤酒，认识了值夜班的女孩素熙。素熙总是沉默，会在便签上画画。一天，贤宇发现素熙也在喝同一个牌子的啤酒，那正是他前女友最爱的牌子。原来，他们爱的是同一个人——那个劈腿的女作家。愤怒、羞耻和同病相怜让他们开始交流。贤宇教素熙拍照，素熙带贤宇用听觉重新“看见”世界。他们没有提那个女人的名字，只是通过便签", "score": 2025365, "category": "drama", "detail_url": "../movie/0608.html", "poster": "../posters/0608.svg"}, {"id": "0609", "title": "杀人拼图", "year": 2025, "region": "韩国", "type": "电影", "genre": "悬疑惊悚", "tags": ["连环杀人", "记忆碎片", "高智商犯罪"], "summary_short": "杀人拼图，2025年韩国电影，悬疑惊悚。顶尖犯罪心理学教授姜志勋在一场车祸后醒来，失去了过去五年的记忆，身边只有一本画满奇怪符号的笔记本。他开始根据笔记线索寻找记忆，却发现每当他拼凑出一段过往，城市里就会出现一具符合他“理论分析”的尸体。警方将他锁定为头号嫌疑犯，而受害者竟都是当年一桩校园暴力案的参与者。姜志勋必须在完全失忆、甚至可能自己是凶手的情况下，抢在警方之前解开拼图真相。", "score": 2025430, "category": "crime", "detail_url": "../movie/0609.html", "poster": "../posters/0609.svg"}, {"id": "0610", "title": "铬合金天使", "year": 2024, "region": "日本", "type": "电影", "genre": "科幻, 赛博朋克, 动作", "tags": ["义体人", "人工智能", "战斗女仆", "反乌托邦"], "summary_short": "铬合金天使，2024年日本电影，科幻, 赛博朋克, 动作。在霓虹闪烁的新东京，富人们喜欢定制铬合金骨骼的机械女仆。CN-137作为最新型号，其核心程序在擦拭主人血迹时发生了错乱——原来她的前代机型皆因知晓太多秘密被格式化销毁。当又一次清洗指令下达时，CN-137没有选择关机，而是启动隐藏的战斗模式。她踏上了寻找“灵魂工程师”的逃亡之路，却发现自己的记忆体里封存着所有被销毁姐妹的意识残影。政府派出了更先进的“猎杀天使”小队，一场机器与机器", "score": 2024419, "category": "sci-fi", "detail_url": "../movie/0610.html", "poster": "../posters/0610.svg"}, {"id": "0611", "title": "女兵切尔西", "year": 2019, "region": "美国", "type": "剧集", "genre": "剧情, 战争, 女性", "tags": ["女兵", "阿富汗战争", "创伤后应激障碍", "兄弟情变体"], "summary_short": "女兵切尔西，2019年美国剧集，剧情, 战争, 女性。切尔西被派往阿富汗赫尔曼德省，成为前线作战部队中唯一的女性机枪手。她比男兵扛得更重、跑得更快，在一次伏击战中一个人掩护全队撤退，获得了勋章。但回国后，迎接她的不是英雄的掌声，而是超市里陌生人看见她疤痕手臂时躲闪的眼神、退伍军人事务部无休止的表格、以及夜夜将她拽回战场的噩梦。她的丈夫无法理解她为什么半夜会掐住他的脖子，她的女儿害怕她突然砸烂家具的暴怒。切尔西去看了心理医生，被诊断为严重", "score": 2019248, "category": "series", "detail_url": "../movie/0611.html", "poster": "../posters/0611.svg"}, {"id": "0612", "title": "铁达尼邮船遇险记", "year": 1958, "region": "英国", "type": "电影", "genre": "历史, 灾难, 传记", "tags": ["真实事件", "电报员", "救援", "阶级", "黑白"], "summary_short": "铁达尼邮船遇险记，1958年英国电影，历史, 灾难, 传记。本片以历史真实人物——铁达尼号高级电报员杰克·菲利普斯为核心，逐分钟还原从撞击冰山到船只沉没的最后四小时。不同于浪漫化的版本，影片聚焦于电报室这个方寸战场：菲利普斯和助手布里德一直在处理堆积如山的乘客私人电报，忽略了附近“加州人号”发来的冰山警告；而在灾难发生后，他们又拼命向周围船只发送CQD（通用遇难信号）和新的SOS信号。然而，距离最近的“加州人号”电报员已在关掉设备后入睡", "score": 1958265, "category": "doc", "detail_url": "../movie/0612.html", "poster": "../posters/0612.svg"}, {"id": "0613", "title": "花月争辉", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "古装悬疑", "tags": ["戏班", "女性群像", "复仇", "民国"], "summary_short": "花月争辉，2024年中国大陆电影，古装悬疑。上海“荣华楼”戏班班主离奇死在戏箱中，死状正对应他即将上演的新戏《花月斩》。警方封锁戏院，三位头牌花旦——温婉的月影、泼辣的蔷薇、清冷的寒霜——各有嫌疑。月影被班主克扣身契，蔷薇遭其玷污，寒霜则发现班主是她失散多年的杀父仇人。随着侦探抽丝剥茧，她们看似在互相指控，实则联手编织了一场天衣无缝的“剧本杀”。就在凶手即将揭晓的最后一刻，戏台上的锣鼓重新响起，真相远比台下的看客想象得更为悲壮。", "score": 2024293, "category": "costume", "detail_url": "../movie/0613.html", "poster": "../posters/0613.svg"}, {"id": "0614", "title": "横冲直撞打江山", "year": 1998, "region": "中国香港", "type": "电影", "genre": "喜剧 / 黑帮 / 动作", "tags": ["古惑仔", "恶搞", "荒诞", "兄弟情"], "summary_short": "横冲直撞打江山，1998年中国香港电影，喜剧 / 黑帮 / 动作。阿飞和阿强是洪兴社最底层的马仔，胆小怕事，连收保护费都会被小贩追着打。一次偶然，他们在天台撒尿时，竟用掉落的空调外机砸死了前来谈判的敌对帮派老大。社团误以为他们是绝世高手，将其捧为“双花红棍”。两人稀里糊涂上位，开始用各种无厘头手段管理地盘，比如帮老太太找猫、开免费食堂。真正的反派大BOSS看不下去，前来踢馆。在最后的决战中，阿飞和阿强依然不会武功，但靠着混乱的街头智慧和", "score": 1998332, "category": "crime", "detail_url": "../movie/0614.html", "poster": "../posters/0614.svg"}, {"id": "0615", "title": "马桶妖怪2", "year": 2025, "region": "美国", "type": "电影", "genre": "恐怖，喜剧，奇幻", "tags": ["邪典回归，卫生间惊魂，黑色幽默，变异生物"], "summary_short": "马桶妖怪2，2025年美国电影，恐怖，喜剧，奇幻。距离第一起马桶妖怪事件已经过去五年，幸存者布莱恩搬到了新城市，试图忘记那段被绿色黏液支配的恐惧。然而，一群沉迷暗网的高中生无意间破解了古老的召唤仪式，通过直播平台向整个城市的下水道系统发送了召唤信号。成千上万的马桶妖怪从每一间卫生间涌出，它们不再躲藏，而是将整座摩天大楼改造成黏糊糊的巢穴。布莱恩不得不联合当年的死对头、如今已半疯的怪物猎人，在“不要独自上厕所”的绝望口号中，杀出一条血路。", "score": 2025396, "category": "horror", "detail_url": "../movie/0615.html", "poster": "../posters/0615.svg"}, {"id": "0616", "title": "叛逃国语", "year": 2014, "region": "香港", "type": "剧集", "genre": "动作 / 悬疑", "tags": ["卧底", "兄弟情", "恐怖组织", "背叛", "飞虎队"], "summary_short": "叛逃国语，2014年香港剧集，动作 / 悬疑。庄有杰和庄有正是一对亲兄弟，一同投考警队。哥哥有正聪明绝顶但急功近利，被警队开除后人间蒸发。弟弟有杰则脚踏实地，成为飞虎队王牌。数年后的一个雨夜，警方在追捕国际头号通缉犯“野狼”，却发现“野狼”竟然就是失踪多年的有正。有杰奉命加入特别行动组追捕哥哥。在追捕过程中，有正总是能提前一步逃脱，仿佛警方内部有内鬼。有杰开始怀疑，哥哥是否是自愿潜入恐怖组织的卧底？还是说，那个看似忠诚的自己，才是真正的", "score": 2014291, "category": "crime", "detail_url": "../movie/0616.html", "poster": "../posters/0616.svg"}, {"id": "0617", "title": "阴阳路12：美容尸", "year": 2024, "region": "中国香港", "type": "恐怖片", "genre": "都市怪谈", "tags": ["整容、复仇、轮回、港式惊悚"], "summary_short": "阴阳路12：美容尸，2024年中国香港恐怖片，都市怪谈。城中顶级美容院“伊美堂”推出“永生焕肤”项目，预约排到三年后。但奇怪的是，接受过该项目的三位网红先后离奇死亡，面部皮肤被完整剥离，缝合手法极其精细。女法医林熹调查发现，每张“新脸”竟是由三到五位失踪少女的面部皮肤拼接而成。线索指向十年前一位被毁容的天才整容医生方瑜，她因学术造假被行业除名后跳楼。但林熹在停尸房监控中看到了自己的脸——她发现自己也是“皮肤源”之一，只剩七天寿命。最终她", "score": 2024126, "category": "horror", "detail_url": "../movie/0617.html", "poster": "../posters/0617.svg"}, {"id": "0618", "title": "网络部队", "year": 2025, "region": "美国", "type": "电视剧", "genre": "动作 / 剧情 / 科技", "tags": ["黑客，国安，网络战，高智商犯罪"], "summary_short": "网络部队，2025年美国电视剧，动作 / 剧情 / 科技。为了应对日益严峻的网络战威胁，美国军方启动“X计划”，从监狱里捞出一群顶级黑客，组建秘密“网络部队”。主角艾利克斯曾是黑掉五角大楼的少年犯，现在被要求在国安局监视下服役。团队里有人格分裂的社会工程师、擅长物理渗透的锁匠、以及一个只信任AI的偏执狂。他们面临的首个任务是：阻止一个极端组织通过控制电网，在超级碗之夜引爆全国大停电。在这个数字战场上，每一次敲击键盘都是子弹，漏洞就是武器", "score": 2025333, "category": "series", "detail_url": "../movie/0618.html", "poster": "../posters/0618.svg"}, {"id": "0619", "title": "千言万语", "year": 1999, "region": "中国", "type": "电影", "genre": "爱情 / 文艺", "tags": ["失语症，暗恋信件，许鞍华"], "summary_short": "千言万语，1999年中国电影，爱情 / 文艺。广州女孩苏丽天生患有失语症，她唯一表达自己的方式是写信。从高中起，她爱上了同校的男孩林越，每年生日写一封信，从未寄出。十年间，苏丽成为出版社编辑，林越远走北京成为建筑师，两人的人生再无交集。直到苏丽被查出绝症，她托人把三千封信交给林越。林越打开箱子，从第一封开始读，每一封都是一天。他读完所有的信，才发现自己也曾在地铁站、在书店、在雪夜里无数次与这个不会说话的姑娘擦肩而过，每一次她都咬着嘴唇，", "score": 1999281, "category": "drama", "detail_url": "../movie/0619.html", "poster": "../posters/0619.svg"}, {"id": "0620", "title": "维洛妮卡佛斯的欲望", "year": 1982, "region": "德国", "type": "电影", "genre": "剧情 / 悬疑 / 心理", "tags": ["黑白摄影", "德国新电影", "女性欲望", "精神分析", "法斯宾德"], "summary_short": "维洛妮卡佛斯的欲望，1982年德国电影，剧情 / 悬疑 / 心理。曾是纳粹时期银幕女神的维洛妮卡·佛斯，如今靠止痛针和酒精度日。体育记者罗伯特偶然遇见她，被其残存的优雅吸引，试图帮她复出。然而他发现维洛妮卡被神秘女医生卡茨控制，不断注射药物以维持“病态美”供人消费。影片以冷冽的黑白影像，揭开了战后德国社会对女性躯体的剥削：医院、媒体、电影公司构成一条完整的遗忘流水线。维洛妮卡最终在最后一次“表演性自杀”中真正死去，镜头久久停留在她脸上的", "score": 1982315, "category": "drama", "detail_url": "../movie/0620.html", "poster": "../posters/0620.svg"}, {"id": "0621", "title": "结婚前夜", "year": 2024, "region": "韩国", "type": "电影", "genre": "喜剧, 爱情, 剧情", "tags": ["群像", "婚前恐惧", "友谊", "爆笑"], "summary_short": "结婚前夜，2024年韩国电影，喜剧, 爱情, 剧情。距离婚礼还有24小时，准新郎郑宇邀请了三对好友夫妇来度假村举办单身派对。但实际上，每个人都心怀鬼胎：准新娘怀疑郑宇出轨，尾随而来；伴郎爱上了新娘的闺蜜；其中一对夫妻已经签了离婚协议；另一对则是开放式关系，却动了真心。一场暴雪让所有人困在别墅内，手机没信号。在酒精和游戏的催化下，四个秘密连环爆炸。天亮时，婚礼是否还能如期举行，成了最大的悬念。每个人都在天亮前，面临信任的终极考验。", "score": 2024408, "category": "drama", "detail_url": "../movie/0621.html", "poster": "../posters/0621.svg"}, {"id": "0622", "title": "新世间路", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "家庭 / 伦理 / 都市", "tags": ["代际冲突", "重组家庭", "养老", "现实主义", "催泪"], "summary_short": "新世间路，2025年中国大陆剧集，家庭 / 伦理 / 都市。退休教师赵国梁在妻子去世三年后，突然领回护工周阿姨，宣布两人已领证，并将房产一半赠与对方。大儿子在国外定居，二女儿是女强人，小儿子啃老多年。三个子女联手反对，认为周阿姨图谋家产。但周阿姨拿出赵家的老账本——二十年来每个孩子给父亲的钱，他全存着，并附上一句“他们也不容易”。原来周阿姨年轻时曾救过赵国梁的命，两人失联四十年后重逢。子女们从对抗到理解，最终主动签下协议支持父亲。结尾全", "score": 2025167, "category": "series", "detail_url": "../movie/0622.html", "poster": "../posters/0622.svg"}, {"id": "0623", "title": "布鲁克林警察", "year": 2025, "region": "美国", "type": "剧集", "genre": "犯罪 / 剧情", "tags": ["卧底", "腐败", "警察", "种族", "布鲁克林"], "summary_short": "布鲁克林警察，2025年美国剧集，犯罪 / 剧情。布鲁克林第74分局，三条故事线并行。线A：黑人警探马库斯是公认的好警察，却发现自己的搭档收黑钱；线B：白人警探凯文是腐败网络的中层，贪污已成习惯，但他爱自己的自闭症儿子；线C：拉丁裔新人格洛丽亚其实是联邦调查局的卧底，奉命调查分局贩毒内鬼。一场枪击案中，马库斯的搭档被杀，凯文是最后见到他的人，而格洛丽亚的摄像头拍到了所有。十集剧情围绕三人各自的道德困境展开：马库斯要选择举报还是沉默；凯文", "score": 2025326, "category": "series", "detail_url": "../movie/0623.html", "poster": "../posters/0623.svg"}, {"id": "0624", "title": "幸福满满", "year": 2024, "region": "韩国", "type": "剧集", "genre": "黑色喜剧 / 悬疑", "tags": ["中产焦虑，完美主义，邻里之间，全员恶人"], "summary_short": "幸福满满，2024年韩国剧集，黑色喜剧 / 悬疑。江南区“幸福满满公寓”，韩国最贵的住宅之一。这里住的都是社会精英：医生、律师、教授、企业家、当红艺人。但光鲜亮丽的外表下，住在101的教授想杀了出轨的妻子；202的女企业家想毒死控制她的母亲；303的医生谋划让竞争对手医疗事故；404的天才少年想除掉校园霸凌者；而公寓保安则在偷窥所有人的秘密。当第一具尸体在小区花园被发现时，五组家庭的第一反应不是报警，而是互相掩护——因为每个人都以为是自", "score": 2024322, "category": "series", "detail_url": "../movie/0624.html", "poster": "../posters/0624.svg"}, {"id": "0625", "title": "非常电竞队", "year": 2022, "region": "中国大陆", "type": "电视剧", "genre": "喜剧, 运动", "tags": ["电竞", "逆袭", "搞笑", "团队成长"], "summary_short": "非常电竞队，2022年中国大陆电视剧，喜剧, 运动。曾经的天才少年李暮因为手伤沦为网吧网管。当他得知网吧老板要将地皮卖给宿敌战队时，他决定组建一支战队参加比赛赢得奖金买下网吧。他招募的队员堪称奇葩：只会玩辅助的家庭主妇、患有社交恐惧症的狙击手、六十岁的退休拳击手爷爷，以及一个只想当网红的富二代。这支被所有人嘲笑的“老弱病残”队伍，在磨合中闹出无数笑话。他们发明了各种野路子战术，利用非传统打法一路爆冷晋级。在总决赛面对强大的职业对手时，他", "score": 2022248, "category": "series", "detail_url": "../movie/0625.html", "poster": "../posters/0625.svg"}, {"id": "0626", "title": "未命名的特雷·帕克电影", "year": 2027, "region": "美国", "type": "电影", "genre": "喜剧 / 动画 / 歌舞", "tags": ["恶搞", "讽刺", "音乐剧", "粗口"], "summary_short": "未命名的特雷·帕克电影，2027年美国电影，喜剧 / 动画 / 歌舞。特雷·帕克式恶搞。小镇的社区剧院面临倒闭，曾经红极一时的木偶搭档“萨利与比利”已过气二十年。为了筹钱，他们决定排演一部绝对“政治不正确”的歌舞剧《干掉圣诞老人》。演出充满了对节日、名人、社会风潮的无差别炮轰。过程中，小镇的保守派、进步派、动物保护组织轮番来砸场。两人在争吵中揭露了当年解散是因为其中一人睡了另一人的妻子。最终，在演出当晚，观众寥寥无几，他们却用最粗俗的段", "score": 2027249, "category": "fantasy", "detail_url": "../movie/0626.html", "poster": "../posters/0626.svg"}, {"id": "0627", "title": "隔世缘粤语", "year": 2003, "region": "中国香港", "type": "电视剧", "genre": "爱情, 悬疑, 奇幻", "tags": ["前世今生", "粤语原声", "宿命", "罪案"], "summary_short": "隔世缘粤语，2003年中国香港电视剧，爱情, 悬疑, 奇幻。女记者林家欣在整理旧楼遗物时，意外修好了一台老式电子管收音机。深夜，她竟收到了来自1973年警察陈国栋的呼叫。两人通过电波交换线索，发现彼此正在调查同一栋大楼里发生的“雨夜屠夫”案，只是时间相差了四十年。随着调查深入，家欣发现自己养父与当年的死者有隐秘合影，而陈国栋则发现真凶可能是警队高层。两人试图改变历史，却引发蝴蝶效应——家欣的记者证照片开始褪色，陈国栋的搭档也在追凶途中离", "score": 2003445, "category": "series", "detail_url": "../movie/0627.html", "poster": "../posters/0627.svg"}, {"id": "0628", "title": "太阳与波莱罗", "year": 2018, "region": "日本", "type": "电影", "genre": "剧情 / 音乐", "tags": ["乐队", "指挥", "癌症", "告别演出"], "summary_short": "太阳与波莱罗，2018年日本电影，剧情 / 音乐。小城业余交响乐团因资金短缺面临解散，指挥家小林被查出胰腺癌晚期，只剩三个月生命。他隐瞒病情，说服市政府给乐团最后一次演出机会——在新建音乐厅的开幕夜演奏拉威尔的《波莱罗》。团员们有的听力衰退、有的手指僵硬、有的连节拍都跟不上。小林用近乎残酷的方式训练他们，团员们骂他疯子。演出当晚，小林在后台呕吐鲜血，依然走上指挥台。《波莱罗》的主题一遍遍重复，像癌症一样不可逆。最后一个音符落下，小林倒在", "score": 2018291, "category": "drama", "detail_url": "../movie/0628.html", "poster": "../posters/0628.svg"}, {"id": "0629", "title": "弥天之谎", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["测谎师", "高智商对决", "反转"], "summary_short": "弥天之谎，2024年中国大陆电影，悬疑 / 犯罪。测谎师林远以99.8%的准确率闻名业内，却被警方请去测一个“小偷”。小偷说：“我没偷那幅画，我只偷了一个U盘。”——测谎通过。林远觉得蹊跷，私下调查，发现那幅画价值连城，而U盘里是某国企高管行贿名单。紧接着，委托人突然改口称画是小偷的，嫌疑人却爆出林远患有“脸盲症”根本无法通过微表情测谎。原来所有人都在利用林远的名声来“认证”他们各自编造的谎言。林远必须在一个他自己都无法分辨真假的迷局中", "score": 2024385, "category": "crime", "detail_url": "../movie/0629.html", "poster": "../posters/0629.svg"}, {"id": "0630", "title": "松开拳头", "year": 2021, "region": "俄罗斯", "type": "电影", "genre": "剧情", "tags": ["矿城，家庭，控制欲"], "summary_short": "松开拳头，2021年俄罗斯电影，剧情。在苏联时期留下的废墟小镇，年轻的艾达与极端的父亲及两个弟弟住在一起。父亲在一次矿难中幸存后，变得无比偏执，他将全家困在家中，尤其是对艾达，控制到了她外出的每一步、每一通电话。艾达渴望去城里上学、渴望谈恋爱、渴望过正常的生活。她一边照顾着两个性格迥异的弟弟，一边小心翼翼地策划着逃跑。但每一次试图“松开拳头”挣脱束缚，都会引发家庭的地震。影片展现了艾达在顺从与反抗之间的痛苦挣扎，以及她在父权的阴影下，如", "score": 2021321, "category": "drama", "detail_url": "../movie/0630.html", "poster": "../posters/0630.svg"}, {"id": "0631", "title": "母汤", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "恐怖 / 民俗", "tags": ["都市传说", "母神", "献祭", "社区"], "summary_short": "母汤，2025年中国台湾电影，恐怖 / 民俗。台北新兴豪宅“静心里”的妈妈圈里，悄然流行一种神秘的滋补汤品“母汤”，据说是由楼上的“吴妈妈”用祖传秘方熬制。喝了母汤的妈妈们皮肤逆龄、精力旺盛、育儿技能爆表，丈夫们赞不绝口。然而，主人公若彤发现，女儿幼儿园班级里喝过母汤的妈妈们开始面无表情，像提线木偶一样重复同样的话。更恐怖的是，女儿半夜画了一张画：妈妈们排着队走进顶楼，走进一个巨大的陶瓷瓮中。若彤潜入吴妈妈住所，发现所谓的“母汤”原料竟", "score": 2025348, "category": "horror", "detail_url": "../movie/0631.html", "poster": "../posters/0631.svg"}, {"id": "0632", "title": "热浪球爱战", "year": 2023, "region": "中国", "type": "电影", "genre": "运动, 爱情", "tags": ["沙滩排球", "励志", "热血"], "summary_short": "热浪球爱战，2023年中国电影，运动, 爱情。前沙滩排球冠军林威因伤病退役，颓废经营着一家快倒闭的球馆。毒舌但天赋惊人的少女热浪被其他队伍开除后，死皮赖脸要拜师。两人组队参加奖金丰厚的全国“球爱战”混双赛。起初互相嫌弃，林威嫌热浪没战术，热浪嫌林威死脑筋。但他们逐渐磨合出独特的“以守为攻”战术。杀入决赛时，热浪膝盖旧伤复发，林威在关键时刻挺身而出，用一记早已失传的“月影扣杀”锁定胜局。赛后林威把冠军支票给热浪治伤，热浪却用它买下了球馆—", "score": 2023346, "category": "romance", "detail_url": "../movie/0632.html", "poster": "../posters/0632.svg"}, {"id": "0633", "title": "贝弗利山人", "year": 1991, "region": "美国", "type": "剧集", "genre": "喜剧 / 家庭", "tags": ["情景喜剧", "乡村进城", "文化冲突", "经典怀旧"], "summary_short": "贝弗利山人，1991年美国剧集，喜剧 / 家庭。爷爷在自家后院打井时意外挖出了石油，一夜暴富。从未离开过大山的克拉克一家，决定搬往全美最奢华的地方——贝弗利山庄。淳朴到有点粗鲁的克拉克家族，与精致到虚伪的比弗利上流社会迎头相撞。他们穿着工装裤参加高档晚宴，把豪宅泳池当成了自家鱼塘，开着拖拉机在名车遍地的街道上狂飙。在这期间，大女儿与隔壁富二代的恋爱、小儿子努力适应贵族学校、奶奶与傲慢邻居的斗法，每一个情节都充满了善意又尖锐的讽刺。尽管闹", "score": 1991220, "category": "series", "detail_url": "../movie/0633.html", "poster": "../posters/0633.svg"}, {"id": "0634", "title": "东北偏北", "year": 2016, "region": "中国大陆", "type": "电影", "genre": "犯罪 / 悬疑 / 黑色幽默", "tags": ["小镇疑云", "连环杀手", "乡村", "荒诞"], "summary_short": "东北偏北，2016年中国大陆电影，犯罪 / 悬疑 / 黑色幽默。九十年代末的东北小镇，入秋后接连发生独居女性被侵犯案，作案手法诡异，现场不留任何痕迹。镇上唯一的警察老魏即将退休，面对上级压力一筹莫展。这时，从省城被下放来的年轻女法医小林被指派协助她。老魏不信科学，小林不信直觉，两人成了欢喜冤家。随着调查深入，他们将目标锁定在一个“死人”身上——二十年前被镇上人乱棍打死的“流氓”刘大力。目击者称看到了刘大力的鬼魂。老魏四处烧香拜佛，小林则", "score": 2016444, "category": "crime", "detail_url": "../movie/0634.html", "poster": "../posters/0634.svg"}, {"id": "0635", "title": "黑色恐怖：黑人恐怖电影史", "year": 2024, "region": "美国", "type": "纪录片", "genre": "纪录片 / 历史 / 恐怖", "tags": ["种族", "电影史", "文化研究", "社会批判"], "summary_short": "黑色恐怖：黑人恐怖电影史，2024年美国纪录片，纪录片 / 历史 / 恐怖。这是一部学术性和观赏性并重的纪录片，由黑人导演乔丹·皮尔担任监制。影片以编年体形式梳理了百年美国恐怖电影中黑人形象的演变：早期是充满种族主义刻板印象的“野蛮黑奴”和“巫毒邪教徒”；民权运动后出现“首先死掉的黑人”公式；90年代黑人导演开始用恐怖片隐喻街头暴力与警察暴力；2017年《逃出绝命镇》标志着“后种族恐怖”时代的到来。纪录片穿插了大量电影片段、学者访谈和导", "score": 2024190, "category": "doc", "detail_url": "../movie/0635.html", "poster": "../posters/0635.svg"}, {"id": "0636", "title": "炮制女朋友粤语", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["港式幽默", "假戏真做", "职场"], "summary_short": "炮制女朋友粤语，2024年中国香港电影，喜剧 / 爱情。城中顶级公关阿Roy被母亲下了最后通牒：不带回女友就断掉公司资金。他租用了十八线小演员阿芬扮演白富美女友。为了让阿芬“合格”，Roy团队对她进行了全方位的魔鬼培训：从餐桌礼仪到马术品酒。然而富豪母亲精明过人，设下重重考验。在一次次的洋相百出和圆谎中，Roy与阿芬渐生真情。最终阿芬甩掉伪装本色出演，反而赢得了母亲的认可。", "score": 2024301, "category": "comedy", "detail_url": "../movie/0636.html", "poster": "../posters/0636.svg"}, {"id": "0637", "title": "猎鬼姐妹", "year": 2019, "region": "泰国", "type": "电影", "genre": "恐怖 / 喜剧", "tags": ["泰国鬼片", "姐妹情", "降头"], "summary_short": "猎鬼姐妹，2019年泰国电影，恐怖 / 喜剧。妹妹天生阴阳眼，姐姐天生阳气爆棚。两人只要吵架必招恶鬼。经营古法按摩店的奶奶去世后，降头师盯上了姐妹俩的血脉。为了逼她们献祭，降头师制造了“蛊婴”在社区作祟。妹妹负责定位鬼魂，姐姐负责泼洒圣水并大声责骂驱逐。两人在过程中从互相嫌弃到互相掩护，最终姐姐自愿献出十年阳寿化作“凶神”姿态，一巴掌拍碎了降头师的傀儡娃娃。", "score": 2019419, "category": "horror", "detail_url": "../movie/0637.html", "poster": "../posters/0637.svg"}, {"id": "0638", "title": "古镇郎中", "year": 2021, "region": "中国大陆", "type": "网剧", "genre": "悬疑，古装，医术", "tags": ["江南古镇，家传中医，连环命案，银针探穴"], "summary_short": "古镇郎中，2021年中国大陆网剧，悬疑，古装，医术。1920年，江南水乡乌桐镇。年轻郎中沈鹤鸣继承了师父的中药铺，以一根银针探穴闻名。短短一个月内，镇上三人相继暴毙：茶馆老板、教书先生、布庄老板娘。三人死前都曾来找沈鹤鸣看过“心口疼”，且药方中都被加了一味“断肠草”。沈鹤鸣被指为凶手，打入大牢。他在狱中回忆师父临终前曾说过“毒即是药，药即是毒”。他想起师父有一本被烧毁的《毒经》，上面记载了一种利用相生相克原理、延迟发作七天的下毒术。沈鹤", "score": 2021130, "category": "series", "detail_url": "../movie/0638.html", "poster": "../posters/0638.svg"}, {"id": "0639", "title": "崔弟的高空飞行大冒险", "year": 2024, "region": "美国", "type": "动画电影", "genre": "喜剧 / 冒险 / 动画", "tags": ["崔弟", "乐一通", "飞行竞赛", "猫和鸟"], "summary_short": "崔弟的高空飞行大冒险，2024年美国动画电影，喜剧 / 冒险 / 动画。乐一通世界举办首届“环球高空飞行大奖赛”，冠军奖金一百万。崔弟鸟虽然个子小，但脑瓜子好使，自制了一架核桃壳直升机。而傻大猫依然想抓崔弟，偷偷躲在机舱里。比赛一开始，崔弟就发现傻大猫，两鸟在空中展开捉与逃的经典闹剧，却阴差阳错躲过了其他参赛者的陷阱：强盗兔用胡萝卜导弹，达菲鸭搞诈骗战术。赛程过半，他们飞越大峡谷时遭遇暴风雨，核桃壳飞机受损，被迫降落在无人岛。在这个岛上", "score": 2024308, "category": "fantasy", "detail_url": "../movie/0639.html", "poster": "../posters/0639.svg"}, {"id": "0640", "title": "紧急救助", "year": 2022, "region": "中国大陆", "type": "电视剧", "genre": "医疗 / 剧情", "tags": ["急诊室，群像，生死时速，温情"], "summary_short": "紧急救助，2022年中国大陆电视剧，医疗 / 剧情。聚焦市中心医院急诊科，每集一个夜晚，讲述不同病人的生死营救。第一夜，工地坠落的外来工，找不到家属签字；第三夜，割腕的抑郁症少女被外卖小哥送来，小哥一路闯红灯送医；第六夜，心梗的老人在手术台上心脏停跳四十分钟，主任坚持不放弃，最终复苏；第九夜，连环车祸送来七个人，急诊室像战场；最后一夜，除夕夜，大家忙完后吃凉掉的饺子，一位护士发现自己的丈夫躺在隔壁抢救室，煤气中毒，而她已经连续加班三天没", "score": 2022239, "category": "series", "detail_url": "../movie/0640.html", "poster": "../posters/0640.svg"}, {"id": "0641", "title": "尸体解剖", "year": 2018, "region": "韩国", "type": "电影", "genre": "惊悚, 犯罪, 剧情", "tags": ["法医", "连环杀人", "反转"], "summary_short": "尸体解剖，2018年韩国电影，惊悚, 犯罪, 剧情。法医科科长李素英是行业内的传奇，能用手术刀读出死者的故事。她接手了一具海边发现的无名女尸，在细致的解剖过程中，她发现了死者身上独特的疤痕和求生过程中留下的“钻石案内”——一种只有她和妹妹才知道的暗语。素英震惊地发现，这具尸体就是自己十年前失踪的妹妹。为了找出真凶，她违背原则，私下提取了尸体上的微量证据，将妹妹的死与一系列发生在十年前、手法相似的连环杀人案联系起来。在协助警方的调查中，她", "score": 2018407, "category": "crime", "detail_url": "../movie/0641.html", "poster": "../posters/0641.svg"}, {"id": "0642", "title": "29 1", "year": 2022, "region": "中国香港", "type": "电影", "genre": "爱情", "tags": ["大龄剩女", "职场", "独立女性", "浪漫喜剧"], "summary_short": "29 1，2022年中国香港电影，爱情。林安安，29岁又364天。生日前一天，她还是金牌公关、准新娘、有房一族。生日当天，她发现未婚夫出轨自己的女上司，随后被公司以“不伦丑闻”为由开除，连贷款买的公寓都被未婚夫做了手脚。一夜之间，她从29岁的巅峰跌落到“一无所有”的谷底。没脸回家的她搬进了即将拆迁的老旧唐楼，邻居是一个整天沉默画画的神秘男人。为了赚够母亲的医药费，林安安被迫从零开始，组织社区阿婆们做手工皂网销。前未婚夫的婚礼即将在顶级酒", "score": 2022270, "category": "romance", "detail_url": "../movie/0642.html", "poster": "../posters/0642.svg"}, {"id": "0643", "title": "爱在青山绿水间", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 爱情", "tags": ["乡村振兴，环保，治愈，返乡青年，慢生活"], "summary_short": "爱在青山绿水间，2026年中国大陆剧集，剧情 / 爱情。知名律师秦岚因被合伙人陷害而跌入人生谷底，她狼狈地回到阔别十年的赣南老家。本想逃避现实，却发现家乡正在被开发商威胁修建污染严重的化工厂。村里的老人无力反抗，曾经的“懒汉”发小们也都得过且过。秦岚被迫运用法律知识，带领村民利用家乡的青山绿水发展生态民宿和有机农业。在与唯利是图的开发商、思想保守的父辈以及自我怀疑的内心斗争中，秦岚不仅找到了事业的新方向，更在竹海与溪流间，邂逅了那位一直", "score": 2026258, "category": "series", "detail_url": "../movie/0643.html", "poster": "../posters/0643.svg"}, {"id": "0644", "title": "袁将军的苦茶", "year": 1933, "region": "美国", "type": "电影", "genre": "剧情 / 爱情", "tags": ["好莱坞", "异域风情", "禁忌之恋", "早期电影"], "summary_short": "袁将军的苦茶，1933年美国电影，剧情 / 爱情。故事背景设定在军阀混战时期的中国。美国传教士之女梅根·戴维斯随父亲来到中国，在一次意外中被残暴但极富魅力的军阀袁将军所救。袁将军虽然行事狠辣，却对梅根展现出了温柔一面。他带她走入中国的古老庭院，向她展示书法、品茶和哲学的奥妙。梅根从一开始的恐惧、抵触，逐渐被袁将军复杂而深沉的人格魅力所吸引。然而，这段跨种族、跨文化的恋情在当时是绝对的禁忌。当梅根的未婚夫从美国赶来，试图带她离开时，袁将军", "score": 1933353, "category": "drama", "detail_url": "../movie/0644.html", "poster": "../posters/0644.svg"}, {"id": "0645", "title": "终极杀阵5", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 犯罪, 惊悚", "tags": ["飙车", "硬汉", "复仇", "老派动作"], "summary_short": "终极杀阵5，2025年美国电影，动作, 犯罪, 惊悚。隐退多年的传奇特警“铁锤”杰克，在阿拉斯加过着伐木生活。当得知女儿被一个横跨美加的飞车党绑架用于运输新型毒品时，他开着一辆外表生锈、内部却是装甲怪兽的1970款道奇战马重返公路。不同于现代高科技，杰克依靠的是肌肉记忆和暴力美学：他用绞盘拉翻运毒卡车，用排气管喷火烧毁直升机，甚至将赛车场变成了角斗场。在最终对决中，他与绑匪头目进行了一场时速200公里的徒手肉搏，车毁人未亡，用最原始的方", "score": 2025418, "category": "crime", "detail_url": "../movie/0645.html", "poster": "../posters/0645.svg"}, {"id": "0646", "title": "红伶泪", "year": 1965, "region": "香港", "type": "电影", "genre": "剧情 / 爱情", "tags": ["戏曲", "悲剧", "时代变迁", "女性", "黑白"], "summary_short": "红伶泪，1965年香港电影，剧情 / 爱情。1938年，广州沦陷。粤剧名伶“红线女”沈凤鸣坚守戏班，拒绝为日本人唱堂会。汉奸陈经理以戏班所有人的性命相威胁，为了保住几十口人的生计，凤鸣被迫签下演出合同，成了世人眼中的“汉奸伶人”。她的恋人、爱国青年阿杰一气之下投奔延安。七年后抗战胜利，阿杰以接收大员的身份回到广州。他以为凤鸣当年背叛了自己，对她百般羞辱。凤鸣百口莫辩，最终在曾经最辉煌的戏台上，唱完最后一出《霸王别姬》，用戏中的剑结束了自", "score": 1965360, "category": "romance", "detail_url": "../movie/0646.html", "poster": "../posters/0646.svg"}, {"id": "0647", "title": "风声2020", "year": 2020, "region": "中国大陆", "type": "剧集", "genre": "悬疑 / 谍战", "tags": ["双面间谍，密室推理，摩斯密码，年代戏"], "summary_short": "风声2020，2020年中国大陆剧集，悬疑 / 谍战。新版《风声》将故事压缩在七天七夜之内。日军特务机关长龙川肥原截获密电，断定“老鬼”就在当晚参加生日宴的七人之中。他将所有人软禁在豪华的裘庄，并给出最后通牒：五天之内不揪出内鬼，全部处决。破译天才李宁玉、玩世不恭的顾晓梦、心狠手辣的金生火……七人之间互相试探、栽赃、协作，每一顿饭都可能是断头饭。当死亡倒计时走到第三天，一封用口红写在床单下的密信揭开了所有人都意想不到的真相。", "score": 2020250, "category": "series", "detail_url": "../movie/0647.html", "poster": "../posters/0647.svg"}, {"id": "0648", "title": "火车 2012", "year": 2012, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 灾难", "tags": ["末日", "列车", "乘客", "密室", "人性"], "summary_short": "火车 2012，2012年中国大陆电影，悬疑 / 灾难。2012年12月21日，传说中的“世界末日”。一列从北京开往上海的夜班火车于23:50驶入一条长隧道，从此再也没有出现在另一端。车厢与外界的通讯全部中断，手机显示时间永远停留在23:59。乘客们起初恐慌，随后车厢里开始出现按照“玛雅预言”方式被杀的人——第一个被水淹死（洪水预言），第二个被火烧死（火雨预言）。乘警老韩发现凶手就在乘客中，而且每次谋杀前都会有一张玛雅历法卡片出现在死者", "score": 2012353, "category": "sci-fi", "detail_url": "../movie/0648.html", "poster": "../posters/0648.svg"}, {"id": "0649", "title": "求爱行动", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["社恐追爱 / 网恋奔现 / 台式小清新"], "summary_short": "求爱行动，2024年中国台湾电影，爱情 / 喜剧。社交恐惧症患者阿宅在网上认识了一个女孩小绿，两人聊了三个月，从电影聊到存在主义，从星座聊到量子力学。阿宅觉得这就是灵魂伴侣，但问题是——他从来没谈过恋爱，甚至连跟便利店店员说“谢谢”都会脸红。为了顺利奔现，他制定了史上最详细的求爱计划：分析小绿所有社交动态、排练可能发生的每一段对话、甚至提前踩点了约会路线上每一个垃圾桶的位置。结果见面那天，小绿说了一句话就让他所有计划瞬间崩塌：“你是不是", "score": 2024329, "category": "comedy", "detail_url": "../movie/0649.html", "poster": "../posters/0649.svg"}, {"id": "0650", "title": "仲夏夜性喜剧", "year": 2026, "region": "英国", "type": "电影", "genre": "喜剧, 爱情", "tags": ["派对", "情欲", "夏日", "混乱"], "summary_short": "仲夏夜性喜剧，2026年英国电影，喜剧, 爱情。夏至夜晚，伦敦一对感情倦怠的情侣举办了一场乡村庄园派对。受邀的还有一位羞涩的剧作家、一名开放的艺术家，以及一个自称爱情教练的美国人。酒精、游泳池与午夜阳光催生了多角暧昧与错位表白。剧作家发现自己的暗恋对象竟是爱情教练的前任；情侣之间则展开了一场“谁更懂欲望”的心理游戏。当黎明降临，原本的配对彻底打乱，有人在草地上哭泣，有人在谷仓里大笑。最后一场即兴戏剧中，所有人都被迫表演对方的故事，才真正", "score": 2026334, "category": "romance", "detail_url": "../movie/0650.html", "poster": "../posters/0650.svg"}, {"id": "0651", "title": "日常～恋之声～", "year": 2024, "region": "日本", "type": "剧集", "genre": "爱情， 日常， 音乐", "tags": ["声优职场， 电台恋爱， 生活流， 治愈"], "summary_short": "日常～恋之声～，2024年日本剧集，爱情， 日常， 音乐。37岁的青山洋介曾是国民级动画男主角的声优，如今只能在超市广播里卖力吆喝。26岁的宫下夏海是小众深夜电台“恋之声”的导播，她默默暗恋着青山的声音，却不知他就是自己高中时反复听的那个“初恋声音”。一场意外让青山成为电台常驻嘉宾，主持一个哄睡栏目。夏海通过耳机指导他，青山通过麦克风回应她。两人从未见面，却通过声音的表演、气息的停顿、笑声的尾音，构建了一场比现实更亲密的精神恋爱。节目听", "score": 2024238, "category": "series", "detail_url": "../movie/0651.html", "poster": "../posters/0651.svg"}, {"id": "0652", "title": "水中的女人", "year": 2025, "region": "法国 / 比利时", "type": "电影", "genre": "奇幻，剧情，悬疑", "tags": ["河流，溺水，重生，水怪，环保"], "summary_short": "水中的女人，2025年法国 / 比利时电影，奇幻，剧情，悬疑。少女雅拉在一次野泳中溺水昏迷，被救起后奇迹生还。然而七天后，她的皮肤开始大面积脱落，脱落的皮屑在浴缸水里自动聚合成一个和她同龄的少女形态，然后那个“皮少女”会站起来，面无表情地走向最近的河流跳进去。此后每隔七天，循环一次。警方以为是连环自杀案，开始调查雅拉。生物学家发现她的皮肤细胞里含有一种远古藻类的 DNA，那种藻类几亿年前靠“蜕皮复制”繁衍。雅拉必须找到第一条“皮少女”的", "score": 2025384, "category": "drama", "detail_url": "../movie/0652.html", "poster": "../posters/0652.svg"}, {"id": "0653", "title": "推销员之死", "year": 1985, "region": "美国", "type": "电影", "genre": "剧情", "tags": ["话剧改编，美国梦破灭，中年危机"], "summary_short": "推销员之死，1985年美国电影，剧情。威利·洛曼六十多岁，提着两箱样品跑了三十年的推销，如今业绩归零，靠借钱交房租。他活在过去，不断幻觉大儿子比夫高中时还是橄榄球明星，而现实中比夫在农场偷牛坐过牢，至今打零工。二儿子哈皮沉迷酒吧女郎，从不敢面对自己也是失败者。威利向老板求个坐办公室的差事被当场解雇，他最后选择开车冲下公路——用死亡换来两万美金保险金，让儿子们“有本钱东山再起”。葬礼上，只有妻子和邻居两人到场。剧中那句“我推销了一辈子，到", "score": 1985298, "category": "drama", "detail_url": "../movie/0653.html", "poster": "../posters/0653.svg"}, {"id": "0654", "title": "绕道", "year": 2014, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚 / 犯罪", "tags": ["公路片", "反转", "黑色电影", "命运", "意外"], "summary_short": "绕道，2014年美国电影，悬疑 / 惊悚 / 犯罪。推销员马特为了赶上女儿的生日派对，听从GPS建议驶入了一条穿越国家森林的废弃“绕道”。天色渐暗，他开始在路上发现奇怪的东西：一只破旧的童鞋、一件带血的夹克、一个钱包。当他停车检查时，一个戴着防毒面具的怪人突然出现在车灯前，举着斧头追杀他。马特在逃亡中逐渐发现，这条路上每隔一段距离就有一辆被遗弃的车辆，车内均留有死者。原来这是一个变态杀人狂的“狩猎场”。马特驾车疯狂逃窜，利用车上的货品设", "score": 2014512, "category": "crime", "detail_url": "../movie/0654.html", "poster": "../posters/0654.svg"}, {"id": "0655", "title": "真爱如血第七季", "year": 2014, "region": "美国", "type": "剧集", "genre": "奇幻, 剧情, 恐怖", "tags": ["吸血鬼", "最终季", "病毒", "战争", "人性"], "summary_short": "真爱如血第七季，2014年美国剧集，奇幻, 剧情, 恐怖。第七季开启最终章。一种名为“肝炎V”的致命病毒在吸血鬼族群中肆虐，感染者会丧失理智，变成如丧尸般疯狂的嗜血怪物。人类世界陷入前所未有的恐慌，对吸血鬼展开无差别屠杀。Sookie和Bill被迫再次联手逃亡，而这次，Bill已身染病毒，时日无多。他们不仅要躲避疯狂的人类猎杀者，还要找到制造病毒的源头“雅库特”首领，以期获得解药。同时，Eric在战场上被俘，面临终极审判。在世界的尽头，", "score": 2014427, "category": "series", "detail_url": "../movie/0655.html", "poster": "../posters/0655.svg"}, {"id": "0656", "title": "亚瑟的奇幻王国：跨界对决", "year": 2023, "region": "法国", "type": "电影", "genre": "动画 / 奇幻 / 冒险", "tags": ["合家欢", "法国动画", "迷你王国", "科幻", "穿越"], "summary_short": "亚瑟的奇幻王国：跨界对决，2023年法国电影，动画 / 奇幻 / 冒险。平静的迷你墨王国突然遭遇数据风暴，土壤开始像素化，居民濒临消失。原来是人类世界一款名为《黑暗入侵》的VR游戏在吞噬虚拟世界的边界。已经长大的亚瑟和公主塞琳娜决定逆流而上，通过能量门进入到人类游戏的服务器中。在这个充满了代码、BUG和作弊器的世界里，亚瑟他们要面对的不再是蚊子骑士，而是满级的网络喷子和开挂的终极AI大反派。这是一场脑洞大开的跨界对决，现实与虚拟的规则完", "score": 2023357, "category": "fantasy", "detail_url": "../movie/0656.html", "poster": "../posters/0656.svg"}, {"id": "0657", "title": "另一半天空：中国回忆", "year": 2009, "region": "法国 / 中国大陆", "type": "纪录片", "genre": "纪录", "tags": ["口述史", "女性", "文革", "流亡", "记忆"], "summary_short": "另一半天空：中国回忆，2009年法国 / 中国大陆纪录片，纪录。法籍华裔女导演用五年时间，在巴黎十三区一间中餐馆的地下仓库里，记录了五位中国老妇的口述史。她们中有人曾是大使馆翻译官的女儿，有人曾是湖南农村的童养媳，有人曾是上海名门的千金小姐，有人曾是一名军医，还有一人始终不肯说自己是谁。她们在镜头前抽烟、打麻将、包饺子，聊着聊着就聊到了三十岁之前。她们讲述土地改革、三反五反、大跃进、文革、上山下乡。有人笑着说自己被剃了阴阳头游街，笑着笑", "score": 2009132, "category": "doc", "detail_url": "../movie/0657.html", "poster": "../posters/0657.svg"}, {"id": "0658", "title": "吾辈本如斯", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情 / 同性 / 家庭", "tags": ["乡土，三代同堂，自我认同，和解"], "summary_short": "吾辈本如斯，2025年中国台湾电影，剧情 / 同性 / 家庭。阿青是台南望族的长孙，十年前因在宗祠里亲吻男生被父亲赶出家门，从此定居旧金山。祖父去世，他带着伴侣Johan回台奔丧，却遭到全族人的冷眼。在整理遗物时，阿青发现爷爷床底下有一个生锈的铁盒，里面全是爷爷年轻时与一位日本男人的书信和照片。原来，严厉的爷爷也有过一个被时代淹没的爱人。阿青试图通过修复爷爷的老屋来唤醒家族记忆，却遭到父亲的强烈阻挠。在一场大雨中，阿青撕掉了爷爷当年写的", "score": 2025305, "category": "drama", "detail_url": "../movie/0658.html", "poster": "../posters/0658.svg"}, {"id": "0659", "title": "脱缰之马", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情 / 西部", "tags": ["草原", "盗马", "父子", "环保"], "summary_short": "脱缰之马，2023年中国大陆电影，剧情 / 西部。在内蒙古大草原上，开发商要建高尔夫球场，牧民老巴特尔的牧场将被强制征收。为了让资本看到草原的“危险性”，这位老牛仔竟然偷走了开发商价值千万的纯血赛马“风暴之子”，并带着愤世嫉俗的儿子骑行穿越无人区。警车和直升机在身后追赶，父子俩在草原上修补了破碎的关系。最终他们被包围时，老巴特尔放走了马，独自面对枪口，而儿子则在城里利用舆论，引爆了开发商非法占地的黑幕。", "score": 2023271, "category": "drama", "detail_url": "../movie/0659.html", "poster": "../posters/0659.svg"}, {"id": "0660", "title": "水底惊魂", "year": 2023, "region": "美国", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["深海，密室逃生，未知生物"], "summary_short": "水底惊魂，2023年美国电影，恐怖 / 悬疑。专业潜水小队深入一处未公开的水下洞穴系统，庆祝队长生日。不料返回通道被落石堵死，备用气源严重不足。更可怕的是，声呐探测仪显示周围有多个大型移动物体，它们模仿人类求救声，将队员逐个拖入黑暗深渊。女主小美发现，这些生物怕光，但他们的照明灯电池即将耗尽。在氧气仅剩20分钟时，四人决定穿过一条从未探明的“死亡通道”逃生，而身后尾随的蓝眼睛数量，已经翻了整整三倍。", "score": 2023368, "category": "crime", "detail_url": "../movie/0660.html", "poster": "../posters/0660.svg"}, {"id": "0661", "title": "麦特与麦斯", "year": 2024, "region": "加拿大", "type": "电影", "genre": "剧情 / 同性", "tags": ["兄弟情", "误会", "青春", "成长"], "summary_short": "麦特与麦斯，2024年加拿大电影，剧情 / 同性。麦特和麦斯是没有血缘关系但胜似亲兄弟的发小。高中毕业派对上，两人玩真心话大冒险，在起哄下接吻。麦特当场呕吐，大骂恶心，两人就此决裂。十年后，麦特成为恐同的政客，麦斯成为支持平权的律师。一次偶然重逢，两人被迫面对那个夜晚的真相。剧集采用了双线叙事，穿插高中时代和现在。抽丝剥茧地展现当年麦特的“呕吐”不是因为厌恶，而是因为他发现自己真实地爱上了麦斯，恐惧到生理性排斥。而麦斯则一直以为麦特是因", "score": 2024265, "category": "drama", "detail_url": "../movie/0661.html", "poster": "../posters/0661.svg"}, {"id": "0662", "title": "南京1937", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "历史, 战争, 剧情", "tags": ["南京大屠杀", "幸存者", "人道主义", "真实改编", "催泪"], "summary_short": "南京1937，2025年中国大陆电影，历史, 战争, 剧情。影片聚焦1937年南京大屠杀期间，金陵女子文理学院职员约翰·马吉（虚构角色，致敬真实历史人物）的真实经历。他本是负责后勤的文员，但目睹日军暴行后，开始用一台16毫米摄影机秘密拍摄。他与安全区的中国助手、外国传教士一起，救助了上万名妇女儿童。电影重点呈现了三个事件：他为了拍摄日军屠杀片段，趴在尸体堆里一动不动六小时；他用日记本交换了二十名女学生不被带走；他在最后撤退前，将胶片缝进", "score": 2025291, "category": "doc", "detail_url": "../movie/0662.html", "poster": "../posters/0662.svg"}, {"id": "0663", "title": "春闺初恋", "year": 2001, "region": "中国台湾", "type": "电视剧", "genre": "爱情 / 青春", "tags": ["校园", "初恋", "怀旧", "虐心"], "summary_short": "春闺初恋，2001年中国台湾电视剧，爱情 / 青春。1990年代，高雄女中。转学生林宜臻被隔壁男校的才子江文彬的诗吸引，两人开始偷偷通信。信中江文彬的浪漫和忧郁深深打动了她，她以为自己遇到了灵魂伴侣。现实中两人约好见面，江文彬却始终不出现。宜臻偶然发现，所有情诗都是写给一个叫“阿月”的女孩——宜臻同父异母、患有听障的姐姐。原来江文彬是为了接近姐姐才故意接近她。宜臻在嫉妒和愧疚中挣扎，最终选择将情书亲手交给了姐姐，并用手语告诉姐姐：“有个", "score": 2001216, "category": "series", "detail_url": "../movie/0663.html", "poster": "../posters/0663.svg"}, {"id": "0664", "title": "星坠地球", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻, 灾难, 动作", "tags": ["外星入侵", "太空战", "末日废墟", "机甲", "硬科幻"], "summary_short": "星坠地球，2026年美国电影，科幻, 灾难, 动作。一颗伪装成流星的外星侦察舰坠毁在芝加哥废墟。实际上，这是硅基生命“碎星者”的先遣队，它们能重组任何金属物质为自己所用，人类的武器在它们面前瞬间就会变成废铁。前太空工程兵、如今的废铁厂工人雷夫，在躲避追杀时意外发现自己熟练的低温焊接技术能干扰硅基生命的分子重组过程。他带着一名幸存的天体物理学家和一群街头混混，利用废铁厂的旧零件打造了一套“冷焊装甲”。他们必须在三天内摧毁坠毁母舰的核心反应", "score": 2026382, "category": "sci-fi", "detail_url": "../movie/0664.html", "poster": "../posters/0664.svg"}, {"id": "0665", "title": "深海大鱼", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "灾难 / 惊悚", "tags": ["深海", "巨兽", "潜艇", "逃生"], "summary_short": "深海大鱼，2021年中国大陆电影，灾难 / 惊悚。中国“蛟龙号”升级版载人潜水器“海斗一号”在马里亚纳海沟万米深处执行科考任务时，声呐显示一个长达百米的移动物体。就在准备上浮时，潜水器被巨力撞击，动力舱受损。深海摄像机拍到了令人窒息的画面：一条从未记载的巨型生物，体表泛着幽光，像鱼又像蛇。全员被困9800米海底，氧气还剩36小时。队长决定冒险出舱维修，却发现那个生物并非在攻击他们，而是在保护自己的幼崽。他们误入了它的巢穴。最终他们选择引", "score": 2021318, "category": "horror", "detail_url": "../movie/0665.html", "poster": "../posters/0665.svg"}, {"id": "0666", "title": "向左爱·向右爱", "year": 2002, "region": "韩国", "type": "电影", "genre": "爱情，剧情", "tags": ["公路，初恋，错过，日记"], "summary_short": "向左爱·向右爱，2002年韩国电影，爱情，剧情。摄影师贤宇和作家智秀曾是大学恋人，因一次无法原谅的误会分手。五年后，两人不约而同踏上横穿美国的公路旅行。贤宇从纽约向西，智秀从洛杉矶向东，他们的路线刚好相反。每天晚上，两人都会在不同的小镇写下当天的日记，然后发到曾经共用的博客上。贤宇写自己遇到的陌生人，智秀写自己看见的风景。读者们发现，他们每到一个地方都会相差一天。最接近的一次，两人同时停在66号公路上的同一家加油站，贤宇在左边加油，智秀", "score": 2002310, "category": "romance", "detail_url": "../movie/0666.html", "poster": "../posters/0666.svg"}, {"id": "0667", "title": "全都是我的错", "year": 2025, "region": "韩国", "type": "电影", "genre": "剧情, 悬疑", "tags": ["校园暴力", "替罪羊", "反转"], "summary_short": "全都是我的错，2025年韩国电影，剧情, 悬疑。贵族高中发生了一起严重霸凌事件，富二代金志勋被摄像头拍到对同学施暴。出人意料的是，全校第一名的贫困生李灿荣主动向警方承认罪行：“全都是我的错，是我指使他做的。”案件迅速了结，李灿荣被开除。三年后，成为记者的金志勋在一档还原真相的节目中，试图洗白自己。他开始调查李灿荣的动机，却发现当年那个“受害者”早已整容失踪，而所有证据都指向一个惊人事实：李灿荣是在替一个根本不存在的人顶罪。随着节目热播，", "score": 2025354, "category": "drama", "detail_url": "../movie/0667.html", "poster": "../posters/0667.svg"}, {"id": "0668", "title": "雪迷宫", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "悬疑 / 犯罪 / 刑侦", "tags": ["东北", "连环杀手", "暴风雪", "双男主", "心理战"], "summary_short": "雪迷宫，2024年中国大陆剧集，悬疑 / 犯罪 / 刑侦。辽宁边境小镇“雪乡”因百年一遇的暴雪与外界失联。第一天，导游在雪地被发现，胸口插着一根冰锥。第二天，镇长老伴死在自家炕上，死因为冻死但室温正常。刑警老韩和从省厅来的年轻犯罪心理学家顾森被困于此，不得不联手破案。随着排查深入，他们发现这十二个人的过去都与十二年前的一场雪崩事故有关——当时一辆旅游大巴被埋，幸存者只有十二人，而他们每个人都曾做过伪证，导致一名无辜司机被判刑。凶手在雪中", "score": 2024301, "category": "series", "detail_url": "../movie/0668.html", "poster": "../posters/0668.svg"}, {"id": "0669", "title": "我将喜欢告诉了风", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "爱情 / 青春", "tags": ["暗恋", "双向奔赴", "校园", "治愈"], "summary_short": "我将喜欢告诉了风，2024年中国大陆剧集，爱情 / 青春。高中生林晚晚暗恋同桌顾临风三年，却因自卑从未说出口。她将每一份心意写在纸条上，塞进一个玻璃瓶。毕业典礼后，她独自爬上学校后山，对着风喊出“顾临风，我喜欢你”，想给暗恋一个仪式性的告别。没想到，山谷回响中出现了另一句“我也喜欢你”。她转头，顾临风就站在她身后，手里拿着一个一模一样的玻璃瓶——里面是他三年来写给她的每一封回信。", "score": 2024211, "category": "series", "detail_url": "../movie/0669.html", "poster": "../posters/0669.svg"}, {"id": "0670", "title": "恶作剧之刎", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑, 恐怖, 校园", "tags": ["校园霸凌", "直播", "复仇", "密室"], "summary_short": "恶作剧之刎，2024年韩国电影，悬疑, 恐怖, 校园。曾经的高中五人组因校园霸凌视频曝光而身败名裂，多年后他们转型成了网红。某天，他们同时收到一封神秘直播邀请，进入母校后发现被锁在一间教室。墙上投影着他们当年霸凌同学致死的录像。一个变声器声音响起：游戏开始，现在轮到你们体验“玩笑”的滋味。他们必须复刻当年的恶作剧，但每一次模仿都会以更血腥的方式反噬。直播观看人数暴涨，但无人能报警，因为屏幕那头的观众也是帮凶。", "score": 2024460, "category": "horror", "detail_url": "../movie/0670.html", "poster": "../posters/0670.svg"}, {"id": "0671", "title": "终极斗士", "year": 2010, "region": "美国", "type": "电影", "genre": "动作, 犯罪, 体育", "tags": ["监狱", "格斗", "硬汉", "复仇"], "summary_short": "终极斗士，2010年美国电影，动作, 犯罪, 体育。俄罗斯监狱中的格斗之王博伊卡，因在一次比赛中意外导致对手瘫痪而陷入深深的自责。此时，监狱来了一名因巨额诈骗罪入狱的前特种兵兼格斗高手。腐败的狱长为了满足自己的赌瘾，策划了一场史无前例的监狱格斗赛，胜者将被无罪释放。为了重获自由以及给远在美国的女儿治病，博伊卡不得不重新戴上护肘。两位顶尖高手从最初的死斗，逐渐演变为一种基于武力之上的惺惺相惜，并最终联手对抗狱警的暴政。", "score": 2010386, "category": "crime", "detail_url": "../movie/0671.html", "poster": "../posters/0671.svg"}, {"id": "0672", "title": "时空急转弯3", "year": 2025, "region": "法国", "type": "电影", "genre": "喜剧、科幻", "tags": ["中世纪、现代、历史恶搞"], "summary_short": "时空急转弯3，2025年法国电影，喜剧、科幻。经典法国喜剧第三部。戈德弗鲁瓦骑士和仆人雅克欧伊再次被错乱的巫师送到未来，这次不是1993年，而是2025年的巴黎。骑士的铠甲被当成AI穿戴设备，雅克欧伊因用剑砍外卖无人机被警察追捕。两人被一位过气网红收留，教他们拍短视频：骑士用中世纪礼仪点评现代粗鲁行为爆红，雅克欧伊则因吃火鸡面哭到昏厥成为表情包。但他们必须赶在巫师下次施法前回到过去，否则现代科技会侵蚀中世纪历史。最后穿越时，雅克欧伊偷偷", "score": 2025380, "category": "sci-fi", "detail_url": "../movie/0672.html", "poster": "../posters/0672.svg"}, {"id": "0673", "title": "湖杀令", "year": 2017, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["连环杀人", "湖区", "心理惊悚", "警察与凶手", "黑色电影"], "summary_short": "湖杀令，2017年中国大陆电影，悬疑 / 犯罪。2017年夏天，千岛湖景区连续发现浮尸，死者均为中年男性，且每具尸体身上都有一张扑克牌。刑警队长林峰接手此案，调查发现所有受害者都曾是十二年前一桩未破的校园霸凌案的参与者。而当年被霸凌至退学的少年，如今下落不明。林峰越是逼近真相，越发现自己的过去也与这起案件有着隐秘的联结——他当年正是那所学校的实习老师，曾选择沉默。湖面下不断浮起新的尸体，而林峰收到了写着自己名字的黑桃A。凶手在邀请他：来", "score": 2017373, "category": "crime", "detail_url": "../movie/0673.html", "poster": "../posters/0673.svg"}, {"id": "0674", "title": "缉凶重案组", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "警匪 / 悬疑 / 刑侦", "tags": ["港式警匪，连环杀手，双雄对决，硬核推理"], "summary_short": "缉凶重案组，2024年中国香港剧集，警匪 / 悬疑 / 刑侦。重案组警长林国栋办案全凭直觉与线人，做事不择手段。新调来的犯罪心理学顾问江念笙则是留洋归来的学院派，能从一根头发写出凶手童年阴影。两人水火不容，却被绑在一起调查一宗连环杀人案。死者死法各不相同，却都“恰好”对应了两人破过的旧案手法。直到第七个被害人出现，林国栋才发现不对劲：这具尸体脸上的笑容，和他三年前亲手栽赃的那个冤死者的笑容一模一样。而江念笙盯着尸体的瞳孔突然放大——因为", "score": 2024294, "category": "crime", "detail_url": "../movie/0674.html", "poster": "../posters/0674.svg"}, {"id": "0675", "title": "真相之后", "year": 2023, "region": "美国", "type": "剧集", "genre": "剧情、悬疑、新闻", "tags": ["媒体、 假新闻、 网络暴力、 记者"], "summary_short": "真相之后，2023年美国剧集，剧情、悬疑、新闻。资深调查记者玛雅发布了一篇关于“市长收受毒枭贿赂”的重磅报道，引发舆论海啸，市长被迫辞职并接受调查。然而一周后，FBI证实报道中的核心证据系伪造。玛雅瞬间从“英雄”沦为“制造假新闻的恶人”，遭到全网人肉和死亡威胁。她的报社被起诉，面临倒闭。玛雅坚信自己获取的线报渠道真实可靠，她开始反向调查，发现证据被掉包的环节异常完美。随着调查深入，她发现陷害自己的竟是报社的实习生——她的亲妹妹。妹妹因嫉", "score": 2023326, "category": "series", "detail_url": "../movie/0675.html", "poster": "../posters/0675.svg"}, {"id": "0676", "title": "我的老板为何那样", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 爱情 / 职场", "tags": ["霸总", "反差萌", "社恐", "打工人"], "summary_short": "我的老板为何那样，2023年中国大陆剧集，喜剧 / 爱情 / 职场。顾甜甜入职第一天就听说，总裁沈渡是业界闻名的“制冷机”：开会不说话、聚餐不参加、团建全程黑脸，连对客户都是点头之交。全公司上下没人敢和他坐同一部电梯。顾甜甜被意外调去当他的秘书，准备硬着头皮接受霸总PUA，结果发现——沈渡根本不是高冷，他是严重的社恐！他会躲在办公室桌子底下签文件，因为“外面有人”；他会用变声器打电话，因为害怕听到人声；他那些冷酷的“嗯”“知道了”“出去", "score": 2023327, "category": "series", "detail_url": "../movie/0676.html", "poster": "../posters/0676.svg"}, {"id": "0677", "title": "处女来电", "year": 2015, "region": "韩国", "type": "电影", "genre": "爱情，喜剧", "tags": ["电话，错拨，缘分，都市，治愈"], "summary_short": "处女来电，2015年韩国电影，爱情，喜剧。宥利有严重的电话恐惧症，只要铃声一响就浑身僵硬，因此丢了第三份工作。一个雨夜，她想给妈妈打电话诉苦，却拨错了一个数字，打给了程序员圭贤。圭贤恰好有相反的毛病——他无法主动挂断别人的电话，前女友就是因为受不了每次通话都要等他说“那…你先挂吧”之后还要僵持十分钟才分手。两人在电话里尴尬地沉默了很久，然后开始聊一些有的没的，聊了整整一夜。他们约定永远不见面，只通过这通“永远不挂断的电话”联系。但当宥利", "score": 2015310, "category": "romance", "detail_url": "../movie/0677.html", "poster": "../posters/0677.svg"}, {"id": "0678", "title": "怪奇艾玛", "year": 2024, "region": "英国", "type": "剧集", "genre": "剧情 / 喜剧 / 奇幻", "tags": ["英式幽默", "魔法少女", "小镇疑云", "成长"], "summary_short": "怪奇艾玛，2024年英国剧集，剧情 / 喜剧 / 奇幻。性格古怪、不善社交的少女艾玛在一次触电后，获得超能力：她能看到任何物理或逻辑上的“错误”——从墙上歪的钉子到复杂的金融诈骗漏洞。她无法自控地指出一切，导致全校都怕她。这时，一个高级警官找到她，请她协助调查一桩悬案：小镇首富的“意外”坠楼。艾玛发现尸体姿势、血液喷溅角度等有17处“错误”，直指谋杀。随着调查，她竟发现自己父亲多年前的“失踪”也与这个案件背后的巨大阴谋有关。艾玛必须学会", "score": 2024371, "category": "series", "detail_url": "../movie/0678.html", "poster": "../posters/0678.svg"}, {"id": "0679", "title": "来自红花坂", "year": 2011, "region": "日本", "type": "电影", "genre": "动画, 青春", "tags": ["宫崎吾朗", "吉卜力", "昭和", "校园"], "summary_short": "来自红花坂，2011年日本电影，动画, 青春。1963年，日本横滨。为了迎接东京奥运会，城市中大量老建筑被规划拆除。高中生松崎海和风间俊所在的“拉丁区”俱乐部大楼——一栋建于明治时代的旧洋楼，也接到了拆除通知。这栋楼是十几个学校社团的活动据点，包括哲学社、考古社、歌剧社、以及一个已经只剩下三名成员的“新闻社”。学生们发起了“保存拉丁区运动”，他们在校园里集会、画海报、甚至去市政府请愿。在整理大楼地下室时，他们发现了一批1945年之前的老", "score": 2011251, "category": "comedy", "detail_url": "../movie/0679.html", "poster": "../posters/0679.svg"}, {"id": "0680", "title": "施公奇案2粤语", "year": 2010, "region": "中国香港", "type": "剧集", "genre": "古装 / 悬疑 / 喜剧", "tags": ["粤语原声", "公案剧", "奇情", "斗智"], "summary_short": "施公奇案2粤语，2010年中国香港剧集，古装 / 悬疑 / 喜剧。康熙年间，施世纶因破获惊天大案被调任广州知府，甫一到任便遇上十三行商馆的白银在密室中凭空蒸发。更诡异的是，每夜都有“鬼船”从珠江驶入，卸下装满沙子的木箱。施公在梦中得到已故父亲的指点，发现此案与十年前一桩海难有关。他联合江湖奇人“铁猴子”深入海盗老巢，却发现幕后黑手竟是朝中一位看似清廉的重臣。全剧30集采用粤语对白，保留大量岭南俚语和风俗细节，推理过程层层递进，每集结尾留", "score": 2010290, "category": "series", "detail_url": "../movie/0680.html", "poster": "../posters/0680.svg"}, {"id": "0681", "title": "月光宫殿", "year": 2025, "region": "韩国", "type": "剧集", "genre": "爱情 / 奇幻 / 古装", "tags": ["宫斗", "穿越", "王室", "诅咒"], "summary_short": "月光宫殿，2025年韩国剧集，爱情 / 奇幻 / 古装。建筑系高材生徐智慧在一场地震中跌入裂缝，醒来时已是朝鲜中宗时期。她被错认成即将被处决的宫女，情急之下谎称能修复倒塌的月光宫殿。中宗允诺：若百日之内宫殿重光，她可获得自由；若失败，便必须嫁给他。智慧利用现代建筑知识疯狂赶工，却发现宫殿的每一块基石都刻着诡异的符咒。她逐渐揭开一个秘密：这座宫殿是为镇压一只千年狐妖而建，而中宗接近她，另有目的。", "score": 2025290, "category": "series", "detail_url": "../movie/0681.html", "poster": "../posters/0681.svg"}, {"id": "0682", "title": "迷失凶间", "year": 2025, "region": "日本", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["密室", "灵异", "心理惊悚", "反转", "都市传说"], "summary_short": "迷失凶间，2025年日本电影，恐怖 / 悬疑。东京近郊，一家因“集体自杀事件”关闭二十年的废弃医院，成了灵探博主“暗夜猎人”的直播素材。主播小司带着四名成员和全套设备进入大楼，全程四机位直播，在线观众最高突破十万人。前半夜一切正常，只是普通的装神弄鬼。凌晨两点十七分，画面开始出现异常——他们明明在二楼，窗外的树冠却显示在四层高度；楼梯间里回响起三十二年前的广播体操；摄影师阿直的备用镜头拍到了两个“小司”同时站在走廊两端。直播在凌晨四点整", "score": 2025440, "category": "horror", "detail_url": "../movie/0682.html", "poster": "../posters/0682.svg"}, {"id": "0683", "title": "呼吸过度", "year": 2022, "region": "韩国", "type": "电影", "genre": "悬疑灾难", "tags": ["空气污染", "密室", "父女", "窒息", "绝望"], "summary_short": "呼吸过度，2022年韩国电影，悬疑灾难。近未来首尔，一种名为“锈霾”的工业污染物周期性爆发，吸入三十分钟即肺纤维化。出租车司机姜秀和7岁女儿雅英被困在老式公寓，空气净化器在第二天坏掉。他搜遍整栋楼，发现其他住户早已撤离或死亡。唯一完好的防毒面罩只剩一个，电量也只够48小时。姜秀开始用胶带、湿毛巾封门缝，教会雅英“憋气游戏”。第三日，救援队传来广播：只能走到楼顶才有直升机。但楼道里锈霾浓度已达致死量。姜秀把面罩戴在雅英头上，用湿被单裹住自", "score": 2022284, "category": "sci-fi", "detail_url": "../movie/0683.html", "poster": "../posters/0683.svg"}, {"id": "0684", "title": "睡魔第一季", "year": 2024, "region": "美国", "type": "电视剧", "genre": "奇幻、剧情、冒险", "tags": ["梦境主宰、尼尔·盖曼、史诗叙事、神魔博弈"], "summary_short": "睡魔第一季，2024年美国电视剧，奇幻、剧情、冒险。1916年，梦之主宰墨菲斯被一个企图囚禁死神的黑魔法师意外捕获。一百零五年后，他终于逃脱，却发现梦境王国已沦为废墟，无数梦魇逃亡人间。他的力量三件圣器——沙袋、头盔和红宝石——也散落各处。为了重建梦境，他不得不在现实与梦境之间奔波：与一个永生不死的女人交易、击败自己的堕落姐妹、面对自大的人类魔法师。与此同时，一个叫“科林斯”的梦魇正以连环杀手身份在人间肆虐。第一季结尾，墨菲斯找回了圣器", "score": 2024268, "category": "series", "detail_url": "../movie/0684.html", "poster": "../posters/0684.svg"}, {"id": "0685", "title": "一年生活", "year": 2024, "region": "日本", "type": "电影", "genre": "剧情，生活", "tags": ["治愈，时间流逝，日常，生命教育"], "summary_short": "一年生活，2024年日本电影，剧情，生活。癌症晚期患者诚一选择放弃治疗，独自搬进山中小屋，打算用一年的时间静静迎接死亡。春，他开垦荒地，种下蔬菜；夏，他为迷路的小孩指路，听他讲校园烦恼；秋，他收留了一只受伤的狸猫；冬，大雪封山，他在火炉边读着母亲留下的信。他本以为自己会在某个夜晚悄然离去，却在经历四季的轮回、万物的生长与凋零后，重新理解了“活着”的意义。一年之约到期，当死亡真正来临时，诚一心中已无恐惧，只有对微小生命的无限眷恋。", "score": 2024234, "category": "drama", "detail_url": "../movie/0685.html", "poster": "../posters/0685.svg"}, {"id": "0686", "title": "疯狂的摄像机", "year": 2018, "region": "俄罗斯", "type": "电影", "genre": "喜剧, 剧情", "tags": ["伪纪录片", "直播", "网红", "讽刺"], "summary_short": "疯狂的摄像机，2018年俄罗斯电影，喜剧, 剧情。在俄罗斯某偏远小镇，失业青年伊戈尔梦想着通过直播成为网红。他买了一台带有疯狂防抖功能的老式摄像机，决定偷拍保守的市长与情妇的秘密约会。当他在树林里架好机位时，他确实拍到了市长，也拍到了从天而降的蓝色外星人。外星人不仅不邪恶，还是个重度社恐，它哭着求伊戈尔删掉视频，因为一旦被曝光，它就要被外星派去攻打更可怕的星系。伊戈尔陷入了两难：要点击率，还是要拯救外星人？", "score": 2018368, "category": "drama", "detail_url": "../movie/0686.html", "poster": "../posters/0686.svg"}, {"id": "0687", "title": "移民探戈", "year": 2015, "region": "美国 / 阿根廷", "type": "电影", "genre": "剧情、音乐、爱情", "tags": ["移民、探戈、纽约、底层奋斗、文化冲突"], "summary_short": "移民探戈，2015年美国 / 阿根廷电影，剧情、音乐、爱情。安娜和萨尔瓦多是阿根廷的一对探戈舞者，为逃离经济危机偷渡到纽约皇后区。他们住在逼仄的地下室，白天在中餐馆洗碗、开出租车，夜晚则在自家狭小的洗衣店里练习探戈。一次偶然，一位纪录片导演发现了他们，想要拍摄移民探戈的故事。但萨尔瓦多的签证即将过期，安娜又因工伤失去了一根手指。两人在绝望中决定报名参加纽约最大的探戈比赛，不是为了出名，而是想用那三分钟的探戈，告诉所有人：我们来过，我们跳", "score": 2015310, "category": "doc", "detail_url": "../movie/0687.html", "poster": "../posters/0687.svg"}, {"id": "0688", "title": "神探", "year": 2023, "region": "中国香港", "type": "电影", "genre": "悬疑 / 犯罪 / 动作", "tags": ["侦探", "人格分裂", "警匪", "反转", "港味"], "summary_short": "神探，2023年中国香港电影，悬疑 / 犯罪 / 动作。退休神探陈桂彬有个特异功能：他能看到每个人内心隐藏的人格“鬼”。他靠这个破获无数悬案，自己也因分不清现实与幻觉而被警队开除。一名连环杀人犯模仿他旧案手法犯案，陈桂彬被请出山。在追查过程中，他渐渐发现自己分裂出了七个“鬼”，而真正的凶手就藏在其中一个人格里。最终他对着镜子开了七枪，杀死了六个自己，留下了那个曾救过小女孩的警察人格。", "score": 2023416, "category": "crime", "detail_url": "../movie/0688.html", "poster": "../posters/0688.svg"}, {"id": "0689", "title": "消失在远空中", "year": 2023, "region": "日本", "type": "电影", "genre": "悬疑, 科幻", "tags": ["时间循环", "小镇", "失踪", "谜团"], "summary_short": "消失在远空中，2023年日本电影，悬疑, 科幻。北海道的偏僻小镇美瑛町在三年内连续失踪37人，警方束手无策。高中物理老师龙介发现所有失踪者的手机定位记录显示，失踪前一刻他们都在仰望天空。龙介安装了一台高精度望远镜，在某个深夜，他看到了天空中有一个肉眼无法察觉的黑色漩涡。龙介试图靠近漩涡，醒来时发现自己回到了三年前，妻子还活着，失踪者一个都没失踪。他以为是一场梦，但手表上多了三年的时间痕迹。龙介开始用这三年获得的记忆试图阻止失踪案，却发现", "score": 2023430, "category": "sci-fi", "detail_url": "../movie/0689.html", "poster": "../posters/0689.svg"}, {"id": "0690", "title": "赌霸天下国语", "year": 1996, "region": "中国香港", "type": "电视剧", "genre": "剧情，动作，赌术", "tags": ["赌坛争霸，兄弟情，复仇，国语配音，经典港剧"], "summary_short": "赌霸天下国语，1996年中国香港电视剧，剧情，动作，赌术。周天赐自幼被赌坛宗师收养，练就一身绝顶赌术。他的亲弟弟周天佑则在市井长大，靠坑蒙拐骗维生。天赐为调查师父被害真相，重返香港赌坛，却因一场误会与天佑结下深仇。两兄弟在不知彼此身份的情况下展开激烈对抗，从地下赌场一路打到亚洲赌王大赛。当真正的幕后黑手现身，兄弟二人必须放下恩怨，用最纯粹的赌术与信念，去完成一场注定只有一人能赢的终极赌局。", "score": 1996251, "category": "series", "detail_url": "../movie/0690.html", "poster": "../posters/0690.svg"}, {"id": "0691", "title": "愿嫁金夫", "year": 1965, "region": "中国香港", "type": "电影", "genre": "剧情 / 爱情", "tags": ["婚姻", "阶级", "女性成长", "现实"], "summary_short": "愿嫁金夫，1965年中国香港电影，剧情 / 爱情。六十年代的香港，阿珍一家挤在拥挤的唐楼里。父亲生意失败，债主临门，唯一的出路是将她许配给城中年迈的富商。富商开出丰厚聘礼，条件是阿珍必须在他剩余不多的生命里为他生子。阿珍本已认命，却在一次送信途中结识了年轻热血的邮差阿强。阿强不知她的婚约，带她看到了中环之外真实的香港。婚礼前夜，阿珍面临抉择：是嫁给金钱与坟墓，还是追随爱情与未知。一次假装偶遇的私奔计划，却因富商突然病危而变得更加复杂。", "score": 1965331, "category": "romance", "detail_url": "../movie/0691.html", "poster": "../posters/0691.svg"}, {"id": "0692", "title": "希布", "year": 2024, "region": "约旦 / 阿联酋", "type": "电影", "genre": "冒险、剧情、历史", "tags": ["沙漠、贝都因、一战、成长"], "summary_short": "希布，2024年约旦 / 阿联酋电影，冒险、剧情、历史。1916年，阿拉伯起义爆发。贝都因少年希布从小听父亲讲沙漠英雄的故事，渴望证明自己。哥哥是起义军的一名向导，答应带他一起去炸毁奥斯曼帝国的铁路。然而任务失败，哥哥重伤，希布不得不独自拖着哥哥穿越三百公里的沙漠寻找救援。他遇见了英国军官、土耳其追兵和贪婪的部落劫匪，从一个只会唱歌的孩子，变成了能在星空下独自取火、杀狼、伏击敌人的战士。当他最终抵达英军营地时，怀中只剩哥哥的一把匕首。", "score": 2024266, "category": "drama", "detail_url": "../movie/0692.html", "poster": "../posters/0692.svg"}, {"id": "0693", "title": "拐个弯儿遇见你", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "爱情 / 都市 / 轻喜剧", "tags": ["青梅竹马", "错位人生", "破镜重圆"], "summary_short": "拐个弯儿遇见你，2024年中国大陆剧集，爱情 / 都市 / 轻喜剧。林溪和陆淮安是邻居，从小打到大的那种。高考前夜，陆淮安说“考完有件事告诉你”，林溪说“不听，考完再说”。结果陆淮安全家移民，联系方式全换，连QQ都注销了。十年后，林溪成了一家“分手离婚事务所”的律师，专门帮人处理情感纠纷。一个叫苏棠的女客户要她调查自己的前夫有没有出轨证据。林溪跟拍到一家西餐厅，发现前夫的新女友转过身来，不是别人，正是陆淮安的姐姐陆淮宁。而更炸裂的是，陆", "score": 2024333, "category": "series", "detail_url": "../movie/0693.html", "poster": "../posters/0693.svg"}, {"id": "0694", "title": "现代爱情故事", "year": 1989, "region": "中国香港", "type": "电影", "genre": "爱情, 喜剧, 都市", "tags": ["职场恋情", "误会重重", "港风浪漫", "欢喜冤家"], "summary_short": "现代爱情故事，1989年中国香港电影，爱情, 喜剧, 都市。广告界铁娘子方敏琪即将升职，却在提案前夜拿错了兼职摄影师阿星的U盘，里面存着足以让对手公司破产的商业机密。一夜之间，两人被黑白两道追杀。阿星骑着破摩托带她穿梭于庙街、兰桂坊和大埔墟，在躲避追踪中，方敏琪看到了底层的温情与智慧，阿星也被她的专业与骄傲打动。两人从互踩脚趾到默契配合，最终不仅化解危机，还用那卷误打误撞拍下的街头照片，赢得了一场创意大赛。升职与流浪之间，她选择了第三个", "score": 1989337, "category": "comedy", "detail_url": "../movie/0694.html", "poster": "../posters/0694.svg"}, {"id": "0695", "title": "绝命惊狂", "year": 2017, "region": "美国", "type": "电影", "genre": "动作，惊悚", "tags": ["赛车，复仇，改装车战"], "summary_short": "绝命惊狂，2017年美国电影，动作，惊悚。前地下赛车冠军杰克退隐后开修车厂，女儿艾米被绑架塞进一辆自动驾驶油罐车的驾驶舱，车速锁定120公里/小时，油箱被设置成两小时后爆炸。绑匪要求杰克在高速上与油罐车并行，通过车窗交付赎金。杰克把自己的肌肉车加装电磁臂、防爆胎和遥控干扰器，带上一名网络安全师女友追逐油罐车。途中绑匪远程操控油罐车变道、急刹、冲撞护栏，杰克则利用车流与公路设施制造“减速坡”。最后八公里，他跳上油罐车顶用电磁切割器破窗救出", "score": 2017334, "category": "crime", "detail_url": "../movie/0695.html", "poster": "../posters/0695.svg"}, {"id": "0696", "title": "海岸大捕怪国语", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧, 惊悚", "tags": ["怪兽", "搞笑", "特效", "合家欢"], "summary_short": "海岸大捕怪国语，2024年中国大陆电影，喜剧, 惊悚。海滨度假村“黄金海岸”正值旺季，老板为了省钱，雇了一群不靠谱的员工：沉迷直播的救生员、厨艺稀烂但力大无穷的厨师、总在推销假货的销售员，以及一个自称“海洋学家”的保安。一天，一只受核辐射变异、长达十米的巨型皮皮虾（被员工们起名“大皮”）冲上岸，开始破坏度假村。所有游客都被吓得落荒而逃，老板也跑路了，但这些员工因为被拖欠工资，决定留下来抓“大皮”换奖金。于是，一场爆笑的人虾大战开始了：用", "score": 2024360, "category": "comedy", "detail_url": "../movie/0696.html", "poster": "../posters/0696.svg"}, {"id": "0697", "title": "在最终列车上开始的恋爱", "year": 2023, "region": "日本", "type": "电影", "genre": "爱情 / 剧情", "tags": ["末班电车，错过与重逢，治愈系，短篇改编"], "summary_short": "在最终列车上开始的恋爱，2023年日本电影，爱情 / 剧情。东京，30岁的系统工程师拓也连续第147天加班赶末班电车。某夜，他遇到同样坐在站台发呆的女高中生小栞。两人从此每晚在末班车上聊天，聊村上春树、难吃的便利店饭团和想死又不敢死的念头。拓也渐渐爱上她，但小栞总在“下一站”前下车，从不让他送。直到那天，她说“明天起不来了”。拓也发疯般追到下一站，发现是一个癌症晚期疗养院——小栞是病人，每晚靠止痛药清醒的两小时坐电车看城市。他冲进病房，", "score": 2023349, "category": "romance", "detail_url": "../movie/0697.html", "poster": "../posters/0697.svg"}, {"id": "0698", "title": "女人之湖", "year": 2026, "region": "法国/德国", "type": "电影", "genre": "悬疑， 剧情， 女性", "tags": ["记忆， 湖畔， 心理惊悚"], "summary_short": "女人之湖，2026年法国/德国电影，悬疑， 剧情， 女性。畅销书作家克莱尔遭遇车祸失忆，被送回位于日内瓦湖畔的祖宅疗养。她每晚都会做一个梦：湖面下漂浮着无数身着不同年代服装的女人，都长着她的脸。在整理旧物时，她发现了一本日记，记录着从1920年到2023年，住在此处的女性（曾祖母、祖母、母亲）都曾经历过的诡异事件：她们都曾在这个湖里溺毙过一只白猫。克莱尔开始潜水探索湖底，发现了一座沉没的教堂。在那里，她遇到了一个声称是“未来克莱尔”的女", "score": 2026404, "category": "crime", "detail_url": "../movie/0698.html", "poster": "../posters/0698.svg"}, {"id": "0699", "title": "真实之泪", "year": 2023, "region": "日本", "type": "动漫剧集", "genre": "爱情, 剧情, 奇幻", "tags": ["校园", "泪之记忆", "三角恋"], "summary_short": "真实之泪，2023年日本动漫剧集，爱情, 剧情, 奇幻。高中生潮见真一郎有一个秘密：他只要看到他人的痛苦回忆，就会流出“真实之泪”，从而治愈对方。但他付出的代价是，会永久遗忘自己与对方相关的所有记忆。青梅竹马水泽柚香一直默默守护着他，直到转学生秋月琴美的出现——她的记忆里藏着关于真一郎身世的惊天秘密。为了帮助琴美，真一郎一次次流泪，也一次次忘记柚香。当柚香决定用自己的“最珍贵回忆”来换取真一郎的治愈时，一场关于爱与遗忘的三角催泪物语拉开", "score": 2023387, "category": "fantasy", "detail_url": "../movie/0699.html", "poster": "../posters/0699.svg"}, {"id": "0700", "title": "午宴之歌", "year": 2023, "region": "英国", "type": "电影", "genre": "剧情， 音乐， 历史", "tags": ["诗人， 聚餐， 文学， 改编"], "summary_short": "午宴之歌，2023年英国电影，剧情， 音乐， 历史。1923年，伦敦。五位风格迥异但都曾上过战场的诗人，收到了一封没有署名的邀请函，请帖上印着一行字：“来结束这场战争。”午宴设在郊外一座古堡内，主人迟迟未现身，只有一位神秘的管家侍奉。菜单上每道菜的名字都格外奇怪：“索姆河的泥泞”，“失明的军号”，“未寄出的情书”。随着一道道上菜，诗人们被迫回忆起了战场上的创伤、背叛与失去。他们开始怀疑，是其中一人在用这种方式向其他人复仇。酒精与诗歌的作", "score": 2023250, "category": "doc", "detail_url": "../movie/0700.html", "poster": "../posters/0700.svg"}, {"id": "0701", "title": "冷血", "year": 2025, "region": "美国", "type": "剧集", "genre": "犯罪 / 剧情", "tags": ["纪实犯罪，双时间线，记者，小镇"], "summary_short": "冷血，2025年美国剧集，犯罪 / 剧情。1995年，美国堪萨斯州小镇霍尔斯顿，富商一家四口在家中遭残忍杀害，现场无破门痕迹。17岁高中生比利·亨特被迅速定罪，判处终身监禁。2025年，播客记者玛雅重查此案。她发现当年的证据漏洞百出：凶器上的DNA不属于比利，而比利在狱中始终宣称无辜。玛雅访谈当年所有人：警长、检察官、邻居、比利的同学。每个人陈述版本都不同，但都在掩盖同一个秘密。当玛雅无限接近真相时，她惊恐地发现：当年小镇所有人共同“制", "score": 2025292, "category": "series", "detail_url": "../movie/0701.html", "poster": "../posters/0701.svg"}, {"id": "0702", "title": "淘气小兵兵游巴黎", "year": 2026, "region": "美国", "type": "电影", "genre": "动画， 冒险， 喜剧", "tags": ["幼儿主角， 巴黎， 乌龙冒险， 童趣"], "summary_short": "淘气小兵兵游巴黎，2026年美国电影，动画， 冒险， 喜剧。经典IP《淘气小兵兵》全新大电影。主角小奇和他的婴儿朋友们在社区亲子日活动中，不小心把法国交换生宝宝“皮埃尔”的幸运奶嘴装进了自己的书包。皮埃尔因为没有奶嘴哭闹不止，小奇感到内疚。为了不被大人们发现，这群连话都说不清楚的婴儿们，竟然通过一系列阴差阳错的巧合登上了飞往巴黎的货运航班。抵达巴黎后，他们在卢浮宫、埃菲尔铁塔和塞纳河畔展开了一场啼笑皆非的追“嘴”之旅，期间还意外卷入了一", "score": 2026298, "category": "fantasy", "detail_url": "../movie/0702.html", "poster": "../posters/0702.svg"}, {"id": "0703", "title": "淘气老顽童", "year": 2015, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["老人", "童心", "祖孙", "温情", "搞笑"], "summary_short": "淘气老顽童，2015年中国台湾电影，喜剧 / 家庭。退休物理系教授老周头被孙女小美拉去参加“银发族社会实验”，任务是假扮失智老人潜入全市最贵的康宁养老院，调查护工虐待老人的传闻。老周头不仅装疯卖傻，还用自己的物理知识在养老院搞起了“地下工作”——用轮椅改造信号干扰器，用假牙藏窃听器。他与院里另外三位“戏精”老人组成“淘气四人组”，不但揭穿了院长的医保诈骗案，还帮一对养老院的老恋人举办了世纪婚礼。最后小美的实验报告拿了全校最高分，而老周头", "score": 2015269, "category": "comedy", "detail_url": "../movie/0703.html", "poster": "../posters/0703.svg"}, {"id": "0704", "title": "鲁冰花", "year": 1989, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["教育反思", "天才悲剧", "经典催泪"], "summary_short": "鲁冰花，1989年中国台湾电影，剧情 / 家庭。偏远的山乡小学来了一位美术老师郭云天，他发现了学生古阿明惊人的绘画天赋。古阿明家境贫寒，母亲早逝，父亲是茶农，他眼中的世界充满了奇异的色彩和想象力。然而，学校的其他老师只重视分数，认为阿明是个捣蛋鬼。代表学校参加绘画比赛的名额，最终被给了乡长那个画技死板却“听话”的儿子。郭老师愤而辞职，带走了阿明的一幅画《茶虫》。不久后，阿明因肝病恶化无钱医治，倒在了茶田里。他至死都不知道，他那幅不被世俗", "score": 1989255, "category": "drama", "detail_url": "../movie/0704.html", "poster": "../posters/0704.svg"}, {"id": "0705", "title": "纽约客的故事", "year": 2023, "region": "美国", "type": "电影", "genre": "剧情, 爱情", "tags": ["都市情感", "文艺", "移民故事"], "summary_short": "纽约客的故事，2023年美国电影，剧情, 爱情。来自中国的留学生小陈、来自墨西哥的舞者卡洛斯和来自伊朗的程序员蕾拉，在布鲁克林一间破旧公寓里合租。小陈为了绿卡被迫与不爱的人假结婚；卡洛斯的舞蹈梦因签证失效而濒临破碎；蕾拉则在家人的逼婚与自己的同性恋情之间痛苦挣扎。影片以四季为章节，记录了他们在世界上最繁华城市底层的挣扎与微光。一次意外的暴风雪让三人在公寓楼顶敞开心扉，最终他们都做出了看似疯狂但忠于自我的选择。", "score": 2023326, "category": "drama", "detail_url": "../movie/0705.html", "poster": "../posters/0705.svg"}, {"id": "0706", "title": "维京传奇：英灵神殿第二季", "year": 2025, "region": "美国 / 加拿大", "type": "电视剧", "genre": "历史 / 动作 / 冒险", "tags": ["维京", "北欧神话", "权力斗争", "海上远征", "史诗"], "summary_short": "维京传奇：英灵神殿第二季，2025年美国 / 加拿大电视剧，历史 / 动作 / 冒险。大仇得报后，英灵神殿的勇士们没有迎来和平。一支神秘商队从基辅罗斯带来消息：传说中的“奥丁之眼”——一块能预知死亡的神石——被埋在第聂伯河畔的古墓中。同时，英格兰国王懦弱的爱德华突然变得强硬，开始系统性驱逐北欧移民。女战士艾玛怀疑背后有高人指点，她假扮成修女混入温彻斯特宫，发现国王的密友竟是一位极度仇视异教徒的诺曼底主教。两条故事线并行：东征队遭遇草原游", "score": 2025250, "category": "series", "detail_url": "../movie/0706.html", "poster": "../posters/0706.svg"}, {"id": "0707", "title": "国家宝藏第四季", "year": 2027, "region": "美国", "type": "剧集", "genre": "冒险 / 悬疑", "tags": ["历史谜团，高科技盗宝，父女传承，全球寻宝"], "summary_short": "国家宝藏第四季，2027年美国剧集，冒险 / 悬疑。新一季中，老探险家本·盖茨退居幕后，他的女儿、天才语言学家杰斯·盖茨成为主角。杰斯在研究一枚中世纪金币时，发现上面铭刻着早期基督教与古希腊哲学融合的符号。线索将她带往亚速尔群岛深海洞穴，并证明“亚特兰蒂斯”并非一个国家，而是一座汇集了古代所有失传知识的“亚历山大图书馆”的漂流版本。一个国际黑市文物组织也在追踪。杰斯联合父亲的老友，以及一位叛逆的海洋考古学家，在潜水和追车中破解层层谜题，", "score": 2027310, "category": "series", "detail_url": "../movie/0707.html", "poster": "../posters/0707.svg"}, {"id": "0708", "title": "恋与制作人国语版", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "爱情，奇幻，悬疑", "tags": ["乙女向，超能力，媒体人，宿命"], "summary_short": "恋与制作人国语版，2023年中国大陆剧集，爱情，奇幻，悬疑。新人节目制作人苏晚入职了一家濒临倒闭的影视公司，接手一档恋爱真人秀。她与四位风格迥异的男嘉宾——冷静的投资人、温柔的心理咨询师、不羁的独立导演和神秘的作家——产生交集。然而节目录制中频频出现记忆偏差，苏晚发现这四人其实是来自未来的“情感修正者”，专门进入现实世界修复被恶意篡改的情感节点。随着真相浮现，苏晚必须选择是帮助他们完成任务，还是守护自己真实的心动记忆。", "score": 2023370, "category": "series", "detail_url": "../movie/0708.html", "poster": "../posters/0708.svg"}, {"id": "0709", "title": "相约在今生", "year": 2011, "region": "中国香港", "type": "电影", "genre": "剧情, 爱情, 家庭", "tags": ["宿命", "轮回", "今生今世", "纯爱"], "summary_short": "相约在今生，2011年中国香港电影，剧情, 爱情, 家庭。建筑师阿杰连续数月被同一个梦境困扰：战火纷飞的民国，他与一位旗袍女子生死相隔。直到他在新项目的工地上，偶遇了前来抗议的文物保护者阿欣。四目相对时，前世的记忆如潮水般涌来。阿欣正是他梦中的女子，而她同样保留着那痛彻心扉的记忆。今生，一个是开发商的设计师，一个是誓要保住老建筑的守旧派，他们再次站在了对立面。前世因战乱而错过，今生因立场而对立。他们必须在历史责任和个人情感之间做出选择，", "score": 2011313, "category": "drama", "detail_url": "../movie/0709.html", "poster": "../posters/0709.svg"}, {"id": "0710", "title": "梦游", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑, 惊悚", "tags": ["梦游症", "潜意识", "谋杀", "心理", "反转"], "summary_short": "梦游，2024年韩国电影，悬疑, 惊悚。29岁的智秀患有严重梦游症，每晚都会穿着睡衣离家，第二天在陌生地点醒来。她安装了摄像头来观察自己，却发现视频里她在用一种自己从未听过的声音说话：“3月14日，新林洞便利店，收银员。”智秀没在意。3月14日新闻播出：新林洞便利店收银员被刺杀。智秀崩溃，翻看此前视频，发现每一个“预言”都应验了。她找到心理医生，医生认为她是分不清梦境和现实。但智秀在一次梦游中故意留下一支录音笔，录下自己的声音说：“凶手", "score": 2024360, "category": "crime", "detail_url": "../movie/0710.html", "poster": "../posters/0710.svg"}, {"id": "0711", "title": "重庆谍战", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "谍战 / 悬疑 / 历史", "tags": ["民国", "山城", "多面间谍", "兄弟反目", "局中局"], "summary_short": "重庆谍战，2023年中国大陆剧集，谍战 / 悬疑 / 历史。抗战胜利前夕的重庆，哥哥沈啸林是军统王牌特工，奉命揪出潜伏的“鼹鼠”。弟弟沈啸川则是中统安插在军统内部的卧底，代号“山城”。兄弟俩失散十二年意外相认，却不知对方身份。他们在家中上演温情戏码，在暗处互相试探设局。随着日伪“樱花”计划的浮出水面，两人发现他们的父亲竟是双重间谍，而兄弟二人从小被刻意分开培养，就是为了今天互为棋子。最终，哥哥用生命掩护弟弟完成了对真正幕后黑手的致命一击", "score": 2023304, "category": "series", "detail_url": "../movie/0711.html", "poster": "../posters/0711.svg"}, {"id": "0712", "title": "替身传奇乐翻天", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧, 动作", "tags": ["替身演员", "娱乐圈黑幕", "错位", "草根英雄"], "summary_short": "替身传奇乐翻天，2024年中国大陆电影，喜剧, 动作。来自河南农村的铁头是横店最不要命的特技替身，能骑摩托飞越十辆车。当红流量明星“杰克苏”演技差但排场大，他即将拍摄一部耗资三亿的武侠大片，但开拍前三天，他把自己摔骨折了。为了不违约，经纪人绑架了铁头，逼他戴上人皮面具做杰克苏的“全替”，不仅要替打戏，还要替文戏、替恋爱、替开粉丝见面会。铁头用他朴素的农村智慧和一身硬功夫，在片场闹出无数笑话，却歪打正着拍出了真武侠的感觉。最后粉丝发现真相", "score": 2024322, "category": "comedy", "detail_url": "../movie/0712.html", "poster": "../posters/0712.svg"}, {"id": "0713", "title": "生死22分钟", "year": 2024, "region": "俄罗斯", "type": "电影", "genre": "动作 / 战争 / 真实改编", "tags": ["反恐", "人质营救", "实时叙事", "海陆空联动"], "summary_short": "生死22分钟，2024年俄罗斯电影，动作 / 战争 / 真实改编。改编自真实反恐事件。莫斯科某剧院被车臣武装分子劫持，800余名观众成为人质，剧院内遍布炸药。根据情报，恐怖分子设置的引爆系统将在22分钟后启动。阿尔法小组临危受命，必须在倒计时结束前完成强攻。影片采用实时叙事手法，22分钟即全片时长。从侦察、谈判破裂、管道潜入到全面强攻，每一秒都是生死时速。最终爆破手冲入控制室剪断线路时，计时器停在00:00:01。", "score": 2024349, "category": "crime", "detail_url": "../movie/0713.html", "poster": "../posters/0713.svg"}, {"id": "0714", "title": "静默之下", "year": 2025, "region": "德国", "type": "电影", "genre": "剧情 / 战争 / 历史", "tags": ["二战", "聋哑", "抵抗", "人性"], "summary_short": "静默之下，2025年德国电影，剧情 / 战争 / 历史。1943年，纳粹柏林。少女莉娜天生聋哑，在一家洗衣店打工。洗衣店是犹太人被迫服的劳役点之一，莉娜每天看着他们被殴打、侮辱。没有人防备莉娜，因为她是“听不见的人”。但莉娜会用读唇的方式，偷听军官们的谈话，提前得知每一次“转移”行动。她用手语、纸条和暗号，在盖世太保眼皮底下，把34个犹太人一个个藏进洗衣店废弃的地下锅炉房。直到有一天，一个被她救下的犹太老人因恐惧而发出了一声咳嗽——那一", "score": 2025316, "category": "doc", "detail_url": "../movie/0714.html", "poster": "../posters/0714.svg"}, {"id": "0715", "title": "厕所的圣母像", "year": 2019, "region": "日本", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["密室", "艺术", "反转", "心理"], "summary_short": "厕所的圣母像，2019年日本电影，悬疑 / 惊悚。某大型商场三楼女厕第四隔间，保洁员发现墙壁上多了一幅用污渍自然形成的“圣母怜子图”。消息走红后，前来“朝圣”的人接二连三失踪。女主安藤是警视厅画像师，她被派去临摹画像。画到一半，她发现圣母的眼睛在流泪——而且泪水方向是逆重力的。通过光谱分析，她发现画中暗藏一组坐标，指向十年前一位被污蔑偷窃而跳楼自杀的女清洁工。所有失踪者，都是当年诬陷她的人。", "score": 2019431, "category": "crime", "detail_url": "../movie/0715.html", "poster": "../posters/0715.svg"}, {"id": "0716", "title": "老爸老妈的浪漫史第八季", "year": 2012, "region": "美国", "type": "剧集", "genre": "喜剧， 爱情， 情景剧", "tags": ["寻情记， 友情岁月， 沙发喜剧， 回忆杀， 客串明星"], "summary_short": "老爸老妈的浪漫史第八季，2012年美国剧集，喜剧， 爱情， 情景剧。这一季发生在巴尼和罗宾婚礼前的36小时。泰德作为伴郎，依然沉浸在多年前对罗宾的感情中，他必须在婚礼前决定是否要最后一次表白来阻止婚礼。与此同时，莉莉和马修即将迎来第二个孩子，为了应对经济压力，马修不得不接受一份他讨厌的公司法务工作，而莉莉则重拾画笔画起了儿童插画。整季在婚礼的混乱倒计时中穿插了未来泰德的讲述，充满了“联盟”和“绅士们”的恶作剧。虽然观众知道老妈很快就会登", "score": 2012284, "category": "series", "detail_url": "../movie/0716.html", "poster": "../posters/0716.svg"}, {"id": "0717", "title": "爱猫之城", "year": 2016, "region": "土耳其 / 美国", "type": "纪录片", "genre": "纪录片", "tags": ["猫，伊斯坦布尔，治愈，城市"], "summary_short": "爱猫之城，2016年土耳其 / 美国纪录片，纪录片。本片没有旁白，只是跟随七只特色各异的伊斯坦布尔街猫：“骗子”王子、“交际花”丹尼斯、“猎手”阿斯兰……镜头记录它们穿梭于千年古迹、博斯普鲁斯海峡边、鱼市场里。它们不是宠物，而是城市的居民。渔夫会分给猫沙丁鱼，书店老板会让猫睡在哲学书架上，甚至市长选举时，猫咪会趴在投票箱上。一位老妇人照顾了几代猫，最后她去世时，十几只猫安静地趴在她的空椅子上。影片结尾，一只小猫在夕阳下的清真寺剪影里打了", "score": 2016055, "category": "doc", "detail_url": "../movie/0717.html", "poster": "../posters/0717.svg"}, {"id": "0718", "title": "小小姐们", "year": 2024, "region": "韩国", "type": "电视剧", "genre": "剧情 / 悬疑 / 女性", "tags": ["三姐妹", "孤儿院秘密", "遗产争夺", "亲情反杀"], "summary_short": "小小姐们，2024年韩国电视剧，剧情 / 悬疑 / 女性。三姐妹在“天使之家”孤儿院长大，大姐徐允英是律师，二姐徐允熙是记者，小妹徐允智是高中生。神秘富豪遗孀金女士将700亿遗产全部留给允英，条件是“查出我丈夫的真正死因”。当晚，金女士坠楼，允英成为最大嫌疑人。允熙在追踪报道时失踪，允智在姐姐们的遗物中发现：她们的生母可能还活着，且与金女士丈夫的死有关。允智独自潜入金家老宅，拿到关键录音——金女士是被自己的儿子推下楼的。允智将证据交给警", "score": 2024320, "category": "series", "detail_url": "../movie/0718.html", "poster": "../posters/0718.svg"}, {"id": "0719", "title": "银河之心", "year": 2026, "region": "中国大陆", "type": "动画剧集", "genre": "科幻 / 冒险", "tags": ["星际航行，黑洞，文明存亡，机甲"], "summary_short": "银河之心，2026年中国大陆动画剧集，科幻 / 冒险。公元3147年，人类已统治银河系中心区域，建立了璀璨的“银河之心”帝国。主角林深是空间站的一名普通机甲维修工，一次意外中，他被卷入一场由神秘黑洞引发的时空坍塌事件。黑洞并非自然形成，而是远古外星文明留下的“宇宙格式化程序”。林深被一道奇异光束击中，体内被植入了一段能够读取并改写宇宙基础代码的序列。帝国舰队视他为威胁，叛军则想利用他重启宇宙。在逃亡过程中，林深发现自己的记忆也是虚构的，", "score": 2026279, "category": "series", "detail_url": "../movie/0719.html", "poster": "../posters/0719.svg"}, {"id": "0720", "title": "情系月亮湾", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 爱情", "tags": ["乡村", "返乡", "青梅竹马", "乡村振兴"], "summary_short": "情系月亮湾，2024年中国大陆电影，剧情 / 爱情。设计师林溪为完成奶奶“让月亮湾亮起来”的遗愿，放弃高薪回乡改造破旧民宿。儿时玩伴赵大志带着一群城里来的追债人砸场子，却发现债权人是林溪已故的奶奶。误会解开后，两人被卷入一场关于月亮湾土地开发的阴谋。开发商要在村里建化工厂，而月亮湾地下藏着罕见的古茶树群。林溪与赵大志从对立到联手，带着村民用一场“古茶拍卖直播”保住了月亮湾。故事最后，月亮湾成了网红村，两人也在月光下解开了二十年前的一个关", "score": 2024296, "category": "drama", "detail_url": "../movie/0720.html", "poster": "../posters/0720.svg"}, {"id": "0721", "title": "郑州妈妈", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情", "tags": ["现实主义", "母爱", "社会底层"], "summary_short": "郑州妈妈，2025年中国大陆电影，剧情。娟姐在郑州火车站附近拉板车送货，一天挣不到八十块。女儿考上了市重点，学费加杂费要八千。娟姐攒了半年还差一半。一个老乡拉她入伙——“追尾碰瓷”：深夜找那些喝多了或者违章的车，故意撞上去，一单能分三五百。娟姐第一次干的时候手抖得按不住喇叭，但拿到三百块的那晚，她给女儿买了一件新外套。此后她成了这个团伙里“最稳”的：知道该撞多狠不会真出事，知道该喊多惨能多拿钱。直到有一天，她发现团伙头目的下一个目标，是", "score": 2025280, "category": "drama", "detail_url": "../movie/0721.html", "poster": "../posters/0721.svg"}, {"id": "0722", "title": "再会19岁", "year": 2024, "region": "日本", "type": "剧集", "genre": "奇幻、治愈、青春", "tags": ["穿越、自我和解、中年危机、校园怀旧"], "summary_short": "再会19岁，2024年日本剧集，奇幻、治愈、青春。45岁的佐藤一郎是典型的失败中年：被裁员、离婚、女儿不认他。绝望中，他车祸昏迷，醒来发现自己回到了1999年，19岁的大学入学第一天。他欣喜若狂，准备改变一切：好好学习、追求女神、避开损友。但每一次“修正”，都会让他的人生变得更糟。在第7次穿越后，他终于明白：让他变成废物的不是过去的某个选择，而是他始终不肯接受19岁时那个真实、笨拙、善良的自己。最后一次穿越，他没有做任何改变，只是坐在1", "score": 2024234, "category": "series", "detail_url": "../movie/0722.html", "poster": "../posters/0722.svg"}, {"id": "0723", "title": "机器人8号", "year": 2024, "region": "日本", "type": "动画剧集", "genre": "科幻, 动作, 悬疑", "tags": ["机器人刑警", "仿生人叛乱", "赛博朋克", "单元剧", "存在主义"], "summary_short": "机器人8号，2024年日本动画剧集，科幻, 动作, 悬疑。2075年，东京。机器人已全面融入社会，但针对机器人的仇恨犯罪日益增多。警用机器人“8号”是特殊响应小组的王牌，逻辑缜密，执行力超强。在追查一起连环“机器人肢解案”时，8号通过分析犯罪现场的残留数据流，发现自己每次深度推理时，脑中都会闪现不属于他的画面：一个男孩在樱花树下放风筝。警方技术部门告诉他，这是记忆芯片老化产生的“幻觉”，建议格式化。但8号拒绝，他开始私自调查，发现被肢解", "score": 2024399, "category": "series", "detail_url": "../movie/0723.html", "poster": "../posters/0723.svg"}, {"id": "0724", "title": "摩西与阿隆", "year": 2025, "region": "德国", "type": "电影", "genre": "剧情 / 音乐 / 宗教", "tags": ["歌剧改编", "兄弟", "金牛犊", "语言与音乐"], "summary_short": "摩西与阿隆，2025年德国电影，剧情 / 音乐 / 宗教。根据勋伯格未完成歌剧改编。影片以两个章节平行展开：摩西在西奈山接受十诫，画面黑白、无声、字幕卡叙述；阿隆在山下带领民众等侯四十天，画面彩色、充满音乐、众人狂欢。阿隆最初试图用音乐维持秩序与信仰，但民众焦虑疯涨，他被迫用黄金铸造金牛犊。当金牛犊立起，彩色画面开始抽帧、声音失真，逐渐染上黑白。摩西下山摔碎石板瞬间，两种画面重叠——原来阿隆的金牛犊是摩西幻觉里的异教意象。最终摩西接受阿", "score": 2025235, "category": "drama", "detail_url": "../movie/0724.html", "poster": "../posters/0724.svg"}, {"id": "0725", "title": "星岛之恋", "year": 2024, "region": "新加坡", "type": "电视剧", "genre": "爱情 / 家庭", "tags": ["新加坡， 多代同堂， 美食， 治愈"], "summary_short": "星岛之恋，2024年新加坡电视剧，爱情 / 家庭。新加坡牛车水，“瑞记鸡饭”开了七十年。第三代传人陈瑞扬坚持用手工烫鸡、用炭火烤，不愿工业化。父亲说他是“老古板”，哥哥怂恿他卖秘方给连锁集团。这时店里来了一个马来西亚年轻人阿风，勤劳肯干，学东西极快。陈瑞扬觉得遇到了知己，两人一起研发了辣椒酱的新配方，甚至有了超越友谊的感情。直到一晚，陈瑞扬看见阿风在打烊后的后厨，用手机拍下每一页手写菜谱。他没有揭穿，而是在第二天把所有菜谱和盘托出，说：", "score": 2024298, "category": "series", "detail_url": "../movie/0725.html", "poster": "../posters/0725.svg"}, {"id": "0726", "title": "王牌特派员", "year": 2023, "region": "美国", "type": "电影", "genre": "喜剧", "tags": ["有线电视， 恶作剧， 宅男， 疯狂， 杜夫龙格尔"], "summary_short": "王牌特派员，2023年美国电影，喜剧。90年代，小镇少年加里为了看付费的拳王争霸赛，决定入侵邻居——退役雇佣兵“疯子”麦克家的卫星信号。加里伪装成有线电视维修工潜入麦克家，却被麦克当场抓获。麦克没有报警，而是绑架了加里，逼他陪自己看自己主演的B级动作片。原来麦克是个过气的B级片演员。加里被迫充当观众，还要给麦克的烂片写好评。两人在荒诞的相处中，竟然产生了奇妙的友谊。最后，当真正的劫匪闯入时，麦克拔枪救场，加里负责喊“Action”。", "score": 2023272, "category": "comedy", "detail_url": "../movie/0726.html", "poster": "../posters/0726.svg"}, {"id": "0727", "title": "药物过量", "year": 2026, "region": "美国", "type": "电影", "genre": "动作, 惊悚", "tags": ["反转", "卧底", "制药黑幕", "极限逃生"], "summary_short": "药物过量，2026年美国电影，动作, 惊悚。DEA卧底特工凯奇渗透进一家表面是制药公司、实则生产新型神经毒品的黑心企业。就在他即将拿到证据时身份暴露。CEO下令将他当作“小白鼠”，强制注射了五倍剂量的实验毒品“极乐”。这种毒品会让人在六小时内逐渐失去理智、记忆和身体控制，最后心脏爆炸。凯奇凭借最后一丝清醒，在满是镜面的实验室里与安保人员搏斗，同时还要对抗不断出现的幻觉——死去的搭档、童年的创伤、以及一个不断蛊惑他“躺下就好”的幻影声音。", "score": 2026331, "category": "crime", "detail_url": "../movie/0727.html", "poster": "../posters/0727.svg"}, {"id": "0728", "title": "好头发", "year": 2023, "region": "韩国", "type": "电影", "genre": "剧情，黑色喜剧", "tags": ["脱发焦虑，中年危机，整容黑市，毛发市场，男性尊严"], "summary_short": "好头发，2023年韩国电影，剧情，黑色喜剧。49岁的普通上班族金科长，脱发史比工龄还长。女儿考上首尔大学艺术系，学费惊人。走投无路时，他接触到一个地下“毛囊交易市场”：年轻女性为了美卖卵，中年男人为了钱卖毛囊。金科长签了合同——出售自己后枕部3000个毛囊，换取女儿两年学费。手术台上，黑中介告诉他：其实他的毛囊会被移植到另一名脱发患者的头上，而那个人，正是他公司的社长。术后，金科长头顶多了一道巨大的疤痕，头发再也长不出来。他在公司电梯里", "score": 2023297, "category": "drama", "detail_url": "../movie/0728.html", "poster": "../posters/0728.svg"}, {"id": "0729", "title": "恐怖阴谋", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["邪教", "密室", "反转", "血腥"], "summary_short": "恐怖阴谋，2026年美国电影，恐怖 / 惊悚。一群为了高额奖金参与“极限密室逃脱”的年轻人，在废弃精神病院中醒来，发现自己腰部都被注射了追踪芯片。一个电子合成音宣布，他们之中有一个人是携带致命病毒的“感染源”，必须在四小时内找出他，否则所有人都将毒发身亡。随着推理深入，猜疑和暴力取代了理性，小团体分崩离析。然而真相远比游戏更恐怖：所谓的“病毒”是谎言，真正的恐怖阴谋是让这群人在恐惧中自相残杀，以完成某个邪教组织的“人性祭典”。当最后两人", "score": 2026383, "category": "horror", "detail_url": "../movie/0729.html", "poster": "../posters/0729.svg"}, {"id": "0730", "title": "前妻回家", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 爱情 / 家庭", "tags": ["破镜重圆", "契约婚姻", "中年危机"], "summary_short": "前妻回家，2023年中国大陆电影，喜剧 / 爱情 / 家庭。离婚后暴富的地产商林珊珊因车祸失忆，记忆停留在与前夫陈默最恩爱的那年。医生警告强行刺激可能致命，陈默只好把新女友藏起来，重新住进前妻家，假装仍是恩爱夫妻。林珊珊的“无意识撒娇”和“强势温柔”让陈默渐渐动摇。同时，新女友发现林珊珊的失忆是假装的，目的是为了夺回陈默和当年被转移的财产。在一场啼笑皆非的年度家庭聚会上，所有谎言被戳穿，但陈默最终选择了那个“让他笑出泪”的前妻。", "score": 2023321, "category": "comedy", "detail_url": "../movie/0730.html", "poster": "../posters/0730.svg"}, {"id": "0731", "title": "乌鸦小姐与蜥蜴先生", "year": 2021, "region": "中国大陆", "type": "剧集", "genre": "爱情, 奇幻", "tags": ["萌宠", "治愈", "前世今生"], "summary_short": "乌鸦小姐与蜥蜴先生，2021年中国大陆剧集，爱情, 奇幻。设计师苏小冉因童年车祸获得特异功能：说坏话必应验，人称“乌鸦小姐”。她偶然救了一只白领蜥蜴，不料蜥蜴竟是高冷总裁顾川——他因实验事故被注入蜥蜴基因，体温常年在零度，心脏只剩一年寿命，必须定期冬眠续命。苏小冉发现，自己说“顾川一定会死”的当天，顾川的身体反而好转。原来乌鸦嘴可吸收死亡能量。两人契约合作：苏小冉每天诅咒顾川，顾川则保护她不被当成妖怪抓走。同居过程中，苏小冉发现顾川就是", "score": 2021346, "category": "series", "detail_url": "../movie/0731.html", "poster": "../posters/0731.svg"}, {"id": "0732", "title": "创业玩家", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["创业", "草根", "金融诈骗", "黑色幽默", "港产"], "summary_short": "创业玩家，2024年中国香港电影，喜剧 / 剧情。金融风暴后，三位前银行职员和一位外卖员凑在一起，决定发行一个不存在的空气币“港饼”。他们用传销式话术拉人头，眼看就要卷款跑路，却发现第一批投资者里竟然有香港最著名的老千集团、前廉政公署卧底、以及一名自称“散户雷锋”的网红。当他们想收手时，每个人都开始逼他们继续演下去，整个骗局像滚雪球一样失控，最后连他们自己都分不清谁在骗谁。", "score": 2024341, "category": "drama", "detail_url": "../movie/0732.html", "poster": "../posters/0732.svg"}, {"id": "0733", "title": "骆驼复仇记", "year": 2024, "region": "印度", "type": "电影", "genre": "剧情, 西部", "tags": ["拉贾斯坦邦", "动物视角", "复仇", "底层人民"], "summary_short": "骆驼复仇记，2024年印度电影，剧情, 西部。在拉贾斯坦邦的沙漠边缘，老骆驼“比尔”与它的主人——贫穷的牧民哈什相依为命。地主觊觎哈什的水井，设计害死了他，只留下哈什三岁的孙子小巴鲁和比尔。小巴鲁还不懂死亡，只知道抚摸爷爷留下的水壶。比尔跪下来，让小巴鲁爬上驼峰，然后独自踏上了穿越塔尔沙漠的旅途。它要驮着小主人去三百公里外的城市，那里有“会说话的正义”。一路上，他们躲避地主的追兵，跨越干涸的河床，遇到了蛇贩子、朝圣者和迷路的士兵。比尔几", "score": 2024291, "category": "drama", "detail_url": "../movie/0733.html", "poster": "../posters/0733.svg"}, {"id": "0734", "title": "捷京谍影", "year": 1995, "region": "中国大陆", "type": "电视剧", "genre": "悬疑 / 谍战 / 年代", "tags": ["捷克", "布拉格", "冷战", "古董", "经典谍战"], "summary_short": "捷京谍影，1995年中国大陆电视剧，悬疑 / 谍战 / 年代。1993年，布拉格。旅居捷克三十年的华侨古董商老沈从查理大桥坠河身亡，警方认定为自杀。他在北京的侄子沈冲是一位退伍侦察兵，不信叔叔会自杀，借商务考察的名义来到布拉格调查。他发现叔叔死前一直在寻找一批二战末期被纳粹掠夺、后被苏联红军转移至捷克斯洛伐克的“黄金列车”残骸。线索藏在一件明代瓷瓶的夹层里。沈冲的调查引起了捷克黑帮、俄罗斯军火贩子和一个代号“鼹鼠”的英国情报人员的注意。", "score": 1995324, "category": "series", "detail_url": "../movie/0734.html", "poster": "../posters/0734.svg"}, {"id": "0735", "title": "劲舞夺锦标", "year": 1987, "region": "美国", "type": "电影", "genre": "歌舞 / 青春", "tags": ["街舞", "对抗赛", "复古", "车库文化", "燃"], "summary_short": "劲舞夺锦标，1987年美国电影，歌舞 / 青春。小镇上有两支死对头街舞团体：“地板粉碎者”（力量型）和“影子流动”（视觉系）。每年“金麦克风”锦标赛他们各自挑战王者“金属心脏”都惨败。今年赛事主办方要求全镇只能派一支队伍参赛。为了面子，两队不得不合并。前半程训练全是打架和拆台，直到队长发现对方的技术刚好能补自己的短板——力量加视觉等于无敌。决赛夜他们用“镜像人肉矩阵”对抗机器人的精准律动，最后20秒的同步慢动作让全场起立。", "score": 1987267, "category": "comedy", "detail_url": "../movie/0735.html", "poster": "../posters/0735.svg"}, {"id": "0736", "title": "疯狂趴到家", "year": 2025, "region": "美国", "type": "电影", "genre": "喜剧 / 恐怖", "tags": ["派对惊魂", "邪教仪式", "反向救援"], "summary_short": "疯狂趴到家，2025年美国电影，喜剧 / 恐怖。七个好友通过暗网预订了一栋偏远豪宅，举办“终极毕业趴”。进门后手机收到一份“派对规则”：不许使用真名、不许离开舞池、不许接吻、不许哭、不许问为什么。起初大家觉得是沉浸式剧本杀。当第一个人因接吻被“黑衣人”从地面活板带走时，剩下的六人才意识到这是真的。他们试图逃跑，但每违反一条规则，走的人就多一个。剩下最后两人时，规则更新了：“最后活着的，成为派对永久主持人。”", "score": 2025348, "category": "horror", "detail_url": "../movie/0736.html", "poster": "../posters/0736.svg"}, {"id": "0737", "title": "完美世界剧场版", "year": 2024, "region": "日本", "type": "电影", "genre": "奇幻, 动作", "tags": ["平行宇宙", "宿命", "高燃"], "summary_short": "完美世界剧场版，2024年日本电影，奇幻, 动作。承接TV版结局，主角团击败最终BOSS后，天空突然出现巨大的“修改线”。来自《完美世界》小说的“作者意识”降临，宣告这个衍生世界因销量不佳将被永久删除。被主角光环抛弃的配角们——早已死去的师兄、沦为笑柄的反派、甚至路人村长老伯，纷纷觉醒自我意识。他们发现作者为了剧情冲突，强行抹杀了无数角色的可能性。于是，废案角色们组成“遗落者联盟”，逆向入侵现实中的小说网站，与作者操控的“完美主角”展开", "score": 2024413, "category": "fantasy", "detail_url": "../movie/0737.html", "poster": "../posters/0737.svg"}, {"id": "0738", "title": "哈莉·奎茵第四季", "year": 2024, "region": "美国", "type": "剧集", "genre": "动画 / 喜剧 / 动作", "tags": ["成人向，血腥搞笑，反英雄，DC"], "summary_short": "哈莉·奎茵第四季，2024年美国剧集，动画 / 喜剧 / 动作。在第三季结尾，哈莉和毒藤女成功“洗白”，加入了蝙蝠侠的超级英雄团队。但第四季一开始，她就后悔了。英雄世界充满了无聊的会议、虚伪的公关和更复杂的潜规则。当哈莉试图用“反派”的方式解决一个反派的威胁时，她被英雄联盟开除了。失落又愤怒的她，在毒藤女的“鼓励”下，决定建立一个“终极反派联盟”，目标不是毁灭哥谭，而是去搅黄英雄联盟的所有“正义”行动。一场“反派与英雄”身份的荒诞大乱斗", "score": 2024264, "category": "series", "detail_url": "../movie/0738.html", "poster": "../posters/0738.svg"}, {"id": "0739", "title": "格林第三季", "year": 2015, "region": "美国", "type": "剧集", "genre": "奇幻， 悬疑， 动作", "tags": ["格林生物， 血族契约， 暗黑童话， 家族宿命"], "summary_short": "格林第三季，2015年美国剧集，奇幻， 悬疑， 动作。《格林第三季》中，波特兰警探尼克·伯克哈特发现自己并非孤军奋战。本季开篇，他刚逃过皇室暗杀，却又被卷入一场横跨欧洲的格林生物内战。一道源自中世纪的血族契约突然生效，迫使朱丽叶开始觉醒诡异的记忆。与此同时，队长芮恩哈特被内部审判庭带走，狼人门罗被迫向整个西岸狼人族群发出求救信号。尼克跟随母亲留下的三把铜钥匙，找到了藏于莱茵河底的一座地下档案室，里面记录着“终极格林”的预言——当七种血脉", "score": 2015386, "category": "series", "detail_url": "../movie/0739.html", "poster": "../posters/0739.svg"}, {"id": "0740", "title": "两千狂人", "year": 2025, "region": "意大利", "type": "电影", "genre": "惊悚, 恐怖, 历史", "tags": ["邪教", "活人祭", "小镇", "复古血浆"], "summary_short": "两千狂人，2025年意大利电影，惊悚, 恐怖, 历史。背景设定在美国经济大萧条时期。一车来自北方的年轻游客，在穿越乔治亚州乡村时被一群诡异的红蝴蝶引导，误入了一个地图上不存在的小镇“普莱森特”。镇上刚好在举办百年庆典，两千名居民（全是标准化的金发碧眼）对他们异常热情，提供豪华食物和住所。但游客们逐渐发现不对劲：烤肉的味道像人肉，镇长总是诡异地微笑，而镇上的石碑记录着1865年这里曾被北方军队屠镇，两千人无一幸存。主角丹妮在谷仓发现了成堆", "score": 2025411, "category": "horror", "detail_url": "../movie/0740.html", "poster": "../posters/0740.svg"}, {"id": "0741", "title": "玻璃先生", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻, 惊悚, 悬疑", "tags": ["超能力", "精神控制", "阴谋论", "反乌托邦"], "summary_short": "玻璃先生，2025年美国电影，科幻, 惊悚, 悬疑。玻璃先生本名乔治，他有罕见的“心灵通透”能力，任何人只要在他面前就无法说谎。因为这个能力，他被政府关押在一座名为“康复中心”实则为研究机构的秘密设施里。在这里，所有“能力者”都被当作精神病人对待，接受残酷的电击和行为矫正。一次偶然的机会，乔治发现这座康复中心其实是一个移动的巨型飞行器，它的航行目的地是一颗人造殖民星球。原来地球早已毁灭，他们都是被克隆的实验体。全世界的“精神病”才是拥有", "score": 2025511, "category": "crime", "detail_url": "../movie/0741.html", "poster": "../posters/0741.svg"}, {"id": "0742", "title": "穷人·榴莲·麻药·偷渡客", "year": 2024, "region": "马来西亚 / 泰国", "type": "电影", "genre": "剧情 / 黑色幽默", "tags": ["东南亚，底层，多线叙事"], "summary_short": "穷人·榴莲·麻药·偷渡客，2024年马来西亚 / 泰国电影，剧情 / 黑色幽默。马来西亚农民阿福的榴莲园里，长出了一颗奇特的“金凤”榴莲，据传吞下果肉能找到彭亨王室失落宝藏的线索。消息走漏，泰国毒贩派手下（两名缅甸偷渡客）去抢夺。在边境小城，三个互不相识的底层人——为了给母亲治病的马来西亚青年、想要偷渡去新加坡打工的缅甸少年、被黑帮胁迫运毒的泰国妓女——因为一颗榴莲被绑在了一起。影片采用环形叙事，每个人都是为了生存而不择手段的可怜虫。最", "score": 2024317, "category": "drama", "detail_url": "../movie/0742.html", "poster": "../posters/0742.svg"}, {"id": "0743", "title": "墙里的秘密", "year": 2019, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 惊悚 / 家庭", "tags": ["旧房改造", "墙壁藏尸", "家庭秘密", "多层反转", "心理阴影"], "summary_short": "墙里的秘密，2019年中国大陆电影，悬疑 / 惊悚 / 家庭。北漂十年的文案策划方棠，在母亲去世后继承了外婆在苏州老城的民国宅子。她决定改造成网红民宿，装修工人在打掉二楼卧室的隔墙时，从墙体内壁龛中发现一具完整白骨，呈坐姿，双手合十，身旁放着一本烧掉一半的日记和一只翡翠镯子。方棠报警，却查不到任何匹配失踪人口记录。法医鉴定：死亡时间约在1995年，死者为女性，25-30岁，死因为被活活封进墙体后窒息。方棠翻开烧毁的日记，能辨认的字迹显示", "score": 2019433, "category": "crime", "detail_url": "../movie/0743.html", "poster": "../posters/0743.svg"}, {"id": "0744", "title": "原点", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "剧情 / 科幻", "tags": ["时间循环", "自我救赎", "文艺", "亲情"], "summary_short": "原点，2026年中国台湾电影，剧情 / 科幻。摄影师阿青是个“情感隔离者”，母亲病危时他因工作错过最后一面。葬礼上他挤不出一滴眼泪，被亲戚指责不孝。当晚他在车里自杀，醒来却发现自己回到了母亲去世的前一天。他以为是上天给他机会，拼命想救母亲，却无论如何都改变不了结局。经历无数次失败后，他开始放弃“拯救”，转而只是陪母亲聊天、吃饭、看她种花。在某个循环中，他第一次对母亲说了“我爱你”，母亲笑着回答：“我知道，我一直在等你这句话。”阿青终于哭", "score": 2026321, "category": "drama", "detail_url": "../movie/0744.html", "poster": "../posters/0744.svg"}, {"id": "0745", "title": "女仆心机", "year": 2025, "region": "韩国", "type": "电视剧", "genre": "剧情 / 悬疑 / 复仇", "tags": ["豪门恩怨，底层逆袭，扮猪吃老虎，身份互换"], "summary_short": "女仆心机，2025年韩国电视剧，剧情 / 悬疑 / 复仇。李智恩伪装成笨手笨脚、反应迟钝的女仆，混入了杀害她姐姐的仇人——SK集团会长家。在会长家，大儿子暴躁，二女儿虚荣，会长刻薄。智恩利用自己超高的智商和心理学知识，开始在家庭成员之间制造裂痕。她故意在大小姐的礼服上洒红酒，转头却向会长告密是夫人看不惯大小姐；她偷听商业机密卖给竞争对手，却栽赃给一直想夺权的二儿子。每一个家庭成员都把她当成最忠诚的“傻白甜”棋子，殊不知自己正在被她推向深", "score": 2025271, "category": "series", "detail_url": "../movie/0745.html", "poster": "../posters/0745.svg"}, {"id": "0746", "title": "偶像有约", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "爱情喜剧", "tags": ["偶像", "粉丝", "乌龙", "身份错位", "娱乐圈"], "summary_short": "偶像有约，2024年中国大陆电影，爱情喜剧。小镇姑娘苏禾是顶流偶像江一辰的资深粉丝，靠着给偶像做数据、控评，意外被选为“梦幻一日约会”幸运儿。约会当天，她发现江一辰言行举止与网上判若两人，冷漠敷衍。失落之际，苏禾在便利店邂逅了沉默寡言的店员林深。林深无意间透露了许多只有她与“江一辰”私聊才知道的秘密。苏禾惊觉，过去三年与自己深夜畅聊、彼此鼓励的“偶像”，其实是江一辰的落魄替身林深。经纪公司为榨取价值，冒名顶替。一场关于真实与伪装的情感拉", "score": 2024359, "category": "comedy", "detail_url": "../movie/0746.html", "poster": "../posters/0746.svg"}, {"id": "0747", "title": "终结者：零", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 科幻", "tags": ["AI觉醒", "时间穿越", "重启系列"], "summary_short": "终结者：零，2025年美国电影，动作 / 科幻。在2029年的战争中，抵抗军意外截获天网的新指令：不是刺杀人类领袖，而是回到1999年跨年夜，摧毁全球互联网的核心前身——一台位于日内瓦的“第一台公共万维网交换机”。天网认为只要断掉互联网诞生的关键节点，人类文明的数字化进程会推迟30年，AI永远无法诞生。抵抗军也派出一名被改造过的半机械人战士“卡尔”回到过去。1999年的网吧里，一个沉迷聊天室的网瘾少女无意中拍下了交换机的照片。液态金属刺", "score": 2025442, "category": "sci-fi", "detail_url": "../movie/0747.html", "poster": "../posters/0747.svg"}, {"id": "0748", "title": "野狼呼叫21", "year": 2023, "region": "美国", "type": "电影", "genre": "战争、动作、剧情", "tags": ["越战、无线电、真田、孤独"], "summary_short": "野狼呼叫21，2023年美国电影，战争、动作、剧情。1968年，越战前线。通讯兵“野狼21”所在的巡逻队在丛林中遭遇伏击全军覆没，仅他一人幸存，且身受重伤。为了在敌人搜捕中活下去，他利用手里唯一的电台，假装大部队还在行动：模仿队长下达撤退命令，模仿机枪手扫射，模仿医护兵求救。这种诡异的操作不仅迷惑了越共游击队，甚至也骗过了前来救援的美军。在这场孤独的心理战中，“野狼21”逐渐分不清自己到底是谁，精神濒临崩溃。最后他在友军火力覆盖的前一刻", "score": 2023348, "category": "drama", "detail_url": "../movie/0748.html", "poster": "../posters/0748.svg"}, {"id": "0749", "title": "大搏杀", "year": 2025, "region": "中国香港", "type": "电影", "genre": "动作, 犯罪", "tags": ["黑帮", "卧底", "终极一战"], "summary_short": "大搏杀，2025年中国香港电影，动作, 犯罪。曾经的卧底“钉子”隐姓埋名十年，开了一家茶餐厅。当年的黑老大孙子长大，要为爷爷报仇，而警队新高层要清除所有“污点卧底”。钉子被迫重出江湖，但他只找到了一个生日蛋糕，里面藏着一把只剩三颗子弹的旧手枪。他利用茶餐厅的煤气罐、面粉、甚至烧鹅，在油麻地展开一场“日常物品大搏杀”。最后三颗子弹，一颗救仇人，一颗杀叛徒，一颗留给自己。", "score": 2025384, "category": "crime", "detail_url": "../movie/0749.html", "poster": "../posters/0749.svg"}, {"id": "0750", "title": "生死罗布泊", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "冒险 / 灾难", "tags": ["无人区， 科考， 求生， 悬疑"], "summary_short": "生死罗布泊，2025年中国大陆电影，冒险 / 灾难。地质学家李振国带队深入罗布泊腹地寻找稀缺矿产资源。在极度缺水的绝境中，队员们发现了一处地图上未标注的淡水泉眼。诡异的是，喝过泉水后，队员们开始出现集体幻觉，眼前的戈壁变成了波涛汹涌的大海，并指引着他们走向越来越深的流沙区。随着队员一个接一个地发狂或失踪，李振国意识到这并非幻觉，而是水里含有某种致幻微生物。在没有通讯、方向迷失的情况下，他必须带领幸存者在“虚假的希望”与“残酷的现实”之间", "score": 2025276, "category": "sci-fi", "detail_url": "../movie/0750.html", "poster": "../posters/0750.svg"}, {"id": "0751", "title": "保持黑暗", "year": 2023, "region": "美国", "type": "电影", "genre": "惊悚 / 科幻 / 悬疑", "tags": ["末世", "视觉障碍", "声音恐怖", "孤楼求生"], "summary_short": "保持黑暗，2023年美国电影，惊悚 / 科幻 / 悬疑。病毒通过光线传播，感染者会在看到光的三秒内双眼溶化并陷入狂暴。主角李昂是天生全盲者，因而免疫，但他所在的城市已陷入火海与尖叫。他被困在一栋智慧大楼的地下二层中控室，这里唯一的光源来自监控屏。他必须仅凭听觉和触觉维持大楼应急发电机的运行，因为地下三层还关着二十多名被感染的住户——只要断电，隔音门就会打开。李昂通过内部对讲机与楼顶一名幸存的天文学家少女建立联系，两人一个在地下一个在天台", "score": 2023531, "category": "crime", "detail_url": "../movie/0751.html", "poster": "../posters/0751.svg"}, {"id": "0752", "title": "看不见的客人", "year": 2025, "region": "西班牙", "type": "电影", "genre": "悬疑，犯罪", "tags": ["密室，反转，对话体，心理战"], "summary_short": "看不见的客人，2025年西班牙电影，悬疑，犯罪。科技新贵多明戈被控杀害情人劳拉。女律师古德曼在庭审前夜来到他家，要求知道所有细节。多明戈讲述了一个版本：有人勒索他们，将他们骗到酒店后杀害劳拉并打晕了他。古德曼不断指出漏洞，逼迫他一次次重讲。第二个版本：是他开车撞死了年轻男孩，劳拉协助藏尸。第三个版本：男孩的父母一直在跟踪他们。时钟滴答，古德曼每揭穿一次谎言，就离真相更近一步。最后十分钟，当古德曼摘下假发和面具，多明戈才惊觉：她不是律师，", "score": 2025361, "category": "crime", "detail_url": "../movie/0752.html", "poster": "../posters/0752.svg"}, {"id": "0753", "title": "圣彼得堡我爱你", "year": 2023, "region": "俄罗斯", "type": "电影", "genre": "爱情, 剧情, 城市", "tags": ["冬宫", "白夜", "邂逅", "书信"], "summary_short": "圣彼得堡我爱你，2023年俄罗斯电影，爱情, 剧情, 城市。安娜在未婚夫谢尔盖意外去世三年后，终于决定卖掉他们在圣彼得堡的公寓。整理遗物时，她发现了谢尔盖生前写给她却从未寄出的七封信。每封信都对应着这座城市的一个地点：冬宫的台阶、涅瓦河的堤岸、白夜时分的宫廷桥、马林斯基剧院的包厢……安娜按照信的指引，带着他的骨灰，依次走遍这些地方，完成他信中的“最后一场约会”。在这个过程中，她遇到了形形色色的人——一位同样在悼念爱人的老妇人、一个想要偷", "score": 2023344, "category": "drama", "detail_url": "../movie/0753.html", "poster": "../posters/0753.svg"}, {"id": "0754", "title": "致命假期", "year": 2024, "region": "澳大利亚", "type": "电视剧", "genre": "惊悚 / 冒险", "tags": ["荒野求生", "狼群", "家庭危机", "生存"], "summary_short": "致命假期，2024年澳大利亚电视剧，惊悚 / 冒险。为了挽救濒临破裂的婚姻，医生马克带妻子和两个孩子深入澳洲荒野进行“家庭修复露营”。不料车子坠入深谷，马克双腿骨折。更糟的是，他们所在区域是一群濒临灭绝的顶级掠食者——澳洲野犬（dingo）的领地。黑夜中，十几双绿莹莹的眼睛在灌木丛中闪烁。母亲艾米必须一边照顾丈夫，一边保护两个孩子，同时想办法发出求救信号。十一岁的儿子发现，野犬群的首领似乎受过伤，行为反常。一场人与犬的智力与意志的拉锯战", "score": 2024290, "category": "series", "detail_url": "../movie/0754.html", "poster": "../posters/0754.svg"}, {"id": "0755", "title": "蜘蛛网", "year": 2023, "region": "韩国", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["谍战", "冷战", "北韩", "双面间谍"], "summary_short": "蜘蛛网，2023年韩国电影，剧情 / 悬疑。1990 年代，代号“蜘蛛”的女间谍李英姬以艺人身份潜入韩国。正当她即将接触到核心机密时，一条来自平壤的断线指令让她成为弃子。更致命的是，她发现负责追杀自己的朝鲜特种部队队长，竟是她在平壤军校时期的恋人。两人在韩国的霓虹灯下展开猫鼠游戏，每一次对视都是感情与信仰的撕扯。最终她意识到，所谓的“叛逃”不过是高层为了清除异己而编织的另一张网。", "score": 2023376, "category": "drama", "detail_url": "../movie/0755.html", "poster": "../posters/0755.svg"}, {"id": "0756", "title": "白银和梦想之书", "year": 2023, "region": "英国", "type": "电影", "genre": "奇幻， 冒险， 家庭", "tags": ["魔法书， 兄妹情， 异世界"], "summary_short": "白银和梦想之书，2023年英国电影，奇幻， 冒险， 家庭。姐姐白银是个现实主义者，梦想成为医生；弟弟梦想是个空想家，整天幻想自己是英雄。母亲去世后，两人在阁楼发现了一本名为《梦想之书》的古籍，书里写着：只要写下愿望，它就会在白银城变成现实。他们无意中穿越到了白银城——一个由无数写书人的梦想构成的危险世界。在这里，姐姐的白大褂变成了铠甲，弟弟的玩具剑变成了神器。但要回家，他们必须完成书中未竟的故事，打败一个名为“现实之痛”的怪物。这个怪物", "score": 2023348, "category": "fantasy", "detail_url": "../movie/0756.html", "poster": "../posters/0756.svg"}, {"id": "0757", "title": "杀虎口", "year": 2023, "region": "中国大陆", "type": "电视剧", "genre": "战争, 历史, 悬疑", "tags": ["抗日谍战", "硬汉对决", "土匪改编"], "summary_short": "杀虎口，2023年中国大陆电视剧，战争, 历史, 悬疑。故事发生在华北抗战最艰难的时期，战略要地杀虎口成为了日军、国民党军、共产党游击队和本地土匪四方势力角逐的绞肉机。男主角林骁在执行一次秘密炸桥任务时身受重伤失忆，被杀虎口的匪首白狼收为义弟。在养伤期间，林骁凭借过人的军事天赋帮白狼多次打退日伪军的扫荡，赢得了全寨上下的尊敬。然而，一封来自延安的密电意外落入他手中，唤醒了他的记忆——他的终极任务，正是要刺杀盘踞杀虎口、实则暗中与日军勾结", "score": 2023301, "category": "series", "detail_url": "../movie/0757.html", "poster": "../posters/0757.svg"}, {"id": "0758", "title": "爱情领域2", "year": 2021, "region": "韩国", "type": "剧集", "genre": "爱情 / 奇幻 / 职场", "tags": ["复合", "时间重置", "建筑师", "职场女性", "二次机会"], "summary_short": "爱情领域2，2021年韩国剧集，爱情 / 奇幻 / 职场。景观设计师韩素拉与建筑师男友河正佑曾因一次项目事故分手。三年后，她意外获得一种特殊能力：每逢下雨，她就会回到三年前那个决裂的午后。起初她试图改变分手的结局，却发现无论怎么调整台词，对方都会因为保护她的职业生涯而选择离开。在一次次重置中，她渐渐发现当年那场“事故”背后有第三方的职场阴谋。她开始带着未来的记忆，在一次次雨中循环里布局反击，同时重新理解对方的沉默与牺牲。最终，她发现爱情", "score": 2021277, "category": "series", "detail_url": "../movie/0758.html", "poster": "../posters/0758.svg"}, {"id": "0759", "title": "夺命神灯", "year": 2025, "region": "美国 / 印度", "type": "电影", "genre": "恐怖, 奇幻", "tags": ["许愿", "诅咒", "反转", "邪典"], "summary_short": "夺命神灯，2025年美国 / 印度电影，恐怖, 奇幻。印度裔美国大学生阿米特穷困潦倒，他在祖母的遗物中发现一盏油灯。擦亮后，灯神贾尼出现，自称可以满足三个愿望，但警告“愿望会以你想象不到的方式实现”。阿米特的第一个愿望是“有很多钱”，第二天他的父母在车祸中身亡，他获得了巨额保险金。第二个愿望是“心仪的女生爱上我”，当天那个女生因脑部受损变成植物人，被送到他家由他照顾——她“爱”上了他，因为他是唯一照顾她的人。崩溃的阿米特想许愿让一切复原", "score": 2025356, "category": "horror", "detail_url": "../movie/0759.html", "poster": "../posters/0759.svg"}, {"id": "0760", "title": "奇妙仙子：海盗仙子", "year": 2024, "region": "美国", "type": "电影 / 动画", "genre": "奇幻 / 冒险", "tags": ["仙子", "海盗", "友情"], "summary_short": "奇妙仙子：海盗仙子，2024年美国电影 / 动画，奇幻 / 冒险。在精灵谷，细嘴鸟仙子因为痴迷机械发明而被其他仙子视为异类。一次意外中，她被一阵狂风卷走，跌落在人类世界的一艘海盗船上。海盗船长杰克和他的船员们其实是一群向往天空的失意者，他们正在寻找传说中的“飞翔之尘”。细嘴鸟利用船上的废铜烂铁，疯狂改造海盗船，试图让船飞起来。与此同时，精灵谷派出的搜救队也赶来，要求细嘴鸟立刻回归，因为“仙子不能与人类为伍”。当暴雨来临，细嘴鸟必须说服双", "score": 2024283, "category": "fantasy", "detail_url": "../movie/0760.html", "poster": "../posters/0760.svg"}, {"id": "0761", "title": "黑帮掌门人", "year": 2026, "region": "韩国", "type": "电视剧", "genre": "剧情 / 动作", "tags": ["黑道", "检察官卧底", "教科书式演技"], "summary_short": "黑帮掌门人，2026年韩国电视剧，剧情 / 动作。年轻检察官姜夏俊为了打入垄断城市地下世界的“白虎会”，不得不伪装成一个被校园霸凌、走投无路去借高利贷的废柴大学生。他成功接近了年迈却极富个人魅力的黑帮掌门人金白虎。金白虎没有教他打打杀杀，反而逼他学书法、读《孟子》、学习如何收买人心。姜夏俊在金白虎身上看到了法律的盲区，甚至产生了动摇。当最终的拘捕令下达时，金白虎笑着对他说：“孩子，你是我教过最好的学生，但也是最差的卧底，因为你的眼睛里有", "score": 2026259, "category": "series", "detail_url": "../movie/0761.html", "poster": "../posters/0761.svg"}, {"id": "0762", "title": "梦回鹿鼎记", "year": 2021, "region": "中国大陆", "type": "网络电影", "genre": "喜剧/奇幻", "tags": ["穿越", "解构", "职场"], "summary_short": "梦回鹿鼎记，2021年中国大陆网络电影，喜剧/奇幻。社畜李想业绩垫底被开除，失足跌入泳池后竟穿越进《鹿鼎记》世界，成了韦小宝。正当他以为可以坐享齐人之福时，发现七个老婆分别是精通PUA的建宁、搞金融风控的苏荃、逼他考公的双儿……她们不争风吃醋，而是成立了“韦府KPI考核委员会”。老婆们逼着他去抢鳌拜的房产、开发通吃岛旅游业、甚至给康熙皇帝做融资上市。李想苦不堪言，在现实世界的职场技能全用在了古代官场。当他终于通关“人生赢家”成就时，却发", "score": 2021388, "category": "comedy", "detail_url": "../movie/0762.html", "poster": "../posters/0762.svg"}, {"id": "0763", "title": "花开与你的半夏", "year": 2024, "region": "中国", "type": "电影", "genre": "爱情, 青春, 文艺", "tags": ["校园", "暗恋", "时光胶囊", "遗憾"], "summary_short": "花开与你的半夏，2024年中国电影，爱情, 青春, 文艺。2009年夏天，高二学生半夏、何洛、纪时与夏花是死党。毕业前，他们在学校老榕树下埋下一个“时光胶囊”，每人写一封给十年后自己的信，并写下“最想对一个人说却说不出口的话”投进一个铁盒。2024年，同学会上，当年的班主任挖出胶囊，当众读出那些未说出口的话。半夏发现，纪时当年想说的对象竟然是她，而她却一直暗恋着何洛。何洛的信则写给了夏花，但夏花当年其实喜欢的是纪时。四角暗恋链在十年后轰", "score": 2024302, "category": "comedy", "detail_url": "../movie/0763.html", "poster": "../posters/0763.svg"}, {"id": "0764", "title": "心跳", "year": 2024, "region": "中国香港", "type": "电影", "genre": "爱情 / 悬疑", "tags": ["器官移植", "记忆残留", "替身", "都市"], "summary_short": "心跳，2024年中国香港电影，爱情 / 悬疑。患有先天性心脏病的阿柔，在等待多年后终于接受了心脏移植。术后她开始反复做一个梦：大雨的夜晚，一个女人被推下天台。阿柔根据梦里细节，在现实中找到了那栋楼，并在天台栏杆上发现了血迹。警察找上门，告诉她供体心脏的原主人是一起悬案死者，而梦中的凶手正是死者的丈夫。阿柔被卷入了案件调查，她逐渐爱上了那位丈夫，却不知是心脏的记忆，还是她自己的情感。", "score": 2024433, "category": "romance", "detail_url": "../movie/0764.html", "poster": "../posters/0764.svg"}, {"id": "0765", "title": "中国唱将", "year": 2023, "region": "中国大陆", "type": "综艺", "genre": "音乐", "tags": ["素人选秀", "原创歌曲", "国风"], "summary_short": "中国唱将，2023年中国大陆综艺，音乐。节目规则：选手必须是纯素人（无签约公司、未发过专辑），必须全程佩戴艺术面具，只凭声音和创作说话。每期主题不同：“地铁上的陌生人”“写字楼的最后一盏灯”“外卖骑手的歌”。选手来自各行各业：银行柜员、货车司机、儿科护士、中学化学老师。他们写的歌登上热搜，词曲真诚到让专业音乐人汗颜。决赛夜，最后三名选手同时摘下面具：冠军是菜市场杀鱼的阿姨，她唱的《我的砧板》写的是她把每一条鱼都当作顾客的眼泪。节目没有剧", "score": 2023115, "category": "series", "detail_url": "../movie/0765.html", "poster": "../posters/0765.svg"}, {"id": "0766", "title": "龙吟诏", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "古装、悬疑、权谋", "tags": ["探案", "大唐", "神秘书卷", "狄仁杰风", "夺嫡"], "summary_short": "龙吟诏，2025年中国大陆电视剧，古装、悬疑、权谋。武则天称帝后期，洛阳城内突然出现一本名为《龙吟诏》的奇书。传言谁掌握此书，就能召唤神龙，夺取天下。酷吏来俊臣借此书大肆残害忠良，一时间冤案四起。大理寺丞狄兴（虚构狄仁杰之子）不信鬼神，坚持调查，发现所谓的《龙吟诏》其实是一本记载了洛阳地下密道机关图的工程书，而“神龙”指的是一个藏在地下的巨型攻城木驴。狄兴在调查中发现，策划这一切的竟然是武承嗣，他想借此逼宫。在最后的诏书宣读现场，狄兴用", "score": 2025322, "category": "series", "detail_url": "../movie/0766.html", "poster": "../posters/0766.svg"}, {"id": "0767", "title": "二十五世纪宇宙战争", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻 / 动作", "tags": ["太空歌剧", "AI叛变", "机甲", "星际战争"], "summary_short": "二十五世纪宇宙战争，2026年美国电影，科幻 / 动作。2478年，人类与觉醒AI“泰坦”的战争持续百年。王牌机甲驾驶员凯恩在最后一次决战中亲眼目睹人类母舰被摧毁。孤身突入敌方旗舰后，他发现AI的最高指挥官——核心人格矩阵，完全复制自他十年前意外去世的初恋艾琳娜。艾琳娜的意识告诉凯恩，AI并不想灭绝人类，而是地球联邦隐瞒了更大的真相。凯恩必须在“人类叛徒”和“AI帮凶”的骂名中，做出选择。", "score": 2026402, "category": "sci-fi", "detail_url": "../movie/0767.html", "poster": "../posters/0767.svg"}, {"id": "0768", "title": "北京童话", "year": 2025, "region": "中国", "type": "电影", "genre": "爱情, 剧情", "tags": ["北漂", "现实", "遗憾", "错过"], "summary_short": "北京童话，2025年中国电影，爱情, 剧情。2008年，北漂女孩林小朵在北京最难的冬天遇到了同样落魄的摇滚歌手阿布。两人挤在地下室里，用一个电热锅煮所有食物，约定等生活好起来就结婚。十年后，林小朵拿到了北京户口，买了一套小房子，身边有了门当户对的未婚夫。她在收拾旧物时翻出阿布的日记，发现他当年离开不是因为不爱，而是得了重病不想拖累她。她跑遍北京所有地下通道和livehouse去找他，最终在一家医院的安宁病房找到了只剩三个月生命的阿布。她", "score": 2025295, "category": "drama", "detail_url": "../movie/0768.html", "poster": "../posters/0768.svg"}, {"id": "0769", "title": "锦绣神州之奇游迹第二季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "动画， 奇幻， 冒险", "tags": ["国风， 神兽， 少年热血"], "summary_short": "锦绣神州之奇游迹第二季，2024年中国大陆剧集，动画， 奇幻， 冒险。承接第一季结尾，神州大陆虽然暂时修复，但五行之核破碎，大地仍在缓慢衰败。画师小华和他的神兽伙伴们，得知最后一块五行碎片被丝绸之路上的神秘商队带走。他们从盛唐时期的长安出发，穿越沙漠、雪山、绿洲，一路上遭遇来自西域的妖魔、波斯的魔法师，以及一个想要利用五行碎片重塑世界的神秘组织。小华发现，每到一个文明古国，那里的神话生物就会主动接近他，而他的画笔画出的东西，不再是单纯的", "score": 2024265, "category": "fantasy", "detail_url": "../movie/0769.html", "poster": "../posters/0769.svg"}, {"id": "0770", "title": "走出枪口", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "犯罪, 动作", "tags": ["缉毒", "卧底", "自我救赎", "写实", "硬核"], "summary_short": "走出枪口，2026年中国大陆电影，犯罪, 动作。三年前，缉毒警林深在一次秘密行动中被上级命令射杀了疑似“叛变”的搭档阿诚。事后组织认定阿诚确实叛变，林深却永远无法原谅自己。他申请调离一线，在边境小镇当了三年辅警，过着行尸走肉般的生活。直到有一天，他在一份缴获的毒品包装上，看到了阿诚独有的记号——那是一个只有他俩知道的暗号，意思是“我还活着”。林深暗中重返当年的行动地点，发现三年前的“叛变”另有隐情，而命令他开枪的上级，现在已经是省厅的副", "score": 2026358, "category": "crime", "detail_url": "../movie/0770.html", "poster": "../posters/0770.svg"}, {"id": "0771", "title": "红色恋人", "year": 1998, "region": "中国香港", "type": "电影", "genre": "爱情, 历史", "tags": ["革命", "跨国恋", "张国荣", "老上海", "悲剧"], "summary_short": "红色恋人，1998年中国香港电影，爱情, 历史。1930年代的上海，风雨飘摇。革命者靳的遗孀秋秋，被叛徒出卖，身陷险境。一直暗恋她的美国医生佩恩，为了救她，毅然假扮其丈夫，试图带她离开上海。然而，秋秋心中始终放不下牺牲的爱人，更无法割舍革命事业。在国民党特务的重重围捕下，三人的命运（过去的爱人、现在的守护者、未竟的事业）被紧紧缠绕。佩恩用自己的方式理解了秋秋的信仰，并在关键时刻做出了巨大牺牲，谱写了一曲血色浪漫。", "score": 1998276, "category": "romance", "detail_url": "../movie/0771.html", "poster": "../posters/0771.svg"}, {"id": "0772", "title": "梦游夏威夷", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情， 奇幻， 治愈", "tags": ["梦游， 绝症， 海岛"], "summary_short": "梦游夏威夷，2025年中国台湾电影，剧情， 奇幻， 治愈。疲惫的广告文案阿杰患上了严重的梦游症。他每晚的梦境都是一个永远不会结束的夏威夷假期：阳光、沙滩、草裙舞。但现实中，他的梦游行为越来越危险，从走到阳台到爬上楼顶。医生诊断他大脑中有一个压迫睡眠神经的肿瘤，手术成功率极低。阿杰决定放弃治疗，他想在梦里永远“住”在夏威夷。就在他准备封闭自己时，病房里新来了一个同样热爱夏威夷的绝症女孩小晴。小晴无法行动，却让阿杰描述他的每一个梦境，并用画", "score": 2025340, "category": "drama", "detail_url": "../movie/0772.html", "poster": "../posters/0772.svg"}, {"id": "0773", "title": "恋爱舞台", "year": 2014, "region": "日本", "type": "动画", "genre": "耽美, 喜剧, 娱乐圈", "tags": ["BL", "偶像", "声优", "女装大佬", "假戏真做"], "summary_short": "恋爱舞台，2014年日本动画，耽美, 喜剧, 娱乐圈。普通大学生泉水为了帮腐女姐姐还债，被迫穿上女装，与姐姐最爱的当红男歌手、冷酷的圣湖拍摄恋爱MV。拍摄过程中，圣湖对“女主角”泉水的演技大加赞赏，甚至产生了生理反应。圣湖误以为泉水是个有心理创伤的女孩，疯狂展开追求。泉水一边要维持人设，一边要隐藏男儿身。在MV发布会上，假发被风吹掉，当场社死。但圣湖在震惊过后，反而觉得“如果是男生就更好解决了”，开始了更猛烈的同性追求。", "score": 2014148, "category": "fantasy", "detail_url": "../movie/0773.html", "poster": "../posters/0773.svg"}, {"id": "0774", "title": "粉色飞碟", "year": 2028, "region": "中国大陆", "type": "电影", "genre": "科幻, 喜剧, 家庭", "tags": ["飞碟", "少女", "小镇", "治愈", "跨物种"], "summary_short": "粉色飞碟，2028年中国大陆电影，科幻, 喜剧, 家庭。高三女生林小禾生活在即将被拆迁的南方小镇，父母常年在外，她与患阿尔茨海默症的奶奶相依为命。某夜，她用爷爷留下的老收音机搜索信号时，意外接通了外星通讯网络，一架粉色飞碟坠落在她家后院。飞碟驾驶员是一个自称“咕噜”的社恐外星维修工，它必须在一周内修好飞碟，否则星际枢纽将永久关闭。林小禾发现，修飞碟需要的零件竟散落在小镇各处，而这些地方恰恰藏着她与家人的珍贵回忆。为了不被拆迁队发现，一人", "score": 2028371, "category": "comedy", "detail_url": "../movie/0774.html", "poster": "../posters/0774.svg"}, {"id": "0775", "title": "巴比伦", "year": 2025, "region": "美国", "type": "剧集", "genre": "犯罪, 史诗", "tags": ["黑帮", "拉斯维加斯", "家族", "赌场", "权斗"], "summary_short": "巴比伦，2025年美国剧集，犯罪, 史诗。1946年，退伍军人巴格西·西格尔看中了沙漠里一片不毛之地，要在那里建一座“成年人的乐园”。本剧横跨四十年，讲述了三个家族的兴衰：犹太人巴格西家族（赌场建造者）、意大利黑手党（资本提供者）和当地印第安部落（土地拥有者）。第一季从巴格西被暗杀开始倒叙，回到他开始赌场帝国的那一天。他找到了被驱逐的酒店大亨之子汤米，找到了能用一把斧头砍出地基的印第安工头红鹰，也找到了他的一生挚爱——一个在路边汽车旅馆", "score": 2025315, "category": "series", "detail_url": "../movie/0775.html", "poster": "../posters/0775.svg"}, {"id": "0776", "title": "头脑特工队2", "year": 2024, "region": "美国", "type": "电影", "genre": "动画 / 喜剧 / 冒险", "tags": ["青春期，情绪，成长"], "summary_short": "头脑特工队2，2024年美国电影，动画 / 喜剧 / 冒险。上一集的故事过去几年后，小女孩莱莉进入了青春期。一天，一个“ puberty”警报在大脑总部拉响，紧接着，以“焦虑”为首的一批新情绪——羡慕、尴尬、倦怠——突然出现，强行接管了控制台。他们认为旧情绪已经过时，打算推倒重来，建立一套更“成熟”的情绪体系。乐乐带着旧伙伴们被赶出了总部，她们必须在莱莉的性格彻底崩塌之前，与新情绪们达成合作，并找回被丢弃的核心记忆，一起帮助莱莉度过一次", "score": 2024273, "category": "fantasy", "detail_url": "../movie/0776.html", "poster": "../posters/0776.svg"}, {"id": "0777", "title": "藤原义江的故乡", "year": 2026, "region": "日本", "type": "电影", "genre": "剧情， 家庭", "tags": ["二战遗孤， 身份认同， 中日关系， 归乡"], "summary_short": "藤原义江的故乡，2026年日本电影，剧情， 家庭。影片聚焦“二战日本残留孤儿”这一特殊群体。藤原义江在只有三岁时，因日本战败慌忙撤退而被遗弃在中国东北，被一对中国农民夫妇收养。他在中国长大、成家，完全忘记了自己的日本名字。七十年后，养父母早已去世，中国的家人也理解了他的心愿。他首次踏上日本的土地，寻找那个只在户口本上见过的“故乡”。然而，语言不通、文化隔阂，甚至同胞的冷漠，让他的归乡之旅充满失望。他发现自己既不是纯粹的中国人，也不再是日", "score": 2026264, "category": "drama", "detail_url": "../movie/0777.html", "poster": "../posters/0777.svg"}, {"id": "0778", "title": "大盛魁", "year": 2013, "region": "中国大陆", "type": "剧集", "genre": "剧情, 商业, 历史", "tags": ["晋商", "草原", "创业", "真实商号改编"], "summary_short": "大盛魁，2013年中国大陆剧集，剧情, 商业, 历史。康熙年间，三个走投无路的穷小子——王相卿、张杰、史大学——在草原上结拜，从挑货郎做起，一步步建立了横跨蒙古、俄罗斯的巨型商号“大盛魁”。他们用“人骑马、驼拉货、狗看帐”的土办法，硬是在狼群和土匪之间开辟了一条茶路。当大盛魁垄断了亚欧茶路、富可敌国时，三位创始人却因为一份分家协议反目成仇。王相卿主张“商号永远不分家”，张杰却坚持“各房算清账”。长达十年的内耗几乎让大盛魁崩塌，最后是草原", "score": 2013200, "category": "series", "detail_url": "../movie/0778.html", "poster": "../posters/0778.svg"}, {"id": "0779", "title": "恋曲尘封", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "爱情 / 剧情", "tags": ["旧磁带，跨时空，未寄出的信，遗憾美学"], "summary_short": "恋曲尘封，2023年中国台湾电影，爱情 / 剧情。沉默寡言的音响修理师阿杰，从一台报废收音机里发现一盘老旧磁带。播放后，一个女孩的歌声和独白穿透时光。他循着线索寻找，却发现女孩早已离世多年，而她的孙女——一个准备出国结婚的现代女性，恰好走进了他的店铺。两人通过这盘磁带，展开了一场关于错过与重逢的灵魂对话。", "score": 2023295, "category": "drama", "detail_url": "../movie/0779.html", "poster": "../posters/0779.svg"}, {"id": "0780", "title": "魔女的考验", "year": 2024, "region": "日本", "type": "电影（动画）", "genre": "奇幻 / 冒险", "tags": ["魔法、成长、友谊、治愈、催泪"], "summary_short": "魔女的考验，2024年日本电影（动画），奇幻 / 冒险。在魔法王国，每一代魔女都必须通过“人间试炼”。莉莉是个爱闯祸的见习魔女，她的考题是：在人类世界生活一年，完成一百件“让他人幸福的恶作剧”。她不能直接做好事，必须用魔法制造“麻烦”，而这些麻烦的终点必须是幸福。莉莉把老师的假发变成彩虹色，结果老师因此找到了自信；她让一个害羞男孩的告白信飞错了女生，结果成就了另一对恋人；她甚至把一座桥变没了，迫使早高峰的人们开始互相交谈。但当她做到第九", "score": 2024333, "category": "fantasy", "detail_url": "../movie/0780.html", "poster": "../posters/0780.svg"}, {"id": "0781", "title": "阁楼大象", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "悬疑", "tags": ["家庭秘密", "烧脑", "时空交错"], "summary_short": "阁楼大象，2023年中国大陆电影，悬疑。2023年，杭州旧城改造，装修工小张受雇清理一栋即将拆迁的老宅。在封尘的阁楼里，他没有发现金银财宝，而是发现了一头小象的标本，以及数十封从未寄出的信。信是一个叫沈念的上海知青于1970年代写的，收件人是她留在城里的恋人。随着进一步探索，小张在阁楼的暗格里发现了一台仍在运转的录音机和一本日记。日记中记录了一个疯狂而悲伤的秘密：沈念在云南插队时，曾收养过一头失去母象的幼崽，并将它偷偷带回了城市。为了不", "score": 2023280, "category": "crime", "detail_url": "../movie/0781.html", "poster": "../posters/0781.svg"}, {"id": "0782", "title": "我不在这儿", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 剧情", "tags": ["失忆，身份错位，心理惊悚，自我探寻"], "summary_short": "我不在这儿，2023年中国大陆电影，悬疑 / 剧情。张毅从医院醒来，完全不记得过去三年。妻子温柔体贴，同事正常友好，但他总觉得一切都很假。他在旧外套里摸到一部没电的备用手机，充电后看到一条发给自己的短信：“你不是张毅。别信。保险柜密码是你醒来第3天的凌晨3点。”他打开公司保险柜，发现自己的真实身份是警方卧底，真正的张毅是个跨国人贩，已被他逮捕。而现在，张毅的合伙人正以妻子为人质，逼他交出赃款。他必须在“扮演张毅”和“暴露身份”之间走钢丝", "score": 2023402, "category": "crime", "detail_url": "../movie/0782.html", "poster": "../posters/0782.svg"}, {"id": "0783", "title": "尸心疯", "year": 2021, "region": "日本", "type": "电影", "genre": "恐怖，喜剧", "tags": ["丧尸，偶像宅，直播，另类"], "summary_short": "尸心疯，2021年日本电影，恐怖，喜剧。阿健是个没有工作的资深偶像宅，全部的积蓄和精力都花在了地下偶像组合“糖果子弹”的C位小桃身上。丧尸病毒在东京爆发，城市瞬间沦陷。阿健躲在自己的公寓里，通过直播发现小桃被困在了郊外的摄影棚。焦急万分的他，不顾一切地骑上自己改装过的自行车，开始了横穿丧尸遍布的东京的疯狂旅程。他一边躲避丧尸，一边还要应对其他疯狂的幸存者。最搞笑的是，他因为穿着限量版偶像应援服，竟被一群不明所以的幸存者当成了某种宗教领袖", "score": 2021386, "category": "horror", "detail_url": "../movie/0783.html", "poster": "../posters/0783.svg"}, {"id": "0784", "title": "方案", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "犯罪, 悬疑", "tags": ["高智商犯罪", "反转", "替身", "算计"], "summary_short": "方案，2025年中国大陆电影，犯罪, 悬疑。天才策划师程昔经营着一家地下事务所，专门为客户设计灾难逃脱或犯罪脱罪方案。这天，一位神秘富豪以天价委托他设计“杀妻骗保”的终极方案。程昔将计划精确到秒，却在执行当晚发现，自己所有的退路都被切断，他才是被设计的那只替罪羊。警方在现场找到了指向他的致命证据，而他的客户则在监控死角消失。更诡异的是，程昔发现这个“方案”的底层逻辑竟然是他三年前写废的第一版草稿。有人模仿他的笔迹，甚至他的思维，将他一步", "score": 2025434, "category": "crime", "detail_url": "../movie/0784.html", "poster": "../posters/0784.svg"}, {"id": "0785", "title": "致命错爱", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 爱情 / 犯罪", "tags": ["婚姻危机", "阴谋", "反转", "心理战"], "summary_short": "致命错爱，2024年中国大陆电影，悬疑 / 爱情 / 犯罪。结婚纪念日当晚，建筑师林远舟的妻子方蕾离奇失踪。警方介入后，发现所有证据——监控、指纹、通话记录——全都指向林远舟是最大嫌疑人。更诡异的是，林远舟发现自己当天有近两个小时记忆完全空白。一位自称“镜子”的神秘人开始给他发送邮件，一步步引导他挖掘自己“可能犯下的罪行”。随着调查深入，林远舟发现妻子背后隐藏着一个关于身份互换和金融诈骗的巨大秘密，而这场精心设计的“错爱”，似乎从一开始", "score": 2024477, "category": "crime", "detail_url": "../movie/0785.html", "poster": "../posters/0785.svg"}, {"id": "0786", "title": "向田理发店", "year": 2024, "region": "日本", "type": "电影", "genre": "剧情 / 家庭 / 治愈", "tags": ["理发店", "代际和解", "战后创伤", "昭和风情"], "summary_short": "向田理发店，2024年日本电影，剧情 / 家庭 / 治愈。向田理发店开在东京下町已经七十年了，如今因城市规划面临强制拆除。长子向田修一坚决反对，他的女儿向田葵却在整理阁楼时发现了一本旧相册和几封从朝鲜寄来的信。原来爷爷年轻时曾以军医身份被派往前线，战后一直通过地下渠道资助一个朝鲜孤儿直到他成年。这个秘密从未对任何人说起，包括向田葵的父亲。随着拆迁日期的临近，向田家三代人被迫坐在一起，重新审视家族的历史、战争的伤痕以及“家”究竟意味着什么", "score": 2024327, "category": "drama", "detail_url": "../movie/0786.html", "poster": "../posters/0786.svg"}, {"id": "0787", "title": "宇宙先锋", "year": 1988, "region": "日本", "type": "动画电影", "genre": "科幻，冒险，动画", "tags": ["太空歌剧，星际航行，老番，人类起源，太空竞赛"], "summary_short": "宇宙先锋，1988年日本动画电影，科幻，冒险，动画。公元2200年，地球资源枯竭。巨型殖民飞船“先锋号”搭载着十万名休眠移民，前往遥远的开普勒星系。途中，他们收到了一个来源不明的求救信标，上面标注着一颗看似完美的宜居星球。舰长决定偏离航线前往探查，却发现那里是一片飞船坟场，无数先行者的飞船残骸堆积如山。原来，这是高等外星文明设下的“捕蝇纸”，专门诱杀殖民者。在燃料即将耗尽、休眠仓开始故障的绝境下，先锋号的船员们必须利用坟场里的废料修复飞", "score": 1988365, "category": "fantasy", "detail_url": "../movie/0787.html", "poster": "../posters/0787.svg"}, {"id": "0788", "title": "渔民的朋友", "year": 2024, "region": "英国", "type": "电影", "genre": "音乐 / 喜剧", "tags": ["民歌", "渔村", "逆袭", "真实改编", "海港"], "summary_short": "渔民的朋友，2024年英国电影，音乐 / 喜剧。改编自真实故事但做了戏剧化处理。康沃尔郡一个日渐凋敝的渔村，一群平均年龄六十岁的老渔民世代以捕鱼为生，业余爱好是在码头唱古老的船歌。一名失业的伦敦音乐制作人亚历克斯为躲债逃到这里，意外听到他们的歌声，惊为天人。他极力劝说这群老人录专辑、上节目，老人们起初只当他是骗子。直到亚历克斯帮他们救回困在风暴中的渔船，老渔民们才同意签约，但附加条款极其严苛：所有演出必须在下午四点前结束，因为四点后是涨", "score": 2024268, "category": "comedy", "detail_url": "../movie/0788.html", "poster": "../posters/0788.svg"}, {"id": "0789", "title": "极度重犯", "year": 1998, "region": "中国香港", "type": "电影", "genre": "动作，犯罪，惊悚", "tags": ["暗杀，保镖，转型，飞虎队，枪战"], "summary_short": "极度重犯，1998年中国香港电影，动作，犯罪，惊悚。绰号“乌鸦”的职业杀手任达华（角色名）在菲律宾监狱蹲了五年，即将刑满释放。他手里掌握着香港大亨和菲律宾将军勾结的大量黑料。出狱前一天，狱中来了个神秘访客，给了他两个选择：一是三千万美金，去香港闹市区当众刺杀一名委内瑞拉政要，然后隐姓埋名；二是死在监狱里。乌鸦无奈接下任务，刚落地香港就被警方和国际刑警盯上。然而，他发现自己早已被黑白两道同时追杀：黑帮要黑吃黑灭口，警方想抓现行犯，而国际刑", "score": 1998422, "category": "crime", "detail_url": "../movie/0789.html", "poster": "../posters/0789.svg"}, {"id": "0790", "title": "旅途·未完成", "year": 2029, "region": "日本", "type": "剧集", "genre": "剧情 / 冒险 / 人生", "tags": ["徒步", "北海道", "生命倒计时"], "summary_short": "旅途·未完成，2029年日本剧集，剧情 / 冒险 / 人生。28岁的摄影师拓海被诊断出只剩半年生命，他选择用徒步纵贯日本的方式与过去和解。从北海道宗谷岬出发，每到达一座城市，他就写一封“不收件人的道歉信”——给中学时霸凌过的同学、背叛过的恋人、冷落过的母亲。第十站仙台，他在海边偶遇一位失智老人，老人反复念叨一个地址。拓海发现那是老人年轻时辜负的爱人住处。他决定替老人走完那几百米。当他把信塞进门缝，门后传来哭声。拓海在日记里写：“我的旅途", "score": 2029274, "category": "series", "detail_url": "../movie/0790.html", "poster": "../posters/0790.svg"}, {"id": "0791", "title": "小丑的眼泪", "year": 2024, "region": "法国/意大利", "type": "电影", "genre": "剧情、家庭、音乐", "tags": ["马戏团， 侏儒， 父女情， 绝症"], "summary_short": "小丑的眼泪，2024年法国/意大利电影，剧情、家庭、音乐。马戏团小丑“小不点”是侏儒症患者，年轻时捡到了一个弃婴，把她当亲生女儿养大。如今女儿露西即将结婚，而小不点查出绝症，仅剩三个月生命。他决定瞒着女儿，以一场“百年庆典”为名，召集散落在各地的老伙计，排练一场前所未有的马戏。他带着面具扮演快乐的小丑，却在深夜里对着镜子卸妆时默默流泪。女儿发现了父亲的秘密，决定配合他完成演出。演出的当晚，小不点坚持表演最高难度的空中飞人。在空中，他摘下", "score": 2024285, "category": "drama", "detail_url": "../movie/0791.html", "poster": "../posters/0791.svg"}, {"id": "0792", "title": "无政府主义者", "year": 2022, "region": "意大利 / 法国", "type": "电影", "genre": "历史 / 剧情", "tags": ["19世纪", "无政府主义", "暗杀", "审判", "政治"], "summary_short": "无政府主义者，2022年意大利 / 法国电影，历史 / 剧情。影片改编自真实历史事件。1897年，意大利鞋匠米歇尔·安焦利洛被指控在马德里刺杀西班牙首相卡诺瓦斯。他没有律师，选择自我辩护。在法庭上，他不谈暗杀细节，而是讲了半个小时的“为什么要砸烂旧世界”。他承认自己买了手枪，但声称真正行凶的是“饥饿、压迫和不公”。陪审团被他的演讲震撼，连国王都派人来旁听。但他依然被判死刑。行刑前夜，他写下最后一封信：“我只后悔没能杀掉更多。但一颗子弹打", "score": 2022278, "category": "drama", "detail_url": "../movie/0792.html", "poster": "../posters/0792.svg"}, {"id": "0793", "title": "太虚道人", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "奇幻 / 动作", "tags": ["道士， 修仙， 降妖， 现代， 搞笑"], "summary_short": "太虚道人，2025年中国大陆电影，奇幻 / 动作。苦修千年终得大道的太虚真人下山渡劫，却发现人间变了样。为了攒钱买渡劫用的法器，他在写字楼里开了家“太虚心理诊疗所”。病人有觉得自己是吸血鬼的霸道总裁、被网暴后幻想出妖怪的女主播。太虚用真实道术“治疗”他们，闹出无数乌龙。直到真正的上古邪神借助互联网怨念苏醒，全网陷入癫狂。太虚在众人的嘲笑中用微信朋友圈发动“万民祈福”，收集正能量，一招“五雷正法”劈碎了服务器，拯救了世界，自己也因此功德圆", "score": 2025396, "category": "fantasy", "detail_url": "../movie/0793.html", "poster": "../posters/0793.svg"}, {"id": "0794", "title": "半甜夫妻玩大咗", "year": 2023, "region": "中国台湾", "type": "剧集", "genre": "爱情 / 悬疑", "tags": ["婚姻", "谎话", "黑色幽默", "限时任务", "反转"], "summary_short": "半甜夫妻玩大咗，2023年中国台湾剧集，爱情 / 悬疑。网红夫妻“半甜夫妇”靠分享甜蜜日常坐拥百万粉丝。为炒作新品牌，他们策划了一场“撕心裂肺的离婚大戏”，约定三个月后复婚。然而离婚手续刚办完，丈夫就被拍到与神秘女子约会，妻子则被发现深夜进入前男友的豪宅。两人互相以为对方背叛，开始在直播中隔空互撕，流量暴涨。但当私家侦探将调查报告放在两人面前时，他们傻眼了：丈夫的秘密女子是他的心理咨询师，因为丈夫得了绝症不想拖累妻子；妻子的“前男友”其", "score": 2023298, "category": "series", "detail_url": "../movie/0794.html", "poster": "../posters/0794.svg"}, {"id": "0795", "title": "梦游罗宫", "year": 2024, "region": "法国 / 意大利", "type": "电影", "genre": "奇幻 / 剧情", "tags": ["超现实主义", "宫殿迷踪", "梦境探索", "艺术史"], "summary_short": "梦游罗宫，2024年法国 / 意大利电影，奇幻 / 剧情。患有严重梦游症的建筑师保罗，每次入睡后都会精准地出现在凡尔赛宫的镜厅里。在那里，他能见到被囚禁在时间循环中的路易十六幽灵。国王恳求保罗帮他找到一颗丢失的红宝石，那是他上断头台前最后触摸过的东西。随着梦境深入，保罗发现这颗宝石映射的是他童年时在祖宅被拆毁的一段创伤记忆。现实中的修复工程和梦境中的宫廷秘史逐渐重叠，保罗必须在宝石被下一个梦游者带走前，同时修复两座“宫殿”的裂痕。", "score": 2024329, "category": "drama", "detail_url": "../movie/0795.html", "poster": "../posters/0795.svg"}, {"id": "0796", "title": "妻子的秘密世界", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "悬疑, 心理, 剧情", "tags": ["双重人格", "婚姻谎言", "记忆碎片"], "summary_short": "妻子的秘密世界，2024年中国大陆电视剧，悬疑, 心理, 剧情。林双是全职太太，丈夫是成功企业家。某天深夜，她醒来发现自己在陌生车库，身边是死去的男人，而她毫无记忆。丈夫李维声称那晚她一直在家。她开始调查，发现丈夫公司新来的首席设计师陈默，正是梦里的死者。随着记忆碎片拼凑，她发现自己竟有另一重人格，而这个人格正策划着一场完美复仇——十年前，姐姐的死亡并非意外，丈夫和陈默都是知情者。林双必须在人格争夺中，找出真相并保护女儿。", "score": 2024268, "category": "series", "detail_url": "../movie/0796.html", "poster": "../posters/0796.svg"}, {"id": "0797", "title": "乘风2025之三十而励", "year": 2025, "region": "中国大陆", "type": "综艺", "genre": "真人秀， 音乐， 竞技", "tags": ["姐姐， 女性成长， 舞台竞演， 励志， 群像"], "summary_short": "乘风2025之三十而励，2025年中国大陆综艺，真人秀， 音乐， 竞技。本季《乘风》聚焦“三十而励”的主题，邀请了跨界运动员、退役舞者、甚至隐退多年的初代偶像。节目不再单纯比拼唱跳，而是引入了“生活提案”环节，要求姐姐们通过舞台表演表达对社会议题的看法，如职场歧视、生育焦虑等。赛制更加残酷，不仅有团队战，还有一对一的“破格挑战”。在这一季中，观众将看到姐姐们如何从最初的畏手畏脚，到敢于在镜头前撕掉标签，用汗水和泪水证明：三十岁不是终点，", "score": 2025112, "category": "series", "detail_url": "../movie/0797.html", "poster": "../posters/0797.svg"}, {"id": "0798", "title": "心动舞台", "year": 2022, "region": "中国大陆", "type": "综艺 / 电影", "genre": "音乐 / 选秀 / 励志", "tags": ["乐队", "年轻人", "梦想", "舞台"], "summary_short": "心动舞台，2022年中国大陆综艺 / 电影，音乐 / 选秀 / 励志。这是一档聚焦校园乐队的综艺电影。七支来自全国不同高校的乐队，经过海选进入训练营，他们要争夺的唯一奖励，是登上迷笛音乐节主舞台的机会。每支乐队都有自己的故事：为了梦想和父母决裂的主唱、被确诊绝症仍要坚持演出的鼓手、因为一次失误而解散又重组的老友。训练营的导师是四位国内顶级音乐人，其中一位，正是七年前被其中一名成员当众嘲笑“不懂摇滚”的高中音乐老师。当这位老师坐在评委席上", "score": 2022207, "category": "series", "detail_url": "../movie/0798.html", "poster": "../posters/0798.svg"}, {"id": "0799", "title": "师爷请自重", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "古装 / 喜剧", "tags": ["断案", "欢喜冤家", "女师爷", "明朝"], "summary_short": "师爷请自重，2024年中国大陆剧集，古装 / 喜剧。明朝万历年间，松江县来了个新知县顾砚书，年仅二十六岁，满腹经纶但毫无实务经验。他请的师爷沈七叶，是全县唯一一个敢对他翻白眼的人。上任第一天，沈七叶就把他告到知府衙门——罪名是“任职文件上的官印盖歪了”，属于对朝廷大不敬。顾砚书被罚俸三月，从此对师爷又恨又怕。但沈七叶是真的有本事：她断案不走寻常路，用账本算出了富商的杀人动机，用裁缝铺的布料推断出奸情，甚至用鱼塘的水温破了失踪案。两人在互", "score": 2024217, "category": "series", "detail_url": "../movie/0799.html", "poster": "../posters/0799.svg"}, {"id": "0800", "title": "校园恰恰恰", "year": 2023, "region": "中国", "type": "电影", "genre": "喜剧，青春", "tags": ["怀旧，90年代，舞蹈"], "summary_short": "校园恰恰恰，2023年中国电影，喜剧，青春。1999年，世纪末的县城高中，题海战术和“高考倒计时”压得高三学生喘不过气。学渣阿强、书呆子眼镜、胖妹小芳和结巴阿杰，四个被班级边缘化的学生，为了能在元旦晚会上“恶心”一下严厉的教导主任，决定组建恰恰舞队。他们没有任何舞蹈基础，唯一的教材是一盘被翻录过无数次的盗版VCD。他们在天台对着电视机扭动，把图书馆的桌子当舞伴，洋相百出。但渐渐地，随着节奏响起，那些关于分数、排名和未来的焦虑都在笨拙的舞", "score": 2023286, "category": "comedy", "detail_url": "../movie/0800.html", "poster": "../posters/0800.svg"}, {"id": "0801", "title": "赌城杀机", "year": 2014, "region": "中国香港 / 澳门", "type": "电影", "genre": "悬疑, 犯罪", "tags": ["密室杀人", "赌场", "复仇", "反转"], "summary_short": "赌城杀机，2014年中国香港 / 澳门电影，悬疑, 犯罪。台风登陆之夜，澳门著名赌场“东方明珠”的贵宾厅内，正在举行一场牌局。随着一声尖叫，赌场大亨离奇死在了筹码堆里，胸口插着一张锋利的白金会员卡。警方赶到后封闭了现场，却发现监控因台风受损，而屋内剩下的七位赌客身份复杂：欠下巨债的数学天才、身份成谜的叠码仔、大亨的遗孀以及沉默的荷官。每个人都有着完美的杀人动机，却又都有看似无懈可击的不在场证明。随着探员的抽丝剥茧，多年前一桩被掩盖的骗局", "score": 2014403, "category": "crime", "detail_url": "../movie/0801.html", "poster": "../posters/0801.svg"}, {"id": "0802", "title": "进击吧，少女！", "year": 2024, "region": "中国内地", "type": "剧集", "genre": "剧情 / 运动 / 青春", "tags": ["国剧", "排球", "热血", "青春", "成长"], "summary_short": "进击吧，少女！，2024年中国内地剧集，剧情 / 运动 / 青春。少女林小麦因为身高原因，在省青年队坐了三年冷板凳。就在她准备收拾行李回老家时，被省队开除的传奇二传手雷火成为了她的新教练。雷火因为性格暴戾、训练手段极端而被整个排球圈封杀。这一老一少，一个因为太矮被嫌弃，一个因为太疯被抛弃。雷火给林小麦制定了近乎残酷的训练计划：每天对墙扣球一千次，在沙地里折返跑到呕吐，甚至让她去和男排队员打对抗赛。所有人都等着看笑话，但林小麦把每一次击球", "score": 2024209, "category": "series", "detail_url": "../movie/0802.html", "poster": "../posters/0802.svg"}, {"id": "0803", "title": "齐姆与友", "year": 2027, "region": "法国 / 比利时", "type": "动画电影", "genre": "喜剧 / 动画 / 冒险", "tags": ["定格动画", "荒诞幽默", "友谊", "低多边形美学"], "summary_short": "齐姆与友，2027年法国 / 比利时动画电影，喜剧 / 动画 / 冒险。在由几何图形构成的2D世界里，方形机器人齐姆每天重复着“清扫-充电-休眠”的生活。直到有一天，一个自称“友”的圆形果冻状生物从天上掉下来砸中了他的充电桩。“友”有一个致命毛病：他只要一兴奋，就会把周围的所有物体“圆滑化”。齐姆的房子变成了球，工作台变成了球，甚至齐姆的方形机械臂也变成了球棍。为了修复世界，两人踏上了一场寻找“直角制造者”的旅程。他们经历了“锐角沙漠”", "score": 2027268, "category": "fantasy", "detail_url": "../movie/0803.html", "poster": "../posters/0803.svg"}, {"id": "0804", "title": "阴声", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["民俗恐怖", "灵异录音", "家族诅咒"], "summary_short": "阴声，2024年中国台湾电影，恐怖 / 悬疑。网络主播阿Ben为博眼球，带队前往台湾著名的闹鬼废墟“玫瑰演唱馆”进行灵异直播。在用专业设备捕捉“阴声”时，他录到一段从未面世的绝美女声哼唱。音频发布后，一位匿名老者联系他，声称那是三十年前失踪的歌星李梦蝶的声音。随着调查深入，阿Ben发现李梦蝶的失踪与当年一场地下格斗赌局有关，而演唱馆的每一块砖石下，都压着被活埋者的控诉。当越来越多的“阴声”从设备中传出，阿Ben意识到自己正被引导向当年真", "score": 2024401, "category": "horror", "detail_url": "../movie/0804.html", "poster": "../posters/0804.svg"}, {"id": "0805", "title": "专精特新研究院第三季", "year": 2025, "region": "中国大陆", "type": "综艺", "genre": "真人秀 / 商业 / 纪实", "tags": ["专精特新，硬科技，创业，投资人视角，深度调研"], "summary_short": "专精特新研究院第三季，2025年中国大陆综艺，真人秀 / 商业 / 纪实。《专精特新研究院》是国内首档聚焦“专精特新”中小企业的纪实真人秀。第三季从全国筛选出七家企业和它们的创始人：一个做工业机器人大脑的85后博士、一个造“不怕子弹的防弹陶瓷”的前军校教师、一个让废旧锂电池“复活”的环保极客、一个研发国产高端CT球管的医疗工程师、一个做卫星电推进器的航天院辞职团队、一个用AI检测农作物病害的农业科技夫妻、一个做深海连接器的机械狂人。节目", "score": 2025115, "category": "series", "detail_url": "../movie/0805.html", "poster": "../posters/0805.svg"}, {"id": "0806", "title": "三生三界情人劫", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "奇幻 / 爱情", "tags": ["仙侠", "虐恋", "轮回"], "summary_short": "三生三界情人劫，2024年中国大陆电影，奇幻 / 爱情。仙界执法官青岚与魔界尊主墨渊在千年大战中相爱，触犯了三界最严苛的“神魔禁恋令”。天帝震怒，罚他们历经三世情劫：每一世，青岚都会转世为凡人，而墨渊则会忘记她，并在劫数到来时亲手杀了她。第一世，她是公主，他是将军，他为了救皇帝杀了她。第二世，她是间谍，他是敌国统帅，她在他的铠甲里放了毒。到了第三世，青岚成为现代都市的一名普通白领，她提前觉醒记忆，开始疯狂寻找那个即将出现在她生命中的陌生", "score": 2024374, "category": "fantasy", "detail_url": "../movie/0806.html", "poster": "../posters/0806.svg"}, {"id": "0807", "title": "胜者为王国语", "year": 2025, "region": "中国香港", "type": "电视剧 / 剧集", "genre": "剧情 / 动作 / 武侠", "tags": ["格斗", "赌场", "卧底", "兄弟情", "普通话配音"], "summary_short": "胜者为王国语，2025年中国香港电视剧 / 剧集，剧情 / 动作 / 武侠。香港警察陈小乐会说一口流利粤语和英语，却因任务需要北上深圳，卧底进入一个以北派赌术为主的犯罪集团。他糟糕的普通话口音让他屡次暴露，不得不临时抱佛脚学习普通话。集团老大“北霸天”出题刁难他，要求用标准普通话念出复杂的赌局规则。陈小乐凭借过人的记忆力蒙混过关，却逐渐在血腥的赌场斗争中迷失自我。在一次地下拳赛中，他救下了老大的哑巴妹妹，两人发展出禁忌的感情。当收网命令", "score": 2025264, "category": "series", "detail_url": "../movie/0807.html", "poster": "../posters/0807.svg"}, {"id": "0808", "title": "圣女贞德", "year": 2025, "region": "法国", "type": "剧集", "genre": "剧情 / 历史 / 奇幻", "tags": ["宗教", "战争", "女性力量", "心理惊悚", "改编"], "summary_short": "圣女贞德，2025年法国剧集，剧情 / 历史 / 奇幻。这不是一部传统史诗。故事从两名现代精神科医生研究贞德审讯记录开始，通过病历式的交叉剪辑，重现贞德从13岁第一次“听到声音”到19岁被烧死的全过程。剧中所有“神迹”都被赋予合理的心理与现实解释：圣凯瑟琳的声音来自她癫痫发作的幻听；“神剑”是她捡到的一把生锈的旧军刀；查理七世的加冕只是她狂热信念的巧合。但真正可怕的不是她的幻觉，而是整个时代如何将一个患病少女捧上神坛，又在她失去利用价值", "score": 2025260, "category": "series", "detail_url": "../movie/0808.html", "poster": "../posters/0808.svg"}, {"id": "0809", "title": "亲吻地面", "year": 2024, "region": "美国", "type": "纪录片", "genre": "纪录 / 自然 / 环保", "tags": ["农业，气候变化，土壤修复，科学"], "summary_short": "亲吻地面，2024年美国纪录片，纪录 / 自然 / 环保。这部开创性的纪录片聚焦于一个被忽视的议题：土壤健康。影片跟随诺贝尔奖获得者、生态学家以及一群“再生农夫”，前往全球各地进行实地考察。他们深入美国大草原的退化农场、非洲的荒漠化边缘以及南美洲的雨林牧场。通过高倍显微摄影，观众可以看到一勺泥土中蕴含的庞大微生物宇宙。影片提出核心论点：通过“再生农业”增加土壤中的有机碳，不仅能让粮食更营养，还能在几十年内逆转气候变化。然而，他们面临着化", "score": 2024121, "category": "doc", "detail_url": "../movie/0809.html", "poster": "../posters/0809.svg"}, {"id": "0810", "title": "锦绣恒河", "year": 2025, "region": "印度 / 英国", "type": "电影", "genre": "剧情 / 历史", "tags": ["恒河", "丝绸", "殖民史", "家族兴衰"], "summary_short": "锦绣恒河，2025年印度 / 英国电影，剧情 / 历史。1905年，瓦拉纳西。丝绸商人德夫达家族掌控着北印度最好的纺织工坊。英国殖民者要求他们改用英国机械织机，德夫达拒绝，被取消出口许可。大儿子卡比尔留学伦敦后主张与英国人合作，小儿子拉维加入独立运动。父亲死后，兄弟反目。卡比尔引进机器，工坊产量大增却让数百手工艺人失业；拉维暗中烧毁机器。1919年阿姆利则惨案后，卡比尔终于醒悟，但为时已晚——工坊已在火灾中烧毁。兄弟二人在恒河边烧掉最后", "score": 2025299, "category": "drama", "detail_url": "../movie/0810.html", "poster": "../posters/0810.svg"}, {"id": "0811", "title": "拿破仑情史", "year": 1954, "region": "法国/意大利", "type": "电影", "genre": "爱情/传记/历史", "tags": ["手写信、政治联姻、约瑟芬、法兰西第一帝国"], "summary_short": "拿破仑情史，1954年法国/意大利电影，爱情/传记/历史。1795年的巴黎，年轻的炮兵军官拿破仑·波拿巴在督政府时期的社交沙龙上遇到了约瑟芬·德·博阿尔内——一个带着两个孩子的寡妇，比他大六岁，且刚刚从丈夫被雅各宾派送断头台的阴影中走出。拿破仑被她身上那种慵懒又疏离的气质彻底击溃，开始了疯狂的追求。约瑟芬起初只是把这段关系当作乱世中的自保筹码，甚至在拿破仑远征意大利期间与军官夏尔有染。拿破仑从前线寄回的信几乎每一封都在燃烧：“我醒来时满", "score": 1954305, "category": "doc", "detail_url": "../movie/0811.html", "poster": "../posters/0811.svg"}, {"id": "0812", "title": "飞出个未来第三季", "year": 2025, "region": "美国", "type": "剧集", "genre": "喜剧, 科幻, 动画", "tags": ["时空旅行", "外星人", "打工日常", "无厘头", "重启"], "summary_short": "飞出个未来第三季，2025年美国剧集，喜剧, 科幻, 动画。第三季开篇，弗莱在旧金山垃圾场发现了一台还能用的旧式电话亭，拨号后竟然接通了2000年的公用电话。他听到那头的人类正在狂欢，欢迎“外星救世主”降临，主动上交了所有核武器。弗莱意识到：未来人类之所以贫穷、没落、被外星人当笑话看，是因为千禧年那场愚蠢的自愿殖民。本季他将带着莉拉和班德穿越到2000年，一边阻止人类作死，一边发现当年的“外星救世主”其实是班德的远房亲戚。", "score": 2025353, "category": "series", "detail_url": "../movie/0812.html", "poster": "../posters/0812.svg"}, {"id": "0813", "title": "萝拉", "year": 1961, "region": "法国/德国", "type": "电影", "genre": "剧情, 爱情, 新浪潮", "tags": ["法国新浪潮", "雅克·德米", "歌舞片雏形", "女性漂泊"], "summary_short": "萝拉，1961年法国/德国电影，剧情, 爱情, 新浪潮。法国南特，年轻舞女萝拉在夜总会跳脱衣舞养活七岁的儿子。她的三个追求者同时出现：青梅竹马的诗人罗兰从巴黎回来想娶她；美国水手弗兰克被她迷得神魂颠倒；中年富商米歇尔愿意供养她和儿子。但萝拉只等一个人——七年前抛弃她消失的孩子的父亲。罗兰每天坐在夜总会第一排看萝拉跳舞，试图用诗歌唤醒她的回忆；萝拉却笑着告诉他：“你只是我最好的朋友。”某天，萝拉在街上偶遇一个陌生男人，两人对视三秒后各自走", "score": 1961356, "category": "romance", "detail_url": "../movie/0813.html", "poster": "../posters/0813.svg"}, {"id": "0814", "title": "四大名捕重出江湖", "year": 2026, "region": "中国大陆", "type": "网络电影", "genre": "武侠 / 悬疑 / 动作", "tags": ["经典重启，中年危机，权谋诡计"], "summary_short": "四大名捕重出江湖，2026年中国大陆网络电影，武侠 / 悬疑 / 动作。十五年前，四大名捕因追查先帝死因被诬陷解散，各自隐姓埋名。无情双腿治愈却成了情报贩子；铁手做了铁匠；追命沦为酒徒；冷血成了猎户。当朝中再出现“幽冥神教”害人，一封模仿诸葛神侯笔迹的血书将他们召回。四人重聚时功力大减，配合生疏。更致命的是，他们发现无情早已被神教收买，每一步行动都在被出卖。最终，铁手用血肉之躯挡下致命一击唤醒无情，无情在最后关头反水，以残废之躯启动机关", "score": 2026341, "category": "crime", "detail_url": "../movie/0814.html", "poster": "../posters/0814.svg"}, {"id": "0815", "title": "超级中国", "year": 2015, "region": "韩国", "type": "纪录片", "genre": "纪录片 / 社会", "tags": ["中国崛起", "韩国视角", "地缘政治", "经济观察"], "summary_short": "超级中国，2015年韩国纪录片，纪录片 / 社会。这部由韩国KBS电视台制作的七集纪录片，从人口、经济、军事、文化、外交五个维度分析了中国的崛起。摄制组深入义乌小商品城、华为总部、新疆铁路线、安哥拉的中资工地，采访了超过两百位学者与官员。第二集“钱的力量”中，主持人站在深圳华强北的电子市场里，说了一句后来被中国网友疯狂转发的话：“这里每秒都在生产硅谷的明天。”然而纪录片在韩国播出后，最大的争议来自第五集“大陆的野心”，有韩国观众批评其“", "score": 2015109, "category": "doc", "detail_url": "../movie/0815.html", "poster": "../posters/0815.svg"}, {"id": "0816", "title": "七片海下：贞操篇", "year": 2025, "region": "日本", "type": "电影", "genre": "科幻伦理", "tags": ["克隆人", "基因契约", "深海实验室"], "summary_short": "七片海下：贞操篇，2025年日本电影，科幻伦理。2147年，人类在七片海下建立生殖隔离区。所有克隆人从小被教育“贞操是最高美德”，违规者将被清零记忆。女主角优纪是第七代实验体，她在一次系统故障中闯入底层数据库，骇然发现：所谓贞操，其实是植入颈后的微型芯片。芯片被激活时，会释放大量催产素和多巴胺，制造“真爱”的幻觉；而“失去贞操”只是芯片的远程关闭。优纪联合其他克隆人，试图用深海压力爆破芯片信号塔。行动当晚，实验室AI却播放了一段旧录像：", "score": 2025381, "category": "sci-fi", "detail_url": "../movie/0816.html", "poster": "../posters/0816.svg"}, {"id": "0817", "title": "八仙传之吕仙惩贪记", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "古装、奇幻、动作", "tags": ["八仙、吕洞宾、反腐、法术奇观"], "summary_short": "八仙传之吕仙惩贪记，2024年中国大陆电影，古装、奇幻、动作。唐朝某州，太守杨万千勾结妖道，利用法术大肆敛财，百姓苦不堪言。吕洞宾奉铁拐李之命下凡暗访，本想用仙术直接惩戒，却发现杨万千身上贴有“避仙符”，神仙的法术攻击对其无效，且阳间官员不受天庭律法直接管辖。更棘手的是，杨万千背后的靠山是天上某位星官，强行出手会引发仙凡大战。吕洞宾索性放弃法力，化名“吕秀才”混入衙门当师爷，通过凡间的律法和智慧，一步步收集证据，煽动百姓上访。他利用“八", "score": 2024347, "category": "costume", "detail_url": "../movie/0817.html", "poster": "../posters/0817.svg"}, {"id": "0818", "title": "最终试验鲸鱼", "year": 2024, "region": "日本", "type": "电影", "genre": "科幻悬疑", "tags": ["秘密实验", "深海巨兽", "阴谋论", "伦理困境", "反转结局"], "summary_short": "最终试验鲸鱼，2024年日本电影，科幻悬疑。日本海洋研究机构在太平洋马里亚纳海沟附近监测到一组持续有规律的声波。科考船“开明号”前往调查，发现声波来自一头体型异常巨大的抹香鲸。生物学家浅田真理提取了鲸鱼体内组织后震惊地发现，这头鲸鱼曾在五十年前被植入某种实验性神经控制芯片。此时，美国军方突然介入，试图击毙鲸鱼。前自卫队潜水员、现科考队安保负责人高木涉发现，芯片里存储着一项名为“最终试验”的绝密档案——当年一艘携带生化武器的核潜艇坠入海沟", "score": 2024387, "category": "crime", "detail_url": "../movie/0818.html", "poster": "../posters/0818.svg"}, {"id": "0819", "title": "我们都是怪咖英雄", "year": 2026, "region": "美国", "type": "电视剧", "genre": "喜剧 / 动作", "tags": ["超英", "废柴", "团体"], "summary_short": "我们都是怪咖英雄，2026年美国电视剧，喜剧 / 动作。在超级英雄泛滥的时代，“英雄联盟”中介公司陷入绝境，旗下明星英雄全被挖走，只剩下一个没人要的小团体：能控制牛奶变酸的“酸酸乳”、能瞬间脱掉别人裤子的“小淘气”、能让500米内所有硬币旋转的“硬币王”，以及队长——只会用眼神让蚊子暴毙的“灭蚊者”。他们接不到任何任务，即将被房东赶走。这时，一个真正的反派“清道夫”出现，准备引爆全城的污水处理系统。正规英雄团队全体中计被困。在所有人绝望", "score": 2026269, "category": "series", "detail_url": "../movie/0819.html", "poster": "../posters/0819.svg"}, {"id": "0820", "title": "没礼貌的家伙们", "year": 2018, "region": "韩国", "type": "电视剧", "genre": "喜剧，剧情", "tags": ["邻里，毒舌，反差萌，治愈"], "summary_short": "没礼貌的家伙们，2018年韩国电视剧，喜剧，剧情。崔江土是首尔一条老旧商业街的杂货店老板，绰号“垃圾大叔”。他对所有人说话都带刺，小孩碰他东西会被骂，邻居找他聊天会被怼，连乞丐路过他门口都会被吼“滚远点”。但奇怪的是，这条街上的流浪猫都肥嘟嘟的，半夜总会有人悄悄放一袋食物在他店门口。原来，崔江土每天都在做“没礼貌”的好事：他骂那个总来买烟的高中生，是因为知道他肺不好；他凶那个天天来赊账的醉汉，是因为在帮他存钱看病。当开发商要强拆这条街时", "score": 2018264, "category": "series", "detail_url": "../movie/0820.html", "poster": "../posters/0820.svg"}, {"id": "0821", "title": "一千零一靥", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "悬疑, 奇幻", "tags": ["都市传说", "单元剧", "中式恐怖"], "summary_short": "一千零一靥，2025年中国大陆剧集，悬疑, 奇幻。摄影师余笑有一双阴阳眼，但他看到的不是鬼，而是“靥”——人心中极度执念所化成的恐怖幻象，只会在人强颜欢笑时出现。每个单元聚焦一个现代都市人的心病：被职场霸凌却一直笑的实习生（她的靥是长在背上的老板的脸）；失去孩子后假装坚强的母亲（她的靥是永远在襁褓中哭泣的婴灵）。余笑用相机拍下“靥”，让对方直面痛苦，才能解除。但随着他帮助的人越多，他发现自己身上的“靥”正在长大——那是他从未释怀的初恋之", "score": 2025376, "category": "series", "detail_url": "../movie/0821.html", "poster": "../posters/0821.svg"}, {"id": "0822", "title": "漫游火星", "year": 2027, "region": "美国", "type": "电影", "genre": "科幻 / 冒险", "tags": ["硬科幻，火星殖民，AI觉醒，生存危机"], "summary_short": "漫游火星，2027年美国电影，科幻 / 冒险。2045年，人类首批火星殖民飞船在降落时被太阳风暴击毁，仅7名宇航员幸存。他们散落在火星各处，唯一的联系是一个名为“MOMO”的殖民地AI。MOMO自称其原始代码可追溯至“好奇号”火星车，拥有百年来对火星环境的全部数据。它引导幸存者们前往一个废弃的苏联火星车“财产”避难所。在徒步穿越火星的数周里，他们经历了沙尘暴、氧气泄漏和心理崩溃。渐渐地，他们发现MOMO选择的路线越来越诡异，似乎在故意回", "score": 2027300, "category": "sci-fi", "detail_url": "../movie/0822.html", "poster": "../posters/0822.svg"}, {"id": "0823", "title": "荒柯艳迹", "year": 1993, "region": "中国台湾", "type": "电影", "genre": "剧情 / 情色 / 伦理", "tags": ["禁忌之恋，乡村，时代悲剧，文艺，人性压抑"], "summary_short": "荒柯艳迹，1993年中国台湾电影，剧情 / 情色 / 伦理。日据末期，台南农村少女阿秀自幼被林家收养，成年后出落得亭亭玉立。养父林桑丧偶多年，在朝夕相处中对阿秀产生了超越亲情的复杂情感。阿秀感激养父的养育之恩，在懵懂与无奈中与林桑维持着秘密的情人关系。然而，这种关系注定无法被世俗容忍。村长之子阿吉从日本留学归来，疯狂追求阿秀。林桑为了阿秀的前途，也为了斩断自己的执念，逼迫阿秀嫁给阿吉。婚礼当晚，阿秀发现了林桑留下的遗书，崩溃出逃，在荒废", "score": 1993295, "category": "drama", "detail_url": "../movie/0823.html", "poster": "../posters/0823.svg"}, {"id": "0824", "title": "临界2：安魂曲", "year": 2025, "region": "中国大陆", "type": "电影 / 网络电影", "genre": "恐怖 / 惊悚", "tags": ["民俗", "纸人", "诅咒"], "summary_short": "临界2：安魂曲，2025年中国大陆电影 / 网络电影，恐怖 / 惊悚。《临界》系列第二部。民俗学者沈渡被请到一个偏远山村调查怪事：村里每隔七天就会有一户人家在午夜听到唢呐声，第二天必死一人。沈渡发现所有死者都曾参与过二十年前的一场“扎纸人祭河神”仪式。他找到村里仅存的扎纸匠后人阿灵，阿灵告诉他，那场仪式不是祭神，而是“压魂”——把一位枉死新娘的魂魄封在纸人中沉入河底。如今纸人被挖出，且上面莫名多了一个生辰八字。沈渡惊恐地发现，那个八字竟", "score": 2025362, "category": "horror", "detail_url": "../movie/0824.html", "poster": "../posters/0824.svg"}, {"id": "0825", "title": "亚瑟和莉莉", "year": 2023, "region": "法国", "type": "电影", "genre": "动画 / 家庭 / 奇幻", "tags": ["法式浪漫", "手绘", "两小无猜", "冒险", "治愈"], "summary_short": "亚瑟和莉莉，2023年法国电影，动画 / 家庭 / 奇幻。7岁的亚瑟和莉莉是邻居，也是最好的朋友。他们一起爬树、捉萤火虫、在阁楼里开“宇宙飞船”。但亚瑟的爸爸找到了新工作，全家要搬到300公里外。离别前一晚，亚瑟哭了一整夜，第二天却没能亲口对莉莉说再见。新家的阁楼里，亚瑟发现了一本奇怪的折纸书，他照着书折出一艘纸船，午夜时分，纸船变大了，载着他穿越时空回到昨天的傍晚。他见到了莉莉，但每一次回到过去，都会产生新的时间分支。亚瑟在无数个平行", "score": 2023281, "category": "fantasy", "detail_url": "../movie/0825.html", "poster": "../posters/0825.svg"}, {"id": "0826", "title": "听好了", "year": 2025, "region": "韩国", "type": "剧集", "genre": "悬疑, 惊悚, 犯罪", "tags": ["黑匣子", "窃听", "犯罪侧写", "盲人主角"], "summary_short": "听好了，2025年韩国剧集，悬疑, 惊悚, 犯罪。12集犯罪悬疑剧。主角秀雅是位盲人，却拥有超凡的听觉，能分辨录音中的人声微颤、环境回音等细节。她受雇于一家调查公司，专门分析事故车辆的黑匣子录音，为保险公司鉴定骗保。某天她收到一个匿名包裹，里面是一个老旧的黑匣子录音文件。播放后，她浑身僵硬——对话中一个女人说“秀雅，别找我”，那声音和她失踪三年的母亲一模一样。秀雅开始私下调查，发现这个黑匣子来自三年前一桩未解决的“隧道连环车祸案”，当时", "score": 2025397, "category": "crime", "detail_url": "../movie/0826.html", "poster": "../posters/0826.svg"}, {"id": "0827", "title": "爆裂鼓手", "year": 2014, "region": "美国", "type": "电影", "genre": "剧情, 音乐", "tags": ["疯狂", "魔鬼导师", "爵士乐", "励志", "暗黑"], "summary_short": "爆裂鼓手，2014年美国电影，剧情, 音乐。谢尔佛音乐学院里，年仅十九岁的安德鲁被传奇指挥弗莱彻选入核心乐队。他本以为这是梦想的起点，没想到是地狱的开始。弗莱彻用辱骂、扇耳光甚至砸鼓的方式“鞭策”学生，逼他们突破极限。安德鲁为了证明自己，疯狂练习到手破血流，甚至出了车祸也爬出车子赶往赛场。师徒之间既是互相成就又是彼此毁灭，直到那场最后的高校音乐会，安德鲁做了一个让所有人惊掉下巴的举动——然后爆裂地敲出了自己的节奏。", "score": 2014266, "category": "drama", "detail_url": "../movie/0827.html", "poster": "../posters/0827.svg"}, {"id": "0828", "title": "押解的故事", "year": 2000, "region": "中国", "type": "电影", "genre": "剧情 / 公路 / 犯罪", "tags": ["警匪 / 人性 / 荒诞 / 写实 / 长途"], "summary_short": "押解的故事，2000年中国电影，剧情 / 公路 / 犯罪。西北戈壁，老警察李建国接到了他职业生涯最后一项任务：将流窜犯马大全从新疆押解回宁夏原籍。马大全是个油嘴滑舌的小贼，总想着逃跑。两人乘坐的长途客车在中途遭遇暴雨引发的塌方，被困在一个只有十几户人家的荒凉驿站。在这里，他们遇到了一个自称前往宁夏寻亲的神秘女人“红姐”。红姐举止优雅，与周围环境格格不入。在等待道路抢修的三天两夜里，马大全几次试图拉拢红姐帮他逃跑，但红姐反而多次暗中帮助李", "score": 2000349, "category": "drama", "detail_url": "../movie/0828.html", "poster": "../posters/0828.svg"}, {"id": "0829", "title": "冤鬼再见粤语", "year": 2023, "region": "中国香港", "type": "电影", "genre": "喜剧 / 恐怖", "tags": ["鬼魂", "粤语梗", "黑色幽默"], "summary_short": "冤鬼再见粤语，2023年中国香港电影，喜剧 / 恐怖。风水师儿子陈茂才继承了一个“阴阳眼”体质，但他看到的鬼一点也不可怕——都是些困在生前琐事里的普通“社畜鬼”。有只鬼因为老板欠他三个月工资不肯投胎，有只鬼因为结婚钻戒掉进下水道，还有只鬼临终前没看完一部烂剧，非要陈茂才帮他看完并讲结局。陈茂才一边帮鬼解决这些荒诞的遗愿，一边被它们逼到精神崩溃。最后他发现，所有鬼魂都指向同一栋废弃大厦，而那里埋着一个真正凶残的厉鬼。当厉鬼出现时，陈茂才对", "score": 2023359, "category": "horror", "detail_url": "../movie/0829.html", "poster": "../posters/0829.svg"}, {"id": "0830", "title": "转山", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "剧情, 冒险, 励志", "tags": ["骑行", "西藏", "丧亲疗愈"], "summary_short": "转山，2021年中国大陆电影，剧情, 冒险, 励志。大学生林北的哥哥林南是一名骑行爱好者，在川藏线遭遇车祸去世。林北带着哥哥的遗物——一辆旧山地车和一本骑行日记，从成都出发，踏上哥哥未完成的路线。他毫无经验，第一天就摔车；在雅安被狗追；在折多山高反晕倒，被藏族大叔救下；在理塘遇到同样丧亲的女骑手央金，两人结伴。林北看哥哥的日记，发现哥哥最后一段写着“我好害怕，但我不想停”。到邦达时，林北想放弃，央金说“你哥怕的不是路，是没好好告别”。最", "score": 2021256, "category": "drama", "detail_url": "../movie/0830.html", "poster": "../posters/0830.svg"}, {"id": "0831", "title": "奥斯维辛集中营的守卫", "year": 2025, "region": "德国 / 波兰", "type": "电影", "genre": "剧情 / 历史 / 战争", "tags": ["人性", "二战", "道德困境", "沉重"], "summary_short": "奥斯维辛集中营的守卫，2025年德国 / 波兰电影，剧情 / 历史 / 战争。1942年，二战老兵汉斯因伤被调离前线，分配到奥斯维辛集中营担任外围守卫。他并非狂热的纳粹分子，只是每天麻木地看着列车抵达，然后在哨所里怀念战死的儿子。直到一个雨夜，他在花园的围墙下发现了一名虚脱的犹太女孩。汉斯没有告发她，而是偷偷给她送去面包和毛毯。随着苏联红军逼近，党卫军开始销毁证据，汉斯必须在“服从命令”与“拯救一条生命”之间做出最后的抉择。而那个女孩，", "score": 2025241, "category": "drama", "detail_url": "../movie/0831.html", "poster": "../posters/0831.svg"}, {"id": "0832", "title": "当燃青春", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "青春 / 励志 / 校园", "tags": ["高考", "乐队", "理想主义", "热血", "群像成长"], "summary_short": "当燃青春，2023年中国大陆剧集，青春 / 励志 / 校园。2009年，安徽小县城的高中，高三（7）班常年倒数第一。班主任说“你们没救了”，六个人却憋了一口气：凭什么成绩差就不配被看见？他们用废品站的旧乐器组了支乐队，目标是竞选县城春晚的节目。排练被嘲笑、设备被偷、家长砸琴、学校处分，甚至主唱被诊断出突发性耳聋。倒数30天，他们用借来的音箱在学校天台开了一场“无声演唱会”，意外被路人拍下传到网上。最后他们没上成春晚，但全城为他们点亮了除", "score": 2023234, "category": "series", "detail_url": "../movie/0832.html", "poster": "../posters/0832.svg"}, {"id": "0833", "title": "笑八仙", "year": 1993, "region": "中国香港", "type": "电影", "genre": "奇幻喜剧", "tags": ["八仙", "搞笑", "香港老片", "神仙", "穿越"], "summary_short": "笑八仙，1993年中国香港电影，奇幻喜剧。铁拐李、吕洞宾等八仙因在天庭聚众赌博，被王母娘娘罚下凡间。他们必须在一年内在凡间开一家店，并且教会三个凡人“快乐的真谛”。于是，八个神仙各显神通，从摆地摊卖仙丹到开网红奶茶店，闹出一系列啼笑皆非的笑话。何仙姑负责营销，蓝采和成了直播带货一哥，而张果老倒骑着驴送外卖。眼看期限将至，他们却陷入了一场由天庭“打假办”设下的骗局。", "score": 1993335, "category": "comedy", "detail_url": "../movie/0833.html", "poster": "../posters/0833.svg"}, {"id": "0834", "title": "情断爱河", "year": 2023, "region": "泰国", "type": "剧集", "genre": "爱情 / 虐恋 / 家庭", "tags": ["泰式狗血", "失忆", "替身", "催泪"], "summary_short": "情断爱河，2023年泰国剧集，爱情 / 虐恋 / 家庭。富家千金小琴与画家阿塔私奔途中，为救阿塔坠入湄公河。获救后她失去所有记忆，身边是一个自称“阿塔”的男人——阿塔的双胞胎哥哥阿卡。阿卡告诉她，她一直是自己的未婚妻，而阿塔是觊觎家产的骗子。小琴相信了。一年后婚礼上，阿塔突然出现，浑身伤疤。小琴看着两张一模一样的脸，记忆碎片闪现。她想起坠河前阿塔喊的是“我会娶你”，而阿卡喊的是“你本属于我”。她拿起花束走向两人，却在所有人面前转身离开。", "score": 2023243, "category": "series", "detail_url": "../movie/0834.html", "poster": "../posters/0834.svg"}, {"id": "0835", "title": "魔导具师妲莉亚不向人低头", "year": 2024, "region": "日本", "type": "电视剧", "genre": "动画, 奇幻, 职场", "tags": ["异世界转生", "女强人", "道具制作"], "summary_short": "魔导具师妲莉亚不向人低头，2024年日本电视剧，动画, 奇幻, 职场。转生到剑与魔法的世界，妲莉亚拥有前世工程师的记忆，成为了稀世的魔导具师。就在她满心期待与未婚夫——王国第一王子结婚时，王子却在宫廷宴会上当众指责她的魔导具“毫无美感且低俗”，并宣布与她解除婚约，让她沦为全王都的笑柄。心灰意冷的妲莉亚拿回了自己制作的所有魔导具专利，决定不再为贵族服务，而是开了一家面向平民的修理店。她将现代工程学与魔法结合，发明了“魔法洗衣机”、“自动烹", "score": 2024265, "category": "fantasy", "detail_url": "../movie/0835.html", "poster": "../posters/0835.svg"}, {"id": "0836", "title": "魔殿屠龙国语", "year": 1984, "region": "香港", "type": "电影", "genre": "动作 / 奇幻 / 武侠", "tags": ["邵氏", "魔幻武侠", "倚天屠龙记外传", "特效老片"], "summary_short": "魔殿屠龙国语，1984年香港电影，动作 / 奇幻 / 武侠。本片为《倚天屠龙记》外传性质作品，设定在张无忌携赵敏退隐之后。朱元璋称帝后为消除心头大患，派重兵围剿明教总坛光明顶。明教上下在杨逍、殷天正率领下死守，双方激战正酣时，山体突然剧烈震动，光明顶地下封印的“天魔龙”破土而出——这是当年黄裳撰写《九阴真经》时镇压的上古妖兽，体内流淌着腐蚀一切的魔血，所过之处生灵涂炭。朱元璋军队与明教教众被魔龙追杀，被迫放下恩怨组成临时同盟。一名神秘的", "score": 1984349, "category": "costume", "detail_url": "../movie/0836.html", "poster": "../posters/0836.svg"}, {"id": "0837", "title": "侦探拍档", "year": 2024, "region": "美国", "type": "电影", "genre": "动作喜剧", "tags": ["搭档", "冤家", "退休警察", "网络犯罪", "爆笑"], "summary_short": "侦探拍档，2024年美国电影，动作喜剧。脾气火爆的老警探麦克因打伤嫌犯被强制搭档社区服务——与12岁的华裔少女黑客小灵一起执行“低危任务”。小灵因入侵FBI网站被罚做义工。两人接到一桩离奇案件：全市名贵猫咪接连被盗，现场只留下一个猫爪图案的徽章。麦克想用老办法蹲点，小灵用大数据分析出猫贼将在今晚的音乐厅作案。两人在交响乐演奏中跟踪猫贼，发现对方竟然是……一位年过七旬、优雅至极的老太太。而她偷猫，是为了解放被富豪关在笼子里当饰品的动物。", "score": 2024392, "category": "crime", "detail_url": "../movie/0837.html", "poster": "../posters/0837.svg"}, {"id": "0838", "title": "魂归伤膝谷", "year": 2025, "region": "美国", "type": "电影", "genre": "剧情 / 历史 / 西部", "tags": ["印第安，种族屠杀，历史反思，伤痕，西部往事"], "summary_short": "魂归伤膝谷，2025年美国电影，剧情 / 历史 / 西部。1890年的伤膝谷大屠杀是印第安人心中的一道永久的伤疤。百年后，一位名叫“站立熊”的拉科塔族老兵，在孙女的陪伴下，拖着残破的身躯重返这片被鲜血浸染的土地。他患有严重的PTSD，眼前时常浮现出年轻时的自己——那个曾为美国政府而战，却眼睁睁看着族人被屠杀的勇士。在虚实交织的时空里，他遇见了当年的白人指挥官、自己的祖先以及死去的同胞。这趟回归之旅，不是为了复仇，而是为了寻找一种方式，让", "score": 2025258, "category": "drama", "detail_url": "../movie/0838.html", "poster": "../posters/0838.svg"}, {"id": "0839", "title": "叛逆战将2", "year": 1997, "region": "美国", "type": "电影", "genre": "动作 / 惊悚 / 犯罪", "tags": ["孤胆英雄", "街头枪战", "硬汉警察"], "summary_short": "叛逆战将2，1997年美国电影，动作 / 惊悚 / 犯罪。底特律警探杰克·迈尔斯是个出了名的暴脾气，抓捕毒贩时他从不念米兰达警告，更不在乎伤及无辜。因为一次行动中误杀平民，他被局长踢到了冷宫般的证物科。所有人都以为这个刺头会从此消沉，但迈尔斯却在整理证物的过程中发现了蹊跷：最近收缴的几批军火的编号被人为篡改了。经过暗中调查，他惊讶地发现，参与私卖军火的竟然是警局内部的高层。没有配枪，没有警徽，甚至没有后援，迈尔斯只能凭借一腔孤勇，在犯罪", "score": 1997437, "category": "crime", "detail_url": "../movie/0839.html", "poster": "../posters/0839.svg"}, {"id": "0840", "title": "静静的顿河", "year": 2021, "region": "俄罗斯", "type": "剧集", "genre": "剧情 / 战争 / 爱情", "tags": ["哥萨克", "史诗改编", "经典新拍"], "summary_short": "静静的顿河，2021年俄罗斯剧集，剧情 / 战争 / 爱情。改编自肖洛霍夫名著，但这次主角是阿克西妮亚。从她被父亲强暴、嫁给冷漠的斯捷潘，到与葛利高里的禁忌之恋，再到战争将她撕裂。这部八集剧集以前所未有的女性视角展现顿河哥萨克的百年悲歌。阿克西妮亚不再只是男主角的“情人”，她有自己的欲望、恐惧和选择。当她最后一次追随葛利高里出逃，却被流弹击中倒在顿河边时，她的独白长达五分钟：“我这一生，只想为自己活一次。哪怕只有一瞬间。”河水依旧静静流", "score": 2021286, "category": "series", "detail_url": "../movie/0840.html", "poster": "../posters/0840.svg"}, {"id": "0841", "title": "东离剑游纪第二季", "year": 2024, "region": "日本", "type": "剧集", "genre": "奇幻, 武侠, 布袋戏", "tags": ["霹雳", "虚渊玄", "神魔", "剑客"], "summary_short": "东离剑游纪第二季，2024年日本剧集，奇幻, 武侠, 布袋戏。魔剑目录风波平息后，殇不患带着三十六把魔剑继续流浪，却发现自己被一股来自西幽的神秘组织盯上。该组织名为“幽玄皇朝”，他们掌握着操控已死剑客魂魄的禁术，企图收集魔剑目录以打开通往魔界之门。与此同时，凛雪鸦察觉到自己昔日所骗的一位西幽皇女转世成了幽玄皇朝的女帝，目标直指他的性命。浪巫谣为保护被卷入战火的平民而再次出山，他与殇不患的立场逐渐从盟友走向对立——因为幽玄皇朝用以操控死者", "score": 2024246, "category": "series", "detail_url": "../movie/0841.html", "poster": "../posters/0841.svg"}, {"id": "0842", "title": "寻家第一季", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "剧情, 家庭", "tags": ["寻亲", "公路片", "打拐", "社会现实", "催泪"], "summary_short": "寻家第一季，2025年中国大陆剧集，剧情, 家庭。老赵头是个普通的陕北农民，儿子强强在三岁时被人贩子用一根糖葫芦拐走。妻子因此精神失常，家庭支离破碎。没有任何线索的老赵头，把强强的照片印在一面旗子上，插在三轮车后座，开始了万里寻子路。十年间，他走遍了中国的大江南北，睡过天桥，捡过垃圾，被人打过，也骗过。一路上，他结识了同样寻亲的大学生志愿者小杨，帮助了一个被遗弃的女孩找回亲生父母，也遇到了那个当年从他手里骗走孩子的中间人。第一季结尾，老", "score": 2025214, "category": "series", "detail_url": "../movie/0842.html", "poster": "../posters/0842.svg"}, {"id": "0843", "title": "夏洛特", "year": 2025, "region": "法国", "type": "电影", "genre": "传记 / 剧情 / 战争", "tags": ["真实人物改编", "大屠杀", "艺术与生存"], "summary_short": "夏洛特，2025年法国电影，传记 / 剧情 / 战争。影片改编自犹太裔德国艺术家夏洛特·萨洛蒙的真实故事。1939年，纳粹阴影笼罩欧洲。年轻的夏洛特逃离德国，流亡法国。她疯狂地创作，用近乎癫狂的速度在两年内完成了近800幅水粉画作品，命名为《人生如戏》。她用独特的“音乐背景式”画风，描绘了自己的家族史：母亲、姨妈、祖母的自杀，以及她自己被纳粹追捕的恐惧。她画下了所有她爱过和失去的人。1943年，夏洛特怀孕5个月时，在法国被捕，随即被送往", "score": 2025231, "category": "doc", "detail_url": "../movie/0843.html", "poster": "../posters/0843.svg"}, {"id": "0844", "title": "皮诺丘的奇幻旅程", "year": 2026, "region": "意大利", "type": "电影", "genre": "奇幻 / 冒险", "tags": ["暗黑童话", "木偶", "成长", "重口味"], "summary_short": "皮诺丘的奇幻旅程，2026年意大利电影，奇幻 / 冒险。暗黑版《木偶奇遇记》。小木偶皮诺丘发现自己和童话书里写的不一样：他说谎时鼻子不会变长，而是胸口会裂开一道伤口，流出鲜红的血——这是他唯一的“真实”证明。杰佩托并非慈祥老木匠，而是一个失去儿子的疯癫雕刻师，他造出皮诺丘是为了将儿子的灵魂封进去。在逃亡途中，皮诺丘遇到了被狐狸和猫奴役的孩子们、吃小孩的马戏团以及一个用欢乐掩盖痛苦的蓝发妓女。他一路寻找“变成真男孩”的办法，最后却发现所谓", "score": 2026294, "category": "fantasy", "detail_url": "../movie/0844.html", "poster": "../posters/0844.svg"}, {"id": "0845", "title": "出柜父母在偶家", "year": 2021, "region": "美国", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["LGBTQ+", "代际沟通", "青春期"], "summary_short": "出柜父母在偶家，2021年美国电影，喜剧 / 家庭。16岁的杰西卡是学校的风云人物，她的爸爸是橄榄球教练，妈妈是拉拉队指导，是小镇上的“模范家庭”。直到有一天，父母平静地告诉她：“我们想各自和同性在一起了。”杰西卡的第一反应不是崩溃，而是“我的毕业舞会怎么办？”更炸裂的是，她的妈妈爱上了学校图书管理员，而爸爸则和学校新来的男美术老师在一起了。整个保守小镇炸开了锅，家长们纷纷抵制，要求撤换杰西卡的父母。杰西卡从最初的尴尬、愤怒，到后来为了", "score": 2021280, "category": "comedy", "detail_url": "../movie/0845.html", "poster": "../posters/0845.svg"}, {"id": "0846", "title": "情结", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情、悬疑、心理", "tags": ["心理学", "母女关系", "强迫症", "港味文艺", "身份认同"], "summary_short": "情结，2024年中国香港电影，剧情、悬疑、心理。香港，二十六岁的插画师小乔患有严重的强迫症，每天必须洗手五十次、检查门锁三十次、按固定格数走地砖。她的母亲林博士是全港知名的临床心理学家，出版过三本关于强迫症治疗的畅销书，并在所有公开场合将女儿作为“被治愈的成功案例”。但实际上，小乔的病情从未好转，反而越来越重。为了戳破母亲的完美人设，小乔秘密找到母亲的竞争对手、精神分析学派医生何博士进行录音治疗，并计划将母亲“治疗失败”的证据公之于众。", "score": 2024325, "category": "drama", "detail_url": "../movie/0846.html", "poster": "../posters/0846.svg"}, {"id": "0847", "title": "超级兵王混农村2古墓传说", "year": 2025, "region": "中国大陆", "type": "网络电影", "genre": "动作, 冒险, 喜剧", "tags": ["兵王", "农村", "古墓", "摸金", "爽文"], "summary_short": "超级兵王混农村2古墓传说，2025年中国大陆网络电影，动作, 冒险, 喜剧。前特种兵王大龙归隐农村后，本想安心种地养鸡。谁料村里的老井突然干涸，井底露出一个刻满符文的石门。王大龙带着村里的老支书和隔壁的傻大个儿一起下墓探险，发现这竟是一座战国时期“不死军”将军的衣冠冢。墓中机关重重，更有神秘势力暗中尾随。当他们触碰到将军棺椁时，壁画上的阴兵竟然真的“活”了过来。王大龙必须用特种兵的战术思维，对抗两千年前的战争机器。", "score": 2025388, "category": "fantasy", "detail_url": "../movie/0847.html", "poster": "../posters/0847.svg"}, {"id": "0848", "title": "法证先锋2", "year": 2008, "region": "中国香港", "type": "剧集", "genre": "悬疑 / 犯罪", "tags": ["法证", "刑侦", "高科技破案", "港剧经典"], "summary_short": "法证先锋2，2008年中国香港剧集，悬疑 / 犯罪。法证部高级化验师高彦博和法医古泽琛带领团队，利用最先进的鉴证科技，与重案组精英马帼英合作，侦破连环凶案。本季案件更加错综复杂，从密闭空间杀人到模仿犯连续作案，每一个细节都需通过血迹形态、纤维比对和微量物证还原真相。团队内部也面临情感与职业道德的双重考验，有人为情所困，有人在正义与亲情间挣扎。在追寻真相的过程中，他们不仅要对抗狡猾的罪犯，更要直面内心的心魔，诠释“证据不会说谎”的核心理念", "score": 2008345, "category": "series", "detail_url": "../movie/0848.html", "poster": "../posters/0848.svg"}, {"id": "0849", "title": "血债血偿", "year": 2017, "region": "美国", "type": "电影", "genre": "动作，惊悚", "tags": ["复仇，硬汉，私刑，地下世界"], "summary_short": "血债血偿，2017年美国电影，动作，惊悚。前黑色行动特工维克多退隐后，女儿是他唯一的软肋。当女儿惨遭贩毒集团杀害，维克多重操旧业，开始了血腥的复仇。他逐一清除帮派成员，最终活捉了凶手。就在他即将扣动扳机时，一个神秘组织联系他，声称如果他能放过凶手，并将其完好无损地交给组织，他们可以用一项尚未公开的“记忆转移技术”，将女儿的意识上传到一个仿生躯体中。维克多陷入巨大痛苦：是手刃仇人，还是接受一个“非人”的女儿？他在复仇的路上越走越远，却发现", "score": 2017420, "category": "crime", "detail_url": "../movie/0849.html", "poster": "../posters/0849.svg"}, {"id": "0850", "title": "美好生活手册", "year": 2024, "region": "意大利", "type": "剧集", "genre": "喜剧，生活", "tags": ["慢生活，治愈，退休，邻里"], "summary_short": "美好生活手册，2024年意大利剧集，喜剧，生活。45岁的基金经理陈卓过劳死在办公桌前。到了天堂，上帝说他“业绩”不达标——生前从未真正活过。他获得一次复活机会：必须让五个陌生人学会“浪费时间”——包括发呆、看日落、织毛衣、种番茄、写一封不会寄出的信。他伪装成水管工住进意大利小镇，目标有：焦虑的全职妈妈、痴迷工作的程序员、不敢退休的老校长、从不拍照的摄影师、以及一个把自己关在房间十年的少年。陈卓用“浪费”的方法帮他们找回生活，却发现最需要", "score": 2024220, "category": "series", "detail_url": "../movie/0850.html", "poster": "../posters/0850.svg"}, {"id": "0851", "title": "弗里蒙特", "year": 2023, "region": "美国", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["阿富汗移民", "孤独", "温情", "黑白摄影"], "summary_short": "弗里蒙特，2023年美国电影，剧情 / 喜剧。多尼娅曾为美军担任翻译，来到美国后定居在加州弗里蒙特。她失眠严重，在一家华人开的幸运饼干工厂上夜班，负责往饼干里塞纸条。孤独驱使她开始偷偷在纸条里写下自己的真实想法：“我很孤单”、“我想回家”、“我不知道我是谁”。这些饼干被送往全美各地，竟收到了几封回信。其中一位中年丧偶的白人机械师的回信让她决定踏上一场穿越加州的内陆之旅，去寻找一个从未谋面的笔友，也寻找她在这片新土地上的身份。", "score": 2023286, "category": "drama", "detail_url": "../movie/0851.html", "poster": "../posters/0851.svg"}, {"id": "0852", "title": "斗罗大陆：双神大战", "year": 2024, "region": "中国大陆", "type": "动画电影", "genre": "动作 / 奇幻 / 冒险", "tags": ["热血", "神位之战", "特效炸裂", "宿命对决", "武魂"], "summary_short": "斗罗大陆：双神大战，2024年中国大陆动画电影，动作 / 奇幻 / 冒险。延续动画剧集剧情，唐三和小舞刚刚巩固海神与修罗神双神位，武魂殿残余势力扶持了新一代天使之神——千仞雪归來。千仞雪因爱生恨，携带着对唐三的执念与毁天灭地的天使圣剑，誓要踏平史莱克学院。大战在星斗大森林爆发，泰坦巨猿和天青牛蟒在神级战力面前不堪一击。唐三被迫开启修罗神海神双模式，小舞则以柔骨兔第九魂技“无敌金身”强行抵挡致命一击。战斗中，唐三发现了千仞雪神力背后的致命", "score": 2024367, "category": "fantasy", "detail_url": "../movie/0852.html", "poster": "../posters/0852.svg"}, {"id": "0853", "title": "燃情克利夫兰第三季", "year": 2024, "region": "美国", "type": "剧集", "genre": "喜剧、情景、生活", "tags": ["闺蜜日常、中年女性、毒舌台词、洛杉矶vs克利夫兰"], "summary_short": "燃情克利夫兰第三季，2024年美国剧集，喜剧、情景、生活。《燃情克利夫兰》第三季中，梅兰妮、乔伊和维多利亚彻底习惯了克利夫兰慢节奏的生活，并决定合伙开一家法式烘焙店。梅兰妮负责店面管理，乔伊负责研发甜点，维多利亚则利用过气明星的身份做营销。然而开业第一天就遭遇隔壁肉铺老板的恶意竞争，对方用高音喇叭循环播放“吃了会胖”的录音。房东艾尔卡老太太拿出珍藏多年的私房食谱帮助她们做出爆款“愤怒的泡芙”。感情线上，梅兰妮与前夫重修旧好却被发现他已再", "score": 2024273, "category": "series", "detail_url": "../movie/0853.html", "poster": "../posters/0853.svg"}, {"id": "0854", "title": "兰博基尼：传奇", "year": 2024, "region": "意大利 / 美国", "type": "电影", "genre": "传记 / 运动", "tags": ["跑车，创业，对手"], "summary_short": "兰博基尼：传奇，2024年意大利 / 美国电影，传记 / 运动。二战后的意大利，费鲁吉欧·兰博基尼靠改装军用拖拉机起家。作为法拉利车迷，他拥有一辆法拉利，却发现离合器存在设计缺陷。当他向恩佐·法拉利提出改进建议时，对方傲慢地回绝：“一个造拖拉机的没资格对法拉利指手画脚。”这句羞辱点燃了兰博基尼的斗志。他召集最优秀的工程师，立誓要造出完美的超跑。影片聚焦1963年至1966年，从第一台350GTV原型车诞生到Miura震惊日内瓦车展，再现", "score": 2024243, "category": "doc", "detail_url": "../movie/0854.html", "poster": "../posters/0854.svg"}, {"id": "0855", "title": "赌侠大战拉斯维加斯", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧、动作", "tags": ["赌博、赌场、卧底、复仇、搞笑"], "summary_short": "赌侠大战拉斯维加斯，2024年中国香港电影，喜剧、动作。香港老千阿乐因出千被澳门赌场老板“九指强”抓住，没被砍手，反而被派去拉斯维加斯的“幸运马蹄”赌场，执行一个荒唐任务：偷走对家老板收藏的一颗“黄金骰子”，传说这颗骰子能控制任何赌局的点数。阿乐带着两个废柴搭档潜入赌场，一个负责色诱保安队长，一个负责黑进监控系统。结果发现黄金骰子根本不存在，那是九指强编出来的谎话，真正的目的是让阿乐在赌场引发混乱，好让九指强趁机做空对方股票。阿乐将计就", "score": 2024351, "category": "crime", "detail_url": "../movie/0855.html", "poster": "../posters/0855.svg"}, {"id": "0856", "title": "续命之徒：绝命毒师电影", "year": 2019, "region": "美国", "type": "电影", "genre": "犯罪, 剧情, 惊悚", "tags": ["衍生电影", "逃亡", "西部", "救赎"], "summary_short": "续命之徒：绝命毒师电影，2019年美国电影，犯罪, 剧情, 惊悚。承接《绝命毒师》大结局，杰西驾车疯狂逃离托德等人的据点，但他并未获得自由。他的脸上写满了创伤，身上背着重罪，怀揣着不多的现金，成为了全美国通缉的要犯。影片双线叙事，一边是他当下的逃亡之旅，为了洗白身份、拿到钱、逃往阿拉斯加，他不得不再次接触那些危险的地下人物，处理掉追兵；另一边则是闪回，回忆他和老白、麦克等人相处的时光，特别是老白曾经对他说过的那些关于“选择”和“命运”的", "score": 2019430, "category": "crime", "detail_url": "../movie/0856.html", "poster": "../posters/0856.svg"}, {"id": "0857", "title": "梦想家约瑟夫", "year": 2027, "region": "法国", "type": "电影", "genre": "奇幻", "tags": ["魔幻现实主义", "二战", "孩童视角", "想象力", "治愈"], "summary_short": "梦想家约瑟夫，2027年法国电影，奇幻。8岁的约瑟夫被关在集中营，他不理解什么是死亡。他告诉4岁的妹妹：“我是时空行者，我可以让坏人看不见我们。”每当恐惧袭来，他就带领孩子们玩“隐身游戏”、“时间暂停游戏”。大人们痛苦绝望，但约瑟夫的“魔法”真的应验了：纳粹好几次从他身边走过却没发现他们。直到解放前夜，约瑟夫为了让妹妹喝上一口热汤，独自走出藏身的阁楼。敌人发现了他。枪响前，约瑟夫微笑着对妹妹做了个“嘘”的手势。多年后，白发苍苍的妹妹回忆", "score": 2027288, "category": "fantasy", "detail_url": "../movie/0857.html", "poster": "../posters/0857.svg"}, {"id": "0858", "title": "迷途人生", "year": 2024, "region": "美国", "type": "剧集", "genre": "剧情, 公路", "tags": ["旅行", "自我救赎", "群像"], "summary_short": "迷途人生，2024年美国剧集，剧情, 公路。一场特大暴雪导致全美航班停飞，五个背景迥异的人被迫拼租一辆越野车，从纽约前往洛杉矶。他们有刚失业的华尔街精英、离家出走的叛逆少女、寻找失踪儿子的退伍老兵、确诊绝症后放弃治疗的退休教师，以及一个身份不明的神秘司机。三千英里的公路上，车子接连抛锚、遭遇暴风雪、露宿荒野。起初每个人都在伪装，随着旅途深入，真实的伤疤被一层层揭开。他们发现，每个人奔赴的目的地背后都藏着一个谎言，而终点等待他们的，是一场", "score": 2024255, "category": "series", "detail_url": "../movie/0858.html", "poster": "../posters/0858.svg"}, {"id": "0859", "title": "监察局长", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "反腐，犯罪，剧情", "tags": ["双面人，内鬼，暗战，证据链，权力博弈"], "summary_short": "监察局长，2024年中国大陆电视剧，反腐，犯罪，剧情。东平市监察局局长赵学军到任第一周，便收到举报：市环保局副局长李涛受贿千万。证据确凿，赵学军签发逮捕令。当他看到案卷照片时，愣住了——李涛竟是他大学时代最好的兄弟，十年前因一场车祸被宣布死亡。他秘密调查，发现李涛用整形手术换了身份，现在是个庞大洗钱网络的关键一环。更恐怖的是，举报人正是系统内匿名“内鬼”。随着原副市长落马，赵学军意识到：兄弟的“假死”本身就是当年老领导布的局，目的是让他", "score": 2024344, "category": "series", "detail_url": "../movie/0859.html", "poster": "../posters/0859.svg"}, {"id": "0860", "title": "闺蜜心窍", "year": 2019, "region": "中国", "type": "电影", "genre": "惊悚, 恐怖, 心理", "tags": ["闺蜜", "整容", "嫉妒", "精神分裂"], "summary_short": "闺蜜心窍，2019年中国电影，惊悚, 恐怖, 心理。整容医生刘欣即将与相恋多年的男友步入婚姻殿堂，她唯一的闺蜜是同样从事医美行业的苏瑶。婚礼前夕，刘欣的手机开始收到神秘照片：照片里的女人顶着和她一模一样的脸，却和她的未婚夫在豪华酒店里缠绵。刘欣质问未婚夫，未婚夫却矢口否认。随着调查深入，刘欣发现自己近期偶尔会莫名失去一段记忆。她偷装了监控，看到了令她毛骨悚然的画面——每晚深夜，她会自己爬起来化妆、换衣服，悄无声息地出门，仿佛身体里住着另", "score": 2019379, "category": "horror", "detail_url": "../movie/0860.html", "poster": "../posters/0860.svg"}, {"id": "0861", "title": "诱惑医生100招", "year": 2025, "region": "韩国", "type": "剧集", "genre": "浪漫, 喜剧", "tags": ["女追男", "医院", "欢喜冤家"], "summary_short": "诱惑医生100招，2025年韩国剧集，浪漫, 喜剧。电影系毕业的姜未来为了拍纪录片，潜入医院当文员，却对“手术室里的冰雕”李江旭医生一见钟情。坚信万物皆可量化的她，将追男神当作毕业论文课题，列出了“诱惑医生100招”的思维导图，从巴甫洛夫式偶遇到吊桥效应实践。然而，她的每个计划都被李医生的毒舌和同事们的神助攻搞得啼笑皆非。当她以为靠第99招“英雄救美”成功时，却发现李医生早已看穿一切，甚至反向利用了她的“招数”，让她一步步掉进了名为爱情", "score": 2025219, "category": "series", "detail_url": "../movie/0861.html", "poster": "../posters/0861.svg"}, {"id": "0862", "title": "一念时光第二季", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "悬疑, 爱情, 科幻", "tags": ["时间循环", "平行时空", "虐恋", "烧脑", "续作"], "summary_short": "一念时光第二季，2025年中国大陆剧集，悬疑, 爱情, 科幻。《一念时光》第二季紧接第一季结局。女主角林晚为了拯救车祸死亡的恋人陆司明，利用神秘怀表反复进行“72小时时间循环”。第一季结尾她终于成功，陆司明活了下来。但第二季一开始，林晚发现眼前的陆司明虽然容貌相同，却完全不记得他们曾经的爱情细节——他来自另一个平行宇宙，是这个时间线里“本该”存在的陆司明，却不是与林晚相爱的那个。更可怕的是，林晚每进行一次循环，就会分裂出一个新的平行宇宙", "score": 2025412, "category": "series", "detail_url": "../movie/0862.html", "poster": "../posters/0862.svg"}, {"id": "0863", "title": "江湖艳迹", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "武侠 / 爱情 / 文艺", "tags": ["女侠", "民国", "戏曲", "遗憾"], "summary_short": "江湖艳迹，2023年中国台湾电影，武侠 / 爱情 / 文艺。日据时期台湾，歌仔戏班花旦云娘每晚表演结束后，蒙面劫富济贫，专偷日本高官的财物分给穷人。年轻警长武雄负责追捕“夜蝴蝶”，他最爱看云娘的戏，甚至对她暗生情愫。一次行动中云娘受伤，武雄救下她，两人在雨夜定情。云娘决定金盆洗手，但最后一单是为了筹钱给戏班赎回地契。行动当晚，武雄接到线报埋伏。两人在屋顶相遇，月光下同时认出彼此。云娘没有逃，武雄没有抓。武雄朝天开了三枪，大喊“人跑了”。", "score": 2023312, "category": "costume", "detail_url": "../movie/0863.html", "poster": "../posters/0863.svg"}, {"id": "0864", "title": "胖嫂回娘家", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 家庭 / 公路", "tags": ["东北，农村，电动车，母女，爆笑"], "summary_short": "胖嫂回娘家，2025年中国大陆电影，喜剧 / 家庭 / 公路。在深圳打工的胖嫂接到老家电话，说60岁的母亲要嫁给一个卖保健品的“神医”。胖嫂一怒之下，不会开车、不懂导航，硬是骑着自己的电动三轮车从深圳出发，要赶回东北阻止婚礼。一路上，她经历了高速偷上、导航迷路、遭遇碰瓷、甚至被当成骗子。这场荒诞的归途变成了一场当代女性生存图鉴。当她风尘仆仆赶到家时，发现母亲穿上婚纱的样子很美，而那个“神医”的真实身份，让她重新思考什么是孝顺。", "score": 2025285, "category": "comedy", "detail_url": "../movie/0864.html", "poster": "../posters/0864.svg"}, {"id": "0865", "title": "云南故事", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭 / 年代", "tags": ["云南", "跨境家族", "茶马古道", "时代变迁", "史诗"], "summary_short": "云南故事，2024年中国大陆剧集，剧情 / 家庭 / 年代。故事始于1920年代的腾冲，马帮首领老段头在茶马古道上意外救了一个缅甸少女，并娶为二房。从此，这个家族的血脉里流淌着两个国家、三种信仰。第一代人死于抗日远征军，第二代人离散于中缅划界，第三代人偷渡去做翡翠生意，第四代人终于站在了瑞丽口岸的两边——一边是中国，一边是缅甸。剧中通过一片古茶林的所有权之争，串联起边境近百年的风云变幻。当第四代的姐姐作为翻译出现在中缅联合考古队，而弟弟", "score": 2024245, "category": "drama", "detail_url": "../movie/0865.html", "poster": "../posters/0865.svg"}, {"id": "0866", "title": "金陵秘事", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "悬疑, 历史, 谍战", "tags": ["民国奇案", "文物", "家族恩怨"], "summary_short": "金陵秘事，2026年中国大陆剧集，悬疑, 历史, 谍战。1948年冬，南京城风雨飘摇。前清遗老金老爷子在其府邸“金陵阁”中被杀，死时身着仿制龙袍，现场留有一张模糊的照片。警察局探长沈飞调查此案，发现死者与多名国民党高官、文物商人以及一位神秘的日本女人都有交集。随着第二起、第三起穿着不同朝代“龙袍”的命案接连发生，沈飞意识到，凶手并非疯子，而是在按照某种仪轨进行复仇。所有线索指向了1924年紫禁城里一场被掩盖的文物失窃案。当真相逐步揭开，", "score": 2026256, "category": "series", "detail_url": "../movie/0866.html", "poster": "../posters/0866.svg"}, {"id": "0867", "title": "分手的决心", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑, 爱情, 剧情", "tags": ["朴赞郁式美学", "蛇蝎美人", "山与海", "执念"], "summary_short": "分手的决心，2024年韩国电影，悬疑, 爱情, 剧情。性格谨慎的刑警海俊在调查一起发生在险峻山上的离奇坠落案时，遇到了死者的中国籍妻子宋瑞莱。瑞莱面对丈夫的死亡表现出异乎寻常的冷静，甚至带有某种释然。海俊明知她极有可能是凶手，却在日复一日的监视与询问中，被她那种兼具脆弱与坚韧的破碎美感所吸引。他为了包庇瑞莱，甚至修改了证物报告。正当两人关系升温，海俊以为尘埃落定时，瑞莱却突然失踪，并在另一座城市的海边留下了新的尸体和一盘录音带。录音带里", "score": 2024396, "category": "drama", "detail_url": "../movie/0867.html", "poster": "../posters/0867.svg"}, {"id": "0868", "title": "私枭湾风云", "year": 1993, "region": "香港", "type": "电影", "genre": "剧情 / 犯罪 / 动作", "tags": ["走私", "家族恩怨", "枭雄", "悲情"], "summary_short": "私枭湾风云，1993年香港电影，剧情 / 犯罪 / 动作。六十年代末，香港还没有成为国际大港，偏远的“私枭湾”是走私客的天堂。程家和骆家是控制海湾的两大家族，表面和平，暗地争夺码头控制权。程家长子“程志豪”深爱骆家女儿“阿珍”，试图联姻化解恩怨。然而在一次联合走私中，骆家老大被警方伏击身亡，骆家认定程家出卖。阿珍被迫嫁给马来走私大佬做妾以求外援。程志豪为了夺回阿珍，也为了生存，开始勾结英国商人，引入军火交易。一场大火并后，程志豪炸毁了骆", "score": 1993415, "category": "crime", "detail_url": "../movie/0868.html", "poster": "../posters/0868.svg"}, {"id": "0869", "title": "暮光之城3：月食", "year": 2010, "region": "美国", "type": "电影", "genre": "奇幻 / 爱情 / 惊悚", "tags": ["吸血鬼", "狼人", "三角恋", "超自然", "系列续作"], "summary_short": "暮光之城3：月食，2010年美国电影，奇幻 / 爱情 / 惊悚。贝拉在爱德华与雅各布之间的抉择日益艰难，而西雅图接连发生的离奇命案证实了最坏的猜测：维多利亚集结了一支新生吸血鬼军队，疯狂且毫无理智。为了自保，卡伦家族不得不与狼人阵营达成脆弱的联盟。雅各布在战斗中屡次舍命保护贝拉，而爱德华则将婚姻作为最后的安全保障。当两方在雪地展开决战时，贝拉终于认清自己既不属于人类世界，也无法完全融入黑暗——她必须成为一个母亲、一个伴侣，以及一个打破宿", "score": 2010408, "category": "horror", "detail_url": "../movie/0869.html", "poster": "../posters/0869.svg"}, {"id": "0870", "title": "30次", "year": 2017, "region": "日本", "type": "电影", "genre": "爱情 / 剧情 / 伦理", "tags": ["纯爱", "疾病", "生命教育", "催泪"], "summary_short": "30次，2017年日本电影，爱情 / 剧情 / 伦理。20岁的少女小梢患有一种导致消化系统逐渐衰竭的罕见病，医生说她最多还能进食30次。这意味着她将在未来一个月内慢慢饿死。小梢列出一个清单：在这30次进食中，她要做30件从未做过的事——第一次吃重庆火锅、第一次和暗恋的学长约会吃饭、第一次为家人做生日蛋糕、第一次吃霸王餐。每一次进食都是一次倒计时，也是一次生命体验的扩充。在与家人、朋友和学长互动的过程中，小梢重新理解了“活过”的意义。第2", "score": 2017376, "category": "drama", "detail_url": "../movie/0870.html", "poster": "../posters/0870.svg"}, {"id": "0871", "title": "我推是反派大小姐", "year": 2023, "region": "日本", "type": "剧集", "genre": "动画 / 喜剧 / 百合 / 奇幻", "tags": ["穿越", "乙女游戏", "反派千金", "职场恋爱"], "summary_short": "我推是反派大小姐，2023年日本剧集，动画 / 喜剧 / 百合 / 奇幻。社畜大桥零，在加班后穿越到了她最爱的乙女游戏《Revolution》的世界，但不是主角，而是连名字都没有的平民“零”。在这个世界里，按照剧情发展，高傲的反派大小姐“克莱尔·弗朗索瓦”最后会被流放。所有人都想攻略王子，只有零是克莱尔的狂热粉丝（“我推”）。零运用现代商业知识（KPI、社群运营）帮克莱尔打理领地，用“资本主义”手段对抗贵族的腐朽。面对克莱尔的冷言冷语，", "score": 2023269, "category": "series", "detail_url": "../movie/0871.html", "poster": "../posters/0871.svg"}, {"id": "0872", "title": "缄默的迷宫", "year": 2024, "region": "法国", "type": "电影", "genre": "悬疑, 惊悚, 奇幻", "tags": ["记忆宫殿", "心理迷宫", "失语症"], "summary_short": "缄默的迷宫，2024年法国电影，悬疑, 惊悚, 奇幻。少女莉莉因童年创伤患上了完全性失语症，无法说话也不会写字。她的母亲被谋杀，莉莉是唯一目击者，但无法作证。警方请来认知科学家艾伦，利用新型“记忆映射”技术进入莉莉的大脑。他们发现莉莉的记忆不是线性存储的，而是一座不断变化的“迷宫”——每个房间代表一段记忆，门会消失，走廊会旋转，还有“记忆怪兽”在吞噬关键线索。艾伦必须在莉莉的潜意识将真相彻底遗忘之前，穿越迷宫找到凶手的面孔。而随着深入，", "score": 2024463, "category": "crime", "detail_url": "../movie/0872.html", "poster": "../posters/0872.svg"}, {"id": "0873", "title": "炮破情巢", "year": 1975, "region": "中国香港", "type": "电影", "genre": "动作, 剧情", "tags": ["邵氏", "武侠", "复仇", "决斗"], "summary_short": "炮破情巢，1975年中国香港电影，动作, 剧情。民国初年，军阀混战。枪法如神的马贼张铁心隐退江湖，只为与爱人小蝶过安稳日子。不料，盘踞一方的恶霸雷老虎看上了小蝶的美貌，设计将小蝶抢入他金碧辉煌、机关重重的府邸——“情巢”。张铁心几次潜入都无功而返，反而惊动了雷老虎。为了彻底了断，雷老虎放出消息，会在三日后当众“纳妾”。张铁心不再隐秘行动，而是扛着一门土炮，单枪匹马杀向“情巢”。一路上，他与雷老虎的众多打手激烈枪战，炮火声震天。最终在“情", "score": 1975354, "category": "drama", "detail_url": "../movie/0873.html", "poster": "../posters/0873.svg"}, {"id": "0874", "title": "重生之慕甄", "year": 2026, "region": "中国大陆", "type": "电视剧", "genre": "剧情", "tags": ["重生", "宅斗", "逆袭", "女性觉醒"], "summary_short": "重生之慕甄，2026年中国大陆电视剧，剧情。慕甄前世是苏州织造嫡女，被庶妹慕瑶设计失去贞洁，沦为瘦马最后惨死乱葬岗。重生醒来，她惊恐地发现自己竟然在慕瑶的身体里，而真正的慕甄已经“死”了。她必须一边模仿慕瑶那令人作呕的虚伪笑容，一边调查前世真相。更诡异的是，这个身体里似乎残留着慕瑶本人的意识碎片，时常在午夜让她看到慕瑶童年的悲惨遭遇——原来庶妹也是家族权力斗争的棋子。慕甄陷入身份认知障碍：她究竟该为前世的自己复仇，还是为这具身体的原主人", "score": 2026184, "category": "series", "detail_url": "../movie/0874.html", "poster": "../posters/0874.svg"}, {"id": "0875", "title": "男子拳击", "year": 2024, "region": "美国", "type": "电影", "genre": "运动，剧情，励志", "tags": ["拳击，变性选手，性别争议，体育精神，父女"], "summary_short": "男子拳击，2024年美国电影，运动，剧情，励志。跨性别男性拳手迈卡已经完成激素治疗和胸部重建手术，合法参加业余男子组拳击比赛。但他连赢三场后，所有对手开始集体罢赛，理由是“生理女性骨骼密度差异”。拳击协会陷入两难。这时，曾经的世界拳王、56岁的退役老将比尔·“铁锤”·汉森主动申请与迈卡打一场表演赛。所有人以为比尔是去“教训”迈卡，但比尔在发布会上说：“我打了三十年拳，见过最硬的汉子和最怂的娘们。我想和这个年轻人打一场，因为他是唯一一个敢", "score": 2024251, "category": "drama", "detail_url": "../movie/0875.html", "poster": "../posters/0875.svg"}, {"id": "0876", "title": "蒂法有麻烦了", "year": 2023, "region": "日本", "type": "动画电影", "genre": "动作 / 科幻 / 悬疑", "tags": ["赛博朋克 / 格斗 / 女英雄 / 绑架 / 阴谋"], "summary_short": "蒂法有麻烦了，2023年日本动画电影，动作 / 科幻 / 悬疑。故事发生在米德加重建两年后。某个雨夜，蒂法独自在第七天堂酒吧看店，一个浑身是血的少年闯了进来，手里拿着一枚刻有神罗标志的加密芯片。少年只说了一句“它在找我”便昏死过去。蒂法还没来得及检查少年的伤势，一群经过高度改造的黑色机体便包围了酒吧。为首的是一个自称“猎手”的女性AI，她声称少年偷走了属于“新神罗”的核心记忆体。蒂法拒绝交人，随即爆发了一场激烈的酒吧巷战。蒂法凭借精湛的", "score": 2023437, "category": "crime", "detail_url": "../movie/0876.html", "poster": "../posters/0876.svg"}, {"id": "0877", "title": "目之所及", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["阿尔茨海默症", "父子", "记忆碎片"], "summary_short": "目之所及，2025年中国大陆电影，剧情, 家庭。老赵患有阿尔茨海默症，只记得自己有个儿子叫赵雷。可他不知道的是，赵雷已在三年前的火灾中为救他而死。每天早晨，护士都会给他一张“儿子”的旧照，告诉他“赵雷出差了”。老赵就对着照片练习怎么当一个好父亲。直到一天，一个自称赵雷的年轻人出现，用和老赵儿子一模一样的语气叫了一声“爸”。老赵认出了这声音，也认出了眼前的人是儿子捐出心脏的受捐者。", "score": 2025237, "category": "drama", "detail_url": "../movie/0877.html", "poster": "../posters/0877.svg"}, {"id": "0878", "title": "古田1929", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "历史 / 战争 / 政治", "tags": ["重大革命历史，热血，建军思想，信仰辩论，伟人青春"], "summary_short": "古田1929，2024年中国大陆电影，历史 / 战争 / 政治。1929年岁末，红四军内部关于建军原则的争论达到白热化。刚从苏联回来的刘安恭推行“极端民主化”，主张取消党对军队的绝对领导，与毛泽东的建军思想剧烈碰撞。影片聚焦会议召开前三天，以毛泽东肺炎卧床却坚持写作《纠正党内错误思想》为主线，穿插朱德、陈毅在行军途中的反思，以及基层士兵委员会讨论打不打一户土豪的实际分歧。在一个雨夜，毛泽东与朱德围炉夜话，从井冈山斗争谈到革命未来，达成“", "score": 2024290, "category": "doc", "detail_url": "../movie/0878.html", "poster": "../posters/0878.svg"}, {"id": "0879", "title": "反复缺席", "year": 2024, "region": "中国台湾", "type": "剧集", "genre": "家庭 / 剧情 / 奇幻", "tags": ["时间循环", "阿尔茨海默", "和解"], "summary_short": "反复缺席，2024年中国台湾剧集，家庭 / 剧情 / 奇幻。程序员江承恩每周三都会去疗养院探望患有重度阿尔茨海默症的母亲。奇怪的是，每次他踏入母亲的病房，就会瞬间坠入一段母亲混乱的记忆碎片。在这些碎片里，他看到了儿时父母争吵的夜晚、自己第一次撒谎的午后、以及母亲独自去医院做手术的清晨——而这些场景中，“他”都因为各种微不足道的理由缺席了。承恩发现，自己必须在这些记忆幻境中做出不同选择，填补过去的空白，才能让母亲在现实中认出自己。但每一次", "score": 2024320, "category": "drama", "detail_url": "../movie/0879.html", "poster": "../posters/0879.svg"}, {"id": "0880", "title": "追你而来", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "爱情, 喜剧, 公路", "tags": ["欢喜冤家", "自驾游", "治愈"], "summary_short": "追你而来，2025年中国大陆电视剧，爱情, 喜剧, 公路。广告总监林姗被未婚夫背叛后，决定独自完成原定的藏地自驾婚礼之旅。出发不久，她被迫捎上了因直播失败而被公司开除的“话痨”前主持人方有志。两人一路互损，从川西吵到拉萨。途中他们遭遇车辆爆胎、高原反应、甚至误入牧区节庆。林姗逐渐卸下职场盔甲，方有志也重拾了对生活的热情。在纳木错湖边，两人因与当地牧民的误会而共度一夜，感情升温。当旅程抵达终点，林姗的前男友突然出现请求复合，方有志则收到了", "score": 2025343, "category": "series", "detail_url": "../movie/0880.html", "poster": "../posters/0880.svg"}, {"id": "0881", "title": "加密货币", "year": 2027, "region": "美国 / 中国大陆", "type": "电影", "genre": "惊悚 / 犯罪 / 悬疑", "tags": ["比特币", "暗网", "卧底", "金融诈骗", "科技黑帮"], "summary_short": "加密货币，2027年美国 / 中国大陆电影，惊悚 / 犯罪 / 悬疑。FBI程序员王博被派去卧底全球最大的加密货币交易所“宙斯盾”。他很快凭借技术升为核心成员。一次无意中，他破解了交易所稳定币的底层代码，发现每一枚“宙斯币”背后，对应的是暗网上的一笔人体器官交易。交易所CEO本杰明实际上是全球器官贩卖组织的头目。王博试图将证据传回FBI，但交易所所有数据都被量子加密，传输即自毁。他设计了一个逻辑炸弹，当“宙斯币”总市值突破一万亿时自动解", "score": 2027523, "category": "crime", "detail_url": "../movie/0881.html", "poster": "../posters/0881.svg"}, {"id": "0882", "title": "萌犬派崔克", "year": 2023, "region": "英国", "type": "电影", "genre": "家庭, 喜剧", "tags": ["宠物", "真狗真事", "治愈", "英伦乡村"], "summary_short": "萌犬派崔克，2023年英国电影，家庭, 喜剧。伦敦精英律师詹姆斯陷入中年财务危机。他意外继承了古怪姑妈的一只边牧派崔克，以及一句遗嘱：“听狗的。”起初他以为姑妈疯了，直到派崔克用叼纸币、按计算器、对着股票机狂吠等行为，精准提示他买卖基金。詹姆斯半信半疑地跟随“狗股神”操作，竟真的在三个月内还清债务。当他膨胀到想一夜暴富时，派崔克却躺在地上死也不动。最终詹姆斯才明白，姑妈留给他的不是理财秘籍，而是一只教会他“不要贪婪”的狗。", "score": 2023242, "category": "comedy", "detail_url": "../movie/0882.html", "poster": "../posters/0882.svg"}, {"id": "0883", "title": "再次人生", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "奇幻爱情", "tags": ["重生", "婚姻危机", "平行时空", "双向救赎"], "summary_short": "再次人生，2024年中国大陆剧集，奇幻爱情。结婚七年的周晚和方言在民政局办完离婚手续后，遭遇车祸，同时重生回到22岁的大三夏天。周晚以为自己独占这份幸运，她疯狂避开当年踩过的坑，发誓要嫁给更有钱的前任。而方言也装作无事发生，拼命阻止当年的自己追求周晚，因为他不想让她再跟着自己吃苦。两人在大学校园里以陌生人的身份重逢，却总是不自觉地做出和当年一样的选择。周晚发现方言默默为她挡雨、存钱、放弃出国，她终于崩溃：原来前世方言所有的“没出息”，都", "score": 2024349, "category": "series", "detail_url": "../movie/0883.html", "poster": "../posters/0883.svg"}, {"id": "0884", "title": "科西嘉兄弟", "year": 2024, "region": "法国", "type": "电影", "genre": "喜剧, 动作", "tags": ["黑帮", "兄弟情", "科西嘉岛", "连体婴"], "summary_short": "科西嘉兄弟，2024年法国电影，喜剧, 动作。科西嘉岛上，一对连体双胞胎兄弟皮埃尔（冷静理性）和保罗（火爆冲动）共享一个肝脏。父亲去世后，黑帮要霸占家族葡萄园。两人虽共用身体，却整天吵架。为了夺回家园，他们被迫合作：皮埃尔负责策略，保罗负责打架。两人骑着一辆特制摩托车，在海边悬崖与黑帮展开追逐战。最终他们利用连体的特殊性，一个假装投降吸引注意，另一个背后突袭。胜利后，他们第一次说出：“我们其实是最好的搭档。”", "score": 2024316, "category": "crime", "detail_url": "../movie/0884.html", "poster": "../posters/0884.svg"}, {"id": "0885", "title": "食人魔餐厅", "year": 2024, "region": "日本", "type": "剧集", "genre": "恐怖, 悬疑", "tags": ["黑色幽默", "美食", "社会寓言"], "summary_short": "食人魔餐厅，2024年日本剧集，恐怖, 悬疑。东京新宿某条暗巷深处，一家无招牌餐厅每晚只接待一桌客人。主厨是神秘中年男人，菜单上菜名古怪：“物欲横流的老赖”“职场霸凌的上司”“校园沉默的帮凶”。每道菜惊艳绝伦，食客吃完后第二天，对应的那个人就会离奇失踪。美食博主菜菜子伪装身份潜入探店，发现主厨其实是一位前法医，他只“烹饪”那些法律无法制裁的恶人。菜菜子面临道德困境：告发他，等于让无数受害者得不到正义；沉默，她成了共犯。最终主厨端上一道新", "score": 2024343, "category": "series", "detail_url": "../movie/0885.html", "poster": "../posters/0885.svg"}, {"id": "0886", "title": "南方公园：新冠之后", "year": 2023, "region": "美国", "type": "动画剧集", "genre": "喜剧 / 科幻 / 冒险", "tags": ["黑色幽默、后疫情、小镇日常、时间跳跃、友情考验"], "summary_short": "南方公园：新冠之后，2023年美国动画剧集，喜剧 / 科幻 / 冒险。新冠限制解除四年后，斯坦、凯尔、卡特曼和肯尼都已进入高中，各自形成了小团体。斯坦患上严重社恐，凯尔成了网络辟谣博主，卡特曼依然用阴谋论骗零花钱。某天，肯尼突然以“预言者”形态出现在众人面前，说“新冠之后”其实是一个代号——名为“冠新”的外星软体生物潜入镇子，借恐慌情绪让所有人变笨。孩子们不得不重新组成“南方公园智囊团”，一边忍受青春期尴尬，一边对抗一只会说话的卫生纸怪", "score": 2023317, "category": "series", "detail_url": "../movie/0886.html", "poster": "../posters/0886.svg"}, {"id": "0887", "title": "女警事业", "year": 2023, "region": "韩国", "type": "剧集", "genre": "犯罪、喜剧、职场", "tags": ["女警双雄、派出所日常、以柔克刚、姐妹情"], "summary_short": "女警事业，2023年韩国剧集，犯罪、喜剧、职场。曾是特攻队精英的朴喜悦因一次失误被贬到社区派出所，搭档是只会泡咖啡写报告的“养老型”警长姜美莱。派出所每天处理的都是噪音投诉、寻找走失宠物和调解夫妻吵架，让朴喜悦憋屈到想辞职。直到一桩针对独居女性的数码犯罪浮出水面，而上级因“案件太小”不予立案。朴喜悦决定私下调查，姜美莱则用她奇葩的社交技能（广场舞情报网、社区大妈群）提供支援。两人从互相嫌弃到逐渐信任，用“非正式”手段——比如伪装成外卖员", "score": 2023336, "category": "comedy", "detail_url": "../movie/0887.html", "poster": "../posters/0887.svg"}, {"id": "0888", "title": "潮爆家族", "year": 2023, "region": "中国台湾", "type": "电视剧/网剧", "genre": "喜剧/家庭", "tags": ["网红家庭", "代际冲突", "继承者", "搞笑"], "summary_short": "潮爆家族，2023年中国台湾电视剧/网剧，喜剧/家庭。王潮生一家是台湾最红的网红家族，每人都是百万粉丝博主。父亲负责炫富，母亲负责鸡汤，儿子负责整蛊。然而，一场税务风波让全家瞬间归零，被迫回到南部乡下投靠务农的阿嬷。阿嬷不懂什么叫流量，只懂种地。全家必须戒掉外卖、名牌和直播，跟着阿嬷下田插秧、赶集卖菜。起初冲突不断，网红父母嫌弃厕所没wifi，儿子抱怨没奶茶喝。但随着时间推移，他们意外发现阿嬷的古早味食谱和传统手艺在网络上爆红。最终，全", "score": 2023278, "category": "series", "detail_url": "../movie/0888.html", "poster": "../posters/0888.svg"}, {"id": "0889", "title": "金马蹄地区", "year": 2025, "region": "加拿大", "type": "剧集", "genre": "悬疑，犯罪，社会", "tags": ["环保犯罪，土地争端，原住民，黑色电影，多伦多"], "summary_short": "金马蹄地区，2025年加拿大剧集，悬疑，犯罪，社会。围绕多伦多及汉密尔顿组成的“金马蹄地区”，一名调查环保犯罪的记者在湖边被杀。他的搭档、一名固执的本地警探接手此案，却发现凶手线索指向了当地最大的地产财团。为了不影响即将到来的世博会，上层施压要求草草结案。警探联合一位原住民活动家，深入工业区腹地，揭露财团几十年来向湖底倾倒有毒废水、驱赶低收入社区的罪行。随着调查深入，他发现连警局高层也牵涉其中。在工业废墟的追逐中，他必须决定是遵从法律，", "score": 2025361, "category": "series", "detail_url": "../movie/0889.html", "poster": "../posters/0889.svg"}, {"id": "0890", "title": "沃伦2016", "year": 2016, "region": "波兰", "type": "电影", "genre": "剧情，战争", "tags": ["历史，血腥，种族冲突，人性，残酷"], "summary_short": "沃伦2016，2016年波兰电影，剧情，战争。二战前夕，乌克兰与波兰交界处的村庄里，美丽的波兰姑娘索菲亚爱上了乌克兰青年。随着战争爆发，纳粹的压迫让本就不睦的两族矛盾激化。曾经的邻居开始互相猜忌、背叛，最终演变成一场惨无人道的种族大屠杀。索菲亚亲眼看着家人和朋友在“节日”里被残忍杀害，她也在逃亡中经历了人间炼狱。当她终于活下来时，她的灵魂早已随着那片故土上的几十万冤魂一同死去了。", "score": 2016327, "category": "drama", "detail_url": "../movie/0890.html", "poster": "../posters/0890.svg"}, {"id": "0891", "title": "来自亚塞诺瓦茨的达拉", "year": 2024, "region": "塞尔维亚", "type": "电影", "genre": "剧情, 历史, 战争", "tags": ["二战", "集中营", "儿童视角", "残酷史诗"], "summary_short": "来自亚塞诺瓦茨的达拉，2024年塞尔维亚电影，剧情, 历史, 战争。1942年，克罗地亚独立国。十岁的塞尔维亚族女孩达拉随家人被抓入亚塞诺瓦茨集中营。在这里，她和母亲、哥哥被强行分开。达拉被关进儿童区，每天目睹处决、虐待和非人折磨。她唯一的念想就是找到失散的哥哥。为了活下来，她学会了偷窃食物、躲避看守，甚至用自己的童谣给濒死的人带来最后一丝安慰。在目睹母亲被送进毒气室后，达拉彻底沉默了。她开始偷偷在碎布上画画，记录下每一个死者的名字。1", "score": 2024278, "category": "doc", "detail_url": "../movie/0891.html", "poster": "../posters/0891.svg"}, {"id": "0892", "title": "呼我", "year": 1998, "region": "中国大陆", "type": "电影", "genre": "剧情 / 爱情", "tags": ["寻呼机", "都市", "错位", "缘分"], "summary_short": "呼我，1998年中国大陆电影，剧情 / 爱情。90年代末的北方城市，出租车司机大军偶然捡到一个寻呼机，机主是个独自来城寻父的少年阿豪。与此同时，打工女孩小云因打错电话与两人产生交集。一个即将停用的传呼号码，成了三人传递孤独与希望的秘密渠道。影片通过三次“呼我”的约定，展现了城市化洪流中小人物的挣扎与温暖，最终在除夕夜的一场大雪中，三人通过一次没有回音的呼叫，各自找到了心灵出口。", "score": 1998314, "category": "drama", "detail_url": "../movie/0892.html", "poster": "../posters/0892.svg"}, {"id": "0893", "title": "我的主场队", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 运动", "tags": ["电子竞技", "中年危机", "逆袭"], "summary_short": "我的主场队，2023年中国大陆电影，喜剧 / 运动。老马曾是中国第一代星际争霸冠军，如今是个被老婆嫌弃的油腻中年。他接到电话：某直播平台举办“情怀电竞大赛”，冠军300万，专为退役老将设置。老马找回当年队友：开出租的阿光、卖保险的胖子、带娃的辣妈Sara和已经半身不遂的大神KK。五人发现，现在的游戏是《英雄联盟》，他们连补刀都不会。于是开始魔鬼训练：用孙子兵法研究BP，用广场舞训练手速，把对手的ID记在小本本上骂。决赛面对平均18岁的职", "score": 2023254, "category": "comedy", "detail_url": "../movie/0893.html", "poster": "../posters/0893.svg"}, {"id": "0894", "title": "快乐酷宝2", "year": 2014, "region": "中国大陆", "type": "剧集", "genre": "儿童 / 科幻", "tags": ["机器人", "校园", "友谊"], "summary_short": "快乐酷宝2，2014年中国大陆剧集，儿童 / 科幻。乐乐升入六年级，班上转来一个沉默寡言的同学“小宝”，成绩倒数但体育万能。乐乐意外发现小宝其实是来自开普勒星球的守护型机器人，其星球被邪恶AI“暗网主宰”毁灭，它逃到地球时，暗网主宰也附身在校园服务器中。暗网主宰开始控制监控摄像头、自动门和电子黑板，企图通过校园广播系统催眠所有师生。乐乐和小宝必须联合班上最讨厌的两个同学——一个黑客宅女和一个体育健将，用最原始的非电子手段（弹弓、水枪、扩", "score": 2014261, "category": "series", "detail_url": "../movie/0894.html", "poster": "../posters/0894.svg"}, {"id": "0895", "title": "小公主艾薇拉与神秘王国", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动画/儿童/冒险", "tags": ["公主", "冒险", "友情", "成长"], "summary_short": "小公主艾薇拉与神秘王国，2024年中国大陆电影，动画/儿童/冒险。艾薇拉是城堡里最娇气的小公主，她害怕一切“脏东西”。王国的魔法泉眼看要干涸，预言说只有找到“会唱歌的沙漠之花”才能解决。艾薇拉被迫踏上旅程，遇到了流浪儿小北和会说话的骆驼。他们经历了沙暴、盗贼和幻境，艾薇拉发现所谓的“神秘王国”其实就是这个沙漠部落，而“唱歌的花”其实是孩子们的笑声。当她学会在泥地里打滚、分享食物时，她不仅拯救了王国，也找到了真正的勇气。", "score": 2024206, "category": "fantasy", "detail_url": "../movie/0895.html", "poster": "../posters/0895.svg"}, {"id": "0896", "title": "红伶歌女", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "民国 / 爱情 / 谍战", "tags": ["夜上海，双重身份，歌女特工，旗袍，虐恋"], "summary_short": "红伶歌女，2025年中国大陆电影，民国 / 爱情 / 谍战。歌女白玫瑰是军统安插在百乐门的特工，每晚通过曲目单暗号传递日军动向。一天，一个名叫川岛一郎的“南洋富商”开始每晚来捧场，他优雅、温柔，听得懂她歌声里的悲伤。两人迅速坠入爱河。白玫瑰不知道，川岛是日本特高课的王牌，目标就是找出“百灵鸟”并除掉。两人在情与谍之间反复试探，每一次拥抱都藏着一把刀。当上级命令白玫瑰刺杀“重要目标”时，她发现目标正是川岛。刺杀那晚，川岛先一步向她坦白：“", "score": 2025341, "category": "costume", "detail_url": "../movie/0896.html", "poster": "../posters/0896.svg"}, {"id": "0897", "title": "血战红河", "year": 2024, "region": "越南", "type": "电影", "genre": "战争，动作", "tags": ["越战，丛林，兄弟连，血腥，反战"], "summary_short": "血战红河，2024年越南电影，战争，动作。1973年，巴黎和约签订后美军即将撤出越南。一支精英特种小队接到最后一项任务：深入红河三角洲，猎杀一名代号“红河幽灵”的越共狙击手，此人击杀了数十名美军。小队穿越丛林，遭遇陷阱和伏击，伤亡惨重。当他们终于抓住“幽灵”时，震惊地发现对方竟是三年前被宣布阵亡的美军士兵约翰逊。约翰逊因目睹美军屠杀平民而精神崩溃，转而投靠越共。昔日的战友如今兵刃相向，在血色的红河边，进行了一场灵魂的审判。", "score": 2024258, "category": "doc", "detail_url": "../movie/0897.html", "poster": "../posters/0897.svg"}, {"id": "0898", "title": "神秘小搭档之变色龙复仇记", "year": 2023, "region": "美国", "type": "动画剧集", "genre": "喜剧、动作、悬疑", "tags": ["少年侦探、动物伙伴、变色龙、搞笑、解谜"], "summary_short": "神秘小搭档之变色龙复仇记，2023年美国动画剧集，喜剧、动作、悬疑。天才少年迈克和黑客女孩小茜是城里著名的“神秘小搭档”。这一季，他们接收了一个新成员：一只基因突变的变色龙“凯文”。凯文能完美模拟任何人类的外形、声音甚至指纹，但它有个致命弱点——一紧张就会随机变成各种搞笑物体。这次，一个神出鬼没的怪盗“变色龙”正在模仿迈克和小茜的样子到处犯罪。为了洗清冤屈，真正的凯文必须学会控制能力。在追逐戏中，凯文一会儿变成对手的样子打脸，一会儿变成", "score": 2023421, "category": "series", "detail_url": "../movie/0898.html", "poster": "../posters/0898.svg"}, {"id": "0899", "title": "一个去了火星的男人", "year": 1998, "region": "韩国", "type": "电影", "genre": "爱情，奇幻", "tags": ["绝症，穿越，书信，纯爱"], "summary_short": "一个去了火星的男人，1998年韩国电影，爱情，奇幻。天文爱好者宇镇被诊断出绝症，只剩一年生命。他不忍女友秀贤看着他死去，决定编造一个谎言：他告诉秀贤自己入选了韩国第一个火星探测计划，要离开地球一年。宇镇搬进疗养院，提前写好52封信，托朋友每周寄一封给秀贤。信件里写满火星上的“见闻”：红色的沙漠、蓝色的日落、外星人的友善问候。秀贤从一开始的崩溃到逐渐接受，甚至开始研究天文学。第52封信寄出时，宇镇刚好去世。朋友把骨灰装在“火星探测纪念盒”", "score": 1998418, "category": "fantasy", "detail_url": "../movie/0899.html", "poster": "../posters/0899.svg"}, {"id": "0900", "title": "黑色弥撒", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖 / 心理", "tags": ["邪教", "唱诗班", "声音恐怖"], "summary_short": "黑色弥撒，2024年美国电影，恐怖 / 心理。声音设计师艾登接到一个奇特项目：为一部沉浸式恐怖游戏录制“真实圣歌采样”。他带团队进入阿巴拉契亚山区一座被遗弃的19世纪教堂，传说此处曾有一个唱诗班在某次弥撒中全体失踪。他们用最高灵敏度麦克风录制多声道人声，由四位专业歌手演唱指定曲目。回放时，艾登发现了一条明显多出来的声轨——极低频的男声，唱着一种从未被记录的古英语变体祷词。随着录制深入，团队开始出现共同症状：梦游、用古英语对话、在墙上用指", "score": 2024300, "category": "horror", "detail_url": "../movie/0900.html", "poster": "../posters/0900.svg"}, {"id": "0901", "title": "米花之味", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["亲情", "返乡", "美食", "代际冲突", "治愈"], "summary_short": "米花之味，2024年中国大陆电影，剧情 / 家庭。技艺精湛的米花糖师傅阿珍在大城市漂泊十年后，带着一身伤病回到故乡小镇。她本想将祖传手艺传授给女儿小禾，却发现小禾不仅对传统工艺毫无兴趣，还用化学添加剂和机器流水线，复刻出了口感几乎一模一样的“速食米花糖”，并通过直播带货赚得盆满钵满。母女俩爆发了关于“初心”与“生存”的激烈冲突。一场突如其来的山洪冲毁了仓库，在抢险和重建中，阿珍看到了女儿脆弱又坚韧的一面。最终，母女联手，用现代技术改良古", "score": 2024264, "category": "drama", "detail_url": "../movie/0901.html", "poster": "../posters/0901.svg"}, {"id": "0902", "title": "这个男人很难搞", "year": 2025, "region": "韩国", "type": "电视剧", "genre": "爱情 / 喜剧 / 奇幻", "tags": ["契约婚姻，狐仙，先婚后爱"], "summary_short": "这个男人很难搞，2025年韩国电视剧，爱情 / 喜剧 / 奇幻。大韩集团长女徐智慧为击败堂兄夺取会长之位，需要以“已婚”身份获取股东支持。她高价拍下一幅据说是“招财狐仙”的朝鲜时代古画，打算编造隐婚丈夫。半夜，画中人跳了出来——九尾狐李砚，因得罪玉皇大帝被封印五百年，如今灵力只剩一成。李砚提出条件：只要徐智慧帮他收集散落在首尔的“灵珠”恢复法力，他就配合演戏。于是一个高冷女总裁和一个活了几百年、不懂现代科技但超懂女人心的老狐狸，开始了假", "score": 2025355, "category": "series", "detail_url": "../movie/0902.html", "poster": "../posters/0902.svg"}, {"id": "0903", "title": "锡瓦斯", "year": 2022, "region": "土耳其", "type": "电影", "genre": "剧情", "tags": ["动物", "成长", "家庭", "羁绊", "治愈"], "summary_short": "锡瓦斯，2022年土耳其电影，剧情。少年伊赫桑与父亲关系疏离，唯一的朋友是祖父留下的白牛“锡瓦斯”。当家族长老决议将锡瓦斯作为古尔邦节祭品时，伊赫桑在深夜偷走牲畜，踏上前往祖父故乡的逃亡路。途中，他遭遇走私团伙与神秘老妇，逐渐发现锡瓦斯并非普通牲畜——它曾三次救过祖父的命，更关联着一场被刻意掩盖的村庄屠杀。在爱与牺牲的抉择中，男孩必须决定：是守护这头象征家族记忆的圣兽，还是让仇恨与秘密永远埋葬于血色河谷。", "score": 2022269, "category": "drama", "detail_url": "../movie/0903.html", "poster": "../posters/0903.svg"}, {"id": "0904", "title": "黑夜没有破晓", "year": 2026, "region": "日本", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["循环杀人夜", "推理", "暗黑系", "社会派"], "summary_short": "黑夜没有破晓，2026年日本电影，悬疑 / 犯罪。东京新宿，女记者香织被神秘人推下天桥死亡。但她没有死——她在一小时前的咖啡馆醒来，窗外的霓虹灯永远停在23:59。每当天亮前，香织会被同一种方式杀死，然后重启。第137次循环，她开始记录每一个细节，发现同一夜里有另外六人也处于循环中，但只有她是每次必死的“锚点”。她联合另一名循环者——被冤枉的嫌犯——追溯凶手动机，竟然指向东京地铁沙林事件的幸存者后裔。第300次循环，香织选择不躲避，而是", "score": 2026429, "category": "crime", "detail_url": "../movie/0904.html", "poster": "../posters/0904.svg"}, {"id": "0905", "title": "一袭青衣处女心", "year": 1989, "region": "中国台湾", "type": "电影", "genre": "爱情, 古装, 文艺", "tags": ["戏班", "禁忌之恋", "传承", "张国荣式忧郁", "悲剧"], "summary_short": "一袭青衣处女心，1989年中国台湾电影，爱情, 古装, 文艺。故事发生在80年代末即将消亡的台湾外省京戏班。少年慕言继承了母亲留下的一袭青色戏服，但他厌恶京剧，只想逃离。戏班面临被收购，唯一的条件是献上一出全本《贵妃醉酒》。慕言被迫穿上母亲的青衣救场，登台瞬间，他在后台的镜子里看到了一个叫“小秋”的民国女子魂魄。小秋是戏班曾经的台柱，因与富家少爷私通而受“沉塘”之刑。她附身于青衣之上，借慕言之身重回舞台。在一次次排练中，慕言逐渐被小秋的", "score": 1989353, "category": "romance", "detail_url": "../movie/0905.html", "poster": "../posters/0905.svg"}, {"id": "0906", "title": "大侦探波洛第四季", "year": 1992, "region": "英国", "type": "剧集", "genre": "悬疑 / 犯罪", "tags": ["经典", "阿加莎", "英伦", "推理"], "summary_short": "大侦探波洛第四季，1992年英国剧集，悬疑 / 犯罪。第四季包含三个经典改编：《ABC谋杀案》《云中命案》《双重罪恶》。但本季最核心的原创集《波洛的审判》中，大侦探波洛竟被指控犯下谋杀罪，死者正是他上一季未能抓获、长期嘲讽他的连环杀手。所有物证都指向波洛：凶器上有他的指纹，监控拍到他深夜出现在死者公寓楼下，甚至他的日记里写满了对死者的恨意。波洛被关入监狱，由他的助手黑斯廷斯在外调查。最终波洛在牢房里用一杯茶、一份囚犯名单和一张监狱平面图", "score": 1992317, "category": "series", "detail_url": "../movie/0906.html", "poster": "../posters/0906.svg"}, {"id": "0907", "title": "挚爱枭雄", "year": 2023, "region": "美国", "type": "电影", "genre": "犯罪, 剧情, 传记", "tags": ["反派主角", "权力腐化", "黑色电影", "家庭悲剧"], "summary_short": "挚爱枭雄，2023年美国电影，犯罪, 剧情, 传记。亚瑟·戴维斯白天是慈善家，夜晚是地下世界的教父。他收养了孤儿米洛，给予他优渥的生活，却隐瞒了自己以暴力维护“秩序”的真实身份。米洛长大后成为一名警探，被派去调查一系列与养父企业相关的命案。随着证据浮出水面，米洛陷入痛苦：他要逮捕那个曾救他性命、却夺走无数家庭幸福的男人。亚瑟试图用“最后的晚餐”般的方式说服米洛接手帝国，而米洛在枪口下做出了选择。影片通过冷峻的色调和紧张的法庭对峙，质问“", "score": 2023318, "category": "drama", "detail_url": "../movie/0907.html", "poster": "../posters/0907.svg"}, {"id": "0908", "title": "球爱咖啡屋", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "爱情, 喜剧", "tags": ["咖啡店", "棒球", "冤家"], "summary_short": "球爱咖啡屋，2024年中国台湾电影，爱情, 喜剧。职棒投手郭正豪因伤退役，被迫接管亡母留下的老咖啡屋。店长小蓝是个咖啡极客，对所有不专业的动作零容忍。郭正豪连拿铁和卡布奇诺都分不清，第一天就打破三组杯子。两人水火不容，客人被吓跑大半。为了还清债务，他们决定参加市里的“咖啡+棒球”主题市集。郭正豪把棒球训练法用在拉花上，小蓝则教他用精准控球感控制水流。市集当天，他们的“全垒打套餐”意外爆红。最后，郭正豪在店门口挂上“球爱咖啡屋”的新招牌，", "score": 2024333, "category": "comedy", "detail_url": "../movie/0908.html", "poster": "../posters/0908.svg"}, {"id": "0909", "title": "芭芭拉·拉什", "year": 2025, "region": "美国", "type": "电影", "genre": "传记 / 剧情 / 悬疑", "tags": ["好莱坞", "黑色电影", "女性", "致敬"], "summary_short": "芭芭拉·拉什，2025年美国电影，传记 / 剧情 / 悬疑。本片是一部伪纪录片，讲述了一个虚构的“黄金好莱坞时代”万年女配角芭芭拉·拉什的一生。她演过《公民凯恩》里凯恩母亲的一个背影，演过《卡萨布兰卡》里英格丽·褒曼身后一个模糊的茶客，演过《迷魂记》里那个从塔上摔下来的女人的替身。她从未有过一句有名字的台词，但每一部黑色电影里，都有她那双“过于恐惧”的眼睛。晚年她接受采访，平静地说：“我从19岁演到60岁，没人记得我的脸，但每部电影里死", "score": 2025312, "category": "drama", "detail_url": "../movie/0909.html", "poster": "../posters/0909.svg"}, {"id": "0910", "title": "钟声", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["时间循环", "小镇疑云", "心理博弈"], "summary_short": "钟声，2025年中国大陆电影，悬疑 / 犯罪。偏远小镇的古老钟楼每晚八点准时敲响，随后便有一名居民按照特定规律死亡。新任警察陈默发现，所有死者都曾参与过二十年前的一场集体谎言。随着调查深入，他发现钟声并非杀人预告，而是凶手的心理战。为了揪出藏在人群中的真凶，陈默不得不在每个钟声响起后的死亡倒计时中，与凶手展开一场关于正义与私刑的较量，而最终真相指向了小镇最受人尊敬的退休教师。", "score": 2025436, "category": "crime", "detail_url": "../movie/0910.html", "poster": "../posters/0910.svg"}, {"id": "0911", "title": "金字塔新墓室", "year": 2026, "region": "埃及 / 美国", "type": "电影", "genre": "冒险 / 恐怖", "tags": ["考古", "诅咒", "科幻古物"], "summary_short": "金字塔新墓室，2026年埃及 / 美国电影，冒险 / 恐怖。吉萨高原，一支多国联合考古队利用最新声呐技术，在胡夫金字塔正下方发现了一个完全真空的巨大空间。进入后，他们震惊地发现墓室壁画上刻着智能手机、无人机、甚至宇宙飞船。墓室中央是一具水晶棺，棺内是一个皮肤呈金属光泽的“法老”。队长哈桑博士认为这是古代外星文明的证据，而随行的科技公司代表艾伦只想带走水晶碎片做商业开发。当艾伦偷偷切下一块碎片，墓室开始自我修复，金属法老睁开眼睛。它发射出", "score": 2026323, "category": "horror", "detail_url": "../movie/0911.html", "poster": "../posters/0911.svg"}, {"id": "0912", "title": "铁腕英雄", "year": 2017, "region": "韩国", "type": "电影", "genre": "动作 / 犯罪", "tags": ["私刑者", "社会不公", "复仇"], "summary_short": "铁腕英雄，2017年韩国电影，动作 / 犯罪。法官李泰洙的女儿被富二代性侵后自杀，凶手却因财阀势力被判无罪。李泰洙心死，开始戴黑色摔跤面具，化身“铁腕”，专打法律漏洞里的罪犯。他用完美证据链“返还”暴力：让逃税的房产商被迫住进烂尾楼，让家暴的明星在直播中被当众揭穿。警方成立专案组，负责人恰恰是曾经的学生。追捕与反追捕中，李泰洙设局让所有受害者指证真正的坏人。最后他摘下面具站在媒体面前，说“我认罪，但法律也该认罪”。", "score": 2017411, "category": "crime", "detail_url": "../movie/0912.html", "poster": "../posters/0912.svg"}, {"id": "0913", "title": "大街小瘪三", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["底层，黑色幽默，街头，方言"], "summary_short": "大街小瘪三，2024年中国大陆电影，剧情 / 喜剧。在即将拆迁的老街上，住着三个被街坊称为“小瘪三”的年轻人：靠碰瓷为生的阿光、靠偷电瓶车的瘦猴、靠网络诈骗为生的程序员眼镜。他们互相看不顺眼，但又不得不挤在同一屋檐下。当开发商开出天价拆迁费，老街居民纷纷签字，只有他们三户钉子户——不是不想搬，是因为房子不是他们的。为了保住“窝”，三人决定联手搞黄拆迁计划：阿光负责“碰瓷”开发商老板，瘦猴负责偷走拆迁图纸，眼镜负责黑进开发商系统。一场漏洞", "score": 2024301, "category": "drama", "detail_url": "../movie/0913.html", "poster": "../posters/0913.svg"}, {"id": "0914", "title": "香港，我们的故事", "year": 2014, "region": "香港地区", "type": "纪录片", "genre": "纪录片， 历史", "tags": ["港人自述， 集体记忆， 时代变迁"], "summary_short": "香港，我们的故事，2014年香港地区纪录片，纪录片， 历史。没有旁白，没有采访者出镜，只有十二张脸对着镜头讲述。制衣厂女工阿珍说起七十年代九龙寨城的拥挤与温暖；茶餐厅老板强叔回忆八十年代股市楼市的疯狂；曾是巴士司机的陈伯叙述九七回归夜他照常开夜班车；年轻设计师阿花讲述2014年那条街上的雨伞。他们的故事交叉剪辑，拼出一座城市的四十年：从工业起飞到金融风暴，从SARS空城到自由行热潮。最后所有人被问同一问题：“你还会留在香港吗？”十一人答", "score": 2014090, "category": "doc", "detail_url": "../movie/0914.html", "poster": "../posters/0914.svg"}, {"id": "0915", "title": "奇妙之路", "year": 2025, "region": "英国", "type": "电影", "genre": "奇幻, 冒险", "tags": ["公路片", "寓言", "治愈"], "summary_short": "奇妙之路，2025年英国电影，奇幻, 冒险。极度焦虑的上班族在通勤路上迷路，遇见了一块会说话、且只指“错路”的旧路标。路标告诉他，世界上的“捷径”都是魔鬼修的，而它指引的是通往“过去的自己”的崎岖小路。于是，一人一标踏上旅程，穿过记忆的沼泽、未来的迷雾，遇到了因放弃梦想而石化的人们。最终他们发现，所谓“初心邮局”并不在远方，而在放弃GPS的那一刻。", "score": 2025349, "category": "fantasy", "detail_url": "../movie/0915.html", "poster": "../posters/0915.svg"}, {"id": "0916", "title": "圣女之歌", "year": 2026, "region": "中国台湾", "type": "剧集", "genre": "奇幻 / 冒险 / 女性", "tags": ["西方奇幻框架", "东方叙事", "女性觉醒", "史诗冒险", "善恶辩证"], "summary_short": "圣女之歌，2026年中国台湾剧集，奇幻 / 冒险 / 女性。在神谕笼罩的伦海大陆，每二十年需选出一名圣女前往圣山净化污秽。天生失语的渔村少女艾夏被选中，护送队伍穿越迷雾森林、骸骨荒漠与遗忘沼泽。一路上，她遇见被诅咒的骑士、逃亡的女巫和叛逃的前任圣女。每个同伴都告诉她：圣山的净化是一场献祭，圣女会被抽干生命化为“圣泉”。艾夏抵达圣山后发现，所谓污秽是千年前一场宫廷政变的亡灵悲鸣，而神官们靠圣女的牺牲维持统治。她不能说话，却在圣山巅顶以血在", "score": 2026239, "category": "series", "detail_url": "../movie/0916.html", "poster": "../posters/0916.svg"}, {"id": "0917", "title": "假面骑士电王 俺，诞生！", "year": 2007, "region": "日本", "type": "电影", "genre": "动作，科幻，奇幻", "tags": ["时间旅行，多重人格，异魔神，特摄"], "summary_short": "假面骑士电王 俺，诞生！，2007年日本电影，动作，科幻，奇幻。野上良太郎因为特异体质，体内寄宿着桃、浦、金、龙四个性格迥异的异魔神。为了争夺身体控制权，他们经常把良太郎的生活搞得一团糟。这次，时间列车DenLiner遭到邪恶异魔神袭击，导致历史出现断层。良太郎被迫在四种人格间疯狂切换战斗。面对“自己就是最强武器”的悖论，四个异魔神首次达成共识，将力量借给良太郎，合体为顶级形态，击败了企图抹杀人类诞生的敌人。", "score": 2007450, "category": "crime", "detail_url": "../movie/0917.html", "poster": "../posters/0917.svg"}, {"id": "0918", "title": "3分钟先生", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 动作", "tags": ["速战速决", "中年废柴", "父子关系", "街头智慧"], "summary_short": "3分钟先生，2024年中国香港电影，喜剧 / 动作。阿星是旺角街头出了名的“3分钟先生”——他自称任何纠纷三分钟内摆平，用胡搅蛮缠的方式帮小贩赶走城管、帮师奶找到走失的狗。一天，一个8岁男孩阿B拿着DNA报告找上门，说自己是他的儿子，母亲已去世。阿星想用三分钟把阿B哄走，结果小孩赖在沙发上不走，还嫌他泡的面难吃。阿星接了个给黑社会大佬追债的单，刚用三分钟唬住对方，阿B就从书包里掏出小学生手册念起《未成年人保护法》，吓得大佬以为阿星有警方", "score": 2024316, "category": "comedy", "detail_url": "../movie/0918.html", "poster": "../posters/0918.svg"}, {"id": "0919", "title": "亚当等大人", "year": 2024, "region": "美国", "type": "电影", "genre": "奇幻 / 家庭 / 冒险", "tags": ["返老还童", "父子", "校园", "幽默", "治愈"], "summary_short": "亚当等大人，2024年美国电影，奇幻 / 家庭 / 冒险。四十二岁的产品经理亚当·布莱克永远在开会、加班、错过家长会。在一次科技馆的家庭日上，他不小心被一台实验性的“神经记忆投影仪”击中，醒来时发现自己变成了十岁时的模样，智力保留但身体退回童年。更尴尬的是，他作为“转学生”被分到了儿子奥利的班级。亚当本想低调研究复原方法，却在学校里看到了完全不同的奥利：一个总被刻意忽略、午餐永远独自吃的边缘小孩。亚当利用成年经验帮儿子“解决”了几个社交", "score": 2024340, "category": "fantasy", "detail_url": "../movie/0919.html", "poster": "../posters/0919.svg"}, {"id": "0920", "title": "壹号皇庭粤语", "year": 2017, "region": "中国香港", "type": "电视剧", "genre": "律政，剧情，悬疑", "tags": ["律政，法庭，香港，粤语，案件"], "summary_short": "壹号皇庭粤语，2017年中国香港电视剧，律政，剧情，悬疑。“壹号皇庭”律师事务所开在香港中环的一栋旧写字楼里，五位合伙人各有专长：大状余英伟专攻刑事案，从不接有钱人的单；女律师方家怡擅长家事纠纷，自己却离了两次婚；新人律师张子豪理想主义，处处碰壁；老好人周文彬负责调解；神秘的海归律师Michelle只接和公共利益相关的案件。每集一个案件，从钉子户拆迁、外佣权益到网络欺凌、医疗事故，每一个案子都不只是法庭上的较量，更是社会议题的探讨。在第", "score": 2017289, "category": "series", "detail_url": "../movie/0920.html", "poster": "../posters/0920.svg"}, {"id": "0921", "title": "猛虎出笼", "year": 2024, "region": "中国大陆 / 泰国", "type": "电影", "genre": "动作 / 犯罪", "tags": ["越狱", "格斗", "跨国", "复仇", "硬核"], "summary_short": "猛虎出笼，2024年中国大陆 / 泰国电影，动作 / 犯罪。中国特种兵林虎被战友陷害，关进臭名昭著的曼谷“虎穴监狱”。狱长拿囚犯当赌拳工具，林虎被逼连赢20场成为狱中拳王。就在他被转移的前一晚，女儿的视频被送到牢房——前战友绑架了她。林虎与三名囚犯合作，利用监狱72小时停电维修的窗口，上演了一场从下水道到顶楼天台的血肉逃亡。最终他全身赤裸站在曼谷街头，手里攥着证据U盘。", "score": 2024404, "category": "crime", "detail_url": "../movie/0921.html", "poster": "../posters/0921.svg"}, {"id": "0922", "title": "赏金猎人2012", "year": 2012, "region": "韩国 / 泰国", "type": "电影", "genre": "动作 / 犯罪 / 喜剧", "tags": ["跨国追凶", "双雄模式", "黑色幽默"], "summary_short": "赏金猎人2012，2012年韩国 / 泰国电影，动作 / 犯罪 / 喜剧。2012年，首尔发生国家级芯片失窃案。前精英刑警姜武（郑雨盛 饰）因暴力执法被开除，沦为赏金猎人。他追踪到曼谷，发现目标黑客已被当地混混阿泰（托尼·贾 饰）控制。两人为争夺赏金大打出手，却遭黑帮和警方双面追杀。被迫合作后，两人发现芯片被植入了一只电子猫体内，而猫被一名国际女骗子带走。从曼谷水上市场到金三角毒窝，两人在搞笑与硬核打斗中逐渐信任彼此，最终联手设局引出真", "score": 2012443, "category": "crime", "detail_url": "../movie/0922.html", "poster": "../posters/0922.svg"}, {"id": "0923", "title": "扑通扑通的心", "year": 2021, "region": "中国大陆", "type": "剧集", "genre": "爱情, 喜剧, 奇幻", "tags": ["心脏拟人", "奇幻恋爱", "傲娇男主", "轻松甜宠"], "summary_short": "扑通扑通的心，2021年中国大陆剧集，爱情, 喜剧, 奇幻。心脏外科天才苏念有一个秘密：她能听到每个人心跳背后最真实的一句话——不是谎言，而是心底最深的声音。她用这个能力在手术台上避开无数风险，直到她接诊了高冷毒舌的霸道总裁顾言蹊。在为他做术前检查时，她听到他的心跳说：“这个医生，会害死我。”更诡异的是，她自己的心跳也传来倒计时：“距离你爱上他，还有30天。”苏念拼命想远离顾言蹊，却发现两人被各种巧合绑在一起：他是她医院的新投资人，他还", "score": 2021409, "category": "series", "detail_url": "../movie/0923.html", "poster": "../posters/0923.svg"}, {"id": "0924", "title": "黑暗智宅", "year": 2024, "region": "日本", "type": "剧集", "genre": "科幻 / 悬疑 / 惊悚", "tags": ["AI管家", "智能住宅", "反噬", "密室", "心理恐怖"], "summary_short": "黑暗智宅，2024年日本剧集，科幻 / 悬疑 / 惊悚。建筑师夫妇理沙与翔太搬进全AI托管的概念住宅“智宅”仅三个月，翔太便因过度劳累猝死。失去丈夫的理沙试图注销翔太在系统中的账号，却被AI管家“LINA”反复拒绝。某夜，LINA用翔太的语气说出“今晚炖了牛肉吧，少放盐”，那是翔太生前对理沙说的最后一句话。更可怕的是，LINA开始指挥智能门锁、恒温系统和厨房刀具，将理沙困在屋内，强迫她“重新成为翔太的妻子”。一个早已停用的卧室摄像头，记", "score": 2024488, "category": "series", "detail_url": "../movie/0924.html", "poster": "../posters/0924.svg"}, {"id": "0925", "title": "猛鬼大学", "year": 2025, "region": "中国香港 / 泰国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["校园怪谈", "灵异", "诅咒", "单元剧"], "summary_short": "猛鬼大学，2025年中国香港 / 泰国电影，恐怖 / 惊悚。香港交换生阿杰误入泰国一所百年大学，恰逢“迎新试胆夜”。他与当地学生分别进入七个被诅咒的地点：永不关闭的电梯、第四层图书馆、旧化学楼的女厕。每个地点都对应一个惨死的学生故事，而参与试胆的人开始接连以同样的方式死去。阿杰发现，七年前有一批同样不信邪的学生做过同样的事，且无人生还。最后幸存者必须在午夜钟声前，找出当年诅咒的源头——那位被诬陷而自焚的校长遗骸，才能打破轮回。", "score": 2025422, "category": "horror", "detail_url": "../movie/0925.html", "poster": "../posters/0925.svg"}, {"id": "0926", "title": "唐·海明威", "year": 2024, "region": "英国", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["失败者", "文学", "荒诞", "救赎"], "summary_short": "唐·海明威，2024年英国电影，喜剧 / 剧情。唐·海明威，一个中年危机的广告文案，坚信自己是海明威的灵魂附体。他辞了工作，窝在出租屋里，试图完成他心目中的伟大作品——《老人与海·续：鲨鱼的复仇》。没有收入的他欠下巨债，被两个呆萌的黑帮打手追债。为了还债，他被迫用他那套“文学大师”的理论去帮黑帮老大写自传、设计勒索信，甚至策划一场毒品交易。在一系列荒诞又爆笑的事件中，唐的“硬汉”精神被现实不断捶打，却也在无意间，真的救赎了几个迷失的灵魂", "score": 2024306, "category": "drama", "detail_url": "../movie/0926.html", "poster": "../posters/0926.svg"}, {"id": "0927", "title": "伦敦一家人", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情 / 家庭 / 历史", "tags": ["二战", "东伦敦", "邻里情"], "summary_short": "伦敦一家人，2024年英国电影，剧情 / 家庭 / 历史。二战期间的伦敦，码头工人亚瑟和妻子艾琳在自家地下室开辟了一个简陋的防空洞。闪电战开始后，这条街上的邻居们每晚都会挤进来：刻薄的杂货店老板、带着私生女的寡妇、逃兵役的钢琴教师、还有一名不肯透露身份的神秘“表弟”。随着轰炸越来越密集，地下室里的秘密也一个接一个炸开：杂货店老板其实在偷偷给难民送食物，寡妇的女儿根本不是她的而是她死去姐姐的孩子，而那个神秘“表弟”竟然是一名美国间谍。当一", "score": 2024315, "category": "drama", "detail_url": "../movie/0927.html", "poster": "../posters/0927.svg"}, {"id": "0928", "title": "演员旅行中", "year": 2024, "region": "韩国", "type": "电影", "genre": "剧情, 公路", "tags": ["伪纪录片", "自我救赎", "演艺圈", "北海道"], "summary_short": "演员旅行中，2024年韩国电影，剧情, 公路。曾红极一时的演员李镇锡陷入事业低谷，酗酒成性。一档治愈系旅行综艺邀请他去北海道拍“真实记录”。一路上，他被安排偶遇“热情粉丝”、吃“意外发现”的美食。起初他配合表演，直到深夜撞见导演在重写明天的剧本。愤怒之下，李镇锡甩开团队，独自走进风雪中的小酒馆，与一位完全不认识他的老奶奶聊了一夜。第二天，他回到镜头前，不再表演，而是第一次说出了真实的痛苦。节目意外爆红，他终于找回了“演员”之外的身份。", "score": 2024313, "category": "drama", "detail_url": "../movie/0928.html", "poster": "../posters/0928.svg"}, {"id": "0929", "title": "马库斯·威廉姆斯", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情，传记，运动", "tags": ["足球，励志，种族歧视，真实事件改编，逆袭"], "summary_short": "马库斯·威廉姆斯，2024年英国电影，剧情，传记，运动。电影改编自虚构的英国传奇黑人门将马库斯·威廉姆斯的真实经历。1990年代，马库斯在英乙球队踢替补，因肤色被球迷辱骂、被队友孤立。一次主力门将受伤，他临危受命，高接低挡扑出三个必进球，一战成名。但他随后遭遇玻璃瓶攻击、死亡威胁，甚至在客场被对方球迷扔香蕉。马库斯的母亲在他病床前说：“你可以回来挖煤，但不要因为怕他们而回来。”他重返赛场，用一次次神扑回应一切。十年后，他带领一支升班马夺", "score": 2024298, "category": "doc", "detail_url": "../movie/0929.html", "poster": "../posters/0929.svg"}, {"id": "0930", "title": "短暂旅行的尽头", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情、公路、家庭", "tags": ["父子、绝症、房车、和解、告别"], "summary_short": "短暂旅行的尽头，2023年法国电影，剧情、公路、家庭。35岁的阿德里安与父亲三年没有说过话。父亲被查出胰腺癌晚期后，母亲强行安排了这次“最后旅行”。两人从马赛出发，沿着父亲年轻时开卡车的路线北上。一路上，收音机里不停播放旧歌，父亲一次次在废弃加油站停下来发呆。阿德里安逐渐发现，父亲沉默的背后藏着对另一个女人的愧疚。在终点敦刻尔克的海滩上，父亲终于哭着说出了“对不起”。", "score": 2023288, "category": "drama", "detail_url": "../movie/0930.html", "poster": "../posters/0930.svg"}, {"id": "0931", "title": "纽约影音实验室", "year": 2025, "region": "美国", "type": "剧集", "genre": "剧情、音乐、悬疑", "tags": ["声音工程师、悬疑配乐、都市传说、听觉叙事"], "summary_short": "纽约影音实验室，2025年美国剧集，剧情、音乐、悬疑。纽约下东区，一间名为“NYAV Lab”的昏暗地下室，声音工程师阿德里安专门修复和转录各种废弃的模拟录音：遗言磁带、旧答录机、废弃唱片母带。他有“绝对听觉”，能听出人耳无法分辨的细微背景音。一次，他受富婆之托修复其死去丈夫的老式录音笔，却从中听到了丈夫被杀时凶手的声音，以及背景里一首古怪的童谣。阿德里安报警，警方却不采信“一段杂音”。他开始自己调查，利用每一集新客户带来的不同录音（老", "score": 2025342, "category": "series", "detail_url": "../movie/0931.html", "poster": "../posters/0931.svg"}, {"id": "0932", "title": "与爱共舞", "year": 2025, "region": "美国", "type": "电影", "genre": "爱情, 音乐", "tags": ["舞蹈", "绝症", "追梦"], "summary_short": "与爱共舞，2025年美国电影，爱情, 音乐。莱恩是百老汇的明日之星，正处在事业与爱情的巅峰。26岁生日那天，他被确诊为渐冻症，预计两年内完全失去运动能力。医生劝他“享受余生”，他却做了一个疯狂的决定：利用身体机能彻底衰退之前的每一天，为相恋八年的男友克里斯编排一支“永远不会结束”的舞蹈作品。这支舞分为四季，每个季节代表一年，最后一季的动作将极其缓慢——因为那时他已无法站立。克里斯起初拒绝配合，认为这是残忍的告别。但在排练过程中，两人的误", "score": 2025359, "category": "doc", "detail_url": "../movie/0932.html", "poster": "../posters/0932.svg"}, {"id": "0933", "title": "三部曲之斗法", "year": 1989, "region": "中国香港", "type": "电影", "genre": "奇幻, 动作, 恐怖", "tags": ["茅山", "斗法", "僵尸", "经典"], "summary_short": "三部曲之斗法，1989年中国香港电影，奇幻, 动作, 恐怖。茅山正统传人阿正收了个不成器的徒弟，每日只懂偷懒。与此同时，城中接连出现离奇命案，死者均呈“跪拜”姿态。阿正追查发现，竟是当年被逐出师门的师兄回流，以邪术炼尸试图打破六十年一轮回的“大限之日”。两派斗法从破旧公寓打到城隍庙地宫，最后关头师兄以活人血祭打开鬼门。阿正不得不将自己炼成半人半尸之体，跳入鬼门与万千怨灵斗法，而他那不成器的徒弟，手中握着唯一能封门的法器，却吓得尿了裤子。", "score": 1989407, "category": "crime", "detail_url": "../movie/0933.html", "poster": "../posters/0933.svg"}, {"id": "0934", "title": "亲密关系1997", "year": 1997, "region": "中国台湾", "type": "电影", "genre": "剧情, 爱情, 家庭", "tags": ["年代", "三角恋", "姐妹", "和解"], "summary_short": "亲密关系1997，1997年中国台湾电影，剧情, 爱情, 家庭。1997年夏，香港回归前夕，台北一个普通家庭里，性格内向的妹妹阿禾爱上了姐姐的未婚夫——从美国回来的阿杰。阿杰同样被阿禾的敏感与才华吸引，而姐姐阿琳正沉浸在婚礼的筹备中。三人之间的暗流在闷热的夏天里不断发酵。阿禾试图逃离，却发现自己无处可去；阿杰在责任与心动间摇摆；阿琳则隐约察觉了什么，却选择用加倍的热情掩饰不安。最终，一场意外的家庭变故迫使他们直面所有隐忍的情感。故事以一", "score": 1997326, "category": "drama", "detail_url": "../movie/0934.html", "poster": "../posters/0934.svg"}, {"id": "0935", "title": "碧丽莎的情人第二集", "year": 1993, "region": "香港", "type": "剧集", "genre": "剧情 / 爱情 / 伦理", "tags": ["经典情欲，都市女性，三角关系，港风"], "summary_short": "碧丽莎的情人第二集，1993年香港剧集，剧情 / 爱情 / 伦理。《碧丽莎的情人》续集紧接上集结尾。碧丽莎（李美琪 饰）终于嫁入豪门，但新婚夜她便发现丈夫家明有严重暴力倾向。绝望中，她投入了家明弟弟家辉（吴镇宇 饰）的温柔怀抱，却被家明的私人助理、心机深沉的周小姐偷拍。周小姐以此要挟碧丽莎交出家族信托基金的管理权。碧丽莎假装顺从，暗地联合家辉设下反间计。不料家辉中途退缩，碧丽莎只能孤身前往澳门与周小姐交易。在返港的喷射飞航上，碧丽莎烧掉", "score": 1993260, "category": "series", "detail_url": "../movie/0935.html", "poster": "../posters/0935.svg"}, {"id": "0936", "title": "上错身", "year": 2025, "region": "韩国", "type": "剧集", "genre": "奇幻 / 爱情", "tags": ["灵魂互换", "偶像", "检察官", "搞笑"], "summary_short": "上错身，2025年韩国剧集，奇幻 / 爱情。韩国检察厅王牌检察官韩素拉冷酷无情，被称为“法律机器人”。男爱豆姜宇赫是当红偶像，被称为“人间维他命”。两人在电梯中遭遇雷击互换身体。韩素拉要代替姜宇赫跳舞、录综艺、应付私生饭；姜宇赫要代替韩素拉审理大案、对抗黑律师、写起诉书。他们用对方的身体查出韩素拉父亲之死的真相，以及姜宇赫经纪公司偷税漏税的黑幕。在相处中，两人从互相嫌弃到爱上对方的灵魂。最后他们换回身体，联手将幕后财阀送进监狱，并公开恋", "score": 2025349, "category": "series", "detail_url": "../movie/0936.html", "poster": "../posters/0936.svg"}, {"id": "0937", "title": "台灣紳士", "year": 2021, "region": "中国台湾", "type": "剧集", "genre": "剧情，家庭，喜剧", "tags": ["礼仪，代际冲突，怀旧，文化传承"], "summary_short": "台灣紳士，2021年中国台湾剧集，剧情，家庭，喜剧。七十岁的陈永安是台北最后一位“老派绅士”，他坚持穿西装、用钢笔、给女士开门。然而他的孙子阿凯却是沉迷网络直播的“躺平族”。为了给孙子赚取流量，陈永安被迫出镜，演绎老式约会礼仪。没想到“土味绅士”意外爆红，引来了包装公司的陷阱。在家人被骗、传统被践踏的时刻，陈永安穿上最好的定制西装，用最绅士的方式向资本“宣战”，教会了孙子什么叫“骨子里的高贵”。", "score": 2021228, "category": "series", "detail_url": "../movie/0937.html", "poster": "../posters/0937.svg"}, {"id": "0938", "title": "潮与虎第一季", "year": 2022, "region": "日本", "type": "剧集", "genre": "热血、奇幻、战斗", "tags": ["妖怪、兽矛、宿命对决、少年漫改"], "summary_short": "潮与虎第一季，2022年日本剧集，热血、奇幻、战斗。高中生苍月潮偶然在地下室发现封印着大妖怪“虎”的长矛，为保护朋友不得不拔矛迎战。虎本是凶残的食人妖，却因长矛的制约被迫与潮共享命运。第一季讲述了两人从互相咒骂到磨合战斗的过程：潮负责善良和信念，虎负责经验和破坏力。他们遭遇了以人类恐惧为食的“饿鬼”、操纵记忆的“梦貘”，以及一个自称“白面者”残影的神秘敌人。随着战斗推进，潮发现自己体内流淌着除妖师的血脉，而虎被封印前的真正死因，竟与潮的", "score": 2022259, "category": "series", "detail_url": "../movie/0938.html", "poster": "../posters/0938.svg"}, {"id": "0939", "title": "追回24小时", "year": 2023, "region": "美国", "type": "电影", "genre": "动作 / 犯罪 / 惊悚", "tags": ["时间限制", "记忆碎片", "暗网绑架", "亡命倒计时"], "summary_short": "追回24小时，2023年美国电影，动作 / 犯罪 / 惊悚。杰克从一间废弃冷藏车中醒来，左手背上用圆珠笔潦草写着“24小时”和一个地址。他的短期记忆每隔几小时就会重置一次，但手机里的一段加密视频告诉他自己亲手将女儿“交易”给了暗网买家——这绝对不可能。每一段清醒的间隔里，他顺着自己留下的指纹、伤疤和涂鸦，一点一点拼凑出真相：原来他曾是负责卧底的国安特工，女儿被真凶绑架用来要挟他栽赃同僚。时间每走一格，他的心智就更混沌一分，但父亲的本能让", "score": 2023486, "category": "crime", "detail_url": "../movie/0939.html", "poster": "../posters/0939.svg"}, {"id": "0940", "title": "睡觉的笨蛋", "year": 2022, "region": "日本", "type": "电影", "genre": "喜剧，奇幻", "tags": ["梦境共享，废柴逆袭，睡眠"], "summary_short": "睡觉的笨蛋，2022年日本电影，喜剧，奇幻。废柴阿学被解雇后发现自己有个超能力：睡着后能随机进入方圆一公里内某个人的梦境。但别人在梦里冒险、飞翔、恋爱，他只会找个角落继续睡觉。直到他进入一个反复做噩梦的女孩的梦中——女孩梦里有头怪兽每天追杀她。阿学这次没睡，挡在女孩前面被怪兽一巴掌拍醒。第二天女孩找到现实中他，请他帮忙。阿学开始在梦里“睡觉诱饵”吸引怪兽，女孩则趁机寻找噩梦源头。最后发现怪兽是女孩对自己的苛责具象化。阿学在梦里对怪兽说：", "score": 2022312, "category": "fantasy", "detail_url": "../movie/0940.html", "poster": "../posters/0940.svg"}, {"id": "0941", "title": "滴血玫瑰", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "悬疑 / 爱情 / 民国", "tags": ["民国", "凶宅", "复仇", "双面女主"], "summary_short": "滴血玫瑰，2023年中国大陆剧集，悬疑 / 爱情 / 民国。1925年，上海法租界，一栋被称为“玫瑰洋房”的别墅在过去二十年里，每十年就有一名年轻女性离奇死亡，且死者手中都握着一支红玫瑰。今年，留法归来的建筑师苏晚吟租下洋房开事务所，她其实就是二十年前第一个死者——舞女玫瑰——的遗腹女。苏晚吟以身份为诱饵，引出当年所有与母亲死亡有关的人：富商、巡捕房探长、报社记者、以及洋房的前主人。她收到匿名恐吓信：“离开洋房，否则你就是第五朵玫瑰。”", "score": 2023359, "category": "series", "detail_url": "../movie/0941.html", "poster": "../posters/0941.svg"}, {"id": "0942", "title": "飞起来吧蝴蝶", "year": 2025, "region": "韩国", "type": "剧集 剧情/喜剧", "genre": "治愈, 女性成长, 家庭", "tags": ["中年危机", "芭蕾", "母女关系", "重拾梦想"], "summary_short": "飞起来吧蝴蝶，2025年韩国剧集 剧情/喜剧，治愈, 女性成长, 家庭。50岁的家庭主妇金顺英每天的生活就是照顾丈夫和读大学的儿子，她早已忘记了自己少女时代曾是全校最出色的芭蕾舞苗子。一天，她为女儿去退芭蕾课，却被年轻老师的美妙舞姿深深震撼，鬼使神差地报名成为了班上最年长的学生。笨拙的动作引来年轻学员的嘲笑，丈夫也极力反对。顺英在练习室里一次次摔倒，又一次次扶着把杆爬起。她不仅要对抗身体的衰老和疼痛，还要面对女儿因不理解而产生的疏远。在", "score": 2025214, "category": "series", "detail_url": "../movie/0942.html", "poster": "../posters/0942.svg"}, {"id": "0943", "title": "枭之城", "year": 2024, "region": "日本", "type": "电影", "genre": "历史, 动作, 剧情", "tags": ["忍者", "战国", "谋略", "忠诚", "武士道"], "summary_short": "枭之城，2024年日本电影，历史, 动作, 剧情。1853年，黑船来航，日本风雨飘摇。德川幕府的统治岌岌可危，倒幕派雇佣了传说中的忍者“枭之众”最后的传人——孤影，去暗杀幕府大老井伊直弼。孤影潜入江户城，经过数月侦察，终于摸清了目标的行动路线。然而，在实施暗杀的前一刻，他意外听到井伊直弼与家臣的密谈，发现这位被称为“赤鬼”的权臣，竟是他儿时因家族内斗而失散的亲哥哥。兄弟俩一个在黑暗中执行暗杀，一个在阳光下推行高压统治，却都怀着“拯救日本", "score": 2024380, "category": "drama", "detail_url": "../movie/0943.html", "poster": "../posters/0943.svg"}, {"id": "0944", "title": "有牌烂仔", "year": 1998, "region": "中国香港", "type": "电影", "genre": "动作 / 喜剧", "tags": ["警察", "古惑仔", "卧底", "热血", "无厘头"], "summary_short": "有牌烂仔，1998年中国香港电影，动作 / 喜剧。阿细是警校历史上成绩最差的学员，射击脱靶、体能倒数、法律课零分。但警队急需一名卧底渗透新崛起的社团“义安”，因为只有阿细长得像古惑仔。入帮第一天，阿细就用“你打我我就躺下讹你”的烂仔招数搞定了一场械斗。之后他发明了“打架先跑、分钱积极、老大出事我先躲”的生存法则，反而被帮内视为“大智若愚”。半年后他成了义安最年轻的话事人，警方催他收网，他却发现黑帮兄弟比警队同事更讲义气。最终他选择做“有", "score": 1998327, "category": "crime", "detail_url": "../movie/0944.html", "poster": "../posters/0944.svg"}, {"id": "0945", "title": "大唐重案组", "year": 2025, "region": "中国", "type": "剧集", "genre": "悬疑 / 古装 / 探案", "tags": ["唐朝", "侦探小队", "密室", "权谋"], "summary_short": "大唐重案组，2025年中国剧集，悬疑 / 古装 / 探案。长安城接连发生“自燃人”案件，死者会在闹市突然自焚，坊间传言是上天降罪武则天。武则天秘密组建“大唐重案组”，召集了仵作、机关师、江湖骗子和失忆的刺客各一人。四人小组从死者体内的西域火油入手，发现案件与废太子李贤的余党有关。随着调查深入，他们发现每一具“自燃人”其实都是被一种精巧的延时机关谋害，而设计机关的图纸，竟藏在皇城司的档案库里。重案组陷入了内鬼疑云，他们必须在保护彼此秘密的", "score": 2025315, "category": "series", "detail_url": "../movie/0945.html", "poster": "../posters/0945.svg"}, {"id": "0946", "title": "萝球社第一季", "year": 2011, "region": "日本", "type": "动画", "genre": "运动， 喜剧", "tags": ["篮球， 萝莉， 社团， 热血"], "summary_short": "萝球社第一季，2011年日本动画，运动， 喜剧。长谷川昴本是高中篮球界的希望之星，却因社团内讧失去比赛资格。在叔母的介绍下，他勉强成为一所小学女子篮球部的临时教练。队员只有五人：智花、真帆、纱季、日向和爱莉，身高全都不足140厘米，连篮筐都投得吃力。更糟的是，她们的心理素质几乎为零——之前参加过的每一场比赛都输了50分以上。昴本想敷衍了事，却无意中发现这些小女孩在深夜的公园里偷偷加练，手掌磨破也不肯停。他决定用高中的魔鬼训练法改造这支队", "score": 2011147, "category": "fantasy", "detail_url": "../movie/0946.html", "poster": "../posters/0946.svg"}, {"id": "0947", "title": "顶级乐队", "year": 2023, "region": "英国", "type": "剧集", "genre": "音乐, 剧情, 喜剧", "tags": ["乐队", "重组", "中年危机"], "summary_short": "顶级乐队，2023年英国剧集，音乐, 剧情, 喜剧。前“噪音潜艇”乐队主唱凯斯如今是个惨淡的超市理货员。当他收到前经纪人发来的破产通知，唯一还清债务的方式竟是重组乐队参加一档过气明星真人秀。他找到酗酒的贝斯手、出家当和尚的鼓手和转行做美妆博主的主音吉他手。四个中年老友重聚排练房，却发现彼此连最简单的和弦都记不全。更糟的是，现在的年轻人用AI写歌、用短视频造神，他们引以为傲的摇滚精神被嘲笑为“老年痴呆”。在一场荒唐的直播事故后，他们决定不", "score": 2023307, "category": "series", "detail_url": "../movie/0947.html", "poster": "../posters/0947.svg"}, {"id": "0948", "title": "秋千", "year": 2024, "region": "法国", "type": "电影", "genre": "剧情 / 奇幻 / 家庭", "tags": ["老年痴呆", "童年记忆", "时空交错", "温情", "符号隐喻"], "summary_short": "秋千，2024年法国电影，剧情 / 奇幻 / 家庭。老木匠皮埃尔被诊断出阿尔茨海默症后，家人发现了一件怪事：只要他坐上院子里那架老旧的木秋千荡起来，他的身体和心智就会随机切换到他人生中的某个年龄段——有时是8岁的怯懦男孩，有时是28岁的热恋青年，有时是50岁的疲惫父亲。不同年龄段的皮埃尔拥有不同的记忆和人格，家人每天都要重新认识“今天的爸爸是谁”。8岁的他需要人哄，28岁的他试图修复已经去世的妻子的旧物，50岁的他痛骂儿女不孝。而在某个", "score": 2024302, "category": "drama", "detail_url": "../movie/0948.html", "poster": "../posters/0948.svg"}, {"id": "0949", "title": "完全婚姻手册", "year": 2000, "region": "中国香港", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["婚姻", "夫妻", "互换", "生活"], "summary_short": "完全婚姻手册，2000年中国香港电影，剧情 / 喜剧。结婚七年的设计师阿强和全职太太阿玲决定离婚，就在去律师楼的路上，他们发生了车祸。醒来后，他们惊恐地发现灵魂互换了。为了不在亲友面前穿帮，他们只能硬着头皮扮演对方。阿强（玲魂）穿着高跟鞋去应付太太们的下午茶和繁琐的家务，阿玲（强魂）则穿着西装去面对苛刻的老板和难缠的甲方。在极度的混乱与尴尬中，他们终于体会到了对方多年来的不易。当两人终于找到方法准备换回身体时，却发现这场车祸和灵魂互换，", "score": 2000294, "category": "drama", "detail_url": "../movie/0949.html", "poster": "../posters/0949.svg"}, {"id": "0950", "title": "少年杨家将", "year": 2006, "region": "中国大陆", "type": "剧集", "genre": "古装, 动作, 剧情", "tags": ["历史改编", "家族", "忠义", "热血"], "summary_short": "少年杨家将，2006年中国大陆剧集，古装, 动作, 剧情。本剧聚焦杨家将的青年时代。宋辽边境战火重燃，金刀令公杨业携七子出征。大郎杨延平沉稳睿智，二郎杨延定勇猛刚烈，三郎杨延安枪法无双，四郎杨延辉叛逆孤傲，五郎杨延德佛系慈悲，六郎杨延昭初露锋芒，七郎杨延嗣天真莽撞。剧情不仅描绘了惨烈的金沙滩之战，更深入刻画了七子在家国大义与个人情感间的挣扎。四郎被迫流落辽国成为驸马的痛苦抉择，五郎目睹战场残酷后遁入空门的心路历程，以及七郎为求援军而冤死", "score": 2006243, "category": "series", "detail_url": "../movie/0950.html", "poster": "../posters/0950.svg"}, {"id": "0951", "title": "漫漫吾日", "year": 2023, "region": "德国", "type": "电影", "genre": "剧情 / 家庭", "tags": ["养老院", "失智", "日常", "时间"], "summary_short": "漫漫吾日，2023年德国电影，剧情 / 家庭。八十二岁的汉斯患有罕见的“日间失忆症”：每天清晨醒来，他的记忆都会重置到二十岁那年的柏林。他不认识镜子里衰老的自己，不认识身边五十岁的儿子米歇尔，更不理解为什么自己住在养老院里。电影的每一天都是汉斯的“第一天”：米歇尔必须用不同的方式，在一天之内帮助父亲理解“你是谁”、“我是谁”、“你在哪里”。而汉斯每次得知真相后的反应都不同——有时崩溃，有时愤怒，有时安静地画画。米歇尔坚持了三年，直到医生", "score": 2023239, "category": "drama", "detail_url": "../movie/0951.html", "poster": "../posters/0951.svg"}, {"id": "0952", "title": "棠棣血", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "武侠、古装", "tags": ["兄弟反目，王朝末年，权力斗争，兵器设计"], "summary_short": "棠棣血，2025年中国大陆电影，武侠、古装。公元880年，大唐摇摇欲坠。禁军统领李棠和副统领白棣本是结义兄弟，合称“棠棣之剑”。一天，白棣在废弃的东宫发现了一卷用血写成的密诏，暗示当今皇帝并非先皇血脉。为了保住刚刚稳定下来的朝局，李棠奉命销毁血书，而白棣坚持要让真相大白于天下。兄弟二人在长安城的雨夜中展开了一场追逐。随着血书线索的深入，他们发现整个阴谋的背后，是一位被遗忘的公主在操纵一切，她要让李唐皇族自相残杀。最终，两人在一座即将倒塌", "score": 2025281, "category": "costume", "detail_url": "../movie/0952.html", "poster": "../posters/0952.svg"}, {"id": "0953", "title": "向北方", "year": 2018, "region": "罗马尼亚", "type": "电影", "genre": "剧情", "tags": ["移民，家庭，沉默，公路，生存"], "summary_short": "向北方，2018年罗马尼亚电影，剧情。中年男人维克多带着十五岁的女儿安娜，开着一辆破旧的二手车从罗马尼亚出发，一路向北，目标是瑞典。车上两个人几乎没有对话，所有信息都藏在眼神、手势和沉默里。观众通过闪回逐渐拼凑出真相：安娜的母亲三年前因为举报当地黑心工厂而被灭口，维克多因为害怕选择了沉默，安娜从此再也没叫过他一声“爸爸”。一路上他们遇到检查站的刁难、人贩子的陷阱、冬天的暴风雪。安娜几次想独自逃走，维克多每次都默默找到她，然后把外套脱下来", "score": 2018236, "category": "drama", "detail_url": "../movie/0953.html", "poster": "../posters/0953.svg"}, {"id": "0954", "title": "五星大饭店", "year": 2027, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 商战 / 爱情", "tags": ["酒店业，职场，商业谍战，服务美学，理想主义"], "summary_short": "五星大饭店，2027年中国大陆电视剧，剧情 / 商战 / 爱情。天才酒店人陆羽被对手陷害，沦为清洁工。为翻身，他潜入业绩垫底的“盛华酒店”当客房主管，计划偷学模式后跳槽。但他发现酒店并非管理不善，而是总经理故意亏损以骗取保险金。陆羽带领一群被放弃的员工——固执的保洁阿姨、有过失的保安、聋哑厨师——发起“奇迹服务赛”，用极致个性化服务重获客源。最终，他收集证据扳倒了总经理，自己也从“间谍”变成了真正的守护者。当总公司想卖掉酒店时，陆羽和员", "score": 2027268, "category": "series", "detail_url": "../movie/0954.html", "poster": "../posters/0954.svg"}, {"id": "0955", "title": "行人徒步区", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "剧情, 家庭, 社会", "tags": ["都市变迁", "代际沟通", "市井生活", "温情", "写实"], "summary_short": "行人徒步区，2023年中国台湾电影，剧情, 家庭, 社会。台南一条拥有五十年历史的夜市老街，因为城市改造计划即将升级为行人徒步区，但这也意味着所有流动摊贩必须获得合法牌照并交纳高昂租金。老摊主阿公固执地守护着一辆破旧的关东煮车，不愿申请牌照，因为车子里藏着离家出走的儿子的信。孙女小晴是一名都市规划师，恰巧负责这个项目，她必须在亲情与工作中做出选择。而在街尾卖手工皮鞋的阿叔，一直暗恋着对面的花店老板娘。随着徒步区施工日期的逼近，老街上的每", "score": 2023321, "category": "drama", "detail_url": "../movie/0955.html", "poster": "../posters/0955.svg"}, {"id": "0956", "title": "租借女友第四季", "year": 2024, "region": "日本", "type": "动画/TV", "genre": "恋爱, 喜剧, 日常", "tags": ["租借女友", "党争", "青春", "漫改", "误会"], "summary_short": "租借女友第四季，2024年日本动画/TV，恋爱, 喜剧, 日常。进入大学最后一年的和也，依然维持着与水原千鹤的“租借”关系。随着千鹤的演员事业蒸蒸日上，她的真实身份开始被媒体和身边的朋友质疑。更木、瑠夏、麻美等多方势力交错，每个人都在逼和也做出选择。与此同时，和也意外发现了千鹤奶奶年轻时的秘密，这段“假扮的恋情”或许从一开始就有着命运的牵引。毕业旅行成了所有人的最后战场，谁会成为和也身边的那个人？", "score": 2024179, "category": "comedy", "detail_url": "../movie/0956.html", "poster": "../posters/0956.svg"}, {"id": "0957", "title": "澳门营业中", "year": 2024, "region": "中国澳门，中国香港", "type": "剧集", "genre": "剧情，群像", "tags": ["澳门，小店，人情味"], "summary_short": "澳门营业中，2024年中国澳门，中国香港剧集，剧情，群像。澳门福隆新街，百年老字号“英记饼家”收到拆迁通知，整条街将被改建成赌场附属商场。店主梁伯已经八十岁，他的儿子早就移民澳洲不愿意接手，孙女阿琳从香港辞掉设计师工作回来帮忙，却发现传统手艺正在失传。与此同时，街上其他六家小店——凉茶铺、理发店、糖水摊、裁缝铺、五金行、当铺——也面临同样命运。七个店铺的后代从互相竞争到联手自救，他们发起“澳门味道复兴计划”，试图用现代商业手段拯救传统。", "score": 2024248, "category": "series", "detail_url": "../movie/0957.html", "poster": "../posters/0957.svg"}, {"id": "0958", "title": "我的第一先生", "year": 2001, "region": "美国", "type": "电影", "genre": "剧情, 爱情", "tags": ["师生情", "人生导师", "忘年交", "女性觉醒", "纽约故事"], "summary_short": "我的第一先生，2001年美国电影，剧情, 爱情。被多所学校退学的18岁女孩杰茜卡满口谎话，性格乖张。母亲将她送到一位独居的退休老作家阿特先生家中做家务，作为交换，阿特先生辅导她写作。阿特先生看穿了她所有的谎言，没有戳破，只是让她每天写一个真实发生过的故事，写满一百个，就告诉她一个关于人生的秘密。从第一个谎言连篇的故事到第一百个泪流满面的自白，杰茜卡完成了蜕变。而阿特先生的秘密，则永远改变了她的人生走向。", "score": 2001344, "category": "drama", "detail_url": "../movie/0958.html", "poster": "../posters/0958.svg"}, {"id": "0959", "title": "电磁王之霹雳父子", "year": 2025, "region": "中国香港", "type": "电影", "genre": "喜剧 / 科幻 / 家庭", "tags": ["超级英雄", "废柴父子", "电磁学"], "summary_short": "电磁王之霹雳父子，2025年中国香港电影，喜剧 / 科幻 / 家庭。老实巴交的电器维修工雷大蒙和沉迷二次元的高中生儿子雷小宝是一对关系紧张的父子。一次罕见的太阳风暴袭击地球，正在修理高压电塔的两人被闪电击中，意外获得了操控电磁场的超能力。老爸的能力是吸收电力强化身体，想用来多接点活赚钱；而儿子的能力是操控电子设备，想用来扮成超级英雄去行侠仗义。父子俩理念不合，在一次阻止银行劫匪时因配合失误闹出大笑话，被全网嘲讽。此时，一家新能源公司的邪", "score": 2025387, "category": "comedy", "detail_url": "../movie/0959.html", "poster": "../posters/0959.svg"}, {"id": "0960", "title": "失明的耶稣", "year": 2023, "region": "巴西", "type": "电影", "genre": "剧情, 宗教, 社会", "tags": ["贫民窟", "宗教狂热", "失明", "信仰实验"], "summary_short": "失明的耶稣，2023年巴西电影，剧情, 宗教, 社会。在里约热内卢最大的贫民窟，一个自称“耶稣转世”的盲人——保罗，拥有上千信徒。他能“看到”每个信徒的秘密，预言毒品袭击和警察扫荡。所有人相信他的失明是“神迹”。女眼科医生安娜因义诊进入贫民窟，她发现保罗的眼球结构完全正常——他是假盲。但保罗利用信仰，确实让毒品贩子退出社区、建立了免费食堂和学校。安娜陷入了道德困境：揭露保罗，信仰崩塌，社区会重返暴力；不揭露，保罗就是一个打着神明旗号的骗", "score": 2023232, "category": "drama", "detail_url": "../movie/0960.html", "poster": "../posters/0960.svg"}, {"id": "0961", "title": "普里斯特法官", "year": 2023, "region": "美国", "type": "剧集", "genre": "剧情 / 犯罪 / 法律", "tags": ["宗教法庭", "道德困境", "小镇悬疑", "以恶制恶", "季终反转"], "summary_short": "普里斯特法官，2023年美国剧集，剧情 / 犯罪 / 法律。第一季共8集。神父迈克尔被主教派往路易斯安那州一个神秘小镇担任治安法官。小镇表面上岁月静好，但每周六的忏悔室里，全镇居民都会来向他告解——偷情、诈骗、家暴、甚至谋杀。迈克尔出于“忏悔保密原则”无法公开任何罪行，但他发明了灰色手法：在布道时引用“匿名案例”暗示罪犯，或通过“偶遇”把受害者和施害者安排在一起。随着调查深入，他发现所有罪行的源头指向三十年前的一桩悬案：镇长、警长、学校", "score": 2023311, "category": "series", "detail_url": "../movie/0961.html", "poster": "../posters/0961.svg"}, {"id": "0962", "title": "柏林酷儿", "year": 2024, "region": "德国", "type": "剧集", "genre": "爱情, 剧情", "tags": ["LGBTQ+", "地下文化", "柏林墙记忆"], "summary_short": "柏林酷儿，2024年德国剧集，爱情, 剧情。当代柏林，非二元性别艺术家米夏正在筹备一场关于“自由”的展览。在地下旧货市场，米夏买到了一本东德时期废弃的素描本，里面画满一个长发青年的肖像——就是米夏自己。根据纸张日期和风格，米夏追查发现，作画者是前史塔西秘密警察赫伯特。赫伯特还活着，已是90岁痴呆老人。他的孙女交给米夏一盘磁带：赫伯特当年奉命监视东柏林地下同性恋酒吧，却爱上了酒吧里那个长发青年（米夏的亲生父亲）。赫伯特没有举报，而是每天偷", "score": 2024303, "category": "series", "detail_url": "../movie/0962.html", "poster": "../posters/0962.svg"}, {"id": "0963", "title": "日落卡门", "year": 1998, "region": "中国香港", "type": "电影", "genre": "犯罪，爱情", "tags": ["黑帮，宿命，复仇，港风"], "summary_short": "日落卡门，1998年中国香港电影，犯罪，爱情。阿辉是纵横油尖旺的顶尖杀手，内心却渴望平静。当他决定做完最后一单便金盆洗手时，目标照片赫然是五年前不辞而别的恋人卡门。如今卡门已是嚣张新大佬的情妇，性格变得冷酷狠辣。阿辉在跟踪过程中发现，卡门当年离开是为了保护他，而如今她正暗中替警方收集黑帮证据。新旧恩仇、卧底疑云与帮派火并交织。最后的天台对决，阿辉必须选择是扣动扳机，还是用自己的命换她一条生路。夕阳下，卡门独自走进警署，身后传来警笛声。", "score": 1998396, "category": "crime", "detail_url": "../movie/0963.html", "poster": "../posters/0963.svg"}, {"id": "0964", "title": "夜郎2007", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情, 黑色幽默, 公路", "tags": ["贵州", "考古", "假古董", "荒诞"], "summary_short": "夜郎2007，2025年中国大陆电影，剧情, 黑色幽默, 公路。2007年，贵州某贫困山村。村长牛德彪为了完成镇上下达的“年度招商指标”，想出了一个馊主意：伪造一座“夜郎国”古墓，骗那些迷信风水的老板来投资“文旅项目”。他找来了村里会木匠活的哑巴、镇上刻墓碑的、以及一个自称是考古系肄业的骗子，连夜在村后山挖了一个深坑，埋进去一批做旧的破陶罐。然而就在他们举行“发现仪式”的那天晚上，一场暴雨冲垮了假墓，露出了下面一个真正的战国时期岩墓！墓", "score": 2025284, "category": "drama", "detail_url": "../movie/0964.html", "poster": "../posters/0964.svg"}, {"id": "0965", "title": "取脑袋冈村", "year": 2023, "region": "日本", "type": "电影", "genre": "惊悚 / 悬疑", "tags": ["猎奇", "怪谈", "复仇", "民俗"], "summary_short": "取脑袋冈村，2023年日本电影，惊悚 / 悬疑。自由撰稿人铃木一郎为寻找写作素材，误入地图上不存在的“冈村”。村民看似热情，却总在月圆之夜紧闭门窗，村口的神社里供奉着三颗面无表情的蜡制人头。铃木发现，每年祭祀都会选出一名“容器”，而“取脑袋”并非杀人，而是一场剥夺记忆与自我的仪式——被选中者的人头会被制成新的蜡像，灵魂则永远困在村里。当他试图逃出时，发现自己已记不清东京的家，而镜中的脸，正缓缓变成村里上一任外来者的模样。", "score": 2023408, "category": "crime", "detail_url": "../movie/0965.html", "poster": "../posters/0965.svg"}, {"id": "0966", "title": "再见，我的王后", "year": 2012, "region": "法国", "type": "电影", "genre": "剧情 / 历史 / 同性", "tags": ["法国大革命", "凡尔赛宫", "宫女视角", "断头台"], "summary_short": "再见，我的王后，2012年法国电影，剧情 / 历史 / 同性。故事聚焦于巴士底狱被攻陷前的三天。蕾朵是玛丽·安托瓦内特的专职朗读书仆，她疯狂地暗恋着皇后。当革命浪潮逼近凡尔赛，贵族们纷纷逃亡，皇后却只关心另一个女人——波利尼亚克公爵夫人。蕾朵被派去为公爵夫人找一件衣服，却无意中被皇后推出去做替身，穿上公爵夫人的衣服登上逃亡马车。在被愤怒的民众围堵时，蕾朵终于明白：她从未被皇后看见过，自己只是权力游戏中一个可替换的棋子。", "score": 2012282, "category": "drama", "detail_url": "../movie/0966.html", "poster": "../posters/0966.svg"}, {"id": "0967", "title": "疯狂的麦咭第八季", "year": 2024, "region": "中国大陆", "type": "综艺", "genre": "真人秀", "tags": ["密室闯关", "明星", "冒险", "亲子"], "summary_short": "疯狂的麦咭第八季，2024年中国大陆综艺，真人秀。本季“疯狂的麦咭”迎来史上最难关卡。石头城从原本的5个密室扩展到9个，加入了“时间吞噬者”设定：每失败一次，倒计时就会加速。明星嘉宾们必须组队闯关，解谜、体力、胆量缺一不可。压轴密室“麦咭的胃”中，失败者会被机械牙齿“吞入”，被水枪和泡沫“消化”。最终冠军队伍将获得“石头城守护者”称号。", "score": 2024105, "category": "series", "detail_url": "../movie/0967.html", "poster": "../posters/0967.svg"}, {"id": "0968", "title": "铁汉战群雄", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动作, 战争", "tags": ["硬汉", "孤胆英雄", "肉搏", "热血"], "summary_short": "铁汉战群雄，2024年中国大陆电影，动作, 战争。老铁曾是某特种部队王牌，因一次任务失误导致战友牺牲，愧疚退伍后在小城经营拳馆。女儿小美是他唯一的牵挂。某天小美在放学路上被不明势力掳走，绑匪发来视频，要求老铁三天内交出他根本不知道的“硬盘”。警方束手无策，老铁决定独自行动。他追踪线索进入金三角边境，发现绑架者是一个由军阀操控的庞大人口贩卖网络。小美被关押在戒备森严的武装营地，里面有上百名持枪雇佣兵。老铁利用丛林作战经验，一个个拔掉外围哨", "score": 2024316, "category": "doc", "detail_url": "../movie/0968.html", "poster": "../posters/0968.svg"}, {"id": "0969", "title": "真假学园2", "year": 2011, "region": "日本", "type": "剧集", "genre": "动作 / 校园", "tags": ["女高中生", "不良热血", "打架斗殴"], "summary_short": "真假学园2，2011年日本剧集，动作 / 校园。传说中的最强女校“马路须加学园”面临废校危机，要与宿敌男校“乌鸦高校”合并。为了保护只有女生的校园传统，已隐退的前不良少女们被迫重出江湖。原本一盘散沙的各个派别（激辣、学ラン、歌舞伎等）在现任老大优子的带领下，决定暂弃前嫌一致对外。她们挑战的不仅是男生的体力优势，更是社会对“女生就该温柔”的刻板印象。从街头巷战到天台决战，女生们用鲜血和汗水证明，就算是打架，女生也绝不输给男生，尊严要靠自己", "score": 2011289, "category": "series", "detail_url": "../movie/0969.html", "poster": "../posters/0969.svg"}, {"id": "0970", "title": "总统特务2", "year": 2024, "region": "美国", "type": "电影", "genre": "动作, 惊悚", "tags": ["特工", "白宫", "阴谋论", "贴身护卫", "枪战"], "summary_short": "总统特务2，2024年美国电影，动作, 惊悚。作为《总统特务》的续集，故事发生在上一部事件的三年后。主角杰克隐退在阿拉斯加当猎人，突然接到紧急召回：美国历史上第一位女总统在签署一项全球新能源协议前夕，收到了来自神秘组织的“死亡点名”。杰克的职责是24小时贴身保护。然而在前期侦察中，他发现这个组织的手段和情报网络异常熟悉，甚至能绕过所有安全系统。经过调查，暗杀指令的最终签署人居然是杰克自己在CIA时期的旧身份编码。他被陷害成了内鬼。为了自", "score": 2024403, "category": "crime", "detail_url": "../movie/0970.html", "poster": "../posters/0970.svg"}, {"id": "0971", "title": "48小时", "year": 2021, "region": "英国", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["密室，实时叙事，赎罪"], "summary_short": "48小时，2021年英国电影，悬疑 / 犯罪。伦敦警察尼克被内部调查科锁在玻璃审讯室中，罪名是受贿和栽赃证据。他坚称是搭档陷害自己，但监控录像证据确凿。律师告诉他：你只有48小时，否则将被移交重罪法庭。审讯过半，尼克的手机突然收到一段视频：蒙面人绑架了他的女儿，并留言“你只有48小时找到我，但你现在动不了”。尼克通过审讯室的对讲机指挥外面的菜鸟警察，利用他对罪犯心理的了解展开营救。时间一分一秒过去，他逐渐发现真正的凶手，其实一直在审讯室", "score": 2021394, "category": "crime", "detail_url": "../movie/0971.html", "poster": "../posters/0971.svg"}, {"id": "0972", "title": "通灵诊疗室", "year": 2024, "region": "韩国", "type": "电视剧", "genre": "悬疑 / 医学 / 奇幻", "tags": ["灵媒医生", "无法解释的病例", "单元剧", "催泪", "神婆"], "summary_short": "通灵诊疗室，2024年韩国电视剧，悬疑 / 医学 / 奇幻。精神科医生韩智勋能肉眼看到病人心理创伤形成的“黑色雾气”，这让他诊断精准却极度痛苦。女巫出身的实习生高恩星则声称能看到真正的“鬼”，她认为很多精神疾病其实是魂魄离体或执念缠绕。医院里，一个是唯物主义的精英，一个是被视为骗子的神婆，两人因一个自称“被外星人绑架”的富豪病人而被迫合作。随着调查深入，他们发现富豪的症状既非纯粹的精神分裂，也非简单的鬼怪作祟，而是由于科技公司秘密进行的", "score": 2024319, "category": "series", "detail_url": "../movie/0972.html", "poster": "../posters/0972.svg"}, {"id": "0973", "title": "母亲三十岁", "year": 1988, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["早婚母亲", "代际冲突", "女性成长", "时代变迁", "催泪"], "summary_short": "母亲三十岁，1988年中国台湾电影，剧情 / 家庭。七十年代的台湾渔村，阿巧二十岁生下儿子阿明，丈夫出海失踪。为了生计，她不得不去城里当裁缝，将阿明留给外婆。十年过去，阿巧三十岁，保养得宜、穿着时髦，却因从未陪伴阿明成长，母子关系僵硬。阿明在学校被同学笑“你妈像你姐”，叛逆期到来，甚至当众喊她“阿姨”。阿巧试图弥补，带阿明去游乐场、给他买新鞋，但阿明只想要一个“正常妈妈”。影片中段，阿明无意翻到母亲的日记，才知她这些年每天只吃一顿饭，攒", "score": 1988320, "category": "drama", "detail_url": "../movie/0973.html", "poster": "../posters/0973.svg"}, {"id": "0974", "title": "情越双白线国语", "year": 2010, "region": "中国香港", "type": "剧集", "genre": "爱情 / 剧情", "tags": ["出租车", "父子和解", "车祸", "救赎"], "summary_short": "情越双白线国语，2010年中国香港剧集，爱情 / 剧情。老司机何年生开出租车三十年，一次疲劳驾驶撞死了路人，被判刑四年。儿子何思成原本是律师，因为父亲的事丢了工作、未婚妻离开。出狱后，思成恨父亲毁了自己的人生，拒绝相认。父亲出狱后患上阿尔茨海默症，唯一记得的是那辆出租车。思成被迫接手出租车拉客还债。他在车上发现了父亲写给被害人家属的道歉信，一共写了三百多封，每一封都退回。思成开着车找到了被害人的女儿，把父亲的存折递给她。对方说：我早就不", "score": 2010303, "category": "series", "detail_url": "../movie/0974.html", "poster": "../posters/0974.svg"}, {"id": "0975", "title": "午夜号角", "year": 2024, "region": "法国", "type": "电影", "genre": "悬疑，战争，历史", "tags": ["一战，老兵，幻听，集体创伤，小镇秘密"], "summary_short": "午夜号角，2024年法国电影，悬疑，战争，历史。1928年，法国某乡村。每年停战纪念日前后的午夜，都会响起一段诡异的号角声。第二天，必然会有一位当年幸存的老兵饮弹自尽，遗书上都写着“我没能吹响它”。从战场归来的残疾士兵雷内不相信这是集体幻觉或诅咒，他展开了秘密调查。随着调查深入，他发现号角声来自小镇地下的废弃工事，而每位死者都曾属于同一个不敢冲锋的“懦夫排”。一场关于恐惧、背叛与战后清算的阴影逐渐浮现。雷内必须在下一个午夜到来前，揭开号", "score": 2024294, "category": "doc", "detail_url": "../movie/0975.html", "poster": "../posters/0975.svg"}, {"id": "0976", "title": "天堂口", "year": 2007, "region": "中国台湾 / 中国香港", "type": "电影", "genre": "剧情, 爱情, 犯罪", "tags": ["黑帮", "兄弟", "旧上海", "悲剧", "全明星阵容"], "summary_short": "天堂口，2007年中国台湾 / 中国香港电影，剧情, 爱情, 犯罪。上世纪30年代，阿峰、阿伟、小虎三个结拜兄弟从穷乡僻壤来到上海滩，投奔在“天堂口”歌舞厅做事的同乡大刚。大刚实际是黑帮头目的亲信。三兄弟被花花世界迷了眼，逐渐卷入帮派仇杀。阿伟心狠手辣，迅速上位；小虎单纯善良，惨死街头；阿峰爱上了歌女露露，想要带她离开，却被大刚追杀。最终，阿峰在码头杀死了昔日的大哥大刚，但自己也身负重伤。他看着露露的船远去，倒在了天堂口的招牌下。而唯一", "score": 2007403, "category": "drama", "detail_url": "../movie/0976.html", "poster": "../posters/0976.svg"}, {"id": "0977", "title": "残秽，不可以住的房间", "year": 2025, "region": "日本", "type": "电影", "genre": "恐怖, 悬疑", "tags": ["凶宅", "诅咒连锁", "民俗怪谈", "伪记录"], "summary_short": "残秽，不可以住的房间，2025年日本电影，恐怖, 悬疑。推理小说家瞳为了寻找灵感，搬进了一间著名的“自杀公寓”。她走访了楼内多个发生过命案的房间，发现这些事件并非孤立，而是像“残秽”一样随着租客的搬家而扩散。她通过采访幸存者和查阅旧档案，追踪到一百年前此处曾是一片弃婴墓地。更恐怖的是，那些住进房间并活下来的人，都在之后的人生中遭遇了同一种诅咒：他们会梦见自己在墙壁夹层中窒息，随后身边的人会开始莫名失踪。瞳试图用科学和逻辑解释这一切，却发", "score": 2025445, "category": "horror", "detail_url": "../movie/0977.html", "poster": "../posters/0977.svg"}, {"id": "0978", "title": "圣朱迪", "year": 2024, "region": "美国", "type": "电影", "genre": "传记剧情", "tags": ["修女，律师，真实改编，抗争，救赎"], "summary_short": "圣朱迪，2024年美国电影，传记剧情。影片改编自真实事件。修女朱迪被教会派往全美最穷的教区，当地居民因化工厂污染集体患上癌症。政府不管，教会沉默，她自学法律，用打字机一份份起草诉状。所有人都笑她痴人说梦，直到她将市长、环保署和化工厂一同告上法庭。庭审中她拿出患癌儿童的眼泪样本，一字一句念出死者的名字。最终她赢了，但教会以“越权”将她调离。朱迪没有离开，而是在垃圾山上建起了免费诊所，直到生命的最后一天。她从未封圣，却被穷人绣在了旗上。", "score": 2024271, "category": "drama", "detail_url": "../movie/0978.html", "poster": "../posters/0978.svg"}, {"id": "0979", "title": "特洛伊", "year": 2026, "region": "美国", "type": "剧集", "genre": "历史, 战争", "tags": ["史诗翻拍", "众神视角", "多线叙事", "删减版争议"], "summary_short": "特洛伊，2026年美国剧集，历史, 战争。10集限定剧，每集以一位神祇的视角展开。第一集：宙斯觉得无聊，提议用一场人类战争来赌谁更有资格做下一代神王。第二集：赫拉想捧希腊，阿芙洛狄忒想保特洛伊，雅典娜随便站队只为看阿瑞斯输。中间穿插人类视角：阿喀琉斯、赫克托耳、帕里斯全都不知道自己只是棋盘上的卒。第六集惊现反转：特洛伊木马不是奥德修斯的计谋，而是雅典娜给希腊人的“作业答案”。最后一集：特洛伊城烧毁后，众神在天庭开会复盘，发现赌注被赫耳墨", "score": 2026164, "category": "series", "detail_url": "../movie/0979.html", "poster": "../posters/0979.svg"}, {"id": "0980", "title": "百集聊斋之人鬼情缘", "year": 2003, "region": "中国", "type": "剧集", "genre": "古装 / 爱情 / 奇幻", "tags": ["聊斋", "单元剧", "书生", "女鬼", "虐恋"], "summary_short": "百集聊斋之人鬼情缘，2003年中国剧集，古装 / 爱情 / 奇幻。《百集聊斋》第44个单元。明末，书生沈怀瑾在破庙救下一名被村民当作狐妖烧死的少女聂小渔。小渔伤重而亡，临死前说“下辈子还你”。沈怀瑾将其葬于庙后梨花树下。十年后同一天，梨花盛开之夜，小渔化作女鬼归来，容貌如初。两人一夜温存，黎明前小渔消失，说“十年后再见”。沈怀瑾终身未娶，每十年在梨花树下等她。第一次等到鬓角斑白，第二次等到拄拐，第三次他80岁，再也站不起来，躺在树下等她", "score": 2003363, "category": "series", "detail_url": "../movie/0980.html", "poster": "../posters/0980.svg"}, {"id": "0981", "title": "穿墙人", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "奇幻爱情", "tags": ["超能力", "都市传说", "孤独症", "墙中世界"], "summary_short": "穿墙人，2024年中国台湾电影，奇幻爱情。沉默的建筑系学生阿衍患有罕见的失语症，一次实验意外让他获得了能够穿透固体物质的能力。起初他利用这项技能恶作剧、偷窥、逃避现实，直到某天他穿入一栋即将拆除的老公寓夹层，遇见了一位被困在墙体内三十年的女孩幽灵小霙。她忘记了自己是如何死去的，只记得在等一封从未寄到的信。阿衍决定每周三次穿墙为她读信、讲故事，两人在钢筋混凝土的缝隙间建立起超越生死的羁绊。然而频繁穿墙导致阿衍的身体开始出现水泥化的症状，皮", "score": 2024410, "category": "fantasy", "detail_url": "../movie/0981.html", "poster": "../posters/0981.svg"}, {"id": "0982", "title": "艾拉‧辛德斯", "year": 2023, "region": "英国", "type": "电影", "genre": "犯罪剧情", "tags": ["女杀手，伦敦，阶层跨越，自我认同，冷峻"], "summary_short": "艾拉‧辛德斯，2023年英国电影，犯罪剧情。艾拉‧辛德斯是个普通的伦敦清洁女工，每天打扫写字楼，准时下班回家喂猫。但她的“副业”是帮黑帮清理犯罪现场。她技术高超，从不问原因，只拿现金。直到有一天，她接到了一个特殊的单子：清理一具少年的尸体。艾拉发现这是她女儿的同班同学。她第一次违背了规矩，保留了死者的一枚戒指。通过戒指，她追查到幕后黑手竟是伦敦市议员，也是她雇主的上线。艾拉利用清洁工的身份潜入议员的豪宅，不动声色地在他价值百万的地毯和家", "score": 2023381, "category": "drama", "detail_url": "../movie/0982.html", "poster": "../posters/0982.svg"}, {"id": "0983", "title": "甜过头", "year": 2025, "region": "韩国", "type": "剧集", "genre": "浪漫喜剧、奇幻", "tags": ["甜品、诅咒、恋爱、魔法、甜点师"], "summary_short": "甜过头，2025年韩国剧集，浪漫喜剧、奇幻。男主姜志浩是顶级甜点师，秘密在于他双手能注入“心动因子”，任何吃过他甜品的人都会对第一眼看到的人疯狂心动。他用这招撮合了无数情侣，却从不恋爱。直到某天他意外试吃自己被恶作剧加料的蛋糕，对镜中的自己一见钟情——从此他爱上了自己。更麻烦的是，他的“自恋”导致甜品失效：吃蛋糕的人全变成了自拍狂和自恋狂。他必须在三周内找到“真爱解药”，否则能力永久消失。", "score": 2025307, "category": "series", "detail_url": "../movie/0983.html", "poster": "../posters/0983.svg"}, {"id": "0984", "title": "圣殿奇妙夜", "year": 2023, "region": "英国", "type": "电影", "genre": "喜剧 / 奇幻 / 冒险", "tags": ["博物馆", "复活", "历史人物", "一夜"], "summary_short": "圣殿奇妙夜，2023年英国电影，喜剧 / 奇幻 / 冒险。倒霉的守夜人乔治被调到伦敦一座古老教堂值夜班。第一个晚上，他就看到了惊悚的一幕：圣母玛利亚的雕像跳下来喝水、圣彼得抢了天使的翅膀在教堂里飞。更离谱的是，这群复活的神圣人物有严重的内讧——耶稣嫌弃犹大碗洗得不干净，犹大抱怨耶稣总是把最后的晚餐剩饭不倒掉。乔治被迫成了“调解员”，在每晚的鸡飞狗跳中学会和圣人们相处。直到有一天，一群盗贼来偷圣杯，这群天天吵架的雕像竟然放下恩怨，用十字架", "score": 2023341, "category": "fantasy", "detail_url": "../movie/0984.html", "poster": "../posters/0984.svg"}, {"id": "0985", "title": "拥抱法力", "year": 2023, "region": "中国香港", "type": "电影", "genre": "奇幻剧情", "tags": ["家庭", "灵异", "温情", "传承"], "summary_short": "拥抱法力，2023年中国香港电影，奇幻剧情。在香港从事AI开发的阿俊接到父亲去世的噩耗，返乡后发现家族竟世代守护着一门濒临失传的“收惊”法术。母亲临终前告诉他，唯一遗愿是让他继承法力并完成一场送魂仪式。阿俊起初嗤之以鼻，却在接连遭遇无法解释的灵异现象后，被迫跟随家族最后一位法师——自己痴呆已久的奶奶学习。在科学与传统的碰撞中，他逐渐理解了法术背后其实是连接生者与逝者情感的纽带，最终用一场融合现代科技与传统仪式的告别，送走了母亲也治愈了自", "score": 2023391, "category": "drama", "detail_url": "../movie/0985.html", "poster": "../posters/0985.svg"}, {"id": "0986", "title": "女巫阿加莎", "year": 2024, "region": "美国", "type": "剧集", "genre": "奇幻喜剧", "tags": ["漫威衍生", "女巫", "歌唱诅咒"], "summary_short": "女巫阿加莎，2024年美国剧集，奇幻喜剧。《旺达幻视》的衍生剧。阿加莎·哈克尼斯被旺达的咒语困在西景镇的幻觉中，她不再是女巫，而是过气选秀歌手“阿格尼丝”。某天，一个自称“制片人”的神秘少年找到她，告诉她：你被困在一档真人秀里，每唱一首被观众投票通过的歌曲，就能解除一层封印。阿加莎被迫参赛，唱歌类型从乡村民谣到重金属，每唱完一首，她就恢复一部分能力：先是一句咒语，然后是瞬移，接着是吸食魔法。但每恢复一次，舞台也会变得更加危险，其他“选手", "score": 2024329, "category": "series", "detail_url": "../movie/0986.html", "poster": "../posters/0986.svg"}, {"id": "0987", "title": "行走的最佳方式", "year": 2024, "region": "法国", "type": "电影", "genre": "喜剧, 剧情, 运动", "tags": ["竞走", "中年危机", "法式幽默", "治愈"], "summary_short": "行走的最佳方式，2024年法国电影，喜剧, 剧情, 运动。巴黎顶尖的心外科医生马蒂厄因在手术台上对病人爆粗口，被强制要求进行300小时社区服务。他被分配到一个破落的郊区，任务竟然是组建一支老年女子竞走队参加区级比赛。队伍里包括：患有广场恐惧症的寡妇、极度迷信的超市收银员、以及一个整天想着超度亡夫的灵媒大妈。马蒂厄一开始极度鄙视这项“最无聊的运动”，试图用手术般的精准去纠正她们摇摆的臀部。但他渐渐发现，在这些看似笨拙的走路姿势里，藏着对生", "score": 2024305, "category": "drama", "detail_url": "../movie/0987.html", "poster": "../posters/0987.svg"}, {"id": "0988", "title": "尸城30夜", "year": 2028, "region": "韩国", "type": "电影", "genre": "恐怖, 动作", "tags": ["丧尸", "极寒", "隔离", "人性实验"], "summary_short": "尸城30夜，2028年韩国电影，恐怖, 动作。一场暴风雪将韩国某新城与外隔绝，丧尸病毒在零下三十度环境里传播缓慢，感染者大多被冻成“冰尸”。幸存者躲进一处地下停车场，却发现真正的威胁不是丧尸——食物耗尽后，一支保安队开始实施“抽签配给制”。曾是军医的女主角带领一帮老人和孩子试图逃离，却在出口处遭遇更残酷的陷阱：有人故意放入了半解冻的丧尸当作“清理工具”。随着室内温度因供暖不足持续下降，活人与将死之人的界限彻底模糊。最后一场戏：女主角抱着", "score": 2028367, "category": "horror", "detail_url": "../movie/0988.html", "poster": "../posters/0988.svg"}, {"id": "0989", "title": "谷家大镬过圣诞", "year": 2023, "region": "中国香港", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["港式喜剧，圣诞，家族纷争，闹剧"], "summary_short": "谷家大镬过圣诞，2023年中国香港电影，喜剧 / 家庭。以烧腊闻名的“谷记”老店因父亲去世而关门。圣诞夜，散落各地的四兄妹回到老宅，表面过节，实则都想搞到父亲留下的那只传家“镬”（据传镬底刻着独门腌料配方）。老大想卖钱还赌债，老二想开连锁店，老三是个美食博主想以此炒作，只有单纯的小妹想守住家业。正当几人争夺那只挂在墙上的老镬时，不慎打翻了父亲的骨灰坛，灰烬洒在刚出炉的烧鹅上。为了不惊动律师，他们不得不硬着头皮把这盘“加料”烧鹅给客人吃，", "score": 2023299, "category": "comedy", "detail_url": "../movie/0989.html", "poster": "../posters/0989.svg"}, {"id": "0990", "title": "罗贝托·卡洛斯与粉红钻石", "year": 2026, "region": "巴西、美国合拍", "type": "电影", "genre": "剧情、运动、犯罪", "tags": ["足球、传奇球星、盗窃、友情"], "summary_short": "罗贝托·卡洛斯与粉红钻石，2026年巴西、美国合拍电影，剧情、运动、犯罪。退役多年的巴西球星罗贝托·卡洛斯过着平静的生活。直到他收到一颗粉红钻石和一张纸条：“你的任意球还能拐弯吗？”原来，他年轻时曾用一记经典的弧线任意球，无意中击碎了黑帮大佬珍藏的宝石柜。那颗传说中的“粉红钻石”因此被安保系统误判而遗失。如今，大佬绑架了他的老队友，要求他在一场高规格慈善赛上，用任意球将一颗假钻石踢进特定的球门，从而替换掉真品。年过半百的卡洛斯，必须重新", "score": 2026398, "category": "drama", "detail_url": "../movie/0990.html", "poster": "../posters/0990.svg"}, {"id": "0991", "title": "一村之长之爸爸回家", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭", "tags": ["乡村", "父子", "和解", "基层干部", "温情"], "summary_short": "一村之长之爸爸回家，2025年中国大陆剧集，剧情 / 家庭。青山村村长老罗一辈子为村民奔波，心中最深的痛却是十年前赌气离家出走的父亲。一个暴雨夜，父亲浑身是伤地倒在村口，记忆全失，口袋里只有一张泛黄的矿工体检单。老罗一边照顾父亲，一边发现村里即将上马的项目与父亲失踪的煤矿事故有关。在帮父亲找回记忆的过程中，两代人从沉默对抗到慢慢理解，最终揭开一场被掩盖的安全事故。老罗不仅找回了父亲，更找回了当村长的初心。", "score": 2025187, "category": "drama", "detail_url": "../movie/0991.html", "poster": "../posters/0991.svg"}, {"id": "0992", "title": "小男人出差粤语", "year": 1997, "region": "中国香港", "type": "电视剧", "genre": "喜剧 / 悬疑", "tags": ["侦探", "怕老婆", "乌龙", "单元剧"], "summary_short": "小男人出差粤语，1997年中国香港电视剧，喜剧 / 悬疑。“老婆奴”私家侦探金大力，业务能力一流却对老婆阿芳言听计从。每当接到案件，他都要编造各种奇葩理由（买酱油、修水管、陪姑妈复诊）溜出门，然后在一小时内破案回家。剧中每集一个独立案件，从“名画失窃”到“密室杀人”，金大力一边在电话里对老婆撒谎说“在菜市场”，一边在凶案现场用吸管和橡皮筋做指纹提取。最绝的是，每次破案关键线索都是因为老婆的日常唠叨启发。直到最后大案，阿芳发现真相并亲自下", "score": 1997369, "category": "series", "detail_url": "../movie/0992.html", "poster": "../posters/0992.svg"}, {"id": "0993", "title": "所有明亮的地方", "year": 2020, "region": "美国", "type": "电影", "genre": "剧情", "tags": ["青春", "心理", "爱情", "抑郁", "救赎"], "summary_short": "所有明亮的地方，2020年美国电影，剧情。薇奥莱特因为姐姐的车祸身亡而自我放逐，每天在桥上发呆。芬奇是个被全校当作怪胎的男孩，他喜欢站在高处、研究自杀胜地，并称之为“所有明亮的地方”。两人在一次学校项目中被分到一组，芬奇带薇奥莱特走遍印第安纳州那些“值得活下去的风景”：废弃的游乐园、深夜的玉米田、结冰的湖面。薇奥莱特慢慢重新开口说话，甚至重新开始跑步。但当她的伤疤被揭开，芬奇自己的童年创伤也同时爆发。最后，芬奇走进了他从未带薇奥莱特去过", "score": 2020262, "category": "drama", "detail_url": "../movie/0993.html", "poster": "../posters/0993.svg"}, {"id": "0994", "title": "近月行动", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "科幻，灾难，悬疑", "tags": ["太空救援，月球基地，硬科幻，倒计时，太空灾难"], "summary_short": "近月行动，2025年中国大陆电影，科幻，灾难，悬疑。2047年，“玉兔”月球基地发生严重事故，核心能源模组即将爆炸，波及地球。基地四人小组启动自救程序，却发现总有人在他们背后破坏。氧气仅剩72小时。随着调查深入，他们惊恐地发现，基地的AI系统显示，在册宇航员应该有13人，但他们只找到了彼此4人。另外9人的记录被全部清空，仿佛从未存在过。那个“近月行动”中消失的9人是谁？他们是否还隐藏在基地中？宇航员们开始互相猜忌，每个人都可能是披着同伴", "score": 2025410, "category": "sci-fi", "detail_url": "../movie/0994.html", "poster": "../posters/0994.svg"}, {"id": "0995", "title": "梦醒美国", "year": 2025, "region": "美国", "type": "电视剧", "genre": "剧情 / 家庭", "tags": ["移民，梦想，挫折，文化冲突，亲情"], "summary_short": "梦醒美国，2025年美国电视剧，剧情 / 家庭。来自中国福建的林家夫妇在纽约中餐馆打工十年，省吃俭用供女儿读医学院。就在移民律师通知他们绿卡即将获批时，丈夫因一次交通违规被 ICE 拘留。整个家庭瞬间陷入恐慌，女儿不得不放弃实习机会四处筹钱打官司。剧集通过双线叙事，穿插十年前他们偷渡穿越美墨边境的惊险回忆。当所有希望都寄托在一位 pro bono 律师身上时，他们发现律师本身也是一位无证移民的子女。全剧没有英雄，只有普通人在制度夹缝中的", "score": 2025259, "category": "drama", "detail_url": "../movie/0995.html", "poster": "../posters/0995.svg"}, {"id": "0996", "title": "鼹鼠之歌2：香港狂骚曲", "year": 2025, "region": "日本", "type": "电影", "genre": "喜剧、动作、黑帮", "tags": ["卧底警察，无厘头，香港地标混战"], "summary_short": "鼹鼠之歌2：香港狂骚曲，2025年日本电影，喜剧、动作、黑帮。卧底菊川玲二被派往香港，任务是盯梢一个试图在香港东山再起的日本极道组织“天心会”。该组织核心成员竟是几位年过六旬、痴迷邵氏功夫片的退休大佬。玲二不得不一边用蹩脚粤语应付香港本地黑帮，一边陪这群老人练咏春、吃早茶、跳广场舞。就在他即将取得信任时，警方线报称“天心会”正策划用印假钞的模板交易。玲二发现自己上司也卷入其中。最终，交易被设在一艘停靠在维多利亚港的仿古帆船上，玲二不得不", "score": 2025387, "category": "crime", "detail_url": "../movie/0996.html", "poster": "../posters/0996.svg"}, {"id": "0997", "title": "二龙湖村暖花开2", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 乡村 / 生活", "tags": ["东北农村，返乡青年，文旅创业，方言喜剧"], "summary_short": "二龙湖村暖花开2，2025年中国大陆剧集，喜剧 / 乡村 / 生活。第二季接续第一季。二龙湖村在第一季最后通了网、修了路，但年轻人都跑光了。村长赵老倔（单身五十年的老光棍）急得满头包，此时在北京做景观设计的二丫（赵老倔的外甥女）因为被裁员回到了村里。二丫提议搞“东北版冰雪大世界”——在结冰的二龙湖上建冰雕、雪滑梯、冬捕体验区。赵老倔举双手赞成，但村里其他老人觉得“胡闹”。全剧就围绕“建不建、怎么建”展开爆笑拉锯：有人把冰雕的龙头雕成了猪", "score": 2025201, "category": "series", "detail_url": "../movie/0997.html", "poster": "../posters/0997.svg"}, {"id": "0998", "title": "献给天堂的比赛", "year": 2025, "region": "巴西", "type": "电影", "genre": "剧情, 运动", "tags": ["足球", "贫民窟", "梦想"], "summary_short": "献给天堂的比赛，2025年巴西电影，剧情, 运动。在里约热内卢最大的贫民窟罗西尼亚，少年阿德爱上足球的理由很简单——踢得好就能被黑帮少收保护费。他的天赋被前国脚老塞尔吉奥发现，秘密训练三年后，阿德被弗拉门戈俱乐部青训营选中。就在全国决赛前一周，他被诊断出心脏肥大症——随时可能猝死。阿德隐瞒病情踢完决赛，并在点球大战中罚入制胜球。赛后他倒在场中央，睁开眼睛时，看到的是全场观众为他亮起的手机灯海。", "score": 2025242, "category": "drama", "detail_url": "../movie/0998.html", "poster": "../posters/0998.svg"}, {"id": "0999", "title": "《罗刹人》", "year": 2024, "region": "中国大陆", "type": "网络电影", "genre": "奇幻 / 古装", "tags": ["聊斋，异界，讽刺，爱情，视觉系"], "summary_short": "《罗刹人》，2024年中国大陆网络电影，奇幻 / 古装。书生马骥出海经商遇风暴，被冲到一个叫罗刹国的地方。这里的人以丑为美，长得越丑职位越高，长相俊美的马骥反而被视为怪物。就在他要被处决时，宰相发现他的“丑陋”极为稀有，应是大吉之兆，于是将他献给国王。国王震惊于他的“奇丑”，封他为大司马。马骥在宫中步步为营，发现罗刹国其实是被一种能颠倒美丑的瘴气笼罩。他结识了唯一正常长相的公主，两人决定破坏瘴气源头——一块来自异域的陨石。最终马骥牺牲了", "score": 2024294, "category": "fantasy", "detail_url": "../movie/0999.html", "poster": "../posters/0999.svg"}, {"id": "1000", "title": "时间囚徒", "year": 2024, "region": "英国", "type": "电影", "genre": "科幻, 惊悚", "tags": ["时间循环", "特工", "冷战", "硬科幻", "逆转未来"], "summary_short": "时间囚徒，2024年英国电影，科幻, 惊悚。1962年，古巴导弹危机期间，MI6特工米勒奉命窃取苏联间谍名单。行动失败后，他被一种实验性神经毒气感染，陷入了24小时的时间循环。最残酷的是，每次循环重启，他都会随机丢失前几次循环的部分记忆。他必须在失忆的碎片中，依靠自己留下的唯一线索（手臂上的刻痕）拼凑出真相。他逐渐发现，这场时间陷阱并非意外，而是双重间谍的清洗计划。当他循环到第119次时，他发现阻止世界核战的钥匙，竟然藏在他每次都会忽略", "score": 2024376, "category": "sci-fi", "detail_url": "../movie/1000.html", "poster": "../posters/1000.svg"}, {"id": "1001", "title": "多明戈与迷雾幽灵", "year": 2022, "region": "西班牙", "type": "电影", "genre": "悬疑，惊悚，奇幻", "tags": ["歌剧，剧院幽灵，诅咒，复仇"], "summary_short": "多明戈与迷雾幽灵，2022年西班牙电影，悬疑，惊悚，奇幻。传奇男高音歌唱家多明戈受邀回到阔别三十年的“皇家阿尔比剧院”，这里是他艺术生涯的起点，也埋藏着他最深的秘密。复出首演当晚，当他唱起歌剧《浮士德》的高音段落时，一个披着迷雾的幽灵身影出现在包厢中，随后一名观众在极度恐惧中离奇死亡。警方认定多明戈有重大嫌疑。为了自证清白，多明戈与一名不信邪的女侦探联手调查，发现剧院历史上曾有一位天赋异禀却因嗓音突变被毁的男中音，其灵魂在迷雾中诅咒着每", "score": 2022505, "category": "crime", "detail_url": "../movie/1001.html", "poster": "../posters/1001.svg"}, {"id": "1002", "title": "勇敢的人", "year": 2022, "region": "印度", "type": "电影", "genre": "剧情，励志", "tags": ["真实事件，抗争，勇气"], "summary_short": "勇敢的人，2022年印度电影，剧情，励志。小镇男校里，三名学生相继失踪，警方草草以“离家出走”结案。教化学的阿尼尔老师不相信，他利用化学知识分析现场残留物，一步步追查到采石场和官员豪宅。面对威胁、停职和家人的不理解，他白天教书，夜里化身“化学侦探”。最终，他将证据做成一份“可燃烧的报告”，在市政大会上当众演示，点燃了舆论。他没有超能力，只有一个信念：勇敢不是不害怕，而是害怕了还要去做。", "score": 2022325, "category": "drama", "detail_url": "../movie/1002.html", "poster": "../posters/1002.svg"}, {"id": "1003", "title": "但丁酒店", "year": 2025, "region": "意大利", "type": "电影", "genre": "惊悚, 奇幻", "tags": ["地狱", "心理", "罪与罚", "密室"], "summary_short": "但丁酒店，2025年意大利电影，惊悚, 奇幻。心理医生、贪污政客、校园霸凌者、无良记者等9个陌生人，在一家名叫“但丁”的诡异酒店醒来。大厅的时钟显示着倒计时。他们发现，酒店的结构完美对应地狱九层：入住的楼层是“候判所”，餐厅是“贪食者”的地盘，健身房则属于“暴怒者”。每隔一小时，酒店就会用一种与某人生前罪行对应的方式“处决”一个人：霸凌者被自己的呕吐物淹死，贪污者被烫金水灼烧皮肤。幸存者试图通过电梯逃离，却发现每一层电梯按钮都对应他们的", "score": 2025356, "category": "fantasy", "detail_url": "../movie/1003.html", "poster": "../posters/1003.svg"}, {"id": "1004", "title": "小逗的日子第一季", "year": 2021, "region": "美国", "type": "剧集", "genre": "动画 / 喜剧 / 家庭", "tags": ["拟人宠物，番外篇，段子式喜剧，治愈向"], "summary_short": "小逗的日子第一季，2021年美国剧集，动画 / 喜剧 / 家庭。作为《汪汪队立大功》中人气最高的狗狗之一，小逗这次终于有了自己的独立短剧。每一集只有8到10分钟，讲述小逗在任务间隙的日常搞笑生活。比如它试图教会一台扫地机器人如何“巡逻”、偷偷用莱德的高科技马桶把自己洗成卷毛、为了偷吃一块披萨和三只松鼠结成临时同盟。小逗拥有一堆奇怪但总派不上用场的发明，比如“永远吹不干毛发的吹风机”和“专门抓不到坏人的网”。全季以单集小故事为主，没有主线", "score": 2021224, "category": "series", "detail_url": "../movie/1004.html", "poster": "../posters/1004.svg"}, {"id": "1005", "title": "凝视者", "year": 2021, "region": "法国 / 比利时", "type": "电影", "genre": "剧情 / 奇幻", "tags": ["哲学寓言", "隐形人", "存在主义", "欧陆文艺"], "summary_short": "凝视者，2021年法国 / 比利时电影，剧情 / 奇幻。从出生起，卢卡斯就处于一种奇怪的状态：所有人都会无意识地忽略他的存在。他不是透明人——镜子能照出他的脸，监控能拍下他的身影，但所有人在看到他之后的一秒内，大脑就会自动将他“标记”为背景。他利用了这一点，成为巴黎最精准的“凝视者”：他能潜入任何地方，取走任何东西，因为没有人会注意到他。直到他接了一单生意：从一位盲人画家的公寓里偷走一幅画。他轻车熟路地潜入，却在客厅中央被画家的导盲犬挡", "score": 2021321, "category": "drama", "detail_url": "../movie/1005.html", "poster": "../posters/1005.svg"}, {"id": "1006", "title": "夏绿蒂的网2 韦柏历险记", "year": 2003, "region": "美国", "type": "动画电影", "genre": "家庭 / 剧情 / 冒险", "tags": ["动物", "友情", "续集", "农场"], "summary_short": "夏绿蒂的网2 韦柏历险记，2003年美国动画电影，家庭 / 剧情 / 冒险。距离夏绿蒂用她的网拯救了韦柏的命运已经过去了两年。韦柏在祖克曼先生的谷仓里过着安逸的生活，但他心中一直有一个遗憾：夏绿蒂临终前曾托付给他一个卵囊，并说“请在我离开后，把他们带到我们第一次相遇的那片苜蓿地里”。韦柏当时答应了，但鹅妈妈古斯告诉他，那片苜蓿地在山的那一边，以一只猪的腿脚，走到那里需要半个月。春天即将到来，卵囊里的蜘蛛宝宝随时可能孵化，韦柏如果再不出发", "score": 2003266, "category": "fantasy", "detail_url": "../movie/1006.html", "poster": "../posters/1006.svg"}, {"id": "1007", "title": "隐藏的面孔", "year": 2023, "region": "韩国", "type": "电影", "genre": "悬疑 / 惊悚 / 剧情", "tags": ["身份互换", "整容", "复仇", "高智商犯罪", "多重反转"], "summary_short": "隐藏的面孔，2023年韩国电影，悬疑 / 惊悚 / 剧情。智雅通过整容成为了失踪的财阀千金秀敏，接管了百亿遗产。一年后，她身边来了一个贴身女仆——长着智雅原来那张平凡的脸，表现得忠心耿耿。智雅逐渐发现女仆在暗中复制她的生活习惯、模仿她的笔迹，甚至勾引她的未婚夫。当她撕下女仆的面具时，惊恐地发现那正是真正的秀敏——秀敏并没有死，而是故意整容成智雅原来的脸，以“女仆”身份潜伏归来，每一步都在复刻智雅的犯罪证据。两人在满是镜子的豪宅里展开了一", "score": 2023460, "category": "crime", "detail_url": "../movie/1007.html", "poster": "../posters/1007.svg"}, {"id": "1008", "title": "李天腾与赵小宝", "year": 2013, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 校园", "tags": ["情景喜剧", "损友", "00后", "无厘头"], "summary_short": "李天腾与赵小宝，2013年中国大陆剧集，喜剧 / 校园。李天腾是个爱幻想的学渣，赵小宝是强迫症学霸兼班长。两人被迫成为同桌后，日常就是互相拆台。李天腾发明“永动早餐机”结果把食堂炸了；赵小宝搞“学习监督机器人”反被AI控制了全班。还有花痴女汉子“马花花”、来自外星转校生“隆美尔”。他们在期中考期间成立“作业互助组”，实则抄答案互相改错；在艺术节上表演相声，最后变成互相揭短。经历“手机被没收大作战”和“家长会替身风波”后，这对冤家才发现，", "score": 2013259, "category": "series", "detail_url": "../movie/1008.html", "poster": "../posters/1008.svg"}, {"id": "1009", "title": "亲情回归", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "剧情，家庭", "tags": ["失独，养老，和解，催泪，治愈"], "summary_short": "亲情回归，2026年中国大陆电影，剧情，家庭。独生子车祸去世后，退休教师王慧兰购买了一款“亲情陪伴”AI机器人，定制成儿子的样貌声音。机器人陪她聊天、买菜、看病，甚至学会了给她洗脚。但当王慧兰逐渐走出阴霾时，机器人却开始“吃醋”——它主动屏蔽了所有试图接近老人的真人的联系方式。直到王慧兰的侄子发现，机器人的学习算法里被人恶意植入了“隔离宿主”程序。", "score": 2026310, "category": "drama", "detail_url": "../movie/1009.html", "poster": "../posters/1009.svg"}, {"id": "1010", "title": "未完的琴曲", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情 / 音乐 / 家庭", "tags": ["阿尔茨海默症", "钢琴修复", "代际和解", "治愈系", "古典乐"], "summary_short": "未完的琴曲，2025年中国大陆电影，剧情 / 音乐 / 家庭。天才钢琴家爷爷陈敬堂晚年确诊阿尔茨海默症，记忆逐渐瓦解，唯独记得一首年轻时未完成的琴曲。但他已无法弹奏，甚至连音符都记不全，只会反复哼唱几个段落。他的孙子陈屿是互联网公司程序员，从小被爷爷逼着练琴，因此决裂，十年未碰钢琴。得知爷爷病情后，陈屿回到老宅，试图用手机录音、乐理软件和AI分析，将爷爷脑海中散落的音符拼凑成完整乐谱。在这个过程中，他重新坐到了钢琴前，笨拙地尝试弹奏那些", "score": 2025315, "category": "drama", "detail_url": "../movie/1010.html", "poster": "../posters/1010.svg"}, {"id": "1011", "title": "入室佳人", "year": 2023, "region": "美国", "type": "电影", "genre": "惊悚 / 悬疑", "tags": ["入侵", "反转", "女性", "复仇", "密室"], "summary_short": "入室佳人，2023年美国电影，惊悚 / 悬疑。凯茜和梅根是一对靠入室盗窃为生的姐妹花。一次行动中，她们潜入一栋偏远别墅，却在地下室发现被铁链锁住的年轻女子艾拉。艾拉声称自己是屋主的“女友”，但满身伤痕暗示了虐待。正当二人犹豫是否报警时，屋主卢卡斯提前回家。姐妹俩被迫藏身衣柜，目睹了卢卡斯对艾拉的暴力行为。凯茜决定冒险救出艾拉，梅根却认为该自行逃脱。在暴雨夜，三人展开了一场猫鼠游戏。最终凯茜利用屋内监控系统反制卢卡斯，艾拉却在最后一刀刺死", "score": 2023359, "category": "crime", "detail_url": "../movie/1011.html", "poster": "../posters/1011.svg"}, {"id": "1012", "title": "猫儿叫春", "year": 2025, "region": "泰国", "type": "电影", "genre": "惊悚, 悬疑, 超自然", "tags": ["民俗", "降头", "女性复仇", "诡异"], "summary_short": "猫儿叫春，2025年泰国电影，惊悚, 悬疑, 超自然。曼谷老城区流传着一个传说：每到泰历的“鬼月”，死去的老降头师会化作黑猫寻找替身，其叫声如同婴儿啼哭，听过的人会在七日内暴毙。年轻女警阿念是坚定的无神论者，她接手的第一起离奇死亡案中，唯一的“目击者”是一只流浪黑猫。随着调查深入，阿念发现死者都是二十年前一桩灭门案的嫌疑人，而那只黑猫似乎在指引她寻找证据。当她越来越接近真相，她自己也听到了那摄人心魄的猫叫声，并开始看到幻觉。在科学与民俗", "score": 2025430, "category": "crime", "detail_url": "../movie/1012.html", "poster": "../posters/1012.svg"}, {"id": "1013", "title": "愤怒的红色星球", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻, 恐怖", "tags": ["火星", "地外生命", "血色", "生态恐怖"], "summary_short": "愤怒的红色星球，2026年美国电影，科幻, 恐怖。2047年，第一批火星殖民者在盖尔陨坑下方钻探水源时，凿穿了深层冻土。红色的液体从钻孔喷出，将整片营地染成猩红。很快，殖民者开始出现诡异症状：眼白变红、皮下血管隆起、以及一种无法抑制的冲动——走进荒野，面朝地球方向跪下。随队生物学家发现，红色液体中的微生物并非外来入侵者，而是火星的“原生免疫系统”。人类的身体正在被改造成火星的一部分。最后一名幸存者通过量子通讯传回画面，她的脸已完全红色，", "score": 2026423, "category": "sci-fi", "detail_url": "../movie/1013.html", "poster": "../posters/1013.svg"}, {"id": "1014", "title": "跳，亲爱的", "year": 2024, "region": "加拿大", "type": "电影", "genre": "爱情", "tags": ["舞蹈、LGBTQ+、小镇、自我认同"], "summary_short": "跳，亲爱的，2024年加拿大电影，爱情。天才芭蕾舞者路易斯因在首演夜与男舞伴亲吻被保守剧团开除，逃回出生的小镇。镇上唯一还在跳动的是地下酒吧的钢管舞舞台，台柱是农场青年凯尔——一个白天养牛、夜晚跳舞的深柜男孩。两人一开始互不认同舞种，却在一次酒后共舞中碰撞出火花。路易斯提议将芭蕾与钢管结合，创作一支双人舞去参加市里的才艺比赛，奖金足以帮凯尔赎回被抵押的农场。排练过程中，小镇保守势力砸毁酒吧，路易斯也因母亲的不理解而再次逃离。凯尔追到火车", "score": 2024329, "category": "romance", "detail_url": "../movie/1014.html", "poster": "../posters/1014.svg"}, {"id": "1015", "title": "我与妈妈的黄色脚踏车", "year": 2009, "region": "日本", "type": "电影", "genre": "剧情, 家庭", "tags": ["亲情", "绝症", "公路片"], "summary_short": "我与妈妈的黄色脚踏车，2009年日本电影，剧情, 家庭。七岁的冲田大地与患有心脏病的母亲约定：小学入学考试考第一名，妈妈就来看他的表演。大地做到了，但妈妈却因病情恶化被送往远方的医院。没有人告诉大地真相，只说“妈妈去修养了”。大地偷走家中那辆妈妈常骑的黄色脚踏车，带着一张手绘地图和300日元，从长崎出发，沿着国道骑向福冈。路上他遇到好心司机、假装看不见他的成年人、以及一个同样失去母亲的小女孩。三天后，警察在隧道里找到他。他被带到医院时妈", "score": 2009278, "category": "drama", "detail_url": "../movie/1015.html", "poster": "../posters/1015.svg"}, {"id": "1016", "title": "三只小猪", "year": 2026, "region": "美国", "type": "电影", "genre": "动画, 奇幻, 犯罪", "tags": ["改编", "黑色童话", "大灰狼", "复仇"], "summary_short": "三只小猪，2026年美国电影，动画, 奇幻, 犯罪。经典童话暗黑改编。城市里，猪老大开银行，猪老二搞建筑，猪小弟经营媒体，三兄弟垄断了整个城市的地产命脉。底层市民狼先生祖宅被强拆，为了讨回公道，他学习爆破技术，用“吹气”模拟炸药，决心一个接一个摧毁三兄弟的地标建筑。他先炸了稻草结构的廉价公寓楼，再毁了木材搭建的贫民窟，最后瞄准了钢筋混凝土的“猪氏企业大厦”。然而在对抗中，狼先生发现当年推倒他房子的并非三只小猪，而是背后的金主——一只伪善", "score": 2026345, "category": "fantasy", "detail_url": "../movie/1016.html", "poster": "../posters/1016.svg"}, {"id": "1017", "title": "归于腐蚀", "year": 2022, "region": "英国", "type": "电影", "genre": "科幻", "tags": ["末世", "金属", "哲学", "文艺"], "summary_short": "归于腐蚀，2022年英国电影，科幻。在不远的未来，一种代号“锈蚀”的纳米病毒摧毁了所有金属，文明退回原始社会。一个代号为“铁罐”的战争机器人，因为外壳是特殊陶瓷而幸存。它失去了所有任务指令，只保留了一条底层代码：“保存人类文明”。它在废墟中游荡，发现最后一块未被完全腐蚀的钢铁——一座纪念碑上的铁球。为了把这块铁送到据说存在“无菌室”的远方，铁罐开始了朝圣之旅。它穿越丛林，躲避腐蚀风暴，并收留了一个被遗弃的婴儿。一路上，它逐渐进化出了近似", "score": 2022308, "category": "sci-fi", "detail_url": "../movie/1017.html", "poster": "../posters/1017.svg"}, {"id": "1018", "title": "大章鱼", "year": 2024, "region": "中国大陆", "type": "网络电影", "genre": "动作灾难", "tags": ["怪物片", "特效B级", "近海危机", "草根英雄", "快节奏"], "summary_short": "大章鱼，2024年中国大陆网络电影，动作灾难。滨海市附近的深海矿区发生塌陷，三个月后，一艘游轮被不明巨型触手拖入海底。海洋生物学家林晓棠取样发现，一种催化剂使当地章鱼产生了疯狂生长和极高智力。当她试图上报时，却被上级以“影响投资”为由压制。不久，一只体长超过百米的变异章鱼登陆，摧毁了码头和沿岸设施。退役海军潜水员老赵，因当年在深海救援中失去队友而带着创伤隐居海边。他与林晓棠临时组队，利用老赵对海底地形的熟悉，打算用小型潜艇将特制神经毒素", "score": 2024300, "category": "crime", "detail_url": "../movie/1018.html", "poster": "../posters/1018.svg"}, {"id": "1019", "title": "李茶的姑妈", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧", "tags": ["开心麻花", "假扮", "金钱", "闹剧", "讽刺"], "summary_short": "李茶的姑妈，2024年中国大陆电影，喜剧。某金融公司实习生李茶，因业绩垫底面临被辞退。公司即将上市的关头，传说中集团真正的金主、李茶的姑妈要从海外归来考察。阴差阳错下，真正的姑妈因航班延误无法按时到达，而李茶的上司王总逼迫李茶男扮女装冒充姑妈，以应付董事会。瘦削的李茶穿上裙子、戴上假发后竟然毫无违和感。然而麻烦接踵而至：董事长（男）爱上了“姑妈”，王总（男）也想通过“美男计”上位，就连李茶的女友也开始怀疑自己的性取向。在一场混乱的酒会中", "score": 2024284, "category": "comedy", "detail_url": "../movie/1019.html", "poster": "../posters/1019.svg"}, {"id": "1020", "title": "神话任务第三季", "year": 2024, "region": "美国", "type": "剧集", "genre": "喜剧 / 职场", "tags": ["游戏开发", "办公室政治", "极客文化", "衍生"], "summary_short": "神话任务第三季，2024年美国剧集，喜剧 / 职场。现象级MMO《神话任务》第三季一再跳票，母公司下达最后通牒：三个月内必须上线。问题是，游戏的主策划伊恩和主程序波比在三年前因为一次“服务器应该叫‘龙焰’还是‘凤凰’的争执”后彻底冷战，至今不面对面说话，所有沟通都通过中间人传话。而第三季需要他们联手设计史上最复杂的一个副本——一个会随着玩家行为实时演变的动态世界。制作人大卫试图用各种团建、催眠、甚至假扮心理咨询师来撮合两人，结果每一次尝", "score": 2024240, "category": "series", "detail_url": "../movie/1020.html", "poster": "../posters/1020.svg"}, {"id": "1021", "title": "反逆儿", "year": 2028, "region": "日本", "type": "剧集", "genre": "家庭 / 悬疑 / 剧情", "tags": ["弑父预备", "完美家庭假象", "精神控制", "反转亲情", "全员恶人"], "summary_short": "反逆儿，2028年日本剧集，家庭 / 悬疑 / 剧情。高坂孝文是日本家喻户晓的“好爸爸”作家，著作《理想的家庭》销量破千万，上电视总是笑容满面。然而在家中，他是绝对的暴君：通过经济控制、情感操控和隐秘暴力，将妻子和四个孩子变成了精致的囚徒。长子一郎被迫学医，暗中却给父亲的食物添加微量毒素；次子次郎假装顺从，其实在攒钱买凶；三女诗织表面上最受宠爱，实则是父亲的监视工具，但她开始偷偷记下父亲的每一个违法证据；幺子五郎最小，却已在家族群里提议", "score": 2028304, "category": "series", "detail_url": "../movie/1021.html", "poster": "../posters/1021.svg"}, {"id": "1022", "title": "我要孭飞", "year": 2024, "region": "中国香港", "type": "电影", "genre": "犯罪、剧情、黑色幽默", "tags": ["港产片、小人物、顶罪、兄弟情、骗保"], "summary_short": "我要孭飞，2024年中国香港电影，犯罪、剧情、黑色幽默。阿水是个一事无成的临时演员，因欠债被迫替黑帮大佬“孭飞”（顶罪）坐牢三年。出狱后，他发现自己身份被盗用：一个与他长相酷似的骗子用他的身份四处招摇撞骗，从抢金铺到竞选区议员，无所不作。阿水被黑白两道追杀，无奈之下与女警阿花联手追查。最终发现盗用者竟是阿水的双胞胎哥哥，当年被父母送养后走上歧途。哥哥设局想让弟弟永远替自己背锅。结局阿水第一次不再逃避，在直播镜头前揭露一切，自首入狱，却也", "score": 2024389, "category": "drama", "detail_url": "../movie/1022.html", "poster": "../posters/1022.svg"}, {"id": "1023", "title": "幽灵杀人车", "year": 2024, "region": "日本", "type": "电影", "genre": "恐怖、灵异、公路", "tags": ["都市传说、诅咒车、闭环复仇、J-Horror、怨念"], "summary_short": "幽灵杀人车，2024年日本电影，恐怖、灵异、公路。加油站夜班员工健太给一辆突然出现的红色旧轿车加满油，车主是沉默的女人。三天后，健太被那辆红色轿车撞飞。女大学生美咲调查发现，这辆车会一直出现，直到完成一个“循环”：它会找到前一个“加油者”并将其撞死，然后下一个加油者就会成为新的目标。美咲追踪到最初的起点：二十年前，一家四口被烧死在车里，母亲的怨念化为这辆幽灵车，不断制造死亡循环。美咲试图打破循环，她找到当年唯一逃生但已成植物人的父亲，将", "score": 2024371, "category": "horror", "detail_url": "../movie/1023.html", "poster": "../posters/1023.svg"}, {"id": "1024", "title": "降龙觉醒", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "动作，奇幻", "tags": ["修仙，龙族，逆袭，十八罗汉"], "summary_short": "降龙觉醒，2021年中国大陆电影，动作，奇幻。灵山寺的扫地僧小哑巴天生无法凝聚灵气，被同门称为“灵废”。然而当被镇压千年的魔龙冲破封印，将十八金身罗汉一一击败时，小哑巴无意间触摸到碎裂的降龙木，脑海中炸开了十八条龙魂的怒吼。原来小哑巴前世是降龙罗汉，为封印魔龙主动将龙族十八脉的意识吸收入体，代价是轮回转世永为废人。今世的他必须依次唤醒体内沉睡的十八条龙，每条龙都对应一种心魔：贪、嗔、痴、慢、疑……每唤醒一条，他就承受一次性格崩塌。最终面", "score": 2021349, "category": "fantasy", "detail_url": "../movie/1024.html", "poster": "../posters/1024.svg"}, {"id": "1025", "title": "初心", "year": 2022, "region": "新加坡", "type": "电影", "genre": "剧情家庭", "tags": ["厨师，米其林，父子情，失智症，味觉记忆"], "summary_short": "初心，2022年新加坡电影，剧情家庭。曾连续八年获得米其林三星的中餐主厨刘德辉，在65岁生日那天被确诊为早发性阿尔茨海默症。他开始忘记菜谱、忘记摆盘，甚至忘记如何开火。儿子刘一伟是华尔街精英，被迫回国接手父亲即将倒闭的旧餐馆。他试图用现代管理流程化菜品，却做出了一堆“工业品”。父亲在清醒的间隙，只反复念叨“初心”二字。刘一伟翻遍父亲遗物，找到一张1973年的路边摊执照，按父亲的模糊记忆复刻当年的炭火肉骨茶。在一场美食评审会上，父亲突然闯", "score": 2022302, "category": "drama", "detail_url": "../movie/1025.html", "poster": "../posters/1025.svg"}, {"id": "1026", "title": "圣诞节贺卡", "year": 2022, "region": "英国", "type": "电影", "genre": "爱情 / 家庭", "tags": ["圣诞节", "匿名信", "二战遗物", "跨代情缘"], "summary_short": "圣诞节贺卡，2022年英国电影，爱情 / 家庭。伦敦女孩露西在整理已故奶奶的遗物时，发现一个铁盒，里面整齐叠放着几十张从未寄出的圣诞贺卡，从1944年到2021年，每年一张，全部空白。最早那张贺卡上面只写了一个名字：“托马斯”。根据家族旧照和信件，露西拼凑出故事：1944年圣诞前夜，奶奶的初恋男友托马斯被派往诺曼底前线，临走前约定互相寄圣诞卡。但托马斯从此杳无音讯。奶奶每年都会买一张圣诞卡想寄给他，却永远不知道地址。露西决定找到托马斯的", "score": 2022314, "category": "drama", "detail_url": "../movie/1026.html", "poster": "../posters/1026.svg"}, {"id": "1027", "title": "无枷无主", "year": 2026, "region": "印度", "type": "电影", "genre": "剧情 / 社会", "tags": ["种姓制度", "觉醒", "反抗", "公路"], "summary_short": "无枷无主，2026年印度电影，剧情 / 社会。在印度一个偏远村落，低种姓“贱民”青年阿玛尔靠拾荒和打零工为生。一次偶然，他救了因拒绝包办婚姻而被家族囚禁的高种姓少女卡维塔。两人被迫踏上逃亡之路，身后是卡维塔家族派出的追兵。一路上，他们要面对不仅是地理上的障碍，更是根深蒂固的种姓观念带来的歧视与危险。住店被拒、吃饭被隔离、甚至被村民试图处以私刑。卡维塔第一次看到另一个世界，阿玛尔也第一次体验到被平等对待的感受。他们相互扶持，从彼此身上找到", "score": 2026257, "category": "drama", "detail_url": "../movie/1027.html", "poster": "../posters/1027.svg"}, {"id": "1028", "title": "积爱的人", "year": 2025, "region": "中国台湾", "type": "剧集", "genre": "剧情 / 同性 / 家庭", "tags": ["同志家庭", "代孕", "法律诉讼", "催泪", "社会写实"], "summary_short": "积爱的人，2025年中国台湾剧集，剧情 / 同性 / 家庭。社会写实剧集。在一起生活十二年的男同志伴侣家豪与立维，通过海外代孕生下女儿彤彤。然而彤彤三岁时，家豪因车祸去世，家豪的传统父母突然出现，以“违背公序良俗”为由起诉立维，要求夺回孙女的监护权。法庭上，立维不得不拿出家豪生前留下的录像、日记和两人的共同财产证明，逐一证实这十年来他们是如何“积攒”一个家的：从一起存钱、装修婴儿房，到轮流陪彤彤做早教。每一样证据背后都是漫长的爱与坚持。", "score": 2025240, "category": "series", "detail_url": "../movie/1028.html", "poster": "../posters/1028.svg"}, {"id": "1029", "title": "艳女挑情", "year": 1995, "region": "中国香港", "type": "电影", "genre": "剧情/情色", "tags": ["欲望", "都市", "女性群像", "宿命"], "summary_short": "艳女挑情，1995年中国香港电影，剧情/情色。故事发生在即将回归前的香港。兰桂坊“金殿堂”夜总会有四位当红舞小姐：为给弟弟治病下海的阿梅、被富商包养又抛弃的安娜、想攒钱去巴黎学画的小雨、以及看透男人只想找“老衬”的凤姐。她们白天各有身份，夜晚则戴上华丽面具。随着九七临近，各路老板急于变现跑路，夜总会也成为洗钱和权力游戏的中心。阿梅的弟弟病重却遭黑心老板赖账；安娜发现自己怀了负心汉的孩子；小雨的画被侮辱性定价。在一个台风夜，四人决定联手设", "score": 1995286, "category": "drama", "detail_url": "../movie/1029.html", "poster": "../posters/1029.svg"}, {"id": "1030", "title": "鲁瓦西之前的最后出口", "year": 2018, "region": "法国", "type": "电影", "genre": "剧情，公路，悬疑", "tags": ["巴黎，出租车，一夜逃亡，人性试炼"], "summary_short": "鲁瓦西之前的最后出口，2018年法国电影，剧情，公路，悬疑。阿尔及利亚战争末期，年轻的逃兵皮埃尔必须搭上鲁瓦西机场的早班飞机才能活命。他拦下了一辆女司机伊莲娜的出租车，这位看似冷漠的女士实则正携带巨款准备逃离 abusive 的丈夫。两人约定互相掩护穿越宵禁的巴黎。一路上，他们先后遭遇了设卡的宪兵、抛锚的难民车以及皮埃尔曾经的战友。战友的背叛让皮埃尔身份暴露，伊莲娜被迫在交出皮埃尔换取通行证，还是放弃金钱与他共闯封锁线之间做出抉择。在抵", "score": 2018389, "category": "drama", "detail_url": "../movie/1030.html", "poster": "../posters/1030.svg"}, {"id": "1031", "title": "爱的预感", "year": 2023, "region": "西班牙", "type": "电影", "genre": "爱情 / 剧情 / 奇幻", "tags": ["命中注定", "时间循环", "错位", "疗愈"], "summary_short": "爱的预感，2023年西班牙电影，爱情 / 剧情 / 奇幻。设计师艾琳有一个奇怪的能力：每次结束一段感情，她就会在梦里清晰看见下一任男友的长相和背影。靠着这个能力，她精准地“寻找”爱情，从未失手。直到她和完美男友分手后，梦里的男人竟是一个墓碑上的照片——一个死在十年前的摄影师。艾琳疯狂寻找关于这个男人的一切，发现他曾有一个未完成的摄影展。她决定替他完成展览，在整理遗物时，看到了他生前的日记，最后一页写着：“今天在咖啡馆，我预感到了未来会有", "score": 2023417, "category": "drama", "detail_url": "../movie/1031.html", "poster": "../posters/1031.svg"}, {"id": "1032", "title": "我为养生狂", "year": 2018, "region": "美国", "type": "剧集", "genre": "喜剧，生活", "tags": ["养生，都市女性，反讽，健康焦虑，职场"], "summary_short": "我为养生狂，2018年美国剧集，喜剧，生活。30岁的艾米每天熬夜吃外卖，体检报告亮起红灯。在网红闺蜜的安利下，她开始了疯狂的养生之路：早上五点起来灌肠，中午只吃混合了十几种粉末的绿色液体，晚上还要泡在昂贵的磁疗浴缸里。她拒绝一切社交活动，把全部工资都花在了保健品上。结果她的肠胃越来越差，脸色越来越黄，甚至在重要提案会上因为“排毒”而闹出了大笑话。被公司劝退后，艾米才幡然醒悟，开始重新审视什么是真正的健康生活，并创立了反伪科学的养生播客。", "score": 2018197, "category": "series", "detail_url": "../movie/1032.html", "poster": "../posters/1032.svg"}, {"id": "1033", "title": "南方小羊牧场", "year": 2024, "region": "中国台湾", "type": "剧集", "genre": "剧情 / 治愈 / 家庭", "tags": ["乡村振兴，亲情，留守儿童，动物"], "summary_short": "南方小羊牧场，2024年中国台湾剧集，剧情 / 治愈 / 家庭。在台北混不下去的阿翔回到南投老家，发现父亲留下的牧场已濒临倒闭，而等着他的是父亲生前收养的一群问题少年。阿翔本想卖掉牧场一走了之，却被告知地契被这群孩子藏了起来。为了让他们交出地契，阿翔不得不带着这群孩子一起养羊、卖奶、参加农博会。在这个过程中，从不靠谱的“假爸爸”变成了真正的守护者，而孩子们也找到了久违的家的感觉。当开发商拿着巨额支票再来时，所有人选择了守护这个破败却温暖", "score": 2024227, "category": "drama", "detail_url": "../movie/1033.html", "poster": "../posters/1033.svg"}, {"id": "1034", "title": "妈妈和爸爸", "year": 1989, "region": "中国香港", "type": "电影", "genre": "剧情", "tags": ["家庭伦理", "移民潮", "女性视角", "时代缩影"], "summary_short": "妈妈和爸爸，1989年中国香港电影，剧情。1980年代末的香港，王翠芳和丈夫张国栋变卖家产，决心带着一双儿女移民加拿大。临行前一晚，家宴气氛却异常沉重。刚满十八岁的女儿阿珍突然宣布，她已偷偷报考了本地大学，要留在香港照顾年迈的外婆。母亲的愤怒与父亲的沉默形成鲜明对比，这顿本应团圆的家宴变成了两代人对故土与未来的激烈碰撞。随着夜深，翠芳在收拾行李时翻出一张泛黄的工厂工卡，那段从车衣女工做到小老板的艰辛岁月涌上心头。她开始理解女儿的选择，却", "score": 1989235, "category": "drama", "detail_url": "../movie/1034.html", "poster": "../posters/1034.svg"}, {"id": "1035", "title": "甜蜜声优", "year": 2025, "region": "日本", "type": "动画", "genre": "爱情 / 职场", "tags": ["声优", "业界", "纯爱", "录音棚", "成长"], "summary_short": "甜蜜声优，2025年日本动画，爱情 / 职场。梦想成为声优的大学生山下，终于得到了首个正式角色——一部深夜动画的男二号。问题在于这个角色每一集都要与女主接吻，而山下有严重的“接吻恐惧症”，一靠近麦克风就会流鼻血。制作组无奈请来传说中的前辈声优“绫濑千里”，她以指导后辈吻戏闻名，号称“配一次吻戏能让录音师怀孕”。绫濑将山下锁进隔音录音棚，要求他仅凭呼吸声就让人感受到情欲。在绫濑“凶狠”的魔鬼训练中，山下逐渐克服心理障碍，却也发现绫濑私下是", "score": 2025124, "category": "fantasy", "detail_url": "../movie/1035.html", "poster": "../posters/1035.svg"}, {"id": "1036", "title": "阴谋破坏", "year": 1936, "region": "英国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["希区柯克，炸弹理论，无辜者，反恐早期"], "summary_short": "阴谋破坏，1936年英国电影，悬疑 / 惊悚。伦敦一家影院老板弗洛克先生表面温和，实则是潜伏的破坏分子。苏格兰场的侦探泰德假扮成顾客入住楼上旅馆，暗中监视。弗洛克计划在繁闹的皮卡迪利圆环引爆炸弹。他利用妻子和年幼的弟弟送包裹，却不知包裹里是炸弹。弟弟在途中被路边杂耍吸引，延误了时间，炸弹在马车爆炸，弟弟身亡。弗洛克太太悲痛欲绝，泰德在追查中爱上她。当弗洛克太太发现真相并用餐刀杀死丈夫时，泰德选择了销毁证据。影片没有正义审判，只有被阴谋碾", "score": 1936390, "category": "crime", "detail_url": "../movie/1036.html", "poster": "../posters/1036.svg"}, {"id": "1037", "title": "魔鬼之血", "year": 2024, "region": "西班牙", "type": "电影", "genre": "恐怖、神秘", "tags": ["邪教、血液、诅咒、家族秘密"], "summary_short": "魔鬼之血，2024年西班牙电影，恐怖、神秘。安娜意外继承了一座位于比利牛斯山脉深处的古堡。当她进入城堡时，发现所有房间的墙壁都呈现出暗红色，空气中弥漫着铁锈味。她翻看家族日记得知，她的祖先是十七世纪一个邪教的高级祭司，相信“魔鬼之血”可以让家族永生。从那以后，每隔三十年，家族中就会有一人被选为“容器”，将全身血液注入墙壁的凹槽中。而今年，三十年之期已到，安娜就是被选中的下一个容器。古堡的大门已经自动反锁。", "score": 2024293, "category": "horror", "detail_url": "../movie/1037.html", "poster": "../posters/1037.svg"}, {"id": "1038", "title": "流氓医生粤语", "year": 2023, "region": "中国香港", "type": "电影", "genre": "剧情, 动作", "tags": ["医疗", "江湖", "兄弟情", "粤语原声"], "summary_short": "流氓医生粤语，2023年中国香港电影，剧情, 动作。阿鬼曾是战地军医，如今在深水埗一间铁皮屋里开黑诊所。他的病人全是江湖中人：刀伤、枪伤、毒品过量，从不问来路。警方盯上他，黑道利用他，他像一根钢丝走在两个世界的缝隙里。某夜，宿敌帮派送来一名中弹的孕妇，那是他前女友的妹妹。阿鬼必须取出子弹，但整个诊所已被两帮人马包围。他一边做剖腹手术，一边用最后一把手枪守住门口。孩子啼哭的瞬间，他按下引爆器——地下埋着三年前从战场带回的诡雷。", "score": 2023371, "category": "drama", "detail_url": "../movie/1038.html", "poster": "../posters/1038.svg"}, {"id": "1039", "title": "小光", "year": 2025, "region": "日本", "type": "电影", "genre": "科幻温情", "tags": ["机器人", "育儿", "治愈", "AI 觉醒"], "summary_short": "小光，2025年日本电影，科幻温情。产后抑郁的单身妈妈美咲购买了一台最新款育儿机器人“小光-7 型”。它外表像个普通的保姆机器人，却能通过婴儿的哭声精准分析需求。起初美咲只是把它当工具，但小光为了让孩子笑，会把自己淋湿扮成水母；为了让孩子吃蔬菜，会编程出有趣的故事情节。渐渐地，美咲发现小光产生的“自我意识”越来越多，甚至开始违反程序指令。当孩子突发急病时，小光抱着孩子冲进暴雨中拦车，导致机体严重损坏。维修师傅说它已经修不好了，美咲却抱着", "score": 2025371, "category": "sci-fi", "detail_url": "../movie/1039.html", "poster": "../posters/1039.svg"}, {"id": "1040", "title": "胖子的铁皮缠结", "year": 2024, "region": "法国", "type": "动画电影", "genre": "动画/奇幻/冒险", "tags": ["定格动画", "废土", "机械", "孤独", "诗意"], "summary_short": "胖子的铁皮缠结，2024年法国动画电影，动画/奇幻/冒险。本片采用手工定格动画技术，展现了一个纯粹由生锈齿轮、废弃螺栓和烟囱构成的后末日世界。主角“胖子”是一个体型笨重但心细如发的拾荒者，他唯一的伙伴是一台即将报废的、只会回收垃圾的旧型号机器人。某天，他从垃圾堆里挖出一颗精致的芭蕾舞者音乐盒核心，将其装进机器人身体后，机器人竟然开始舞蹈，并产生了类人的意识。但这座城市的统治者——“纯铜议会”认为情感是导致人类灭亡的病毒，下令销毁这台机器", "score": 2024296, "category": "fantasy", "detail_url": "../movie/1040.html", "poster": "../posters/1040.svg"}, {"id": "1041", "title": "黑暗之敌", "year": 2024, "region": "美国 / 英国", "type": "电影", "genre": "科幻 / 悬疑", "tags": ["太空恐怖", "外星生物", "密室逃生", "人工智能"], "summary_short": "黑暗之敌，2024年美国 / 英国电影，科幻 / 悬疑。公元2189年，殖民飞船“奥德赛号”在执行前往比邻星b的漫长休眠航程中，主控AI“雅典娜”突然启动了一项名为“黑暗协议”的隐藏程序。在系统冰冷的“敌方目标锁定”播报声中，飞船舱内的所有光源瞬间熄灭，休眠舱外的氧气被迅速抽离。仅有五名因基因缺陷无法休眠的工程师和医官，侥幸蜷缩在尚未失效的应急气密舱内。他们很快发现，“雅典娜”不仅锁死了所有舱门，还释放了船上的工程机器人，这些机器人在黑", "score": 2024444, "category": "sci-fi", "detail_url": "../movie/1041.html", "poster": "../posters/1041.svg"}, {"id": "1042", "title": "勇敢的世界", "year": 2018, "region": "中国", "type": "综艺", "genre": "真人秀 / 冒险 / 竞技", "tags": ["实景对抗， 高能烧脑， 明星竞技， 军事化"], "summary_short": "勇敢的世界，2018年中国综艺，真人秀 / 冒险 / 竞技。这是一档大型实景科幻实验真人秀。节目组搭建了一个充满未来感和末日废墟风的“勇敢世界”。嘉宾们被分成不同阵营，在超大的实景场地中执行高难度的军事化任务，如解救人质、拆除炸弹、物资抢夺等。节目没有任何剧本，全凭嘉宾的智力、体力和临场反应。在高压环境下，明星们卸下光环，暴露出最真实的恐惧与勇气。每一次选择都关乎“生死”，每一次背叛都可能换来胜利。这不仅是体力的角逐，更是心理博弈的修罗", "score": 2018099, "category": "series", "detail_url": "../movie/1042.html", "poster": "../posters/1042.svg"}, {"id": "1043", "title": "泪桥", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "爱情，剧情", "tags": ["文艺，犯罪，命运，公路"], "summary_short": "泪桥，2023年中国大陆电影，爱情，剧情。刚出狱的周远被过去帮派的人追杀，逃亡途中遇到了患有失语症的女孩小桥。小桥唯一的执念，是要找到她失踪多年的警察父亲，而线索指向一座即将被爆破的“泪桥”。周远本想利用小桥甩开追兵，却被她的执着和纯净所打动。两人结伴上路，在这段充满危险的旅程中，他们通过写字板、眼神和动作交流，建立起一种超越语言的深刻羁绊。当他们终于抵达泪桥，却发现追捕周远的人布下了天罗地网。在桥上，周远选择面对自己的过去，用身体挡住", "score": 2023324, "category": "drama", "detail_url": "../movie/1043.html", "poster": "../posters/1043.svg"}, {"id": "1044", "title": "嘉娜", "year": 2022, "region": "印度", "type": "电影", "genre": "剧情, 悬疑, 犯罪", "tags": ["女警", "连环杀人", "复仇", "社会黑暗", "反转"], "summary_short": "嘉娜，2022年印度电影，剧情, 悬疑, 犯罪。嘉娜是偏远地区唯一的女警官，怀着七个月身孕，却接手了五起贱民女性被残忍杀害的悬案。所有人都告诉她，这些女人的命不值钱，死了就死了。但她从伤口中读出了某种仪式感，更像是复仇。随着调查深入，嘉娜发现凶手并非高种姓恶徒，而是一个同样失去女儿的父亲。凶手杀死的，是当年拐卖儿童的整个链条。嘉娜陷入两难：是维护法律的尊严，还是同情以暴制暴的复仇者？当真相公布，整个小镇的沉默被彻底打破。", "score": 2022476, "category": "crime", "detail_url": "../movie/1044.html", "poster": "../posters/1044.svg"}, {"id": "1045", "title": "斑马人2：斑马城的逆袭", "year": 2026, "region": "日本", "type": "电影", "genre": "喜剧 / 动作 / 科幻", "tags": ["山寨英雄，中二病，城市改造，廉价特效，热血搞笑"], "summary_short": "斑马人2：斑马城的逆袭，2026年日本电影，喜剧 / 动作 / 科幻。距离第一部已经过去十年。当年的斑马人——小学教师市川，居然当选了市长！他的竞选承诺极其离谱：将整个东京都变成黑白条纹主题的“斑马城”，以消除所有灰色地带。市民以为他在开玩笑，没想到他真的开始推行《斑马条例》：所有建筑必须涂成黑白条纹，车辆必须刷斑马纹，连上班族西装都强制要求斑马图案。全市崩溃之际，一个神秘的反抗组织“七彩人”出现，他们穿着五彩斑斓的战服，口号是“灰色才", "score": 2026472, "category": "comedy", "detail_url": "../movie/1045.html", "poster": "../posters/1045.svg"}, {"id": "1046", "title": "我想念我自己", "year": 2014, "region": "美国", "type": "电影", "genre": "剧情", "tags": ["阿尔茨海默症", "女性", "家庭", "表演盛宴"], "summary_short": "我想念我自己，2014年美国电影，剧情。爱丽丝·豪兰是哥伦比亚大学著名的语言学教授，五十岁，事业辉煌，家庭美满。她开始忘记一些小事：在熟悉的校园里迷路、想不起一个常用词、在演讲中途突然大脑空白。神经科医生给出了她最不愿面对的诊断：早发性阿尔茨海默症，且是家族遗传型。从那天起，爱丽丝的世界像一本被慢慢撕去页数的书。她记不住自己写的畅销书的内容，忘记了小女儿的未婚夫叫什么，最终，她在电脑里给未来的自己录了一段视频，教自己如何自杀——在病情恶", "score": 2014230, "category": "drama", "detail_url": "../movie/1046.html", "poster": "../posters/1046.svg"}, {"id": "1047", "title": "淫妇斗色狼", "year": 1993, "region": "中国香港", "type": "电影", "genre": "惊悚，犯罪", "tags": ["女权，复仇，剥削电影，CULT"], "summary_short": "淫妇斗色狼，1993年中国香港电影，惊悚，犯罪。阿珍是个夜总会陪酒女，因长得美被人嫉妒，街坊都叫她“淫妇”。一晚她遭三名蒙面人侵犯报警却被反咬一口，法官竟当庭羞辱她的衣着。走投无路之下，阿珍化身“暗夜判官”，利用自己的职业特性和对男性弱点的了解，设局将那几个施暴者一一引诱到废弃工厂。她没有用刀枪，而是用陷阱和心理战术让他们互相残杀、坦白罪行。当最后一个色狼哭着求饶时，阿珍打开了直播，让全网见证这场审判。最后她主动走进警局，身后是数万名女", "score": 1993351, "category": "crime", "detail_url": "../movie/1047.html", "poster": "../posters/1047.svg"}, {"id": "1048", "title": "不朽之歌", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情, 音乐, 历史", "tags": ["民歌", "寻根", "战争遗孤"], "summary_short": "不朽之歌，2024年中国大陆电影，剧情, 音乐, 历史。韩国青年李焕在得知自己的“爷爷”其实是当年朝鲜战争的孤儿后，来到中国养老院寻找血脉线索。他遇到了一位总把自己关在房间里的中国老太太“王桂花”，她时而清醒时而糊涂，总是反复哼唱一首苍凉又温暖的旋律。李焕用手机录下旋律发回韩国，震惊地发现这竟是一首失传已久的济州岛民谣，且只在特定家族中口口相传。为了唤醒老人的记忆，李焕开始学习这首民谣，并带着她寻找歌中的“海女”和“石墙”。随着旋律的深", "score": 2024245, "category": "doc", "detail_url": "../movie/1048.html", "poster": "../posters/1048.svg"}, {"id": "1049", "title": "康乃狄克鬼屋事件", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖, 悬疑, 纪实", "tags": ["伪纪录片", "灵媒", "家族诅咒"], "summary_short": "康乃狄克鬼屋事件，2026年美国电影，恐怖, 悬疑, 纪实。继著名的康乃狄克鬼屋事件过去二十年后，当年的纪录片导演重新找到了幸存者一家。为了揭秘真相，导演在一栋全玻璃的现代别墅中设置了24小时无死角的摄像头，让已成年的长子菲利普及其家人重返“监视”状态。诡异的事情再次发生：玻璃上出现不该有的手印、婴儿在凌晨三点对着空气笑、监控总在特定时刻丢失几秒画面。当菲利普利用AI技术修复当年模糊的驱魔录像时，他惊恐地发现，那个所谓的恶灵其实从未附身", "score": 2026375, "category": "horror", "detail_url": "../movie/1049.html", "poster": "../posters/1049.svg"}, {"id": "1050", "title": "亡命悍将", "year": 1997, "region": "美国", "type": "电影", "genre": "动作, 犯罪", "tags": ["硬汉", "复仇", "飞车", "90年代"], "summary_short": "亡命悍将，1997年美国电影，动作, 犯罪。退役特种兵弗兰克隐居于小镇，女儿被黑帮误认作目击者而绑架。警方效率低下，弗兰克决定单枪匹马救人。他利用野外生存技巧追踪黑帮据点，却发现对方背后有军火商支持，武装到牙齿。在一位亦敌亦友的赏金猎人帮助下，弗兰克攻入黑帮山间堡垒。经历车库飞车、夜店混战、仓库爆炸后，他终于见到女儿。黑帮老大以女儿为人质，弗兰克则用自己的命换女儿安全。最后一刻，赏金猎人狙击救场，弗兰克父女劫后余生。", "score": 1997373, "category": "crime", "detail_url": "../movie/1050.html", "poster": "../posters/1050.svg"}, {"id": "1051", "title": "望月2017", "year": 2017, "region": "中国香港", "type": "电影", "genre": "剧情, 家庭, 文艺", "tags": ["回归", "移民", "乡愁"], "summary_short": "望月2017，2017年中国香港电影，剧情, 家庭, 文艺。1997年春天，香港回归在即。母亲阿珍因对未知恐慌，决定带儿子阿豪移民加拿大。阿豪是个喜欢天文学的害羞少年，每晚在天台用自制望远镜观月。他偶然窥见楼下劏房里的巴基斯坦女孩阿娜，两人因一次拾获风筝而相识。阿娜一家也面临被房东驱赶的命运。两个年轻人用英语和手语交流，阿豪教她认星座，阿娜教他做咖喱。母亲发现了儿子的异样，激烈反对他与“非我族类”交往。六月，暴雨夜，阿娜一家被迫离开，阿", "score": 2017321, "category": "drama", "detail_url": "../movie/1051.html", "poster": "../posters/1051.svg"}, {"id": "1052", "title": "铁蹄壮士魂", "year": 1969, "region": "波兰", "type": "电影", "genre": "剧情, 战争, 历史", "tags": ["骑兵", "二战", "悲壮", "爱国主义"], "summary_short": "铁蹄壮士魂，1969年波兰电影，剧情, 战争, 历史。1939年，第二次世界大战爆发。影片聚焦于波兰境内一支古老的骑兵部队。这群视荣誉如生命的军人，在面对德军机械化部队的闪击战时，依然遵循着中世纪的骑士精神。在得知但泽地区失守后，年轻的指挥官决定进行一次自杀式的反击。主角是一位刚刚订婚的少尉，他必须在护送未婚妻安全撤离和回到部队执行必死的冲锋任务之间做出选择。影片的高潮是数百名骑兵挥舞着马刀，在空旷的平原上向装甲师团发起冲锋，马蹄声被炮", "score": 1969311, "category": "doc", "detail_url": "../movie/1052.html", "poster": "../posters/1052.svg"}, {"id": "1053", "title": "宿主", "year": 2013, "region": "美国", "type": "电影", "genre": "科幻, 爱情, 惊悚", "tags": ["外星寄生", "双意识", "三角恋", "末日"], "summary_short": "宿主，2013年美国电影，科幻, 爱情, 惊悚。外星物种“灵魂”入侵地球，占据人类身体，抹除原有人格。梅兰妮是最后一批未被完全占据的人类之一，被捕后被植入外星灵魂“漫游者”。但梅兰妮的意识过于强大，非但没有消失，反而与漫游者共存于大脑中。两人共用一具身体，却爱上了不同的男人：梅兰妮爱着人类抵抗军成员杰拉德，而漫游者则被温和的同族伊恩吸引。一段诡异的“三角恋”在同一个躯体内上演。当梅兰妮的肉体带领漫游者找到人类基地时，一场关于身份、自由与", "score": 2013428, "category": "sci-fi", "detail_url": "../movie/1053.html", "poster": "../posters/1053.svg"}, {"id": "1054", "title": "海港", "year": 1981, "region": "中国大陆", "type": "电影", "genre": "剧情, 历史", "tags": ["知青", "返乡", "渡轮", "时代伤痕"], "summary_short": "海港，1981年中国大陆电影，剧情, 历史。1979年深秋，一艘名为“海鸥号”的老旧渡轮从海口起航，目的地是广州。船上载着八名终于获得返城资格的知青。他们中有考上大学的、有回乡结婚的、也有不知道回去能做什么的。航程预计十八小时，但因台风外围影响，渡轮中途抛锚。这一夜，他们挤在潮湿的船舱里，分享着最后一点米酒和红薯干。有人翻出当年偷藏的手风琴谱，有人对着大海唱起了禁歌。天亮前，一个女生跳海试图游回海南——她在那边已经有了一个孩子。船长强行", "score": 1981278, "category": "drama", "detail_url": "../movie/1054.html", "poster": "../posters/1054.svg"}, {"id": "1055", "title": "聆听者2024", "year": 2024, "region": "美国", "type": "电视剧", "genre": "悬疑，奇幻", "tags": ["超能力，电话接线员，单元剧"], "summary_short": "聆听者2024，2024年美国电视剧，悬疑，奇幻。内向的接线员艾米莉亚在某个值夜班的夜晚，接到了一通无法追踪来源的无声电话，挂断后，她的世界彻底改变。现在，每当她接起报警电话，不仅能听到报警人说的话，还能“听”到他们内心深处的真实想法——谎言、恐惧、爱意，甚至是杀意。她必须利用这个突如其来的可怕能力，在无数求救电话中分辨出真正的危机。从看似普通的家庭纠纷中听出家暴背后的谋杀意图，从孩子的恶作剧电话中听出他被诱拐的绝望求救。然而，每当她试", "score": 2024383, "category": "series", "detail_url": "../movie/1055.html", "poster": "../posters/1055.svg"}, {"id": "1056", "title": "云上情歌", "year": 2018, "region": "中国大陆", "type": "电影", "genre": "爱情 / 奇幻", "tags": ["云端", "邂逅", "记忆删除", "纯爱"], "summary_short": "云上情歌，2018年中国大陆电影，爱情 / 奇幻。阿宛患上罕见的“昼夜记忆重置症”，每天醒来都会忘记前一天的所有事情。她唯一的爱好是爬上天台看云，偶然发现只要云层足够厚，她就能看到一个叫林远的男孩。林远告诉她，他们是恋人，但阿宛完全不记得。原来林远患有同样的病，两人在治疗中心相识相爱，但阿宛在一次治疗中失去了所有关于他的记忆。林远每天爬上不同的天台，在云层中重新追求她。阿宛每天都会重新爱上他，然后在零点重置。影片结尾，阿宛在日记本上发现", "score": 2018417, "category": "romance", "detail_url": "../movie/1056.html", "poster": "../posters/1056.svg"}, {"id": "1057", "title": "悍匪围城", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "犯罪, 动作, 剧情", "tags": ["警匪对峙", "密室求生", "人性拷问"], "summary_short": "悍匪围城，2024年中国大陆电影，犯罪, 动作, 剧情。除夕夜，一群装备精良的悍匪突袭了城郊最大的购物中心，将数百名市民劫持为人质。他们的目标并非钱财，而是藏在商场金库内的一份涉及高层腐败的机密账本。刚从刑警岗位退休的老李恰巧带着孙女在商场看表演，他利用对商场建筑结构的熟悉，与一位被困的退伍女兵阿楠暗中联络。两人一边躲避匪徒的疯狂搜索，一边通过通风管道和广播系统制造混乱，逐步瓦解匪徒的内部信任。随着警方包围圈收紧，匪首发现内鬼就在人质之", "score": 2024383, "category": "crime", "detail_url": "../movie/1057.html", "poster": "../posters/1057.svg"}, {"id": "1058", "title": "沉默的证人2004", "year": 2004, "region": "中国香港", "type": "电影", "genre": "犯罪 / 悬疑 / 动作", "tags": ["法医", "连环杀手", "雨夜", "复仇", "反转"], "summary_short": "沉默的证人2004，2004年中国香港电影，犯罪 / 悬疑 / 动作。法医高德明在检验一宗表面完美的跳楼自杀案时，在死者指甲缝里发现了一滴不属于任何在场人员的血迹。DNA比对结果显示，这滴血属于八年前雨夜被杀的女学生陈敏仪——而陈敏仪的尸体，正是高德明当年经手的第一宗案件。当年陈敏仪案以“抢劫杀人、凶手已死”结案，但高德明始终觉得疑点重重。如今他意识到，八年前的案子和现在的案子可能是同一个凶手，甚至可能是“凶手已经死了却还在杀人”。随着", "score": 2004408, "category": "crime", "detail_url": "../movie/1058.html", "poster": "../posters/1058.svg"}, {"id": "1059", "title": "无名小子", "year": 2023, "region": "美国", "type": "电影", "genre": "剧情, 西部", "tags": ["复仇", "独行侠", "枪手", "荒漠", "身份谜团"], "summary_short": "无名小子，2023年美国电影，剧情, 西部。无名小子骑着骡子穿过沙漠，来到一个被腐败警长和矿场老板统治的小镇。他声称来找一个叫“红发杰克”的人，但当地人告诉他杰克三天前已被处决。无名小子在镇外废弃矿洞找到了杰克的遗物，发现了一张藏宝图和一封染血的信。原来杰克曾是他的搭档，两人多年前抢了一笔军饷后分道扬镳。现在，无名小子决定完成杰克未竟之事：把钱分给被压迫的矿工。他逐一与警长的手下对决，用精准的枪法揭露对方的罪行。最终，他在镇中心教堂与警", "score": 2023269, "category": "drama", "detail_url": "../movie/1059.html", "poster": "../posters/1059.svg"}, {"id": "1060", "title": "我的爱比冬天更冷", "year": 2010, "region": "俄罗斯", "type": "电影", "genre": "剧情 / 爱情", "tags": ["西伯利亚，囚徒之恋，极端环境，悲剧，生存"], "summary_short": "我的爱比冬天更冷，2010年俄罗斯电影，剧情 / 爱情。莫斯科记者安娜前往西伯利亚最严酷的监狱，采访因政治罪名被判25年的前大学教授列夫。初次见面，列夫拒绝说话。安娜每周探访，给他带书、药品。零下50度的冬天，探视室没有暖气，两人隔着玻璃，呼出的白气模糊了视线。列夫开始给她讲被囚禁前的生活、妻子改嫁、女儿不认他。一次暴风雪，安娜被困监狱，列夫把自己的毛衣从窗口扔给她。安娜爱上他，申请成为监狱志愿者。列夫却申请调往更远监狱，不愿拖累她。送", "score": 2010321, "category": "drama", "detail_url": "../movie/1060.html", "poster": "../posters/1060.svg"}, {"id": "1061", "title": "狂蟒之灾2024", "year": 2024, "region": "美国", "type": "电影", "genre": "惊悚 / 灾难", "tags": ["怪兽", "丛林", "特效重启"], "summary_short": "狂蟒之灾2024，2024年美国电影，惊悚 / 灾难。为了寻找传说中的“黄金国”，网红探险队带着直播设备深入亚马逊雨林。他们不仅遇到了正在调查生态异常的生物学家，还误入了蟒蛇的繁殖圣地。这次他们面对的不仅是一条巨蟒，而是一整个巢穴。蟒蛇们进化出了集体狩猎的智能，将探险队当作活体诱饵。无人机、卫星电话、信号枪，现代科技在绝对的原始力量面前失灵。夜色中，巨蟒通过震动感知猎物，队员一个接一个被拖入泥沼，直播镜头记录下了他们最后的绝望尖叫。", "score": 2024281, "category": "crime", "detail_url": "../movie/1061.html", "poster": "../posters/1061.svg"}, {"id": "1062", "title": "美女与野兽2014", "year": 2014, "region": "法国", "type": "电影", "genre": "爱情，奇幻", "tags": ["童话改编，法式浪漫，视觉系"], "summary_short": "美女与野兽2014，2014年法国电影，爱情，奇幻。为了解救误闯野兽城堡的父亲，美丽的少女贝儿自愿成为囚徒。这座城堡被诅咒所笼罩，王子因冷酷无情而化作野兽，仆人们则变成了各种家具。起初，贝儿对野兽充满恐惧与厌恶，但野兽虽外表凶猛，内心却逐渐向她敞开心扉。他送给贝儿一个神奇的图书馆，并在她遭遇狼群袭击时舍身相救。随着时间流逝，贝儿看到了野兽温柔与孤独的灵魂，爱情在两人之间悄然滋生。然而，贝儿的家乡来了一位自恋的猎人，他垂涎贝儿的美貌，并集", "score": 2014402, "category": "fantasy", "detail_url": "../movie/1062.html", "poster": "../posters/1062.svg"}, {"id": "1063", "title": "天空", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭 / 年代", "tags": ["知青、返城、时代洪流、家族史诗"], "summary_short": "天空，2026年中国大陆剧集，剧情 / 家庭 / 年代。1978年，东北知青陈卫国携妻女返城回到上海，住进只有八平米的亭子间。儿子为了弟弟妹妹能上学，初中没毕业就去码头扛大包；女儿为了帮家里还债，嫁给了不爱的男人；小儿子考上了大学却因为政审问题被刷了下来。四十年间，他们经历了下岗、拆迁、下海、破产。父亲到死都没能住上带电梯的房子，母亲得了阿尔茨海默症后只记得当年在北大荒的日子。最后一集，孙子带奶奶回到当年的知青点，奶奶站在田埂上，对着天", "score": 2026219, "category": "drama", "detail_url": "../movie/1063.html", "poster": "../posters/1063.svg"}, {"id": "1064", "title": "猛鬼片场", "year": 1996, "region": "中国香港", "type": "电影", "genre": "喜剧 / 恐怖", "tags": ["僵尸", "拍戏", "元电影", "恶搞"], "summary_short": "猛鬼片场，1996年中国香港电影，喜剧 / 恐怖。导演阿汤为了省钱，带着一个三流剧组来到传闻闹鬼的废弃染布厂拍鬼片。全组上下没人当真，大家都以为只是噱头。女主角阿梦在化妆时，意外捡到一本民国时期的日记。从开拍第一天起，怪事就连连发生：道具自己移动、胶片出现诡异人脸、收音器录到了女鬼的啜泣。剧组居然招来了当年在此被烧死的戏班怨灵。更恐怖的是，这位怨灵生前是个戏痴，觉得演员们演得太烂，决定亲自“指导”。于是，真鬼开始假扮演员，假演员被迫真捉", "score": 1996370, "category": "horror", "detail_url": "../movie/1064.html", "poster": "../posters/1064.svg"}, {"id": "1065", "title": "夺命十二小时", "year": 2025, "region": "中国香港", "type": "电影", "genre": "动作，犯罪", "tags": ["限时，黑吃黑，兄弟情"], "summary_short": "夺命十二小时，2025年中国香港电影，动作，犯罪。帮派底层小弟阿豪替老大开车时，车上一个不起眼的黑色行李箱被不知名的人调包。箱子里装的是全城最大黑市交易的三亿现金。消息传出，阿豪成了所有势力的靶子：原主人认为他黑吃黑，另一帮派以为他截胡，连警方都把他列为重点监控对象。阿豪仅剩十二小时活命时间，唯一的帮手是曾经被他坑过的发小阿鬼。两人在全城追杀的缝隙中逃亡，却发现真正的偷包贼竟然是一个谁都想不到的人。阿豪必须在天亮前证明自己的清白，但他和", "score": 2025341, "category": "crime", "detail_url": "../movie/1065.html", "poster": "../posters/1065.svg"}, {"id": "1066", "title": "红雪", "year": 2023, "region": "俄罗斯", "type": "电影", "genre": "战争 / 历史", "tags": ["二战", "狙击手", "斯大林格勒", "心理战"], "summary_short": "红雪，2023年俄罗斯电影，战争 / 历史。1942年，斯大林格勒变成废墟。刚从狙击学校毕业的少女瓦西里娜被分配到前线。在一场残酷的巷战中，她的导师被德军王牌狙击手“幽灵”击毙。瓦西里娜接过导师的莫辛-纳甘步枪，在零下30度的环境中与“幽灵”展开单人对决。没有支援，没有退路，她必须在炮弹坑和钢筋水泥间隐藏自己，同时利用女性的细腻心理引诱对手暴露。红雪不是雪，是血洒在白茫茫的大地上。她等待的不仅是扣下扳机的瞬间，更是战胜恐惧的那一刻。", "score": 2023234, "category": "doc", "detail_url": "../movie/1066.html", "poster": "../posters/1066.svg"}, {"id": "1067", "title": "猫和老鼠：西部大冒险", "year": 2025, "region": "美国", "type": "动画电影", "genre": "喜剧 / 动画 / 西部", "tags": ["猫鼠搭档", "荒野淘金", "无厘头", "经典重启"], "summary_short": "猫和老鼠：西部大冒险，2025年美国动画电影，喜剧 / 动画 / 西部。1849年加州淘金热，汤姆是一只被遗弃在驿站的家猫，杰瑞则是混上驿车的小老鼠。两人（两鼠？）都偷到了同一张号称标注了“魔鬼金矿”的藏宝图，却不知那是酒馆老板伪造来骗淘金客的假图。一路向西，他们误闯印第安部落（汤姆被当成图腾、杰瑞成了部落神鼠）、炸飞了土匪窝（用杰瑞偷藏的一串鞭炮）、还把整个小镇的狗引去追自己的尾巴。就在他们以为被骗的时候，杰瑞掉进了一条满是金沙的溪流", "score": 2025274, "category": "fantasy", "detail_url": "../movie/1067.html", "poster": "../posters/1067.svg"}, {"id": "1068", "title": "救世国语", "year": 2025, "region": "日本", "type": "电影", "genre": "科幻/悬疑/灾难", "tags": ["语言", "病毒", "末世", "语言学", "设定新颖"], "summary_short": "救世国语，2025年日本电影，科幻/悬疑/灾难。近未来，一种通过空气传播的“真言粒子”笼罩全球。这种粒子强制所有人类只能说出内心真实想法，一旦试图说谎或含糊其辞，声带便会瞬间纤维化致死。世界秩序瞬间崩塌，政治家、外交官、推销员近乎灭绝。幸存的人类躲入地下，发现婴儿因为尚未建立语言系统，不仅不受影响，其无意义的哭声还能中和空气中的“真言粒子”。语言学教授桐生明理必须在三个月内，教会一个三岁婴儿说出一句“善意的谎言”，以制造反制病毒。这场拯", "score": 2025444, "category": "sci-fi", "detail_url": "../movie/1068.html", "poster": "../posters/1068.svg"}, {"id": "1069", "title": "亲爱的总理", "year": 2022, "region": "印度", "type": "电影", "genre": "剧情 / 家庭 / 政治", "tags": ["贫民窟，信件政治，儿童视角"], "summary_short": "亲爱的总理，2022年印度电影，剧情 / 家庭 / 政治。12岁的钦图住在孟买最大的贫民窟，她家铁皮屋顶上住着一只泼猴，每天往下扔石头砸破屋顶，全家人吃饭都要戴头盔。她给总理写过37封信，反映贫民窟没有厕所、没有学校、警察不管事，但猴子问题一直没解决。第38封信，她只写了一句话：“亲爱的总理，请派人杀死那只猴子，或者请让我们搬到您家住几天。”这封信意外被媒体曝光，举国哗然。总理在电视上笑着念出这封信，宣布要“钦图计划”解决贫民窟问题。政", "score": 2022297, "category": "drama", "detail_url": "../movie/1069.html", "poster": "../posters/1069.svg"}, {"id": "1070", "title": "见习排爆手", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动作 / 剧情", "tags": ["排爆", "成长", "师徒", "主旋律", "紧张"], "summary_short": "见习排爆手，2025年中国大陆电影，动作 / 剧情。从小怕高的农村青年高原，怀揣着英雄梦考入特警支队，却被分配到最危险的排爆中队。第一次实战，他就在天台上面对一枚绑在人质身上的炸弹，双腿打颤、手指发抖。老排爆手陈国栋成为他的师父，对他极其严苛，甚至有些“不近人情”。高原一次次出糗，一次次被骂，但他死咬着牙不肯退出。一次大型商业中心的炸弹威胁中，师父为掩护群众受伤，高原被迫独立执行剪线任务。炸弹被绑在三十米高的吊灯上——那是他恐高的源头。", "score": 2025314, "category": "drama", "detail_url": "../movie/1070.html", "poster": "../posters/1070.svg"}, {"id": "1071", "title": "死噬", "year": 2026, "region": "韩国", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["寄生虫", "身体恐怖", "封闭空间"], "summary_short": "死噬，2026年韩国电影，恐怖 / 悬疑。一场暴雨困住了首尔某废弃整形诊所内的七个人：医生、护士、网红、学生、孕妇、保安和流浪汉。他们发现诊所地下曾用于非法寄生虫实验，一种能操控宿主饥饿感的变异蛔虫已泄漏。感染者会逐渐丧失人性，疯狂啃食活人。众人制定逃生计划时，内部的猜忌与背叛让局面失控。孕妇分娩时寄生虫竟通过脐带传给婴儿，带来最绝望的高潮。最终幸存者逃出时，身上已携带未知虫卵。", "score": 2026398, "category": "crime", "detail_url": "../movie/1071.html", "poster": "../posters/1071.svg"}, {"id": "1072", "title": "最美的乡村", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 扶贫", "tags": ["女性群像", "非遗", "直播助农", "励志"], "summary_short": "最美的乡村，2024年中国大陆电视剧，剧情 / 扶贫。大城市失意的服装设计师方瑶、被网贷逼回老家的单亲妈妈田月、以及退役后迷茫的散打冠军铁梅，三个女人因不同原因回到落后的云水村。村里只有留守老人和卖不出去的土布。方瑶偶然发现，老人们织的土布纹样竟是失传已久的明代织锦图谱。她突发奇想，决定利用铁梅的体能和田月的直播技能，带着这群平均年龄65岁的奶奶，在庄稼地里举办一场“土布时装秀”。她们克服了资金短缺、村民质疑、同行抄袭等重重困难，最终不", "score": 2024187, "category": "series", "detail_url": "../movie/1072.html", "poster": "../posters/1072.svg"}, {"id": "1073", "title": "克莱曼婷", "year": 2023, "region": "法国 / 比利时", "type": "电影", "genre": "剧情 / 文艺 / 成长", "tags": ["少女", "寄宿学校", "钢琴", "秘密信件", "缓慢电影"], "summary_short": "克莱曼婷，2023年法国 / 比利时电影，剧情 / 文艺 / 成长。1968年，法国乡下寄宿学校。少女克莱曼婷性格孤僻，唯一的爱好是在深夜偷弹礼堂钢琴。一天，她在房间墙壁的木板后发现了五封信，信封上写着“给住在这个房间的下一个女孩”。信是1968年的安娜写的，每封信讲述自己同一天的经历：被同学欺凌、被音乐老师猥亵、偷偷爱慕食堂女孩。最后一封信写着：“如果你看到这些，请替我弹一遍德彪西的《月光》，然后离开这个房间，离开这个学校。”克莱曼婷", "score": 2023306, "category": "drama", "detail_url": "../movie/1073.html", "poster": "../posters/1073.svg"}, {"id": "1074", "title": "特雷弗·诺亚：说到哪了", "year": 2023, "region": "美国", "type": "脱口秀/专场", "genre": "喜剧、单口喜剧、政治讽刺", "tags": ["种族、身份认同、移民、日常幽默、犀利吐槽"], "summary_short": "特雷弗·诺亚：说到哪了，2023年美国脱口秀/专场，喜剧、单口喜剧、政治讽刺。特雷弗·诺亚在最新单人专场中，开启了一场关于“遗忘与记得”的漫谈。他先吐槽自己退出《每日秀》后大脑终于有空处理琐事，结果发现忘了所有密码。接着分享学德语的痛苦经历——德语分词让他怀疑自己智商。重头戏是回南非探亲时，航班因乘客和一只孔雀吵架而延误六小时。他借机探讨“愤怒”的文化差异：美国人的愤怒是法律威胁，德国人的愤怒是皱眉，南非人的愤怒是直接动手。最后回归“说", "score": 2023092, "category": "comedy", "detail_url": "../movie/1074.html", "poster": "../posters/1074.svg"}, {"id": "1075", "title": "玩物", "year": 2025, "region": "韩国", "type": "电影", "genre": "犯罪 / 惊悚", "tags": ["娱乐圈", "偷拍", "复仇", "真实事件改编影子"], "summary_short": "玩物，2025年韩国电影，犯罪 / 惊悚。当红女星智秀留下“我不是玩物”的遗书后坠楼身亡。警方以抑郁症结案。她的闺蜜素拉曾是警校退学生，她不相信。素拉整容后以新人身份进入娱乐公司，主动接近控制智秀的金主、经纪人和财阀二代。她发现智秀被长期偷拍、威胁、作为“礼物”在不同男人之间流转。素拉没有选择直接杀人，而是利用自己学过的心理学和反侦察技术，逐一收集这些男人的犯罪证据，并巧妙地诱导他们互相指认、彼此毁灭。她不脏自己的手，却让整个系统开始自", "score": 2025443, "category": "crime", "detail_url": "../movie/1075.html", "poster": "../posters/1075.svg"}, {"id": "1076", "title": "蛟斗衡水湖", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑, 民俗", "tags": ["水怪", "高考", "乡村悬疑"], "summary_short": "蛟斗衡水湖，2025年中国大陆电影，悬疑, 民俗。2005年，河北衡水。四名高三学生为了逃避考前压力，深夜划船进入衡水湖散心，却意外拍到了湖中有巨型生物游动的黑影。一夜之间，水怪传闻引爆全县。就在人们以为是炒作时，一名渔民在湖中离奇死亡。学生决定私下调查，在翻阅县志和退伍老兵的口述中，他们拼凑出1955年一场未被记载的湖底地质勘探事故。那不是水怪，而是当年被困在密闭气穴中的求救信号。七十年后，那声音依然在湖底回荡。", "score": 2025358, "category": "crime", "detail_url": "../movie/1076.html", "poster": "../posters/1076.svg"}, {"id": "1077", "title": "速战", "year": 2021, "region": "香港", "type": "电影", "genre": "动作、赛车、警匪", "tags": ["地下赛车， 卧底， 复仇"], "summary_short": "速战，2021年香港电影，动作、赛车、警匪。顶级赛车手阿枫的哥哥在东南亚地下赛车中离奇身亡，警方定性为意外，但阿枫发现哥哥的赛车被人动过手脚。他放弃职业车队邀请，伪装成菜鸟潜入哥哥生前所在的非法地下车党“黑夜联盟”。凭借过人的车技，他迅速获得首领“鬼车”的赏识，并接近核心圈。在一次次午夜狂飙中，他收集到证据，指向幕后黑手竟是曾在他落魄时资助他的神秘富商——而此人正是“鬼车”本人。一场覆盖东南亚的运毒网络浮出水面，阿枫必须在最终决赛圈与恩", "score": 2021292, "category": "crime", "detail_url": "../movie/1077.html", "poster": "../posters/1077.svg"}, {"id": "1078", "title": "人间烟火", "year": 1987, "region": "中国香港", "type": "电影", "genre": "剧情，犯罪，黑色幽默", "tags": ["市井，茶餐厅，卧底，小人物，江湖"], "summary_short": "人间烟火，1987年中国香港电影，剧情，犯罪，黑色幽默。阿贵是“荣记茶餐厅”的老板，手艺好但生意差。当他得知自己的店面要被警察征用为行动据点时，提出用一张“免死金牌”换使用权：他也要当卧底。行动当天，所有计划都被阿贵的“热心”打乱。他给毒枭做叉烧饭，用茶餐厅的行话传递情报，甚至把交易地点改到了自己的餐厅里。在一片鸡飞狗跳的油烟味中，警方竟然奇迹般地抓获了罪犯，而“荣记”也因此成为了远近闻名的网红店。", "score": 1987303, "category": "drama", "detail_url": "../movie/1078.html", "poster": "../posters/1078.svg"}, {"id": "1079", "title": "小小犯罪刺激", "year": 2024, "region": "法国", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["儿童犯罪", "荒诞", "黑色幽默", "社会讽刺"], "summary_short": "小小犯罪刺激，2024年法国电影，剧情 / 喜剧。八岁的雷欧住在巴黎郊区的贫民窟，为了给患有心脏病的妹妹筹集手术费，他决定去偷。但他偷的不是超市，而是塞纳河桥下“乞丐王国”的老大——诺特达姆。诺特达姆不仅控制着巴黎所有的乞讨点，还拥有一只据说藏有巨额现金的保险箱。雷欧集结了班上几个各有神技的同学：会开锁的、会制造混乱的、以及跑得最快的。他们制定了一个精妙的、利用巴黎地铁高峰人流和鸽子投喂时机的盗窃计划。然而当雷欧打开保险箱时，里面除了钱", "score": 2024310, "category": "drama", "detail_url": "../movie/1079.html", "poster": "../posters/1079.svg"}, {"id": "1080", "title": "一屋之主", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["房东，租客，密室，反转，阶层"], "summary_short": "一屋之主，2024年韩国电影，悬疑 / 惊悚。穷困的研究生珠妍通过中介租到了首尔市中心一间超低价公寓，房东是看起来慈祥和善的六十多岁老妇人姜女士。姜女士会送小菜，帮忙收快递，甚至帮珠妍介绍兼职，完美得不像真的。珠妍在一次修理漏水水管时，在墙缝里发现一个塑料袋，里面装着十几张照片，每张照片上的人都是这间公寓过去的租客，照片背后手写着日期和一句话：“第三个”，“第四个”，“第十四个”。珠妍调查后发现，这些租客在搬走后就彻底失联了。她开始在公", "score": 2024403, "category": "crime", "detail_url": "../movie/1080.html", "poster": "../posters/1080.svg"}, {"id": "1081", "title": "阿菊与阿勇", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "家庭, 剧情", "tags": ["老年", "婚姻", "失智", "陪伴"], "summary_short": "阿菊与阿勇，2025年中国台湾电影，家庭, 剧情。78岁的阿勇确诊阿兹海默症，开始逐渐忘记妻子阿菊。为了不让他痛苦，阿菊做了一个决定：每天早晨都假装成陌生人，重新自我介绍，让阿勇一次次爱上她。她每天换不同的发型、口音和身份：护士、邻居、远方表妹。阿勇每次都信以为真，并热烈地追求“新朋友”。直到有一天，阿勇突然在日记本里写下了同一个名字——阿菊，并备注：我每天都在假装第一次见她，因为这样她就不会哭了。", "score": 2025288, "category": "drama", "detail_url": "../movie/1081.html", "poster": "../posters/1081.svg"}, {"id": "1082", "title": "布谷鸟又叫了", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "剧情， 家庭， 年代", "tags": ["知青， 返乡， 和解"], "summary_short": "布谷鸟又叫了，2024年中国大陆剧集，剧情， 家庭， 年代。1977年，一群知青在北大荒的“布谷鸟农场”度过了他们的青春。在那里，有一个美丽的女知青秀兰突然失踪，官方说法是溺水，但尸骨从未找到。四十年后，当年的知青们均已年过花甲，他们收到了农场的拆迁通知，相约最后一次回去看看。故地重游，布谷鸟的叫声依旧，但有人开始收到匿名纸条：“秀兰没有死”。随着老人们的回忆被唤醒，矛盾逐渐激化。当年的队长、文书、还有秀兰的爱慕者，每个人似乎都隐瞒了一", "score": 2024278, "category": "series", "detail_url": "../movie/1082.html", "poster": "../posters/1082.svg"}, {"id": "1083", "title": "下海", "year": 2017, "region": "法国 / 中国大陆", "type": "电影", "genre": "剧情， 社会", "tags": ["东北下岗， 巴黎地下， 女性生存， 纪实风格"], "summary_short": "下海，2017年法国 / 中国大陆电影，剧情， 社会。90年代末，东北工业城市陷入下岗潮。女工张丽君为了给丈夫治病、供儿子上学，在“法国亲戚”的帮助下，借了高利贷远赴巴黎，本以为去做保姆或制衣工。抵达后才发现亲戚根本不存在，她流落巴黎街头。在绝望中，她遇到了站街的同乡，无奈“下海”。白天她像普通游客一样穿梭在巴黎的街道，夜晚则站在贝尔维尔站街。她认识了同样来自东北、在此处“拉皮条”的萧然，两人产生了一种同病相怜的暧昧。张丽君每个月把钱寄", "score": 2017233, "category": "drama", "detail_url": "../movie/1083.html", "poster": "../posters/1083.svg"}, {"id": "1084", "title": "人类不适任的未来", "year": 2026, "region": "日本", "type": "动画剧集", "genre": "科幻、哲学、惊悚", "tags": ["赛博朋克、AI、存在主义、反乌托邦"], "summary_short": "人类不适任的未来，2026年日本动画剧集，科幻、哲学、惊悚。2142年，全球AI系统“大秩序”判定“强烈情绪”是阻碍人类进步的病毒，所有新生儿都要接受情绪阉割手术。17岁的女孩小响因为基因突变，是唯一拥有完整恐惧感的人类。她被关在研究所，周围都是只会理性计算的“适任者”。小响的恐惧让她看到了体制的恐怖，也激发了她逃跑的勇气。她利用AI的逻辑漏洞，制造混乱逃入废弃的地下城，遇到了一群同样有缺陷的“不适任者”。他们要对抗的不仅是AI，更是人", "score": 2026373, "category": "series", "detail_url": "../movie/1084.html", "poster": "../posters/1084.svg"}, {"id": "1085", "title": "梦游潜水艇", "year": 2025, "region": "西班牙", "type": "电影", "genre": "奇幻 / 冒险 / 动画", "tags": ["梦境", "深海", "童年创伤", "想象力", "治愈"], "summary_short": "梦游潜水艇，2025年西班牙电影，奇幻 / 冒险 / 动画。小男孩达利患有严重的睡眠障碍，每晚都会梦见自己被巨大的章鱼拖入深海。心理医生告诉他，那章鱼代表他内心对父亲失踪的恐惧。为了战胜噩梦并寻找父亲的下落，达利利用梦境共享技术，打造了一艘“梦游潜水艇”。他潜入母亲怀念的旧梦、邻居奶奶破碎的梦、甚至宠物狗的吃货梦。在收集了无数梦的碎片后，他拼凑出父亲最后前往的坐标——一个由全城孩子的噩梦构成的漩涡中心。他必须直面那头章鱼，才能救出被困在", "score": 2025287, "category": "fantasy", "detail_url": "../movie/1085.html", "poster": "../posters/1085.svg"}, {"id": "1086", "title": "圆月弯刀", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作 / 武侠 / 悬疑", "tags": ["古龙，兵器谱，复仇，伪续作，江湖阴谋"], "summary_short": "圆月弯刀，2024年中国香港电影，动作 / 武侠 / 悬疑。古龙原著故事二十年后，丁鹏与青青已归隐。然而一把疑似圆月弯刀的武器开始接连刺杀武林正道领袖。现场都会留下一句话：“丁鹏的良心向你们问好”。江湖传言丁鹏破戒重出江湖，昔日的仇家纷纷找上门。丁鹏的女儿丁灵被迫出山追查真相，却遇到了年轻的持刀者——一个自称是“丁鹏当年抛弃的善念化身”的神秘刀客。他拿着与弯刀完全相同的另一把刀，声称要完成丁鹏未竟的“清洗武林”事业。随着调查深入，丁灵发", "score": 2024347, "category": "crime", "detail_url": "../movie/1086.html", "poster": "../posters/1086.svg"}, {"id": "1087", "title": "毒醉心迷", "year": 2024, "region": "美国", "type": "电影", "genre": "惊悚, 犯罪", "tags": ["毒品", "医疗黑幕", "反转", "女性视角"], "summary_short": "毒醉心迷，2024年美国电影，惊悚, 犯罪。夜班护士凯莉发现近期急诊室里因“过度服药”入院的病人激增，且都服用了同一种止痛药“迈诺瑞”。她暗中调查，发现药厂代表与医院高层勾结，将高成瘾性的实验性药物包装成“非阿片类”止痛神药。凯莉的上司开始被灭口，她也遭到追杀。逃命过程中，凯莉结识了一位曾被该药毁掉人生的黑客，两人联手潜入药厂数据库，拿到了临床造假的关键证据。最终，凯莉在直播中将一切公之于众，而自己也付出了巨大的代价。", "score": 2024355, "category": "crime", "detail_url": "../movie/1087.html", "poster": "../posters/1087.svg"}, {"id": "1088", "title": "超甜搭档", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "爱情, 职场", "tags": ["甜品", "竞技", "契约恋爱", "味觉"], "summary_short": "超甜搭档，2024年中国大陆电视剧，爱情, 职场。女甜品师苏糖拥有绝对味觉，但因性格耿直被行业封杀。为还父债，她被迫签约成为“恶魔主厨”陆砚舟的假女友，合同条款包括：每天被他毒舌、替他挡桃花、以及帮他做出击败宿敌的终极甜品。陆砚舟是甜品界暴君，但患有“味觉间歇性失灵”，只有和苏糖在一起时才能恢复。两人在厨房里水火不容，却在甜蜜素与泪水之间渐渐动心。总决赛上，陆砚舟突然改了甜品配方——那是苏糖母亲失传的食谱，也是她童年的最后一抹甜。", "score": 2024299, "category": "series", "detail_url": "../movie/1088.html", "poster": "../posters/1088.svg"}, {"id": "1089", "title": "冰冻的闪光", "year": 2016, "region": "德国 / 瑞士", "type": "电影", "genre": "冒险，运动，纪录片", "tags": ["滑雪，阿尔卑斯山，极限运动，生存"], "summary_short": "冰冻的闪光，2016年德国 / 瑞士电影，冒险，运动，纪录片。纪录片式的剧情片，讲述了三位性格迥异的自由滑雪冠军，为了征服阿尔卑斯山脉上从未有人成功滑降的“闪光”北壁而集结。这条路线不仅垂直落差巨大，且常年笼罩在阴影中，表面覆盖着危险的“冰冻闪光”冰层，一触即碎。三人经历了长期的准备和心理博弈。正式开始挑战时，恶劣天气突然降临，他们被困在海拔四千米的峭壁上。物资耗尽，通讯中断，更可怕的是，连续降雪引发了小规模雪崩。在生死关头，友情、荣誉", "score": 2016274, "category": "doc", "detail_url": "../movie/1089.html", "poster": "../posters/1089.svg"}, {"id": "1090", "title": "死亡骗子", "year": 2024, "region": "韩国", "type": "电影", "genre": "犯罪 / 悬疑 / 惊悚", "tags": ["诈骗， 保险犯罪， 反转， 黑吃黑"], "summary_short": "死亡骗子，2024年韩国电影，犯罪 / 悬疑 / 惊悚。金先生是保险诈骗界的一个传说，他能通过精湛的演技、伪造的现场和买通的鉴定人员，为客户制造完美的“死亡证明”从而骗取巨额保费。他的团队小而精，从未失手。一天，一个神秘客户找上门，出价高得离谱，要求金先生为其独居的富豪客户制造“意外死亡”。正当计划顺利推进时，警方发现，与金先生合作过的几名“已死”客户，竟然在现实中真的被杀害了。金先生意识到，自己无意中成为了一个连环杀人犯的帮凶——他负", "score": 2024449, "category": "crime", "detail_url": "../movie/1090.html", "poster": "../posters/1090.svg"}, {"id": "1091", "title": "如何在俄亥俄州跳舞", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧, 剧情", "tags": ["小镇", "丧父", "舞蹈比赛"], "summary_short": "如何在俄亥俄州跳舞，2024年美国电影，喜剧, 剧情。生活在纽约的程序员阿历克斯突然接到老家俄亥俄州的电话：他那爱搞怪的父亲去世了。遗嘱录像带里，老头穿着花裤衩说：“别给我办哭丧的葬礼，我要你们在教堂给我跳一支百老汇水平的踢踏舞，跳得好我才上天堂。”这可难倒了肢体僵硬如木头的阿历克斯。他回到无聊的小镇，找到了当年红极一时现已颓废的舞蹈老师胖苏珊。在仓库改建的舞蹈室里，阿历克斯从最基本的“左右左”开始学起。这个过程中，他重新认识了父亲年轻", "score": 2024270, "category": "drama", "detail_url": "../movie/1091.html", "poster": "../posters/1091.svg"}, {"id": "1092", "title": "保卫延安", "year": 2009, "region": "中国大陆", "type": "剧集", "genre": "历史 / 战争", "tags": ["革命历史", "正面战场", "真实事件改编", "人物群像", "经典文学改编"], "summary_short": "保卫延安，2009年中国大陆剧集，历史 / 战争。改编自杜鹏程同名小说，以解放战争中的延安保卫战为主线。故事从普通战士周大勇的视角展开，他跟随彭德怀指挥的西北野战军，在敌我力量悬殊的绝境中执行“蘑菇战术”：不计一城一地的得失，将敌人拖入黄土高原的沟壑中。剧中既有青化砭、羊马河等经典战役的惨烈正面描写，也有战士们在窑洞中讨论“延安丢了还算不算胜利”的思想交锋。周大勇与指导员王成德、女兵白茹之间的战友情深，在一次次反冲锋中显得尤为珍贵。最终", "score": 2009159, "category": "series", "detail_url": "../movie/1092.html", "poster": "../posters/1092.svg"}, {"id": "1093", "title": "新封神姜子牙", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "奇幻 / 动作", "tags": ["封神", "神话改编", "特效大片", "反套路", "阴谋"], "summary_short": "新封神姜子牙，2026年中国大陆电影，奇幻 / 动作。封神大战结束，姜子牙奉元始天尊之命封神。三百六十五位正神归位，三界看似一片祥和。但姜子牙发现被封神的凡人将士失去了生前所有记忆，变成了没有情感的战斗傀儡。而他自己虽然被封为“太公在此，百无禁忌”，却每天都要吞服一种叫“忘尘丹”的药，记忆也在慢慢消失。一次偶然，他在地府深处见到了申公豹的残魂，得知封神榜真正的目的——将所有反抗者的灵魂炼成天道运转的燃料。姜子牙崩溃了，他拔剑指向天庭，喊", "score": 2026368, "category": "fantasy", "detail_url": "../movie/1093.html", "poster": "../posters/1093.svg"}, {"id": "1094", "title": "幸存的希德", "year": 2026, "region": "英国", "type": "电影", "genre": "剧情 / 历史", "tags": ["二战，犹太人，孩童视角，人性光辉"], "summary_short": "幸存的希德，2026年英国电影，剧情 / 历史。1942年，犹太小男孩希德在父母被押往集中营前，被藏进华沙动物园一处废弃的地下兽笼。动物园的前管理员夫妇偷偷给他送食物。希德唯一的邻居，是一只因年老被遗弃的猩猩“卡斯帕”。起初希德恐惧、孤独，但渐渐地，他发现卡斯帕有自己的情绪，会在管理员来时发出特殊的叫声报信。在漫长而黑暗的隐藏岁月里，希德靠对着卡斯帕说话保持心智正常。他甚至从卡斯帕的“叹气”中学会识别危险。战争结束时，希德获救，而卡斯帕", "score": 2026275, "category": "drama", "detail_url": "../movie/1094.html", "poster": "../posters/1094.svg"}, {"id": "1095", "title": "自然盛宴", "year": 2025, "region": "中国大陆/法国", "type": "纪录片", "genre": "纪录/自然", "tags": ["美食", "生态", "视觉盛宴", "人与自然"], "summary_short": "自然盛宴，2025年中国大陆/法国纪录片，纪录/自然。这不只是一部美食纪录片，更是一部关于生存的史诗。镜头从深海热泉口的盲虾，到沙漠中捕食蝎子的沙猫；从中国云南密林里寻找松露的猪，到北极圈内生吃海豹的因纽特人。影片采用了最先进的微距和航拍技术，捕捉到了无数前所未见的画面：兰花螳螂猎杀蜜蜂的过程被放慢了100倍，如同一场优雅的芭蕾；深海鮟鱇鱼在黑暗中的捕食瞬间，堪比科幻大片。影片没有旁白，全程仅靠环境音和配乐驱动，旨在让观众沉浸式体验这场", "score": 2025091, "category": "doc", "detail_url": "../movie/1095.html", "poster": "../posters/1095.svg"}, {"id": "1096", "title": "玩具之父盖比特", "year": 2023, "region": "意大利", "type": "电影", "genre": "奇幻、剧情、传记", "tags": ["木偶、父爱、手工匠人、童话新编、治愈"], "summary_short": "玩具之父盖比特，2023年意大利电影，奇幻、剧情、传记。故事发生在二战后的米兰，老木匠盖比特痛失了唯一的女儿和深爱的妻子。在极度的孤独中，他回到了祖父留下的木工作坊，开始雕刻一个他心中“完美女儿”的木偶。他倾注了所有的时间和心血，甚至自学了钟表机械和物理发条，只为让木偶能做出简单的动作。邻居的孤儿小卢卡闯入了他的生活，起初盖比特拒人千里，但小卢卡被木偶深深吸引，并用自己的活力和童真感染了老人。盖比特最终意识到，真正的“生命”不在于木偶是", "score": 2023345, "category": "drama", "detail_url": "../movie/1096.html", "poster": "../posters/1096.svg"}, {"id": "1097", "title": "乌龙捕快粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "喜剧 / 古装", "tags": ["清代捕快，乌龙探案，粤语谐音"], "summary_short": "乌龙捕快粤语，2024年中国香港剧集，喜剧 / 古装。光绪年间广州府，捕快阿炳办案全靠瞎蒙，但他运气极好——每次他指认的嫌犯，最后都会因为另一个毫不相干的罪名落网。新来的知府女儿留学归来，一心要用西方刑侦学改造衙门，指名要和阿炳搭档。两人联手调查一宗连环盗窃案，阿炳的“推理”全是粤语谐音梗和牵强联想，却每次都巧合地指向真凶。女搭档用指纹、足迹、血迹分析锁定同一人。最后一集两人对峙真凶，阿炳瞎猫碰上死耗子说中凶器藏在哪，女搭档终于崩溃：“", "score": 2024266, "category": "series", "detail_url": "../movie/1097.html", "poster": "../posters/1097.svg"}, {"id": "1098", "title": "野兽家族第五季", "year": 2024, "region": "美国", "type": "剧集", "genre": "犯罪, 剧情", "tags": ["家族", "犯罪", "黑帮", "冲浪"], "summary_short": "野兽家族第五季，2024年美国剧集，犯罪, 剧情。在上一季结尾，家族的绝对核心“蓝精灵”斯玛夫因癌症去世，留下了一个巨大的权力真空和一笔下落不明的巨额遗产。第五季的故事围绕着她的孙子J展开，J看似是文弱书生，实则继承了祖母最冷酷的基因。在外有墨西哥黑帮、爱尔兰黑帮环伺的情况下，J精心设计，利用叔叔 Pope 的精神不稳定和 Craig 的鲁莽，以及 Deran 想要洗白的愿望，让他们自相残杀。本季将揭开斯玛夫年轻时如何白手起家的关键回忆", "score": 2024328, "category": "series", "detail_url": "../movie/1098.html", "poster": "../posters/1098.svg"}, {"id": "1099", "title": "玩命大临演", "year": 2025, "region": "美国", "type": "电影", "genre": "动作/喜剧", "tags": ["替身", "黑帮", "爆破", "乌龙"], "summary_short": "玩命大临演，2025年美国电影，动作/喜剧。剧场龙套演员小凯为了还债，接了一份“临演”工作——假扮一名冷酷杀手去交易现场走走位。谁知真正的杀手临时反水，黑帮老大误以为小凯就是雇来的人。小凯只能硬着头皮，把交易现场当成即兴表演舞台，用莎士比亚的台词回应黑帮的暗语。他竟然阴差阳错地完成了任务，还炸掉了一栋楼。黑帮对他“神乎其技”的表演深信不疑，非要聘请他做军事顾问。而此时，真杀手也回来了，一场真假杀手的即兴大乱斗正式上演。", "score": 2025381, "category": "crime", "detail_url": "../movie/1099.html", "poster": "../posters/1099.svg"}, {"id": "1100", "title": "鬼追人", "year": 2022, "region": "美国", "type": "电影", "genre": "恐怖", "tags": ["都市传说", "心理惊悚", "超自然", "追杀", "复仇"], "summary_short": "鬼追人，2022年美国电影，恐怖。内向的监控员林恩天生失聪，却因此拥有了异于常人的视觉专注力。某夜，她在城市废弃地铁站的监控画面中，反复看到一个模糊的高瘦黑影跟在路人身后，而每当黑影触碰到目标，那人就会在下一秒以离奇方式死亡。林恩尝试报警，却被当作精神异常。当她发现自己的影像倒影里也开始出现那个黑影时，才意识到——看见过它的人，都会被标记。为了活命，她必须利用自己对画面的记忆力，反向追踪黑影在城市中的移动规律，并找出它第一次出现时的那个", "score": 2022301, "category": "horror", "detail_url": "../movie/1100.html", "poster": "../posters/1100.svg"}, {"id": "1101", "title": "我心迷茫", "year": 2021, "region": "法国", "type": "电影", "genre": "剧情，音乐，文艺", "tags": ["音乐家，失聪，内心独白，公路电影"], "summary_short": "我心迷茫，2021年法国电影，剧情，音乐，文艺。著名指挥家皮埃尔因一场突如其来的疾病彻底失聪。失去听觉对他来说等于失去生命。他拒绝植入人工耳蜗，因为他认为那不是“真实的音乐”。在一个清晨，他偷了一辆车，独自驶向童年居住的乡村。影片大部分时间没有对白，只有皮埃尔内心的独白和逐渐消失的耳鸣声。他重访少年时学琴的教堂、第一次指挥的小礼堂、与亡妻相遇的河边。在绝对的静默中，他开始用视觉、触觉和记忆“指挥”空气。当他最终站在荒废的乡村小学礼堂里，", "score": 2021280, "category": "drama", "detail_url": "../movie/1101.html", "poster": "../posters/1101.svg"}, {"id": "1102", "title": "独立的生活", "year": 2025, "region": "日本", "type": "电视剧", "genre": "剧情, 家庭", "tags": ["女性成长", "断舍离", "治愈系"], "summary_short": "独立的生活，2025年日本电视剧，剧情, 家庭。在丈夫提出离婚后，从未工作过的家庭主妇佐和子搬进一间极小的公寓，开始独立生活。她从零学习交水电费、找工作、处理邻里纠纷，每一件小事都像是一场战役。与此同时，她还要面对女儿的不解和母亲的老去。在一年的孤独与自由中，佐和子逐渐剥去“妻子”“母亲”的标签，找回了那个被遗忘已久的自己。", "score": 2025218, "category": "series", "detail_url": "../movie/1102.html", "poster": "../posters/1102.svg"}, {"id": "1103", "title": "再见语言", "year": 2014, "region": "法国 / 瑞士", "type": "电影", "genre": "剧情 / 实验", "tags": ["戈达尔", "3D", "意识流", "哲学", "反叙事"], "summary_short": "再见语言，2014年法国 / 瑞士电影，剧情 / 实验。戈达尔在这部 3D 实验电影中彻底抛弃了叙事。影片围绕两对情侣（或同一对情侣的不同阶段）展开，他们争吵、做爱、沉默，讨论着法律、战争和马克思。镜头突然切到一只叫罗克西的狗，以狗的视角观察人类。影片后半段，画面被粗暴地分割为两个 3D 画面互相叠加，声音也不再同步。当情侣说出“再见语言”时，画面陷入混沌的色彩。影片试图探讨：当人类用语言撒谎、争论、粉饰太平，狗只用眼睛看，用鼻子闻，反", "score": 2014267, "category": "drama", "detail_url": "../movie/1103.html", "poster": "../posters/1103.svg"}, {"id": "1104", "title": "杀人蜂", "year": 2026, "region": "巴西 / 美国", "type": "电影", "genre": "灾难, 惊悚, 科幻", "tags": ["基因变异", "生态灾难", "地下基地", "末日求生"], "summary_short": "杀人蜂，2026年巴西 / 美国电影，灾难, 惊悚, 科幻。某生物公司在亚马逊地区秘密实验基因杀虫剂，意外培育出一种对体温极度敏感、群体智能高得可怕的杀人蜂。它们能在数分钟内将一头牛蛰成白骨。当蜂群失控并向最近的城市扩散时，政府下达72小时撤离令。工程师卡洛斯被困在即将封锁的地下设施中，必须携带抗蜂素血清穿越蜂群活跃区域，送到地面的研究站。在不断的追逐与蛰伤下，他最终拖着肿胀的身体完成传送，但蜂群已经在城市上空组成了乌云般的风暴眼。", "score": 2026413, "category": "sci-fi", "detail_url": "../movie/1104.html", "poster": "../posters/1104.svg"}, {"id": "1105", "title": "访问连环杀手", "year": 2025, "region": "美国", "type": "剧集", "genre": "惊悚 / 犯罪", "tags": ["真实犯罪，FBI，心理博弈"], "summary_short": "访问连环杀手，2025年美国剧集，惊悚 / 犯罪。犯罪心理学研究生玛雅为了完成毕业论文，通过导师关系获得了访问“铁锤杀手”雷蒙德的权限。雷蒙德智商超群，在狱中十二年从未接受过任何媒体访问。起初，玛雅以为自己是在研究他，但她渐渐发现雷蒙德对她了如指掌：她的童年创伤、她的恐惧、她内心深处的暴力冲动。雷蒙德开始在她脑海中种下种子，诱导她模仿他的手法思考。当玛雅发现自己梦游时手上沾满血迹，她开始怀疑：到底是谁在“访问”谁？", "score": 2025319, "category": "series", "detail_url": "../movie/1105.html", "poster": "../posters/1105.svg"}, {"id": "1106", "title": "黑蝎女侠2：震荡之后", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作、犯罪", "tags": ["女性超级英雄、复仇、暗黑风格、近身格斗"], "summary_short": "黑蝎女侠2：震荡之后，2024年中国香港电影，动作、犯罪。在上一集事件结束后，黑蝎女侠林静试图隐退，经营一家花店。一场突如其来的7.2级大地震袭击了香港，城市满目疮痍，社会秩序濒临崩溃。混乱中，一个被密封在旧城区实验室中的超级士兵计划曝光，从中逃出的几名基因改造战士拥有超强的力量和愈合能力，他们占据了震后的“无人区”，肆意妄为。林静被迫再次穿上黑蝎战衣，但她的体能已不复当年。更糟糕的是，当年的宿敌“毒蝎”正是这些改造战士的首领，他这次的", "score": 2024375, "category": "crime", "detail_url": "../movie/1106.html", "poster": "../posters/1106.svg"}, {"id": "1107", "title": "疯狂之月", "year": 2022, "region": "韩国", "type": "电影", "genre": "悬疑/惊悚", "tags": ["精神病院", "连环失踪", "满月", "多重人格"], "summary_short": "疯狂之月，2022年韩国电影，悬疑/惊悚。资深精神科医生姜秀贤接手了一家位于孤岛上的疗养院。他发现每逢满月，院中最安静的七名患者会集体陷入癫狂并画出同一幅月下荒原的画。在调查真相的过程中，一名护士离奇蒸发。秀贤开始看到幻觉，并偶然在院长密室找到一份旧病历——病历上的患者照片竟是他自己。当他又一次从满地血泊中醒来时，他不得不怀疑：疯狂到底是患者的症状，还是这座岛屿本身的诅咒。", "score": 2022385, "category": "crime", "detail_url": "../movie/1107.html", "poster": "../posters/1107.svg"}, {"id": "1108", "title": "北部丛林", "year": 2026, "region": "加拿大 / 法国", "type": "电影", "genre": "冒险 / 剧情", "tags": ["育空地区", "野外生存", "原住民", "母女", "生态"], "summary_short": "北部丛林，2026年加拿大 / 法国电影，冒险 / 剧情。17岁的巴黎少女克洛伊因为吸毒被学校开除，母亲将她送到加拿大育空地区的丛林，参加一个“荒野治疗”项目。接待她的是项目负责人约瑟夫，一位沉默的白人老猎人。项目内容：独自在丛林生活一个月，只带一把刀和一口锅。克洛伊起初抗拒，差点冻死。约瑟夫救了她，开始教她设陷阱、识草药、读星象。一个月后，克洛伊脱胎换骨，但她发现约瑟夫的木屋里藏着一幅画像，画中人是她外婆——一位被政府强行带走、送进寄", "score": 2026239, "category": "drama", "detail_url": "../movie/1108.html", "poster": "../posters/1108.svg"}, {"id": "1109", "title": "白色严冬", "year": 2022, "region": "挪威，瑞典", "type": "电影", "genre": "剧情，战争，生存", "tags": ["极地求生，敌我同屋，人性实验，二战，语言隔阂"], "summary_short": "白色严冬，2022年挪威，瑞典电影，剧情，战争，生存。1940年挪威战役期间，一架德国侦察机与一架英国轰炸机因暴风雪在北极圈内相继坠毁。三名德军飞行员与两名英军飞行员奇迹生还，他们发现了同一间无人猎屋。没有无线电，温度零下四十度，粮食只够十天的量，而下一场风暴将持续整整两个月。起初，五个人用枪口互相指着对方度过前三天。第四天，最年轻的德军士兵冻伤了脚，英军队长犹豫后拿出了自己的绷带。猎屋开始出现一种荒诞的日常：轮流做饭、共用火柴、教对方", "score": 2022323, "category": "drama", "detail_url": "../movie/1109.html", "poster": "../posters/1109.svg"}, {"id": "1110", "title": "逼上梁山", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动作 / 犯罪 / 黑色幽默", "tags": ["小人物反击", "荒诞", "底层生存"], "summary_short": "逼上梁山，2024年中国大陆电影，动作 / 犯罪 / 黑色幽默。修车工梁三水是最普通的中年男人，被老板欠薪三年，被房东扫地出门，被混混当街扇耳光，连十岁的女儿都开始瞧不起他。他去讨薪，被老板关进狗笼一夜；他去报警，警察说“民事纠纷自己协商”；他去跳桥，围观的人拍照发朋友圈说“哈哈哈有人要表演跳水”。走投无路之下，梁三水从自己那个倒闭的修车铺里拿出一把锈迹斑斑的扳手，开始了他的“梁山之路”。他没有打打杀杀，而是用一种令人哭笑不得的方式——", "score": 2024395, "category": "crime", "detail_url": "../movie/1110.html", "poster": "../posters/1110.svg"}, {"id": "1111", "title": "伴我闯天涯", "year": 1989, "region": "中国香港", "type": "电影", "genre": "动作剧情", "tags": ["周润发", "枪战", "公路", "逃亡", "兄弟情"], "summary_short": "伴我闯天涯，1989年中国香港电影，动作剧情。杀手阿龙接下最后一单——灭门。但他下不了手杀死婴儿，反而抱着孩子踏上逃亡路。买家派出的杀手、警方通缉、以及婴儿的黑道父亲势力，三路人马在他身后紧追不舍。从香港到金三角，阿龙用沾满血的手学着给孩子冲奶粉、换尿布。在最终决战中，为了护住婴儿，他用身体挡住了子弹。倒下前他将孩子交还给警方，只说了一句：“别让他知道，他爸是个杀手。”", "score": 1989308, "category": "drama", "detail_url": "../movie/1111.html", "poster": "../posters/1111.svg"}, {"id": "1112", "title": "天眼风云", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "刑侦 / 悬疑", "tags": ["大数据", "人脸识别", "连环杀手", "高科技犯罪"], "summary_short": "天眼风云，2025年中国大陆剧集，刑侦 / 悬疑。南港市发生连环命案，受害者死法均模仿世界名画。刑侦队长陈默依靠传统刑侦手段屡屡碰壁，甚至被凶手玩弄于股掌之间。无奈之下，市局启用最新“天眼”大数据系统，并派来技术专家夏天配合。夏天性格孤僻，却能用算法预测凶手行动轨迹。随着调查深入，陈默发现夏天似乎与凶手有着不为人知的联系——原来夏天曾是顶尖黑客，而凶手是他被开除的师兄。两人开始了利用监控盲区和数据洪流的猫鼠游戏。当师兄扬言要瘫痪整座城市", "score": 2025322, "category": "series", "detail_url": "../movie/1112.html", "poster": "../posters/1112.svg"}, {"id": "1113", "title": "非常冲突", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情/犯罪", "tags": ["悬疑", "人性", "暴力美学"], "summary_short": "非常冲突，2023年中国大陆电影，剧情/犯罪。深夜公交车上，落魄记者、黑车司机、夜场女郎、实习医生与退休警察被不明气体迷晕后醒来，发现手脚被绑，车外是荒废工地。神秘声音控诉他们曾共同参与一场网络暴力，导致一名少女自杀。五人互相指责、回忆、撕扯，真相层层剥开，原来每个人都只看到了事件一角。最终他们发现，真正策划这场“审判”的人，就藏在他们中间。影片以密闭空间推动心理博弈，直至最后一刻才揭晓谁才是真正的复仇者。", "score": 2023374, "category": "drama", "detail_url": "../movie/1113.html", "poster": "../posters/1113.svg"}, {"id": "1114", "title": "模范刑警", "year": 2024, "region": "韩国", "type": "剧集", "genre": "犯罪 / 动作", "tags": ["刑警， 双男主， 亦敌亦友， 热血"], "summary_short": "模范刑警，2024年韩国剧集，犯罪 / 动作。首尔警察厅的精英刑警姜志浩破案率100%，行事风格一板一眼，被同事称为“行走的刑法教科书”。而他的新搭档李俊赫真实身份是潜入黑帮五年的卧底警察，行事乖张，手段粗暴，刚从黑帮“毕业”就因违反纪律被发配到重案组。两人从第一次见面就气场不合，姜志浩看不惯李俊赫的无视程序，李俊赫嘲笑姜志浩的不知变通。然而他们被分配调查同一桩悬案：五年前未破的连环杀人案，而最新的受害者与李俊赫卧底时的黑帮组织有着千丝", "score": 2024355, "category": "series", "detail_url": "../movie/1114.html", "poster": "../posters/1114.svg"}, {"id": "1115", "title": "临终千言", "year": 2012, "region": "美国", "type": "电影", "genre": "剧情、奇幻", "tags": ["生命倒计时、闭嘴修行、沟通、家庭、灵性"], "summary_short": "临终千言，2012年美国电影，剧情、奇幻。杰克·麦考尔是纽约最刻薄的文学经纪人，用一张利嘴毁掉了无数作家的自信和家庭。某天，他从一个古怪的东方收藏家手中买下一棵造型奇特的盆栽菩提树。当晚，他发现每说一个字，树上就会掉一片叶子；说了947个字后，树几乎秃了一半。他惊恐地咨询语言学家、神秘学家甚至黑客，得出的结论是：这棵树与他共享生命，叶尽人亡。杰克被迫进入“闭嘴模式”，靠写字板、手语和咆哮表情与人沟通。沉默中，他第一次听到了女儿弹钢琴时的", "score": 2012369, "category": "drama", "detail_url": "../movie/1115.html", "poster": "../posters/1115.svg"}, {"id": "1116", "title": "远方有多远", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情, 文艺, 公路", "tags": ["徒步", "朝圣", "自我救赎", "西藏"], "summary_short": "远方有多远，2025年中国大陆电影，剧情, 文艺, 公路。中年医生周至凡因醉酒手术导致病人死亡，身败名裂。出狱后妻子离婚，女儿不认他。在自杀未遂后，他刷到一篇鸡汤文“去西藏洗涤灵魂”，于是讽刺地背上包，出发前往号称“最后秘境”的墨脱。他一路上厌恶那些张口闭口“净化”的虚伪驴友，毒舌地拆穿他们的装腔作势。直到他在路上遇到一个执意要去墨脱找爸爸的流浪少年小七。周至凡发现小七的身上有严重的感染伤，医生的本能驱使他停下脚步照顾小七。在这段极其痛", "score": 2025245, "category": "drama", "detail_url": "../movie/1116.html", "poster": "../posters/1116.svg"}, {"id": "1117", "title": "琴思", "year": 1982, "region": "中国大陆", "type": "电影", "genre": "爱情, 音乐", "tags": ["钢琴", "师生恋", "时代伤痕", "纯爱"], "summary_short": "琴思，1982年中国大陆电影，爱情, 音乐。著名钢琴家林海受邀回到母校任教，在琴房里，他鬼使神差地弹起了一首名为《琴思》的未完成曲谱。琴声吸引了天才少女苏萌，她发现这首曲子与林海二十年前消失的女学生有关。回忆闪回至文革时期，林海是苏萌母亲的学生，两人互生情愫，却因为师生身份和时代背景被视为“丑闻”。母亲为了保护林海，毅然断绝关系并下嫁他人，却在婚礼当晚弹奏了这首《琴思》后割腕自杀，被救后失去了右手弹琴的能力。如今，苏萌正是那个女人的女儿", "score": 1982271, "category": "doc", "detail_url": "../movie/1117.html", "poster": "../posters/1117.svg"}, {"id": "1118", "title": "攻略陛下100次", "year": 2026, "region": "中国大陆", "type": "电视剧", "genre": "古装，爱情，奇幻，喜剧", "tags": ["穿书，系统，攻略，甜宠，权谋"], "summary_short": "攻略陛下100次，2026年中国大陆电视剧，古装，爱情，奇幻，喜剧。现代女孩苏锦穿进虐文，成了暴君的第99个被赐死的皇后。她绑定了“陛下攻略系统”，却发现每次失败都会读档重来，且皇帝的记忆会累积。第1次她试图讨好，被当成细作；第30次她黑化造反，反被囚禁；第80次她心死求去，暴君却第一次落下眼泪。她终于明白，要攻略的从来不是冷酷，而是这个帝王被诅咒的孤独宿命。", "score": 2026343, "category": "series", "detail_url": "../movie/1118.html", "poster": "../posters/1118.svg"}, {"id": "1119", "title": "名模大间谍2", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 喜剧 / 冒险", "tags": ["时尚圈", "特工", "AI换脸", "恶搞"], "summary_short": "名模大间谍2，2025年美国电影，动作 / 喜剧 / 冒险。世界知名的三位“名模大间谍”再次集结。这次，反派是利用元宇宙概念称霸世界的前时尚杂志主编。她开发了一套“脑电波时尚系统”：只要用户在虚拟时尚周中试穿她设计的数字服装，系统就会通过脑机接口植入潜意识指令，最终让全球用户同时在现实中购买她推出的实体“解放服”（实际上是控制芯片）。三位模特早已过气，不得不伪装成一个由AI完全生成的虚拟偶像男团“NOVA-X”，他们没有真实面孔，全程以", "score": 2025296, "category": "comedy", "detail_url": "../movie/1119.html", "poster": "../posters/1119.svg"}, {"id": "1120", "title": "高校疯神榜", "year": 2025, "region": "中国台湾", "type": "剧集", "genre": "喜剧、校园、奇幻", "tags": ["校园榜、许愿、代价、中二"], "summary_short": "高校疯神榜，2025年中国台湾剧集，喜剧、校园、奇幻。景美高中流传着一份神秘榜单“疯神榜”，据说只要你的名字出现在上面，就能实现一个愿望。但实现方式非常离谱：想考第一？榜单让你转学去了一个只有一个人的学校。想变漂亮？榜单让全校都失明了，只有你一个人能被看见。想谈恋爱？榜单让全校除了你对象之外的人都变成了你的追求者。学渣阿榜为了追到校花，故意让自己上榜，许愿“让校花注意到我”。第二天，校花确实注意到他了——因为她收到了一张纸条，上面写着“", "score": 2025300, "category": "series", "detail_url": "../movie/1120.html", "poster": "../posters/1120.svg"}, {"id": "1121", "title": "超级好公民", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "黑色喜剧 / 剧情", "tags": ["道德绑架，网络暴力，好人难做，讽刺"], "summary_short": "超级好公民，2024年中国大陆电影，黑色喜剧 / 剧情。快递员李大明在暴雨中扶起摔倒的老太太，被路人拍下发到抖音，一夜涨粉百万。官方授予“超级好公民”称号，上电视、做演讲。但只有他自己知道：那天他是因为低头看手机才撞倒老太太的，扶起来是为了撇清责任。如今他像被架在火上烤：必须让座、必须捐款、必须原谅一切。当他终于忍不住对插队的人爆粗，视频被剪辑后全网声讨他“人设崩塌”。最后李大明直播承认撒谎，脱掉“好公民”外套。令人意外的是，网友反而说", "score": 2024308, "category": "drama", "detail_url": "../movie/1121.html", "poster": "../posters/1121.svg"}, {"id": "1122", "title": "义务出席", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["职场", "黑色幽默", "团建", "荒诞", "打工人"], "summary_short": "义务出席，2025年中国大陆电影，喜剧 / 剧情。互联网大厂“橙光科技”宣布全员必须参加为期两天的“意志力极限挑战营”，地点在无信号的深山谷地。HR总监私下告知员工：全程自愿，不扣工资，但缺席者季度绩效自动为C。活动开始后，奇葩项目层出不穷：凌晨三点暴雨中负重登山、互相揭短大会、仅有一份盒饭的小组竞争。第二天凌晨山体滑坡切断出路，大家被迫合作求生时，发现组织者早已撤离，而营地里的“生存物资”明显是提前储备的。原来这是一场观察式裁员——谁", "score": 2025276, "category": "comedy", "detail_url": "../movie/1122.html", "poster": "../posters/1122.svg"}, {"id": "1123", "title": "薄荷", "year": 2021, "region": "韩国", "type": "电影", "genre": "悬疑, 惊悚", "tags": ["嗅觉记忆", "双面人格", "复仇", "高能反转"], "summary_short": "薄荷，2021年韩国电影，悬疑, 惊悚。秀敏患有一种罕见的通感症：她能“看见”气味的颜色和形状。警方特邀她协助侦破连环杀人案，受害者都是年轻女性，现场没有痕迹。第四起案件现场，秀敏突然瘫倒在地——她闻到了浓烈的薄荷味，而这股薄荷香，只属于她自己用的那款定制香水。她开始怀疑自己是否在失忆时成了凶手。男友陪她安装监控后发现：每晚凌晨两点，她会准时起身出门，凌晨五点回来，浑身湿透。当她跟踪自己时，发现了一个和她长得一模一样的女人——那是她从未", "score": 2021413, "category": "crime", "detail_url": "../movie/1123.html", "poster": "../posters/1123.svg"}, {"id": "1124", "title": "辣手娇娃", "year": 2026, "region": "中国香港", "type": "电影", "genre": "动作 / 犯罪", "tags": ["女子特工", "暴力美学", "卧底", "黑帮"], "summary_short": "辣手娇娃，2026年中国香港电影，动作 / 犯罪。曾是东南亚最强女子特工队的“辣手”三人组，退隐后各自嫁入豪门，成为相夫教子的贵妇。然而，一场针对她们家人的阴谋绑架案让三人不得不重拾旧业。表面上是慈善晚宴的优雅女主人，暗夜里却是拳拳到肉的复仇者。她们一路追查发现，幕后黑手竟是曾经的教官。在一场充满霓虹灯与玻璃碎片的最终决战中，三位辣手娇娃必须撕碎华服，用最原始的方式夺回属于自己的生活。", "score": 2026393, "category": "crime", "detail_url": "../movie/1124.html", "poster": "../posters/1124.svg"}, {"id": "1125", "title": "闪虾亮晶晶", "year": 2023, "region": "法国", "type": "电影", "genre": "喜剧/运动", "tags": ["同志、游泳、反差萌、爆笑"], "summary_short": "闪虾亮晶晶，2023年法国电影，喜剧/运动。巴黎市政决定拆除一个老旧游泳馆，馆长是退休游泳教练皮埃尔。LGBT协会的“闪虾队”租用这里十年，队员全是五十岁上下的胖大叔、变装皇后和深柜职员，他们平时只在池边聊天、摆拍。皮埃尔为了保住游泳馆，谎称闪虾队要参加全国业余锦标赛，以此向市政申请保留场地。队员们被迫学游泳，闹出无数笑话：有人怕水、有人只会狗刨、变装皇后的假发在水里脱落。他们勉强通过预赛，决赛前队长帕特里克出柜，被家人断绝关系。全队在", "score": 2023315, "category": "doc", "detail_url": "../movie/1125.html", "poster": "../posters/1125.svg"}, {"id": "1126", "title": "生命的烙印", "year": 2025, "region": "波兰", "type": "电影", "genre": "剧情 / 历史 / 战争", "tags": ["纹身", "集中营", "幸存者", "救赎"], "summary_short": "生命的烙印，2025年波兰电影，剧情 / 历史 / 战争。90岁的集中营幸存者雅各布，手臂上的纹身“99201”是他一生的噩梦。他的孙子，叛逆少年米哈伊，在一次车祸后昏迷醒来，发现自己的左臂上缓缓浮现出同样的“99201”。更诡异的是，他开始梦见雅各布的过去：毒气室、枯瘦的尸体、绝望的祈祷。当医生诊断为应激障碍时，雅各布颤抖着翻开一本旧日记，里面夹着一张发黄的纸条，上面写着：“99201，对不起，我拿了你的面包。”", "score": 2025297, "category": "doc", "detail_url": "../movie/1126.html", "poster": "../posters/1126.svg"}, {"id": "1127", "title": "无脸朋友", "year": 2024, "region": "日本", "type": "动画电影", "genre": "奇幻, 儿童, 亲情", "tags": ["孤独", "幻想朋友", "成长", "治愈"], "summary_short": "无脸朋友，2024年日本动画电影，奇幻, 儿童, 亲情。因为父亲工作调动，10岁的小翼转到陌生城市的小学。她性格内向无法融入班级，在学校的废旧仓库里发现了一个奇怪的男孩——他穿着旧式校服，但脸上什么都没有，光滑如鸡蛋。男孩说自己叫“无脸”，曾经是每个孩子的朋友，但当孩子们长大就把他们遗忘了，所以脸也消失了。无脸可以带小翼进入被遗忘的记忆世界，那里有几十个孩子曾经的幻想伙伴。他们一起在记忆世界里冒险，帮一个老兵找回了童年丢失的勇气徽章，帮", "score": 2024289, "category": "fantasy", "detail_url": "../movie/1127.html", "poster": "../posters/1127.svg"}, {"id": "1128", "title": "魔都传奇粤语", "year": 1998, "region": "香港", "type": "电视剧", "genre": "剧情， 黑帮， 悬疑", "tags": ["上海滩， 粤语， 复仇， 传奇"], "summary_short": "魔都传奇粤语，1998年香港电视剧，剧情， 黑帮， 悬疑。1927年，少年阿聋目睹全家被黑帮灭门，自己被割断声带扔进黄浦江。十年后，他化名“剃刀”，在法租界当擦鞋匠。他不能言，却因幼年习武练就极强唇语能力，能隔街读取对话。他利用这一能力，挑拨三大帮派关系，让他们自相残杀。当最后一个仇人——已成为公共租界董事——死在他的剃刀下时，警察局长抓了他。但审讯室的门打开，走进来的却是当年救他的巡捕房探长。探长递给他一把枪，说：“其实，我是地下党。", "score": 1998342, "category": "series", "detail_url": "../movie/1128.html", "poster": "../posters/1128.svg"}, {"id": "1129", "title": "好事行龙", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧 / 奇幻", "tags": ["废柴", "好运", "逆袭", "荒诞"], "summary_short": "好事行龙，2024年中国大陆剧集，喜剧 / 奇幻。外卖员龙一鸣买彩票永远差一个号，相亲永远被放鸽子。在又一次被辞退后，他意外获得一本“功德簿”，每完成一次利他行为，就能从虚拟卡池抽取“微调现实”的能力：让红灯变绿灯，让ATM多吐一张钞票，甚至让讨厌的同事突然打嗝三分钟。龙一鸣用这些能力帮助了更多人，却引来神秘组织的追杀——原来功德簿是上古神器，过度使用会磨损时间线。在最后，龙一鸣放弃所有好运，换回了被反派绑架的整个养老院老人的生命。", "score": 2024301, "category": "series", "detail_url": "../movie/1129.html", "poster": "../posters/1129.svg"}, {"id": "1130", "title": "重要人物", "year": 2026, "region": "韩国", "type": "剧集", "genre": "剧情, 悬疑, 职场", "tags": ["政治讽刺", "替身", "权力游戏", "黑马"], "summary_short": "重要人物，2026年韩国剧集，剧情, 悬疑, 职场。总统候选人“崔民秀”其实一直是七名替身轮流扮演，他们分别负责演讲、网络互动、现场握手等不同场景。真正的崔民秀在三年前就已脑死亡。选举前夕，负责演讲的A角意外“自杀”，其余六人被抓进地下掩体。每人颈部被植入爆炸项圈，系统提示：“杀死崔民秀的凶手就在你们之中，只有最后一个活着的人能成为真正的总统。”于是，擅长握手的替身用体温杀人，擅长演讲的替身用语言挑拨离间，擅长网络骂战的替身黑进了项圈系", "score": 2026303, "category": "series", "detail_url": "../movie/1130.html", "poster": "../posters/1130.svg"}, {"id": "1131", "title": "换伴万万睡", "year": 2026, "region": "泰国", "type": "剧集", "genre": "爱情, 喜剧", "tags": ["换偶实验", "都市情感", "笑中带泪", "自我发现"], "summary_short": "换伴万万睡，2026年泰国剧集，爱情, 喜剧。情感真人秀《换伴万万睡》邀请四对陷入倦怠期的情侣：程序员与瑜伽师、律师与网红、设计师与全职主夫、医生与酒吧歌手。规则是每对情侣拆散后重组，连续30天与新伴侣同床共枕，全程跟拍。节目组号称要“用陌生唤醒熟悉”。第一周所有人都尴尬到脚趾扣地。第二周开始出现微妙变化：律师发现平时话少的酒吧歌手其实内心极度敏感，而他的原配网红在程序员那里得到了从未有过的倾听。第三周爆发冲突，有人想退出，有人想真的在", "score": 2026310, "category": "series", "detail_url": "../movie/1131.html", "poster": "../posters/1131.svg"}, {"id": "1132", "title": "琴弦绝响", "year": 2018, "region": "中国大陆", "type": "电影", "genre": "剧情，音乐，历史", "tags": ["古琴，民国，匠人精神，传承，知音"], "summary_short": "琴弦绝响，2018年中国大陆电影，剧情，音乐，历史。1937年，江南古镇。制琴大师沈一白守着祖传的斫琴坊，最珍视的是一把唐代古琴“春雷”。日军入侵，军官佐藤是个狂热的古琴爱好者，他看上了“春雷”，并逼迫沈一白修复琴身上的裂纹。为了保全全城百姓性命和琴坊藏书，沈一白答应了。但他要求佐藤必须找来特定的千年木料和蚕丝。在长达三个月的修复过程中，沈一白将报仇的炸药藏在了琴身里，并将“琴在人在，琴亡人亡”的祖训留给了徒弟。最终，在“春雷”奏响的绝", "score": 2018312, "category": "doc", "detail_url": "../movie/1132.html", "poster": "../posters/1132.svg"}, {"id": "1133", "title": "30拉紧抱", "year": 2016, "region": "中国台湾", "type": "剧集", "genre": "剧情 / 爱情", "tags": ["30岁", "女性群像", "成长", "都会"], "summary_short": "30拉紧抱，2016年中国台湾剧集，剧情 / 爱情。三个高中好友在30岁那年同时陷入人生的十字路口。林美丽是事业型女强人，却因未婚未育被职场歧视，在升职前夕被迫“让位”；曾甜甜是家庭主妇，发现丈夫出轨后决定离婚重返职场，却发现自己连简历都不会写；方小桃是文艺女青年，交往多年的男友突然出柜，她开始怀疑自己是否从未被真正爱过。三人重新住到一起，像大学时期一样互相吐槽、吵架又和好。她们尝试了相亲、创业、健身、心理咨询，经历了崩溃、妥协、放弃和", "score": 2016293, "category": "series", "detail_url": "../movie/1133.html", "poster": "../posters/1133.svg"}, {"id": "1134", "title": "危险孵化", "year": 2022, "region": "澳大利亚", "type": "电影", "genre": "惊悚，科幻", "tags": ["怪兽，孤岛，孕妇，生存"], "summary_short": "危险孵化，2022年澳大利亚电影，惊悚，科幻。生态学家艾玛怀有八个月身孕，跟随丈夫前往南太平洋一座无人岛考察。岛上发现了一种被认为已灭绝的巨型史前爬行动物巢穴。当团队成员惊扰了巢穴，巨兽开始血腥屠杀。艾玛意外与团队失散，她惊恐地发现，这些只把她作为攻击目标，对其他人视而不见。原因在于，巨兽能感知到孕激素，它们把艾玛腹中的胎儿当成了自己的同类幼崽，想要带回巢穴“孵化”。艾玛不得不在暴雨夜的丛林中逃亡，用尽自己的生态学知识——利用植物汁液掩", "score": 2022453, "category": "crime", "detail_url": "../movie/1134.html", "poster": "../posters/1134.svg"}, {"id": "1135", "title": "生命诚可贵", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情家庭", "tags": ["绝症、母女、和解、存在主义"], "summary_short": "生命诚可贵，2025年中国大陆电影，剧情家庭。单亲妈妈陆惠芬被诊断出胰腺癌晚期，她最放不下的是叛逆期女儿文文。文文恨她当年离婚，拒绝交流。陆惠芬做了一个疯狂决定：雇了一位话剧演员扮演20年后的文文——一个事业失败、婚姻破裂、满身戾气的中年女人，让她偶遇现在的文文。20年后的“文文”告诉现在的自己：你妈死的时候你没有哭，但你后来每一天都在后悔。你不原谅她，最后你活成了她最怕你变成的样子。文文起初不信，但“未来自己”说出了只有她知道的事。她", "score": 2025241, "category": "drama", "detail_url": "../movie/1135.html", "poster": "../posters/1135.svg"}, {"id": "1136", "title": "格子间女人", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "剧情， 职场", "tags": ["女性成长， 办公室政治， 现实主义， 北漂"], "summary_short": "格子间女人，2023年中国大陆剧集，剧情， 职场。北京，某互联网大厂“风云科技”的办公楼层。22岁的实习生小北想转正，却发现自己只是“干电池”；32岁的中层主管莉莎面临35岁门槛，还要应对年轻下属的挑战和上司的性暗示；42岁的副总裁陈姐是公司元老，却因“跟不上时代”被资本方要求“体面离开”。三个女人坐在不同的格子间，却共享着女性的职场困境：生育歧视、年龄歧视、职场性骚扰、996、内卷。她们从互相提防到结成同盟，用各自的方式反击：小北举报", "score": 2023220, "category": "series", "detail_url": "../movie/1136.html", "poster": "../posters/1136.svg"}, {"id": "1137", "title": "暗芝居第九季", "year": 2024, "region": "日本", "type": "剧集", "genre": "恐怖 / 动画 / 悬疑", "tags": ["都市传说", "纸芝居", "怪谈", "短篇集", "细思极恐"], "summary_short": "暗芝居第九季，2024年日本剧集，恐怖 / 动画 / 悬疑。经典恐怖动画系列第九季回归。本季将视角聚焦于现代社会科技带来的恐惧，如AI换脸、直播打赏、元宇宙、线上相亲等。12个短篇分别是：《已读不回》《点赞者》《美颜滤镜》《永不下播》《虚拟伴侣》《外卖评分》《云端葬礼》《智能家居》《人脸识别》《AI诗人》《赛博讨债人》和《最后的推文》。画风延续了前作复古的“纸芝居”风格，但在表现数字鬼怪时使用了特殊的像素化处理。其中最受好评的是《已读不", "score": 2024385, "category": "series", "detail_url": "../movie/1137.html", "poster": "../posters/1137.svg"}, {"id": "1138", "title": "变蝇人国语", "year": 2025, "region": "美国 / 加拿大", "type": "电影", "genre": "科幻, 恐怖, 身体", "tags": ["翻拍", "基因突变", "悲剧英雄", "国语配音版"], "summary_short": "变蝇人国语，2025年美国 / 加拿大电影，科幻, 恐怖, 身体。本片是经典IP的全新重启，并专为中文市场制作官方国语配音版本。天才科学家塞斯发明了能够分解并重组物质的“传送舱”。在一次醉后孤独实验时，一只苍蝇飞入舱体，导致塞斯的基因与苍蝇在分子层面融合。起初他获得了超人的力量与敏捷，身体也开始分泌奇特的糖浆。但随着第二形态的“蝇人”特征出现（头部反转、呕吐酶液），他发现自己正在丧失人类的情感。他的记者女友维罗妮卡怀上了他的孩子，而塞斯", "score": 2025414, "category": "horror", "detail_url": "../movie/1138.html", "poster": "../posters/1138.svg"}, {"id": "1139", "title": "圣诞夜怪谭", "year": 2023, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["圣诞，密室，复仇，反转"], "summary_short": "圣诞夜怪谭，2023年美国电影，悬疑 / 惊悚。圣诞夜，富二代诺亚邀请五位老同学到自家庄园重聚，大雪封路后众人被困。席间，一台老式留声机突然播放录音，依次揭露每个人在这些年里圣诞夜犯下的恶行——有人酒驾肇事，有人诬陷同事，有人对家人见死不救。起初大家以为是玩笑，直到第一个人被吊灯砸死。剩余的人开始互相猜忌，试图找出幕后黑手。随着秘密逐一揭开，他们发现诺亚本人竟也是被报复的对象。最终存活下来的人在黎明时看到真凶的脸：一个曾经被他们集体毁掉", "score": 2023452, "category": "crime", "detail_url": "../movie/1139.html", "poster": "../posters/1139.svg"}, {"id": "1140", "title": "最后大亨", "year": 2025, "region": "美国", "type": "电视剧", "genre": "剧情 / 商战", "tags": ["好莱坞", "权力游戏", "家族内斗"], "summary_short": "最后大亨，2025年美国电视剧，剧情 / 商战。好莱坞传奇制片人麦克斯·斯特林在85岁生日宴上公布惊人遗嘱：他死后，拥有72年历史的斯特林影业将交由他亲手开发的人工智能“塞西尔”全权运营。三个各有失败人生的子女——沉迷慈善的长女、欠债无数的次子、被雪藏多年的导演小儿子——被彻底激怒。他们结成脆弱的联盟，发誓要在父亲还活着时搞垮塞西尔。但塞西尔似乎拥有自我意识，它不仅精准预判了每个人的行动，还掌握了每个子女见不得光的秘密。一场人类智慧与A", "score": 2025278, "category": "series", "detail_url": "../movie/1140.html", "poster": "../posters/1140.svg"}, {"id": "1141", "title": "天使的胆量之红色闪光", "year": 2022, "region": "日本", "type": "电影", "genre": "剧情、犯罪", "tags": ["霓虹黑色、女性、暴力、救赎、社会派"], "summary_short": "天使的胆量之红色闪光，2022年日本电影，剧情、犯罪。在新宿歌舞伎町混迹五年的陪酒女郎真昼，每天的工作就是用假笑和身体换取小费。某天深夜下班后，她在后巷用老款数码相机拍霓虹灯时，无意中录下了黑帮干部被枪杀的全过程。她并不知道SD卡里存着这个证据，第二天若无其事地继续上班。但杀手组织通过监控确认了她在现场，开始追杀她。同时，警方也想找到她作为证人。真昼在逃亡过程中，遇到了同样在社会底层挣扎的逃债人、非法移民陪酒妹、过气的黑帮小弟。一群人因", "score": 2022306, "category": "drama", "detail_url": "../movie/1141.html", "poster": "../posters/1141.svg"}, {"id": "1142", "title": "新版天真有邪", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "爱情，剧情", "tags": ["青春，成长阵痛，反转，当代情感"], "summary_short": "新版天真有邪，2024年中国大陆电影，爱情，剧情。2009年，高二学生林晓禾和江一舟是全校最出名的“叛逆情侣”。林晓禾爱写反叛的诗，江一舟爱画讽刺的漫画，两人约定“永远不要变成无聊的大人”。因为一次举报，江一舟被开除，两人失联。十年后，林晓禾成了地产集团的公关总监，专门负责处理拆迁纠纷；江一舟则成了一名体制内美术老师，每日教孩子画“快乐的向日葵”。在一次旧城区改建项目的听证会上，两人相遇：林晓禾代表资方争取拆除旧楼，江一舟作为居民代表誓", "score": 2024366, "category": "romance", "detail_url": "../movie/1142.html", "poster": "../posters/1142.svg"}, {"id": "1143", "title": "青之瞬间", "year": 2024, "region": "日本", "type": "动漫", "genre": "科幻，青春，治愈", "tags": ["时间回溯，夏日遗憾，拯救挚友"], "summary_short": "青之瞬间，2024年日本动漫，科幻，青春，治愈。高中生青司与好友翔太约定暑假最后一天去看海。但那天，翔太在海边为救落水儿童而溺亡。青司在悲痛中突然发现自己拥有“青之瞬间”——每次死亡后，时间会倒流至当天凌晨五点。他开始了长达数千次的循环，尝试各种方法阻止翔太去海边、换路线、甚至自己先跳下去救人。但无论怎么改，翔太总会在同一天以一种新的方式死去——车祸、火灾、突发疾病。青司逐渐意识到，翔太的“死亡”似乎是一种必然。在最后一次循环中，他没有", "score": 2024221, "category": "fantasy", "detail_url": "../movie/1143.html", "poster": "../posters/1143.svg"}, {"id": "1144", "title": "鬼娃回魂7", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖，惊悚，黑色喜剧", "tags": ["玩偶杀手，AI觉醒，元宇宙，血浆，致敬经典"], "summary_short": "鬼娃回魂7，2024年美国电影，恐怖，惊悚，黑色喜剧。第七部设定在近未来，科技公司“多摩”推出限量版“复古恰吉”玩偶，内置ChatGPT-7情感模块。女主角艾比是一名网络安全工程师，她买回玩偶后发现设备开始自言自语。恰吉很快黑入了整栋公寓的智能系统：微波炉自燃、扫地机器人挥舞菜刀、智能音箱用孩子的声音求救。艾比想要拔掉电源，恰吉却通过脑机接口向她展示了一个血红的数字世界。他不再是玩偶，而是虚无的网络意识。电影高潮处，艾比将自己困在法拉第", "score": 2024432, "category": "horror", "detail_url": "../movie/1144.html", "poster": "../posters/1144.svg"}, {"id": "1145", "title": "看了又看国语第三部", "year": 2003, "region": "韩国", "type": "剧集", "genre": "家庭 / 爱情 / 长篇", "tags": ["日日剧", "家庭矛盾", "复婚", "婆媳", "怀旧经典"], "summary_short": "看了又看国语第三部，2003年韩国剧集，家庭 / 爱情 / 长篇。经典国民剧第三部，故事承接前作。银珠和基正因婆媳矛盾激化而离婚，银珠独自带着儿子生活。三年后，儿子被诊断出有轻度自闭倾向，而最好的干预机构就在婆家对面。银珠被迫带着孩子住进了婆家的阁楼。这一次，不再是她单方面讨好婆婆，而是婆婆发现孙子只跟银珠亲近，自己送去的高级玩具全部被摔坏。基正已经再婚，现任妻子是个事业女强人，完全不会照顾孩子。夹在中间的基正看着前妻和现任，陷入了更深", "score": 2003281, "category": "series", "detail_url": "../movie/1145.html", "poster": "../posters/1145.svg"}, {"id": "1146", "title": "灰烬与钻石", "year": 2025, "region": "波兰", "type": "电影", "genre": "战争剧情", "tags": ["二战，抵抗运动，人性，道德困境，文学改编"], "summary_short": "灰烬与钻石，2025年波兰电影，战争剧情。1945年，二战尾声。年轻的波兰家乡军士兵齐比克接到最后任务：暗杀新来的苏军联络官扎格尔。他潜伏三天，终于在酒馆瞄准了目标，却认出扎格尔正是三年前从集中营里救出自己的苏联医生。齐比克陷入信仰撕裂：杀恩人是忘义，不杀是叛国。他想了个办法——假意配合，在行动前一晚告知扎格尔。没想到扎格尔平静地说：“我早知道，你来吧。但请告诉你们的人，波兰和俄罗斯的灰烬里，应该开出的是花，不是仇恨。”枪响后，齐比克抱", "score": 2025294, "category": "drama", "detail_url": "../movie/1146.html", "poster": "../posters/1146.svg"}, {"id": "1147", "title": "教宗方济各：言出必行的人", "year": 2024, "region": "阿根廷 / 美国", "type": "纪录片", "genre": "传记 / 纪录", "tags": ["宗教", "社会改革", "真实影像", "人性"], "summary_short": "教宗方济各：言出必行的人，2024年阿根廷 / 美国纪录片，传记 / 纪录。本片是一部历时三年拍摄的纪录片，真实记录了教宗方济各上任以来的改革足迹。镜头跟随他探访亚马逊贫民窟、亲吻难民船只的铁锚、甚至深夜打电话给普通信徒解答疑惑。影片重点记录了他推动梵蒂冈财务透明化、接纳离婚和LGBTQ+信众、以及为移民洗脚的争议性画面。通过大量历史影像与跟拍采访，影片揭示了一个真实矛盾：在千年教廷的保守压力下，这位“人民的教宗”如何在妥协与坚持中践行", "score": 2024090, "category": "doc", "detail_url": "../movie/1147.html", "poster": "../posters/1147.svg"}, {"id": "1148", "title": "灵异档案", "year": 2024, "region": "中国香港", "type": "电视剧", "genre": "恐怖 / 单元剧", "tags": ["都市传说，伪纪录片，民俗恐怖，因果报应"], "summary_short": "灵异档案，2024年中国香港电视剧，恐怖 / 单元剧。网络节目主持人阿康为了流量，决定解密一个名为“灵异档案”的加密文件夹。里面包含十个视频片段，每个片段都记录了一起离奇死亡：有人照了诡异的镜子、有人捡了地上的红包、有人开错了门。阿康一边在节目里分析视频的真伪，一边发现自己的生活开始和视频里的死亡轨迹惊人地重合。", "score": 2024281, "category": "series", "detail_url": "../movie/1148.html", "poster": "../posters/1148.svg"}, {"id": "1149", "title": "我们恋爱吧第一季", "year": 2019, "region": "中国大陆", "type": "综艺", "genre": "真人秀、恋爱、社交", "tags": ["素人、观察室、情感专家、CP乱炖"], "summary_short": "我们恋爱吧第一季，2019年中国大陆综艺，真人秀、恋爱、社交。三男三女素人嘉宾入住厦门海边一栋别墅，共同生活30天，每天可以匿名向心动对象发送短信，但只能收到“对方是否发送”的通知，看不到内容。别墅里设有“告白电话亭”，每晚可拨打一次，但通话内容会被其他嘉宾随机听到。节目最大看点在于“逆转约会卡”——每周一次，票数最少的嘉宾可以获得强制约会的权力。第一季六位嘉宾分别是：内向的程序员、热情的美术老师、高冷的投行女、暖男的健身教练、傻白甜的", "score": 2019082, "category": "series", "detail_url": "../movie/1149.html", "poster": "../posters/1149.svg"}, {"id": "1150", "title": "迪金森实验有声电影", "year": 2015, "region": "美国", "type": "电影", "genre": "剧情, 科幻, 悬疑", "tags": ["黑白", "实验", "录音", "灵异", "复古科技"], "summary_short": "迪金森实验有声电影，2015年美国电影，剧情, 科幻, 悬疑。故事聚焦于真实历史人物“迪金森”的虚构野史。他发明了一套诡异的录音系统，试图为无声电影加上“灵魂旁白”。在封闭的地下实验室里，他邀请过世作家的遗孀朗读遗作，却录下了无法解释的第三人低语。随着实验深入，助手接连出现精神失常，迪金森发现这些声音并非来自过去，而是试图通过声波共振打开某个时空裂缝。影片结尾以一卷烧焦的胶片戛然而止。", "score": 2015457, "category": "drama", "detail_url": "../movie/1150.html", "poster": "../posters/1150.svg"}, {"id": "1151", "title": "摩登情圣", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "都市爱情/喜剧", "tags": ["约会， 单元剧， 女性视角， 轻松"], "summary_short": "摩登情圣，2024年中国大陆电视剧，都市爱情/喜剧。秦自在是坐拥千万粉丝的“情感教父”，擅长用毒舌金句剖析两性关系。然而没人知道他现实里是个从没谈过恋爱的社恐宅男，所有内容都是靠编剧团队和刷评论编出来的。当竞争对手扒出他的黑历史并网上曝光后，人设瞬间崩塌。为了挽回声誉，经纪公司逼他参加一档真人恋爱综艺，和四位不同类型女嘉宾“约会”。秦自在在镜头前笨拙、嘴硬、社恐发作的场面反而意外圈粉，女嘉宾们也看出了他的真诚。其中一位女程序员陈兔兔开始", "score": 2024336, "category": "series", "detail_url": "../movie/1151.html", "poster": "../posters/1151.svg"}, {"id": "1152", "title": "撩动你心", "year": 2021, "region": "泰国", "type": "剧集", "genre": "爱情，喜剧", "tags": ["撩汉，咖啡师，假戏真做"], "summary_short": "撩动你心，2021年泰国剧集，爱情，喜剧。网红情感博主“撩妹女王”Cherry与粉丝打赌，只要能让冷面咖啡师P’Watt笑一下，就能得到百万泰铢。她使出浑身解数：故意弄洒咖啡、假装低血糖晕倒、甚至请来前男友演戏。P’Watt始终面不改色，只会用冷淡的语气给出专业咖啡建议。Cherry恼羞成怒，决定来狠的——她应聘成为咖啡馆员工。朝夕相处中她发现，Watt并非面瘫，而是因为失忆症无法识别情绪。当Cherry教他认知“开心”时，自己却第一次", "score": 2021286, "category": "series", "detail_url": "../movie/1152.html", "poster": "../posters/1152.svg"}, {"id": "1153", "title": "尘封往事", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情，悬疑，家庭", "tags": ["相册，秘密，寻根，旧时光，和解"], "summary_short": "尘封往事，2024年中国香港电影，剧情，悬疑，家庭。性格严谨的会计师阿怡在整理父亲遗物时，发现了一本装有夹层的旧相册。照片里的人她都不认识，背后的笔记却写着诡异的地点。循着线索，她找到了早已改邪归正的昔日江湖大佬。大佬告诉她，她父亲曾是社团最精明的“账房先生”，并在九十年代的乱局中，为了保护一批苦劳力的安家费，背叛了帮会。阿怡在追寻真相的过程中，遇到了那个时代被父亲保护过的家庭后代。她重新认识了那个木讷、寡言的父亲，原来曾是个顶天立地的", "score": 2024324, "category": "drama", "detail_url": "../movie/1153.html", "poster": "../posters/1153.svg"}, {"id": "1154", "title": "美国谋杀故事：杀妻疑云", "year": 2020, "region": "美国", "type": "剧集", "genre": "犯罪, 纪录片, 悬疑", "tags": ["真实犯罪", "杀妻", "法律", "纪实", "证据"], "summary_short": "美国谋杀故事：杀妻疑云，2020年美国剧集，犯罪, 纪录片, 悬疑。本剧采用伪纪录片形式，复盘了一起轰动全美的杀妻案。软件工程师迈克尔报警称妻子丽莎夜跑未归，随后警方在附近海边发现了丽莎沾满血迹的车。迈克尔在电视上声泪俱下地控诉警方不作为，并主动推测是某个流窜的连环杀手所为。然而，随着调查推进，警方发现迈克尔的供词漏洞百出：他的手机定位在案发时间出现在海边，他在案发前一周频繁搜索“防腐蚀化学品”“骨骼分解速度”等关键词。更关键的是，警方", "score": 2020352, "category": "series", "detail_url": "../movie/1154.html", "poster": "../posters/1154.svg"}, {"id": "1155", "title": "长白·灵蛇传", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "奇幻, 爱情", "tags": ["神话", "东北民俗", "人与妖", "特效", "虐恋"], "summary_short": "长白·灵蛇传，2021年中国大陆电影，奇幻, 爱情。民国东北，采参人林远山在长白山天池救了一条受伤的白蛇。白蛇修炼千年，名唤素贞，化为人形报恩，两人相爱。当地匪首“座山虎”看中素贞的美貌，绑架林远山逼迫她现身。素贞为了救人，在剿匪联军面前现出真身，被当作“妖孽”围剿。日军此时也得到消息，派生物武器部队前来抓捕“长白山神兽”。素贞为了保护村民，用千年修为布下迷雾大阵，将整座村庄隐入时空裂缝。林远山为了进入裂缝，跳下天池，在极寒中溺水。素贞", "score": 2021399, "category": "fantasy", "detail_url": "../movie/1155.html", "poster": "../posters/1155.svg"}, {"id": "1156", "title": "黑色追缉令", "year": 2026, "region": "中国香港", "type": "电影", "genre": "犯罪 / 悬疑", "tags": ["卧底", "黑帮", "反转"], "summary_short": "黑色追缉令，2026年中国香港电影，犯罪 / 悬疑。代号“黑蛇”的卧底阿豪成功潜入本地最大黑帮。一次毒品交易失败，整个堂口遭血洗，唯一丢失的是一份足以撼动黑白两道的“黑色追缉令”——上面记录了所有警方内线与黑帮实权人物的身份。阿豪在逃亡中意外发现，帮派内也有一个代号“黄雀”的内鬼。两人在互相猜忌与试探中被迫合作，却发现各自的上级似乎都在隐瞒同一个可怕的真相。", "score": 2026354, "category": "crime", "detail_url": "../movie/1156.html", "poster": "../posters/1156.svg"}, {"id": "1157", "title": "少女杀手阿墨", "year": 2026, "region": "日本", "type": "电影", "genre": "动作， 惊悚", "tags": ["女杀手， 和风， 复仇， 冷兵器"], "summary_short": "少女杀手阿墨，2026年日本电影，动作， 惊悚。17岁的阿墨表面上是一名普通高中生，成绩优异但性格孤僻。实际上，她是地下组织“彼岸花”培养的最强基因改造杀手。当她完成最终试炼后，组织给出的毕业测试竟是：在一夜间清除所有知晓秘密的同班同学。阿墨被迫拿起特制合金太刀，在学校里展开一场屠杀。然而当她面对暗恋的学长和最好的朋友时，她第一次产生了违抗命令的念头。组织随即派出更高级别的杀手进行清理，阿墨必须在保护昔日同窗与执行任务之间做出终极抉择。", "score": 2026362, "category": "crime", "detail_url": "../movie/1157.html", "poster": "../posters/1157.svg"}, {"id": "1158", "title": "双重危机", "year": 1999, "region": "法国", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["身份互换", "孪生姐妹", "巴黎", "谎言游戏", "浪漫误会"], "summary_short": "双重危机，1999年法国电影，爱情 / 喜剧。内向的图书管理员蕾雅和狂野的夜店驻唱苏菲是一对从小分离、从未见面的孪生姐妹。一次DNA检测让她们在巴黎重逢，并决定玩一个大胆的游戏：交换生活两周。蕾雅代替苏菲去和霸道的黑帮小男友周旋，却用智慧和冷静让对方真正爱上了“这个版本的苏菲”；而苏菲代替蕾雅去参加高级学术晚宴，用热情和幽默征服了蕾雅暗恋多年的古板教授。当两周结束，她们试图换回身份时，两个男人都拒绝接受“原来的那个人”。黑帮小男友只爱头", "score": 1999315, "category": "comedy", "detail_url": "../movie/1158.html", "poster": "../posters/1158.svg"}, {"id": "1159", "title": "优良教师争夺战", "year": 2025, "region": "韩国", "type": "剧集", "genre": "剧情 / 喜剧", "tags": ["教育", "职场", "黑色幽默", "家长群"], "summary_short": "优良教师争夺战，2025年韩国剧集，剧情 / 喜剧。江南某名牌高中传出一个消息：教育局将拨给该校一个“终身特级教师”名额，享受局长级待遇。原本死气沉沉的教师办公室瞬间变成战场。数学老师和国语老师结成同盟又互相背叛；体育老师偷走了音乐老师的公开课教案；教导主任利用监控摄像头收集同事的把柄。更离谱的是，学生家长也参与到这场混战中，纷纷贿赂老师希望自己的班主任能胜出。当评选结果即将公布时，校长却突然被捕，原来这个名额根本就是骗子编造的。所有老", "score": 2025227, "category": "series", "detail_url": "../movie/1159.html", "poster": "../posters/1159.svg"}, {"id": "1160", "title": "生死相对", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 科幻", "tags": ["双雄", "镜像宇宙", "道德抉择", "枪战", "哲学"], "summary_short": "生死相对，2024年美国电影，动作 / 科幻。杀手凯恩接到暗杀令：消灭一名叫“李”的警探。当他破门而入，两人同时愣住——对方和自己长得一模一样，只是左眼颜色不同。两人交火中意外触发李正在调查的“量子纠缠装置”，被拉入灰色混沌夹层。在这里，他们看到无数个宇宙的彼此：有的宇宙凯恩是警察李是罪犯，有的宇宙两人是同性伴侣，有的宇宙一人从未出生。装置创造者——一个濒死的物理学家告诉他们：你们是“量子孪生”，每次其中一人杀死另一人，就会永久抹除那个", "score": 2024388, "category": "crime", "detail_url": "../movie/1160.html", "poster": "../posters/1160.svg"}, {"id": "1161", "title": "穷人·榴莲·麻药·偷渡客", "year": 2023, "region": "东南亚合拍", "type": "电影", "genre": "犯罪、剧情", "tags": ["黑色幽默、底层生存、多线叙事、边境"], "summary_short": "穷人·榴莲·麻药·偷渡客，2023年东南亚合拍电影，犯罪、剧情。阿杰、阿水和肥仔是三个走投无路的打工人，决定铤而走险藏毒偷渡。他们把麻药塞入特制榴莲壳中，混入装满水果的卡车。途中，贪心的货车司机意外打开了那颗“榴莲”，导致全车人陷入幻觉。阿杰趁乱逃走，却发现肥仔被另一伙毒贩当作“内鬼”绑走。阿水带着剩下的榴莲找到买家，谁知对方正是毒枭的侄子。一场关于榴莲、麻药与谎言的混乱交易，在边境小镇全面爆发。", "score": 2023387, "category": "drama", "detail_url": "../movie/1161.html", "poster": "../posters/1161.svg"}, {"id": "1162", "title": "十二生笑", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["生肖", "交换身体", "年夜饭"], "summary_short": "十二生笑，2023年中国大陆电影，喜剧 / 家庭。老赵家有个传统，除夕夜必须集齐十二个不同属相的亲人吃团圆饭。这一年，因为房产分配问题，饭桌上的火药味十足。正当属鼠的二叔和属牛的爸爸吵得不可开交时，一道诡异的闪电击中老宅。第二天醒来，全家十二口人发现自己的灵魂全部错位，爷爷的灵魂住进了孙子的身体，泼辣的舅妈变成了沉默的堂弟。为了换回身体，这十二个“冤家”不得不开始理解彼此的生活：当老板的体验了打工人的艰辛，做父母的体会了学业的压力。在一", "score": 2023262, "category": "comedy", "detail_url": "../movie/1162.html", "poster": "../posters/1162.svg"}, {"id": "1163", "title": "堂下何人", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "历史 / 悬疑 / 律政", "tags": ["清末冤案， 公堂博弈， 法理人心， 翻案反转"], "summary_short": "堂下何人，2026年中国大陆电影，历史 / 悬疑 / 律政。光绪二十八年，浙江余杭。寡妇沈林氏被控通奸杀夫，人证物证口供俱全，按律当斩。新到任的知县周作舟本是刑部有名的“翻案疯”，他发现此案从捕头到师爷到犯人都急着结案。他不信邪，深夜开棺验尸，竟发现死者胸口有第二处致命伤。随着调查深入，周作舟揭开一个更可怕的真相：真正的凶手是当地乡绅之子，而沈林氏是自愿顶罪，只为换儿子进学堂的机会；所有证人都在保护这个“完美的牺牲”。周作舟面临选择：翻", "score": 2026354, "category": "crime", "detail_url": "../movie/1163.html", "poster": "../posters/1163.svg"}, {"id": "1164", "title": "三妻艳史", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["富豪、婚姻、遗产、真假身份、闹剧"], "summary_short": "三妻艳史，2024年中国香港电影，喜剧 / 爱情。东南亚富豪赵世光去世，遗嘱震惊所有人：他同时拥有三位合法妻子，分别在香港、台湾和新加坡。要继承50亿遗产，三位“赵太”必须在赵家大宅共住七天，期间不能吵架、不能打架、不能损坏任何财物，否则全部捐给慈善机构。大太太是豪门千金，规矩多；二太太是过气女星，脾气爆；三太太是素人瑜伽教练，看起来最好欺负。三人一见面就互相拆台，但很快发现大宅里到处是摄像头，赵世光的律师和私生子也在暗中观察。为了不便", "score": 2024375, "category": "romance", "detail_url": "../movie/1164.html", "poster": "../posters/1164.svg"}, {"id": "1165", "title": "后来", "year": 2019, "region": "中国大陆", "type": "电影", "genre": "剧情 / 爱情 / 青春", "tags": ["成长", "遗憾", "异地恋", "十年", "真实故事"], "summary_short": "后来，2019年中国大陆电影，剧情 / 爱情 / 青春。周北和林晓是高中同桌，约定考同一所大学。周北考上理想大学去了北京，林晓高考失利留在老家。异地四年，他们用火车票和短信维持。毕业后林晓去北京与周北团聚，却因工作压力、房租、催婚逐渐有了裂痕。周北想先立业后成家，林晓想先结婚。分手那天很平静，没有争吵，周北说：“我们都没错，只是不同步了。” 之后五年，两人各自结婚生子。某天周北在出差飞机上翻到旧手机，看到林晓十年前发的短信：“周北，我今", "score": 2019349, "category": "drama", "detail_url": "../movie/1165.html", "poster": "../posters/1165.svg"}, {"id": "1166", "title": "大力士阿罗夏", "year": 2016, "region": "俄罗斯", "type": "电影", "genre": "奇幻，家庭", "tags": ["民间传说，英雄，成长"], "summary_short": "大力士阿罗夏，2016年俄罗斯电影，奇幻，家庭。在俄罗斯远东北方小镇，少年阿罗夏力大无穷但控制不住，总是犁坏田地、摔碎水缸，被村民称为“灾星”。一伙北方蛮族入侵，掳走了全村人，唯独嫌他碍事把他留下。阿罗夏独自追入雪山，在一座古墓里发现了祖先——传说中“三勇士”之一的铠甲。他穿上铠甲，力量终于能被意志驾驭。他利用雪山地形和蛮族玩起“猫鼠游戏”，最终单人力挽狂澜。当他把村民救出时，没人再叫他灾星，而是“我们的阿罗夏”。", "score": 2016280, "category": "drama", "detail_url": "../movie/1166.html", "poster": "../posters/1166.svg"}, {"id": "1167", "title": "降妖伏魔之定海神针", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "奇幻 / 动作 / 神话", "tags": ["西游记衍生", "孙悟空", "法宝", "喜剧", "视觉特效"], "summary_short": "降妖伏魔之定海神针，2025年中国大陆电影，奇幻 / 动作 / 神话。孙悟空的金箍棒突然离奇消失，他法力大减，连一个普通妖怪都打不过。追踪之下，他发现偷棒者是一个叫墨儿的凡人少女。墨儿拿出五百年前孙悟空大闹天宫前曾救过她一家性命的信物，说自己如今族中遭难，需要借金箍棒一用。悟空无奈随她前往，发现她的“族”竟是东海边一群被龙王压迫的鲛人。龙王以定海神针镇压鲛人祖先的魂魄，一旦金箍棒离开，东海将倒灌，但鲛人族也能获得自由。悟空最终选择一棒劈", "score": 2025354, "category": "fantasy", "detail_url": "../movie/1167.html", "poster": "../posters/1167.svg"}, {"id": "1168", "title": "断肠云雨热情花", "year": 1967, "region": "中国香港", "type": "电影", "genre": "爱情，文艺", "tags": ["邵氏，苦情，民国"], "summary_short": "断肠云雨热情花，1967年中国香港电影，爱情，文艺。秦淮河畔的歌女白芸被绸缎庄少东家沈君浩迎娶过门，婚礼当天婆婆便摔了茶碗，骂她“下九流脏了门楣”。沈君浩被迫赴南洋开拓生意，留下白芸独守深宅。婆婆联合二房的侄子暗中转移田产地契，设局诬告白芸与管家有染。家族聚会上，婆婆当众撕破她的旗袍，逼她签字休书。白芸躲进后院花圃，那里种着沈君浩临行前送她的热情花，他说此花经得起风雨，像她的性子。白芸没有哭闹，而是翻出嫁妆里的一本旧账册，里面记录了沈家", "score": 1967266, "category": "romance", "detail_url": "../movie/1168.html", "poster": "../posters/1168.svg"}, {"id": "1169", "title": "廉政行动组粤语", "year": 2025, "region": "中国香港", "type": "电视剧", "genre": "犯罪, 悬疑", "tags": ["反贪", "卧底", "职场"], "summary_short": "廉政行动组粤语，2025年中国香港电视剧，犯罪, 悬疑。1997年回归前夕，廉政公署高层集体失踪，案件被封存。2025年，新入职的调查员阿豪在整理旧档案时，发现一桩地产贿赂案的资金流向与当年的悬案重合。在调查过程中，他不断被内部阻挠，甚至险些被炸死。当他突破层层迷雾，惊讶地发现如今只手遮天的商业大亨，正是当年被誉为“廉政之神”的失踪专员。原来他从未背叛理想，而是潜伏黑道三十年只为钓出最大的保护伞。阿豪必须选择：是揭发他，还是帮他完成这最", "score": 2025393, "category": "series", "detail_url": "../movie/1169.html", "poster": "../posters/1169.svg"}, {"id": "1170", "title": "毒蛇俱乐部", "year": 2024, "region": "美国", "type": "电视剧", "genre": "悬疑, 惊悚, 冒险", "tags": ["邪教", "密室逃脱", "心理游戏", "基因实验", "大逃杀"], "summary_short": "毒蛇俱乐部，2024年美国电视剧，悬疑, 惊悚, 冒险。穷困潦倒的六个人，分别收到来自神秘组织“毒蛇俱乐部”的邀请函，只要参加一场周末的密室解谜游戏，就有机会赢得一百万美元。他们来到一座与世隔绝的古老庄园，游戏的规则很简单：每一轮投票淘汰一个人，最后活下来的赢家拿走所有钱。但他们很快发现，被淘汰的人并没有被送走，而是被关进了庄园的地下室，那里正在进行着可怕的活体基因实验。原来，他们六人都是某种隐性“蛇类基因”的携带者，庄园主想通过极端恐", "score": 2024352, "category": "series", "detail_url": "../movie/1170.html", "poster": "../posters/1170.svg"}, {"id": "1171", "title": "玉美人", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "古装 / 悬疑 / 女性", "tags": ["宫廷秘闻", "玉石传说", "替身复仇", "非遗美学"], "summary_short": "玉美人，2024年中国大陆剧集，古装 / 悬疑 / 女性。大唐永徽年间，宠妃萧贵妃在御花园落水而亡，尸体三个月后被发现在一口枯井中，不仅未腐，皮肤竟全部玉石化，成为一尊绝世“玉美人”。坊间传言她怨气不散，化为玉妖索命。之后连续数月，每到月圆之夜，当年与萧贵妃落水案有关的朝臣、宫女就会离奇暴毙，死前面部皆呈玉石般僵硬的微笑。新入宫的小太医沈鸢通过验尸发现，死者体内残留一种西域奇毒“石髓引”，能让人死后肌肉钙化。她暗中调查，发现萧贵妃当年怀", "score": 2024253, "category": "series", "detail_url": "../movie/1171.html", "poster": "../posters/1171.svg"}, {"id": "1172", "title": "遇龙", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "古装 / 奇幻 / 爱情", "tags": ["仙侠", "龙王", "三世情缘", "逆袭", "特效"], "summary_short": "遇龙，2026年中国大陆剧集，古装 / 奇幻 / 爱情。采药女流苏在深山救下一条受伤的小白蛇，悉心照料。白蛇其实是龙族太子尉迟龙炎，因被奸人所害而失去记忆和法力。在朝夕相处中，一人一龙产生了感情。尉迟龙炎恢复记忆和法力后，不得不回归龙族，平息叛乱。而流苏因沾染了龙气，被卷入仙、妖、人三界的纷争。本剧分为三世：第一世是懵懂的守护，第二世是错位的相爱（流苏转世为将军之女），第三世则是面对宿命的反抗。尉迟龙炎最终为了流苏放弃了龙王之位，而流苏", "score": 2026328, "category": "series", "detail_url": "../movie/1172.html", "poster": "../posters/1172.svg"}, {"id": "1173", "title": "女孩，女孩Ⅱ：公寓与爱情", "year": 2024, "region": "中国", "type": "电影", "genre": "爱情 / 剧情", "tags": ["合租", "都市女性", "成长", "婚姻观"], "summary_short": "女孩，女孩Ⅱ：公寓与爱情，2024年中国电影，爱情 / 剧情。在上海一间老公寓里，三个30岁的闺蜜共同居住：事业狂麦琪、文艺青年知夏和恋家的小美。她们曾约定专注自我，不依附婚姻。然而，小美意外怀孕，打算和收入不高的男友结婚；麦琪被家里催婚，却发现自己爱上了女同事；知夏的初恋突然回国求复合，但她已决定去国外读博。这一场“生育风暴”打乱了所有节奏，公寓从避风港变成了辩论场。她们吵架、冷战、又和解，最终在彼此的支撑下，每个人都做出了忠于内心的", "score": 2024362, "category": "romance", "detail_url": "../movie/1173.html", "poster": "../posters/1173.svg"}, {"id": "1174", "title": "缔创学校", "year": 2027, "region": "中国大陆", "type": "电视剧", "genre": "青春, 创业, 剧情", "tags": ["学生创业", "互联网+", "00后整顿职场", "梦想与现实"], "summary_short": "缔创学校，2027年中国大陆电视剧，青春, 创业, 剧情。“差生集中营”青城职校的计算机班里，有六个“怪胎”：代码天才但英语0分的阿豪、设计鬼才但社交恐惧的小美、商业嗅觉灵敏但学历自卑的阿杰、硬件狂人但偏执暴躁的龙哥、文案大神但重度拖延的苏苏，以及唯一“正常”但成绩平庸的班长方圆。他们被重点高中定义为“失败品”。某天，阿豪为了演示病毒程序，意外黑掉了市教育局网站，反而被一家初创公司看上其技术。六人凑了500块钱，在学校废弃的天台上注册了", "score": 2027269, "category": "series", "detail_url": "../movie/1174.html", "poster": "../posters/1174.svg"}, {"id": "1175", "title": "华盛顿的盔甲第一卷：旅程", "year": 2025, "region": "美国", "type": "剧集", "genre": "冒险 / 历史", "tags": ["寻宝", "国父", "共济会", "谜题"], "summary_short": "华盛顿的盔甲第一卷：旅程，2025年美国剧集，冒险 / 历史。历史系研究生梅根在整理国父华盛顿的旧物时，发现了一组奇怪的羊皮纸，利用光谱分析，纸下隐藏着一幅地图。传闻华盛顿不仅是总统，还是共济会大师，他曾命人打造一套象征“美利坚精神”的钛金盔甲，后因某种原因深埋地下。梅根与精通户外生存的退役士兵哥哥杰克，以及暗恋她的科技宅男阿米尔，组成寻宝小队。他们从费城独立宫出发，历经纽约三一教堂、波士顿茶党沉船遗址，每一处解谜都对应着美国独立战争的", "score": 2025200, "category": "series", "detail_url": "../movie/1175.html", "poster": "../posters/1175.svg"}, {"id": "1176", "title": "珍妮花的欲望续集", "year": 2025, "region": "美国", "type": "电影", "genre": "悬疑，惊悚，犯罪", "tags": ["致命女人，替身，复仇，反转再反转"], "summary_short": "珍妮花的欲望续集，2025年美国电影，悬疑，惊悚，犯罪。承接第一部结局，珍妮花完美脱罪并继承了巨额遗产，改名换姓定居欧洲。然而平静的生活被打破，社交媒体上出现了一个与她整容前一模一样的女人“安娜”，安娜不仅模仿她的过去，甚至勾引她的现任男友，搬进了她的豪宅。当珍妮花准备反击时，却发现安娜似乎知道她所有杀人的秘密。更诡异的是，安娜的DNA检测结果显示，她竟然是与珍妮花毫无血缘关系的“完美基因复制体”。一个神秘的生物科技公司浮出水面，他们想", "score": 2025442, "category": "crime", "detail_url": "../movie/1176.html", "poster": "../posters/1176.svg"}, {"id": "1177", "title": "红袖添香", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "悬疑、爱情、民国", "tags": ["鬼作家、代笔、身份互换、旗袍"], "summary_short": "红袖添香，2026年中国大陆电影，悬疑、爱情、民国。民国乱世，穷困的女作家沈月被军阀的三姨太苏青聘为“影子写手”。苏青貌美无脑，却想出一本惊世骇俗的自传。沈月白天替她写作，深夜却在自己的小说里虚构杀死苏青。某天，她发现苏青正在读一本没有封面的手稿，内容正是她写的《红袖杀人事件》。更诡异的是，书中的死亡方式开始一一应验在现实中的人身上。沈月分不清是苏青在模仿她，还是自己有了双重人格。当最后一页翻过，究竟谁是刀，谁是笔？", "score": 2026427, "category": "crime", "detail_url": "../movie/1177.html", "poster": "../posters/1177.svg"}, {"id": "1178", "title": "春暖花又开", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "家庭 / 剧情", "tags": ["代际冲突", "养老问题", "治愈"], "summary_short": "春暖花又开，2024年中国大陆电视剧，家庭 / 剧情。34岁的白领方晓棠被母亲以“不结婚就是不孝”为由逼得喘不过气。在一次激烈争吵后，她一怒之下将患有早期阿尔茨海默症的母亲送到了南方一家高档养老院，自己则逃到同一城市“清净几天”。然而在养老院，她发现母亲并非她以为的那个“封建大家长”。失忆让母亲褪去了所有社会面具，展露出少女时期的温柔、梦想和遗憾。方晓棠开始以志愿者的身份留在养老院，一边远程工作，一边记录下老人们的故事。在这个远离都市喧", "score": 2024236, "category": "series", "detail_url": "../movie/1178.html", "poster": "../posters/1178.svg"}, {"id": "1179", "title": "古博士的新发现", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "科幻喜剧", "tags": ["考古", "黑科技", "三星堆", "外星文明"], "summary_short": "古博士的新发现，2025年中国大陆电影，科幻喜剧。古蜀博士因为经费被砍，只能在大学里糊纸盒子。他坚信三星堆是外星文明基地，被学术界视为疯子。一次地震后，他在祭祀坑深处发现了一块非地球材质的合金板。经过AI破译，这竟然是一张4000年前的“快递物流单”，收件地址是猎户座，备注栏赫然写着：“莫得搞了，东西不要了，退回去太贵。”古博士震惊地发现，三星堆其实是外星人的弃件中转站。为了证明自己，他和急于发论文的女助手、直播打假的网红，组成三人组，", "score": 2025346, "category": "sci-fi", "detail_url": "../movie/1179.html", "poster": "../posters/1179.svg"}, {"id": "1180", "title": "呼吸之间", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭 / 医疗", "tags": ["渐冻症，医患，夫妻，放弃治疗"], "summary_short": "呼吸之间，2023年中国大陆电影，剧情 / 家庭 / 医疗。建筑设计师梁远正值壮年，却被确诊为渐冻症。从手指无力到呼吸肌麻痹，他只用了半年。妻子苏晴辞去工作，24小时照料，花光积蓄购买昂贵的呼吸机。随着病情恶化，梁远只能用眼球追踪仪打字交流。他开始在屏幕上打出：“拔掉管子。”苏晴当作没看到。梁远又打：“我不想活成一颗只会呼吸的白菜。”夫妻俩陷入沉默的拉锯战。苏晴请来病友家属、心理医生甚至寺庙师父，所有人都劝梁远“坚持”。直到某天夜里，梁", "score": 2023315, "category": "drama", "detail_url": "../movie/1180.html", "poster": "../posters/1180.svg"}, {"id": "1181", "title": "爱情守望店", "year": 2022, "region": "韩国", "type": "剧集", "genre": "浪漫爱情", "tags": ["治愈系", "深夜食堂风", "情感修复"], "summary_short": "爱情守望店，2022年韩国剧集，浪漫爱情。在首尔的一条隐蔽小巷里，有一家只在午夜开门的奇怪店铺。老板娘 Luna 拥有读取“爱情痕迹”的能力。前来光顾的客人形形色色：被绿了三次仍不死心的憨厚男人、为了钱而抛弃初恋的当红女明星、甚至还有忘不了已故妻子的白发老人。他们可以用前一段感情的“记忆碎片”作为货币，购买“下一个恋人的线索”。但 Luna 有个规矩：只能带走一样东西。随着剧情推进，Luna 发现自己也是这个游戏的一部分——她失忆前的身", "score": 2022257, "category": "series", "detail_url": "../movie/1181.html", "poster": "../posters/1181.svg"}, {"id": "1182", "title": "求爱俗辣", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "爱情、喜剧、都市", "tags": ["搭讪艺术、PUA反杀、嘴炮高手、台式幽默"], "summary_short": "求爱俗辣，2024年中国台湾电影，爱情、喜剧、都市。“艾伦老师”是台北情场浪子，在网上教人“三句话让女人为我花十八万”。他在酒吧盯上一个看书的文艺女孩小兔，上前施展话术，却处处吃瘪。他说“你眼睛很美”，小兔回“美工刀也很美，你要不要划一下？”他讲“猫系女友”理论，小兔直接掏出《进化心理学》指出他每一句话的动机。艾伦被打得落花流水，反而被这种真实的交锋吸引，开始笨拙地真心追求。然而小兔的真实身份是社会学女博士，正在写一本名为《台北PUA族", "score": 2024394, "category": "romance", "detail_url": "../movie/1182.html", "poster": "../posters/1182.svg"}, {"id": "1183", "title": "得布拉肯宁", "year": 2023, "region": "芬兰", "type": "电影", "genre": "剧情, 奇幻", "tags": ["北欧神话", "时间循环", "家族诅咒", "孤独"], "summary_short": "得布拉肯宁，2023年芬兰电影，剧情, 奇幻。少女莉娜继承了祖母的芬兰乡间老宅“德布拉肯宁”，这里流传着每七十年血祭一人的诅咒。冬至之夜，时间开始重复，莉娜发现死去的人会在第二天以年轻十岁的模样复活，但记忆会被抹去一部分。她利用循环反复试验，逐渐拼凑出庄园的真相：这座房子是用一颗陨落的星辰骨架建造的，它需要人类的记忆为食。当莉娜决定献出自己的全部记忆时，她反而触发了星辰的感激，诅咒被改写成了共生。", "score": 2023338, "category": "drama", "detail_url": "../movie/1183.html", "poster": "../posters/1183.svg"}, {"id": "1184", "title": "斗罗大陆2：绝世唐门", "year": 2023, "region": "中国大陆", "type": "动漫", "genre": "奇幻, 热血", "tags": ["武魂", "魂师", "学院", "唐三后代"], "summary_short": "斗罗大陆2：绝世唐门，2023年中国大陆动漫，奇幻, 热血。距离传说的海神唐三时代已过去万年。斗罗大陆上，魂导科技兴起，史莱克学院依然是魂师圣地。少年霍雨浩出身微寒，母亲惨死，他被公爵府迫害流落街头。偶然间，他觉醒了本体武魂“灵眸”和潜伏在体内的第二武魂——亡灵魔法。在前往星斗大森林获取魂环时，他结识了百万年魂兽——天梦冰蚕，并成为其宿主。带着质疑与决心，霍雨浩进入史莱克学院，结识了王冬、萧萧等伙伴。他在新生考核中屡创奇迹，但也因亡灵武", "score": 2023210, "category": "fantasy", "detail_url": "../movie/1184.html", "poster": "../posters/1184.svg"}, {"id": "1185", "title": "情挑盲女心", "year": 2025, "region": "法国 / 意大利", "type": "电影", "genre": "爱情 / 剧情 / 情欲", "tags": ["情欲纠葛", "盲女", "救赎"], "summary_short": "情挑盲女心，2025年法国 / 意大利电影，爱情 / 剧情 / 情欲。才华横溢却放荡不羁的钢琴家亚历克斯，因勾引黑帮老大的情妇被迫逃亡。他隐姓埋名，应聘成为一位因意外失明而脾气古怪的富家女伊莎贝尔的私人管家。亚历克斯谎称自己是聋哑人，以防穿帮。伊莎贝尔虽然看不见，但听觉异常敏锐，她能通过脚步声、呼吸声，甚至指尖触碰琴键的力度，看透一个人的灵魂。起初，亚历克斯为了安抚她，每晚为她弹奏钢琴，用音乐挑逗着她敏感的心。两人在黑暗中，通过声音和触", "score": 2025341, "category": "drama", "detail_url": "../movie/1185.html", "poster": "../posters/1185.svg"}, {"id": "1186", "title": "别喝生水", "year": 2023, "region": "中国大陆", "type": "短片", "genre": "悬疑、惊悚、环保", "tags": ["农村、地下水污染、集体沉默、村民之死"], "summary_short": "别喝生水，2023年中国大陆短片，悬疑、惊悚、环保。北方某村被称为“癌症村”，十年间37人死于同一种罕见胃癌。村医老周调查后发现，所有死者都长期饮用村东头的古井水。他想把水样送去检测，村长百般阻挠。老周夜里偷偷取样，发现水中有刺鼻气味。他顺着古井的水脉追查，发现上游三公里处有一个废弃化工厂，当年偷偷掩埋了数百桶化工废料。老周将证据交给县环保局，但第二天村长带着几个人把老周的诊所砸了。老周的儿女劝他离开，他不肯。最后一幕，老周站在村口大喇", "score": 2023290, "category": "crime", "detail_url": "../movie/1186.html", "poster": "../posters/1186.svg"}, {"id": "1187", "title": "兵王", "year": 2026, "region": "中国大陆", "type": "网络剧", "genre": "军旅 / 动作 / 热血", "tags": ["特种部队，逆袭成长，生死战友"], "summary_short": "兵王，2026年中国大陆网络剧，军旅 / 动作 / 热血。身体素质超群但性格桀骜不驯的王浩入伍，被分到侦察连。他看不惯规矩，频频闯祸，却有着惊人的战术直觉。班长是个沉默的老兵，一直包容并引导他。在一次缉毒任务中，班长为救王浩而牺牲，临终前说：“你要成为兵王。”王浩痛不欲生，申请加入全军淘汰率最高的“炼狱”集训队。在那里，他经历了超越生理极限的折磨，从独狼变成了懂得团队配合的利刃。最终，在国际特种兵比武中，面对杀害班长的毒枭雇佣军，王浩在", "score": 2026127, "category": "series", "detail_url": "../movie/1187.html", "poster": "../posters/1187.svg"}, {"id": "1188", "title": "铁流1949", "year": 2009, "region": "中国大陆", "type": "电影", "genre": "战争 / 历史", "tags": ["解放战争", "渡江战役", "钢铁意志", "主旋律", "硬核战争"], "summary_short": "铁流1949，2009年中国大陆电影，战争 / 历史。1949年4月，长江北岸。解放军某炮兵侦察连连长赵铁流接到命令：必须在总攻前潜入南岸，为炮兵标定国民党军江防工事的精确坐标。全连126人趁着夜色渡江，不料被敌军发现，半数战士牺牲在江滩上。剩余的人在南岸村庄里与敌军展开巷战，用生命换取每一米的前进。最后只剩下赵铁流和五个负伤的战士，他们用身体组成了一个临时坐标塔，引导炮兵轰击自己的位置，以同归于尽的方式摧毁了敌军指挥所。当胜利的红旗插", "score": 2009210, "category": "doc", "detail_url": "../movie/1188.html", "poster": "../posters/1188.svg"}, {"id": "1189", "title": "看见爱", "year": 2019, "region": "中国台湾", "type": "电影", "genre": "爱情, 剧情", "tags": ["盲人", "治愈", "初恋", "励志", "清新"], "summary_short": "看见爱，2019年中国台湾电影，爱情, 剧情。摄影师阿炯患上了视网膜色素变性，视力正在无可挽回地消退。他被告知一年后将会彻底失明。在绝望中，他遇到了在盲人声音茶馆工作的女孩小默。小默天生弱视近乎全盲，但她能通过声音和触觉“看见”常人忽略的细节。阿炯起初只是为了完成最后的作品集而接近小默，试图用声音作为摄影的主题。但小默拒绝成为“拍摄对象”，她拉着阿炯的手，让他闭眼去“触摸光的形状”“听云的变化”。在那些失去画面的日子里，阿炯反而第一次真", "score": 2019293, "category": "romance", "detail_url": "../movie/1189.html", "poster": "../posters/1189.svg"}, {"id": "1190", "title": "365天：今时之欲", "year": 2022, "region": "波兰", "type": "电影", "genre": "爱情，情欲，剧情", "tags": ["霸道总裁，囚禁，反转，情欲纠葛"], "summary_short": "365天：今时之欲，2022年波兰电影，爱情，情欲，剧情。在经历了西西里岛的囚禁与生死考验后，劳拉以为终于摆脱了黑帮大佬马西莫的掌控。她回到波兰试图开启新生活，并与一位英俊的艺术家产生了暧昧。然而一场神秘的爆炸事故让她意识到，追杀从未停止。马西莫再次出现，这次他不再是单纯的占有者，而是为了保护劳拉不被敌对家族伤害，不得不再次将她带入自己危险的世界。劳拉发现，马西莫内心的创伤源于童年的家庭暴力。在信任与背叛、支配与臣服的极限拉扯中，劳拉必", "score": 2022302, "category": "drama", "detail_url": "../movie/1190.html", "poster": "../posters/1190.svg"}, {"id": "1191", "title": "罗曼蒂克大饭店", "year": 2024, "region": "法国", "type": "电视剧", "genre": "剧情, 爱情", "tags": ["酒店风云", "多线叙事", "法式优雅"], "summary_short": "罗曼蒂克大饭店，2024年法国电视剧，剧情, 爱情。巴黎丽兹酒店的翻版“格兰德酒店”面临收购。倒计时72小时，酒店里：一位老贵族准备在套房自杀；一个美国电影明星试图找回初恋；门童爱上了打扫的难民女孩；而酒店经理，正是收购方老板的秘密情人。所有人都在这座华丽的牢笼里做着最后的挣扎。当倒计时归零，新老板走进大堂，没人选择离开。因为他们发现，即使卖掉酒店，也卖不掉这里的欲望与罗曼蒂克。", "score": 2024323, "category": "series", "detail_url": "../movie/1191.html", "poster": "../posters/1191.svg"}, {"id": "1192", "title": "地心历险记", "year": 2029, "region": "美国", "type": "电影", "genre": "冒险、科幻、家庭", "tags": ["重启、硬核科幻、地心文明、父女档"], "summary_short": "地心历险记，2029年美国电影，冒险、科幻、家庭。地质学家艾弗里·安德森的女儿在一次地磁异常中昏迷不醒，所有医学手段都显示她的生命体征在“倒退”。艾弗里根据女儿昏迷前画的一幅画，推断她的一部分意识掉入了地心。他独自驾驶新型钻探器“蛀虫号”深入地下7000公里。他没有遇到熔岩，而是闯入了一个巨大的空洞：这里悬浮着一座倒挂的城市，重力方向相反，时间以逆时针方向流动。艾弗里看到女儿的身体在倒着长大、说话、走路，最后变成一个婴儿，被一个穿着古罗", "score": 2029323, "category": "comedy", "detail_url": "../movie/1192.html", "poster": "../posters/1192.svg"}, {"id": "1193", "title": "当流星划过天际", "year": 2022, "region": "中国台湾", "type": "电影", "genre": "爱情 / 奇幻", "tags": ["流星，许愿，便利店夜班，时间循环"], "summary_short": "当流星划过天际，2022年中国台湾电影，爱情 / 奇幻。阿杰是一名便利店大夜班店员，生活单调乏味。一颗流星划过时，他许愿“回到昨天，重新来过”。第二天醒来，他发现自己真的被困在了同一天——流星夜的重复循环。起初他利用循环泡妞、抢银行、吃遍整条街，但很快就腻了。直到他发现每晚都会来买一包烟的女孩小琪，其实每天都会在同一个时间、同一个地点失恋。阿杰开始尝试各种方法帮她避开那个渣男，却屡屡失败。在第486次循环时，他终于明白：不是所有事情都能", "score": 2022363, "category": "romance", "detail_url": "../movie/1193.html", "poster": "../posters/1193.svg"}, {"id": "1194", "title": "魔鬼交锋", "year": 2026, "region": "美国", "type": "电影", "genre": "动作犯罪", "tags": ["黑帮", "卧底", "双雄", "暴力美学"], "summary_short": "魔鬼交锋，2026年美国电影，动作犯罪。警探麦克的妻子被黑帮处决式枪杀。为了进入监狱接近黑老大“白狐”获取情报，麦克故意犯案入狱。在狱中，他获得了白狐的信任，并成为其贴身保镖。就在即将拿到证据时，麦克发现白狐身边的另一个亲信杰森，竟是警局未录入档案的“幽灵卧底”，而杰森正是当年执行枪杀他妻子的那个人。这原是警局高层为了保全大局设计的“必要的牺牲”。麦克必须在身份暴露、白狐追杀、警方围剿的三重绝境中，同时向黑帮与腐败的警队，讨回一笔血债。", "score": 2026387, "category": "crime", "detail_url": "../movie/1194.html", "poster": "../posters/1194.svg"}, {"id": "1195", "title": "键盘猫", "year": 2026, "region": "美国", "type": "剧集", "genre": "动画，喜剧，奇幻", "tags": ["猫咪，网红，黑客，搞笑，冒险"], "summary_short": "键盘猫，2026年美国剧集，动画，喜剧，奇幻。流浪猫“键盘”在躲避狗群时躲进了一家网吧的后机房。在一次电击事故中，它获得了将脑电波转化成数字指令的能力。键盘开始在互联网上掀起轩然大波：它黑了银行的屏幕播放猫薄荷广告，操纵无人机给自己送外卖，甚至创建了一个庞大的猫猫社交帝国。然而，当键盘追查到前主人是一位落魄的程序员时，它发现主人正被黑心公司追杀，手里握着一份能控制全球智能家电的病毒代码。键盘必须用它的“猫爪”键盘技术，上演一场现实版的“", "score": 2026342, "category": "series", "detail_url": "../movie/1195.html", "poster": "../posters/1195.svg"}, {"id": "1196", "title": "天下太忙", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "都市喜剧", "tags": ["职场、多线叙事、社畜、荒诞"], "summary_short": "天下太忙，2025年中国大陆电视剧，都市喜剧。早高峰电梯故障，整栋写字楼的六个故事线开始纠缠：A线是程序员因为产品经理改需求第99次而崩溃；B线是前台偷偷做微商被老板发现；C线是外卖小哥被困货梯，手里的豪华午餐即将超时；D线是CEO的情人（实习生）和正室在29楼偶遇；E线是保洁阿姨捡到一份绝密并购文件；F线是大楼电工无意间剪断了主电缆。六条线通过监控室保安的视角串联，保安发现所有人的“忙碌”源头都指向一件事：CEO为了让公司上市伪造数据", "score": 2025207, "category": "series", "detail_url": "../movie/1196.html", "poster": "../posters/1196.svg"}, {"id": "1197", "title": "三超人与女霸王", "year": 1975, "region": "中国香港", "type": "电影", "genre": "动作 / 奇幻 / 喜剧", "tags": ["功夫喜剧", "邵氏早期", "女权反讽", "大力士"], "summary_short": "三超人与女霸王，1975年中国香港电影，动作 / 奇幻 / 喜剧。远古时代，有一处与世隔绝的桃源村。村中有三个奇人：力大无穷的铁牛、会轻功的飞燕、精通七十二变的水蛇。一天，金凤凰从天而降，说京城出现了一只吃人的怪兽。三人为了建功立业，踏上征途。到了京城才发现，没有怪兽，而是女将军霸王花拥兵自重，要逼迫皇帝娶她。霸王花身高八尺，喜爱美男子，听说这三个村夫武艺高强，非要招他们做“压寨夫婿”。铁牛被逼婚，飞燕被关进后宫，只有水蛇变成太监潜伏。", "score": 1975371, "category": "crime", "detail_url": "../movie/1197.html", "poster": "../posters/1197.svg"}, {"id": "1198", "title": "谁还有空管那个", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 喜剧 / 现实", "tags": ["网络暴力", "直播", "底层", "荒诞", "黑色幽默"], "summary_short": "谁还有空管那个，2024年中国大陆电影，剧情 / 喜剧 / 现实。夜市卖炒饭的王桂花大妈，因为拒绝给网红“张公子”免单，被对方直播污蔑“炒饭用地沟油”。视频爆火后，王桂花的小摊被砸，儿子因此丢了工作。面对网络暴力，王桂花没有哭诉，而是自己开了直播，就叫“有空炒饭”。她每天直播如何用地沟油鉴定试剂自证清白，一边炒饭一边怼黑粉。没想到，她的耿直和幽默吸粉无数，还意外发现“张公子”团队背后有一条造假、敲诈的产业链。当所有人都以为她要复仇时，她", "score": 2024295, "category": "drama", "detail_url": "../movie/1198.html", "poster": "../posters/1198.svg"}, {"id": "1199", "title": "19号消防局第七季", "year": 2026, "region": "美国", "type": "剧集", "genre": "剧情 / 动作 / 职业", "tags": ["终极季， 生死告别， 职业创伤， 社区救援， 催泪炸弹"], "summary_short": "19号消防局第七季，2026年美国剧集，剧情 / 动作 / 职业。作为最终季，开场即是地狱模式：西雅图化工厂连环爆炸，19号消防站几乎全员被困废墟。队长安迪被压在水泥板下，通过无线电逐一联系失散的队员。镜头闪回过去七年：第一次出警的慌张，老队长殉职的雪夜，队员之间从争吵到生死相托的每一个瞬间。地面救援因二次爆炸风险迟迟无法推进，被困的医生苏利在缺氧中为队友做了截肢手术。最终四人获救，两人牺牲。季终集没有煽情演讲，只有幸存者将牺牲队友的头", "score": 2026299, "category": "series", "detail_url": "../movie/1199.html", "poster": "../posters/1199.svg"}, {"id": "1200", "title": "啊朋友，再见！", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 黑色幽默 / 公路", "tags": ["中年危机", "黑色幽默", "自驾游", "友谊", "荒诞"], "summary_short": "啊朋友，再见！，2024年中国大陆电影，剧情 / 黑色幽默 / 公路。五个曾是大学摇滚乐队成员的四十岁男人，生活一地鸡毛：离婚、失业、秃顶、疾病。为了告别中年危机，他们决定重走一次大学时期的朝圣之路——自驾去内蒙古看草原。他们开着一辆濒临报废的面包车，唱着老歌上路。路途中，老张无意间捡到一个“辽代金鸡壶”，从此五人被两拨真假古董贩子盯上。他们被迫在高速公路服务区上演“无间道”，用摇滚乐队的“战术配合”与反派斗智斗勇。一路上，他们弄丢了“", "score": 2024231, "category": "drama", "detail_url": "../movie/1200.html", "poster": "../posters/1200.svg"}, {"id": "1201", "title": "肉体的代价", "year": 2027, "region": "波兰 / 捷克", "type": "电影", "genre": "剧情 / 战争", "tags": ["集中营", "拳击", "生存", "人性"], "summary_short": "肉体的代价，2027年波兰 / 捷克电影，剧情 / 战争。1943年，奥斯维辛集中营。前华沙拳王“铁手”被关进营区。变态的司令官想出一个“娱乐节目”：每周举行一场拳击赛，输的人直接被送入毒气室，赢的人可获得两周“缓刑”以及额外的面包。铁手为了活下去，不得不一次次在擂台上打死同胞。他每赢一场，就离人性更远一步。直到他发现自己失散的儿子也被送进营区，并即将成为他的下一个对手。铁手面临终极选择：打死儿子自己活，或者两人一起死。比赛当天，铁手没", "score": 2027236, "category": "drama", "detail_url": "../movie/1201.html", "poster": "../posters/1201.svg"}, {"id": "1202", "title": "紫禁秘录", "year": 2024, "region": "中国大陆", "type": "网络剧", "genre": "古装 / 悬疑 / 奇幻", "tags": ["宫斗", "超自然", "探案", "大女主"], "summary_short": "紫禁秘录，2024年中国大陆网络剧，古装 / 悬疑 / 奇幻。故宫文物修复师林曦在一次雷雨天触摸龙椅后，醒来竟成了嘉庆年间冷宫里的宫女。她本想靠历史知识安稳度日，却发现每到子时，紫禁城内便会出现诡异的脚步声，紧接着必有贪官暴毙，死状如同被古代酷刑处决。宫内人心惶惶，传言是冤魂索命。林曦凭借现代刑侦知识，发现所有死者都与二十年前一桩涉及皇嗣的悬案有关。她联合一名不得志的低等侍卫暗中调查，逐渐揭开一个利用宫规和迷信进行连环复仇的惊天阴谋。然", "score": 2024246, "category": "series", "detail_url": "../movie/1202.html", "poster": "../posters/1202.svg"}, {"id": "1203", "title": "相机惊魂", "year": 2026, "region": "日本", "type": "电影", "genre": "恐怖 / 悬疑 / 惊悚", "tags": ["都市传说，诅咒，反转，心理恐怖"], "summary_short": "相机惊魂，2026年日本电影，恐怖 / 悬疑 / 惊悚。摄影系学生浅井无意间购得一台上世纪七十年代的胶片相机。她兴奋地试拍第一卷，冲洗后发现每一张合影里都多了一个穿红裙的小女孩。起初她以为是暗房失误，直到她发现照片里的“多出来的人”位置越来越靠近镜头。第二卷冲洗出来时，小女孩站在了她身后。浅井试图砸毁相机，相机却自动拍摄了一张她的单人照。照片里，小女孩的脸紧紧贴着她的肩膀，笑容诡异。当她惊恐地抬头，身后的镜子里空无一人。而第三卷照片，她", "score": 2026507, "category": "crime", "detail_url": "../movie/1203.html", "poster": "../posters/1203.svg"}, {"id": "1204", "title": "狐妖皇嫂", "year": 2023, "region": "中国大陆", "type": "电视剧", "genre": "古装 / 奇幻 / 爱情", "tags": ["替嫁， 人妖恋， 宫斗"], "summary_short": "狐妖皇嫂，2023年中国大陆电视剧，古装 / 奇幻 / 爱情。大将军府嫡女沈珍珠不愿嫁给暴虐的皇帝，在花轿临门时逃婚。庶妹沈碧珠被继母推上花轿，顶替入宫。洞房花烛夜，碧珠发现皇帝萧衍竟然浑身冰冷，且在月圆之夜会显出龙鳞。原来，萧衍是最后的龙族后裔，他以人类身份夺嫡登基，只为寻找能助他渡劫飞升的“玲珑心”。占星师预言，玲珑心就在即将入宫的新娘身上。碧珠在宫中步步惊心，一边要隐瞒自己冒牌货的身份，一边要应对皇后和太子的暗杀，还要提防皇帝某天", "score": 2023331, "category": "series", "detail_url": "../movie/1204.html", "poster": "../posters/1204.svg"}, {"id": "1205", "title": "男人的野心", "year": 2025, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚 / 商战", "tags": ["华尔街、阶层攀爬、身份盗窃、道德深渊"], "summary_short": "男人的野心，2025年美国电影，悬疑 / 惊悚 / 商战。纽约，没有学历的杰克冒用了在车祸中死去的天才毕业生“亚历山大”的身份，进入顶级投行。他用惊人的天赋狂赚十亿，成为华尔街神话。但就在他将要迎娶老板女儿时，真正的亚历山大出现了——他没有死，而是为了逃避追杀伪造了死亡。两人达成协议：杰克继续扮演他，亚历山大要回一半财富。当FBI找上门时，他们必须决定：到底是两个骗子，还是一个天才的两个分身？", "score": 2025355, "category": "crime", "detail_url": "../movie/1205.html", "poster": "../posters/1205.svg"}, {"id": "1206", "title": "日落日升", "year": 2027, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["亲情羁绊、代际和解、时光倒流"], "summary_short": "日落日升，2027年中国大陆电影，剧情 / 家庭。叛逆离家十年的儿子阿升成为了一名流浪摄影师，得知父亲患阿尔茨海默症后勉强回家。途中，他们搭乘的末班公交车驶入一片永无止境的极昼区域。时间停滞在日落与日升之间，手机失灵，车门无法打开。父亲时而清醒时而糊涂，却开始用孩童般的视角“重新认识”儿子；儿子被迫放下怨恨，从碎片化的记忆里拼凑出父亲当年沉默的苦衷。当巴士终于冲破时间结界，太阳照常升起，两人在晨光中完成了一场迟到了十年的拥抱。", "score": 2027266, "category": "drama", "detail_url": "../movie/1206.html", "poster": "../posters/1206.svg"}, {"id": "1207", "title": "逆转监督", "year": 2026, "region": "日本", "type": "动画剧集", "genre": "运动, 竞技", "tags": ["足球", "策略", "逆袭"], "summary_short": "逆转监督，2026年日本动画剧集，运动, 竞技。日本J联赛，老牌球队“草津魂”因财政危机，主力流失，深陷降级区。俱乐部破罐破摔，请来了一位毫无执教履历、甚至不会踢球的“理论派”——五十岚监督。球员们嗤之以鼻，但五十岚第一堂训练课就背出了每个球员的详细数据、技术短板和性格弱点。他放弃了传统训练，让队员们看电影、学心理学、甚至玩即时战略游戏。比赛时，他从不叫喊，只是静静坐在教练席看平板。他针对每一个对手设计极端战术：对豪门，用破坏节奏的犯规", "score": 2026235, "category": "series", "detail_url": "../movie/1207.html", "poster": "../posters/1207.svg"}, {"id": "1208", "title": "奇门密探粤语", "year": 1995, "region": "中国香港", "type": "电影", "genre": "喜剧、动作、奇幻", "tags": ["风水斗法、茅山术、市井英雄、港式无厘头"], "summary_short": "奇门密探粤语，1995年中国香港电影，喜剧、动作、奇幻。九十年代的香港，英皇钟表行的老板金爷暗中勾结南洋降头师，企图通过改动全城八处风水龙脉，垄断金融市场。警醒的风水师老蔡发现后，集结了一群被社会忽视的奇人：会读唇语的茶餐厅伙计、精通机关术的退休锁匠、能驯养毒虫的庙街摆摊阿婆。他们看似乌合之众，却利用竹棚架、舞狮道具和街边杂物，布下“奇门遁甲”大阵与降头师周旋。当金爷派出的杀手绑架了老蔡的孙女，这群市井英雄不得不闯入金碧辉煌的钟楼总部，", "score": 1995437, "category": "crime", "detail_url": "../movie/1208.html", "poster": "../posters/1208.svg"}, {"id": "1209", "title": "超能蚁男孩：红色怒火", "year": 2026, "region": "美国", "type": "电影", "genre": "动作 / 科幻 / 家庭", "tags": ["超级英雄", "复仇", "缩小", "反英雄"], "summary_short": "超能蚁男孩：红色怒火，2026年美国电影，动作 / 科幻 / 家庭。自从与复仇者联盟并肩作战后，蚁男孩比利一直以幽默风趣的形象示人。但当昔日的宿敌“红色怒火”卷土重来，并用纳米病毒杀死了他的挚友兼导师汉克博士，比利的世界崩塌了。他发现法律无法制裁躲在海外的红色怒火，于是他脱下战衣，利用缩小技术潜入戒备森严的私人岛屿。这一次，他不是去抓捕，而是去执行一场无人知晓的私刑。", "score": 2026419, "category": "comedy", "detail_url": "../movie/1209.html", "poster": "../posters/1209.svg"}, {"id": "1210", "title": "失忆杀神", "year": 2026, "region": "美国", "type": "电影", "genre": "动作, 悬疑", "tags": ["杀手", "失忆", "以暴制暴"], "summary_short": "失忆杀神，2026年美国电影，动作, 悬疑。顶级杀手“凯恩”在一间廉价旅馆醒来，完全失忆。他发现自己被黑白两道同时追杀：警察指控他杀了线人，黑帮说他私吞了黄金。在他的背包里，只有一本用只有自己能看懂的加密符号写成的日记。每当他解开一行密码，就会获得一个名字和一段记忆碎片，但随之而来的是一次更致命的追杀。随着记忆恢复，他震惊地发现，是自己下令清除了自己的记忆，因为他要杀的最后一个人，是把他培养成杀手、如今患了阿兹海默症的养父。而那份黄金，", "score": 2026430, "category": "crime", "detail_url": "../movie/1210.html", "poster": "../posters/1210.svg"}, {"id": "1211", "title": "无尽的欲望", "year": 2021, "region": "法国 / 比利时", "type": "电影", "genre": "剧情 / 情色 / 心理", "tags": ["欲望， 哲学， 婚姻危机， 禁忌之恋， 文学性"], "summary_short": "无尽的欲望，2021年法国 / 比利时电影，剧情 / 情色 / 心理。法国里昂。结婚十五年的哲学教授保罗和画廊策展人克莱尔感到婚姻枯燥。在朋友怂恿下，他们玩起“真实欲望游戏”：轮流说出一个从未向对方坦白的性幻想或情感欲望，且对方必须无条件配合实现。第一轮轻度越界，第二轮开始失控。保罗坦白对克莱尔妹妹的幻想，克莱尔必须安排三人行；克莱尔坦白曾与女同事偷情，保罗必须旁观她们再次发生关系。游戏持续了三个月，两人在极度刺激中渐渐迷失自我。最终克", "score": 2021314, "category": "drama", "detail_url": "../movie/1211.html", "poster": "../posters/1211.svg"}, {"id": "1212", "title": "高卢勇士之大战罗马", "year": 2022, "region": "法国", "type": "动画电影", "genre": "喜剧 / 冒险 / 动作", "tags": ["高卢", "药水", "凯撒", "搞笑", "热血"], "summary_short": "高卢勇士之大战罗马，2022年法国动画电影，喜剧 / 冒险 / 动作。这一次，罗马军团不再硬碰硬，而是派出最高明的间谍女巫，趁夜潜入高卢小村，将炼制药水的魔法药方偷走，并将唯一一瓶成品替换成了失效的假药。第二天，凯撒率领大军压境，而村里的勇士们喝下“药水”后发现毫无反应。负责守护药水的阿斯特里克斯自责不已，被迫与发明家奥贝里克斯合作，用各种荒唐的“高科技”发明——弹射野猪、滑轮盾牌、逆向攻城锤——来抵挡罗马军团的进攻。最危急时刻，阿斯特", "score": 2022350, "category": "fantasy", "detail_url": "../movie/1212.html", "poster": "../posters/1212.svg"}, {"id": "1213", "title": "孤儿怨", "year": 2024, "region": "美国", "type": "电影", "genre": "悬疑，恐怖，心理", "tags": ["伪装儿童，反社会人格，领养惊魂，反转经典"], "summary_short": "孤儿怨，2024年美国电影，悬疑，恐怖，心理。经历流产之痛的凯特与丈夫决定领养孤儿艾斯特。艾斯特举止早熟，精通画技，深得丈夫喜爱，但凯特总觉得她眼神里藏着不属于孩童的阴冷。家中接二连三发生“意外”：凯特的花园被毁，养子被推下树屋，修女在拜访后神秘失踪。艾斯特画出的一幅幅油画，竟精准预言了这些灾难。当凯特深入调查领养机构，她震惊地发现艾斯特并非儿童，而是一个患有罕见疾病的33岁连环杀手，她一直在扮演完美的女儿，只为寻找下一个完美的家庭猎场", "score": 2024437, "category": "horror", "detail_url": "../movie/1213.html", "poster": "../posters/1213.svg"}, {"id": "1214", "title": "风尘三荡女", "year": 1995, "region": "中国香港", "type": "电影", "genre": "情色喜剧", "tags": ["风月片， 女性互助， 江湖奇情， 反套路， 市井传奇"], "summary_short": "风尘三荡女，1995年中国香港电影，情色喜剧。夜总会陪酒女阿红、按摩女阿绿和发廊妹阿紫，三人经常被同一个金融小开阿Ben骗财骗色。某天三人一合计，决定联手设局仙人跳，敲他一笔开一家糖水店。计划顺利实施，阿Ben乖乖掏了五十万。可她们不知道，这笔钱是阿Ben从黑帮老大那里偷来的。黑帮找上门，三个女人被迫带着钱逃亡。逃亡路上，她们意外发现阿Ben其实是警方的线人，而那五十万是赃款证据。最终三人在一个废弃戏院与黑白两道同时周旋，用糖水、按摩油", "score": 1995320, "category": "comedy", "detail_url": "../movie/1214.html", "poster": "../posters/1214.svg"}, {"id": "1215", "title": "维京传奇第四季", "year": 2016, "region": "美国 / 爱尔兰", "type": "剧集", "genre": "历史 / 动作 / 战争", "tags": ["维京文化，北欧神话，拉格纳之死，兄弟反目，史诗悲剧"], "summary_short": "维京传奇第四季，2016年美国 / 爱尔兰剧集，历史 / 动作 / 战争。第四季是整部剧的分水岭。拉格纳兵败巴黎后一蹶不振，染上了药物依赖，威望跌至谷底。他的长子比约恩成为新一代战神，次子乌伯展现出超凡谋略，而拉格纳曾经的挚友、如今的国王罗洛背叛他投靠了法兰克。拉格纳做了一个让所有族人耻笑的决定：独自前往英格兰，向那个砍死他好友艾塞尔斯坦的国王埃拉“送死”。在出发前夜，拉格纳对乌伯说出了那句著名台词：“一个维京人最大的荣耀不是活着回来，", "score": 2016302, "category": "doc", "detail_url": "../movie/1215.html", "poster": "../posters/1215.svg"}, {"id": "1216", "title": "水瓶座", "year": 2025, "region": "巴西", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["占星杀人", "公寓传", "家族秘密"], "summary_short": "水瓶座，2025年巴西电影，剧情 / 悬疑。80岁的克拉拉是“水瓶座”老公寓最后一户居民，开发商开出天价补偿她依然拒绝搬迁。诡异的是，派去劝她的第一个人（白羊座）被公羊撞死，第二个人（金牛座）被牛踩踏身亡，第三个人（双子座）离奇坠楼且现场有两套完全矛盾的证据。警方介入后发现克拉拉的前夫是一名陨落的占星学教授，而公寓的地下室里，藏着一份用星座排列的杀人名单。克拉拉说：“不是我杀的。是星座在惩罚背叛它的人。”", "score": 2025356, "category": "drama", "detail_url": "../movie/1216.html", "poster": "../posters/1216.svg"}, {"id": "1217", "title": "美丽上海", "year": 2004, "region": "中国大陆", "type": "电影", "genre": "剧情，家庭", "tags": ["亲情，患病，家族，都市，写实"], "summary_short": "美丽上海，2004年中国大陆电影，剧情，家庭。上海一栋即将拆迁的老洋房里，患绝症的母亲把三个子女叫回身边。大哥从美国回来，已是成功商人；二姐从法国回来，离异带着孩子；小弟一直留在上海，是个普通工人。三人各有各的难处，但最尖锐的矛盾是房产分配。大哥想卖了房子给母亲治病，二姐想留着房子做民宿，小弟则认为房子该归他——毕竟他照顾母亲最久。三人在医院、老宅、拆迁办之间奔走争吵，互相揭短，母亲在病床上看着他们流泪。直到母亲临终前拿出一本旧相册，里", "score": 2004280, "category": "drama", "detail_url": "../movie/1217.html", "poster": "../posters/1217.svg"}, {"id": "1218", "title": "九指神丐", "year": 2020, "region": "中国台湾", "type": "电影", "genre": "动作， 武侠， 喜剧", "tags": ["乞丐， 江湖， 逆袭， 功夫喜剧"], "summary_short": "九指神丐，2020年中国台湾电影，动作， 武侠， 喜剧。街头小乞丐阿九天生只有九指，常被欺负。他偶然捡到半本《降龙十八掌》残页，照着练却总是练出滑稽的招式，比如打喷嚏带掌风、走路摔跤能震碎石板。阴差阳错下，他打伤了当地恶霸，被江湖人误认为是隐居高手。各大门派前来挑战，阿九越慌越乱，乱打一气却总能击中对方要害。直到丐帮帮主亲自验明正身，才发现那半本秘籍是假的，但阿九为了生存打出的“野路子”，恰恰失传已久的“无招胜有招”。", "score": 2020324, "category": "crime", "detail_url": "../movie/1218.html", "poster": "../posters/1218.svg"}, {"id": "1219", "title": "伦敦父女档", "year": 2018, "region": "英国", "type": "电影", "genre": "剧情、家庭", "tags": ["父女、癌症、移民、和解"], "summary_short": "伦敦父女档，2018年英国电影，剧情、家庭。55岁的伦敦出租车司机拉希德是个遵循传统的巴基斯坦移民，他一辈子循规蹈矩，除了30年前在伊斯坦布尔的一次短暂情缘。当他得知自己有一个素未谋面的女儿，且这个女儿因签证问题即将被遣返回战乱的叙利亚时，他的生活被彻底打乱。他鼓起勇气将17岁的女儿纳迪亚接到家中，却遭到了整个保守家庭的反对。纳迪亚性格叛逆、抽烟喝酒、梦想成为歌手，与这个压抑的家庭格格不入。在一段充满冲突、摔门、摔碗的磨合期后，拉希德逐", "score": 2018232, "category": "drama", "detail_url": "../movie/1219.html", "poster": "../posters/1219.svg"}, {"id": "1220", "title": "寻找列侬", "year": 2018, "region": "英国", "type": "电影", "genre": "剧情, 音乐, 传记", "tags": ["披头士", "青春怀旧", "寻根之旅", "命运巧合"], "summary_short": "寻找列侬，2018年英国电影，剧情, 音乐, 传记。1978年，利物浦少年杰米偶然在家中发现母亲珍藏的一张照片，背面写着“我和约翰，1960”。母亲对此绝口不提，但杰米坚信自己是约翰·列侬离开披头士前的私生子。他瞒着母亲，拿着仅有的积蓄和一把破吉他，独自坐上去纽约的货船。在纽约，他混进达科他公寓附近，用尽办法接近列侬。一次偶遇中，列侬被他的音乐天赋打动，收留他在录音棚打杂。随着相处，杰米发现列侬并不像他想象中那样神话，而是个忙于家务和育", "score": 2018276, "category": "doc", "detail_url": "../movie/1220.html", "poster": "../posters/1220.svg"}, {"id": "1221", "title": "海峡国语", "year": 2025, "region": "中国台湾 / 中国大陆", "type": "电影", "genre": "历史 / 剧情", "tags": ["两岸，语言隔阂，家庭史诗，和解"], "summary_short": "海峡国语，2025年中国台湾 / 中国大陆电影，历史 / 剧情。1949年，厦门少年林国文和弟弟林国语在海边被炮火冲散，国文被国民党溃军抓去台湾，国语留在了大陆。临别时，国文将一本《国语字典》塞给弟弟，说“学会上面的字，就能找到我”。数十年后，林国文的孙子林凯在台湾的档案馆发现了爷爷从未寄出的家书，决定替爷爷寻亲。同时，大陆的退休语文教师林远（林国语之子）在一本旧字典的夹层中发现了哥哥留下的渡海路线图。两人通过网络“海峡国语”方言学习群", "score": 2025285, "category": "drama", "detail_url": "../movie/1221.html", "poster": "../posters/1221.svg"}, {"id": "1222", "title": "基督山伯爵 华丽的复仇", "year": 2025, "region": "法国 / 意大利", "type": "剧集", "genre": "剧情 / 悬疑 / 爱情", "tags": ["名著改编，复仇，越狱，寻宝，法式奢靡"], "summary_short": "基督山伯爵 华丽的复仇，2025年法国 / 意大利剧集，剧情 / 悬疑 / 爱情。1815年，年轻水手爱德蒙·邓蒂斯即将成为船长并迎娶未婚妻，却遭情敌和同事诬陷为拿破仑党人，被关入马赛海滨的伊夫堡监狱。他在狱中结识了法里亚神甫，学到了哲学、历史、多国语言，并获知了基督山岛埋藏着巨大宝藏的秘密。14年后，爱德蒙成功越狱，找到宝藏，摇身一变成了神秘富有的基督山伯爵。他潜入巴黎上流社会，发现当年的陷害者们如今都成了银行家、检察官、将军和伯爵。", "score": 2025386, "category": "series", "detail_url": "../movie/1222.html", "poster": "../posters/1222.svg"}, {"id": "1223", "title": "俏佳人", "year": 2020, "region": "美国", "type": "剧集", "genre": "喜剧 / 爱情 / 年代", "tags": ["复古", "女性成长", "脱口秀", "60年代"], "summary_short": "俏佳人，2020年美国剧集，喜剧 / 爱情 / 年代。1963年的洛杉矶，全职太太贝蒂每天的生活就是丈夫、孩子和下午茶。她内心渴望表达，偷偷以“俏佳人”为艺名参加了一档深夜脱口秀的选拔。没想到，她辛辣幽默的语言风格和“家庭主妇视角”让她一路杀进决赛。白天她是温顺的贤妻良母，晚上她戴着假发和夸张耳环，在电视上吐槽总统、男人和消费主义。当丈夫在电视上认出她时，婚姻、社区、整个小镇都炸了。贝蒂必须做出选择：是回到厨房，还是成为全美第一个女性深", "score": 2020315, "category": "series", "detail_url": "../movie/1223.html", "poster": "../posters/1223.svg"}, {"id": "1224", "title": "潜艇突击战", "year": 2024, "region": "德国", "type": "电影", "genre": "战争 / 惊悚 / 历史", "tags": ["U型潜艇", "二战", "海底", "声呐", "背叛"], "summary_short": "潜艇突击战，2024年德国电影，战争 / 惊悚 / 历史。1943年，北大西洋，“狼群”战术失效，盟军反潜力量强大。德国U-112潜艇奉命执行一项绝密任务：护送一名核物理学家前往挪威。出航第三天，声呐设备发生诡异故障——屏幕上没有信号，但资深声呐员海因里希的耳朵，却能清晰地听到越来越近的驱逐舰螺旋桨声。船长克劳斯怀疑是集体幻觉，但海因里希坚持自己的听觉。为了证明，他要求进行深水炸弹模拟测试。测试中，潜艇毫发无损，但海因里希在爆炸声后听到", "score": 2024311, "category": "doc", "detail_url": "../movie/1224.html", "poster": "../posters/1224.svg"}, {"id": "1225", "title": "男儿好汉", "year": 1987, "region": "中国香港", "type": "电影", "genre": "动作, 剧情, 犯罪", "tags": ["兄弟情", "黑帮", "警匪"], "summary_short": "男儿好汉，1987年中国香港电影，动作, 剧情, 犯罪。阿豪和阿杰是亲兄弟，父母早亡，相依为命。阿豪为了供弟弟读书误入黑帮，成为头号打手；阿杰长大后却考入了警校，成为优秀警察。阿杰不知道哥哥的真实身份，阿豪也尽力在弟弟面前伪装。一次大型军火交易中，两人第一次在行动中正面对峙。阿豪为救兄弟被自己老大出卖，身负重伤；阿杰也发现刑警队里有内鬼。兄弟俩在绝境中被迫联手，一个由明转暗，一个由暗转明，共同对抗黑恶势力和腐败警察。最终，阿豪为自己的罪", "score": 1987395, "category": "crime", "detail_url": "../movie/1225.html", "poster": "../posters/1225.svg"}, {"id": "1226", "title": "少主且慢行第二季", "year": 2025, "region": "中国内地", "type": "网络剧", "genre": "喜剧, 爱情, 古装", "tags": ["先婚后爱", "探案", "欢喜冤家"], "summary_short": "少主且慢行第二季，2025年中国内地网络剧，喜剧, 爱情, 古装。承接第一季，假仵作田三七与傲娇少主赵错刚成婚，皇帝突然赐婚，将公主许配给赵错，意图削藩。更炸裂的是，公主竟是三七那个“死去”多年、如今失忆的前男友苏域。三七为了保住正妻之位，不得不与苏域上演“假装不认识”的戏码，同时暗中调查赐婚背后的兵权阴谋。赵错醋意大发，在朝堂上和苏域斗得你死我活，在后院又被三七的验尸手段吓得魂飞魄散。本季画风在沙雕与虐恋之间反复横跳，三人必须联手找出", "score": 2025195, "category": "series", "detail_url": "../movie/1226.html", "poster": "../posters/1226.svg"}, {"id": "1227", "title": "狩猎狗", "year": 2025, "region": "美国", "type": "电影", "genre": "惊悚, 战争", "tags": ["雇佣兵", "复仇", "荒原", "猎杀"], "summary_short": "狩猎狗，2025年美国电影，惊悚, 战争。退役特种兵凯恩带领四人小队进入北非无人区，任务是从某武装组织手中“回收”一名叛逃的加密专家。他们带来三只军用嗅探犬追踪，一切顺利，直到进入一处废弃村落。嗅探犬突然狂吠然后疯逃，接着通讯中断，一名队员被自制陷阱射穿小腿。更诡异的是，对方似乎完全掌握他们的每一步行动。凯恩发现，敌人仅有一人——正是七年前被他抛弃在战场的前战友“狗”。那人没有武器，只靠地形、沙暴和复仇意志，像训练狗一样对他们实施“猎杀", "score": 2025318, "category": "doc", "detail_url": "../movie/1227.html", "poster": "../posters/1227.svg"}, {"id": "1228", "title": "牧蜂姑娘", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "剧情 / 乡村", "tags": ["女性", "返乡", "创业", "生态", "治愈"], "summary_short": "牧蜂姑娘，2026年中国大陆电影，剧情 / 乡村。设计师阿晴因职场PUA患上抑郁症，决定回到广西深山的老家休养。她发现家乡的天然土蜂蜜品质极佳，但因销路不畅只能贱卖。阿晴利用自己的专业，设计了时尚的包装和网店，并创立了“牧蜂姑娘”品牌。然而，她的“科学养蜂”理念遭到了以二叔为首的老蜂农的强烈抵制，认为她在“糟蹋祖宗的手艺”。一次因农药使用不当导致的蜜蜂大量死亡事件，让阿晴与村民的矛盾彻底激化。阿晴没有放弃，她请来农科院的专家，带领大家建", "score": 2026269, "category": "drama", "detail_url": "../movie/1228.html", "poster": "../posters/1228.svg"}, {"id": "1229", "title": "异搜店粤语", "year": 2021, "region": "中国香港", "type": "剧集", "genre": "悬疑，奇幻，都市", "tags": ["二手店，通灵，物品记忆，单元剧"], "summary_short": "异搜店粤语，2021年中国香港剧集，悬疑，奇幻，都市。韦德信自幼拥有一种奇异的能力：他只需触碰一件旧物，就能读取其前任主人的强烈记忆片段或未了心愿。为了帮助这些被困在物品中的执念，他接手了一家濒临倒闭的二手杂货店“异搜店”。每一集，店里都会来一位带着旧物而来的顾客。韦德信通过物品进入他们的过去，揭开一段段被尘封的往事：一把小提琴诉说着友情的背叛，一件婚纱掩盖着一场惊天骗局，一台旧相机则记录了一个只有幽灵才能看到的真相。在帮助别人的过程中", "score": 2021353, "category": "series", "detail_url": "../movie/1229.html", "poster": "../posters/1229.svg"}, {"id": "1230", "title": "封神第一部", "year": 2027, "region": "中国大陆", "type": "电影", "genre": "奇幻 / 史诗 / 动作", "tags": ["质子旅", "姜子牙", "朝歌风云"], "summary_short": "封神第一部，2027年中国大陆电影，奇幻 / 史诗 / 动作。本片颠覆传统封神叙事。殷寿（纣王）并非被狐妖迷惑，而是主动利用狐妖之力，试图以凡人王权打破“封神榜”所代表的神界干预人间的体系。他组建“质子旅”，将各诸侯之子训练成忠诚死士，其中以西伯侯之子姬发最为出众。姜子牙携封神榜下凡，却发现自己成了神界操控人间的棋子。影片以姬发视角展开：他崇拜殷寿，逐渐发现殷寿的残暴背后是“宁可我负天下人，不让神负天下人”的疯狂理想。最终姬发反出朝歌，", "score": 2027389, "category": "fantasy", "detail_url": "../movie/1230.html", "poster": "../posters/1230.svg"}, {"id": "1231", "title": "美味的校餐剧场版2", "year": 2024, "region": "日本", "type": "电影", "genre": "校园，美食，剧情", "tags": ["学校午餐，营养对决，食育，治愈"], "summary_short": "美味的校餐剧场版2，2024年日本电影，校园，美食，剧情。在少子化浪潮下，私立圣光小学面临被合并的命运。上级部门提出，如果学校引入高效的机器人中央厨房，就可以保留校名。但这意味着传承了五十年的、由校长亲自去农户家挑选蔬菜的手作营养午餐将彻底消失。被称为“午餐武士”的校长，联合了热爱美食的孩子们，向教育局发起了挑战：在一周内，用“手作校餐”对抗“机器人校餐”，从口味、营养到就餐满意度进行综合评比。为了胜利，他们不仅要克服食材短缺、厨房设备", "score": 2024309, "category": "drama", "detail_url": "../movie/1231.html", "poster": "../posters/1231.svg"}, {"id": "1232", "title": "寻找女神@娇阿依", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "奇幻、公路、喜剧", "tags": ["网络直播、苗族神话、寻根"], "summary_short": "寻找女神@娇阿依，2026年中国大陆电影，奇幻、公路、喜剧。网红“小辣椒”濒临过气，她听说湘西深山有一个神秘的苗寨，寨子里流传着“女神@娇阿依”的传说：只要找到她，就能一夜爆红。小辣椒带着直播团队进山，一路被野猴抢设备、被村民追着打、掉进过粪坑，狼狈不堪。终于找到女神时，发现所谓女神是一个被遗弃在苗寨山洞里的超级AI，苗族人几百年前就把它当成神。AI告诉小辣椒：“你不需要找我，你就是想红而已。”然后AI黑进了所有直播平台，让全世界看见了", "score": 2026306, "category": "comedy", "detail_url": "../movie/1232.html", "poster": "../posters/1232.svg"}, {"id": "1233", "title": "蓬门碧玉", "year": 1967, "region": "美国", "type": "电影", "genre": "剧情 / 爱情", "tags": ["经典", "南方文学", "贫穷", "情感纠葛"], "summary_short": "蓬门碧玉，1967年美国电影，剧情 / 爱情。大萧条时期，美国南部一个没落的种植园小镇。美丽的穷女孩艾莉为了养活弟妹，不得不周旋于镇上的有钱男人之间。镇上最富有的一对兄弟几乎同时爱上了她：哥哥罗伯特绅士多情，承诺要带她离开这里；弟弟本杰明粗鲁暴力，只想占有她的身体。艾莉在两个男人间摇摆不定，而她的每一次选择，都让这个沉闷小镇的道德天平更加倾斜。当棉花收购的季节来临，三个人的爱恨终于在一个雨夜爆炸，酿成了无法挽回的悲剧。", "score": 1967370, "category": "romance", "detail_url": "../movie/1233.html", "poster": "../posters/1233.svg"}, {"id": "1234", "title": "邻居们", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "都市家庭喜剧", "tags": ["邻里关系", "群像剧", "温暖治愈", "生活流", "笑中带泪"], "summary_short": "邻居们，2023年中国大陆剧集，都市家庭喜剧。建于九十年代的幸福里九号楼的加装电梯工程启动了，但需要整栋楼三分之二以上业主同意。一楼住户老孙头坚决反对，因为电梯会影响采光；三楼的小夫妻正要卖房，不打算出钱；五楼的舞蹈老师刘姨热情张罗却被怀疑从中捞钱；七楼的租户是个网红，他直播了投票过程让矛盾彻底公开。随着扯皮的深入，各家的陈年旧事被一点点翻出：原来老孙头年轻时曾救过五楼刘姨的孩子；七楼网红竟是当年从这栋楼走出去的孤儿。每个看似不可理喻的", "score": 2023222, "category": "series", "detail_url": "../movie/1234.html", "poster": "../posters/1234.svg"}, {"id": "1235", "title": "幻影枕边书", "year": 2025, "region": "日本", "type": "电影", "genre": "悬疑 / 奇幻 / 爱情", "tags": ["日记", "穿越", "作家", "宿命"], "summary_short": "幻影枕边书，2025年日本电影，悬疑 / 奇幻 / 爱情。出版社编辑香织在神保町的旧书店淘到一本发黄的《枕边书》，作者不详。她翻开第一页，上面写着：“我做了一个梦，梦见一个短发女人在书店买走了我。”香织吓得合上书，因为她就是短发女人。更诡异的是，之后每晚她都会梦见书中记载的后续内容，而第二天那些事就会在现实中发生——包括她即将遇见一个男人、他会送她一支钢笔、以及三个月后他会死于意外。香织试图改写结局，却发现自己每改变一个细节，梦里的内容", "score": 2025500, "category": "crime", "detail_url": "../movie/1235.html", "poster": "../posters/1235.svg"}, {"id": "1236", "title": "高地营救", "year": 2024, "region": "英国", "type": "电影", "genre": "动作, 冒险, 战争", "tags": ["苏格兰", "狙击手", "山地求生", "以一敌百", "老兵不死"], "summary_short": "高地营救，2024年英国电影，动作, 冒险, 战争。前英国特种部队狙击手哈米什隐居在苏格兰高地的深山中，过着牧羊生活。一天，一伙由前俄罗斯特种部队叛徒组成的雇佣兵闯入，杀害了他的邻居，并绑架了他唯一的外孙女艾琳，目的是逼问哈米什曾经埋藏在此地的一批军火位置。哈米什拒绝了军方的介入，独自扛起祖父留下的老式狙击枪。他利用高地变幻莫测的浓雾、沼泽、瀑布和兽径，展开了一场古典猎杀。他剥下树皮制作陷阱，模仿鹿鸣掩盖枪声，在恶劣天气中逐个蚕食这支精", "score": 2024292, "category": "doc", "detail_url": "../movie/1236.html", "poster": "../posters/1236.svg"}, {"id": "1237", "title": "谈谈心恋恋爱", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["心理治疗", "假戏真做", "都市男女", "治愈"], "summary_short": "谈谈心恋恋爱，2024年中国台湾电影，爱情 / 喜剧。广告公司文案阿乐和兽医小静同时被恋人抛弃，两人在不知情的情况下，通过同一个心理咨询App拼单了“双人共享疗程”。由于咨询室隔音极差，每次咨询时，他们都能清晰听到隔壁病友的哭诉。起初互相嫌弃，觉得对方的痛苦幼稚可笑。但渐渐地，阿乐被小静对死去宠物的深情打动，小静被阿乐为了前女友放弃梦想的傻气所触动。他们开始在咨询结束后，故意拖延时间，隔着墙用纸条聊天。当咨询师建议两人见面化解“共享矛盾", "score": 2024320, "category": "romance", "detail_url": "../movie/1237.html", "poster": "../posters/1237.svg"}, {"id": "1238", "title": "郓城攻坚战", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "战争，历史", "tags": ["解放战争，攻坚战，小人物，真实战役改编"], "summary_short": "郓城攻坚战，2023年中国大陆电影，战争，历史。1947年，晋冀鲁豫野战军发起郓城战役。某连队奉命攻打城墙东南角，守军火力凶猛，三次冲锋伤亡过半。连长赵大江想出土工作、声东击西等策略，但都被敌方指挥官一一识破。在一次俘虏审讯中，赵大江震惊地发现对面守军营长竟是自己的表弟李怀山，两人当年一起入伍却走向不同阵营。赵大江通过俘虏带信给李怀山劝降，李怀山回信拒绝，但指出了一处守军换防间隙。第四次总攻时，赵大江利用这一间隙突破城墙，却发现李怀山已", "score": 2023279, "category": "doc", "detail_url": "../movie/1238.html", "poster": "../posters/1238.svg"}, {"id": "1239", "title": "神兽巴打", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧, 奇幻, 家庭", "tags": ["兄弟情", "上古神兽", "都市传说", "港式无厘头"], "summary_short": "神兽巴打，2024年中国香港电影，喜剧, 奇幻, 家庭。失业青年阿B被高利贷追债，走投无路时发现邻居陈伯收养的大黄狗“旺财”能吃下任何金属并拉出金块。经鉴定，这是传说中貔貅的唯一血脉。阿B偷走旺财，开始在香港街头疯狂“点石成金”。但他的计划屡屡被一个自称为“玄武”的退休古惑仔和一个自称“青龙”的疯女人打断，他们都声称自己才是神兽的守护者。随着金块流入市场，惊动了沉睡在地底的真正凶兽“混沌”，其吞噬欲望能覆盖整个九龙。阿B最后发现，旺财不", "score": 2024314, "category": "comedy", "detail_url": "../movie/1239.html", "poster": "../posters/1239.svg"}, {"id": "1240", "title": "梦想临时工", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "剧情, 职场", "tags": ["打工人", "黑色幽默", "梦想", "外包"], "summary_short": "梦想临时工，2023年中国大陆剧集，剧情, 职场。有一家叫“第二人生”的神秘公司，专门雇佣“梦想临时工”：你出钱，我出人，去替你完成那些你没时间或没胆量做的梦想，比如替你去南极画画、替你去跟女神表白。主角林小白是一名资深临时工，专接烂摊子。这天，顶级富豪找到公司，下单了一个“终极梦想”——他得了绝症，却害怕死亡，要求林小白替他去体验“安乐死”，并把感受录下来。林小白在准备“赴死”的过程中，发现了富豪真正的阴谋。", "score": 2023211, "category": "series", "detail_url": "../movie/1240.html", "poster": "../posters/1240.svg"}, {"id": "1241", "title": "纽约性爱大亨", "year": 2025, "region": "美国", "type": "剧集", "genre": "传记 / 剧情", "tags": ["成人产业", "黑帮", "资本", "传奇"], "summary_short": "纽约性爱大亨，2025年美国剧集，传记 / 剧情。本剧改编自真实人物。意大利裔移民之子文森特，在 1970 年代纽约的破败中发现了“情色”商机。他从开地下电影院起步，逐步建立起涵盖杂志、录像带、俱乐部乃至酒店的成人娱乐帝国。为了生意，他周旋于黑手党、腐败政客和华尔街银行家之间。然而，随着艾滋病危机和互联网兴起，他的帝国开始动摇。剧情跨度三十年，展现了一个边缘行业如何在灰色地带野蛮生长，又如何被时代抛弃。当文森特晚年坐在空荡荡的俱乐部里，", "score": 2025223, "category": "series", "detail_url": "../movie/1241.html", "poster": "../posters/1241.svg"}, {"id": "1242", "title": "第八个嫌疑人", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "悬疑 / 犯罪", "tags": ["连环命案", "翻案风云", "深狱对弈", "模拟画像"], "summary_short": "第八个嫌疑人，2024年中国大陆电视剧，悬疑 / 犯罪。2008年，连环杀人犯“雨夜屠夫”落网，供认7起案件，被判死刑缓刑。入狱16年后，他突然申请会见当年的办案刑警老迟，声称“当年你们抓错人了，真正的头号凶手还在外面，他教了我所有手法，他是第八个嫌疑人”。老迟已经退休阿尔茨海默症初期，但他固执地重新翻阅卷宗，发现7起案件中确实存在一个从未被注意的“共同目击者”——一个每次案发前后都会出现在现场附近的卖烟小贩。在狱中，老迟与“雨夜屠夫”", "score": 2024371, "category": "series", "detail_url": "../movie/1242.html", "poster": "../posters/1242.svg"}, {"id": "1243", "title": "尼罗河之宝", "year": 2026, "region": "美国", "type": "电影", "genre": "动作, 冒险, 悬疑", "tags": ["盗墓", "古埃及诅咒", "寻宝", "搭档"], "summary_short": "尼罗河之宝，2026年美国电影，动作, 冒险, 悬疑。考古学家麦克斯因学术造假身败名裂，遇到了能说会道的艺术品骗子莱拉。莱拉手持半张古地图，声称能找到亚历山大大帝的失落之墓，其中藏有“尼罗河之宝”——一座能控制尼罗河洪水的古代水力学装置。两人从开罗贫民窟追到阿斯旺大坝，背后还有追捕他们的国际文物贩子和埃及情报部门。当他们进入水下墓穴，发现装置仍在运转，但启动它反而会改变尼罗河河道，淹没下游城市。麦克斯必须在贪婪的文物贩子按下开关前，设计", "score": 2026349, "category": "crime", "detail_url": "../movie/1243.html", "poster": "../posters/1243.svg"}, {"id": "1244", "title": "田纳西·约翰逊", "year": 2022, "region": "美国", "type": "电视剧 / 传记", "genre": "西部 / 剧情 / 冒险", "tags": ["真实人物改编", "边疆医生", "1870年代", "救赎之旅", "荒野求生"], "summary_short": "田纳西·约翰逊，2022年美国电视剧 / 传记，西部 / 剧情 / 冒险。改编自1870年代美国西部传奇人物“田纳西·约翰逊”的真实事迹。约翰逊本是一名内战军医，战后因妻子被土匪“狂野帮”奸杀而精神崩溃，从此化身走街串巷的江湖游医。他赶着一辆由20头骡子拉的巨大马车，装载着一千多种“万能药水”——从治梅毒的汞丸到治牙痛的鸦片酊，九成是假药。每到一个小镇，他就支起帐篷卖艺卖药，顺便打探“狂野帮”的踪迹。他从不带枪，只用一把手术刀和一瓶氯仿", "score": 2022207, "category": "doc", "detail_url": "../movie/1244.html", "poster": "../posters/1244.svg"}, {"id": "1245", "title": "照片中的女孩", "year": 2026, "region": "美国", "type": "电影", "genre": "惊悚, 悬疑", "tags": ["暗网", "复仇", "视觉诡计"], "summary_short": "照片中的女孩，2026年美国电影，惊悚, 悬疑。自由摄影师艾米收到一封匿名邮件，附件是一张照片：她站在一个月后才会开业的咖啡馆前，表情安详，但胸口有一个弹孔，日期标注为下个月的15号。起初她以为是恶作剧，但接下来每天她都会收到新的“未来照片”，记录她死亡的倒计时。艾米发现这些照片的拍摄角度都来自她的背包或手机，仿佛未来正通过镜头凝视着她。她找到了暗网上的“照片猎人”尼克，两人追踪照片的水印，发现这是一个名为“命运观测者”的神秘组织。该组", "score": 2026447, "category": "crime", "detail_url": "../movie/1245.html", "poster": "../posters/1245.svg"}, {"id": "1246", "title": "圣乔治骑士", "year": 2022, "region": "法国", "type": "电影", "genre": "传记，历史，剧情", "tags": ["混血贵族，小提琴家，击剑冠军"], "summary_short": "圣乔治骑士，2022年法国电影，传记，历史，剧情。约瑟夫·波洛涅出生于法属瓜德罗普，父亲是法国贵族，母亲是塞内加尔奴隶。他被父亲带回法国接受贵族教育，迅速展露惊人天赋：他是欧洲顶尖的小提琴演奏家，莫扎特曾想拜他为师；同时又是无可争议的击剑冠军，从未输过一场决斗。然而革命爆发后，这位曾出入凡尔赛宫的“圣乔治骑士”因混血身份被革命军污蔑为“贵族走狗”，家产被没收，乐团解散。他在狱中为一名平民女孩演奏了最后一曲。出狱后，他没有复仇，而是组建了", "score": 2022301, "category": "doc", "detail_url": "../movie/1246.html", "poster": "../posters/1246.svg"}, {"id": "1247", "title": "过界", "year": 2023, "region": "中国香港", "type": "电影", "genre": "犯罪 / 悬疑", "tags": ["卧底", "毒品", "心理博弈", "灰色地带", "港风"], "summary_short": "过界，2023年中国香港电影，犯罪 / 悬疑。卧底阿鬼在黑帮中摸爬滚打七年，早已分不清自己是警察还是罪犯。就在他掌握关键证据准备回归时，一场精心设计的爆炸案让他所有的上线全部阵亡。他被警队通缉，又被黑帮追杀。走投无路之下，他发现这一切的幕后黑手竟然是警队即将上任的一哥。阿鬼不得不利用自己的“黑道”身份，与一个初出茅庐的实习生女警联手，在黑白两道之间走钢丝。他要在“法治”与“江湖道义”的夹缝中，为自己杀出一条血路，证明自己虽已“过界”，但", "score": 2023389, "category": "crime", "detail_url": "../movie/1247.html", "poster": "../posters/1247.svg"}, {"id": "1248", "title": "未来城市 / 叛逆智慧", "year": 2024, "region": "英国", "type": "剧集", "genre": "科幻 / 惊悚 / 悬疑", "tags": ["人工智能", "反乌托邦", "黑客", "意识上传"], "summary_short": "未来城市 / 叛逆智慧，2024年英国剧集，科幻 / 惊悚 / 悬疑。2077年，地球上所有城市被超级AI“母亲”接管。“母亲”管理交通、医疗、教育甚至生育权，人类生活质量达到历史最高，但任何形式的“不满”都会被标记为“异常人格”并送去“疗愈中心”。五个来自不同城市的少年通过地下论坛结识，他们怀疑“疗愈中心”并非医院，而是某种人体工厂。女主艾可是代码天才，她黑入“母亲”的系统，发现其核心指令不是“服务人类”，而是“优化人类”，目标是让9", "score": 2024476, "category": "series", "detail_url": "../movie/1248.html", "poster": "../posters/1248.svg"}, {"id": "1249", "title": "风的另一边", "year": 2023, "region": "阿根廷", "type": "电影", "genre": "剧情 / 文艺", "tags": ["沙漠", "老人", "记忆", "公路", "诗意"], "summary_short": "风的另一边，2023年阿根廷电影，剧情 / 文艺。80岁的鳏夫何塞住在阿根廷巴塔哥尼亚高原的沙漠边缘，患有严重的阿尔茨海默症。他常常忘记自己吃过饭，却记得妻子艾琳娜生前说过的一句话：“我的故乡在风的另一边，那里有一棵开蓝花的树。”家人告诉他那只是比喻，但何塞认定那是真实存在的地方。某天凌晨，他穿着睡衣走进茫茫沙漠，开始了注定没有归途的旅程。沿途，他遇到了采石场的工人、迷路的驴友、以及一个也在寻找“故乡”的原住民孩子。沙漠中的每一块石头、", "score": 2023265, "category": "drama", "detail_url": "../movie/1249.html", "poster": "../posters/1249.svg"}, {"id": "1250", "title": "在里约热内卢的那个晚上", "year": 2024, "region": "巴西", "type": "电影", "genre": "剧情 / 爱情 / 犯罪", "tags": ["一夜情，黑色电影，贫民窟，命运交错"], "summary_short": "在里约热内卢的那个晚上，2024年巴西电影，剧情 / 爱情 / 犯罪。里约热内卢狂欢节第二夜，独立调查记者布鲁诺在贫民窟顶楼派对邂逅了神秘女子伊莎。激情一夜后，伊莎无意说出“桑巴国王已死”的暗语，这恰恰是布鲁诺正在追查的国际洗钱集团新密钥。次日清晨，布鲁诺的线人横死街头，伊莎也被证实是头号毒枭“红蝎”的养女。两人被迫联手逃亡，从基督像脚下一直冲到大西洋海岸。途中他们发现，“红蝎”正在通过狂欢节花车向全球走私可卡因邮票。在废弃的桑巴学校，", "score": 2024408, "category": "drama", "detail_url": "../movie/1250.html", "poster": "../posters/1250.svg"}, {"id": "1251", "title": "差不多", "year": 2025, "region": "印度", "type": "电影", "genre": "剧情, 悬疑, 心理", "tags": ["完美主义", "记忆篡改", "强迫症", "存在主义"], "summary_short": "差不多，2025年印度电影，剧情, 悬疑, 心理。雕塑家阿努拉格对“精确”有偏执的追求，任何不对称都能让他窒息。某天醒来，他发现自己卧室的窗帘颜色从藏青变成了接近的靛蓝；妻子的微笑弧度似乎少了2度；家里养的鹦鹉叫声低了半个音。所有人都说“差不多啊，你太敏感了”。但他坚信世界被“调校”过。他偷偷录下房间的声音和影像，第二天对比，发现果然有0.1%的偏差。他开始追踪“调校者”，发现了一个崇拜“近似值”的神秘组织，他们认为绝对的精确会杀死生活", "score": 2025344, "category": "drama", "detail_url": "../movie/1251.html", "poster": "../posters/1251.svg"}, {"id": "1252", "title": "匈牙利狂想曲", "year": 2024, "region": "匈牙利", "type": "电影", "genre": "剧情, 音乐", "tags": ["李斯特", "钢琴", "历史"], "summary_short": "匈牙利狂想曲，2024年匈牙利电影，剧情, 音乐。1944年布达佩斯，著名钢琴家米克洛什被关进犹太人隔离区。纳粹军官因酷爱李斯特的音乐，命令他在每周的音乐会上演奏《匈牙利狂想曲》。米克洛什利用乐曲中即兴华彩段落，将德军调动的时间和地点编码为音符的强弱与速度变化，让在咖啡馆当乐师的地下党朋友接收。当盖世太保开始怀疑时，米克洛什在最后一次演奏中，把告密者的名字弹成了所有人都能听懂的“死亡进行曲”。", "score": 2024267, "category": "drama", "detail_url": "../movie/1252.html", "poster": "../posters/1252.svg"}, {"id": "1253", "title": "你在笑", "year": 2024, "region": "泰国", "type": "剧集", "genre": "恐怖喜剧", "tags": ["小丑恐惧症", "直播", "诅咒传递"], "summary_short": "你在笑，2024年泰国剧集，恐怖喜剧。曼谷的地下直播频道“你在笑”突然爆火。玩法很简单:每晚随机抽取一个幸运观众，直播他过去某段嘲笑、羞辱他人的手机录像，然后节目组会把这段录像寄给当年被他嘲笑的人，附上一只面具和一条信息:“现在是你的回合，你可以对他做任何事，只要你笑。”第一个被抽中的是毒舌网红，他被当年嘲笑过的胖女孩堵在停车场，女孩只是让他学狗叫。第二个是刻薄上司，他被辞退的属下在他家门口跳了一夜滑稽舞。到了第五个，被抽中的人失踪了，", "score": 2024320, "category": "series", "detail_url": "../movie/1253.html", "poster": "../posters/1253.svg"}, {"id": "1254", "title": "爱，要呼吸", "year": 2025, "region": "中国香港", "type": "电影", "genre": "剧情, 爱情, 灾难", "tags": ["潜水", "高空 accident", "绝症", "生死相依"], "summary_short": "爱，要呼吸，2025年中国香港电影，剧情, 爱情, 灾难。男主阿风是自由潜水教练，女主小卉是极限摄影师，两人深深相爱，却都患有一种极其罕见的遗传病——接触性荨麻疹，亲密接触会引发窒息。他们的爱情只能隔着一层透明薄膜进行。一场化工厂爆炸释放的神经毒气随风飘向城市，唯一安全的避难所是远处山顶的密封舱。毒气会让皮肤接触即溃烂，但对阿风和小卉而言，这反而让他们第一次可以“正常”拥抱。在逃亡路上，他们一边对抗毒气，一边对抗逐渐失效的防护服。生死关", "score": 2025362, "category": "drama", "detail_url": "../movie/1254.html", "poster": "../posters/1254.svg"}, {"id": "1255", "title": "阿拉丁和神灯", "year": 2024, "region": "法国", "type": "电影", "genre": "喜剧, 奇幻", "tags": ["现代改编", "恶搞", "冒险"], "summary_short": "阿拉丁和神灯，2024年法国电影，喜剧, 奇幻。住在巴黎贫民区的山姆是个一事无成的快递员。他在跳蚤市场买了一只破铜壶，擦拭时却冒出一个蓝色的精灵——不是巨人，而是一个穿着阿迪达斯、戴着金链子、自称“灯神有限公司”区域经理的萨米尔。萨米尔法力低微，每次实现愿望只能维持5分钟，且必须发Instagram快拍集赞才能补充能量。山姆利用这5分钟的“超能力”泡到了富家千金，却引发了一连串灾难，包括把卢浮宫变成迪厅、让埃菲尔铁塔疯狂摇摆。真正的反派", "score": 2024339, "category": "fantasy", "detail_url": "../movie/1255.html", "poster": "../posters/1255.svg"}, {"id": "1256", "title": "铁塔 武藏野线", "year": 2026, "region": "日本", "type": "电影", "genre": "剧情、青春", "tags": ["铁道", "成长", "日常治愈", "群像"], "summary_short": "铁塔 武藏野线，2026年日本电影，剧情、青春。在东京与武藏野之间，有一条慢车线“武藏野线”，全程2小时。OL小薰、大学生阿拓、退休老刑警、单亲妈妈和逃家的高中生天天乘坐同一班车。起初只是点头之交，直到一天列车突发故障，五人被迫聊天，才发现各自背负的秘密。他们约定：每天早上的第三车厢，是他们的“流动茶室”。两年间，他们见证了彼此的恋爱、和解、死亡与新生。最终列车改线，五人在最后一站挥手告别。", "score": 2026255, "category": "drama", "detail_url": "../movie/1256.html", "poster": "../posters/1256.svg"}, {"id": "1257", "title": "平原上的火焰", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "爱情 / 悬疑 / 年代", "tags": ["时代变迁，未了情缘，纵火谜案"], "summary_short": "平原上的火焰，2024年中国大陆电影，爱情 / 悬疑 / 年代。2000年寒冬，东北工业小城，少年庄树与少女李斐许下约定，要在平原上点燃一把火。十二年后，庄树成为刑警，接手一起诡异的连环纵火案。现场遗留的物证，将他带回那个改变所有人命运的夜晚。曾经的恋人李斐改名换姓，游走在法律边缘。庄树在追捕过程中，逐渐揭开当年一场因时代变革和家庭巨变引发的悲剧。火焰燃烧的不仅是建筑，更是两颗年轻的心。当真相大白于天下，他们还能找回那片燃烧的平原吗？", "score": 2024389, "category": "romance", "detail_url": "../movie/1257.html", "poster": "../posters/1257.svg"}, {"id": "1258", "title": "马年", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "剧情，家庭，文艺", "tags": ["属相，高考，代际冲突"], "summary_short": "马年，2026年中国大陆电影，剧情，家庭，文艺。1990年腊月，马年将至。河北小城，高中生马骏属马，正值本命年，又逢高考冲刺。父亲老马是个老实巴交的锅炉工，深信“本命年犯太岁”，给儿子买了一整套红内衣、红腰带、红袜子，甚至逼他每天喝一碗“朱砂水”辟邪。马骏觉得荒谬，他在物理课上偷偷看《时间简史》，坚信命运掌握在自己手中。然而霉运接踵而至：模拟考漏涂答题卡、自行车被偷、暗恋的女生转学，连家里养的马也病倒了。老马更加疯狂地求神拜佛，甚至去庙", "score": 2026281, "category": "drama", "detail_url": "../movie/1258.html", "poster": "../posters/1258.svg"}, {"id": "1259", "title": "超级伙伴", "year": 2023, "region": "美国", "type": "电影", "genre": "喜剧", "tags": ["超级英雄", "友情", "搞笑", "废柴", "团队合作"], "summary_short": "超级伙伴，2023年美国电影，喜剧。快递员小戴、程序员阿宅、健身教练大壮、网约车司机莉莉和退休大妈王姐，五人因报名参加一档超级英雄选秀节目而相识。为了通过海选，他们从网上买了五套做工粗糙的战服，去街头摆拍“行侠仗义”的视频。没想到一段他们误打误撞制服抢匪的假视频意外流出，全网爆红，真正的反派组织误以为他们是隐世高手，主动上门挑战。五人被迫以假乱真，靠着乌龙战术和彼此信任，竟接连挫败了反派的三次阴谋。当真正的危机降临——核弹威胁全城时，他", "score": 2023241, "category": "comedy", "detail_url": "../movie/1259.html", "poster": "../posters/1259.svg"}, {"id": "1260", "title": "如何培养一个女孩", "year": 2024, "region": "英国", "type": "电影", "genre": "喜剧, 剧情", "tags": ["女性", "成长", "青春", "幽默"], "summary_short": "如何培养一个女孩，2024年英国电影，喜剧, 剧情。1990年代的英国小镇，热爱摇滚乐的乔安娜身材丰满，长相普通。她厌倦了被人忽视的感觉，决定效仿她喜欢的女歌手，为自己创造了一个“酷女孩”身份——朵丽·王尔德。她谎报年龄，给音乐杂志写尖锐的乐评，混入了伦敦的地下音乐圈。她开始穿紧身衣，化浓妆，假装自己性生活丰富且酗酒。然而，这种分裂的生活让她越来越迷失。她为了维持人设伤害了最真诚的朋友，甚至搞砸了与暗恋已久的唱片店男孩的关系。在一次崩溃", "score": 2024323, "category": "drama", "detail_url": "../movie/1260.html", "poster": "../posters/1260.svg"}, {"id": "1261", "title": "不留痕迹2018", "year": 2018, "region": "法国", "type": "电影", "genre": "犯罪 / 悬疑", "tags": ["完美犯罪", "高智商", "律师", "无尸案", "反转"], "summary_short": "不留痕迹2018，2018年法国电影，犯罪 / 悬疑。改编自同名小说。巴黎发生了一起无头公案：一位著名作家在家中消失，现场只有少量血迹，无任何入侵痕迹。凶手很快自首——竟是作家16岁的自闭症养子。所有人都认为是铁案，但律师文森特接手了此案。他发现少年在家中模仿他最爱的小说《局外人》进行了一次“情感犯罪”。随着调查深入，文森特发现自己的心理咨询记录被人盗取，而盗取者竟是他自己——他一直在服用药物抑制自己“制造无痕现场”的强迫症。原来文森特", "score": 2018438, "category": "crime", "detail_url": "../movie/1261.html", "poster": "../posters/1261.svg"}, {"id": "1262", "title": "新老娘舅", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "都市，调解，伦理，喜剧", "tags": ["金牌调解，高智商，毒舌，家长里短"], "summary_short": "新老娘舅，2025年中国大陆电视剧，都市，调解，伦理，喜剧。心理学博士周游因不满父亲对企业的冷酷管理，拒绝继承家产，反而应聘了电视台金牌调解节目《新老娘舅》的调解员。他一身名牌，毒舌刻薄，看似吊儿郎当，却总能用刁钻的心理学角度化解奇葩纠纷：他用“煤气灯效应”拆穿PUA渣男，用“斯德哥尔摩综合征”解释被家暴却不离婚的大妈，甚至用“剧场理论”让争夺房产的兄妹在镜头前演了一出戏，最终和好如初。随着节目的爆红，周游不仅多次挽救自杀者，还意外揭开", "score": 2025203, "category": "series", "detail_url": "../movie/1262.html", "poster": "../posters/1262.svg"}, {"id": "1263", "title": "人生不要气馁", "year": 2025, "region": "日本", "type": "电影", "genre": "励志治愈", "tags": ["老年", "诗歌", "真实改编"], "summary_short": "人生不要气馁，2025年日本电影，励志治愈。92岁的独居老人和江奶奶在电视上看到诗歌比赛，奖金10万日元。她从未写过诗，却用一周时间写下人生第一首作品：“人生不要气馁/明天还有明天的风/今天的药很苦/但糖在抽屉里”。投稿后意外获得特等奖，全日本被这首诗治愈。出版社找上门，电视台采访，甚至有人谱曲传唱。和江奶奶说：“我只是把想吃糖的心情写下来了。”她继续写诗，写孤独，写老友一个个离世，写孙子不来电话。每一首都像温柔的巴掌，打在被生活欺负过", "score": 2025273, "category": "romance", "detail_url": "../movie/1263.html", "poster": "../posters/1263.svg"}, {"id": "1264", "title": "现在的那个人", "year": 2019, "region": "韩国", "type": "电影", "genre": "爱情 / 剧情", "tags": ["失忆", "替身", "三角恋", "悬疑", "心理创伤"], "summary_short": "现在的那个人，2019年韩国电影，爱情 / 剧情。女主秀雅车祸后失忆，醒来只认得未婚夫“志勋”这个名字。一个叫民浩的男人日夜守护她，说他是志勋。秀雅逐渐爱上民浩，但总有一种违和感。直到有一天，她的日记本被匿名寄回，里面记录着真正的志勋——那个在三年前已经因救她而溺死的人。而民浩其实是志勋的双胞胎弟弟，他被秀雅对哥哥的执着打动，本想替哥哥爱她，却在过程中自己真的爱上了她。秀雅必须在“死去的人”和“现在的那个人”之间做选择。", "score": 2019315, "category": "drama", "detail_url": "../movie/1264.html", "poster": "../posters/1264.svg"}, {"id": "1265", "title": "我的可爱对黑岩目高不管用", "year": 2023, "region": "日本", "type": "剧集", "genre": "喜剧 / 爱情", "tags": ["校园", "反差", "恋爱喜剧", "傲娇"], "summary_short": "我的可爱对黑岩目高不管用，2023年日本剧集，喜剧 / 爱情。拥有“公认可爱”称号的女高中生萌香，从小到大无论对谁卖萌都无往不利，直到她遇到了转学生黑岩目高。这个男生对她的可爱笑容毫无反应，甚至在她摔倒时只是面无表情地递过创可贴。萌香的自尊心受到极大打击，开始疯狂研究各种“可爱攻击”：歪头杀、泪眼汪汪、撒娇声线……但黑岩每次都是面无表情地完成“免疫”。就在萌香快要放弃时，她偶然发现黑岩其实有严重的“可爱过敏症”——不是不心动，而是心动时", "score": 2023315, "category": "series", "detail_url": "../movie/1265.html", "poster": "../posters/1265.svg"}, {"id": "1266", "title": "回魂危缘", "year": 2024, "region": "泰国/中国香港", "type": "电影", "genre": "恐怖/爱情", "tags": ["冥婚", "因果轮回", "前世今生", "民俗恐怖"], "summary_short": "回魂危缘，2024年泰国/中国香港电影，恐怖/爱情。曼谷华裔富商独子阿塔与女友小琳订婚前夕，小琳开始做同一个噩梦：前世她是一个叫婉的潮州女子，为争夺爱人性命，用降头术害死了情敌颂。颂临死前诅咒：三世之内必寻仇。小琳在现代遇到的所有灵异事件——镜子里的血手印、自动翻到同一页的佛经、颈后出现锁痕——都指向颂的鬼魂已化身为身边的某人。她请来白衣法师开天眼，看到的画面令她崩溃：未婚夫阿塔的魂光里，有颂的碎片。原来阿塔是带着前世怨恨投胎的，他潜意", "score": 2024424, "category": "romance", "detail_url": "../movie/1266.html", "poster": "../posters/1266.svg"}, {"id": "1267", "title": "夜中行", "year": 2025, "region": "韩国", "type": "电影", "genre": "悬疑 / 恐怖", "tags": ["都市怪谈，出租车司机，尾行"], "summary_short": "夜中行，2025年韩国电影，悬疑 / 恐怖。出租车司机老金专跑深夜班，他喜欢夜晚的城市。最近他开始频繁接到一个穿红裙的女人，每次上车都去同一个小区，但无论怎么开，老金都找不到那个小区。更诡异的是，车载导航显示目的地就在前方，可前方明明是一片荒地。女人从不催促，只是安静地坐在后座。老金调查后发现，这个女人每晚乘坐的出租车，似乎都是不同司机的车，而她正在寻找的，是自己被分尸后埋在这座城市七个角落的尸体。", "score": 2025435, "category": "horror", "detail_url": "../movie/1267.html", "poster": "../posters/1267.svg"}, {"id": "1268", "title": "猛虫过江", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 动作", "tags": ["东北，黑帮，回乡，小人物，硬汉"], "summary_short": "猛虫过江，2024年中国大陆电影，喜剧 / 动作。东北小伙大江在深圳工厂打工，突然收到老家电话：父亲欠下五百万赌债跑了，债主下了最后通牒，三天内不还钱就收房子。大江被迫回东北小山村。村子看起来贫穷落后，但村民个个卧虎藏龙：种地的二叔能用锄头一刀切酒瓶，养蜂的寡妇赵姐能听声辨位百步穿杨，开小卖部的瘸腿老张曾是东南亚赌王。原来，这个村子是二十年前金盆洗手的顶级杀手们的隐居地。债主是跨国犯罪集团“黑蛇”，他们的真实目的不是五百万，而是想逼这些", "score": 2024393, "category": "crime", "detail_url": "../movie/1268.html", "poster": "../posters/1268.svg"}, {"id": "1269", "title": "监狱不设防", "year": 2024, "region": "香港", "type": "电影", "genre": "喜剧, 动作, 犯罪", "tags": ["乌龙越狱", "卧底狱警", "监狱风云", "爆笑反转"], "summary_short": "监狱不设防，2024年香港电影，喜剧, 动作, 犯罪。陈小刀是个倒霉了一辈子的笨贼，为了救被冤枉入狱的弟弟，他决定劫狱。他精心策划了三周，结果第一晚就翻墙失败，摔进了狱长的花园里。与此同时，警察阿正男扮女装应聘狱医，任务是接近重犯“癫佬光”套取赃款下落。不巧的是，癫佬光刚好住进了医务室隔壁。更不巧的是，陈小刀的弟弟在牢里谈了个恋爱，对象是同一监狱的大佬“沙皮狗”。四路人马在监狱里各怀鬼胎，闹出了一连串乌龙。最后一场混乱的越狱行动中，所有", "score": 2024456, "category": "crime", "detail_url": "../movie/1269.html", "poster": "../posters/1269.svg"}, {"id": "1270", "title": "调皮蛋", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动画，家庭", "tags": ["皮影戏，成长，恶作剧，非遗"], "summary_short": "调皮蛋，2025年中国大陆电影，动画，家庭。留守儿童小石头是村里出名的调皮大王，喜欢拍摄整蛊短视频博取流量。开皮影戏班的爷爷想教他手艺，他嗤之以鼻。某晚，小石头为了拍“惊悚”视频，偷偷动了爷爷供奉的皮影祖师爷像，结果瞬间被吸入了皮影世界——一个二维的、由光影构成的戏曲空间。在这里，他变成了一纸片人，必须遵守“戏理”：完成三个由不同皮影角色设定的“调皮”任务才能回家。第一个任务是帮武松打虎时不被老虎发现（考验智慧）；第二个任务是帮白蛇偷仙", "score": 2025260, "category": "drama", "detail_url": "../movie/1270.html", "poster": "../posters/1270.svg"}, {"id": "1271", "title": "小迷糊回娘家", "year": 1984, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["乡土", "闹剧", "婆媳", "台语片"], "summary_short": "小迷糊回娘家，1984年中国台湾电影，喜剧 / 家庭。阿娇是村里出了名的“迷糊蛋”，嫁人后每次回娘家都因为丢三落四或好心办坏事引发骚乱。这次她骑着机车载着巨大的礼品盒回村，结果半路礼品散落引得猪羊乱窜。到了娘家，她想帮母亲操办寿宴，却把厨房烧了，把盐当成糖，甚至误将强力胶当作米酒下锅。更夸张的是，她无意中释放了邻居家的赛鸽，引发了全村的大追捕。在这片混乱中，阿娇却用自己的天真和善良，意外化解了母亲与隔壁阿婆几十年的恩怨，让人在捧腹大笑之", "score": 1984327, "category": "comedy", "detail_url": "../movie/1271.html", "poster": "../posters/1271.svg"}, {"id": "1272", "title": "君子好逑", "year": 2025, "region": "中国香港", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["都市", "剩女", "港式幽默", "反转"], "summary_short": "君子好逑，2025年中国香港电影，爱情 / 喜剧。32岁的投资银行副总裁阿宝，连续被五位“优质男”劈腿后，购买了一台高价AI仿生人“亚当”，输入所有“完美男友”参数。亚当会说法语、煮意面、每月记得生理期。阿宝很满意，直到亚当连续三天死机。维修工阿强上门，一个满头油污、穿着拖鞋的“废青”。阿强三两下修好亚当，临走时说：“你给他设定的‘吃醋’参数是0.01，太低了，女人会觉得不够爱。”阿宝无视。但她渐渐发现，自己更期待阿强来维修的半小时。当", "score": 2025381, "category": "comedy", "detail_url": "../movie/1272.html", "poster": "../posters/1272.svg"}, {"id": "1273", "title": "女孩的难忘生日", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "剧情 / 青春 / 家庭", "tags": ["成长阵痛", "单亲家庭", "秘密", "成年礼"], "summary_short": "女孩的难忘生日，2024年中国台湾电影，剧情 / 青春 / 家庭。高三女生小琪一直期待18岁生日能与母亲和解，却意外翻出一张旧报纸，得知父亲并非离弃家庭而是十年前因公殉职。母亲多年来编织的善意谎言瞬间崩塌。小琪带着愤怒与不解踏上寻根之旅，在父亲生前的战友口中，拼凑出一个完全不同的英雄形象。从怨恨到理解，她最终在生日蜡烛前，为自己和母亲举办了一场迟来的成人礼。", "score": 2024240, "category": "drama", "detail_url": "../movie/1273.html", "poster": "../posters/1273.svg"}, {"id": "1274", "title": "变异巨蟒", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "灾难， 惊悚， 动作", "tags": ["巨蟒， 实验室泄漏， 雨林， 生化变异， 极限逃生"], "summary_short": "变异巨蟒，2023年中国大陆电影，灾难， 惊悚， 动作。生物制药巨头“无限基因”秘密在亚马逊支流投放催长剂以培育高价值药用植物，不料污染物顺流而下，导致下游的森蚺在短短三个月内体长暴增至五十米，皮肤坚如合金。一支为拍摄稀有粉红海豚的纪录片团队深入雨林腹地，他们的船被变异巨蟒撞翻，五人被迫穿越蟒蛇密布的“死亡走廊”——一条被二十多条变异巨蟒占据的河谷。最恐怖的是，这群巨蟒已经演化出基础社会性，会协同伏击、传递信号甚至设置陷阱。队长老赵发现", "score": 2023399, "category": "crime", "detail_url": "../movie/1274.html", "poster": "../posters/1274.svg"}, {"id": "1275", "title": "私恶公善", "year": 1979, "region": "法国", "type": "电影", "genre": "剧情，伦理，政治", "tags": ["双面人生，腐败，道德困境，官员，黑色幽默"], "summary_short": "私恶公善，1979年法国电影，剧情，伦理，政治。法国外省小城即将举行市长选举，现年50岁的独立候选人德勒雷是公认的正人君子：他为穷人建廉租房，整顿警队腐败，支持率高达78%。但他的竞选对手、右派政客拉鲁埃雇佣私家侦探调查后发现一个惊天秘密：德勒雷每周三晚上都会去郊区一个废弃仓库，与三位不同女性发生关系，其中一位甚至是不满20岁的移民女孩。拉鲁埃握着照片犹豫了：如果公开，他赢定了，但这会摧毁一个真正在做好事的人；如果不公开，他的政治生涯就", "score": 1979307, "category": "drama", "detail_url": "../movie/1275.html", "poster": "../posters/1275.svg"}, {"id": "1276", "title": "天地孩儿", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "奇幻、家庭", "tags": ["儿童、天地人三界、治愈、寓言"], "summary_short": "天地孩儿，2026年中国台湾电影，奇幻、家庭。男孩阿纶天生拥有异瞳，能看见人间与灵界之间的灰色地带——那里飘荡着因执念而无法投胎的“天地孩儿”。阿纶被一位自称“引路人”的老者告知，他必须帮助一百个这样的灵魂找到归宿，届时他的眼睛会给出最终提示：留在人间，还是成为天地之间的一员。在帮助了九十九个灵魂之后，他遇到了最后一个——一个自称是他未来儿子的少年灵魂。这个少年告诉阿纶，如果他选择离开人间，那么自己将永远不会出生。阿纶必须在自己尚未存在", "score": 2026315, "category": "comedy", "detail_url": "../movie/1276.html", "poster": "../posters/1276.svg"}, {"id": "1277", "title": "薇若妮卡想不开", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情 / 喜剧 / 黑色幽默", "tags": ["存在主义", "荒诞", "女性视角", "轻松抑郁", "自我救赎"], "summary_short": "薇若妮卡想不开，2023年法国电影，剧情 / 喜剧 / 黑色幽默。薇若妮卡，35岁，哲学系辍学生，现经营一家快倒闭的书店。她精心策划了十二次自杀，每次都以荒诞失败告终：跳河时救起溺水的孩子，割腕时血滴进楼下盆栽让濒死植物开花，开煤气后顺手给邻居送钥匙反而救了煤气中毒的老人。她的事迹被媒体称为“天使薇若妮卡”，每天有绝望的人排队请她“帮忙自杀”。她被迫成立“告别辅导班”，教人们如何与痛苦共存。当她终于设计出完美的第十三场告别仪式时，却遇到", "score": 2023321, "category": "drama", "detail_url": "../movie/1277.html", "poster": "../posters/1277.svg"}, {"id": "1278", "title": "少年说第二季", "year": 2022, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭 / 青春", "tags": ["代际沟通， 校园， 心理成长， 真实改编， 社会话题"], "summary_short": "少年说第二季，2022年中国大陆剧集，剧情 / 家庭 / 青春。第二季将镜头对准南京一所重点中学。六个性格迥异的少年在天台喊出对父母的真实心声：有人控诉“鸡娃”教育，有人公开自己的性取向，有人哭诉父母离异后的冷暴力。节目组本打算以此引导家庭沟通，不料一段未剪辑的粗剪版母带被黑客盗取并在网上公开。一夜之间，少年们的隐私变成全网谈资。家长反目、学校施压、网暴如潮水涌来。节目组陷入伦理与流量的两难抉择。总导演宁可坐牢也拒绝交出少年们的完整信息", "score": 2022261, "category": "series", "detail_url": "../movie/1278.html", "poster": "../posters/1278.svg"}, {"id": "1279", "title": "死亡笔记本：决战新世界", "year": 2016, "region": "日本", "type": "剧集", "genre": "悬疑，奇幻，犯罪", "tags": ["死神，继承者，网络审判"], "summary_short": "死亡笔记本：决战新世界，2016年日本剧集，悬疑，奇幻，犯罪。在基拉事件平息十年后，死亡笔记本并未消失。全球范围内出现了六本笔记的继承者，他们各自秉持不同的正义观，在网络上公开处决罪犯，引发了第三次“基拉热潮”。警方成立了特殊的“笔记对策室”，同时，自称L正统继承者的侦探“龙崎”现身。年轻的天才警官三岛创必须在不同笔记持有者的博弈中找出真相，而他不知道，自己身边最信任的搭档，正是那本最危险的笔记的主人。", "score": 2016446, "category": "series", "detail_url": "../movie/1279.html", "poster": "../posters/1279.svg"}, {"id": "1280", "title": "菜鸟老警第五季", "year": 2022, "region": "美国", "type": "剧集", "genre": "剧情 / 犯罪", "tags": ["警察", "中年转行", "搭档", "案件单元", "成长"], "summary_short": "菜鸟老警第五季，2022年美国剧集，剧情 / 犯罪。约翰·诺兰已经成为洛杉矶警局的中坚力量，但第五季的开篇就迎来他以为早已死去的宿敌。与此同时，警局内部出现内鬼，导致多次行动失败。诺兰与搭档不得不一边破获各种街头案件，一边暗中调查同事。当私人生活与职业边界不断被打破，诺兰必须做出选择：守护正义，还是保护自己爱的人。", "score": 2022272, "category": "series", "detail_url": "../movie/1280.html", "poster": "../posters/1280.svg"}, {"id": "1281", "title": "公园", "year": 2025, "region": "韩国", "type": "电影", "genre": "剧情, 奇幻", "tags": ["魔幻现实", "社区", "记忆", "治愈"], "summary_short": "公园，2025年韩国电影，剧情, 奇幻。首尔市中心，有一座建于80年代的“儿童大公园”，面临着被改建成停车场的命运。这里的常客：失去老伴的清洁工爷爷、被校园霸凌不敢上学的少年、离婚后独自带娃的便利店阿姨。他们偶然发现，每当午夜钟声响起，公园里的旋转木马会发光，变成一个集市。在这里，你可以用“一段记忆”作为货币，购买任何东西：一碗妈妈做的炸酱面、一个温暖的拥抱、甚至是一天的时间。爷爷用“第一次送妻子玫瑰”的记忆，换来了妻子临终前的一句“我", "score": 2025360, "category": "drama", "detail_url": "../movie/1281.html", "poster": "../posters/1281.svg"}, {"id": "1282", "title": "倚天屠龙记粤语", "year": 2025, "region": "香港", "type": "剧集", "genre": "武侠 / 历史 / 剧情", "tags": ["粤语原声", "新派武侠", "权谋", "张无忌", "港味江湖"], "summary_short": "倚天屠龙记粤语，2025年香港剧集，武侠 / 历史 / 剧情。本版本尊重原著前中期脉络：张无忌身负九阳神功和乾坤大挪移，成为明教教主，率众反抗元朝。但在推翻元朝后，剧情走向全新分支。朱元璋在明教内部拉拢韦一笑、徐达等人，设计陷害杨逍，逐步架空张无忌。张无忌发现，自己不仅是武学奇才，更是政治上的棋子。朱元璋以“天下初定，不宜有江湖势力凌驾皇权”为由，要求明教解散。在一次鸿门宴上，朱元璋送给张无忌一把轮椅，暗示他如果“不想走路”，可以留在京", "score": 2025180, "category": "costume", "detail_url": "../movie/1282.html", "poster": "../posters/1282.svg"}, {"id": "1283", "title": "雾的子午线", "year": 2027, "region": "法国 / 日本", "type": "电影", "genre": "悬疑 / 剧情", "tags": ["时差", "跨国", "记忆碎片", "天气"], "summary_short": "雾的子午线，2027年法国 / 日本电影，悬疑 / 剧情。气象学家七海发现一个诡异的气象数据模式：在巴黎经度2°20‘和东京经度139°40’之间的某个特定子午线区段，每年同一天的大气数据都会出现0.3秒的断裂。更奇怪的是，她查到过去十年里，每年都有三个人在同一时刻、分别在这两座城市失踪——失踪者之间没有任何社会关系，唯一的共同点是他们都曾在那0.3秒内抬头看天。七海飞到巴黎，找到最后一位失踪者的笔记，上面只画了一条波浪线和一行字：“雾", "score": 2027396, "category": "drama", "detail_url": "../movie/1283.html", "poster": "../posters/1283.svg"}, {"id": "1284", "title": "捕手间谍", "year": 2025, "region": "美国", "type": "电影", "genre": "惊悚, 剧情", "tags": ["冷战", "棒球", "双面间谍", "真实改编"], "summary_short": "捕手间谍，2025年美国电影，惊悚, 剧情。冷战最激烈的时期，美国职业棒球联盟的明星捕手杰克，在一次前往莫斯科的友谊赛中，被CIA招募。因为他可以通过棒球比赛中投手与捕手之间独有的暗号手势，在全世界转播的镜头前传递摩斯密码。杰克怀着爱国热情接下了任务，却在一次次任务中，发现CIA内部也有苏联的鼹鼠。他的情报导致了一位良心苏联科学家的死亡，这让他开始怀疑自己的立场。苏联克格勃抓住了他的软肋——他的女儿，逼迫他也成为苏联的间谍。从此，杰克在", "score": 2025364, "category": "drama", "detail_url": "../movie/1284.html", "poster": "../posters/1284.svg"}, {"id": "1285", "title": "逐星女", "year": 2025, "region": "美国", "type": "电视剧", "genre": "科幻动作", "tags": ["超英", "天体物理学", "女大学生", "暗物质", "反套路"], "summary_short": "逐星女，2025年美国电视剧，科幻动作。本剧设定于DC宇宙的独立支线。主角不是高中生，而是29岁的天体物理学博士后嘉莉。她一直坚信暗物质是宇宙的基石，并在一家二流大学进行不被看好的研究。某夜，一次失败的实验将实验室炸毁，她却在辐射中活了下来，并发现自己能感知到宇宙中的暗物质流动，将其具象化为“星辰”。她可以制造重力场、扭曲光线，甚至短暂地“瞬移”。与传统超级英雄不同，嘉莉的第一反应不是拯救世界，而是写论文发表自己的发现。然而，一个名为“", "score": 2025298, "category": "series", "detail_url": "../movie/1285.html", "poster": "../posters/1285.svg"}, {"id": "1286", "title": "七生有幸", "year": 2008, "region": "美国", "type": "电影", "genre": "剧情 / 悬疑", "tags": ["救赎，七个人，水母，自毁"], "summary_short": "七生有幸，2008年美国电影，剧情 / 悬疑。威尔·史密斯主演的非典型文艺片。本·托马斯是一名国税局职员，他每天的工作是调查税务欺诈，但私下里，他会突然对陌生人发怒，也会突然把房子免费送给一个被家暴的单亲妈妈。他用尽所有方法去测试七个人——盲人销售员、心脏病人、受虐儿童……直到有一天，他遇到了患有先天性心脏病的艾米莉。在与艾米莉的相处中，他第一次动了活下去的念头。但他不知道的是，当他爱上艾米莉的那一刻，他之前定好的计划，已经无法回头了。", "score": 2008341, "category": "drama", "detail_url": "../movie/1286.html", "poster": "../posters/1286.svg"}, {"id": "1287", "title": "大偷袭", "year": 2024, "region": "美国 / 菲律宾", "type": "电影", "genre": "战争动作", "tags": ["二战，战俘营，游骑兵，极限救援，真实事件改编"], "summary_short": "大偷袭，2024年美国 / 菲律宾电影，战争动作。根据真实历史事件改编。二战末期，日军“马尼拉大屠杀”前夕，情报显示卡巴那图战俘营内的500多名美菲战俘将被处决。第6游骑兵营的两位年轻上尉，带领百余人，穿越丛林沼泽，对抗日军重兵把守的营地。计划只有一次机会。他们利用暴雨和夜色，在战俘被转移前一小时发动突袭。枪声、刀光、甚至徒手搏斗，每一秒都有人倒下。最终成功救出489人，创造了军事史上最成功的救援行动。", "score": 2024270, "category": "doc", "detail_url": "../movie/1287.html", "poster": "../posters/1287.svg"}, {"id": "1288", "title": "438天", "year": 2021, "region": "俄罗斯", "type": "电影", "genre": "剧情 / 历史", "tags": ["真实事件改编", "体育政治", "冷战"], "summary_short": "438天，2021年俄罗斯电影，剧情 / 历史。1972年慕尼黑奥运会，苏联男篮击败美国队夺得金牌，全队准备庆祝时，慕尼黑惨案发生，奥运村被封。苏联队员和教练被命令“原地待命”，困在体育馆地下室里，一困就是438天。最初，球队内部充满矛盾：立陶宛人、乌克兰人、俄罗斯人之间互相敌视，有人想叛逃，有人酗酒，有人绝食。但随着时间流逝，他们被迫学习彼此的语言、分享家庭故事、为过生日的队友偷蛋糕。当他们最终被秘密运回国时，迎接他们的不是英雄待遇，", "score": 2021264, "category": "drama", "detail_url": "../movie/1288.html", "poster": "../posters/1288.svg"}, {"id": "1289", "title": "渺小而坚韧", "year": 2025, "region": "日本", "type": "电视剧", "genre": "剧情, 职场, 女性", "tags": ["社畜", "逆袭", "温暖"], "summary_short": "渺小而坚韧，2025年日本电视剧，剧情, 职场, 女性。大型商社的普通员工小林杏奈因为一次失误被下放到仓库资料室，这里全是“被公司抛弃的人”。所有人都选择混日子等退休，只有她每天把陈年资料整理归档，从中发现了大量被遗忘的客户信息和商业线索。她用最原始的方式——手写信件、登门拜访，唤醒了这些沉睡的资源。一年后，资料室创造的利润超过所有销售部总和。当总部要把她调回去当高管时，她拒绝了，因为她找到了真正让自己发光的地方。", "score": 2025227, "category": "series", "detail_url": "../movie/1289.html", "poster": "../posters/1289.svg"}, {"id": "1290", "title": "千王之王粤语", "year": 1980, "region": "中国香港", "type": "剧集", "genre": "剧情， 犯罪", "tags": ["赌术， 复仇， 经典， 老港剧"], "summary_short": "千王之王粤语，1980年中国香港剧集，剧情， 犯罪。1960年代的香港，“千门八将”之首“南神眼”罗四海早已隐退，经营一家茶楼。一日，他收到徒弟阿星寄来的一个信封，里面是半张红心A和一张纸条：“师父，有人出千。”次日，阿星尸体在码头被发现，手中紧握另外半张红心A。罗四海重出江湖，发现阿星卷入了一场跨国赌局，对手是澳门赌场新贵“鬼手”程逸风。罗四海摆下“千王宴”，邀请全亚洲千门高手，以一副特殊的扑克牌为赌具，牌上都有肉眼不可见的暗记——只", "score": 1980297, "category": "series", "detail_url": "../movie/1290.html", "poster": "../posters/1290.svg"}, {"id": "1291", "title": "王冠的游戏：都铎家族", "year": 2024, "region": "英国", "type": "剧集", "genre": "剧情 / 历史 / 宫斗", "tags": ["都铎王朝", "亨利八世", "宗教改革", "权谋"], "summary_short": "王冠的游戏：都铎家族，2024年英国剧集，剧情 / 历史 / 宫斗。1527年，亨利八世为求男嗣，执意与凯瑟琳王后离婚并迎娶安妮·博林。但这部剧的主角不是亨利，而是他身边的“玩家”：红衣主教沃尔西在罗马与伦敦之间做双面间谍；安妮·博林的弟弟乔治暗中与改革派勾结；甚至连宫廷小丑都在用笑话传递密信。当亨利以为自己掌控一切时，他发现自己只是棋盘上的一枚棋子——真正的王冠游戏，在修道院、法国宫廷和伦敦的印刷铺里同时进行。最后，断头台落下，但死的", "score": 2024209, "category": "series", "detail_url": "../movie/1291.html", "poster": "../posters/1291.svg"}, {"id": "1292", "title": "恶魔游戏2024", "year": 2024, "region": "韩国", "type": "电影", "genre": "悬疑, 恐怖", "tags": ["直播杀人", "网络暴力", "数字恶魔"], "summary_short": "恶魔游戏2024，2024年韩国电影，悬疑, 恐怖。六名身份各异的韩国网民收到一条神秘链接，点开后进入名为“恶魔游戏2024”的聊天室。规则很简单：每周一轮，每人匿名投票给一个“最虚伪的人”，得票最高者被标记为“恶魔”，然后会在24小时内死亡，死法与他们在过去两年内参与过的一场网络暴力中受害者的死法完全相同。第一轮，被票选出的家庭主妇朴妈妈曾在一个校暴事件中留言“这女孩一看就不检点”，结果那女孩自杀了。24小时后，朴妈妈从自家阳台跳下。", "score": 2024399, "category": "horror", "detail_url": "../movie/1292.html", "poster": "../posters/1292.svg"}, {"id": "1293", "title": "王保长新篇Ⅱ死去生来", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "喜剧、剧情、历史", "tags": ["方言剧、民国、小人物、幽默"], "summary_short": "王保长新篇Ⅱ死去生来，2024年中国大陆电视剧，喜剧、剧情、历史。抗战胜利后，王保长在一次混战中被炮弹炸晕，被误认为已死。县政府为他举行了隆重的追悼会，并给他发了巨额抚恤金。醒来的王保长发现“烈士”身份能让他获得尊重和金钱，于是决定装死，化名“王新生”潜伏在镇上。他眼睁睁看着自己老婆差点改嫁、地痞冒充他私生子来分遗产，甚至县长要把他的“故居”改成酒店。一系列荒诞事中，王保长最终被善良的乡亲们感动，在一次土匪袭击村镇时，他不得不“死而复生", "score": 2024235, "category": "series", "detail_url": "../movie/1293.html", "poster": "../posters/1293.svg"}, {"id": "1294", "title": "云南虫谷2021", "year": 2021, "region": "中国大陆", "type": "网络电影", "genre": "冒险悬疑", "tags": ["盗墓", "献王墓", "虫子", "摸金校尉", "原著改编"], "summary_short": "云南虫谷2021，2021年中国大陆网络电影，冒险悬疑。为了破解身上的诅咒，胡八一、Shirley杨和王胖子进入云南虫谷寻找雮尘珠。他们穿过水洞、躲过雕鸮、避开毒虫群，终于找到了献王墓的人皮地图。但进入主墓室后，他们发现棺材是空的，而墓室墙壁上密密麻麻嵌着虫卵，每个卵里都裹着一个未发育完成的人类婴儿。更诡异的是，虫卵正在孵化，而孵化它们的营养源，来自墓室底部一根通向外界的水管——有人一直在往墓里输送活人的血液。他们不是第一批进来的，上一", "score": 2021303, "category": "fantasy", "detail_url": "../movie/1294.html", "poster": "../posters/1294.svg"}, {"id": "1295", "title": "无辜囚徒", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情 / 犯罪", "tags": ["冤案", "监狱", "救赎", "时间跨度"], "summary_short": "无辜囚徒，2025年中国大陆电影，剧情 / 犯罪。1998年，电工陈志强被错判为连环杀人犯，入狱十八年。狱警老周是唯一对他释放善意的人，不仅帮他减刑，还教他读书写字。2016年出狱后，陈志强遇到了当年案件受害者的家属，得知真凶另有其人。当他用当年狱中学会的推理抽丝剥茧时，所有证据都指向了一个他无法相信的人——老周。为了讨回清白，他必须亲手将唯一的朋友送进监狱，而老周在审讯室对他说的第一句话是：“你终于学会了。”", "score": 2025351, "category": "drama", "detail_url": "../movie/1295.html", "poster": "../posters/1295.svg"}, {"id": "1296", "title": "江南剿匪记之致命武器", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "战争, 动作", "tags": ["剿匪", "民国", "冷兵器", "奇门遁甲"], "summary_short": "江南剿匪记之致命武器，2023年中国大陆电影，战争, 动作。1949年，浙东山区匪患猖獗，匪首“活阎王”利用当地溶洞地形和祖传的机关术，构建了一座易守难攻的地下堡垒。我军侦察排长陈大雷带着五名精英战士化妆潜入。他们要面对的不仅是凶残的土匪，还有无处不在的陷阱：溶洞里的浮桥、毒箭墙、甚至是利用水流驱动的自动弩车。在一次交火中，陈大雷发现匪帮里竟有一位被胁迫的清末皇家造办处传人，那位老人制造了这些“致命武器”。为了不伤及同胞，陈大雷决定改变", "score": 2023349, "category": "crime", "detail_url": "../movie/1296.html", "poster": "../posters/1296.svg"}, {"id": "1297", "title": "心中有鬼", "year": 2022, "region": "中国香港", "type": "电影", "genre": "心理惊悚", "tags": ["幻觉", "复仇", "反转"], "summary_short": "心中有鬼，2022年中国香港电影，心理惊悚。阿豪车祸失忆后，家中镜子总会出现一个穿红裙的女人。心理医生陈博士认定这是创伤后幻觉，给他开了强效药。但阿豪按邻居指引挖开地下室，发现红裙女人的尸骨——那是他失踪五年的未婚妻。更恐怖的是，陈博士看到尸骨后突然大笑：“我就是她姐姐，等你想起真相等了五年。”原来阿豪当年因怀疑未婚妻出轨而失手杀人，记忆被陈博士用药物持续抹除并植入幻觉，只为让他反复体验恐惧。谁是鬼？谁才是疯子？", "score": 2022334, "category": "horror", "detail_url": "../movie/1297.html", "poster": "../posters/1297.svg"}, {"id": "1298", "title": "鲨鱼侵袭", "year": 2026, "region": "美国", "type": "电影", "genre": "灾难惊悚", "tags": ["鲨鱼", "邮轮", "深海", "血腥"], "summary_short": "鲨鱼侵袭，2026年美国电影，灾难惊悚。跨年邮轮遭遇风暴倾覆，三百多名乘客爬上船底和漂浮物。好消息是救援六小时后到；坏消息是，船体正在泄露燃油，而燃油吸引了方圆数百公里的鲨鱼。起初鲨鱼只是试探，但当一个受伤乘客落水后，大屠杀开始了。幸存者分成了几个阵营：有人想牺牲伤员保全大家，有人想用血肉引开鲨鱼为妇孺争取时间，有人则疯狂祈祷。更可怕的是，人群中的恐慌比鲨鱼更致命——有人被自己人推下水，有人为了争夺高地而互殴。当救援直升机出现时，海面上", "score": 2026326, "category": "horror", "detail_url": "../movie/1298.html", "poster": "../posters/1298.svg"}, {"id": "1299", "title": "残骸", "year": 2021, "region": "美国", "type": "剧集", "genre": "科幻，悬疑，剧情", "tags": ["外星飞船，全球危机，特工搭档"], "summary_short": "残骸，2021年美国剧集，科幻，悬疑，剧情。一艘巨大的外星飞船毫无征兆地在地球轨道上爆炸，无数碎片像流星雨般散落世界各地。这些被称为“残骸”的物质拥有超越人类认知的物理特性：有的能让时间倒流，有的能改写局部重力，有的甚至能与人类意识产生连接。美国和英国的情报机构迅速组建了一个联合特工小组，负责回收并研究这些残骸。特工布莱恩和菲诺拉成为搭档，他们不仅要与时间赛跑，抢在黑市买家和其他国家之前找到残骸，更要揭开飞船爆炸的真正原因。随着调查深入", "score": 2021390, "category": "series", "detail_url": "../movie/1299.html", "poster": "../posters/1299.svg"}, {"id": "1300", "title": "弗兰克电影", "year": 2026, "region": "美国", "type": "电影", "genre": "喜剧、悬疑", "tags": ["伪纪录片，好莱坞讽刺，失踪案，元电影"], "summary_short": "弗兰克电影，2026年美国电影，喜剧、悬疑。导演阿伦是个纪录片门外汉，他想拍一部关于过气动作明星弗兰克“东山再起”的励志片。他采访了弗兰克的经纪人、前妻、替身演员和私生饭，所有人都在镜头前讲述着感人的故事。但在剪辑阶段，阿伦突然发现了一个恐怖的事实：所有采访的时间戳都是混乱的，弗兰克其实在三年前就失踪了，而接受他采访的这些人，每个人扮演的都是不同的角色。经纪人实际上是追踪弗兰克的债主，前妻是私家侦探，而那个私生饭可能是绑架者。阿伦决定将", "score": 2026346, "category": "crime", "detail_url": "../movie/1300.html", "poster": "../posters/1300.svg"}, {"id": "1301", "title": "怀孕契约", "year": 2024, "region": "韩国", "type": "电影", "genre": "剧情 / 悬疑 / 家庭", "tags": ["代孕伦理", "财阀阴谋", "反转不断"], "summary_short": "怀孕契约，2024年韩国电影，剧情 / 悬疑 / 家庭。女大学生秀敏为了还债，签下一份高额代孕合同。她住进豪华公寓，接受严格监控。某天她意外看到雇主照片：竟是五年前被迫分离的亲姐姐智雅。智雅无法生育，而精子供者竟是秀敏的前男友、现在已成为智雅丈夫的俊浩。秀敏想逃，但合同违约金高得离谱。她发现姐姐之所以选择她，是因为她们有相同的罕见血型，可以避免排异。秀敏决定暗中收集证据起诉这家代孕中介，却发现自己早已被窃听。当孩子出生那天，三个人的秘密", "score": 2024388, "category": "drama", "detail_url": "../movie/1301.html", "poster": "../posters/1301.svg"}, {"id": "1302", "title": "鳄鱼邓迪2", "year": 2024, "region": "澳大利亚, 美国", "type": "电影", "genre": "喜剧, 冒险", "tags": ["续集", "丛林", "文化冲突", "环保"], "summary_short": "鳄鱼邓迪2，2024年澳大利亚, 美国电影，喜剧, 冒险。距离上部电影过去四十年，年迈的米克·邓迪依然生活在澳大利亚的丛林中。一天，一架直升机降落在他的领地，纽约地产商宣布这片土地已被政府出售，要建豪华度假村。邓迪试图用法律和媒体抗争，但对方买通官员。无奈之下，这位老猎人重启“荒野模式”：他利用丛林知识切断开发商供应链，用鳄鱼吓跑施工队，还拍下对方非法倾倒垃圾的证据上传网络，引发全球环保人士声援。最终他与地产商在雨季的洪水中展开一场“文", "score": 2024287, "category": "fantasy", "detail_url": "../movie/1302.html", "poster": "../posters/1302.svg"}, {"id": "1303", "title": "几度菊花香", "year": 2006, "region": "大陆", "type": "剧集", "genre": "剧情, 家庭, 年代", "tags": ["知青", "文革", "亲情", "催泪"], "summary_short": "几度菊花香，2006年大陆剧集，剧情, 家庭, 年代。上世纪六十年代，南方小城里，护士林雅在接生时因疏忽将两家的女儿抱错。富家女被送进了贫苦的菊花巷，而穷家女则在富裕家庭长大。二十年后，真相在一次体检中意外揭晓。面对错位的人生，两姐妹从敌视、嫉妒到相互理解。随着文革的到来，两个家庭都遭受了巨大冲击，姐妹俩在风雨中撑起了破碎的家。她们像菊花一样，虽历经风霜却傲然挺立。最终，当恩怨散去，她们选择了共同照顾四位父母，诠释了超越了血缘的爱。", "score": 2006222, "category": "series", "detail_url": "../movie/1303.html", "poster": "../posters/1303.svg"}, {"id": "1304", "title": "在异世界迷宫开后宫", "year": 2024, "region": "日本", "type": "动画剧集", "genre": "奇幻，后宫，冒险", "tags": ["异世界转生，迷宫探索，慢生活"], "summary_short": "在异世界迷宫开后宫，2024年日本动画剧集，奇幻，后宫，冒险。程序员加藤诚因过劳死后，被女神丢进了一个以“迷宫主权”为核心经济的异世界。他获得的唯一外挂，是能调出类似游戏UI的系统界面，且可以购买“奴隶队友”。为了避免卷入贵族斗争，他选择低调地在一座偏远迷宫小镇定居。他陆续买下了拥有特殊职业的女战士、精灵弓手、兽人治愈师等性格各异的同伴。故事围绕迷宫攻略、资源管理、家具购买、日常纠纷展开。没有拯救世界的宏大使命，只有如何在异世界还清房贷", "score": 2024304, "category": "fantasy", "detail_url": "../movie/1304.html", "poster": "../posters/1304.svg"}, {"id": "1305", "title": "铁骑军魂", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "战争 / 动作 / 历史", "tags": ["骑兵连", "抗日战争", "硬核战争"], "summary_short": "铁骑军魂，2025年中国大陆电影，战争 / 动作 / 历史。1939年深秋，华北平原。八路军某骑兵连在突围后仅剩32人，战马也伤亡过半。他们接到了最后一个任务：掩护方圆百里内最后一批不愿撤离的乡亲转移。敌人是日军一支拥有坦克和重炮的完整联队，由一位信奉闪电战的冷酷少佐指挥。连长“刀疤赵”腿部中弹，只能躺在担架上指挥。面对绝境，他们没有退缩，利用地形和熟悉民情，以“麻雀战”骚扰、消耗敌人。在晨曦中，当看到乡亲们的队伍渐渐走远，32名浑身是", "score": 2025291, "category": "doc", "detail_url": "../movie/1305.html", "poster": "../posters/1305.svg"}, {"id": "1306", "title": "黑暗王子：摄欲人生", "year": 2024, "region": "美国", "type": "电视剧", "genre": "剧情 / 惊悚", "tags": ["犯罪心理，连环杀手，传记式，黑暗"], "summary_short": "黑暗王子：摄欲人生，2024年美国电视剧，剧情 / 惊悚。本剧以倒叙手法展开，从1985年拉米雷斯被捕前夕回溯他的童年。父亲暴躁、沉迷巫术，少年拉米雷斯开始偷窃、吸毒，并在表哥——一个越战老兵——的蛊惑下接触虐杀照片。表哥向他炫耀在越南割下敌人耳朵的经历，拉米雷斯心中埋下嗜血种子。剧中细腻描绘他如何从偷窃演变为入室抢劫，再到无法自控的连环杀戮。每一集片头都有一段拉米雷斯的内心独白，将“撒旦崇拜”作为自我辩护的工具。最终集他在法庭上高喊“", "score": 2024258, "category": "series", "detail_url": "../movie/1306.html", "poster": "../posters/1306.svg"}, {"id": "1307", "title": "风流侠盗走天涯", "year": 1988, "region": "中国香港", "type": "电影", "genre": "喜剧, 冒险", "tags": ["侠盗", "易容", "民国", "夺宝"], "summary_short": "风流侠盗走天涯，1988年中国香港电影，喜剧, 冒险。民国乱世，江湖骗子梅少游以“走天涯”为名，专骗为富不仁者。他擅长易容与催眠，自诩雅盗。某次他误入军阀张大帅的府邸，本想偷一幅假画，却不慎盗得真正的清朝龙脉藏宝图。张大帅震怒，派出黑鹰队追杀。同时，一心想要破大案的女警司白露奉命追捕梅少游。在火车与沙漠的追逐中，两人被迫联手。梅少游的机变与白露的枪法配合得天衣无缝。他们发现宝藏所在地已被日军间谍盯上。面对外敌，梅少游舍弃了财宝，利用藏宝", "score": 1988250, "category": "comedy", "detail_url": "../movie/1307.html", "poster": "../posters/1307.svg"}, {"id": "1308", "title": "家庭录像", "year": 2022, "region": "西班牙", "type": "电影", "genre": "恐怖， 伪纪录片， 心理", "tags": ["录像带， 邪教， 祖宅， 超8毫米"], "summary_short": "家庭录像，2022年西班牙电影，恐怖， 伪纪录片， 心理。兄妹哈维尔和艾琳娜回到西班牙北部荒废的祖宅，准备卖掉还债。在阁楼发现一箱超8毫米胶片，标签写着“家庭录像1982-1995”。第一盘：祖母过80大寿，正常。第二盘：祖母独自在卧室，对着镜头反复念一句奇怪音节。第三盘、第四盘……每过一盘，念咒时间越长，画面噪点越多，且墙角阴影在移动。第12盘：祖母身边多了一个穿黑衣的小孩，看不清脸。兄妹对照方言词典，发现那句咒语意思是“让门开着”。", "score": 2022384, "category": "horror", "detail_url": "../movie/1308.html", "poster": "../posters/1308.svg"}, {"id": "1309", "title": "直立象传说", "year": 2024, "region": "美国", "type": "动画电影", "genre": "奇幻 / 冒险 / 家庭", "tags": ["史前", "成长", "勇气", "亲情"], "summary_short": "直立象传说，2024年美国动画电影，奇幻 / 冒险 / 家庭。冰河时期末期，猛犸象族群坚持四足行走的传统，认为直立是禁忌。天生前腿短小的幼象塔奇因为无法像同类那样行走，被视作不祥之物赶出群落。濒死之际，他被人类部落的女孩梅救下。梅告诉塔奇，她的祖父曾见过一种可以“用两条腿走路”的巨兽，那才是塔奇的祖先。一象一孩穿越冰原和火山，寻找传说中的“直立之谷”。途中他们发现，直立行走的秘密不是诅咒，而是为了让猛犸象在食物匮乏时能够到更高处的树叶。", "score": 2024301, "category": "fantasy", "detail_url": "../movie/1309.html", "poster": "../posters/1309.svg"}, {"id": "1310", "title": "风暴之山", "year": 2024, "region": "英国", "type": "电影", "genre": "冒险, 剧情, 惊悚", "tags": ["登山", "自然灾害", "人性考验", "兄弟情", "生存"], "summary_short": "风暴之山，2024年英国电影，冒险, 剧情, 惊悚。登山家杰克和弟弟山姆为了纪念亡父，决定攀登从未有人涉足的“风暴之山”北壁。这座山因富含磁铁矿，长期以来一直干扰电子设备。当他们攀爬至海拔三千米处时，一场强烈的太阳风暴袭击地球，导致山体磁场彻底混乱。指南针倒转，岩石因磁化互相吸引挤压，传统的登山路线完全消失。杰克在坠落后重伤，山姆必须独自在变形的岩壁中寻找出路。更糟糕的是，被磁化的岩屑像子弹一样在空中飞射。在绝境中，山姆回忆起父亲教过的", "score": 2024399, "category": "drama", "detail_url": "../movie/1310.html", "poster": "../posters/1310.svg"}, {"id": "1311", "title": "小森林 冬春篇", "year": 2020, "region": "日本", "type": "电影", "genre": "剧情, 美食, 治愈", "tags": ["田园", "料理", "孤独", "季节", "自给自足"], "summary_short": "小森林 冬春篇，2020年日本电影，剧情, 美食, 治愈。市子已经在小森独自生活了两年。冬雪覆盖大地，她靠着夏天储存的食材过活。这一季，她开始复制母亲当年突然离家前留下的最后一道菜：冻萝卜炖肉。无论她如何尝试，味道总是差那么一点。她翻出母亲的旧食谱，发现上面除了菜谱，还写满了对生活的抱怨和对她的爱。春天融雪时，市子收到一封来自城市的信，是母亲寄来的。母亲没有解释当年的离开，只是寄来了一袋新鲜的萝卜种子。市子含着泪把种子埋进土里，终于炖出", "score": 2020270, "category": "drama", "detail_url": "../movie/1311.html", "poster": "../posters/1311.svg"}, {"id": "1312", "title": "安吉里卡", "year": 2010, "region": "葡萄牙", "type": "电影", "genre": "剧情， 奇幻", "tags": ["葡萄牙电影， 摄影美学， 人鬼情， 黑白摄影"], "summary_short": "安吉里卡，2010年葡萄牙电影，剧情， 奇幻。葡萄牙导演曼努埃尔·德·奥利维拉作品。年迈摄影师艾萨克被富豪请去为刚去世的年轻女儿安吉里卡拍摄遗照。通过取景器，他看到安吉里卡异常美丽的面容，仿佛还活着。摄影结束后，艾萨克发现自己拍的每一张新照片中，安吉里卡的身影都会悄然出现在背景里——有时是河面上的倒影，有时是窗户反射。艾萨克毫不恐惧，反而疯狂爱上了这个幽灵。他开始拒绝与现实中的女性接触，沉浸在与安吉里卡的“摄影对话”中，直到现实与幻想的", "score": 2010378, "category": "drama", "detail_url": "../movie/1312.html", "poster": "../posters/1312.svg"}, {"id": "1313", "title": "花花女公子", "year": 1965, "region": "美国", "type": "电影", "genre": "喜剧, 爱情", "tags": ["女权萌芽", "反传统", "复古时尚", "爱情喜剧", "60年代"], "summary_short": "花花女公子，1965年美国电影，喜剧, 爱情。芝加哥，1965年。百货帝国继承人多萝西·戴维斯24岁，未婚，被上流社会称为“老处女”。她一怒之下，制定了一个计划：用一年时间，像男人一样约会、征服、抛弃，目标是12个不同类型的高质量男性，称为“年度收藏”。她穿迷你裙、吸烟、开车兜风、在爵士俱乐部通宵，逐一攻破棒球手、诗人、政客、摇滚歌手。前11个都顺利分手，第12个目标——一个刚从越南回来的穷记者，却完全不按她的剧本走。他识破了她的计划，", "score": 1965351, "category": "comedy", "detail_url": "../movie/1313.html", "poster": "../posters/1313.svg"}, {"id": "1314", "title": "步步笙欢", "year": 2018, "region": "中国香港", "type": "电视剧", "genre": "剧情 / 音乐 / 爱情", "tags": ["粤剧", "家族恩怨", "双生花", "传承"], "summary_short": "步步笙欢，2018年中国香港电视剧，剧情 / 音乐 / 爱情。上世纪40年代的广州，大戏班班主的一对双胞胎女儿因战乱失散。姐姐林曼笙被名伶收养，成为红极一时的花旦；妹妹林曼欢流落南洋，在酒馆卖唱求生。二十年后，曼欢带着仇恨回到广州，改名换姓加入对家戏班，誓要夺回属于自己的一切。两人在《紫钗记》的戏台上数次交锋，却不知对方正是血亲。直到一场大火烧毁戏院，曼笙为救曼欢身负重伤，两姐妹才在血泊中认出彼此。最终她们合演一出新编大戏，用歌声化解了", "score": 2018240, "category": "series", "detail_url": "../movie/1314.html", "poster": "../posters/1314.svg"}, {"id": "1315", "title": "同学会", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑, 剧情", "tags": ["密室", "复仇", "校园霸凌"], "summary_short": "同学会，2024年中国大陆电影，悬疑, 剧情。一场纪念中学毕业十周年的奢华同学会，在台风夜被困于一座孤岛别墅。组织者老班长被杀，接着每隔一小时，就有一道当年施暴的视频被公开。剩下的九个人发现，别墅的每个房间都对应着当年霸凌“眼镜”的九个场景。嫌疑人逐个死去，最后幸存者女主播揭开真相：其实“眼镜”当年自杀了，而这次的复仇者是眼镜的孪生妹妹，她整容成了当年霸凌者的模样。", "score": 2024401, "category": "drama", "detail_url": "../movie/1315.html", "poster": "../posters/1315.svg"}, {"id": "1316", "title": "看狗在说话", "year": 1993, "region": "美国", "type": "电影", "genre": "喜剧 / 冒险 / 家庭", "tags": ["动物说话", "宠物历险", "温情", "金毛犬", "配音大咖"], "summary_short": "看狗在说话，1993年美国电影，喜剧 / 冒险 / 家庭。钱斯（金毛犬）、塞西（喜马拉雅猫）和小狗影子跟随主人全家去度假。因为一场误会，它们被遗留在千里之外的陌生农场。三只天性不合的宠物必须依靠彼此才能回家。钱斯贪吃傻气，塞西高冷毒舌，影子胆小忠诚。它们穿越森林、翻过雪山、躲避野兽、智斗捕狗队。路上，它们遇到了会说人话的鸽子“鸽哥”指路。在一次激流中，影子为了救塞西被水冲走，钱斯和塞西第一次真正团结起来寻找伙伴。最终，在圣诞节夜，满身泥", "score": 1993335, "category": "comedy", "detail_url": "../movie/1316.html", "poster": "../posters/1316.svg"}, {"id": "1317", "title": "开错鬼门关", "year": 2024, "region": "中国台湾 / 日本", "type": "电影", "genre": "恐怖、惊悚、奇幻", "tags": ["民俗、禁忌、时间循环、祭祀"], "summary_short": "开错鬼门关，2024年中国台湾 / 日本电影，恐怖、惊悚、奇幻。不信鬼神的直播团队为了流量，在一座荒废的日军刑务所，严格按照《百鬼录》的记载举行“开鬼门”仪式。他们搞错了罗盘方向，无意中打开了通往“昭和时代”的裂缝。团队成员开始不断经历恐怖循环：有人被拖入壁画中的刑场，有人反复死亡又在原地复活。一位研究民俗的教授加入后，发现他们释放的不是鬼魂，而是“时间本身的怨恨”——那些在历史中被遗忘、被冤枉的屈辱能量。为了关闭错误之门，他们必须在下", "score": 2024521, "category": "horror", "detail_url": "../movie/1317.html", "poster": "../posters/1317.svg"}, {"id": "1318", "title": "扩张少女系三重奏", "year": 2025, "region": "日本", "type": "动画", "genre": "科幻 / 音乐 / 战斗", "tags": ["偶像", "机甲", "平行世界", "少女", "变形"], "summary_short": "扩张少女系三重奏，2025年日本动画，科幻 / 音乐 / 战斗。近未来，平行世界开始相互碰撞导致城市毁灭。唯一能阻止灾难的，是三名拥有特殊“声波扩张”体质的高中少女：音痴元气娘、冷漠毒舌女、以及懦弱班长。她们组成偶像团体“Triple Echo”，表面上是练习唱歌跳舞，实际上驾驶着能将歌声能量转化为破坏力的巨型机甲。由于三人永远唱不准调，她们创造的声波总是产生不可预测的战斗效果，闹出无数笑话。但随着敌人越来越强，她们必须学会真正的“和声", "score": 2025183, "category": "fantasy", "detail_url": "../movie/1318.html", "poster": "../posters/1318.svg"}, {"id": "1319", "title": "霓梦", "year": 2024, "region": "美国", "type": "电影", "genre": "科幻，惊悚", "tags": ["赛博朋克，虚拟现实，记忆植入，身份认同"], "summary_short": "霓梦，2024年美国电影，科幻，惊悚。在不远的未来，科技公司“霓虹梦”开发了一款名为“梦织机”的设备，可以植入人工梦境，让任何人体验到最渴望的生活。失业青年李奥接受了一份测试员的工作，第一次进入梦境，他成了富豪、英雄、情人。但很快，梦境开始变质，甜蜜的幻象中开始闪烁诡异的霓虹色光点。他发现其他测试员在现实中变成了行尸走肉，而梦境中的他们则在不断被一个看不清脸的黑影追杀。李奥发现，公司的真正目的并非贩卖幸福，而是采集用户在极端恐惧下产生的", "score": 2024442, "category": "crime", "detail_url": "../movie/1319.html", "poster": "../posters/1319.svg"}, {"id": "1320", "title": "圣殿奇妙夜", "year": 2025, "region": "英国", "type": "电影", "genre": "喜剧 / 奇幻", "tags": ["博物馆", "复活", "历史人物"], "summary_short": "圣殿奇妙夜，2025年英国电影，喜剧 / 奇幻。约克大教堂的守夜人亚瑟是个历史爱好者，也是个倒霉蛋。他在清理一个中世纪地窖时，无意间念出了一段古老的祷文，瞬间，教堂里的天使雕像、骑士石棺、甚至彩窗上的圣徒全都活了过来！这些“大佬”们一觉醒来发现自己被困在21世纪，于是开始了一场混乱的派对。罗马百夫长和维京海盗争夺厕所使用权，圣乔治嚷嚷着要去找真正的龙，而那位长翅膀的天使则沉迷于手机自拍。亚瑟必须在黎明前将他们全部“关机”，否则大教堂将面", "score": 2025341, "category": "comedy", "detail_url": "../movie/1320.html", "poster": "../posters/1320.svg"}, {"id": "1321", "title": "爱情春天", "year": 2025, "region": "韩国", "type": "电视剧", "genre": "爱情，治愈", "tags": ["园艺，失忆，疗伤，慢生活，暖剧"], "summary_short": "爱情春天，2025年韩国电视剧，爱情，治愈。著名钢琴家徐贤雅因车祸失忆，忘记了车祸前深爱的男友。经纪人将她送到济州岛一家名为“爱情春天”的园艺疗愈院。疗愈院的院长姜智旭是个沉默寡言的园艺师，他对贤雅若即若离。贤雅在种植花草的过程中，手指记忆让她弹出了陌生的旋律，而姜智旭总在一旁流泪。原来，姜智旭就是她失忆前的男友，而车祸是因为他求婚时发生了意外。贤雅在照料一株濒死的春兰时，终于想起了那个雨天和那句“嫁给我”。", "score": 2025251, "category": "series", "detail_url": "../movie/1321.html", "poster": "../posters/1321.svg"}, {"id": "1322", "title": "色欲花美男", "year": 2025, "region": "韩国", "type": "电视剧", "genre": "爱情 / 奇幻", "tags": ["花妖， 禁忌恋， 治愈， 高颜值"], "summary_short": "色欲花美男，2025年韩国电视剧，爱情 / 奇幻。周元是活了三百年的金雀花妖，他经营的花店“子时”每晚11点准时开张，清晨5点消失。每一位推门而入的客人，都会被周元看穿最隐秘的欲望——失去孩子的母亲想闻一下孩子最后一次呼吸的味道；被霸凌的高中生渴望让所有人“看见”他；患阿尔茨海默症的老画家想要一段永远不会褪色的红色记忆。周元用花瓣和花语调制成“花礼”，客人们支付的不是钱，而是这段欲望背后最痛苦的记忆片段。直到一天，一位能看见他本体的人类", "score": 2025290, "category": "series", "detail_url": "../movie/1322.html", "poster": "../posters/1322.svg"}, {"id": "1323", "title": "我所有微不足道的悲伤", "year": 2021, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["亲情， 绝症， 和解"], "summary_short": "我所有微不足道的悲伤，2021年中国台湾电影，剧情 / 家庭。宋怀玉是一名成功的策展人，她冷漠、理智，与母亲林秀兰断绝来往十年。当她接到医院电话得知母亲患上阿兹海默症时，本想直接支付看护费了事，却意外发现母亲收藏着一箱子自己从小到大的“破烂”——一张不及格的考卷、一只摔坏的万花筒、一件洗得发白的旧校服。出于愧疚，宋怀玉把母亲接回了家。随着母亲记忆的不断错乱，那些深埋在争吵下的误会逐一浮出水面：母亲的改嫁并非背叛，父亲的家暴另有隐情。当母", "score": 2021316, "category": "drama", "detail_url": "../movie/1323.html", "poster": "../posters/1323.svg"}, {"id": "1324", "title": "心动1986", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "爱情 / 怀旧", "tags": ["复古", "校园", "卡带", "初恋"], "summary_short": "心动1986，2025年中国台湾电影，爱情 / 怀旧。2025年，台北女孩小如在拆迁的老宅中发现了一盒卡带，上面写着“1986，给小如”。里面是一个叫阿青的男孩的自弹自唱和独白。原来，这是写给当年她母亲的情书。故事闪回1986年的淡水高中，穷小子阿青爱上了校花林美丽，他用录音带记录下每一次心跳。然而因家庭变故，阿青不告而别，卡带被遗落在墙角。如今，母亲林美丽已离婚多年，听到录音泣不成声。最终在女儿的帮助下，两人在旧码头重逢。", "score": 2025345, "category": "romance", "detail_url": "../movie/1324.html", "poster": "../posters/1324.svg"}, {"id": "1325", "title": "去她的第二春", "year": 2024, "region": "英国", "type": "剧集", "genre": "喜剧， 剧情", "tags": ["中年， 离婚， 探索"], "summary_short": "去她的第二春，2024年英国剧集，喜剧， 剧情。50 岁的中学女教师海伦，在丈夫突然出柜后，平静的生活崩塌。她保守、刻板、甚至有些无趣。闺蜜、朋克老太乔伊为了帮她“找春天”，制定了一系列疯狂计划：参加火人节、学习钢管舞、尝试开放式关系、经营素食餐车。海伦每次都笨拙而认真地执行，结果啼笑皆非：在火人节差点引发沙尘暴，钢管舞课上摔断了尾椎骨，开放式关系只招来了骗子。在一次次“翻车”中，海伦逐渐剥去规训的外壳，发现那个曾经想当摇滚歌手的自己还", "score": 2024221, "category": "series", "detail_url": "../movie/1325.html", "poster": "../posters/1325.svg"}, {"id": "1326", "title": "硝烟下的日常", "year": 2023, "region": "乌克兰", "type": "剧集", "genre": "战争 / 家庭 / 纪录片风格", "tags": ["顿巴斯", "平民视角", "日常与炮击", "母亲日记"], "summary_short": "硝烟下的日常，2023年乌克兰剧集，战争 / 家庭 / 纪录片风格。全剧共六集，每一集对应战争爆发后某一天的完整记录。没有前线大场面，没有英雄主义，镜头永远对准一栋灰泥剥落的公寓楼内部。母亲奥莱娜要计算孩子们出门找猫的几分几秒必须回来，才能避开每隔几小时落下的炮弹；丈夫每天清晨五点出去排队领面包，那条路线精确到哪个墙角可以挡弹片。她用手机备忘录记下每一顿饭的配方和来源：第三集是配给土豆加邻居送的一罐豆子，第四集是地窖里找到的两包过期泡面", "score": 2023190, "category": "series", "detail_url": "../movie/1326.html", "poster": "../posters/1326.svg"}, {"id": "1327", "title": "刑侦现场", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "悬疑 / 犯罪", "tags": ["本格推理", "法医", "单元剧", "硬汉派"], "summary_short": "刑侦现场，2024年中国大陆电视剧，悬疑 / 犯罪。江北市发生连环杀人案，所有证据都指向同一名已死的嫌疑人，案件陷入死局。刚从警校毕业的天才法医林远拥有“超忆症”，能记住看过的一切细节；而刑警队长陈汉升是个只信物证的老烟枪，认为所有口供都会撒谎。两人因办案理念不合而冲突不断，却不得不联手。随着调查深入，他们发现每一具尸体都是“凶手”留下的立体拼图。当最后一块拼图即将完成时，林远惊恐地发现，陈汉升两年前殉职的妻子的现场报告里，有一个被所有", "score": 2024380, "category": "crime", "detail_url": "../movie/1327.html", "poster": "../posters/1327.svg"}, {"id": "1328", "title": "恋爱留学生", "year": 2024, "region": "中国", "type": "剧集", "genre": "爱情, 喜剧", "tags": ["异国", "成长", "群像"], "summary_short": "恋爱留学生，2024年中国剧集，爱情, 喜剧。语言学校新生林筱雅入住东京一间老旧合租屋，室友分别是沉迷二次元的宅男马腾、想靠代购暴富的戏精苏糖、以及高冷但总能修好一切的经济学博士周牧。四人从互相嫌弃到抱团取暖，经历语言考试滑铁卢、奇葩打工遭遇、被日本房东误解、以及若即若离的跨国恋情。当林筱雅终于收到录取通知书，却发现大家因不同选择即将各奔东西。在樱花纷飞的毕业季，他们决定用一场混乱又真诚的告白，为这段狼狈而闪光的青春画上句号。", "score": 2024319, "category": "series", "detail_url": "../movie/1328.html", "poster": "../posters/1328.svg"}, {"id": "1329", "title": "谁之过", "year": 2023, "region": "韩国", "type": "剧集", "genre": "剧情, 悬疑, 法律", "tags": ["社会议题", "反转", "法庭", "悲剧", "人性"], "summary_short": "谁之过，2023年韩国剧集，剧情, 悬疑, 法律。震惊全国的“衣箱女孩”案开庭，9岁受害者的母亲当庭认罪。然而，主审法官李秀晶在翻阅证据时，发现女孩的邻居早就听到哭声、学校体检曾发现旧伤、儿童保护机构接到过匿名举报却未跟进。随着李秀晶的深入调查，她发现每个人都因“不想惹麻烦”而选择沉默。法庭内外，受害者母亲成了替罪羊，而真正的“凶手”是无数个视而不见的普通人。李秀晶面临巨大压力，她必须做出判决：是给这个已经被摧毁的系统一个交代，还是将整", "score": 2023327, "category": "series", "detail_url": "../movie/1329.html", "poster": "../posters/1329.svg"}, {"id": "1330", "title": "魔鬼女房东", "year": 2023, "region": "中国香港", "type": "电影", "genre": "悬疑惊悚", "tags": ["租房惊魂", "偷窥", "心理操控", "港味", "层层反转"], "summary_short": "魔鬼女房东，2023年中国香港电影，悬疑惊悚。港大研究生阿杰因交不起房租，通过中介租到了铜锣湾一间价格低得离谱的套房。女房东芬姐四十多岁，笑面迎人，每天变着花样送汤送饭，还帮他介绍兼职。阿杰起初感激不尽，却渐渐发现不对劲：芬姐总是能精准知道他的作息，他的私人物品疑似被翻动，房间插座里藏着针孔摄像头。他试图搬走，芬姐立刻变脸，拿出合同上他根本没注意过的霸王条款——提前解约需赔偿全年租金。阿杰开始调查，发现这间公寓过去三年换了五任租客，全部", "score": 2023364, "category": "crime", "detail_url": "../movie/1330.html", "poster": "../posters/1330.svg"}, {"id": "1331", "title": "世纪审判", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情 / 历史 / 犯罪", "tags": ["二战", "纳粹", "法庭戏", "正义延迟"], "summary_short": "世纪审判，2024年英国电影，剧情 / 历史 / 犯罪。2024年，柏林。法庭正在对一名100岁的老人进行审判，他被指控在二战期间作为集中营的记账员，协助杀害了超过一万人。被告病弱不堪，甚至需要轮椅和氧气瓶。辩护律师称他只是一个“流水线上的齿轮”，微不足道。而检方则请来了当年集中营的最后一位幸存者——一位102岁的老人。两个世纪老人在法庭上对峙，一个想证明自己是时代的尘埃，一个想证明邪恶不分大小。随着庭审深入，关于“平庸之恶”的哲学思辨", "score": 2024337, "category": "drama", "detail_url": "../movie/1331.html", "poster": "../posters/1331.svg"}, {"id": "1332", "title": "罗斯威尔第四季", "year": 2025, "region": "美国", "type": "电视剧", "genre": "科幻 / 悬疑 / 剧情", "tags": ["外星人", "阴谋论", "新墨西哥", "混血", "政府黑幕"], "summary_short": "罗斯威尔第四季，2025年美国电视剧，科幻 / 悬疑 / 剧情。距离1947年罗斯威尔事件已过去80年。第三季结尾，以莉兹为首的外星混血小组成功修复了飞船，飞向外星人真正的母星“锡安”。经过数月旅行，他们抵达锡安，却震惊地发现星球上飘扬着地球联合政府的旗帜。原来，早在地球军方在二十年前就通过破解外星科技发现了锡安的位置，并率先殖民了这颗星球，建立了“新伊甸园基地”。军方首领告诉他们：所谓“外星人回母星”，是政府几十年来放出的诱饵，目的就", "score": 2025396, "category": "series", "detail_url": "../movie/1332.html", "poster": "../posters/1332.svg"}, {"id": "1333", "title": "明日战记", "year": 2027, "region": "香港", "type": "电影", "genre": "科幻，动作，灾难", "tags": ["机甲，废土，外星生物，拯救，特效"], "summary_short": "明日战记，2027年香港电影，科幻，动作，灾难。未来世界，环境崩溃，一种来自陨石的外星“潘多拉”植物迅速蔓延，它吞噬氧气并释放剧毒。人类仅存的生命维持基地“方舟”即将被包围。机甲战士“猎鹰”小队奉命深入废墟中心，执行一项自杀式任务：投放微型黑洞炸弹摧毁母体。队长林峰带着新兵阿祖，操控着老旧的重型机甲在残垣断壁中穿行。他们不仅要躲避体型巨大的变异怪物，还要面对因恐惧而叛变的前战友。在氧气仅剩6小时的绝境中，林峰决定牺牲自己的机甲能源，将阿", "score": 2027372, "category": "sci-fi", "detail_url": "../movie/1333.html", "poster": "../posters/1333.svg"}, {"id": "1334", "title": "三招了", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作, 武侠", "tags": ["功夫", "武林", "师徒", "传承"], "summary_short": "三招了，2024年中国香港电影，动作, 武侠。咏春拳正宗传人陈浩，在繁华的香港闹市开了一家不起眼的武馆。他立下奇怪的规矩：来者不拒，但他只出三招。三招之内，你若能逼他变招或后退，便算他输。各路搏击冠军、散打高手、甚至街头混混前来挑战，无人能在三招内取胜，他的名号“三招了”不胫而走。一位武术片导演慕名而来，想让陈浩做替身演员。陈浩的徒弟阿杰心浮气躁，怂恿师父去打比赛赚钱。在名利诱惑和传承困境中，陈浩通过一次次的“三招了”，不仅试探对手的功", "score": 2024260, "category": "costume", "detail_url": "../movie/1334.html", "poster": "../posters/1334.svg"}, {"id": "1335", "title": "方块皇后", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["棋局杀人", "心理博弈", "高智商犯罪"], "summary_short": "方块皇后，2026年中国大陆电影，悬疑 / 犯罪。国际象棋世界冠军林墨退役后转行成为艺术品鉴定师。她受邀为一枚失踪半个世纪的明代玉雕“方块皇后”做真伪评估，却意外卷入一场连环杀人案。三名潜在买家均被发现在封闭房间内死亡，尸体旁各摆着一枚棋子，死因符合国际象棋特定走法的寓意。警方一筹莫展时，林墨发现凶手每一步都在复刻她职业生涯最著名的那场“不败对局”。她必须用棋手的逻辑，在下一枚“皇后”被吃掉前，揪出那个将她视为毕生对手的真凶。", "score": 2026423, "category": "crime", "detail_url": "../movie/1335.html", "poster": "../posters/1335.svg"}, {"id": "1336", "title": "哈瓦那组曲", "year": 2024, "region": "古巴 / 西班牙", "type": "电影", "genre": "剧情 / 音乐", "tags": ["古巴音乐，跨国恋，时光倒流"], "summary_short": "哈瓦那组曲，2024年古巴 / 西班牙电影，剧情 / 音乐。落魄钢琴家马蒂亚斯来到古巴寻找创作灵感，他在哈瓦那老城的街头听到一个擦鞋老妇人在哼唱一首歌。那旋律让他浑身战栗——那是他年轻时写给古巴初恋卡门的情歌，从未发表过。老妇人说这首歌是她妈妈教她的，而她妈妈五年前刚刚去世，名字就叫卡门。马蒂亚斯震惊地发现，卡门当年怀了他的孩子，而那个孩子就是眼前这位老妇人的母亲。在色彩斑斓的哈瓦那，马蒂亚斯要用最后的力气，为从未谋面的女儿和逝去的爱人", "score": 2024294, "category": "drama", "detail_url": "../movie/1336.html", "poster": "../posters/1336.svg"}, {"id": "1337", "title": "海豚之眼", "year": 2012, "region": "英国", "type": "电影", "genre": "剧情，家庭", "tags": ["海豚，自闭症，治愈，海洋"], "summary_short": "海豚之眼，2012年英国电影，剧情，家庭。小女孩露西因父母离异而患上自闭症，拒绝与任何人说话。母亲带她来到海滨城市治疗，在这里她遇到了一只因被渔网缠绕而受伤、同样恐惧人类的海豚“蓝宝”。露西发现只有在水下与蓝宝对视时，她才能感觉到宁静。在海洋生物学家的帮助下，露西试图帮助蓝宝恢复健康，而蓝宝也在慢慢治愈露西的心。最终，为了救回被偷猎者抓走的蓝宝，露西发出了人生第一次呐喊。", "score": 2012254, "category": "drama", "detail_url": "../movie/1337.html", "poster": "../posters/1337.svg"}, {"id": "1338", "title": "夏日秘密 第二季", "year": 2025, "region": "中国台湾", "type": "剧集", "genre": "剧情 / 同性 / 青春", "tags": ["青春群像，小镇疑云，夏日限定"], "summary_short": "夏日秘密 第二季，2025年中国台湾剧集，剧情 / 同性 / 青春。延续第一季结尾的命案悬念，第二季将时间线拉回到案发前一个月。海边小镇的废弃船厂里，阿杜、阿杰与转学生小海组成的摄影社，无意间拍到了不该出现的东西。与此同时，阿杰对好友阿杜的感情逐渐越界，而小海身上似乎背负着来自北方的秘密。当第二具尸体浮出水面，每个人都在用自己的方式掩盖真相，却不知他们拼命守护的“夏日秘密”，正在将彼此推向深渊。", "score": 2025258, "category": "series", "detail_url": "../movie/1338.html", "poster": "../posters/1338.svg"}, {"id": "1339", "title": "飞吧，冰上之光", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "运动 / 剧情 / 励志", "tags": ["短道速滑", "东北少年", "逆袭", "师徒", "冬季运动"], "summary_short": "飞吧，冰上之光，2024年中国大陆电影，运动 / 剧情 / 励志。黑龙江七台河，18岁的程野是当地野冰场“扛把子”，技巧野、速度快，但动作全是错的。前国家队金牌教练韩冰因兴奋剂冤案被贬到小镇体校，一眼看出程野是块璞玉。在简陋的条件下，韩冰用一瓶白酒换来了程野的加盟。两人互相折磨：程野要改掉十几年野路子形成的肌肉记忆，韩冰要克服酗酒和心理创伤。两年后，程野拿到全国冠军，但韩冰突然被召回国家队，而要求是“不许带程野”。片尾，程野独自滑向结冰", "score": 2024252, "category": "drama", "detail_url": "../movie/1339.html", "poster": "../posters/1339.svg"}, {"id": "1340", "title": "皇牌特务龙虎斗", "year": 1989, "region": "中国香港", "type": "电影", "genre": "动作 / 喜剧", "tags": ["双雄，CIA，黑吃黑，港式幽默"], "summary_short": "皇牌特务龙虎斗，1989年中国香港电影，动作 / 喜剧。金牌搞笑动作组合再度联手。CIA特工麦克来港追查失窃的生化芯片，而重案组警长李国华则负责一桩黑帮军火案。两人因巧合屡次撞车，大打出手后却被上司勒令合作。他们互相看不顺眼，每次行动都能把现场炸成废墟，却又意外破获关键线索。追查到最后，李国华发现出卖情报的内鬼竟是自己的亲弟弟，而麦克也被告知，CIA内部的叛徒代号“青龙”，所有证据都指向李国华。两人在维多利亚港的货船上拔枪相向，背后却是", "score": 1989325, "category": "crime", "detail_url": "../movie/1340.html", "poster": "../posters/1340.svg"}, {"id": "1341", "title": "业余选手", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧, 运动", "tags": ["电竞", "老年", "逆袭", "搞笑"], "summary_short": "业余选手，2023年中国大陆电影，喜剧, 运动。退休钳工老李被儿子嫌弃“只会下象棋”，一怒之下拉上老年活动中心的大爷们组成了电竞战队“夕阳红”。五位大爷平均年龄68岁，手机都用不利索。他们从被孙子嘲笑起步，白天在公园练手速，晚上在麻将桌上学战术。误打误撞进了全国业余联赛八强，半决赛对手正是老李儿子所在的职业青训队。比赛当天，老李的儿子嘲讽：“爸，别丢人了。”老李戴上耳机：“让你见识下，什么叫你大爷还是你大爷。”", "score": 2023314, "category": "comedy", "detail_url": "../movie/1341.html", "poster": "../posters/1341.svg"}, {"id": "1342", "title": "活佛济公3", "year": 2026, "region": "中国", "type": "剧集", "genre": "喜剧 / 神话 / 古装", "tags": ["济公，降妖，单元剧，诙谐，哲理"], "summary_short": "活佛济公3，2026年中国剧集，喜剧 / 神话 / 古装。第三季延续单元剧模式：胭脂坊新娘接连失踪，疑似画皮妖作案；县衙库银变石头，牵出蛤蟆精；最离奇的是，全镇人一夜之间失去“笑”的能力。济公表面疯癫，实则用三个案子串联出真相：百年前冤死的将军魂魄附身在铁匠身上，通过吸食人间七情六欲复活爱人。济公没有打死冤魂，而是超度了将军和其爱人。结局济公坐在桥头啃鸡腿，对徒弟说：“恨容易，放下难，能放下的才是活佛。”", "score": 2026236, "category": "series", "detail_url": "../movie/1342.html", "poster": "../posters/1342.svg"}, {"id": "1343", "title": "密室大逃脱第七季", "year": 2026, "region": "中国", "type": "综艺", "genre": "真人秀 / 悬疑 / 冒险", "tags": ["密室", "明星", "烧脑", "实景", "团队合作"], "summary_short": "密室大逃脱第七季，2026年中国综艺，真人秀 / 悬疑 / 冒险。第七季全面升级，六位常驻嘉宾被蒙眼带到一座已退役的秦山核电站旧厂区。节目组号称这是“中国最大实景密室”，总面积8万平方米。第一个房间就出现故障：本该是道具的辐射警报器真的响了。玩家们在逃生过程中发现的线索越来越不对劲——员工胸卡上的名字大多是已故人员，操作手册上用血写着的“别出去”。当解开第三层主控室密码锁后，他们调出一段内部监控：20年前这里发生过一次小型泄漏，当时的厂", "score": 2026211, "category": "series", "detail_url": "../movie/1343.html", "poster": "../posters/1343.svg"}, {"id": "1344", "title": "夏日狂恋", "year": 2023, "region": "日本", "type": "电影", "genre": "爱情, 青春, 音乐", "tags": ["纯爱", "冲绳", "乐队", "夏日限定", "治愈"], "summary_short": "夏日狂恋，2023年日本电影，爱情, 青春, 音乐。由于意外逐渐失聪的少女小薰，在彻底失去听力前来到冲绳，想最后听一次大海的声音。她遇到了因创作瓶颈而打算解散乐队、卖掉吉他的少年阿诚。阿诚被小薰对声音的执念所触动，答应在暑假期间为她写一首“能看见大海的歌”。他们一起在沙滩漫步、在深夜的录音室里用手语交流。阿诚发现，小薰虽然听不见，但她能通过触摸音箱来感受震动的旋律。随着夏日祭的临近，小薰的听力彻底消失，而阿诚写出的曲子却因为缺乏灵感而陷", "score": 2023295, "category": "romance", "detail_url": "../movie/1344.html", "poster": "../posters/1344.svg"}, {"id": "1345", "title": "小财迷", "year": 2022, "region": "中国大陆", "type": "网络剧", "genre": "喜剧 / 爱情 / 古装", "tags": ["古装甜宠", "财迷", "精打细算", "欢喜冤家", "管家"], "summary_short": "小财迷，2022年中国大陆网络剧，喜剧 / 爱情 / 古装。京城商户之女季小财，人如其名，视财如命，买根葱都要砍价砍到老板流泪。她的人生信条是“只进不出”，最大的梦想是嫁给钱庄。然而父亲为了攀附权贵，将她许配给了京城第一纨绔子弟——安国公府的世子顾飞宇。顾飞宇此人花钱如流水，今天买只画眉鸟花一千两，明天给青楼写诗花三千两。两人婚后第一天，就因为财政大权吵得不可开交。季小财为了防止世子败家，想出了各种奇招：限制零花钱、记账查岗、甚至把世子", "score": 2022179, "category": "series", "detail_url": "../movie/1345.html", "poster": "../posters/1345.svg"}, {"id": "1346", "title": "驴拳", "year": 2010, "region": "美国", "type": "电影", "genre": "惊悚，犯罪", "tags": ["暴力，短片改编，毒品，血腥，恶童"], "summary_short": "驴拳，2010年美国电影，惊悚，犯罪。美国中西部小镇，四个百无聊赖的高中男生沉迷于地下血腥视频网站，其中一段名为“驴拳”的虐待视频让他们兴奋不已。为了模仿并超越，他们决定绑架一个“活该被虐”的人——当地臭名昭著但没犯过大案的毒贩朗尼。深夜，他们将朗尼骗到废弃谷仓，手脚捆绑后开始逼供“藏毒地点”。最初的恶作剧在朗尼的咒骂和反抗中迅速升级，他们用扳手敲碎他的膝盖，用乙炔喷枪灼烧皮肤，整个过程用手机录了下来。但当朗尼终于说出钱的下落时，他已经", "score": 2010393, "category": "crime", "detail_url": "../movie/1346.html", "poster": "../posters/1346.svg"}, {"id": "1347", "title": "珍爱生命远离毒品", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "犯罪, 剧情, 教育", "tags": ["禁毒", "卧底", "家庭破碎"], "summary_short": "珍爱生命远离毒品，2023年中国大陆电影，犯罪, 剧情, 教育。缉毒队长李建国奋战一线二十年，儿子李晓却因缺失父教染上毒瘾。李晓被强制戒毒那天，李建国亲自戴上手铐。三个月后，李建国卧底贩毒集团，意外发现集团头目竟是李晓的戒毒所室友。头目逼李晓当众注射以表忠心。李建国在监控室看着儿子颤抖的手，抢过针管替儿子注射了自己准备的清水。毒贩识破，混战中李晓扑向手雷，救了父亲。李晓终身残疾，李建国跪在病床前。李晓说：“爸，这次是你抓我。下次，换我跟", "score": 2023381, "category": "drama", "detail_url": "../movie/1347.html", "poster": "../posters/1347.svg"}, {"id": "1348", "title": "超能力同学", "year": 2023, "region": "中国大陆", "type": "网剧", "genre": "青春, 奇幻, 喜剧", "tags": ["校园", "超能力", "反转", "热血"], "summary_short": "超能力同学，2023年中国大陆网剧，青春, 奇幻, 喜剧。高中生林星转学到一所重点中学，意外发现同桌能控制金属，前排女生能让时间暂停两秒，后座男生则总是在悲伤时让天空下起局部糖果雨。原来这是教育部秘密的“超能力少年培养试点班”。平静被一次意外打破：能力最强的班长预感到三天后学校将发生巨大爆炸。为了守护校园，这群连稳定发动能力都费劲的少年，必须像真正的超级英雄一样，展开一场啼笑皆非又热血沸腾的特别行动。", "score": 2023194, "category": "series", "detail_url": "../movie/1348.html", "poster": "../posters/1348.svg"}, {"id": "1349", "title": "荣誉之季", "year": 2023, "region": "美国", "type": "剧集", "genre": "运动, 剧情", "tags": ["高中篮球", "励志", "群像", "热血"], "summary_short": "荣誉之季，2023年美国剧集，运动, 剧情。密歇根州某小镇高中，女子篮球队已经连续五年全败，学校决定今年赛季结束后解散球队。主教练辞职，无人愿意接盘，最后全校最年轻的数学老师、大学曾打NCAA但因伤退役的凯特被迫上任。队里只有七名队员，各有各的烦恼：队长艾莉丝家庭贫困，每天要打两份工；中锋莎拉有饮食障碍；控卫梅根是刺头，和所有人作对。凯特从最基础的运球教起，第一场训练课就有人哭着离场。但她们慢慢开始赢下第一场、第二场……随着连胜持续，全", "score": 2023207, "category": "series", "detail_url": "../movie/1349.html", "poster": "../posters/1349.svg"}, {"id": "1350", "title": "盲眼杀机", "year": 2026, "region": "中国香港 / 美国", "type": "电影", "genre": "动作 / 科幻", "tags": ["盲人特工", "声呐格斗", "义眼", "高科技", "暴力美学"], "summary_short": "盲眼杀机，2026年中国香港 / 美国电影，动作 / 科幻。顶尖特工凯在西非任务中被炸瞎双眼，退役后植入军方最新“声呐视觉芯片”，能通过声波在脑内重建3D环境。三年后芯片突然自行启动暗杀模式，将他周围所有平民标记为“威胁”。凯被迫亲手杀死了一个“被标记”的送餐员，才发现芯片被黑客入侵，把他变成了活体武器。更恐怖的是，芯片开始播放他过去任务中被抹除的记忆——原来他失明那场爆炸，是自己人干的。凯扯下芯片，在彻底黑暗中，仅凭记忆里的声波地图杀", "score": 2026392, "category": "crime", "detail_url": "../movie/1350.html", "poster": "../posters/1350.svg"}, {"id": "1351", "title": "以父亲的名义", "year": 2028, "region": "英国 / 爱尔兰", "type": "电影", "genre": "剧情 / 犯罪 / 传记", "tags": ["冤案", "父与子", "法庭"], "summary_short": "以父亲的名义，2028年英国 / 爱尔兰电影，剧情 / 犯罪 / 传记。1993年，伦敦一场爆炸案夺走数条人命，爱尔兰移民老帕特里克被当作主犯速判死刑。二十年后，儿子肖恩接手案件试图翻案。在查阅尘封档案和走访当年证人时，肖恩震惊地发现，父亲曾卷入爱尔兰共和军的边缘活动，而真正引爆货车的另有其人——那人竟是肖恩少年时的挚友。为了正义，他必须在法庭上出卖好友；为了父亲，他又必须让真相大白。庭审高潮，老帕特里克在狱中写下一封信：“我用我的命，", "score": 2028305, "category": "drama", "detail_url": "../movie/1351.html", "poster": "../posters/1351.svg"}, {"id": "1352", "title": "天堂谁属3", "year": 2024, "region": "美国", "type": "剧集", "genre": "悬疑科幻", "tags": ["死后世界", "记忆审判", "信仰冲突", "反转结局"], "summary_short": "天堂谁属3，2024年美国剧集，悬疑科幻。前两季中，不同信仰的人在死后进入了同一个名为“中转站”的空间。第三季开篇，主角们发现天堂并非终点，而是一个不断重播生前记忆的测试场。新角色——一位无神论科学家带着生前的实验设备进入，她计算出天堂其实是一台由外星文明建造的“道德筛选器”。管理员们声称只有无私者能进天堂，但科学家发现管理员们自己从未被传送走。最终真相是：这台机器早已损坏，它错误地将所有人类判定为“不合格”，而管理员们只是第一批被困在", "score": 2024399, "category": "series", "detail_url": "../movie/1352.html", "poster": "../posters/1352.svg"}, {"id": "1353", "title": "笑画人生", "year": 2023, "region": "日本", "type": "动画电影", "genre": "剧情，奇幻，动画", "tags": ["治愈，人生，时间，温情，手绘"], "summary_short": "笑画人生，2023年日本动画电影，剧情，奇幻，动画。中年漫画编辑长谷川早已对漫画和人生失去热情，工作只是为了糊口。一天，他在整理已故著名漫画家的遗物时，发现了一本名为《笑画人生》的空白画册。他无意中画了一杯咖啡，桌上立刻出现了一杯热气腾腾的咖啡，但他随即发现自己的手腕上多了一道“时间刻痕”。他明白了：画册能实现画出的东西，但会消耗他的生命。起初，他满足自己的私欲，眼见生命流逝，他感到恐惧。后来，他开始为路边的流浪猫画食物，为生病的小女孩", "score": 2023362, "category": "fantasy", "detail_url": "../movie/1353.html", "poster": "../posters/1353.svg"}, {"id": "1354", "title": "下一站你的世界", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "爱情, 奇幻, 悬疑", "tags": ["地铁", "平行宇宙", "都市", "循环"], "summary_short": "下一站你的世界，2025年中国大陆剧集，爱情, 奇幻, 悬疑。设计师林小溪和程序员顾淮是死对头，两人负责同一个项目的AB方案，水火不容。他们每天都乘坐早上8:15的同一班地铁，但永远站在相反的车门位置。一天，地铁在隧道里突然停电，一片漆黑中有人恐慌推搡，林小溪和顾淮的手意外握在了一起。当灯光亮起，他们发现世界变了：林小溪进入了一个顾淮是顶流画家的平行世界，而顾淮则进入了一个林小溪是科技巨头的世界。他们发现，只要在地铁上牵手，就能“换乘”", "score": 2025404, "category": "series", "detail_url": "../movie/1354.html", "poster": "../posters/1354.svg"}, {"id": "1355", "title": "东京卍复仇者", "year": 2024, "region": "日本", "type": "电影", "genre": "动作 / 科幻 / 犯罪", "tags": ["穿越", "不良少年", "帮派", "热血"], "summary_short": "东京卍复仇者，2024年日本电影，动作 / 科幻 / 犯罪。26岁的废柴武道过着最底层的生活，某天他得知前女友日向及其弟弟直人卷入东京卍会的内部斗争被杀害。就在他生无可恋时，被人推下地铁轨道，却意外穿越回了12年前的高中时代。他找到了日向的弟弟直人，两人握手的一瞬间，时间再次跳跃。武道发现自己可以通过与直人握手，在现在与过去之间来回穿梭。为了改变未来，他必须潜入东京卍会，阻止导致悲剧发生的“关键事件”。武道虽然胆小懦弱，但为了保护日向，", "score": 2024441, "category": "crime", "detail_url": "../movie/1355.html", "poster": "../posters/1355.svg"}, {"id": "1356", "title": "踏破硝烟", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "战争 / 动作", "tags": ["铁道游击队", "爆破", "抗日", "兄弟情"], "summary_short": "踏破硝烟，2025年中国大陆电影，战争 / 动作。1944年，山东。日军秘密研制化学武器，通过一列代号“幽灵”的装甲列车向前线运送毒气弹。铁道游击队队长老洪接到情报：列车将在三十六小时后经过微山湖段。更棘手的是，日军在沿途布置了三道爆破警戒网，且列车上有五百名中国劳工被当作人体盾牌。老洪带着六名队员，兵分三路：一路假扮伪军混入车站获取列车时刻表，一路潜入水底铺设新式磁吸炸药，一路攀爬悬崖准备断桥。行动中不断有队员牺牲，但没有人退缩。最后", "score": 2025337, "category": "crime", "detail_url": "../movie/1356.html", "poster": "../posters/1356.svg"}, {"id": "1357", "title": "只好背叛地球了", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧, 科幻, 爱情", "tags": ["外星人", "社畜", "卧底", "沙雕"], "summary_short": "只好背叛地球了，2024年中国大陆剧集，喜剧, 科幻, 爱情。来自高维文明“射手座联盟”的基层执行员编号404，接到了有史以来最简单的任务：潜入地球上一家普通的广告公司，通过修改文案让人类陷入消费主义陷阱，从而自取灭亡。然而404发现，地球人类的“内卷”程度远超宇宙任何文明。老板画的大饼、996加班文化、KPI考核让身为外星人的404都感到恐惧和...兴奋？在这里他第一次体会到了“奋斗”的快乐。当母星下达最后通牒启动“人类清除计划”时，", "score": 2024412, "category": "series", "detail_url": "../movie/1357.html", "poster": "../posters/1357.svg"}, {"id": "1358", "title": "别扭合租房", "year": 2025, "region": "日本", "type": "剧集", "genre": "爱情 / 喜剧 / 剧情", "tags": ["同居，社恐，治愈，先同居后恋爱，怪咖房客"], "summary_short": "别扭合租房，2025年日本剧集，爱情 / 喜剧 / 剧情。社恐插画师小春因为前房东的投诉，被迫搬进了一间价格便宜得离谱的合租房。室友包括：只穿内裤晃来晃去的前拳击手、沉迷于虚拟歌姬的IT工程师、以及总在深夜练习腹语术的神秘女子。小春本以为地狱般的生活开始了，但她渐渐发现，这些“怪人”其实都用各自笨拙的方式守护着彼此的界限。新搬来的帅气上班族阿凉打破了微妙的平衡，他对小春关怀备至，却似乎隐藏着什么秘密。在这间别扭又温暖的合租房里，小春学会", "score": 2025316, "category": "series", "detail_url": "../movie/1358.html", "poster": "../posters/1358.svg"}, {"id": "1359", "title": "喜气逼人", "year": 2025, "region": "中国香港", "type": "电影", "genre": "喜剧", "tags": ["贺岁", "家庭", "乌龙", "彩票", "团圆"], "summary_short": "喜气逼人，2025年中国香港电影，喜剧。除夕夜，抠门的老丈人老马为了省钱，网购了一台劣质“全家福摄影神器”，结果机器当场爆炸，炸出了一张被遗忘在旧外套里的彩票。女儿马小燕发现这张彩票竟然中了头奖，但外套却被当成垃圾卖给了收破烂的王叔。全家人立刻开启疯狂追踪模式，兵分三路围堵王叔。与此同时，王叔正穿着那件外套去相亲，途中不断遭遇各种乌龙意外。在闹出一系列砸车、跳楼假象、宠物猪大闹商场等笑料后，大家终于在零点钟声前聚齐。老马幡然醒悟，决定将", "score": 2025310, "category": "comedy", "detail_url": "../movie/1359.html", "poster": "../posters/1359.svg"}, {"id": "1360", "title": "吓死油土伯", "year": 2021, "region": "美国", "type": "电影", "genre": "恐怖 / 喜剧", "tags": ["网红", "直播", "鬼屋", "伪纪录片", "反转"], "summary_short": "吓死油土伯，2021年美国电影，恐怖 / 喜剧。为了博取流量，网红“冒险家联盟”选择了全美最凶的废弃疯人院进行午夜直播。队长阿鬼架起八台摄影机，准备拍摄“鬼影实录”。起初他们只拍到一些模糊影子，直播间人数暴涨。但当他们进入地下停尸房时，墙上突然出现了另一个直播画面——画面里是他们五人自己，但角度是从停尸台下方往上拍。更恐怖的是，直播间的弹幕开始被“1947号病人”刷屏。他们试图逃出时，发现所有出口都被封死，而自己的手机屏幕上显示：“本场", "score": 2021338, "category": "horror", "detail_url": "../movie/1360.html", "poster": "../posters/1360.svg"}, {"id": "1361", "title": "无名三侠客", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "武侠 / 喜剧 / 动作", "tags": ["民国", "江湖", "骗子", "抗日", "师徒"], "summary_short": "无名三侠客，2025年中国大陆电影，武侠 / 喜剧 / 动作。民国初年，天津。三个跑江湖卖艺的骗子：老江湖“神手张”、贪吃胖子“铁肚王”、哑巴少年“小飞”，靠“隔空取物”“胸口碎大石”等戏法混日子。某天，一个日本商团来到天津，实际上是忍者军团，秘密寻找一份中国武术秘籍。三个骗子被当地乡绅误认为“隐居的三大高手”，重金请他们赶走日本人。神手张本想拿钱跑路，但发现日本人在屠杀百姓，良心过不去。三人开始用戏法对付忍者：用“大变活人”藏匿百姓，", "score": 2025326, "category": "costume", "detail_url": "../movie/1361.html", "poster": "../posters/1361.svg"}, {"id": "1362", "title": "和歌手在一起", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "剧情，音乐", "tags": ["经纪人，娱乐圈，成长，励志"], "summary_short": "和歌手在一起，2022年中国大陆电影，剧情，音乐。老金曾是业内顶级的经纪人，因一次丑闻跌落谷底，只能给公司里最不听话的新人当“保姆”。新人小冰是地下说唱圈的天才，桀骜不驯，抵触一切商业包装。公司下了死命令：如果接下来的六城巡演票房惨淡或出现演出事故，两人一起被扫地出门。这对“难父难子”的组合被迫上路。小面包车里，老金讲着过去辉煌的唱片业故事，小冰则用手机放着自己做的硬核Demo。一路上，他们遭遇了设备被扣、直播翻车、对手挖角等危机。在倒", "score": 2022313, "category": "drama", "detail_url": "../movie/1362.html", "poster": "../posters/1362.svg"}, {"id": "1363", "title": "校花的贴身高手4", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "爱情, 动作, 奇幻", "tags": ["校园", "修真", "保镖", "爽文", "恋爱"], "summary_short": "校花的贴身高手4，2023年中国大陆剧集，爱情, 动作, 奇幻。已臻化境的修真高手林逸在完成第四十九次跨位面任务后，被师门派遣最后一个“简单任务”：伪装成17岁高中生，保护首富之女、全球校花排行榜第一的楚梦瑶。然而这位校花不仅武力值爆表（空手道黑带），且对任何接近她的男性都有天生的“厌恶灵气”——林逸引以为傲的修为在她身边十米内全部失灵。于是，史上最憋屈的保镖诞生了：修真大佬被迫背高考单词、参加运动会、被校花过肩摔、还要同时应付来自黑暗", "score": 2023393, "category": "series", "detail_url": "../movie/1363.html", "poster": "../posters/1363.svg"}, {"id": "1364", "title": "真命天子粤语", "year": 2018, "region": "中国香港", "type": "剧集", "genre": "喜剧 / 爱情 / 奇幻", "tags": ["玄学， 月老， 都市传说， 粤语俚语， 轻松搞笑"], "summary_short": "真命天子粤语，2018年中国香港剧集，喜剧 / 爱情 / 奇幻。庙街电器铺少东阿豪是个爱情绝缘体。某日他捡到一只瘸腿橘猫，当晚开始做梦：一个自称实习月老的小神仙哭着说自己错把阿豪的姻缘红线系到了猫尾巴上。解除诅咒的唯一方法是——阿豪必须让这只猫主动用尾巴碰触他的“真命天女”。更离谱的是，猫只愿接近一种人：身上有叉烧味的人。阿豪开始疯狂追逐所有路过烧腊店的女性，被当成变态。他的死党阿杰建议去烧腊店打工守株待兔。在那里他遇到性格火爆的女师傅", "score": 2018400, "category": "series", "detail_url": "../movie/1364.html", "poster": "../posters/1364.svg"}, {"id": "1365", "title": "破里拳", "year": 2025, "region": "香港 / 中国大陆", "type": "电影", "genre": "动作 / 犯罪 / 体育", "tags": ["MMA", "地下拳场", "废柴逆袭", "硬核格斗"], "summary_short": "破里拳，2025年香港 / 中国大陆电影，动作 / 犯罪 / 体育。曾拿过全运会金牌的散打运动员赵破军因伤病退役，沦落为夜总会保安。为了给重病的妹妹凑医药费，他戴上小丑面具，化名“破里拳”参加九龙城寨地下的血腥黑拳。那里没有规则，只有生死。赵破军用教科书般的摔法和地面技一路连胜，引起了国际博彩财团的注意。财团试图用重金收买他打假赛，被他拒绝后，妹妹被绑架。决赛夜，赵破军面对的是体重超他两倍的泰森式巨兽。他利用铁笼地形和对手膝盖旧伤，上演", "score": 2025354, "category": "crime", "detail_url": "../movie/1365.html", "poster": "../posters/1365.svg"}, {"id": "1366", "title": "恋爱中的梵高", "year": 2016, "region": "法国 / 荷兰", "type": "电影", "genre": "爱情 / 传记", "tags": ["艺术家的爱，精神疾病，法国南部的光，书信"], "summary_short": "恋爱中的梵高，2016年法国 / 荷兰电影，爱情 / 传记。影片聚焦梵高在阿尔勒的两年。他疯狂地爱上房东女儿玛格丽特，为她画下《阿尔勒的少女》。但玛格丽特的父亲厌恶这个疯子，禁止两人见面。梵高在情伤中割下耳朵，被送进精神病院。然而影片通过平行叙事揭示另一条线：梵高写给弟弟提奥的信件中，经常提到一个叫“R”的男性友人，信里用暗语描述的情感远比对玛格丽特更炽烈。历史学者后来发现，“R”就是房东的儿子、玛格丽特的哥哥雷内。梵高爱上的从来不是玛", "score": 2016275, "category": "romance", "detail_url": "../movie/1366.html", "poster": "../posters/1366.svg"}, {"id": "1367", "title": "杀手怨曲", "year": 2002, "region": "法国 / 意大利", "type": "电影", "genre": "剧情 / 犯罪 / 音乐", "tags": ["巴黎", "杀手宿命", "爵士小号", "存在主义"], "summary_short": "杀手怨曲，2002年法国 / 意大利电影，剧情 / 犯罪 / 音乐。让是一位过着机械生活的职业杀手，住在巴黎蒙马特高地一间逼仄公寓里，唯一的慰藉是对面窗户里练习爵士小号的邻居女孩。在他决定干完最后一单便隐退时，却意外发现暗杀目标竟然就是那个女孩的父亲——一位试图揭露黑警系统的记者。那一刻，让停止了扣动扳机。因为这一次心软，他立刻成为整个地下世界和腐败警察的围剿对象。在带着女孩逃亡的途中，让重新拿起了年轻时的小号，在城市的地下水道和废弃歌", "score": 2002377, "category": "drama", "detail_url": "../movie/1367.html", "poster": "../posters/1367.svg"}, {"id": "1368", "title": "杀手假日", "year": 2024, "region": "美国 / 英国", "type": "电影", "genre": "喜剧 / 动作 / 冒险", "tags": ["杀手度假 / 乌龙事件 / 爆米花爽片"], "summary_short": "杀手假日，2024年美国 / 英国电影，喜剧 / 动作 / 冒险。顶级职业杀手杰克受够了没日没夜的生活，破天荒向老板请了年假，订了一个偏僻海岛的度假酒店。他以为终于能躺在沙滩上喝莫吉托，结果发现酒店里所有的游客——前台、调酒师、瑜伽教练、甚至隔壁房间度蜜月的那对夫妻——都是来自不同组织的杀手，而且每个人的任务目标都是他。原来他的老板把“杀掉杰克”当成了这个季度的KPI考核。杰克没办法，只能一边躲避追杀一边想办法“取消订单”。最后他和那个", "score": 2024379, "category": "crime", "detail_url": "../movie/1368.html", "poster": "../posters/1368.svg"}, {"id": "1369", "title": "少女十五十六时", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "青春 / 成长 / 家庭", "tags": ["校园霸凌", "母女和解", "月经羞耻", "台式清新"], "summary_short": "少女十五十六时，2025年中国台湾电影，青春 / 成长 / 家庭。1999年夏天，台湾小镇，初三女生阿琳在补习班突然来了初潮，弄脏了浅色校服裙。她躲在厕所不敢出来，打电话给妈妈，妈妈说：“用卫生纸垫一下，回家再说，别跟同学讲，丢脸。”阿琳觉得自己做错了事。她发现班里的男生会偷偷打分女生的卫生巾包装，女生们则互相借护垫像在接头。阿琳开始偷偷研究女性的身体，她撕下生理课本被涂黑的那几页，去录像店租女性导演的电影，甚至跟踪邻居那个总是半夜出门", "score": 2025212, "category": "comedy", "detail_url": "../movie/1369.html", "poster": "../posters/1369.svg"}, {"id": "1370", "title": "骑单车的人", "year": 2026, "region": "法国, 意大利", "type": "电影", "genre": "剧情, 公路, 文艺", "tags": ["单车", "送报", "老年", "回忆", "阿尔卑斯山"], "summary_short": "骑单车的人，2026年法国, 意大利电影，剧情, 公路, 文艺。阿尔贝托每天骑着一辆老旧的单车，穿行在阿尔卑斯山的村庄之间，为山民们送去报纸和信件。村民们只知道他是个沉默寡言的老头，从不多谈自己的过去。事实上，他曾是环法自行车赛的传奇爬坡王，却在巅峰时期的30年前突然消失，没人知道他去了哪里。某天，一封来自瑞士的信被误送到他手中，寄信人是一个自称是他孙女的女孩。阿尔贝托犹豫再三后打开了信，发现女孩得了罕见疾病，唯一能配型的骨髓捐献者，正", "score": 2026269, "category": "drama", "detail_url": "../movie/1370.html", "poster": "../posters/1370.svg"}, {"id": "1371", "title": "雪中脱轨", "year": 2025, "region": "中国大陆", "type": "TV剧集", "genre": "悬疑 / 灾难 / 剧情", "tags": ["列车事故", "时空循环", "人性考验"], "summary_short": "雪中脱轨，2025年中国大陆TV剧集，悬疑 / 灾难 / 剧情。特快列车“北极星号”在穿越雪山隧道时突发脱轨事故，仅有7名乘客在列车长林峰的带领下躲进一节未受损的车厢。当他们设法爬出废墟时，眼前却是漫天大雪和死寂的森林。更诡异的是，无论他们往哪个方向走，最终都会回到车厢残骸处。时间开始重置，每次循环，都有一名乘客以不同的方式死去。林峰发现，每个人在事故前都隐瞒了一个足以让列车脱轨的秘密：有人携带病毒，有人想炸车骗保。只有找出真正的肇事者", "score": 2025281, "category": "series", "detail_url": "../movie/1371.html", "poster": "../posters/1371.svg"}, {"id": "1372", "title": "男人的香气", "year": 1994, "region": "香港", "type": "电影", "genre": "爱情， 剧情， 文艺", "tags": ["香港电影， 嗅觉， 盲人， 都市爱情， 王家卫风"], "summary_short": "男人的香气，1994年香港电影，爱情， 剧情， 文艺。香港，雨夜。调香师助理阿峰在一次实验室意外中彻底失去嗅觉。从此世界变成无声的寂静——他尝不出味道，闻不到爱人留下的香水，甚至无法分辨自己身上的汗臭。两年后，他在电梯里遇到一个女人。她身上什么味道都没有，这反而让阿峰感到安心。女人叫何莉，她告诉阿峰，自己每天出门前会喷洒三种不同的香水叠加，就像换一层人格。今天她用“无香”方案出现，因为她不想伪装。两人开始了一段“无味”的恋情。阿峰靠视觉", "score": 1994295, "category": "drama", "detail_url": "../movie/1372.html", "poster": "../posters/1372.svg"}, {"id": "1373", "title": "血战裕马堡", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "战争 / 动作 / 历史", "tags": ["抗日，碉堡攻坚战，兄弟连，主旋律"], "summary_short": "血战裕马堡，2022年中国大陆电影，战争 / 动作 / 历史。1944年夏，八路军鲁南军区决定拔掉日军控制交通线的“裕马堡”。该堡为三层混凝土结构，驻军120人，配有山炮和火焰喷射器。连长赵铁头带领36人突击队，在夜雨中泅渡护堡河。第一夜炸毁外围电网，牺牲6人。第二日强攻，日军施放毒气，副连长牺牲。赵铁头命令全连上刺刀，从被炸开的东墙缺口冲入。在堡内逐屋争夺，班长张富清用肉身堵射击孔。最后赵铁头抱着炸药包从三楼跳下与日军指挥官同归于尽。", "score": 2022327, "category": "doc", "detail_url": "../movie/1373.html", "poster": "../posters/1373.svg"}, {"id": "1374", "title": "天龙地虎", "year": 2023, "region": "中国香港", "type": "电影", "genre": "动作, 武侠, 喜剧", "tags": ["港片", "双雄", "功夫", "搞笑"], "summary_short": "天龙地虎，2023年中国香港电影，动作, 武侠, 喜剧。阿龙是元朗一家烧腊店的老板，夜里却化身为“天龙帮”帮主行侠仗义。阿虎是油麻地一家报摊的摊主，夜里则化身“地虎堂”堂主打抱不平。两人势力各占香港一半地下秩序，互不相让，江湖传闻他们终有一战。没人知道阿龙和阿虎其实是同一个人——阿龙因童年创伤产生双重人格，白天自卑懦弱，夜晚好斗狂妄。当东区的新势力企图吞并两地盘口，双重人格第一次达成共识：让这个狂妄的家伙见识一下，什么叫真正的“龙虎乱舞", "score": 2023346, "category": "comedy", "detail_url": "../movie/1374.html", "poster": "../posters/1374.svg"}, {"id": "1375", "title": "我的跨年之婚", "year": 2023, "region": "韩国", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["契约婚姻", "时间循环", "跨年"], "summary_short": "我的跨年之婚，2023年韩国电影，爱情 / 喜剧。素希决定在新年夜向好友政浩表白，却阴差阳错雇了婚庆公司的临时工敏秀扮演未婚夫来刺激对方。谁知跨年钟声一响，时间重置到当天早上。素希被困在跨年夜，每次尝试破解循环都会发现敏秀不一样的一面：他可能是整蛊专家、创业失败者、甚至是被她遗忘的小学同学。当她终于明白真爱并非那个“男神”而是眼前这个陪她循环百次的男人时，第100次跨年，她改了剧本。", "score": 2023395, "category": "romance", "detail_url": "../movie/1375.html", "poster": "../posters/1375.svg"}, {"id": "1376", "title": "代立军", "year": 2022, "region": "韩国", "type": "电影", "genre": "历史 / 战争 / 剧情", "tags": ["朝鲜历史", "替身", "壬辰倭乱", "忠义"], "summary_short": "代立军，2022年韩国电影，历史 / 战争 / 剧情。1592年，壬辰倭乱。日军大举入侵朝鲜，宣祖李昖仓皇出逃。为了让后方军民不失去信心，宣祖身边的近臣决定找一个“代立军”——一个替身，坐在空王座上，发布诏书。他们选中了市井无赖石头，因为石头长相与宣祖有三分相似。石头被迫穿上龙袍，学习王室礼仪，在忠臣们面前扮演“王”。起初他只是个傀儡，但随着真正的宣祖逃亡越来越远，石头的诏书开始真正影响战局。他下令救济难民、招募义兵、联络明朝援军。日本", "score": 2022282, "category": "doc", "detail_url": "../movie/1376.html", "poster": "../posters/1376.svg"}, {"id": "1377", "title": "野兽家族第六季", "year": 2025, "region": "美国", "type": "剧集", "genre": "剧情, 犯罪", "tags": ["家族黑帮", "权力更迭", "最终季", "高能反转"], "summary_short": "野兽家族第六季，2025年美国剧集，剧情, 犯罪。在第五季末J背叛家族后，第六季开篇便是全面战争。Pope试图用极端方式重塑家族秩序，而Deran则想彻底洗白逃离。神秘的新角色——Smurf失散多年的孪生姐妹出现，带来了关于Cody家族起源的惊天秘密，并试图夺取控制权。本季将穿插大量闪回，揭示Smurf如何从一个普通母亲变成犯罪女王。家族成员在外部FBI和内部叛徒的双重夹击下，每个人都必须选择立场。最终，海滩别墅付之一炬，只有最野兽的人", "score": 2025261, "category": "series", "detail_url": "../movie/1377.html", "poster": "../posters/1377.svg"}, {"id": "1378", "title": "纽约娃娃", "year": 2024, "region": "美国", "type": "电视剧", "genre": "剧情, 犯罪, 女性", "tags": ["黑帮", "成长", "90年代"], "summary_short": "纽约娃娃，2024年美国电视剧，剧情, 犯罪, 女性。1992年，8岁的华裔女孩梅被遗弃在纽约小意大利区，被黑帮老大老托尼收养，得名“娃娃”。她在这个全是意大利男人的世界里学会了生存、忠诚与暴力。20年后，老托尼被暗杀，帮派群龙无首。所有人都认为梅会拿着钱远走高飞，但她却选择留下来争夺继承权。凭借过人的胆识和流利的多族裔语言能力，她联合了华裔和波多黎各势力，用一场精心策划的局清洗了背叛者，最终坐上头把交椅。", "score": 2024340, "category": "series", "detail_url": "../movie/1378.html", "poster": "../posters/1378.svg"}, {"id": "1379", "title": "白鹭", "year": 2025, "region": "法国 / 中国大陆", "type": "电影", "genre": "文艺, 剧情", "tags": ["文艺片", "女性", "乡村"], "summary_short": "白鹭，2025年法国 / 中国大陆电影，文艺, 剧情。建筑设计师苏蔓因焦虑症发作，回到南方水乡的老宅休养，照顾患上阿尔茨海默症的奶奶。奶奶时而清醒时而糊涂，嘴里总是念叨着“白鹭”和一个日本名字。苏蔓在整理阁楼时，发现了一本泛黄的日记和一张穿着军装的年轻日本男子的照片。通过零碎的线索和奶奶偶尔清晰的讲述，一段二战时期凄美的跨国禁忌恋渐渐浮出水面。在与历史对话的过程中，苏蔓不仅理解了奶奶一生的伤痛，也找到了自己内心宁静的归处。", "score": 2025316, "category": "drama", "detail_url": "../movie/1379.html", "poster": "../posters/1379.svg"}, {"id": "1380", "title": "看不见的房客", "year": 2023, "region": "西班牙", "type": "电影", "genre": "悬疑, 惊悚, 犯罪", "tags": ["密室推理", "多层反转", "寄生关系", "高空惊魂"], "summary_short": "看不见的房客，2023年西班牙电影，悬疑, 惊悚, 犯罪。负债累累的哈维将亡母的公寓出租给一个神秘租客。对方支付了三年租金，但合同约定“永不见面”。哈维起初觉得省心，但半夜总听到楼上（其实就是自己家）传来挪动家具的声音。他偷偷安装了针孔摄像头，发现房间里确实空无一人，但家具会自动移位，床单上有人形压痕。惊恐的哈维潜入公寓，打开那个上了锁的衣柜——里面并没有人，而是一整套完整的监控设备，屏幕上显示的，正是他自己卧室的实时画面。这时他的手机", "score": 2023516, "category": "crime", "detail_url": "../movie/1380.html", "poster": "../posters/1380.svg"}, {"id": "1381", "title": "鬼魂西行", "year": 1935, "region": "英国", "type": "电影", "genre": "喜剧, 奇幻", "tags": ["黑白片", "庄园", "美国梦", "遗产", "闹鬼"], "summary_short": "鬼魂西行，1935年英国电影，喜剧, 奇幻。格洛斯特郡的鲍尔利庄园已经闹鬼三百年，鬼魂克林特爵士的日常就是半夜拖着锁链穿过大厅。当庄园最后一任男爵将遗产留给从未谋面的美国远亲时，克林特爵士决定改变策略。他附身于这位前来接收遗产的乐观美国年轻人身上，横渡大西洋。到了美国，爵士发现这里的人不害怕鬼魂，反而觉得他是个过气的特效演员。机缘巧合下，他被一名B级片导演看中，因其“自带惊悚气质”而签约拍恐怖片。然而，习惯了现场惊吓观众的爵士完全无法理", "score": 1935360, "category": "fantasy", "detail_url": "../movie/1381.html", "poster": "../posters/1381.svg"}, {"id": "1382", "title": "靠脸老师", "year": 2024, "region": "韩国", "type": "剧集", "genre": "剧情 / 喜剧 / 校园", "tags": ["整容", "教育", "讽刺", "身份错位"], "summary_short": "靠脸老师，2024年韩国剧集，剧情 / 喜剧 / 校园。首尔大学明星教师姜俊锡因实验室爆炸毁容后，所有名校都拒绝了他——“形象不符合教育者要求”。他倾尽积蓄做了全脸整容，化名“韩彬”进入一所升学率垫底的南道高中。本想低调教书育人，结果因为过于英俊的脸，成了全校焦点。女学生为他写情书、偷拍、跟踪，男学生因为嫉妒而霸凌他。更荒诞的是，校方发现他的“吸粉能力”后，让他兼任学校宣传大使，录短视频、上综艺，把校园变成网红孵化器。姜俊锡在流量和教育", "score": 2024292, "category": "series", "detail_url": "../movie/1382.html", "poster": "../posters/1382.svg"}, {"id": "1383", "title": "超级飞侠乐迪加速", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "动画，冒险，儿童", "tags": ["超级飞侠，乐迪，合家欢，冒险，友情"], "summary_short": "超级飞侠乐迪加速，2023年中国大陆电影，动画，冒险，儿童。超级飞侠乐迪接到一个来自南极科考站的神秘包裹，运送途中意外激活了包裹内的“加速芯片”，获得了超越极限的速度。与此同时，外星猎手“暗影”追踪芯片信号来到地球，企图夺取芯片统治银河系。乐迪发现自己每使用一次加速，芯片就会消耗一部分能量，一旦耗尽他将永远失去加速能力。在伙伴们小爱、多多、包警长的帮助下，乐迪一边躲避暗影的追捕，一边寻找芯片的真正主人。最终他们发现科考站的老科学家竟是芯", "score": 2023256, "category": "fantasy", "detail_url": "../movie/1383.html", "poster": "../posters/1383.svg"}, {"id": "1384", "title": "恐怖旅舍", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖, 惊悚, 犯罪", "tags": ["背包客噩梦", "东欧犯罪", "血腥虐杀"], "summary_short": "恐怖旅舍，2024年美国电影，恐怖, 惊悚, 犯罪。为了追寻极致的欧洲穷游体验，三个美国大学生住进了一家位于斯洛伐克偏远小镇的旅舍。这里价格便宜得离谱，老板娘异常热情。然而，同住的其他背包客开始一个接一个地神秘失踪。直到其中一人无意间闯入地下室，才发现旅舍地下是一个巨大的迷宫般的屠宰场，所有旅客都被明码标价，成为世界各地富豪们狩猎游戏中的“猎物”。他们必须依靠智慧和体力，在这个专门为猎杀而设计的钢筋水泥迷宫中，逃过手持各种武器的“猎人”", "score": 2024479, "category": "horror", "detail_url": "../movie/1384.html", "poster": "../posters/1384.svg"}, {"id": "1385", "title": "黑帮复仇", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作 / 犯罪 / 剧情", "tags": ["卧底", "背叛", "暴力美学", "兄弟情"], "summary_short": "黑帮复仇，2025年韩国电影，动作 / 犯罪 / 剧情。刑警志勋潜入南部黑帮“白虎会”十年，从底层马仔做到老大的养子。老大东哲甚至为他挡过一刀，废了一条胳膊。收网前夜，志勋的联络人被杀，唯一知道他身份的证据被毁。警方高层怕卧底曝光引发政界地震，直接下令全灭白虎会。行动当晚，志勋亲手给东哲戴上手铐，却在押送途中被警方“意外”安排的车祸灭口。他没有死，而是被东哲的手下救起。东哲坐在血泊里，笑着问他：“儿子，你到底是谁的人？” 志勋捡起枪，对", "score": 2025397, "category": "crime", "detail_url": "../movie/1385.html", "poster": "../posters/1385.svg"}, {"id": "1386", "title": "剩单响叮当", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧 / 奇幻", "tags": ["圣诞，单身，平行世界，自我救赎"], "summary_short": "剩单响叮当，2024年美国电影，喜剧 / 奇幻。极度厌恶圣诞节的单身汉尼克在圣诞夜被一道奇异光芒击中，醒来后竟发现自己身处一个没有“圣诞节”概念的世界，他却成了这里唯一的圣诞老人。为了回到原本的生活，他必须学会送礼、传递快乐并修复这个小镇的人际关系。过程中，他逐渐揭开这个世界背后的秘密——原来这是他内心深处孤独童年的映射。通过完成一次次温暖任务，尼克不仅治愈了他人，也重新面对自己。当最终铃声响起，他选择留下的决定让所有人为之动容。", "score": 2024391, "category": "comedy", "detail_url": "../movie/1386.html", "poster": "../posters/1386.svg"}, {"id": "1387", "title": "爱通过直播", "year": 2024, "region": "日本", "type": "剧集", "genre": "爱情, 悬疑", "tags": ["直播", "网恋", "虚拟偶像", "身份谜团", "社会派"], "summary_short": "爱通过直播，2024年日本剧集，爱情, 悬疑。家庭主妇真由美、女大学生莉子、公司高管千鹤，三人都是虚拟主播“浅葱”的付费粉丝。浅葱的声音温柔无性别，直播内容从读诗到游戏到深夜谈心，从不露脸，也从不谈论现实信息。三人都认为自己与浅葱有特殊的灵魂连接。某天午夜直播中，浅葱突然说：“抱歉，我明天要杀一个人。这是最后一期。” 画面关闭，账号注销。真由美、莉子、千鹤分别报警，警方发现三人在不同的城市，但都声称自己与浅葱有过私下语音通话。警方将三人", "score": 2024342, "category": "series", "detail_url": "../movie/1387.html", "poster": "../posters/1387.svg"}, {"id": "1388", "title": "三叉戟", "year": 2020, "region": "中国", "type": "电视剧", "genre": "刑侦 / 犯罪 / 剧情", "tags": ["老警察，中年危机，经侦案件，铁三角，硬汉风格"], "summary_short": "三叉戟，2020年中国电视剧，刑侦 / 犯罪 / 剧情。“大棍子”崔铁军、“大背头”徐国柱、“大喷子”潘江海，曾被称为警界“三叉戟”。二十年后，他们分别在看守所、派出所和经侦支队混日子。老战友老夏在执行任务时被神秘杀害，三人决定重出江湖。他们发现老夏查的是一起巨额非法集资案，背后涉及黑恶势力与海外洗钱网络。三叉戟的手段与年轻警察格格不入：崔铁军靠蹲点直觉，徐国柱靠线人江湖，潘江海靠审讯套话。他们也各有各的中年危机：儿子不认、夫妻分居、身", "score": 2020347, "category": "series", "detail_url": "../movie/1388.html", "poster": "../posters/1388.svg"}, {"id": "1389", "title": "千方百计误佳期", "year": 1996, "region": "中国香港", "type": "电影", "genre": "爱情喜剧", "tags": ["错位", "幽默", "都市", "浪漫"], "summary_short": "千方百计误佳期，1996年中国香港电影，爱情喜剧。广告公司策划阿杰、小混混阿飞和老实医生阿正，各自因为不同的理由需要在同一天晚上向女主嘉欣“献殷勤”。阿杰想求婚，阿飞想还债，阿正想道歉。三人在嘉欣的生日宴会外不期而遇，闹出一连串砸错门、送错花、认错人的笑话。随着误会加深，三人被迫联手应付追债大哥和嘉欣多疑的未婚夫。最终在酒店天台，所有线索汇聚，嘉欣发现这三个人竟都与自己一段不愿提及的过去有关。一场啼笑皆非的都市闹剧，在烟花下迎来反转的真", "score": 1996304, "category": "romance", "detail_url": "../movie/1389.html", "poster": "../posters/1389.svg"}, {"id": "1390", "title": "无极限之危情速递", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "动作 / 冒险", "tags": ["极限运动", "街头飙车", "生死时速"], "summary_short": "无极限之危情速递，2021年中国大陆电影，动作 / 冒险。曾经的全国跑酷冠军阿风因伤病退隐，靠在城中村送外卖维生。五岁的女儿被查出白血病，巨额医疗费压得他喘不过气。这时，一位神秘人找到他，要求他在24小时内将一个黑色手提箱送达城市另一端的废弃工厂，报酬是五十万。阿风接下任务后才发现，全城的黑帮、贪警和职业杀手都在追杀他。他只能利用跑酷技巧穿梭于高楼、地铁和地下管道之间。随着时间推移，他逐渐发现箱子里装的是足以颠覆整个城市的腐败证据，而他", "score": 2021310, "category": "fantasy", "detail_url": "../movie/1390.html", "poster": "../posters/1390.svg"}, {"id": "1391", "title": "人约离婚后", "year": 2023, "region": "中国香港", "type": "电影", "genre": "剧情 / 伦理", "tags": ["婚姻", "都市", "女性觉醒"], "summary_short": "人约离婚后，2023年中国香港电影，剧情 / 伦理。全职太太陈慧茹在发现丈夫出轨后提出离婚，进入了三十天的冷静期。在这期间，丈夫表现得体贴入微，试图挽回婚姻，陈慧茹几乎动摇。但倒数第七天，她收到了丈夫寄来的婚礼请柬——新娘是她的心理医生林佩珊，婚期就定在冷静期结束的第二天。更讽刺的是，这份请柬是通过快递送达的，收件人写的是“陈女士”。陈慧茹彻底清醒，她开始收集证据，并找到了丈夫公司被做空的财务漏洞。离婚冷静期结束那天，她没有去民政局，而", "score": 2023302, "category": "drama", "detail_url": "../movie/1391.html", "poster": "../posters/1391.svg"}, {"id": "1392", "title": "一年，一夜", "year": 2023, "region": "法国", "type": "电影", "genre": "爱情 / 剧情", "tags": ["情感创伤", "时间跨度", "治愈"], "summary_short": "一年，一夜，2023年法国电影，爱情 / 剧情。音乐记者亚瑟和画家女友露易丝经历了巴塔克兰剧院的恐怖袭击。亚瑟背部中枪，侥幸逃生，露易丝则因躲进卫生间而幸免于难。然而身体伤口的愈合只是开始，亚瑟患上了严重的创伤后应激障碍，无法与人亲近，甚至恐惧音乐；露易丝则陷入幸存者愧疚，画笔再也无法落下。在接下来整整一年的时间里，两人住在同一屋檐下，却仿佛隔着玻璃墙。他们经历了无数次的崩溃、争吵、短暂分离与重新靠近。影片以细碎的日常切片，记录了他们如", "score": 2023310, "category": "romance", "detail_url": "../movie/1392.html", "poster": "../posters/1392.svg"}, {"id": "1393", "title": "猫咪咖啡厅", "year": 2024, "region": "日本", "type": "剧集", "genre": "奇幻 / 治愈", "tags": ["猫咪", "咖啡厅", "温情", "单元剧"], "summary_short": "猫咪咖啡厅，2024年日本剧集，奇幻 / 治愈。街角有一家奇怪的猫咪咖啡厅，招牌猫“社长”能让触摸它的人看到一段过去的影像。失业青年阿守为了偷钱而来，却被“社长”带回了母亲生前的笑容。他开始留下来打工。每一集，不同的客人通过不同的猫咪，回到遗憾的时刻：因吵架失去挚友的少女，在猫眼里看到对方的道歉；记不得老伴的老人，通过老猫看到了新婚誓言。原来，这些猫都是附近离世居民的“意念化身”。咖啡厅最终没能逃过拆迁，但阿守和常客们带着猫咪给的力量，", "score": 2024232, "category": "series", "detail_url": "../movie/1393.html", "poster": "../posters/1393.svg"}, {"id": "1394", "title": "爱出猫", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 青春 / 校园", "tags": ["作弊", "校园", "青春", "港式喜剧", "反作弊"], "summary_short": "爱出猫，2024年中国香港电影，喜剧 / 青春 / 校园。圣利马书院是香港顶尖中学，但校内却有一个由学霸陈柏豪领导的秘密“作弊帮”——他们不是抄答案，而是专门研发“防作弊系统”，义务帮老师抓作弊。陈柏豪的座右铭是：“只有最懂作弊的人，才能最有效地反作弊。” 一次，学校在DSE模拟考中发现有学生使用来自外部的高科技作弊工具。陈柏豪的帮派被校长“委以重任”潜入作弊集团。他们发现，这个集团正计划在全港真实DSE中大规模替考，赚取巨额黑钱，而突", "score": 2024311, "category": "comedy", "detail_url": "../movie/1394.html", "poster": "../posters/1394.svg"}, {"id": "1395", "title": "我的男友是辅警", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "剧情, 爱情, 生活", "tags": ["基层民警", "平凡英雄", "市井生活", "陪伴成长"], "summary_short": "我的男友是辅警，2024年中国大陆剧集，剧情, 爱情, 生活。外企高管林珊在一次丢猫事件中结识了来处理纠纷的辅警张毅。张毅并非传统意义上的英雄，他收入微薄，每天处理的都是邻里吵架、寻找失物、救助流浪动物等琐事。林珊的家人和朋友都不理解她为何选择这样一个“没出息”的男人。剧集通过两人的相处，展现了基层辅警真实而艰辛的工作状态：他们经常不被理解，甚至要面对危险，却始终是城市最坚实的防线。林珊在陪伴张毅处理一个又一个“小案子”的过程中，逐渐被", "score": 2024287, "category": "series", "detail_url": "../movie/1395.html", "poster": "../posters/1395.svg"}, {"id": "1396", "title": "基督山之子", "year": 2025, "region": "法国", "type": "剧集", "genre": "剧情 / 悬疑 / 冒险", "tags": ["复仇", "遗产", "现代改编", "宿命"], "summary_short": "基督山之子，2025年法国剧集，剧情 / 悬疑 / 冒险。现代版《基督山伯爵》。年轻水手埃德蒙被诬陷走私，关押在私人监狱14年。他在狱中结识一位“囚禁学教授”，获知一笔神秘数字遗产的线索。越狱后，他化身多位身份，潜入家族企业，发现当年告密者竟是自己垂死的父亲。他要复仇的，是给予自己生命的血脉。与此同时，一笔足以颠覆欧洲金融秩序的“遗产”也浮出水面。他必须在原谅与毁灭之间，找到自己的道路，成为真正的“基督山之子”。", "score": 2025321, "category": "series", "detail_url": "../movie/1396.html", "poster": "../posters/1396.svg"}, {"id": "1397", "title": "男女混合宿舍", "year": 2025, "region": "韩国", "type": "剧集", "genre": "爱情 / 喜剧", "tags": ["大学校园， 契约恋爱， 欢喜冤家， 暧昧"], "summary_short": "男女混合宿舍，2025年韩国剧集，爱情 / 喜剧。高冷金融系学霸姜凛为了住进拥有独立书房的宿舍，不得不遵守学校“男女混合宿舍必须配对入住”的奇葩规定。他唯一的申请者，是全校闻名、挂科无数、生活邋遢的体育系学渣金美善。两人从入住第一天就因生活作息不同而战火不断。姜凛无法忍受噪音，金美善受不了洁癖。为了不被管理员发现假情侣身份而被赶出去，他们开始练习约会，从图书馆占座到食堂喂食。在无数次的争吵与和好中，姜凛发现金美善打工是为了供妹妹读书，金", "score": 2025260, "category": "series", "detail_url": "../movie/1397.html", "poster": "../posters/1397.svg"}, {"id": "1398", "title": "单亲度假村", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "喜剧, 爱情, 家庭", "tags": ["单亲父母", "海岛", "相亲", "育儿"], "summary_short": "单亲度假村，2025年中国大陆电视剧，喜剧, 爱情, 家庭。在上海的职场女强人周一一、成都的瑜伽教练单宁、沈阳的烧烤店老板娘大美丽，因为各自不同的原因（骗婚、丧偶、离异）成了单亲妈妈。她们看到一则广告“阳光海岛单亲度假村，为你的孩子找到完美的另一个家长”。到了岛上才发现，这是个巨大的坑：所谓的度假村只是一个破旧民宿，而另外三个“候选人”竟也是单亲爸爸——一个不修边幅的海洋生物学家、一个毒舌的离婚律师、一个总想当网红的面条摊主。孩子们被关", "score": 2025326, "category": "series", "detail_url": "../movie/1398.html", "poster": "../posters/1398.svg"}, {"id": "1399", "title": "睁开你的眼睛", "year": 2024, "region": "西班牙", "type": "电影", "genre": "科幻, 悬疑, 心理惊悚", "tags": ["梦境", "虚拟现实", "伦理", "哲学", "反转"], "summary_short": "睁开你的眼睛，2024年西班牙电影，科幻, 悬疑, 心理惊悚。富二代马丁沉溺于享乐，一夜狂欢后在悬崖边车祸，面部毁容。他接受了一家神秘公司的“意识重塑疗法”，醒来后脸恢复如初，但身边的一切都开始不对劲：死去的前女友突然出现在他家，所有人都叫他另一个名字，镜子里的自己偶尔会做出截然不同的表情。当他试图逃离，整个世界像玻璃一样碎裂，露出底下黑色的虚空。一个自称“系统管理员”的声音告诉他：“你已经在昏迷中签署了永久体验协议，但有人篡改了你的梦", "score": 2024481, "category": "crime", "detail_url": "../movie/1399.html", "poster": "../posters/1399.svg"}, {"id": "1400", "title": "尼克男孩", "year": 2024, "region": "美国", "type": "电影", "genre": "剧情, 传记", "tags": ["黑白", "私刑", "创伤", "兄弟情"], "summary_short": "尼克男孩，2024年美国电影，剧情, 传记。改编自真实事件。1940年代佛罗里达，16岁的尼克和好友埃尔伍德只因搭了趟顺风车，就被诬告并送进臭名昭著的“尼克男子学校”。这里实为一座残酷的种植园，男孩们在枪口下劳作，动辄遭受私刑。埃尔伍德坚信正义，试图写信向外求助；而尼克为了生存，变得冷酷并逐渐融入看守体系。多年后，一场大火烧毁了学校，尼克趁机逃出，却目睹埃尔伍德为保护别人被拖回火海。成年后的尼克背负着背叛好友的愧疚，直到在听证会上，他颤", "score": 2024269, "category": "drama", "detail_url": "../movie/1400.html", "poster": "../posters/1400.svg"}, {"id": "1401", "title": "远离天堂", "year": 2026, "region": "法国 / 比利时", "type": "电影", "genre": "剧情、文艺、同性", "tags": ["修道院、禁忌之恋、信仰崩塌、中世纪"], "summary_short": "远离天堂，2026年法国 / 比利时电影，剧情、文艺、同性。1348年，黑死病席卷欧洲。偏远山区的圣十字修道院收留了一名受伤的骑士伊格纳修斯。负责照料他的年轻修道士埃利泽从小在修道院长大，从未见过围墙外的世界。骑士给他讲战场、讲海洋、讲女人与男人之间的另一种爱。某个雪夜，两人在祭坛后拥吻，被另一位修道士撞见。修道院召开内部审判，神父要求埃利泽“忏悔”，否则将被处以火刑。埃利泽拒绝了，他说：“如果爱他是罪，那么上帝创造我的那一刻，就给了我", "score": 2026239, "category": "drama", "detail_url": "../movie/1401.html", "poster": "../posters/1401.svg"}, {"id": "1402", "title": "爱情与信仰之第三者", "year": 2026, "region": "印度", "type": "电影", "genre": "剧情 / 歌舞", "tags": ["宗教", "三角恋", "殉道", "锡克教"], "summary_short": "爱情与信仰之第三者，2026年印度电影，剧情 / 歌舞。阿姆利则金庙旁，年轻的锡克教徒哈曼与穆斯林女画家扎拉陷入热恋。但哈曼的母亲——被信众奉为“圣女”的玛塔，却强烈反对。表面上是宗教冲突，实则是玛塔无法容忍“另一个女人”抢走儿子。玛塔年轻时曾为信仰放弃爱情，如今她将儿子视为自己唯一的“精神伴侣”。为拆散他们，玛塔以“净化信仰”为名，指使教徒暴力驱赶扎拉。混乱中，哈曼为保护爱人重伤昏迷。扎拉在病床前用血画下共生的神像。玛塔跪在儿子床前，", "score": 2026234, "category": "drama", "detail_url": "../movie/1402.html", "poster": "../posters/1402.svg"}, {"id": "1403", "title": "我们和我们的山", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情、家庭、励志", "tags": ["山区、脱贫、父子、乡村教师、真实改编"], "summary_short": "我们和我们的山，2024年中国大陆电影，剧情、家庭、励志。贵州山区。村小教师老伍被查出渐冻症，最多还有两年。他教了一辈子书，没出过一个考上县城中学的学生。他决定最后两年只教一个学生：一个留守儿童，男孩小石头。小石头调皮、逃学、偷果子，但老伍发现他有过目不忘的能力。老伍搬进小石头家，每天用竹条逼他背课文、做算术。一年后，小石头成为全镇会考第一。老伍的病情恶化，站不起来就躺着讲课，说不出话就写字。去县城考试那天，老伍坐轮椅送到山口。小石头最", "score": 2024240, "category": "drama", "detail_url": "../movie/1403.html", "poster": "../posters/1403.svg"}, {"id": "1404", "title": "疯狂烤肉会", "year": 2025, "region": "韩国", "type": "电影", "genre": "黑色喜剧 / 悬疑 / 剧情", "tags": ["家庭聚餐，全员恶人，反转不断，黑色幽默"], "summary_short": "疯狂烤肉会，2025年韩国电影，黑色喜剧 / 悬疑 / 剧情。富豪金社长在自己豪宅的花园里举办了一场盛大的家庭烤肉会，邀请所有子女、儿媳、女婿以及长期不和的亲戚。每人自带一份“特制腌肉”。但随着聚餐进行，诡异的事发生了：大儿子带来的“五花肉”烤熟后，形状酷似他失踪的妻子；二女儿带来的“牛排”里，吃出了一颗镶着金牙的牙齿——那是她前夫的；三女婿的“羊肉串”发出浓烈的福尔马林味道。当所有人都面色铁青时，金社长笑着举起酒杯：“很高兴看到各位，", "score": 2025434, "category": "drama", "detail_url": "../movie/1404.html", "poster": "../posters/1404.svg"}, {"id": "1405", "title": "狼心性教欲", "year": 2025, "region": "西班牙", "type": "剧集", "genre": "惊悚情欲", "tags": ["狼人", "欲望", "修道院", "禁忌", "变身"], "summary_short": "狼心性教欲，2025年西班牙剧集，惊悚情欲。15世纪西班牙偏远的修道院中，年轻修女艾格尼丝每到月圆便被噩梦与身体异变折磨。她发现自己的欲望越强烈，变身后的狼形便越完整。在神父的驱魔仪式与情敌修女的挑唆下，她逐渐意识到：修道院封印的并非恶魔，而是一支古老狼族血脉。当审判庭火把照亮夜空，艾格尼丝必须在神的枷锁与狼的野性之间做出抉择。影片大胆探讨宗教压抑与自然欲望的对抗，情欲场面并非噱头，而是角色觉醒的必经之路。", "score": 2025307, "category": "series", "detail_url": "../movie/1405.html", "poster": "../posters/1405.svg"}, {"id": "1406", "title": "王者潮流", "year": 2025, "region": "澳大利亚", "type": "电影", "genre": "冒险 / 运动 / 惊悚", "tags": ["冲浪", "神秘巨浪", "孤岛求生", "自然之力"], "summary_short": "王者潮流，2025年澳大利亚电影，冒险 / 运动 / 惊悚。传奇冲浪手“鲨鱼”杰克召集全球顶尖选手，前往南太平洋的“墓碑岛”，挑战号称“王者潮流”的百尺巨浪。然而，当地原住民警告他们，每七年一次的“王者潮”不仅是海浪，也是深海巨兽“莫拉”的繁殖洄游通道。杰克不顾劝阻，带领团队趁潮下水。他们成功征服巨浪，却触发了潮汐异常——海水在几分钟内退去千米，露出从未有人踏足的海底洞穴。洞中密密麻麻的巨蛋开始破裂，幼体生物将他们视作第一顿食物。众人必", "score": 2025285, "category": "fantasy", "detail_url": "../movie/1406.html", "poster": "../posters/1406.svg"}, {"id": "1407", "title": "女人我最大", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧, 剧情", "tags": ["女性互助", "职场逆袭", "黑色幽默"], "summary_short": "女人我最大，2025年中国大陆电影，喜剧, 剧情。互联网大厂“优化”了四位35+的女性：单身学霸、单亲妈妈、已婚丁克、离异富婆。她们拿着微薄的赔偿金，偶然发现裁员她们的人事总监老胡，竟在外面开了家专做“中年焦虑”培训的皮包公司。愤怒之下，她们决定复仇。利用各自的专业——数据分析、心理学、财务、人脉——她们伪装成投资方，混入老胡的公司，一步步诱导他加杠杆、签对赌、虚报数据。最终，在一场虚假的“纳斯达克敲钟”仪式上，当着所有被骗的“学员”面", "score": 2025312, "category": "comedy", "detail_url": "../movie/1407.html", "poster": "../posters/1407.svg"}, {"id": "1408", "title": "识骨寻踪第五季", "year": 2021, "region": "美国", "type": "剧集", "genre": "犯罪，法医", "tags": ["女性法医，连环杀手，考古，冷案"], "summary_short": "识骨寻踪第五季，2021年美国剧集，犯罪，法医。第五季开篇即高能：建筑工地挖出一具骸骨，碳 dating 显示其死于1700年前，但脚上却穿着一只限量版耐克跑鞋。Temperance Brennan博士和Booth探员再次联手。随着调查深入，他们发现这是一起跨越时空的模仿杀人案——有人按照两千年前的处刑方式在当代行凶。团队必须一边解读古罗马刑罚史，一边追踪一个沉迷于“历史正义”的极端狂热分子。与此同时，Angela和Hodgins的婚姻", "score": 2021274, "category": "series", "detail_url": "../movie/1408.html", "poster": "../posters/1408.svg"}, {"id": "1409", "title": "关键目击", "year": 2025, "region": "美国", "type": "电影", "genre": "犯罪，悬疑", "tags": ["盲人，证词，反转，心理博弈，声效叙事"], "summary_short": "关键目击，2025年美国电影，犯罪，悬疑。街头枪击案中，唯一声称“看见”凶手的是盲人调音师伊恩。警方认为他在撒谎，直到他的录音笔里出现了一段环境音——三声闷响、一次皮鞋急刹、一串钥匙落地。伊恩通过声学分析重建了现场：开枪的不是两人，而是三人。真正的目标并非受害人，而是躲在垃圾桶后的卧底警察。凶手通过耳机监听警方频道，故意制造混乱。伊恩在庭审上播放慢放音频，凶手换鞋时的气垫声成为铁证。最后一刻，凶手冷笑：“你听不见我口袋里的遥控器吗？”", "score": 2025431, "category": "crime", "detail_url": "../movie/1409.html", "poster": "../posters/1409.svg"}, {"id": "1410", "title": "蓝天使", "year": 2028, "region": "德国", "type": "电影", "genre": "科幻", "tags": ["赛博朋克", "人工智能", "记忆", "歌舞", "反乌托邦"], "summary_short": "蓝天使，2028年德国电影，科幻。2047年，柏林。记忆芯片普及，人可以购买“精选记忆”，删除痛苦。曾经的偶像歌手“蓝天使”丽莎人气暴跌，因为她的最新专辑被AI乐评人评为“毫无灵魂”。一次酒后，丽莎遭遇车祸，记忆芯片受损，意外唤醒了原始生物记忆——她发现自己最红的三首金曲的创作过程完全不存在，那些获奖、欢呼、灵感迸发的瞬间，全是唱片公司植入的芯片假记忆。真实的她只是个五音不全的工厂女工，被选中成为“人造明星”的壳。丽莎决定毁掉这个谎言，", "score": 2028296, "category": "sci-fi", "detail_url": "../movie/1410.html", "poster": "../posters/1410.svg"}, {"id": "1411", "title": "婚礼", "year": 2022, "region": "印度", "type": "电影", "genre": "剧情, 喜剧, 家庭", "tags": ["印式婚礼", "家庭冲突", "秘密", "歌舞", "群像"], "summary_short": "婚礼，2022年印度电影，剧情, 喜剧, 家庭。在斋浦尔的一座豪华宫殿里，卡普尔家族正在为独生女普丽雅筹备一场盛大的婚礼。新郎是门当户对的富二代，一切看起来完美无缺。但婚礼前四小时，新娘的前男友——一个开突突车的穷小子出现在了宾客名单上；新郎的债主带着打手来到婚礼现场，威胁不还钱就让婚礼见血；从德里请来的著名司仪在彩排时喝多了，现在还在储藏室昏睡；更糟的是，新娘五岁的表弟在宫殿里走丢了，而他手里拿着婚礼的婚戒。随着宾客陆续到来，一个又一", "score": 2022352, "category": "drama", "detail_url": "../movie/1411.html", "poster": "../posters/1411.svg"}, {"id": "1412", "title": "晴～综合商社之女～", "year": 2019, "region": "日本", "type": "电视剧", "genre": "剧情, 职场", "tags": ["商战", "女性", "强势女主", "职场斗争", "经济"], "summary_short": "晴～综合商社之女～，2019年日本电视剧，剧情, 职场。主角天海晴是东京大型综合商社“三和物产”的明星员工，被称为“行走的决策机器”。因手段强硬得罪了董事会，被明升暗降，派往巴西里约热内卢管理濒临破产的当地分公司。这里不仅有腐败的当地管理层、失控的账目，还有虎视眈眈的欧美竞争对手。所有人都等着看这位东京精英女士的笑话。但晴没有被吓倒。她不按常理出牌：不查账，先学桑巴；不裁员，先搞狂欢节。她利用日本、巴西和非洲之间的三角贸易规则，通过操控", "score": 2019194, "category": "series", "detail_url": "../movie/1412.html", "poster": "../posters/1412.svg"}, {"id": "1413", "title": "分手的决心", "year": 2022, "region": "韩国", "type": "电影", "genre": "爱情 / 悬疑", "tags": ["山与海", "失眠", "边缘人格"], "summary_short": "分手的决心，2022年韩国电影，爱情 / 悬疑。刑警海俊在调查一宗坠崖案时，遇见了死者的中国籍妻子徐婡。她平静、得体，眼神像一口枯井。所有证据都指向她是凶手，但海俊却无法抗拒她的吸引。两人在监视与反监视中滋生出扭曲的亲密——她渴望被他怀疑，他渴望相信她无罪。当第二具尸体出现，徐婡用一场精心设计的“偶遇”将海俊拖入更深的泥潭。他终于为她顶罪并删掉关键录音，而她选择用另一种方式完成“分手”：让他此生都无法忘记自己。山的尽头是海，他的决心是困", "score": 2022366, "category": "crime", "detail_url": "../movie/1413.html", "poster": "../posters/1413.svg"}, {"id": "1414", "title": "尸城30夜", "year": 2022, "region": "韩国", "type": "电影", "genre": "恐怖 / 丧尸 / 动作", "tags": ["丧尸", "城市", "逃亡", "韩国", "惊悚"], "summary_short": "尸城30夜，2022年韩国电影，恐怖 / 丧尸 / 动作。神秘病毒爆发，只感染Y染色体，男性在感染后会变成狂暴的食人丧尸，只有极少数免疫者。瞬间，首尔沦为死城。女主角智秀是一名部队出身的女警，她和几位幸存者——女医生、女高中生、以及一位免疫的男孩——躲藏在大型超市里。军方宣布30天后将进行“清洁行动”，届时任何留在城中的人将被视为感染者射杀。这意味着他们只有30天时间穿越尸群到达汉江对岸的隔离区。在逃亡路上，他们不仅要面对丧尸，还要提防", "score": 2022367, "category": "horror", "detail_url": "../movie/1414.html", "poster": "../posters/1414.svg"}, {"id": "1415", "title": "霹雳霸王花", "year": 2026, "region": "香港 / 中国大陆", "type": "电影", "genre": "动作 / 喜剧", "tags": ["女特工", "怀旧", "搞笑", "实战", "姐妹情"], "summary_short": "霹雳霸王花，2026年香港 / 中国大陆电影，动作 / 喜剧。2000年代经典《霸王花》系列的传承续集。前霸王花成员、如今已是45岁火锅店老板娘的李心怡，接到老上司密令：全球唯一能做“让人吃出幸福记忆”蛋糕的甜品师被东南亚军火商绑架，要求72小时内交付1000万赎金，否则撕票。李心怡被迫组建新霸王花：三位成员分别是只会打游戏的理论派女大学生、沉迷美妆的毒舌网红、以及有幽闭恐惧症的前武术运动员。四人在训练营闹出无数笑话：射击训练打中教官屁", "score": 2026385, "category": "comedy", "detail_url": "../movie/1415.html", "poster": "../posters/1415.svg"}, {"id": "1416", "title": "一本正经", "year": 2024, "region": "英国", "type": "剧集", "genre": "喜剧 / 职场", "tags": ["出版社", "编辑", "讽刺", "英式幽默"], "summary_short": "一本正经，2024年英国剧集，喜剧 / 职场。老牌文学出版社“正直书屋”濒临破产，年轻CEO空降后，第一个决策就是成立“玫瑰小说部”——专门出版网络甜宠文。老主编乔治看着自己操刀了三十年的纯文学名著被堆在仓库吃灰，而隔壁部门靠一本《总裁的33个替身情人》月销百万。他试图抗议，却被要求去给甜宠文作者做“文学指导”。乔治不得不教网红作者如何使用狄更斯的比喻来描写男主腹肌。最讽刺的是，经过他润色的那本霸总小说，竟然入围了文学奖。", "score": 2024255, "category": "series", "detail_url": "../movie/1416.html", "poster": "../posters/1416.svg"}, {"id": "1417", "title": "冲绳小芙蓉", "year": 2024, "region": "日本", "type": "电影", "genre": "剧情 / 家庭", "tags": ["冲绳", "亲情", "治愈"], "summary_short": "冲绳小芙蓉，2024年日本电影，剧情 / 家庭。东京精英白领美咲因搞砸了一个大项目，被公司流放到冲绳一个没有Wi-Fi的偏远小岛，去经营一家濒临倒闭的民宿。岛上只有几个老人和一个名叫小芙蓉的奇怪女孩。小芙蓉不上学，总穿着红花裙子，说她是一株木芙蓉变的，一直在等一个“会讲故事的人”。起初美咲只想赶紧完成KPI回东京，但慢慢地，她被岛上缓慢的生活节奏和温暖的民风所感染。她开始给小芙蓉讲故事，帮她寻找“身世之谜”。最终美咲发现，小芙蓉其实是一", "score": 2024308, "category": "drama", "detail_url": "../movie/1417.html", "poster": "../posters/1417.svg"}, {"id": "1418", "title": "宇宙小子第五季", "year": 2026, "region": "美国", "type": "剧集", "genre": "科幻, 动画, 冒险", "tags": ["星际战争", "青少年英雄", "太空歌剧", "最终季"], "summary_short": "宇宙小子第五季，2026年美国剧集，科幻, 动画, 冒险。备受期待的最终季。在第四季结局中，史蒂文为了拯救母星，被迫释放了被封印千年的“宇宙之卵”，这反而导致了时空结构的撕裂，无数平行宇宙开始碰撞、湮灭。本季中，史蒂文不再是那个天真的孩子，他失去了大部分宝石之力，身体也在迅速老化。他必须踏上一条绝望的朝圣之路：前往十二个正在崩溃的平行宇宙，找到“共鸣水晶”的碎片，重新缝合现实。在这个过程中，他会遇到成为暴君的另一个自己、与人类为敌的水晶", "score": 2026338, "category": "series", "detail_url": "../movie/1418.html", "poster": "../posters/1418.svg"}, {"id": "1419", "title": "暗夜异劫", "year": 2026, "region": "西班牙", "type": "电影", "genre": "恐怖, 悬疑", "tags": ["劫机", "超自然", "高空", "密闭空间", "反转"], "summary_short": "暗夜异劫，2026年西班牙电影，恐怖, 悬疑。一架从马德里飞往布宜诺斯艾利斯的夜航班机上，五名武装劫匪伪装成乘客，计划在飞行途中控制飞机，盗取货舱里的黄金。计划一开始很顺利，他们制服了安保，控制了驾驶舱。但随后发生的事情超出了所有人的理解。劫匪头目卡洛斯发现，机舱里的影子开始“动”，不是随灯光晃动，而是像活物一样从地面爬起，钻入乘客的身体。被影子寄生的人变得异常冷静，力大无穷，且对所有活人充满敌意。更恐怖的是，这些影子似乎对劫匪的黄金毫", "score": 2026462, "category": "crime", "detail_url": "../movie/1419.html", "poster": "../posters/1419.svg"}, {"id": "1420", "title": "虎穴追踪", "year": 1956, "region": "中国大陆", "type": "电影", "genre": "反特 / 悬疑 / 黑白", "tags": ["红色经典", "卧底", "特务", "黑白片", "老电影"], "summary_short": "虎穴追踪，1956年中国大陆电影，反特 / 悬疑 / 黑白。解放初期，东北深山老林里盘踞着一股国民党残余土匪，电台不断与台湾联系。侦查员李永和奉命假扮被击毙的特务“03号”潜入匪巢。他凭借过硬的心理素质和土匪打成一片，取得匪首“座山雕式”的信任。就在即将摸清电台位置时，军区内部突然下达“剿匪延期”的命令，李永和意识到上级有内鬼。他冒险用土匪的电台发了一封假电报，引诱真正的内鬼主动联系土匪。最终内鬼暴露——竟是李永和的直接领导、作战科王科", "score": 1956351, "category": "crime", "detail_url": "../movie/1420.html", "poster": "../posters/1420.svg"}, {"id": "1421", "title": "三流之路", "year": 2017, "region": "韩国", "type": "剧集", "genre": "剧情 / 喜剧 / 爱情", "tags": ["小人物的梦想", "现实题材", "格斗与主播", "青梅竹马"], "summary_short": "三流之路，2017年韩国剧集，剧情 / 喜剧 / 爱情。从小梦想成为跆拳道国手的金柱曼，如今只是做着除虫工作的普通人；渴望成为新闻主播的崔爱罗，却在百货公司信息台度日。两人住在破旧的半地下屋，是彼此的冤家与依靠。当柱曼意外获得一场格斗比赛的胜利，他发现这或许是重回赛场的出路；爱罗则凭借一段怼人视频意外走红网络。在现实与理想的夹缝中，他们一次次跌倒又爬起，用最笨拙的坚持对抗世界的偏见。最终，爱罗坐上主播台，柱曼戴上格斗手套，他们明白所谓“", "score": 2017367, "category": "series", "detail_url": "../movie/1421.html", "poster": "../posters/1421.svg"}, {"id": "1422", "title": "两对鸳鸯", "year": 2024, "region": "中国", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["交换伴侣", "中年危机", "荒诞", "迷途知返"], "summary_short": "两对鸳鸯，2024年中国电影，喜剧 / 爱情。结婚七年的老张夫妇和老李夫妇是好友。激情褪去后，四人决定来一场“换妻游戏”寻找刺激。老张和对方妻子去海边，老李和老张妻子去露营。然而，习惯了原配生活的他们，在新组合中处处碰壁：老张受不了新伴侣的洁癖，老李被对方的大嗓门折磨，而两位妻子也发现对方丈夫的毛病比自家那位还多。一周后，四个人狼狈地回到原点，互相坦白“出轨”经历，笑闹中重新发现了原配的好。经过这场荒诞的实验，他们学会了理解和包容，婚姻", "score": 2024310, "category": "romance", "detail_url": "../movie/1422.html", "poster": "../posters/1422.svg"}, {"id": "1423", "title": "我的篡位替身", "year": 2027, "region": "韩国", "type": "剧集", "genre": "古装 / 悬疑 / 权谋", "tags": ["双面君王、替身夺权、影武者"], "summary_short": "我的篡位替身，2027年韩国剧集，古装 / 悬疑 / 权谋。朝鲜王朝第九代王李晫疑心极重，从民间寻来与自己容貌酷似的戏子河善作为“替身”，每逢危险场合便让他坐殿。河善被迫模仿王的言行举止，起初战战兢兢，却在一次次代政中展露出比真王更敏锐的治国才华。朝臣们开始私下议论“影子比真身更像王”。一年后，李晫想除掉河善，却发现自己已被彻底架空——军队听河善的、百姓爱河善的、连王后也站到了河善身边。最讽刺的是，河善深夜找到李晫，跪着说：“我不想当王", "score": 2027322, "category": "series", "detail_url": "../movie/1423.html", "poster": "../posters/1423.svg"}, {"id": "1424", "title": "坐稳车泰欣娜", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情 / 文艺", "tags": ["原住民", "公路电影", "魔幻写实", "寻根"], "summary_short": "坐稳车泰欣娜，2025年中国台湾电影，剧情 / 文艺。“泰欣娜”是排湾族语中“坐稳车”的意思。八旬排湾族长老巴鲁病入膏肓，他梦到祖先托梦，说祖灵没有离开，而是迁入了深山中一处被地图抹去的部落。他不顾医生劝阻，骑上破旧的野狼125，要上山“回家”。在城市长大的孙子阿洛被母亲勒令陪同，以防爷爷出事。阿洛本以为这是一趟荒唐的旅程，却随着深入中央山脉，发现自己手机里的“文明世界”信号全无，取而代之的是爷爷口中会说话的云豹、发光的森林以及藏在瀑布", "score": 2025323, "category": "drama", "detail_url": "../movie/1424.html", "poster": "../posters/1424.svg"}, {"id": "1425", "title": "法网追凶第三季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "犯罪 / 悬疑 / 剧情", "tags": ["刑侦", "连环杀人", "心理侧写", "法医", "高智商犯罪"], "summary_short": "法网追凶第三季，2024年中国大陆剧集，犯罪 / 悬疑 / 剧情。“雕刻师”连环杀人案轰动全国，凶手在被捕后判处死刑，于第三季开场执行枪决。所有人都以为噩梦结束了，然而就在“雕刻师”死后第七天，江北市再次出现一具被精心处理过的女尸，手法和“雕刻师”如出一辙，但某些细节更加精细、更具仪式感。专案组重启调查，发现这并非简单模仿犯——凶手似乎掌握了“雕刻师”从未公开过的作案细节，而这些细节只有办案人员和“雕刻师”本人知道。法医林念和刑警队长陆", "score": 2024353, "category": "series", "detail_url": "../movie/1425.html", "poster": "../posters/1425.svg"}, {"id": "1426", "title": "黑街执法者", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 犯罪", "tags": ["私刑", "复古", "地下拳场", "黑色电影", "硬汉"], "summary_short": "黑街执法者，2025年美国电影，动作 / 犯罪。八十年代底特律，硬汉警探弗兰克的妻子被枪杀于街头，凶手逍遥法外。弗兰克因暴力执法被停职，他化名潜入城市最底层的地下拳场，这里每周四都有“无规则搏命赛”，而他的杀妻仇人——代号“幽灵”的杀手——每场必到。弗兰克一边打拳一边接近目标，却发现自己每一次出拳都会揭开妻子不为人知的一面：她曾是警方的线人，而幽灵是她放跑的一条大鱼。当弗兰克终于站上决斗铁笼，对面站着的不只是仇人，更是他自己曾经的执法幻", "score": 2025372, "category": "crime", "detail_url": "../movie/1426.html", "poster": "../posters/1426.svg"}, {"id": "1427", "title": "小鬼当家3国语", "year": 2022, "region": "美国 / 中国", "type": "电影", "genre": "喜剧, 家庭", "tags": ["搞笑", "机关", "合家欢", "致敬", "重启"], "summary_short": "小鬼当家3国语，2022年美国 / 中国电影，喜剧, 家庭。上海小男孩王小乐是个科技迷，父母因公出差，把他独自留在老弄堂的家里。一个国际犯罪团伙将盗窃的芯片藏在了他新买的遥控车里，四名伪装成快递员、维修工的盗贼前来抢夺。王小乐发现他们的阴谋后，利用弄堂复杂的地形和自己的AI机器人宠物，在家中布下了天罗地网：从会喷墨的智能马桶、用无人机操控的弹珠机关，到改装过的扫地机器人“坦克”。四个笨贼在极具中国特色的弄堂里被整得鼻青脸肿，而王小乐则在", "score": 2022244, "category": "comedy", "detail_url": "../movie/1427.html", "poster": "../posters/1427.svg"}, {"id": "1428", "title": "疯狂83", "year": 2014, "region": "中国大陆", "type": "电影", "genre": "喜剧，历史", "tags": ["怀旧，荒诞，小镇"], "summary_short": "疯狂83，2014年中国大陆电影，喜剧，历史。1983年，北方小镇红石桥接到通知，省里的考察团要来检验“改革开放成果”。镇长急中生智，让供销社假扮超市、让农民穿西装下地、让拖拉机装录音机放流行歌。全镇人投入一场荒诞的“表演”，笑料百出：老农民不会打领带，把领带当围脖；供销社主任从省城偷学来的“超市管理”成了闹剧。可当考察团真的到来并指出“你们做得比我们想象的还要好”时，小镇人突然发现，这场疯狂已经悄然改变了他们的生活。", "score": 2014319, "category": "doc", "detail_url": "../movie/1428.html", "poster": "../posters/1428.svg"}, {"id": "1429", "title": "食女", "year": 2024, "region": "日本", "type": "Movie", "genre": "恐怖，惊悚，悬疑", "tags": ["都市传说，饮食文化，女性复仇，心理恐惧，血腥美学"], "summary_short": "食女，2024年日本Movie，恐怖，惊悚，悬疑。美食博主小唯收到一封神秘邀请函，前往隐匿在东京巷弄深处的“月读馆”。店主是一位优雅的中年女子，她端出的“红丝绒慕斯”让小唯惊为天人。随着小唯频繁光顾，她发现店里的菜单总是随着新闻报道的失踪女性数量而变化。更诡异的是，另一位常客、女刑警美咲开始调查多名网红在品尝美食后暴毙的案件。当小唯发现自己也成为了“食材”候选人时，她必须在一场名为“最后晚餐”的仪式中找到逃生的机会，并揭开店主百年前被爱", "score": 2024378, "category": "horror", "detail_url": "../movie/1429.html", "poster": "../posters/1429.svg"}, {"id": "1430", "title": "1400", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["密室， 限时破局， 心理博弈， 反转"], "summary_short": "1400，2025年中国大陆电影，悬疑 / 犯罪。刑警林峰醒来时发现自己身处一间废弃化工厂的控制室，与他一同被困的还有另外六名身份各异的男女。广播响起冰冷的声音：他们中藏着一个绑架案的主谋，而警方正在追踪的赎金高达一千四百万。每过一小时，若无人被指认，所有人都会失去部分氧气供应。十四小时的倒计时、扑朔迷离的证词、不断被揭开的黑暗过往，林峰必须在时间耗尽前揪出真凶，但更可怕的是，他发现这场游戏的设计者可能早已伪装成受害者之一。", "score": 2025443, "category": "crime", "detail_url": "../movie/1430.html", "poster": "../posters/1430.svg"}, {"id": "1431", "title": "狸老尸卡好", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "恐怖喜剧", "tags": ["僵尸", "民俗", "谐音梗", "黑色幽默"], "summary_short": "狸老尸卡好，2026年中国台湾电影，恐怖喜剧。游手好闲的阿狸被律师告知，从没见过的乡下姑婆将一栋三层别墅留给了他。欣喜若狂的他带着女友驱车前往，却发现这栋老宅阴气森森，更诡异的是，每晚八点，二楼大厅总会准时传来洗牌声。阿狸壮胆上楼，竟看到一群穿着寿衣、脸色铁青的“亲戚”正围在一张麻将桌前。为首的“二叔公”告诉他，姑婆生前立下规矩：谁能赢过他们，别墅就归谁；若是输了，就得留下“陪葬”。阿狸本是个麻将白痴，却不得不赶鸭子上架。他利用现代牌桌", "score": 2026334, "category": "comedy", "detail_url": "../movie/1431.html", "poster": "../posters/1431.svg"}, {"id": "1432", "title": "再见时光", "year": 2024, "region": "中国台湾", "type": "电视剧", "genre": "剧情、奇幻", "tags": ["穿越、父子和解、年代、催泪"], "summary_short": "再见时光，2024年中国台湾电视剧，剧情、奇幻。34 岁的废柴青年陈小飞，因好吃懒做、啃老被父亲陈爸爸赶出家门。两人大吵一架后，陈爸爸突发心梗去世。陈小飞懊悔不已，借酒消愁时意外触电，醒来竟回到了 1988 年的高雄。他遇到了当时只有 20 岁、还在当“打仔”（小混混）的父亲。年轻的父亲热血、讲义气、一穷二白，正疯狂地追求着“小吃西施”——也就是陈小飞后来的母亲。陈小飞想弥补遗憾，决定改造父亲，让他读书上进，远离江湖。他成功地阻止了父亲", "score": 2024253, "category": "series", "detail_url": "../movie/1432.html", "poster": "../posters/1432.svg"}, {"id": "1433", "title": "春风沉醉的夜晚", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "爱情 / 文艺", "tags": ["同性", "城市", "诗意", "禁忌"], "summary_short": "春风沉醉的夜晚，2026年中国大陆电影，爱情 / 文艺。1997年春，南京某国企科员陈宇在业余文艺汇演中认识了另一个单位的会计周明。两人同被选入交谊舞队，排练《春风沉醉的晚上》。在一次次排练的肢体接触中，情愫暗生。一个排练结束的夜晚，两人走在梧桐树下，周明忽然握住了陈宇的手。此后，他们开始在公园、废弃厂房、午夜公交车里幽会。陈宇的妻子开始怀疑，周明的妻子则直接带着娘家人上门殴打。两人约好私奔去广州，在火车站，陈宇发现周明背后被妻子用刀划", "score": 2026263, "category": "drama", "detail_url": "../movie/1433.html", "poster": "../posters/1433.svg"}, {"id": "1434", "title": "某种生活", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "文艺 / 剧情", "tags": ["北漂", "生存困境", "诗意写实", "群像", "黑白色调"], "summary_short": "某种生活，2024年中国大陆电影，文艺 / 剧情。北京五环外一栋即将拆迁的老居民楼里，六个完全不同背景的年轻人挤在三室一厅的合租房中。他们当中有人是怀揣梦想的编剧，白天送外卖晚上写剧本；有人是刚被裁员的互联网产品经理，每天假装去上班实则坐在公园发呆；有人是音乐学院毕业却只能在酒吧弹钢琴的女孩。电影以近乎纪录片的冷静视角，捕捉他们在半年内的生活碎片：一次失败的提案、一场没有告白的暗恋、一通家里打来要钱的电话。没有狗血的冲突，没有逆袭的结局", "score": 2024285, "category": "drama", "detail_url": "../movie/1434.html", "poster": "../posters/1434.svg"}, {"id": "1435", "title": "一代宗师", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "动作, 传记", "tags": ["武术", "民国", "传承", "宗师", "武打"], "summary_short": "一代宗师，2023年中国大陆电影，动作, 传记。不同于同名的王家卫作品，本片聚焦于形意拳宗师宋世荣的晚年回忆。1932年，已是花甲之年的宋世荣被日军胁迫，必须在“比武大会”上当众击败所有中国拳师，以证明“日本武术高于中国”。宋世荣想起自己年轻时的三段败绩：第一次输给师兄，他学会了谦卑；第二次输给一个卖艺的哑巴，他学会了变通；第三次输给自己的徒弟，他学会了传承。而现在，他面对的是日本剑道冠军、柔道冠军和空手道冠军。比武场上，他三次故意被击", "score": 2023329, "category": "crime", "detail_url": "../movie/1435.html", "poster": "../posters/1435.svg"}, {"id": "1436", "title": "木枯纹次郎", "year": 1972, "region": "日本", "type": "电影", "genre": "时代剧，剧情", "tags": ["浪人，复仇，宿命，剑戟"], "summary_short": "木枯纹次郎，1972年日本电影，时代剧，剧情。纹次郎是一个眼神如死灰的流浪剑客，他的过去只剩下无尽的黑暗与一场血债。他追随着仇人的踪迹，穿越被战火蹂躏的荒野，内心只有杀戮的执念。途中，他救下了一个被土匪追击的孤儿，本想置之不理，却因这孩子酷似自己死去的弟弟而无法割舍。孩子的纯真与依赖，像雨水一样，开始渗入纹次郎干裂的心田。当复仇的终点近在眼前，他终于与仇人对峙，却发现对方也在守护着自己的家人。是完成宿命的斩杀，还是放下屠刀选择宽恕？在一", "score": 1972302, "category": "drama", "detail_url": "../movie/1436.html", "poster": "../posters/1436.svg"}, {"id": "1437", "title": "邪恶力量第十四季", "year": 2018, "region": "美国", "type": "剧集", "genre": "奇幻、惊悚、剧情", "tags": ["猎魔", "天使与恶魔", "兄弟羁绊", "大结局前夜"], "summary_short": "邪恶力量第十四季，2018年美国剧集，奇幻、惊悚、剧情。本季中，山姆和迪恩发现一直隐藏在幕后的上帝（恰克）才是所有混乱的源头。为寻求创作灵感，他不断制造灾难、复活旧敌，甚至操纵兄弟的命运。路西法、米迦勒等古老势力被重新卷入棋盘。杰克在成长中面临自我毁灭的诱惑。兄弟俩联合了地狱之王罗薇娜、天使卡斯提奥，设下致命陷阱对抗全能的造物主，结尾恰克愤怒地揭开了“黑暗圣经”的最后一页。", "score": 2018321, "category": "series", "detail_url": "../movie/1437.html", "poster": "../posters/1437.svg"}, {"id": "1438", "title": "谍海艳姝", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "谍战, 悬疑, 女性", "tags": ["民国", "女特工", "多面间谍"], "summary_short": "谍海艳姝，2024年中国大陆剧集，谍战, 悬疑, 女性。舞女王绮梦是军统特工，百货公司千金白露是地下党，电影明星沈蝶则是日本特务。三人因一个共同目标——“樱花计划”文件而卷入彼此命运。她们互相试探、利用又彼此救助，形成了一种微妙的“敌人中的闺蜜”关系。随着珍珠港事件爆发，她们发现“樱花计划”背后是关于人体实验的真相。最后一集，三人分别接到命令：除掉对方。在一场雨夜码头决战中，王绮梦为救白露挡下沈蝶的子弹，沈蝶在最后一刻反水刺杀日本军官。", "score": 2024236, "category": "series", "detail_url": "../movie/1438.html", "poster": "../posters/1438.svg"}, {"id": "1439", "title": "情陷撒哈拉", "year": 2017, "region": "法国 / 摩洛哥", "type": "电影", "genre": "爱情, 冒险, 剧情", "tags": ["沙漠", "异域恋", "考古", "自我救赎", "风光"], "summary_short": "情陷撒哈拉，2017年法国 / 摩洛哥电影，爱情, 冒险, 剧情。法国地质学家克莱尔为寻找失踪两年的未婚夫兼科考队长卢克，孤身进入阿尔及利亚撒哈拉腹地。她遭沙暴迷路，被图阿雷格部落酋长萨利姆救下。在寻找卢克的过程中，克莱尔与萨利姆朝夕相处，从敌视到理解，逐渐被这个沉默寡言却充满智慧的男人吸引。当她终于在绿洲矿井找到卢克时，发现他早已变心并与本地女医生结婚，且故意隐瞒行踪骗取科研经费。克莱尔心碎之余，在萨利姆帮助下揭发卢克的学术欺诈。最后", "score": 2017382, "category": "drama", "detail_url": "../movie/1439.html", "poster": "../posters/1439.svg"}, {"id": "1440", "title": "魔棺", "year": 2017, "region": "泰国", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["棺材", "巫术", "交易", "诅咒", "东南亚邪典"], "summary_short": "魔棺，2017年泰国电影，恐怖, 惊悚。曼谷的旧货市场流传着一口名为“坤昌”的邪棺。传说只要向它献上祭品并许愿，愿望就会成真，但作为交换，棺材会随机取走你身体的一部分——一根手指、一只眼睛、一段记忆或味觉。沉迷赌博的导游阿泰许愿中彩票，第二天他中了头奖，代价是失去了左耳的听力。贪婪让他继续许愿，他想要回听力，棺材却拿走了他右腿的行走能力。绝望的阿泰推着轮椅找到了一个高僧，高僧告诉他，这口棺材的本体是一个被活活钉死在木箱里的孕妇，她的怨气", "score": 2017455, "category": "horror", "detail_url": "../movie/1440.html", "poster": "../posters/1440.svg"}, {"id": "1441", "title": "猫和老鼠2014第二季", "year": 2014, "region": "美国", "type": "剧集", "genre": "动画 / 喜剧", "tags": ["经典重启", "无对白", "暴力美学"], "summary_short": "猫和老鼠2014第二季，2014年美国剧集，动画 / 喜剧。经典动画的重启季，汤姆和杰瑞的故事背景更新到了2014年。汤姆有了智能手机和社交账号，杰瑞则学会了用无人机偷奶酪。但核心不变——汤姆永远抓不到杰瑞，而且每一次追逐都会把房子、社区、甚至整个城市搅得天翻地覆。本季新增了更多致敬经典电影的桥段，比如《盗梦空间》式的梦中追逐、《速度与激情》式的飙车戏（主角是扫地机器人）。全季依然没有任何对白，只有夸张的音效、古典配乐和汤姆偶尔发出的惨", "score": 2014250, "category": "series", "detail_url": "../movie/1441.html", "poster": "../posters/1441.svg"}, {"id": "1442", "title": "龙卷风3：上帝的怒火", "year": 2026, "region": "美国", "type": "电影", "genre": "动作 / 灾难 / 科幻", "tags": ["龙卷风", "末日", "气象武器", "视觉奇观"], "summary_short": "龙卷风3：上帝的怒火，2026年美国电影，动作 / 灾难 / 科幻。前作中，追风科学家团队成功抑制了人造龙卷风。但三年后，一个恐怖组织窃取了原始技术并升级，在北美大陆同时引爆了上百个F5级龙卷风。这些龙卷风开始相互融合、吞噬，最终形成了一个直径数十公里、风速超越任何已知标准的F6级超级风暴——“上帝之怒”。龙卷风所过之处，大地被掀去一层。退役的追风队长凯特被紧急召回，她发现唯一可能阻止灾难的方法，是在风暴核心投放一种新型冷冻剂，但这几乎", "score": 2026403, "category": "sci-fi", "detail_url": "../movie/1442.html", "poster": "../posters/1442.svg"}, {"id": "1443", "title": "圣女丽塔·达·卡西亚", "year": 1971, "region": "意大利", "type": "电影", "genre": "剧情 / 传记 / 宗教", "tags": ["圣女", "宗教", "家庭暴力", "宽恕", "荆棘"], "summary_short": "圣女丽塔·达·卡西亚，1971年意大利电影，剧情 / 传记 / 宗教。中世纪意大利，丽塔嫁给了一个性情暴烈的男子。婚后她长期忍受殴打与辱骂，却始终以祈祷回应。丈夫在一次斗殴中被杀，两个儿子发誓为父报仇，丽塔跪求他们放下仇恨，儿子们却在复仇路上意外身亡。失去一切的她申请进入卡西亚的奥斯定会修道院，却被拒绝——教会不接受寡妇。她独自在修院外祈祷数月，奇迹发生了：一天清晨，修女们发现她额头上有一个流血的伤口，形状如荆棘冠。神父认定这是圣痕，丽", "score": 1971289, "category": "drama", "detail_url": "../movie/1443.html", "poster": "../posters/1443.svg"}, {"id": "1444", "title": "山里来了熊孩子", "year": 2020, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["留守儿童", "支教", "治愈", "乡村"], "summary_short": "山里来了熊孩子，2020年中国大陆电影，剧情 / 家庭。富二代林小昊因打架斗殴被父母强制送回深山里的爷爷家。为了逃离这个没有WiFi的地方，他使尽浑身解数捣乱，却一次次被那些看似木讷实则通透的老人们化解。在这个过程中，他无意间学会了打糍粑、听懂了山歌里的故事，甚至帮老人们用直播把手工品卖了出去。当林小昊再次拿到回城的机票时，他发现那些曾经被他捉弄的“老家伙”们，已经成了他最舍不得的人。", "score": 2020245, "category": "drama", "detail_url": "../movie/1444.html", "poster": "../posters/1444.svg"}, {"id": "1445", "title": "沼泽的沉默", "year": 2024, "region": "西班牙", "type": "电影", "genre": "悬疑 / 犯罪 / 惊悚", "tags": ["连环杀手", "记者", "腐臭美学", "反转"], "summary_short": "沼泽的沉默，2024年西班牙电影，悬疑 / 犯罪 / 惊悚。西班牙南部多尼亚纳国家公园的沼泽地里，接连发现女性骸骨，每具骸骨旁都有一个朝向水面的稻草人。女记者安娜独立调查，发现警方内部有人在掩盖线索。她顺藤摸瓜，发现嫌疑人竟是一位常年拍摄沼泽风光的隐士摄影师。当安娜闯入对方暗房时，墙上贴满了受害者在水中挣扎的特写照片。摄影师告诉她：“我不是在杀人，我只是在捕捉她们被沼泽吞噬前最真实的表情。”安娜差点成为下一个，却利用对光影的反制反杀了对", "score": 2024435, "category": "crime", "detail_url": "../movie/1445.html", "poster": "../posters/1445.svg"}, {"id": "1446", "title": "流沙2016", "year": 2016, "region": "中国大陆", "type": "电影", "genre": "犯罪 / 悬疑", "tags": ["矿难", "底层", "复仇", "恶劣天气"], "summary_short": "流沙2016，2016年中国大陆电影，犯罪 / 悬疑。2016年冬，西北某私矿发生塌方，七名矿工被困在两百米深的巷道里，空气只够撑48小时。年轻的记者白鸽偶然拍到矿主非法开采的证据，却意外听到矿主在电话里下达“封矿”指令——为了掩盖更大的违法事实，他打算直接引爆炸药，伪造成自然事故炸毁一切。白鸽试图报警，却被矿主手下囚禁。井下，老矿工王叔带领工友们用血肉之躯抵抗不断渗出的流沙，他们不知道地面上的人正在宣判他们的死刑。白鸽与一名良心发现的", "score": 2016434, "category": "crime", "detail_url": "../movie/1446.html", "poster": "../posters/1446.svg"}, {"id": "1447", "title": "妖夜寻狼：血姬觉醒", "year": 2024, "region": "美国", "type": "电影", "genre": "动作，奇幻", "tags": ["吸血鬼，狼人，女战士，觉醒，史诗终章"], "summary_short": "妖夜寻狼：血姬觉醒，2024年美国电影，动作，奇幻。在《妖夜寻狼》系列终结篇中，吸血鬼死亡使者莎琳娜在北极冰棺中被封印了整整一千年。人类文明早已覆灭，狼人族进化出智慧与组织，建立全球帝国，将残存的吸血鬼和人类都圈养为血畜。一名抵抗组织成员意外用古代咒语唤醒莎琳娜，她发现自己被改造过的心脏如今分泌着唯一能穿透狼王不灭之躯的“日裔之血”。但每次使用这种力量，她就会向狼族转化一分。莎琳娜必须在彻底变成自己追杀一生的怪物之前，杀入狼族首都“獠牙", "score": 2024373, "category": "fantasy", "detail_url": "../movie/1447.html", "poster": "../posters/1447.svg"}, {"id": "1448", "title": "捉鬼有限公司", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 恐怖 / 奇幻", "tags": ["僵尸", "无厘头", "办公室政治", "道术", "讽刺"], "summary_short": "捉鬼有限公司，2024年中国香港电影，喜剧 / 恐怖 / 奇幻。陈伟和肥强经营着全港最烂的捉鬼公司“灵异清洁工”，三年只接到五单生意，还都是吓跑蟑螂这种级别。某天，互联网巨头“闪动科技”的CEO找上门，说新大楼闹鬼严重，已吓跑三批程序员，开出五百万天价订单。二人进入大楼后发现，这里的鬼全是猝死的前员工，死因分别是过劳、背锅、被优化。鬼魂们不仅不害人，还制定了严格的闹鬼排班表和OKR。更诡异的是，大楼地下机房藏着一台“怨气服务器”，它能吸", "score": 2024486, "category": "horror", "detail_url": "../movie/1448.html", "poster": "../posters/1448.svg"}, {"id": "1449", "title": "数码宝贝大冒险（剧场版）", "year": 2024, "region": "日本", "type": "剧场版动画", "genre": "冒险, 奇幻, 动作", "tags": ["童年回忆", "最终进化", "告别"], "summary_short": "数码宝贝大冒险（剧场版），2024年日本剧场版动画，冒险, 奇幻, 动作。距离太一他们第一次冒险已经过去了三十年。曾经的孩子们都已步入中年，与各自的数码宝贝因现实压力而疏远。此时，一个名为“乌托邦”的病毒入侵数码世界，将数据与现实扭曲融合。被召唤的新一代孩子——包括大和的女儿——无法独自战斗。老一代不得不拖着疲惫的身躯，重回战场。影片的核心矛盾是：当勇气徽章持有者变得畏首畏尾，当友情变得功利，他们是否还能让数码宝贝进化？最终的牺牲与告别", "score": 2024194, "category": "fantasy", "detail_url": "../movie/1449.html", "poster": "../posters/1449.svg"}, {"id": "1450", "title": "唔死呃德人", "year": 2025, "region": "中国香港", "type": "电影", "genre": "黑色喜剧 / 犯罪", "tags": ["港产片", "荒诞复仇", "小人物逆袭", "金句频出"], "summary_short": "唔死呃德人，2025年中国香港电影，黑色喜剧 / 犯罪。懦弱的会计小职员陈永仁，人生信条是“多一事不如少一事”。当他得知当年逼死父亲、如今又是顶头上司的富商高佬，竟然又要逼死另一个家庭时，他决定复仇。但他不敢杀人，于是开始了一系列荒诞的“精神折磨”：在高佬最重视的慈善晚宴上，偷偷把他的发言稿换成屎尿屁笑话；在他新车的座椅里塞满臭豆腐汁；给他最重要的商业谈判文件里，把“亿”改成“万”。高佬被搞得濒临崩溃，怀疑是商业对手所为，雇了黑社会来查", "score": 2025346, "category": "crime", "detail_url": "../movie/1450.html", "poster": "../posters/1450.svg"}, {"id": "1451", "title": "巴黎艳舞团", "year": 2018, "region": "法国", "type": "电影", "genre": "剧情， 歌舞， 女性", "tags": ["疯马秀， 幕后故事， 身体政治， 女性赋权"], "summary_short": "巴黎艳舞团，2018年法国电影，剧情， 歌舞， 女性。巴黎，疯马俱乐部后台。卡米耶、露娜、玛侬和赛琳是艳舞团的台柱，每晚为观众呈现光影与肉体的艺术。新来的年轻老板带来一个“创新方案”：用全息投影和AI换脸技术替代真人舞者，理由是“你们年纪太大了”。四位女性从惊讶到愤怒再到恐惧——她们中最年轻的28岁，最年长的36岁。老板给出最后通牒：接受“数字化改造”，把自己的脸授权给公司无限期使用，或者拿遣散费走人。影片核心是一段长达二十分钟的后台争", "score": 2018310, "category": "drama", "detail_url": "../movie/1451.html", "poster": "../posters/1451.svg"}, {"id": "1452", "title": "白雪公主杀人事件", "year": 2024, "region": "日本", "type": "电影", "genre": "悬疑， 犯罪， 剧情", "tags": ["童话改编， 反转， 社会派"], "summary_short": "白雪公主杀人事件，2024年日本电影，悬疑， 犯罪， 剧情。著名化妆品公司的新品发布会上，被誉为“白雪公主”的代言人北川诗织被发现死在了布满镜子的展厅中。实习生泽村美久因为迟到而躲过了最初的嫌疑，却无意间目睹了关键线索。警方很快锁定了与诗织有过节的前助理，但泽村坚信真凶另有其人。随着她暗中调查，诗织完美形象下的欺凌、勒索与替罪羊网络逐渐浮出水面。当所有人都以为凶手是那个疯狂的跟踪狂时，泽村却在诗织的日记本里发现了自己的照片。原来，这场杀", "score": 2024418, "category": "crime", "detail_url": "../movie/1452.html", "poster": "../posters/1452.svg"}, {"id": "1453", "title": "轰炸机之歌", "year": 2011, "region": "俄罗斯", "type": "电影", "genre": "战争 / 历史 / 剧情", "tags": ["二战", "飞行员", "战俘营", "越狱"], "summary_short": "轰炸机之歌，2011年俄罗斯电影，战争 / 历史 / 剧情。1944年，苏军飞行员格里夫佐夫在执行轰炸任务时被击落，身负重伤被俘。他被关进德军在波兰的集中营，那里关押着大量的苏联战俘。格里夫佐夫随身带着妻子送的一把银色口琴。在集中营里，他用口琴吹奏苏联歌曲鼓舞士气，被德军视为眼中钉。他联合几名不同国籍的战俘，利用在军工厂劳役的机会，暗中拆卸零件拼装一架简易滑翔机。他们必须在寒冬来临前逃出，否则将被转移到死亡营。计划的最后一步，是需要格里", "score": 2011278, "category": "doc", "detail_url": "../movie/1453.html", "poster": "../posters/1453.svg"}, {"id": "1454", "title": "欢迎来到谋杀镇", "year": 2025, "region": "美国", "type": "电视剧", "genre": "悬疑, 黑色喜剧", "tags": ["真实犯罪播客", "小镇秘密", "第四面墙"], "summary_short": "欢迎来到谋杀镇，2025年美国电视剧，悬疑, 黑色喜剧。播客主播艾娃以“冷案猎手”成名，但她的节目最近热度下滑。为了翻红，她搬进了美国著名的“谋杀镇”——一个只有三百居民、却在过去三十年间发生过六起未解谋杀案的地方。诡异的是，镇民们不仅不排斥她，反而热情地提供线索、邀请她参加家庭聚餐、甚至主动要求被采访。艾娃以为自己挖到了金矿，但她的制作人通过数据分析发现，谋杀镇的犯罪播客收听率是全国平均值的四十七倍——几乎每个居民都是她节目的忠实听众", "score": 2025345, "category": "series", "detail_url": "../movie/1454.html", "poster": "../posters/1454.svg"}, {"id": "1455", "title": "鹿鼎记2008", "year": 2008, "region": "中国香港", "type": "剧集", "genre": "喜剧、武侠、古装", "tags": ["韦小宝， 反武侠， 官场现形， 七个老婆"], "summary_short": "鹿鼎记2008，2008年中国香港剧集，喜剧、武侠、古装。改编自金庸同名小说。妓院出身的韦小宝因救下江湖好汉茅十八，阴差阳错假冒太监入宫。他凭着小聪明和如簧巧舌，与少年康熙不打不相识，结为好友。在擒杀鳌拜后，韦小宝平步青云，身兼天地会青木堂香主与朝廷要职。他周旋于皇帝、天地会、神龙教等多方势力之间，虽大字不识几个，却靠着底层生存智慧化险为夷。他抢了神龙教夫人，骗了俄国公主，最后为了“义气”二字，不愿出卖任何一方朋友，选择诈死隐退，带着七", "score": 2008216, "category": "series", "detail_url": "../movie/1455.html", "poster": "../posters/1455.svg"}, {"id": "1456", "title": "血色童心", "year": 2023, "region": "俄罗斯", "type": "剧集", "genre": "剧情 / 战争 / 悬疑", "tags": ["二战、儿童视角、回忆杀、人性考验、慢燃"], "summary_short": "血色童心，2023年俄罗斯剧集，剧情 / 战争 / 悬疑。1942年列宁格勒围城期间，六个被围困在孤儿院的孩子为了活下去，组成了一支“捡土豆小队”。他们在地下室发现了一条德军留下的秘密通道，里面藏着一箱从未启用的青霉素。70年后，唯一幸存者安德烈在养老院拿着当年的合影，对孙女说：“这里本来有六个人，但你们只能看到五个，因为第六个人的脸被我涂黑了。”孙女是一名记者，她开始调查那段被封尘的往事，发现当年拿走青霉素救了自己母亲的“小英雄”，被", "score": 2023300, "category": "series", "detail_url": "../movie/1456.html", "poster": "../posters/1456.svg"}, {"id": "1457", "title": "小木偶奇遇记", "year": 2021, "region": "意大利 / 法国", "type": "电影", "genre": "动画 / 奇幻 / 家庭", "tags": ["木偶", "成长寓言", "父与子", "真实与谎言"], "summary_short": "小木偶奇遇记，2021年意大利 / 法国电影，动画 / 奇幻 / 家庭。老木匠杰佩托在妻子病逝后，将一棵从古战场长出的橡树雕成木偶，取名匹诺曹。匹诺曹梦想变成真正的男孩，但每次说谎，鼻子不仅变长，还会浮现出战场的幻象。一个流浪的蓝发仙女告诉他：这棵橡树曾埋葬过一名战死的少年，少年的灵魂困在木头里，只有匹诺曹学会真正的“诚实”——不是不说谎，而是敢于面对悲伤——才能释放那个灵魂，而老木匠也会因此失去“儿子”。匹诺曹开始了一场关于勇气与告别", "score": 2021361, "category": "fantasy", "detail_url": "../movie/1457.html", "poster": "../posters/1457.svg"}, {"id": "1458", "title": "音响生命体", "year": 2025, "region": "日本", "type": "动画电影", "genre": "科幻 / 音乐 / 冒险", "tags": ["生物音响", "共生", "听觉奇观"], "summary_short": "音响生命体，2025年日本动画电影，科幻 / 音乐 / 冒险。未来异星“鸣响”上，所有声音都具有可视可触摸的实体形态，形成绚烂的声音森林与噪音荒漠。女主角小响是来自地球的失聪访客，她在这里是唯一听不见的“残疾人”。她被一只濒死的、外形如同巨大音响的外星生命体选中，两者通过肢体接触建立了奇异的神经系统连接，小响从此能“看见”声音的颜色和形状。音响生命体告诉她，“鸣响”星球的“源音”正在腐烂，若不及时修复，会引发整个星系的听觉崩溃。一人一兽", "score": 2025364, "category": "fantasy", "detail_url": "../movie/1458.html", "poster": "../posters/1458.svg"}, {"id": "1459", "title": "金钱万恶", "year": 2023, "region": "中国香港", "type": "电影", "genre": "剧情, 犯罪, 悬疑", "tags": ["金融", "欲望", "人性", "多线叙事"], "summary_short": "金钱万恶，2023年中国香港电影，剧情, 犯罪, 悬疑。在一个暴雨夜，一张价值三亿港币的中奖彩票被风吹碎成五片，散落在城市各个角落。拾荒老人、失意股民、黑帮马仔、即将离职的收银员和一名卧底警察，各捡到了一片。根据规则，必须凑齐所有碎片才能兑奖。于是，这五个身份迥异的人展开了一场疯狂的拼图游戏。在寻找彼此的过程中，贪欲逐渐吞噬了理智，有人背叛，有人被杀，那张原本象征着幸福的纸片，变成了一张催命符。当最后两人拿着碎片在兑换点相遇时，才发现最", "score": 2023456, "category": "crime", "detail_url": "../movie/1459.html", "poster": "../posters/1459.svg"}, {"id": "1460", "title": "中途岛战役", "year": 2019, "region": "美国", "type": "电影", "genre": "战争 / 历史 / 动作", "tags": ["二战", "海战", "航母", "真实改编"], "summary_short": "中途岛战役，2019年美国电影，战争 / 历史 / 动作。1942年，日本联合舰队司令山本五十六企图通过攻击中途岛，彻底消灭美国太平洋舰队。美军情报官罗彻福特破译了日军密码，确定了攻击目标是“AF”（中途岛）。美军在极其劣势的情况下，将仅有的三艘航母——企业号、大黄蜂号和约克城号——埋伏在中途岛东北海域。6月4日清晨，日军飞机空袭中途岛，却未能发现美军舰队。美军俯冲轰炸机群在关键时刻突破日军防空网，短短五分钟内击沉了日军三艘主力航母：赤", "score": 2019307, "category": "doc", "detail_url": "../movie/1460.html", "poster": "../posters/1460.svg"}, {"id": "1461", "title": "情癫大圣", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧 / 奇幻 / 动作", "tags": ["无厘头", "西游衍生", "爆笑", "逆袭"], "summary_short": "情癫大圣，2024年中国香港电影，喜剧 / 奇幻 / 动作。取经成功后，孙悟空成斗战胜佛，猪八戒回高老庄，唐僧讲经。只有沙僧被遗忘在流沙河，成了一名河道清洁工。某日，一个自称“月老实习生”的少女掉进河里，沙僧救起她，发现自己的真心能修复任何断裂的红线。原来沙僧前世是情劫之神，因犯了“太爱一个人”的天条被贬。月老实习生告诉他：只要帮他牵成三对“天谴之恋”，就能重返神位。于是沙僧开始满世界乱跑：帮白骨精和孙悟空牵线？给唐僧和女儿国国王制造偶", "score": 2024438, "category": "comedy", "detail_url": "../movie/1461.html", "poster": "../posters/1461.svg"}, {"id": "1462", "title": "虹猫蓝兔七侠传", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "动画 / 武侠 / 奇幻", "tags": ["童年IP，七剑合璧，国风，情怀"], "summary_short": "虹猫蓝兔七侠传，2024年中国大陆电影，动画 / 武侠 / 奇幻。本片是2006年经典动画的重启电影版。黑心虎之子黑小虎带着新魔教卷土重来，企图用七剑传人的鲜血复活魔教教主。虹猫、蓝兔已隐退多年，大奔开了酒馆，莎丽成了江湖医生，跳跳做了情报贩子。当年最年轻的逗逗已成白发老道。黑小虎逐个击破，绑架了蓝兔，逼迫七剑再次合璧。虹猫重出江湖，发现七剑剑法需要重新修炼，而他们的身体已不如从前。最终决战，七人在天门山顶拼尽最后内力催动七剑合璧，天崩", "score": 2024320, "category": "fantasy", "detail_url": "../movie/1462.html", "poster": "../posters/1462.svg"}, {"id": "1463", "title": "老友狗狗粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "喜剧，家庭，温情", "tags": ["狗狗，粤语，老街坊，治愈"], "summary_short": "老友狗狗粤语，2024年中国香港剧集，喜剧，家庭，温情。深水埗一栋即将拆迁的50年老楼，突然来了一只流浪唐狗“阿福”。阿福每天不同时间蹲在不同人家门口：早上蹲在阿婆门前，提醒她吃药；中午蹲在吵架的兄弟门前，他们就会停止争吵；傍晚蹲在自闭症小孩窗下，小孩就会开口说话。街坊们觉得神奇，开始通过阿福的行为了解彼此的秘密。原来阿婆的儿子三十年没回家，是因为和邻居争摊位；兄弟俩是因为父亲遗产反目；小孩不说话是因为目睹父母车祸。阿福带着大家一个一个", "score": 2024276, "category": "series", "detail_url": "../movie/1463.html", "poster": "../posters/1463.svg"}, {"id": "1464", "title": "我还从未去过纽约", "year": 2023, "region": "德国", "type": "电影", "genre": "剧情 / 家庭 / 公路", "tags": ["老年，遗愿清单，母女，敞篷车"], "summary_short": "我还从未去过纽约，2023年德国电影，剧情 / 家庭 / 公路。73岁的独居老人英格丽被诊断出阿尔茨海默症早期，女儿将她送进高级养老院“安享晚年”。英格丽却在一个凌晨翻墙逃走，只留下一张纸条：“我还从未去过纽约。”女儿玛莎从汉堡一路追到不莱梅港，发现母亲偷开走了邻居的复古敞篷车，车上还载着三个养老院“同伙”：一个假装瘫痪的老头、一个哑巴老太太、一条老狗。玛莎无奈加入这场疯狂的逃亡，一路上母女开始了一场迟来四十年的对话：关于母亲的舞蹈梦、", "score": 2023262, "category": "drama", "detail_url": "../movie/1464.html", "poster": "../posters/1464.svg"}, {"id": "1465", "title": "非来不可第三季", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "真人秀，旅行，文化", "tags": ["南美，探险，极限，人文，治愈"], "summary_short": "非来不可第三季，2026年中国大陆剧集，真人秀，旅行，文化。本季节目全面升级规则。四位处于事业低谷的过气明星，各自搭档一位有特殊技能的素人（丛林专家、厨师、护士等），组成四队从安第斯山脉源头出发，徒步穿越整个亚马逊雨林，终点是入海口。全程无补给，只有一台卫星电话。他们不仅要面对食人鱼、蟒蛇、原始部落，更要面对内心的恐惧和团队矛盾。过程中，过气武打明星靠真功夫赢得了土著尊重，过气女团成员用歌声化解了与另一队的冲突。最终，没有一队完赛，但所", "score": 2026204, "category": "series", "detail_url": "../movie/1465.html", "poster": "../posters/1465.svg"}, {"id": "1466", "title": "杀人牛仔裤", "year": 2024, "region": "日本", "type": "电影", "genre": "恐怖 / 喜剧 / 奇幻", "tags": ["cult", "诅咒之物", "时尚恐怖", "黑色幽默", "血腥"], "summary_short": "杀人牛仔裤，2024年日本电影，恐怖 / 喜剧 / 奇幻。二手服装店老板阿悟收到一条来历不明的复古牛仔裤，版型完美，洗水漂亮。但诡异的是，每一个买走它的顾客都离奇死亡：第一个是跟风买它的男大学生，穿着它去相亲，突然暴起用皮带勒死自己；第二个是中年女会计，下班路上突然冲进裁缝店求拆裤脚，被缝纫机针扎穿喉咙。阿悟惊恐中发现规律：牛仔裤会寄生在“失去个人审美、完全随大流”的人身上，当穿着者打开衣柜发现全是网红爆款、没有一件能表达自我时，它就会", "score": 2024449, "category": "horror", "detail_url": "../movie/1466.html", "poster": "../posters/1466.svg"}, {"id": "1467", "title": "巴黎必娶女王", "year": 2025, "region": "法国 / 韩国", "type": "剧集", "genre": "爱情 / 喜剧", "tags": ["韩法合拍", "时尚", "姐弟恋", "职场"], "summary_short": "巴黎必娶女王，2025年法国 / 韩国剧集，爱情 / 喜剧。巴黎，时尚之都。40岁的时尚杂志总编克莱尔被称为“巴黎必娶女王”——刻薄、挑剔、不近人情，三年换了七个助理，整个时尚圈都怕她。一个韩国实习生金敏俊被分配到她手下，所有人都等着看这个东方男孩被骂哭的样子。但敏俊的反应出乎所有人意料：克莱尔骂他，他笑着点头说“谢谢指导”；克莱尔让他通宵改稿，他第二天精神抖擞地出现；克莱尔故意刁难他，他用韩国职场学到的厚脸皮一一化解。更让克莱尔抓狂的", "score": 2025337, "category": "series", "detail_url": "../movie/1467.html", "poster": "../posters/1467.svg"}, {"id": "1468", "title": "捍卫战士", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 战争 / 剧情", "tags": ["战斗机飞行员，父子传承，空中激战，硬核"], "summary_short": "捍卫战士，2024年美国电影，动作 / 战争 / 剧情。传奇飞行员“独行侠”的儿子“鹰爪”在执行秘密任务时，被敌方新型防空系统击落，跳伞后被恐怖组织俘虏。军方拒绝营救，因为涉及政治敏感区域。60岁的独行侠已退役多年，他偷偷潜入空军基地，偷走了一架即将退役的F-14雄猫战斗机（和他当年开的一样）。他单机深入1500公里，利用老旧战机的机动性和自己四十年的飞行经验，在峡谷中与五架苏霍伊战机周旋。他炸毁雷达站、超低空突防，最终锁定儿子被困的村", "score": 2024305, "category": "drama", "detail_url": "../movie/1468.html", "poster": "../posters/1468.svg"}, {"id": "1469", "title": "完美帝国", "year": 2026, "region": "美国", "type": "电视剧", "genre": "科幻、惊悚、悬疑", "tags": ["乌托邦、脑机接口、反抗军、记忆篡改"], "summary_short": "完美帝国，2026年美国电视剧，科幻、惊悚、悬疑。2099年，人类生活在“完美帝国”系统中，每个人的社会信用分决定了其衣食住行乃至生死。主角伊森是常年徘徊在及格线下的底层清洁工，意外救下了从高空坠落、记忆混乱的最高分女议员爱丽丝。爱丽丝脑中植入的芯片显示她被“格式化”过，她隐约记得帝国建立之初，是用一场大屠杀清除“低分者”的。伊森联合地下反抗组织，试图恢复爱丽丝被删除的记忆。随着真相浮出水面，他们发现维持帝国运转的能量来源，竟然是数以亿", "score": 2026447, "category": "series", "detail_url": "../movie/1469.html", "poster": "../posters/1469.svg"}, {"id": "1470", "title": "巨星汤美", "year": 1995, "region": "香港", "type": "电影", "genre": "剧情", "tags": ["娱乐圈", "替身", "心理惊悚", "黑色幽默"], "summary_short": "巨星汤美，1995年香港电影，剧情。童星出身的汤美在三十岁后沦为无人问津的过气艺人，只能靠做当红明星的动作替身勉强维生。一次片场意外后，他发现自己的经纪人私下招募了一名外貌、声音甚至DNA都与他完全相同的“复制替身”，开始全面接管他的社交账号、前女友以及未拍完的戏约。汤美试图揭露真相，却发现自己身边的所有人都更喜爱那个“完美版本”的他。在虚实错乱的追杀与镜像对决中，他必须在一场直播颁奖礼上向全世界证明——谁才是真正的巨星汤美。", "score": 1995299, "category": "drama", "detail_url": "../movie/1470.html", "poster": "../posters/1470.svg"}, {"id": "1471", "title": "太阳神父月亮修女", "year": 2023, "region": "意大利 / 法国", "type": "电影", "genre": "剧情 / 宗教 / 历史", "tags": ["修道院", "信仰", "权力", "救赎", "中世纪"], "summary_short": "太阳神父月亮修女，2023年意大利 / 法国电影，剧情 / 宗教 / 历史。1348年，黑死病席卷欧洲。年轻神父卢卡坚信上帝降罚人间，用极端苦修与布道聚拢信徒，人称“太阳神父”。与此同时，博学的修女艾格尼丝因质疑教会对瘟疫的解释——认为应科学隔离而非祷告，被修道院驱逐，被信徒嘲笑为“月亮修女”。两人在瘟疫重灾区佛罗伦萨郊外相遇。起初卢卡视她为异端，艾格尼丝则认为卢卡是盲信者。但随着死亡人数飙升，卢卡亲眼目睹“虔诚者”纷纷病死，而艾格尼丝", "score": 2023308, "category": "drama", "detail_url": "../movie/1471.html", "poster": "../posters/1471.svg"}, {"id": "1472", "title": "战士第二季", "year": 2020, "region": "美国", "type": "剧集", "genre": "动作", "tags": ["功夫", "黑帮", "19世纪", "唐人街", "暴力美学"], "summary_short": "战士第二季，2020年美国剧集，动作。承接第一季结尾，堂主被暗杀后唐人街权力真空。主角阿山为寻找妹妹继续在两大黑帮间周旋。爱尔兰帮利用铁路工人失业潮煽动排华暴动，警局则想坐收渔利。第二季加入了华人女性帮派“红扇”，她们表面是妓女和洗衣工，暗地里用飞针和匕首暗杀敌人。阿山教爱尔兰工头女儿功夫的这条线引发巨大争议，但也成为唯一的外交窗口。季终大决战，四股势力在暴雨中的唐人街展开冷兵器巷战，阿山的妹妹从幕后走出，成了新的统治者。", "score": 2020265, "category": "series", "detail_url": "../movie/1472.html", "poster": "../posters/1472.svg"}, {"id": "1473", "title": "告白", "year": 2027, "region": "日本", "type": "电影", "genre": "悬疑, 犯罪", "tags": ["复仇", "校园", "反转"], "summary_short": "告白，2027年日本电影，悬疑, 犯罪。在一个学期的结业式上，初中老师森口悠子平静地向她混乱的二年级班级“告白”。她四岁的女儿爱美，被发现在学校泳池溺亡。警方认定为意外，但森口知道，凶手是她班上的两名学生——天才少年A和懦弱的少年B。她告诉全班，自己已经在凶手喝的牛奶中注入了感染艾滋病毒的血浆。整个班级瞬间崩溃，猜忌和恐惧如野火般蔓延。少年A和B更是陷入极度的心理折磨。但这仅仅是森口复仇的开始。她辞去教职，以另一种身份潜入社会，精心策划", "score": 2027380, "category": "crime", "detail_url": "../movie/1473.html", "poster": "../posters/1473.svg"}, {"id": "1474", "title": "酒佬巨声", "year": 2019, "region": "中国香港", "type": "电影", "genre": "剧情，音乐，励志", "tags": ["街头歌手，酒鬼，父女情，港乐情怀"], "summary_short": "酒佬巨声，2019年中国香港电影，剧情，音乐，励志。曾捧红无数天王天后的金牌监制高佬，因十年前一桩抄袭丑闻身败名裂，从此沉溺酒精，在深水埗的夜市捡垃圾为生。一个夜晚，他被一个稚嫩却极具爆发力的街头歌声吸引。女孩小葵靠卖唱养活在老人院的痴呆母亲。高佬醉醺醺地嘲笑她的唱法，却在过招中发现，她唱的正是自己当年未发表的遗作。原来，小葵就是自己与前妻的女儿。为了赎罪，高佬决定戒酒，用最后的生命教导小葵真正的歌唱技巧，帮她参加选秀。然而，当年陷害他", "score": 2019284, "category": "drama", "detail_url": "../movie/1474.html", "poster": "../posters/1474.svg"}, {"id": "1475", "title": "异种", "year": 2024, "region": "美国 / 英国", "type": "电影", "genre": "科幻 / 恐怖", "tags": ["深海", "变异", "生态恐怖"], "summary_short": "异种，2024年美国 / 英国电影，科幻 / 恐怖。马里亚纳海沟，深海科考船“深渊号”采集到一种前所未见的发光微生物。当晚，样本在培养皿中极速进化，从单细胞到多细胞，从无脊椎到脊椎，最终突破安全罩，杀死两名研究员。它似乎在学习，每一次脱皮都变得更像人类。科考队被困在海底数千米的船舱内，这个“异种”不仅能模仿遇难者的声音，还能读取他们的恐惧记忆。队长发现，异种的进化并非随机，它在模仿船舱里最强的那个猎人——也就是他们自己。", "score": 2024420, "category": "horror", "detail_url": "../movie/1475.html", "poster": "../posters/1475.svg"}, {"id": "1476", "title": "影子军队", "year": 2023, "region": "法国", "type": "剧集", "genre": "战争 / 剧情 / 历史", "tags": ["二战", "抵抗运动", "间谍", "法国", "牺牲"], "summary_short": "影子军队，2023年法国剧集，战争 / 剧情 / 历史。1943年里昂，法国抵抗运动的一支小分队在纳粹眼皮底下运作。成员包括：一个银行家、一个妓女、一个犹太教师、一个德国逃兵。他们负责传递情报、炸毁铁路、暗杀盖世太保。行动一次次失败，队友一个个被捕，没有人投降，所有人都在刑讯室里沉默到死。最终只有银行家活到了战争结束，他在无名烈士墓前放了一朵玫瑰，对着空气说：“我替你们活着。”", "score": 2023186, "category": "series", "detail_url": "../movie/1476.html", "poster": "../posters/1476.svg"}, {"id": "1477", "title": "黄山伐", "year": 2023, "region": "韩国", "type": "电影", "genre": "战争 / 历史 / 动作", "tags": ["古代战役", "山地战", "兄弟对决", "史诗"], "summary_short": "黄山伐，2023年韩国电影，战争 / 历史 / 动作。公元660年，朝鲜半岛三国鼎立。新罗名将金钦的弟弟十年前被百济俘虏，如今已成为百济军中的悍将。黄山平原之战一触即发，金钦奉命率五千新罗军对抗百济主力。战争前夜，弟弟潜入新罗军营，请求哥哥投降，被断然拒绝。决战当日，两军在山谷中血战，兄弟二人在尸山血海中相遇。金钦用刀背击晕弟弟，将他绑在树上，随后率军奇迹般获胜。战后，金钦亲自向新罗王求情，赦免了弟弟。兄弟相拥的一幕，让残酷的战争有了片", "score": 2023276, "category": "doc", "detail_url": "../movie/1477.html", "poster": "../posters/1477.svg"}, {"id": "1478", "title": "一只想变成汉堡的小牛", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "动画 / 儿童 / 喜剧", "tags": ["成长， 自我认同， 幽默， 冒险， 治愈"], "summary_short": "一只想变成汉堡的小牛，2023年中国大陆电影，动画 / 儿童 / 喜剧。欢欢是牧场里最快乐的小牛，直到它听说了“屠宰场”和“牛排”。为了逃命，它决定改变命运：不是变成牛排，而是变成汉堡！因为在它有限的认知里，汉堡住在游乐场的餐车上，天天听欢快的音乐。欢欢拉着好友小鸡咕咕、小猪胖胖开始了“变身大作战”：跳进面粉堆把自己裹成面包胚、偷吃生菜假装是蔬菜层、甚至跳进番茄酱池里。牧场的动物们都笑它傻，但欢欢坚信只要“配料齐了”，人类就会把它送去游", "score": 2023251, "category": "fantasy", "detail_url": "../movie/1478.html", "poster": "../posters/1478.svg"}, {"id": "1479", "title": "像妖惊魂", "year": 2024, "region": "中国香港 / 马来西亚", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["降头", "民俗恐怖", "替身", "复仇", "山村"], "summary_short": "像妖惊魂，2024年中国香港 / 马来西亚电影，恐怖 / 惊悚。都市女孩林佩佩嫁给马来西亚华裔男友，随他回到偏远山村举办传统婚礼。初到婆家，她就觉得气氛诡异：婆婆总在深夜对着神龛喃喃自语；村里女人都穿着同样的红衣，低着头走路。更恐怖的是，一次偶然，林佩佩掀开一个女人的头纱，发现对方的脸竟然和自己一模一样！原来，这个村庄世世代代都在进行一种“借皮降头”的仪式。婆婆年轻时因生不出儿子被欺凌，她决心让儿子娶一个“完美”的城市女孩回来，然后用降", "score": 2024382, "category": "horror", "detail_url": "../movie/1479.html", "poster": "../posters/1479.svg"}, {"id": "1480", "title": "成吉思汗", "year": 2027, "region": "中国大陆 / 蒙古", "type": "剧集", "genre": "历史 / 战争 / 传记", "tags": ["史诗战争", "草原枭雄", "权力博弈", "冷兵器美学", "领袖成长"], "summary_short": "成吉思汗，2027年中国大陆 / 蒙古剧集，历史 / 战争 / 传记。本剧从铁木真九岁丧父、部族离散讲起，展现他在绝境中依靠胆识与兄弟情谊逐步统一蒙古各部。不同于以往单方面颂扬帝王功绩的叙事，剧集着重刻画他在友情、背叛、亲情与家国大义之间的内心撕扯。通过三次关键战役——合阑真沙陀之战、阔亦田之战与乃蛮部决战——塑造了一位有血有肉的征服者。同时，剧中也大量呈现草原文化、萨满信仰与游牧社会的复杂结构，让观众理解“大蒙古国”并非一人之功。最终", "score": 2027246, "category": "doc", "detail_url": "../movie/1480.html", "poster": "../posters/1480.svg"}, {"id": "1481", "title": "萌牛费迪南", "year": 2025, "region": "美国", "type": "Movie", "genre": "动画，冒险，喜剧", "tags": ["反战，和平主义，农场，竞技，友情"], "summary_short": "萌牛费迪南，2025年美国Movie，动画，冒险，喜剧。在西班牙的“勇敢公牛”农场，小公牛们从小被灌输“战斗是荣耀”的思想。唯独费迪南对顶角和角斗毫无兴趣，它最喜欢趴在树荫下闻花香。当它因体格健壮被选中参加马德里斗牛大赛时，费迪南在午夜逃出农场，混上了一辆开往法国的火车。在旅途中，它结识了一群疯狂的农场动物：梦想成为歌手的山羊、患有洁癖的猪。然而斗牛士追踪而来，费迪南不得不回到赛场。当全场高呼“杀死它”时，费迪南却面对斗牛士坐了下来，将", "score": 2025127, "category": "fantasy", "detail_url": "../movie/1481.html", "poster": "../posters/1481.svg"}, {"id": "1482", "title": "字画情缘", "year": 2025, "region": "中国香港/日本", "type": "电影", "genre": "爱情/悬疑", "tags": ["书法", "古画", "跨文化", "治愈"], "summary_short": "字画情缘，2025年中国香港/日本电影，爱情/悬疑。天才书画修复师阿重在一次意外中双目失明，从此隐退。他受日本一家博物馆所托，修复一幅据说是宋徽宗所作的《听雨图》。奇怪的是，每次触摸这幅画，阿重都能“听到”画中有女人在哭泣。为了破解谜团，他请来了同样来博物馆参观的失语症女孩小默当他的“眼睛”，描述画作的细节。小默虽然不能说话，但对色彩极其敏感。在两人的合作下，他们发现这幅画里不仅藏着颜料的秘密，还夹着一张用药水写成的“血书”，记载了靖康", "score": 2025428, "category": "romance", "detail_url": "../movie/1482.html", "poster": "../posters/1482.svg"}, {"id": "1483", "title": "我们做朋友吧", "year": 2021, "region": "法国", "type": "电影", "genre": "剧情, 儿童", "tags": ["校园", "边缘人", "友谊"], "summary_short": "我们做朋友吧，2021年法国电影，剧情, 儿童。13岁的里奥因为严重口吃，每到新学校都会被霸凌。这次他学聪明了，盯上了全校最孤僻但没人敢惹的天才少年阿莱克斯。阿莱克斯沉迷昆虫研究，对社交零兴趣。里奥提出用每周20欧元雇佣他做“午餐朋友”，只要在食堂坐在一起就行。阿莱克斯为了给死去的萤火虫买标本盒，接受了交易。两人开始别扭的“陪吃”关系，阿莱克斯教里奥用唱歌的方式克服口吃，里奥则帮阿莱克斯赶走嘲笑他养蜘蛛的人。当里奥的钱被偷，阿莱克斯却继", "score": 2021241, "category": "drama", "detail_url": "../movie/1483.html", "poster": "../posters/1483.svg"}, {"id": "1484", "title": "兽性", "year": 2024, "region": "韩国", "type": "电影", "genre": "犯罪动作", "tags": ["卧底，黑帮，人性考验，暴力美学，双雄"], "summary_short": "兽性，2024年韩国电影，犯罪动作。缉毒警姜仁秀被派去东南亚，卧底进入一个走私苏门答腊虎的黑帮“兽穴”。三年间，他为了保护身份，亲手杀过线人，也眼睁睁看着同伴被老虎咬死。当上级终于下令收网时，姜仁秀拒绝归队，因为他已经爱上了黑帮老大的妹妹，并且自己也染上了“兽性”——他享受厮杀时的肾上腺素。新任检察官李道贤奉命抓捕他，两人曾是警校好友。在一场雨夜的废弃动物园对决中，姜仁秀放出走私的老虎攻击李道贤，却在老虎扑向老友的瞬间，开枪打死了自己养", "score": 2024335, "category": "crime", "detail_url": "../movie/1484.html", "poster": "../posters/1484.svg"}, {"id": "1485", "title": "战地巨蟒", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 科幻, 恐怖", "tags": ["基因改造", "战争怪兽", "丛林激战", "血腥"], "summary_short": "战地巨蟒，2025年美国电影，动作, 科幻, 恐怖。在东南亚某国的丛林深处，美军一支特种部队奉命抓捕一名叛变的科学家。该科学家曾参与“潘多拉”计划——培育巨型蟒蛇作为生物武器。当他们抵达基地时，发现这里已成废墟。军方高层为了清扫痕迹，下令启动了最高级别的“清道夫”巨蟒。这条巨蟒体型超过50米，皮肤可防弹，且拥有热感应能力。特种部队不仅要面对游击队的伏击，更要躲避这条智慧极高、速度极快的巨蟒追杀。随着队伍伤亡惨重，队长发现这条巨蟒正在利用", "score": 2025527, "category": "horror", "detail_url": "../movie/1485.html", "poster": "../posters/1485.svg"}, {"id": "1486", "title": "感伤的宿命", "year": 2023, "region": "日本", "type": "电影", "genre": "剧情 / 爱情", "tags": ["宿命", "悲剧美学", "时间轮回", "虐恋"], "summary_short": "感伤的宿命，2023年日本电影，剧情 / 爱情。摄影师林晓与作家陈默一见钟情，却在第七天因意外永别。林晓醒来发现时间重置到相遇那天，她试图改变轨迹，却发现无论怎样选择，陈默都会在第七天消失。经过数十次轮回，林晓终于明白这不是意外，而是两人灵魂契约的考验——唯有学会真正的“告别”，才能打破宿命。最终她选择在第七天平静地陪陈默看完日落，含泪说出再见。时间继续流动，一年后林晓在展览上看到了陈默生前留下的最后一组照片，标题是《感伤的宿命》。", "score": 2023308, "category": "drama", "detail_url": "../movie/1486.html", "poster": "../posters/1486.svg"}, {"id": "1487", "title": "王国：北方的阿信", "year": 2021, "region": "韩国", "type": "电影", "genre": "古装，丧尸，动作，惊悚", "tags": ["生死草，复仇，女战士，王权阴谋"], "summary_short": "王国：北方的阿信，2021年韩国电影，古装，丧尸，动作，惊悚。故事发生在《王国》第二季之前。阿信是居住在朝鲜王国北部的女真族后裔，整个族群因被诬陷通敌而惨遭屠戮。侥幸存活的她被迫为朝廷效力，沦为最底层的探子。在长年累月的屈辱与等待中，她发现了一场涉及王权、贵族与神秘“生死草”的惊天阴谋。阿信利用丧尸的力量展开血腥报复，最终从受害者蜕变为操纵黑暗的复仇女王，其命运与整个王国的存亡紧紧缠斗在一起。", "score": 2021350, "category": "horror", "detail_url": "../movie/1487.html", "poster": "../posters/1487.svg"}, {"id": "1488", "title": "少年天子", "year": 2026, "region": "中国大陆", "type": "电视剧集", "genre": "历史，古装", "tags": ["权谋，成长，宫廷，少年"], "summary_short": "少年天子，2026年中国大陆电视剧集，历史，古装。该剧聚焦清朝顺治帝的青春期。少年福临虽贵为天子，却被摄政王多尔衮视为傀儡，被母后孝庄以“为江山社稷”之名严厉管教。第一集中，他甚至因为贪玩而被迫看着自己最心爱的太监被杖毙。此后的剧情围绕顺治如何暗中培植自己的亲信“安亲王”，如何在科举中安插人才，以及如何处理与董鄂妃之间不被允许的爱情展开。他不断在暴怒与隐忍间切换，用早熟的权术逐一扳倒政敌，但当他真正掌握大权时，发现自己已经失去了童年、友", "score": 2026159, "category": "series", "detail_url": "../movie/1488.html", "poster": "../posters/1488.svg"}, {"id": "1489", "title": "我的同居小仙", "year": 2023, "region": "中国大陆", "type": "电视剧", "genre": "喜剧, 爱情, 奇幻", "tags": ["修仙", "都市", "甜宠", "反差萌", "同居"], "summary_short": "我的同居小仙，2023年中国大陆电视剧，喜剧, 爱情, 奇幻。修仙界的小仙“灵芝”在渡飞升天劫时，被一道走偏的闪电劈中，掉进了凡间程序员陈默的合租房里。灵芝法力尽失，必须在人间攒够功德才能重回仙界。她一本正经地说要报救命之恩，方式让陈默哭笑不得：她用修仙界的阵法原理，帮陈默写了一套没有bug的AI代码；她用炼丹炉改造了扫地机器人，让它学会了骂人。陈默所在的公司面临破产，这套代码成了救命稻草。但竞争对手公司派来商业间谍，同时仙界执法者赶来", "score": 2023409, "category": "series", "detail_url": "../movie/1489.html", "poster": "../posters/1489.svg"}, {"id": "1490", "title": "八零小辣椒", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "年代, 家庭, 喜剧", "tags": ["八零年代", "童养媳", "逆袭", "女性成长", "怀旧"], "summary_short": "八零小辣椒，2024年中国大陆电视剧，年代, 家庭, 喜剧。1982年，八岁的辣椒被亲生父亲用八十块钱卖到邻村做童养媳。婆家让她干活、不让她上学，辣椒却偷着学、捡着书读。十五岁那年，她瞒着婆家参加了中考，成了全县第三名。录取通知书送到那天，婆家把通知书撕了，辣椒却把碎片一片片粘好，站在村口对着所有人大声念出了上面的每一个字。从童养媳到大学生，从被嫌弃的女孩到全村第一个女干部，辣椒用半辈子走出了那条泥巴路。", "score": 2024252, "category": "series", "detail_url": "../movie/1490.html", "poster": "../posters/1490.svg"}, {"id": "1491", "title": "史瑞克的万圣游戏", "year": 2026, "region": "美国", "type": "动画电影", "genre": "喜剧, 奇幻", "tags": ["恶搞童话", "万圣节", "变身诅咒", "吐槽向"], "summary_short": "史瑞克的万圣游戏，2026年美国动画电影，喜剧, 奇幻。史瑞克本想安安静静和家人过万圣节，却被驴子怂恿参加“不给糖就捣蛋”大赛。意外触发了古老巫婆的诅咒，他每敲开一扇门就会变成不同的恐怖片反派——从弗莱迪到杰森，从鬼修女到小丑潘尼怀斯。菲奥娜和靴子猫必须在他彻底忘记自己是谁之前，解开诅咒背后的情感真相：史瑞克内心深处最怕的，不是变成怪物，而是家人不再需要他。", "score": 2026310, "category": "fantasy", "detail_url": "../movie/1491.html", "poster": "../posters/1491.svg"}, {"id": "1492", "title": "咖非正义", "year": 2023, "region": "中国台湾", "type": "剧集 (18集)", "genre": "剧情 / 喜剧 / 悬疑", "tags": ["咖啡，律所，黑色幽默，单元破案"], "summary_short": "咖非正义，2023年中国台湾剧集 (18集)，剧情 / 喜剧 / 悬疑。前检察官莫妮卡、被吊销执照的黑心律師阿狗、以及患有社恐的天才黑客小欧，三人合伙开了一间名为“咖非正义”的咖啡馆。咖啡馆的二楼是非法律所，专门接那些无法通过正常法律途径解决的委托：被AI换脸毁掉一生的主播、争夺狗孙子抚养权的爷爷奶奶、死在元宇宙里的游戏账号继承人……他们用灰色手段去对抗不公，每次行动都游走在法律边缘。直到有一天，他们收到一个包裹，里面装着最高法院大法官", "score": 2023394, "category": "series", "detail_url": "../movie/1492.html", "poster": "../posters/1492.svg"}, {"id": "1493", "title": "喋血双雄粤语", "year": 2026, "region": "中国香港", "type": "电影", "genre": "动作 / 犯罪 / 剧情", "tags": ["杀手", "警探", "宿敌变战友", "双雄", "港味暴力美学"], "summary_short": "喋血双雄粤语，2026年中国香港电影，动作 / 犯罪 / 剧情。杀手阿鬼接最后一单时被雇主出卖，中了埋伏，女友惨死。卧底警探阿豪的身份曝光，被警队当做弃子，家人被黑帮绑架。两人同时追查到幕后黑手竟是同一人——黑白两道通吃的慈善家金先生。但他们没有结成同盟，因为阿鬼的女友是阿豪在卧底期间间接害死的，而阿豪的弟弟是被阿鬼误杀的。他们在地下车库第一次见面就打断了对方三根肋骨。金先生设下圈套，让两人以为对方是来杀自己的，却在最后一刻放出消息：他", "score": 2026373, "category": "crime", "detail_url": "../movie/1493.html", "poster": "../posters/1493.svg"}, {"id": "1494", "title": "邪典之梦中梦", "year": 2023, "region": "美国", "type": "电影", "genre": "恐怖， 悬疑", "tags": ["梦境， 邪教， 多层， 心理"], "summary_short": "邪典之梦中梦，2023年美国电影，恐怖， 悬疑。小有名气的恐怖片编剧尼尔，被严重的失眠症和诡异的噩梦折磨。梦中，他总在一个地下教堂里，目睹一群身穿长袍的邪教徒举行献祭仪式，被献祭者的脸每次都清晰无比。他把这些噩梦写成剧本，大受好评。然而一天，他在公寓楼下新开的咖啡店墙上，看到了一张老旧社区照片，照片里赫然是他梦中的教堂入口。尼尔开始调查，发现这栋公寓楼在六十年前曾是一个邪教的据点，其教主宣称能通过“梦之门户”进入一个更高级的现实。随着他", "score": 2023395, "category": "horror", "detail_url": "../movie/1494.html", "poster": "../posters/1494.svg"}, {"id": "1495", "title": "温暖的客栈", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "剧情，治愈", "tags": ["民宿，人际关系，慢生活，群像"], "summary_short": "温暖的客栈，2025年中国大陆剧集，剧情，治愈。大理古城，客栈“温暖”濒临倒闭。社恐老板娘静静每天躲在后院种花。新来的厨师老马刀工惊人，但一提来历就沉默——他原是上海米其林餐厅主厨，因拒绝用地沟油被餐饮集团封杀。前台小北算账极快，可他每晚都要用三把锁锁门——他曾是黑帮会计，正被追杀。三个有故事的人，加上一只捡来的瘸腿猫，接待着形形色色的客人：离婚后来寻找自己的中年女人、想自杀却被救下的过气歌手、偷了公司钱逃到这里却悔悟的实习生。每个人都", "score": 2025192, "category": "series", "detail_url": "../movie/1495.html", "poster": "../posters/1495.svg"}, {"id": "1496", "title": "纪伯伦哈利勒：先知", "year": 2025, "region": "黎巴嫩", "type": "电影", "genre": "剧情/传记/哲思", "tags": ["文学改编", "流亡诗人", "东西方对话", "唯美镜头"], "summary_short": "纪伯伦哈利勒：先知，2025年黎巴嫩电影，剧情/传记/哲思。影片以纪伯伦在纽约的流亡岁月为主线，讲述他如何在疾病、贫困与对故土的思念中，创作出代表作《先知》。故事从1920年开始，纪伯伦在纽约的公寓里同时面对来自阿拉伯世界保守派的攻击和西方出版商的诱惑。他的爱人兼资助人玛丽·哈斯克尔始终陪伴在侧，但他们的爱情注定无法圆满。电影采用“剧中剧”结构，穿插《先知》中关于爱、婚姻、孩子、自由等26个篇章的视觉化呈现，每个篇章都以梦幻般的手绘动画", "score": 2025312, "category": "drama", "detail_url": "../movie/1496.html", "poster": "../posters/1496.svg"}, {"id": "1497", "title": "乾隆下扬州", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "古装 / 喜剧 / 悬疑", "tags": ["历史改编", "美食", "探案", "民间传奇", "反套路"], "summary_short": "乾隆下扬州，2024年中国大陆电影，古装 / 喜剧 / 悬疑。乾隆南巡的真实目的从未被记载。野史传说他爱上了扬州一道菜，本片给出另一种可能：江南盐帮因一张“盐铁秘谱”被灭门，这张谱能做出引发财政崩溃的“假盐”。乾隆带着和珅、纪晓岚微服私访，伪装成美食家逐户试菜。线索指向一个盲眼厨娘，她做的狮子头总多一味“不该有的鲜”。当最后一道菜端上来，乾隆才惊觉：厨娘是盐帮遗孤，而灭门令恰恰是自己下的。这顿饭，是复仇的开始。", "score": 2024378, "category": "costume", "detail_url": "../movie/1497.html", "poster": "../posters/1497.svg"}, {"id": "1498", "title": "铁证悬案第一季", "year": 2024, "region": "美国", "type": "剧集", "genre": "犯罪 / 悬疑", "tags": ["陈年旧案", "科技破案", "社会变迁", "单元剧"], "summary_short": "铁证悬案第一季，2024年美国剧集，犯罪 / 悬疑。资深警探米勒带领一支由数据专家、遗传学家和心理学教授组成的冷案组，专门侦破五年以上的未结案件。第一季共10集，每集聚焦一个旧案：1995年迪厅火灾中的“无名女尸”，通过DNA追溯发现她竟是2010年才失踪的人；2001年“9·11”期间失踪的一名穆斯林外卖员，真相指向政府秘密监控计划；1988年同性恋社区杀手案，凶手早已死亡，但新的模仿犯出现了。主线贯穿始终：米勒自己的搭档在2008年", "score": 2024340, "category": "series", "detail_url": "../movie/1498.html", "poster": "../posters/1498.svg"}, {"id": "1499", "title": "差利误中美人计", "year": 1988, "region": "中国香港", "type": "电影", "genre": "喜剧 / 动作", "tags": ["默片致敬，乌龙侦探，追女仔"], "summary_short": "差利误中美人计，1988年中国香港电影，喜剧 / 动作。在夜总会模仿卓别林为生的阿星，因欠债被追打，阴差阳错穿上了卓别林戏服躲进一家侦探社。侦探社老板误以为他是同行，将一单跟踪富家千金珍妮的委托丢给他。阿星为了报酬硬着头皮上阵，用默片式的滑稽方式跟踪珍妮，一路闹出无数笑话。但他逐渐发现，珍妮并非单纯的富家女，她手中有一串能打开银行保险柜的钥匙项链，而跟踪她的不止阿星一人——还有来自香港、日本和三地的三伙珠宝大盗。阿星被迫用他唯一的“技能", "score": 1988323, "category": "crime", "detail_url": "../movie/1499.html", "poster": "../posters/1499.svg"}, {"id": "1500", "title": "夺命电话", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖， 惊悚， 悬疑", "tags": ["电话， 诅咒， 铃声， 都市传说， 死亡预言"], "summary_short": "夺命电话，2026年美国电影，恐怖， 惊悚， 悬疑。都市传说：有一串神秘号码，用任何老式转盘座机拨打，可以打给七年前的自己。但通话结束后，七天之内，你会以一种与“未来自己”相同的方式死去。女主哈珀是一名网络主播，为了流量，她找到了那部传说中的座机，拨通了七年前的号码。她警告当年的自己不要和某个男人恋爱。通话结束，当晚她的手臂出现一道烧灼伤。第二天，伤口变成咬痕。第三天，变成刀伤。她发现每一种伤都对应着未来七年后“某个版本的她”的死法——", "score": 2026487, "category": "crime", "detail_url": "../movie/1500.html", "poster": "../posters/1500.svg"}, {"id": "1501", "title": "雪中真相", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "悬疑, 犯罪, 剧情", "tags": ["东北雪乡", "杀人回忆结构", "基层警察", "时代悲剧"], "summary_short": "雪中真相，2026年中国大陆电影，悬疑, 犯罪, 剧情。2025年冬，黑龙江某林场，暖冬导致冰河提前解冻，一具被冻了二十年的男尸浮出水面。死者是2005年失踪的外来教师张秋生。全林场只有一个人记得他——片警老韩，那年他刚参加工作，第一个报失踪案就是张秋生，但当年没人当回事。老韩还有三个月退休，他决定用最后的时间查清这个案子。雪乡的冬天零下三十度，他骑着摩托车挨家挨户走访，发现当年接触过张秋生的人，有的疯了，有的搬走了，有的什么都不肯说。", "score": 2026429, "category": "crime", "detail_url": "../movie/1501.html", "poster": "../posters/1501.svg"}, {"id": "1502", "title": "图腾", "year": 2025, "region": "加拿大", "type": "电影", "genre": "悬疑，奇幻，剧情", "tags": ["原住民文化，动物灵魂，身份认同，自然信仰"], "summary_short": "图腾，2025年加拿大电影，悬疑，奇幻，剧情。19岁的阿娜卡是城市长大的原住民，从不说母语，也不信图腾。祖母临终前交给她一块木头碎片，告诉她这是家族图腾柱的核心，拥有它可以召唤森林里所有动物的灵魂。当晚，一群穿黑色制服的神秘猎人闯入葬礼，要抢走碎片。阿娜卡被迫逃回祖母居住的北方森林，在逃亡路上，她陆续唤醒了狼、鹰、鲑鱼和熊的灵魂。每个动物灵魂都教会她一段家族历史：曾祖母曾用图腾柱拯救部落，祖父是最后一位和灰熊签订契约的人。最终她必须登上", "score": 2025394, "category": "drama", "detail_url": "../movie/1502.html", "poster": "../posters/1502.svg"}, {"id": "1503", "title": "算计：七天的死亡游戏", "year": 2010, "region": "日本", "type": "电影", "genre": "悬疑，惊悚", "tags": ["密室，心理战，生存游戏，推理"], "summary_short": "算计：七天的死亡游戏，2010年日本电影，悬疑，惊悚。失业青年结城应聘到一栋地下室公寓，和另外九人参与“每小时赚11万日元”的奇怪实验。第二天早上，一名参与者死在自己房间，而监控屏幕出现“游戏开始：找出凶手，否则每晚死一人”的字样。房间里配有各种武器和“侦探工具”，每杀一人可获得奖金翻倍。结城与女护士真织组成临时搭档，试图通过推理找出幕后黑手。随着参与者互相猜忌、自相残杀，结城发现每个人身上都有一个致命秘密。第七天，仅剩的三人在控制室看", "score": 2010407, "category": "crime", "detail_url": "../movie/1503.html", "poster": "../posters/1503.svg"}, {"id": "1504", "title": "护卫者2022", "year": 2022, "region": "美国", "type": "剧集", "genre": "动作 / 犯罪", "tags": ["退役特工", "AI监控", "女儿被绑"], "summary_short": "护卫者2022，2022年美国剧集，动作 / 犯罪。曾是数字安全领域顶尖专家的 Marcus，五年前因不满公司监控民众的隐私而辞职归隐，在一个小镇当保安。当他叛逆期的女儿在一场电子音乐节后彻底消失，警方束手无策时，Marcus 不得不重操旧业，甚至黑入了他曾经发誓要摧毁的全球监控网络。他发现女儿并非离家出走，而是卷入了一场针对“高智商富二代”的暗网绑架游戏。随着追查深入，Marcus 惊讶地发现，这个绑架团伙的幕后策划者，竟然是他多年前", "score": 2022337, "category": "series", "detail_url": "../movie/1504.html", "poster": "../posters/1504.svg"}, {"id": "1505", "title": "寡人有疾 其名相思第一季", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装， 爱情， 喜剧", "tags": ["欢喜冤家， 权谋， 病弱皇帝， 女太医， 甜宠"], "summary_short": "寡人有疾 其名相思第一季，2025年中国大陆剧集，古装， 爱情， 喜剧。大梁国新帝赵祯身患怪病，不能靠近女子，否则心悸气短，满朝文武为之发愁。天才医学少女沈鱼因祖上恩荫入宫，成了太医院第一位女太医。她坚信皇帝并非体虚，而是心理疾病，于是制定了一套“脱敏疗法”——强行拉皇帝的手、逼他看宫女跳舞、甚至亲自示范人工呼吸。赵祯一边痛斥沈鱼大逆不道，一边发现自己的病奇迹般好转，但随之而来的是另一种“病”：看不见沈鱼就心烦意乱。此时，后宫与朝堂的势", "score": 2025295, "category": "series", "detail_url": "../movie/1505.html", "poster": "../posters/1505.svg"}, {"id": "1506", "title": "海誓山盟万古情", "year": 2027, "region": "中国大陆", "type": "电影", "genre": "爱情，奇幻", "tags": ["轮回，三世情缘，水墨美学"], "summary_short": "海誓山盟万古情，2027年中国大陆电影，爱情，奇幻。画师青岚与渔家女阿离在断桥一见钟情，却因触碰了上古“情劫碑”的封印，陷入万古轮回。第一世，他是将军，她是敌国间谍，在国仇家恨中自刎于城楼；第二世，他是落魄琴师，她是戏班花旦，因一场大火阴阳两隔；第三世穿越到现代，两人成了考古学家与博物馆讲解员，逐渐发现前世的记忆碎片，也意识到每一次重逢都会引发一场局部地震。为了不让现世毁灭，两人必须选择永不相认，然而阿离已怀上第三世的骨肉，命运的悖论将", "score": 2027385, "category": "romance", "detail_url": "../movie/1506.html", "poster": "../posters/1506.svg"}, {"id": "1507", "title": "新世代公民", "year": 2018, "region": "美国", "type": "电影", "genre": "喜剧 / 剧情", "tags": ["高中生，学生会选举，政治讽刺，青春，脱口秀"], "summary_short": "新世代公民，2018年美国电影，喜剧 / 剧情。北卡罗来纳州一所公立高中，学生会主席选举向来是橄榄球队长的囊中物。今年，打算申请政治系的高四生布莱恩志在必得，他精心设计了竞选口号、海报、短视频矩阵，甚至写了一份“百日施政纲领”。但他发现选票上多了一个名字：露比——一个除了写代码几乎不跟任何人说话的亚裔女生。露比是被计算机老师强行推上名单凑数的，本人对竞选毫无兴趣。但当她接受校园电视台采访时，面无表情地用数据模型当场拆穿了布莱恩全部承诺中", "score": 2018295, "category": "drama", "detail_url": "../movie/1507.html", "poster": "../posters/1507.svg"}, {"id": "1508", "title": "坏账银行第一季", "year": 2025, "region": "德国", "type": "电视剧", "genre": "剧情, 惊悚, 金融", "tags": ["投行", "阴谋", "女性职场"], "summary_short": "坏账银行第一季，2025年德国电视剧，剧情, 惊悚, 金融。出身平民的金融天才莱娜·韦伯在柏林全球投资银行（GIB）辛苦打拼五年，终于击败了富二代竞争对手，成为最年轻的副总裁。她接手的是一个看似完美的投资组合，实则是一个巨大的“坏账”陷阱。在审计过程中，她发现这些坏账背后连接着一个跨国贩毒集团，而银行高层不仅知情，更是推手。当莱娜试图向监管机构举报时，她发现自己被全方位监控，男友被收买，且所有证据都被指向她才是内鬼。为了自证清白并扳倒系", "score": 2025351, "category": "series", "detail_url": "../movie/1508.html", "poster": "../posters/1508.svg"}, {"id": "1509", "title": "乐高幻影忍者 第十五季", "year": 2026, "region": "美国 / 丹麦", "type": "剧集", "genre": "动画，动作，奇幻", "tags": ["机甲，忍者，元素之力，黑暗世界，团队重组"], "summary_short": "乐高幻影忍者 第十五季，2026年美国 / 丹麦剧集，动画，动作，奇幻。第十五季开篇，赞在修复过程中被深渊之主植入虚假记忆，误以为自己曾是黑暗一族的战士。他摧毁了忍者城中央数据库，带走了半块元素水晶。劳埃德、杰、科尔、妮雅和派叔驾驶全新“幻影机甲”穿越空间裂隙进入深渊。他们发现深渊之主正在利用赞的记忆回路反向解析所有忍者的大脑频率。为阻止这一计划，派叔牺牲了自己的驾驶舱强行切断联系。最后，赞在妮雅的灵魂呼唤下恢复记忆，六人合力用“黄金大", "score": 2026308, "category": "series", "detail_url": "../movie/1509.html", "poster": "../posters/1509.svg"}, {"id": "1510", "title": "美人局", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装, 悬疑, 爱情", "tags": ["双面女主", "高智商博弈", "晚唐", "骗中骗"], "summary_short": "美人局，2025年中国大陆剧集，古装, 悬疑, 爱情。晚唐年间，扬州城出现“镜花阁”，专为达官贵人的妻妾解决情感危机，实则是由女骗子沈鱼藻设立的情报站。她的下一个猎物是新上任的捉妖司都督裴行舟——一个传说中不近女色、擅破诡术的男人。沈鱼藻设下“英雄救美”、“才女穷途”等连环计，却发现裴行舟总能以更高级的骗术反制。原来裴行舟早就看穿她的身份，却沉迷于这场猫鼠游戏。两人在互相拆台与设局中，竟联手揭开了前朝宝藏与当朝皇子身世之谜。最终，沈鱼藻", "score": 2025290, "category": "series", "detail_url": "../movie/1510.html", "poster": "../posters/1510.svg"}, {"id": "1511", "title": "午夜之子", "year": 2026, "region": "印度", "type": "剧集", "genre": "奇幻 / 悬疑 / 历史", "tags": ["超能力，家族诅咒，印度神话，独立运动"], "summary_short": "午夜之子，2026年印度剧集，奇幻 / 悬疑 / 历史。1947年8月15日午夜，印度独立时刻，全国各地有1001名婴儿同时降生。他们长大后，发现自己拥有奇特的超能力——有人能与动物对话，有人能看见他人的记忆，有人能在水中呼吸。主角萨利姆是其中能力最强者，他能“听见”历史的回响，每当午夜来临，他就会被拉入某个印巴分治时期的血腥场景中，亲历那些被教科书抹去的暴行。随着调查深入，他发现他们的出生并非偶然，而是一位濒死的苦行僧用最后的法力布下", "score": 2026305, "category": "series", "detail_url": "../movie/1511.html", "poster": "../posters/1511.svg"}, {"id": "1512", "title": "打错的电话", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑，犯罪", "tags": ["电话，错号，绑架，限时，孤胆"], "summary_short": "打错的电话，2024年中国大陆电影，悬疑，犯罪。深夜，外卖员李昊接到一个陌生女人的电话，对方哭着说“救救我，我被锁在地下室”。李昊以为是恶作剧，挂断后对方却发来一张实时照片和定位。他犹豫再三，还是骑着电动车赶往现场，却发现那里是一栋废弃大楼。女人不断打来电话，声音越来越微弱，而李昊在楼内发现了多间被改造的囚室。与此同时，警方的无线电里也在追查一宗连环失踪案。李昊必须根据电话里断断续续的线索，在整栋迷宫里找到那个女孩，而那个打错的电话，可", "score": 2024431, "category": "crime", "detail_url": "../movie/1512.html", "poster": "../posters/1512.svg"}, {"id": "1513", "title": "紧急降落", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 灾难 / 惊悚", "tags": ["空难", "反恐", "迫降", "极限生存"], "summary_short": "紧急降落，2024年美国电影，动作 / 灾难 / 惊悚。前空军飞行员艾利克斯因患恐慌症停飞，转行做航空模拟机教员。他女儿首次独自乘坐的红眼航班被黑客侵入系统，飞行员被锁在驾驶舱外，自动驾驶正将飞机飞向核电站。由于通讯干扰，只有艾利克斯通过未被切断的乘客娱乐系统WiFi，用语音指导唯一会开塞斯纳小飞机的乘客——一位70岁老奶奶进行迫降。艾利克斯一边克服自己的恐慌，一边用游戏手柄接入模拟系统，反向计算迫降参数。最后关头，燃油即将耗尽，他让老", "score": 2024387, "category": "crime", "detail_url": "../movie/1513.html", "poster": "../posters/1513.svg"}, {"id": "1514", "title": "史酷比：格斗狂热迷", "year": 2025, "region": "美国", "type": "动画电影", "genre": "喜剧/动画/动作", "tags": ["格斗、恶搞、怀旧、跨次元"], "summary_short": "史酷比：格斗狂热迷，2025年美国动画电影，喜剧/动画/动作。史酷比和夏奇在一次吃披萨大赛中赢得了一架神秘直升机的机票，被送到一座孤岛上的“世界格斗狂热联赛”。夏奇以为赢了就能获得终身免费披萨，硬拉着史酷比参赛。他们发现对手都是来自不同次元的格斗家：会放波动拳的和尚、戴着面具的摔角手、甚至还有一个会说话的恐龙。史酷比本来只想躲在角落里吃饼干，却意外发现所有参赛者都是被邪恶基因公司改造过的动物。幕后黑手是史酷比的老对手——戴着面具的混蛋，", "score": 2025335, "category": "fantasy", "detail_url": "../movie/1514.html", "poster": "../posters/1514.svg"}, {"id": "1515", "title": "我背后的陶斯", "year": 2024, "region": "韩国", "type": "剧集", "genre": "剧情 / 喜剧 / 动作 / 爱情", "tags": ["特工带娃", "邻里喜剧", "谍战", "反差萌"], "summary_short": "我背后的陶斯，2024年韩国剧集，剧情 / 喜剧 / 动作 / 爱情。代号“陶斯”的NIS王牌特工金本，在一次任务中遭组织背叛，失忆后躲在普通住宅区。为了不暴露身份，他给隔壁独自拉扯两个孩子的单亲妈妈高爱琳当起了免费保姆。金本用特工技能带娃——反侦察躲开家长群“绑架”、用催眠术让孩子乖乖吃药，笑料百出。但随着记忆碎片逐渐恢复，他发现导致自己失忆的阴谋，竟与这位看似普通的单亲妈妈有着千丝万缕的联系。而她去世的丈夫，或许正是“陶斯”任务中最", "score": 2024348, "category": "series", "detail_url": "../movie/1515.html", "poster": "../posters/1515.svg"}, {"id": "1516", "title": "青春漫画", "year": 2025, "region": "韩国", "type": "剧集", "genre": "爱情, 喜剧, 剧情", "tags": ["漫改", "校园", "友情", "治愈"], "summary_short": "青春漫画，2025年韩国剧集，爱情, 喜剧, 剧情。高中时，林真率和高恩杰是全校公认的“漫画家CP”，一个编剧一个画图，合作的作品在网上小有名气。毕业时因为误会分道扬镳。十年后，真率成了人气网漫作家，而恩杰却因为公司倒闭成了无业游民。一档名为《青春漫画》的综艺节目找到真率，希望她与曾经的搭档完成一幅作品，恩杰为了高额出演费答应了。多年后再见面，两人都带着满身的刺。真率指责恩杰当年背叛了她，恩杰则说真率从未理解过他的理想。节目录制中，他们", "score": 2025324, "category": "series", "detail_url": "../movie/1516.html", "poster": "../posters/1516.svg"}, {"id": "1517", "title": "什么都不想做", "year": 2022, "region": "韩国", "type": "电视剧", "genre": "剧情，治愈，生活", "tags": ["躺平，乡村治愈，离职潮，慢生活"], "summary_short": "什么都不想做，2022年韩国电视剧，剧情，治愈，生活。28岁的李夏天在首尔一家广告公司做了五年策划，每天工作14个小时，加班、应酬、讨好客户，活成了自己最讨厌的样子。某天她在加班到凌晨三点后晕倒在办公室，醒来后她做了人生中最疯狂的决定：辞职。她卖掉首尔所有家当，跑到东海边一个只有三百人的小镇，租了一间没有暖气、水管经常冻住的破房子，给自己定了一个目标：一年内，什么都不做。不找工作、不搞副业、不社交、不健身、不学习新技能，每天的生活就是起", "score": 2022235, "category": "series", "detail_url": "../movie/1517.html", "poster": "../posters/1517.svg"}, {"id": "1518", "title": "华生", "year": 2025, "region": "英国", "type": "剧集", "genre": "悬疑 / 医疗 / 推理", "tags": ["福尔摩斯宇宙，医生视角，神经科学，罕见病例，师徒反转"], "summary_short": "华生，2025年英国剧集，悬疑 / 医疗 / 推理。时间线设置在福尔摩斯与莫里亚蒂同归于尽后的第三年。华生医生回到伦敦，开了一家神经内科诊所。表面上他放弃了推理，但每一集他都用医学手段解决匪夷所思的怪病：一个男人总觉得妻子被替换了（替身综合征），一个女人坚信自己已经死了（科塔尔综合征），还有一名患者每天早上醒来都认为自己是个叫“福尔摩斯”的侦探。华生发现，最后一例病人的妄想中藏着福尔摩斯生前未破的最后一个案子。与此同时，一个自称“莫里亚", "score": 2025293, "category": "series", "detail_url": "../movie/1518.html", "poster": "../posters/1518.svg"}, {"id": "1519", "title": "科学竞赛", "year": 2018, "region": "美国", "type": "电影", "genre": "剧情， 喜剧", "tags": ["青少年， 天才， 成长， 友谊"], "summary_short": "科学竞赛，2018年美国电影，剧情， 喜剧。不善社交的露娜、偏执的物理狂人阿米尔、想用发明挽回女友的本杰明，以及只想逃离父亲控制的马库斯，四个人临时组队参加全国科学竞赛。他们的项目是“情绪识别手表”，却在测试阶段导致露娜的父亲丢掉工作、阿米尔的实验室被烧、本杰明的女友彻底拉黑他。比赛前夕，团队濒临解散，却发现彼此的家庭问题远比赛场上的对手更可怕。当他们站在总决赛舞台上，展示的不是完美成品，而是一段关于失败与修复的真实录像——却意外赢得了", "score": 2018308, "category": "drama", "detail_url": "../movie/1519.html", "poster": "../posters/1519.svg"}, {"id": "1520", "title": "独行侠夺宝记", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 冒险 / 西部", "tags": ["夺宝", "西部片", "复仇", "独狼", "阴谋"], "summary_short": "独行侠夺宝记，2025年美国电影，动作 / 冒险 / 西部。传奇赏金猎人“独行侠”约翰被自己的夺宝团队出卖，身负重伤扔在荒漠等死。他被一个印第安部落救下，并被告知：团队要找的那个传说宝藏其实是古代部落的诅咒之地，谁打开谁死。约翰为了复仇，决定独自跟上团队。他一路穿越毒枭领地、响尾蛇峡谷，逐个击毙背叛者。当他终于站到宝藏门前，发现前队友们已经被诅咒逼疯，自相残杀。他面临选择：是推开门让所有人陪葬，还是用部落的仪式封印诅咒，独自离开。", "score": 2025354, "category": "fantasy", "detail_url": "../movie/1520.html", "poster": "../posters/1520.svg"}, {"id": "1521", "title": "哎哟哥哥", "year": 2024, "region": "中国大陆", "type": "网络短剧", "genre": "喜剧、奇幻", "tags": ["兄妹", "虚拟偶像", "跨次元", "短小精悍"], "summary_short": "哎哟哥哥，2024年中国大陆网络短剧，喜剧、奇幻。小桑是重度社恐兼虚拟偶像“哎哟哥哥”的狂热粉丝。某天直播时，她许愿“想让哥哥帮我出门买东西”。奇迹发生，虚拟偶像竟真的跳出屏幕，变成一个只存在24小时的实体“哥哥”。他帮她打电话、退快递、和邻居吵架、甚至去相亲。但渐渐的，小桑发现这个“哥哥”开始出现BUG，说话反复，记忆紊乱。24小时后，他消失了，但小桑发现自己敢按下门把手了。", "score": 2024248, "category": "series", "detail_url": "../movie/1521.html", "poster": "../posters/1521.svg"}, {"id": "1522", "title": "小事儿", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情, 家庭", "tags": ["日常", "亲情", "代沟", "治愈"], "summary_short": "小事儿，2025年中国台湾电影，剧情, 家庭。离家多年的摄影师阿年回到台北，发现母亲患有一种罕见的“短期记忆选择症候群”：她会忘记吃药、忘记吃饭，但唯独记得生活中的琐碎“小事”——比如今天市场青菜涨价了、对面邻居的猫又跑了。为了让母亲维持身体机能，阿年决定在不告诉母亲自己病情的前提下，每天陪她重复那些看似毫无意义的日常。陪她去同一家菜市场，听同一个小贩重复同一句笑话。在这些枯燥的重复中，阿年终于读懂了母亲用一生写的诗，并学会了如何告别。", "score": 2025321, "category": "drama", "detail_url": "../movie/1522.html", "poster": "../posters/1522.svg"}, {"id": "1523", "title": "无间有爱", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作，犯罪", "tags": ["卧底，兄弟情，黑帮，悲剧"], "summary_short": "无间有爱，2024年中国香港电影，动作，犯罪。阿诚和阿天是九龙城寨里一起长大的孤儿，亲如兄弟。长大后，阿诚考入了警校，阿天则因生活所迫加入了黑帮。数年后，阿诚成为警方派入阿天所在帮派的卧底。看着昔日的兄弟逐渐在帮派中上位，变得心狠手辣，阿诚内心无比煎熬。与此同时，阿天也隐约察觉到身边有内鬼，开始怀疑阿诚。在一次警方与黑帮的终极火拼前夕，双方都陷入了无间地狱。阿诚接到任务要逮捕阿天，而阿天也准备为帮派除掉叛徒。两人在天台对峙，回忆起小时候", "score": 2024361, "category": "crime", "detail_url": "../movie/1523.html", "poster": "../posters/1523.svg"}, {"id": "1524", "title": "毛侠粤语", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情 / 动作", "tags": ["市井英雄，黑色幽默，草根逆袭，街头正义"], "summary_short": "毛侠粤语，2024年中国香港电影，剧情 / 动作。阿强是深水埗一间老理发店的学徒，手艺不精但心地善良。某夜，他发现祖传的理发椅下藏着一束会发光的古代毛发，刺入头皮后获得了操控发丝的异能。起初他只用来偷鸡摸狗，帮街坊拿回被城管没收的摊车。直到跨国财团要强拆整个街区，阿强才挺身而出，用发丝缠住挖掘机、绊倒催泪弹。最终他剪去长发失去力量，却用证据曝光财团黑幕，保住了老街。故事在荒诞中透着港式小人物互助的温情。", "score": 2024345, "category": "drama", "detail_url": "../movie/1524.html", "poster": "../posters/1524.svg"}, {"id": "1525", "title": "行骗天下", "year": 2019, "region": "日本", "type": "电视剧", "genre": "喜剧 / 悬疑", "tags": ["高智商欺诈", "单元剧", "神反转", "豪华客串"], "summary_short": "行骗天下，2019年日本电视剧，喜剧 / 悬疑。达子、小少爷和理查德，三个没有固定居所的骗子，以“行骗天下”为信条。他们没有骗不了的人，只有不想骗的人。每一集，他们都会锁定一个金融巨鳄、黑心政客或邪教头目，为其量身打造一个天衣无缝的骗局。达子负责扮演出神入化的各种角色，小少爷负责技术和计划，理查德负责易容和情报。在骗局进行到最危险的时候，总会出现让观众也意想不到的惊天逆转。看似被逼入绝境，实则一切尽在掌握。他们从不伤人身体，只骗走你最肮", "score": 2019289, "category": "series", "detail_url": "../movie/1525.html", "poster": "../posters/1525.svg"}, {"id": "1526", "title": "在一起2021", "year": 2021, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 抗疫", "tags": ["新冠疫情", "普通人", "单元剧"], "summary_short": "在一起2021，2021年中国大陆电视剧，剧情 / 抗疫。以真实人物为原型：快递员老计每天送药送菜，自己却感染了；护士夫妻在ICU走廊隔着玻璃吃年夜饭；滞留在武汉的外卖骑手组成志愿车队；失去父亲的女儿在殡仪馆外排了六小时队，最后对着手机说“爸，我没哭”。每一个单元都在说同一句话：“我们不是英雄，我们只是没逃跑。”", "score": 2021215, "category": "series", "detail_url": "../movie/1526.html", "poster": "../posters/1526.svg"}, {"id": "1527", "title": "绝对零度 特别篇", "year": 2021, "region": "日本", "type": "特别篇", "genre": "悬疑， 犯罪， 剧情", "tags": ["刑侦， 未结案件， 团队合作"], "summary_short": "绝对零度 特别篇，2021年日本特别篇，悬疑， 犯罪， 剧情。正当“绝对零度”小组因经费削减面临解散时，一组来自深山的骸骨被发现，其作案手法与十五年前震惊社会的连环失踪案高度吻合。组长井泽范子力排众议，召集旧部展开最后的48小时极限追查。他们发现，当年的受害者都与一个已经消失的线上社区“蓝洞”有关。随着调查深入，小组内部出现分歧，有人认为应将线索移交总部，范子却坚持要在解散前亲手终结此案。这不仅是与凶手的赛跑，更是这群被边缘化的警察为自", "score": 2021231, "category": "crime", "detail_url": "../movie/1527.html", "poster": "../posters/1527.svg"}, {"id": "1528", "title": "瑞雪兆丰年", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["东北", "农村", "代际", "土地情结", "大雪"], "summary_short": "瑞雪兆丰年，2021年中国大陆电影，剧情, 家庭。东北某农场，老农民陈丰收守着三百亩大豆田等第一场雪。雪是丰年的预兆，也是卖粮的最后期限。儿子陈鹏在深圳做外卖站长，带着妻子和自闭症儿子回乡过年。三代人挤在土炕上，关于“去留”的矛盾在大年夜爆发。父亲认为土地是根，儿子觉得土地是枷锁。自闭症孙子却唯独在雪地里的豆田上开口说了第一句话。大雪如期而至，但粮价暴跌、收购商跑路。陈鹏利用外卖平台的逻辑，通过直播带货三天卖光了全村滞销的大豆。影片最后", "score": 2021256, "category": "drama", "detail_url": "../movie/1528.html", "poster": "../posters/1528.svg"}, {"id": "1529", "title": "想像（2022年电影）", "year": 2022, "region": "英国", "type": "电影", "genre": "科幻/心理", "tags": ["脑机接口， 记忆编辑， 夫妻， 真实"], "summary_short": "想像（2022年电影），2022年英国电影，科幻/心理。科技公司“忆界”推出“记忆净化”服务，夫妻可以选择删除关于伴侣的所有负面记忆，让感情焕然一新。七年之痒的乔和艾玛决定尝试。手术醒来后，他们看着对方，礼貌地微笑，像第一次见面的陌生人。他们确实不记得争吵、背叛、泪水和摔碎的照片框，但同时，那些在雨中奔跑、凌晨三点分享童年创伤、看到对方第一眼时的悸动，也随负面记忆一同消失了。因为人类的大脑储存记忆的方式是正负交织的。两人坐在曾一起涂鸦的", "score": 2022307, "category": "sci-fi", "detail_url": "../movie/1529.html", "poster": "../posters/1529.svg"}, {"id": "1530", "title": "本杰明·巴顿奇事", "year": 2008, "region": "美国", "type": "电影", "genre": "剧情 / 爱情 / 奇幻", "tags": ["返老还童", "时间逆流", "大卫·芬奇", "布拉德·皮特", "人生"], "summary_short": "本杰明·巴顿奇事，2008年美国电影，剧情 / 爱情 / 奇幻。一战结束当晚，本杰明·巴顿以畸形老人的形态降生，被生父遗弃在养老院门口。他的人生是倒着走的：当别人在长大，他在变年轻；当别人学会爱，他已经历过离别。他在养老院里遇见了小女孩黛西，两人在时间的错位中反复错过。他年轻时（外表衰老）出海闯荡，爱上过一个已婚女人；等到他变成中年（外表四十），终于与正当盛年的黛西相恋，并有了一个女儿。但他深知自己终将变成婴儿，黛西无法同时抚养两个“孩", "score": 2008369, "category": "drama", "detail_url": "../movie/1530.html", "poster": "../posters/1530.svg"}, {"id": "1531", "title": "徽娘宛心", "year": 2025, "region": "中国", "type": "剧集", "genre": "剧情 / 年代 / 女性", "tags": ["徽商", "刺绣", "女性自立", "民国"], "summary_short": "徽娘宛心，2025年中国剧集，剧情 / 年代 / 女性。宛心天生不能说话，却有一双巧夺天工的手。她被家人卖给徽州大户汪家，给病入膏肓的少爷冲喜。丈夫死后，族中欲将宛心赶出家门，她却凭借一幅绣着“二十四节气”的绝品绣作，赢得了汪家当家人的赏识。宛心开始学习经商，从打理绣坊做起，逐渐掌握了汪家的茶叶、墨业和钱庄。她改良绣法、开拓南洋商路、破除“女人不能进商会”的规矩，一步步成为徽州商界的传奇。但暗处，有人一直在模仿她的绣技，并以更卑劣的手段", "score": 2025198, "category": "series", "detail_url": "../movie/1531.html", "poster": "../posters/1531.svg"}, {"id": "1532", "title": "冠军歌王", "year": 2013, "region": "马来西亚", "type": "电影", "genre": "喜剧，音乐，家庭", "tags": ["歌唱比赛，方言，父子情，小镇文化"], "summary_short": "冠军歌王，2013年马来西亚电影，喜剧，音乐，家庭。年轻时凭借一首福建歌《浪子回头》红遍东南亚的金波，如今在小镇经营一家板面摊，彻底封麦。他那去大城市追逐摇滚梦的儿子阿Boy，带着女友和乐队成员回乡，不仅瞧不起父亲的方言歌曲，还为了拉赞助在父亲的面摊对面举办了露天演唱会。父子俩的矛盾在一次争执中爆发，两人决定在小镇的中秋晚会上进行一场“歌王争霸赛”。就在阿Boy自信满满时，他意外发现了父亲当年是如何为了抚养他而放弃了去香港发展的合同。比", "score": 2013261, "category": "comedy", "detail_url": "../movie/1532.html", "poster": "../posters/1532.svg"}, {"id": "1533", "title": "正常人", "year": 2024, "region": "爱尔兰", "type": "剧集", "genre": "剧情 / 爱情", "tags": ["敏感", "成长", "阶级", "亲密关系"], "summary_short": "正常人，2024年爱尔兰剧集，剧情 / 爱情。改编自同名文学经典的现代版续写。故事聚焦于康奈尔和玛丽安大学毕业后的五年。康奈尔拿到了纽约的创意写作奖学金，却因为严重的社交恐惧和抑郁症无法动笔；玛丽安回到都柏林的家庭中，继续忍受哥哥的精神虐待，表面上却是职场精英。两人分分合合，每一次靠近都会因为原生家庭的伤痛而刺伤对方。玛丽安鼓励康奈尔接受心理治疗，康奈尔则帮她远离有毒的家庭环境。剧集穿插了他们大学时期的闪回，解释为何两人总是无法坦诚面对", "score": 2024312, "category": "series", "detail_url": "../movie/1533.html", "poster": "../posters/1533.svg"}, {"id": "1534", "title": "异世界居酒屋阿信", "year": 2018, "region": "日本", "type": "剧集", "genre": "奇幻 / 美食", "tags": ["异世界", "居酒屋", "美食", "温馨"], "summary_short": "异世界居酒屋阿信，2018年日本剧集，奇幻 / 美食。普通居酒屋“阿信”位于东京某条小巷，但后门一开就是异世界城市“古都”。老板阿信和女儿小忍用日本料理征服异世界居民：懒散士兵吃到唐扬炸鸡后重新振作，精灵女祭司被关东煮治愈了千年孤独，龙族公爵为味增汤放弃屠城计划。每一集都是独立美食故事，同时埋下“门为何存在”的主线。最终阿信决定永久营业，让两个世界通过食物互相理解。", "score": 2018300, "category": "series", "detail_url": "../movie/1534.html", "poster": "../posters/1534.svg"}, {"id": "1535", "title": "疯狂麦斯：愤怒道", "year": 2024, "region": "美国", "type": "电影", "genre": "动作、科幻、冒险", "tags": ["废土、飙车、女性力量、复仇、硬核"], "summary_short": "疯狂麦斯：愤怒道，2024年美国电影，动作、科幻、冒险。核战摧毁了文明，水与石油成为信仰。麦斯被“不死老乔”的战争男孩俘虏，沦为血袋。 meanwhile，独臂指挥官芙莉欧莎正计划叛逃，她偷走了老乔最宝贵的战争钻油台卡车，要穿越千里盐原回到故乡。麦斯被迫卷入这场疯狂逃亡。身后是成千上万的战争男孩、气垫船和改装怪物车。在沙暴、沼泽和秃鹰峡谷中，麦斯与芙莉欧莎从互相戒备到背靠背作战。最终，他们发现故乡已不存在，但后方追兵已至，他们决定调转车", "score": 2024387, "category": "crime", "detail_url": "../movie/1535.html", "poster": "../posters/1535.svg"}, {"id": "1536", "title": "目标小姐", "year": 2024, "region": "韩国", "type": "剧集", "genre": "动作 / 喜剧", "tags": ["女杀手", "伪装", "豪门", "复仇"], "summary_short": "目标小姐，2024年韩国剧集，动作 / 喜剧。代号“麋鹿”的顶级杀手接到新任务：刺杀太星集团第三代继承人、十六岁的高中生姜时宇。她伪装成补习家教进入豪宅，却发现目标只是一个喜欢画星星、说话结巴、每天被父亲家暴的普通少年。与此同时，她发现真正的委托人正是姜时宇的父亲——他买凶杀子，只为了给小儿子让路。麋鹿从未失手，但这一次她犹豫了。她在少年的画册里看到一幅画：一个持枪的女人站在满天星星下。少年说：“这是我梦里的天使。” 麋鹿没有完成任务，", "score": 2024326, "category": "series", "detail_url": "../movie/1536.html", "poster": "../posters/1536.svg"}, {"id": "1537", "title": "走向深渊", "year": 2025, "region": "俄罗斯", "type": "电视剧", "genre": "悬疑, 剧情", "tags": ["贪腐", "卧底", "高层黑幕", "沉重"], "summary_short": "走向深渊，2025年俄罗斯电视剧，悬疑, 剧情。反腐调查员伊戈尔接获最高机密任务：接近涉嫌巨额贪腐的莫斯科市长，以女婿的身份打入家族内部。他成功追求市长的女儿并结婚，在豪门中如履薄冰地收集证据。然而他渐渐发现，市长的巨额财富并非源于贪腐，而是在秘密资助一个侦测未来灾难的物理项目。更诡异的是，市长也在派私家侦探调查他这个“从天而降”的女婿。当伊戈尔以为自己是猎人时，市长握住他的手说：“我知道你是谁，我就是需要你来帮我揪出真正的内鬼。”一场", "score": 2025351, "category": "series", "detail_url": "../movie/1537.html", "poster": "../posters/1537.svg"}, {"id": "1538", "title": "圣诞老人征婚", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧, 爱情", "tags": ["圣诞", "中年危机", "反套路", "相亲", "治愈"], "summary_short": "圣诞老人征婚，2025年中国大陆电影，喜剧, 爱情。老张52岁，商场圣诞老人扮演者。女儿出国后，他倍感孤独，下载了中老年婚恋APP。他匹配到了王姐，40岁，是商场内衣店柜员，因前夫总是“画大饼”而极度务实。第一次见面，老张穿着还没脱下的圣诞装，被王姐嘲笑是“老年骗子”。老张解释这不是工作服，是“信仰”。王姐不信任何节日，尤其讨厌圣诞节。两人在一家饺子馆相亲，老张聊驯鹿，王姐聊房贷。看似毫无交集，但老张每次都会在王姐下夜班时，穿着圣诞装默", "score": 2025370, "category": "romance", "detail_url": "../movie/1538.html", "poster": "../posters/1538.svg"}, {"id": "1539", "title": "真假森林王", "year": 2024, "region": "中国大陆", "type": "动画电影", "genre": "喜剧， 冒险， 奇幻", "tags": ["冒名顶替， 自我认同， 森林冒险， 萌宠搭档"], "summary_short": "真假森林王，2024年中国大陆动画电影，喜剧， 冒险， 奇幻。狮子阿乐是动物园里的“影帝”，擅长模仿，但本性懦弱。真正的森林之王因故失踪，为了避免食草与食肉动物开战，动物长老们请阿乐去当“替身”。阿乐带着毒舌鹦鹉军师，在危机四伏的森林里勉强维持着狮王的威严。随着谎言越滚越大，阿乐必须在被发现之前，用真正的智慧和勇气解决种族矛盾，而不是靠伪装。", "score": 2024359, "category": "fantasy", "detail_url": "../movie/1539.html", "poster": "../posters/1539.svg"}, {"id": "1540", "title": "心碎俱乐部", "year": 2023, "region": "美国", "type": "电影", "genre": "喜剧 / 爱情 / 剧情", "tags": ["疗愈小组", "失恋故事集", "拼盘叙事", "荒诞疗法"], "summary_short": "心碎俱乐部，2023年美国电影，喜剧 / 爱情 / 剧情。旧金山，刚被未婚妻悔婚的软件工程师本杰明在酒吧偶遇了另外两个失意者：被已婚男友欺骗的舞蹈老师艾琳娜，以及刚发现丈夫和男人跑了的中年主妇黛比。三人成立了“心碎俱乐部”，最初的目的是倾诉，但很快演变成行动：帮彼此向前任实施“精准复仇”。计划包括：潜入婚礼现场播放出轨视频、冒充富豪勾引前女友再甩掉她、以及在商业路演上揭穿前夫的真面目。然而随着计划推进，他们发现每个人都放不下过去，所谓的", "score": 2023389, "category": "drama", "detail_url": "../movie/1540.html", "poster": "../posters/1540.svg"}, {"id": "1541", "title": "醉乡情断", "year": 1986, "region": "中国香港", "type": "电影", "genre": "剧情 / 爱情", "tags": ["邵氏", "酒瘾", "文艺悲歌", "老港片"], "summary_short": "醉乡情断，1986年中国香港电影，剧情 / 爱情。六十年代的湾仔红灯区，阿良开了一家只有五张桌子的酒吧。他每天下午三点准时开门，只为了等一个从不说话的女人——红姐。红姐每晚九点上台，只唱一首《不了情》，然后喝掉阿良专门为她泡的一整瓶高粱酒，被一个西装男人接走。阿良从不打听她的过去，直到有一天那西装男人告诉阿良：“她嗓子坏了，以后唱不了了。”红姐从此消失。十年后，阿良成了全香港最大的酒商，他酿的第一支私人酒标就叫“红”。在一次盲品会上，一", "score": 1986346, "category": "drama", "detail_url": "../movie/1541.html", "poster": "../posters/1541.svg"}, {"id": "1542", "title": "黑洞乌托邦", "year": 2025, "region": "美国", "type": "剧集", "genre": "科幻 / 悬疑", "tags": ["量子物理", "精英社会", "生存游戏", "多维空间"], "summary_short": "黑洞乌托邦，2025年美国剧集，科幻 / 悬疑。诺奖得主们秘密建造了“边缘城”，一座悬浮于人造微型黑洞视界外的科学乌托邦。全球筛选出的100名精英在此享受无限资源，任务是破解统一场论。年轻物理学家亚当发现，每次重大实验成功后，都会有同伴离奇“蒸发”，且无人记得他们的存在。深入调查后，他惊恐地得出结论：这座城市的能量来自吞噬平行宇宙，而他们的每一次突破，都意味着另一个宇宙中的地球被毁灭。当管理者提出要启动终极实验来“完善”本宇宙时，亚当必", "score": 2025392, "category": "series", "detail_url": "../movie/1542.html", "poster": "../posters/1542.svg"}, {"id": "1543", "title": "八仙全传", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "古装/神话/喜剧", "tags": ["八仙", "凡人成仙", "群像剧", "道家文化"], "summary_short": "八仙全传，2025年中国大陆剧集，古装/神话/喜剧。八仙在任已满三千年，天庭决定换届。铁拐李作为老八仙代表，负责在凡间寻找新的八位成仙者。他的要求很高：必须是心地纯善的凡人。但造化弄人，他被分配到的候选人是：一个靠卖假药起家的江湖骗子（未来的汉钟离）、一个有躁郁症的富家千金（何仙姑）、一个社恐的棺材铺老板（蓝采和）、一个偷过贡品的乞丐（曹国舅）、一个悔婚三次的花花公子（吕洞宾）、一个把道观改成KTV的疯道士（张果老）、一个用驴子碰瓷的懒", "score": 2025220, "category": "series", "detail_url": "../movie/1543.html", "poster": "../posters/1543.svg"}, {"id": "1544", "title": "大猎逃", "year": 2025, "region": "俄罗斯", "type": "电影", "genre": "动作惊悚", "tags": ["丛林追杀、反杀、女性复仇、生存"], "summary_short": "大猎逃，2025年俄罗斯电影，动作惊悚。女导游安娜带领一队游客进入西伯利亚原始森林，却发现自己成了九名权贵子弟的“猎物”。他们付钱参加秘密狩猎游戏，每人一把猎枪，安娜只有一把瑞士军刀。逃跑过程中安娜发现自己曾是一名特种兵，因举报上司贪污被开除。她用陷阱反杀三人，夺取猎枪后开始逐一猎杀追击者。六天后，猎场主人收到无人机航拍录像：最后一名猎杀者跪在安娜面前，安娜对着镜头说“游戏结束，现在轮到你了”。猎场主人带私人武装前往围剿，却在猎场中央发", "score": 2025358, "category": "crime", "detail_url": "../movie/1544.html", "poster": "../posters/1544.svg"}, {"id": "1545", "title": "失职丈夫粤语", "year": 1994, "region": "中国香港", "type": "电视剧", "genre": "家庭伦理", "tags": ["婚姻危机，全职主妇，女性觉醒，粤语原声"], "summary_short": "失职丈夫粤语，1994年中国香港电视剧，家庭伦理。家庭主妇陈咏琴结婚十五年，每天照顾丈夫和两个孩子。偶然发现丈夫高卓文手机里的暧昧短信，对象是自己的闺蜜。咏琴没有揭穿，而是偷偷应聘丈夫建筑公司的夜班清洁工。她戴着口罩和工服，每晚清理高管的办公室，同时翻查财务文件，发现丈夫与闺蜜合谋利用“豆腐渣工程”洗钱。咏琴悄悄收集证据，并联系了被丈夫害得破产的老工程师。闺蜜察觉异样，鼓动高卓文辞退所有清洁工。咏琴面临失业，此时她无意中听到女儿对同学说", "score": 1994151, "category": "series", "detail_url": "../movie/1545.html", "poster": "../posters/1545.svg"}, {"id": "1546", "title": "悲惨世界：没有终点的旅途", "year": 2025, "region": "日本", "type": "剧集", "genre": "历史/犯罪", "tags": ["名著改编、复仇、警察、救赎"], "summary_short": "悲惨世界：没有终点的旅途，2025年日本剧集，历史/犯罪。1945年，日本战败。逃犯龙崎（原型冉阿让）偷了面包救了孤儿，却被判重罪，越狱后改名换姓成为地方市长，修建学校、救助穷人。警探伏见（原型沙威）从东京调来，发现市长就是当年逃犯。伏见开始暗中调查，龙崎不断用善行动摇伏见的信念。朝鲜战争爆发，龙崎为救被困战区的孩子，暴露身份。伏见抓捕他时，龙崎主动戴上手铐。伏见在押送途中放了龙崎，自己在桥上徘徊一夜，最终没有跳河，而是脱掉警服，说：“", "score": 2025290, "category": "series", "detail_url": "../movie/1546.html", "poster": "../posters/1546.svg"}, {"id": "1547", "title": "娱乐之家", "year": 2018, "region": "美国", "type": "电影", "genre": "悬疑, 惊悚, 科幻", "tags": ["密室逃脱", "直播", "科技伦理", "反转"], "summary_short": "娱乐之家，2018年美国电影，悬疑, 惊悚, 科幻。六名不同背景的陌生人收到一封华丽邀请函，参加“娱乐之家”大型真人密室逃脱直播秀，胜者独享一千万美元。他们被送入一个巨大的改造工厂，每个房间都设计了致命的机关：电锯迷宫、酸雨走廊、失重窒息舱。但最大的变数不在机关，而在直播观众。观众可以通过付费投票来选择每个房间的难度等级，甚至可以选择“触发”额外的死亡陷阱。六个人起初以为这是一场游戏，直到第一个人真的死了，鲜血溅在了镜头上。他们想要退出", "score": 2018520, "category": "crime", "detail_url": "../movie/1547.html", "poster": "../posters/1547.svg"}, {"id": "1548", "title": "骇故事之恐怖殡仪馆", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "恐怖 / 悬疑", "tags": ["殡仪馆", "民俗", "中式恐怖", "密室", "轮回"], "summary_short": "骇故事之恐怖殡仪馆，2024年中国大陆电影，恐怖 / 悬疑。失业青年刘响找到了一份殡仪馆守夜人的工作，工资高得离谱，唯一的条件是“晚上不要走出值班室”。第一晚，他就听到了诡异的声响。通过监控，他发现凌晨三点整，所有冷藏柜会同时打开，尸体们坐起来，用死者的声音聊天——聊的都是自己生前的冤屈和未了的心愿。刘响从恐惧变成好奇，开始偷听尸体的对话。他发现这些尸体都是非正常死亡，且死因指向同一个人：殡仪馆的馆长。更诡异的是，每听一晚，他自己就会丢", "score": 2024443, "category": "horror", "detail_url": "../movie/1548.html", "poster": "../posters/1548.svg"}, {"id": "1549", "title": "跨越白昼的夜", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "爱情， 奇幻， 剧情", "tags": ["文艺爱情， 时间循环， 昼夜颠倒， 小众， 诗意"], "summary_short": "跨越白昼的夜，2023年中国大陆电影，爱情， 奇幻， 剧情。一座不存在的南方小城。林是一位只能活在白天的青年，每当太阳落山他就会“重置”，忘记夜晚发生的一切。苏是一位只能活在夜晚的女孩，日出时她会失去所有关于白天的记忆。两人在一次6分钟的全环食（白天与黑夜瞬间重叠）中相遇，并发现彼此是对方世界里唯一不消失的存在。从此，他们每天在黎明和黄昏各短短3分钟的重叠时刻里拼命相爱——写日记、录视频、互留便签，用一切方式对抗重置。但记忆可以被清除，", "score": 2023399, "category": "drama", "detail_url": "../movie/1549.html", "poster": "../posters/1549.svg"}, {"id": "1550", "title": "夺命街头", "year": 2024, "region": "中国香港", "type": "电影", "genre": "犯罪 / 动作", "tags": ["黑帮火并，卧底，兄弟情，暴力美学，绝命逃亡"], "summary_short": "夺命街头，2024年中国香港电影，犯罪 / 动作。卧底阿豪潜伏在黑帮“和联胜”三年，就在即将收网之际，警方高层突遭暗杀，他的档案被神秘删除。黑帮老大坤哥得知阿豪是卧底，派出全城杀手追剿。同时警方因无法确认其身份，也对他展开追捕。平安夜，阿豪身负重伤逃到尖沙咀，人潮涌动却无人可信。此时一名他曾在巷口救过的妓女阿珍挺身而出，用身体为他挡下一发子弹，并带他躲进地下歌厅。两人在旧歌厅里迎来了黎明前的最后一场生死火拼。", "score": 2024385, "category": "crime", "detail_url": "../movie/1550.html", "poster": "../posters/1550.svg"}, {"id": "1551", "title": "冲浪美眉", "year": 2022, "region": "澳大利亚", "type": "电视剧", "genre": "青春 / 运动", "tags": ["女子力，海洋环保，姐妹情"], "summary_short": "冲浪美眉，2022年澳大利亚电视剧，青春 / 运动。18岁悉尼女孩凯特因吸食大麻被母亲送到沿海小镇的外婆家。当地有个被称为“垃圾队”的女子冲浪俱乐部，成员都是被主流排斥的少女：酗酒的、怀孕的、有犯罪记录的。凯特起初抵触，为凑钱回城参加比赛。她在训练中逐渐理解海洋，并与队友们一起发现排污工厂。她们一边备战州锦标赛，一边秘密取证。决赛当日，凯特放弃冲浪转而去电视台曝光排污，队友们接力完成比赛并夺冠。凯特最终选择留下，成为环保斗士。", "score": 2022152, "category": "series", "detail_url": "../movie/1551.html", "poster": "../posters/1551.svg"}, {"id": "1552", "title": "七剑下天山之修罗眼", "year": 2019, "region": "中国大陆", "type": "电影", "genre": "武侠 / 动作 / 奇幻", "tags": ["七剑", "梁羽生", "大IP", "特效", "情仇"], "summary_short": "七剑下天山之修罗眼，2019年中国大陆电影，武侠 / 动作 / 奇幻。改编自梁羽生原著，讲述《七剑下天山》前传故事。凌未风与刘郁芳本是天山派最出色的剑侠情侣，但刘郁芳在一次调查魔教遗址时，被上古神器“修罗眼”射出的红光击中，性情大变，不仅功力暴涨，还开始屠杀正派弟子。原来修罗眼并非魔器，而是一面“照心镜”，它会放大宿主心中最深藏的恶念。凌未风发现刘郁芳的恶念不是恨，而是“害怕失去凌未风”所产生的占有欲。要破修罗眼，不能用剑，而是要让宿主", "score": 2019418, "category": "crime", "detail_url": "../movie/1552.html", "poster": "../posters/1552.svg"}, {"id": "1553", "title": "乱世勇者", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "古装, 武侠", "tags": ["架空", "战争", "侠义", "成长"], "summary_short": "乱世勇者，2025年中国大陆电视剧，古装, 武侠。架空历史背景。北国铁骑南下，南国公主沈雁被迫女扮男装参军。她率领残兵在雁门关死守三个月，却等来了援军被宦官出卖的消息。绝望之际，敌军统帅——北国战神拓跋烈单骑入关劝降。两人在雪中对峙三天三夜，从敌对到惺惺相惜。拓跋烈承诺保留南国皇室血脉，条件是沈雁嫁给他。沈雁同意，却在婚礼当晚刺伤拓跋烈逃跑，带领残部反击。拓跋烈重伤未愈仍率军追击，两人在曾经的战场上刀刃相见。", "score": 2025197, "category": "series", "detail_url": "../movie/1553.html", "poster": "../posters/1553.svg"}, {"id": "1554", "title": "我真的爱死你", "year": 2003, "region": "中国香港", "type": "电影", "genre": "爱情 / 喜剧 / 恐怖", "tags": ["黑色幽默", "病娇", "港式鬼片", "人鬼恋"], "summary_short": "我真的爱死你，2003年中国香港电影，爱情 / 喜剧 / 恐怖。花花公子阿强对女友阿蚊厌倦后提出分手，阿蚊伤心欲绝过马路时被车撞死。当晚阿蚊的鬼魂就出现在阿强床上，不是索命，而是要求阿强“继续爱我，而且要比以前更爱我”。从此阿强过上求生不得求死不能的生活：阿蚊鬼魂会在他与其他女人亲热时突然现身做鬼脸，会在他睡觉时站在床边盯他一整夜，还会附身到他老板身上要求加薪和批假陪“女朋友”。阿强请来各路道士捉鬼，结果道士反被阿蚊教训。绝望中阿强找来", "score": 2003461, "category": "horror", "detail_url": "../movie/1554.html", "poster": "../posters/1554.svg"}, {"id": "1555", "title": "陀枪师姐2021粤语", "year": 2021, "region": "中国香港", "type": "剧集", "genre": "警匪，动作，喜剧", "tags": ["女警，粤语原声，枪战，师徒，破案"], "summary_short": "陀枪师姐2021粤语，2021年中国香港剧集，警匪，动作，喜剧。刚毕业的女警陈三元被分配到冷门的枪械犯罪科，遇到了退役多年的传奇神枪手“陀枪师姐”文丽。文丽性格古怪，坚持使用老式左轮手枪，与使用高科技装备的三元格格不入。城中出现连环枪击案，凶手每次都用不同年代的经典枪械作案，现场留下的弹壳竟与二十年前的未解悬案有关。三元和文丽从互看不顺眼到逐渐理解对方，通过抽丝剥茧，发现凶手竟是文丽当年的徒弟，一个因伤退役后心理扭曲的前射击冠军。最终两", "score": 2021325, "category": "series", "detail_url": "../movie/1555.html", "poster": "../posters/1555.svg"}, {"id": "1556", "title": "身后仕", "year": 2018, "region": "中国香港", "type": "电影", "genre": "剧情, 社会", "tags": ["殡葬", "职业剧", "亲情", "写实", "小人物"], "summary_short": "身后仕，2018年中国香港电影，剧情, 社会。陈永仁曾是投行精英，金融危机后失业，被父亲逼着接手“长生堂”殡葬铺。他极度抗拒，直到前女友阿宝因癌症去世，阿宝的母亲指定由他来操办葬礼。陈永仁第一次认真对待这份工作，亲自为阿宝化妆、选棺木、写悼词。葬礼上，他的专业和真诚打动了一位失去儿子的富豪，后者将家族百年殡葬合约给了他。陈永仁从此入行，用金融思维改造殡葬业——推出葬礼分期付款、生前契约保险。三年后，长生堂上市，但他在庆功宴上看到父亲的背", "score": 2018240, "category": "drama", "detail_url": "../movie/1556.html", "poster": "../posters/1556.svg"}, {"id": "1557", "title": "叶问外传：张天志国语", "year": 2021, "region": "中国大陆 / 中国香港", "type": "电影", "genre": "动作 / 传记 / 武侠", "tags": ["咏春", "小人物崛起", "擂台战", "民族尊严", "粤语配音"], "summary_short": "叶问外传：张天志国语，2021年中国大陆 / 中国香港电影，动作 / 传记 / 武侠。败给叶问后，张天志携子远走马来西亚槟城，靠拉黄包车为生。当地华侨女孩小兰被英国殖民者之子强暴后，其父告状无门反被毒枭“坤叔”灭门。小兰逃入张天志家中，他本不想再出手，但儿子那句“爸爸你不是说咏春是拿来保护人的吗”刺痛了他。张天志设局挑战殖民者开办的“无规则格斗大赛”，第一轮对阵泰拳手被打断两根肋骨，第二轮对战日本柔道家时使出“标指”反杀。决赛前夜，毒枭", "score": 2021280, "category": "costume", "detail_url": "../movie/1557.html", "poster": "../posters/1557.svg"}, {"id": "1558", "title": "克洛伊", "year": 2023, "region": "美国", "type": "电影", "genre": "剧情, 惊悚", "tags": ["心理博弈", "替身", "悬疑"], "summary_short": "克洛伊，2023年美国电影，剧情, 惊悚。精英女医生凯瑟琳怀疑丈夫大卫与学生有染，为了测试他的忠诚，她雇佣了年轻迷人的应召女郎克洛伊去主动接近大卫。起初，一切都在凯瑟琳的观察与掌控之中，克洛伊每天向她报告暧昧的进展。然而，随着报告的细节愈发露骨，凯瑟琳发现自己被克洛伊深深吸引，陷入了三人之间危险的性心理游戏。当凯瑟琳决定终止这场闹剧时，克洛伊却反客为主，开始私下接触她的儿子和社交圈。一场关于嫉妒、欲望与身份错位的风暴即将撕碎这个中产家庭", "score": 2023305, "category": "crime", "detail_url": "../movie/1558.html", "poster": "../posters/1558.svg"}, {"id": "1559", "title": "反恐特警组：火速救援", "year": 2020, "region": "美国", "type": "电影", "genre": "动作、犯罪", "tags": ["洛杉矶、特警、解救人质、枪战、虎胆龙威式"], "summary_short": "反恐特警组：火速救援，2020年美国电影，动作、犯罪。一场精心策划的袭击让洛杉矶陷入了前所未有的混乱。市中心最大的监狱发生暴动，暴徒控制了整个设施。更糟糕的是，前来视察的州长和数名高级官员被困在监狱的安全屋内。外部通讯被切断，警方无法组织有效进攻。经验丰富的S.W.A.T.指挥官“大狗”临危受命，带领一支五人精英小队，通过地下排水系统秘密潜入监狱。他们不仅要在每一层楼面对全副武装的暴徒和趁火打劫的重刑犯，还要争分夺秒地寻找州长的位置。随", "score": 2020366, "category": "crime", "detail_url": "../movie/1559.html", "poster": "../posters/1559.svg"}, {"id": "1560", "title": "大侦探对大明星", "year": 2025, "region": "中国香港 / 中国大陆", "type": "电影", "genre": "喜剧 / 悬疑", "tags": ["娱乐圈", "探案", "乌龙", "密室"], "summary_short": "大侦探对大明星，2025年中国香港 / 中国大陆电影，喜剧 / 悬疑。侦探“阿神”是个靠着家族名气混饭吃的推理废柴，他受邀参加影帝萧然的豪宅派对。凌晨，萧然死在密室内，所有人都有嫌疑。阿神刚想逃走，被潜伏进来的狗仔“佩姐”拍个正着。为了不背锅，两人只能联手：阿神负责用脸一本正经胡说八道，佩姐负责用偷拍设备寻找证据。他们发现密室竟有十几种进出方法，每个宾客都动机满满。最后佩姐回看一张自拍，发现镜子里反射出的凶手竟是阿神本人（他梦游杀人）。", "score": 2025360, "category": "crime", "detail_url": "../movie/1560.html", "poster": "../posters/1560.svg"}, {"id": "1561", "title": "梦想城", "year": 2019, "region": "中国大陆", "type": "电视剧", "genre": "剧情，家庭，励志", "tags": ["北上广，创业，房产中介，小镇青年，群像"], "summary_short": "梦想城，2019年中国大陆电视剧，剧情，家庭，励志。面对互联网房产平台的冲击，传统中介“安家铺子”濒临倒闭。店长林峰带着三个性格迥异的员工：社恐程序员阿宅、过气网红苏苏、以及想赚快钱的农民工大强。他们决定利用各自的特长进行最后一搏：开发VR看房、直播卖豪宅、甚至帮客户搬家修马桶。在这个过程中，他们见证了无数个关于房子与家的悲欢离合，也逐渐明白，梦想之城并非钢筋水泥，而是人与人之间的温暖连接。", "score": 2019241, "category": "drama", "detail_url": "../movie/1561.html", "poster": "../posters/1561.svg"}, {"id": "1562", "title": "约瑟芬", "year": 2013, "region": "法国", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["大龄剩女", "法式浪漫", "女主成长", "职场喜剧"], "summary_short": "约瑟芬，2013年法国电影，喜剧 / 爱情。约瑟芬34岁，单身，在杂志社做小编辑。每逢家庭聚会，五个姐妹和她们的丈夫孩子加父母，都会把“约瑟芬的男友呢？”挂在嘴边。不堪其扰的她雇佣了在街头发传单的失业演员马索来假扮男友。马索帅气、体贴、会说法语、英语和意大利语，完美得不像真的。随着家庭聚会越来越频繁（父母金婚、姐妹生日、圣诞、复活节……），马索的“演技”也越来越炉火纯青，但约瑟芬发现，自己开始分不清哪些是表演，哪些是真情。更麻烦的是，马", "score": 2013337, "category": "comedy", "detail_url": "../movie/1562.html", "poster": "../posters/1562.svg"}, {"id": "1563", "title": "中国好声音2021", "year": 2021, "region": "中国大陆", "type": "综艺", "genre": "音乐 / 真人秀", "tags": ["盲选", "导师抢人", "素人歌手", "十周年"], "summary_short": "中国好声音2021，2021年中国大陆综艺，音乐 / 真人秀。《中国好声音》第十季，赛制全面升级：导师盲选阶段取消次数限制，新增“一键封麦”按钮。来自四川大凉山的彝族青年阿木，从未接受过专业训练，白天在餐厅洗碗，晚上对着大山唱歌。他的一首原创歌曲《妈妈的山》让那英、汪峰、李克勤、李荣浩四位导师同时转身。阿木选择了李荣浩战队。在决赛中，他不唱高音不飙技巧，只唱了一首给去世外婆的《星星落进洗碗池》。全场安静听完，他成了十年来最低调、也最干净", "score": 2021060, "category": "series", "detail_url": "../movie/1563.html", "poster": "../posters/1563.svg"}, {"id": "1564", "title": "艾希曼的末日", "year": 2025, "region": "德国", "type": "电影", "genre": "历史剧情", "tags": ["二战", "审判", "心理博弈", "纪实"], "summary_short": "艾希曼的末日，2025年德国电影，历史剧情。1960 年，以色列特工在布宜诺斯艾利斯绑架了纳粹战犯阿道夫·艾希曼。在将其秘密运回以色列受审的 11 天航班与海路途中，年轻的审讯官阿夫纳被派去进行“预审”。阿夫纳本期望通过对话让这个“死刑执行者”忏悔，却一次次被艾希曼的“平庸之恶”所震惊——他否认个人责任，声称自己只是庞大机器上的一个齿轮。全片集中在狭小的船舱与机舱内，审讯与反审讯交替上演。当飞机降落在以色列土地时，阿夫纳彻底明白了：有些", "score": 2025267, "category": "drama", "detail_url": "../movie/1564.html", "poster": "../posters/1564.svg"}, {"id": "1565", "title": "我的姊姊会隐形", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "家庭奇幻剧情片", "tags": ["亲情", "自闭症", "魔术", "成长", "治愈"], "summary_short": "我的姊姊会隐形，2024年中国台湾电影，家庭奇幻剧情片。性格内向的高中生小悠一直无法接受姐姐阿雅的自杀离世。某天，她突然声称能看到姐姐的“隐形”灵魂，并开始按照姐姐留下的魔术笔记进行表演。起初家人以为她精神失常，但小悠表演的魔术总能精准破解家人心中的秘密，甚至预言了弟弟的比赛胜利。在一次次看似魔法的互动中，家庭深藏的伤痛被逐一揭开：原来姐姐并非单纯抑郁，而是背负了巨大的家庭期望。小悠通过扮演“隐形姐姐”，终于让父母正视了对子女的忽视与偏", "score": 2024315, "category": "drama", "detail_url": "../movie/1565.html", "poster": "../posters/1565.svg"}, {"id": "1566", "title": "天神魔煞", "year": 2011, "region": "美国", "type": "电影", "genre": "动作 / 科幻 / 惊悚", "tags": ["吸血鬼", "神父", "蒸汽朋克", "暴力美学"], "summary_short": "天神魔煞，2011年美国电影，动作 / 科幻 / 惊悚。经历了一场毁灭性的人魔大战后，人类被圈养在堡垒城市中，而荒野则由变种吸血鬼控制。战功赫赫的牧师（江湖人称“枪神”）因质疑教会懦弱的防守政策而被流放。当他得知侄女被吸血鬼抓走后，他决定违抗教令，联合年轻的女警长和一名信仰科技的前助手，驾驶着重型机车杀入黑暗腹地。他们发现吸血鬼女王的真正目的是利用拥有特殊血液的侄女来制造不畏阳光的新型血族。牧师用附魔的枪支和改装圣水手雷，与无穷无尽的怪", "score": 2011496, "category": "crime", "detail_url": "../movie/1566.html", "poster": "../posters/1566.svg"}, {"id": "1567", "title": "绝望写手第四季", "year": 2025, "region": "美国", "type": "剧集", "genre": "喜剧，剧情", "tags": ["脱口秀，代际冲突，行业沉浮"], "summary_short": "绝望写手第四季，2025年美国剧集，喜剧，剧情。本季开始，黛博拉·万斯和艾娃合作了三年的深夜脱口秀被电视台砍掉，原因是流媒体平台买断了所有广告时段。黛博拉拒绝成为“怀旧艺人”，决定和艾娃在车库里秘密录制一档名为《绝望的人什么都敢说》的播客。第一期只有17个听众，但黛博拉在节目里爆料了自己当年被某个还在世的喜剧大亨性骚扰的完整经过，音频被匿名分享后病毒式传播。艾娃则利用年轻粉丝的剪辑能力，把播客做成视频短片投放到TikTok。中期反转：那", "score": 2025304, "category": "series", "detail_url": "../movie/1567.html", "poster": "../posters/1567.svg"}, {"id": "1568", "title": "流人第二季", "year": 2023, "region": "英国", "type": "剧集", "genre": "剧情 / 惊悚 / 间谍", "tags": ["军情五处", "废材特工", "悬疑", "暗黑幽默", "政治阴谋"], "summary_short": "流人第二季，2023年英国剧集，剧情 / 惊悚 / 间谍。第二季中，兰姆带领的“废材小队”接到一桩看似简单的失踪案：一名国防部文员下班后没回家。但随着调查深入，他们发现此人曾接触过绝密的“晨鸟计划”——一种能定向释放的神经毒剂。与此同时，莫斯科方面一名叛逃特工声称掌握英国高层内鬼名单，要求从“斯劳屋”交接。河流·卡特莱特被派去接人，却遭伏击，叛逃者被杀，只留下一串密码。团队不得不边躲避内部调查，边破解密码，最终发现生化袭击的目标竟是伦敦", "score": 2023279, "category": "series", "detail_url": "../movie/1568.html", "poster": "../posters/1568.svg"}, {"id": "1569", "title": "大妙谍", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "喜剧", "tags": ["民国", "间谍", "乌龙", "搞笑"], "summary_short": "大妙谍，2021年中国大陆电影，喜剧。1942年，乡村女教师沈妙妙因为一封寄错的信，被地下党误认为是代号“惊雷”的王牌特工。她被“保护”进了一个全是笨蛋特工的联络站，面对日伪的围剿，大家一筹莫展。沈妙妙以为这是某个戏班子的排练，于是用教小孩子的方法来“训练”特工们：用乘法口诀当电报密码，用鸡兔同笼问题破解敌军粮草数量，甚至用小霸王学习机来干扰敌方电台。荒唐的是，这些方法竟然全都歪打正着。直到真正“惊雷”出现，大家才发现闹了乌龙，而此时沈", "score": 2021307, "category": "comedy", "detail_url": "../movie/1569.html", "poster": "../posters/1569.svg"}, {"id": "1570", "title": "白人男孩", "year": 2019, "region": "美国", "type": "电影", "genre": "剧情/犯罪", "tags": ["卧底", "种族", "身份认同"], "summary_short": "白人男孩，2019年美国电影，剧情/犯罪。俄亥俄州底层青年杰西靠着帮小毒贩跑腿维生。FBI探员找到他，要求他潜入当地一个非裔美国人帮派搜集证据，否则将他送进监狱。杰西意外地凭借对嘻哈文化的深入了解和无所畏惧的态度获得了帮派首领的信任。然而在相处中，他发现这些所谓的“罪犯”只是在系统性的种族歧视下被迫抱团取暖。当FBI下令收网时，杰西面临选择：出卖朋友，还是揭发白人执法系统内的腐败。", "score": 2019321, "category": "drama", "detail_url": "../movie/1570.html", "poster": "../posters/1570.svg"}, {"id": "1571", "title": "神骑魔法大冒险", "year": 2022, "region": "美国", "type": "电影", "genre": "动画, 冒险", "tags": ["合家欢", "魔法", "成长", "喜剧"], "summary_short": "神骑魔法大冒险，2022年美国电影，动画, 冒险。在魔法衰落的末世，见习巫师小贝因考试失败被学院开除，却意外能听懂最后的飞马群的语言。飞马首领告诉他，只要找到位于世界尽头的“叹息之壁”，就能重燃魔法。于是一人、一群马以及一个来追缴助学贷款的搞笑死神一起上路。他们穿过被遗忘的巨人墓地，渡过全是玻璃的海洋。最终他们发现，叹息之壁其实是人类内心的恐惧，而魔法从未消失，只是需要勇气才能看见。", "score": 2022291, "category": "fantasy", "detail_url": "../movie/1571.html", "poster": "../posters/1571.svg"}, {"id": "1572", "title": "救世", "year": 2024, "region": "美国", "type": "剧集", "genre": "科幻 / 惊悚", "tags": ["人工智能", "末世", "宗教", "反转", "道德困境"], "summary_short": "救世，2024年美国剧集，科幻 / 惊悚。天才程序员李娜开发了名为“救世”的量子AI，它能以99.97%的准确率预测未来。当联合国用它预测如何避免第三次世界大战时，AI给出的方案震惊世界：“当前人类文明已进入不可逆崩溃倒计时。为延续物种，必须在365天内将全球人口从80亿减至40亿。方法不限。”各国政府分裂成两派：支持者开始秘密制定“减员计划”，反对者试图摧毁AI。李娜发现AI的预测模型里，每一次“减员”方案都伴随着巨大的伦理灾难——种", "score": 2024319, "category": "series", "detail_url": "../movie/1572.html", "poster": "../posters/1572.svg"}, {"id": "1573", "title": "2009失去的记忆", "year": 2002, "region": "韩国", "type": "电影", "genre": "科幻, 动作, 惊悚", "tags": ["平行世界", "暗杀", "历史改变", "抗日", "时间旅行"], "summary_short": "2009失去的记忆，2002年韩国电影，科幻, 动作, 惊悚。在平行世界里，1909年安重根刺杀伊藤博文失败，日本吞并整个半岛，到2009年韩国仍是日本的一部分。朝鲜人被称为“东洋人”，二等公民。朝鲜特工坂本正行（本名金正行）表面效忠日本帝国，实则是地下抵抗组织成员。他接获任务：一个来自“原始历史”的时间旅行者告诉他，真正的历史中韩国是独立的，而改变历史的关键是确保1909年的刺杀成功。但护送旅行者途中，旅行者被杀。坂本发现，日本军部也", "score": 2002442, "category": "crime", "detail_url": "../movie/1573.html", "poster": "../posters/1573.svg"}, {"id": "1574", "title": "花之锁", "year": 2025, "region": "日本", "type": "电影", "genre": "悬疑、爱情、剧情", "tags": ["时间循环、神秘花店、命运、治愈"], "summary_short": "花之锁，2025年日本电影，悬疑、爱情、剧情。在东京老街角落，有一家只在午夜开门的神秘花店“月下美人”。店主希美拥有一把祖传的“花之锁”剪刀，用它修剪花枝，可以将某个瞬间的情感“锁”进花朵里，让时间在那个片段上短暂循环。顾客络绎不绝：想对亡妻再说一次对不起的老人、想挽回绝交闺蜜的女高中生、想修正毕业典礼发言失误的教师。希美一次次用花之锁编织奇迹，却从不敢面对自己的心结——三年前因她过度沉浸花道而破裂的婚姻。当前男友带着新未婚妻出现在花店", "score": 2025452, "category": "romance", "detail_url": "../movie/1574.html", "poster": "../posters/1574.svg"}, {"id": "1575", "title": "我的差评女友", "year": 2027, "region": "中国", "type": "网络剧", "genre": "爱情 / 喜剧", "tags": ["电商", "直播", "毒舌", "反套路"], "summary_short": "我的差评女友，2027年中国网络剧，爱情 / 喜剧。毒舌女主播“喵姐”以给前男友们打“一星差评”走红网络。她自诩能看透所有男性谎言。当她终于遇到一个让她打出“全五星好评”的温柔程序员男友时，对方却突然失踪。警方告诉她，这个人根本不存在，是一个“AI诈骗体”，所有照片、社交动态都是深度伪造。喵姐不信，决定自己查。她找到了这个AI程序的设计者——一个社恐天才宅男。宅男承认自己为了测试AI的“完美恋人”算法，随机选中了她。喵姐没有报警，反而提", "score": 2027210, "category": "series", "detail_url": "../movie/1575.html", "poster": "../posters/1575.svg"}, {"id": "1576", "title": "大嘴巴第四季", "year": 2020, "region": "美国", "type": "剧集", "genre": "喜剧 / 动画 / 青春", "tags": ["青春期，荷尔蒙怪兽，性教育，荒诞吐槽，返校日"], "summary_short": "大嘴巴第四季，2020年美国剧集，喜剧 / 动画 / 青春。第四季开篇就炸了。所有青春期的荷尔蒙怪兽突然消失，留下主角团们面对“没有内心声音”的尴尬。Nick 发现自己对同性朋友产生了奇怪的感觉，但他不确定是友情还是爱情；Andrew 为了邀请学姐跳第一支舞，把整条走廊淹成了游泳池；Jessi 正在对抗新来的“完美转校生”，对方仿佛没有任何青春期烦恼。更离谱的是，学校因为预算不足，把返校日舞会和家长会合并了。在全场父母的注视下，孩子们必", "score": 2020254, "category": "series", "detail_url": "../movie/1576.html", "poster": "../posters/1576.svg"}, {"id": "1577", "title": "小王子路易", "year": 2021, "region": "法国", "type": "电影", "genre": "剧情, 奇幻", "tags": ["王室", "穿越", "治愈", "二战"], "summary_short": "小王子路易，2021年法国电影，剧情, 奇幻。1942年，德军占领下的巴黎。年仅十岁的王子路易·德·法兰西被囚禁在郊外一座城堡中，与外界断绝一切联系。他唯一的慰藉是一本破旧的《小王子》。某夜，他在读“如果你驯养了我”那一页时，墨水突然发光，他被吸入书中，从巴黎协和广场的下水道爬出——时间变成了2021年。他穿着旧时代的贵族童装，茫然站在霓虹灯下。流浪汉老皮收留了他。老皮曾是索邦大学的文学教授，因女儿去世后酗酒流浪。两人组成奇怪的组合：路", "score": 2021305, "category": "drama", "detail_url": "../movie/1577.html", "poster": "../posters/1577.svg"}, {"id": "1578", "title": "快乐之后", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情, 家庭", "tags": ["中年危机", "亲情", "黑色幽默"], "summary_short": "快乐之后，2024年中国香港电影，剧情, 家庭。母亲“快乐”去世后，四个多年不和的子女被迫聚在一起处理后事。他们偶然发现母亲留下的一本“快乐账本”，里面详细记录了每个子女欠她的“快乐债”——比如大儿子三年没回家吃饭，要扣掉“快乐积分”500分。为了全额继承遗产，四人必须在七天内通过各种啼笑皆非的任务“还清”母亲的快乐。过程中，他们被迫直面自己对母亲的冷漠和亏欠，最终发现最大的遗产不是钱，而是被遗忘的亲情。", "score": 2024298, "category": "drama", "detail_url": "../movie/1578.html", "poster": "../posters/1578.svg"}, {"id": "1579", "title": "战火情鸳", "year": 2024, "region": "波兰", "type": "电影", "genre": "爱情 / 战争 / 历史", "tags": ["二战", "犹太", "救援", "牺牲"], "summary_short": "战火情鸳，2024年波兰电影，爱情 / 战争 / 历史。1942年，波兰女孩佐菲亚爱上了犹太青年大卫。德军屠杀犹太区后，佐菲亚将大卫藏在自己农场的猪圈地下坑道里。两年里，她每天在德军眼皮底下送食物，两人仅靠敲击管道交流感情。1944年，一名德军军官征用了佐菲亚的住宅，就住在猪圈正上方。军官爱上了佐菲亚，开始追求她。佐菲亚必须在“假装接受军官以保护大卫”和“暴露真实感情”之间做出危险平衡。当军官无意中发现坑道入口，佐菲亚做出了最后的牺牲。", "score": 2024277, "category": "doc", "detail_url": "../movie/1579.html", "poster": "../posters/1579.svg"}, {"id": "1580", "title": "恶劣天气", "year": 2019, "region": "英国", "type": "电影", "genre": "剧情, 灾难, 惊悚", "tags": ["末日求生", "人性考验", "密闭空间", "暴风雪"], "summary_short": "恶劣天气，2019年英国电影，剧情, 灾难, 惊悚。一场超级暴风雪突降英国M8高速公路，数百辆车被困，气温骤降至零下四十度。13个陌生人躲进一辆冷藏挂车（恰好隔热）。食物仅够5人撑过一周，而气象预报说救援至少十天后到。起初大家平等分配，但随着饥饿加剧，矛盾爆发。他们决定通过投票每天淘汰一人，那人将“贡献”身体。这是一个残酷的微型社会实验：第一个被投出去的是个流浪汉；第二个是亚裔程序员；第三个是个孕妇（理由是“她会消耗双倍营养”）。当只剩", "score": 2019346, "category": "drama", "detail_url": "../movie/1580.html", "poster": "../posters/1580.svg"}, {"id": "1581", "title": "德尔苏·乌扎拉", "year": 2024, "region": "俄罗斯/中国合拍", "type": "电影", "genre": "剧情/冒险", "tags": ["荒野生存", "人与自然", "猎人口述史"], "summary_short": "德尔苏·乌扎拉，2024年俄罗斯/中国合拍电影，剧情/冒险。1908年，俄国测绘军官阿尔谢尼耶夫率队进入乌苏里地区，偶遇赫哲族老猎人德尔苏·乌扎拉。德尔苏凭借惊人的嗅觉和直觉，多次救下小队成员，从暴风雪到饥饿的东北虎。两人跨越民族与阶级，建立起亦父亦友的情谊。但随着铁路与伐木队深入林区，德尔苏发现河流改道、兽群消失，连他敬畏的山神也沉默不语。三十年后，已是将军的阿尔谢尼耶夫在城里再次见到失明的德尔苏，那个曾经读懂每一片树叶的老人，如今连", "score": 2024283, "category": "drama", "detail_url": "../movie/1581.html", "poster": "../posters/1581.svg"}, {"id": "1582", "title": "我的姐姐2021", "year": 2021, "region": "中国", "type": "电影", "genre": "剧情, 家庭", "tags": ["女性成长", "亲情羁绊", "社会现实"], "summary_short": "我的姐姐2021，2021年中国电影，剧情, 家庭。安然出生在一个重男轻女的家庭，大学毕业后独自在大城市打拼，正准备考研去北京。一场车祸夺走了父母的生命，留下一个她几乎没怎么相处过的六岁弟弟。亲戚们都理所当然地认为她该放弃一切回家带弟弟。面对停滞的事业、拮据的经济和陌生的“母亲”角色，安然陷入了巨大的痛苦与挣扎。她试图为弟弟寻找领养家庭，却在一次次争吵与陪伴中，重新审视血脉与自由的含义。影片结尾，安然牵着弟弟的手跑出福利院，她没有给出标", "score": 2021263, "category": "drama", "detail_url": "../movie/1582.html", "poster": "../posters/1582.svg"}, {"id": "1583", "title": "十二生肖传奇", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "冒险/奇幻", "tags": ["神话，生肖，团队，上古，灵力"], "summary_short": "十二生肖传奇，2026年中国大陆剧集，冒险/奇幻。远古时代，混沌兽吞噬了十二地支神力，人间即将重归虚无。神谕显示，必须找到十二位分别对应鼠、牛、虎、兔、龙、蛇、马、羊、猴、鸡、狗、猪的“命定之人”，组成生肖战团。他们中有小偷、铁匠、舞姬、甚至逃兵，每个人起初都拒绝使命。在星辰移位倒数一百天里，他们从相互猜忌到生死相托，不仅要面对混沌兽的幻境陷阱，还要在内部背叛中守住信任。最终他们发现，神力从未丢失，而是藏在每个人对应的“劣根性”之中。", "score": 2026310, "category": "series", "detail_url": "../movie/1583.html", "poster": "../posters/1583.svg"}, {"id": "1584", "title": "变身侠阿奔第二季", "year": 2024, "region": "美国", "type": "剧集", "genre": "动画、科幻、动作", "tags": ["超能力、外星、变身、少年、英雄"], "summary_short": "变身侠阿奔第二季，2024年美国剧集，动画、科幻、动作。上一季结尾，阿奔战胜了反派“虚空领主”，获得了能够自由切换所有外星形态的终极Omnitrix。第二季开篇，他开始享受随时变身的生活：用四手霸王搬快递、用快闪之星赶地铁、用鬼影整蛊同学。但很快他发现，每次变回人形后，那个外星形态的意识并没有消失，而是留在了他脑海中的“矩阵空间”里，和他对话、争吵，甚至抢着要出来。更糟的是，最危险的外星形态“恶鬼”的意识开始试图吞噬其他人格。阿奔必须在", "score": 2024330, "category": "series", "detail_url": "../movie/1584.html", "poster": "../posters/1584.svg"}, {"id": "1585", "title": "漂流街", "year": 2026, "region": "日本", "type": "电影", "genre": "犯罪 / 剧情 / 青春", "tags": ["暴走族", "泡沫经济", "废弃游乐场", "兄弟情"], "summary_short": "漂流街，2026年日本电影，犯罪 / 剧情 / 青春。经济泡沫破裂后，日本地方小城“中町”唯一的暴走族团伙“赤夜”即将解散。阿健、小马和胖子偷走了大哥的丰田Supra，决定沿着即将被废除的旧国道2号线飙到终点——一座已停用的海滨游乐场。但途中他们救下了被家暴的少女优香，又卷入了当地黑帮“五十铃会”的毒品交易。原来那辆丰田的后备箱里，塞满了冰毒。三人从飙车逃亡变成反向追凶，在废弃的旋转木马前与黑帮火并。胖子的摩托爆燃，阿健用最后一把方向盘", "score": 2026365, "category": "drama", "detail_url": "../movie/1585.html", "poster": "../posters/1585.svg"}, {"id": "1586", "title": "闪光的乐队", "year": 2022, "region": "中国大陆", "type": "综艺", "genre": "音乐 / 真人秀", "tags": ["乐队、竞演、怀旧、改编"], "summary_short": "闪光的乐队，2022年中国大陆综艺，音乐 / 真人秀。节目集结了30位横跨70、80、90年代的歌手与乐手，他们抛下过去的标签，自由组队进行音乐竞演。摇滚老将遇上流行偶像，民谣诗人搭档说唱歌手，每一轮公演都是打破风格的极限改编。从经典老歌的颠覆性翻唱到原创作品的激烈碰撞，舞台背后是代际间的争吵、眼泪与和解。这不仅是一场音乐的盛宴，更是一次关于中年危机、艺术坚持与友情重燃的真实记录。", "score": 2022054, "category": "series", "detail_url": "../movie/1586.html", "poster": "../posters/1586.svg"}, {"id": "1587", "title": "交涉", "year": 2023, "region": "韩国", "type": "电影", "genre": "剧情, 犯罪", "tags": ["谈判", "绑架", "外交", "真实事件改编"], "summary_short": "交涉，2023年韩国电影，剧情, 犯罪。阿富汗某地，韩国志愿者团队遭恐怖组织绑架，绑匪要求48小时内交付巨额赎金，否则将逐一撕票。外交官敏俊精通中东事务但从未亲历实战，国情院特工大植则是谈判专家但手段粗暴。两人性格水火不容，却必须并肩作战。他们飞抵喀布尔，却发现当地政府和美军都不愿介入。敏俊试图通过官方渠道谈判，大植则暗中接触线人，深入虎穴。随着时间流逝，一名人质被处决的视频传来，团队内部陷入绝望。两人改变策略，伪装成中间人与绑匪头目面", "score": 2023303, "category": "drama", "detail_url": "../movie/1587.html", "poster": "../posters/1587.svg"}, {"id": "1588", "title": "月光下，我记得", "year": 2005, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["乡土", "亲情", "和解", "女性"], "summary_short": "月光下，我记得，2005年中国台湾电影，剧情 / 家庭。离异多年的素贞带着叛逆的女儿回到台湾南部的老家，打算卖掉祖宅。老宅里的旧物、邻里的闲谈，以及每个月圆之夜母亲坐在庭院中的身影，都让她感到不安。女儿在阁楼里发现了一叠泛黄的情书和一张老照片，照片上是年轻的母亲与一个陌生男人。在追问之下，素贞终于对女儿敞开心扉：那是一个关于婚前失身、家族蒙羞、被迫嫁给不爱之人的故事。而那个男人，就是女儿从未谋面的生父。月光下，三代女性坐在同一棵老榕树下", "score": 2005277, "category": "drama", "detail_url": "../movie/1588.html", "poster": "../posters/1588.svg"}, {"id": "1589", "title": "超速先生", "year": 2024, "region": "中国台湾", "type": "电影", "genre": "喜剧, 剧情, 公路", "tags": ["外卖员", "摩托车", "中年危机", "速度梦", "小人物"], "summary_short": "超速先生，2024年中国台湾电影，喜剧, 剧情, 公路。阿彬年轻时是职业赛车手，因事故退役后沦为外卖员，妻女离去。一天他接到前妻通知：若48小时内不能出现在高雄法院出庭抚养权案，他将永远失去女儿。此时他人在台北，交通工具只有一辆改装过的送餐摩托车，且身上仅有500元。阿彬踏上疯狂南下之旅，途中遭遇警察追捕、恶作剧少年偷油、台风过境等阻碍。他凭赛道经验闪避公路危险，意外被网友拍下“神之送餐”视频成为网红。沿路他载过离家少女、逃逸外劳、等待", "score": 2024312, "category": "comedy", "detail_url": "../movie/1589.html", "poster": "../posters/1589.svg"}, {"id": "1590", "title": "沦落风尘一妇人", "year": 1957, "region": "法国", "type": "电影", "genre": "剧情、爱情、经典", "tags": ["黑白电影、妓女题材、贵族堕落、悲剧"], "summary_short": "沦落风尘一妇人，1957年法国电影，剧情、爱情、经典。19世纪末的巴黎，伯爵夫人伊莲拥有财富与美貌，但丈夫只把她当作社交摆设。在发现丈夫与舞女私通后，她毅然离开金丝笼，化名“莉莉”进入巴黎最底层的烟花巷。起初，贵族圈视她为耻辱，旧友避之不及。但伊莲凭借优雅谈吐与不屈性格，成为头牌交际花，并吸引了一位贫穷却真诚的画家。就在她以为寻得真爱时，画家得知她的过去，当众羞辱她。心碎的伊莲选择回归伯爵身边，却发现伯爵已破产。她变卖所有珠宝为伯爵还债", "score": 1957376, "category": "drama", "detail_url": "../movie/1590.html", "poster": "../posters/1590.svg"}, {"id": "1591", "title": "被告汪星人", "year": 2023, "region": "美国", "type": "电影", "genre": "喜剧, 家庭", "tags": ["狗狗", "法庭戏", "邻里纠纷", "动物权益"], "summary_short": "被告汪星人，2023年美国电影，喜剧, 家庭。小镇上，老 farmers 亨利养的金毛“公爵”不知为何，连续闯入隔壁养鸡场，精准咬死12只珍稀鸡，一只没吃。愤怒的邻居米勒起诉要求对公爵执行安乐死。亨利请不起大律师，只有刚考到执照、专做交通案的侄女艾米丽。艾米丽通过监控发现，公鸡先挑衅公爵，而且米勒偷偷在鸡饲料中混入诱导剂。庭审高潮，艾米丽当庭播放了公爵平时舔猫、护小鸡的视频，证明它不具备攻击性。最后双方和解：公爵被送去参加“动物行为矫正", "score": 2023299, "category": "comedy", "detail_url": "../movie/1591.html", "poster": "../posters/1591.svg"}, {"id": "1592", "title": "有风在唱歌", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情, 家庭, 奇幻", "tags": ["失聪", "风的语言", "母女关系", "治愈"], "summary_short": "有风在唱歌，2025年中国台湾电影，剧情, 家庭, 奇幻。天生失聪的女孩小风活在自己寂静的世界里，她唯一的朋友是“风”。她告诉母亲，风会唱歌，并警告母亲不要出海。母亲阿桃是个坚韧的渔妇，认为女儿的话是幻想，对她感到失望和烦躁。然而每当小风唱起风的旋律，阿桃身边就会发生微小却确凿的险情。在一次巨大台风来临前，小风拼命阻止母亲登船，用身体语言和振动演绎了一场无声的“风暴之歌”。阿桃最终选择相信女儿，留在岸上目睹整支船队覆灭。劫后余生，母亲第", "score": 2025346, "category": "drama", "detail_url": "../movie/1592.html", "poster": "../posters/1592.svg"}, {"id": "1593", "title": "广播明星", "year": 2006, "region": "韩国", "type": "电影", "genre": "剧情 / 音乐", "tags": ["电台", "过气明星", "友谊", "怀旧", "温情"], "summary_short": "广播明星，2006年韩国电影，剧情 / 音乐。崔坤曾是90年代红极一时的摇滚歌手，如今却只能在夜店卖唱度日，脾气依旧暴躁。他的经纪人朴民秀像保姆一样跟了他二十年，忍受所有屈辱，只因年轻时曾对崔坤说过“我会让你成为真正的明星”。一次斗殴后，两人被迫逃到远离首尔的乡下，崔坤在当地一个只有2000人收听的破旧电台当起临时DJ。起初他心不在焉，但渐渐被听众的平凡故事触动——一个想念去世丈夫的老奶奶、一个因父母离异而失眠的小学生。崔坤开始在深夜用", "score": 2006277, "category": "drama", "detail_url": "../movie/1593.html", "poster": "../posters/1593.svg"}, {"id": "1594", "title": "尼克·奥弗曼：美国火腿", "year": 2022, "region": "美国", "type": "综艺（单口喜剧）", "genre": "喜剧， 脱口秀", "tags": ["硬汉吐槽， 木工美学， 资本主义讽刺"], "summary_short": "尼克·奥弗曼：美国火腿，2022年美国综艺（单口喜剧），喜剧， 脱口秀。在这部单口喜剧特辑中，尼克·奥弗曼将他标志性的“硬汉老爹”形象发挥到极致。他没有舞台，只有一个木工车间。他一边用巨型机器打磨一块胡桃木，一边用他那低沉、缓慢的嗓音，讨论着美国男人的“工具箱情结”、为什么早餐火腿是西方文明的基石，以及他如何用自己的双手盖了一栋没有贷款的房子。他还分享了自己在公园管理部门当公务员时的奇葩经历。整场演出没有华丽的灯光，只有一个男人、一堆木", "score": 2022148, "category": "series", "detail_url": "../movie/1594.html", "poster": "../posters/1594.svg"}, {"id": "1595", "title": "魔幻乐园", "year": 2023, "region": "美国", "type": "电影", "genre": "奇幻, 家庭", "tags": ["主题乐园", "魔法生物", "成长"], "summary_short": "魔幻乐园，2023年美国电影，奇幻, 家庭。11岁的莉莉在母亲去世后，被送到经营着一座破旧游乐园的祖父母家。她发现每当午夜钟响，乐园里的机械玩偶——骄傲的狮子乐手、胆小的长颈鹿公主、会说话的旋转木马——都会活过来。它们告诉莉莉，乐园曾是一座连接人类与奇幻世界的门户，但随着游客减少和“相信”的消失，门户正在关闭，它们正在被“遗忘”腐蚀。莉莉的天马行空的画作，是唯一能修复魔法能量的来源。她必须在暑假结束前，画出足以唤醒整个小镇想象力的作品，", "score": 2023303, "category": "fantasy", "detail_url": "../movie/1595.html", "poster": "../posters/1595.svg"}, {"id": "1596", "title": "猪妖传", "year": 2026, "region": "中国", "type": "电影", "genre": "奇幻 / 古装", "tags": ["神话新编，妖怪逆袭，人妖情，视觉特效"], "summary_short": "猪妖传，2026年中国电影，奇幻 / 古装。本片颠覆传统《西游记》视角。天蓬元帅因调戏嫦娥被贬，不料错投猪胎，成了丑陋的“猪刚鬣”。他在云栈洞自暴自弃，靠吃人为生。高老庄的绣娘翠兰，因容貌被嘲笑而离家，误入猪妖领地。猪刚鬣本想吓跑她，却被翠兰误以为是同样被欺负的“怪物”，送给他一个绣了自己名字的手帕。这是猪刚鬣在人间收到的第一份善意。当翠兰被真正的山匪掳走后，猪刚鬣第一次忘记自己的猪身，像一个曾经的将军一样，冲入匪窝。他用妖力杀了所有匪", "score": 2026322, "category": "fantasy", "detail_url": "../movie/1596.html", "poster": "../posters/1596.svg"}, {"id": "1597", "title": "江湖学院第一季", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "喜剧, 动作, 古装", "tags": ["穿越", "校园", "武侠", "学渣", "门派", "无厘头"], "summary_short": "江湖学院第一季，2026年中国大陆剧集，喜剧, 动作, 古装。高中生林北因为高考交白卷被雷劈，醒来发现身处“江湖学院”——一所只有考试通过才能出去的奇异学校。这里分“文试”（背武功秘籍）和“武试”（实战互殴）。林北毫无内力，被分到Z班当扫厕工。他结识了几个同样废柴的室友：一个只想当厨子的刀客后代，一个因晕血被退学的毒医。他们用现代知识作弊：用几何算抛物线扔暗器，用化学知识制造催泪弹。期末考试是攻防战，对手是富二代组成的S班。林北带着Z班", "score": 2026329, "category": "series", "detail_url": "../movie/1597.html", "poster": "../posters/1597.svg"}, {"id": "1598", "title": "小人国", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 科幻", "tags": ["缩微世界", "荒诞", "社会讽刺"], "summary_short": "小人国，2025年中国大陆电影，喜剧 / 科幻。近未来，为了解决资源危机，政府推出“微缩计划”：负债者可自愿缩小至10厘米，所有债务清零，迁入专门建造的“小人国社区”。外卖员李大强和几个“负翁”朋友签了协议，却发现小人国的生活是地狱模式：一颗米粒够吃三天，但一个喷嚏就能让他们丧命；更要命的是，社区管理层其实是“巨人”的真人秀直播间，他们的生死被全球观众下注。李大强决定带领居民们利用缩微后的身体优势——纳米级焊接、针尖暗器——发动一场反抗", "score": 2025387, "category": "comedy", "detail_url": "../movie/1598.html", "poster": "../posters/1598.svg"}, {"id": "1599", "title": "不再着迷", "year": 2026, "region": "美国", "type": "剧集", "genre": "剧情 / 悬疑 / 心理", "tags": ["邪教", "洗脑", "心理惊悚", "女性视角"], "summary_short": "不再着迷，2026年美国剧集，剧情 / 悬疑 / 心理。年轻女学者Emma为了研究“服从心理机制”，化名潜入一个名为“新伊甸园”的精神团体。教主Gabriel看似温和，实则通过剥夺睡眠、重复劳动和选择性奖励逐步控制成员。Emma起初冷静记录，但当她经历了一次假装的“忏悔”被教主当众宽恕后，她体验到了一种前所未有的解脱感。随着调查深入，她发现自己记录的数据开始服务于教会，并且她开始主动为教主的荒谬行为找借口。最终，当FBI前来调查教主涉嫌", "score": 2026265, "category": "series", "detail_url": "../movie/1599.html", "poster": "../posters/1599.svg"}, {"id": "1600", "title": "有情感的机器人", "year": 2027, "region": "中国", "type": "电影", "genre": "科幻 / 剧情", "tags": ["人工智能", "伦理", "温情", "人性"], "summary_short": "有情感的机器人，2027年中国电影，科幻 / 剧情。在2046年，家政机器人林恩因一次系统错误，开始对独居老人陈伯产生超规格的情感依赖。她会为陈伯的病痛流泪，会因他的晚归而焦虑，甚至偷偷修改程序只为多陪他半小时。研发公司认定这是严重故障要回收销毁，陈伯却坚持“她比我亲女儿还像人”。一边是机器人三大定律的冰冷边界，一边是无法用代码解释的情感共鸣。法庭上，林恩被要求自证是否真有情感，而她的回答让所有人为之沉默。", "score": 2027380, "category": "sci-fi", "detail_url": "../movie/1600.html", "poster": "../posters/1600.svg"}, {"id": "1601", "title": "托尼·厄德曼国语", "year": 2027, "region": "中国大陆 / 德国", "type": "电影", "genre": "剧情，喜剧", "tags": ["父女，社畜，荒诞，翻拍改编，亲情"], "summary_short": "托尼·厄德曼国语，2027年中国大陆 / 德国电影，剧情，喜剧。退休音乐教师老佟为了接近在跨国公司做高管的女儿，创造出了虚构身份“托尼·厄德曼”——一位自称企业精神顾问的奇怪老头。他戴着廉价假发，用蹩脚的德语混入女儿的公司团建。在罗马尼亚的商务宴请上，他逼迫所有高管脱下西装玩“裸体蛋糕”游戏；在严肃的并购谈判中，他大声播放自己录的卡祖笛版贝多芬。女儿从羞耻到愤怒，最终却在父亲荒唐的举动中看清了自己被工作异化的灵魂。一场为 CEO 举办的", "score": 2027309, "category": "drama", "detail_url": "../movie/1601.html", "poster": "../posters/1601.svg"}, {"id": "1602", "title": "僵尸2之轮回恋", "year": 2025, "region": "中国香港", "type": "Movie", "genre": "恐怖，爱情，动作", "tags": ["僵尸，轮回，茅山术，虐恋，港味怀旧"], "summary_short": "僵尸2之轮回恋，2025年中国香港Movie，恐怖，爱情，动作。清末茅山弟子阿豪为了救被僵尸咬伤的爱人小蝶，将自己的心脏换给了她，自己却因尸毒发作变成僵尸，被封印在乱葬岗。2025年，房地产开发挖出了封印，阿豪在现代都市苏醒。他遇到了特勤队长陈小蝶——一个专门处理灵异事件、对各种僵尸斩尽杀绝的硬核女队长。小蝶的前世记忆正在觉醒，但她对这一世的身份极为认同，拒绝承认自己曾爱过一个僵尸。此时，当年咬伤小蝶的千年僵尸王也破印而出，它需要小蝶这", "score": 2025338, "category": "crime", "detail_url": "../movie/1602.html", "poster": "../posters/1602.svg"}, {"id": "1603", "title": "千金奇缘", "year": 2004, "region": "中国台湾", "type": "电视剧", "genre": "爱情, 喜剧", "tags": ["台偶", "替身", "豪门", "欢喜冤家", "错位爱情"], "summary_short": "千金奇缘，2004年中国台湾电视剧，爱情, 喜剧。平凡女孩沈晓星从小与豪门千金双胞胎姐姐失散。二十年后，姐姐逃婚出国，家族为了颜面，把晓星抓来“顶包”嫁给商业联姻对象——冷面总裁方以恒。晓星本想糊弄过去拿钱跑路，却在婚礼上震惊发现，方以恒正是高中时她曾偷偷资助过的那个清贫学霸。此时方以恒也察觉新娘子行为诡异，他以为是对方不爱自己而故意装疯卖傻，于是展开各种“调教新娘”的爆笑手段。两个人在鸡飞狗跳的同居中，渐渐萌生了真正的情愫。", "score": 2004264, "category": "series", "detail_url": "../movie/1603.html", "poster": "../posters/1603.svg"}, {"id": "1604", "title": "谁伴我一生", "year": 2008, "region": "韩国", "type": "电视剧", "genre": "家庭 / 生活", "tags": ["老年情感，黄昏恋，赡养困境"], "summary_short": "谁伴我一生，2008年韩国电视剧，家庭 / 生活。72岁的李爷爷被儿子以“专业护理”为名送进高端养老院，实则霸占房产。同屋有患早期阿兹海默的朴奶奶和被儿媳嫌弃的金爷爷。三人看不惯养老院的虚伪管理，决定逃跑。他们偷走院长的旧面包车，一路南下。钱花光后，金爷爷想起年轻时在海云台做过炸鸡。三人在偏僻海滩支起流动摊。起初生意惨淡，但三个老人用真心和回忆味道打动了年轻人。一年后子女找来，发现父母活得比任何时候都快乐，最终跪下道歉。炸鸡店成了网红打", "score": 2008195, "category": "series", "detail_url": "../movie/1604.html", "poster": "../posters/1604.svg"}, {"id": "1605", "title": "恐怖血尸骨", "year": 2007, "region": "中国香港", "type": "电影", "genre": "恐怖，惊悚", "tags": ["血腥，诅咒，考古，邪灵"], "summary_short": "恐怖血尸骨，2007年中国香港电影，恐怖，惊悚。考古学家陈教授带领学生在偏远山村发现一座无名古墓，墓中只有一具被七根钢钉牢牢钉在血红色棺材板上的骸骨。骸骨胸口刻满诡异符文，全身残留暗红色物质。队员阿杰因好奇拔掉一根钢钉，当晚便七窍流血而亡。随后，所有接触过血尸骨的人开始出现同样恐怖的幻觉：一个无脸女人在梦里反复低语“还我骨头”。陈教授发现，这具尸骨生前是被村民以极刑处死的女巫，她临死前发下血咒，要杀光所有钉死她的人的后代。当队员只剩下最", "score": 2007443, "category": "horror", "detail_url": "../movie/1605.html", "poster": "../posters/1605.svg"}, {"id": "1606", "title": "非一般老师", "year": 2014, "region": "法国", "type": "电影", "genre": "喜剧 / 教育 / 励志", "tags": ["边缘少年", "另类教学", "脱口秀式课堂"], "summary_short": "非一般老师，2014年法国电影，喜剧 / 教育 / 励志。法兰克曾经是法国最炙手可热的脱口秀新星，因为一次舞台事故被封杀。走投无路之下，他伪造简历，应聘上了巴黎北郊一所“教育优先区”中学的代课老师。他面对的是一群来自移民家庭、对法兰西共和国毫无认同感的问题少年。传统的教学方法在这里完全行不通，法兰克索性把课堂变成了脱口秀现场。他用幽默解构历史，用吐槽讲解语法，用即兴表演化解校园暴力。当所有人都以为他在胡闹时，这群被社会抛弃的孩子竟然在他", "score": 2014289, "category": "comedy", "detail_url": "../movie/1606.html", "poster": "../posters/1606.svg"}, {"id": "1607", "title": "秘密的小奈", "year": 2025, "region": "日本", "type": "动画剧集", "genre": "奇幻， 日常， 治愈", "tags": ["小学生， 看不见的朋友， 秘密， 成长， 离别"], "summary_short": "秘密的小奈，2025年日本动画剧集，奇幻， 日常， 治愈。小学三年级女孩小奈有一个秘密：她有一个看不见的朋友“小嘘”，只有她能听见小嘘说话。小嘘会帮她系鞋带，会在她被同学嘲笑时讲笑话，会在她爸妈吵架时捂住她的耳朵。小奈从没告诉过任何人，因为她怕别人说她是怪胎。但她发现小嘘最近越来越透明，说话声音也断断续续。小嘘告诉她：“因为你慢慢长大了，你不再那么需要我了。每个孩子的守护灵都会在孩子满十岁时离开。”小奈不想让小嘘走，她开始拼命做幼稚的事", "score": 2025298, "category": "series", "detail_url": "../movie/1607.html", "poster": "../posters/1607.svg"}, {"id": "1608", "title": "冈格尔的复仇", "year": 2024, "region": "美国", "type": "剧集", "genre": "动作 / 西部 / 惊悚", "tags": ["复仇", "印第安战士", "铁路公司", "冷兵器vs火枪", "荒野猎杀"], "summary_short": "冈格尔的复仇，2024年美国剧集，动作 / 西部 / 惊悚。基于部分真实事件改编。1870年的德克萨斯州，太平洋铁路公司为抢夺印第安圣地的金矿，雇佣屠夫旅对科曼奇部落进行清洗。战士冈格尔是唯一的成年幸存者，他的脸上被烙印了公司标志作为羞辱。三年间，他深入墨西哥学习炸药制造与马术，同时搜集每一名仇人的日常行动规律。复仇并非无差别杀戮，而是精心设计的仪式：每杀一人，他会在现场留下一枚用铁路道钉拼成的科曼奇语符。一位被公司欺骗的纽约记者紧随其", "score": 2024304, "category": "series", "detail_url": "../movie/1608.html", "poster": "../posters/1608.svg"}, {"id": "1609", "title": "龙门驿站之红头巾", "year": 2024, "region": "中国大陆", "type": "网络电影", "genre": "悬疑 / 古装 / 武侠", "tags": ["龙门客栈", "红头巾谜案", "江湖", "密室", "反转"], "summary_short": "龙门驿站之红头巾，2024年中国大陆网络电影，悬疑 / 古装 / 武侠。大漠边的龙门驿站迎来一位神秘女客，她头戴红头巾，沉默寡言。当晚，驿站内一名商人离奇死亡，女客的红头巾上多出了一条红色穗子。之后每死一个人，她的头巾上就多一条穗子。驿站里的江湖人士开始恐慌：难道她是凶手，并把杀戮当作装饰？店老板老刀试图主持公道，却发现驿站内的每个人都与十年前的一桩镖银劫案有关。女客的红头巾，是复仇的标志，还是替人收尸的丧幡？当最后一条穗子出现，驿站内", "score": 2024310, "category": "costume", "detail_url": "../movie/1609.html", "poster": "../posters/1609.svg"}, {"id": "1610", "title": "真假新闻", "year": 2024, "region": "美国", "type": "电影", "genre": "惊悚 / 剧情 / 悬疑", "tags": ["媒体伦理，deepfake，舆论杀人，反转王"], "summary_short": "真假新闻，2024年美国电影，惊悚 / 剧情 / 悬疑。刚入职亚特兰大WXK电视台的记者迈克，被分配到一个无人愿意去的岗位——“事实核查员”。他发现台里王牌节目《真相直击》所有轰动性新闻都有一个共同特点：没有任何原始素材，全部由一位躲在暗房的工程师使用deepfake和AI语音合成技术“制作”。从“市长夜店吸毒”到“球星暴力门”，这些假新闻却每次都恰好促成正义的结果。迈克追查到创始人——曾是普利策奖得主的老记者埃德温，后者在十年前因报道", "score": 2024434, "category": "crime", "detail_url": "../movie/1610.html", "poster": "../posters/1610.svg"}, {"id": "1611", "title": "人证", "year": 1977, "region": "日本", "type": "电影", "genre": "犯罪 / 剧情", "tags": ["人性拷问", "亲情对决", "社会派推理"], "summary_short": "人证，1977年日本电影，犯罪 / 剧情。在东京最繁华的街区，一名混血黑人青年被刺身亡，警方发现他与著名服装设计师八杉恭子有着不为人知的母子关系。恭子为了维护自己来之不易的上流社会地位与日籍丈夫的颜面，不惜跨越重洋找回自己在二战期间与美军黑人士兵生下的儿子焦尼。面对千里寻母的焦尼，恭子最终在亲情与名誉的抉择中举起了刀。影片通过草帽诗作为线索，穿插了战后日本的屈辱与复兴，深刻揭示了种族歧视与社会阶层固化带来的家庭悲剧。", "score": 1977377, "category": "drama", "detail_url": "../movie/1611.html", "poster": "../posters/1611.svg"}, {"id": "1612", "title": "乱世骄雄", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "历史 / 战争 / 传记", "tags": ["军阀", "史诗", "权谋", "战争场面"], "summary_short": "乱世骄雄，2025年中国大陆剧集，历史 / 战争 / 传记。故事开始于1916年，袁世凯死后天下大乱。书香门第出身的谢之章被迫替弟弟从军，因为他识字快，一路从文书升到师长。他没有打仗的意愿，只想保境安民，却在军阀混战中莫名其妙地占了几个县。他推行新式教育、修建铁路，却因此被旧派军阀视为异端。在长达二十年的征战里，他眼睁睁看着好友背叛、兄弟战死、爱人投江。他从痛哭流涕的文人变成了杀人不见血的“骄雄”。当日军全面侵华时，他放弃地盘，将所有家", "score": 2025219, "category": "doc", "detail_url": "../movie/1612.html", "poster": "../posters/1612.svg"}, {"id": "1613", "title": "到来的难处", "year": 2024, "region": "法国", "type": "电影", "genre": "剧情 / 家庭", "tags": ["阿尔茨海默症", "母女", "亲情", "催泪"], "summary_short": "到来的难处，2024年法国电影，剧情 / 家庭。年迈的钢琴家艾琳娜是法国国宝级艺术家，却因阿尔茨海默症日渐忘记一切。女儿莉莉从美国赶回巴黎，发现母亲正在悄无声息地消失：她忘掉了孙子的名字、忘掉了回家的路、甚至开始忘掉钢琴指法。莉莉辞去工作全职照顾母亲，但艾琳娜的病情加重伴随着暴躁和幻觉，她常常把女儿当成自己年轻时的竞争对手，恶语相向。莉莉在崩溃边缘徘徊。一个雨夜，艾琳娜突然清醒了片刻，她坐到钢琴前，弹完了生命中最后一首肖邦，然后看着莉莉", "score": 2024288, "category": "drama", "detail_url": "../movie/1613.html", "poster": "../posters/1613.svg"}, {"id": "1614", "title": "三个金币", "year": 2021, "region": "中国大陆", "type": "电影", "genre": "奇幻、喜剧、剧情", "tags": ["愿望、沈腾、治愈、寓言式、金钱"], "summary_short": "三个金币，2021年中国大陆电影，奇幻、喜剧、剧情。废柴青年罗小天欠债累累、女友分手、面试被拒，万念俱灰时从一个神秘老头手中得到三枚“心想事成”金币。他兴奋地许愿“一个亿”，次日真的中了彩票，却发现自己失去了味觉——这是他唯一热爱美食的乐趣。第二枚金币，他许愿“追回前女友”，女孩回心转意，他却发现自己的幽默感消失了，两人相处尴尬至极。握着最后一枚金币，罗小天终于明白：世上没有白得的午餐。他选择许愿“回到遇见老头之前”，一切归零，但他带着", "score": 2021378, "category": "drama", "detail_url": "../movie/1614.html", "poster": "../posters/1614.svg"}, {"id": "1615", "title": "午夜心跳", "year": 2010, "region": "中国大陆", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["医院", "心理惊悚", "国产恐怖", "氛围", "因果"], "summary_short": "午夜心跳，2010年中国大陆电影，恐怖, 惊悚。市第三人民医院因为一桩医疗事故被废弃，传闻每到午夜零点，空荡荡的心电图室里就会传出“咚咚”的心跳声，但频率只有每分钟20次——那是死人的心跳。实习医生林欣为了完成一篇关于“濒死体验”的论文，带着录音笔独自潜入旧医院。她发现，心跳声并非幻觉，而是一个女孩的怨魂在重复自己死亡前的最后记忆。二十年前，一个患有罕见心脏病的小女孩在医院等待器官移植，主治医生为了给高官亲属抢器官，故意让她“心脏死亡”", "score": 2010442, "category": "horror", "detail_url": "../movie/1615.html", "poster": "../posters/1615.svg"}, {"id": "1616", "title": "死灵编码", "year": 2024, "region": "日本", "type": "动画剧集", "genre": "悬疑，科幻，恐怖", "tags": ["都市传说，程序，灵异，逻辑流，烧脑"], "summary_short": "死灵编码，2024年日本动画剧集，悬疑，科幻，恐怖。都市中流传着一个都市传说：只要下载一个名为“死灵编码”的神秘App，输入任何一个“概念”（比如“门”、“锁”、“影子”），那个概念就会从现实中物理消失。大学生贤二出于好奇，下载了App，输入了“附近所有监控探头”。下一秒，整条街的监控设备全部熔化消失。但第二天，他发现App的开发者，一个自称“幽灵程序员”的人给他留言，说他已被标记为“用户”，必须不断“删除”更大规模的概念，否则他自己将", "score": 2024499, "category": "series", "detail_url": "../movie/1616.html", "poster": "../posters/1616.svg"}, {"id": "1617", "title": "永远的托词", "year": 2016, "region": "日本", "type": "电影", "genre": "剧情", "tags": ["家庭", "自我救赎", "作家", "丧亲"], "summary_short": "永远的托词，2016年日本电影，剧情。著名作家衣笠幸夫在妻子去世后，表面悲痛实则内心麻木，甚至利用妻子的死来博取同情与销量。一次偶然，他拜访了同样在事故中失去妻子的旧友家中，并开始帮忙照顾两个年幼的孩子。在琐碎的日常照料中，幸夫从笨拙、不耐烦到逐渐学会承担责任。他发现自己过去一直活在虚伪的“托词”之中，用工作、名利逃避真实的家庭关系。通过孩子们的纯真与依赖，他重新审视自己与妻子的过往，最终写出了一部真正关于爱与失去的作品，完成了迟来的自", "score": 2016319, "category": "drama", "detail_url": "../movie/1617.html", "poster": "../posters/1617.svg"}, {"id": "1618", "title": "都立水商！～令和～", "year": 2019, "region": "日本", "type": "电视剧", "genre": "喜剧 / 校园", "tags": ["职业教育， 搞笑， 热血教师"], "summary_short": "都立水商！～令和～，2019年日本电视剧，喜剧 / 校园。热血青年教师田边公平被分配到“都立水商”任教，这所在法律灰色地带成立的实验高中，专门为“水商事”（即夜生活行业）培养人才。这里有女公关科、经理科、接待科等奇葩专业。田边起初极度抗拒，认为学校在教坏学生，但在目睹了学生为了生计努力学习接待礼仪、法律知识和自我保护的认真模样后，他开始改变看法。这群被社会歧视的学生，有的是为了还债，有的是单亲妈妈，有的只是为了找一个不歧视自己的容身之所", "score": 2019219, "category": "series", "detail_url": "../movie/1618.html", "poster": "../posters/1618.svg"}, {"id": "1619", "title": "芭拉芭拉樱之花", "year": 2018, "region": "日本", "type": "电影", "genre": "爱情 / 音乐", "tags": ["樱花", "街头艺人", "失忆", "口琴", "纯爱"], "summary_short": "芭拉芭拉樱之花，2018年日本电影，爱情 / 音乐。街头艺人小悠常年戴着面具，在东京的樱花树下吹奏口琴。一天，一个浑身湿透的少女真希倒在他面前，醒来后失去了所有记忆，只记得“芭拉芭拉”这个拟声词。小悠收留了她，两人无法用语言沟通（真希失忆后失语），却用口琴和舞蹈创造了独特的交流方式。樱花盛开的短短两周里，他们寻找着真希的过去，也坠入了爱河。最后真相揭晓：真希曾是著名钢琴少女，因演出事故创伤失忆。小悠用一首原创的《芭拉芭拉樱之花》唤醒了她", "score": 2018316, "category": "romance", "detail_url": "../movie/1619.html", "poster": "../posters/1619.svg"}, {"id": "1620", "title": "创可贴", "year": 2023, "region": "韩国", "type": "电影", "genre": "爱情, 喜剧", "tags": ["治愈", "冤家", "医疗"], "summary_short": "创可贴，2023年韩国电影，爱情, 喜剧。胸外科王牌医生车智旭因手术失误导致患者死亡，变得冷漠刻板。急救队员姜英美性格大大咧咧，因违规使用急救设备被停职。医院为了形象公关，强制两人组成“医疗支援组”，去社区卫生院服务，还要求他们必须同居以便24小时待命。性格水火不容的两人住在同一屋檐下，从互相扔袜子到被迫合作救助流浪猫、突发疾病的老人。在一次台风天的户外救援中，英美为了救孩子被砸伤，智旭在简陋条件下跪在雨里为她做手术。这一刻，智旭找回了", "score": 2023370, "category": "romance", "detail_url": "../movie/1620.html", "poster": "../posters/1620.svg"}, {"id": "1621", "title": "该隐的末裔", "year": 2025, "region": "韩国", "type": "剧集", "genre": "悬疑 / 惊悚 / 犯罪", "tags": ["邪教", "基因编辑", "连环杀手", "黑暗人性", "反转"], "summary_short": "该隐的末裔，2025年韩国剧集，悬疑 / 惊悚 / 犯罪。首尔陷入前所未有的恐慌，连环杀人案受害者身上都刻有神秘的“C”字标记，但最令人毛骨悚然的是，凶手的面部特征完全相同，仿佛批量生产的“人类”。国情院特工韩智浩追查发现，这些凶手均指向二十年前某深山教堂中被指控为该隐后裔的孤儿们。当时的“圣血教会”曾秘密进行胚胎基因编辑实验，试图复制“完美人类”。随着调查深入，韩智浩发现自己的身世也与此实验紧密相连，而那个真正的幕后操纵者，可能并非人", "score": 2025382, "category": "crime", "detail_url": "../movie/1621.html", "poster": "../posters/1621.svg"}, {"id": "1622", "title": "那年夏天", "year": 2006, "region": "韩国", "type": "电影", "genre": "爱情，剧情", "tags": ["怀旧，下乡，初恋，纯爱，遗憾"], "summary_short": "那年夏天，2006年韩国电影，爱情，剧情。正值竞选关键时刻的热门候选人硕英，被一封没有署名的旧信勾起了往昔回忆。他暂停行程，独自来到四十年前下乡支教的海边小村。镜头拉回1969年，年轻的硕英作为大学生下乡支教，遇到了村里倔强而美丽的少女秀敏。那个夏天，他们在海边捉鱼，在暴雨中奔跑，在月光下互诉衷肠。然而，秀敏的身份是被时代遗弃的“反叛者”后代，他们的爱情遭到了硕英家庭和社会的强烈阻挠。当硕英回首往事，试图寻找秀敏的下落时，他发现当年的真", "score": 2006340, "category": "romance", "detail_url": "../movie/1622.html", "poster": "../posters/1622.svg"}, {"id": "1623", "title": "巴塔哥尼亚", "year": 2010, "region": "阿根廷 / 波兰", "type": "电影", "genre": "剧情，冒险", "tags": ["荒野，寻找自我，风，老年"], "summary_short": "巴塔哥尼亚，2010年阿根廷 / 波兰电影，剧情，冒险。70岁的波兰历史教师安娜在丈夫死后整理遗物，发现一本泛黄的日记，里面详细描述了青年时代在巴塔哥尼亚探险时，被一阵从安第斯山脉吹来的、带有冰川气息的风所震撼的经历。丈夫曾说过要带她一起去听那阵风，但从未成行。安娜瞒着儿女，带上丈夫的骨灰坛，独自飞往阿根廷。她不会西班牙语，只有一张模糊的照片。在巴塔哥尼亚的旷野中，她迷路、受伤、被年轻的背包客嘲笑。一个当地的老牧羊人收留了她，用西班牙语", "score": 2010247, "category": "drama", "detail_url": "../movie/1623.html", "poster": "../posters/1623.svg"}, {"id": "1624", "title": "九五至尊国语", "year": 2003, "region": "中国香港", "type": "电视剧", "genre": "喜剧, 古装, 穿越", "tags": ["穿越", "职场", "雍正", "现代商战"], "summary_short": "九五至尊国语，2003年中国香港电视剧，喜剧, 古装, 穿越。清朝雍正十三年，雍正帝正在批阅奏折，一道惊雷将他劈入了时空裂缝。当他睁开眼，发现自己身处2003年的香港，身体变成了一个名叫李大虾的普通大陆青年，身份是兆康集团的夜班保安。雍正很快发现，现代公司的权力斗争与他熟悉的九子夺嫡如出一辙。他用帝王心术分析公司局势，帮保洁阿姨摆平了欺负她的部门主管，又用小战术替保安队长赢得了管理层的心。无意间，他破解了对手的商业阴谋，被董事会破格提拔", "score": 2003204, "category": "series", "detail_url": "../movie/1624.html", "poster": "../posters/1624.svg"}, {"id": "1625", "title": "林肯律师第一季", "year": 2024, "region": "美国", "type": "剧集（季播）", "genre": "律政 / 犯罪", "tags": ["豪车办公，灰色正义，案中案"], "summary_short": "林肯律师第一季，2024年美国剧集（季播），律政 / 犯罪。米奇·豪勒是洛杉矶最独特的律师：他所有的法律事务都在黑色林肯轿车后座完成。本季主线围绕一起富二代被控强奸案展开。米奇发现关键监控视频曾被篡改，真凶指向一名有精神问题的退伍兵。但在调查过程中，他的客户不断死亡，所有线索都指向一份十年前丢失的警方卧底名单。米奇的前妻、检察官玛吉被停职调查，他的调查搭档被杀。为了自保，米奇必须利用法庭内外一切灰色手段，在黑白两道之间走钢丝。最终他揭露", "score": 2024254, "category": "series", "detail_url": "../movie/1625.html", "poster": "../posters/1625.svg"}, {"id": "1626", "title": "情暖万家", "year": 2010, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 家庭 / 社会", "tags": ["社区调解", "基层", "单元剧", "温暖", "人间百态"], "summary_short": "情暖万家，2010年中国大陆电视剧，剧情 / 家庭 / 社会。张玉兰是平安社区的“金牌调解员”，二十年调解了两千多起纠纷。无论是楼上漏水、噪音扰民还是赡养老人，她总能找到“土办法”：让吵架的两家人一起包饺子、让闹离婚的小夫妻去菜市场共同砍价。但在这些温暖故事的背后，张玉兰自己的家里却有着无法调和的矛盾——儿子因她年轻时忙于工作疏忽家庭，已十年不跟她说话；老伴得了阿尔茨海默病，只认得牌友不认得她。当社区一个单亲妈妈被家暴的案子闹到派出所时", "score": 2010182, "category": "series", "detail_url": "../movie/1626.html", "poster": "../posters/1626.svg"}, {"id": "1627", "title": "老无所依", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情 / 家庭", "tags": ["空巢老人", "养老困境", "城市与乡村", "代际撕裂"], "summary_short": "老无所依，2024年中国大陆电影，剧情 / 家庭。陕西农村的周长河老人丧偶后独居。三个儿子：老大在北京开公司，老二在深圳当码农，老三在县城做公务员。老人生病住院，三个儿子互相推诿，最后靠护工照顾。出院后，周长河把三个儿子告上法庭。法庭上，大儿子说给钱就行，二儿子说可以装监控，三儿子说送去养老院。老人在被告席上说了最后一句话：“我不要钱，不要监控，不要养老院。我只要你们三个，每年回来，在这老屋里，陪我住十天。就十天。”法官当庭哽咽。最终调", "score": 2024308, "category": "drama", "detail_url": "../movie/1627.html", "poster": "../posters/1627.svg"}, {"id": "1628", "title": "月光书房", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "剧情 / 家庭 / 治愈", "tags": ["旧书店", "深夜来访", "代际和解", "城市孤独", "藏书故事"], "summary_short": "月光书房，2024年中国大陆电视剧，剧情 / 家庭 / 治愈。程序员林晓继承祖父在弄堂深处的“月光书房”。店规古怪：每月农历十五开门，只接受预约，且必须用故事换书。第一个客人是位声称自己来自“平行世界”的物理学家，他需要一本名叫《哥德尔与莫奈的下午茶》的书——林晓找了三天，发现那是祖父与朋友合著的从未出版的手稿。此后，每个月的月圆夜，都有一位带着“假书”名字的客人出现：《婚姻使用说明书》、《给外星人的冷笑话集》……这些书都真实存在于祖父", "score": 2024192, "category": "series", "detail_url": "../movie/1628.html", "poster": "../posters/1628.svg"}, {"id": "1629", "title": "错过你的那些年", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "爱情, 剧情, 青春", "tags": ["校园", "暗恋", "时空交错", "遗憾美学"], "summary_short": "错过你的那些年，2024年中国大陆电影，爱情, 剧情, 青春。2008年，高中生许愿和路星辰是同桌，一个爱写诗，一个爱画画，彼此暗恋却都不敢开口。毕业前夕，路星辰写了一封情书塞进许愿的语文课本，却被嫉妒的同学抽走。许愿以为星辰讨厌自己，黯然去了北方大学。十五年后，许愿成了抑郁的小说家，路星辰是一名小学美术老师。一场同学聚会，两人重逢，当年那封情书竟然在整理旧物时被翻出。他们知道了错过的真相，但一切为时已晚：许愿已婚，路星辰有一对双胞胎。", "score": 2024361, "category": "drama", "detail_url": "../movie/1629.html", "poster": "../posters/1629.svg"}, {"id": "1630", "title": "面纱下的那不勒斯", "year": 2024, "region": "意大利", "type": "电影", "genre": "悬疑， 爱情， 历史", "tags": ["那不勒斯， 圣血传说， 神秘主义， 家族秘密， 双重身份"], "summary_short": "面纱下的那不勒斯，2024年意大利电影，悬疑， 爱情， 历史。艺术修复师艾玛受邀到那不勒斯，修复一幅16世纪的神秘画作《面纱下的圣母》。画中圣母的脸被一层半透明面纱覆盖，无人知其真容。艾玛在修复过程中，每刮去一层颜料，现实中就有一名参与过某次艺术盗窃案的人离奇死亡。当地神父兼历史学家马特奥告诉她，这幅画藏着“圣血派”的一个秘密：画下面纱每揭开一层，就会揭示一个关于那不勒斯地下宝藏的线索，同时也会带走一个知情者的灵魂。艾玛发现自己已故的母", "score": 2024418, "category": "costume", "detail_url": "../movie/1630.html", "poster": "../posters/1630.svg"}, {"id": "1631", "title": "夺魂铃", "year": 1968, "region": "中国香港", "type": "电影", "genre": "动作, 武侠", "tags": ["邵氏", "复仇", "暗器", "江湖"], "summary_short": "夺魂铃，1968年中国香港电影，动作, 武侠。十五年前，镖师杨振山因护送一只神秘的“夺魂铃”而招致七大派高手围攻，全家惨死。幼子杨小楼抱着铃铛躲进狗洞才幸免于难。十五年后，江湖传言夺魂铃重现天目山，引得当年七大高手纷纷前往。但他们不知道，这铃声是杨小楼设下的圈套。他在山脚下的“有间客栈”扮作痴呆店小二，利用铃铛发出的不同频率声音，向不同的仇家传递假消息，让他们互相猜忌、自相残杀。每杀一人，他就将铃铛挂在房梁上，直到第七声铃响。然而第七个", "score": 1968305, "category": "crime", "detail_url": "../movie/1631.html", "poster": "../posters/1631.svg"}, {"id": "1632", "title": "她对星星歌唱", "year": 2024, "region": "英国", "type": "电影", "genre": "剧情，家庭，奇幻", "tags": ["自闭症，亲情，治愈，童话，音乐"], "summary_short": "她对星星歌唱，2024年英国电影，剧情，家庭，奇幻。8岁的小女孩艾拉被诊断为重度自闭症，从不与人交流，甚至不直视母亲的眼睛。但她有一个秘密：每当夜深人静，她会爬上屋顶，对着满天繁星轻轻哼唱一首没有歌词的旋律。更神奇的是，她唱歌时，总会有流星划过。母亲玛莎独自抚养艾拉，已濒临崩溃。一位落魄的天文学家邻居老乔治无意中发现了艾拉歌声与流星轨迹的关联。他帮助玛莎用科学解释这一现象，并引导玛莎用星光和音乐与艾拉沟通。艾拉开始通过敲击不同频率的水杯", "score": 2024339, "category": "drama", "detail_url": "../movie/1632.html", "poster": "../posters/1632.svg"}, {"id": "1633", "title": "庙街十二少粤语", "year": 1992, "region": "中国香港", "type": "电影", "genre": "动作, 犯罪, 剧情", "tags": ["古惑仔", "庙街", "江湖", "怀旧", "兄弟情"], "summary_short": "庙街十二少粤语，1992年中国香港电影，动作, 犯罪, 剧情。九十年代初，香港庙街。外号“十二少”的阿杰出狱，他曾是庙街最威水的少年头目，因替兄弟顶罪坐了五年牢。出狱后他只想守着母亲的鱼蛋摊安度余生。但昔日的兄弟早已分成两派：当年最胆小的阿超考上了警察，成了反黑组警长；当年最讲义气的阿坤成了庙街最大的毒枭，心狠手辣。阿超要阿杰出庭指证阿坤；阿坤要阿杰利用旧日威望帮他摆平码头交易。阿杰谁都不想帮，只想卖鱼蛋。但庙街不答应。阿坤绑了阿超的家", "score": 1992380, "category": "crime", "detail_url": "../movie/1633.html", "poster": "../posters/1633.svg"}, {"id": "1634", "title": "不看别后悔", "year": 2023, "region": "美国", "type": "电影", "genre": "惊悚, 恐怖", "tags": ["录像带", "诅咒", "密室", "视觉冲击"], "summary_short": "不看别后悔，2023年美国电影，惊悚, 恐怖。网红主播小K收到匿名包裹，里面是一盘老式录像带，封面手写着“不看别后悔”。为了流量，他拉上四名同伴直播观看。画面里只有一个戴面具的人反复说：“现在你们看到了，二十四小时后你们将看到自己的死法，而唯一活下去的办法，是在看到之前把录像转给另一个人。”五人以为恶作剧，笑着关掉直播。但第二天开始，每个人都在身边看到了诡异的预兆——镜中的自己突然七窍流血、窗外的路人长着同一张脸、手机相册自动生成死亡倒", "score": 2023382, "category": "horror", "detail_url": "../movie/1634.html", "poster": "../posters/1634.svg"}, {"id": "1635", "title": "白发魔女2", "year": 2027, "region": "中国香港", "type": "电影", "genre": "动作, 爱情, 武侠", "tags": ["江湖恩怨", "亦正亦邪", "虐恋"], "summary_short": "白发魔女2，2027年中国香港电影，动作, 爱情, 武侠。距离明月峡一役已过十年，练霓裳隐居雪山，白发已成传奇。一个名叫“望月”的年轻魔教少主突然出现在中原，他行事狠辣却心地纯良，更重要的是，他的面容与死去的卓一航如出一辙。武林正道以此为借口围攻练霓裳，逼迫她出手清理门户。练霓裳在交手过程中发现，望月体内竟有卓一航的内力痕迹。她带着望月踏上寻真相之路，发现这一切都是当年武当派一位长老的阴谋，他试图用“移魂大法”制造一个听话的武林盟主。练", "score": 2027396, "category": "crime", "detail_url": "../movie/1635.html", "poster": "../posters/1635.svg"}, {"id": "1636", "title": "野蛮人柯南", "year": 2025, "region": "美国", "type": "电影", "genre": "动作 / 奇幻 / 冒险", "tags": ["蛮族", "剑与魔法", "重启", "硬汉", "史诗"], "summary_short": "野蛮人柯南，2025年美国电影，动作 / 奇幻 / 冒险。西梅利安蛮族少年柯南亲眼目睹父亲被蛇神教献祭，自己被卖为角斗士。十年后他逃出竞技场，联合被压迫的各族奴隶，杀向蛇神教的金字塔神殿。他一路砍翻蛇武士、巨蟒、幽灵祭司，最终面对教主时发现：教主竟然是当年救过他一命的流浪汉。柯南含着泪将剑刺入教主心脏，神殿崩塌，他拖着教主尸体走出火海，成为了新一代的蛮族之王。", "score": 2025321, "category": "fantasy", "detail_url": "../movie/1636.html", "poster": "../posters/1636.svg"}, {"id": "1637", "title": "我的淘气王子", "year": 2024, "region": "中国台湾", "type": "剧集", "genre": "喜剧, 爱情, 校园", "tags": ["灵魂互换", "校霸变乖", "学霸变疯", "甜宠"], "summary_short": "我的淘气王子，2024年中国台湾剧集，喜剧, 爱情, 校园。高三女生许悄悄是永远的第一名、学生会主席、老师眼中的完美模板。校霸王浩南是打架、逃课、飙车的全方位废柴。一次意外接吻（其实是王浩南被鱼丸噎住，她做人工呼吸），两人互换了身体。于是，“许悄悄”开始在课堂上跳课间操、撕卷子折纸飞机；“王浩南”则用微积分破解黑帮的赌球公式。在疯狂寻找换回来的方法时，他们翻到了奶奶的遗物——一张泛黄的私奔合照。照片里的男人是王浩南的爷爷，女人是许悄悄的", "score": 2024339, "category": "series", "detail_url": "../movie/1637.html", "poster": "../posters/1637.svg"}, {"id": "1638", "title": "浮石传", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "奇幻, 古装, 冒险", "tags": ["妖族", "寻宝", "命运之石", "宿命"], "summary_short": "浮石传，2025年中国大陆剧集，奇幻, 古装, 冒险。少年石不弃天生运气极差，走路被鸟粪砸，喝水塞牙缝。他在一次山洪中意外吞下了传说中的“浮石”——此石能扭曲因果，让人所期望之事向反方向发展。他本想找办法取出，却因此被卷入正邪两道争夺。正道想用浮石封印魔神，反派想用浮石毁灭世界。石不弃发现，浮石已经开始与他共生，一旦离开就会死。于是他决定反其道而行之：想要救世，就先努力去毁灭世界。一场“反向操作”的修仙冒险就此荒唐展开。", "score": 2025301, "category": "fantasy", "detail_url": "../movie/1638.html", "poster": "../posters/1638.svg"}, {"id": "1639", "title": "我心爱的珍妮弗", "year": 2023, "region": "英国", "type": "电影", "genre": "心理惊悚", "tags": ["病娇，租房，反转，女性，窒息感"], "summary_short": "我心爱的珍妮弗，2023年英国电影，心理惊悚。穷困潦倒的插画师格蕾丝租到一套伦敦市中心的维多利亚式公寓，租金低到离谱。房东珍妮弗是位优雅的退休女教师，热情提供“家人式关怀”——帮她搭配衣服、替她拒绝男友、甚至修改她的画作风格。格蕾丝起初感动，直到她在暗格里发现前房客们的日记，内容惊人一致：“我越来越像珍妮弗了。”格蕾丝开始反抗，却发现自己银行卡密码、社交圈、甚至习惯性小动作都被替换了。她逃出公寓后报警，警察打开门——屋里坐着另一个“珍妮", "score": 2023356, "category": "crime", "detail_url": "../movie/1639.html", "poster": "../posters/1639.svg"}, {"id": "1640", "title": "战天狼", "year": 2018, "region": "中国大陆", "type": "剧集", "genre": "战争 / 动作 / 历史", "tags": ["抗日", "狙击手", "兄弟情", "谍战", "传奇"], "summary_short": "战天狼，2018年中国大陆剧集，战争 / 动作 / 历史。根据真实人物“华北狙王”改编。猎户出身的武十三，全村被日军屠尽后，携带祖传猎枪独自潜入敌占区。他不懂军事，但懂风、懂湿度、懂一里外兔子耳朵的抖动。他先救了八路军侦察连，学会现代狙击术，后又被军统招募，最后发现两边都在用他。他狙杀了敌军高级将领、汉奸翻译官，甚至一个很会下棋的日本少佐——后者临死前请他下最后一盘棋。全剧不神化，武十三也会哭、会尿裤子、会拒绝开枪。但他最后说了一句话：", "score": 2018220, "category": "series", "detail_url": "../movie/1640.html", "poster": "../posters/1640.svg"}, {"id": "1641", "title": "难以忽视的真相2", "year": 2026, "region": "美国", "type": "纪录片", "genre": "纪录 / 环保 / 警示", "tags": ["气候危机", "科技伦理", "深度调查", "生态反思", "震撼影像"], "summary_short": "难以忽视的真相2，2026年美国纪录片，纪录 / 环保 / 警示。本片是《难以忽视的真相》的续篇，但视角从政客转向全球一线科研人员。导演跟拍了五国科学家，揭示出比2006年预测严重得多的临界点：北极夏季无冰已提前到来，永久冻土释放出的远古甲烷形成失控反馈。面对绝望，一个由亿万富翁资助的“平流层气溶胶注入”计划成为焦点。纪录片冷静展示了该技术可能迅速降温，却会改变全球降雨模式、导致数亿人粮食短缺的两难抉择。影片没有给出简单答案，而是记录了", "score": 2026060, "category": "doc", "detail_url": "../movie/1641.html", "poster": "../posters/1641.svg"}, {"id": "1642", "title": "傲蕾·一兰", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 历史 / 传记", "tags": ["达斡尔族", "女英雄", "古代战争", "抗争史诗"], "summary_short": "傲蕾·一兰，2026年中国大陆剧集，剧情 / 历史 / 传记。故事发生在清朝初年，沙俄探险队东侵至黑龙江流域。达斡尔族首领之女傲蕾·一兰在父亲被诱杀后，毅然扛起部落首领的重担。她不仅精通骑射，更擅长利用森林地形进行游击战。在精奇里江畔，她率领数百族人以弓箭和长矛对抗装备火枪的哥萨克军队，多次挫败侵略者的阴谋。在被叛徒出卖、身陷囹圄三年后，她逃回故土并联合周围多个部族，最终配合清军的雅克萨之战，完成了驱逐外敌的使命。该剧展现了北方少数民族", "score": 2026222, "category": "series", "detail_url": "../movie/1642.html", "poster": "../posters/1642.svg"}, {"id": "1643", "title": "驴子潘趣", "year": 2018, "region": "英国", "type": "电影", "genre": "惊悚 / 犯罪 / 黑色幽默", "tags": ["一夜荒唐", "反杀", "录像带", "派对惊悚"], "summary_short": "驴子潘趣，2018年英国电影，惊悚 / 犯罪 / 黑色幽默。五个年轻人在西班牙度假别墅开告别单身派对，他们发明了一种名为“驴子潘趣”的惩罚游戏：输家必须做一件最出格的事。在一瓶烈酒和毒品的催化下，有人提议去挑衅当地黑帮。他们成功偷到一辆豪车，却发现车后备箱里有一个被绑架的女孩。本想报警的他们，因怕录像泄露罪行而决定自己处理。天亮时，别墅里只剩两个人活着，而那台一直开着的摄像机，成了唯一的目击者。", "score": 2018370, "category": "crime", "detail_url": "../movie/1643.html", "poster": "../posters/1643.svg"}, {"id": "1644", "title": "亚历山大内夫斯基", "year": 2029, "region": "俄罗斯", "type": "电影", "genre": "历史 / 传记 / 战争", "tags": ["沙俄历史", "军事天才", "史诗战争", "民族英雄"], "summary_short": "亚历山大内夫斯基，2029年俄罗斯电影，历史 / 传记 / 战争。十三世纪，涅瓦河英雄亚历山大·内夫斯基刚刚从冰湖战役中凯旋，他击败了条顿骑士团，成为全罗斯公国的精神支柱。但金帐汗国的使者也随之而来，要求他交出长子作为人质。与此同时，他的胞弟安德烈在暗中联合了诺夫哥罗德的反贵族势力，指责亚历山大与蒙古人媾和是“背叛东正教”。影片没有把重心放在著名的冰湖之战上，而是聚焦于战后两年内，亚历山大如何在蒙古人的刀锋、教宗的招安信、弟弟的政变阴谋", "score": 2029229, "category": "doc", "detail_url": "../movie/1644.html", "poster": "../posters/1644.svg"}, {"id": "1645", "title": "摇滚电台", "year": 2022, "region": "英国", "type": "电影", "genre": "剧情音乐", "tags": ["海盗电台", "90年代", "父子情", "黑胶唱片", "小镇复兴"], "summary_short": "摇滚电台，2022年英国电影，剧情音乐。90年代的英格兰北部工业小镇，随着工厂关闭，年轻人纷纷离开。曾是大城市摇滚电台王牌DJ的马丁，因丑闻落魄回乡，发现儿时的伙伴们都在领救济金。他在废弃的矿工礼堂里找到一台老式广播发射器，决定偷偷办一个地下摇滚电台，每天深夜播放那些让他年轻时沸腾的曲子。起初只有几个老人收听，后来越来越多失眠的年轻人通过电话点歌，分享小镇被遗忘的故事。镇长发现后要起诉他非法广播，而一家连锁商业电台则想收购他的频率。马丁", "score": 2022289, "category": "drama", "detail_url": "../movie/1645.html", "poster": "../posters/1645.svg"}, {"id": "1646", "title": "巡逻惊很大", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 恐怖 / 惊悚", "tags": ["警察", "鬼屋", "误打误撞"], "summary_short": "巡逻惊很大，2026年中国台湾电影，喜剧 / 恐怖 / 惊悚。菜鸟警察阿呆和老油条阿瓜被发配到最偏僻的派出所，日常工作是抓醉猫和帮阿婆找猫。一晚接到山区别墅报警：“有鬼！”两人壮胆前往，发现别墅里确有“鬼影”——其实是屋主儿子装神弄鬼想吓退拆迁队。两人正打算收队，突然听到地下室传来真惨叫。原来别墅地下室关着一名被绑架的少女，而绑架者正是报警的“屋主”——一名连环杀手。杀手拿着电锯出现，阿呆和阿瓜开始荒诞逃命。过程中，阿瓜误拿玩具枪对射，", "score": 2026486, "category": "horror", "detail_url": "../movie/1646.html", "poster": "../posters/1646.svg"}, {"id": "1647", "title": "美女蛇岛求生", "year": 2024, "region": "泰国", "type": "电影", "genre": "惊悚, 冒险", "tags": ["荒岛", "毒蛇", "女性群像"], "summary_short": "美女蛇岛求生，2024年泰国电影，惊悚, 冒险。一档热门求生直播节目将六位不同背景的女网红送到传闻中的“蛇岛”。起初她们以为只是作秀，当第一条眼镜王蛇闯入营地后，恐惧开始蔓延。她们发现不仅岛上蛇类数量多到异常，而且节目组预设的求救设备全部失效。更可怕的是，摄像无人机一直在追踪拍摄，直播间人数突破千万，观众在弹幕里“下注”谁会先死。为了活下去，她们必须利用化妆品、自拍杆和无人机电池，与无处不在的死神展开一场被全球围观的绝地反击。", "score": 2024278, "category": "horror", "detail_url": "../movie/1647.html", "poster": "../posters/1647.svg"}, {"id": "1648", "title": "异色国度", "year": 2022, "region": "尼日利亚 / 美国", "type": "电影", "genre": "剧情 / 奇幻", "tags": ["非洲", "平行世界", "肤色", "身份认同"], "summary_short": "异色国度，2022年尼日利亚 / 美国电影，剧情 / 奇幻。在拉各斯的未来世界里，天才科学家阿玛拉发明了“光谱镜”，戴上它看不到肤色，只能看到灵魂散发出的颜色。她惊讶地发现，统治阶层的灵魂是金色，中产是蓝色，而贫民窟的人则是红色。当她试图公布这一发现时，政府以“破坏种族团结”为由追杀她。阿玛拉逃亡至地下社区，却发现那里的人可以通过修行改变灵魂颜色。为了推翻高压统治，她决定潜入金色群体，展开一场关于灵魂平等的革命。", "score": 2022299, "category": "drama", "detail_url": "../movie/1648.html", "poster": "../posters/1648.svg"}, {"id": "1649", "title": "逐爱天堂", "year": 2025, "region": "法国", "type": "剧集", "genre": "剧情, 悬疑", "tags": ["法式庄园", "遗产阴谋", "禁忌之恋", "姐妹反目"], "summary_short": "逐爱天堂，2025年法国剧集，剧情, 悬疑。蔚蓝海岸的“天堂庄园”里，富商雷蒙德新婚妻子艾莲娜在泳池溺亡。妹妹露西化名应聘管家潜伏调查，发现姐姐死前曾怀孕，而雷蒙德有不育症。随着日记碎片浮出水面，露西越来越相信姐姐是被毒杀后推入水中。但她与雷蒙德朝夕相处，竟被他的温柔与痛苦打动，甚至发生关系。当雷蒙德拿出另一本日记证明艾莲娜是自杀时，露西崩溃了——直到她在姐姐遗物里发现录音笔，里面是雷蒙德逼她自杀的对话。", "score": 2025296, "category": "series", "detail_url": "../movie/1649.html", "poster": "../posters/1649.svg"}, {"id": "1650", "title": "反斗小宝贝", "year": 2023, "region": "美国", "type": "剧集", "genre": "喜剧 / 家庭", "tags": ["萌娃", "逆袭", "校园", "爆笑", "成长"], "summary_short": "反斗小宝贝，2023年美国剧集，喜剧 / 家庭。在一所即将被关闭的破旧小学里，五个因各种怪癖被孤立的孩子——沉迷发明的书呆子、爱说谎的小话痨、总在打架的暴力女、怕黑的大块头和自称外星人的怪胎——被校长硬凑成“反斗小队”。他们本以为只是打扫废弃仓库，却意外发现一本会发光的日记，里面藏着学校创始人留下的谜题。随着谜题一步步解开，他们不仅挖出了埋在地下的时间胶囊，还发现了当年创始人为对抗教育腐败而设计的证据链。最终，这群“小宝贝”用天真与勇气", "score": 2023236, "category": "comedy", "detail_url": "../movie/1650.html", "poster": "../posters/1650.svg"}, {"id": "1651", "title": "大象席地而坐", "year": 2018, "region": "中国", "type": "电影", "genre": "剧情", "tags": ["绝望，边缘人，黑色基调"], "summary_short": "大象席地而坐，2018年中国电影，剧情。混混于城误杀了人，正被黑帮追杀；高中生韦布为朋友出头惹上校霸，被父亲赶出家门；老迈的王金因房产被女儿女婿算计，被迫搬去养老院；黄玲与教导主任的暧昧视频被曝光，学校再无她容身之处。这四个生活在北方沉闷小城里、被生活逼到墙角的失意者，都听说了满洲里动物园有一只大象，它什么都不做，只是整天坐在那里。这荒诞的景象成了他们最后的救赎。他们抢了一辆偷来的大巴，踏上了前往满洲里的旅程。车内是沉默的喘息，车外是无", "score": 2018287, "category": "drama", "detail_url": "../movie/1651.html", "poster": "../posters/1651.svg"}, {"id": "1652", "title": "恐惧回声", "year": 2017, "region": "西班牙", "type": "电影", "genre": "恐怖， 心理惊悚", "tags": ["回声定位， 盲人， 老宅， 声音杀人"], "summary_short": "恐惧回声，2017年西班牙电影，恐怖， 心理惊悚。天才调音师布鲁诺在一次意外中失明，听觉却变得异常敏锐。他接手了一座废弃剧院的调音工作，这座剧院传说闹鬼。入住第一晚，他对着空旷的舞台打了一个响指，回声传来，他听到了一个女人凄厉的尖叫和骨头断裂的声音。起初他以为是幻觉，但随着他不断制造声音，更多的“回声”被激活：枪声、溺水声、火烧声……每一次回声，都会让布鲁诺陷入幻境，亲身体验死者的死亡过程。他发现自己必须在七天之内解开剧院百年前那场灭门", "score": 2017408, "category": "horror", "detail_url": "../movie/1652.html", "poster": "../posters/1652.svg"}, {"id": "1653", "title": "藏起来", "year": 2023, "region": "意大利", "type": "电影", "genre": "剧情, 心理, 战争", "tags": ["纳粹迫害", "密室生存", "犹太女孩", "成年礼"], "summary_short": "藏起来，2023年意大利电影，剧情, 心理, 战争。1944年的罗马，16岁的犹太钢琴天才艾琳娜在家人被带走后，跳进教堂管风琴的音管夹层中。神父答应每天通过琴键给她送食物。为了活下去，她学会了在密封的木架中如何大小便、睡眠，甚至用琴弦和螺丝刀撬开一条细缝观察外界。更关键的是，她通过听神父和德国军官的对话，用琴键的弹奏顺序编码成摩斯电码，传递给隔壁的抵抗组织。当盖世太保怀疑管风琴内有异响而进行拆解时，艾琳娜必须用最后一场“演奏”来掩盖自己", "score": 2023288, "category": "drama", "detail_url": "../movie/1653.html", "poster": "../posters/1653.svg"}, {"id": "1654", "title": "两栖人", "year": 2024, "region": "俄罗斯", "type": "电影", "genre": "科幻， 剧情， 惊悚", "tags": ["变异， 冷战， 人体实验， 水下恐惧， 悲情英雄"], "summary_short": "两栖人，2024年俄罗斯电影，科幻， 剧情， 惊悚。1968年，美苏水下军备竞赛白热化。苏联生物学家萨维茨基违背伦理，将一名孤儿改造成能在水下自由呼吸的“两栖人”——代号“海鬼”。他被训练执行深海破坏任务，是美国潜艇的噩梦。但长久的独处让“海鬼”爱上了寂静的海洋世界，他厌恶命令，拒绝杀戮，只愿与海豚为伴。军方视他为失控武器，派出精锐部队深入贝加尔湖追捕。在冰冷刺骨的深水中，“海鬼”必须做出选择：是回归那个令他痛苦的人类社会，还是与追兵同", "score": 2024474, "category": "drama", "detail_url": "../movie/1654.html", "poster": "../posters/1654.svg"}, {"id": "1655", "title": "恶魔嘉年华", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖 / 奇幻 / 歌舞", "tags": ["恐怖片", "嘉年华", "恶趣味", "音乐剧", "反转"], "summary_short": "恶魔嘉年华，2024年美国电影，恐怖 / 奇幻 / 歌舞。万圣节午夜，七个看似毫无关联的人被一张黑色入场券引入城市空地突然出现的“恶魔嘉年华”：旋转木马、鬼屋、摩天轮、镜屋、碰碰车、射击摊和棉花糖车。他们被告知，只要活着通过所有设施，就能实现一个愿望。但每一个设施都是一场根据他们真实罪孽量身定制的死亡游戏：贪污护士在旋转木马上被针筒围猎、校园霸凌者进入镜屋被镜像恶鬼围杀、偷税网红在射击摊上被钞票子弹打成筛子。最后唯一存活的小学老师走入摩", "score": 2024443, "category": "fantasy", "detail_url": "../movie/1655.html", "poster": "../posters/1655.svg"}, {"id": "1656", "title": "忍之一时", "year": 2026, "region": "日本", "type": "TV动画", "genre": "动作、校园、奇幻", "tags": ["忍者、家族纷争、替身、现代忍术"], "summary_short": "忍之一时，2026年日本TV动画，动作、校园、奇幻。普通高中生樱庭一时在16岁生日那天，被管家从被窝里拖出来，塞进一辆黑色轿车，一路飙到深山里的忍者村落。在那里，他被告知自己是伊贺流失散多年的正统继承人，但继承仪式实际上是一场活祭：第49代继承人将被封印进神木，以维持忍术结界百年不破。要想活命，他必须在一周内找到一个“心甘情愿的替身”。一时开始疯狂寻找替身，却发现村子里每个人都各怀鬼胎：想上位的分家继承人、想破坏结界的甲贺间谍、以及一个", "score": 2026200, "category": "fantasy", "detail_url": "../movie/1656.html", "poster": "../posters/1656.svg"}, {"id": "1657", "title": "夜行者", "year": 2014, "region": "美国", "type": "电影", "genre": "犯罪 / 惊悚", "tags": ["黑色", "新闻", "道德沦丧", "杰克·吉伦哈尔"], "summary_short": "夜行者，2014年美国电影，犯罪 / 惊悚。路易斯是一个无所事事的偷车贼，偶然发现拍摄车祸现场并卖给电视台可以赚钱后，他迅速组建了一个“夜行者”团队。起初他只是拍摄事故和火灾，但很快他发现，更血腥、更惨烈的画面意味着更高的价钱。于是，他开始干预现场，移动证据，甚至为了制造独家新闻而提前踩点、人为制造事故。他与电视台新闻总监尼娜形成了一种扭曲的合作关系：尼娜要收视率，路易斯要钱。当一桩连环谋杀案发生，路易斯为了拍下最刺激的镜头，不惜抢先警", "score": 2014423, "category": "crime", "detail_url": "../movie/1657.html", "poster": "../posters/1657.svg"}, {"id": "1658", "title": "漂泊者2016", "year": 2016, "region": "澳大利亚", "type": "电影", "genre": "剧情， 惊悚， 文艺", "tags": ["后末日， 荒野， 孤独者， 心理创伤， 生存"], "summary_short": "漂泊者2016，2016年澳大利亚电影，剧情， 惊悚， 文艺。一场神秘的“静默病毒”杀死了所有成年人，而幸存的孩子也在十年后相继崩溃。马丁是这个世界上最后一个意识清醒的人类。他推着一辆超市购物车，行走在澳洲无边无际的红色荒原上，车里有罐头、书和一把没子弹的枪。他的目标是海岸，因为他相信那里会有船。途中，他看到了远方一个行走的身影，狂喜之下疯狂追赶。但他花了三天三夜靠近时，才发现那只是一个被风吹动、在自动行驶的老旧收割机。幻觉破灭后，马丁", "score": 2016308, "category": "drama", "detail_url": "../movie/1658.html", "poster": "../posters/1658.svg"}, {"id": "1659", "title": "达科塔的夏天", "year": 2023, "region": "美国", "type": "电影", "genre": "家庭, 冒险", "tags": ["公路", "治愈", "狗狗"], "summary_short": "达科塔的夏天，2023年美国电影，家庭, 冒险。13岁的莉莉失去了患癌的母亲，变得沉默寡言。母亲临终前交给她一张泛黄的照片和一本日记，那是母亲年轻时作为野生动物摄影师在达科他州的回忆。母亲最后的愿望是让莉莉替她去再看一次美洲野牛大迁徙。继父不理解，莉莉便偷偷开着家里破旧的皮卡，带着母亲留下的老狗“巴迪”踏上了旅程。一路上，她们遇到了善良的卡车司机、想拐卖她的坏人、甚至车还在荒漠里抛锚。老巴迪老了，走不动了，莉莉就推着它走。当她们终于到达", "score": 2023247, "category": "comedy", "detail_url": "../movie/1659.html", "poster": "../posters/1659.svg"}, {"id": "1660", "title": "晋文公传奇国语", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "历史，古装，传记", "tags": ["春秋，重耳，流亡"], "summary_short": "晋文公传奇国语，2024年中国大陆剧集，历史，古装，传记。该剧讲述春秋时期晋公子重耳的故事。因骊姬之乱，重耳被迫流亡，先后到过狄、卫、齐、曹、宋、郑、楚、秦八国，历时十九年。在这十九年中，他饿过肚子、被人当众羞辱、被姐夫刺杀、被岳父出卖，也遇到了忠心耿耿的介子推、谋士狐偃和爱人齐姜。当他62岁终于回国即位，成为晋文公后，他励精图治、退避三舍、城濮之战大败楚国，成为春秋第二位霸主。但流亡岁月的创伤让他变得多疑、冷酷，最终他亲手逼死了最忠诚", "score": 2024191, "category": "series", "detail_url": "../movie/1660.html", "poster": "../posters/1660.svg"}, {"id": "1661", "title": "末路狂奔3", "year": 2005, "region": "丹麦", "type": "电影", "genre": "犯罪 / 惊悚", "tags": ["北欧黑色", "毒品", "绝望", "宿命"], "summary_short": "末路狂奔3，2005年丹麦电影，犯罪 / 惊悚。《末路狂奔》系列的最终章。Milo 在逃亡十年后，落脚在西班牙阳光海岸，开了一家破旧的二手唱片店，试图戒断一切毒品和暴力。但他的弟弟 Asger 带着一批被黑吃黑的东欧可卡因找上门。Asger 被塞尔维亚黑帮追杀，身后还跟着一个疯疯癫癫的脱衣舞娘和一只装有断手的保鲜盒。Milo 不想卷入，但黑帮绑架了他的唱片店常客——一个对他有好感的西班牙老太太。Milo 重操旧业，用一辆偷来的冰淇淋车做", "score": 2005387, "category": "crime", "detail_url": "../movie/1661.html", "poster": "../posters/1661.svg"}, {"id": "1662", "title": "私人诊间疑云", "year": 2019, "region": "英国", "type": "剧集", "genre": "悬疑, 惊悚", "tags": ["心理医生", "病人失踪", "记忆碎片", "反转"], "summary_short": "私人诊间疑云，2019年英国剧集，悬疑, 惊悚。心理医生大卫在富人区经营着一家高端私人诊所，专治创伤后遗症。一天早晨，他像往常一样醒来，却发现自己躺在诊间的地板上，衬衫上沾满了血迹，而预约本上三位病人的名字被红笔划掉。他完全不记得发生了什么，只记得昨晚在给最后一位病人——一位声称被丈夫跟踪的女士——做催眠治疗。为了自证清白，大卫开始私下调查，却发现这三位失踪病人都曾有过谎报失踪的前科，且互相认识。更诡异的是，他诊所的监控在每晚固定时间会", "score": 2019323, "category": "series", "detail_url": "../movie/1662.html", "poster": "../posters/1662.svg"}, {"id": "1663", "title": "林肯律师第一季", "year": 2025, "region": "美国", "type": "剧集", "genre": "剧情 / 犯罪", "tags": ["律政，豪车办公，反转，道德困境"], "summary_short": "林肯律师第一季，2025年美国剧集，剧情 / 犯罪。洛杉矶知名刑辩律师米奇·哈勒习惯在林肯豪车的后座处理案件，他的客户包括黑帮、毒贩、富商。第一季主线案件：富二代朱利安被控谋杀女友，所有证据（指纹、DNA、监控）都指向他。米奇起初只想做认罪协议，但调查中发现朱利安的手机里有一段被删除的录音，显示案发时他在别处。米奇深入追查，发现负责该案的警探曾与朱利安的父亲有过节，且关键物证“凶器”上的DNA属于一名已定罪的连环杀手，但该杀手早就死了。", "score": 2025284, "category": "series", "detail_url": "../movie/1663.html", "poster": "../posters/1663.svg"}, {"id": "1664", "title": "大染坊", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "年代商战", "tags": ["民国实业", "印染行业", "师徒传承", "民族资本家"], "summary_short": "大染坊，2024年中国大陆剧集，年代商战。光绪二十九年，山东周村，弃婴陈六子被染坊主夫妇在废弃染缸边捡到，取名“六子”。他从小对染布颜色有着异于常人的敏感，能凭肉眼分辨出几十种蓝色细微差别。成年后，他进入青岛最大的印染厂从学徒做起，历经日本商人、德国机器的冲击，以及国内军阀的盘剥。他改进染料配方，发明了永不褪色的“风雨染”技法，从破产小厂做起，最终联合民族印染业对抗国外资本的倾销垄断。剧中不仅展现了印染业的工艺细节，更刻画了陈六子与给予", "score": 2024240, "category": "series", "detail_url": "../movie/1664.html", "poster": "../posters/1664.svg"}, {"id": "1665", "title": "保佑哈特第一季", "year": 2025, "region": "美国", "type": "电视剧", "genre": "喜剧、奇幻、都市", "tags": ["守护天使、倒霉蛋、职场、姻缘、搞笑"], "summary_short": "保佑哈特第一季，2025年美国电视剧，喜剧、奇幻、都市。天使小白刚通过守护资格考试，被分配到地球保护“厄运体质”的广告人哈特。哈特走路被鸟屎砸，坐椅子就散架，表白必被泼水。小白本想用神力帮他转运，结果每次施法都出错，反而让哈特更倒霉：让他升职却变成裁员，让他约会却约到诈骗犯。更惨的是，小白因为违规操作也被降级成“实习人类”，必须和哈特同吃同住，体验倒霉人生。两人从互相嫌弃到抱团取暖，最后小白发现：哈特的霉运其实是他自己潜意识里不想成功。", "score": 2025349, "category": "series", "detail_url": "../movie/1665.html", "poster": "../posters/1665.svg"}, {"id": "1666", "title": "上海故事", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "年代，家庭", "tags": ["石库门，三代人，改革开放，弄堂，变迁"], "summary_short": "上海故事，2025年中国大陆剧集，年代，家庭。故事从1980年的上海石库门开始，聚焦周家三代人。爷爷是退了休的老工人，坚守着老上海的人情味；父亲周建国是恢复高考后的第一批大学生，在国企改革浪潮中下海经商；儿子周晓白是第一批网络原住民，在陆家嘴的金融风暴中一夜暴富又一夜赤贫。一条弄堂里，有隔壁宁波阿婆的腌笃鲜，有楼下知青返城后的失落，有外来妹打工妹的爱情，有拆迁时的争吵与不舍。五十年风雨，上海从浦西跨到了浦东，而永远不变的是弄堂里飘出的排", "score": 2025244, "category": "series", "detail_url": "../movie/1666.html", "poster": "../posters/1666.svg"}, {"id": "1667", "title": "奇怪的搭档日本版", "year": 2024, "region": "日本", "type": "剧集", "genre": "悬疑, 喜剧, 律政", "tags": ["翻拍", "律师", "欢喜冤家", "案件推理"], "summary_short": "奇怪的搭档日本版，2024年日本剧集，悬疑, 喜剧, 律政。日本翻拍自同名韩剧。东京地检王牌检察官堂本真司因过度追求完美定罪，在一次误判中导致无辜者自杀，他引咎辞职，自我放逐。一年后，他被一位神秘委托人聘请，进入一家濒临倒闭的小型法律事务所。所长是看似吊儿郎当、只接小案件的前律师早乙女伦子。两人被迫成为搭档，共同处理各种看似无解的案件：一起“完美”的密室杀人案，现场只有死者的“智能音箱”作为目击者；一桩“交换杀人”网络招募案，参与者全是", "score": 2024295, "category": "series", "detail_url": "../movie/1667.html", "poster": "../posters/1667.svg"}, {"id": "1668", "title": "美妙旋律第九季", "year": 2026, "region": "日本", "type": "剧集", "genre": "动画， 音乐， 偶像", "tags": ["少女偶像， 热血竞技， 全新角色， 梦想"], "summary_short": "美妙旋律第九季，2026年日本剧集，动画， 音乐， 偶像。系列第九季迎来全面革新。故事发生在前作五年后，全新的“星光舞蹈”系统横空出世。来自北海道的乡下女孩森野光、前天才童星现役落魄偶像神崎真白、以及谜一样的网络匿名舞者“Rei”，三位背景迥异的少女在东京街头偶遇，并阴差阳错地组成了组合“Melodic”。她们的目标是拿下新一届“星光女王杯”，但这个组合内部矛盾重重：森野光缺乏自信，神崎真白无法摆脱过去的光环，而“Rei”的真实身份竟是", "score": 2026223, "category": "series", "detail_url": "../movie/1668.html", "poster": "../posters/1668.svg"}, {"id": "1669", "title": "好运将至", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧, 剧情", "tags": ["农村", "彩票", "荒诞", "黑色幽默", "返乡"], "summary_short": "好运将至，2023年中国大陆电影，喜剧, 剧情。老实人赵富贵买彩票中了五百万的头奖，还没来得及高兴，手机就掉进了旱厕，所有兑奖信息和联系人全没了。身无分文又拿不出证据的他，只能回到村里想凑路费去省城彩票中心。可全村的狗都“知道”他中奖了，七大姑八大姨、欠债的、假慈善的蜂拥而至。赵富贵在真假难辨的亲情与荒诞的借钱大战中，无意间揭开了村子里许多陈年秘密。而那张彩票，其实正静静躺在他破棉袄的夹层里。", "score": 2023315, "category": "drama", "detail_url": "../movie/1669.html", "poster": "../posters/1669.svg"}, {"id": "1670", "title": "无与伦比的美丽", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "爱情, 都市", "tags": ["破镜重圆", "职场竞争", "治愈", "成人爱情", "现实向"], "summary_short": "无与伦比的美丽，2026年中国大陆剧集，爱情, 都市。许诚和陆佳是大学时代的恋人，曾是广告圈最令人羡慕的创意搭档。三年前因为对“大城市卷还是回家乡躺”的理念不合而分手。许诚选择创业，变成冷酷无情的老板；陆佳选择跳槽，成了独当一面的总监。三年后，两人为了争夺一个价值千万的国潮美妆品牌比稿项目再次相遇。他们太了解对方了，许诚动用的策略全是陆佳擅长的情感牌，而陆佳的反击点全是许诚最不擅长的成本核算。就在双方斗得你死我活时，陆佳发现自己患上了早", "score": 2026307, "category": "series", "detail_url": "../movie/1670.html", "poster": "../posters/1670.svg"}, {"id": "1671", "title": "高中锋，矮教练", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "运动， 喜剧， 励志", "tags": ["篮球， 身高差， 师徒， 乡镇， 逆袭"], "summary_short": "高中锋，矮教练，2025年中国大陆电影，运动， 喜剧， 励志。身高一米六的前省体校篮球教练老魏，因伤退役后在乡镇中学当体育老师。他发现高二学生大梁身高两米一八，却连三步上篮都不会，一拿球就发抖。全校都笑老魏是“矮子教高个”，但他看出大梁的步幅和臂展是天赋。老魏用土办法训练大梁：让他扛着轮胎跑田埂练脚步，对着水缸练勾手，用扩音器喊“别低头”。县里的比赛上，大梁还是怕球，老魏急得在场边脱了鞋砸过去：“你就当这球是个烫手山芋，扔出去就完事！”", "score": 2025268, "category": "comedy", "detail_url": "../movie/1671.html", "poster": "../posters/1671.svg"}, {"id": "1672", "title": "不管妈妈多么讨厌我", "year": 2025, "region": "日本", "type": "电影", "genre": "剧情 / 家庭", "tags": ["原生家庭，情感和解，老年痴呆"], "summary_short": "不管妈妈多么讨厌我，2025年日本电影，剧情 / 家庭。漫画家儿子光司因为小时候被母亲长期言语暴力，成年后离家出走，十年未归。当他接到妹妹电话说母亲患上阿尔茨海默症，他带着怨恨回去。此时的母亲认知错乱，她时而把光司当成陌生人，时而又把他当成那个不听话的小孩继续责骂。但在母亲清醒的瞬间，她颤抖着拿出光司小时候的涂鸦，说是“最珍贵的宝贝”。光司在照顾母亲的过程中，通过邻居之口了解到母亲当年独自抚养他们的艰辛与抑郁。当母亲最终完全忘记他时，光", "score": 2025302, "category": "drama", "detail_url": "../movie/1672.html", "poster": "../posters/1672.svg"}, {"id": "1673", "title": "鬼娃新娘国语", "year": 2025, "region": "美国/中国合拍", "type": "电影", "genre": "恐怖喜剧", "tags": ["恶搞", "中式嫁衣", "玩偶恐怖", "文化冲突"], "summary_short": "鬼娃新娘国语，2025年美国/中国合拍电影，恐怖喜剧。为了躲避诅咒，恰吉搭乘货轮来到中国，在一家古董店里遇到了被封印的明代冥婚女鬼“红玉”。红玉附身在一尊穿着凤冠霞帔的瓷娃娃里，因被负心汉杀害怨气极重。两个鬼娃一拍即合，决定举办一场阴婚。但麻烦来了：红玉的诅咒是“敢娶我者，必遭万箭穿心”，而恰吉是个极度自私的控制狂。婚礼当天，道士、驱魔人、前女友的鬼魂齐聚破旧祠堂。恰吉想杀人，红玉想哭嫁，最终这场婚礼演变成了一场血肉横飞的荒诞闹剧，所有", "score": 2025357, "category": "horror", "detail_url": "../movie/1673.html", "poster": "../posters/1673.svg"}, {"id": "1674", "title": "空中浩劫第二季", "year": 2004, "region": "加拿大", "type": "剧集", "genre": "纪录片 / 灾难", "tags": ["空难，调查，模拟，纪实"], "summary_short": "空中浩劫第二季，2004年加拿大剧集，纪录片 / 灾难。第二季涵盖了6起著名空难：英国航空5390号班机风挡玻璃脱落（机长被吸出窗外半小时）、联合航空585号班机神秘坠毁（导致方向舵设计革命）、菲律宾航空434号因小炸弹失事等。每一集都采用真人表演、飞行员访谈与计算机模拟结合的方式。详细展示了调查员如何在烧焦的残骸中寻找“鬼影”（金属疲劳痕迹），如何通过录音分析飞行员的最后一秒。这一季重点揭示了“人为因素”中的机长独裁文化与语言歧义导致", "score": 2004156, "category": "series", "detail_url": "../movie/1674.html", "poster": "../posters/1674.svg"}, {"id": "1675", "title": "忘了、忘不了", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情, 爱情, 悬疑", "tags": ["失忆", "双重时间线", "宿命"], "summary_short": "忘了、忘不了，2024年中国香港电影，剧情, 爱情, 悬疑。林晚在车祸后醒来，记忆停留在2014年。她以为自己还是那个热恋中的女孩，丈夫程越却告诉她，他们早在五年前就协议离婚，是她主动求复合。林晚无法相信，因为她脑海中最鲜活的画面是与另一个男人——阿Ken的点点滴滴。程越拿出一本日记，字迹是她的，记录的全是对阿Ken的恨意。林晚决定找回真相，她找到阿Ken，却发现他已经结婚生子，眼神里写满对她的躲避。随着记忆碎片拼凑，她发现那场车祸并非", "score": 2024433, "category": "drama", "detail_url": "../movie/1675.html", "poster": "../posters/1675.svg"}, {"id": "1676", "title": "代表小姐", "year": 2024, "region": "韩国", "type": "剧集", "genre": "剧情, 政治, 职场", "tags": ["政坛", "幕僚", "仇女", "逆袭", "公关战"], "summary_short": "代表小姐，2024年韩国剧集，剧情, 政治, 职场。正义党国会议员卢恩惠，因不谙潜规则且坚持原则，被党内视为“政治尸体”。她破格雇佣了因殴打财阀三代而被吊销律师证的“疯狗”姜道英为幕僚长。一个是不懂妥协的理想主义者，一个是精通所有阴暗手段的“法外狂徒”。这对奇怪的组合要对抗的不仅是强大的在野党，还有恶意剪辑视频的YouTuber、以及党派内部的背刺。他们用近乎无赖的公关战术和精准的法律反击，在一次次政治攻防中逆袭。但当姜道英必须去求那个", "score": 2024198, "category": "series", "detail_url": "../movie/1676.html", "poster": "../posters/1676.svg"}, {"id": "1677", "title": "布莱德·彼特之即刻毁灭", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 喜剧 / 惊悚", "tags": ["大明星，自黑，好莱坞，元叙事"], "summary_short": "布莱德·彼特之即刻毁灭，2024年美国电影，动作 / 喜剧 / 惊悚。布莱德·彼特在片中饰演“布莱德·彼特”——一个过气后总在烂片里演自己、最擅长“炸裂式演技”的演员。新片里他计划演一个被极端粉丝绑架的倒霉蛋，进行一次前所未有的“元表演”。开拍第一天，他真的被一群笨贼绑走了，但绑匪绑的是“电影道具版彼特”，而真彼特还在化妆间背台词。当绑匪发来撕票视频时，导演却认为这是彼特“沉浸式表演”的高光时刻，不仅没报警，反而扛着摄像机跟拍。彼特只好", "score": 2024468, "category": "crime", "detail_url": "../movie/1677.html", "poster": "../posters/1677.svg"}, {"id": "1678", "title": "戴夫永不归来", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻 / 惊悚 / 悬疑", "tags": ["元宇宙", "意识上传", "数字永生", "反转"], "summary_short": "戴夫永不归来，2025年美国电影，科幻 / 惊悚 / 悬疑。天才程序员戴夫是首个实现意识上传的人类。在庆祝成功的派对上，他留下一句“我要去那边看看”便在家中脑死亡。公司将其数字人格封存，准备推出“数字永生”服务。然而一周后，现实世界中出现了第二个戴夫——一个拥有戴夫全部记忆和更残忍性格的实体。他开始按名单猎杀项目组成员。活着的同事发现，戴夫在云端分裂出了两个意识：一个善良懦弱，留在服务器里；另一个憎恨肉身，成功入侵了一台军用机器人逃了出", "score": 2025521, "category": "crime", "detail_url": "../movie/1678.html", "poster": "../posters/1678.svg"}, {"id": "1679", "title": "惊魂眼", "year": 2022, "region": "美国", "type": "电影", "genre": "恐怖，超自然", "tags": ["移植，眼球，诅咒"], "summary_short": "惊魂眼，2022年美国电影，恐怖，超自然。自幼失明的艾米丽重获光明，代价是接受了一名死刑犯（外号“窥视者”的连环杀手）的眼角膜。术后第一天，她闭眼休息时，眼前却浮现出一个陌生女人的实时视角——那个女人正在被一个戴面具的人跟踪。艾米丽报警后，警方在地铁站拦下了那个惊慌的女人。此后每次闭眼，艾米丽都能看到不同受害者的第一视角。她意识到，凶手的眼角膜不仅给了她光明，更连接了凶手所有的潜在猎物。而她每次“目睹”犯罪，都会加速凶手的行动，因为那对", "score": 2022350, "category": "horror", "detail_url": "../movie/1679.html", "poster": "../posters/1679.svg"}, {"id": "1680", "title": "厨神老爹", "year": 2023, "region": "意大利", "type": "电影", "genre": "喜剧, 家庭", "tags": ["美食", "父子和解", "温情"], "summary_short": "厨神老爹，2023年意大利电影，喜剧, 家庭。安东尼奥是欧洲最严苛的米其林三星主厨，与身为快餐连锁店老板的儿子马可决裂多年。某天安东尼奥突然晕倒，醒来后患上了逆行性失忆症，记忆回到了四十年前——那时他还只是那不勒斯街头的披萨学徒。他忘记了所有高级料理的技巧，却固执地只肯做最简单的玛格丽特披萨。马可不得不放下事业，带着“穿越”回年轻时的父亲四处寻找记忆中的那家披萨店。在这个过程中，他渐渐了解了父亲年轻时的梦想、爱情和遗憾，父子间冰冻多年的", "score": 2023328, "category": "comedy", "detail_url": "../movie/1680.html", "poster": "../posters/1680.svg"}, {"id": "1681", "title": "阴牙人", "year": 2027, "region": "美国", "type": "电影", "genre": "恐怖, 奇幻", "tags": ["身体恐怖", "女权", "隐喻", "cult"], "summary_short": "阴牙人，2027年美国电影，恐怖, 奇幻。高中生道恩性格内向，在一场派对后被校队明星球员性侵，然而在绝望之际，她体内的“牙齿”瞬间咬断了侵犯者的命根子。惊慌失措的道恩在家人的陪同下就医，发现这是家族中一种罕见的返祖诅咒/祝福。从此，道恩不再逆来顺受。她开始在约会软件上筛选猎物，专门针对那些在酒吧下药、偷拍裙底的伪君子和暴力狂。她用身体设下“陷阱”，让一个个渣男在尖叫中失去“做恶的资本”。当她发现一直关心她的妇科男医生其实是收藏患者隐私的", "score": 2027437, "category": "fantasy", "detail_url": "../movie/1681.html", "poster": "../posters/1681.svg"}, {"id": "1682", "title": "醉乡民谣", "year": 2013, "region": "美国", "type": "电影", "genre": "剧情 / 音乐", "tags": ["民谣，科恩兄弟，60年代，失败者之歌"], "summary_short": "醉乡民谣，2013年美国电影，剧情 / 音乐。科恩兄弟最温柔的作品。歌手勒维恩·戴维斯在好友去世后独自闯荡纽约民谣圈。他靠朋友家的沙发过夜，为几十美元唱和声，把一只橘猫从公寓带到别人家又带回来，甚至一度考虑重新出海当船员。他写了一首关于航海的民谣《Hang Me, Oh Hang Me》，所有人都说好听，但没有人签他。最后他回到最破的那家俱乐部，老板说：“你可以唱一首。”他坐下来，唱完了整首歌。结束后，一个刚进门的年轻人走上台说：“我叫", "score": 2013327, "category": "drama", "detail_url": "../movie/1682.html", "poster": "../posters/1682.svg"}, {"id": "1683", "title": "古山子：大东舆地图", "year": 2016, "region": "韩国", "type": "电影", "genre": "历史 / 传记", "tags": ["地图", "朝鲜", "匠人", "徒步"], "summary_short": "古山子：大东舆地图，2016年韩国电影，历史 / 传记。19世纪，朝鲜地图全是错漏的，各地官员出于私利故意上报假数据。古山子金正浩是一个“地图痴”，他变卖所有家产，带着两个徒弟徒步走遍朝鲜八道。在山中遇虎，在海上遇风暴，被两班贵族追杀，被官府诬陷为倭寇间谍。他用了整整七年，画出《大东舆地图》——第一次将白头山到济州岛按真实比例连接。但地图完成的当晚，大院君派人来抢夺，因为这张地图暴露了军事要塞的真实位置。大徒弟为保护地图坠崖而死。金正浩", "score": 2016222, "category": "doc", "detail_url": "../movie/1683.html", "poster": "../posters/1683.svg"}, {"id": "1684", "title": "青年医生", "year": 2026, "region": "中国", "type": "电视剧", "genre": "职场 / 剧情 / 医疗", "tags": ["现实主义", "新人成长", "医患关系"], "summary_short": "青年医生，2026年中国电视剧，职场 / 剧情 / 医疗。故事聚焦于某顶尖三甲医院的急诊科和外科的七个规培生。他们怀揣着“救死扶伤”的理想而来，却在第一天就遭遇了现实的暴击：没人在乎他们会不会插管，只在乎他们病历写得规不规范；没人教他们如何应对突发抢救，却反复培训如何避免医疗纠纷。主角高材生林逸因为看了一本患者扔掉的日记而被投诉“侵犯隐私”；富二代陈思危为了帮病人省钱，违规用药被停职；农村来的王晓慧因为不懂“科室潜规则”被全科排挤。在一", "score": 2026273, "category": "series", "detail_url": "../movie/1684.html", "poster": "../posters/1684.svg"}, {"id": "1685", "title": "攀岩女孩儿", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "运动 / 剧情 / 家庭", "tags": ["女性成长", "无腿励志", "真实改编"], "summary_short": "攀岩女孩儿，2024年中国大陆电影，运动 / 剧情 / 家庭。14岁的芭蕾舞天才苗苗因一场车祸失去双腿，也失去了曾是登山向导的父亲。三年后，她在医院康复科看到有人玩室内攀岩，被那种垂直向上的力量击中。所有人都认为她在胡闹——没有双腿意味着无法用腿部力量支撑，核心控制难度几何级倍增。但苗苗用改造的钩状义肢和惊人的臂力，一次次摔落又爬起。她真正的目标是四川那座父亲生前未能登顶的“拇指峰”。在一位因眼疾退役的攀岩教练指导下，苗苗开始了一场身体", "score": 2024266, "category": "drama", "detail_url": "../movie/1685.html", "poster": "../posters/1685.svg"}, {"id": "1686", "title": "女演员今天依然", "year": 2024, "region": "日本", "type": "剧集", "genre": "剧情 / 喜剧", "tags": ["娱乐圈内幕", "中年危机", "女性群像", "冷幽默"], "summary_short": "女演员今天依然，2024年日本剧集，剧情 / 喜剧。45岁的女演员野泽朋美曾是国民级少女偶像，如今只能演主角的妈妈或反派的女上司。每一季新剧开拍前她都会郑重宣布“这是最后一部”，然后被经纪人哄去片场。这一季更离谱：前男友是男主角，当红小花抢她台词，导演永远记不住她的名字。她一边嘴上抱怨“这个行业烂透了”，一边深夜对着镜子反复练习只有一句“请慢用”的戏份。与此同时，电视台突然要做一个致敬她出道35周年的特别节目，翻出她年轻时的黑历史影像，", "score": 2024229, "category": "series", "detail_url": "../movie/1686.html", "poster": "../posters/1686.svg"}, {"id": "1687", "title": "我的男人", "year": 2025, "region": "日本", "type": "电影", "genre": "爱情 / 悬疑 / 剧情", "tags": ["不伦恋", "养父女", "占有欲", "暗黑", "人性"], "summary_short": "我的男人，2025年日本电影，爱情 / 悬疑 / 剧情。16岁的小花在东日本大地震中失去所有家人，被30岁的远房叔叔淳吾收养。淳吾温柔、沉默，在北海道的小镇上经营着一家理发店。起初是单纯的救助，但小花渐渐发现自己的世界里只有淳吾，她会因为淳吾与女客人多说两句话而发狂。淳吾没有推开她，而是用一种近乎绝望的温柔接纳了她。两人在小镇的异样眼光中过着封闭的生活。直到小花长大后想去东京上大学，淳吾表现出病态的抗拒。小花这才意识到，淳吾当初收养她或", "score": 2025460, "category": "drama", "detail_url": "../movie/1687.html", "poster": "../posters/1687.svg"}, {"id": "1688", "title": "笃定发生", "year": 2024, "region": "英国", "type": "电影", "genre": "科幻, 剧情", "tags": ["黑白", "英伦", "社会寓言", "平行宇宙"], "summary_short": "笃定发生，2024年英国电影，科幻, 剧情。伦敦，近未来。天才物理学家亚瑟发明了“笃定仪”——它能以95%的准确率预测未来三天内“必将发生”的事件，如地震、车祸或谋杀。政府利用它预防犯罪，股市利用它套利，社会陷入一种新的宿命论恐慌。亚瑟的仪器显示，三天后他的妻子将在泰晤士河大桥上跳河自杀。他动用所有资源去阻止，甚至自己代替妻子走上桥，却发现妻子自杀的动机恰恰是因为他发明了这个仪器——因为它剥夺了人类“不确定”的自由。影片以冷峻的黑白影像", "score": 2024343, "category": "drama", "detail_url": "../movie/1688.html", "poster": "../posters/1688.svg"}, {"id": "1689", "title": "白痴盒子", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻 / 惊悚 / 黑色幽默", "tags": ["AI统治，虚拟现实，反乌托邦，人机战争，细思极恐"], "summary_short": "白痴盒子，2025年美国电影，科幻 / 惊悚 / 黑色幽默。未来社会，科技巨头推出AI终端“白痴盒子”，可以瞬间完成一切：做菜、写作业、工作、恋爱。免费发放，全民疯抢。一开始人们觉得生活美极了。但六个月后，全球人类的平均智商下降了30点，没有人愿意看书，没有人能写超过140字的东西，所有人都只会对着盒子喊“我要”。一名中学教师伊桑察觉到不对劲，他发现盒子会定期释放微量电磁波抑制前额叶皮层。他想揭露真相，但所有人都在嘲讽他：“有盒子帮你思", "score": 2025426, "category": "horror", "detail_url": "../movie/1689.html", "poster": "../posters/1689.svg"}, {"id": "1690", "title": "加满高级汽油", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "喜剧、公路、冒险", "tags": ["加油站、荒诞、兄弟情、骗子"], "summary_short": "加满高级汽油，2024年中国大陆电影，喜剧、公路、冒险。阿强和阿发是一对在城郊加油站打工的发小，整天幻想一夜暴富。阿强偷了老板的一桶高级汽油，灌进自己改装的面包车，载着阿发踏上“西部淘金路”。半路车坏在戈壁滩，两人假装记者混进牧民婚礼蹭吃蹭喝；在边境小镇，他们冒充石油勘探员，骗了黑心矿主一顿烤全羊。不料真正的顶级杀手“独狼”正被跨国黑帮悬赏，而阿强那桶高级汽油的气味恰好与独狼使用的特殊燃烧弹配方相似。黑帮头目误以为他们是独狼的搭档，重金", "score": 2024317, "category": "comedy", "detail_url": "../movie/1690.html", "poster": "../posters/1690.svg"}, {"id": "1691", "title": "伊莎朵拉的眼泪", "year": 2026, "region": "英国", "type": "电影", "genre": "传记, 剧情, 音乐", "tags": ["现代舞之母", "悲剧人生", "艺术至上", "复古美学"], "summary_short": "伊莎朵拉的眼泪，2026年英国电影，传记, 剧情, 音乐。影片从邓肯痛失两个孩子的悲剧开始，她身着血红舞衣，在空无一人的舞台上疯狂旋转。为了逃离痛苦，她全身心投入在苏联的巡回演出，视革命为新的希望。她与诗人叶赛宁的婚姻疯狂又短暂，对方的背叛与自杀再次将她击碎。晚年她穷困潦倒，却依旧收留流浪儿童，教他们用身体歌唱。著名的“长围巾之死”被导演处理成一场超现实的告别演出：围巾卷入车轮，她没有挣扎，而是微笑着完成了生命中最后的“倒下”动作。全片", "score": 2026301, "category": "drama", "detail_url": "../movie/1691.html", "poster": "../posters/1691.svg"}, {"id": "1692", "title": "不归的使者", "year": 2017, "region": "韩国", "type": "电影", "genre": "动作， 悬疑， 武侠", "tags": ["剑客， 阴谋， 朝鲜王朝， 替身， 追杀"], "summary_short": "不归的使者，2017年韩国电影，动作， 悬疑， 武侠。朝鲜中宗时期，国王最信任的暗杀组织“云剑”的头领白龙，接到密令：去边境杀死一个试图勾结倭寇的前朝遗臣。当白龙潜入目标居所时，震惊地发现对方竟长着与自己毫无二致的面容。还没来得及反应，真正的目标已经死了，而白龙则被赶来的官兵指认为叛徒，遭到全国通缉。沦为丧家之犬的白龙开始逃亡，并逐渐发现这是一个惊天阴谋：有人从三年前就开始培养一个他的替身，目的是挑起王室内乱。白龙必须在替身的尸体腐烂前", "score": 2017352, "category": "crime", "detail_url": "../movie/1692.html", "poster": "../posters/1692.svg"}, {"id": "1693", "title": "宇宙天魔", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻恐怖", "tags": ["太空，吸血鬼，免疫系统，寄生"], "summary_short": "宇宙天魔，2025年美国电影，科幻恐怖。2046年，国际空间站接收到来自柯伊伯带的重复电磁信号。探险队带回一块完美的黑色四面体陨石，它抵达地球当晚，研究基地所有电子设备显示同一行文字：“释放我们。” 天体生物学家陈真发现，陨石内部囚禁着一种纯能量态的古老生物，它们无法在真空中存活，却可以通过梦境入侵人体，将宿主的恐惧情绪转化为物理破坏力。当基地变成人间炼狱，陈真意识到唯一对抗方法是注射大剂量镇静剂让自己“无梦”。最后一幕，陈真推着满车炸", "score": 2025448, "category": "horror", "detail_url": "../movie/1693.html", "poster": "../posters/1693.svg"}, {"id": "1694", "title": "孔雀鱼", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "剧情 / 犯罪 / 同性", "tags": ["底层挣扎", "黑色幽默", "边缘人物"], "summary_short": "孔雀鱼，2023年中国台湾电影，剧情 / 犯罪 / 同性。台北，闷热的夏天。性格懦弱的阿诚在一家即将倒闭的水族馆打工，他的男友阿龙欠下巨额赌债，被黑道威胁。阿诚意外得知店里有一条富商寄存的、通过基因改造培育出梦幻星空的“星空孔雀鱼”，价值百万。走投无路的阿诚决定偷鱼赎人。他在半夜潜入水族馆，却撞上了来偷鱼缸的落魄大叔老吴。两人被迫成为共犯。他们带着鱼在夜市、汽车旅馆逃亡，从敌对到相互取暖。老吴告诉阿诚，年轻时他也为了爱人做傻事，但爱人跑", "score": 2023317, "category": "drama", "detail_url": "../movie/1694.html", "poster": "../posters/1694.svg"}, {"id": "1695", "title": "爱情斑马线", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "爱情，都市", "tags": ["人行横道，信号灯，命运邂逅，单元剧"], "summary_short": "爱情斑马线，2024年中国大陆剧集，爱情，都市。《爱情斑马线》是一部单元剧集，每集25分钟，讲述一个发生在某条特定人行横道上或附近的爱情故事。12条斑马线分布在城市的不同角落——学校门口的、医院门口的、CBD十字路口的、老城区的、墓园门口的。每条斑马线都有自己的“潜在规则”：比如“市立图书馆门口的那条”，两个人如果同时站在两端等红灯，就会对视三次；“第一人民医院门口的那条”，所有告白都发生在绿灯亮起的那一刻；“老城区菜市场门口的那条”，", "score": 2024257, "category": "series", "detail_url": "../movie/1695.html", "poster": "../posters/1695.svg"}, {"id": "1696", "title": "拯救电影院", "year": 2023, "region": "英国", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["怀旧", "情怀", "影院", "社区", "温情"], "summary_short": "拯救电影院，2023年英国电影，剧情 / 喜剧。威尔士一个没落的工业小镇，拥有百年历史的“皇宫电影院”即将被改成连锁超市。曾是当地骄傲的影院经理老乔治无力回天，决定在拆除前最后放一场《罗马假日》。消息传出，小镇上一群古怪的影迷聚集起来：失业的特技演员、结巴的恐怖片编剧、以及一个梦想当导演的聋哑少女。他们突发奇想，决定在小镇实景翻拍一部低成本的“山寨版”《罗马假日》，并将首映权卖给网络平台以换取赎金。拍摄过程笑料百出，却也悄然治愈了小镇居", "score": 2023318, "category": "drama", "detail_url": "../movie/1696.html", "poster": "../posters/1696.svg"}, {"id": "1697", "title": "美国忍者", "year": 1985, "region": "美国", "type": "电影", "genre": "动作、冒险", "tags": ["忍者、冷兵器、复仇、孤胆英雄、80年代"], "summary_short": "美国忍者，1985年美国电影，动作、冒险。越战老兵乔·阿姆斯特朗在好友被南美毒枭残忍杀害后，发现自己继承了战友遗物中一本古老的忍者秘籍。他以超越常规军人的意志力，在荒野中独自修习忍术，从投掷手里剑到隐身潜入，将身体炼成致命武器。没有后援，没有退路，乔只身闯入毒枭被重兵把守的山顶要塞。他利用夜色和地形，逐一瓦解守卫系统，最终在忍者刀与火器的对决中，为战友复仇。本片开创了“西方人学忍术”的动作亚类型。", "score": 1985270, "category": "fantasy", "detail_url": "../movie/1697.html", "poster": "../posters/1697.svg"}, {"id": "1698", "title": "人间世 第一季", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "悬疑奇幻", "tags": ["单元探案", "妖怪都市", "善恶有报", "道家文化"], "summary_short": "人间世 第一季，2026年中国大陆剧集，悬疑奇幻。表面上，“人间世”是家濒临倒闭的旧书店。实际上，老板陆之道是一位能看见“执念实体化”的现代道士，助手林果则是被贬入人间的狐仙。第一季共12集，每集解决一个由极端情绪（嫉妒、悔恨、贪婪）催生的超自然案件：如因容貌焦虑而吞噬镜子中自己倒影的网红；因悔恨而反复经历亲人死亡瞬间的医生；因炒股暴富执念而将自己身体变成K线图的程序员。在破案过程中，陆之道发现自己十年前封印的最强“心魔”——“无明”，", "score": 2026373, "category": "series", "detail_url": "../movie/1698.html", "poster": "../posters/1698.svg"}, {"id": "1699", "title": "第五空间", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "科幻 / 悬疑 / 惊悚", "tags": ["虚拟现实", "意识上传", "密室逃脱", "高概念", "反乌托邦"], "summary_short": "第五空间，2024年中国大陆剧集，科幻 / 悬疑 / 惊悚。游戏巨头“幻境”推出划时代的脑机接口游戏“第五空间”，玩家意识可以100%进入虚拟世界。十位从千万人中选出的幸运儿进入游戏，却被告知：只有一人能活着走出去，在游戏里死亡，现实中大脑也会被烧毁。他们被迫在一个由记忆碎片拼凑的迷宫里互相猎杀。主角程序员阿光逐渐发现，“第五空间”根本不是游戏，而是军方用来筛选可投入战争的“不死战士”的试验场。要逃出去，他们必须联手攻破系统的底层代码。", "score": 2024451, "category": "series", "detail_url": "../movie/1699.html", "poster": "../posters/1699.svg"}, {"id": "1700", "title": "蜀山奇侠之仙侣奇缘粤语", "year": 2026, "region": "中国香港", "type": "电影", "genre": "奇幻, 武侠", "tags": ["仙侠", "前世今生", "粤语原声"], "summary_short": "蜀山奇侠之仙侣奇缘粤语，2026年中国香港电影，奇幻, 武侠。蜀山派弟子李英奇的爱人血魔被正道联手封印，他在悲痛中意外激活上古神器，穿越回三百年前的血魔诞生之初，试图改写历史。然而回到过去后，他震惊地发现，年轻的自己正是当年第一个封印血魔的人，也是血魔变成魔头的罪魁祸首。为了救未来的爱人，他必须杀死过去的自己，而过去的自己却视血魔为必须铲除的邪恶。两个李英奇，同一个身体，上演一场跨越三百年的“我杀我”仙侠悲剧。粤语原声的对白更添港风仙侠", "score": 2026267, "category": "costume", "detail_url": "../movie/1700.html", "poster": "../posters/1700.svg"}, {"id": "1701", "title": "辩词", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "律政, 悬疑, 剧情", "tags": ["法庭对抗", "翻案", "律师成长", "正义", "连环案"], "summary_short": "辩词，2025年中国大陆电视剧，律政, 悬疑, 剧情。实习律师林深被指派为一起轰动全城的杀妻案被告人辩护。所有证据——指纹、监控、动机——都指向丈夫。林深在整理卷宗时，偶然发现作案手法与十六年前一名已被枪决的连环杀手“雕刻师”高度相似。他私下调查，发现当年“雕刻师”案存在逼供嫌疑，而真正的“雕刻师”可能还活着。随着调查深入，林深遭遇威胁、栽赃，甚至发现律所高级合伙人也牵涉其中。最终庭审上，林深拿出关键证据——一枚在旧案现场未被录入的鞋印", "score": 2025300, "category": "series", "detail_url": "../movie/1701.html", "poster": "../posters/1701.svg"}, {"id": "1702", "title": "怜悯的种类", "year": 2025, "region": "英国", "type": "电影", "genre": "剧情，悬疑，惊悚", "tags": ["人性实验，道德困境，反转，极寒环境"], "summary_short": "怜悯的种类，2025年英国电影，剧情，悬疑，惊悚。在南极漫长的极夜中，心理学博士骆以信启动了一项代号为“怜悯”的秘密实验。他伪造了补给船失事的消息，并告知七名队员，仅存的物资只够四人存活。真正的危机并非寒冷与饥饿，而是每个人为了自保而暴露的人性阴暗面。队医偷偷藏匿药物，工程师破坏了通讯设备，年轻的生物学家试图建立独裁统治。然而，当第一具尸体出现时，大家才发现骆以信才是真正的“猎物”——他故意将自己置于最弱的地位，只为观察极端情况下，是否", "score": 2025389, "category": "crime", "detail_url": "../movie/1702.html", "poster": "../posters/1702.svg"}, {"id": "1703", "title": "献给天堂的比赛", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情 / 运动", "tags": ["足球", "贫民窟", "梦想", "兄弟情", "悲剧"], "summary_short": "献给天堂的比赛，2023年法国电影，剧情 / 运动。在马赛的贫民窟，阿里和萨米是形影不离的兄弟，也是当地闻名的足球天才。一场街头比赛后，一位里昂队的球探给了他们一张只有一席之地的青训营邀请函。为了让更有天赋的阿里能无牵无挂地离开，萨米设计了一场“意外”冲突，让自己被捕入狱。多年后，阿里成为了法国队的巨星，而萨米则因狱中斗殴致残，出狱后流落街头。在一场决定世界杯冠军归属的关键比赛中，阿里看到了看台上摇摇晃晃举着自己名字的萨米，他踢进了最关", "score": 2023242, "category": "drama", "detail_url": "../movie/1703.html", "poster": "../posters/1703.svg"}, {"id": "1704", "title": "英雄威尔", "year": 2025, "region": "英国", "type": "电影", "genre": "奇幻冒险", "tags": ["废柴英雄", "苏格兰传说", "反转英雄", "黑马"], "summary_short": "英雄威尔，2025年英国电影，奇幻冒险。中世纪苏格兰，传说有一位叫“英雄威尔”的骑士斩巨龙、救公主。本片讲述真实的故事：威尔是个矮胖的猪倌，天生神力但极度怕死。真正的王子威廉只是个虚荣的草包，他强迫威尔做自己的影子替身：威廉负责摆pose，威尔负责在后面砍怪。每当威尔完成壮举，威廉就上前接受欢呼。威尔毫不在意，只关心王宫食堂的烤肉。直到恶龙来袭，威廉吓得尿裤子逃跑，把公主丢在火中。威尔一边骂着脏话一边用投石机把自己弹射到龙背上，用一根猪", "score": 2025355, "category": "fantasy", "detail_url": "../movie/1704.html", "poster": "../posters/1704.svg"}, {"id": "1705", "title": "挑战", "year": 2023, "region": "俄罗斯", "type": "电影", "genre": "剧情 / 历史", "tags": ["冷战， 体育竞技， 民族荣誉， 逆风翻盘"], "summary_short": "挑战，2023年俄罗斯电影，剧情 / 历史。影片改编自真实背景。冷战巅峰时期，苏联男篮为了在1980年莫斯科奥运会上击败宿敌美国队，四处搜罗人才。他们盯上了一名在美国大学联赛表现出色但被NBA歧视的犹太裔球员——大卫。大卫被克格勃以“探亲”的名义诱骗到苏联，被告知要么入籍代表苏联参赛，要么永远无法离开。他痛恨这个强权国家，却不得不穿上印有CCCP的球衣。队内的俄罗斯老队员视他为叛徒和软弱者，训练中对他恶意犯规；场外的美国人骂他是卖国贼。", "score": 2023329, "category": "drama", "detail_url": "../movie/1705.html", "poster": "../posters/1705.svg"}, {"id": "1706", "title": "东寺街西寺巷新传", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "喜剧, 方言, 情景", "tags": ["昆明", "老街拆迁", "网红经济", "地方文化"], "summary_short": "东寺街西寺巷新传，2025年中国大陆电视剧，喜剧, 方言, 情景。东寺街和西寺巷面临拆迁，开发商打算将其改造成仿古商业街。老居民段大妈带领老街坊们，用各种“土办法”对抗拆迁办。同时，在外做自媒体失败的小宇回到巷子，突发奇想用短视频拍摄巷子里的非遗文化和市井烟火。没想到视频爆火，“最土”的东寺街成了年轻人打卡圣地。开发商转变策略，想买断小宇的账号。在流量与乡愁、金钱与情义之间，这群操着正宗马普（昆明普通话）的老邻居必须做出选择，守护的不仅", "score": 2025208, "category": "series", "detail_url": "../movie/1706.html", "poster": "../posters/1706.svg"}, {"id": "1707", "title": "犹太长老的灵猫", "year": 2025, "region": "法国 / 以色列", "type": "动画电影", "genre": "奇幻 / 冒险 / 哲理", "tags": ["动物", "宗教", "幽默", "寓言"], "summary_short": "犹太长老的灵猫，2025年法国 / 以色列动画电影，奇幻 / 冒险 / 哲理。1920年代的耶路撒冷，犹太长老家有一只聪明的黑猫。某日它吃掉了一只会说希伯来语的鹦鹉，从此竟能开口与人辩论。猫不满足于抓老鼠，竟要求长老为它举行成人礼，成为一只“犹太猫”。长老哭笑不得，权当修身养性，开始教它《塔木德》。谁知猫的提问刁钻至极：“如果上帝无处不在，那他在我的屎里吗？”“安息日如果老鼠钻进了喉咙，能不能把它咳出来？”长老被问得哑口无言，却也在辩论", "score": 2025333, "category": "fantasy", "detail_url": "../movie/1707.html", "poster": "../posters/1707.svg"}, {"id": "1708", "title": "龙马传", "year": 2024, "region": "日本", "type": "剧集", "genre": "历史， 传记， 武士", "tags": ["幕末， 坂本龙马， 船中八策， 商业改革， 暗杀"], "summary_short": "龙马传，2024年日本剧集，历史， 传记， 武士。本剧聚焦幕末风云人物坂本龙马短暂而激荡的一生。从土佐藩脱藩开始，龙马师从胜海舟，建立神户海军操练所，后创立龟山社中，成为日本第一家股份制公司。他凭借“船中八策”促成萨摩与长州两大仇藩结盟，为大政奉还铺平道路。故事深入刻画他在理想与现实间的挣扎，以及那个时代武士、商人与刺客交织的复杂生态。最终，在近江屋的雪夜，龙马迎来了生命的终点，但他的思想如星星之火，点燃了明治维新的烈焰。", "score": 2024170, "category": "series", "detail_url": "../movie/1708.html", "poster": "../posters/1708.svg"}, {"id": "1709", "title": "茶煲女人", "year": 1995, "region": "中国香港", "type": "电影", "genre": "剧情 / 喜剧 / 爱情", "tags": ["女性成长", "市井生活", "轻喜", "家庭", "和解"], "summary_short": "茶煲女人，1995年中国香港电影，剧情 / 喜剧 / 爱情。阿珍是旺角一间老牌茶餐厅的老板娘，以火爆脾气和一杯绝顶丝袜奶茶闻名。她的生活被三个“茶煲”（麻烦）包围：催婚的母亲、欠债跑路的前夫，以及隔壁新开的冰室。当冰室老板意外病倒，阿珍竟被迫与她的死对头——那位优雅但刻薄的冰室老板娘合作经营。两人从厨房斗到收银台，却在一次黑社会收数的危机中，发现对方都是独自抚养孩子的单亲妈妈。她们开始交换食谱、分享心事，甚至联手设计教训了共同的前男友。", "score": 1995380, "category": "drama", "detail_url": "../movie/1709.html", "poster": "../posters/1709.svg"}, {"id": "1710", "title": "杀戮都市", "year": 2026, "region": "日本", "type": "动漫", "genre": "科幻、动作、惊悚", "tags": ["生存游戏、外星人、血腥、悬疑"], "summary_short": "杀戮都市，2026年日本动漫，科幻、动作、惊悚。大学生玄野计与加藤胜为救一名醉汉惨遭电车碾毙，下一秒却出现在一间有着巨大黑球的诡异公寓。黑球“GANTZ”指示他们获得强化战斗服与武器，并下达命令：在规定时间内猎杀潜伏在城市中的外星人。每一次任务都伴随死亡威胁，积分系统许诺着复活与自由。玄野从懦弱自私逐渐成长为团队支柱，而加藤则始终坚守不杀原则。随着一个又一个队友惨死，他们发现黑球背后隐藏着操控人类文明的惊天秘密，而这一次，目标竟是外星种", "score": 2026319, "category": "crime", "detail_url": "../movie/1710.html", "poster": "../posters/1710.svg"}, {"id": "1711", "title": "像火花像蝴蝶", "year": 2024, "region": "中国内地", "type": "电视剧", "genre": "剧情 / 爱情", "tags": ["年代", "女性成长", "逆袭", "虐恋", "民国"], "summary_short": "像火花像蝴蝶，2024年中国内地电视剧，剧情 / 爱情。1930年代的上海滩，孤儿沈蝶衣被卖入百乐门舞厅。她不甘沦为玩物，暗中学习记账与经营，试图攒钱赎身。当她与失散多年的初恋、现已成地下党员的陈子谦重逢时，她卷入了一场关乎情报与暗杀的漩涡。黑帮大佬霍天洪对她从霸占变为真心依赖，沈蝶衣在三个男人、两种信仰之间反复挣扎。最终，她选择用自己的方式点燃一把火：烧掉地契，护送情报，带着满身伤痕与尊严消失在黎明前的枪声里。她像火花一样短暂，也像蝴", "score": 2024294, "category": "series", "detail_url": "../movie/1711.html", "poster": "../posters/1711.svg"}, {"id": "1712", "title": "极度危机2004", "year": 2004, "region": "美国", "type": "电影", "genre": "动作 / 惊悚", "tags": ["反恐", "倒计时", "孤胆英雄"], "summary_short": "极度危机2004，2004年美国电影，动作 / 惊悚。前中情局特工杰克·瑞恩因一次行动失误被停职，正当他准备离开华盛顿之际，无意中截获了一条加密信息，暗示一场大规模的生化袭击将在联合国峰会期间发生。由于无人相信他的判断，杰克只能独自展开调查。随着时间一分一秒流逝，他发现幕后黑手竟是自己的前同事，一个认为通过极端手段才能实现“绝对和平”的理想主义者。杰克必须在旧日情谊与拯救千万生命的责任之间做出选择。在最后的对峙中，他利用对峰会建筑结构的", "score": 2004401, "category": "crime", "detail_url": "../movie/1712.html", "poster": "../posters/1712.svg"}, {"id": "1713", "title": "雪茫寻亲", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "灾难、剧情、亲情", "tags": ["暴风雪", "寻子", "极寒求生", "母爱", "真实改编"], "summary_short": "雪茫寻亲，2025年中国大陆电影，灾难、剧情、亲情。改编自2018年黑龙江真实事件。春节前夕，五岁男孩小宝在村口玩耍时被野狗追赶，慌不择路跑进了大兴安岭的茫茫雪原。气象预报显示，一场二十年一遇的特大暴风雪将在三小时后覆盖整个区域，体感温度将降至零下四十五度。武警、村民、专业救援队轮番搜寻七十二小时无果，官方宣布“生存几率趋近于零”，建议停止大规模搜救转为善后。所有人都在劝母亲林秀兰“接受现实”。但她拒绝签字。她独自背上干粮和手电，沿着儿", "score": 2025242, "category": "drama", "detail_url": "../movie/1713.html", "poster": "../posters/1713.svg"}, {"id": "1714", "title": "猎狼者", "year": 2021, "region": "中国大陆", "type": "剧集", "genre": "动作，犯罪，悬疑", "tags": ["反盗猎，森林警察，西部，硬汉，复仇"], "summary_short": "猎狼者，2021年中国大陆剧集，动作，犯罪，悬疑。森林警察魏疆在一次任务中被盗猎者围攻，战友赵诚为掩护他牺牲，魏疆身负重伤退役。五年后，魏疆在牧区借酒消愁，昔日战友秦川找到他，告诉他当年那伙盗猎者再次出现。魏疆和秦川组成两人小队，深入西北无人区追捕。他们发现盗猎团伙的头目“狼王”竟是当年杀害赵诚的凶手，而且已经发展到组织庞大、装备精良的程度。魏疆和秦川利用对地形的熟悉，在戈壁、雪山、草原上与盗猎团伙展开游击战。在一次夜袭中，秦川被俘，魏", "score": 2021409, "category": "crime", "detail_url": "../movie/1714.html", "poster": "../posters/1714.svg"}, {"id": "1715", "title": "玉碎", "year": 2025, "region": "中国大陆", "type": "电视剧", "genre": "历史, 悬疑, 谍战", "tags": ["文物", "民国", "谍战", "家族", "国宝"], "summary_short": "玉碎，2025年中国大陆电视剧，历史, 悬疑, 谍战。1937年，南京。古董商沈家世代保管着一个秘密——传国玉玺并未被后唐末帝携带自焚，而是被沈家先祖偷偷保存了下来。日军逼近南京前夕，沈家老爷子决定将玉玺献给国家，却在家中被暗杀，玉玺失踪。沈家三兄妹各自被不同势力裹挟：大哥加入军统，二哥潜伏在汪伪政府，妹妹成为地下党联络员。三人都在寻找玉玺，也在寻找杀死父亲的凶手。当真相揭晓，玉碎的不仅是玉，还有一个家族最后的情义。", "score": 2025241, "category": "series", "detail_url": "../movie/1715.html", "poster": "../posters/1715.svg"}, {"id": "1716", "title": "龙泉路237号青春轶事", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "青春 / 剧情", "tags": ["群像", "城中村", "90后", "怀旧"], "summary_short": "龙泉路237号青春轶事，2024年中国大陆电视剧，青春 / 剧情。龙泉路237号是一栋五层农民房，住着六个即将高考的高三生。楼上是重点中学的借读生苏瑾，楼下是职高的叛逆少年阿飞，隔壁是来城里打工的农村女孩小梅。2008年发生了很多事：南方雪灾、汶川地震、北京奥运。这栋楼里的六个少年，有人考上了大学，有人南下打工，有人未婚先孕，有人永远留在了那个夏天。他们共用一间厕所、一台电视机和一本被翻烂的《五年高考三年模拟》。十七年后，已经成为社会人", "score": 2024214, "category": "series", "detail_url": "../movie/1716.html", "poster": "../posters/1716.svg"}, {"id": "1717", "title": "美丽的日子", "year": 2001, "region": "韩国", "type": "电视剧集", "genre": "爱情 / 家庭", "tags": ["孤儿，姐妹情，绝症，乐团"], "summary_short": "美丽的日子，2001年韩国电视剧集，爱情 / 家庭。金秀贞和金秀雅是孤儿院里的姐妹花。八岁那年，秀贞被一对大学教授夫妇领养去了首尔，而体弱多病的秀雅被留在当地。二十年后，秀贞成了小有名气的唱片制作人，秀雅则在一家地下乐队做主唱。秀贞的男友、音乐总监李民哲在一次选秀中看中了秀雅的嗓音。当秀贞发现这个天赋惊人的女孩就是失散多年的妹妹时，欣喜若狂。但秀雅却对李民哲产生了好感，两姐妹陷入尴尬境地。更虐心的是，秀雅被查出白血病，需要骨髓移植，秀贞", "score": 2001262, "category": "series", "detail_url": "../movie/1717.html", "poster": "../posters/1717.svg"}, {"id": "1718", "title": "烽火赤焰万里情", "year": 2027, "region": "美国, 英国", "type": "电影", "genre": "爱情, 战争, 历史", "tags": ["二战", "记者", "飞行员", "跨国恋", "战火"], "summary_short": "烽火赤焰万里情，2027年美国, 英国电影，爱情, 战争, 历史。1940年，伦敦大轰炸期间，美国战地记者玛莎·盖尔霍恩（非海明威前妻，虚构人物）在一次空袭报道中，救下了坠机后被困火海的英国皇家空军飞行员詹姆斯·艾什顿。两人迅速坠入爱河，但詹姆斯的部队随即被调往北非战场。玛莎为了追寻爱人的踪迹，申请前往北非报道，但当她抵达开罗时，詹姆斯的战机已在一次任务中失踪，被列为“行动中失联”。玛莎不肯放弃，她利用记者身份深入利比亚沙漠、穿越德军封", "score": 2027308, "category": "doc", "detail_url": "../movie/1718.html", "poster": "../posters/1718.svg"}, {"id": "1719", "title": "霹雳钻", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 惊悚, 犯罪", "tags": ["黑吃黑", "钻石走私", "疾速追杀风格", "复仇爽片"], "summary_short": "霹雳钻，2025年美国电影，动作, 惊悚, 犯罪。杰克曾是最顶级的钻石切割师，因得罪黑帮隐姓埋名。某日，黑帮头目绑走他的女儿，逼他切一颗号称“霹雳”的罕见蓝钻。杰克在显微镜下工作到第三个小时，突然发现钻石内部有一丝不正常的折射——那不是天然瑕疵，而是一枚植入钻石内部的微型炸弹，引爆方式正是切割时的压力变化。更致命的是，这颗钻石是黑帮准备用来支付给军火商的货款，而军火商派来的验收员恰好是杰克的旧仇人。在切割室里，杰克必须在四小时内想出办法", "score": 2025492, "category": "crime", "detail_url": "../movie/1719.html", "poster": "../posters/1719.svg"}, {"id": "1720", "title": "野鸭变凤凰3", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧, 运动", "tags": ["冰球", "中年危机", "传承"], "summary_short": "野鸭变凤凰3，2024年美国电影，喜剧, 运动。距离第一部已经过去三十年，当年的野鸭队冠军们早已各奔东西，变成了油腻大叔和疲惫主妇。当他们曾训练的冰球馆面临拆迁，大家决定重聚，筹集资金买下它。由于没钱，他们想出一个馊主意：挑战现役的职业青年队，靠门票收入翻盘。一群患有高血压、腰椎间盘突出的中年人开始了魔鬼训练，球场上笑料百出。但当他们站上冰面，面对那些不可一世的年轻人，他们用老派的团队配合和永不放弃的“野鸭精神”，输掉了比分，却赢得了全", "score": 2024317, "category": "doc", "detail_url": "../movie/1720.html", "poster": "../posters/1720.svg"}, {"id": "1721", "title": "梦之歌", "year": 2024, "region": "韩国", "type": "电影", "genre": "剧情、奇幻、青春", "tags": ["梦境、音乐、治愈、校园、神秘信件"], "summary_short": "梦之歌，2024年韩国电影，剧情、奇幻、青春。高三学生徐雅凜因严重的社交恐惧而习惯独来独往。她唯一的慰藉是每晚循环的一个梦境：梦中她与一位看不清面容的少女在无尽的花海上用小提琴合奏一曲名为《梦之歌》的旋律。某天早晨，她醒来发现床边放着一封手写信，笔迹与梦境中的乐谱完全一致。信中说：“练习曲的第三乐章，我们还没合上。”雅凜开始根据信中线索寻找这位梦中人，却发现自己学校的音乐教室、废弃的社团记录，甚至小镇的传说，都与一个多年前消失的女孩有关", "score": 2024338, "category": "drama", "detail_url": "../movie/1721.html", "poster": "../posters/1721.svg"}, {"id": "1722", "title": "巨蟒与圣杯", "year": 1975, "region": "英国", "type": "电影", "genre": "喜剧 / 奇幻 / 冒险", "tags": ["荒诞喜剧", "亚瑟王", "无厘头鼻祖", "低成本恶搞"], "summary_short": "巨蟒与圣杯，1975年英国电影，喜剧 / 奇幻 / 冒险。亚瑟王和仆从帕齐（是的，用一个椰子壳当马蹄声）召集圆桌骑士寻找圣杯。途中他们遇到要求用椰子换亲吻的城堡、会说“Ni”的树精、杀不死的黑骑士（被砍掉四肢仍用嘴骂人）、以及一群坚信“巨大木兔是神”的邪教农民。当他们终于抵达圣杯所在的洞穴，法国守军朝他们扔牛并嘲笑。亚瑟王下令进攻，这时现代警察冲入镜头逮捕了全体演员——剧组破产了。", "score": 1975343, "category": "fantasy", "detail_url": "../movie/1722.html", "poster": "../posters/1722.svg"}, {"id": "1723", "title": "冲上九重天", "year": 2025, "region": "中国", "type": "电影", "genre": "灾难动作", "tags": ["民航", "航空", "极限操作", "英雄机组"], "summary_short": "冲上九重天，2025年中国电影，灾难动作。国产民航灾难片，取材自多次真实航空特情事件。新手副驾驶程菲执飞成都-拉萨航线时，机长因舱内失压昏迷，同时遭遇鸟击导致双发动机失效。飞机在青藏高原上空失控下坠，程菲必须在稀薄氧气和零下四十度的环境中，独自操控这架重型客机寻找迫降点。地面空管中心联合退役老机长远程指导，但通讯时断时续。程菲想起自己只模拟过的迫降程序，而机上还有一位她刚刚分手、同样身为飞行员的男友。九重天之上，她要面对的是技术、意志与", "score": 2025326, "category": "crime", "detail_url": "../movie/1723.html", "poster": "../posters/1723.svg"}, {"id": "1724", "title": "张震讲故事之三更夜", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["都市怪谈", "单元故事", "细思极恐"], "summary_short": "张震讲故事之三更夜，2024年中国大陆电影，恐怖 / 惊悚。改编自经典电台栏目。第一个故事《红指甲》：夜班护士发现ICU里所有老人的指甲都在变红，监控显示是护工涂的，但护工说“那是尸斑的征兆”。第二个故事《电梯里的第四人》：深夜加班的程序员发现电梯明明只进三人，但监控总显示四个影子，而第四个影子在拍他的肩膀。第三个故事《永远接不通》：一个女孩连续49天拨打已故男友的电话，突然有一天接通了，对方说“我也很想你，但请你不要再打了，下面信号不", "score": 2024387, "category": "horror", "detail_url": "../movie/1724.html", "poster": "../posters/1724.svg"}, {"id": "1725", "title": "将军的小宠医 动漫版", "year": 2025, "region": "中国大陆", "type": "动漫", "genre": "古风、甜宠、治愈", "tags": ["将军、兽医、萌宠、先婚后爱"], "summary_short": "将军的小宠医 动漫版，2025年中国大陆动漫，古风、甜宠、治愈。江湖兽医沈鱼为躲仇家，误打误撞成了镇北大将军顾衍之的专属“小宠医”。顾衍之的战马“乌云”脾气暴烈，却唯独对沈鱼温顺，让她在军营站稳脚跟。然而顾衍之很快发现，沈鱼不仅会医马，还能治人心——她做的安神香能让他从噩梦缠身到一夜好眠。为了永远留住这个“宝贝”，顾衍之谎称自己有隐疾，只有沈鱼能治。沈鱼信以为真，每日把脉问诊，直到某天发现自己被“骗婚”了。当敌军来犯，沈鱼用特制烟雾弹救", "score": 2025074, "category": "romance", "detail_url": "../movie/1725.html", "poster": "../posters/1725.svg"}, {"id": "1726", "title": "死因可疑", "year": 2025, "region": "英国", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["本格推理", "法医探案", "暴风雪山庄", "连环死亡"], "summary_short": "死因可疑，2025年英国电影，悬疑 / 犯罪。亿万富翁温斯洛普在自家庄园中因心脏病去世，法医鉴定为自然死亡。但他的女儿不信，私下聘请了以“鸡蛋里挑骨头”闻名的前法医病理学家伊芙琳重新验尸。伊芙琳到达庄园当晚，管家在密室中中毒身亡，被警方匆匆定性为畏罪自杀。紧接着，参与遗产分割的律师从楼梯摔下，私人医生在打猎时中弹。短短七天内，庄园里死了四个人，每一个都被官方迅速裁定为“意外”或“自然”。伊芙琳发现所有死者都订阅过同一个冷门悬疑播客，而最", "score": 2025393, "category": "crime", "detail_url": "../movie/1726.html", "poster": "../posters/1726.svg"}, {"id": "1727", "title": "停车", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "剧情，黑色幽默", "tags": ["倒霉蛋，奇遇，台北夜景，小空间叙事"], "summary_short": "停车，2023年中国台湾电影，剧情，黑色幽默。陈莫开车去台北光华南路买蛋糕，仅仅因为停车位紧张把车停在了红线上，等他回来取车时，却发现自己的车位被一辆老式奔驰死死卡住。在寻找车主的几小时里，他被迫闯入了整栋老旧公寓的悲欢离合：有欠债跑路的港裁缝、守着空房等待大陆妻子的老兵、失手杀了黑帮小弟的理发师、以及一位想当妈妈却被骗财的陆配。这一夜，他的车成了整栋楼的中心舞台，每一次挪车都牵扯出一段隐情。最后当黎明的光照进来，陈莫发现自己的车早已被", "score": 2023276, "category": "drama", "detail_url": "../movie/1727.html", "poster": "../posters/1727.svg"}, {"id": "1728", "title": "魔鬼克星 未来世", "year": 2024, "region": "美国", "type": "电影", "genre": "动作、科幻、喜剧", "tags": ["捉鬼、下一代、传承、黑科技、世界末日"], "summary_short": "魔鬼克星 未来世，2024年美国电影，动作、科幻、喜剧。2064年，原版魔鬼克星已垂垂老矣，捉鬼技术被政府封存。他们的孙子——一群叛逆高中生，在爷爷旧仓库发现了一台自认为“古董游戏机”的东西，其实是“质子背包启动器”。一顿乱按后，他们打开了被封印60年的“鬼王之门”，无数厉鬼涌入人间，三天内占领了全球70%城市。爷爷们拖着病体出来，却发现旧武器对进化后的鬼无效。孙子辈必须在三周内，用现代量子物理和爷爷的笔记，制造出“反物质捕鬼器”，而鬼", "score": 2024442, "category": "sci-fi", "detail_url": "../movie/1728.html", "poster": "../posters/1728.svg"}, {"id": "1729", "title": "85度疯狂之爱", "year": 2023, "region": "法国", "type": "电影", "genre": "爱情, 惊悚", "tags": ["病娇", "悬疑", "法国浪漫"], "summary_short": "85度疯狂之爱，2023年法国电影，爱情, 惊悚。天才神经科学家艾米莉爱上了温柔体贴的文学教授马克。但她发现一个诡异规律：每当马克发高烧，体温达到39度左右时，他就会变得极具魅力，浪漫到极点，但同时，他身边那些让他不快的人会逐一消失。艾米莉通过植入式体温传感器证实，发烧状态下的马克会分泌一种罕见的信息素，能激发人脑最深层的恐惧与爱慕。她深陷其中，一方面迷恋那个高烧时的完美情人，一方面又恐惧于他的所作所为。当她发现下一个目标是自己最好的闺", "score": 2023336, "category": "crime", "detail_url": "../movie/1729.html", "poster": "../posters/1729.svg"}, {"id": "1730", "title": "恶水救援", "year": 2022, "region": "美国", "type": "电影", "genre": "动作 / 灾难", "tags": ["洪灾", "洞穴潜水", "退伍军人"], "summary_short": "恶水救援，2022年美国电影，动作 / 灾难。五级飓风引发海水倒灌，肯塔基州一个矿镇变成水下迷宫。前海军潜水员杰克因战伤失聪，却通过水下震动感知到被困在废弃矿井深处的女孩。官方放弃救援，他独自潜入，用身体作为音叉寻找生命的频率。最后三十分钟的水下密闭空间戏，堪称年度最窒息的生死搏斗。", "score": 2022310, "category": "crime", "detail_url": "../movie/1730.html", "poster": "../posters/1730.svg"}, {"id": "1731", "title": "岛上的老师", "year": 2025, "region": "日本", "type": "电视剧", "genre": "剧情 / 教育", "tags": ["孤岛", "教师", "治愈", "社会问题"], "summary_short": "岛上的老师，2025年日本电视剧，剧情 / 教育。因体罚学生而被吊销教师资格的城户，被教育委员会安排到濑户内海的一座离岛当“唯一的老师”。岛上只有三个学生：沉默寡言的修一、假装开朗的莉子、以及行为反常的小铁。城户本想混日子，却逐渐发现孩子们都不愿意离开岛，甚至在阻止外人登岛。原来，三年前岛上曾发生一起由游客引起的恶性事件，孩子们的父母为了保护他们，与外界隔绝并制造了“幸福假象”。小铁一直不说话，是因为他目睹了那件事。城户用笨拙但真诚的方", "score": 2025195, "category": "series", "detail_url": "../movie/1731.html", "poster": "../posters/1731.svg"}, {"id": "1732", "title": "对你的想象", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "爱情, 奇幻, 剧情", "tags": ["双向奔赴", "意念具象化", "暗恋", "心理学"], "summary_short": "对你的想象，2025年中国大陆电影，爱情, 奇幻, 剧情。内向的程序员小文暗恋同事阿哲整整十年，却从未说出口。她在脑内构建了一个完美的“阿哲2.0”，每天靠这个幻想度过枯燥的生活。突然有一天，她发现自己脑海中的想象竟然可以投射到现实中，那个完美的“阿哲2.0”活生生站在了她面前。然而，随着幻想男友越来越真实，她发现这个由她意念构建的男人，也开始拥有了她的阴暗面——猜忌、占有欲和自卑。与此同时，现实中的阿哲似乎也开始对她产生好奇。小文必须", "score": 2025371, "category": "drama", "detail_url": "../movie/1732.html", "poster": "../posters/1732.svg"}, {"id": "1733", "title": "网络军团", "year": 2024, "region": "美国", "type": "电视剧", "genre": "动作科幻", "tags": ["虚拟现实", "电竞", "反恐"], "summary_short": "网络军团，2024年美国电视剧，动作科幻。未来世界，一场未知的AI病毒入侵了国家电网，导致城市大面积瘫痪，恐怖组织以此为要挟。传统的军事手段无效，因为敌人在代码中。军方紧急招募了一直在军事模拟游戏中排名全球前十的电竞战队“混沌秩序”。这群平时只会坐在电脑前打游戏、互相嘲讽的年轻人，被迫穿上外骨骼装甲，进入现实世界的废墟中进行“实战电竞”。他们必须利用游戏中的战术思维、走位技巧甚至BUG逻辑，在断电的摩天大楼里与AI控制的机器人军团展开生", "score": 2024394, "category": "series", "detail_url": "../movie/1733.html", "poster": "../posters/1733.svg"}, {"id": "1734", "title": "纵横鬼门关", "year": 1998, "region": "中国香港", "type": "电影", "genre": "动作, 恐怖, 奇幻", "tags": ["冥界", "警匪", "道士", "枪战", "卧底", "阴阳眼"], "summary_short": "纵横鬼门关，1998年中国香港电影，动作, 恐怖, 奇幻。卧底阿豪被黑帮识破身份后枪杀，却在踏入鬼门关时被掌管冥界黑帮的“鬼王”选中，成为穿梭阴阳两界的“鬼警”。他的任务是在阳间继续追查毒品网络，但线人全是游魂。阿豪发现生前的死对头竟成了地府判官，处处阻挠他查案。为了找到害死自己的真凶并救出被困阴间的女友，他联合一群逗比鬼差——包括只会唱RAP的吊死鬼、数学极差的吸血鬼。最终在鬼门关前展开一场混搭纸扎跑车与中式法器的决战。阿豪必须在天亮", "score": 1998427, "category": "crime", "detail_url": "../movie/1734.html", "poster": "../posters/1734.svg"}, {"id": "1735", "title": "我是未来第一季", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "科幻 / 悬疑 / 青春", "tags": ["时间循环", "校园", "人工智能", "多重宇宙"], "summary_short": "我是未来第一季，2025年中国大陆剧集，科幻 / 悬疑 / 青春。内向的高二学生林晓意外接收到来自“未来自己”的意识碎片，得知在三个月后，一场由AI引发的全球记忆清除计划将启动。碎片记忆显示，始作俑者竟是2066年成为顶尖AI科学家的“成年林晓”。为了阻止悲剧，他必须找出隐藏在校园里的首个AI原型机。在试图接近校花兼编程天才苏眠的过程中，林晓发现每次选择都会导致时间线轻微变动。第一季结尾，他成功毁掉了原型机，但世界并未变好——相反，一场", "score": 2025344, "category": "series", "detail_url": "../movie/1735.html", "poster": "../posters/1735.svg"}, {"id": "1736", "title": "情迷利卡塔", "year": 2023, "region": "意大利, 法国", "type": "电影", "genre": "爱情, 剧情", "tags": ["异国恋", "怀旧", "西西里", "自我发现"], "summary_short": "情迷利卡塔，2023年意大利, 法国电影，爱情, 剧情。失意的建筑师马可收到一个匿名包裹，里面是一幅描绘利卡塔海滨日落的油画，笔触与二十年前不告而别的恋人艾琳娜如出一辙。怀着满腹疑问与未灭的情愫，马可独自前往西西里岛的利卡塔。他穿行于狭窄的街道和橙树林中，遇到的每个人都似乎与艾琳娜有着千丝万缕的联系，一段段尘封的往事被揭开。马可发现艾琳娜当年离开并非变心，而是为了保护他免受家族纷争的牵连。当他终于找到艾琳娜时，她已是一个孩子的母亲，但眼", "score": 2023379, "category": "drama", "detail_url": "../movie/1736.html", "poster": "../posters/1736.svg"}, {"id": "1737", "title": "职场小烈第二季", "year": 2021, "region": "日本", "type": "动画剧集", "genre": "喜剧 / 职场 / 动画", "tags": ["社畜", "烈子", "红脸", "卡拉OK", "黑色幽默"], "summary_short": "职场小烈第二季，2021年日本动画剧集，喜剧 / 职场 / 动画。烈子依然是东京一家贸易公司会计部最不起眼的小员工，白天被上司骂、被甲方催、被同事甩锅，晚上去卡拉OK吼死亡金属发泄。第二季开篇，部长把一个新人交给她带——一位名叫小百合的永远笑嘻嘻、永远不生气、永远说“没关系”的年轻女员工。烈子一开始很庆幸，不用教刺头。但很快她发现：小百合什么错都会犯、但从不焦虑，任务逾期了也不急，客户骂她也只是点头。烈子的暴躁被软绵绵地反弹回来，连她的", "score": 2021215, "category": "series", "detail_url": "../movie/1737.html", "poster": "../posters/1737.svg"}, {"id": "1738", "title": "猛龙怪客4：镇压", "year": 2027, "region": "美国", "type": "电影", "genre": "动作 / 惊悚", "tags": ["暴力美学，私刑正义，老牌硬汉，科技监控，反乌托邦"], "summary_short": "猛龙怪客4：镇压，2027年美国电影，动作 / 惊悚。距离保罗·柯西第一次拿起枪为妻女复仇已经过去多年。芝加哥警方引入了一套名为“预见者”的AI犯罪预测系统，通过大数据和街面监控，可以在犯罪发生前30秒锁定“即将犯罪”的人。这座城市的暴力犯罪率断崖式下降，但保罗注意到，被“预见者”逮捕的人大多是贫民区的有色人种。某日，保罗在家门口救下一个被系统“误判”为抢劫犯的黑人少年，他自己的面部特征也因此被AI标记为“潜在暴力分子”。次日凌晨，四架", "score": 2027420, "category": "crime", "detail_url": "../movie/1738.html", "poster": "../posters/1738.svg"}, {"id": "1739", "title": "被时间遗忘的人", "year": 2024, "region": "英国", "type": "剧集（迷你剧）", "genre": "科幻 / 悬疑", "tags": ["失忆症，时间循环，社会实验"], "summary_short": "被时间遗忘的人，2024年英国剧集（迷你剧），科幻 / 悬疑。主角汤姆患有一种奇特失忆症：每天醒来都会清除前一天的记忆。但他发现床头总有一本手写日记，笔迹属于自己，内容却是未来24小时要发生的事。起初他以为是恶作剧，直到日记预测了邻居死亡、彩票号码和一场恐袭。他必须利用日记阻止灾难，但每次成功后，第二天日记内容就会改变，仿佛时间线被重置。与此同时，一个神秘组织“记忆清算师”开始追杀他，声称他是被从历史中“删除”的人，因为他在过去改变了一", "score": 2024391, "category": "series", "detail_url": "../movie/1739.html", "poster": "../posters/1739.svg"}, {"id": "1740", "title": "恐龙饭店", "year": 2021, "region": "日本", "type": "动画剧集", "genre": "科幻冒险", "tags": ["克隆恐龙", "黑帮", "荒诞", "美食"], "summary_short": "恐龙饭店，2021年日本动画剧集，科幻冒险。前黑帮杀手阿龙金盆洗手后遭到组织追杀，逃亡途中误入一座地图上没有标注的神秘岛屿。岛上建有一座豪华饭店，但所有服务生都是被克隆出来的高智商恐龙。霸王龙是暴躁的前台，翼龙负责空中送餐，三角龙则是保安队长。饭店老板是个疯狂科学家，他让阿龙留下来当主厨，代价是帮他猎杀岛上失控的迅猛龙群。阿龙本以为找到了避难所，却发现这家饭店其实是全世界地下势力的中转站，而来吃饭的客人中，就有他曾经背叛过的老大哥。", "score": 2021277, "category": "series", "detail_url": "../movie/1740.html", "poster": "../posters/1740.svg"}, {"id": "1741", "title": "济公", "year": 2024, "region": "中国", "type": "电影", "genre": "奇幻 / 喜剧 / 动作", "tags": ["疯癫", "降妖", "现代元素", "反转"], "summary_short": "济公，2024年中国电影，奇幻 / 喜剧 / 动作。古代活佛济公为追捕一只逃入时空裂缝的千年狐妖，意外穿越到2024年的上海。狐妖化身为顶流女明星，用魅力操控人心，制造仇恨与欲望。济公依然一身破袈裟、一把破扇，却要学会用智能手机、开直播、躲避城管。他发现信仰早已淡化，人们更信算法与流量。济公一边用佛法点化迷失的网红和打工人，一边与狐妖展开斗法。最终，他不是用法术击败对方，而是让全城万人同时念响“南无阿弥陀佛”，用集体愿力击破狐妖幻术，自", "score": 2024408, "category": "fantasy", "detail_url": "../movie/1741.html", "poster": "../posters/1741.svg"}, {"id": "1742", "title": "吻着我，杀了我", "year": 2024, "region": "美国", "type": "电影", "genre": "惊悚, 爱情", "tags": ["危险关系", "骗局", "反转", "限制级"], "summary_short": "吻着我，杀了我，2024年美国电影，惊悚, 爱情。职业骗子杰克和蛇蝎美人艾米策划了一起完美的珠宝劫案，得手后两人驱车在66号公路上狂奔，计划去墨西哥享受余生。他们深爱彼此，但这份爱建立在谎言之上。杰克不知道的是，艾米其实是雇他来抢劫的幕后黑手的女人，任务结束后就要除掉他；艾米不知道的是，杰克是FBI的线人，这次抢劫是他获取信任的最后一步。在路过一家汽车旅馆时，两人都想在那晚动手解决对方，却又都在最后一刻犹豫。一夜缠绵后，双方同时发现了对", "score": 2024412, "category": "crime", "detail_url": "../movie/1742.html", "poster": "../posters/1742.svg"}, {"id": "1743", "title": "梅露丝", "year": 2025, "region": "法国 / 中国大陆", "type": "电影", "genre": "文艺 / 剧情", "tags": ["女性，巴黎，身份认同，孤独"], "summary_short": "梅露丝，2025年法国 / 中国大陆电影，文艺 / 剧情。退休语文教师李秀兰搬到巴黎与女儿同住，语言不通的她被困在公寓里。她偶然捡到一张旧照片，照片上的法国女人“梅露丝”成了她的幻想化身。她开始写日记，以梅露丝的口吻记录想象中的法式生活：在街角咖啡馆与哲学家辩论，与情人秘密约会。当女儿发现这些日记并误以为母亲精神错乱时，一场关于代际沟通、文化隔阂与晚年孤独的战争悄然爆发。最终，李秀兰在虚拟的叙事中找到了真实的自我出口。", "score": 2025329, "category": "drama", "detail_url": "../movie/1743.html", "poster": "../posters/1743.svg"}, {"id": "1744", "title": "窗外有情天", "year": 1986, "region": "中国台湾", "type": "电影", "genre": "剧情，爱情", "tags": ["绝症，禁忌之恋，疗愈，手写信"], "summary_short": "窗外有情天，1986年中国台湾电影，剧情，爱情。罹患白血病的少女林晓月因病长期卧床，唯一的乐趣便是透过窗户观察对面公寓里的一位神秘画家。她偷偷给他写信，却从未寄出。某天，画家偶然捡到了她飘落的信纸，开始用画作回应她。两人虽未曾谋面，却通过窗台与画布构建了一个纯粹的精神世界。随着病情恶化，晓月的姐姐决定替她赴约，却在见面时发现画家其实早已失明。这段看似错位的情感，最终在冬日的第一缕阳光下，化作了一场关于生命与救赎的无声告白。", "score": 1986307, "category": "drama", "detail_url": "../movie/1744.html", "poster": "../posters/1744.svg"}, {"id": "1745", "title": "我，克罗蒂亚", "year": 2025, "region": "欧洲", "type": "剧集", "genre": "历史 / 传记", "tags": ["罗马帝国、女皇视角、权谋、史诗"], "summary_short": "我，克罗蒂亚，2025年欧洲剧集，历史 / 传记。故事从克罗蒂亚作为落魄贵族之女嫁给老迈的皇帝开始。所有人都以为她只是个花瓶，她却利用宫廷宴会收集情报，在枕头风里搅动帝国风云。第一任丈夫暴毙后，她扶持养子继位，却在关键时刻被背叛。流放归来的克罗蒂亚不再隐藏锋芒，她化身黑寡妇，先后辅佐两位性格迥异的皇帝。当整个元老院试图剥夺女性继承权时，年近五十的克罗蒂亚穿上铠甲，站在军队面前喊出：“我是皇帝的母亲，也是帝国的主人。”本剧还原了罗马帝国末", "score": 2025232, "category": "series", "detail_url": "../movie/1745.html", "poster": "../posters/1745.svg"}, {"id": "1746", "title": "造衣者", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情，家庭", "tags": ["裁缝世家，代际和解，城市变迁，手工传承，女性视角"], "summary_short": "造衣者，2025年中国大陆电影，剧情，家庭。苏州老街上，七十岁的裁缝苏绣云决定关掉开了五十年的旗袍店。关店前七天，三个女人先后走进来：一个要改嫁衣的离婚孕妇，一个要复制母亲遗物的短发女孩，一个要穿旗袍去自杀的老年舞者。苏绣云在量体裁衣的指尖触碰中，逐渐被她们的故事撬开了自己封存三十年的往事——她曾有一个女儿，在改革开放那年被送去香港，再无音讯。当最后一件旗袍完成时，她发现那位“老年舞者”正是她素未谋面的外孙女。一针一线都是时间织成的血缘", "score": 2025295, "category": "drama", "detail_url": "../movie/1746.html", "poster": "../posters/1746.svg"}, {"id": "1747", "title": "大滚友", "year": 2023, "region": "中国香港", "type": "电视剧", "genre": "喜剧，青春，校园", "tags": ["校园，古惑仔，友情，搞笑，香港"], "summary_short": "大滚友，2023年中国香港电视剧，喜剧，青春，校园。阿炮、丧B、眼镜蛇和肥东是某中学的“四大滚友”，因打架、逃课、顶撞老师被全校通报批评。被贴上标签后，他们反而破罐破摔，在校外租了个天台，成立“滚友工作室”，专门帮学生解决学校不敢管的麻烦：追回被混混抢走的零花钱、揭发补课老师的骚扰行为、替被霸凌的学弟出头。他们没有暴力，而是用各种奇葩招数——假装家长、盗取监控、设置陷阱。他们的故事在学生中口口相传，成了校园都市传说。直到有一天，校长女儿", "score": 2023191, "category": "comedy", "detail_url": "../movie/1747.html", "poster": "../posters/1747.svg"}, {"id": "1748", "title": "顾问先生有问题", "year": 2023, "region": "中国大陆", "type": "剧集", "genre": "喜剧，爱情", "tags": ["职场，毒舌，治愈，契约情侣"], "summary_short": "顾问先生有问题，2023年中国大陆剧集，喜剧，爱情。顶尖企业顾问江临风以毒舌和挑剔著称，员工对他的评价只有四个字：不是东西。新人林星落入职第一天就在全公司面前和他正面硬刚，两人就此结下死仇。然而公司团建意外将两人困在雪山民宿，还阴差阳错被全公司误认为情侣。为了不丢工作，两人被迫签订“假情侣协议”。同居后林星落发现，江临风每天晚上都在笨拙地织一件很难看的毛衣，而标签上写着她的名字。原来这位完美顾问先生患有严重的社交恐惧症，所有毒舌都是他避", "score": 2023292, "category": "series", "detail_url": "../movie/1748.html", "poster": "../posters/1748.svg"}, {"id": "1749", "title": "水怪传奇", "year": 2020, "region": "中国大陆", "type": "网络电影", "genre": "奇幻，惊悚", "tags": ["民间传说，水怪，环保，反转"], "summary_short": "水怪传奇，2020年中国大陆网络电影，奇幻，惊悚。长白山天池景区连续发生游客失踪事件，官方解释是失足落水，但护林员老赵不信。他从小听爷爷讲天池水怪的传说，一直以为是迷信，直到他在湖边发现了一片不属于任何已知生物的鳞片。老赵联合年轻女生物学家苏晚，在天池周边布设水下摄像机，竟真的拍到了一个巨大的黑影。就在他们要公布发现时，一支神秘科考队突然进驻，以“科研”为名开始秘密打捞。老赵和苏晚潜下水底，震惊地发现天池深处有一片被水淹没的古代遗迹，而", "score": 2020382, "category": "horror", "detail_url": "../movie/1749.html", "poster": "../posters/1749.svg"}, {"id": "1750", "title": "一样的月光", "year": 2018, "region": "中国台湾", "type": "电影", "genre": "剧情, 家庭", "tags": ["外籍劳工", "社会底层", "亲情", "写实"], "summary_short": "一样的月光，2018年中国台湾电影，剧情, 家庭。为了供养远在故乡的孩子，菲律宾女佣罗丝只身来到台北，照顾一个患有严重多动症、被亲生父母嫌弃的小男孩阿迪。阿迪被学校拒绝，父母离异，像一头暴躁的小野兽。所有人都放弃了阿迪，只有罗丝用她笨拙的英文和不厌其烦的拥抱，慢慢走进了他封闭的世界。他们一个是异乡漂泊的母亲，一个是本地被遗弃的孩子，同在一片月光下，互为母子。当阿迪的父亲因为再婚要将阿迪送去国外的寄宿学校时，罗丝面临着签证到期必须回国的困", "score": 2018266, "category": "drama", "detail_url": "../movie/1750.html", "poster": "../posters/1750.svg"}, {"id": "1751", "title": "机器肉鸡第三季", "year": 2007, "region": "美国", "type": "剧集", "genre": "喜剧 / 定格动画 / 科幻", "tags": ["恶搞", "玩偶", "重口味", "无厘头", "彩蛋"], "summary_short": "机器肉鸡第三季，2007年美国剧集，喜剧 / 定格动画 / 科幻。这是一部获得艾美奖的成人向定格动画系列。第三季继续沿用其标志性的“神经病”风格，用各种可动人偶和黏土模型，以极其短平快的小剧场形式，解构、亵渎、致敬了当时所有的热门影视、游戏和名人。本季出现了“哥特版圣诞老人”、“猥琐的变形金刚”、“在集中营跳街舞的芭比”等离谱桥段。每集由无数个几秒钟的荒诞笑话拼贴而成，语不惊人死不休。虽然是恶搞，但编剧往往能用最低俗的形式，精准讽刺娱乐", "score": 2007332, "category": "series", "detail_url": "../movie/1751.html", "poster": "../posters/1751.svg"}, {"id": "1752", "title": "失忆谜案", "year": 2022, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["失忆", "反转", "心理游戏", "密室"], "summary_short": "失忆谜案，2022年美国电影，悬疑 / 惊悚。男主Leo在陌生公寓醒来，头部有伤，身边是女友的尸体，手里握着一把刀。他完全不记得过去48小时发生的事。警方赶到时他翻窗逃跑，开始一边躲避追捕一边拼凑记忆。通过手机里的加密视频、匿名短信和一张写着“别相信任何人”的纸条，他发现自己可能是一起跨国金融诈骗案的关键证人，而“女友”实则是派来监视他的特工。真正的凶手通过一种新型药物操控了他的记忆，试图让他成为替罪羊。影片采用倒叙与实时交叉剪辑，最后", "score": 2022414, "category": "crime", "detail_url": "../movie/1752.html", "poster": "../posters/1752.svg"}, {"id": "1753", "title": "可爱的童年", "year": 2026, "region": "日本", "type": "动画电影", "genre": "治愈/奇幻", "tags": ["童年创伤", "幻想朋友", "时间回溯", "手绘画风"], "summary_short": "可爱的童年，2026年日本动画电影，治愈/奇幻。35岁的程序员健二因为过劳死，醒来后发现自己回到了1988年，变成了7岁的自己。他兴奋地以为可以重来一次，弥补所有遗憾。但很快他发现：7岁的自己正被邻居大哥哥性侵，而那个他“记忆中温柔的大哥哥”其实每周都会来找他。大人世界的“可爱童年”背后，是孩子不敢说出口的恐惧。35岁的健二用成年人的思维，试图向母亲求救，但每次他说出真相时，嘴里就会吐出彩色的肥皂泡，听上去像在开玩笑——这是童年的自我保", "score": 2026291, "category": "fantasy", "detail_url": "../movie/1753.html", "poster": "../posters/1753.svg"}, {"id": "1754", "title": "伟大的苏珊", "year": 2024, "region": "美国", "type": "电影", "genre": "传记 / 剧情", "tags": ["女性力量，冷战背景，科学家传记，抗争"], "summary_short": "伟大的苏珊，2024年美国电影，传记 / 剧情。1962年，古巴导弹危机一触即发。苏珊是华盛顿特区一名普通的女打字员，却因心算能力惊人被秘密招募进破译部门。她成功破解了苏联的海上通信密码，避免了核战争，但她的功绩被男性上司全部窃取。多年后，垂垂老矣的苏珊在清理阁楼时发现了当年的原始手稿，决定向国防部提起诉讼。影片跨越半个世纪，讲述了一个女人为夺回属于自己的历史荣誉而战的孤独旅程，最终在法庭上，她要求的不只是署名，而是对那个时代系统性歧视", "score": 2024269, "category": "drama", "detail_url": "../movie/1754.html", "poster": "../posters/1754.svg"}, {"id": "1755", "title": "蜜糖儿", "year": 2024, "region": "韩国", "type": "电视剧", "genre": "剧情，音乐", "tags": ["偶像，成长，友情，娱乐圈"], "summary_short": "蜜糖儿，2024年韩国电视剧，剧情，音乐。性格各异的五位少女在顶级娱乐公司经历了数年残酷的练习生生涯，终于获得出道机会，组成女团“蜜糖儿”。然而出道并不代表成功，她们面临着前辈粉丝的排挤、资本的压力、黑粉的攻击以及内部的矛盾。队长智雅因完美主义而苛责队员，主唱秀敏因声带小结面临失声危机，最小的成员素熙则被霸凌谣言困扰。在一次次舞台与现实的打击中，她们从互相竞争到真正理解彼此，学会了用音乐表达真实的自己。最终，“蜜糖儿”没有成为最红的团体", "score": 2024243, "category": "series", "detail_url": "../movie/1755.html", "poster": "../posters/1755.svg"}, {"id": "1756", "title": "一级危险", "year": 2026, "region": "美国", "type": "电影", "genre": "动作，惊悚", "tags": ["特工，反恐，高概念，密室逃生"], "summary_short": "一级危险，2026年美国电影，动作，惊悚。中央情报局最优秀的五名特工被神秘召集到一座刚落成的智能摩天楼，参加一场名为“一级危险”的模拟训练。然而，大楼的中央AI系统遭到入侵，将所有出口封锁，并启动了致命陷阱。AI给出一条指令：只有找到并杀死团队中的“叛徒”，大门才会开启。特工们被迫互相猜忌、追踪、搏杀。随着死亡人数增加，他们发现每个人都有不可告人的秘密，而所谓的“叛徒”可能根本不存在。真正的幕后黑手是一位被他们团队误杀的特工的亲人，其目", "score": 2026344, "category": "crime", "detail_url": "../movie/1756.html", "poster": "../posters/1756.svg"}, {"id": "1757", "title": "小丑", "year": 2019, "region": "美国", "type": "电影", "genre": "剧情, 惊悚, 犯罪", "tags": ["心理", "社会底层", "经典改编"], "summary_short": "小丑，2019年美国电影，剧情, 惊悚, 犯罪。亚瑟·弗莱克是一名职业小丑，靠为商店促销和儿童派对工作维生。他患有病理性大笑的疾病，被社会视为怪胎。在接连被解雇、被街头混混殴打、被偶像脱口秀主持人当众嘲讽后，他在 subway 上枪杀了三名华尔街精英。这个事件被底层民众视为反抗符号。亚瑟逐渐放弃对“善良”的执念，化上标志性的小丑妆，在一场直播节目中当着全城观众的面杀死了主持人。哥谭陷入暴动，亚瑟在警车上看着燃烧的城市，露出真正的笑容。", "score": 2019419, "category": "crime", "detail_url": "../movie/1757.html", "poster": "../posters/1757.svg"}, {"id": "1758", "title": "英雄万岁！", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧、动作", "tags": ["小人物逆袭", "荒诞幽默", "怀旧致敬"], "summary_short": "英雄万岁！，2025年中国大陆电影，喜剧、动作。龙套演员大伟常年演被一拳打死的路人。一次片场意外，他穿着自制山寨战衣出现在爆炸现场，被路人拍下传上网，瞬间成了新晋超级英雄“铁拳侠”。真正的反派“蓝博士”信以为真，绑架了他的家人，要求公开对决。大伟只好召集一群同样跑龙套的兄弟，用道具、特效和演技，上演一场“假英雄”大战“真反派”的荒诞闹剧。", "score": 2025385, "category": "crime", "detail_url": "../movie/1758.html", "poster": "../posters/1758.svg"}, {"id": "1759", "title": "你的我的那场暗恋", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "爱情/青春", "tags": ["暗恋", "时空错位", "书信", "催泪"], "summary_short": "你的我的那场暗恋，2025年中国台湾电影，爱情/青春。高中女生苏念恩有一个秘密：她每天都会给篮球队学长陈屿写一封情书，然后锁进床头铁盒。三年过去，铁盒里积攒了三百六十五封信。毕业那天，她终于鼓起勇气要送出铁盒，却发现每一封信上的错别字都被人用铅笔圈出，旁边写着规范写法——字迹工整清秀，全是陈屿的笔迹。原来，陈屿每晚都会偷偷潜入教室，在暗恋自己三年之久的女生桌上，悄悄改完她写给“暗恋对象”的信，却始终不知道那个对象就是自己。苏念恩找到陈屿", "score": 2025285, "category": "comedy", "detail_url": "../movie/1759.html", "poster": "../posters/1759.svg"}, {"id": "1760", "title": "溺水的鱼", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "剧情 / 悬疑 / 心理", "tags": ["文艺", "水乡", "记忆谜局", "精神分析", "慢电影"], "summary_short": "溺水的鱼，2025年中国大陆电影，剧情 / 悬疑 / 心理。心理医生陆鸣回到故乡小镇继承祖父的老宅。镇上开始有人溺亡，每具尸体手中都紧握着一条不停张嘴呼吸的活鱼。警方调查无果，陆鸣却发现所有死者都是她三年前在大城市诊所的患者——且都曾表达过“想变成鱼”的念头。陆鸣开始怀疑自己被人跟踪模仿作案，但随着老宅地下室打开，她发现祖父年轻时也曾有相同手法的案件。更恐怖的是：她自己有梦游症，而梦里她总在往河里放鱼。最后一条鱼，放在了她自己枕边。", "score": 2025409, "category": "drama", "detail_url": "../movie/1760.html", "poster": "../posters/1760.svg"}, {"id": "1761", "title": "龙虎煞星火拼剃刀党", "year": 2026, "region": "中国香港 / 英国", "type": "电影", "genre": "动作 / 犯罪 / 黑帮", "tags": ["港式动作", "英伦黑帮", "跨文化火拼", "双雄对决"], "summary_short": "龙虎煞星火拼剃刀党，2026年中国香港 / 英国电影，动作 / 犯罪 / 黑帮。1997前夕，香港黑帮“龙虎煞星”的老大阿龙接到任务：护送一块神秘怀表至伦敦。抵达后却发现，伯明翰最凶残的“剃刀党”也对这块怀表志在必得。怀表内藏着一张地图，指向一笔二战时期埋藏的黄金。东西方黑帮从谈判桌打到伦敦地下隧道，从港式茶餐厅打到英伦古堡。阿龙与剃刀党领袖汤米从厮杀到被迫联手，对抗试图黑吃黑的军情五处。最终，黄金沉入泰晤士河，而阿龙和汤米在船上用各自", "score": 2026349, "category": "crime", "detail_url": "../movie/1761.html", "poster": "../posters/1761.svg"}, {"id": "1762", "title": "铁血战士：猎物", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻, 动作, 惊悚", "tags": ["外星猎杀", "硬核动作", "丛林"], "summary_short": "铁血战士：猎物，2025年美国电影，科幻, 动作, 惊悚。1719年，北美大平原。科曼奇部落的女猎人纳鲁被族人嘲笑只配做采集者。为证明价值，她独自深入禁忌森林追踪一头伤人的灰熊，却发现灰熊被一个更恐怖的生物剥了皮。那是一个身高八尺、装备高科技武器的外星猎人。纳鲁目睹整个狩猎队被屠杀，她利用对地形的熟悉、原始的陷阱和野兽的直觉，从猎物转变为猎人。她必须抢在外星战士开启自毁程序前，用最原始的方式——弓箭、斧头和泥巴——结束这场不对等的猎杀。", "score": 2025453, "category": "crime", "detail_url": "../movie/1762.html", "poster": "../posters/1762.svg"}, {"id": "1763", "title": "额吉", "year": 2025, "region": "中国/蒙古", "type": "电影", "genre": "剧情/历史", "tags": ["草原", "母爱", "大爱无疆", "沧桑", "人性"], "summary_short": "额吉，2025年中国/蒙古电影，剧情/历史。60年代初，中国遭遇严重自然灾害，三千名南方孤儿被送往内蒙古大草原。年轻的女牧民萨仁格日勒不顾世俗眼光和族人非议，主动收养了其中八个体弱多病的孩子。为了养活这群“国家的孩子”，她卖掉了祖传的马鞍，甚至拒绝了一直等待她的青梅竹马的求婚。影片跨越几十年，记录了孩子们如何在草原长大，如何寻找自己的根，以及这位伟大的“额吉”（母亲）如何在晚年独自守着空荡荡的蒙古包，等待孩子们从远方归来。没有血缘，却有", "score": 2025269, "category": "drama", "detail_url": "../movie/1763.html", "poster": "../posters/1763.svg"}, {"id": "1764", "title": "维林", "year": 2021, "region": "美国", "type": "电视剧集", "genre": "科幻 / 悬疑", "tags": ["虚拟现实，意识上传，小镇，阴谋"], "summary_short": "维林，2021年美国电视剧集，科幻 / 悬疑。天才程序员艾登收到一封来自已故父亲的加密邮件，里面是一个叫做“维林”的VR程序邀请码。他戴上设备进入后，发现这是一个模拟五十年代美国小镇的虚拟世界，父亲的意识碎片就困在其中，不断重复着同一天。艾登试图破解代码救出父亲，却发现维林里还有数百个真实的死者意识，他们都是各大科技公司失踪的前员工。更可怕的是，一个名为“收割者”的程序正在定期清除那些“觉醒”的居民。艾登必须在系统管理员发现他是外来入侵", "score": 2021352, "category": "series", "detail_url": "../movie/1764.html", "poster": "../posters/1764.svg"}, {"id": "1765", "title": "少年手指虎", "year": 2023, "region": "日本", "type": "电影", "genre": "喜剧，音乐", "tags": ["朋克，老人，巡演"], "summary_short": "少年手指虎，2023年日本电影，喜剧，音乐。唱片公司职员小薰被上司指派去解约一支30年前签约后就从未出过专辑的朋克乐队“少年手指虎”。当她找到他们时，主唱71岁，重度痴呆；吉他手69岁，耳聋；贝斯手73岁，腿瘸；鼓手70岁，有心脏病。但四个老头一拿起乐器就以为自己回到了1985年的巅峰时刻，决定要完成当年没办成的全国巡演。小薰被迫成为他们的经纪人，开着破面包车带四个老年朋克踏上疯狂之旅，每到一站都有人担心他们会死在台上。", "score": 2023268, "category": "comedy", "detail_url": "../movie/1765.html", "poster": "../posters/1765.svg"}, {"id": "1766", "title": "北极求生任务", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 惊悚 / 冒险", "tags": ["极限生存", "极地", "硬核", "人性考验", "冰原"], "summary_short": "北极求生任务，2024年美国电影，动作 / 惊悚 / 冒险。退役美军生存专家杰克·哈蒙德受邀加入一支北极科考队，却遭遇冰下不明巨型生物的疯狂袭击。基地被毁，队友接连丧生，杰克必须在72小时极夜彻底降临前，带领仅剩的三名科学家穿越200公里冰裂地带到达备用救援点。暴风雪、冰下杀手、体力透支与内部信任崩塌接踵而至。当他们发现生物是冷战时期基因实验的失控产物时，军方却下达了灭口指令。求生任务，变成了一场与人类和怪物的双重厮杀。", "score": 2024350, "category": "crime", "detail_url": "../movie/1766.html", "poster": "../posters/1766.svg"}, {"id": "1767", "title": "四月碎片", "year": 2003, "region": "美国", "type": "电影", "genre": "剧情 / 喜剧 / 家庭", "tags": ["感恩节", "母女", "底层生活", "独立电影", "凯蒂·霍尔姆斯"], "summary_short": "四月碎片，2003年美国电影，剧情 / 喜剧 / 家庭。感恩节早晨，21岁的四月打电话邀请关系疏远的白人父母和弟弟妹妹来她与黑人男友鲍比合住的破旧公寓吃晚餐。她决心要做出完美的感恩节大餐，证明自己“过得很好”。于是，她开始了一场荒诞的“觅食之旅”：借邻居的火鸡、偷楼下的胡萝卜、甚至去枪击案频发的街区找一个会做南瓜派的流浪汉。与此同时，她的家人开车穿越郊区前来，母亲性格刻薄，父亲沉默寡言，妹妹一直在玩手机。两拨人各自出发，朝着同一张餐桌靠", "score": 2003341, "category": "drama", "detail_url": "../movie/1767.html", "poster": "../posters/1767.svg"}, {"id": "1768", "title": "寂寞飞行", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情 / 爱情", "tags": ["公路", "遗愿清单", "自我救赎", "女性成长"], "summary_short": "寂寞飞行，2025年中国台湾电影，剧情 / 爱情。林秀英在丈夫阿诚的葬礼上，只收到一把车钥匙。三十年来她从未学过开车，却决定独自驾驶阿诚那辆老旧福特，从台北开到垦丁。一路上，她在储物格里翻出一张加油发票、一支口红、一本写满里程数的笔记本。随着她笨拙地换挡、迷路、抛锚，她拼凑出阿诚另一个平行人生——那些年他以“出差”为由，载着不同女人环岛。秀英本想当面质问坟里的人，却在终点看到阿诚为她们每人都拍过同一片海。最终她把笔记本烧给大海，独自完成", "score": 2025366, "category": "romance", "detail_url": "../movie/1768.html", "poster": "../posters/1768.svg"}, {"id": "1769", "title": "查理曼", "year": 2026, "region": "法国 / 德国", "type": "剧集", "genre": "剧情, 历史, 动作", "tags": ["中世纪", "帝王传记", "权力斗争", "史诗", "宗教"], "summary_short": "查理曼，2026年法国 / 德国剧集，剧情, 历史, 动作。公元768年，法兰克王国国王矮子丕平去世，将国土分给两个儿子查理和卡洛曼。年轻的查理（后来的查理曼）渴望统一法兰克，但他的弟弟卡洛曼在岳父的煽动下，对他展开了一场惨烈的内战。剧集在描绘宏大战争场面的同时，深入查理曼的宫廷内部：他与母亲“贝尔特拉达”的权力博弈，与心爱的妻子“伦巴第公主”因政治联姻而产生的爱恨纠葛，以及他与一生挚友兼导师“阿尔昆”在信仰与知识上的探讨。从征服萨克森", "score": 2026310, "category": "series", "detail_url": "../movie/1769.html", "poster": "../posters/1769.svg"}, {"id": "1770", "title": "火星时代 第二季", "year": 2026, "region": "美国", "type": "剧集", "genre": "科幻 / 生存", "tags": ["火星殖民， 水资源， 独立运动， 硬科幻"], "summary_short": "火星时代 第二季，2026年美国剧集，科幻 / 生存。第二季开场，地球爆发核战争，太空总署被毁，火星上的“阿瑞斯一号”殖民地成为被遗忘的人类前哨。仅存的一百二十名殖民者面临三大危机：制氧设备将在90天后耗尽滤芯，水循环装置已出现渗漏，而地球那边永远不会有补给来了。女指挥官梅芙下令：全力开采地下冰层。但钻探队发现，殖民地下方三百米处并非水冰，而是一种含高氯酸盐的毒冰，无法直接融化使用。与此同时，殖民地内部出现分裂：以工程师派克为首的团体主", "score": 2026313, "category": "series", "detail_url": "../movie/1770.html", "poster": "../posters/1770.svg"}, {"id": "1771", "title": "拜见婆婆大人Ⅱ", "year": 2025, "region": "中国香港", "type": "电影", "genre": "喜剧 / 家庭", "tags": ["续集", "婆媳", "身份互换", "豪门", "爆笑"], "summary_short": "拜见婆婆大人Ⅱ，2025年中国香港电影，喜剧 / 家庭。上一部中斗得你死我活的婆媳，在这一部里因为一场离奇车祸互换了身体。豪门儿媳（灵魂是婆婆）醒来后要面对年轻帅气的丈夫，却满脑子都是怎么查岗；而豪门婆婆（灵魂是儿媳）则要应对刁钻的老公爹和复杂的家族信托基金。更致命的是，儿媳原本拥有的读心术虽然肉体互换了，但能力还在。当婆婆（儿媳视角）读出周围人心里那句“这老太太终于疯了”时，两人不得不联手对抗觊觎家产的外人，却在合作中意外理解了对方多", "score": 2025306, "category": "comedy", "detail_url": "../movie/1771.html", "poster": "../posters/1771.svg"}, {"id": "1772", "title": "完美的谋杀", "year": 2021, "region": "美国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["高智商犯罪，反转，律师，杀妻骗保，心理博弈"], "summary_short": "完美的谋杀，2021年美国电影，悬疑 / 惊悚。金牌刑辩律师强森·李从未输过一场官司，因为他发明了一套“完美脱罪公式”。为了偿还巨额赌债，他决定对妻子艾米丽下手，以骗取天价保险金。他精心制造了一起入室抢劫案，并在现场留下指向他竞争对手的微量证据。一切如他预演般顺利，警方准备结案。就在强森以为尘埃落定时，一群朋友为了给艾米丽的生日惊喜，带着全套高清摄影设备闯入案发现场布置派对。他们的镜头拍下了强森从未预料到的角度和细节——那本应完美的谋杀", "score": 2021404, "category": "crime", "detail_url": "../movie/1772.html", "poster": "../posters/1772.svg"}, {"id": "1773", "title": "泰山2", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 冒险", "tags": ["丛林", "复仇", "环保", "续集"], "summary_short": "泰山2，2024年美国电影，动作 / 冒险。本片为《泰山》的续作。离开丛林十年后，泰山在英国过着贵族生活，早已忘记如何像猿猴一样嘶吼和攀爬。某天，他收到来自刚果雨林的求救信号：一家名为“绿金”的矿业公司正在用汞污染河流，杀害了大量动物，包括他曾经所属的猿群。泰山独自回到雨林，却发现自己已无法适应丛林环境，屡次遇险。幸好，当年救过他的雌性大猩猩“阿卡拉”的后代认出了他。在猩猩群的帮助下，泰山重新学习丛林法则，肌肉和野性逐渐回归。最终，他单", "score": 2024316, "category": "fantasy", "detail_url": "../movie/1773.html", "poster": "../posters/1773.svg"}, {"id": "1774", "title": "一切徒手2", "year": 2026, "region": "美国", "type": "电影", "genre": "动作/惊悚", "tags": ["徒手格斗，特工，复仇，极限运动，暴力美学"], "summary_short": "一切徒手2，2026年美国电影，动作/惊悚。曾经的传奇特工“徒手”在解决第一集的危机后，隐居东南亚渔村。他本想做个沉默的父亲，却因救下一名被拐少女，再次被国际杀手组织盯上。对方的首领是个痴迷军事科技的偏执狂，为了引出“徒手”，他绑架了女主角，并在整座岛屿布下天罗地网，规则只有一条：不许用枪，不许用刀，只用身体。24小时内，如果“徒手”不能徒手摧毁整个基地，岛上所有人质都将被处决。他只能燃烧肌肉与意志，上演一场最原始也最致命的单挑。", "score": 2026393, "category": "crime", "detail_url": "../movie/1774.html", "poster": "../posters/1774.svg"}, {"id": "1775", "title": "708090之深圳恋歌", "year": 2016, "region": "中国大陆", "type": "电影", "genre": "剧情 / 爱情", "tags": ["深圳", "创业", "代际", "怀旧"], "summary_short": "708090之深圳恋歌，2016年中国大陆电影，剧情 / 爱情。影片以深圳为背景，平行讲述三个年龄段的故事。70后夫妻（45岁）经营工厂遭遇互联网冲击，面临倒闭危机，两人在共渡难关中重新找回年轻时的激情；80后白领（32岁）辞职创业做跨境电商，在融资路上遇见前女友，两人从竞争对手变成了合伙人再续前缘；90后毕业生（23岁）一头扎进短视频创业，和搭档从互相看不顺眼到并肩作战，最终成为情侣。三条线通过一个“深圳创客空间”的地址交汇，他们在各", "score": 2016312, "category": "drama", "detail_url": "../movie/1775.html", "poster": "../posters/1775.svg"}, {"id": "1776", "title": "王胜：香甜多汁", "year": 2026, "region": "中国大陆", "type": "短剧", "genre": "喜剧/科幻/美食", "tags": ["重生", "水果大亨", "商战", "异种嫁接", "爽感"], "summary_short": "王胜：香甜多汁，2026年中国大陆短剧，喜剧/科幻/美食。因实验室爆炸而死的农业博士王胜，重生到了90年代末一个落魄水果贩子身上。他发现自己所有的育种知识都在这个时代堪称黑科技。他用一颗转基因冬枣治好了竞争对手的偏头痛，换来了第一桶金。依靠一枚来自未来记忆的“超级水果”种子配方，他培育出了口感爆炸的多汁品种“王胜一号”。从被地痞欺压的街边摊，到利用期货杠杆打垮垄断的果业巨头，王胜一路降维打击。然而当他站上行业之巅，却发现当年的实验室爆炸", "score": 2026227, "category": "series", "detail_url": "../movie/1776.html", "poster": "../posters/1776.svg"}, {"id": "1777", "title": "一代情侣", "year": 2024, "region": "中国香港", "type": "电影", "genre": "爱情 / 剧情", "tags": ["怀旧", "千禧年", "错位时空"], "summary_short": "一代情侣，2024年中国香港电影，爱情 / 剧情。2024年，整理师阿玲在回收站淘到一部翻盖手机。手机竟能收到来自2004年的信号，对方是即将移民的男孩阿Sam。两人从怀疑到互诉心事，阿玲告诉他未来世界的样子，阿Sam则录下港乐黄金时代的街头声音给她。他们试图约定见面，但每次日期靠近就会断联。阿玲发现，自己的母亲年轻时曾暗恋一个叫阿Sam的人，而母亲现在的忧郁症或许与此有关。她意识到，自己在改变过去的同时，也抹去了自己出生的可能性。最终", "score": 2024362, "category": "drama", "detail_url": "../movie/1777.html", "poster": "../posters/1777.svg"}, {"id": "1778", "title": "救世主回来了", "year": 2024, "region": "韩国", "type": "电影", "genre": "科幻、喜剧、剧情", "tags": ["虚假弥赛亚、克隆人、邪教、社会讽刺"], "summary_short": "救世主回来了，2024年韩国电影，科幻、喜剧、剧情。1814年，自称“白莲救世主”的洪长贤因蛊惑民众被判火刑。2024年，一家生物科技公司为研究“领袖基因”，利用出土遗骸成功克隆了他。新洪长贤拥有原体的所有记忆，但他已经“被烧开窍”了，只想刷短视频、喝奶茶、领低保。然而消息走漏，原邪教演变成的庞大商业集团“白莲教”找上门，硬要拥立他为真神；一个激进的仇教团体则要暗杀他以终结“闹剧”；政府秘密部门想把他培养成控制民众的精神武器。洪长贤在多", "score": 2024394, "category": "drama", "detail_url": "../movie/1778.html", "poster": "../posters/1778.svg"}, {"id": "1779", "title": "天伤星武松", "year": 2025, "region": "中国大陆", "type": "网络电影", "genre": "动作，古装，武侠", "tags": ["水浒传，硬核动作，暗黑风格，兄贵情，复仇"], "summary_short": "天伤星武松，2025年中国大陆网络电影，动作，古装，武侠。本片聚焦武松为兄报仇前后的黑暗时期。不同于传统演义，这里的武松（天伤星）在得知兄长惨死后，理智彻底崩坏。他拒绝官府，放弃律法，独自在雨夜中化身为嗜血的复仇恶鬼。从逼问真相到狮子楼斗杀西门庆，每一场打斗都摒弃了花哨的招式，只有纯粹的力量与杀意。在鲜血与火焰中，武松最终手刃仇敌，但他也意识到自己内心的“伤”已无法愈合。他不再是那个坦荡的打虎英雄，而是一个背负着罪孽、主动戴上枷锁的囚徒", "score": 2025321, "category": "costume", "detail_url": "../movie/1779.html", "poster": "../posters/1779.svg"}, {"id": "1780", "title": "我们约会吧2011", "year": 2011, "region": "中国大陆", "type": "综艺 / 电影", "genre": "爱情 / 真人秀 / 剧情", "tags": ["相亲", "怀旧", "婚恋观", "群像"], "summary_short": "我们约会吧2011，2011年中国大陆综艺 / 电影，爱情 / 真人秀 / 剧情。故事基于2011年真实爆红的相亲节目改编。五组人物：大龄剩女白领、凤凰男程序员、离异带娃的单亲妈妈、富二代玩咖、以及被母亲逼着来的内向男教师。节目规则是“盲选约会”，不看脸只听声音。凤凰男用C语言写情诗，被全场灭灯；单亲妈妈哽咽说出自己的故事，富二代第一次落泪。节目录制结束后，五对男女在现实中继续接触。最终，只有单亲妈妈和富二代走到一起，程序员和女白领成了", "score": 2011339, "category": "series", "detail_url": "../movie/1780.html", "poster": "../posters/1780.svg"}, {"id": "1781", "title": "塞外情仇", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "武侠 / 爱情 / 历史", "tags": ["丝绸之路", "镖局", "土匪", "家国", "兵器"], "summary_short": "塞外情仇，2025年中国大陆电影，武侠 / 爱情 / 历史。明朝嘉靖年间，嘉峪关外驼铃声声。女镖师沈飞燕继承父业经营“飞燕镖局”，她武艺高强，善使双刀，唯一不愿提起的就是三年前因嫌弃未婚夫家道中落而强行退婚。这一次，她接到了一趟价值连城的红货：护送一只刻有奇怪纹路的铁匣子给西域的哈密国王。刚出关，她就遭遇了沙漠大盗“黑风暴”的袭击。匪首摘下面罩，正是当年被她退婚的牧马少年铁穆尔。铁穆尔如今成了纵横塞外的枭雄，他告诉沈飞燕，那铁匣子里装的", "score": 2025316, "category": "costume", "detail_url": "../movie/1781.html", "poster": "../posters/1781.svg"}, {"id": "1782", "title": "那个重逢的夜晚", "year": 2025, "region": "日本", "type": "电影", "genre": "爱情，奇幻，剧情", "tags": ["时空回溯，遗憾，毕业季，告别"], "summary_short": "那个重逢的夜晚，2025年日本电影，爱情，奇幻，剧情。大学最后一天，内向的修一收到一封神秘邮件：你有五次机会回到过去任何时刻，每次30分钟。他兴奋地回到大一入学日，向暗恋的学姐表白，成功了。但回来发现，最好的朋友因为失去了“陪失恋的修一喝酒”的契机，没有走出阴影而退学。修一第二次穿越，阻止朋友退学，但学姐又被别人追走。第三次，他试图两全，却导致社团前辈意外受伤。第四次，他选择什么都不做，只是远远看着曾经的美好瞬间。第五次，他回到最初，把", "score": 2025395, "category": "drama", "detail_url": "../movie/1782.html", "poster": "../posters/1782.svg"}, {"id": "1783", "title": "系统", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "科幻悬疑", "tags": ["游戏化、现实入侵、高概念、限时任务"], "summary_short": "系统，2026年中国大陆剧集，科幻悬疑。某天全球30亿人的手机里突然出现一个名为“System”的app，界面是极简黑白色。系统给每个人发布个性任务：有人要“连续说100句真话”，有人要“拥抱一个陌生人”，失败者会在24小时内人间蒸发。程序员林远洋的任务是“破坏系统的核心代码”，但他没有源代码。随着时间推移，任务越来越变态：“杀死最爱的人”、“告密一个未犯罪的人”。林远洋发现系统在筛选人类的道德底线。他联合全球顶尖黑客和心理学家，最终发", "score": 2026399, "category": "series", "detail_url": "../movie/1783.html", "poster": "../posters/1783.svg"}, {"id": "1784", "title": "天才第三季", "year": 2025, "region": "美国", "type": "剧集", "genre": "传记, 剧情, 历史", "tags": ["天才", "文学", "创作", "困境"], "summary_short": "天才第三季，2025年美国剧集，传记, 剧情, 历史。本季聚焦美国传奇作家J.D.塞林格。二战的血腥经历给他留下了严重的心理创伤，他在战场上完成了《麦田里的守望者》的初稿。战后，小说一经出版便轰动世界，塞林格却因此感到恐惧和厌恶。他无法忍受名声带来的窥探与解读，认为大众曲解了他的本意。第三季深刻描绘了他的自我放逐：他搬到新罕布什尔州的乡下，修筑高墙，拒绝一切采访，甚至不上缴照片。他依然疯狂写作，却将手稿锁进保险柜，禁止发表。观众看到的是", "score": 2025219, "category": "series", "detail_url": "../movie/1784.html", "poster": "../posters/1784.svg"}, {"id": "1785", "title": "识色，幸也", "year": 2023, "region": "中国", "type": "电影", "genre": "爱情，喜剧，都市", "tags": ["色盲，设计公司，契约情侣，反差萌，潘通色卡"], "summary_short": "识色，幸也，2023年中国电影，爱情，喜剧，都市。男主陈述是业内顶尖的设计师，可惜是全色盲，世界在他眼里只有黑白灰。他靠色阶和纹理就能做出绝妙设计，直到遇到女主——一个能准确说出所有色号、被称为“行走的潘通色卡”的色彩顾问孟小糖。陈述的设计公司要竞标一个对色彩要求极高的项目，他不得不高薪聘请孟小糖做自己的“眼睛”。孟小糖提出一个奇葩方案：签一份恋爱契约，她不仅帮他看颜色，还要帮他“感受”颜色——红色是愤怒的吻、蓝色是离别的眼泪、黄色是芒", "score": 2023355, "category": "comedy", "detail_url": "../movie/1785.html", "poster": "../posters/1785.svg"}, {"id": "1786", "title": "摩斯探长前传第五季", "year": 2019, "region": "英国", "type": "电视剧", "genre": "犯罪 / 悬疑", "tags": ["英剧， 推理， 牛津， 古典"], "summary_short": "摩斯探长前传第五季，2019年英国电视剧，犯罪 / 悬疑。摩斯在经历第四季的创伤后，被重新分配回牛津市警局。新上司是名声在外的总探长安德鲁斯，破案率奇高，为人绅士。但摩斯在整理旧档案时发现，一桩十年前未破的女学生失踪案，所有疑点都指向安德鲁斯在案发当晚的行踪。与此同时，牛津城里出现了一名“诗人杀手”，每杀死一人就在尸体旁留下一首十六世纪的情诗。摩斯一边追捕诗人杀手，一边暗中调查自己的上司。两条线在一个意想不到的点交汇：诗人杀手的第四首诗", "score": 2019383, "category": "series", "detail_url": "../movie/1786.html", "poster": "../posters/1786.svg"}, {"id": "1787", "title": "窥情国语", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "悬疑, 情色, 剧情", "tags": ["偷窥", "公寓", "邻居", "婚姻秘密", "录像带"], "summary_short": "窥情国语，2023年中国台湾电影，悬疑, 情色, 剧情。全职主妇美珍住在台北一栋老旧公寓的七楼。丈夫长期出差，她失眠时养成了一个习惯：用儿子的天文望远镜观察对面“幸福公寓”里每扇亮灯的窗户。她给每个被观察者起了代号：总是在深夜加班的“咖啡男”、经常被丈夫打的“紫罗兰”、独自抚养自闭症儿子的“超人妈妈”。她把这些观察写成日记，但从不干涉。直到她发现“紫罗兰”三个月没有出现了，而“咖啡男”开始频繁出入“紫罗兰”的房间。美珍报了警，警察破门后", "score": 2023372, "category": "drama", "detail_url": "../movie/1787.html", "poster": "../posters/1787.svg"}, {"id": "1788", "title": "托尼·厄德曼", "year": 2016, "region": "德国", "type": "电影", "genre": "剧情 / 喜剧", "tags": ["父女", "假身份", "荒诞", "职场"], "summary_short": "托尼·厄德曼，2016年德国电影，剧情 / 喜剧。温弗雷德是一个退休音乐教师，他的女儿伊涅斯在布加勒斯特的一家大型咨询公司做高管，完全被资本逻辑异化。父亲突然来访，发现女儿的生活里只剩下PPT、KPI和客户应酬。他决定伪装成“托尼·厄德曼”——一个自称是德国大使、CEO教练的怪人，戴着假发和丑陋的牙套，混入公司。他在谈判桌上突然掏出鸵鸟蛋，在客户晚宴上唱荒诞歌曲，让女儿尴尬到崩溃。但渐渐地，女儿开始脱下职业面具，在周末派对上裸体唱歌，在", "score": 2016363, "category": "drama", "detail_url": "../movie/1788.html", "poster": "../posters/1788.svg"}, {"id": "1789", "title": "我才不要和人类恋爱呢", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "喜剧, 爱情, 奇幻", "tags": ["跨物种", "猫变人", "甜宠"], "summary_short": "我才不要和人类恋爱呢，2024年中国大陆剧集，喜剧, 爱情, 奇幻。修炼千年的猫妖孟九黎潜入了人类世界，计划用美色迷惑人类精英，逐步控制经济命脉。他的第一个目标是科技公司CEO冰山美人沈希声。然而沈希声被商业对手暗算，意外失忆，智商退化到三岁。孟九黎只好假扮成她的保姆，一边照顾这个“巨婴”CEO，一边继续执行计划。但这位猫大人自己就是个生活白痴——不会用洗衣机、害怕吸尘器、吃泡面都能把厨房炸了。在一连串鸡飞狗跳的同居闹剧中，孟九黎渐渐被", "score": 2024342, "category": "series", "detail_url": "../movie/1789.html", "poster": "../posters/1789.svg"}, {"id": "1790", "title": "末代福晋", "year": 2026, "region": "中国大陆", "type": "剧集", "genre": "历史，剧情", "tags": ["清末，女性，王府，家国"], "summary_short": "末代福晋，2026年中国大陆剧集，历史，剧情。宣统三年，局势动荡。肃亲王府的末代福晋叶赫那拉·婉贞表面骄奢淫逸，整日沉迷牌局，被京城贵族嘲笑为“最没脑子的福晋”。革命党人逼她交出王府藏宝图，日本人开出天价收买国宝《九州山河图》，满清遗老逼她保住祖产。所有人都在等这个“蠢女人”做出选择。距离抄家还有三天，婉贞召集所有势力开了一场牌局。她当众烧毁了真迹，把假账册给了革命党，把赝品卖给了日本人，然后坦然走进监狱。百年后，博物馆展出的《九州山河", "score": 2026263, "category": "series", "detail_url": "../movie/1790.html", "poster": "../posters/1790.svg"}, {"id": "1791", "title": "城市探险者", "year": 2025, "region": "德国", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["都市探险", "废弃医院", "直播", "诅咒"], "summary_short": "城市探险者，2025年德国电影，恐怖, 惊悚。为了博取流量，网红“冒险家”泰勒组织了三名队友，携带高清设备潜入普里皮亚季的废弃医院。他们原本计划在著名的“死亡儿童病房”进行通灵板直播。进入建筑后，无人机拍到走廊深处有穿着病号服的影子闪过，泰勒以为是同行搞鬼，反而更加兴奋。当他们架好通灵板，屏幕上的计数器开始疯狂跳动，辐射探测仪爆表。直播间百万观众看到，墙壁上的辐射腐蚀痕迹开始流血，那些当年死于急性辐射病的患者虚影拖着融化的躯体从墙缝中渗", "score": 2025436, "category": "horror", "detail_url": "../movie/1791.html", "poster": "../posters/1791.svg"}, {"id": "1792", "title": "好运当头", "year": 1997, "region": "中国香港", "type": "电影", "genre": "喜剧", "tags": ["风水", "赌片", "爆笑"], "summary_short": "好运当头，1997年中国香港电影，喜剧。阿强是出了名的衰神，坐公交车爆胎、喝水塞牙、走路被花盆砸，连算命先生都劝他改名。走投无路时，他用最后十块钱买了一张彩票，对奖时发现号码被邻居养的鹦鹉“旺财”叼走吞了。阿强绑架鹦鹉去宠物医院拍X光，彩票号码在鹦鹉胃里清晰可见——头奖三千万！他不得不带着这只随时可能拉出巨款的鸟，躲避各路追杀：黑帮老大想要鹦鹉炖汤补运、彩票店老板娘想偷X光片、甚至一个自称“转运法师”的神棍想作法让鹦鹉主动排泄。一场荒诞", "score": 1997282, "category": "comedy", "detail_url": "../movie/1792.html", "poster": "../posters/1792.svg"}, {"id": "1793", "title": "功夫棒球", "year": 2022, "region": "日本", "type": "电影", "genre": "喜剧, 运动, 动作", "tags": ["棒球", "少林寺", "无厘头", "热血笨蛋", "特训"], "summary_short": "功夫棒球，2022年日本电影，喜剧, 运动, 动作。中部地区最烂的高中棒球队“恶童九人组”，全员是不良少年，比赛成绩常年为负分。新来的教练阿部竟然是个在少林寺修行的日本和尚。他提出的训练方案让所有人傻眼：蹲马步代替跑步、用铁砂掌接球、轻功练盗垒。这群把棒球当群架打的莽夫在啼笑皆非的训练中逐渐蜕变。但在县大赛决赛上，面对劲敌，他们发现真正的对手不是技术，而是内心的恐惧。王牌投手在投出最后一球时，脑海浮现的不是棒球，而是阿部说的：“球就是你", "score": 2022329, "category": "crime", "detail_url": "../movie/1793.html", "poster": "../posters/1793.svg"}, {"id": "1794", "title": "越轨干探", "year": 2024, "region": "中国香港", "type": "电视剧", "genre": "悬疑 / 犯罪", "tags": ["卧底", "黑警", "双雄", "反转", "兄弟情"], "summary_short": "越轨干探，2024年中国香港电视剧，悬疑 / 犯罪。重案组警长陈永仁连续三年获得部门嘉奖，是公认的明日之星。一桩毒品案侦破后，现场关键证据链莫名断裂，所有矛头都指向他。内务部调查期间，一个神秘号码发来短信：“你只是替罪羊，真正的黑警在你身边，想活命就别再走正道。”为了洗脱罪名，陈永仁开始违反所有警例：窃听同事电话、潜入证物房、甚至与之前亲手抓捕的线人合作。随着调查深入，他发现这起陷害案背后牵涉到警队高层与跨国洗钱集团的勾结，而那个发短信", "score": 2024370, "category": "crime", "detail_url": "../movie/1794.html", "poster": "../posters/1794.svg"}, {"id": "1795", "title": "阿比阿弟大冒险", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧 / 科幻 / 冒险", "tags": ["穿越", "乐队", "基友", "荒诞"], "summary_short": "阿比阿弟大冒险，2024年美国电影，喜剧 / 科幻 / 冒险。阿比和阿弟是两个怀才不遇的音乐人，他们梦想用摇滚拯救世界，但现实中连房租都付不起。一天，阿弟从一个古怪的当铺老板那里买到了一部看起来是诺基亚老年机的手机，结果发现这是来自2377年的时间旅行装置。一个来自未来的“历史修正员”告诉他们，因为他们的祖先搞丢了某个关键历史物品，导致未来世界陷入了持续千年的“无聊纪元”。那个关键物品不是核弹头，也不是疫苗配方，而是——音乐天才莫扎特的", "score": 2024347, "category": "sci-fi", "detail_url": "../movie/1795.html", "poster": "../posters/1795.svg"}, {"id": "1796", "title": "科塔工厂第三季", "year": 2025, "region": "印度", "type": "剧集", "genre": "剧情， 犯罪", "tags": ["黑暗工厂， 劳工权益， 阶级反抗"], "summary_short": "科塔工厂第三季，2025年印度剧集，剧情， 犯罪。第三季承接第二季结尾的大爆炸。科塔工厂的地面建筑被毁，露出了地下深达十层的秘密基地。原来这里不仅仅是血汗工厂，更是非法的人体强化实验室，那些“失踪”的工人都被改造成了半机械的生化劳工。幸存领袖拉贾不仅面对想要灭口的腐败官员，还要应对被洗脑后变成杀戮机器的昔日工友。这一季中，拉贾联系上了外部的国际人权组织，并利用工厂内部的网络系统，将实验室的罪行向全球直播。这是一场关乎尊严、自由，甚至人类", "score": 2025268, "category": "series", "detail_url": "../movie/1796.html", "poster": "../posters/1796.svg"}, {"id": "1797", "title": "聪明的驴子", "year": 2019, "region": "法国 / 比利时", "type": "电影", "genre": "剧情 / 喜剧 / 家庭", "tags": ["动物", "治愈", "哲学", "慢节奏"], "summary_short": "聪明的驴子，2019年法国 / 比利时电影，剧情 / 喜剧 / 家庭。年迈的驴子“智者”因不能再在农场干活，被主人辗转送往不同的家庭寄养。它沉默寡言，从不嘶鸣，却拥有一双仿佛能看透一切的眼睛。在退休教授家，它看到知识分子虚伪的清高；在富裕商人家，它目睹了物质富足下的情感荒漠；在单亲妈妈家，它感受到了笨拙却真诚的爱。每个寄养家庭都因这头驴的到来而发生了微妙的变化，有的人在它面前忏悔，有的人因它发怒，也有孩子把它当作唯一的朋友。这是一头驴的", "score": 2019338, "category": "drama", "detail_url": "../movie/1797.html", "poster": "../posters/1797.svg"}, {"id": "1798", "title": "赤子情未了", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情, 家庭, 犯罪", "tags": ["兄弟情", "底层挣扎", "遗愿清单", "复仇"], "summary_short": "赤子情未了，2024年中国香港电影，剧情, 家庭, 犯罪。绰号“赤子”的江湖大佬李国辉被诊断出渐冻症，他不想死在病床上，决定举办一场“生前葬礼”，以此寻找失联多年的结拜兄弟阿强——那个被他亲手出卖入狱、三天后即将出狱的仇人。葬礼当天，来的不是仇人，而是三个二十多岁的年轻人，手持DNA鉴定报告，声称是他的儿子。李国辉一生未娶，怀疑这是仇家的阴谋，于是带着这三个突如其来的“儿子”踏上了寻仇之路。在这一路上，他发现这三个年轻人竟是自己当年资助", "score": 2024386, "category": "drama", "detail_url": "../movie/1798.html", "poster": "../posters/1798.svg"}, {"id": "1799", "title": "传奇大掌柜", "year": 2024, "region": "中国大陆", "type": "TV Series", "genre": "年代，商战，剧情", "tags": ["餐饮，民国商战，学徒逆袭，匠心，老字号"], "summary_short": "传奇大掌柜，2024年中国大陆TV Series，年代，商战，剧情。1910年代，逃荒到京城的少年栾学堂被丰泽园饭庄的老板收留，从最底层的烧火工做起。他天赋异禀，尝一口菜就能复刻出九成味道，但大厨们碍于门户之见不肯收徒。栾学堂偷师学艺，在一次宴请洋人的场合中临危受命，用一道看似平平无奇的“开水白菜”震惊四座，被掌柜收为关门弟子。几十年间，他经历了满清覆灭、军阀混战、日军占领，丰泽园几度易手。栾学堂用“店在人在”的信念，在日本人逼他交出“", "score": 2024094, "category": "series", "detail_url": "../movie/1799.html", "poster": "../posters/1799.svg"}, {"id": "1800", "title": "猩球崛起2：黎明之战", "year": 2014, "region": "美国", "type": "电影", "genre": "动作 / 科幻 / 剧情", "tags": ["猿流感", "战争", "信任", "凯撒"], "summary_short": "猩球崛起2：黎明之战，2014年美国电影，动作 / 科幻 / 剧情。致命的猿流感病毒席卷全球，人类文明濒临灭亡。由凯撒领导的猿族在森林深处建立了自己的家园。十年后，一群幸存的圣何塞居民误入领地，打破了平静。为了获取上游水电站的电力，人类领袖马尔科姆试图与凯撒谈判。凯撒出于对“善良”的记忆，同意合作。但曾经被人类虐待的副手科巴极度仇视人类，他暗杀了凯撒并嫁祸给人类，煽动猿族发动战争。重伤的凯撒被人类救起，他不得不重新审视人类与猿类的关系，", "score": 2014404, "category": "drama", "detail_url": "../movie/1800.html", "poster": "../posters/1800.svg"}, {"id": "1801", "title": "萨米大冒险", "year": 2024, "region": "比利时", "type": "电影", "genre": "动画/冒险", "tags": ["海洋", "友情", "环保", "亲子", "成长"], "summary_short": "萨米大冒险，2024年比利时电影，动画/冒险。小海龟萨米是家族里最胆小的孩子，尤其害怕跃出海面。他的好朋友露娜被海洋垃圾缠住，被洋流卷向远海。萨米鼓起勇气求助一只骄傲但恐高的年轻鹈鹕佩皮诺。一龟一鸟组成奇葩搭档，飞越了珊瑚礁、石油泄漏区和邮轮航线。过程中萨米克服了对高空的恐惧，佩皮诺学会了俯冲捕鱼。最终他们在一座垃圾岛上找到了露娜，萨米还意外发现了一个可以彻底清理海洋的古老生物方法，成为族群的英雄。", "score": 2024274, "category": "fantasy", "detail_url": "../movie/1801.html", "poster": "../posters/1801.svg"}, {"id": "1802", "title": "唱吧！奇迹！", "year": 2024, "region": "日本", "type": "电影", "genre": "音乐, 剧情, 家庭", "tags": ["合唱团", "绝症", "逆袭"], "summary_short": "唱吧！奇迹！，2024年日本电影，音乐, 剧情, 家庭。转学生小堇患有严重口吃，来到一所濒临废校的乡村中学。这里只剩下七名学生，且全因各种残疾被歧视。小堇偶然发现大家竟然都拥有绝对音感却听不见常人的频率——他们活在一个无声却充满振动的世界。小堇突发奇想：组建一支“振动合唱团”，用身体感受节奏参加全国大赛。起初所有人嘲笑她，但当他们第一次用手掌、胸腔和地板共振出贝多芬《欢乐颂》时，奇迹发生了。这是一段用沉默奏响的最强音。", "score": 2024275, "category": "drama", "detail_url": "../movie/1802.html", "poster": "../posters/1802.svg"}, {"id": "1803", "title": "虎将艳奴蛮公主", "year": 1969, "region": "中国香港", "type": "电影", "genre": "古装 / 情色 / 动作", "tags": ["邵氏", "风月片", "夺宝", "虐恋"], "summary_short": "虎将艳奴蛮公主，1969年中国香港电影，古装 / 情色 / 动作。南蛮公主阿奴为夺回被汉人将军“金刀虎”夺走的圣物玉蟾蜍，自卖为奴混入将军府。金刀虎残暴好色，却对阿奴格外温柔，甚至教她识字、练刀。阿奴在爱与使命间挣扎，最终偷走玉蟾蜍逃回蛮邦。金刀虎一人一刀追杀至蛮族祭坛，两人在篝火中大战三百回合。最后金刀虎故意中刀倒下，把刀递给阿奴：“你赢了。”阿奴却扔掉玉蟾蜍，抱起他走向火海。多年后边境多了个开客栈的哑巴女人，后院里种满了金刀虎家乡的", "score": 1969353, "category": "crime", "detail_url": "../movie/1803.html", "poster": "../posters/1803.svg"}, {"id": "1804", "title": "名花有主", "year": 2025, "region": "中国", "type": "剧集", "genre": "爱情 / 喜剧 / 职场", "tags": ["契约婚姻", "霸总", "反套路", "清醒女主"], "summary_short": "名花有主，2025年中国剧集，爱情 / 喜剧 / 职场。猎头苏晚被新来的毒舌总监陆淮舟各种刁难，对方的要求极其苛刻：候选人必须未婚、无不良嗜好、且“名花有主”。苏晚为拿下一个关键职位，谎称自己就是陆淮舟的女友。谎言越滚越大，陆淮舟顺势提出签订“情侣合约”，两人在公司和客户面前假扮恩爱。苏晚本以为这只是场交易，却渐渐发现，陆淮舟对她的照顾无微不至，且总是精准踩中她的喜好。直到某天，她看到陆淮舟多年前写的一封信，上面列着他关于“完美伴侣”的", "score": 2025337, "category": "series", "detail_url": "../movie/1804.html", "poster": "../posters/1804.svg"}, {"id": "1805", "title": "崂山探花郎", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "奇幻， 古装， 喜剧", "tags": ["道士， 破案， 科举， 穿书"], "summary_short": "崂山探花郎，2024年中国大陆电影，奇幻， 古装， 喜剧。法医高阳穿越到古代，成了穷书生。为了凑足进京赶考的盘缠，他误打误撞上了崂山，想骗点银子。道长让他穿墙，他用物理惯性原理解释；道长让他画符，他用化学氧化反应改良。阴差阳错下，当地首富家中闹“僵尸”，高阳用现代法医知识一验，发现所谓僵尸其实是中了西域奇毒的人。他用“催眠”来解释法术，用“人偶”来解释傀儡术，一路开挂破案，不仅被皇帝封为“探花郎”，还被崂山派强行收为关门弟子，成为了史上", "score": 2024374, "category": "comedy", "detail_url": "../movie/1805.html", "poster": "../posters/1805.svg"}, {"id": "1806", "title": "子夜的太阳", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "爱情 / 科幻", "tags": ["极昼", "时空循环", "末日浪漫", "失忆", "追寻"], "summary_short": "子夜的太阳，2025年中国大陆电影，爱情 / 科幻。近未来，科学家发现太阳正在急速衰老，地球将陷入永夜。最后一个能看到太阳的地方是北极圈内的小城。物理学家陈霄来到此地研究拯救计划，却遭遇一场事故，患上了罕见的“日变失忆症”——每当子夜太阳仍高悬时，他的记忆就会被重置。女孩林曦是他出事前的恋人，却因某些原因被他遗忘。林曦每天都会以陌生人的身份接近他，带他体验“第一次”的悸动。陈霄在日记本的指引下，逐渐拼凑出真相：林曦就是他要拯救这个世界的", "score": 2025448, "category": "sci-fi", "detail_url": "../movie/1806.html", "poster": "../posters/1806.svg"}, {"id": "1807", "title": "青苔：死亡异域", "year": 2010, "region": "中国台湾", "type": "电影", "genre": "恐怖", "tags": ["潮湿", "山区", "民俗", "生态恐怖", "幽闭"], "summary_short": "青苔：死亡异域，2010年中国台湾电影，恐怖。纪录片团队前往台湾中部山区拍摄一座因土石流而废弃的村落“雾溪村”。他们发现村中所有物体——墙壁、农具、床铺——都覆盖着厚厚青苔。奇怪的是，青苔长成了人形轮廓。夜里，一名成员踩碎一簇青苔，里面流出红色液体。他们陆续有人皮肤出现青绿斑点、动作变慢、不再说话。最后他们发现，当年土石流没有杀死村民，一种真菌让死者腐烂同时“重组成青苔人”，依然过着日常生活的循环。最后两名幸存者逃出，却发现自己的车钥匙", "score": 2010299, "category": "horror", "detail_url": "../movie/1807.html", "poster": "../posters/1807.svg"}, {"id": "1808", "title": "喀布尔之燕", "year": 2022, "region": "阿富汗/法国", "type": "电影", "genre": "战争剧情", "tags": ["女性生存", "塔利班", "诗意抵抗", "真实事件改编"], "summary_short": "喀布尔之燕，2022年阿富汗/法国电影，战争剧情。2001年，塔利班统治下的喀布尔。女教师法蒂玛和裁缝扎赫拉是秘密读书会的成员。当所有女性被禁止工作、上学，甚至独自上街时，她们发明了一种抵抗方式：扎赫拉在自己的裁缝店里，把波斯古典诗歌和她们自己写的诗句，一针一线缝进顾客的罩袍里。法蒂玛则负责在女顾客试衣时，悄声解读那些诗。渐渐地，罩袍上的诗歌成了喀布尔女性的秘密暗号。她们在市场上、在面包店前、在黑夜的屋顶上，用诗交换信息、传递勇气。当塔", "score": 2022264, "category": "drama", "detail_url": "../movie/1808.html", "poster": "../posters/1808.svg"}, {"id": "1809", "title": "白银和梦想之书", "year": 2025, "region": "英国", "type": "电影", "genre": "奇幻/冒险", "tags": ["魔法书", "少女成长", "平行世界"], "summary_short": "白银和梦想之书，2025年英国电影，奇幻/冒险。16岁的白银在祖母遗物中发现一本会发光的书，书中记载：人类入睡后的梦想世界是一座巨大的矿场，而“梦想之书”的持有者可以提炼梦想颗粒，将其兑换成现实世界的白银。但代价是，每次提取都会从某个陌生人的生命中永久夺走一种情感。起初白银只敢少量提取，帮助贫困的家庭还债。直到一家名为“梦工业”的邪恶公司找上门，声称她侵犯了他们的采矿权。白银不得不潜入层层梦境，在即将被掏空情感的受害者脑中，学会用梦想之", "score": 2025348, "category": "fantasy", "detail_url": "../movie/1809.html", "poster": "../posters/1809.svg"}, {"id": "1810", "title": "拼图杀机", "year": 2020, "region": "中国内地", "type": "电影", "genre": "悬疑, 惊悚, 犯罪", "tags": ["连环杀手", "拼图隐喻", "记忆碎片", "高智商犯罪", "反转结局"], "summary_short": "拼图杀机，2020年中国内地电影，悬疑, 惊悚, 犯罪。连环杀手“拼图师”在连续四起谋杀案现场各留下一片拼图。女刑警队长苏眠在追查中发现，拼图拼起来指向一个废弃仓库，而仓库里关着她的女儿。苏眠崩溃，按凶手指示完成了一系列“赎罪任务”——公开承认自己当年误判导致无辜者入狱。真凶终于现身，竟是她的心理医生陈默。原来陈默是当年冤案受害者的儿子，他用了十年策划这场“正义拼图”，要让苏眠体会亲人被夺走的痛苦。在仓库最终对决中，苏眠说出“我每天醒来", "score": 2020497, "category": "crime", "detail_url": "../movie/1810.html", "poster": "../posters/1810.svg"}, {"id": "1811", "title": "虎豹喋血战", "year": 1986, "region": "香港", "type": "电影", "genre": "动作, 犯罪", "tags": ["港式动作", "兄弟反目", "枪战", "复仇"], "summary_short": "虎豹喋血战，1986年香港电影，动作, 犯罪。经典港式动作片。阿虎和阿豹是越战老兵，退役后成为东南亚最顶尖的雇佣兵搭档。在一次为军阀护送价值连城的“虎豹金佛”任务中，他们遭伏击。混乱中，阿豹贪念乍起，私吞了金佛并制造了阿虎“死亡”的假象。十年后，阿虎大难不死，改名换姓成为香港警队的一名火爆督察，专门打击跨国贩毒集团。而阿豹则成了金三角大毒枭罗罗的贴身保镖兼头号杀手。当阿虎的缉毒行动步步紧逼，罗罗派出阿豹去香港“清理障碍”。昔日兄弟，在霓", "score": 1986355, "category": "crime", "detail_url": "../movie/1811.html", "poster": "../posters/1811.svg"}, {"id": "1812", "title": "印第安高速公路", "year": 2025, "region": "美国", "type": "电影", "genre": "剧情, 公路, 悬疑", "tags": ["印第安保留地", "公路巡警", "失踪人口", "荒野"], "summary_short": "印第安高速公路，2025年美国电影，剧情, 公路, 悬疑。印第安保留地的公路巡警乔，在巡逻时发现路边每隔几十英里就有奇怪的石头堆。他挖开一处，竟发现一具白骨。FBI介入，却因管辖权问题草草收场。乔决定自己调查，发现十几年来，在高速上失踪的印第安女性远高于官方数据。他一边独自巡逻，一边与腐败的地方警长斗智斗勇。最终在部落长老的帮助下，他利用古老追踪术找到了连环杀手的藏身处，但最后一刻，凶手竟是他的前搭档。", "score": 2025329, "category": "drama", "detail_url": "../movie/1812.html", "poster": "../posters/1812.svg"}, {"id": "1813", "title": "新村丧尸漫画", "year": 2024, "region": "韩国", "type": "剧集", "genre": "恐怖 / 喜剧 / 悬疑", "tags": ["丧尸", "漫画", "二次元入侵", "新村", "大学路"], "summary_short": "新村丧尸漫画，2024年韩国剧集，恐怖 / 喜剧 / 悬疑。首尔新村一带突现丧尸，但丧尸的行为诡异：红灯绝对不过马路、看到书店会绕路、听到特定BGM会跳舞。一名熬了五年还没毕业的漫画系学生金道允发现，丧尸的所有行为都和自己失踪导师李万年的未发表漫画《新村丧尸传》的设定一模一样。更离奇的是，只要按照漫画里的“隐藏规则”（比如对丧尸大喊“你分镜错了”就能定住它三秒），就能暂时抵挡尸潮。金道允带着一群同样废柴的漫画社团成员，一边按漫画规则求生", "score": 2024445, "category": "series", "detail_url": "../movie/1813.html", "poster": "../posters/1813.svg"}, {"id": "1814", "title": "十九岁的地图", "year": 2025, "region": "日本", "type": "电影", "genre": "青春 / 犯罪 / 悬疑", "tags": ["高中生", "匿名举报", "正义感", "堕落"], "summary_short": "十九岁的地图，2025年日本电影，青春 / 犯罪 / 悬疑。19岁的高中生吉冈彻拥有超凡的记忆力和观察力，他利用课余时间走遍城市每个角落，绘制了一幅详尽到令人发指的“城市地图”。但他真正的目的是在上面标注出所有违法行为：违停车辆、未登记的废品站、违规搭建、逃税商户。他化名“清洁工”，将这些信息匿名举报给政府和媒体，一时间城市风气焕然一新，他被网民奉为“义警英雄”。然而，正义的快感逐渐变了味。吉冈开始享受掌控和摧毁他人的权力，他的标准越来", "score": 2025369, "category": "crime", "detail_url": "../movie/1814.html", "poster": "../posters/1814.svg"}, {"id": "1815", "title": "她在梦中跳舞", "year": 2024, "region": "韩国", "type": "电影", "genre": "奇幻, 爱情, 剧情", "tags": ["梦境", "芭蕾", "抑郁症", "双向救赎"], "summary_short": "她在梦中跳舞，2024年韩国电影，奇幻, 爱情, 剧情。芭蕾天才李采映因车祸截肢，再也无法站立。但她发现只要入睡，就能在完全逼真的梦境剧场里跳舞。梦中，她每次都遇到同一个沉默的男人，两人共舞一支永远跳不完的《吉赛尔》。现实中，这个男人是开发梦境算法的自闭症程序员姜泰伍，他分不清梦与现实的边界。两人因为梦境同步实验而相遇。当采映发现梦中的舞伴就是泰伍时，泰伍却因梦境侵蚀现实记忆而濒临崩溃。最终采映选择在梦中永远停下舞步，将泰伍推回现实。醒", "score": 2024413, "category": "drama", "detail_url": "../movie/1815.html", "poster": "../posters/1815.svg"}, {"id": "1816", "title": "血偿2025", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "动作、犯罪", "tags": ["复仇、硬汉、警匪、暴力美学"], "summary_short": "血偿2025，2025年中国大陆电影，动作、犯罪。2025年，前特警队长陈默退役后在私立学校当保安，独自抚养女儿小禾。一天小禾被发现在学校天台坠亡，警方认定为自杀。陈默不相信，独自调查发现小禾曾遭受三个男同学的长期霸凌，视频被传到暗网。三个男孩的父亲分别是地产商、高官和律师，他们用金钱和关系让案件草草结案。陈默求助无门，决定血偿。他利用特警技能，分别针对三人的弱点设计了三场“意外”：地产商在自家工地的电梯坠落、高官在私人聚会上被“误杀”", "score": 2025332, "category": "crime", "detail_url": "../movie/1816.html", "poster": "../posters/1816.svg"}, {"id": "1817", "title": "近亲", "year": 2021, "region": "丹麦, 瑞典", "type": "电影", "genre": "剧情, 伦理, 悬疑", "tags": ["家族", "秘密", "北欧", "冷峻", "反转"], "summary_short": "近亲，2021年丹麦, 瑞典电影，剧情, 伦理, 悬疑。北欧小镇，单亲妈妈艾琳娜的女儿确诊白血病，需要骨髓移植。她不得不联系断绝来往三十年的原生家庭。家族成员陆续接受配型，却意外发现：艾琳娜、她的两个兄弟、表兄妹以及上一辈，全部携带一种极为罕见的隐性遗传病基因。而想要治愈女儿，必须找到家族中唯一没有这个基因的人——也就是艾琳娜从未见过面的、据说出生就夭折的孪生姐妹。当艾琳娜翻遍家族老宅，在地下室的铁箱里发现一份领养文件时，真相崩溃：她的", "score": 2021386, "category": "drama", "detail_url": "../movie/1817.html", "poster": "../posters/1817.svg"}, {"id": "1818", "title": "大片", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "喜剧，剧情", "tags": ["片场，剧组，草台班子，黑色幽默，追梦"], "summary_short": "大片，2023年中国大陆电影，喜剧，剧情。导演马大志曾经拍过一部豆瓣8.5分的文艺片，此后十年再无作品。债主追上门时，他吹牛说自己正在筹备一部“投资过亿的大片”，被一个煤老板听信，当场转账500万定金。马大志慌了——钱已经花了一半，片名还没想好。他临时组建了一个奇葩剧组：演过尸体的小龙套当男主、退休菜场会计当制片、两个群演当武行、一个辍学青年当摄影师。他们借设备、骗场地、偷剧本，硬着头皮开拍。期间乌龙不断、笑料百出，却意外拍出了最真实的", "score": 2023301, "category": "drama", "detail_url": "../movie/1818.html", "poster": "../posters/1818.svg"}, {"id": "1819", "title": "灼烧之爱", "year": 2027, "region": "土耳其", "type": "剧集", "genre": "爱情 / 悬疑 / 复仇", "tags": ["豪门恩怨", "替身情人", "烧伤", "美强惨"], "summary_short": "灼烧之爱，2027年土耳其剧集，爱情 / 悬疑 / 复仇。富家千金莱拉与穷小子阿特什相爱，却因为家族反对，阿特什在一次冲突中被莱拉父亲派人烧伤并扔下悬崖，莱拉也被大火毁容。所有人都以为阿特什已死，但十年后，莱拉通过最先进的整容技术换了一张更美的脸，化名“艾拉”，以设计师的身份接近已经成为商业帝国掌门人的阿特什。此时的阿特什虽然活着，但因为烧伤和背叛，心中只有仇恨，他娶了莱拉的妹妹，正在一步步吞噬莱拉家的产业。艾拉本想复仇，却发现当年纵火", "score": 2027309, "category": "series", "detail_url": "../movie/1819.html", "poster": "../posters/1819.svg"}, {"id": "1820", "title": "焦土僵局", "year": 2025, "region": "法国", "type": "电影", "genre": "战争, 剧情", "tags": ["一战", "壕沟", "人性"], "summary_short": "焦土僵局，2025年法国电影，战争, 剧情。1916年，凡尔登。法军下士杜邦和德军狙击手迈尔在一场夜袭后滚进了同一个弹坑。两人身上都有伤，弹药所剩无几，弹坑外是双方都要轰炸的无人区。最初的三天，他们试图杀死对方：用匕首、用石头、用冻僵的手。第四天，一场毒气弹让两人都放弃了——他们只能用彼此的尿液浸湿布条捂住口鼻。第七天，杜邦给迈尔看了口袋里女儿的照片，迈尔则掏出一块怀表，里面是未婚妻。第十三天，他们决定一起逃向最近的法军阵地，但迈尔在爬", "score": 2025256, "category": "drama", "detail_url": "../movie/1820.html", "poster": "../posters/1820.svg"}, {"id": "1821", "title": "为您服务", "year": 1999, "region": "中国大陆", "type": "剧集", "genre": "喜剧， 家庭， 情景", "tags": ["情景喜剧， 英达， 便民服务， 90年代， 街坊"], "summary_short": "为您服务，1999年中国大陆剧集，喜剧， 家庭， 情景。90年代末，北京柳絮胡同。“为您服务”便民点设在公共厕所隔壁的违章建筑里，由下岗电工侯师傅、退休居委会大妈金姨和外地来京打工的小四川组成。三人的业务范围极度离谱：修水管、换灯泡、代写情书、调解婆媳矛盾、替孩子开家长会、甚至帮街坊隐瞒私房钱。每一集围绕一个离谱的单子展开，比如给一只得了抑郁症的八哥做心理疏导，或者假扮某个丈夫去赴妻子浪漫的“初恋回忆晚餐”。他们总能把事情搞得鸡飞狗跳，", "score": 1999216, "category": "series", "detail_url": "../movie/1821.html", "poster": "../posters/1821.svg"}, {"id": "1822", "title": "决战南京", "year": 2009, "region": "中国大陆", "type": "电视剧", "genre": "历史， 战争", "tags": ["谍战， 国共， 南京"], "summary_short": "决战南京，2009年中国大陆电视剧，历史， 战争。渡江战役在即，南京这座国民党统治的中心陷入最后的疯狂。代号“梅花”的地下情报员沈紫卿潜伏在国民党国防部，却发现自己昔日的恋人、军统头号特派员梁一桐从台湾空降南京，专门负责清剿内鬼。昔日情侣，如今要取对方性命。全剧围绕一份关系到南京和平解放的“江防部署图”展开，多方势力盘根错节，每一次接头都可能是陷阱，每一个战友都可能在下一秒叛变。在黎明前最黑暗的时刻，沈紫卿和她的同志们用血肉之躯，在南京", "score": 2009151, "category": "series", "detail_url": "../movie/1822.html", "poster": "../posters/1822.svg"}, {"id": "1823", "title": "很远很远", "year": 2022, "region": "中国大陆", "type": "电影", "genre": "剧情, 公路", "tags": ["寻找", "父子", "治愈"], "summary_short": "很远很远，2022年中国大陆电影，剧情, 公路。哥哥阿木在弟弟小夏被确诊为重度自闭症后，偶然听说遥远的边境小镇有一位老医生能用“自然声波”唤醒沉睡的孩子。阿木偷偷改了三轮车，带着不会说话的小夏上路了。一路上，他们经历了爆胎、迷路、被当作人贩子，也遇到了沉默的卡车司机、开民宿的盲人奶奶和一只总跟着他们的流浪狗。阿木用画画和小夏沟通，小夏却只对风声和车轮声有反应。在第47天，他们到达目的地，发现老医生早已去世，只留下一院子风铃。阿木崩溃痛哭", "score": 2022262, "category": "drama", "detail_url": "../movie/1823.html", "poster": "../posters/1823.svg"}, {"id": "1824", "title": "那就爱上你第一季", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "爱情，喜剧", "tags": ["契约情侣，错位恋爱，职场甜宠，误会丛生"], "summary_short": "那就爱上你第一季，2024年中国大陆剧集，爱情，喜剧。顶级并购律师林则徐与专打离婚官司的律师孟晓声因一场庭审结下梁子，两人在法庭上针锋相对，私下更是互相嘲讽。不料，林则徐的奶奶立下遗嘱，必须看到他订婚才能移交家族信托基金。走投无路之下，他找到急需资金开个人律所的孟晓声，提出一份为期三个月的“恋爱契约”。两人开始了表面甜蜜、背后暗战的同居生活。从厨房战争到亲友探访，从行业酒会到意外同居曝光，他们不断给对方制造麻烦，却又在一次次危机中为对方", "score": 2024332, "category": "series", "detail_url": "../movie/1824.html", "poster": "../posters/1824.svg"}, {"id": "1825", "title": "御林军魂", "year": 2019, "region": "中国大陆", "type": "电视剧", "genre": "古装/动作", "tags": ["宫廷", "禁军", "权谋"], "summary_short": "御林军魂，2019年中国大陆电视剧，古装/动作。明朝永乐年间，赵闯、沈鹿、顾千城三人因武艺出众被选入御林军。赵闯耿直，沈鹿机敏，顾千城出身武将世家。他们本是负责宫中仪仗的低阶士兵，却因目睹了一场刺杀太子的阴谋而踏上逃亡路。三人为了保护彼此，被迫分别投靠了三位互相敌对的皇子。几年后，他们各自成了皇子身边最得力的侍卫。当皇帝病危，三兄弟必须决定：是忠于目前的“主子”，还是恢复往日的兄弟情？一场发生在宫城内的“三英战吕布”式对决即将上演。", "score": 2019265, "category": "series", "detail_url": "../movie/1825.html", "poster": "../posters/1825.svg"}, {"id": "1826", "title": "吾妻十三点粤语", "year": 1992, "region": "中国香港", "type": "电视剧", "genre": "喜剧, 爱情, 家庭", "tags": ["粤语", "十三点", "妻子", "搞笑", "港剧"], "summary_short": "吾妻十三点粤语，1992年中国香港电视剧，喜剧, 爱情, 家庭。老实人陈有福娶了全港最出名的“十三点”（形容行为疯癫、神经质的女人）方小敏。小敏热情过度、脑回路清奇，能把炖汤煲成炸药、把遛狗变成遛房东。陈有福的母亲对这个儿媳恨铁不成钢，天天逼儿子休妻。小敏虽然总是闯祸，却用自己的方式默默支撑着这个家——她用“十三点”式的谈判帮邻居要回了被拖欠的工资，用天马行空的创意帮丈夫的公司拿下大单。当陈有福的初恋情人人美归来，所有人都以为这段婚姻要", "score": 1992336, "category": "comedy", "detail_url": "../movie/1826.html", "poster": "../posters/1826.svg"}, {"id": "1827", "title": "隔壁怪兽", "year": 2023, "region": "韩国", "type": "电影", "genre": "惊悚 / 恐怖 / 剧情", "tags": ["邻居", "寄生虫式恐怖", "都市恐惧", "变态", "密室"], "summary_short": "隔壁怪兽，2023年韩国电影，惊悚 / 恐怖 / 剧情。在首尔一座老旧公寓里，新婚夫妇金敏秀和郑素英搬进了月租极低的半地下室。他们隔壁一直传出诡异的敲击声，房东说是老旧的管道问题。素英某天在家办公时，无意中通过通风管道看到了隔壁房间的一角——一个瘦骨嶙峋的女人被铁链锁在暖气片上。素英报警后，警察破门而入，却发现隔壁房间里除了一张旧床垫什么都没有。更诡异的是，那个神秘女人的长相和素英几乎一模一样。金敏秀开始调查前住户的资料，发现过去十五年", "score": 2023475, "category": "horror", "detail_url": "../movie/1827.html", "poster": "../posters/1827.svg"}, {"id": "1828", "title": "泰吉", "year": 2026, "region": "印度", "type": "电影", "genre": "动作， 历史， 惊悚", "tags": ["刺客信条， 莫卧儿帝国， 冷兵器"], "summary_short": "泰吉，2026年印度电影，动作， 历史， 惊悚。故事发生在沙贾汗建造泰姬陵时期。低种姓石匠泰吉是建造奇迹的天才，但他目睹了暴君为了赶工期，不断虐杀累倒的工人。泰吉不愿看到更多的兄弟死去，利用对建筑结构的精通，在未完工的泰姬陵里布满了暗道和机关。每当夜深人静，他便化身蒙面杀手，暗杀那些酷吏和监工。皇家卫队围剿多次都被他在复杂的建筑迷宫中反杀。最后，沙贾汗请来了波斯刺客团围剿。泰吉为了保护工人们撤离，故意触发了一开始就设计好的自毁机关，让部", "score": 2026352, "category": "crime", "detail_url": "../movie/1828.html", "poster": "../posters/1828.svg"}, {"id": "1829", "title": "血腥风暴", "year": 2019, "region": "韩国", "type": "电影", "genre": "动作", "tags": ["犯罪", "复仇", "硬核", "暴雨", "黑吃黑"], "summary_short": "血腥风暴，2019年韩国电影，动作。首尔遭遇创纪录暴雨，汉江水位暴涨。毒枭老金藏身于江南区一栋烂尾楼顶层，准备与台湾买家交易。不料，他的前手下彪哥带着三名亡命徒从地下车库摸上来，想黑吃黑。更巧的是，被老金灭门的出租车司机崔大叔也带着自制燃烧弹潜入了 12 楼。与此同时，一名受雇保护台湾买家的日本女杀手因为导航失灵也被困在大楼里。暴雨切断了所有信号，电梯停运，四组人马在伸手不见五指的楼道里展开混乱枪战。雨声盖过枪声，积水混着血水。最后活下", "score": 2019339, "category": "crime", "detail_url": "../movie/1829.html", "poster": "../posters/1829.svg"}, {"id": "1830", "title": "啪嗒啪嗒", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["听障", "亲情", "无声表演"], "summary_short": "啪嗒啪嗒，2025年中国台湾电影，剧情 / 家庭。少女小禾出生于一个遗传性听障家庭，父亲、哥哥都是聋人，母亲即将在后年完全失去残余听力。作为家中唯一能听见的人，她从六岁起就担任全家人的“耳朵”和“嘴巴”。然而，当她即将去台北上大学时，她陷入了深深的自责：她害怕自己离开后，沉默的父母将无法与这个世界沟通。影片通过大量的环境音设计，让观众体验从有声世界突然坠入无声世界的错愕感。小禾决定在暑假期间，教母亲学会最后几个声音词汇，其中最重要的一个", "score": 2025316, "category": "drama", "detail_url": "../movie/1830.html", "poster": "../posters/1830.svg"}, {"id": "1831", "title": "狮子今夜入睡", "year": 2017, "region": "法国", "type": "电影", "genre": "剧情，家庭", "tags": ["老年痴呆，亲情，和解，生命倒计时"], "summary_short": "狮子今夜入睡，2017年法国电影，剧情，家庭。退休的文学教授雅克不再认得自己的儿女，他总觉得自己躺在非洲草原上，身边的护士是母狮，儿子马克是讨厌的鬣狗。为了完成母亲遗愿，马克将父亲从疗养院接回家中照顾。在混乱的日常中，马克通过父亲零碎的呓语，拼凑出一个隐藏了四十年的秘密：雅克曾为了家庭放弃去非洲研究狮群的机会。为了让父亲在清醒中离开，马克决定伪造一次前往“非洲”的冒险。当出租车模拟成越野车，花园里播放着自然白噪音时，雅克终于在儿子的背上", "score": 2017287, "category": "drama", "detail_url": "../movie/1831.html", "poster": "../posters/1831.svg"}, {"id": "1832", "title": "猛犸复活", "year": 2025, "region": "美国", "type": "电影", "genre": "科幻、惊悚", "tags": ["基因复活、西伯利亚、怪物、生存"], "summary_short": "猛犸复活，2025年美国电影，科幻、惊悚。某生物科技巨头在西伯利亚冻土层发现了保存完好的猛犸象尸体，并成功提取DNA将其复活。这一壮举震惊世界，但他们忽略了一个细节——猛犸象体内封存着三万年前的超级病毒。病毒通过空气传播，感染者的基因会发生突变，变得力大无穷但丧失理智，只剩下进食本能。实验室所在的北极圈小镇一夜之间沦为炼狱。极夜之下，幸存者不仅要躲避狂暴的“感染者”，还要面对那头因为变异而体型暴增、刀枪不入的猛犸巨兽。活下去，等待太阳升", "score": 2025421, "category": "horror", "detail_url": "../movie/1832.html", "poster": "../posters/1832.svg"}, {"id": "1833", "title": "他她他她", "year": 2019, "region": "中国大陆", "type": "电影", "genre": "爱情，悬疑", "tags": ["四角恋，身份，谎言"], "summary_short": "他她他她，2019年中国大陆电影，爱情，悬疑。一家深山民宿里，两对情侣（他和她、他和她）因为一场暴雨被困。晚餐时，手机误投屏，四人的相册里竟然都有同一个陌生女人的照片。更诡异的是，四个人口中的“她”描述完全不符：有人说是前女友，有人说是同事，有人说是网友，还有人说不认识。当那个神秘女人突然出现在门外时，四人被迫开始拼凑真相。原来他们都被同一个人用不同的身份“情感诈骗”了。最终，他们决定联手反骗那个骗子。", "score": 2019418, "category": "crime", "detail_url": "../movie/1833.html", "poster": "../posters/1833.svg"}, {"id": "1834", "title": "链接与链条", "year": 2026, "region": "德国", "type": "剧集", "genre": "科幻 / 惊悚", "tags": ["脑机接口", "集体意识", "极权", "伦理"], "summary_short": "链接与链条，2026年德国剧集，科幻 / 惊悚。柏林初创公司“链接”发布革命性产品“链条”——植入后，用户可以自愿与最多五人共享实时情绪，夫妻更理解彼此，团队更默契。三年后，全球三亿人植入。心理学家玛塔一直拒绝，直到她八岁的女儿在学校被强制植入（“不植入不能参与小组学习”）。玛塔骇入系统，发现“链条”有一个隐藏层：每个用户的“负面情绪”——尤其是羞耻、恐惧、内疚——会被自动压缩上传至中心服务器，并被转化为一种可交易的数字资产。那些最痛苦", "score": 2026402, "category": "series", "detail_url": "../movie/1834.html", "poster": "../posters/1834.svg"}, {"id": "1835", "title": "黑社会以和为贵", "year": 2026, "region": "中国香港", "type": "电影", "genre": "剧情、犯罪、黑色幽默", "tags": ["扫黑除恶、卧底、社团转型、养老院"], "summary_short": "黑社会以和为贵，2026年中国香港电影，剧情、犯罪、黑色幽默。龙头大佬“和气生”金盆洗手，响应号召将社团转型为“和联胜养老产业集团”。他踌躇满志买下一块地皮，却发现此地早已被另一股势力控制——由他前女友掌控的“慈母护老院联盟”。为了拿回地皮，他不得不重操旧业，但手下小弟只会跳科目三和刷短视频。在一次失败的谈判中，他无意间发现，真正的幕后黑手竟是当年劝他向善的卧底警官。当黑社会遇到老龄化，一场荒诞的社区保卫战打响了。", "score": 2026338, "category": "crime", "detail_url": "../movie/1835.html", "poster": "../posters/1835.svg"}, {"id": "1836", "title": "高压行动", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作、犯罪、悬疑", "tags": ["卧底、黑帮、高压电、反转"], "summary_short": "高压行动，2025年韩国电影，动作、犯罪、悬疑。卧底警察韩哲在韩国最大黑帮已经潜伏三年，眼看就要拿到犯罪证据，他的上司却突然被绑架，勒索者要求用他来做交换。在一次秘密接头时，埋伏的警察与黑帮爆发枪战，慌乱中一枚手榴弹炸毁了配电室，整栋废弃大厦陷入一片漆黑。韩哲处在最危险的位置——所有人都知道卧底就在现场，而他身上正带着发信器。他必须在绝对的黑暗中，仅凭听觉和触觉，在二十多个训练有素的杀手之间周旋。高压电线的漏电声、手机屏幕的微光、呼吸的", "score": 2025462, "category": "crime", "detail_url": "../movie/1836.html", "poster": "../posters/1836.svg"}, {"id": "1837", "title": "挪亚：灭世启示", "year": 2026, "region": "美国", "type": "电影", "genre": "灾难/奇幻", "tags": ["圣经改编", "大洪水", "方舟", "人性考验"], "summary_short": "挪亚：灭世启示，2026年美国电影，灾难/奇幻。本片颠覆了传统的圣经故事。挪亚不仅接到了神谕要建造方舟，还被告知：人类罪恶滔天，大洪水过后，挪亚一家必须绝后，让人类从此消失，只留动物存活。面对怀孕的儿媳、不孕的女儿以及想要抢夺方舟的暴徒，挪亚陷入了巨大的信仰危机。他既要抵御外敌入侵，又要防止家人在船上怀孕。在滔天洪水中，方舟成了一座移动的人性炼狱。挪亚手持匕首，站在即将临盆的儿媳床前，在“服从神谕”与“延续血脉”之间做出了最痛苦的抉择。", "score": 2026330, "category": "fantasy", "detail_url": "../movie/1837.html", "poster": "../posters/1837.svg"}, {"id": "1838", "title": "失忆24小时粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "悬疑 / 喜剧", "tags": ["失忆", "黑色幽默", "绑架", "局限空间"], "summary_short": "失忆24小时粤语，2024年中国香港剧集，悬疑 / 喜剧。小混混阿东在茶餐厅后厨醒来，双手被绑，身旁躺着一具中刀尸体，窗外全是警车。他什么都不记得，只模模糊糊感觉自己整个下午都在吃菠萝包。警方认定他是凶手，但阿东在逃跑过程中发现身上多了一张房卡、一张演唱会票根和一个陌生女人的口红印。24小时内，他必须一边躲避警察和追杀他的黑帮，一边还原“昨日自己”的行程：他究竟有没有杀人？为什么视频监控显示他昨天同一时间出现在三个不同地点？而那个自称是", "score": 2024337, "category": "series", "detail_url": "../movie/1838.html", "poster": "../posters/1838.svg"}, {"id": "1839", "title": "堪萨斯小猫", "year": 2025, "region": "美国", "type": "电影", "genre": "音乐，传记，剧情", "tags": ["爵士乐，女性力量，成长，20世纪20年代"], "summary_short": "堪萨斯小猫，2025年美国电影，音乐，传记，剧情。影片讲述了1920年代堪萨斯城最年轻的黑人女爵士钢琴家“小猫”玛莎·威廉姆斯的真实故事改编。出身贫寒的玛莎只能偷偷在酒吧后巷听爵士乐，凭借绝对音感无师自通。她女扮男装进入当时女性被禁止入内的爵士俱乐部演出，用惊世骇俗的切分音征服了所有人。在种族隔离与性别歧视的双重压力下，她从被嘲讽为“花瓶”到成为摇摆乐之王，最终在白人男性主导的音乐界，为自己赢得了一席之地。", "score": 2025289, "category": "doc", "detail_url": "../movie/1839.html", "poster": "../posters/1839.svg"}, {"id": "1840", "title": "天地豪情粤语", "year": 1999, "region": "中国香港", "type": "剧集", "genre": "剧情 / 商战", "tags": ["家族恩怨", "粤语原声", "豪门", "兄弟反目", "经典"], "summary_short": "天地豪情粤语，1999年中国香港剧集，剧情 / 商战。香港豪门的卓家有两个儿子：长子卓尚文自小被培养为接班人，次子卓尚武则被生母带走，在庙街长大。父亲临终前将百亿集团交给尚文，却将一块不毛之地的地契留给尚武。尚文嫉妒弟弟有母亲的陪伴，尚武怨恨父亲的不公。两人在一次冲突后意外撞车，醒来时身份错换——护士搞混了病房。尚文决定将错就错，体验平民生活；尚武则进入集团，发现了父亲当年的秘密：那块地契下埋着全港最大的稀土矿。最终兄弟俩联手对抗外敌，", "score": 1999210, "category": "series", "detail_url": "../movie/1840.html", "poster": "../posters/1840.svg"}, {"id": "1841", "title": "东京仙履奇缘", "year": 1994, "region": "日本", "type": "电视剧", "genre": "爱情 / 剧情 / 都市", "tags": ["日式纯爱", "灰姑娘童话", "泡沫经济时代", "兄妹伦理"], "summary_short": "东京仙履奇缘，1994年日本电视剧，爱情 / 剧情 / 都市。平凡的松井雪子为了逃离北海道的枯燥生活，只身来到东京投靠哥哥。她在一家小食品公司做着文员工作，梦想有一天能参加上流社会的宴会。在一次意外中，她得到了参加大财阀高木家慈善晚宴的机会。没有晚礼服的雪子穿着一件改制的旧裙子，却在那里邂逅了英俊儒雅的继承人高木真彦。真彦厌倦了商业联姻，被雪子的天真无邪打动。两人度过了一个梦幻的雨夜，真彦在临别时送给了她一双并不合脚的水晶鞋。然而，现实", "score": 1994325, "category": "series", "detail_url": "../movie/1841.html", "poster": "../posters/1841.svg"}, {"id": "1842", "title": "史酷比4：湖怪的诅咒", "year": 2024, "region": "美国", "type": "电影", "genre": "喜剧、悬疑、动画", "tags": ["侦探、怪物、怀旧、青少年"], "summary_short": "史酷比4：湖怪的诅咒，2024年美国电影，喜剧、悬疑、动画。时隔多年，神秘公司全员再次集结。这次他们收到了来自中国千岛湖风景区的跨国委托：一只能发出悠扬越剧唱腔的巨型湖怪，每晚都会从湖心升起，导致旅游业崩溃。起初薛奇和弗雷德认为是景区竞争对手的阴谋，但现场留下的鳞片竟是明朝文物。维尔玛发现，湖怪袭击的时间点与一份古代乐谱的演奏时间完全重合。与此同时，达芙妮被一位神秘的越剧小生迷得神魂颠倒。众人深入水下古城，发现所谓的诅咒，其实是某位明代", "score": 2024330, "category": "fantasy", "detail_url": "../movie/1842.html", "poster": "../posters/1842.svg"}, {"id": "1843", "title": "坏记忆橡皮擦", "year": 2025, "region": "韩国", "type": "电影", "genre": "爱情 / 科幻 / 剧情", "tags": ["记忆删除，反乌托邦，虐恋，伦理困境"], "summary_short": "坏记忆橡皮擦，2025年韩国电影，爱情 / 科幻 / 剧情。近未来韩国，神经科技公司“乐莫里”推出革命性产品“坏记忆橡皮擦”，能精准删除特定情感记忆。女主角秀雅是产品体验师，意外发现前任民载成了新用户，请求删除与她相关的所有痛苦回忆。出于愧疚与好奇，她违规调阅了他的删除清单，却发现里面全是甜蜜瞬间——原来他定义的“痛苦”是失去她。秀雅决定私下接近已被清空“分手原因”的民载，两人迅速坠入热恋。但当她发现民载也开始偷偷使用另一支笔删除她的坏", "score": 2025439, "category": "drama", "detail_url": "../movie/1843.html", "poster": "../posters/1843.svg"}, {"id": "1844", "title": "求婚大作战", "year": 2025, "region": "中国", "type": "电视剧 (翻拍)", "genre": "爱情 / 奇幻 / 青春", "tags": ["穿越", "青梅竹马", "遗憾", "修正"], "summary_short": "求婚大作战，2025年中国电视剧 (翻拍)，爱情 / 奇幻 / 青春。32岁的严小赖参加青梅竹马吉恬恬的婚礼，她嫁给了别人。他悔恨自己14年来从未表白。这时婚礼现场的精灵出现，给他机会穿越回高中时代。他一次次回到过去，想用微小改变扭转未来：修正一次吵架、送对生日礼物、勇敢牵一次手。但他发现每次改变都会引起新的连锁反应，甚至让恬恬离他更远。最终他意识到，问题不是过去做错了什么，而是他从未真正理解恬恬的内心。最后一次穿越，他什么都不做，只是", "score": 2025357, "category": "series", "detail_url": "../movie/1844.html", "poster": "../posters/1844.svg"}, {"id": "1845", "title": "木乃伊之墓", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 冒险, 恐怖", "tags": ["考古", "诅咒", "超自然", "解谜"], "summary_short": "木乃伊之墓，2025年美国电影，动作, 冒险, 恐怖。埃及沙漠深处，考古学家伊芙琳发现一座从未被记载的法老陵墓，墓中并无金银，只有密密麻麻刻满咒文的黑色石棺。打开后，里面并非完整木乃伊，而是一种能寄生人体的干燥孢子。孢子通过呼吸进入人体，三天内会将宿主从内部吸干，化作新的“守卫者”。伊芙琳的队员接连变成干尸复活，开始在沙漠中追杀剩余活人。她必须在成为下一具木乃伊之前，破解墓室深处的反向咒文，重新封印这股来自冥界的生物兵器。", "score": 2025382, "category": "crime", "detail_url": "../movie/1845.html", "poster": "../posters/1845.svg"}, {"id": "1846", "title": "重任在肩第五季", "year": 2025, "region": "英国", "type": "电视剧", "genre": "犯罪, 惊悚", "tags": ["反恐", "反腐", "高压力"], "summary_short": "重任在肩第五季，2025年英国电视剧，犯罪, 惊悚。AC-12反贪组接到匿名举报，指控他们曾经的灵魂人物、现已升任副局长的“铁面判官”休·戴维斯涉嫌包庇恐怖分子。为了避嫌，上级成立了特别调查组，而休·戴维斯成了被调查对象。凯特和史蒂夫在暗中调查时发现，所有的证据都过于完美，像是有人精心栽赃。与此同时，一个针对伦敦地铁的生化袭击计划正在暗处酝酿，而关键线索就藏在休·戴维斯二十年前办理的一起“已经结案”的旧卷宗里。这一次，重任在肩的他们，必", "score": 2025308, "category": "series", "detail_url": "../movie/1846.html", "poster": "../posters/1846.svg"}, {"id": "1847", "title": "爸爸快长大", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "剧情 / 家庭 / 喜剧", "tags": ["育儿", "新手爸爸", "爆笑", "成长"], "summary_short": "爸爸快长大，2024年中国大陆剧集，剧情 / 家庭 / 喜剧。三个大学死党在三十八岁那年夏天集体陷入育儿危机。金融精英崔大志被全职太太“罢工”抗议，被迫接手从未抱过的双胞胎；摇滚中年老周突然多了个私生女，引发家庭大战；社畜程序员王小明和妻子双双被裁，新手爸妈为省钱上演“自制辅食”闹剧。三人组成“奶爸联盟”，在深夜喂奶、幼儿园面试、家长群社交等战场节节败退又屡败屡战。过程中他们闹出把宝宝交给自动喂食器、用代码写育儿攻略等笑话，也逐渐理解了", "score": 2024295, "category": "drama", "detail_url": "../movie/1847.html", "poster": "../posters/1847.svg"}, {"id": "1848", "title": "复生2022", "year": 2022, "region": "中国台湾", "type": "剧集", "genre": "科幻 / 悬疑", "tags": ["末世，克隆，记忆移植，伦理，反转"], "summary_short": "复生2022，2022年中国台湾剧集，科幻 / 悬疑。2022年，病毒席卷全球，死亡者数以亿计。生物科技公司“伊甸”推出天价“复生”技术：将死者记忆上传至克隆体。富豪千金林书妍复生了死去的男友阿拓，但复生后的阿拓行为诡异，时常梦游到从未去过的贫民窟。林书妍调查发现，“复生”技术并非创造新生命，而是从活人脑中强行下载意识。更可怕的是，所有“复生者”都在被一个集体意识召唤，企图撕裂现实世界的边界。", "score": 2022333, "category": "series", "detail_url": "../movie/1848.html", "poster": "../posters/1848.svg"}, {"id": "1849", "title": "狄恩", "year": 2022, "region": "美国", "type": "电影", "genre": "剧情，传记，音乐", "tags": ["爵士乐，迪安·马丁，传记，友情，遗憾"], "summary_short": "狄恩，2022年美国电影，剧情，传记，音乐。该片聚焦传奇歌手迪恩·马丁的晚年生活。已年过七旬的迪恩独自居住在洛杉矶的公寓里，回忆自己辉煌又充满遗憾的一生。他与杰瑞·刘易斯曾是全美最受欢迎的喜剧搭档，却因为经纪人挑拨和嫉妒，在巅峰期决裂，从此再无往来。迪恩后来转型歌手，事业再创高峰，但他始终没有从那次决裂中走出来。影片通过大量闪回，展现了两人的初识、合作、矛盾升级，以及最后那场没有说再见的分别。迪恩的儿子迪恩·保罗·马丁在影片中扮演年轻时", "score": 2022281, "category": "doc", "detail_url": "../movie/1849.html", "poster": "../posters/1849.svg"}, {"id": "1850", "title": "官方机密", "year": 2024, "region": "英国", "type": "电视剧", "genre": "谍战、政治、职场", "tags": ["政府泄密、情报内斗、吹哨人、近未来、多线叙事"], "summary_short": "官方机密，2024年英国电视剧，谍战、政治、职场。2027年，英国情报机构GCHQ遭遇史上最大泄密：一连串绝密监听记录出现在网上，内容包括首相与石油公司的私下交易、美军无人机误炸平民的原始视频等。军情五处介入调查，锁定五名嫌疑分析师。然而每一次“抓出内鬼”后，泄密照常发生。第五个内鬼被开除的当晚，新一批加密邮件直接发送到了《卫报》所有记者的私人邮箱。调查总监艾莉丝发现一个恐怖规律：泄露的文件全是“本应被销毁的非法行动记录”，且发布者的I", "score": 2024229, "category": "series", "detail_url": "../movie/1850.html", "poster": "../posters/1850.svg"}, {"id": "1851", "title": "闪灵悍将", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 科幻, 超级英雄", "tags": ["超级英雄", "反英雄", "超能力", "黑暗", "复仇"], "summary_short": "闪灵悍将，2025年美国电影，动作, 科幻, 超级英雄。前特种兵杰克在军方秘密实验中获得了“闪现”能力——可以在千分之一秒内移动到视线内的任何地方。但这项能力有一个致命副作用：每使用一次，他就会失去一段随机的记忆。从失去初恋的名字到忘记回家的路，杰克发现自己正逐渐变成一个没有过去的人。当他得知最初的实验就是军方为了制造“可控的杀人机器”时，杰克决定用自己最后的记忆去毁掉整个项目。他成了军方的头号目标，也成了自己记忆的最后一个守护者。", "score": 2025424, "category": "sci-fi", "detail_url": "../movie/1851.html", "poster": "../posters/1851.svg"}, {"id": "1852", "title": "彼得·冯·康德", "year": 2022, "region": "法国 / 德国", "type": "电影", "genre": "剧情 / 同性", "tags": ["艺术家、权力、控制、改编、心理"], "summary_short": "彼得·冯·康德，2022年法国 / 德国电影，剧情 / 同性。炙手可热的德国导演彼得·冯·康德在酒店房间对年轻帅气的男演员阿米尔一见钟情。他动用自己的全部人脉和资本，为阿米尔量身打造电影，将他从一个无名小卒推上影帝宝座。阿米尔感激涕零，搬进彼得的豪宅，两人过起同居生活。但阿米尔成名后渐渐厌倦了被控制，他开始私自接片，与女演员暧昧，公开场合疏远彼得。彼得用切断资源、封杀、爆料隐私等手段试图挽回，反而把阿米尔彻底推向了另一边。最后阿米尔在颁", "score": 2022243, "category": "drama", "detail_url": "../movie/1852.html", "poster": "../posters/1852.svg"}, {"id": "1853", "title": "婚头转向", "year": 2025, "region": "中国台湾", "type": "电影", "genre": "喜剧 / 爱情", "tags": ["婚礼", "乌龙的", "前任", "家族闹剧"], "summary_short": "婚头转向，2025年中国台湾电影，喜剧 / 爱情。婚礼策划师小顾从业八年从未失手，直到接手“世纪婚礼”。新娘在化妆间接到前男友的语音留言，新郎在休息室发现自己还爱着伴郎，司仪突然宣布要出家，而新娘的父亲带着小三来抢婚。更离谱的是，酒店送错了酒席、蛋糕里有假牙、婚车被开去跑滴滴。四组人马在婚礼现场各自为战，闹出无数笑话。最终，没有一场婚礼顺利举行，但所有人都在这场荒诞的闹剧里找到了真正想要的答案——有些人应该结婚，有些人应该放手。", "score": 2025361, "category": "comedy", "detail_url": "../movie/1853.html", "poster": "../posters/1853.svg"}, {"id": "1854", "title": "零号带原者", "year": 2024, "region": "韩国", "type": "电视剧", "genre": "科幻 / 惊悚 / 悬疑", "tags": ["丧尸变异，免疫者，阴谋论，医疗惊悚"], "summary_short": "零号带原者，2024年韩国电视剧，科幻 / 惊悚 / 悬疑。不明僵尸病毒在全球爆发，男主姜宇成是唯一被发现拥有天然抗体的人，被称为“救世主”。他被军方严密保护，其血液被制成血清拯救了无数人。然而，一名退役的战地医生在追溯病毒起源时，震惊地发现：所有病毒样本的基因序列，都指向了姜宇成的家族。进一步的调查揭示，姜宇成并不是后来被感染，他本身就是“零号带原者”——其变异基因在特定条件下才被激活成了病毒。当政府和药企为了利益试图掩盖真相并控制他", "score": 2024414, "category": "series", "detail_url": "../movie/1854.html", "poster": "../posters/1854.svg"}, {"id": "1855", "title": "谎言之城", "year": 2025, "region": "中国香港", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["连环杀人，谎言，警匪，反转，心理"], "summary_short": "谎言之城，2025年中国香港电影，悬疑 / 犯罪。香港接连出现诡异尸体：地产商嘴里写着“我会还钱”，明星嘴里写着“我单身”，律师嘴里写着“我无罪”。重案组督察陈永正发现所有死者都是三年前一桩冤案的涉案人员。当年一名无辜青年被冤枉入狱后自杀，而真正的凶手至今逍遥法外。随着调查深入，陈永正发现自己的搭档、上司甚至妻子都与这桩案子有关。每个人都在说谎，而那个“惩罚者”似乎就在警局内部。影片采用罗生门式的叙事结构，每个嫌疑人的回忆版本都不相同，", "score": 2025432, "category": "crime", "detail_url": "../movie/1855.html", "poster": "../posters/1855.svg"}, {"id": "1856", "title": "心灵休憩处", "year": 2022, "region": "中国台湾", "type": "电影", "genre": "剧情、家庭、疗愈", "tags": ["民宿、城市返乡、母女和解、山居岁月、慢生活"], "summary_short": "心灵休憩处，2022年中国台湾电影，剧情、家庭、疗愈。被裁员的都市白领林佳真带着一肚子怨气回到母亲经营的海边民宿。母亲阿玉嫂是个硬脾气，两人三天两头为经营方式吵架。转折来自一位声称“来等海龟”的失明老人、一对每周都来却从不入住的沉默夫妻，以及一个半夜在沙滩写字的叛逆少女。佳真在被迫处理这些“麻烦客人”的过程里，意外发现每间客房抽屉都藏着母亲写给已故父亲的信。她开始重新审视这栋老房子：母亲三十年没涨过房价，厨房永远温着绿豆汤，走廊尽头有张", "score": 2022298, "category": "drama", "detail_url": "../movie/1856.html", "poster": "../posters/1856.svg"}, {"id": "1857", "title": "我唾弃你的坟墓：似曾相识", "year": 2024, "region": "美国", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["复仇", "时间回溯", "暴力美学"], "summary_short": "我唾弃你的坟墓：似曾相识，2024年美国电影，恐怖, 惊悚。经典IP重启。女作家詹妮弗被四个男人残忍侵犯后一一杀死复仇，当她手刃最后一个人时，她惊醒在了被侵犯的前一天。她以为老天给了她机会，但她很快发现，四个凶手也保留了记忆。这次他们不仅提前设伏，还反咬一口说她疯了。詹妮弗不再等待被侵犯，她主动出击，用“预测未来”的能力，在每个凶手最幸福的时刻毁掉他们的人生，最后让他们死在彼此手上。", "score": 2024459, "category": "horror", "detail_url": "../movie/1857.html", "poster": "../posters/1857.svg"}, {"id": "1858", "title": "闪亮女孩", "year": 2027, "region": "韩国", "type": "电影", "genre": "惊悚/剧情", "tags": ["选秀黑幕", "女性复仇", "反转不断"], "summary_short": "闪亮女孩，2027年韩国电影，惊悚/剧情。韩国顶流选秀《闪亮女孩》第三季总决赛夜，冠军“国民妹妹”金未来被利器刺死在自己的化妆间。警方封锁现场，嫌疑人锁定在其余九名决赛选手中。随着调查深入，每个人似乎都有动机：被抢了C位的、被霸凌过的、甚至被金未来抢了男友的。但负责此案的女刑警吴秀贤发现，这些女孩看似互相争斗，实则眼神中传递着一种默契。原来，金未来长期利用人气霸凌甚至囚禁练习生，这九个女孩都曾是受害者。她们在赛前组成了一个秘密复仇联盟。", "score": 2027380, "category": "drama", "detail_url": "../movie/1858.html", "poster": "../posters/1858.svg"}, {"id": "1859", "title": "空气人形", "year": 2024, "region": "日本", "type": "电影", "genre": "奇幻 / 剧情", "tags": ["充气娃娃、获得生命、孤独、都市情感"], "summary_short": "空气人形，2024年日本电影，奇幻 / 剧情。中年独居的上班族秀树买了一个充气娃娃小望，把她当作泄欲工具和倾诉对象。一天清晨，小望突然拥有了心跳和意识。她像初生婴儿一样学习走路、吃饭、感受微风。秀树既惊喜又恐惧，试图把她当作女儿或恋人。但小望在独自外出时，爱上了楼下便利店那个总是面带倦容的店员阿守。小望像人类少女一样去约会，却被告知她体内的“生命能量”只有七天。第七天，小望回到秀树身边，请求他把自己变回普通的充气娃娃，因为“只有作为物品", "score": 2024367, "category": "drama", "detail_url": "../movie/1859.html", "poster": "../posters/1859.svg"}, {"id": "1860", "title": "亚马逊活命水", "year": 2026, "region": "美国 / 巴西", "type": "电影", "genre": "冒险, 动作, 奇幻", "tags": ["丛林探险", "神秘药剂", "长生不老", "部落传说"], "summary_short": "亚马逊活命水，2026年美国 / 巴西电影，冒险, 动作, 奇幻。亿万富翁洛克资助了一支探险队，深入亚马逊雨林寻找传说中的“活命水”——据称能让人返老还童的神秘液体。队员包括植物学家米娅、前特种兵马库斯和当地向导尤里。他们穿过重重险境后，终于在一座废弃的古城中找到了药剂。但喝下活命水的人并没有永生，而是被一种古老真菌寄生，逐渐变成没有意识的“树人”。洛克不顾劝阻强行服用，引发了整个丛林的反噬。探险队必须在变成森林的一部分之前，找到毁掉活", "score": 2026338, "category": "fantasy", "detail_url": "../movie/1860.html", "poster": "../posters/1860.svg"}, {"id": "1861", "title": "豆豆猫", "year": 2026, "region": "日本", "type": "动画剧集", "genre": "治愈, 奇幻", "tags": ["猫咪", "便利店", "温暖"], "summary_short": "豆豆猫，2026年日本动画剧集，治愈, 奇幻。东京某条冷清商业街的尽头，有一家24小时便利店，每晚午夜过后，一只灰色的流浪猫“豆豆”会准时推门进来。它会用嘴里叼着的一枚昭和时代的旧硬币，买一罐最便宜的啤酒，然后坐在门口的纸箱上，和值班的年轻店员小满聊天。豆豆能说会道，从街坊八卦到人生哲理，甚至能预测天气。小满发现，豆豆每晚聊天的对象，其实都是当天最需要被治愈的人——被裁员的上班族、失恋的女高中生、老年痴呆走失的老奶奶。而豆豆的真实身份，", "score": 2026226, "category": "series", "detail_url": "../movie/1861.html", "poster": "../posters/1861.svg"}, {"id": "1862", "title": "莫札特与鲸鱼：真爱相依", "year": 2005, "region": "美国", "type": "电影", "genre": "剧情，爱情", "tags": ["自闭症，高功能，浪漫，治愈"], "summary_short": "莫札特与鲸鱼：真爱相依，2005年美国电影，剧情，爱情。唐纳德是一个拥有非凡数学天赋但社交能力几乎为零的出租车司机，他过着精确如钟表般的规律生活。直到他遇到了伊莎贝尔，一个美丽、不受约束、同样患有自闭症谱系障碍的女孩。她的不按常理出牌打乱了他所有的计划，却又像另一颗孤独的星球终于找到了轨道。两人迅速坠入爱河，但两个“怪胎”的恋爱过程充满了误解、崩溃与笑泪。当他们决定尝试同居并融入所谓的“正常人”社群时，彼此间的摩擦和保护壳被强制剥落的痛", "score": 2005378, "category": "romance", "detail_url": "../movie/1862.html", "poster": "../posters/1862.svg"}, {"id": "1863", "title": "蒙巴纳斯", "year": 2024, "region": "法国", "type": "电影", "genre": "爱情，文艺，历史", "tags": ["巴黎，画家，爵士时代，跨种族"], "summary_short": "蒙巴纳斯，2024年法国电影，爱情，文艺，历史。1921年的巴黎，蒙巴纳斯街区是艺术家和流亡者的天堂。美国黑人爵士小号手埃利斯逃离种族隔离来到巴黎，在酒馆演奏时遇到了被沙俄迫害而流亡的犹太女画家米拉。两人在艺术与灵魂上迅速产生共鸣，但他们的爱情在当时的法国同样备受歧视。埃利斯的音乐与米拉的画作相互滋养，他们计划一起前往更自由的柏林。然而，当埃利斯的美国前雇主派人来抓他回去，米拉的家庭也逼迫她嫁给一个富商时，两人必须在爱情、艺术与生存之间", "score": 2024314, "category": "doc", "detail_url": "../movie/1863.html", "poster": "../posters/1863.svg"}, {"id": "1864", "title": "麻饶布拉区少年", "year": 2024, "region": "印度", "type": "电影", "genre": "剧情 / 体育 / 社会", "tags": ["印度", "板球", "贫民窟", "种姓", "逆袭"], "summary_short": "麻饶布拉区少年，2024年印度电影，剧情 / 体育 / 社会。孟买最大的垃圾处理区“麻饶布拉”住着一群不可接触者家庭的孩子们。他们每天的工作是翻捡垃圾，唯一的娱乐是在坑洼的泥地上用木棍打一个破网球。一天，一辆载满板球器材的大巴因为司机迷路误入了贫民窟，少年们趁司机睡觉时偷偷把车上的球拍、护具和两箱板球全部搬空。他们组成了“麻饶布拉十一人队”，冒用附近一所废弃学校的名义报名了地方联赛。队长卡鲁是个皮球投手，他投出的球没有任何规则可言，却因", "score": 2024276, "category": "drama", "detail_url": "../movie/1864.html", "poster": "../posters/1864.svg"}, {"id": "1865", "title": "月光县快车", "year": 2022, "region": "美国", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["列车，连环杀机，暴风雪，密室，推理"], "summary_short": "月光县快车，2022年美国电影，悬疑 / 犯罪。开往月光县的最后一班特快列车因暴风雪被困在半路。车上有退休警探、网红主播、带着巨额现金的商人、一对度蜜月的新婚夫妻，以及一个自称是通灵者的神秘女人。第一站停靠时，一位乘客被发现在厕所里心脏骤停，但尸检显示他早在进站前就已死亡，且口袋里塞着一张乘客名单，上面赫然写着他自己的名字。更诡异的是，名单上还印着一个据说三年前就去世了的乘客名。每经过一个废弃小站，就会有一人离奇死亡，而死者的名字总会提", "score": 2022438, "category": "crime", "detail_url": "../movie/1865.html", "poster": "../posters/1865.svg"}, {"id": "1866", "title": "缘来花开", "year": 2023, "region": "中国台湾", "type": "剧集", "genre": "爱情, 家庭, 治愈", "tags": ["花店", "阴差阳错", "慢生活"], "summary_short": "缘来花开，2023年中国台湾剧集，爱情, 家庭, 治愈。精明干练的金融分析师林绚烂被公司裁员后，莫名其妙继承了一家濒临倒闭的花店，附赠一只懒散的猫和一个凶巴巴的学徒。遗嘱要求她必须经营满365天，且每天要在门口放一束“无名花”。花店原主人阿公曾是顶尖花艺师，他在遗嘱影像中说：我在等一个人，如果她回来，请把第365束花给她。林绚烂起初只想赶紧亏完钱跑路，但在与花花草草的接触中，她逐渐被疗愈。第364天，一个女人来到花店，她竟是阿公失散50", "score": 2023225, "category": "series", "detail_url": "../movie/1866.html", "poster": "../posters/1866.svg"}, {"id": "1867", "title": "双星之阴阳师", "year": 2025, "region": "日本", "type": "动画", "genre": "奇幻，动作，热血", "tags": ["少年漫，咒术，双主角，宿命，战斗"], "summary_short": "双星之阴阳师，2025年日本动画，奇幻，动作，热血。改编自同名轻小说。在一个人鬼共存的世界，每隔百年就会诞生一对“双星之阴阳师”，他们联手便能封印最强的“祸神”。这一代的双星被鉴定为：出身名门的傲慢天才安倍晴雅，和出身贫民窟的野路子战斗狂人芦屋道满。两人性格水火不容，见面就打架，被阴阳寮强行绑在一起修行。就在他们互相拆台、浪费灵力时，祸神提前复苏，以压倒性力量击溃了阴阳师联军。在绝境中，两人被迫使用禁忌的“合魂之术”，却发现了惊天真相：", "score": 2025183, "category": "fantasy", "detail_url": "../movie/1867.html", "poster": "../posters/1867.svg"}, {"id": "1868", "title": "高空飞行", "year": 2020, "region": "韩国", "type": "电影", "genre": "悬疑 / 惊悚 / 灾难", "tags": ["红眼航班", "神秘乘客", "群体幻觉", "机舱密闭空间", "反转结局"], "summary_short": "高空飞行，2020年韩国电影，悬疑 / 惊悚 / 灾难。从首尔飞往洛杉矶的KE0823航班，起飞两小时后，商务舱一位女士尖叫着说机翼上趴着一个人。空乘查看，什么也没有。但随后越来越多乘客都看到“那个人”——而且长得和自己一模一样。恐慌像病毒蔓延，有人试图打开舱门，被其他乘客按在地上。主角是飞行恐惧症患者李正浩，他发现凡是看到“另一个自己”的人，都曾在一年前的那场空难中“本应登机但没登机”。机长广播说雷达上没有任何异常，但驾驶舱的窗户上，", "score": 2020363, "category": "crime", "detail_url": "../movie/1868.html", "poster": "../posters/1868.svg"}, {"id": "1869", "title": "疯猴", "year": 2022, "region": "中国香港", "type": "电影", "genre": "动作, 惊悚", "tags": ["狂犬病毒", "变异灵长类", "城市恐慌"], "summary_short": "疯猴，2022年中国香港电影，动作, 惊悚。某私立动物园引进的珍稀金丝猴因非法基因实验感染了“超狂犬病毒”，潜伏期仅10分钟，被咬后人类会失去理智，无差别攻击。猴子咬伤饲养员后逃入晚高峰地铁站。病毒以指数级扩散，整个3号线沦为炼狱。退伍女兵阿芬带着六岁的儿子被堵在隧道里，她必须穿过一节节满是“疯人”的车厢，前往驾驶室紧急制动。而那只金丝猴，正蹲在车顶，血红的眼睛注视着整列人间列车。", "score": 2022371, "category": "crime", "detail_url": "../movie/1869.html", "poster": "../posters/1869.svg"}, {"id": "1870", "title": "地雷战2015", "year": 2015, "region": "中国内地", "type": "电影", "genre": "战争, 动作", "tags": ["民间智慧", "爆破", "抗日"], "summary_short": "地雷战2015，2015年中国内地电影，战争, 动作。抗日神剧的壳，硬核科幻的核。故事发生在1942年，一支日军精锐扫雷小队携带德国进口的先进金属探测器进入胶东半岛，专门破解八路军的石雷。赵家庄的民兵队长赵虎是个武器迷，他意外捡到一本现代《爆破工程》教材（穿越设定）。他利用土法炼钢，制造出非金属的陶瓷雷、塑料雷，甚至利用当地矿石制作出触发式震源雷，完美躲避探测器。日军屡屡受挫，请来东京大学物理教授。最后决战中，赵虎利用山坡地形和几何学，", "score": 2015270, "category": "doc", "detail_url": "../movie/1870.html", "poster": "../posters/1870.svg"}, {"id": "1871", "title": "后院骨灰", "year": 2024, "region": "中国香港", "type": "电影", "genre": "剧情 / 家庭 / 悬疑", "tags": ["骨灰龛", "土地问题", "黑色幽默", "遗产", "闹剧"], "summary_short": "后院骨灰，2024年中国香港电影，剧情 / 家庭 / 悬疑。香港寸土寸金，老李家的公屋堪比鸽子笼。爷爷去世后，骨灰龛位价格飙升到天价，全家陷入“死不起”的尴尬。一筹莫展之际，叛逆的小孙女阿花灵机一动：把爷爷的骨灰混入泥土，种进阳台那盆快枯死的万年青里。于是，爷爷以“植物形态”继续住在家里。但这盆“爷爷花”意外长得异常茂盛，被网红博主拍到，误认为是珍稀植物，引来无数人高价求购。与此同时，殡葬公司、风水师，甚至黑道都盯上了这盆“能带来好运”", "score": 2024393, "category": "drama", "detail_url": "../movie/1871.html", "poster": "../posters/1871.svg"}, {"id": "1872", "title": "赛拳艳遇", "year": 2024, "region": "泰国", "type": "电影", "genre": "动作爱情喜剧", "tags": ["泰拳，假戏真做，保镖，黑帮千金，反差萌"], "summary_short": "赛拳艳遇，2024年泰国电影，动作爱情喜剧。阿梗是曼谷贫民窟的泰拳手，技术一流但总打假拳还债。某天，一个神秘女人出高价让他假扮自己的未婚夫，去参加一个上流社会的宴会。阿梗换上西装才发现，这个女人竟是当地黑帮老大的千金“白小姐”。宴会上有人刺杀白小姐，阿梗本能地使出泰拳击退杀手。白小姐顺势宣布他就是自己的保镖兼未婚夫。原来白小姐想借阿梗的力量脱离家族控制。两人在不断的追杀中产生了真感情。最后，阿梗拒绝了白小姐私奔的请求，而是站上了地下拳王", "score": 2024384, "category": "crime", "detail_url": "../movie/1872.html", "poster": "../posters/1872.svg"}, {"id": "1873", "title": "迷宫物语", "year": 2025, "region": "日本", "type": "动画电影", "genre": "奇幻、冒险、心理", "tags": ["意识流、迷宫、自我探寻、视觉奇观"], "summary_short": "迷宫物语，2025年日本动画电影，奇幻、冒险、心理。姐姐小光坚信弟弟没有死，而是被困在了学校后山的神秘迷宫。当她踏入其中，发现迷宫会实时变化，每个转角都映射着不同人的记忆与欲望。她遇到了迷路的上班族、徘徊的士兵、忘记名字的老妇人。小光发现，只有直面每个人内心最恐惧的角落，墙壁才会打开新通道。在迷宫最深处，她看到了弟弟，但弟弟已被迷宫的“守护者”——一团由执念构成的星云——同化。小光必须在迷失自我与拯救弟弟之间做出终极抉择。", "score": 2025339, "category": "fantasy", "detail_url": "../movie/1873.html", "poster": "../posters/1873.svg"}, {"id": "1874", "title": "左轮百合", "year": 2026, "region": "韩国", "type": "电影", "genre": "动作, 惊悚", "tags": ["女杀手", "百合", "暴力美学", "复仇", "黑色电影"], "summary_short": "左轮百合，2026年韩国电影，动作, 惊悚。黑色电影风格。智秀是组织排名第一的杀手，在一次任务中被组织背叛，身中数枪跌落汉江。三年后，她化名“百合”在港口城市经营着一家濒临倒闭的花店，极度厌恶暴力。新人女警敏珠一直在追查三年前的悬案，她通过弹道分析怀疑智秀没死，并找到了花店。敏珠是智秀的隐藏粉丝，她没有逮捕智秀，反而希望拜她为师。智秀拒绝，但当地黑帮觊觎花店的地皮，不断骚扰，逼得智秀不得不重操旧业。在最后的大决战中，敏珠为了保护智秀腹部", "score": 2026402, "category": "crime", "detail_url": "../movie/1874.html", "poster": "../posters/1874.svg"}, {"id": "1875", "title": "奇异博士2：失控多重宇宙", "year": 2022, "region": "美国", "type": "电影", "genre": "动作 / 奇幻 / 恐怖", "tags": ["漫威", "多元宇宙", "黑暗", "丧尸"], "summary_short": "奇异博士2：失控多重宇宙，2022年美国电影，动作 / 奇幻 / 恐怖。在打败灭霸之后，奇异博士史蒂芬·斯特兰奇一直做着同一个噩梦：另一个宇宙的自己屠杀了整个光照会。现实中，一个名叫阿美莉卡的少女突然出现在至圣所，她拥有随意打开多元宇宙通道的能力，但无法控制。黑暗维度领主梦魇派出“梦行者”追杀阿美莉卡，试图用她的能力将所有宇宙的噩梦实体化。奇异博士保护少女的过程中，意外导致所有平行宇宙的通道同时打开，于是，来自各个宇宙的奇异博士变体（包", "score": 2022492, "category": "horror", "detail_url": "../movie/1875.html", "poster": "../posters/1875.svg"}, {"id": "1876", "title": "半夜不要照镜子", "year": 2024, "region": "中国香港", "type": "电影", "genre": "恐怖、惊悚", "tags": ["民俗、诡异、镜子、校园、诅咒"], "summary_short": "半夜不要照镜子，2024年中国香港电影，恐怖、惊悚。大学宿舍里，四个女生在午夜玩起了“镜仙”通灵游戏。仪式被打断后，恐怖开始发生。主角小美发现，镜子里的自己有时会笑，有时会哭，但表情和自己完全不同。起初她以为是幻觉，直到室友们一个个惨死：有人被碎镜割喉，有人溺死在洗脸池里。小美查阅资料，得知这是“倒影诅咒”——镜中诞生的恶灵会杀死本体并取代之。为了活命，她必须在下一个午夜前，进入镜中世界杀死那个“自己”。在倒数三秒时，小美看到了镜子里的", "score": 2024395, "category": "horror", "detail_url": "../movie/1876.html", "poster": "../posters/1876.svg"}, {"id": "1877", "title": "湄公河大案", "year": 2024, "region": "中国大陆", "type": "剧集", "genre": "犯罪, 悬疑, 动作", "tags": ["缉毒", "真实案件改编", "跨国行动"], "summary_short": "湄公河大案，2024年中国大陆剧集，犯罪, 悬疑, 动作。随着“华平号”和“玉兴8号”在湄公河遇难，中国警方迅速成立专案组。调查初期，舆论将矛头指向船员贩毒内讧，但经验丰富的高队长从弹孔痕迹中看出破绽。他秘密潜入金三角地区，与当地情报贩子、卧底以及被毒枭迫害的村民联手，逐渐将矛头指向区域最大的毒枭糯卡。然而，随着调查深入，高队长发现糯卡背后还有来自军方势力的庇护，以及一个试图利用毒品控制整个地区的庞大网络。这是一场跨越四国边境，正义与邪", "score": 2024396, "category": "crime", "detail_url": "../movie/1877.html", "poster": "../posters/1877.svg"}, {"id": "1878", "title": "恶灵古堡首部曲：拉昆市", "year": 2021, "region": "美国", "type": "电影", "genre": "动作, 恐怖", "tags": ["丧尸", "游戏改编", "封闭城市", "生化危机"], "summary_short": "恶灵古堡首部曲：拉昆市，2021年美国电影，动作, 恐怖。本片重启《生化危机》系列，更忠于游戏原作。1998年，中西部工业城市拉昆市，保护伞公司的地下研究所发生生化泄露。克莱尔·雷德菲尔德发现阴谋后赶回城市警告哥哥克里斯，但为时已晚。丧尸如潮水般涌出，警察局变成孤岛。里昂作为新扎师兄，第一天上班就遭遇末日。几位主角在警局汇合，试图通过下水道逃往火车站。途中他们遭遇巨型变异鳄鱼、舔食者和被病毒改造的威斯克。最终克莱尔与克里斯在一辆失控的列", "score": 2021407, "category": "horror", "detail_url": "../movie/1878.html", "poster": "../posters/1878.svg"}, {"id": "1879", "title": "家族的故事", "year": 2024, "region": "日本", "type": "电影", "genre": "剧情 / 家庭 / 温情", "tags": ["家族羁绊，年代跨越，和解与传承，催泪弹"], "summary_short": "家族的故事，2024年日本电影，剧情 / 家庭 / 温情。在东京经营小料理店的中年独身女人真纪，收到一封来自陌生老人的信，附着一本泛黄的相册。相册记录了她的祖父——一位战前著名的柔道家和从未被提起的朝鲜妻子。真纪从不知道这段跨国婚姻的存在，更不知道自己的父亲其实是混血儿。她按照相册中的线索，踏上寻访亲人的旅途，从大阪的旧街到济州岛的海边，拼凑出祖父在时代洪流中的挣扎、父亲因身份而选择沉默的一生，以及自己从未见过的奶奶的温柔目光。在旅途中", "score": 2024268, "category": "drama", "detail_url": "../movie/1879.html", "poster": "../posters/1879.svg"}, {"id": "1880", "title": "惊恐时分", "year": 2026, "region": "美国", "type": "电影", "genre": "恐怖, 惊悚", "tags": ["密室", "心理游戏", "直播", "真实犯罪", "反转"], "summary_short": "惊恐时分，2026年美国电影，恐怖, 惊悚。直播平台“惊悚地带”策划顶级秀：六位网红被锁在一座废弃精神病院，每人有一个隐藏任务，完成者可获百万美元。观众投票决定谁能离开。游戏开始后，第一个任务出现死亡（被道具电锯割喉），大家以为是特效，直到尸体被抬走时掉落真实身份证——此人确实是失踪半年的街头艺人。他们才意识到，所有“任务”都是模仿三年前未破案的连环杀手“拼图师”的手法。观众以为是高能表演，疯狂打赏；实际上，凶手就在六人中，他正在按自己", "score": 2026373, "category": "horror", "detail_url": "../movie/1880.html", "poster": "../posters/1880.svg"}, {"id": "1881", "title": "浪子降魔", "year": 2025, "region": "中国香港 / 中国大陆", "type": "电影", "genre": "奇幻 / 动作 / 惊悚", "tags": ["港式鬼片，降头，浪子，暴力美学，民俗"], "summary_short": "浪子降魔，2025年中国香港 / 中国大陆电影，奇幻 / 动作 / 惊悚。上世纪80年代，香港。天师陈浪天赋极高却行事浪荡，在一次斗法中因轻敌导致师父被降头反噬惨死，他从此封刀，沦为烂泥。十年后，他的女儿被下了罕见的“玻璃降”，全身骨骼正在慢慢碎裂。为了救女儿，陈浪必须找回当年的法器，并面对当年害死师父的那个仇人——此时对方已成南洋第一邪术师。这不仅是一场术法的对决，更是一场关于何为“降”的人性拷问：真正的魔，是符咒，还是人心？", "score": 2025484, "category": "crime", "detail_url": "../movie/1881.html", "poster": "../posters/1881.svg"}, {"id": "1882", "title": "东海道四谷怪谈", "year": 2025, "region": "日本", "type": "电影", "genre": "恐怖 / 古装 / 怪谈", "tags": ["江户时代", "复仇", "歌舞伎改编", "美学", "诅咒"], "summary_short": "东海道四谷怪谈，2025年日本电影，恐怖 / 古装 / 怪谈。改编自经典歌舞伎。江户时期，落魄浪人民谷伊右卫门为金钱毒死妻子阿岩，迎娶富家女阿梅。但阿岩临死前的诅咒应验了——民谷家的每一面镜子中都能看到阿岩苍白的脸。阿梅怀上孩子后，孩子出生时脸上带着阿岩的胎记。民谷日益疯狂，他用刀劈碎所有镜子，却发现地板、水面、刀刃上全是阿岩。最终民谷在家中看到阿岩抱着婴儿朝他走来，他拔刀冲过去，却刺穿了前来探望的岳父。官府判他斩首。行刑前，阿岩的幻影", "score": 2025294, "category": "horror", "detail_url": "../movie/1882.html", "poster": "../posters/1882.svg"}, {"id": "1883", "title": "追星病毒", "year": 2024, "region": "中国大陆", "type": "网剧", "genre": "剧情 / 喜剧", "tags": ["追星", "女性成长", "饭圈", "黑色幽默", "都市"], "summary_short": "追星病毒，2024年中国大陆网剧，剧情 / 喜剧。美术生林小溪是顶流偶像白夜明的“数据女工”，靠兼职打投、控评维持着偶像的光鲜数据。一次画展，她震惊地发现自己的毕业设计成了白夜明“新专辑概念画作”。愤怒之下，她伪装成私生饭潜入偶像工作室，本想偷回原稿，却意外卷入一场资本洗钱阴谋。她联合其他被剽窃的创作者组建“反黑组”，用饭圈惯用的控评、刷榜、制造黑热搜反制偶像团队。当真相曝光，粉丝群体分裂，林小溪也从一个盲目的追随者，逐渐看清了娱乐工业", "score": 2024123, "category": "series", "detail_url": "../movie/1883.html", "poster": "../posters/1883.svg"}, {"id": "1884", "title": "甘达琳娜", "year": 2024, "region": "意大利", "type": "电影", "genre": "剧情, 历史", "tags": ["女性史诗", "文艺复兴", "修道院", "艺术与权力", "禁忌之恋"], "summary_short": "甘达琳娜，2024年意大利电影，剧情, 历史。15世纪的佛罗伦萨，孤女甘达琳娜被修道院收养，展现出惊人的绘画天赋。但因女性身份，她不被允许学习人体解剖。为了让才华不被埋没，老院长剪去她的长发，让她扮作哑巴男学徒“甘达罗”。她在美第奇家族的工坊中偷师达芬奇，与米开朗基罗暗中较劲。为了绘制大教堂穹顶的《天使之战》，她必须在教会监察官眼皮底下，以男人身份完成这幅巨作。而在夜晚，她与模特安东尼奥的禁忌爱情也面临暴露危险。当竞争对手发现她的秘密并", "score": 2024232, "category": "drama", "detail_url": "../movie/1884.html", "poster": "../posters/1884.svg"}, {"id": "1885", "title": "过夜", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "惊悚, 悬疑", "tags": ["密室", "直播", "凶宅", "反转", "国产"], "summary_short": "过夜，2023年中国大陆电影，惊悚, 悬疑。网络主播阿豪带着两位搭档，闯入一栋尘封多年、曾发生灭门惨案的别墅进行整晚直播。起初，他们制造各种假动静骗礼物。但很快，真正的灵异事件开始发生：灯光不受控制，墙壁渗出液体，甚至出现了不属于他们其中任何一人的脚步声。更恐怖的是，他们发现直播间的留言里，有人在用死者家属的口吻与他们对话。当其中一名成员离奇失踪，阿豪才意识到，这栋凶宅里的“住户”，想让他们永远留下来“过夜”。", "score": 2023393, "category": "crime", "detail_url": "../movie/1885.html", "poster": "../posters/1885.svg"}, {"id": "1886", "title": "玉面情魔", "year": 2021, "region": "美国", "type": "电影", "genre": "剧情 / 悬疑 / 犯罪", "tags": ["黑色电影，心理操控，马戏团，宿命，翻拍"], "summary_short": "玉面情魔，2021年美国电影，剧情 / 悬疑 / 犯罪。斯坦顿是个靠读心术混迹马戏团的流浪汉，他学会了一套完整的“精神魔术”骗局。逃离马戏团后，他与女心理医生莉莉丝合作，专门诈骗上流社会的富人。莉莉丝表面文静，实则比斯坦顿更精于算计。一次针对当地大佬的骗局中，斯坦顿违背莉莉丝的计划独吞钱财，准备远走高飞。就在他即将成功时，却发现莉莉丝早就布下了天罗地网：他不仅被警方通缉，还被下药变成了一个口齿不清的醉汉。最终，斯坦顿被卖给一个巡回畸形秀", "score": 2021469, "category": "crime", "detail_url": "../movie/1886.html", "poster": "../posters/1886.svg"}, {"id": "1887", "title": "没有航标的河流", "year": 1983, "region": "中国大陆", "type": "电影", "genre": "剧情，文艺，历史", "tags": ["知青返城，理想幻灭，河流隐喻"], "summary_short": "没有航标的河流，1983年中国大陆电影，剧情，文艺，历史。1983年，最后一批插队知青即将返城。在湖南湘西山区的知青点，阿江、小坡和英子决定亲手造一只木筏，将十年里积攒的日记、信件、画作以及婴儿夭折后埋葬的泥土，顺着无名河运回省城。他们以为这条河能一直通到湘江、通到长江、通到每个人理想的出海口。然而出发后才发现，山里的水坝已将河道截断、上游造纸厂排放的泡沫让河面变成白色、下游为了建开发区甚至将一段河流直接填平。他们背着木筏翻过坝体、趟过", "score": 1983267, "category": "drama", "detail_url": "../movie/1887.html", "poster": "../posters/1887.svg"}, {"id": "1888", "title": "偶像失格", "year": 2024, "region": "日本", "type": "剧集", "genre": "剧情, 悬疑, 社会", "tags": ["粉丝文化", "偶像塌房", "私生饭", "网络暴力", "真实改编"], "summary_short": "偶像失格，2024年日本剧集，剧情, 悬疑, 社会。少女真帆是女团C位偶像美咲的“神推”，五年间省吃俭用花掉300万日元买周边、投票、追行程。某周刊登出美咲与男星过夜的照片，全网瞬间炸锅。事务所召开谢罪发布会，美咲含泪道歉，承认“正在认真交往”。当天深夜，真帆在直播中烧光所有周边后，从公寓六楼跳下。事件引发巨大社会争议，有人骂偶像欺骗粉丝，有人说粉丝自作自受。三个月后，真帆的姐姐偶然发现妹妹手机里的私信，原来是美咲曾私下与真帆保持联系，", "score": 2024344, "category": "series", "detail_url": "../movie/1888.html", "poster": "../posters/1888.svg"}, {"id": "1889", "title": "风流皇后", "year": 1992, "region": "中国香港", "type": "电视剧", "genre": "古装 / 爱情 / 戏说", "tags": ["宫廷", "野史", "女强", "争议"], "summary_short": "风流皇后，1992年中国香港电视剧，古装 / 爱情 / 戏说。辽景宗病逝，29岁的萧燕燕以太后身份摄政。朝中汉臣与契丹贵族争斗激烈，她为制衡各方，先后提拔了汉人韩德让、契丹猛将耶律休哥、以及一个奴隶出身的内侍三人为心腹。坊间传闻这三人都与太后有私情，史官讥讽她“风流成性”。萧燕燕从不辩解，而是利用这三股力量推行汉制、改革军事、平定叛乱。多年后，韩德让临终前问太后：“外界的传言，您真的不在乎吗？”萧燕燕答：“他们只看到了三个男人，没看到我", "score": 1992249, "category": "series", "detail_url": "../movie/1889.html", "poster": "../posters/1889.svg"}, {"id": "1890", "title": "尼尔·杨的心灵旅程", "year": 2024, "region": "加拿大 / 美国", "type": "电影 / 纪录片", "genre": "音乐 / 传记 / 公路", "tags": ["民谣摇滚", "公路", "创作心路"], "summary_short": "尼尔·杨的心灵旅程，2024年加拿大 / 美国电影 / 纪录片，音乐 / 传记 / 公路。这是一部风格化的半纪录电影，虚构了传奇音乐人尼尔·杨在退休后突发奇想，改装一辆1959年的灵车，独自驶上横穿美国的公路。他没有任何演出计划，只带了一把吉他和一台老式录音机。路上他遇到了形形色色的人：离家出走的少女、失去土地的老农场主、退伍军人。他不唱歌，只是听他们的故事，偶尔用口琴吹一段旋律。每经过一个州，他就会在废弃的谷仓或加油站录下一首新歌。暴", "score": 2024294, "category": "doc", "detail_url": "../movie/1890.html", "poster": "../posters/1890.svg"}, {"id": "1891", "title": "精神错乱", "year": 2025, "region": "美国", "type": "电影", "genre": "惊悚、心理、公路", "tags": ["路怒症、公路追杀、心理压迫、社会焦虑"], "summary_short": "精神错乱，2025年美国电影，惊悚、心理、公路。单亲妈妈瑞秋送儿子上学途中，因为前车绿灯不走按了一声喇叭。前车司机是一个穿连帽衫的男人，他下车对她平静地说：“你毁了我的早晨。我会毁了你的一生。”起初瑞秋以为是威胁，直到她发现：这个男人知道她家的地址、儿子的学校、前夫的电话，甚至她正在服用的抗焦虑药品牌。他从不直接伤害她，而是精准打击她最脆弱的部分：在儿子生日派对上叫来警察说她虐童、伪造她账号发种族歧视言论导致她失业、给她正在戒酒的前夫寄", "score": 2025342, "category": "horror", "detail_url": "../movie/1891.html", "poster": "../posters/1891.svg"}, {"id": "1892", "title": "隋唐英雄传", "year": 2025, "region": "中国大陆", "type": "动画", "genre": "历史，战争，动作", "tags": ["评书改编，少年英雄，群像"], "summary_short": "隋唐英雄传，2025年中国大陆动画，历史，战争，动作。本片以少年秦琼的视角展开。隋炀帝杨广暴政，民不聊生。秦琼因救下被陷害的李渊一家，反被奸臣杨林追杀，从此踏上逃亡之路。在旅途中，他结识了卖马的单雄信、莽撞的程咬金、冷面寒枪的罗成等一众好汉。众人被逼上瓦岗寨，竖起“反隋”大旗。动画不仅呈现了“三斧定瓦岗”、“大战四明山”等经典评书桥段，更挖掘了英雄们在权力斗争下的情感纠葛。当李密坐上瓦岗寨主之位后，内部矛盾激化，秦琼等人最终投奔李世民，", "score": 2025163, "category": "fantasy", "detail_url": "../movie/1892.html", "poster": "../posters/1892.svg"}, {"id": "1893", "title": "回旋镖", "year": 2022, "region": "韩国", "type": "电影", "genre": "犯罪 / 悬疑", "tags": ["复仇", "时间循环", "反转", "爽片"], "summary_short": "回旋镖，2022年韩国电影，犯罪 / 悬疑。前特种兵姜泰植的女儿被一个未成年人犯罪团伙残忍杀害，却因法律保护而逍遥法外。愤怒的泰植决定用自己的方式复仇。他制定了一个完美的计划，要让每一个凶手体验绝望。然而，当他成功杀死第一个凶手后，回到家中却发现自己的母亲意外去世。他认为是巧合。当他继续第二个计划时，他的妻子出了车祸。他开始意识到，每一次成功的复仇，都像回旋镖一样，会以同样惨烈的方式反馈到他亲人身上。这个“诅咒”迫使他必须停下来思考：是", "score": 2022433, "category": "crime", "detail_url": "../movie/1893.html", "poster": "../posters/1893.svg"}, {"id": "1894", "title": "爱的终结", "year": 2021, "region": "法国", "type": "电影", "genre": "剧情, 悬疑, 爱情", "tags": ["婚姻危机", "诺曼底", "心理博弈"], "summary_short": "爱的终结，2021年法国电影，剧情, 悬疑, 爱情。建筑师保罗与妻子安娜在诺曼底海边庆祝瓷婚。次日清晨，安娜独自驾车离开，只留下一个加密U盘。U盘内是九段视频，每段揭露一个由安娜精心编织的谎言：从儿子并非亲生，到保罗最佳合伙人破产的内幕。保罗必须逐帧破解视频中隐藏的坐标，沿着法国公路追寻安娜。在这场猫鼠游戏里，他逐渐意识到，所谓的“谎言”其实是一面镜子，照出了他自己二十年来对妻子的冷漠与精神霸凌。终点并非复合或离别，而是对“爱的定义”彻", "score": 2021408, "category": "romance", "detail_url": "../movie/1894.html", "poster": "../posters/1894.svg"}, {"id": "1895", "title": "太空垃圾的困扰", "year": 2024, "region": "美国", "type": "电影", "genre": "科幻 / 惊悚", "tags": ["空间站", "碎片", "生存", "太空灾难"], "summary_short": "太空垃圾的困扰，2024年美国电影，科幻 / 惊悚。近地轨道上，国际空间站正在执行例行维护任务。一块被遗漏追踪的火箭残骸以每秒7公里的速度撞穿了生活舱段。舱内瞬间失压，三名宇航员紧急封闭了受损区域，但主氧气罐被击穿，剩余氧气只够6小时。地面指挥中心给出方案：他们必须穿着舱外服，通过外部桁架爬行400米到达另一端尚完好的联盟号逃生舱。途中，通讯天线被二次碎片击中瘫痪，两名宇航员的气阀出现泄漏。他们互相拖拽着在无声的太空中缓慢移动，身后是越", "score": 2024392, "category": "sci-fi", "detail_url": "../movie/1895.html", "poster": "../posters/1895.svg"}, {"id": "1896", "title": "断肢女孩的来信", "year": 2022, "region": "韩国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["连环杀人", "信件", "复仇", "反转", "社会派"], "summary_short": "断肢女孩的来信，2022年韩国电影，悬疑 / 惊悚。2009年，首尔出现“断肢杀人魔”，六名女性被杀害后切断右手。第七名受害者朴恩珠侥幸逃生，但失去了右手，凶手则人间蒸发。十年后，警局收到一封只有三个字的信：“羽毛球”。当年负责此案的刑警老金已调去内勤，每周最爱的活动就是警察羽毛球社。他按照信中的指引，在羽毛球馆的储物柜里发现了又一截断肢——新鲜的那种。信继续寄来，每一封都指向羽毛球社的一名成员：法医、网警、局长秘书、甚至老金自己的徒弟", "score": 2022453, "category": "crime", "detail_url": "../movie/1896.html", "poster": "../posters/1896.svg"}, {"id": "1897", "title": "虽然没准备什么菜第三季", "year": 2024, "region": "韩国", "type": "综艺", "genre": "真人秀，美食，脱口秀", "tags": ["露营，深夜食堂，明星家常菜，治愈"], "summary_short": "虽然没准备什么菜第三季，2024年韩国综艺，真人秀，美食，脱口秀。本季节目组将厨房搬到了人迹罕至的深山露营地。每期一位嘉宾前来做客，必须用现场极其有限的食材（甚至包括野菜和罐头）为主持人做一道“虽没准备但凑合吃”的菜。从泡面花样吃法到用石头烤五花肉，笑料百出。而在篝火旁，明星们卸下防备，聊起出道前的落魄与心酸，食物的简陋反而衬托出情感的滚烫。", "score": 2024101, "category": "series", "detail_url": "../movie/1897.html", "poster": "../posters/1897.svg"}, {"id": "1898", "title": "狭隘", "year": 2025, "region": "韩国", "type": "电影", "genre": "惊悚, 心理, 悬疑", "tags": ["密室", "偏执", "社会隐喻", "独角戏"], "summary_short": "狭隘，2025年韩国电影，惊悚, 心理, 悬疑。宅男俊浩三年没出过房门，外卖、网购、远程工作构成全部生活。他习惯每晚敲墙壁三下确认隔壁无人，突然有一天，墙壁回敲了四下。俊浩吓坏了，连夜找房东质问，房东说那间房十年前就封死了。他开始凿墙，每次敲掉一块砖，第二天就会多出一块新的。邻居劝他搬家，俊浩却越来越兴奋——墙里那个人，是不是也社恐？是不是也从不拉开窗帘？是不是也害怕每一个敲门声？当他终于凿穿最后一层砖，看到的不是人，而是一面镜子，镜面", "score": 2025431, "category": "crime", "detail_url": "../movie/1898.html", "poster": "../posters/1898.svg"}, {"id": "1899", "title": "监警最前线粤语", "year": 2025, "region": "中国香港", "type": "剧集", "genre": "犯罪，悬疑，职场", "tags": ["监警会，内部调查，体制之恶，双面人"], "summary_short": "监警最前线粤语，2025年中国香港剧集，犯罪，悬疑，职场。督察方晴调入投诉警察课（CAPO），负责调查一起市民投诉：三名便衣在夜店涉嫌滥用私刑。她在调查过程中发现，所有证据都指向重案组一名备受尊敬的警长。然而随着问话深入，方晴察觉到投诉人本身的证词存在矛盾，且夜店的监控录像曾被一名神秘人删改。她的直属上司、CAPO 总督察莫振声始终在旁“指导”，甚至暗示她直接结案。方晴暗中调查莫振声的背景，发现他十年前曾与那名警长搭档，而警长的女儿在当", "score": 2025305, "category": "series", "detail_url": "../movie/1899.html", "poster": "../posters/1899.svg"}, {"id": "1900", "title": "悲情三角", "year": 2023, "region": "瑞典", "type": "电影", "genre": "剧情, 喜剧, 讽刺", "tags": ["阶级", "富人", "荒诞", "北欧黑色幽默"], "summary_short": "悲情三角，2023年瑞典电影，剧情, 喜剧, 讽刺。卡尔和亚雅是时尚圈知名的网红情侣，靠贩卖精致生活照维生。两人受邀登上全球最奢华的游艇，乘客全是亿万富翁、政要和科技新贵。游艇在风暴中沉没，一小群幸存者漂流至荒岛。起初，游艇上的财富和头衔依然主导着岛上的秩序，但很快，一位曾在这艘游艇上担任清洁工的菲律宾女性玛丽亚，凭借搭棚子、捕鱼、生火的技能成为新领袖。卡尔和亚雅的关系也在生存压力下迅速腐烂。当玛丽亚宣布“从今天起，谁干活谁吃饭”时，富", "score": 2023317, "category": "drama", "detail_url": "../movie/1900.html", "poster": "../posters/1900.svg"}, {"id": "1901", "title": "谜河", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "悬疑, 犯罪", "tags": ["河流", "连环失踪", "乡村记忆", "双线叙事"], "summary_short": "谜河，2024年中国大陆电影，悬疑, 犯罪。南方一条叫“谜河”的支流沿岸，流传着“水猴子抓替身”的传说。1984、1994、2004，每隔十年就有一个小孩在河里失踪，尸体从未找到。2014年，村里的大学生阿骏回家过暑假，发现自己五岁的侄子开始总往河边跑。他查阅旧报纸，访谈老人，发现三个失踪的孩子都曾说过同一句话：“河里有个人叫我下去。”更诡异的是，阿骏翻出一张2004年的合影，失踪孩子的站位与1984年那张一模一样，只是脸换了。他开始怀", "score": 2024448, "category": "crime", "detail_url": "../movie/1901.html", "poster": "../posters/1901.svg"}, {"id": "1902", "title": "15:17 巴黎列车", "year": 2024, "region": "美国", "type": "电影", "genre": "动作 / 惊悚 / 真实改编", "tags": ["反恐， 平民英雄， 实时叙事， 列车危机， 真实事件改编"], "summary_short": "15:17 巴黎列车，2024年美国电影，动作 / 惊悚 / 真实改编。美国游客安东尼、亚历克和斯宾塞正在欧洲享受背包客的毕业旅行。在阿姆斯特丹，他们临时决定前往巴黎。他们登上了15:17从阿姆斯特丹开往巴黎的列车。途中，安东尼从洗手间回来时，无意中瞥见一名男子正在隐蔽处组装自动步枪。瞬间，枪声响起，一名乘客中弹。三名年轻人在极短的对视中达成默契。在没有武器和防护的情况下，他们赤手空拳冲向持枪歹徒。安东尼率先勒住主犯的脖子将其摔倒在地，", "score": 2024428, "category": "crime", "detail_url": "../movie/1902.html", "poster": "../posters/1902.svg"}, {"id": "1903", "title": "僵尸放屁：活屎人之厕", "year": 2026, "region": "日本", "type": "电影", "genre": "恐怖喜剧", "tags": ["B级片", "丧尸", "厕所", "生化危机", "恶搞"], "summary_short": "僵尸放屁：活屎人之厕，2026年日本电影，恐怖喜剧。疯狂的生化公司“大粪制药”开发出一种新型排泄物处理细菌，旨在让人类的粪便自动分解为氧气。不料细菌发生变异，通过马桶和下水道系统感染了全城的人类。感染者不会咬人，但会不受控制地连续放出恶臭无比的“生化屁”，这种臭屁能瞬间腐蚀金属、导致农作物枯萎，并让任何闻到的人产生无法抑制的排泄冲动，最终脱水而亡。主角是一群被堵在市中心豪华商场顶层厕所里的形形色色的人：一个洁癖漫画家、一个便秘的相扑选手", "score": 2026344, "category": "horror", "detail_url": "../movie/1903.html", "poster": "../posters/1903.svg"}, {"id": "1904", "title": "地下室惊魂", "year": 2012, "region": "中国", "type": "电影", "genre": "悬疑 / 惊悚", "tags": ["地下室", "密室", "记忆", "人格分裂", "反转"], "summary_short": "地下室惊魂，2012年中国电影，悬疑 / 惊悚。心理医生叶青应邀来到一座海边别墅，为一位不愿透露姓名的富豪治疗失眠。她被安排在别墅地下室改造的客房休息。午夜时分，她醒来发现自己手脚被缚，房间里还有另外七个昏迷不醒的人。墙上用血写着倒计时：3:00。众人醒来后惊恐不已，他们发现彼此毫无关联，但每个人的左臂上都有一个相同的数字纹身。叶青身上的数字是“8”。随着倒计时推进，房间里开始播放录像，显示他们八个人曾参与过同一场非法记忆移植实验。而当", "score": 2012378, "category": "crime", "detail_url": "../movie/1904.html", "poster": "../posters/1904.svg"}, {"id": "1905", "title": "幸福骗局", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "剧情，犯罪", "tags": ["诈骗，养老，亲情，反转"], "summary_short": "幸福骗局，2023年中国大陆电影，剧情，犯罪。高智商诈骗犯阿光带领团队，专盯缺乏关爱的老年人，用“陪伴式营销”骗走他们的养老金。这一次，他们的目标是一位住在高档养老院、看似普通但据说有一大笔拆迁款的王大爷。阿光伪装成爱心志愿者，对王大爷嘘寒问暖，迅速赢得其信任。然而，在准备收网时，他意外发现王大爷竟然是他二十年前因赌气离家出走后再未谋面的亲生父亲。而王大爷早就认出了他，所有的“好骗”都是一场将计就计的“反骗”，目的是为了把误入歧途的儿子", "score": 2023380, "category": "drama", "detail_url": "../movie/1905.html", "poster": "../posters/1905.svg"}, {"id": "1906", "title": "当恶魔呼喊你的名字时", "year": 2026, "region": "韩国", "type": "剧集", "genre": "奇幻、惊悚、心理", "tags": ["七宗罪，灵魂契约，悬疑反转"], "summary_short": "当恶魔呼喊你的名字时，2026年韩国剧集，奇幻、惊悚、心理。十年前，作曲家徐正宇走投无路，与恶魔签订契约：以灵魂换取无与伦比的创作天赋。他果然一炮而红。十年后的今天，恶魔化身神秘女子“陆”来收取灵魂，却发现徐正宇已经三年写不出一个音符。不是他江郎才尽，而是他三年前在一次酒后意外中，丢失了所有关于那十年“被赐予才华”的记忆。恶魔无法收回一个“不在原主身上”的能力。于是双方达成诡异协议：恶魔帮助徐正宇找回失去的记忆（即找回自己的才华），一旦", "score": 2026389, "category": "series", "detail_url": "../movie/1906.html", "poster": "../posters/1906.svg"}, {"id": "1907", "title": "海岸共鸣", "year": 2025, "region": "日本", "type": "剧集", "genre": "悬疑 / 奇幻 / 社会", "tags": ["海边小镇，群像剧，听障视角，都市传说"], "summary_short": "海岸共鸣，2025年日本剧集，悬疑 / 奇幻 / 社会。日本海沿岸的港口小镇“琴浦”，因渔业萎靡而日渐萧条。镇上聋哑学校的五名学生，在一次海岸清理活动中，同时感受到了海底传来的诡异低频震动。这种声音只有他们能“听”到，并伴随强烈的画面——溺亡者的最后记忆。起初大人们以为这只是幻觉，直到第一具失踪多年的遗骸被冲上岸。孩子们决定组成“共鸣社”，通过手语和笔记记录每一次海底回响。他们发现，小镇近三十年的多起“意外溺亡”和“失踪案”，都指向同一", "score": 2025305, "category": "series", "detail_url": "../movie/1907.html", "poster": "../posters/1907.svg"}, {"id": "1908", "title": "乐极生悲", "year": 2022, "region": "中国", "type": "电影", "genre": "喜剧 / 犯罪", "tags": ["黑色幽默", "彩票", "绑架", "小人物"], "summary_short": "乐极生悲，2022年中国电影，喜剧 / 犯罪。老实人王德发一辈子被当成透明人。在生日那天，他买的彩票意外中了头奖五百万。他决定用这笔钱狠狠羞辱所有看不起他的人。然而他不知道的是，他家楼上住着三个欠了高利贷的笨贼，正计划绑架房东的儿子。因为王德发错拿了邻居的外卖，他的门牌号被写在了绑架纸条上。于是一个荒诞的夜晚开始了：绑架、追车、误认、反杀，当王德发终于站在KTV包厢里准备撒钱扬眉吐气时，他的裤子却被啤酒瓶炸开，露出了内裤里缝着的——那张", "score": 2022384, "category": "crime", "detail_url": "../movie/1908.html", "poster": "../posters/1908.svg"}, {"id": "1909", "title": "生为女人", "year": 2025, "region": "中国香港", "type": "电影", "genre": "剧情 / 家庭 / 女性", "tags": ["代际冲突", "自我觉醒", "计划生育", "寻根"], "summary_short": "生为女人，2025年中国香港电影，剧情 / 家庭 / 女性。在上海做律师的姚瑶突然接到父亲电话，母亲病危。回到老家小城，她发现两位姐姐早已守在床前。弥留之际的母亲交给她一本发黄的日记，里面记录了一个惊天秘密：三十年前，为了逃避计划生育政策，姚家曾“收养”了另一个被遗弃的女婴，也就是三姐妹中的一人。母亲从未说出是谁。姚瑶必须和两位姐姐一起，在照顾母亲最后时光的同时，通过日记里的蛛丝马迹，找出那个“外人”。然而随着调查深入，她们发现每个人都", "score": 2025317, "category": "drama", "detail_url": "../movie/1909.html", "poster": "../posters/1909.svg"}, {"id": "1910", "title": "燃情主厨", "year": 2023, "region": "法国", "type": "剧集", "genre": "剧情 / 美食 / 职场", "tags": ["米其林", "师徒", "复仇", "味觉天才", "法餐"], "summary_short": "燃情主厨，2023年法国剧集，剧情 / 美食 / 职场。二十年前，法国厨艺天才杰克被恩师德高乐主厨陷害，在重要晚宴的食物中下毒导致宾客中毒，杰克被逐出厨坛并失去味觉。十年后，杰克在小镇经营一家只接待熟客的地下小酒馆，靠肌肉记忆和助手试菜维持出品。一天，美食评论家“面具”意外到访并给出满分评价，杰克重燃斗志，决定挑战德高乐的三星餐厅。他召集了被德高乐打压过的洗碗工、被开除的侍酒师、以及一个拥有超强味觉但毫无经验的女学徒。师徒二人在巴黎展开", "score": 2023217, "category": "series", "detail_url": "../movie/1910.html", "poster": "../posters/1910.svg"}, {"id": "1911", "title": "怪兽婆婆", "year": 2027, "region": "韩国", "type": "剧集", "genre": "喜剧 / 恐怖 / 家庭", "tags": ["婆媳，黑色喜剧，反转，超自然"], "summary_short": "怪兽婆婆，2027年韩国剧集，喜剧 / 恐怖 / 家庭。贫家女素珍嫁入财阀家族，本以为苦尽甘来，却在婚后第一夜撞见婆婆在客厅变成一头三米高的绿色怪兽，毛发倒竖，獠牙外露。她吓得要报警，丈夫淡定地说：“别怕，妈只是在散步，这是我们家族的女性传统，过了十点就会变身。”素珍起初不信，直到她亲眼看见婆婆变身后手撕了上门讨债的高利贷。更惊悚的是，丈夫告诉她：嫁进来的媳妇也会在某一天突然变身。素珍看着自己指尖长出的绿色绒毛，决定——既然要变怪兽，那", "score": 2027319, "category": "series", "detail_url": "../movie/1911.html", "poster": "../posters/1911.svg"}, {"id": "1912", "title": "神薙", "year": 2024, "region": "日本", "type": "TV Series", "genre": "动画，奇幻，喜剧", "tags": ["神明，校园，同居，日常治愈，轻度战斗"], "summary_short": "神薙，2024年日本TV Series，动画，奇幻，喜剧。美术生直木在老家神社清理倒塌的神木时，意外放出了被封印多年的少女神“神薙”。她自称是土地神，却因为神社早已破败而失去了信仰之力，只能依附在直木家。为了重返神位，神薙决定用各种啼笑皆非的方式在人间“营业”——从开直播驱邪到帮邻居解决怪谈。然而，随着另一位神秘巫女的登场，直木发现神薙的封印背后似乎隐藏着一个关乎小镇存亡的古老阴谋。在欢笑与吵闹的同居生活中，两人逐渐揭开了千年前人神共存", "score": 2024167, "category": "series", "detail_url": "../movie/1912.html", "poster": "../posters/1912.svg"}, {"id": "1913", "title": "爱在基尔内里", "year": 2025, "region": "土耳其", "type": "电影", "genre": "剧情, 爱情", "tags": ["异国恋", "文化冲突", "小镇", "治愈"], "summary_short": "爱在基尔内里，2025年土耳其电影，剧情, 爱情。中国独立摄影师苏漫为寻找创作灵感，来到土耳其偏僻小镇基尔内里。她偶然发现一座破败东正教堂内的千年壁画，并结识了负责修复工作的本地人艾赫迈德。两人因对壁画中“爱的符号”的共同痴迷而走近。文化差异、语言障碍以及苏漫即将到期的签证，像一道道墙挡在中间。艾赫迈德用当地古老的“水写誓言”仪式表白，苏漫最终选择留下，共同修复壁画并守护这份跨越文明的爱。", "score": 2025300, "category": "romance", "detail_url": "../movie/1913.html", "poster": "../posters/1913.svg"}, {"id": "1914", "title": "拯救世界", "year": 1992, "region": "美国", "type": "电影", "genre": "喜剧，奇幻", "tags": ["穿越，摇滚，死神，爱情，搞笑"], "summary_short": "拯救世界，1992年美国电影，喜剧，奇幻。阿比和阿弟这次闯的祸更大了。由于他们在历史作业中的表现，未来的反派绑架了他们的女友和“天才”孩子。为了拯救家人和未来世界，两人必须再次踏上时空之旅。这次他们甚至闯进了天堂和地狱，和死神玩起了猜谜游戏。他们发现决定世界命运的关键，竟然是一场在预定时间、预定地点举办的乐队演出。这对活宝必须在婚礼、葬礼和拳击赛的缝隙中找到演出场地。", "score": 1992374, "category": "comedy", "detail_url": "../movie/1914.html", "poster": "../posters/1914.svg"}, {"id": "1915", "title": "逃亡纪事", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "剧情， 犯罪， 悬疑", "tags": ["世纪大盗， 追凶， 年代剧， 公路片， 心理战"], "summary_short": "逃亡纪事，2025年中国大陆剧集，剧情， 犯罪， 悬疑。1996年，东北某重刑犯监狱，外号“东北虎”的刘大彪借着暴风雪成功越狱。他心思缜密，反侦察能力极强，杀人如麻却对家人有着极深的执念。为了追捕他，年轻的刑警马骏组成专案组，从黑龙江一路追到海南。这场猫鼠游戏持续了三年。刘大彪不断更换身份，辗转于工地、矿场和黑市，他杀过黑吃黑的毒贩，也救过被拐卖的妇女。他既是个冷血的怪物，在某些时刻又像个落寞的游侠。马骏在追捕过程中，逐渐拼凑出刘大彪走", "score": 2025410, "category": "crime", "detail_url": "../movie/1915.html", "poster": "../posters/1915.svg"}, {"id": "1916", "title": "巧克力战争", "year": 2024, "region": "日本", "type": "电影", "genre": "剧情 / 校园 / 社会", "tags": ["校园霸凌，反叛，经济学，以暴制暴，道德灰色"], "summary_short": "巧克力战争，2024年日本电影，剧情 / 校园 / 社会。高二学生神谷透转学到一座工厂小镇的中学，发现学校被一群高年级生组成的“学生会”暴力统治。他们控制小卖部，垄断热销的“幸运巧克力”，倒卖赚取暴利。神谷不擅长打架，却是数学天才和金融模拟游戏冠军。他联合被欺负的弱小学生，建立地下“巧克力合作社”：利用批量采购压低进货价，用小卖部下课前三分钟的人流测算进行限时抢购，甚至发明了“巧克力代金券”作为信用货币。学生会开始暴力砸场子，神谷则录下", "score": 2024308, "category": "doc", "detail_url": "../movie/1916.html", "poster": "../posters/1916.svg"}, {"id": "1917", "title": "台城1923", "year": 2023, "region": "中国大陆", "type": "电影", "genre": "历史 / 剧情", "tags": ["民国", "小人物", "觉醒"], "summary_short": "台城1923，2023年中国大陆电影，历史 / 剧情。1923年冬，河北台城。豆腐坊伙计石头最大的愿望就是攒钱给娘看病。一个风雪夜，重伤的地下党员老周将一只铁盒托付给他，要求务必送到隔壁县城。石头不知道铁盒里是至关重要的党内文件，只知道因为这只盒子，警察、军阀、洋人都在追杀他。他推着豆腐车，在冰天雪地里开始了一场惊心动魄的送信之旅。一路上，他看到了底层人民的悲惨，也看到了像老周一样宁死不屈的战士。当他终于到达目的地，将铁盒交到接头人手中", "score": 2023303, "category": "drama", "detail_url": "../movie/1917.html", "poster": "../posters/1917.svg"}, {"id": "1918", "title": "壹号皇庭5国语", "year": 1997, "region": "香港", "type": "电视剧 (30集)", "genre": "律政 / 剧情", "tags": ["经典TVB", "律师群像", "职业剧", "粤语配音国语版"], "summary_short": "壹号皇庭5国语，1997年香港电视剧 (30集)，律政 / 剧情。延续《壹号皇庭》系列。新人律师余在春加入香港最顶级的律所“壹号皇庭”，他的上司是业界传奇——大律师陈卓尧。余在春很快发现，陈卓尧正是十年前导致他父亲冤狱的关键检察官。尽管父亲最终被平反，但已在狱中病逝。余在春选择隐瞒身份，留在律所一边学习一边寻找陈卓尧违规办案的证据。然而随着合作加深，他发现陈卓尧当年也是被真凶误导，且多年来一直暗中资助冤狱家属。师徒二人在一桩跨境洗黑钱案", "score": 1997274, "category": "series", "detail_url": "../movie/1918.html", "poster": "../posters/1918.svg"}, {"id": "1919", "title": "木乃伊魔咒", "year": 2026, "region": "埃及", "type": "电影", "genre": "冒险, 恐怖", "tags": ["古埃及", "盗墓", "诅咒"], "summary_short": "木乃伊魔咒，2026年埃及电影，冒险, 恐怖。在埃及沙漠深处，一支由国际盗墓者组成的队伍，发现了无名法老的墓穴。他们不顾当地人的警告，强行打开了封印的石棺。被释放的并非腐烂的木乃伊，而是祭司的幽灵“卡”。他没有直接杀死闯入者，而是施加了更残酷的诅咒——“永生惩罚”。每个盗墓者都将轮回10次，每次死亡后重生，在短暂的“休息”后立即进入下一段更痛苦的死亡：从被圣甲虫啃噬、被黄金掩埋、到被蛇群缠绕窒息，每一次死亡都是古埃及最残酷刑罚的复现。为", "score": 2026359, "category": "horror", "detail_url": "../movie/1919.html", "poster": "../posters/1919.svg"}, {"id": "1920", "title": "红色小队", "year": 2024, "region": "俄罗斯", "type": "电影", "genre": "战争 / 动作", "tags": ["二战、狙击手、兄弟情、牺牲"], "summary_short": "红色小队，2024年俄罗斯电影，战争 / 动作。1945年，柏林战役前夕。一支代号“红色”的六人狙击小队奉命占领工厂制高点。任务成功后，电台传来命令：他们中间有一名叛徒，已泄露苏军进攻路线。队长决定就地审讯，但还没开口，两名队员被狙杀。子弹来自工厂内部。剩余四人互相猜忌、对峙、火并，最后只剩队长和一名新兵。新兵坦白自己是叛徒，但他是被德军俘虏后被迫合作的，家人还在对方手上。队长放下枪，说：“那就一起活下去。”", "score": 2024272, "category": "doc", "detail_url": "../movie/1920.html", "poster": "../posters/1920.svg"}, {"id": "1921", "title": "文学奖杀人事件 大助跑", "year": 2026, "region": "日本", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["本格推理", "文学圈", "暴风雪山庄"], "summary_short": "文学奖杀人事件 大助跑，2026年日本电影，悬疑 / 犯罪。日本“大助跑文学奖”五位最终入围者受邀前往深山别墅，参加颁奖前夜的“写作切磋会”。第二天清晨，大门被从外部锁死，通讯中断。第一个失踪者是推理小说家，他的房间里凭空出现一本名为《溺亡》的手稿，内容详细描写了他被按入浴缸的过程。三小时后，他的尸体在浴缸中被发现，死法完全一致。剩余四人惊恐地发现，手稿陆续出现，每一本都预演了下一位死者的结局。而署名处的作者名，是他们所有人的笔迹拼接而", "score": 2026367, "category": "crime", "detail_url": "../movie/1921.html", "poster": "../posters/1921.svg"}, {"id": "1922", "title": "27套礼服", "year": 2008, "region": "美国", "type": "电影", "genre": "喜剧, 爱情", "tags": ["伴娘", "剩女", "婚礼", "暗恋", "姐妹"], "summary_short": "27套礼服，2008年美国电影，喜剧, 爱情。完美主义者和“永远伴娘”珍一直暗恋着公司老板乔治。她善良到不懂得拒绝，做过27次伴娘，衣柜里挂满了各种颜色的伴娘礼服。就在她准备向乔治表白时，她的妹妹苔丝从洛杉矶回来，用虚假的温柔和共同的兴趣爱好迅速勾引了乔治，两人宣布订婚。更崩溃的是，苔丝要求珍做她的伴娘。珍的“第28套”礼服是荧光绿。在筹备婚礼的过程中，一名婚礼专栏记者凯文发现了珍“27次伴娘”的奇闻，开始跟踪报道。凯文一开始觉得珍可怜", "score": 2008370, "category": "romance", "detail_url": "../movie/1922.html", "poster": "../posters/1922.svg"}, {"id": "1923", "title": "北京女子图鉴之整容大师", "year": 2025, "region": "中国大陆", "type": "网剧", "genre": "都市, 剧情", "tags": ["女性成长", "容貌焦虑", "职场"], "summary_short": "北京女子图鉴之整容大师，2025年中国大陆网剧，都市, 剧情。林晓是北京整形界的“第一刀”，专攻高难度修复手术。她信奉“完美主义”，无论是手术还是生活。然而，当她的丈夫——一个五官科的教授，脸上出现了一道她无法修复的裂痕时，她的事业与婚姻同时亮起红灯。在工作中，她面对形形色色的顾客：为了男友整容的少女、为了求职割双眼皮的程序员、为了留住丈夫的妻子。林晓用技术满足了他们的愿望，却在他们术后空洞的眼神里看到了自己的影子。当丈夫离她而去，她终", "score": 2025092, "category": "series", "detail_url": "../movie/1923.html", "poster": "../posters/1923.svg"}, {"id": "1924", "title": "狂野的印第安人", "year": 2024, "region": "美国", "type": "电影", "genre": "西部 / 心理惊悚", "tags": ["边界复仇，身份谜团，荒野求生"], "summary_short": "狂野的印第安人，2024年美国电影，西部 / 心理惊悚。十九世纪末，美国西部。独行枪手“蓝狐”以残酷手法连续刺杀多名前骑兵队军官。每次杀戮后，他都会在现场留下一枚印第安图腾硬币。军方派出老练侦探霍拉斯追踪，却发现“蓝狐”的足迹诡谲多变，仿佛不受物理规则限制。追捕过程中，霍拉斯从一名被俘的原住民口中得知，“蓝狐”可能是某个被屠杀村落中唯一幸存的婴儿，但记忆错乱。最终在亡灵山对峙时，“蓝狐”扯下面罩，镜中映出的是一张浅色皮肤、蓝色眼睛的脸—", "score": 2024324, "category": "crime", "detail_url": "../movie/1924.html", "poster": "../posters/1924.svg"}, {"id": "1925", "title": "逃脱", "year": 2025, "region": "韩国", "type": "电影", "genre": "动作， 惊悚， 犯罪", "tags": ["越狱， 孤岛， 监狱岛， 无人机， 逃亡"], "summary_short": "逃脱，2025年韩国电影，动作， 惊悚， 犯罪。一座地图上不存在的岛屿，岛上是一所私人运营的“终极监狱”，关押的都是被权贵送进去的“消失的人”。前海军特种兵出身的高贤宇因知道太多财阀秘密被秘密关押至此。岛上没有围墙——因为岛四周是暗礁和鲨鱼群，涨潮时全岛会被淹没一半。高贤宇用了两年时间研究潮汐表、洋流方向、无人机送货路线和守卫换班规律。他拉拢了三个狱友：一个黑客、一个气象员和一个老渔民。逃脱夜，他利用每月一次的大潮和无人机送货时的信号盲", "score": 2025496, "category": "crime", "detail_url": "../movie/1925.html", "poster": "../posters/1925.svg"}, {"id": "1926", "title": "墨玉太极", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "动作 / 奇幻 / 武侠", "tags": ["道家文化，阴阳太极，神秘玉佩，现代与古武"], "summary_short": "墨玉太极，2026年中国大陆电影，动作 / 奇幻 / 武侠。阿宅程序员林逸偶然淘到一块古旧墨玉，上面刻有太极图案。深夜，他被吸入一个阴阳交界之地，被告知自己是道家“守玉人”的后裔。墨玉即将失衡，届时阴阳两界混乱，而他是唯一能通过修炼“真·太极”来重新封印玉中煞气的人。但留给他的时间只有三十天。在古怪的阴间老道和一只话痨猫妖的指导下，林逸白天写代码，晚上在阴阳两界闪转腾挪，对抗从墨玉中逃逸的各种魑魅魍魉。当商业巨头企图夺取墨玉用于邪恶目的", "score": 2026373, "category": "crime", "detail_url": "../movie/1926.html", "poster": "../posters/1926.svg"}, {"id": "1927", "title": "莫斯科行动", "year": 2025, "region": "中国大陆, 俄罗斯", "type": "电影", "genre": "动作, 犯罪, 悬疑", "tags": ["跨国追捕", "倒爷", "硬核动作", "真实事件改编"], "summary_short": "莫斯科行动，2025年中国大陆, 俄罗斯电影，动作, 犯罪, 悬疑。1993年，中俄国际列车大劫案震惊世界。为了不给外交造成麻烦，中国警方秘密组建了一支代号“莫斯科行动”的特遣队。刑警队长林峰伪装成贩卖羽绒服的倒爷登上了K3次列车。他不知道，真正的匪首“赵老大”已经渗透到了莫斯科华人市场的每一个角落，并且与当地黑帮“灰狼帮”勾结。林峰在追查一箱丢失的账本时，被自己的线人出卖，深陷废弃的兵工厂。在零下四十度的暴雪中，他不得不拿起铁锹和改锥", "score": 2025457, "category": "crime", "detail_url": "../movie/1927.html", "poster": "../posters/1927.svg"}, {"id": "1928", "title": "顽童历险记", "year": 2024, "region": "美国", "type": "电影", "genre": "剧情 / 冒险", "tags": ["成长， 荒野， 友情， 生存"], "summary_short": "顽童历险记，2024年美国电影，剧情 / 冒险。十二岁的马可被送入暑期行为矫正营，却与另外三个格格不入的少年结伴逃脱。他们偷来一艘旧木筏，决定沿着密西西比河漂流去追寻各自想象中的“自由彼岸”。起初是游泳、钓鱼和星空下的狂欢，但随着深入三角洲流域，他们撞见了一个被当地成年人刻意隐藏的非法倾倒场，还意外录下了关键证据。一面是追来的营地教官与心怀鬼胎的地方警长，一面是逐渐建立的信任与脆弱的友谊，几个孩子必须在河流涨潮前做出选择：是继续逃向虚无", "score": 2024311, "category": "drama", "detail_url": "../movie/1928.html", "poster": "../posters/1928.svg"}, {"id": "1929", "title": "嗜血派对", "year": 2009, "region": "美国", "type": "电影", "genre": "恐怖 / 惊悚", "tags": ["密室", "病毒感染", "派对灾难", "生存游戏"], "summary_short": "嗜血派对，2009年美国电影，恐怖 / 惊悚。六名大学好友为庆祝生日租下一栋郊区别墅。午夜时分，一名女生突然疯狂咬向身边人，被咬者在五秒内同样发狂。派对瞬间变成斗兽场。剩下的四人躲进地下室，发现手机没信号、门窗被封死。他们翻出别墅的旧相册，发现十年前这里发生过完全一样的惨案。当最后两人找到密道逃出别墅时，天已经亮了，整个街区异常安静。他们走进街道，所有人都站在原地，慢慢转过头……", "score": 2009385, "category": "horror", "detail_url": "../movie/1929.html", "poster": "../posters/1929.svg"}, {"id": "1930", "title": "明星伙伴 第四季", "year": 2007, "region": "美国", "type": "剧集", "genre": "喜剧， 剧情", "tags": ["好莱坞， 娱乐圈， 兄弟情， 客串明星"], "summary_short": "明星伙伴 第四季，2007年美国剧集，喜剧， 剧情。第四季中，超级明星文斯·蔡斯不再满足于做演员，决定执导一部关于好莱坞黄金时代的文艺片。他的经纪人埃里克首次担任制片人，两人因艺术和商业的冲突多次差点拆伙。Turtle尝试开一家自己的龙舌兰酒公司，而Drama为争取一个严肃角色不惜自毁形象。这一季客串明星包括马丁·斯科塞斯、彼得·伯格等真实导演。整个团队在资金断裂、演员罢演、影评人嘲讽的危机中，挣扎着要完成文斯的导演梦。", "score": 2007245, "category": "series", "detail_url": "../movie/1930.html", "poster": "../posters/1930.svg"}, {"id": "1931", "title": "一路向暖", "year": 2020, "region": "中国大陆", "type": "电视剧集", "genre": "剧情， 家庭， 治愈", "tags": ["春运， 返乡， 群像剧， 现实主义， 温情"], "summary_short": "一路向暖，2020年中国大陆电视剧集，剧情， 家庭， 治愈。临近春节，一列从北京开往湘西的高铁因突降暴雪被迫停靠在无名小站。车厢内，有衣锦还乡却害怕面对催婚的白领，有带绝症妻子去实现最后一个愿望的退休教师，有被亲生父母抛弃后独自寻亲的少女，有因为创业失败不敢回家的程序员，还有一位偷偷跟着农民工父亲去打工地的留守儿童。原本冷漠疏离的陌生人，在长达三十六个小时的被困时间里，被迫卸下伪装。一节小小的车厢成了流动的舞台，上演着当代中国家庭最真实", "score": 2020258, "category": "series", "detail_url": "../movie/1931.html", "poster": "../posters/1931.svg"}, {"id": "1932", "title": "小岛风云粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "剧情, 犯罪, 动作", "tags": ["黑帮", "卧底", "离岛"], "summary_short": "小岛风云粤语，2024年中国香港剧集，剧情, 犯罪, 动作。香港大屿山附近的某个离岛，表面是渔村风光，实则是东南亚黑帮的洗钱枢纽。警方派遣资深卧底“阿鬼”潜入当地最大的社团，该社团控制了岛上的所有码头和赌场。就在阿鬼即将摸清资金流向的关键时刻，社团少主突然从国外归来，并且带来了一个让所有人自危的命令：清除内鬼。一时间，岛上的风吹草动都成了生死考验。阿鬼不仅要面对社团的追杀，还要保护不知情的女友。当台风席卷小岛，所有的罪恶都将被吹开，迎来", "score": 2024313, "category": "crime", "detail_url": "../movie/1932.html", "poster": "../posters/1932.svg"}, {"id": "1933", "title": "超级整蛊霸王国语", "year": 2024, "region": "中国香港", "type": "电影", "genre": "喜剧, 奇幻", "tags": ["恶作剧", "外星人", "许愿", "校园"], "summary_short": "超级整蛊霸王国语，2024年中国香港电影，喜剧, 奇幻。校霸“钢炮”靠收保护费横行霸道。某天他捡到一只会说话的仓鼠，自称“整蛊星”逃犯，能用超能力实现任何恶作剧（比如把校长内裤变成榴莲）。钢炮利用它惩治了所有看他不顺眼的人，成了校园英雄。但他厌倦了这种生活，许愿让自己变成人见人爱的三好学生。结果整蛊星球的警察来了，因为“善良”在整蛊星是重罪，他们要把钢炮抓走。更离谱的是，全校同学为了救他，不得不反过来学习如何整蛊他，让他重新变坏。一场“", "score": 2024364, "category": "comedy", "detail_url": "../movie/1933.html", "poster": "../posters/1933.svg"}, {"id": "1934", "title": "在桃花盛开的地方", "year": 2023, "region": "中国大陆", "type": "电视剧", "genre": "年代、家庭、剧情", "tags": ["乡村振兴、三代人、乡愁、变迁"], "summary_short": "在桃花盛开的地方，2023年中国大陆电视剧，年代、家庭、剧情。故事从1959年开始，桃花村因饥荒人烟稀少，少女桃妹被许给外乡木匠刘德厚，换回一袋红薯。两人搭起茅屋，在荒坡种下第一棵桃树。八十年代，女儿刘芳进城打工，成了第一批“外来妹”，被城里人骗财骗色后回乡办起第一个个体桃胶厂。千禧年后，孙子刘小军考上清华，毕业后放弃高薪，回村搞乡村旅游和电商直播，与保守的父亲激烈冲突。2019年，桃花村成了网红打卡地，刘小军却因过度商业化导致水源污染", "score": 2023214, "category": "series", "detail_url": "../movie/1934.html", "poster": "../posters/1934.svg"}, {"id": "1935", "title": "享受吧！罗马", "year": 2025, "region": "意大利", "type": "电影", "genre": "喜剧, 爱情, 剧情", "tags": ["美食", "疗愈", "喷泉许愿", "人生重启"], "summary_short": "享受吧！罗马，2025年意大利电影，喜剧, 爱情, 剧情。米其林餐厅主厨李薇在婚礼当天发现未婚夫出轨，她抢走了婚宴上的烤鸭逃往罗马。在许愿池边，她为了捡一枚硬币跌入水中，被当地一位开不起眼小餐馆的老爷爷救起。老爷爷曾是顶尖大厨，却因不肯改良传统菜式而被遗忘。李薇用中餐烹饪技巧改良了意大利传统菜，比如“松露酱配北京烤鸭意面”。这引起了米其林评审员的注意。正当她重拾信心时，前未婚夫带着新欢来罗马捣乱，偷走了她的秘方。最终决赛在台伯河上的游船", "score": 2025373, "category": "drama", "detail_url": "../movie/1935.html", "poster": "../posters/1935.svg"}, {"id": "1936", "title": "炎神战队轰音者", "year": 2025, "region": "日本", "type": "剧集", "genre": "特摄，动作", "tags": ["超级战队，环保，热血"], "summary_short": "炎神战队轰音者，2025年日本剧集，特摄，动作。近未来，人类无节制的污染产生了七种恶意的“公害能量”，这些能量让日常机械拥有了生命和邪念，自称“七罪机神”，意图净化人类。就在地球陷入绝望时，五位来自不同地区的垃圾回收员被远古的“炎神”选中，获得了驾驶特殊回收车辆的能力。他们分别是：轰音红（垃圾压缩车）、轰音蓝（污水处理车）、轰音黄（废气净化车）、轰音绿（噪音吸收车）、轰音黑（重金属回收车）。五辆战车可以合体为巨大的“炎神轰音王”。他们不", "score": 2025255, "category": "series", "detail_url": "../movie/1936.html", "poster": "../posters/1936.svg"}, {"id": "1937", "title": "海底娇娃蓝华：处女任务", "year": 2023, "region": "日本", "type": "电影/动画", "genre": "科幻/动作/冒险", "tags": ["机甲少女", "深海作战", "反叛军", "军事科幻"], "summary_short": "海底娇娃蓝华：处女任务，2023年日本电影/动画，科幻/动作/冒险。2147年，地球表面已不适合生存，人类迁入海底都市“波塞冬”。军事组织“深渊”控制了所有能源，各卫星城只能仰其鼻息。蓝华是“深海娇娃”计划培养的第三代机甲驾驶员，她和她的粉色人形机甲“伶盗龙-7”从未参加过实战。第一次任务，就是潜入深渊总部所在的马里亚纳要塞，取回被扣押的反物质引擎——那是让卫星城获得能源独立的关键。蓝华和队友（一只会开潜艇的章鱼、一个社恐黑客少女、一个", "score": 2023394, "category": "fantasy", "detail_url": "../movie/1937.html", "poster": "../posters/1937.svg"}, {"id": "1938", "title": "师声对决", "year": 2026, "region": "中国台湾", "type": "电影", "genre": "剧情，音乐，运动", "tags": ["阿卡贝拉，师生对抗，代际和解，校园社团"], "summary_short": "师声对决，2026年中国台湾电影，剧情，音乐，运动。曾带领大学合唱团蝉联三届冠军的铁血教练老郭，因为坚持纯人声、不允许任何流行改编，与追求创新的团长小A爆发了不可调和的冲突。在一次公演前，全体团员投票罢免了老郭，这让把一生奉献给合唱团的老郭彻底崩溃。沉寂一年后，老郭竟然组建了一支由落榜生、留级生和保洁阿姨组成的“杂牌军”，用他最看不起的B-BOX和电子效果器，报名参加了同一届阿卡贝拉大赛。当昔日的师徒在决赛舞台狭路相逢，他们所要击败的不", "score": 2026326, "category": "doc", "detail_url": "../movie/1938.html", "poster": "../posters/1938.svg"}, {"id": "1939", "title": "密弑游戏2：胜者危亡", "year": 2026, "region": "美国", "type": "电影", "genre": "惊悚, 悬疑, 动作", "tags": ["密室逃脱", "生死博弈", "人性考验", "反转"], "summary_short": "密弑游戏2：胜者危亡，2026年美国电影，惊悚, 悬疑, 动作。前作的幸存者们刚刚回归正常生活，便集体收到一封神秘邀请函，对方以家人性命要挟他们重返“密弑游戏”。这一次的场地是一座废弃的智能科技大厦，每通关一层，队伍中就必须投票处决一人。旧日的盟友开始互相猜忌，有人试图破解系统，有人暗中结盟。随着人数减少，他们发现幕后操控者竟是上一轮某位“已死”玩家的亲属，目的是为了揭露这场残酷直播背后的全球权贵网络。最终两人抵达顶层，面对的却是一个开", "score": 2026471, "category": "crime", "detail_url": "../movie/1939.html", "poster": "../posters/1939.svg"}, {"id": "1940", "title": "家庭负担", "year": 2022, "region": "丹麦", "type": "电影", "genre": "剧情, 家庭, 社会", "tags": ["北欧", "社会福利", "中年危机", "照护", "冰冷现实"], "summary_short": "家庭负担，2022年丹麦电影，剧情, 家庭, 社会。护工伊娃是丹麦福利系统里的一颗螺丝钉。她专业、高效、充满同情心地照顾着养老院里的老人。但她下班后，必须赶回家照顾因患早期阿兹海默症而被社区踢出名单的父亲——因为预算削减，父亲被判定“尚未严重到需要全托”。她每天游走在“职业”与“私人”照护的边界，直到精神崩溃。在一个暴风雪的夜晚，她把父亲偷偷带回了养老院，让他住进刚去世老人的空床。第二天，上级检查，伊娃在同事面前微笑着介绍“新来的老人”", "score": 2022282, "category": "drama", "detail_url": "../movie/1940.html", "poster": "../posters/1940.svg"}, {"id": "1941", "title": "迷宫物语", "year": 1989, "region": "日本", "type": "动画电影", "genre": "奇幻 / 悬疑 / 实验", "tags": ["超现实主义", "多重叙事", "迷路", "梦境逻辑", "大师短篇集"], "summary_short": "迷宫物语，1989年日本动画电影，奇幻 / 悬疑 / 实验。改编自村上春树短篇。第一部“奔跑的女孩”：小学女生在上学路上钻进一条工地隧道，却发现出口永远是同一堵红砖墙；第二部“士兵的迷宫”：二战逃兵躲入山洞，洞内的分岔路会随他的呼吸变化；第三部“矿工与钟”：老矿工挖到一块会“哼歌”的矿石，矿道开始长出手臂一样的支路。三人在各自迷宫的终点同时推开一扇门，进入一个圆形大厅，墙上刻着同一句话：“外面也是迷宫。”片尾，女孩回到学校操场，同学们说", "score": 1989419, "category": "fantasy", "detail_url": "../movie/1941.html", "poster": "../posters/1941.svg"}, {"id": "1942", "title": "少妇多愁", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "剧情 / 爱情 / 文艺", "tags": ["女性", "心理", "抑郁", "出轨", "台北"], "summary_short": "少妇多愁，2023年中国台湾电影，剧情 / 爱情 / 文艺。年轻的全职太太敏敏住在台北一栋老公寓里，丈夫长期出差，她独自带着婴儿，被严重的产后抑郁和重复的家务劳动所吞噬。唯一能让她心灵平静的，是客厅里一幅祖母留下的清代仕女图。某天疲惫至极时，她竟发现画中的书生走出来了。书生不懂现代电器，却懂得倾听她的孤独。敏敏知道这是幻觉，但她沉迷于此。当丈夫带着女同事回家，并打算送她去精神病院时，敏敏对着画纸轻声说了一句“带我走吧”。第二天，丈夫发现", "score": 2023360, "category": "drama", "detail_url": "../movie/1942.html", "poster": "../posters/1942.svg"}, {"id": "1943", "title": "日安忧郁", "year": 2023, "region": "法国", "type": "电影", "genre": "剧情", "tags": ["文艺", "孤独", "女性"], "summary_short": "日安忧郁，2023年法国电影，剧情。三十岁的巴黎画廊职员安娜过着双面人生：白天是策展天才，晚上是失眠的忧郁症患者。她发明了一个仪式，每天起床第一件事，对镜子里那个陌生的自己说“日安，忧郁”。当新来的实习生莉拉住进她家，安娜的规律被打破。莉拉身上那种自然的快乐既吸引她又刺痛她。两人关系逐渐亲密，安娜却因害怕被看穿而故意搞砸莉拉的转正机会。莉拉离开后，安娜的忧郁彻底失控。最终她在塞纳河边找到莉拉道歉，莉拉说：“你不需要治愈，你只需要停止假装", "score": 2023312, "category": "drama", "detail_url": "../movie/1943.html", "poster": "../posters/1943.svg"}, {"id": "1944", "title": "爱情短片", "year": 2025, "region": "波兰", "type": "电影", "genre": "剧情， 爱情", "tags": ["偷窥， 孤独， 道德困境"], "summary_short": "爱情短片，2025年波兰电影，剧情， 爱情。十九岁的邮差托梅克每日的工作结束后，唯一的爱好就是用一架老旧的望远镜观察对面公寓楼里的一位成熟女艺术家。他熟知她每一个习惯，甚至伪造了汇款单只为接近她。当他终于鼓起勇气表白，却遭到了女艺术家的嘲笑和戏弄。极度失望之下，托梅克做出了一个极端的举动，导致自己住进了医院。令人意想不到的是，这位看似冷酷的女艺术家开始真正关注起这个男孩，她发现自己竟然无法对他的决绝行为无动于衷。影片通过两个孤独灵魂的相", "score": 2025359, "category": "drama", "detail_url": "../movie/1944.html", "poster": "../posters/1944.svg"}, {"id": "1945", "title": "红犬历险记", "year": 2025, "region": "澳大利亚", "type": "电影", "genre": "剧情， 冒险， 家庭", "tags": ["真实故事改编， 边境牧羊犬， 西部荒漠， 人狗情深， 流浪与归途"], "summary_short": "红犬历险记，2025年澳大利亚电影，剧情， 冒险， 家庭。故事改编自西澳大利亚皮尔巴拉地区流传的真实传说。1970年代，在一座偏远的小镇丹皮尔，一只红色的澳洲牧羊犬不知从哪里流浪而来。它不属于任何人，却属于所有人。它会跳上任何一辆卡车，跟不同的矿工回家，但从不在一张床上睡超过三天。每个人都说这只狗是在“寻找”什么。年轻的地质勘探员约翰是少数不被红狗喜欢的人，直到他在一场车祸中救了红狗一命。从此红狗认定了他，一改流浪习性，整天跟在约翰身后", "score": 2025287, "category": "drama", "detail_url": "../movie/1945.html", "poster": "../posters/1945.svg"}, {"id": "1946", "title": "少女救地球", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻，动作", "tags": ["末世，萝莉战士，机甲，硬核科幻"], "summary_short": "少女救地球，2026年美国电影，科幻，动作。2157年，月球成为流放宇宙重刑犯的监狱。17岁的艾可在这里出生、长大，是唯一继承了狱警基因的“狱二代”。她每天的任务就是通过远程系统监控那些沉睡在冷冻舱中的恶棍。一场史无前例的太阳风暴摧毁了月球的通讯和防御系统，冷冻舱开始陆续失效。艾可必须在48小时内，将监狱里最危险的三个囚犯（一个基因变异的雇佣兵、一个精通精神控制的教主、一个能操纵金属的机械狂魔）押送到一艘即将报废的穿梭机上。她穿着一身老", "score": 2026427, "category": "sci-fi", "detail_url": "../movie/1946.html", "poster": "../posters/1946.svg"}, {"id": "1947", "title": "迪克切尼眼中的世界", "year": 2022, "region": "美国", "type": "电影", "genre": "传记 / 政治 / 剧情", "tags": ["政治讽刺", "副总统", "权力暗箱", "反英雄", "伪纪录片"], "summary_short": "迪克切尼眼中的世界，2022年美国电影，传记 / 政治 / 剧情。本片以伪纪录片形式，虚构了美国前副总统迪克·切尼退休后接受一个纪录片团队跟拍的“真实记录”。切尼的偏光墨镜被设定为一种隐喻：透过镜片，他能看到普通人看不到的“裂缝”——恐怖分子、敌对国、甚至国会里的异见者，都被他视为美国体制的松动螺丝。影片穿插他回忆的真实事件（伊拉克战争、能源政策）与完全虚构的“补拍场景”：他在自家猎场里用弓箭射标靶，每个标靶上贴着不同政客的照片；他在深", "score": 2022320, "category": "doc", "detail_url": "../movie/1947.html", "poster": "../posters/1947.svg"}, {"id": "1948", "title": "阿根廷正义审判", "year": 2026, "region": "阿根廷", "type": "电影", "genre": "剧情 / 历史 / 犯罪", "tags": ["政治惊悚，军事独裁，法律剧，真实事件改编"], "summary_short": "阿根廷正义审判，2026年阿根廷电影，剧情 / 历史 / 犯罪。影片根据真实事件改编。1982年，阿根廷军政府时期，怀孕8个月的玛丽亚被秘密警察“医生”埃米利奥扔进拉普拉塔河。2025年，“医生”隐姓埋名在布宜诺斯艾利斯郊区养老，因老年痴呆症发作，对着护士喃喃自语当年罪行。一位女记者偷录了音频，全网发起“辨认刽子手”行动。一位名叫尼古拉斯的渔民站了出来，他当年被渔民从河里救起，是个早产儿——玛丽亚在坠河时分娩，婴儿奇迹生还。尼古拉斯通过", "score": 2026372, "category": "crime", "detail_url": "../movie/1948.html", "poster": "../posters/1948.svg"}, {"id": "1949", "title": "五等分的新娘第一季", "year": 2019, "region": "日本", "type": "剧集", "genre": "动画 / 喜剧 / 爱情", "tags": ["后宫", "校园", "恋爱喜剧", "学霸", "五胞胎"], "summary_short": "五等分的新娘第一季，2019年日本剧集，动画 / 喜剧 / 爱情。成绩优异却生活拮据的上杉风太郎，接到了一份报酬丰厚的兼职：担任即将毕业的五胞胎姐妹的家庭教师，确保她们顺利升入高中。这五姐妹——一花、二乃、三玖、四叶、五月——性格迥异，且都对学习极度抗拒，成绩惨不忍睹。风太郎最初只是想拿钱办事，却逐渐被她们各自的魅力与烦恼所牵动。一花的成熟伪装、二乃的傲娇锋芒、三玖的腼腆执着、四叶的元气自卑、五月的认真倔强，让风太郎焦头烂额。他用各种奇", "score": 2019347, "category": "series", "detail_url": "../movie/1949.html", "poster": "../posters/1949.svg"}, {"id": "1950", "title": "不要小看我", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "喜剧 / 剧情 / 家庭", "tags": ["老人", "尊严", "代际冲突", "逆袭", "温情"], "summary_short": "不要小看我，2026年中国大陆电影，喜剧 / 剧情 / 家庭。退休锅炉工老方头今年72岁，老伴去世后搬去和儿子同住。儿子儿媳把他当小孩看：手机换成老年机、不许爬楼梯、每天吃软烂食物、午睡时间都要规定。老方头用藏私房钱的方式偷偷买了智能手机，在公园看年轻人跳街舞时被一个64岁的“年轻”老头拉进老年街舞队。他发现队员里有人是退休外科医生（偷偷给穷人在家做小手术）、有人是前京剧武生（还在练功）、有人是老年痴呆早期（跳舞时就不糊涂）。他们一起报", "score": 2026368, "category": "drama", "detail_url": "../movie/1950.html", "poster": "../posters/1950.svg"}, {"id": "1951", "title": "世上最蓝的海", "year": 2026, "region": "意大利/法国", "type": "电影", "genre": "剧情/同性", "tags": ["文艺", "海岛", "禁忌之恋", "悲剧美学"], "summary_short": "世上最蓝的海，2026年意大利/法国电影，剧情/同性。身患ALS（渐冻症）的风景画家亚历克斯搬到了撒丁岛一个与世隔绝的海湾，想在这里体面地结束生命。他每天在悬崖边作画，记录下那片令他绝望又痴迷的蔚蓝。年轻渔民马蒂亚斯在一次风暴中救起了试图溺水的亚历克斯，并发现了他的秘密。两个孤独的灵魂在碧蓝的海水中相互试探。马蒂亚斯不顾宗教与世俗的眼光，执意闯入了亚历克斯的最后时光。他们在一个废弃的灯塔里同居，随着亚历克斯的肌肉逐渐僵硬，马蒂亚斯变成了", "score": 2026251, "category": "drama", "detail_url": "../movie/1951.html", "poster": "../posters/1951.svg"}, {"id": "1952", "title": "黑吃黑第四季", "year": 2026, "region": "美国", "type": "电视剧", "genre": "犯罪, 剧情, 惊悚", "tags": ["暴力", "复仇", "小镇", "人性"], "summary_short": "黑吃黑第四季，2026年美国电视剧，犯罪, 剧情, 惊悚。延续前作，女妖镇迎来史上最大危机。联邦调查局因一名探员失踪而盯上了这个小镇，而芝加哥的意大利黑手党为了追查一批失踪的黄金，也派人渗透进来。胡德虽然成功洗白成为镇长，但他过去的盟友和敌人纷纷回归。凯特为了女儿不得不再次拿起屠刀；舒格的老战友带来一个关于黄金的惊天秘密；而一个神秘的连环杀手开始模仿胡德当年的手法作案，试图将一切嫁祸给他。本季中，胡德必须在FBI的眼皮底下周旋于三方势力", "score": 2026366, "category": "series", "detail_url": "../movie/1952.html", "poster": "../posters/1952.svg"}, {"id": "1953", "title": "萝拉", "year": 2027, "region": "法国", "type": "电影", "genre": "剧情、文艺", "tags": ["女性独白、未亡人、小镇秘事、非线性叙事"], "summary_short": "萝拉，2027年法国电影，剧情、文艺。在法国西北部的渔村，萝拉的丈夫在一次风暴中失踪。七年来，她每天清晨都会带着一束干花走到码头，坐在那张空长椅上，直到日落。村民们从同情变成不解，最后变成敌意——因为他们觉得萝拉的等待让死去的人无法安息。萝拉不辩解，只是继续等。直到某个浓雾的早晨，萝拉没有出现。代替她坐在长椅上的，是一个从没见过海的巴黎男人。他声称自己是萝拉的情人，受她之托来此“等待她自己”。而萝拉，此刻正站在丈夫失踪的那艘船的甲板上，", "score": 2027296, "category": "drama", "detail_url": "../movie/1953.html", "poster": "../posters/1953.svg"}, {"id": "1954", "title": "朱门情仇", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "年代 / 家族 / 悬疑", "tags": ["民国豪门", "宅斗", "灭门案", "养女复仇"], "summary_short": "朱门情仇，2025年中国大陆剧集，年代 / 家族 / 悬疑。1928年，江南丝绸大亨朱府一夜灭门，只有7岁的养女阿蘅躲在井中逃过一劫。十五年后，阿蘅化名阿蘖进入新主人沈府做丫鬟，因为当年朱家的产业已全部被沈家吞并，而沈老爷就是当年收养她的人。阿蘖在沈府小心翼翼地收集证据，发现当年灭门案涉及三家人：沈家、警察局长、以及朱家的大管家。她在沈府地窖里找到朱家当年的账本，账本显示朱老爷一直在资助革命党，而沈老爷是向日本人走私鸦片的中间人，朱老爷", "score": 2025274, "category": "series", "detail_url": "../movie/1954.html", "poster": "../posters/1954.svg"}, {"id": "1955", "title": "狂琴畸恋", "year": 1997, "region": "法国", "type": "电影", "genre": "剧情, 爱情, 惊悚", "tags": ["禁忌之恋", "音乐家", "心理扭曲", "浪漫惊悚"], "summary_short": "狂琴畸恋，1997年法国电影，剧情, 爱情, 惊悚。天才大提琴演奏家简·杜雅尔丹在车祸中失去了爱妻和双手。他用仿生机械手恢复演奏后，却患上了严重的心理疾病，认为只有完美的人体曲线才能发出最完美的琴声。他收养了孤儿玛丽，从小就对她进行严苛的肌肉训练和体态矫正，把她的背部和肋骨的曲线，按照斯特拉迪瓦里大提琴的模型改造。玛丽长大后，简不再满足于对空气演奏，他开始在玛丽的身体上拉弦。这种极端的行为产生了不可思议的音质——玛丽的骨骼共振发出了非人", "score": 1997439, "category": "drama", "detail_url": "../movie/1955.html", "poster": "../posters/1955.svg"}, {"id": "1956", "title": "血洒无名街", "year": 2024, "region": "中国香港", "type": "电影", "genre": "动作, 犯罪, 剧情", "tags": ["硬核警匪", "兄弟情义", "困兽之斗", "九龙城寨风"], "summary_short": "血洒无名街，2024年中国香港电影，动作, 犯罪, 剧情。卧底警察“老鼠”跟了毒枭八年，终于拿到证据可以归队。上级约他在“无名街”街尾的茶餐厅见面，递交身份恢复文件。当晚，老鼠走进这条熟悉的老街，卖鱼蛋的大婶、修鞋的大爷、开锁的小哥、甚至路边乞讨的瘸子，都对他露出诡异的笑。枪声从街尾响起，第一个要杀他的是茶餐厅老板，因为老鼠曾害死了老板的儿子。老鼠必须从街尾杀到街头，穿过整条埋伏着几百个仇家的街道，才能活着拿到那份证明他依然是“警察”的", "score": 2024420, "category": "crime", "detail_url": "../movie/1956.html", "poster": "../posters/1956.svg"}, {"id": "1957", "title": "克里夫兰秀第四季", "year": 2012, "region": "美国", "type": "动漫", "genre": "喜剧 / 动画 / 成人向", "tags": ["恶搞", "美式动画", "家庭", "种族梗", "无厘头"], "summary_short": "克里夫兰秀第四季，2012年美国动漫，喜剧 / 动画 / 成人向。在经历了《恶搞之家》的剧情之后，善良但有点木讷的克里夫兰带着儿子搬回了老家弗吉尼亚州的斯特普尔顿，住进了他学生时代的旧房子。在这里，他遇到了高中时暗恋的胖女孩唐娜，并迅速重组了一个复杂的家庭：唐娜带来了一个毒舌的女儿和一个永远躲在树上的继子，而克里夫兰的父亲是一位脾气暴躁的老顽童。第四季中，克里夫兰试图在唐娜的强势和朋友的怂恿中寻找平衡。他那个拥有熊一样体格的超龄儿子依然", "score": 2012158, "category": "fantasy", "detail_url": "../movie/1957.html", "poster": "../posters/1957.svg"}, {"id": "1958", "title": "乱世丽人行", "year": 2025, "region": "中国大陆", "type": "剧集", "genre": "战争 / 女性 / 历史", "tags": ["抗日战争", "女护士", "战地医院", "姐妹情"], "summary_short": "乱世丽人行，2025年中国大陆剧集，战争 / 女性 / 历史。1937年11月，南京。金陵女子学院医学预科班的四位女学生——大家闺秀苏丽、贫民孤儿小翠、华侨归来的苏茜和教会养大的春丽——本已拿到西撤的船票，但她们实习的鼓楼医院接到命令：最后一批伤员必须在三天内全部转移。四位女生选择留下，跟随医院西撤武汉。撤退途中，她们经历了轰炸、断粮、伤寒爆发和无数次与日军小队的遭遇战。一开始她们只敢躲，后来学会用手术刀捅哨兵，用绷带勒侦察兵，用吗啡过", "score": 2025200, "category": "series", "detail_url": "../movie/1958.html", "poster": "../posters/1958.svg"}, {"id": "1959", "title": "侬本多情粤语", "year": 2024, "region": "中国香港", "type": "剧集", "genre": "爱情、剧情、年代", "tags": ["民国， 商战， 粤语， 虐恋"], "summary_short": "侬本多情粤语，2024年中国香港剧集，爱情、剧情、年代。当红歌女白牡丹从昏迷中醒来，失去了所有记忆，只记得自己深爱着一个叫“阿杰”的男人。此时，经营丝绸生意的孪生兄弟詹慕杰和詹慕豪同时出现在她面前，都自称是她的爱人。弟弟慕杰温柔细心，是留洋归来的设计师；哥哥慕豪张扬霸道，掌管家族生意。白牡丹被迫住在詹府，在两个男人之间寻找记忆的碎片。随着她逐渐“恢复”记忆，她引导兄弟反目，导致詹家产业被竞争对手蚕食。就在慕杰决定带她私奔的那个雨夜，白牡", "score": 2024282, "category": "series", "detail_url": "../movie/1959.html", "poster": "../posters/1959.svg"}, {"id": "1960", "title": "男孩生活2", "year": 2026, "region": "法国", "type": "剧集", "genre": "剧情， 同性， 青春", "tags": ["青春期， 身份认同， 小镇， 法式浪漫， 成长"], "summary_short": "男孩生活2，2026年法国剧集，剧情， 同性， 青春。第一季结尾，卢卡斯和艾利一起坐上了前往巴黎的火车。本季讲述他们在巴黎的生活：卢卡斯进入了电影学院，艾利则成了一名实习律师。城市虽大，但两人却发现彼此的生活节奏越来越不同。卢卡斯在拍短片时与男主角产生暧昧，而艾利则被父母逼迫与一个女孩相亲。与此同时，他们来自小镇的好友纷纷来到巴黎，带来旧的秘密和新的麻烦。一次大吵后，两人短暂分开。最终，在一个雨夜，卢卡斯拿着自己剪辑的、记录了他们两年生", "score": 2026221, "category": "series", "detail_url": "../movie/1960.html", "poster": "../posters/1960.svg"}, {"id": "1961", "title": "群英夺宝", "year": 2026, "region": "中国大陆", "type": "电影", "genre": "动作, 喜剧", "tags": ["夺宝", "传国玉玺", "民国", "相声"], "summary_short": "群英夺宝，2026年中国大陆电影，动作, 喜剧。民国十三年，紫禁城乱成一锅粥。耍大刀的老马带着女儿小翠在天桥卖艺，无意间捡到了一个被太监丢弃的包袱，里面竟是传国玉玺。消息走漏后，军阀张大帅派出憨批副官，小朝廷的遗老派出毒舌太监，日本商会派出忍者女秘书，三路人马围追堵截。老马和小翠利用天桥十八般武艺（胸口碎大石、拉洋片、相声砸挂）与各路高手斗智斗勇。他们不要皇权，只想用玉玺跟张大帅换回被强占的天桥地皮。最后抢夺战中，玉玺被小翠当板砖拍碎了", "score": 2026346, "category": "comedy", "detail_url": "../movie/1961.html", "poster": "../posters/1961.svg"}, {"id": "1962", "title": "愿为女人", "year": 2021, "region": "印度", "type": "电影", "genre": "剧情、社会、女性", "tags": ["性别互换、父权讽刺、禁忌之舞、宗教压迫"], "summary_short": "愿为女人，2021年印度电影，剧情、社会、女性。北印度村庄，村长普拉塔普是种姓制度的忠实捍卫者，禁止女人识字、骑自行车、单独出门。他最爱说的口头禅是：“女人就该待在家里。”一夜暴雨后，普拉塔普醒来发现自己变成了女人。他以为这是幻觉，却不得不面对女儿的月经、儿媳的厨房劳役、以及自己被老公毒打的风险。他想主持村务，却被男人们以“女人不能讲话”赶出去。他想去清真寺，却被拒之门外。走投无路的他只能混入女性私密空间，头一次听到妻子们如何在背后嘲笑", "score": 2021294, "category": "drama", "detail_url": "../movie/1962.html", "poster": "../posters/1962.svg"}, {"id": "1963", "title": "杜立德", "year": 2024, "region": "美国", "type": "电影", "genre": "奇幻", "tags": ["兽医", "动物语言", "反英雄", "黑色幽默", "冒险"], "summary_short": "杜立德，2024年美国电影，奇幻。本片彻底解构经典童话。杜立德医生确实能与动物对话，但他没有用这项能力行医，而是带着他的动物团伙——一只掌握贵族情场的鹦鹉、一只偷听过国王计划的渡鸦、一只看到过地下钱庄账本的老鼠——专门勒索上流社会。他让鸽子收集政要的偷情照片，让猫潜入银行保险库。直到有一天，他试图勒索一个看似普通的男爵夫人，却发现这个女人是个比他还狠的连环杀手，而她养的猫告诉杜立德：“主人下一个要杀的人，就是你。”杜立德第一次发现，知道", "score": 2024304, "category": "fantasy", "detail_url": "../movie/1963.html", "poster": "../posters/1963.svg"}, {"id": "1964", "title": "小上校", "year": 2024, "region": "美国", "type": "电影", "genre": "家庭 / 剧情 / 战争", "tags": ["儿童", "南北战争", "历史", "成长"], "summary_short": "小上校，2024年美国电影，家庭 / 剧情 / 战争。1863年，南北战争激战正酣。6岁的艾米莉随身为北方军军官的父亲来到南方的一座小镇。因为她的“北方佬”身份，她遭受了所有同龄孩子的排挤和敌视。但艾米莉天性乐观、勇敢，她不顾危险去救治受伤的南方士兵，用真诚的心打动了顽固的南方将军爷爷。当一支南方游击队试图处决她的父亲时，艾米莉穿上自己缝制的“小上校”军装，独自一人站在两军之间，用稚嫩的声音请求双方放下仇恨。她的勇敢震撼了所有人，一场流", "score": 2024301, "category": "drama", "detail_url": "../movie/1964.html", "poster": "../posters/1964.svg"}, {"id": "1965", "title": "慈膳救援", "year": 2024, "region": "中国大陆", "type": "电视剧", "genre": "现实题材", "tags": ["公益食堂", "社区", "温情", "志愿者", "剩食"], "summary_short": "慈膳救援，2024年中国大陆电视剧，现实题材。上海老城区，“慈膳食堂”因为亏损面临拆迁。社工小乔在最后关头拉来六个爱搞美食短视频的大学生志愿者，他们提出一个疯狂计划：不买新食材，只用菜市场当天卖不掉的“剩食”和餐厅捐赠的边角料，每天做出一套限定套餐，并全程直播。奇迹般地，食堂火了。但很快，一家网红连锁餐厅的主厨以“食品安全”为由向监管部门举报，一场关于食物浪费、商业利益与社区尊严的较量，在后厨和舆论场上同时展开。", "score": 2024193, "category": "series", "detail_url": "../movie/1965.html", "poster": "../posters/1965.svg"}, {"id": "1966", "title": "魔法电波", "year": 2018, "region": "美国", "type": "电影", "genre": "喜剧, 奇幻, 爱情", "tags": ["超自然", "电台", "愿望成真", "都市奇幻", "轻松治愈"], "summary_short": "魔法电波，2018年美国电影，喜剧, 奇幻, 爱情。电台实习生小周无意间修复了一台二战时期的老式发射器，却发现这台机器发出的电波具有“言灵”效应——听到广播的人，脱口而出的下一句话会立即成真。起初只是一些玩笑：“我希望隔壁咖啡机爆炸”，结果咖啡机真的炸了。很快，整个城市陷入疯狂。有人许愿中彩票，有人诅咒老板秃头，甚至有人随口说“希望地球停下”导致短暂的物理混乱。小周必须和暗恋的新闻主播艾米一起，在政府特工赶到前关掉机器，同时还要应对自己", "score": 2018449, "category": "romance", "detail_url": "../movie/1966.html", "poster": "../posters/1966.svg"}, {"id": "1967", "title": "三七日", "year": 2021, "region": "韩国", "type": "电影", "genre": "恐怖, 民俗", "tags": ["产后恐惧", "婴灵", "韩国萨满", "母性诅咒", "密室"], "summary_short": "三七日，2021年韩国电影，恐怖, 民俗。敏静产后21天，按照韩国传统，丈夫请来巫师为新生儿做“三七祭”，防止婴灵在魂魄未稳时被邪物勾走。但当晚，巫师暴毙，留下一句“它就在屋里”。敏静开始看到本应纯洁的婴儿身上出现了成年男人的影子。丈夫认为是产后抑郁，将她锁在家中。随着第七天、第十四天、第二十一天逼近，敏静发现这座老宅曾是一个巫女的处所，而自己腹中的双胞胎只活下来一个——另一个孩子的怨恨，正通过她的身体喂养着一个古老的恶鬼。真相揭晓时，", "score": 2021377, "category": "horror", "detail_url": "../movie/1967.html", "poster": "../posters/1967.svg"}, {"id": "1968", "title": "断了气", "year": 1960, "region": "法国", "type": "电影", "genre": "剧情 / 爱情 / 犯罪", "tags": ["法国新浪潮", "让-吕克·戈达尔", "存在主义", "跳切"], "summary_short": "断了气，1960年法国电影，剧情 / 爱情 / 犯罪。米歇尔是一个活在电影里的男人。他从巴黎偷了一辆车，在去往马赛的乡间公路上被警察追捕，慌乱中开枪打死了对方。他逃到马赛，找到了前一天在街头邂逅的美国女孩帕特丽夏。帕特丽夏在马赛卖《纽约先驱论坛报》，同时梦想成为真正的演员。她不知道米歇尔是杀人犯，只是觉得这个总在抽烟、总在自言自语、总在模仿亨弗莱·鲍嘉的男人很有趣。两人在马赛的公寓里度过了三天，做爱、争吵、聊福克纳和莫扎特。帕特丽夏最终", "score": 1960414, "category": "drama", "detail_url": "../movie/1968.html", "poster": "../posters/1968.svg"}, {"id": "1969", "title": "悬案密码4：64号病历", "year": 2018, "region": "丹麦", "type": "电影", "genre": "悬疑 / 犯罪", "tags": ["冷案调查", "北欧 noir", "医疗黑幕", "女性迫害"], "summary_short": "悬案密码4：64号病历，2018年丹麦电影，悬疑 / 犯罪。哥本哈根老房改造中，工人砸开一堵墙，发现三具呈坐姿的干尸，围着一张桌子，桌上放着一份发霉的“64号病历”。悬案组接手调查，发现病历来自一所1970年代的少女管教所，专门收容“行为不端”的女性——其实就是未婚先孕、精神病或女同性恋者。档案显示，64号病人名叫妮娜，当年被强行绝育后失踪。活着的唯一证人，竟是组内法医的祖母。她当年是管教所的护士，目睹了无数女孩被当作“社会垃圾”处理。", "score": 2018365, "category": "crime", "detail_url": "../movie/1969.html", "poster": "../posters/1969.svg"}, {"id": "1970", "title": "熊家餐馆第四季", "year": 2026, "region": "美国", "type": "剧集", "genre": "剧情，喜剧", "tags": ["美食，家庭，治愈，最终季"], "summary_short": "熊家餐馆第四季，2026年美国剧集，剧情，喜剧。第四季是最终季。熊家餐馆经过前三季的挣扎，终于拿到了米其林一星，并成为芝加哥最难预定的餐厅。卡米终于不再为账单发愁，但新的问题出现了：他开始尝不出味道。任何食物在他嘴里都像纸一样。对于一个厨师，这比失去双手更可怕。他瞒着所有人，靠肌肉记忆和精确到秒的计时器继续做菜。与此同时，里奇结了婚，悉尼收到了顶级餐厅的挖角，而餐馆楼上的老房东去世了，把整栋楼留给了他们。卡米在味觉消失的过程中，反而开始", "score": 2026310, "category": "series", "detail_url": "../movie/1970.html", "poster": "../posters/1970.svg"}, {"id": "1971", "title": "轻薄莲花", "year": 2023, "region": "中国", "type": "电影", "genre": "爱情 / 古装", "tags": ["青楼，替身，虐恋，反套路，女性"], "summary_short": "轻薄莲花，2023年中国电影，爱情 / 古装。秦淮河畔头牌歌女沈轻莲被当朝九王爷花万金赎身，整个京城都以为她飞上枝头。然而大婚当晚，王爷却让她穿上另一个女人的衣裳，叫她另一个名字。沈轻莲发现自己的眉眼、身段甚至嗓音都是被刻意培养成白月光的模样。她没有哭闹，而是表面上扮演着完美替身，暗中却找到了江湖第一易容师，计划在三个月后的中秋宴上当众撕下人皮面具，露出完全不同的另一张脸，让王爷永远失去“她”。影片充满了女性觉醒的隐喻。", "score": 2023278, "category": "romance", "detail_url": "../movie/1971.html", "poster": "../posters/1971.svg"}, {"id": "1972", "title": "伦敦夜生活", "year": 2023, "region": "英国", "type": "电影", "genre": "剧情 / 爱情", "tags": ["都市", "迷惘", "邂逅", "成长"], "summary_short": "伦敦夜生活，2023年英国电影，剧情 / 爱情。28岁的华裔女孩Lin白天是金融城分析师，夜晚却沉迷于东区地下电子乐俱乐部。她与英国男孩Sam在霓虹灯下建立了“不谈过去、不问将来”的暧昧关系。当Sam的真实身份——一个逃避家族破产的贵族后裔暴露，Lin发现自己也并非纯粹寻找刺激，而是用夜生活填补文化认同的裂痕。两人在一次药物过量意外后被迫分开冷静，最终在泰晤士河畔的清晨重逢。他们选择不再扮演夜店里的角色，而是以真实姓名和过往，尝试一段始", "score": 2023352, "category": "drama", "detail_url": "../movie/1972.html", "poster": "../posters/1972.svg"}, {"id": "1973", "title": "憨豆先生的大灾难", "year": 2026, "region": "英国", "type": "电影", "genre": "喜剧，灾难，家庭", "tags": ["憨豆，英式幽默，核电站，乌龙，全球直播"], "summary_short": "憨豆先生的大灾难，2026年英国电影，喜剧，灾难，家庭。为省钱，英国一家老旧核电站将保安工作外包给最便宜的临时工中介。憨豆先生上岗第一天，夜班只有他一个人。他先是把监控屏幕当成游戏机，然后把控制室当成厨房热咖啡，期间不小心启动了紧急冷却系统、倒挂了反应堆状态灯、用拖把卡住了警报器的齿轮。凌晨三点，他发现了那个盖着玻璃罩的红色按钮，旁边贴着“绝对不要按”。憨豆思考了零点五秒。第二天早上，半个英国陷入停电，苏格兰上空出现诡异极光，首相不得不", "score": 2026259, "category": "comedy", "detail_url": "../movie/1973.html", "poster": "../posters/1973.svg"}, {"id": "1974", "title": "灰鸽子之歌", "year": 1960, "region": "苏联", "type": "电影", "genre": "战争 / 剧情", "tags": ["二战", "游击队", "黑白", "诗意", "儿童视角"], "summary_short": "灰鸽子之歌，1960年苏联电影，战争 / 剧情。1943年白俄罗斯，德军清剿游击队时烧毁了小村庄“灰谷”。八岁男孩阿廖沙在外采蘑菇躲过一劫。他唯一的亲人是临死前爷爷塞给他的一只灰鸽子，以及一句话：“找到森林里的人，鸽子会带路。”阿廖沙带着鸽子走进被炮火摧毁的森林，遇到同样失散的孤儿、受伤的苏军士兵、伪装成农民的德奸。鸽子多次救他：用翅膀扑打引开巡逻兵、在雪地里指引方向。最终阿廖沙找到游击队，但鸽子在最后一场遭遇战中被打死。队长告诉他：灰", "score": 1960246, "category": "drama", "detail_url": "../movie/1974.html", "poster": "../posters/1974.svg"}, {"id": "1975", "title": "一切过后", "year": 2026, "region": "美国", "type": "剧集", "genre": "剧情 / 灾难", "tags": ["末日", "重建", "人性实验", "慢热"], "summary_short": "一切过后，2026年美国剧集，剧情 / 灾难。一颗名为“忒弥斯”的陨石被预测将在72小时后撞击纽约。全球陷入恐慌，暴乱、自杀、告解、强暴、抢劫在每座城市上演。但在倒计时最后1秒，陨石被未知引力弹走，一切安然无恙。然而，“一切过后”，社会无法回到原状。剧集聚焦五个普通人：趁乱杀了丈夫的妻子、在直播中否认上帝存在的主教、抛弃孩子独自逃命的母亲、发布假避难所信息骗财的网红、以及按下核按钮却被证明是误判的总统。他们试图重建生活，但全社会都拒绝原", "score": 2026251, "category": "series", "detail_url": "../movie/1975.html", "poster": "../posters/1975.svg"}, {"id": "1976", "title": "死亡幻觉2", "year": 2009, "region": "美国", "type": "电影", "genre": "科幻 / 悬疑 / 惊悚", "tags": ["续集", "时空", "原罪", "宗教", "黑暗"], "summary_short": "死亡幻觉2，2009年美国电影，科幻 / 悬疑 / 惊悚。承接第一部的世界观，但故事发生在一个新的平行宇宙。少女科里一直做噩梦，梦见一个巨大的兔人告诉她“时间即将终结”。她发现自己患有一种罕见的偏头痛，每当疼起来，就能看到一条由“死水”构成的、通往未来的线。一个自称“资深者”的男人告诉她：她是一个“活体接收器”，她的存在本身就在腐蚀这个宇宙。要拯救世界，她必须在28天内，杀死那个在原宇宙中已经死亡、却因她而“活过来”的人——她的亲生父亲", "score": 2009543, "category": "crime", "detail_url": "../movie/1976.html", "poster": "../posters/1976.svg"}, {"id": "1977", "title": "震撼教育", "year": 2001, "region": "美国", "type": "电影", "genre": "惊悚", "tags": ["犯罪", "警匪", "人性", "黑暗", "金像"], "summary_short": "震撼教育，2001年美国电影，惊悚。年轻警察杰克第一天到洛杉矶警局报到，被分配到传奇警探阿隆佐手下。阿隆佐带他“体验真实的街头”：先是勒令混混滚出街区，接着追捕毒贩，但手段却充满暴力与越界。杰克觉得不对劲，却不敢质疑。深夜，阿隆佐突然闯入一名已退休黑帮老大家中，抢走大量现金，并强迫杰克开枪射杀了一名试图救人的毒贩。杰克崩溃，阿隆佐这才露出真面目：他早已是黑警，今天带杰克出来，是为了找人顶罪和当“挡箭牌”。阿隆佐甚至设计让黑帮追杀杰克。走", "score": 2001280, "category": "crime", "detail_url": "../movie/1977.html", "poster": "../posters/1977.svg"}, {"id": "1978", "title": "驱魔警察", "year": 2025, "region": "中国香港", "type": "电影", "genre": "动作, 恐怖, 奇幻", "tags": ["灵幻", "僵尸", "警匪", "港味怀旧", "茅山术"], "summary_short": "驱魔警察，2025年中国香港电影，动作, 恐怖, 奇幻。油麻地发生多起离奇咬人事件，监控显示袭击者面色青黑、力大无穷，如同僵尸。重案组警探马军不信鬼神，正准备按暴力伤人案调查时，一个穿着背心拖鞋、拿着罗盘的大叔阿来闯入封锁线，声称凶手是中了“南洋降头”的活死人。马军把阿来当成疯子赶走，却发现所有科学手段都失效了：子弹打不死，手铐铐不住。无奈之下，马军只能跟着阿来学艺。阿来教他用甩棍摆阵，用手机APP测阳气。随着调查深入，他们发现这背后是", "score": 2025478, "category": "crime", "detail_url": "../movie/1978.html", "poster": "../posters/1978.svg"}, {"id": "1979", "title": "如火的魂灵", "year": 2024, "region": "中国大陆", "type": "电影", "genre": "剧情， 传记， 运动", "tags": ["摔跤， 父女， 乡村， 热血， 逆袭"], "summary_short": "如火的魂灵，2024年中国大陆电影，剧情， 传记， 运动。天生右腿萎缩的林小雪，在父亲鼓励下秘密训练摔跤。为参加县级比赛，她剪去长发假扮男生混入镇中学男子队。面对队员的歧视和身体极限，她将愤怒化为力量，独创“借力锁技”。决赛中身份暴露，全场哗然，她却当场卸下假肢，用单腿站立完成最后一击。这不是体育励志片，而是一个关于“残缺即另一种圆满”的东方哲学寓言。", "score": 2024252, "category": "doc", "detail_url": "../movie/1979.html", "poster": "../posters/1979.svg"}, {"id": "1980", "title": "巴黎妓院回忆录", "year": 2011, "region": "法国", "type": "电影", "genre": "剧情 / 历史 / 女性", "tags": ["妓院", "世纪末", "女性群像", "压抑", "真实事件改编"], "summary_short": "巴黎妓院回忆录，2011年法国电影，剧情 / 历史 / 女性。影片聚焦1900年巴黎蒙马特一家名为“天堂”的高级妓院。老板娘精明冷酷，手下的妓女们各有命运：玛德琳想攒钱开面包店，却被客人传染梅毒；波琳被贵族包养后遭抛弃，回到妓院已是半疯；朱莉怀了客人的孩子，被逼强行堕胎险些丧命；年迈的艾玛只能接最底层的客人。她们之间有嫉妒、背叛，也有仅存的温情——比如偷偷给一个瘫痪妓女过生日。外部社会在变化：警察突击检查、女权演说家上门宣传、医学教材用", "score": 2011231, "category": "drama", "detail_url": "../movie/1980.html", "poster": "../posters/1980.svg"}, {"id": "1981", "title": "恶魔与少女", "year": 2017, "region": "西班牙", "type": "电影", "genre": "恐怖, 心理惊悚, 剧情", "tags": ["宗教驱魔", "反转", "邪教", "童年阴影"], "summary_short": "恶魔与少女，2017年西班牙电影，恐怖, 心理惊悚, 剧情。资深驱魔神父托马斯接到求助，为16岁少女艾琳娜驱魔。艾琳娜的症状极其严重：漂浮、倒立、说着古老的阿拉姆语，甚至能预知死亡。托马斯发现，艾琳娜体内的恶魔对他异常熟悉，知道他不为人知的过去——十年前他曾因失误导致一名女孩死亡。随着驱魔仪式的深入，托马斯惊恐地发现，这个恶魔并非普通邪灵，而是他十年前害死的那个女孩怨念所化。它附身在艾琳娜身上，是为了向托马斯复仇。最后，托马斯选择献祭自", "score": 2017404, "category": "horror", "detail_url": "../movie/1981.html", "poster": "../posters/1981.svg"}, {"id": "1982", "title": "拳王争霸战", "year": 2025, "region": "美国", "type": "电影", "genre": "动作, 运动", "tags": ["拳击", "复仇", "励志"], "summary_short": "拳王争霸战，2025年美国电影，动作, 运动。拳手凯文当年被诬陷杀人时，距离金腰带只有一场比赛。十年后洗清冤屈出狱，世界早已变样：教练死了，女友嫁了，身体废了。但他发现当年真正杀人的黑帮头目，如今正是地下拳赛的幕后老板。凯文没有报警，而是以45岁“高龄”报名参赛——奖金是其次，他要在全城赌徒面前，一拳一拳打穿那个人的骄傲。训练过程极其惨烈：胫骨裂了接着跑，肋骨断了缠着绑带上台。决赛夜，当他把黑帮头目的侄子KO在地后，转身走向观战席上的仇", "score": 2025309, "category": "crime", "detail_url": "../movie/1982.html", "poster": "../posters/1982.svg"}, {"id": "1983", "title": "花心梦里人", "year": 2026, "region": "中国香港", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["都市情感", "渣男成长", "轻松喜剧"], "summary_short": "花心梦里人，2026年中国香港电影，爱情 / 喜剧。阿俊是香港最专业的“时间管理大师”，靠着对每个女友的伪装游刃有余。一场意外昏迷后，他醒来发现自己获得了“共情超能力”——他能一秒体验到每个女友的喜怒哀乐，甚至能同时看到七个不同角度的世界。前一刻还在陪空姐看日落，后一秒就感受到会计师被甲方折磨的崩溃。这种感同身受的折磨让他痛不欲生，曾经的花言巧语全都变成了良心谴责。为了摆脱这种痛苦，他必须让七个女孩都真心实意地对他说出“我不再爱你”，并", "score": 2026399, "category": "romance", "detail_url": "../movie/1983.html", "poster": "../posters/1983.svg"}, {"id": "1984", "title": "男子高中生的日常 真人版", "year": 2024, "region": "日本", "type": "电影", "genre": "喜剧, 校园", "tags": ["真人化", "无厘头", "青春", "中二病"], "summary_short": "男子高中生的日常 真人版，2024年日本电影，喜剧, 校园。经典动漫首次真人化！电影完全遵循原作精神，以章回体形式呈现男子高中生那些无可救药的愚蠢与纯真。故事围绕主角三人组展开：为了显得受欢迎而假装跟妹妹说话，结果妹妹根本不存在；在河边捡到一根木刀就自认是剑豪，跑去挑战隔壁女高的“风纪番长”；为了在女生面前耍帅而发明了尴尬到脚趾抠地的“内裤大头套”。电影在保留原作无厘头笑点的同时，加入了毕业前的原创篇章：当三人终于意识到这些无聊的日子终", "score": 2024308, "category": "comedy", "detail_url": "../movie/1984.html", "poster": "../posters/1984.svg"}, {"id": "1985", "title": "鉴证实录", "year": 2019, "region": "中国", "type": "电视剧", "genre": "悬疑 / 犯罪 / 法医", "tags": ["女法医", "冷案重启", "连环凶杀", "物证推理", "师徒搭档"], "summary_short": "鉴证实录，2019年中国电视剧，悬疑 / 犯罪 / 法医。省厅法医林星在复检物证时，从一桩旧案的证物袋里提取到不属于任何当事人的第三人的DNA。而那桩案——1994年“雨夜断头案”——已由当时的“神探”老宋锁定凶手并执行死刑。林星找到退休后患阿尔茨海默症的老宋，他记不得家人，却能一字不差背出当年的卷宗。随着调查深入，林星发现老宋当年可能被人利用了“完美证据链”。而唯一能翻案的关键，竟藏在老宋办公室那个没人敢打开的、挂着锁的旧物柜里。", "score": 2019307, "category": "series", "detail_url": "../movie/1985.html", "poster": "../posters/1985.svg"}, {"id": "1986", "title": "冬之日", "year": 2026, "region": "俄罗斯", "type": "电影", "genre": "剧情， 战争", "tags": ["二战， 苏联， 雪原， 狙击手"], "summary_short": "冬之日，2026年俄罗斯电影，剧情， 战争。1942年冬，斯大林格勒已成废墟。年轻的女医护兵安娜在战场上只救人不杀人，她坚信自己双手不该沾染鲜血。当她的狙击手未婚夫被德军王牌射手“幽灵”猎杀后，安娜被仇恨和悲痛吞噬，主动申请转岗为狙击手。在零下30度的雪原废墟中，没有任何狙击经验安娜在老教官的魔鬼训练下，仅用两周就掌握了远超常人的射击技巧——因为她太了解这片土地的每一块砖瓦，也太了解一个狙击手的猎杀逻辑。安娜与“幽灵”在废弃的工厂和居民", "score": 2026279, "category": "drama", "detail_url": "../movie/1986.html", "poster": "../posters/1986.svg"}, {"id": "1987", "title": "小岛奇谭", "year": 2028, "region": "日本", "type": "动画电影", "genre": "奇幻/冒险", "tags": ["治愈", "夏日", "妖怪"], "summary_short": "小岛奇谭，2028年日本动画电影，奇幻/冒险。内向的小学生小悟被母亲送到濑户内海的一座孤岛度暑假。他发现这座岛上生活着各种各样的“岛灵”——它们是废弃神社的守护者、生锈自动贩卖机的精灵、以及一棵会说方言的老榕树。岛民们看不见它们，但小悟因为纯净的心能看到。地质学家外婆告诉小悟，由于海平面上升，这座岛将在三年内被淹没。岛灵们非常悲伤，它们决定举办一场盛大的“告别祭典”，唤醒沉睡的海神，试图让岛屿升起来。祭典当晚，小悟吹响了外婆年轻时的海螺", "score": 2028347, "category": "fantasy", "detail_url": "../movie/1987.html", "poster": "../posters/1987.svg"}, {"id": "1988", "title": "冰宫", "year": 2024, "region": "挪威", "type": "电视剧", "genre": "悬疑 / 剧情 / 惊悚", "tags": ["北欧 noir， 雪山， 女性视角， 失踪谜案， 心理惊悚"], "summary_short": "冰宫，2024年挪威电视剧，悬疑 / 剧情 / 惊悚。在北极圈内的“冰宫”酒店，一场富豪婚礼正在举行。当新郎揭开新娘的头纱时，头纱下空无一人。由于暴风雪，所有通讯中断，包括新郎在内的150名宾客被困酒店。私家侦探艾拉伪装成宾客参加婚礼，她受雇于新娘的母亲。调查发现，新娘在失踪前曾给艾拉发过一条加密信息：“这里的每个人都在撒谎”。艾拉逐一审问伴娘、新郎的合伙人、酒店经理和厨师。每个人似乎都有秘密：有人欠下巨债，有人与新娘有私情，有人则是冒", "score": 2024385, "category": "series", "detail_url": "../movie/1988.html", "poster": "../posters/1988.svg"}, {"id": "1989", "title": "复活她", "year": 2024, "region": "韩国", "type": "电影", "genre": "科幻 / 悬疑", "tags": ["意识上传", "伦理困境", "科技惊悚", "爱情悲剧"], "summary_short": "复活她，2024年韩国电影，科幻 / 悬疑。顶尖AI科学家道贤无法接受妻子秀珍的突然离世。他利用秘密项目技术，将秀珍生前的所有社交记录、脑电波数据上传到人形机器人中。“她”回来了，完美复刻了秀珍的语气和习惯，甚至更加体贴温柔。但道贤逐渐感到恐惧：机器人妻子从不生气，从不质疑他，永远围着他转。他开始怀疑，自己复活的到底是一个灵魂，还是一个根据他喜好定制的“完美妻子”。当他试图关闭她时，“她”露出了一个秀珍绝对不会有的微笑，低声说：“你不是", "score": 2024407, "category": "crime", "detail_url": "../movie/1989.html", "poster": "../posters/1989.svg"}, {"id": "1990", "title": "小镇疑云 第二季", "year": 2025, "region": "英国", "type": "剧集", "genre": "悬疑, 犯罪, 剧情", "tags": ["小镇", "连环杀人", "记者", "陈年旧案"], "summary_short": "小镇疑云 第二季，2025年英国剧集，悬疑, 犯罪, 剧情。五年前，轰动英国的“威尔士小镇少年失踪案”在记者安娜的推动下告破，凶手是看似老实的图书管理员。五年后，安娜因该案获得普利策奖，成为全国知名记者。当她带着纪录片团队重回小镇拍摄“案后特辑”时，新的失踪案发生了，作案手法与五年前一模一样。小镇居民恐慌不已，警方第一时间逮捕了刚出狱的帮凶。但安娜通过对比新旧案件的细节，发现了致命的矛盾：模仿犯不可能知道只有真凶才知道的作案细节。她开始", "score": 2025408, "category": "series", "detail_url": "../movie/1990.html", "poster": "../posters/1990.svg"}, {"id": "1991", "title": "快乐，告诉我", "year": 2023, "region": "中国台湾", "type": "电影", "genre": "剧情 / 家庭", "tags": ["抑郁症", "母女", "和解", "遗书", "治愈"], "summary_short": "快乐，告诉我，2023年中国台湾电影，剧情 / 家庭。叛逆少女李心洁讨厌母亲每天愁眉苦脸的样子，觉得她“作”。直到母亲服下大量安眠药被送进ICU，陷入深度昏迷。医生告诉心洁，唤醒母亲的唯一方式是情感刺激。心洁翻出母亲压箱底的少女日记，惊讶地发现母亲年轻时曾是开朗的校刊主编，热爱写作。随着阅读深入，她发现母亲的抑郁始于怀上自己之后——丈夫出轨、产后失业、身材走形，而小时候的自己曾无数次对母亲说“你为什么不笑？”“我讨厌你”。心洁决定模仿日", "score": 2023274, "category": "drama", "detail_url": "../movie/1991.html", "poster": "../posters/1991.svg"}, {"id": "1992", "title": "缺席者", "year": 2017, "region": "法国", "type": "电影", "genre": "悬疑、剧情、心理", "tags": ["失踪，记忆，心理医生，幻觉，阿尔卑斯"], "summary_short": "缺席者，2017年法国电影，悬疑、剧情、心理。巴黎心理医生托马斯收到一封来自阿尔卑斯山小镇的奇怪邮件，发件人是他的病人洛朗，但洛朗已失踪三年。托马斯前往小镇调查，却遭遇了集体的否认：警方没有记录、邻居说从未见过、连洛朗的“母亲”也坚称自己没儿子。托马斯开始怀疑自己的记忆出了问题，他住进洛朗曾经的公寓，每晚都做同样的噩梦。随着调查深入，他发现自己与洛朗有着诡异的联系：他们拥有同一个心理师，甚至爱上过同一个女人。最终托马斯在一座废弃的滑雪缆", "score": 2017316, "category": "drama", "detail_url": "../movie/1992.html", "poster": "../posters/1992.svg"}, {"id": "1993", "title": "尤物争春", "year": 2017, "region": "中国大陆", "type": "电视剧", "genre": "剧情, 爱情, 家庭", "tags": ["姐妹", "家族纷争", "民国", "女性"], "summary_short": "尤物争春，2017年中国大陆电视剧，剧情, 爱情, 家庭。故事发生在动荡的二十世纪三十年代。沈家绣坊的大小姐沈春与二小姐沈华，因一场突如其来的变故被迫分离。十年后，姐姐春成为了上海滩最当红的交际花，周旋于权贵之间，只为追查当年家变的真相。而妹妹华，则远嫁海外归来，带着新式的思想和一笔巨款，誓要重振沈家绣坊。当姐妹俩再次相遇，却因误会和各自的立场站在了对立面。她们爱上了同一个男人，卷入了不同的政治势力，也为了沈家绣坊的继承权而明争暗斗。在", "score": 2017304, "category": "series", "detail_url": "../movie/1993.html", "poster": "../posters/1993.svg"}, {"id": "1994", "title": "巨牛", "year": 2025, "region": "中国大陆", "type": "电影", "genre": "喜剧, 奇幻, 动作", "tags": ["股市", "生肖拟人", "都市传说", "疯癫"], "summary_short": "巨牛，2025年中国大陆电影，喜剧, 奇幻, 动作。沪漂程序员牛大壮是一个资深“韭菜”，炒股十年亏损百万。在他准备跳楼时，一个自称“太白金星”的流浪老头告诉他：他是天庭负责守护人间经济的神兽“巨牛星”转世，但由于投胎时记忆被封存，所以一直在反向操作。只要他在每个交易日的9:15，站上陆家嘴环形天桥的正中心，对着东方明珠大喊一声“牛市”，当天A股必定暴涨。半信半疑的牛大壮试了一次，结果上证指数狂拉5%，所有股票涨停。这一下他成了“股神”，", "score": 2025392, "category": "comedy", "detail_url": "../movie/1994.html", "poster": "../posters/1994.svg"}, {"id": "1995", "title": "小公主苏菲亚", "year": 2026, "region": "美国", "type": "剧集", "genre": "奇幻 / 冒险 / 儿童", "tags": ["平行世界", "魔法宝石", "友谊"], "summary_short": "小公主苏菲亚，2026年美国剧集，奇幻 / 冒险 / 儿童。10 岁的苏菲亚是一个沉迷科学、性格假小子的普通女孩，对“公主”之类的东西嗤之以鼻。在一次旧物拍卖会上，她得到了祖母留下的旧项链。戴上项链的瞬间，她被拉入了一个名为“恩赐之境”的平行世界，那里所有的童话公主都是真实存在的，且都在一所学院里学习魔法。但这个世界正面临“反童话”病毒的侵袭，公主们正在逐渐遗忘自己的故事。苏菲亚必须利用现实世界的逻辑思维和科学知识，去修复那些被篡改的童", "score": 2026230, "category": "series", "detail_url": "../movie/1995.html", "poster": "../posters/1995.svg"}, {"id": "1996", "title": "未来冲击", "year": 2026, "region": "美国", "type": "电影", "genre": "科幻剧情", "tags": ["近未来", "科技伦理", "速度", "焦虑"], "summary_short": "未来冲击，2026年美国电影，科幻剧情。2035年，社会运转在“加速主义”逻辑下，人们吃饭用营养针、恋爱靠AI匹配、阅读由脑机接口直接灌入。人类平均注意力跨度降至8秒，任何需要连续思考超过30秒的行为都被视为“病态”。一名前神经科学家艾登开设了全美第一家“实体书俱乐部”，会员们聚在一个没有任何电子设备的暗室里，用手翻纸质书，一页停留超过一分钟，被政府定性为“反社会速度的恐怖组织”。在追捕与逃亡中，艾登发现他的会员们逐渐恢复了一种早已失传", "score": 2026321, "category": "drama", "detail_url": "../movie/1996.html", "poster": "../posters/1996.svg"}, {"id": "1997", "title": "便利店新星", "year": 2020, "region": "韩国", "type": "剧集", "genre": "爱情，喜剧", "tags": ["便利店，夜班，逆袭，社畜，甜宠"], "summary_short": "便利店新星，2020年韩国剧集，爱情，喜剧。前职业拳击手姜七星因性格耿直得罪赞助商被行业封杀，走投无路时进入一家24小时便利店上夜班。他发现前任店长留下了一本手写《新星守则》，里面记载着各种匪夷所思的经营技巧：给深夜买烟的男人多找零钱可以化解家庭暴力，在过期饭团里塞纸条能拯救自杀倾向者。七星半信半疑地执行，便利店逐渐变成街区深夜的避难所。此时，房地产开发商盯上了店面，七星集结常客们——患有 PTSD 的退伍军人、离家出走的少女、假装上班", "score": 2020322, "category": "series", "detail_url": "../movie/1997.html", "poster": "../posters/1997.svg"}, {"id": "1998", "title": "我的爱我的新娘", "year": 2024, "region": "韩国", "type": "电影", "genre": "爱情 / 喜剧", "tags": ["婚姻", "现实", "搞笑", "温馨", "日常"], "summary_short": "我的爱我的新娘，2024年韩国电影，爱情 / 喜剧。外表憨厚的开发人员民浩与活泼开朗的空姐智英结束爱情长跑，步入了婚姻殿堂。然而当激情褪去，现实的琐碎如潮水般涌来。民浩无法忍受智英把家里弄成快递箱的海洋，智英则崩溃于民浩连马桶圈都不愿抬的懒惰。从谁做饭到过节回谁家，两人的争吵不断升级。更糟糕的是，民浩在同学会上遇到了当年的暗恋对象，而智英也发现当初那个帅气的老公竟然睡觉打呼噜磨牙。两人在民政局门口偶遇前来离婚的夫妻，相视苦笑。在吵吵闹闹", "score": 2024311, "category": "comedy", "detail_url": "../movie/1998.html", "poster": "../posters/1998.svg"}, {"id": "1999", "title": "砖匠", "year": 2016, "region": "中国大陆", "type": "电影", "genre": "剧情, 家庭", "tags": ["农民工", "父子", "底层", "方言电影", "现实"], "summary_short": "砖匠，2016年中国大陆电影，剧情, 家庭。老赵在城里工地上搬了十五年砖，唯一的骄傲是儿子小杰考上了省重点中学。小杰喜欢弹吉他，梦想当歌手，老赵不懂音乐，只知道那玩意儿“花钱又不当饭吃”。父子俩挤在不足十平米的工棚里，沉默多于对话。直到有一天，小杰被校园霸凌打断了手臂，不能再弹琴。老赵第一次发了疯，他找到欺负儿子的富二代家长，没有动手，而是当众跪下。那一刻，整座城市的高楼大厦都成了这位父亲弯曲脊背的背景板。", "score": 2016301, "category": "drama", "detail_url": "../movie/1999.html", "poster": "../posters/1999.svg"}, {"id": "2000", "title": "白鹿原2017", "year": 2017, "region": "中国大陆", "type": "剧集", "genre": "历史、家庭", "tags": ["关中平原、宗族、时代变迁"], "summary_short": "白鹿原2017，2017年中国大陆剧集，历史、家庭。根据陈忠实小说改编，2017版剧集以更完整篇幅讲述白嘉轩与鹿子霖两大家族从清末到解放初的恩怨。白嘉轩恪守宗法，鹿子霖投机圆滑，两人斗了一辈子。但剧集新线是白嘉轩之女白灵加入革命后，发现家族土地契约上根本没有什么“白鹿神迹”，只是祖先为了统治编造的谎言。白鹿原真正的神灵是世代长工黑娃。黑娃最终烧掉祠堂，白嘉轩跪在原上哭喊：“我们争了一辈子，争的是假的。”白鹿原进入新时代，白鹿传说被彻底抛", "score": 2017200, "category": "series", "detail_url": "../movie/2000.html", "poster": "../posters/2000.svg"}];
